// Файл РІЧНИЙ — на новий рік згенеруй новий і онови ensureVkazivky() в index.html.
const VKAZIVKY_2026 = [
{"date":"01-01","weekday":"четвер","title":"Обрізання Господнє. Свт. Василія Великого, архієп. Кесарії Каппадокійської (379). Мч. Василія Анкірського (бл. 362). Св. Емілії, матері свт. Василія Великого (ІV). Прп. Амфілохія Почаївського, в малій схимі Йосифа, чудотворця Іловецького. (1971). Літургія за чином свт. Василія Великого.","readings":["Ран. – Ін., 35 зач. (від половини), X, 1 – 9.","Літ. – Обрізання: Кол., 254 зач., II, 8 – 12. Лк., 6 зач., II, 20 – 21, 40 – 52.","Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23. (під зачало)."],"notes":"Подаємо порядок звершення служби Обрізання Господнього у поєднанні із бдінною службою свт. Василія Великого та шестеричною службою прп. Амфілохія Почаївського (із Загальної Мінеї).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 10: свята, глас 8-ий – 4 (по двічі), святителя Василія, глас 4-ий – 4 (перша стихира – двічі) і преподобного, глас 8-ий – 2. «Слава» – святителя, глас 8-ий: «Ти, преподобний, був ревнителем премудрости...», «І нині» – свята, глас той самий: «Як сходив Спас...». Вхід з кадилом. Прокимен дня. Паремії Мінеї – 3. На літії стихира храму і стихири святителя, глас 3-ій. «Слава» святителя, глас 6-ий: «Виливалася благодать...», «І нині» – свята, глас 8-ий: «Як сходив Спас...». На стиховні стихири святителя, глас 1-ий та 2-ий. «Слава» – святителя, глас 6-ий: «Благодать чудес...», «І нині» – свята, глас 8-ий: «Не посоромився Всеблагий Бог...». Після Трисвятого – тропар святителя Василія, глас 1-ий (двічі), і «Богородице Діво...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» тропар свята, глас 1-ий (один раз), святителя Василія (один раз), глас той самий. «Слава» – преподобного, глас 8-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 13-та і 14-та. Малі ектенії. Сідальні Мінеї. Полієлей. Величання тільки святителя: «Величаємо тебе,/святителю отче Василію,/ і шануємо святу пам’ять твою,/ бо ти молиш за нас Христа Бога нашого». Величання співається з вибраними стихами із псалмів Давидових, співають по черзі обидва хори. Після полієлею сідальні із Мінеї. Степенна – 1-ий антифон 4-го гласу. Прокимен святителя, глас 1-ий: «Уста мої промовлятимуть премудрість, і повчання серця мого розум»; стих: «Почуйте це, всі народи, зрозумійте, всі, що живете у світі». Євангеліє. Після 50-го псалма: «Слава» – «Молитвами святителя Василія...». Стихира святителя, глас 6-ий: «Вилилася благодать...». Канони: свята на 6, святителя Василія на 6 і преподобного на 2. Біблійні пісні: «Співаймо Господеві...». Катавасія – ірмоси канонів свята Богоявлення. Після 3-ої пісні – кондак свята, глас 3-ій; кондак та ікос преподобного глас 2-ий; сідальний святителя Василія, глас 8-й; «Слава» – сідальний преподобного «І нині» – сідальний свята, глас 4-ий. Після 6-ої пісні – кондак та ікос святителя Василія, глас 4-ий. На 9-ій пісні «Чеснішу...» не співаємо, але співаємо приспіви свята Обрізання та святителя Василія. Після 9-ої пісні – світильний святителя Василія (двічі). «Слава» – світильний преподобного, «І нині» – світильний свята. На хвалітніх стихири свята і святителя, глас 5-ий – 6 (перша стихира – двічі). «Слава» – святителя, глас 6-ий: «Вилилася благодать...», «І нині» – свята, глас 8-й: «Зійшовши до роду людського, Спас...». Велике славослів’я. Після Трисвятого – тропар святителя Василія, глас 1-ий. «Слава» преподобного, глас 8-ий, «І нині» – тропар свята, глас 1-ий. Відпуст: «Христос, істинний Бог наш, що на восьмий день плоттю обрізатися зволив ради нашого спасіння, молитвами Пречистої Своєї Матері, святого отця нашого Василія Великого, архієпископа Кесарії Каппадокійської і преподобного отця нашого Амфілохія Почаївського їх же пам’ять нині звершуємо, і всіх святих, помилує і спасе нас, як Благий і Людинолюбний». (Святий храму і місцевошановані святі не згадуються)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ: На 1-му і 6-му часі – тропар свята. «Слава» – тропар святителя Василія. Кондак свята. На 3-му і 9-му часі – тропар свята. «Слава» – тропар преподобного. Кондак святителя Василія."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 3-я – 4 (з ірмосом), святителя Василія, пісня 6-а – 4 (без ірмоса). На вході – «Прийдіть поклонімось... у святих Дивний Ти...». Після входу – тропар свята, тропар святителя Василія, тропар преподобного, кондак святителя. «Слава» – кондак преподобного, «І нині» – кондак свята. Співається Трисвяте. Прокимен – свята, глас 6-ий: «Спаси, Господи, людей Твоїх...»; стих: «До Тебе, Господи...», і святителя, глас 1-ий: «Уста мої промовлятимуть...». Апостол і Євангеліе – свята, святителя і преподобного (під зачало). Алилуарій – свята, глас 8-ий: «Пастирю Ізраїля...»; і святителя, глас той самий: «Уста праведного...». Замість «Достойно є...» – «Тобою радується...». Причасний – свята: «Хваліте Господа з Небес...», і святителя: «В пам’ять вічну...»."}]},
{"date":"01-02","weekday":"п’ятниця","title":"Передсвято Богоявлення. Свт. Сильвестра, єпископа Римського (335). Прп. Серафима Саровського, чудотворця (1833). Прп. Сильвестра Києво-Печерського, в Ближніх печерах (ХІІ). Сщмч. Феогена, єп. Парійського (бл. 320).","readings":["Євр., 326 зач., X, 35 – XI, 7. Мк., 39 зач., IX, 10 – 16 (за четвер, під зачало).","Євр., 327 зач., XI, 8, 11 – 16. Мк., 41 зач., IX, 33 – 41 (за п’ятницю).","Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 8 зач., ІІІ, 1 – 15."],"notes":"Служба свт. Сильвестра шестирична звершується разом із службою передсвята.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: передсвята, глас 4-ий – 3, і святителя, глас 8-ий – 3. «Слава: І нині» – передсвята, глас 6-ий: «Гряде до Йордану Христос-істина...». Входу немає. Прокимен дня. На стиховні стихири передсвята, глас 1-ий, 2-ий і 3-ій (зі своїми приспівами). «Слава: І нині» – передсвята, глас 3-ій: «Прийдіть, усі вірні...». Після Трисвятого – тропар святителя, глас 4-ий. «Слава: І нині» – тропар передсвята, глас 4-ий: «Готуйся, Завулоне...». Після співу тропарів на вечірні. Диякон виголошує: «Премудрість». Хор: «Благослови». Ієрей: «Сущий благословенний...». Хор: «Утверди, Боже...». Ієрей: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Ієрей: «Слава Тобі, Христе Боже...». Хор: «Слава: І нині», «Господи, помилуй» (тричі), «Благослови». Ієрей виголошує відпуст."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї співаємо трипіснець передсвята, глас 2-ий і глас 6-ий та двопіснець."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий: «Готуйся, Завулоне...» (двічі). «Слава» – тропар святителя, глас 4-ий, «І нині» – тропар передсвята, глас той самий: «Готуйся, Завулоне...». Кафизми 19-та і 20-та. Малі ектенії. Сідальні передсвята. Псалом 50-ий. Канони: передсвята, глас 2-ий з ірмосом на 8 (ірмоси по двічі) і святителю на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої, 9-ої пісень – ірмос канону святителя. Після 3-ої пісні – кондак святого, глас 4-ий; сідальний святого, глас 8-ий «Слава: І нині» – сідальний передсвята. Після 6-ої пісні – кондак та ікос передсвята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є...» не співається. Після 9-ої пісні – світильний передсвята. «Слава: І нині» – знову світильний передсвята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 4: передсвята, глас 6-ий. «Слава» – передсвята, глас 6-ий: «І нині» – передсвята, глас той самий: «Вся земля нехай нині радіє...». «Тобі слава належить...» не читається, але одразу «Слава Тобі, що показав нам світло» і читається повсякденне славослів’я. На стиховні стихири передсвята глас 6-ий. «Слава: І нині» – передсвята, глас 8-ий: «Іоан Хреститель...». Після Трисвятого – тропар святителя, глас 4-ий. «Слава: І нині» – тропар передсвята, глас 4-ий: «Готуйся, Завулоне...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар передсвята. «Слава» – тропар святителя. Кондак передсвята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ – блаженні передсвята, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. На вході – «Прийдіть поклонімось... у святих Дивний Ти...». Після входу – тропарі і кондаки: Примітка. У період передсвята і післясвята Хрещення денні тропарі не співають, оскільки піснеспіви Октоїха скасовуються. У храмі Господньому – тропар передсвята, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак передсвята. У храмі Богородиці – тропар передсвята, тропар храму, тропар святителя; кондак храму, «Слава» – кондак святителя, «І нині» – кондак передсвята. У храмі святого – тропар передсвята, тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – кондак передсвята. Співається Трисвяте. Прокимен, алилуарій і причасний – дня (п’ятниці) та святителя. Апостол і Євангеліє – дня (п’ятниці і четверга, під зачало) і святителя."}]},
{"date":"01-03","weekday":"субота","title":"Субота перед Богоявленням. Прор. Малахії (400 р. до Р. Х.). Мч. Гордія (ІV).","readings":["Суботи перед Богоявленням: 1 Тим., 284 зач., III, 14 – IV, 5. Мф., 5 зач., III, 1 – 11.","Мч.: 2 Тим., 292 зач., II, 1 – 10. Мф., 36 зач., Х, 16 – 22."],"notes":"Служба пророка Малахії і мученика Гордія без святкового знаку звершується разом з службою передсвята.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 18-та. На «Господи, взиваю» стихири на 6: пророка, глас 8-ий – 3, і мученика, глас той самий – 3. «Слава: І нині» – передсвята, глас 4-ий: «Ось просвічення вірних...». Входу немає. Прокимен дня. На стиховні стихири передсвята, глас 6-ий (зі своїми приспівами). «Слава: І нині» – передсвята, глас 5-ий: «На Йорданську річку...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава: І нині» – тропар передсвята, глас 4-ий: «Готуйся, Завулоне...»."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї співаємо трипіснець передсвята, глас 2-ий і глас 6-ий та двопіснець з попереднього дня."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий: «Готуйся, Завулоне...» (двічі). «Слава» – тропар мученика, глас 4-ий, «І нині» – тропар передсвята, глас той самий: «Готуйся, Завулоне...». Кафизми 16-та і 17-та. Малі ектенії. Сідальні передсвята. Псалом 50-ий. Канони: передсвята, глас 6-ий з ірмосом на 6 (ірмоси по двічі), пророка на 4 і мученика на 4. Біблійні пісні: «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої, 9-ої пісень – ірмос канону мученика. Після 3-ої пісні – кондак пророку, глас 4-ий, кондак мученика, глас 8-ий; сідальний пророка, глас 8-ий. «Слава» – сідальний мученика, «І нині» – сідальний передсвята. Після 6-ої пісні – кондак та ікос передсвята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Після 9-ої пісні – світильний передсвята. «Слава: І нині» – знову світильний передсвята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири передсвята, глас 6-ий – 4. «Слава» – передсвята, глас 6-ий: «Зірка від Якова...», «І нині» – передсвята, глас той самий: «Закону Виконавець...». «Тобі слава належить» не читається, але одразу «Слава Тобі, що показав нам світло» і читається повсякденне славослів’я. На стиховні стихири передсвята глас 2-ий. «Слава: І нині» – свята, глас той самий: «Явилося Отчої слави...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава: І нині» – тропар передсвята, глас 4-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар передсвята. «Слава» – тропар мученика. Кондак тільки передсвята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ – блаженні передсвята, пісня 3-тя – 4 (з ірмосом), і мученика, пісня 6-та – 4. На вході – «Прийдіть поклонімось... у святих Дивний Ти...». Після входу – тропарі і кондаки: У храмі Господньому – тропар передсвята, тропар мученика; кондак пророка. «Слава» – кондак мученика, «І нині» – кондак передсвята. Примітка. У період передсвята і післясвята Хрещення денні тропарі не співають, оскільки піснеспіви Октоїха скасовуються. У передсвята і післясвята Господніх свят, у всю П’ятидесятницю, в недільні дні, в великі і середні Господні свята тропар і кондак Господнього храму не співають. У храмі Богородиці устав співу може бути двох варіантів: I. Тропар передсвята, тропар храму, тропар мученика; кондак храму, кондак пророка. «Слава» – кондак мученика, «І нині» – кондак передсвята. II. Тропар передсвята, тропар храму, тропар мученика; кондак передсвята; кондак пророка. «Слава» – кондак мученика, «І нині» – кондак храму. Примітка. У передсвята і післясвята Богородичних двонадесятих свят, в Богородичні великі, полієлейні та славослівні свята тропар і кондак храму Богородиці не співають. Кондак храму Богородиці співається у всю П’ятидесятницю. У храмі святого – тропар передсвята, тропар храму, тропар мученика; кондак храму, кондак пророка. «Слава» – кондак мученика, «І нині» – кондак передсвята. Прокимен, алилуарій і причасний – дня і мученика. Апостол і Євангеліє – суботи перед Богоявленням і мученика."}]},
{"date":"01-04","weekday":"неділя","title":"30-та неділя після П’ятдесятниці, перед Богоявленням. Глас 5-й. Собор 70-х апостолів: Якова, брата Господнього; Марка і Луки, євангелістів; Клеопи, Симеона, Варнави, Іосії, званого Юстом, Фадея, Ананія, Стефана, Филипа, Прохора, Никанора, Тимона, Пармена, Тимофія, Тита, Филимона, Онисима, Епафраса, Архипа, Сили, Силуана, Крискента, Криспа, Епенета, Андроніка, Стахія, Амплія, Урвана, Наркиса, Апелія, Аристовула, Родіона (Іродіона), Агава, Руфа, Асинкрита, Флегонта, Єрма, Патрова, Єрмія, Ліна, Гая, Філолога, Лукія, Ясона, Сосипатра, Олімпа (Олімпана), Тертія, Ераста, Куарта, Евода, Онисифора, Климента, Сосфена, Аполлоса, Тихика, Епафродита, Карпа, Кондрата, Марка, сина Варнави, Зіни, законника, Аристарха, Пуда, Трофима, Марка, Артеми, Акили, Фортуната, Ахаїка, Діонісія Ареопагіта і Симеона Нігера. Прп. Феоктиста, ігум. Кукума Сикелійського (800). Свт. Євстафія І, архієп. Сербського (бл. 1285). Прп. Ахіли, дияк., Києво-Печерського, в Дальніх печерах (ХІV). Прмч. Зосими і мч. Афанасія (ІІІ – ІV).","glas":5,"readings":["Ран. – Єв. 8-е, Ін., 64 зач., XX, 11 – 18.","Літ. – неділі перед Богоявленням: 2 Тим., 298 зач., IV, 5 – 8. Мк., 1 зач., I, 1 – 8.","Апп.: Рим., 96 зач. (від половини), VIII, 3 – 9. Лк., 50 зач., X, 1 – 15."],"notes":"Звершується Воскресна служба Октоїха разом зі службою передсвята Богоявлення Господнього та славослівною службою собору 70-х апостолів.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж...» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 5-ий – 4, передсвята, глас 8-ий – 3 (див. стихири на стиховні на вечірні, без написаних в Мінеї приспівів), і апостолів, глас 4-ий – 3. «Слава» – передсвята, глас 3-ій: «Світле пройшовни свято...», «І нині» – догматик, глас 5-ий: «У Червоному морі...». Вхід. Прокимен дня. На літії стихира храму і стихири передсвята, глас 2-ий (див. на стиховні на ранній, без написаних в Мінеї приспівів). «Слава: І нині» – свята, глас той же: «Нині Христос дарує...» (див. стихири на стиховні на ранній). На стиховні стихири воскресні, глас 5-ий. «Слава: І нині» – передсвята, глас 6-ий: «Гряде на Йордан Христос...» (див. стихири на стиховні на вечірній). Після Трисвятого – «Богородице Діво радуйся» (двічі) і тропар передсвята, глас 4-ий: «Готуйся, Завулоне...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 5-ий (двічі). «Слава» – тропар апостолів, глас 3-ій; «І нині» – тропар передсвята, глас 4-ий: «Готуйся, Завулоне...». Кафизми 2-а і 3-я. Малі ектенії. Сідальні воскресні. Непорочні. «Ангельський собор...». Іпакої, Степенні і прокимен – гласу. Євангеліє воскресне 8-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу ..». Канони: воскресний з ірмосом на 4 (ірмос один раз), Богородиці (Октоїха) на 2, передсвята на 4 і апостолів (перший) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія свята Богоявлення: «Глибини відкрив Ти дно...». Після 3-ої пісні – кондак та ікос передсвята, глас 4-ий; кондак та ікос апостолів, глас 2-ий, сідальний апостолів, глас 3-ій. «Слава: І нині» – сідальний передсвята, глас 1-ий. Після 6-ої пісні – кондак і ікос воскресні, глас 5-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Після 9-ої пісні – «Свят Господь Бог наш», Екзапостиларій воскресний 8-ий. «Слава» – світильний передсвята, «І нині» – інший світильний передсвята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас, 3-ій – 4 і передсвята, глас 6-ий – 4 (див. хвалітні стихири Мінеї з приспівами, які слід брати зі стихир на стиховних вечірні). «Слава» – стихира євангельска 6-та, «І нині» – «Преблагословенна Богородице...» Велике славослів’я. Після Трисвятого – тропар воскресний: «Вдень спасіння світу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ: на 1-му і 6-му часі – тропар воскресний. «Слава» – тропар передсвята; кондак передсвята. На 3-му і 9-му часі – тропар воскресний, «Слава» – тропар апостолам; кондак воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ – блаженні гласу – 4. передсвята, пісня 3-я – 4, і апостолів, пісня 6-а – 4. На вході – «Прийдіть поклонімось... що воскрес із мертвих...». Після входу – тропарі і кондаки: У храмі Господньому – тропар воскресний, тропар передсвята, тропар апостолів; кондак воскресний. «Слава» – кондак апостолів, «І нині» – кондак передсвята. У храмі Богородиці і святого – тропар воскресний, тропар передсвята, тропар храму, тропар апостолів; кондак воскресний, кондак храму. «Слава» – кондак апостолів, «І нині» – кондак передсвята. Прокимен, алилуарій, апостол та євангеліє – неділі перед Богоявленням та апостолів. Співається «Достойно є...». Причасний – воскресний: «Хваліте Господа...» та апостолів."}]},
{"date":"01-05","weekday":"понеділок","title":"31-й тиждень після П’ятдесятниці. Навечір’я Богоявлення (Хрещенський святвечір). Сщмч. Феопемпта, єп. Нікомидійського, і мч. Феони, волхва (303). Прп. Синклітикії Олександрійської (бл. 350). Прор. Михея (ІХ ст. до Р. Х.). Прп. Аполінарії (бл. 470). Прпп. Фостирія та Мини (VІ). Прп. Григорія Акритського (бл. 820). Літургія за чином свт. Василія Великого.","readings":["На 1-му часі – Діян., 33 зач., ХІІІ, 25 – 32. Мф., 5 зач., ІІІ, 1 – 11.","На 3-му часі – Діян., 42 зач., ХІХ, 1 – 8. Мк., 1 зач., І, 1 – 8.","На 6-му часі – Рим., 91 зач., VI, 3 – 11. Мк., 2 зач., І, 9 – 15.","На 9-му часі – Тит., 302 зач., ІІ, 11 – 14; ІІІ, 4 – 7. Мф., 6 зач., ІІІ, 13 – 17.","Літ. – 1 Кор., 143 зач., IX, 19 – 27. Лк., 9 зач., III, 1 – 18.","Під час освячення води – 1 Кор., 143 зач. (від пол.), Х, 1 – 4. Мк., 2 зач., І, 9 – 11."],"sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: мучеників, глас 4-ий – 3, і преподобної, глас 1-ий – 3. «Слава: І нині» – передсвята, глас 6-ий: «Готуйся, Йордане-ріко...». Входу немає. Прокимен дня. На стиховні стихири передсвята, глас 6-ий (зі своїми приспівами). «Слава: І нині» – передсвята, глас той же: «Нехай радіє пустеля...». Після Трисвятого – тропар передсвята, глас 4-ий: «Повернувся колись Йордан-ріка милоттю Єлисеєвою...» (один раз)."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї співаємо канон передсвята, глас 6-ий: «Хвилею морською...» (ірмоси по двічі, тропарі на 6). Катавасія після кожної пісні канону."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий: «Повернувся колись Йордан-ріка милоттю Єлисеєвою...» (двічі). «Слава, і нині» – той же тропар. Кафизми 4-а і 5-а. Малі єктенії. Сідальні передсвята. Псалом 50-ий. Канони: передсвята з ірмосом на 6 (ірмоси по двічі), мучеників на 4 і преподобної на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісні – ірмоси канону Мінеї (преподобної). Після 3-ої пісні – інший кондак передсвята, глас 2-ий: «Всіх, Христе, милосердно...»; сідальний мучеників, глас 1-ий, сідальний преподобної, глас 5-ий. «Слава: І нині» – сідальний передсвята, глас 1-ий. Після 6-ої пісні – кондак («Господь, будучи нині в струменях Йорданських...») та ікос передсвята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний передсвята. «Слава: І нині» – інший світильний передсвята. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихирах передсвята, глас 6-ий – 4. «Слава» – передсвята, глас той же: «З тремтінням служачи...», «І нині» – передсвята, глас той же: «Оспіваймо, люди...». «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири передсвята, глас 2-ий (зі своїми приспівами). «Слава: І нині» – передсвята, глас 8-ий: «Іоане Хрестителю...». Після Трисвятого – тропар передсвята, глас 4-ий: «Повернувся колись Йордан-ріка милоттю Єлисеєвою...» (один раз). Потрійна єктенія: «Помилуй нас, Боже...» і відпуст (виголошується на амвоні при зачинених царських вратах). Перший час до ранньої не приєднується. Окремо від ранньої (за Уставом, «на початку 2-ої години», тобто, за нашим відліком часу, близько 8 години ранку) відбувається послідовність часів навечір’я (1-го, 3-го, 6-го і 9-го) з приєднанням до них чину зображальних і вечірні з Літургією святого Василія Великого. Царські часи звершуються при відкритих царських вратах. Священик в єпитрахилі, фелоні та, за традицією, в поручах, з Євангелієм в руках (у супроводі свічконосця і диякона в облаченні, з кадилом та свічкою) виходить з вівтаря через царські врата до аналоя поставленого посеред церкви навпроти Царських врат. Обійшовши навколо аналоя, свічконосець ставить свічку з його східної сторони. Ієрей, поклавши Євангеліє на аналой, виголошує початковий виголос 1-го часу: «Благословенний Бог наш...». Читець: «Амінь», «Слава Тобі, Боже наш, слава Тобі», «Царю Небесний...», Трисвяте. Після «Отче наш...» ієрей – виголос: «Бо Твоє є Царство...». Читець: «Амінь», «Господи, помилуй (12 разів), «Слава: І нині», «Прийдіть, поклонімось...» (тричі) і псалми 1-го часу (5-ий, 22-ий і 26- ий). З початком читання псалмів ієрей, разом з дияконом зі свічкою, звершує кадіння навколо Євангелія, потім кадить вівтар, іконостас, народ і весь храм. Після закінчення 26-го псалма читець виголошує: «Слава: І нині», «Алилуя, Алилуя, Алилуя, слава Тобі, Боже» (тричі), «Господи, помилуй» (тричі), «Слава» – хор або читець: тропар передсвята, глас 4-ий: «Повернувся колись Йордан...», читець: «І нині» – Богородичний: «Як Тебе назвемо, Благодатна?..». Після Богородичного часу хор співає (зазвичай стихирним наспівом) особливі тропарі свята зі стихами: 1-ий хор – тропар, глас 8-ий: «Сьогодні освячується природа води...», 2-ий хор – той же тропар. Читець – стих, глас той же: «Заради цього пом’янув Тебе на землі Йорданській і Єрмонській», 1-ий хор – тропар, глас той же: «Як Людина на ріку прийшов Ти...». Читець – стих: «Побачили Тебе води, Боже; побачили Тебе води і убоялися.», 2-ий хор – той же тропар. 1-ий хор – «Слава» – тропар, глас той же: «На голос, що лунав у пустелі: готуйте путь Господню, – прийшов Ти, Господи...», 2-ий хор – «І нині» – той же тропар. Після виконання тропарів диякон виголошує: «Будьмо уважні». Читець – прокимен, глас 4-ий: «Прокимен, глас 4-ий: І прогримів Господь з небес, і Вишній подав голо Свій». Стих: «Полюблю Тебе, Господи, кріпость моя; Господь утвердження моє». Після виконання хором прокимна читаються паремія і Апостол. Диякон: «Премудрість». Читець: «Пророцтва Ісаї читання». Диякон: «Будьмо уважні». Читець читає Паремію (гл. 35). Диякон: «Премудрість». Читець: «Діянь святих апостолів читання». Диякон: «Будьмо уважні». Читець читає апостол (Діян., Зач. 33). «Алилуя» після Апостола не читається, але відразу диякон виголошує: «Премудрість, станьмо побожно, вислухаймо святого Євангелія». Ієрей: «Мир всім». Хор: «І духові твоєму». Ієрей: «Від Матфея святого Євангелія читання». Хор: «Слава Тобі, Господи, слава Тобі». Диякон: «Будьмо уважні». Ієрей читає Євангеліє (Мф., Зач. 5). Після закінчення Євангелія хор співає: «Слава Тобі, Господи, слава Тобі». Читець – тропарі: «Стопи мої направ...» і «Нехай сповняться уста моя...», Трисвяте. після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Читець або хор: «Амінь», і кондак передсвята, глас 4-ий: «Господь, будучи нині в струменях Йорданських, взиває до Іоана: не бійся хрестити Мене, бо Я прийшов спасти Адама первозданного». Читець: «Господи, помилуй» (40 разів), молитва: «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава: І нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Ієрей: «Боже, ущедри нас і благослови нас...». Читець: «Амінь». Ієрей: «Христе, Світло Істинне...». Читець: «Прийдіть, поклонімось...» (тричі), і починає 3-ій час. Під час читання псалмів 3-го часу (28-го, 41-го і 50-го) ієрей з дияконом (за Типіконом – диякон) звершують мале кадіння храму: кадять навколо Євангеліє, іконостас, предстоятеля і моляться. Після закінчення 50-го псалма читець: «Слава: І нині», «Алилуя, Алилуя, Алилуя, слава Тобі, Боже» (тричі), «Господи, помилуй» (тричі), «Слава» – хор або читець: тропар передсвята, глас 4-ий: «Повернувся колись Йордан...», читець: «І нині» – Богородичний: «Богородице, Ти єси виноградна лоза істинна...». Хор співає тропарі свята зі стихами: 1-ий хор – тропар, глас 8-ий: «Тремтіла правиця Предтечі Хрестителя і пророка,...», 2-ий хор – той же тропар. Читець – стих, глас 4-ий: «Заради цього пом’янув Тебе на землі Йорданській і Єрмонській.», 1-ий хор – тропар, глас той же: «Тройця, Бог наш...». Читець – стих: «Побачили тебе води, Боже, побачили Тебе води й убоялися.», 2-ий хор – той же тропар. 1-ий хор – «Слава» – тропар, глас 5-ий: «Хто йде з тілом...», 2-ий хор – «І нині» – той же тропар. Після виконання тропарів диякон: «Будьмо уважні». Читець – Прокимен, глас 6-ий: «Побачили Тебе води, Боже, побачили Тебе води й убоялися». Стих: «Голосом моїм до Господа взивав, голосом моїм до Бога, і вислухав мене». Після виконання хором прокимна читаються паремія і Апостол. Диякон: «Премудрість». Читець: «Пророцтва Ісаї читання». Диякон: «Будьмо уважні». Читець читає Паремію (глава 1). Диякон: «Премудрість». Читець: «Діянь святих апостолів читання». Диякон: «Будьмо уважні». Читець читає апостол (Діян., Зач. 42). Ієрей: «Мир тобі». Читець: «І духові твоєму». Диякон: «Премудрість, станьмо побожно, вислухаймо святого Євангелія». Ієрей: «Мир всім». Хор: «І духові твоєму». Ієрей: «Від Марка святого Євангелія читання». Хор: «Слава Тобі, Господи, слава Тобі». Диякон: «Будьмо уважні». Ієрей читає Євангеліє (Мк., Зач. 1). Після закінчення Євангелія хор співає: «Слава Тобі, Господи, слава Тобі». Читець – тропар: «Господь Бог благословенний...», Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Читець або хор: «Амінь», і кондак передсвята, глас 4-ий: «Господь, будучи нині в струменях Йорданських...». Читець: «Господи, помилуй» (40 разів), молитва: «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава: І нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Ієрей: «Молитвами святих отців наших...». Читець – «Амінь» і молитву: «Владико, Отче Вседержителю...». Читець: «Прийдіть, поклонімось...» (тричі), і починає 6-ий час. Під час читання псалмів 6-ого часу (73-го, 76-го і 90-го) ієрей з дияконом (за Типіконом – диякон) здійснюють мале кадіння храму, як на 3-му часі. Після закінчення 90-го псалма читець: «Слава: І нині», «Алилуя, Алилуя, Алилуя, слава Тобі, Боже» (тричі), «Господи, помилуй» (тричі), «Слава» – хор або читець: тропар передсвята, глас 4-ий: «Повернувся колись Йордан...», читець: «І нині» – Богородичний: «Через превеликі гріхи наші сміливости не маємо...». Хор співає тропарі свята зі стихами: 1-ий хор – тропар, глас 8-ий: «Так говорить Господь...», 2-ий хор – той же тропар. Читець – стих, глас 6-ий: «Заради цього пом’янув Тебе на землі Йорданській і Єрмонській», 1-ий хор – тропар, глас той же: «Нині псаломське пророцтво...». Читець – стих: «Побачили тебе води, Боже, побачили Тебе води й убоялися», 2-ий хор – той же тропар. 1-й хор – «Слава» – тропар, глас 5-ий: «Чого повертаєш назад твої води, Йордане...», 2-ий хор – «І нині» – той же тропар. Після виконання тропарів диякон: «Будьмо уважні». Читець – прокимен, глас 4-й: «В морі путі Твої, і стежки Твої на водах многих». стих: «Голос грому твого в колесах». Після виконання хором прокимна читаються паремія і Апостол. Диякон: «Премудрість». Читець: «Пророцтва Ісаї читання». Диякон: «Будьмо уважні». Читець читає Паремію (глава 12). Диякон: «Премудрість». Читець: «До римлян послання святого апостола Павла читання». Диякон: «Будьмо уважні». Читець читає апостол (Рим., Зач. 91). Ієрей: «Мир тобі». Читець: «І духові твоєму». Диякон: «Премудрість, станьмо побожно, вислухаймо святого Євангелія». Ієрей: «Мир всім». Хор: «І духові твоєму». Ієрей: «Від Марка святого Євангелія читання». Хор: «Слава Тобі, Господи, слава Тобі». Диякон: «Будьмо уважні». Ієрей читає Євангеліє (Мк., Зач. 2). Після закінчення Євангелія хор співає: «Слава Тобі, Господи, слава Тобі». Читець – тропар: «Скоро пошли нам щедроти Твої...», Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Читець або хор: «Амінь», і кондак передсвята, глас 4-ий: «Господь, будучи нині в струменях Йорданських...». Читець: «Господи, помилуй» (40 разів), молитва: «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава: І нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Ієрей: «Молитвами святих отців наших...». Читець – «Амінь» і молитву: «Боже і Господи Сил...». Читець: «Прийдіть, поклонімось...» (тричі), і починає 9-ий час. Під час читання псалмів 9-го часу (92-го, 113-го і 85-го) ієрей з дияконом (за Уставом – диякон) звершують кадіння всього храму, як на 1-му часі. Після закінчення 85-го псалма читець: «Слава, і нині», «Алилуя, Алилуя, Алилуя, слава Тобі, Боже» (тричі), «Господи, помилуй» (тричі), «Слава» – хор або читець: тропар передсвята, глас 4-ий: «Повернув колись Йордан...», читець: «І нині» – Богородичний: «Ти, що ради нас народився від Діви...». Хор співає тропарі свята зі стихами: 1-ий хор – тропар, глас 7-ий: «Страшно було бачити на річці Творця неба і землі...», 2-ий хор – той же тропар. Читець – стих, глас 2-ий: «Заради цього пом’янув Тебе на землі Йорданській і Єрмонській...», 1-ий хор – тропар, глас той же: «Коли побачив Предтеча грядущого до себе Господа слави...». Читець – стих: «Побачили Тебе води, Боже, побачили Тебе води й убоялися», 2-ий хор – той же тропар. Канонарх (за Типіконом – диякон) читає голосно стихиру, глас 5-ий: «Руку твою, що доторкнулася...» (три поклони). Після закінчення стихири ієрей або диякон виголошує многоліття. 1-е прохання: «Блаженнішому Владиці...», 2-е прохання: «Всім православним християнам...». На кожне прохання хор співає: «Многії літа» (тричі). Якщо служба відбувається в монастирі, то до двох зазначених прохань додається третя: «Спаси, Христе Боже, преподобного отця нашого ігумена...», в цьому випадку хор починає співати зі слів «Спаси, Христе Боже...», співається цей піснеспів також тричі. Після співу многоліття обидва хори на «Слава: І нині» співають стихиру, глас 5-ий: «Руку твою, що доторкнулася до пречистої глави Владики...». Диякон: «Будьмо уважні». Читець – прокимен, глас 3-ій: «Господь просвічення моє і Спаситель мій, кого убоюся»; стих: «Господь Захисник життя мою, кого устрашуся». Після виконання хором прокимна читаються паремія і Апостол. Диякон: «Премудрість». Читець: «Пророцтва Ісаї читання». Диякон: «Будьмо уважні». Читець читає Паремію (гл. 49). Диякон: «Премудрість». Читець: «До Тита послання святого апостола Павла читання». Диякон: «Будьмо уважні». Читець читає апостол (Тит., Зач. 302). Ієрей: «Мир тобі». Читець: «І духові твоєму». Диякон: «Премудрість, станьмо побожно, вислухаймо святого Євангелія». Ієрей: «Мир всім». Хор: «І духові твоєму». Ієрей: «Від Матфея святого Євангелія читання». Хор: «Слава Тобі, Господи, слава Тобі». Диякон: «Будьмо уважні». Ієрей читає Євангеліє (Мф., Зач. 6). Хор: «Слава Тобі, Господи, слава Тобі». Після прочитання Євангелія ієрей у супроводі диякона вносить Євангеліє у вівтар, попередньо хрестоподібно осінивши ним з амвону народ. Диякон зачиняє царські врата, а завіса залишається відкритою до відпусту зображальних (в деяких храмах завіса закривається і знову відкривається з початком зображальних). Читець – тропар: «Не залиш нас до кінця...», Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Читець або хор: «Амінь», і кондак передсвята, глас 4-ий: «Господи, будучи нині в струменях Йорданських...». Читець: «Господи, помилуй» (40 разів), молитва: «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава: І нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Ієрей: «Боже, ущедри нас і благослови нас...». Читець – «Амінь» і молитву: «Владико Господи, Ісусе Христе...». Після заключної молитви 9-ого часу починається читання зображальних: «Благослови, душе моя, Господа...», «Слава» – «Хвали, душе моя, Господа...», «І нині» – «Єдинородний Сину...», «У царстві Твоїм...», «Слава: І нині» – «Пом’яни нас, Господи...», «Пом’яни нас, Владико...», «Пом’яни нас, Святий...», «Хор Небесний...», «Приступіть до Нього...», «Хор Небесний...», «Слава» – «Хор святих ангелів...», «І нині» – «Полегши, відпусти...», «Отче наш», виголос: «Бо Твоє є Царство...»; хор або читець – кондак передсвята, глас 4-ий: «Господи, будучи нині в струменях Йорданських...», читець: «Господи, помилуй» (40 разів); молитва «Всесвята Тройце...». Диякон: «Премудрість». Хор: «Достойно є», закінчуючи словами «і Матір Бога нашого». Ієрей: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Ієрей: «Слава Тобі, Христе Боже, надіє наша, слава Тобі». Хор: «Слава: І нині», «Господи, помилуй» (тричі), «Благослови». Ієрей творить відпуст (на амвоні, при зачинених царських вратах). За усталеною церковною практикою, відразу після відпусту зображальних звершується Літургія свт. Василія Великого, яка починається великою вечірнею. До того ж, Устав спеціально обумовлює час початку богослужіння «в годину 5-у дня», тобто. За нашим відліком об 11-ій ранку (див. Типікон, 6 січня). Таким чином, на думку Типікону, вечірня з Літургією св. Василія Великого відбувається окремо від послідовності часів навечір’я для того, щоб забезпечити для неї більш урочисте служіння. Відбувається дзвоніння у великий дзвін, і потім у всі дзвони. Перед початком Літургії ієрей з дияконом моляться у вівтарі перед престолом: «Царю Небесний...», «Слава в вишніх Богу...» та інше. Потім диякон, вийшовши на амвон, виголошує: «Благослови, владико». Ієрей – виголос: «Благослови Царство...». Хор: «Амінь». Хор: «Амінь». Предстоятель (за усталеною практикою – читець): «Слава Тобі, Боже наш, слава Тобі», «Царю Небесний...», Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Предстоятель (за усталеною практикою – читець): «Амінь», «Господи, помилуй» (12 разів), «Слава: І нині», «Прийдіть, поклонімось...» і 103-ї псалом. (Священик під час псалма за звичаєм читає світильничні молитви перед царськими вратами). Велика єктенія. Кафизми немає. На «Господи, взиваю» стихири свята, глас 2-ий – 8 (кожна стихира – двічі). «Слава, і нині» – свята, глас той же: «Нахилить Ти голову...» (під час співу стихир священик закінчує проскомидію). Вхід з Євангелієм. «Світло Тихе». Прокимен дня. Читання 13 паремій свята. Після 3-ої паремії, за звичаєм, відкриваються царські врата. Читець виголошує: «Глас п’ятий», і сам співає тропар: «Явився Ти у світ, який сотворив, щоб просвітити тих, що сидять у пітьмі, Людинолюбче, слава Тобі». За Уставом, як тропарі, так і стихи псалмів слід співати. Але зазвичай, за усталеною практикою, співаються тільки останні слова тропаря. Тому виконання цих тропарів зі стихами відбувається в наступному порядку: Читець виголошує тропар: «Явився Ти у світ, який сотворив, щоб просвітити тих, що сидять у пітьмі, Людинолюбче, слава Тобі». Хор співає закінчення: «Людинолюбче, слава Тобі». Читець: «Боже, ущедри нас, і благослови нас; просвіти лице Твоє на нас, і помилуй нас, щоб ми пізнали на землі путь Твою, в усіх народах спасіння Твоє. щоб просвітити тих, що сидять у пітьмі». Хор: «Людинолюбче, слава Тобі». Читець: «Нехай сповідуються Тобі люди, Боже; нехай сповідуються Тобі люди всі; нехай веселяться, і нехай радіють народи, бо Ти судиш людей правдою, і народи на землі настановляєш, щоб просвітити тих, що сидять у пітьмі». Хор: «Людинолюбче, слава Тобі». Читець: «Нехай сповідуються Тобі люди, Боже; нехай сповідуються Тобі люди всі; земля дасть плід свій, благослови нас, Боже, і нехай бояться Тебе всі краї землі, щоб просвітити тих, що сидять у пітьмі». Хор: «Людинолюбче, слава Тобі». Читець: «Слава» – «щоб просвітити тих, що сидять у пітьмі». Хор: «Людинолюбче, слава Тобі». Читець: «І нині» – «щоб просвітити тих, що сидять у пітьмі». Хор: «Людинолюбче, слава Тобі». Читець: «Явився Ти у світ, який сотворив, щоб просвітити тих, що сидять у пітьмі, Людинолюбче, слава Тобі». Зачиняються царські врата. Так само виповнюється тропар після 6-ої паремії. На кліросі співають завершальні його слова: «тільки на сидячих у пітьмі, слава Тобі». Після закінчення паремій відкриваються царські врата. Мала єктенія. Виголос: «Бо Ти святий єси, Боже наш...». Співається Трисвяте. Після Трисвятого відразу диякон: «Будьмо уважні». Ієрей: «Мир усім». Читець: «І духові твоєму». Диякон: «Премудрість». Читець: Прокимен, глас 3-ій: «Господь – Просвічення моє...». Апостол – 1 Кор., Зач. 143. Алилуарій, глас 6-ий: «Вилилося із серця мого...». Євангеліє – Лк., Зач. 9. За Уставом, на Літургії після Євангелія царські врата зачиняються. Потрійна ектенія: «Промовмо всі...», і далі за чином Літургія свт. Василія Великого. Замість «Достойно» – «Тобою радується...». Причасний: «Хваліте Господа з Небес...». Після заамвонної молитви відразу співаються (зазвичай стихирним наспівом) тропарі, глас 8-ий священнослужителі виходять царськими вратами «на джерела» або до сосудів з водою на освячення води поставлених в притворі або у дворі храму співаючи (зазвичай стихирним наспівом) тропарі, глас 8-й: «Голос Господній...», та все інше за чином. Предстоятель (а перед ним свічконосець і диякон з кадилом та свічкою) виносить на голові Святий Хрест і кладе його на прикрашеному аналої біля води. Потім роздає свічки співслужителям і робить звичайне кадіння навколо води, кадить ікони і присутніх. Після закінчення тропарів диякон: «Премудрість», читаються три паремії, Апостол і Євангеліє, виголошується велика єктенія з кадінням і особливими проханнями, під час якої ієрей таємно читає молитву: «Господи Ісусе Христе, Єдинородний Сину...». Якщо освячення води відбувається одним ієреєм (без диякона), він може прочитати таємну молитву під час паремій. Після закінчення єктенії виголосу нема, але безпосередньо після того, як хористи проспівають заключне: «Тобі, Господи», ієрей виголошує: «Великий Ти, Господи...» (тричі) і читає молитву на освячення води. При триразовому проголошенні слів «Ти ж, Людинолюче Царю...» священик кожен раз благословляє воду рукою, не занурюючи руку в воду. Після таємної молитви з схилянням голови і виголосу ієрей хрестоподібно благословляє воду Чесним Хрестом, занурюючи його. При цьому ієрей співає тропар, глас 1-ий: «В Йордані хрестився Ти, Господи...». Тропар співається тричі, і відбуваються три занурення Святого Хреста в воду. За загальноприйнятою практикою, священнослужителі співають тільки початок тропаря: «В Йордані хрестився Ти, Господи», зі слів же: «і Троїчне явилося поклоніння...» продовжують співаки. Після цього предстоятель, тримаючи Хрест в лівій руці, кропить хрестоподібно на чотири сторони (схід, захід, південь і північ). Відразу після окроплення на чотири сторони при співі на «Слава: І нині» святкової стихири, глас 6-ий: «Оспіваймо, вірні...» священнослужителі входять у вівтар. Відпуст короткий святковий: «Христос істиний Бог наш, що від Іоана у Йордані зволив хреститися, заради нашого спасіння, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і Людинолюбець». Після відпусту відбувається славлення свята – посеред церкви ставиться світильник, і біля нього священнослужителі вийшовши із вівтаря співають тропар свята Богоявлення, «Слава: І нині» – кондак свята Богоявлення. Потім співається многоліття: «Блаженнішого Владику...», і всіх присутніх окроплюють свяченою водою. Примітка. На трапезі піст: «І входимо в трапезу, і їмо з оливковою олією, випиваємо ж і вина. А сиру, і подібних до нього страв, і риби не насмілюймось їсти, бо це заборонено Божественними правилами. Так відбувається служба пісного дня, в навечір’я Просвічення» (Типікон, 6 січня). У Хрещенський святвечір церковні правила вказують на найбільш суворе постування (до трапези після вечірні), нагадуючи про стародавній звичай оголошених, що готувалися до прийняття Таїнства Хрещення. В Українській Церкві здавна існує благочестивий звичай постити до пізнього вечора, до з’явлення першої зірки."}]},
{"date":"01-06","weekday":"вівторок","title":"СВЯТЕ БОГОЯВЛЕННЯ. ХРЕЩЕННЯ ГОСПОДА БОГА І СПАСИТЕЛЯ НАШОГО ІСУСА ХРИСТА. Літургія за чином свт. Іоана Золотоустого.","readings":["Ран. – Мк., 2 зач., I, 9 – 11.","Літ. – Тит., 302 зач., II, 11 – 14; III, 4 – 7. Мф., 6 зач., III, 13 – 17.","Під час освячення води – 1 Кор., 143 зач. (від пол.), Х, 1 – 4. Мк., 2 зач., І, 9 – 11."],"notes":"ВСЕНІЧНЕ БДІННЯ на свято Богоявлення складається з великого повечір’я з літією, ранньої та 1-го часу. За Уставом, богослужіння має починатися «о 10-ій годині ночі», тобто, за нашим відліком – о 4 годині ранку (див. Типікон, 6 січня). Перед його початком звершують благовіст і дзвоніння у всі дзвони. Відкриваються завіса і царські врата. Ієрей з дияконом творять початок, як в усі свята з бдінням, тобто спочатку звершують кадіння престолу і всього вівтаря. Диякон зі свічкою виходить на солію і виголошує: «Благослови, владико». Ієрей перед престолом: «Благословенний Бог наш...» (при цьому творить кадилом хрест). Хор: «Амінь». Читець: «Слава Тобі, Боже наш...», «Царю Небесний» та інше, і читає велике повечір’я. Ієрей виходить з вівтаря у супроводі диякона зі свічкою і звершує повне кадіння всього храму, як напочатку всенічної. Після закінчення кадіння царські врата зачиняються. Завіса залишається відкритою. На спів «З нами Бог...», спів тропаря і кондака після 1-го і 2-го Трисвятого, за традицією, відкриваються царські врата. Після 1-го Трисвятого співається тропар свята, глас 1-ий: «В Йордані хрестився Ти, Господи...». Після 2-го Трисвятого співається кондак свята, глас 4-ий: «Явився Ти сьогодні вселенній...». Після «Слава у вишніх Богу...» – вихід на літію. На літії стихири свята, глас 4-ий. «Слава» – свята, глас 8-ий: «Господи, бажаючи виконати все...», «І нині» – свята, глас той самий: «Нині творіння просвічується...». На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава: І нині» – свята, глас 6-ий: «Побачив світильник світлий...». Після Трисвятого – тропар свята, глас 1-ий (тричі).","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава: І нині» – той самий тропар. Кафизми 7-а і 8-а. Малі ектенії. Сідальні свята. Полієлей. Величання свята: «Величаємо Тебе, Життєдавче Христе, що ради нас нині плоттю хрестився від Іоана у водах Йорданських», і вибраний псалом. Сідальний свята після полієлея, глас 4-ий. «Слава: І нині» – той самий сідальний. Степенна – 1-ий антифон 4-го гласу. Прокимен свята, глас 4-й: «Море побачило і розступилося, Йордан повернув назад»; стих: «Чого ти море розступилося? І ти, Йордане, чого повернув назад?» Євангеліє – свята. Після 50-го псалма: «Слава» – свята, глас 2-ий: «Все сьогодні нехай радується, бо Христос явився на Йордані», «І нині» – той самий стих. Стихира свята, глас 6-й: «Бог Слово явився...». Канони: свята два, на 16 (ірмоси 1-го канону: «Глибини відкрив Ти дно...», по двічі, тропарі на 6, і ірмоси 2-го канону: «Проходячи морем...», по двічі, тропарі на 6). Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси обох канонів (після кожної пісні). Після 3-ої пісні – іпакої свята, глас 5-ий (один раз). Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспіви свята. (Звершується звичайне кадіння). 1-ий хор співає приспів 1-го канону: «Величай, душе моя, Чеснішу від горніх воїнств, Діву Пречисту Богородицю», та ірмос 1-го канону: «Не в змозі ніяка людина...». 2-ий хор – те саме. 1-ий хор приспів: «Величай, душе моя, Того, Хто від Предтечі хрещення просить», тропар: «Давиде, прийди Духом...». 2-ий хор приспів: «Величай, душе моя, Того, Хто прийшов на Йордан хреститися», тропар: «Давиде, прийди Духом...». 1-ий хор приспів: «Величай, душе моя, Того, Кого засвідчив глас Отця», тропар: «Ісая взиває: омийтеся...». 2-ий хор приспів: «Величай, душе моя, Єдиного від Тройці, що схилив главу і прийняв хрещення», тропар: «Ісая взиває: омийтеся...». 1-ий хор приспів: «Пророче, прийди до Мене, простягни руку і хрести Мене скоро», тропар: «Зберігаємося, вірні, благодаттю і печаттю...». 2-ий хор приспів: «Пророче, залиш нині, і хрести Мене з Моєї волі, бо Я прийшов виконати всяку правду», тропар: «Зберігаємося, вірні, благодаттю і печаттю...». 1-ий хор співає приспів 2-го канону: «Сьогодні Владика прихиляє главу під руку Предтечі.», та ірмос 2-го канону: «О, вище розуму...». 2-ий хор – те саме. 1-ий хор приспів: «Сьогодні Іоан хрестить Владику в струменях Йорданських», тропар: «Пізнали ми те, що купиною Мойсею було явлене». 2-ий хор – той самий приспів і тропар. 1-ий хор приспів: «Сьогодні Владика водами погрібає людський гріх», тропар: «Пізнали ми те, що купиною Мойсею було явлене». 2-ий хор приспів: «Сьогодні Владика засвідчується з небес як Син улюблений», тропар: «Помазуєш, Царю безначальний...». 1-ий хор приспів (замість «Слави»): «Сьогодні Владика прийшов, щоб освятити водну природу», тропар: «Помазуєш, Царю безначальний...». 2-й хор приспів (замість «І нині»): «Сьогодні Владика приймає хрещення рукою Предтечі.», тропар: «Помазуєш, Царю безначальний...». Потім обидва кліроси разом співають приспів 1-го канону: «Величай, душе моя, Чеснішу...», та ірмос 1-го канону: «Не в змозі ніяка людина...», потім обидва кліроси приспів 2-го канону: «Сьогодні Владика прихиляє главу...», та ірмос 2-го канону: «О, вище розуму...». Після 9-ої пісні «Достойно є...» не співається. Світильний свята. «Слава: І нині» – той самий світильний. На хвалітніх стихири свята, глас 1-ий – 4. «Слава» – свята, глас 6-ий: «Водами Йорданськими...», «І нині» – свята, глас 2-й: «Сьогодні прийшов Христос...». Велике славослів’я. Після Трисвятого – тропар свята, глас 1-ий (один раз). Відпуст святковий: «Христос, істинний Бог наш, що у Йордані зволив хреститися від Іоана, заради нашого спасіння, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята. Примітка. «У цей день Літургія буває рано, для труда невсипущого» (Типікон, 6 січня)."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ святкові антифони. Вхідний (вхідні стих): «Благословенний, хто йде в ім’я Господнє, благословляємо вас з дому Господнього: Бог Господь і явився нам». Після входу – тропар свята. «Слава: І нині» – кондак свята. Замість Трисвятого – «Усі ви, що в Христа хрестилися...». Прокимен, Апостол, алилуарій, Євангеліє і причасний – свята. Задостойник – приспів: «Величай, душе моя, Чеснішу горніх воїнств, Діву Пречисту Богородицю», та ірмос 9-ої пісні: «Не в змозі ніяка людина...» (так співаємо до віддання). Після заамвонної молитви, за звичаєм, – велике освячення води (як в навечір’я). Примітка. Велике освячення води починається після заамвонної молитви співом тропарів, глас 8-ий: «Глас Господній...», та ін. Після закінчення чину водосвяття, при співі на «Слава: І нині» святкової стихири, глас 6-ий: «Оспіваймо, вірні...», священнослужителі входять у вівтар, і закінчується Літургія за звичаєм: «Нехай буде ім’я Господнє благословенне...» (тричі), псалом 33-ий і відпуст. Відпуст короткий святковий (див. у кінці ранньої) зі згадування імені свт. Василія Великого. За традицією, після відпусту Літургії посеред церкви перед іконою свята вийшовши з вівтаря священнослужителі співають тропар свята, «Слава: і нині» – кондак свята і, за звичаєм, величання. Під час цілування Хреста священник всіх окроплює освяченою водою. З 7 по 13 січня – післясвято Богоявлення. 14 січня – віддання свята Богоявлення."}]},
{"date":"01-07","weekday":"середа","title":"Собор Предтечі і Хрестителя Господнього Іоана.","readings":["Як., 50 зач., I, 1 – 18. Мк., 44 зач., X, 11 – 16.","Предтечі: Діян., 42 зач., XIX, 1 – 8. Ін., 3 зач., I, 29 – 34."],"notes":"Служба Собору Предтечі і Хрестителя Господнього Іоана славослівна, звершується разом зі службою післясвята Богоявлення.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: свята, глас 2-ий – 3, і Предтечі, глас 1-ий – 3. «Слава» – Предтечі, глас 6-ий: «У плоті світильник...», «І нині» – свята, глас той самий: «Бог Слово явився...». Вхід. Прокимен великий, глас 7-ий: «Бог наш на небесах і на землі...», зі стихами (за звичаєм). На стиховні стихири свята, глас 4-ий (зі своїми приспівами). «Слава» – Предтечі, глас той самий: «Як Духа ревнитель...», «І нині» – свята, глас той самий: «Прийдіть, уподібнимося...». Після Трисвятого – тропар Предтечі, глас 2-ий. «Слава: І нині» – тропар свята, глас 1-ий. Відпуст святковий (у відкритих царських вратах): «Христос Істинний Бог наш, що в Йордані...» (зі згадуванням Предтечі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар Предтечі, глас 2-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 10-а і 11-а. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмосом на 6 (ірмоси по двічі), свята 2-ий з ірмосом на 4 (ірмоси по двічі) і Предтечі на 4. Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси обох канонів свята. Після 3-ої пісні – кондак та ікос свята, глас 4-ий; сідальний Мінеї, глас 8-ий: «Йордан водами служить...». «Слава: І нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос Предтечі, глас 6-ий. На 9-й пісні «Чеснішу...» не співаємо, але співаємо приспіви свята і Предтечі (див. в Мінеї). (Звершується звичайне кадіння). Після 9-ої пісні «Достойно є...» не співається. Світильний Предтечі. «Слава: і нині» – світильний свята. На хвалітніх стихири свята, глас 1-ий – 4 (див. у день свята Богоявлення). «Слава» – Предтечі, глас 6-ий: «Ти, Хрестителю, як ангел, вийшов із неплідного лона...», «І нині» – свята, глас 2-ий: «Сьогодні прийшов Христос на Йордан...» . Велике славослів’я. Після Трисвятого – тропар Предтечі, глас 2-ий. «Слава: І нині» – тропар свята, глас 1-ий. Відпуст: «Христос Істинний Бог наш, що в Йордані...» (зі згадуванням Предтечі)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар Предтечі. Кондаки свята і Предтечі читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні свята (обох канонів), пісня 3-я – 4 (1-го канону – з ірмосом) і Предтечі, пісня 6-а – 4. На вході – «Прийдіть поклонімось... що в Йордані хрестився...». Після входу – тропар свята, тропар Предтечі. «Слава» – кондак Предтечі, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і Предтечі. Апостол і Євангеліє – дня і Предтечі. Задостойник свята (і до віддання). Відпуст: «Христос Істинний Бог наш, що в Йордані...» (зі згадуванням Предтечі та свт. Іоана Золотоустого)."}]},
{"date":"01-08","weekday":"четвер","title":"Прпп. Георгія Хозевіта (VІІ) та Еміліана, спов. (ІХ). Прп. Домніки (бл. 474). Прп. Григорія, чудотворця Києво-Печерського, в Ближніх печерах (1093). Прп. Григорія, затворника Києво-Печерського, в Дальніх печерах (ХІІІ – ХІV). Сщмч. Картерія, пресвітера Кесарії Каппадокійської (304). Сщмч. Феофіла, диякона, та мч. Елладія (ІV). Мчч. Юліана, Келсія, Антонія, Анастасія, мцц. Василіси і Маріоніли, сімох отроків та 20-ох воїнів (313). Прп. Іллі Єгипетського (ІV). Мч. Або Тбіліського (бл. 790, Груз.).","readings":["Як., 51 зач., I, 19 – 27. Мк., 45 зач., X, 17 – 27."],"notes":"Служба преподобних немає святкового знаку і звершується із службою післясвята Богоявлення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-а. На «Господи, взиваю» стихири на 6: преподобного, глас 4-ий – 3, і преподобної, глас той самий – 3. «Слава: І нині» – свята, глас 1-ий: «Той, Хто покриває небо хмарами...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава: І нині» – свята, глас 2-ий: «На Йорданській річці...». Після Трисвятого – тропар свята, глас 1-ий (один раз). Відпуст: «Христос Істинний Бог наш, що в Йордані...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава: І нині» – той самий тропар. Кафизми 13-а і 14-а. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий «Глибини відкрив Ти дно...» [1] з ірмосом на 6 (ірмоси по двічі), преподобного на 4 і преподобної на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобної). Після 3-ої пісні – кондак преподобного, глас 4-ий; сідальний преподобного, глас 5-ий. «Слава» – сідальний преподобної, глас 4-ий, «І нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава: І нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава: І нині» – свята, глас той самий: «Побачили Тебе води...». Після Трисвятого – тропар свята, глас 1-ий (один раз). Відпуст 1-го часу: «Христос Істинний Бог наш, що в Йордані...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 1-а (обох канонів) – 6 (1-го канону – з ірмосом). На вході – «Прийдіть поклонімось... що в Йордані хрестився...». Після входу – тропарі і кондаки: У храмі Господньому – тропар свята [2]. «Слава» – кондак преподобного, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму; кондак свята. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму; кондак храму. «Слава» – кондак преподобного, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос Істинний Бог наш, що в Йордані...». [1] Два канони свята Богоявлення (в період віддання свята) співаються по черзі з 8 січня: в перший день – перший канон, в другий день – другий і т. д. (див. Типікон, 8 – 13 січня). [2] Тропар рядового святого не співається, оскільки в Мінеї немає особливого тропаря святого."}]},
{"date":"01-09","weekday":"п’ятниця","title":"Мч. Полієвкта (259). Прор. Самея (Х ст. до Р. Х.). Свт. Петра, єп. Севастії Вірменської (ІV). Прп. Євстратія, чудотворця (ІХ). Прп. Іони Київського (1902).","readings":["Як., 52 зач., IІ, 1 – 13. Мк., 46 зач., X, 24 – 32."],"notes":"Служба мч. Полієвкта немає святкового знаку і звершується зі службою післясвята Богоявлення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-а. На «Господи, взиваю» стихири на 6: свята, глас 8-ий – 3, і мученика, глас 1-ий – 3. «Слава» мученика, глас той самий, «І нині» – свята, глас 2-ий: «Нині Творець неба і землі...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава: І нині» – свята, глас 4-ий: «Одягнувся Ти світлом, як ризою...». Після Трисвятого – тропар мученика, глас 4-ий «Слава: І нині» тропар свята, глас 1-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-й (двічі). «Слава» тропар мученика, глас 4-ий, «І нині» – тропар свята. Кафизми 19-а і 20-та. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 2-ий з ірмосом на 8 (ірмоси по двічі) і мученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (мученика). Після 3-ої пісні – кондак та ікос мученика, глас 4-ий; сідальний мученика, глас 5-ий. «Слава: І нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є...» не співається. Світильний мученика. «Слава: І нині» – світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава: І нині» – свята, глас той самий: «Відійшовши від шкідливого земного...». Після Трисвятого – тропар мученика «Слава: І нині» тропар свята, глас 1-ий. Відпуст 1-го часу: «Христос Істинний Бог наш, що в Йордані...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята «Слава» тропар мученика. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 4-а – 6 (з ірмосом). На вході – «Прийдіть поклонімось... що в Йордані хрестився...». Після входу – тропарі і кондаки: У храмі Господньому – тропар свята, тропар мученика. «Слава» – кондак мученика, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму; тропар мученика, кондак свята. «Слава» – кондак мученика, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму; тропар мученика, кондак храму. «Слава» – кондак мученика, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос Істинний Бог наш, що в Йордані...»."}]},
{"date":"01-10","weekday":"субота","title":"Субота після Богоявлення. Свт. Григорія, єп. Ниського (395). Прп. Дометіана, єп. Мелітинського (601). Прп. Маркіана, пресвітера (V). Прп. Макарія. Блж. Феозви, диякониси, сестри свт. Григорія Ниського (385).","readings":["Суботи після Богоявлення: Еф., 233 зач., VI, 10 – 17. Мф., 7 зач., IV, 1 – 11.","Свт.: 1 Кор., 151 зач., XII, 7 – 11. Мф., 34 зач. (від пол.), X, 1 – 8."],"notes":"Служба свт. Григорія Ниського і прп. Дометіана не має святкового знака, звершується разом зі службою післясвята Богоявлення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: святителя, глас 5-ий – 3, і преподобного, глас 1-ий – 3. «Слава» – святителя, глас 4-ий: «Слово твоєї мудрості...», «І нині» – свята, глас той самий: «Тремтіла рука Хрестителева...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава» – святителя, глас 4-ий. «І нині» – свята, глас 4-ий: «Тебе, Який Духом...». Після Трисвятого – тропар святих, глас 4-ий. «Слава: І нині» – тропар свята, глас 1-ий."},{"svc":"ПОВЕЧІР’Ї","text":"НА ПОВЕЧІР’Ї співається канон преподобного Маркіана."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар святих, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 16-а і 17-а. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-й свята з ірмосом на 6 (ірмоси по двічі) і святих на 8. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобного). Після 3-ої пісні – кондак та ікос свята, кондак святителя, глас 2-ий, сідальний святителя, глас 3-ій, «Слава» – сідальний преподобного, глас 1-ий. «І нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос святителя, глас 1-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний святителя. «Слава: І нині» – світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава» – святителя, глас 1-ий. «І нині» – свята, глас той самий. Після Трисвятого – тропар святих, глас 4-ий. «Слава: І нині» – тропар свята, глас 1-ий. Відпуст 1-го часу: «Христос Істинний Бог наш, що в Йордані...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святих. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні на 8: свята, пісня 5-а – з ірмосом на 4 і святителя пісня 6 на 4. На вході – «Прийдіть поклонімось... що в Йордані хрестився...». Після входу – тропарі і кондаки: У храмі Господньому – тропар свята, тропар святих. «Слава» – кондак святителя, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар святих; кондак свята. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар святих; кондак храму. «Слава» – кондак святителя, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і святителя. Апостол і Євангеліє – суботи після Богоявлення та святителя. Задостойник свята. Відпуст: «Христос Істинний Бог наш, що в Йордані...»."}]},
{"date":"01-11","weekday":"неділя","title":"31-ша неділя після П’ятдесятниці, після Богоявлення. Глас 6-й. Прп. Феодосія Великого, засновника спільнотного життя (529). Прп. Феодосія Антіохійського (бл. 412). Єлецької ікони Божої Матері (1060).","glas":6,"readings":["Ран. – Єв. 9-е, Ін., 65 зач., XХ, 19 – 31.","Літ. – неділі після Богоявлення: Еф., 224 зач. (від половини), IV, 7 – 13. Мф., 8 зач., IV, 12 – 17.","Прп.: 2 Кор., 176 зач., IV, 6 – 15. Мф., 43 зач., XI, 27 – 30."],"notes":"Подаємо порядок звершення воскресної служби Октоїха у поєднанні з полієлейною службою преподобного Феодосія Великого та службою післясвята Богоявлення.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж...» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 6-ий – 3, свята, глас 2-ий – 3, і преподобного, глас 5-ий – 4 (перша стихира двічі). «Слава» – преподобного, глас 2-ий: «Преподобний отче...», «І нині» – догматик, глас 6-ий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії преподобного – 3. На літії стихири свята, глас 6-ий (див. стихири на стиховні на вечірні (без приспівів) у службі преподобного Феодосія). «Слава» – преподобного, глас 2-ий: «Чеснот ліствиця...», «І нині» – свята, глас той самий: «Нині Христос прийшов на Йордан...» (див. в службі преподобного Феодосія на хвалітніх ранньої). На стиховні стихири воскресні, глас 6-ий. «Слава» – преподобного, глас 8-ий: «Ченців безліч наставника...», «І нині» – свята, глас той самий: «Ангельські сили вжахнулися...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар свята, глас 1-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 6-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 2-га і 3-тя. Малі ектенії. Сідальні воскресні. Полієлей. Величання преподобного: «Ублажаємо тебе, / преподобний отче наш Феодосію, / і шануємо святу пам’ять твою, / наставнику монахів// і співрозмовнику ангелів» і вибраний псалом. «Ангельський собор...». Іпакої гласу. Сідальний преподобного після полієлея, глас 3-ій: «Стовпом світлоносним явився ти преподобний...» (двічі). «Слава: І нині» – сідальний свята, глас той самий: «Владика днесь...». Степенні і прокимен – гласу. Євангеліє воскресне 9-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний із ірмосом на 4 (ірмос один раз), свята (другий) на 4 і преподобного на 6. Біблійні пісні «Співаймо Господеві...». Катавасія свята Богоявлення: «Глибини відкрив Ти дно...». Після 3-ої пісні – кондак та ікос свята, глас 4-ий; кондак та ікос преподобного, глас 8-ий; сідальний преподобного, глас той самий. «Слава: І нині» – сідальний свята, глас той самий: «Йордан струменями служить...». Після 6-ої пісні – кондак та ікос воскресні, глас 6-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Свят Господь Бог наш», екзапостиларій воскресний 6-ий. «Слава» – світильний преподобного, «І нині» – світильний свята: «Явився Спас...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас, 6-ий – 4 і преподобного, глас 5-ий – 4. «Слава» – стихира євангельска 9-а, «І нині» – «Преблагословенна Богородице...» Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...». На 1-му часі – тропар воскресний. «Слава» – тропар свята. Кондак свята. На 3-му часі – тропар воскресний. «Слава» – тропар преподобного. Кондак воскресний. На 6-му часі – тропар воскресний. «Слава» – тропар свята. Кондак преподобного. На 9-му часі – тропар воскресний. «Слава» – тропар преподобного. Кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4; свята, пісня 6-а – 4 і преподобного, пісня 6-а – 4. На вході – «Прийдіть поклонімось... що воскрес із мертвих...». Після входу – тропарі і кондаки: У храмі Господньому – тропар воскресний, тропар свята, тропар преподобного; кондак воскресний. «Слава» – кондак преподобного, «І нині» – кондак свята. У храмі Богородиці – тропар воскресний, тропар свята, тропар храму, тропар преподобного; кондак воскресний, кондак свята. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар свята, тропар храму, тропар преподобного; кондак воскресний, кондак храму. «Слава» – кондак преподобного, «І нині» – кондак свята. Прокимен і алилуарій – неділі після Богоявлення і преподобного. Апостол і Євангеліє – неділі після Богоявлення і преподобного. Задостойник свята. Причасний – воскресний: «Хваліте Господа з Небес», і преподобного: «В пам’ять вічну...»."}]},
{"date":"01-12","weekday":"понеділок","title":"32-й тиждень після П’ятдесятниці (рядові читання 29-го тижня через Хрещенську відступку). Мц. Тетяни і тих з нею, які в Римі були замучені (226 – 235). Мч. Мертія (284 – 305). Мч. Петра Авесаломіта (309 – 310). Прп. Євпраксії, діви Тавенської (393). Свт. Сави, архієп. Сербського (1237). Ікон Божої Матері, званих «Акафістна» та «Молокоживителька».","readings":["Євр., 308 зач., ІІI, 5 – 11, 17 – 19. Лк., 102 зач., XX, 27 – 44."],"notes":"Служба мц. Тетяни немає святкового знаку і звершується зі службою післясвята Богоявлення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: свята, глас 8-ий – 3, і мучениці, глас 2-ий – 3. «Слава: І нині» – свята, глас 5-ий: «Бачачи Тебе всяке єство...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава: І нині» – свята, глас той же: «Оспіваймо, вірні...». Після Трисвятого – тропар свята, глас 1-ий (один раз). Відпуст: «Христос Істинний Бог наш, що в Йордані...»."},{"svc":"ПОВЕЧІР’Ї","text":"НА ПОВЕЧІР’Ї співається канон Пресвятій Богородиці заради Її чудотворної ікони «Молокоживителька»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-й(двічі). «Слава: І нині» – той же тропар. Кафизми 4-а і 5-а. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмосом на 8 (ірмоси по двічі) і мучениці на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (мучениці). Після 3-ої пісні – кондак мучениці, глас 4-ий; сідальний мучениці, глас той же. «Слава: І нині» – сідальний свята, глас той же: «Світлом, як ризою одягнений...». Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається Повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава: І нині» – свята, глас той же: «О, незбагненне Боже провидіння...». Після Трисвятого – тропар свята, глас 1-ий (один раз). Відпуст 1-го часу: «Христос Істинний Бог наш, що в Йордані...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 7-а – 6 (з ірмосом). На вході – «Прийдіть поклонімось... що в Йордані хрестився...». Після входу – тропарі і кондаки: У храмі Господському – тропар свята. «Слава» – кондак мучениці, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму; кондак свята. «Слава» – кондак мучениці, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму; кондак храму. «Слава» – кондак мучениці, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос Істинний Бог наш, що в Йордані...»."}]},
{"date":"01-13","weekday":"вівторок","title":"Мчч. Єрмила та Стратоніка (бл. 315). Мч. Петра Анійського (309 – 310). Прп. Якова, єп. Низибійського (350).","readings":["Євр., 310 зач., IV, 1 – 13. Лк., 106 зач., XXI, 12 – 19.","Прп.: Рим., 99 зач., VІІІ, 28 – 39. Лк., 24 зач., VI, 17 – 23."],"notes":"Із вівторка (14 січня) на сьогодні переноситься пам’ять преподобних отців, що в Синаї і Раїфі були вбиті. Служба мучеників і преподобних отців немає святкового знаку і звершується разом із службою післясвята Богоявлення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-а. На «Господи, взиваю» стихири на 6: мучеників, глас 4-ий – 3, і преподобних, глас 8-ий – 3. «Слава» – преподобних, глас той самий: «Преподобні отці...», «І нині» – свята, глас той самий: «Господи, бажаючи виконати...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава» – преподобних, глас 8-ий, «І нині» – свята, глас той самий: «Ангельські воїнства...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава» – тропар преподобних, глас той самий, «І нині» – тропар свята, глас 1-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (один раз), тропар мучеників, глас 4-ий (один раз). «Слава» – тропар святого, глас той самий, «І нині» – тропар свята, глас 1-ий. Кафизми 7-а і 8-а. Малі ектенії. Сідальні свята (по двічі). Канони: свята 2-ий з ірмос на 6 (ірмоси по двічі), мучеників на 4 і преподобних на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобних). Після 3-ої пісні – кондак та ікос преподобних, глас 2-ий; сідальний мучеників, глас 1-ий. «Слава» – сідальний преподобних, глас 4-ий, «І нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний преподобних. «Слава: І нині» – світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава» – святих, глас 8-ий, «І нині» – свята, глас той самий: «Нині творіння просвіщається...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава» – тропар преподобних, глас той самий, «І нині» – тропар свята, глас 1-й."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропарі мучеників і преподобних читаються поперемінно. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні свята, пісня 8-ма – 4 (з ірмосом), і преподобних, пісня 6-та – 4. На вході – «Прийдіть... що в Йордані хрестився...». Після входу – тропарі та кондаки: У храмі Господньому – тропар свята, тропар мучеників, тропар преподобних. «Слава» – кондак преподобних, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар мучеників, тропар преподобних; кондак свята. «Слава» – кондак преподобних, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар мучеників, тропар преподобних; кондак храму. «Слава» – кондак преподобних, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і преподобних. Апостол і Євангеліє – дня і преподобних. Задостойник свята. Відпуст: «Христос Істинний Бог наш, що в Йордані...»."}]},
{"date":"01-14","weekday":"середа","title":"Віддання свята Богоявлення. Прпп. отців, які в Синаї й Раїфі були вбиті: Ісаї, Сави, Мойсея і учня його Мойсея, Єремії, Павла, Адама, Сергія, Домна, Прокла, Іпатія, Ісаака, Макарія, Марка, Веніаміна, Євсевія, Іллі та інших із ними (ІV – V). Рівноап. Ніни, просвітительки Грузії (335). Прп. Йосифа Аналітина Раїфського (ІV). Прп. Феодула (V). Прп. Стефана (VІІІ).","readings":["Ран. – Мф., 34 зач. (від половини), X, 1 – 8.","Літ. – Євр., 312 зач., V, 11 – VІ, 8. Лк., 104 зач., XXI, 5 – 7, 10 – 11, 20 – 24.","Рівноап.: 1 Кор., 131 зач., IV, 9 – 16. Мф., 104 зач., XXV, 1 – 13."],"notes":"Звершується служба віддання Богоявлення в поєднанні з полієлейною службою св. рівноап. Ніни, просвітительки Грузії (за Марковою главою Типікону за 25 травня про поєднання служби віддання Вознесіння зі службою Знайдення глави Іоана Предтечі).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 10: свята, глас 2-ий – (див. 6 січня на «Господи, взиваю»; перші дві стихири – двічі) – 6, і рівноап. Ніни, глас 4-ий і глас 8-ий – 4. «Слава» – рівноап. Ніни, глас 2-ий: «Прийдіть, усі вірні...», «І нині» – свята, глас той самий: «Нахилив Ти голову...». Вхід. Прокимен дня. Паремії рівноап. Ніни – 3. На стиховні стихири свята, глас 2-ий (див. 6 січня на стиховні вечірні; зі своїми приспівами). «Слава» – рівноап. Ніни, глас 8-ий: «Чашу благодаті...», «І нині» – свята, глас 6-ий: «Побачив світильник світлий, що від неплідної, Сонце...». Після Трисвятого – тропар рівноап. Ніни, глас 4-ий. «Слава: І нині» – тропар свята, глас 1-ий. Відпуст: «Христос Істинний Бог наш, що в Йордані...» (з поминанням рядових святих дня)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар рівноап. Ніни, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 10-а і 11-а. Малі ектенії. Сідальні свята. Величання рівноап. Ніни: «Величаємо тебе, / свята рівноапостольна Ніно, / бо ти всі краї Іверські світлом Євангелія просвітила, // і до Христа привела» і вибраний псалом: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь». Сідальний рівноап. Ніни, глас 3-ій: (див. Після 1-ої кафизми), інший сідальний рівноап. Ніни, глас 8-ий: (див. Після 1-ої кафизми), інший сідальний рівноап. Ніни, глас той самий: (див. Після 2-ої кафизми). «Слава» – сідальний рівноап. Ніни після полієлея, глас той самий, «І нині» – сідальний свята після полієлея, глас 4-ий: (див. 6 січня). Степенна – 1-ий антифон 4-го гласу. Прокимен рівноап. Ніни, глас 4-ий: «По всій землі розійшлося віщування їх і в кінці вселенної слова їх»; стих: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь». Євангеліє рівноап. Ніни – Мф., зач. 34 (від половини). Після 50-го псалма: «Слава» – «Молитвами святої рівноапостольної Ніни...». Стихира рівноап. Ніни, глас 6-ий. Канони: свята 1-ий з ірмосом на 6 (ірмоси по двічі), рівноап. Ніни на 4 і свята 2-ий на 4. Біблійні пісні «Співаймо Господеві...». Катавасія свята: «Глибини відкрив Ти дно...». Після 3-ої пісні – кондак та ікос свята, глас 4-ий; сідальний рівноап. Ніни, глас 2-ий. «Слава: І нині» – іпакої свята, глас 5-ий. Після 6-ої пісні – кондак та ікос рівноап. Ніни, глас 2-ий. На 9-й пісні «Чеснішу» не співаємо, але співаємо приспіви свята. 1-ий приспів: «Величай, душе моя, чеснішу від небесних воїнств Діву Пречисту Богородицю». (Звершується звичайне кадіння). Після 9-ої пісні «Достойно є» не співається. Світильний рівноап. Ніни. «Слава: І нині» – світильний свята. На хвалітніх стихири на 6: свята, глас 1-ий – 3, і рівноап. Ніни, глас той самий – 3 (перша стихира – двічі). «Слава» – рівноап. Ніни, глас 2-ий: «Нині сили небесні...», «І нині» – свята, глас той самий: «Сьогодні Христос...». Велике славослів’я. Після Трисвятого – тропар рівноап. Ніни, глас 4-ий. «Слава: І нині» – тропар свята, глас 1-ий. Відпуст: «Христос Істинний Бог наш, що в Йордані...» (з поминанням рядових святих дня)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар рівноап. Ніни. Кондаки свята і рівноап. Ніни читаються позмінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні свята (обох канонів), пісня 9-та – 4 (1-го канону – з ірмосом), і рівноап. Ніни, пісня 3-тя – 4. На вході – «Прийдіть поклонімось... що в Йордані хрестився...». Після входу – тропар свята, тропар рівноап. Ніни. «Слава» – кондак рівноап. Ніни, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і рівноап. Ніни. Апостол і Євангеліє – дня і рівноап. Ніни. Задостойник свята. Відпуст: «Христос істинний Бог наш, що в Йордані...» (з поминанням рядових святих дня)."}]},
{"date":"01-15","weekday":"четвер","title":"Прп. Павла Фівейського (341) та Іоана Кущника (V). Прмч. Пансофія (249 – 251). Прпп. Прохора (Х) і Гавриїла (ХІ, Серб.).","readings":["Євр., 315 зач., VІІ, 1 – 6. Лк., 107 зач., XXI, 28 – 33.","Прпп.: Гал., 213 зач., V, 22 – VI, 2. Мф., 43 зач., XI, 27 – 30."],"notes":"З цього дня до передсвята Стрітення Господнього співається Октоїх. З цього дня і до Стрітення на святковій ранній катавасія «Сушу в глибині землі...». Служба прпп. Павла Фівейського та Іоана Кущника шестирична, звершується разом зі службою Октоїха. Примітка. Починаючи з 15 січня по неділях співається полієлей, до Неділі сиропусної включно (див. Типікон, 21 вересня, 1-е «див») – крім Неділі про митаря і фарисея, коли, за Уставом, співаються непорочні (див. Типікон, гл. 49). У період від віддання Богоявлення (з 15 січня) до суботи перед Неділею про блудного сина на седмичній ранній читаються три кафизми, а на вечірні – 18-та. А в п’ятницю, суботу та неділю в цей період на ранній читається дві кафизми. З 15 січня і до віддання свята Стрітення (якщо на ранній співається велике славослів’я) – катавасія Стрітення: «Сушу в глибині землі сонце осяяло колись...» Крім того, починаючи з цього дня, береться канон молебний до Пресвятої Богородиці (з Октоїха) на повечір’ї (див. Типікон, 15 січня, 2-е «див»).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: прп. Павла, глас 1-ий – 3, і прп. Іоана, глас 2-ий – 3. «Слава» – прп. Іоана, глас той самий: «Зрікшись світу і сущого у світі...», «І нині» – Богородичний за гласом «Слави», від менших: «Як плодовите оливкове дерево...» Богородичні додатки розподілені за гласами. У свою чергу, Богородичні кожного гласу розподілені по днях седмиці, а серед Богородичних дня розрізняються піснеспіви ранньої та вечірні. Такий порядок допомагає швидко знайти Богородичний потрібного гласу для конкретного дня седмиці і для конкретної служби добового кола в певний день (сама назва розділу показує, що Богородичні мають бути обрані за гласом «Слави»; йдеться про це і в Типіконі, див. Гл. 48, Місяцеслов, 2 вересня). Таким чином, після піснеспівів Мінеї на «Славу», на «І нині» співається Богородичний з додаткової частини Мінеї (надруковані в брошурі Всенічна для хору Видавничого відділу ПЦУ); якщо в Мінеї немає піснеспівів на «Славу», то співається: «Слава: І нині» – Богородичний, надрукований в Мінеї на ряду. У середу і п’ятницю на «І нині» або на «Слава: І нині» співається Хрестобогородичний Мінеї, поміщений на ряду. Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 6-ий. «Слава» – прп. Павла, глас 6-ий: «Преподобний отче...», «І нині» – Богородичний за гласом «Слави», від менших: «Око серця мого...». Після Трисвятого – тропар святих, глас 4-ий. «Слава: І нині» – Богородичний за гласом «Слави», від менших: «Слово Отче, Христа Бога нашого...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святих, глас 4-ий (двічі). «Слава: І нині» – Богородичний за гласом «Слави», від менших: «Слово Отче, Христа Бога нашого...». Кафизми 13-а, 14-а і 15-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Примітка. Якщо у понеділок, вівторок, середу і п’ятницю припаде пам’ять шестеричного або славослівного святого з 1-го канону Октоїха пропускаються два тропаря, що мають напис «мученичні»; таким чином, 1-ий канон Октоїха співається з ірмосом на 4 (ірмоси один раз, тропарі з Богородичним на 3), 2-ий канон Октоїха на 4 і святого на 6 (див. Типікон, гл. 11). Канони: Октоїха 1-ий з ірмосом на 6, прп. Павла на 4 і прп. Іоана на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси останнього канону Мінеї. Після 3-ої пісні – кондак прп. Павла, глас 3-ій; сідальний прп. Павла, глас 1-ий. «Слава» – сідальний прп. Іоана, глас 3-ій, «І нині» – Богородичний Мінеї. Після 6-ої пісні – кондак та ікос прп. Іоана, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співаємо «Достойно є...». Екзапостиларій Октоїха. «Слава» – світильний прп. Іоана, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири преподобного, глас 4-ий – 4 (перша стихира – двічі). «Слава» – преподобного, глас 2-ий: «Зрікшись світу і сущого у світі...», «І нині» – Богородичний, за гласом «Слави», від менших: «Все уповання моє на Тебе покладаю...». «Тобі слава належить» не читається, але одразу «Слава Тобі, що показав нам світло» і читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 6-ий. «Слава» – прп. Павла, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Вирви мене, Владичице...». Після Трисвятого – тропар святого, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря: «Богородице, Тивища від усіх творінь...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар святого. Кондаки прп. Павла і прп. Іоана читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. На вході – «Прийдіть поклонімось... у святих Дивний Ти...» (в седмичні і суботні дні). Примітка. У недільні дні на вході співається: «Прийдіть поклонімось... що воскрес із мертвих...». Після вході – тропарі та кондаки: У храмі Господньому – тропарі дня (апостолів та свт. Миколая), тропар преподобних, кондаки дня (апостолів та свт. Миколая), кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі Богородиці – тропарі дня (апостолів та свт. Миколая), тропар храму, тропар преподобних; кондаки дня (апостолів та свт. Миколая), кондак прп. Павла, кондак прп. Іоана. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропарі дня (апостолів та свт. Миколая), тропар храму, тропар преподобних; кондаки дня (апостолів та свт. Миколая), кондак прп. Павла, кондак прп. Іоана. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобних. Апостол і Євангеліє – дня і преподобних."}]},
{"date":"01-16","weekday":"п’ятниця","title":"Поклоніння оковам ап. Петра. Мчч. Спевсипа, Єлевсипа, Малевсипа і бабці їхньої Леоніли, і з ними Неона, Турвона та Іовили (161 – 180). Мч. Данакта, читця (ІІ).","readings":["Євр., 317 зач., VІІ, 18 – 25. Лк., 108 зач., XXI, 37 – XXII, 8.","Ап.: Діян., 29 зач., XII, 1 – 11. Ін., 67 зач., XXI, 15 – 25."],"notes":"Звершується шестерична служба поклоніння оковам апостола Петра разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 18-та. На «Господи, взиваю» стихири на 6: апостола, глас 4-ий – 6 «Слава» – апостола, глас 6-ий: «Нині Петро, основа Церкви...», «І нині» – Хрестобогородичний Мінеї: «Бачачи наше Життя...» Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 6-ий. «Слава» – апостола, глас 6-ий: «Знову нас теплий предстоятель скликає...», «І нині» – Хрестобогородичний Мінеї: «Бачачи розіп’ятого Тебе, Христе...» Після Трисвятого – тропар апостола, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» тропар апостола, глас 4-ий: «Рима не залишивши...» (двічі). «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших: «Діво Пренепорочна...». Кафізми 19-а і 20-а. Малих ектеній немає. Сідальні Октоїха. 50-ий псалом. Канони: Октоїха 1-ий і 2-ий з ірмосом на 8 і апостола на 6. Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси канону апостола. Після 3-ої пісні – кондак апостола, глас 2-ий, сідальний апостола, глас 4-ий (двічі). «Слава: І нині» – Хестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 2-й. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співаємо «Достойно є...». Екзапостиларій Октоїха. «Слава» – світильний апостола, «І нині» – Хрестобогородичний Октоїха. Читається повсякденне славослів’я. Стихири на стиховні Октоїха, глас 6-ий «Слава» – апостола, глас 4-ий: «Трикратним запитанням...», «І нині» – Хрестобогородичний за гласом «Слави», від менших: «Коли побачила Тебе розіп’ятого...». Після трисвятого – тропар апостола, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостола."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні канону апостола пісня 3-тя і 6-та. Після входу – тропарі та кондаки: У Господньому храмі – тропар дня «Спаси, Господи...», тропар апостола, кондак апостола. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар апостола; кондак дня, кондак апостола. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар апостола; кондак дня, кондак храму, кондак апостола. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня та апостолу. Апостол і Євангеліє – дня та апостола."}]},
{"date":"01-17","weekday":"субота","title":"Прп. Антонія Великого (356).","readings":["Ран. – Мф., 43 зач., XI, 27 – 30.","Літ. – Прп.: Євр., 335 зач., XIII, 17 – 21. Лк., 24 зач., VI, 17 – 23.","Ряд: Еф., 220 зач., ІІ, 11 – 13. Лк., 72 зач., XIII, 18 – 29."],"notes":"Звершується полієлейна служба прп. Антонія Великого.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири преподобного, глас 4-ий – 8 (дві перші стихири – тричі, третя стихира – двічі). «Слава» – преподобного, глас 6-ий: «Те, що за образом зберіг...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить, Пресвята Діво...». Вхід. Прокимен дня. Паремії преподобного – 3. На стиховні стихири преподобного, глас 5-ий (зі своїми приспівами). «Слава» – преподобного, глас 8-ий: «Ченців безліч...», «І нині» – Богородичний воскресний, глас той самий: «Неневісна Діво, що невимовно зачала Бога тілом...». Після Трисвятого – тропар святого, глас 4-ий. «Слава: І нині» – Богородичний воскресний, глас 6-ий: «Благословенною назвавши Свою Матір...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 4-ий (двічі). «Слава: І нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафізми 16-а і 17-а. Малі ектенії. Сідальні преподобного (двічі). Полієлей. Величання преподобного: «Ублажаємо тебе, / преподобний отче наш Антонію, / і шануємо святу пам’ять твою, / наставнику монахів/ і співрозмовнику ангелів» і вибраний псалом. Сідальний преподобного після полієлея, глас 8-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен преподобного, глас 4-ий: «Чесна перед Господом смерть преподобних Його»; стих: «Що віддам Господеві за все, що Він воздав мені?». Євангеліє святого – Мф., зач. 43. Після 50-го псалма: «Слава» – «Молитвами преподобного Антонія...». Стихира преподобного, глас 6-ий: «Преподобний отче...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і преподобного на 8. Примітка. У святих, що мають полієлей, канон Богородиці іноді знаходиться в Мінеї на ряду, але іноді на ряду його немає. У такому випадку він береться з Часослова (глас 8-ий: «Воду пройшовши...»). Біблійні пісні «Співаймо Господеві...». Катавасія «Сушу в глибині землі сонце осяяло колись...». Після 3-ої пісні – сідальний преподобного, глас 8-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є...» не співається. Світильний преподобного (двічі). «Слава: І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири преподобного, глас 8-ий – 4 (перша стихира – двічі). «Слава» – преподобного, глас той самий, «І нині» – Богородичний, глас той самий: «Владичице, прийми...». Велике славослів’я. Після Трисвятого – тропар святого, глас 4-ий. «Слава: І нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні преподобного, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар храму, тропар святого; кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – преподобного та дня. Апостол і Євангеліє – преподобного і рядовий."}]},
{"date":"01-18","weekday":"неділя","title":"32-га неділя після П’ятдесятниці. Глас 7-й. Свтт. Афанасія (373) та Кирила (444), архієпп. Олександрійських. Прп. Маркіана Кирського (бл. 388).","glas":7,"readings":["Ран. – Єв. 10-е, Ін., 66 зач., XXI, 1 – 14.","Літ. – Кол. 257 зач.; ІІІ, 4 – 11. Лк., 85 зач., XVІІ, 12 – 19 (неділі 29-ої).","Свтт.: Євр., 334 зач., XIII, 7 – 16. Мф., 11 зач., V, 14 – 19."],"notes":"Служба свт. Афанасія та Кирила, архієпископів Олександрійських, шестерична, звершується разом з воскресною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж...» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 7-ий – 4, свт. Афанасія, глас 4-ий – 3 і свт. Кирила, глас той же – 3. «Слава» – свт. Афанасія, глас 6-ий: «Христового ієрарха, Афанасія...», «І нині» – догматик, глас 7-ий: «Матір’ю надприродно стала Ти...». Вхід. Прокимен дня. На літії стихири храму. На стиховні стихири воскресні, глас 7-ий. «Слава» – свт. Афанасія, глас 3-ій: «Знову нам золототекучий Ніл...», «І нині» – Богородичний воскресний за гласом «Слави»: «Безсіменно від Божественного Духа...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 7-ий (двічі). «Слава» – тропар святих, глас 4-ий, «І нині» – Богородичний воскресний за гласом «Слави»: «Від початку віку...». Кафизми 2-а і 3-я. Малі єктенії. Сідальні воскресні. Полієлей. «Ангельський собор...». Іпакої, сідальні, степенні і прокимен гласу. Євангеліє воскресне 10-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний гласу з ірмосом на 4 (ірмоси раз), Богородиці на 2, свт. Афанасія на 4 і свт. Кирила на 4. Біблійні пісні: «Співаймо Господеві...». Катавасія: «Сушу в глибині землі...». Після 3-ої пісні – кондак і ікос свт. Афанасія, глас 2-ий, кондак святителів, глас 4-ий; сідальний свт. Афанасія, глас 3-ій. «Слава» – сідальний свт. Кирила, глас той самий, «І нині» – Богородичний Мінеї. Після 6-й пісні – кондак та ікос воскресні, глас 7-ий. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 10-ий. «Слава:» – Світильний святих, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 7-ий на 8. «Слава» – стихира євангельська 10-а, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «В день спасіння світу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар святителів. Кондак тільки воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4, свт. Афанасія, пісня – 3-тя – 4 і свт. Кирила, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар воскресний, тропар святителів; кондак свт. Афанасія. «Слава» – кондак святителів, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар святителів; кондак воскресний; кондак свт. Афанасія. «Слава» – кондак святителів, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар святителів; кондак воскресний, кондак храму; кондак свт. Афанасія. «Слава» – кондак святителів, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні та святителів. Апостол і Євангеліє – дня і святителів."}]},
{"date":"01-19","weekday":"понеділок","title":"33-й тиждень після П’ятдесятниці (рядові читання 32-го тижня через Хрещенську відступку). Прп. Макарія Великого, Єгипетського (390 – 391). Свт. Марка, архієп. Ефеського (1457). Прп. Макарія, посника Києво-Печерського, в Ближніх печерах (ХІІ). Прп. Макарія, диякона Києво-Печерського, в Дальніх печерах (ХІV). Мц. Євфрасії, діви (303). Прп. Макарія Олександрійського (394 – 395). Свт. Арсенія, архієп. Керкирського (VІІІ). Прп. Антонія, стовпника, Марткобського (VІ, Груз.). Прп. Лаврентія Чернігівського (1950).","readings":["Ран. – Лк., 24 зач., VI, 17 – 23.","Літ. – Як., 53 зач., II, 14 – 26. Мк., 48 зач., X, 46 – 52.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Мф., 43 зач., XI, 27 – 30."],"notes":"Звершується полієлейна служба прп. Макарія Великого.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири преподобного, глас 4-ий – 8 (перші дві стихири по тричі, а третя – двічі). «Слава» – преподобного, глас 8-ий: «Веселися, Єгипте...», «І нині» – Богородичний воскресний, глас той самий: «Цар Небесний...». Вхід. Прокимен дня. Паремії преподобного – 3. На стиховні стихири преподобного, глас 1-ий (зі своїми приспівами). «Слава» – преподобного, глас 6-ий: «Преподобний отче, по всій землі...», «І нині» – Богородичний воскресний за гласом «Слави»: «Творець і Визволитель...». Після Трисвятого – тропар преподобного, глас 4-ий. «Слава: І нині» – Богородичний воскресний, глас 4-ий: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святого, глас 4-ий (двічі). «Слава: І нині» – Богородичний воскресний, глас 4-ий: «Від початку віку утаємнене...». Кафизми 4-а і 5-а. Малі ектенії. Сідальні преподобного. Полієлей. Величання преподобного і вибраний псалом. Сідальний преподобного після полієлея, глас 4-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен преподобного, глас 4-ий: «Чесна перед Господом...». Євангеліє – преподобного. Після 50-го псалма: «Слава» – «Молитвами преподобного отця нашого Макарія...». Стихира преподобного, глас 6-ий: «По всій землі розійшлося віщування про твої подвиги...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і преподобного на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Сушу в глибині землі...». Після 3-ої пісні – сідальний преподобного, глас 1-ий. «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 1-ий. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний преподобного. «Слава: І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири преподобного, глас 6-ий – 4. «Слава» – преподобного, глас 4-ий: «Засяяли твої добрі діла...», «І нині» – Богородичний, глас той самий: «Богородице, Царице всіх...». Велике славослів’я. Після Трисвятого – тропар преподобного, глас 4-ий. «Слава: І нині» – Богородичний воскресний, глас 4-ий: «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні преподобного, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар храму, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"01-20","weekday":"вівторок","title":"Прп. Євфимія Великого (473). Мчч. Інни, Пінни і Римми (І – ІІ). Прпп. Євфимія схимника (ХІV) і Лаврентія затворника (ХІІІ – ХІV), Києво-Печерських, в Дальніх печерах. Мчч. Васса, Євсевія, Євтихія і Василіда (303).","readings":["Як., 54 зач., III, 1 – 10. Мк., 50 зач., XI, 11 – 23.","Прп.: Євр., 335 зач., XIII, 17 – 21. Лк., 24 зач., VI, 17 – 23."],"notes":"Служба прп. Євфимія Великого шестерична і звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-а (яка не була прочитана на ранній понеділка). На «Господи, взиваю» стихири преподобного, глас 1-ий і глас 4-ий – 6. «Слава» – преподобного, глас 8-ий: «Присвячений був ти Богу...», «І нині» – Богородичний за гласом «Слави», від менших: «Радуйся, вселенної похвало...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава» – преподобного, глас той самий: «Преподобний отче...», «І нині» – Богородичний за гласом «Слави», від менших: «Радуйся, сонця духовного і невимовного Владичице...» Після Трисвятого: – тропар святого, глас 4-ий. «Слава: І нині» – Богородичний за гласом «Слави», від менших: «До Богородиці щиро нині звернімося...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святого, глас 4-ий (двічі). «Слава: І нині» – Богородичний за гласом «Слави», від менших: «До Богородиці щиро нині звернімося...». Кафизми 7-а, 8-а і 9-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий на 6 (з ірмосом) і преподобного (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої та 9-ої пісень – ірмоси канону преподобного. Після 3-ої пісні – сідальний преподобного, глас 8-ий. «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 8-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» співається. Екзапостиларій Октоїха. «Слава» – світильний преподобного, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякленне славослів’я. Стихири на стиховні Октоїха, глас 7-ий. «Слава: І нині» Богородичний Октоїха. Після Трисвятого – тропар святого, глас 4-ий. «Слава: І нині» – Богородичний за гласом «Слави», від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар преподобного; кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар преподобного; кондак дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"01-21","weekday":"середа","title":"Прп. Максима Сповідника (662). Мч. Неофіта (304). Мчч. Євгенія, Кандида, Валеріана й Акили (ІІІ). Прп. Максима Грека (1556). Мц. Агнії, діви (бл. 304). Мч. Анастасія (662). Ктиторської (ІV) та названої «Відрада» або «Втіха» (807), Ватопедських ікон Божої Матері.","readings":["Як., 55 зач., III, 11 – IV, 6. Мк., 51 зач., XI, 23 – 26.","Прп.: Євр., 330 зач., XI, 33 – XII, 2. Лк., 64 зач., XIІ, 8 – 12."],"notes":"Служба прп. Максима Сповідника, шестирична, і мч. Неофіта, без святкового знаку, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: преподобного, глас 4-ий – 3 і мученика, глас 8-ий – 3. «Слава» – преподобного, глас 6-й: «Преподобний отче...», «І нині» – Хрестобогородичний Мінеї: «Агниця нескверна і непорочна...». Входу немає. Прокимен дня. Стихири на стиховні Октоїха, глас 7-ий. «Слава» – преподобного, глас 8-ий: «Ченців безліч наставника тебе шануємо...»; «І нині» – Хрестобогородичний Мінеї: «Що це за видіння, яке бачиться...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава» – тропар мученика, глас 4-ий; «І нині» – Хрестобогородичний за гласом «Слави», від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 8-ий (двічі). «Слава» – тропапр мученика, глас 4-ий; Хрестобогородичний за гласом «Слави», від менших: «Діво Пренепорочна...». Кафізми 10-а, 11-а і 12-а. Малих ектеній немає. Сідальні Октоїха. Канони: Октоїха 1-ий на 4 (з ірмосом), преподобного на 6 і мученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої та 9-ої пісень – ірмос канону мученика. Після 3-ої пісні – інший кондак преподобного, глас 8-ий; сідальний преподобного, глас 5-ий. «Слава» – сідальний мученика, глас 4-ий, «І нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 6-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» співається. Екзапостиларій Октоїха. «Слава» – світильний преподобного, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякленне славослів’я. Стихири на стиховні Октоїха, глас 5-ий. «Слава: І нині» – Хрестобогородичний Октоїха. Після Трисвятого – тропар святого, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобному. «Слава» – тропар мученику. Кондак преподобному."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі та кондаки: У Господньому храмі – тропар дня «Спаси, Господи...», тропар преподобного, тропар мученика, кондак преподобного, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар преподобного, тропар мученика; кондак дня, кондак преподобного, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар преподобного, тропар мученика; кондак дня, кондак храму, кондак преподобного, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"01-22","weekday":"четвер","title":"Ап. Тимофія (бл. 96). Прмч. Анастасія Перського (628). Прмч. Анастасія, дияк. Києво-Печерського, в Ближніх печерах (ХІІ). Сщмчч. Мануїла, Георгія, Петра, Леонтія, єпископів, Сионія, Гавриїла, Іоана, Леонта, Парода, пресвітерів, та інших 377 мучеників (бл. 817).","readings":["Як., 56 зач., IV, 7 – V, 9. Мк., 52 зач., XI, 27 – 33.","Ап.: 2 Тим., 290 зач. (від половини), I, 3 – 9. Лк., 50 зач., X, 1 – 15."],"notes":"Служба ап. Тимофія славослівна, звершується разом із службою прмч. Анастасія, без святкового знаку, та службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: апостола, глас 1-ий – 3, і преподобномученика, глас той самий – 3. «Слава» – апостола, глас 8-ий: «Богом наперед визначений...», «І нині» – догматик, глас 8-ий: «Цар Небесний...». Входу немає. Прокимен дня. На стиховні стихири апостола (зі своїми стихами, див. Загальна Мінея), глас 4-ий. «Слава» – апостола, глас 1-ий: «Світильника вірних і апостола...» (див. у Мінеї на січень), «І нині» – Богородичний, за гласом «Слави»: «Радуйся, радосте прадідів...». Після Трисвятого – тропар апостола, глас 4-ий. «Слава» – тропар преподобномученика, глас той самий, «І нині» – Богородичний воскресний: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 4-ий (двічі). «Слава» – тропар преподобномученика, глас той самий, «І нині» – Богородичний воскресний: «Від початку віку...». Кафізми 13-а і 14-а. Малі ектенії. Сідальні апостола (із Загальної Мінеї). Псалом 50-ий. Канони: Октоїха 1-ий на 4, апостола на 6 і преподобномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія: «Сущу в глибині землі...». Після 3-ої пісні – сідальний апостола, глас 4-ий. «Слава» – сідальний преподобномученика, глас той самий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос святих, глас 1-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні не співається «Достойно є...». Світильний святих. «Слава: І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостола (із Загальної Мінеї), глас 4-ий – 4 (перша стихири – двічі). «Слава» – апостола, глас 8-ий: «Покинувши все земне...», «І нині» – Богородичний: «Вирви мене, Владичице, із рук змія...». Велике славослів’я. Після Трисвятого – тропар апостола, глас 4-й. «Слава» – тропар преподобномученика, глас той самий, «І нині» – Богородичний воскресний: «Від початку віку...». Ектенії та відпуст."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар апостола. «Слава» – тропар преподобномученика. Кондак святих."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Після входу – тропарі та кондаки: У храмі Господньому і Богородиці – тропар храму, тропар апостола, тропар преподобномученика. «Слава» – кондак святих, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостола, тропар преподобномученика; кондак храму. «Слава» – кондак святих, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і апостола. Апостол і Євангеліє – дня і апостола."}]},
{"date":"01-23","weekday":"п’ятниця","title":"Сщмч. Климента, єп. Анкирського, і мч. Агафангела (312). Прп. Мавсими Сирійця (ІV). Прп. Самана, мовчальника (бл. 400). Свт. Павліна Милостивого, єп. Ноланського (431). Пам’ять VІ Вселенського собору (680 – 681).","readings":["1 Пет., 58 зач., I, 1 – 2, 10 – 12; II, 6 – 10. Мк., 53 зач., XII, 1 – 12."],"notes":"Служба сщмч. Климента та мч. Агафангела не має святкового знака та звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-а (яка не була прочитана на ранній четверга). На «Господи взиваю» стихири на 6: священномученика, глас 1-ий – 3 і мученика, 2-ий – 3. «Слава» – священномученика, глас 8-ий: «Чотири рази переходив...», «І нині» – Хрестобогородичний Мінеї: «Не можу терпіти, Сину...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава» – мученика, глас 1-ий, «І нині» – Хрестобогородичний Мінеї: «Стоячи біля Хреста Сина Твого...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-ий (двічі). «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших: «Діво Пренепорочна...». Кафизми 19-а і 20-а. Малих ектеній немає. Сідальні Октоїха. 50-ий псалом. Канони: Октоїха 1-ий на 6, 2-ий на 4 і священномученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону священномученика. Після 3-ої пісні – кондак священномученика, глас 4-ий, сідальний священномученика, глас 4-ий «Слава: І нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос священномученика, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співаємо «Достойно є...». Екзапостиларій Октоїха. «Слава» – світильний священномученика, «І нині» – Хрестобогородичний Октоїха. Читається повсякденне славослів’я. Стихири на стиховні Октоїха, глас 7-ий «Слава: І нині» – Хрестобогородичний Октоїха. Після Трисвятого – тропар священномученика, глас 4-ий. «Слава: І нині» – Хрестобогородичний від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі та кондаки: У Господньому храмі – тропар дня «Спаси, Господи...», тропар священномученика, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар священномученика; кондак дня, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар священномученика; кондак дня, кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"01-24","weekday":"субота","title":"Прп. Ксенії Римлянки, дияконіси (V). Мчч. Вавили Сицилійського та учнів його Тимофія й Агапія (ІІІ). Прп. Македонія, сирійського пустельника (бл. 420).","readings":["1 Сол., 273 зач., V, 14 – 23. Лк., 84 зач., XVII, 3 – 10."],"notes":"Служба прп. Ксенії не має святкового знака, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири святої, глас 8-ий – 6 (кожна стихира по двічі). «Слава: І нині» – Богородичний воскресний, глас 7-ий: «Матір’ю надприродно стала Ти...». Входу немає. Прокимен дня. На стиховні стихири Октоїха (мученичі з числа стихир на «Господи, взиваю»), глас 5-ий. «Слава: І нині» – Богородичний Октоїха, глас той самий: «Ти єдина прийняла». Після Трисвятого – тропар прп. Ксенії, глас 8-ий. «Слава: І нині» – Богородичний воскресний, глас 7-ий: «Як скарб нашого воскресіння...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар прп. Ксенії, глас 8-ий (двічі). «Слава: І нині» – Богородичний воскресний за гласом тропаря: «Ти, що заради нас народився від Діви...». Кафізми 16-а і 17-та. Малі ектенії. Сідальні Октоїха. Псалом 50-ий. Канони: У храмі Господському та Богородиці: храму (ірмос двічі) на 6, прп. Ксенії на 4 і Октоїха (мученичий) на 4. У храмі святого: прп. Ксенії (ірмос двічі) на 6, храму на 4 і Октоїха (мученичий) на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичого канону Октоїха. Після 3-ої пісні – сідальний прп. Ксенії, глас 8-ий. «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак глас 2-ий та інший кондак прп. Ксенії, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є...». Екзапостиларій Октоїха. «Слава: І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий (мученичі з числа стихир на хвалітніх). «Слава: І нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар прп. Ксенії, глас 8-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Діво Пречиста, спаси нас молитвами Твоїми...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святої."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6. Після входу – тропарі і кондаки: У храмі Господньому та Богородиці – тропар храму, тропар дня «Апостоли, мученики...», тропар святої, кондак храму, кондак святої. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». У храмі святого – тропар дня «Апостоли, мученики...», тропар святої, кондак святої. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"01-25","weekday":"неділя","title":"33-тя неділя після П’ятдесятниці. Глас 8-й. Свт. Григорія Богослова, архієп. Константинопольського (389). Мц. Філіцати та синів її мчч. Януарія, Фелікса, Филипа, Сильвана, Олександра, Віталія і Марціала (164). Прп. Поплія Сирійського (380). Прп. Мара, співця (бл. 430). Ікони Божої Матері, званої «Утамуй мої печалі».","glas":8,"readings":["Ран. – Єв. 11-е, Ін., 67 зач., XXI, 15 – 25.","Літ. – 1 Тим., 285 зач. (від половини), IV, 9 – 15. Лк., 94 зач., XIX, 1 – 10 (про Закхея).","Свт.: 1 Кор., 151 зач., XII, 7 – 11. Ін., 36 зач., X, 9 – 16."],"notes":"Звершується воскресна служба Октоїха у поєднанні з полієлейною службою свт. Григорія Богослова.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блаженний муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні глас 8-ий – 4 і святителя, глас 1-й і глас 2-й – 6. «Слава» – святителя, глас 8-й: «Живий твій язик до повчання...», «І нині» – догматик, глас 8-ий: «Цар Небесний...». Вхід. Прокимен дня. Паремії святителя – 3. На літії стихира храму та святителя. На стиховні стихири воскресні, глас 8-ий. «Слава» – святителя, глас 8-ий: «Серця вірних...», «І нині» – Богородичний воскресний, глас той самий: «Безневісна Діво...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 8-ий (двічі). «Слава» – тропар святителя, глас 1-ий, «І нині» – Богородичний воскресний, глас той самий: «Коли Гавриїл звістив Тобі...». Кафізми 2-а та 3-я. Малі єктенії. Сідальні воскресні. Полієлей. Величення святителя та вибраний псалом. «Ангельський собор...». Іпакої, сідальні, степенні і прокимен гласу. Євангеліє воскресне 11-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний на 4, Хрестовоскресний на 2, Богородиці на 2 і святителя на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Сушу в глибині землі сонце осяяло колись...». Після 3-ої пісні – кондак та ікос святителя, глас 3-ій; сідальний святителя, глас 8-й. «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресний, глас 8-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 11-ий. «Слава:» – Світильний святителя, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» та хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 8-ий – 4 і святителя, глас 4-ий – 4. «Слава» – рання євангельська стихира 11-та, «І нині» – «Преблагословення єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробі...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний і святителя; кондаки воскресний і святителя читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і святителя пісня 3-я – 4. Після входу – тропарі та кондаки: У храмі Господському – тропар воскресний, тропар свчятителя. «Слава» – кондак святителю, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар святителя; кондак воскресний. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар святителя; кондак воскресний, кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресний і святителя. Апостол та Євангеліє – дня і святителя."}]},
{"date":"01-26","weekday":"понеділок","title":"34-й тиждень після П’ятдесятниці. Прпп. Ксенофонта, дружини його Марії та синів їхніх Аркадія та Іоана (V – VІ). Мчч. Ананії, пресвітера, Петра, сторожа в’язниці, а з ними сімох воїнів (295). Прп. Симеона Древнього, пустельника (бл. 390). Перенесення мощів прп. Федора, ігумена Студійського (845). Свт. Йосифа, архієп. Солунського (830). Блгв. Давида ІІІ Відновителя, царя Іверії та Абхазії (1125, Груз.).","readings":["1 Пет., 59 зач., II, 21 – III, 9. Мк., 54 зач., XII, 13 – 17."],"notes":"Служба святих не має святкового знака, звершується разом службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізми немає. На «Господи, взиваю» стихири на 6: Октоїха, глас 8-ий – 3, і святих, глас 2-ий – 3. «Слава: І нині» – Богородичний Мінеї, глас той же: «Єдина Невмістимого Бога Ти...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава: І нині» – Богородичний Октоїха. Після Трисвятого – тропар святих, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Вихованій у храмі...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святих, глас 4-ий (двічі). «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Вихованій у храмі...». Кафізми 4-а, 5-а і 6-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-й з ірмосом на 6 (ірмоси один раз), 2-й на 4, і святих на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої та 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – інший кондак святих, глас 4-ий; сідальний святих, глас 8-ий. «Слава: І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос святих, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний Мінеї, «І нині» – Богородичний Мінеї. «Хваліть Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава: І нині» – Богородичний Октоїха. Після Трисвятого – тропар святих, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти вища від усіх творінь...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар святих. Кондаки святих читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар святих; кондак дня, кондак святих. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар святих; кондак дня, кондак храму, кондак святих. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн усердная...». Прокимен, алилуарій і причасний – дня. Апостол та Євангеліє – дня."}]},
{"date":"01-27","weekday":"вівторок","title":"Перенесення мощів свт. Іоана Золотоустого (438).","readings":["Ран. – Ін., 35 зач. (від половини), X, 1 – 9.","Літ. – 1 Пет., 60 зач., III, 10 – 22. Мк., 55 зач., XII, 18 – 27.","Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16."],"notes":"Звершується полієлейна служба свт. Іоана Золотоустого.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири святителя глас 4-ий – 8 (перші дві стихири по двічі). «Слава» – святителя, глас той самий: «Не подобає тобі...», «І нині» – Богородичний воскресний, глас той самий: «Пророк Давид...». Вхід. Прокимен дня. Паремії святителя – 3. На стиховні стихири святителя, зі своїми приспівами. «Слава» – святителя глас 6-ий: «Преподобний, преблаженний...», «І нині» – Богородичний: «Ти є лоза істинна...». Після Трисвятого – тропар святителя, глас 8-ий. «Слава: І нині» – Богородичний воскресний, глас той самий: «Ти, що ради нас...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 8-ий (двічі). «Слава: І нині» – Богородичний воскресний, глас той самий: «Ти, що ради нас...». Кафізми 7-а і 8-а. Малі єктенії. Сідальні святителя. Полієлей. Величання святителя і вибраний псалом. Сідальний святителя після полієлею. «Слава: І нині» – Богородичний Мінеї. Степенна – 1-ий антифон 4-го гласу. Прокимен святителя, глас 4-ий: «Уста мої промовлятимуть премудрість, і повчання серця мого розум»; стих: «Почуйте це, всі народи, зрозумійте, всі, що живете по вселенній». Євангеліє святителя – Ін., зач. 35 (від половини). Після 50- го псалма: «Слава» – «Молитвами святителя...». Стихира святителя: «Трубою золотоголосою...» Канони: Богородиці з ірмос на 6 (ірмоси по двічі) і святителя (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія: «Сушу в глибині землі сонце осяяло колись...». Після 3-ої пісні – сідальний святителя, глас 8-ий. «Слава: І нині» – Богородичний Мінеї. Після 6-ої пісні – кондак та ікос святителя, глас 1-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є...» не співається. Світильний святителя. «Слава: І нині» – Богородичний Мінеї. «Все що дише...» і хвалітні псалми. На хвалітніх стихири святителя, – 4. «Слава» – святителя, глас той самий: «Отче Золотоустий...», «І нині» – Богородичний за гласом «Слави»: «Від усяких бід рабів Твоїх...». Велике славослів’я. Після Трисвятого – тропар святителя, глас 8-ий. «Слава: І нині» – Богородичний воскресний, глас той самий: «Ти, що ради нас...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні святителя, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"01-28","weekday":"середа","title":"Прп. Єфрема Сиріна (373 – 379). Прп. Єфрема Києво-Печерського, єп. Переяславського (бл. 1098). Прп. Палладія, пустельника (ІV). Прп. Ісаака Сиріна, єп. Ніневійського (VІ). Прп. Єфрема Угрина, Новоторзького (1053). Свтт. єпп. Переяславських: Єфрема († бл. 1098), Миколая († 1074), Петра († 1082), Лазаря († 1117), Сильвестра († 1123), Євфимія († 1155), Симеона († 1239).","readings":["1 Пет., 61 зач., IV, 1 – 11. Мк., 56 зач., XII, 28 – 37."],"notes":"Служба прп. Єфрема Сиріна без святкового знаку звершується із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-а (яка не була прочитана на ранній вівторка). На «Господи, взиваю» стихири Октоїха, глас 8-ий – 3, і преподобного, глас 1-ий – 3. «Слава» – преподобного, глас 6-ий: «Свідомо покинув ти...», «І нині» – Хрестобогородичний Мінеї: «На Хресті бачачи наше Життя...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава» – преподобного, глас 4-ий: «Як пророк ти...», «І нині» – Хрестобогородичний Мінеї: «Агнця і Пастиря...». Після Трисвятого: – тропар святого, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святого, глас 4-й (двічі). «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших: «Діво Пренепорочна...». Кафизми 10-а, 11-а і 12-а. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий на 6, 2-ий на 4 (з ірмосом) і преподобного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісні: ірмоси канону преподобного. Після 3-ої пісні – сідальний преподобного, глас 5-ий. «Слава: І нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» співається. Екзапостиларій Октоїха. «Слава» – світильний преподобного, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякленне славослів’я. Стихири на стиховні Октоїха, глас 8-ий. «Слава» – преподобного, глас 2-ий: «Як фінік, за Давидом...», «І нині» – Хрестобогородичний Мінеї: «Бачачи на Хресті Творця всього...». Після Трисвятого – тропар святого, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У Господському храмі – тропар дня «Спаси, Господи...», тропар священномученика, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар священномученика; кондак дня, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар священномученика; кондак дня, кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"01-29","weekday":"четвер","title":"Перенесення мощів сщмч. Ігнатія Богоносця (107). Свт. Лаврентія, затворника Києво-Печерського, єп. Турівського, в Ближніх печерах (1194). Мчч. Романа, Якова, Філофея, Іперихія, Авіва, Юліана і Паригорія (297). Сщмчч. Сильвана, єп., Луки, дияк., мч. Мокія, читця (312).","readings":["1 Пет., 62 зач., IV, 12 – V, 5. Мк., 57 зач., XII, 38 – 44 (за четвер).","2 Пет., 64 зач., I, 1 – 10. Мк., 58 зач., XIIІ, 1 – 8 (за п’ятницю, під зачало).","Сщмч.: Євр., 311 зач., IV, 14 – V, 6. Мк., 41 зач., IX, 33 – 41."],"notes":"Служба сщмч. Ігнатія Богоносця шестирична і звершується зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири священномученика, глас 4-ий – 6 (кожна стихира – двічі). «Слава» – священномученика, глас 8-ий: «Богоносний Ігнатію...», «І нині» – Богородичний за гласом «Слави», від менших: «Я, Діво Свята Богородице...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава» – священномученика, глас 1-ий: «О, тверда і адамантова душа твоя...», «І нині» – Богородичний за гласом «Слави», від менших: «Радуйся, радосте прадідів...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава: І нині» – Хрестобогородичний від менших: «Слово Отче, Христа Бога нашого...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-й (двічі). «Слава: І нині» – Хрестобогородичний від менших: «Слово Отче, Христа Бога нашого...». Кафизми 13-а, 14-а і 15-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-й з ірмосом на 4 (ірмоси один раз), 2-й на 4 і священномученика на 6. Біблійні пісні «Співаємо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісні – ірмоси канону священномученика. Після 3-ої пісні – сідальний священномученика, глас 3-ій (двічі). «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак і ікос священномученика, глас 4-ий. На 9-й пісні співаємо «Чеснішу...». По 9-й пісні співається «Достойно є...». Екзапостиларій Октоїха. «Слава» – світильний священномученика, «І нині» – Богородичний Мінеї. «Хваліте Господа з небес...». і хвалітні псалми Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава» – священномученика, глас 1-ий: «Стовп одухотворений і натхненний...», «І нині» – Богородичний за гласом «Слави», від менших: «Радуйся, Богородице Діво...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава: І нині» – Хрестобогородичний по гласу «Слави», від менших: «Богородице, Ти вища від усіх творінь...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4 і священномученика, пісня 3-я – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, два тропарі дня, тропар священномученика; два кондаки дня, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – два тропарі дня, тропар храму, тропар священномученика; два кондаки дня, кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн усердная...». Прокимен, аллилуарій і причасний – дня (четверга) і священномученика. Апостол і Євангеліє – дня (четверга і п’ятниці, під зачало) і священномученика."}]},
{"date":"01-30","weekday":"п’ятниця","title":"Собор вселенських учителів і святителів Василія Великого, Григорія Богослова та Іоана Золотоустого. Сщмч. Іполита, єп. Римського та з ним мчч. Кенсорина, Савина, Фрисії, діви та інших 20 мчч. (ІІІ). Прп. Зинона, посника Києво-Печерського, в Дальніх печерах (ХІV). Прп. Зинона, учня свт. Василія Великого (V). Мч. Феофіла Нового (784). Блгв. Петра, царя Болгарського (967).","readings":["Ран. – Ін., 36 зач., X, 9 – 16.","Літ. – Свтт.: Євр., 334 зач., XIII, 7 – 16. Мф., 11 зач., V, 14 – 19."],"notes":"Звершується всенічне бдіння трьох вселенських святителів.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» 1-й антифон. На «Господи, взиваю» стихири святителів, глас 4-й і глас 2-ий – 8. «Слава» святителів, глас 6-й: «Прославмо нині таємничі груби Духа...», «І нині» – Богородичний воскресний: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії святителів – 3. На літії стихира храму і стихири святителів, глас 2-ий і глас 6-ий. «Слава» святителів, глас 6-ий: «Святителів Христових...», «І нині» Богородичний Мінеї, глас той самий: «Дівствену доброту...». На стиховні стихири святителів, глас 1-ий (зі своїми приспівами). «Слава» святителів, глас 2: «Святителів Христових і славу отців...», «І нині» – Богородичний Мінеї, глас 2-ий: «Сьогодні Христос приноситься в храм...». Після Трисвятого тропар святителів, глас 4-ий (двічі), «Богородице Діво...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь тропар святителів, глас 4-ий (двічі). «Слава: І нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 19-а і 20-а. Малі єктенії. Сідальні святителів. Полієлей. Величання святителів: «Величаємо вас,/ святителі Христові Василію Великий, Григорію Богослове та Іоане Золотоустий, / і шануємо святу пам’ять вашу,/ бо ви молите за нас// Христа Бога нашого»; і вибраний псалом. Сідальний святителів після полієлею, глас 4-й.«Слава» інший сідальний святителів після полієлея, глас той самий «І нині» Богородичний Мінеї, глас той самий. Степенна 1-ий антифон 4-го гласу. Прокимен святителів, глас 4-ий: «Священики Твої зодягнуться у правду, і преподобні Твої зрадіють»; стих: «Уста мої промовлятимуть премудрість, і повчання серця мого розум». Євангеліє святителів Ін., Зач. 36. Після 50-го псалма: «Слава» – «Молитвами святителів...». Стихира святителів, глас 6-ий: «Вилилась благодать...». Канони: Богородиці (в службі святителів) з ірмосом на 6 (ірмоси по двічі), святителів (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія–«Сушувглибиніземлісонцеосяялоколись...». Після 3-ої пісні сідальний святителів, глас 8-ий, «Слава» – інший сідальний святителів, глас той самий, «І нині» – Богородичний Мінеї. Після 6-ої пісні – кондак та ікос святителів, глас 2-ий. На 9-й пісні «Чеснішу» не співаємо, але співаємо особливі приспіви (див. В Минеї на ряду), 1-ий приспів: «Величай, душе моя, Чеснішу Небесних воїнств, Діву Пречисту Богородицю» [2]. (Звершується звичайне кадіння). Після 9-ої пісні «Достойно не співається. Світильний святителів. «Слава» інший святильний святителів «І нині» Мінеї: «Єдине Божество...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири святителів, глас 5-ий – 6. «Слава» святителів, глас той самий: «Заграймо пісні, та трубах гучних...», «І нині» – Богородичний Мінеї, глас той самий: «Заспіваймо вірні, як на трубах гучних...». Велике славослів’я. Після Трисвятого тропар святителів, глас 4-ий. «Слава: І нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителів"},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ – блаженні святителів на 8 Після входу тропарі і кондаки: УхраміГосподськомуіБогородиці–тропархраму,тропар святителів.«Слава»–кондаксвятителів,«Інині»–кондакхраму. У храмі святого – тропар святителів, тропар храму, кондак храму. «Слава» кондак святителів, «І нині» – «Заступнице християн...» Прокімен, Апостол, алилуарій, Євангеліє і причасний – святителів. Співаємо «Достойно є...»."}]},
{"date":"01-31","weekday":"субота","title":"Безсрр., мчч. Кира та Іоана і з ними мцц. Афанасії та дочок її Феодотії, Феоктисти і Євдоксії (311). Свт. Микити, затворника Києво-Печерського, єп. Новгородського (1108). Мчч. Вікторина, Віктора, Никифора, Клавдія, Діодора, Серапіона і Папія (251). Мц. Трифени Кизицької.","readings":["Безсрібн.: 1 Кор., 153 зач., XII, 27 – XIII, 8. Мф., 34 зач. (від половини), X, 1, 5 – 8.","Ряд.: 2 Тим., 293 зач., II, 11 – 19. Лк., 88 зач., XVIII, 2 – 8."],"notes":"Служба святих безсрібників без святкового знаку звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізми немає. На «Господи, взиваю» стихири безсрібників, глас 1-ий – 6 (перша стихира – двічі). «Слава» – безсрібників, глас 8-ий: «Двоїця мучеників...», «І нині» – Богородичний воскресний, глас 8-ий: «Цар Небесний...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий (мученичі з числа стихир на «Господи, взиваю»). «Слава» – безсрібників, глас 2-ий: «Прийдіть нині, собор вірних...», «І нині» – Богородичний за гласом «Слави», від менших: «Спаси від бід рабів Твоїх...». Після Трисвятого – тропар безсрібників, глас 5-ий. «Слава: І нині» – Богородичний воскресний, глас 8-ий: «Ти, що заради нам народився від Діви...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар безсрібників, глас 5-ий (двічі). «Слава: І нині» – Богородичний за гласом тропаря: «Радуйс, лвері Господні непрохідні...». Кафізми 16-а і 17-а. Малі єктенії. Сідальні Октоїха. Псалом 50-ий.Канони: У храмі Господському та Богородиці: храму (ірмос двічі) на 6, святих на 4 і Октоїха (мученичий) на 4. У храмі святого: святих (ірмос двічі) на 6, храму на 4 і Октоїха (мученичий) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичого канону Октоїха. Після 3-ої пісні – сідальний безсрібників, глас 4-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той самий. За 6-й пісні – кондак та ікос безсрібників, глас 3-ій. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Світильний безсрібників, «Слава» – екзапостиларій Октоїха. – «І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий (мученичі з числа стихир на хвалітніх). «Слава» – безсрібників, глас 4-ий: «Достохвальними піснями звеличимо...», «І нині» – Богородичний за гласом «Слави», від менших: «Єдина Чиста і Пречиста Діво...». Після Трисвятого – тропар безсрібників, глас 5-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Від Діви засяяв Ти світові, Христе Боже...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак безсрібників."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4 і безсрібників, пісня 3-тя – 4. Після входу – тропарі та кондаки: У храмі Господньому та Богородиці – тропар храму, тропар дня «Апостоли, мученики...», тропар безсрібників, кондак храму, кондак безсрібників. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». У храмі святого – тропар дня «Апостоли, мученики...», тропар безсрібників, кондак безсрібників. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». Прокимен, алилуарій і причасний – безсрібників ідня. Апостол і Євангеліє – безсрібників і дня."}]},
{"date":"02-01","weekday":"неділя","title":"Неділя про митаря і фарисея. Глас 1-й. Передсвято Стрітення Господнього. Мч. Трифона (250). Мцц. Перпетуї і Феліцитати, мчч. Сатира, Ревоката, Саторнила, Секунда (202 – 203). Прп. Петра Галатійського (429). Прп. Вендиміана, пустельника Вифинійського (бл. 512).","glas":1,"readings":["Ран. – Єв. 1-е, Мф., 116 зач., XXVIII, 16 – 20.","Літ. – 2 Тим., 296 зач., III, 10 – 15. Лк., 89 зач., XVIII, 10 – 14."],"notes":"Початок співу Постової Тріоді. Згідно Типікону під час співу Постової Тріоді до вербної неділі служба недільного дня звершується за Октоїхом та Тріоддю, а служби Мінеї опускаються за винятком днів пам’яті святих, які мають бдіння чи полієлей, свят Стрітення Господнього, Благовіщення Пресвятої Богородиці, їх передсвят і післясвят. Недільна служба Октоїха звершується зі службою Постової Тріоді та передсвята Стрітення Господнього. Служба мученика Трифона переноситься на Мале Повечір’я в середу увечері (29 січня), або на інший день, як цього вимагають обставини. За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню. Мала вечірня служиться лише за Октоїхом.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири, глас 1-ий – 4 (перша стихира – двічі (на початку, та в кінці як четверта). «Слава, і нині» – богородичний (догматик малої вечірньої), глас 1-ий: «Сьогодні браття, торжество дівства!...» Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. Перша стихира недільна, а інші стихири Пресвятої Богородиці зі своїми приспівами. На стиховні стихири глас 1-ий: «Стражданням Твоїм Христе...» із своїми приспівами. «Слава, і нині» – Богородичний, глас то й же: «Хмарою вічного світла...». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар недільний, глас 1-ий «Хоч камінь запечатали юдеї...» «Слава, і нині» – Богородичний за гласом тропаря: «Коли Гавриїл звістив...». Після співу тропаря з богородичним священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, що воскрес із мертвих, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи взиваю» стихири на 10: недільні, глас 1-ий – 4, Тріоді, глас 1-ий – 3, передсвята – 3. «Слава» – Тріоді, глас 8-ий: «Вседержителю Господи». «І нині» – догматик, глас 1-ий: «Всесвітню славу...». Вхід. Прокимен дня. На літії стихира храму. Стихира передсвята і стихири Тріоді хвалітні: 1-ша, глас 3-ій: «Фарисеїв гонористий голос...» і 2-га: «Фарисея, що виправдовував себе, хвалячись ділами...», глас 8-ий. «Слава» – Тріоді, глас 3-ій: «Душе моя...» , «І нині» – Богородичний передсвята зі стиховних стихир ранньої. На стиховні стихири недільні, глас 1-ий. «Слава» – Тріоді, глас 5-ий: «Очима моїми обважнілими», «І нині» – Богородичний передсвята: «Святого Пресвята Діва принесла...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар передсвята (один раз), глас 1-ий: «Небесний собор небесних ангелів, спустившись на землю, бачить, як Немовля, приносять у храм Первонародженого раніше всього творіння Матір’ю Безневістною, співає з нами передсвяткову пісню радіючи»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар недільний, глас 1-ий (двічі). «Слава і нині» – передсвята: «Небесний собор небесних ангелів ...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні недільні. Непорочні (за вказівкою Типікону співаються лише в Неділю митаря і фарисея. В інші підготовчі неділі до Великого посту співатиметься полієлей). Іпакої, степенні і прокимен – гласу. Євангеліє недільне 1-ше. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Покаяння відкрий мені двері...». – «І нині...» – «На стежки спасіння...», «Помилуй мене Боже...» і «Багато вчинених...». Примітка. У Неділю митаря і фарисея починається Постова Тріодь і на ранній після 50-го псалма (до 5-ї неділі включно) співаються розчулені стихири «Покаяння відкрий мені двері, Життєдавче...». Воскресна стихира, глас 6-ий: «Воскрес Ісус із гробу...», не співається, оскільки вона замінюється особливою стихирою Тріоді, глас 6-ий: «Багато вчинених...». Канони: недільний гласу з ірмосом на 4 (ірмоси раз), Богородиці на 2, передсвята на 4 і Тріоді на 4. Біблійні пісні «Співаймо Господеві...». Катавасія свята Стрітення. Після 3-ої пісні – Кондак та ікос передсвята. Сідальний Тріоді, глас 4-ий. «Слава» – інший сідальний Тріоді «І нині» – передсвята, глас 1-ий: «Вічний скарб...» Після 6-ої пісні – кондак Тріоді, глас 4-ий, інший кондак Тріоді, глас 3-ій та ікос. Далі читається синаксарій. Примітка. Про кондак Тріоді, глас 4-ий «Тікаймо від фарисеєвої похвальби...» Типікон не згадує. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 1-ий. «Слава» – світильний Тріоді, «І нині» – Богородичний Тріоді: «Творець творіння...» «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: недільні Октоїха, глас 1-ий – 4, і Тріоді, глас 3-ій – 4 «Слава» – стихира Тріоді, глас 8-ий: «Фарисея, що виправдовував себе...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар недільний: «Днесь спасіння...». Примітка. Перед початком 1-го часу читець читає або співає хор: «Слава і нині» євангельську стихиру 1-шу, оскільки сьогодні читалося недільне Євангеліє 1-ше. При співі або читанні стихири буває вихід у притвор для читання Оголошених прп. Феодора Студита. Повчання за Типіконом має читати настоятель монастиря. по закінченню читання співають тропар прп. Феодора, глас 8-ий: «Православ’я наставнику...» без Богородичного. І читається 1 час, який завершується малим відпустом. Примітка. Якщо в храмі не було всенічної, то на вечірній у суботу після «Нині відпускаєш...» співається тропар гласу «Слава і нині» – тропар передсвята. А також на малому повечір’ї увечері після читаються кондак передсвята «Слава і нині» – кондак Тріоді."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний. «Слава» – тропар передсвята. Кондаки Тріоді і передсвята читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні на 12: гласу – 4, передсвята, пісня 3-тя – 4 і Тріоді, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар недільний, тропар передсвята. «Слава» – кондак Тріоді. «І нині» – кондак передсвята. У храмі святого – тропар недільний, тропар передсвята, тропар храму кондак Тріоді. «Слава» – кондак храму. «І нині» – кондак передсвята. Прокимен, алилуарій – гласу. Апостол і Євангеліє – Неділі митаря і фарисея. Причасний – недільний: «Хваліть Господа...»."}]},
{"date":"02-02","weekday":"понеділок","title":"СТРІТЕННЯ ГОСПОДА НАШОГО ІСУСА ХРИСТА.","readings":["Ран. – Лк., 8 зач., II, 25 – 32.","Літ. – Євр., 316 зач., VII, 7 – 17. Лк., 7 зач., II, 22 – 40."],"notes":"Звершується всенічна свята Стрітення Господнього (за Мінеєю). За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири свята, глас 1-ий – 4. (перша стихира – двічі). «Слава, і нині» – свята, глас 4-ий: «Нині свята Мати...» Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня (неділі вечора). Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. На стиховні стихири свята, глас 2-ий: «Нині Спаситель...» із своїми приспівами. «Слава, і нині» – свята, глас то й же: «Прийми, о Симеоне...». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар свята, глас 1-ий «Радуйся Благодатна...». Після співу тропаря священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири свята, глас 1-ий – 8 (перші дві стихири – тричі, третя стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «Нехай відкриються нині двері Небесні...». Вхід. Прокимен дня. Паремії свята – 3. На літії стихири свята, глас 1-ий і глас 2-ий. «Слава» – свята, глас 5-ий: «Дослідіть Писання...», «І нині» – свята, глас той же: «Вічний Господь став Немовлям плоттю...». На стиховні стихири свята, глас 7-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Того, Кого носять Херувими...». Після Трисвятого – тропар свята, глас 1-ий (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава, і нині» – той же тропар. Кафизми 4-та і 5-та. Малі ектенії. Сідальні свята. Полієлей. Величання свята: «Величаємо Тебе,/ Життєдавче Христе,/ і шануємо Пречисту Матір Твою,/ Нею ж за законом нині принесений був// до храму Господнього», і вибраний псалом. Сідальний свята після полієлею, глас 4-ий: «Задля мене Ти, Вічний, стаєш Немовлям...». «Слава, і нині» – той же сідальний. Степенна – 1-ий антифон 4-го гласу. Прокимен свята, глас 4-ий: «Пом’яну ім’я Твоє у всякому роді і роді»; стих: «Вилилось із серця мого слово благе, кажу я Цареві про мої діла». Євангеліє – свята – Лк., зач. 8. Після 50-го псалма: «Слава» – «Молитвами Богородиці...». Стихира свята, глас 6-ий: «Нехай відкриються нині двері Небесні...». Канон свята з ірмосом на 14 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія свята: «Сушу в глибині землі сонце осяяло колись...». Після 3-ої пісні – сідальний свята, глас 4-ий: «На горі Синайській...». «Слава, і нині» – той же сідальний. Після 6-ої пісні – кондак та ікос свята, глас 1-ий. На 9-ій пісні – приспіви свята і звичайне кадіння. («Чеснішу» не співаємо). 1-ий хор співає перший приспів: «Богородице Діво, уповання християн...» 1, та ірмос: «В законі тіні і писань...». 2-ий хор співає другий приспів: «Богородице Діво, світу Блага помічнице...», і той же ірмос. 1-ий хор: «Богоносний Симеоне...», і тропар: «Замість двох горлиць або двох голубів...». 2-ий хор: «Обіймає руками старець Симеон...», і той же тропар. 1-ий хор: «Не старець Мене тримає...», і той же тропар. 2-ий хор: «Кліщі таємничі...», і той же тропар. 1-ий хор: «О дочко Фануїлова!..», І тропар: «Ти дарував мені радість...». 2-ий хор: «Анна цнотлива...», і той же тропар. 1-ий хор: «Незбагненно є...», і той же тропар. 2-ий хор: «Чиста Голубко...», і той же тропар. 1-ий хор: «О Христе, всіх Царю!...», і тропар:»Священноліпно і побожно...». 2-ий хор: «О Христе, всіх Царю!...», і той же тропар. 1-ий хор: «Трисяйне і Триіпостасне Божество...», і той же тропар. 2-ий хор: «О Діво Маріє!..», І той же тропар. Потім обидва хори разом співають 1-ий приспів: «Богородице Діво, уповання християн...», та Ірмос: «В законі тіні і писань...». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава» – той же світильний, «І нині» – той же світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «На руках старечих...». Велике славослів’я. Після Трисвятого – тропар свята, глас 1-ий (один раз). Відпуст свята: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як Благий і Людинолюбний»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ за чином свт. Іоана Золотоустого. Антифони зображальні. Блаженні свята, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4 (За Типіконом). Увага! Відповідно до рішення №41 Священного Синоду Української Православної Церкви (Православної Церкви України) від 7 листопада 2024 р. «Про надання благословення на богослужбові тексти». Священний Синод вирішив: Надати благословення на використання на розсуд настоятеля на святкових службах особливих антифонів замість звичайних, як це є в грецькій церковній традиції та включити зазначені тексти до богослужбових книг Православної Церкви України. Антифон 1 Стих 1: Вилило серце моє / слово благе (Пс 44:1). Молитвами Богородиці, / Спасе, спаси нас. Стих 2: Язик мій – / мов перо книжника-скорописця (Пс. 44:2). Молитвами Богородиці, / Спасе, спаси нас. Стих 3: Виливається благодать / із уст Твоїх (Пс. 44:3Б). Молитвами Богородиці, / Спасе, спаси нас. Стих 4: Тому благословив Тебе / Бог навіки (Пс. 44:3В). Молитвами Богородиці, / Спасе, спаси нас. Слава, і нині: Молитвами Богородиці, Спасе, / спаси нас. Антифон 2 Стих 1: Прив’яжи меч Твій / до стегна Твого, Сильний (Пс. 44:4А). Спаси нас, Сину Божий, / що на руках праведного Симеона cпочивати зволив, співаємо Тобі: алилуя. Стих 2: І натягни лук, і встигай, / і царюй заради істини (Пс. 44: 5А). Спаси нас, Сину Божий, / що на руках праведного Симеона cпочивати зволив, співаємо Тобі: алилуя. Стих 3: Гострі стріли Твої, Сильний! / Впадуть народи перед Тобою (Пс 44:6). Спаси нас, Сину Божий, / що на руках праведного Симеона cпочивати зволив, співаємо Тобі: алилуя. Стих 4: Жезл правоти – / жезл Царства Твого (Пс 44:7Б). Спаси нас, Сину Божий, / що на руках праведного Симеона cпочивати зволив, / співаємо Тобі: алилуя. Слава, і нині: Єдинородний Сину: Антифон 3, глас 1 Стих 1: Слухай, Дочко, і споглянь,/ і прихили вухо Твоє (Пс. 44:11А). Тропар, глас 1: Радуйся, Благодатна Богородице Діво, бо з Тебе засяяло Сонце правди – Христос Бог наш, що просвічує тих, що в темряві. Веселися і ти, старче праведний, що прийняв в обійми Визволителя душ наших, Який дарує нам воскресіння. Стих 2: Найбагатші з народів помоляться лицю твоєму (Пс. 44:13Б). Тропар: Радуйся, Благодатна Богородице Діво: Стих 3: Пом’яну ім’я Твоє / у всякому роді і роді (Пс. 44:18А). Тропар: Радуйся, Благодатна Богородице Діво: Вхідний стих: «Явив Господь спасіння Своє, перед народами відкрив правду Свою». Примітка. Перед виголошенням вхідного стиха слід виголошувати «Премудрість, станьмо побожно» Після входу – тропар свята. «Слава, і нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – свята (рядові читання переносяться на наступний день). Задостойник свята – приспів: «Богородице Діво, уповання християн...», та Ірмос: «В законі тіні...» (задостойник співається на Літургії до віддання свята Стрітення Господнього). Відпуст свята (той самий, що й на ранній) із згадуванням імені свт. Іоана Золотоустого. Примітка. За традицією після Божественної літургії звершується Мале освячення води і освячуються свічі. Чини малого освячення води та свічок на Стрітення Господнє дивись в Требнику."}]},
{"date":"02-03","weekday":"вівторок","title":"Післясвято Стрітення Господнього. Післясвято Стрітення Господнього. Правв. Симеона Богоприїмця і Анни, пророчиці (І). Прор. Азарії (Х ст. до Р. Х.). Мчч. Папія, Діодора, Клавдіана (250). Мчч. Адріана і Єввула (308 – 309). Мч. Власія Кесарійського (ІІІ). Свт. Ігнатія Маріупольського, митр. Готфейського і Кефайського (1786). Рівноап. Миколая, архієп. Японського (1912). Знайдення мощів свт. Рафаїла (Заборовського), митр. Київського, Галицького і всієї Руси (2024). День інтронізації Блаженнійшого Митрополита Київського і всієї України Епіфанія.","readings":["2 Пет., 66 зач., I, 20 – II, 9. Мк., 59 зач., XIII, 9 – 13 (за понеділок).","2 Пет., 67 зач., II, 9 – 22. Мк., 60 зач., XIII, 14 – 23 (за вівторок).","Прав.: Євр., 321 зач. (від половини), IX, 11 – 14. Лк., 8 зач., II, 25 – 38 (під зачало)."],"notes":"Звершується служба післясвята Стрітення Господнього та славослівна правв. Симеона і пророчиці Анни.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: свята, глас 1-ий – 3 (див. 3 лютого, у службі правв. Симеона і пророчиці Анни), і святого, глас 4-ий – 3. «Слава, і нині» – свята, глас 5-ий: «Ветхий днями, ставши немовлям...» Входу немає. Прокимен дня. На стиховні стихири свята, глас 1-ий зі своїми приспівами. «Слава, і нині» – свята, глас той же. Після Трисвятого – тропар праведного, глас 4-ий: «Симеон старець нині веселиться, прийнявши на руки немовля Предвічного Бога, просячи звільнення від уз плоті і взиваючи: побачили очі мої спасіння Твоє світові» (Мінея – лютий ст. 83). «Слава, і нині» тропар свята, глас 1-ий (один раз). Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив»."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в понеділок увечері канон Богородиці із Октоїха опускається. Звершується служба Пресвятої Богородиці заради Її ікони «Пом’якшення злих сердець» (Мінея – Лютий 3 лютого) ."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар праведному. «І нині» – той же свята. Кафизми 7-ма і 8-ма. Малі ектенії. Сідальні праведного (по двічі) «Слава, і нині» – сідальний свята. Псалом 50-ий. Канони: свята з ірмосом на 6 (ірмоси по двічі) і святого на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після кожної пісні – ірмоси канону свята Стрітення. Після 3-ої пісні – кондак та ікос свята, глас 1-ий. сідальний свята, глас 3-ій. «Слава, і нині» – той же сідальний. Після 6-ої пісні – кондак святого, глас 4-ий: «Старець нині молиться звільнитися від уз цього тлінного життя, Христа прийнявши, Сотворителя і Господа». На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний Мінеї. «Слава» – світильний праведного (Мінея – Лютий. с. 86), «І нині» – світильний свята: «Натхнений Духом Святим» (див. 2 ​​ лютого с. 57). «Хваліте Господа з Небес...» і хвалітні псалми. На хвалитніх стихири на 6: свята – 3, глас 4-ий і праведного – 3 (див. стихири з «Господи взиваю», глас 4-ий). «Слава» – праведного «У Господі Бозі, Спасі Своєму...». «І нині» – свята: «На руках старця...» Співається велике славослів’я. Після Трисвятого – тропар праведного «Слава, і нині» – тропар свята глас 1-ий. Потрійна і благальна ектенії. Відпуст ранньої: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята «Слава» – тропар праведного. Кондаки свята і праведного читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 1-ша – 4 (з ірмосом), і праведного, пісня 6-та – 4. На вході – «... у святих Дивний єси...». Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята, тропар праведного; кондак храму. «Слава» – кондак праведного, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар праведного. «Слава» – кондак праведного, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму тропар праведного; кондак храму. «Слава» – кондак праведного, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і праведного. Апостол і Євангеліє – дня (за понеділок і вівторок під одне зачало) і праведного. Задостойник свята. Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив»."}]},
{"date":"02-04","weekday":"середа","title":"Прп. Ісидора Пелусіота (бл. 436 – 440). Мч. Іадора (ІІІ). Сщмч. Авраамія, єп. Арвільського (бл. 344 – 347). Прп. Миколая, спов., ігумена Студійського (868).","readings":["2 Пет., 68 зач., III, 1 – 18. Мк., 61 зач., XIII, 24 – 31."],"notes":"Служба прп. Ісидора Пелусіотского не має святкового знака, звершується разом зі службою післясвята Стрітення Господнього.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3, і преподобного,гластойже–3.«Слава,інині»–свята,глас2-ий. Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами) (див. у службі преподобного 4 лютого). «Слава, і нині» – свята, глас той же. Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – тропар свята, глас 1-ий. Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння»."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї у вівторок увечері канон Богородиці із Октоїха. Після Трисвятого – кондак Стрітення."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 10-та, 11-та Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята з ірмосом на 8 (ірмоси по двічі) і преподобного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобного). Після 3-ої пісні – кондак преподобного, глас 4-ий; сідальний преподобного, глас 3-ій. «Слава, і нині» – сідальний свята, глас 8-ий. Після 6-ої пісні – кондак та ікос свята, глас 1-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ій пісні «Достойно є» не співається. Світильний свята (див. 2 ​​ лютого). «Слава, і нині» – той же світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 7-ий: «Світло на просвіту народів...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – тропар свята, глас 1-ий. Відпуст 1-го часу: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святого. Кондак тільки свята Стрітення ."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 4-а – 6 (з ірмосом). На вході – «Дивний у святих...». Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння...»."}]},
{"date":"02-05","weekday":"четвер","title":"Мц. Агафії (251). Свт. Феодосія, архієп. Чернігівського (1696). Мц. Феодули і мчч. Елладія, Макарія і Євагрія (бл. 304). Єлецько-Чернігівської (1060), Сицилійської, або Дивногорської (1092), і званої «Віднайдення загиблих» ікон Божої Матері.","readings":["1 Ін., 69 зач., I, 8 – II, 6. Мк., 62 зач., XIII, 31 – XIV, 2.","Свт.: Євр., 335 зач., XIII, 17 – 21. Ін., 36 зач., X, 9 – 16."],"notes":"Славослівна служба свт. Феодосія, архієп. Чернігівського звершується разом зі службою післясвята Стрітення Господнього. Службу свт. Феодосія дивись 9 вересня.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. На «Господи, взиваю» стихири на 6: свята, глас 1-ий – 3, і святителя, глас 2-ий – 3. «Слава» – святителя. «І нині» – свята, глас 8-й: «Той, Кого носять херувими і оспівують серафими,...» (див. служба Стрітення стихири на стиховні). Входу немає. Прокимен дня. На стиховні стихири свята, глас 6-ий (зі своїми приспівами, або стихири святителя, глас 5-ий (зі своїми приспівами). «Слава» – святителя. «І нині» – свята. Після Трисвятого – тропар святителя, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї канон Богородиці з Октоїха та служба мч. Агафії (без ірмосів)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар святителя, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми13-таі14-та.Малі єктенії.Післякожноїкафизми– сідальний святителя (двічі), «Слава, і нині» – сідальний свята. 50 псалом. Канони: свята з ірмосом на 8 (ірмоси по двічі) і святителя на 6. Біблійні пісні «Співаймо Господеві...». Катавасія свята: «Сушу в глибині землі сонце осяяло колись...» після кожної пісні. Після 3-ої пісні – кондак і ікос свята, глас 1-ий; сідальний святителя, гл,ас 4-й (двічі). «Слава, і нині» – сідальний свята. Після 6-ої пісні – кондак та ікос святителя, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний святителя. «Слава, і нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 4: святителя, – 4. «Слава» – святителя, «І нині» – свята. Велике славослів’я. Після Трисвятого – тропар святителя, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння..»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святителя. Кондаки свята і святителя читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 3-я (з ірмосом) – 4, і святителя, пісня 6-а – 4. На вході – «Прийдіть поклонімось... Дивний у святих єси...». Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і святителя. Апостол і Євангеліє – дня і святителя. Задостойник свята. Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння..»."}]},
{"date":"02-06","weekday":"п’ятниця","title":"Прп. Вукола, єп. Смирнського (бл. 100). Прп. Варсонофія Великого та Іоана, пророка (VІ). Свт. Фотія, патр. Константинопольського (891). Мцц. Дорофеї, Христини, Каллісти і мч. Феофіла (288 – 300). Мц. Фавсти, мчч. Євіласія і Максима (305 – 311). Мч. Юліана (312). Мцц. Марфи, Марії та брата їх прмч. Ликаріона, юнака.","readings":["1 Ін., 70 зач., II, 7 – 17. Мк., 63 зач., XIV, 3 – 9."],"notes":"Служба прп. Вукола, єп. Смирнского, не має святкового знака, звершується разом зі службою післясвята Стрітення Господнього.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-та. На «Господи, взиваю» стихири на 6: свята, глас 1-ий – 3, і преподобного, глас 6-ий – 3. «Слава, і нині» – свята, глас 5-ий: «Дослідіть Писання...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 5-ий: «Вічний Господь...». Після Трисвятого – тропар преподобного, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння..»."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в четвер увечері канон Богородиці Октоїха."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар преподобного, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 19-та і 20-та. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята з ірмосом на 8 (ірмоси по двічі) і преподобного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобного). Після 3-ої пісні – сідальний преподобного, глас 4-ий. «Слава, і нині» – сідальний свята, глас той же. Після 6-ої пісні – кондак та ікос свята, глас 1-ий. На 9-ій пісні співаймо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – той же світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас той же. Після Трисвятого – тропар преподобного, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. Відпуст 1-го часу: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння..»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святого. Кондак свята. Примітка. Кондак прп. Вуколу відсутній в Мінеї."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 7-а – 6 (з ірмосом). На вході – «Прийдіть поклонімось... Дивний у святих єси...». Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята, тропар преподобного. «Слава» – кондак храму, «І нині» – кондак свята. У храмі Богородиці – тропар свята. «Слава» – тропар преподобного, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар святого. «Слава» – кондак храму, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос, істинний Бог наш, що в обіймах праведногоСимеонаноситисьзволиврадинашогоспасіння...»."}]},
{"date":"02-07","weekday":"субота","title":"Прп. Парфенія, єп. Лампсакійського (ІV). Прп. Луки Елладського (бл. 946). 1003 мчч. Нікомидійських (303).","readings":["2 Тим., 295 зач., III, 1 – 9. Лк., 103 зач., XX, 45 – XXI, 4."],"notes":"Служба прп. Парфенія, єп. Лампсакійського і прп. Луки Елладського шестирична звершується разом зі службою післясвята Стрітення Господнього.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: святителя, глас 1-ий – 3, і преподобного, глас 6-ий – 3. «Слава,» – свята, глас 5-ий: «Дослідіть Писання...». «І нині» – догматик, глас 1-ий: «Всесвітню славу...» Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 6-ий: «Нехай нині відкриються...». Після Трисвятого – тропар святих, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння..»."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї співається канон Богородиці Октоїха та служба св. мч. Федора Стратилата і св. прор. Захарії (із 8 лютого)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар святих, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 16-та і 17-та1. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята з ірмосом на 6 (ірмоси по двічі) і святих на 8. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобного Луки). Після 3-ої пісні – кондак свт Парфенія, кондак прп. Луки. сідальний прп. Парфенія, глас 3-ій. «Слава» – сідальний прп. Луки. «І нині» – сідальний свята, глас той же. Після 6-ої пісні – кондак та ікос свята Стрітення, глас 1-ий. На 9-ій пісні співаймо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – той же світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас той же. Після Трисвятого – тропар святих, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. Відпуст 1-го часу: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння..»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святих. Кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 7-а – 6 (з ірмосом). На вході – «Прийдіть поклонімось... Дивний у святих єси...». Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята, тропар святих. «Слава» – кондак храму, «І нині» – кондак свята. У храмі Богородиці – тропар свята. «Слава» – тропар святих, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар святих. «Слава» – кондак храму, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння..»."}]},
{"date":"02-08","weekday":"неділя","title":"Неділя про блудного сина. Глас 2. Вмч. Федора Стратилата (319). Прор. Захарії Серповидця (бл. 520 до Р. Х.). Свт. Сави ІІ, архієп. Сербського (1268 – 1269).","glas":2,"readings":["Ран. – Єв. 2-е, Мк., 70 зач., XVI, 1 – 8.","Літ. – 1 Кор., 135 зач., VI, 12 – 20. Лк., 79 зач., XV, 11 – 32."],"notes":"Служба вмч. Федора Стратилата та прор. Захарії Серповидця співається «в п’ятницю на повечір’ї» (див.: Типікон, розд. 49-ий, 1-е «див»). Воскресна служба Октоїха звершується разом зі службою Тріоді і службою післясвята Стрітення Господнього (за 9-ою Марковою главою Типікону від 2 лютого: «Якщо припаде післясвято Стрітення Господнього в Неділю фарисеєву, або блудного, або м’ясопусну»). За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню. Мала вечірня служиться лише за Октоїхом.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири, глас 2-ий – 4. (перша стихира – двічі (на початку, та в кінці як четверта). «Слава, і нині» – богородичний (догматик малої вечірньої), глас 2-ий: «О превелика таємнице!...» Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. Перша стихира недільна, а інші стихири Пресвятої Богородиці зі своїми приспівами. На стиховні стихири глас 2-ий: «: «Воскресіння Твоє Христе, Спасе...», ...» із своїми приспівами. «Слава, і нині» – Богородичний, глас то й же: «Хто Тебе Діво...». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар недільний, глас 2-ий «Коли ти зійшов...» «Слава, і нині» – Богородичний за гласом тропаря: «Все вище розуму...». Після співу тропаря з богородичним священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж», кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 2-ий – 4, Тріоді, глас 1-ий – 3 (перша стихира – двічі), і свята, глас той же – 3. «Слава» – Тріоді, глас 2-ий: «О, скількох благ я, окаянний, позбавив себе!...», «І нині» – догматик, глас 2-ий: «Минула тінь закону...». Вхід. Прокимен дня. На літії стихири Тріоді, глас 2-ий: «Гласом блудного викликую до Тебе, Господи...», і глас 8-й: «Розтративши і розвіявши блудно отцівського майна багатство, нікчемним я став...» (див. на хвалітніх). «Слава» – Тріоді, глас 4-й: «Як блудний син...», «І нині» – свята, глас 5-ий: «Дослідіть Писання...» (див. у службі велмч. Федора на стиховні стихири ранньої 8 лютого). На стиховні стихири воскресні, глас 2-ий. «Слава» – Тріоді, глас 6-ий: «Батьківського дару багатство розтративши...», «І нині» – свята, глас 5-й: «Ветхий днями...» (див. див. у службі велмч. Федора на стиховні стихири вечірньої 8 лютого). Після Трисвятого – «Богородице Діво...» (двічі) і тропар свята, глас 1-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 2-ий (двічі). «Слава, і нині» – тропар свята, глас 1-ий. Кафізми 2-га і 3-тя. Малі ектенії. Сідальні воскресні. Полієлей. До двох полієлейних псалмів приєднується псалом 136-ий: «На ріках вавилонських...» [1]. «Ангельський собор...». Іпакої, Степенні і прокимен гласу. Євангеліє воскресне 2-ге. «Воскресіння Христове бачивши...». Після 50-го псалма: Після 50-го псалма: «Слава» – «Покаяння відкрий мені двері...». – «І нині...» – «На стежки спасіння...», «Помилуй мене Боже...» і «Множество вчинених...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Богородиці (Октоїха) на 2, Тріоді на 4 і свята на 4. Біблійні пісні «Співаймо Господеві...». Катавасія свята після кожної пісні «Сушу в глибині землі сонце осяяло колись...». Після 3-ої пісні – кондак та ікос свята, глас 1-ий. «Слава» – сідальний Тріоді, глас той же: «Батьківські обійми...», «І нині» – сідальний свята, глас 1-ий: «Будучи на святому престолі з Отцем..» (див. Мінея за 8 лютого). Після 6-ої пісні – кондак та ікос Тріоді, глас 3-ій. Читаємо синаксар. Стихи: Хто, як і я, розпусник, дерзай, прийди: Адже двері Божого милосердя для всіх відчинені... На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 2-ий. «Слава» – світильний Тріоді (за вибором), «І нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 2-ий – 4, і свята, глас 1-ий – 4 (див. 8 лютого, в службі вемлмч. Федора, на стиховні ранньої, зі «Славою» і приспівами своїми). «Слава» – Тріоді, глас 6-ий: «Отче Благий...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...». Відпуст воскресний: «Христос, що воскрес із мертвих...». Перед 1-им часом на «Слава, і нині» – стихира євангельська 2-а."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар свята. Кондаки Тріоді і свята читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4, Тріоді, пісня 6-а – 4, і свята, пісня 8-а – 4. На вході – «Прийдіть поклонімось... що воскрес із мертвих...». Після входу – тропарі і кондаки: Примітка. Порядок співу тропарів і кондаків в 9-ій Марковій главі Типікону про 2 лютого викладається без урахування присвячених храму: тропар воскресний, тропар свята. «Слава» – кондак Тріоді, «І нині» – кондак свята. Згідно із загальним уставом, в храмі святого може співатися тропар і кондак храму. У храмі Господському і Богородиці – тропар воскресний, тропар свята. «Слава» – кондак Тріоді, «І нині» – кондак свята. У храмі святого – тропар воскресний, тропар свята, тропар храму; кондак Тріоді. «Слава» – кондак храму, «І нині» – кондак свята. Прокимен, алилуарій і причасний – воскресний і свята. Примітка. 9-та Маркова глава Типікон за 2 лютого замовчує про Прокимни, алилуарії і причасні свята, але відповідно до загального уставу вони повинні співатися. Апостол і Євангеліє – Неділі про блудного сина. Задостойник свята. Відпуст воскресний: «Христос, що воскрес із мертвих...». [1]. «Полієлей: звичайні два псалми. Також співаємо до них і третій псалом: На ріках вавилонських з Алилуя красним» (Типікон, гл. 49-а,«Неділя, в яку читається священне і святе Євангеліє, притчі про блудного сина»). Примітка. В м’ясопусний тиждень «Алилуя» не співається. Третя кафизма ранньої переноситься на вечірню, не співається міжчасся і молебний канон Пресвятій Богородиці Октоїха на Повечір’ї. Читається Мале повечір’я."}]},
{"date":"02-09","weekday":"понеділок","title":"Віддання свята Стрітення Господнього. Мч. Никифора з Антіохії Сирійської (бл. 257). Прп. Панкратія, ієром., затворника Києво-Печерського, в Дальніх печерах (ХІІІ). Знайдення мощів свт. Інокентія (Кульчицького), єп. Іркутського (1805). Сщмчч. Маркела, єп. Сикелійського, Філагрія, єп. Кіпрського, і Панкратія, єп. Тавроменійського (І).","readings":["1 Ін., 71 зач., II, 18 – III, 10. Мк., 49 зач., XI, 1 – 11."],"notes":"Звершується славослівна служба віддання свята Стрітення Господнього","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає На «Господи, взиваю» стихири свята, глас 1-ий – 6 (кожна стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «Нехай відкриються нині двері небесні...». Входу немає. Прокимен дня. Паремій немає. На стиховні стихири свята, глас 7-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Той, Кого носять херувими і оспівують серафими...». Після Трисвятого – тропар свята, глас 1-ий (один раз). Відпуст: «Христос, істинний Бог наш, що в обіймах праведногоСимеонаноситисьзволиврадинашогоспасіння...»."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї у неділю увечері співається служба мч. Никифора."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава, і нині» – той же тропар. Кафизми 4-та і 5-та. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канон свята з ірмосом на 14 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія свята: «Сушу в глибині землі сонце осяяло колись...». Після 3-ої пісні – сідальний свята, глас 4-ий. «Слава, і нині» – той же сідальний. Після 6-ої пісні – кондак та ікос свята, глас 1-ий. На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспіви свята. (Звершується звичайне кадіння). 1-ий хор співає перший приспів: «Богородице Діво, уповання християн...», і ірмос: «В законі тіні і писань...». 2-ий хор співає другий приспів: «Богородице Діво, світу Блага помічнице...», і той же ірмос. 1-ий хор: «Богоносний Симеоне...», і тропар: «Замість двох горлиць або двох голубів...». 2-ий хор: «Обіймає руками старець Симеон...», і той же тропар. 1-ий хор: «Не старець Мене тримає...», і той же тропар. 2-ий хор: «Кліщі таємничі...», і той же тропар. 1-ий хор: «О дочко Фануїлова!..», І тропар: «Ти дарував мені радість...». 2-ий хор: «Анна цнотлива...», і той же тропар. 1-ий хор: «Незбагненно є...», і той же тропар. 2-ий хор: «Чиста Голубко...», і той же тропар. 1-ий хор: «О Христе, всіх Царю!...», і тропар: «Священноліпно і побожно...». 2-ий хор: «О Христе, всіх Царю!...», і той же тропар. 1-ий хор: «Трисяйне і Триіпостасне Божество...», і той же тропар. 2-ий хор: «О Діво Маріє!..», І той же тропар. Потім обидва хори разом співають 1-ий приспів: «Богородице Діво, уповання християн...», та Ірмос: «В законі тіні і писань...». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – той же світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «На руках старечих...». Велике славослів’я. Після Трисвятого – тропар свята, глас 1-ий (один раз). Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння..»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні свята, пісня 9-та – 6 (з ірмосом). На вході – «Прийдіть поклонімось... Дивний у святих єси...». Після входу – тропар свята. «Слава, і нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос, істинний Бог наш, що в обіймах праведного Симеона носитись зволив ради нашого спасіння..»."}]},
{"date":"02-10","weekday":"вівторок","title":"Сщмч. Харалампія і з ним мчч. Порфирія і Ваптоса та трьох мучениць (202). Прп. Прохора, чудотворця Києво-Печерського, в Ближніх печерах (1107). Мцц. дів Єнафи, Валентини і Павли (308). Блгв. кн. Анни Новгородської (1056). Ікони Божої Матері «Вогневидна».","readings":["1 Ін., 72 зач., III, 10 – 20. Мк., 64 зач., XIV, 10 – 42."],"notes":"Служба сщмч. Харалампія немає святкового знака, звершується разом зі службами Октоїха [А] Служба прп. Прохора чудотворця Києво-Печерського, в Ближніх печерах немає святкового знака, звершується разом зі службами Октоїха [Б] Примітка. Служба одного з рядових святих дня переноситься на Мале повечір’я. [А] НА ВЕЧІРНІ кафизма 6-та На «Господи, взиваю» стихири на 6: Октоїха, глас 2-ий – 3, і священномученика, глас 6-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той же: «Мене пораненого...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава, і нині» – Богородичний: «Все уповання на Тебе покладаю...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря: «До Богородиці».","sections":[{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї співається служба одному рядових святих дня (яка не бралась за вечірнім богослужінням), молебний канон Богородиці з Октоїха не читається."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря: «До Богородиці...». Кафизми 7-ма і 8-ма. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4 і священномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний священномученика, глас 3-ій. «Слава, і нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос священномученика, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха, глас 2-ий: «Предтечу Іоана...». «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава, і нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар священномученика. Кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар священномученика; кондак дня, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар священномученика; кондак дня, кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня. [Б] НА ВЕЧІРНІ кафизма 6-та На «Господи, взиваю» стихири на 6: Октоїха, глас 2-ий – 3, і преподобного, глас 4-ий – 3. «Слава» – преподобного, глас 5-тий: «Хто не здивується твоєму житію...», «І нині» – Богородичний Мінеї, за гласом «Слави»: Вгамуй хвороби...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава» – преподобному, глас 6-ий: «Ченців безліч...», «І нині» – Богородичний за гласом «Слави»: «Ніхто з тих, що приходить до Тебе...» Після Трисвятого – тропар преподобного, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря: «До Богородиці»."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї співається служба одному рядових святих дня (яка не бралась за вечірнім богослужінням), молебний канон Богородиці з Октоїха не читається."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря: «До Богородиці...». Кафизми 7-ма і 8-ма. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4 і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний преподобного, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак преподобного, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха, глас 2-ий: «Предтечу Іоана...». «Слава» – світильний преподобного. «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. Співається стихира преподобного із приспівом: «Прославляться преподобні у славі...1» «Слава, і нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар преподобного, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобного. Кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар преподобного; кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар преподобного; кондак дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"02-11","weekday":"середа","title":"Сщмч. Власія, єп. Севастійського (бл. 316). Блгв. кн. Всеволода, у хрещенні Гавриїла, Псковського (1138). Прав. Феодори, цариці Грецької, що відновила вшанування святих ікон (бл. 867).","readings":["1 Ін., 73 зач., III, 21 – IV, 6. Мк., 65 зач., XIV, 43 – XV, 1."],"notes":"Служба сщмч. Власія, єп. Севастійського, не має святкового знака, звершується разом зі службами Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та На «Господи, взиваю» стихири на 6: Октоїха, глас 2-ий – 3, і священномученика, глас 1-ий – 3. «Слава» – священномученика, глас 4-ий: «Як добрий наставник дітей і вчитель благочестя...», «І нині» – Хрестобогородичний Мінеї, глас той же: «Пречиста, бачачи Христа Людинолюбця...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава» – священномученика, глас 6-ий: «Виріс ти в пості Власію...», «І нині» – Хрестобогородичний Мінеї: «Люди беззаконні...» Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших6 «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-ий (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...». Кафизми 10-та і 11-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4 і священномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – інший кондак священномученика, глас 2-ий; сідальний священномученика, глас 8-ий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос священномученика, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний священномученика, «І нині» – Хрестобогородичний Октоїха: «Біля Хреста стояла...». «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той же. Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Величаємо Тебе...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар священномученика. Кондаки священномученика читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У храмі Господському – тропар дня «Спаси Господи людей Твоїх...», тропар священномученика; кондак священномученика, інший кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси Господи людей Твоїх...», тропар храму, тропар священномученика; кондак дня, кондак священномученика, інший кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси Господи людей Твоїх...», тропар храму, тропар священномученика; кондак дня: «Вознісся на Хрест..», кондак храму, кондак священномученика, інший кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"02-12","weekday":"четвер","title":"Іверської ікони Божої Матері. Свт. Мелетія, архієп. Антіохійського (381). Свт. Олексія, митр. Київського і всієї Руси, чудотворця (1378). Свт. Мелетія, архієп. Харківського (1840). Прп. Марії, званої Марином, та батька її Євгенія (VІ). Свт. Антонія, патр. Константинопольського (895).","readings":["Ран. – Богородиці: Лк., 4 зач., I, 39 – 49, 56.","Літ. – 1 Ін., 74 зач., IV, 20 – V, 21. Мк., 66 зач., XV, 1 – 15.","Богородиці: Флп., 240 зач., II, 5 – 11. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершується полієлейна служба на честь Іверської ікони Божої Матері. Примітка. Полієлейна служба написана за тестами служби на честь Іверської ікони Божої Матері, що подається в Мінеї-Лютий, 12 день.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири Богородиці – на 8 (перша і друга стихири – тричі, а третя – двічі) «Слава, І нині» – Богородиці, глас 8-ий. Вхід. Прокимен дня. Паремії Богородиці – 3. На стиховні стихири Богородиці (зі своїми приспівами), глас 2-ий. «Слава, І нині» – Богородиці, глас 5-ий. Після Трисвятого – тропар Богородиці, глас 1-ий (один раз). Примітка. На службах в честь Богородиці – богородичні не співаються."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в середу увечері співається служби свт. Мелетія, архієп. Антіохійського та свт. Олексія, митрополита Київського без молебного канону Богородиці."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Богородиці, глас 1-ий (двічі). «Слава, і нині» – тропар той же. Кафизми 13-та і 14-та. Малі ектенії. Після 1-ої кафизми – сідальний Богородиц, глас 1-ий. «Слава, і нині» – сідальний Богородиці. Після 2-ої кафизми – сідальний Богородиці, глас 3-ій. «Слава, і нині» – сідальний Богородиці. Полієлей. Величання Богородиці і вибраний псалом. Після полієлею сідальний Богородиці, глас 5-тий. «Славаі нині» – сідальний то й же. Степенна – 1-й антифон 4-го гласу. Прокимен і Євангеліє – Богородиці. Після 50-го псалма: «Слава» – «Молитвами Богородиці...». Стихира Богородиці, глас 6-ий: «Коли прийшов час явлення». Канон Богородиці (ікони) з ірмосом на 14 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний Богородиці. «Слава, і нині» – сідальний то й же. Після 6-ої пісні – кондак та ікос Богородиці. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний Богородиці. «Слава, і нині» – світильний то же. «Все що дише...» і хвалітні псалми. На хвалітніх стихири Богородиці на 4 (перша стихира – двічі) «Слава і нині» – Богородиці. Велике славослів’я. Після Трисвятого – тропар Богородиці, глас 1-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Богородиці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Богородиці на 8: пісня 3-тя – 4 (з ірмосом), і пісня 6-та – 4. На вході – «... Дивний у святих єси...». На практиці співається «...молитвами Богородиці...». Увага! Спів на Літургії «Молитвами Богородиці...» є традицією. За Типіконом і на Богородичні свята має бути приспів «Дивний у святих...». Святі отці – упорядники церковного уставу вбачали у особі Божої Матері воєводу сонму усіх святих. Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар Богородиці. «Слава» – кондак храму, «І нині» – кондак Богородиці. У храмі Богородиці – тропар Богородиці (ікони). «Слава і нині» – кондак Богородиці (ікони). У храмі святого – тропар Богородиці, тропар храму. «Слава» – кондак храму, «І нині» – кондак Богородиці. Прокимен, алилуарій і причасний – Богородиці. Апостол і Євангеліє – дня і Богородиці."}]},
{"date":"02-13","weekday":"п’ятниця","title":"Прп. Мартиніана (V). Прпп. Зої і Фотинії (Світлани) (V). Прп. Євлогія, архієп. Олександрійського (607 – 608). Блгв. кн. Костянтина Острозького (1608). Прп. Стефана, у чернецтві Симеона, царя Сербського, Мироточивого (1200).","readings":["2 Ін., 75 зач., I, 1 – 13. Мк., 68 зач., XV, 22, 25, 33 – 41.","Блгв.: Гал., 213 зач., V, 22 – VI, 2. Мф., 10 зач., IV, 25 – V, 12."],"notes":"Служба благовірного кн. Костянтина Острозького шестирична звершується разом зі службами Октоїха. Примітка. Служба благовірного кн. Костянтина Острозького у Мінеї – Лютий, 2018 року видання, міститься за 26 день лютого.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-та На «Господи, взиваю» стихири на 6: перша і друга стихири – двічі. «Слава» – благовірного, глас 2-ий: «Настав день пам’яті твоєї.», «І нині» – Хрестобогородичний Мінеї, глас той же: «Гроно дозріле...» (див у службі прп. Мартиніана за 13 день лютого). Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава» – благовірного, глас 7-ий: «Земле Волинська...», «І нині» – Хрестобогородичний Мінеї: «Люди беззаконні» (див у службі прп. Мартиніана за 13 день лютого). Після Трисвятого – тропар благовірного, глас 8-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця і Пастиря...»."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в четвер увечері співається служба прп. Мартиніана без молебного канону Богородиці (Октоїха)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар благовірного, глас 8-ий (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця і Пастиря...». Кафизми 19-та і 20-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 4 (ірмоси раз), 2-ий на 4 і благовірного на 6. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний благовірного, глас 7-ий (двічі). «Слава, і нині» – Хрестобогородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос благовірного, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний благовірного, глас 1-ий. «І нині» – Хрестобогородичний Октоїха: «Біля Хреста стояла...». «Хваліте Господа з Небес...» і хвалітні псалми. Стихири «На хваліте» на 4, глас 8-ий. «Слава і нині» – Хрестобогородичний Мінеї. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той же. Після Трисвятого – тропар благовірного, глас 8-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Плід утроби Твоєї...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак благовірного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні на 8: Октоїха на 4, і благовірного 3-тя пісня канону Мінеї на 4. Після входу – тропарі та кондаки: У храмі Господському – тропар дня «Спаси Господи людей Твоїх...», тропар благовірного; кондак благовірного. «Слава» – «Зі святими упокой...», «І нині» – кондак дня «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси Господи людей Твоїх...», тропар храму, тропар благовірного; кондак дня, кондак благовірного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси Господи людей Твоїх...», тропар храму, тропар благовірного; кондак дня: «Вознісся на Хрест..», кондак храму, кондак благовірного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і благовірного. Апостол і Євангеліє – дня і благовірного."}]},
{"date":"02-14","weekday":"субота","title":"Субота м’ясопусна. Пам’ять усіх від віку спочилих православних християн – отців, братів і сестер наших. Прп. Авксентія (бл. 470). Рівноап. Кирила, учителя слов’янського (869). Прп. Ісакія, затворника Києво- Печерського, в Ближніх печерах (бл. 1090). 12-ох греків, будівників соборної Успенської церкви Києво-Печерської лаври (ХІ). Прп. Марона, пустельника Сирійського (ІV). Свт. Авраамія, єп. Каррійського (V).","readings":["Заупокійне: 1 Сол., 270 зач., IV, 13 – 17. Ін., 16 зач., V, 24 – 30.","Ряд.: 1 Кор., 146 зач., X, 23 – 28. Лк., 105 зач., XXI, 8 – 9, 25 – 27, 33 – 36."],"notes":"Звершуємо пам’ять всіх від віку спочилих православних християн, отців і братів наших. Служба за Октоїхом і Тріоддю. Примітка. Аналогічна служба звершується і в Троїцьку батьківську суботу (перед святом П’ятидесятниці). Якщо ж на дні цих Вселенських батьківських субот випаде храмове свято, то співається служба храму, а суботня заупокійна служба звершується тільки в особливих храмах – «гробницях» (порівн.: Типікон, гл. 49, «У суботу м’ясопусну...», 1-е «див») або переноситься на попередні суботу або четвер (порівн.: Типікон, 26-а і 54-а Храмова глава, 3-я Маркова глава за 2 лютого).","sections":[{"svc":"ПОВСЯКДЕННІЙ ВЕЧІРНІ","text":"НА ПОВСЯКДЕННІЙ ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха (мученичі), глас 2-ий – 3 («Ви стастотерпці...»), «Молитвами за на святих мучеників», «Собори мучеників» і Тріоді, глас 8-ий – 3. «Слава» – Тріоді, глас той же: «Плачу і ридаю...», «І нині» – догматик, глас 2-ий: «Минула тінь закону...». Входу немає. Замість прокимна – «Алилуя», на 8-ий глас, із заупокійними стихами – стих 1-ий: «Блаженні, кого обрав і прийняв Ти, Господи, і пам’ять їх з роду в рід»; стих 2-ий: «Душі їх у блаженстві перебуватимуть». «Сподоби, Господи...». Ектенія прохальна: «Доповнимо вечірню...», і голововклонна молитва. На стиховні стихири Октоїха, глас 2-ий (із заупокійними приспівами, див. Тріодь). «Слава» – Тріоді, глас той же, «І нині» – Богородичний Тріоді, глас той же: «Молитвами Матері Твоєї, Христе...». Після Трисвятого – тропар, глас 8-ий: «Глибиною мудрості...». «Слава, і нині» – Богородичний, глас той же: «Тебе твердиню, і пристанище...». Ектенія потрійна: «Помилуй нас, Боже...», і відпуст: «Христос, істинний Бог наш...»."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї можуть співатися служби на вибір: 1) рівноапостольного Кирила, учителя слов’янського; 2) преподобного Авксентія; 3) преподобного Ісаакія, затворника Печерського (всі служби з цього дня) [1], а також канон мертвих Октоїха (без ірмосів) [2]. Після «Достойно» – кондак, глас 8-ий: «Зі святими упокой...». Примітка. Спочатку співаються канони рядових святих, а потім канон з Октоїха – це особливість суботи, коли молитви святого читаються перед молитвами дня [3]. В 9-тій Марковій главі Типікону від 24 лютого міститься вказівка, що заупокійний канон потрібно читати першим, а тоді святим. Примітка. Якщо після відпусту вечірні служилась панахида, то канон спочилим чергового гласу на повечір’ї не співається, з огляду на те, що він вже проспіваний на панахиді, а звершуються служби рядових святих [4]."},{"svc":"РАННІЙ","text":"НА РАННІЙ замість «Бог Господь» – «Алилуя» [5] на глас 8-ий, із заупокійними стихами – стих 1-ий: «Блаженні, кого обрав і прийняв Ти, Господи»; стих 2-ий: «Пам’ять їх з роду в рід»; стих 3-ій: «Душі їх у блаженстві перебуватимуть». Тропар, глас 8-ий: «Глибиною мудрості...» (двічі). «Слава, і нині» – Богородичний, глас той же: «Тебе твердиню...». Кафизма 16-та. Мала ектенія (звичайна, а не заупокійна). Сідальні Октоїха [6], зі стихами сідальних (1 і 2 кафизми) «Слава, і нині» – Богородичний після 2-ої кафизми, або Богородичний гласу, після 1-ої кафизми. Кафизма 17-та, розділена на дві статті, співається, за Уставом, на 5-ий глас, без «заходу» («Господи, помилуй» (3), «Слава, і нині»); до кожного стиха 1-ої статті співається приспів: «Благословен єси, Господи, навчи мене заповітів Твоїх», до стихів 2-ої статті приспів: «Спасе, спаси мене». Примітка. Згідно з поширеною практикою, стихи 17- ої кафизми читаються священнослужителями. З початком співу кафизми священик з дияконом виходять через північні і південні врата на середину храму до тетраподу (панахидний столу), священник (зі свічкою в руці) читає стихи псалмів, а співаки тихо співають приспів: на 1-ій статті – «Благословен єси, Господи», на 2-ій статті – «Спасе, спаси мене». Диякон в цей час безперервно кадить тетрапод. Примітка. У парафіяльних храмах існує практика виходу на читання 17-ої кафизми і на малу заупокійну ектенію після 6-ої пісні канону через царські врата. Перша стаття починається співом: «Блаженні непорочні...». Після 91-го стиха хористи співають (із приспівом) 92-ий і 93-ій стихи: «Коли б не закон був утіхою мені...», «Повік не забуду повелінь Твоїх, бо ними Ти оживив мене» (цих два стихи співаємо по тричі) [7]. Потім виголошується мала заупокійна ектенія (за звичаєм, з кадилом): «Ще і ще...», хор: «Господи, помилуй» (один раз); «Ще молимось за упокоєння душ спочилих рабів Божих праотців, отців, і братів наших, що тут лежать, і повсюди православних християн, і за відпущення їм усякої провини вільної невільної», хор: «Господи, помилуй» (один раз); «Щоб Господь Бог оселив душі їх...», хор: «Господи, помилуй» (один раз); «Милості Божої...», хор: «Подай, Господи». «Господу помолимось», хор тихо: «Господи, помилуй» (40). Священник таємно читає молитву: «Боже духів і всього тілесного...». Виголос: «Бо Ти є Воскресіння...». Хор: «Амінь». Після виголосу: «Бо Ти є Воскресіння...» правий хор починає співати другу статтю: «Твій я...». Священник з дияконом (або диякон) звершують, за традицією, мале кадіння (тетрапод навкруги, іконостас, хори, народ, місцеві ікони іконостас, тетрапод спереду, тобто із західної сторони). Останні стихи: 175-ий і 176-ий (також цих два стихи співають по тричі) і відразу – тропарі після Непорочних, глас 5-ий: «Собор Святих знайшов...», під час яких священик з дияконом звершують, за звичаєм, повне кадіння всього храму. Потім виголошується мала заупокійна ектенія (за звичаєм, з кадилом;). Після виголосу співається сідальний, глас 5-ий: «Упокой, Спасе наш...». «Слава, і нині» – Богородичний, глас той же: «Христе Боже, що від Діви...» [8]. Псалом 50-ий. Канони: храму з ірмосом на 6 (ірмоси по двічі) і Тріоді на 8. Біблійні пісні «Господеві співаймо...». Катавасія Тріоді: «Пісню возсилаємо...». Співається 2-а пісня канону, на 8 (Ірмос двічі, тропарі на 6, приспів до тропарів: «Упокой, Господи, душі спочилих рабів Твоїх – «Слава» і «І нині»). В кінці цієї пісні катавасія – той же ірмос. Після 3-ої пісні – мала ектенія (звичайна, а не заупокійна). Сідальний Тріоді, глас 5-ий. «Слава» – той же сідальний, «І нині» – Богородичний Тріоді, глас той же. Після 6-ої пісні – мала заупокійна єктенія (див. Після 1-ої статті 17-ої кафизми). Кондак, глас 8-й: «Зі святими упокой...», та ікос, глас той же. Примітка. За традицією, під час співу катавасії 6-ої пісні, через північні і південні (або через царські) врата священик з дияконом виходять до тетраподу. Біля тетраподу виголошується мала заупокійна ектенія (за звичаєм, з кадилом). Під час співу кондака «Зі святими упокой...» ієрей з дияконом (або диякон) звершують мале кадіння (навколо тетраподу, іконостас і присутніх). Після співу кондака та ікоса священик з дияконом повертаються до вівтаря. Після ікосу читається синаксар: «Не згадуй гріхів померлих...» На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» зазвичай не співається [9]. Мала ектенія (звичайна, а не заупокійна). Світильний Тріоді. «Слава» – інший світильний Тріоді, «І нині» – Богородичний Тріоді. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 8-ий – 4. «Слава» – Тріоді, глас 2-ий: «Як цвіт в’яне...», «І нині» – Богородичний Тріоді, глас той же: «Радуйся, Маріє Богородице...». «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. Благальна ектенія. На стиховні стихири Октоїха (запокійні) чергового гласу (другого гласу) із заупокійними стихами. «Слава» – Тріоді, глас 6-й: «Хворобою стало для Адама...», «І нині» – Богородичний Тріоді, глас той же: «Ти єси Бог наш...». Після Трисвятого – тропар, глас 8-й: «Глибиною мудрості...». «Слава, і нині» – Богородичний, глас той же: «Тебе твердиню...». Ектенія сугуба: «Помилуй нас, Боже...». Диякон: «Премудрість». Хор: «Благослови». Священник: «Сущий благословенний...». Хор: «Утверди Боже...». Читається 1-ший час, і відпуст: «Христос, істинний Бог наш...». Примітка. На першому часі після молитви «Христе Світло істинне» співається «Непереможній Воєводі...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар: «Глибиною мудрості...». Кондак: «Зі святими упокой...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні Тріоді на 8: пісня 3-тя (з ірмосом) – 4 і 6-та – 4. На вході – «Прийдіть поклонімось... Дивний у святих єси...». Після входу – тропар, глас 8-ий: «Глибиною мудрості...». «Слава» – кондак, глас той же: «Зі святими упокой...», «І нині» – Богородичний, глас той же: «Тебе твердиню..». Прокимен заупокійний, глас 6-ий: «Душі їх у блаженстві перебуватимуть», із стихом: «До Тебе, Господи, підношу душу мою...». Апостол – дня і за упокій. Алилуарій, глас 6-ий: «Блаженні, кого обрав...», зі стихом. Євангеліє – дня і за упокій. Після «Особливо за Пресвяту, Пречисту...» співається «Достойно є». Причасний: «Блаженні, кого обрав...». Відпуст: «Христос, істинний Бог наш...». [1] Див .: Богослужбовий устав... [2] Канон Спочилих, або заупокійний, запозичується з Октоїха з ранньої суботи поточного гласу (2-ий канон). [3] Однак щодо літургійних читань періоду співу Тріоді порядок інший – від Неділі митаря і фарисея і до Неділі всіх святих по суботах Апостол і Євангеліє читаються так: спочатку читання дня, потім святого (див. Типікон, гл. 49, 5-е «див»). [4] Служби рядових святих можуть бути звершені заздалегідь – на повечір’ї попередніх днів м’ясопусної седмиці. [5] «Алилуя» зазвичай співається тричі по тричі. [6] «Богослужбовий устав» [7] Після першої статті не вимовляється: «Слава, і нині», але співаються з приспівом заключні два стихи 1-ої статті. [8] Священнослужителі йдуть до вівтаря. [9] Спів «Достойно є» допустимий, оскільки в аналогічній службі Троїцької батьківської суботи в Квітній Тріоді «Достойно є» зазначено співати."}]},
{"date":"02-15","weekday":"неділя","title":"Неділя м’ясопусна, про Страшний суд. Глас 3-й. Ап. від 70-х Онисима (бл. 109). Прп. Пафнутія, затворника Києво-Печерського, в Дальніх печерах (ХІІІ). Прп. Пафнутія і дочки його Єфросинії (V). Прп. Євсевія, пустельника Сирійського (V). Віленської (перенесення у Вільно в 1495 р.) і Далматської (1646) ікон Божої Матері.","glas":3,"readings":["Ран. – Єв. 3-тє, Мк., 71 зач., XVI, 9 – 20.","Літ. – 1 Кор., 140 зач., VIII, 8 – IX, 2. Мф., 106 зач., XXV, 31 – 46."],"notes":"Заговини на м’ясо. Воскресна служба Октоїха звершується у поєднанні зі службою Тріоді. Служба апостола Онисима переноситься на Мале повечір’я 16 лютого. За уставом перед Всенічною необхідно звершувати 9-тий час і Малу вечірню. Мала вечірня служиться лише за Октоїхом.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири, глас 3-ій – 4. (перша стихира – двічі (на початку, та в кінці як четверта). «Слава, і нині» – богородичний (догматик малої вечірньої), глас 3-ій: «Превелике чудо! ...» Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. Перша стихира недільна, а інші стихири Пресвятої Богородиці зі своїми приспівами. На стиховні стихири глас 3-ій: «Стражданням Твоїм Христе...» із своїми приспівами. «Слава, і нині» – Богородичний, глас то й же: «Через Тебе, Пречиста Маріє...». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар недільний, глас 3-ій «Нехай веселяться небесні...» «Слава, і нині» – Богородичний за гласом тропаря: «Тебе оспівуємо...». Після співу тропаря з богородичним священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, що воскрес із мертвих, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 3-ій – 6, Тріоді, глас 6-ий – 4 . «Слава» – Тріоді, глас 8-ий: «Коли поставлять престоли...», «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Вхід. Прокимен дня. На літії стихира храму, «Слава», Тріоді, глас 7: «Господні розуміли заповіді...», «І нині» – Богородичний Тріоді за гласом стихири «Під покров Твій Владичице...». На стиховні стихири воскресні, глас 3-ій. «Слава» – Тріоді, глас 8: «Горе мені, затьмарена душа...» – «І нині» – Тріоді, глас той же: «Безневістна Діво...», Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 3-ій (двічі). «Слава, і нині» – Богородичний воскресний, глас той же: «Тебе оспівуємо...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні воскресні. Полієлей. До двох полієлейних псалмів приєднується псалом 136-й: «На ріках вавилонських...» «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє воскресне 3-тє. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – Тріоді, глас 8-ий: «Покаяння відкрий мені двері...», «І нині» – Богородичний Тріоді, глас той же: «На стежки спасіння...». Глас 6-ий: «Помилуй мене, Боже...», і стихира Тріоді, глас той же: «Множество вчинених...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Богородиці (Октоїха) на 2, Тріоді на 8. Біблійні пісні «Співаймо Господеві...». Катавасія Тріоді «Помічник і покровитель...». Після 3-ої пісні – Сідальний Тріоді, глас 6-ий: «Роздумую про страшний день...». «Слава» – Тріоді, глас то й же: «В долині плачу...». «І нині» – Богородичний Тріоді, глас той же: «Надіє світу...». Після 6-ої пісні – кондак та ікос Тріоді, глас 1-ий. Читаємо синаксар зі стихом: «Землю коли сядеш судити будучи Суддею...». На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 3-ій, світильний Тріоді «Страшний день суду...». «Слава» – інший світильний Тріоді: «Ось настає день..», «І нині» – Богородичний Тріоді: «Роздумуючи про час випробування...». «Все що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 3-ій – 5 (чотири воскресні і Східна одна), і Тріоді, глас 6-ий, глас 8-ий і глас 1-ий – 4. Примітка. Перші 6 стихир співаються із приспівами хвалитніх псалмів, а останні три із додатковими приспівами: 1) «Славитиму Тебе Господи, всім серцем моїм, розповідатиму про всі чудеса Твої»; 2) «Буду веселитися і хвалитися Тобою, буду співати імені Твоєму Всевишній»; 3) «Воскресни Господи, нехай піднесеться рука Твоя, не забуть убогих Твоїх до кінця». «Слава» – Тріоді, глас 1-ий: «Заздалегідь очистьмо себе браття...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Днесь спасіння...». Перед 1-м часом на «Слава, і нині» – стихира євангельська 3-тя. Примітка. В монастирях після 1-го часу читається огласительне слово прп. Федора Студита."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. Кондак Тріоді."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні на 10: гласу – 6 і Тріоді, пісня 3-я – 4. Після входу – тропарі та кондаки: У храмі Господському – тропар воскресний. «Слава, і нині» – кондак Тріоді. У храмі Богородиці – тропар воскресний, тропар храму. «Слава» – кондак Тріоді. «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму. «Слава» – кондак храму. «І нині» – кондак Тріоді. Прокимен, алилуарій Апостол і Євангеліє – Неділі про М’ясопусної. Причасний: «Хваліте Господа...» і «Радуйтеся праведні...». Примітка. Починаючи з понеділка і до Великодня м’ясо в їжу не вживаються."}]},
{"date":"02-16","weekday":"понеділок","title":"Тиждень сирний (масляний) – загальниця. Сщмчч. Памфіла, пресвітера, Валента (Уалента), диякона, мчч. Павла, Порфирія, Селевкія, Феодула, Юліана, Самуїла, Іллі, Даниїла, Єремії, Ісаї (307 – 309). Мчч. перських в Мартирополі (ІV). Прп. Маруфа, єп. Месопотамського (422).","readings":["3 Ін., 76 зач., I, 1 – 15. Лк., 96 зач., XIX, 29 – 40; XXII, 7 – 39."],"notes":"Впродовж усього тижня дозволяється вживання молока та яєць. Кожне богослужіння сирного тижня є підготовчим до Великого посту. Отже, служби цього тижня будуть звершуватися за Октоїхом, Мінеєю та Постовою Тріоддю. Примітка. З цього дня до суботи 6-го тижня Великого посту стихири на стиховні Октоїха на вечірній і ранній замінюються самогласними стихирами дня із Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» на 6 стихири Октоїха, глас 3-ій – 3 і мч. Памфіла – 3. «Слава, і нині» – Богородичний Мінеї: «Жезлом Твого заступництва»...» Входу немає. Прокимен дня. Після прокимна читець читає одразу «Сподоби Господи...», далі слідує прохальна ектенія та головоприклонна молитва. На стиховні стихири Тріоді, глас 8-ий (зі звичайними приспівами). «Слава, і нині» – Богородичний Тріоді, глас той же: «Небесні оспівують Тебе...». Після Трисвятого – тропар мучеників загальний глас 4-ий: «Мученики Твої Господи...» (В службі св. мч. Памфіла відсутній тропар) «Слава, і нині» – Богородичний за гласом тропаря: «Вихованій у храмі...». Потрійна ектенія: «Помилуй нас Боже...» і відпуст. Примітка. Якщо вечірня поєднується із ранньою то, після співу «Утверди Боже...» священик промовляє виголос ранньої «Слава Святій...» далі читець читає «Слава ввишніх Богу...» і шестопсалміє."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в неділю увечері співається служба апостолу Онисиму (з 15 лютого) без молебного канону Богородиці Октоїха."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучеників, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря: «Вихованій у храмі...». Кафизми 4-та і 5-та. Малих ектеній немає. Після першої кафизми – Сідальні Октоїха, глас 3-ій. І читаємо слово свт. Василія Великого (Див. Постова Тріодь) Після другої кафизми – (мається на увазі порядок кафизм на Ранній) – Сідальний Тріоді, глас 1-ий. «Слава і нині» – Богородичний Тріоді, глас то й же. 50-го псалом. Канони: 1-ша, 8-ма, 9-та пісні: канон мучеників із ірмосом на 6 (ірмос один раз) і Трипіснеці Тріоді на 8; 3-тя, 4-та, 5-та, 6-та і 7-ма пісні – Октоїха 1-ий (ірмос один раз) на 6, 2-ий канон Октоїха 4, і мучеників на 4. Біблійні пісні «Господеві співаймо...». Катавасія – після 1-шої, 8-ої, 9-тої – ірмоси другого трипіснеця Тріоді; після 3-ої та 6-ої – ірмоси канону мучеників. Після 3-ої пісні – сідальний мучеників, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак мучеників, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» співається. Екзапостиларій Октоїха «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з небес..» і хвалітні псалми. Читець виголошує «Слава Тобі, що показав нам світло» і читає повсякденне славослів’я. Слідує прохальна ектенія. На стиховні стихири Тріоді, глас 3-ій. «Слава і нині» – Богородичний Тріоді, глас той же: «Без сімені зачала...». «Благо є» (один раз). Після Трисвятого – тропар мучеників, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря: «Богородице Ти вища від усіх творінь...». Потрійна ектенія: «Помилуй нас Боже... перший час приєднується до ранньої."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар мучеників загальний. Кондак мучеників зі рядової служби Мінеї."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. На вході – «Прийдіть поклонімось... Дивний у святих єси...». Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар мучеників (загальний), кондак дня, кондак мучеників «Слава» – «Зі святими упокой..», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар мучеників; кондак дня, кондак храму кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня. Примітка. В понеділок сирного тижня споживаємо двічі на день сир і яйця (див. Типікон, глава 49)."}]},
{"date":"02-17","weekday":"вівторок","title":"Вмч. Федора Тирона (бл. 306). Прп. Федора, мовчальника Києво-Печерського, в Дальніх печерах (ХІІІ). Прав. Маріамни, сестри ап. Филипа (І). Знайдення мощів мч. Мини Калікелада (867 – 889).","readings":["Іуд., 77 зач., I, 1 – 10. Лк., 109 зач., XXII, 39 – 42, 45 – XXIII, 1.","Вмч.: 2 Тим., 292 зач., II, 1 – 10. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"Служба вмч. Федора Тирона шестирична, звершується разом зі службою Октоїха і Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-та. На «Господи, взиваю» стихири на 6: преподобного, глас 2-ий – 3, глас 4-ий – 3. «Слава» – преподобного, глас 6-ий: «Освячення дар...». «І нині» – Богородичний Мінеї за гласом слави: «Ніхто із тих...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 8-ий. «Слава, – преподобного, глас 8-ий : «Страдницькою мужністю..». «І нині» – Богородичний Тріоді, глас той же: «Преславну і Пречисту Богородицю...». Після Трисвятого – тропар преподобного, глас 2-ий: «Великої віри...». «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тобою Богородице Приснодіво..»"},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 2-ий: «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тобою Богородице Приснодіво...». Кафизми 7-ма і 8-ма. Малих ектеній немає. Після першої кафизми – сідальні Октоїха, глас – 3-тій. Після другої кафизми – сідальні Тріоді, глас 8-ий. Читання повчання свт. Василія Великого «Слово про подяку». Примітка. «Слово про подяку» знаходиться у книзі Святитель Василій Великий. Творіння . Т-1, книга 2. – К. 2010 – с. 31 1. Псалом 50-ий. Канони: 1-ша, 3-тя, 4-та, 5-та, 6-та і 7-ма пісні – Октоїха 1-го канону із ірмосом на 6 (ірмос один раз) 2-го на 2 , і преподобного на 6. 2-га пісня: спочатку співається ірмос 1-го трипіснеця, а в кінці на катавасію ірмос 2-го трипіснеця, глас 2-ий. приспів до тропарів: «Слава Тобі Боже наш, слава Тобі...», а до богородичного 1-го трипіснеця: «Пресвята Богородице спаси, нас». 8-ма та 9-та пісні: канон преподобного із ірмосом на 6 (ірмос один раз) і Трипіснеці Тріоді на 8; Біблійні пісні «Співаймо Господеві...». Катавасія – після 2-гої, 8-ої, 9-тої – ірмоси другого трипіснеця Тріоді; після 3-ої і 6-ої – ірмоси канону преподобного. Після 3-ої пісні – сідальний преподобного, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос преподобного, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» співається. Світильний Мінеї. «Слава, і нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 3-ій. «Слава, і нині» – Богородичний Тріоді, глас той же: «Богородице, Заступнице всіх...». Після Трисвятого – тропар преподобного, глас 2-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ зображальні. Блаженні: на 8: Октоїха на 4 і преподобного пісня 3-тя на 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар преподобного; кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар преподобного; кондак дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"02-18","weekday":"середа","title":"Свт. Лева, папи Римського (461). Свт. Агапіта, спов., єп. Синадського (ІV). Свт. Флавіана, спов., патр. Константинопольського (449 – 450). Прп. Косми Яхромського (1492). ЛІТУРГІЯ У СЕРЕДУ СИРНОГО ТИЖНЯ НЕ ЗВЕРШУЄТЬСЯ","notes":"На 6-му часі: Іоїл. II, 12 – 26. На веч.: Іоїл. III, 12 – 21. Служба свт. Лева без святкового знаку, звершується разом зі службами Октоїха та Тріоді. Починаючи з вечірні, служби відправляються подібно до великопостових. Наприкінці вечірні, великого повечір’я, опівнічної, ранньої, кожного часу, зображальних – молитва прп. Єфрема Сиріна з поклонами.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 3-ій – 3 і святителя, глас глас 8-ий – 3. «Слава і нині» – Хрестобогородичний Мінеї, глас той же: Агниця, коли побачила...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 1-ий (зі звичайними приспівами). «Слава і нині» – Тріоді (Стихири на стиховні святителю Леву в Мінеї відсутні). Після Трисвятого – тропарі, глас 4-ий: «Богородице Діво...» (поклін). «Слава» – «Хрестителю Христів...» (поклін), «І нині» – «Моліться за нас...» (поклін), «Під Твою милість...» (без поклону). Читець: «Господи, помилуй» (40), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник: «Сущий благословенний...». Читець: «Амінь». Молитва: «Небесний Царю...». Священник – молитву прп. Єфрема Сиріна: «Господи і Владико...» (з поділом на три частини і з великим поклоном після кожної), потім 12 малих поклонів з молитвою: «Боже, очисти мене грішного», і знову один великий поклін в кінці молитви: «Господи і Владико...» (без поділу на частини). Читець: Трисвяте по «Отче наш». Після «Отче наш» священник – виголос. Читець: «Амінь», «Господи, помилуй» (12). Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник творить великий відпуст. Примітка. Земні поклони священник творить на амвоні перед Царськими вратами. Читається ВЕЛИКЕ ПОВЕЧІР’Я з поклонами (на повечір’ї спів всюди замінюється читанням). Після «Достойно...» і Трисвятого «Господи Сил, будь з нами...» не співається, як у Великий піст, а виконуються тропарі з малого повечір’я, а саме: У храмі Господському – денний тропар: «Спаси, Господи, людей Твоїх...». «Боже отців наших...», «Ти, що у всьому світі...». «Слава» – «Зі святими упокой...», «І нині» – «Молитвами, Господи...». У храмі Богородиці і святого – денний тропар: «Спаси, Господи...», тропар храму. «Боже отців наших...», «Ти, що у всьому світі...». «Слава» – «Зі святими упокой...», «І нині» – «Молитвами, Господи...». Читець: «Господи, помилуй» 40 разів. Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священик – виголос: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з 16 поклонами). Читець: «Амінь». Кінцеве Трисвяте. Після «Отче наш» Священник – виголос. Читець: «Амінь», «Господи, помилуй» (12). Молитви: «Непорочна, Пречиста...», «І дай нам, Владико...», «Преславна Приснодіво...», «Уповання моє...». Священник: «Слава Тобі, Христе Боже...». Хор або читець: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник – відпуст малий (але не «Владико Многомилостивий...»). Звичайне прощення від настоятеля і ектенії: «Помолимось за Блаженнійшого Владику...», в кінці якої Священник промовляє: «Промовмо і за себе самих». Хор: «Господи, помилуй» (тричі). Священник: «Молитвами святих отців наших...». Хор: «Амінь». ПОЛУНОШНИЦЯ повсякденна з її «поклонами» і молитвою прп. Єфрема Сиріна (з 16-ма поклонами)."},{"svc":"РАННІЙ","text":"НА РАННІЙ після виголосу «Благословенний Бог наш...» – Трисвяте. Після «Отче наш» Священник – виголос: «Бо Твоє є Царство...». Читець: «Амінь», «Господи, помилуй» (12), «Слава, і нині», «Прийдіть, поклонімось...», псалми 19- ий та 20-ий та інше за чином (під час читання двохпсалмія священник звершує повне кадіння храму при закритих царських вратах). Замість «Бог Господь» – «Алилуя» на глас Октоїха (в даному випадку 3-ій). Троїчні гласу (як під час Великого посту). Кафизми 10-а і 11-а. Малих ектеній немає. Після першої кафизми – сідальні Октоїха, глас 2-ий. Після другої кафизми – сідальні Тріоді, глас 2-ий. Читається повчання свт. Василія Великого про піст «Утішайте, тішайте...» (Постова Тріодь). Псалом 50-ий. Біблійні пісні «Господеві співаймо...». Пісня 1-ша – Октоїха 1-ий канон [1] зі ірмосом, без мученичних, на 4 (Ірмос раз), Мінеї (святителя) на 6 (без ірмосів, пісня 1-а і 3-я), Тріоді повний канон на 4 (без ірмоса, пісня 1-а). Пісня 3-тя – Тріоді повний канон з ірмосом на 6 (Ірмос раз), трипіснеці Тріоді на 8 (без ірмосів) [2]. На катавасію – ірмос 2-го трипіснеця, глас 2-ий: «Неплідний мій розум...». Після 3-ої пісні – мала ектенія; сідальний святителя, глас 3-ій. «Слава, і нині» – Хрестобогородичний Мінеї, глас той же. Пісня 4-а – Октоїха 1-ий канон з ірмосом на 6 (Ірмос раз), Мінеї (святителя) на 4 (без ірмосу, пісня 4-а), Тріоді повний канон на 4 (без ірмоса, пісня 4-а). Пісня 5-а – Октоїха 1-ий канон з ірмосом на 6 (Ірмос раз), Мінеї (святителя) на 4 (без ірмосу, пісня 5-а), Тріоді повний канон на 4 (без ірмосу, пісня 5-а). Пісня 6-а – Октоїха 1-ий канон з ірмосом, без мученичних, на 4 (Ірмос раз), Мінеї (святителя) на 6 (без ірмосів, пісня 6-а і 8-а), Тріоді повний канон на 4 (без ірмоса, пісня 6-а). На катавасію – ірмос повного канону Тріоді, глас 4-ий: «Як пророка Іону...». Після 6-ої пісні – мала ектенія; кондак та ікос святителя, глас 3-ій. Пісня 7-а – Октоїха 1-ий канон з ірмосом, без мученичних, на 4 (Ірмос раз), Мінеї (святителя) на 6 (без ірмосів, пісня 7-а і 9-а), Тріоді повний канон на 4 (без ірмосу, пісня 7-а). Пісня 8-а – Тріоді повний канон з ірмосом на 6 (Ірмос раз), трипіснеці Тріоді на 8 (без ірмосів). «Хвалимо, благословимо...». На катавасію – ірмос 2-го трипіснеця, глас 2-ий: «В купині Мойсею Діви чудо...». На 9-ій пісні співаємо «Чеснішу». (Звершується звичайне кадіння). Пісня 9-ої – Тріоді повний канон з ірмосом на 6 (Ірмос раз), трипіснець Тріоді на 8 (без ірмосів). На катавасію – ірмос 2-го трипіснеця, глас 2-ий: «Пречудесно плоттю зачавши...». Після 9-ої пісні співається «Достойно є». Мала ектенія. Світильний Троїчний гласу (як під час Великого посту). «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 1-ий (з приспівами звичайними). «Слава, і нині» – Хрестобогородичний Тріоді, глас той же. «Благо є...» (один раз) [3]. Трисвяте. Після «Отче наш» Священник – виголос: «Бо Твоє є Царство...». Після виголосу промовляють тропар: «Стоячи у храмі слави Твоєї...». «Господи, помилуй» (40), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник: «Сущий благословенний Христос...». Читець: «Амінь». Молитва: «Небесний Царю...». Священник – молитву прп. Єфрема Сиріна (з 16-ма поклонами). Читець: «Амінь», і відразу (без відпусту ранньої) – 1-ий час. Примітка. На часах кафизми не читаються. Ударів на кожному часі в дзвін, як це прийнято під час Великого посту, немає. 1-ИЙ ЧАС. «Прийдіть, поклонімось...» (тричі) і звичайні псалми. За великопостовим чином, читається (але не співається) тропар: «Зранку вислухай...» зі своїми стихами (стих 1-ий: «Вислухай Господи слова мої...», і стих 2-ий: «Бо до Тебе помолюся...»). «Слава, і нині» – Богородичний часу: «Як назвемо Тебе...». «Стопи мої направ...», «Нехай сповняться уста мої...», Трисвяте. Після «Отче наш» Священник – виголос. Читець – тропар: «Скоро поспіши...». «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з 16-ма поклонами). Читець: «Амінь». Кінцеве Трисвяте. Після «Отче наш» Священник – виголос. Читець: «Амінь», «Господи, помилуй» (12). Священник: «Христе, Світло Істинне...». Хор (за звичаєм): «Непереможній Воєводі...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст та многоліття. Виходимо в притвор і звершуємо звичайну літію за спочилих. 3-ІЙ ЧАС. Священник в єпитрахилі, перед царськими вратами (завіса не відкривається), зробивши три поясних поклони, виголошує виголос: «Благословен Бог наш...». Читець: «Амінь», «Слава Тобі, Боже наш...» та інша послідовність 3-го часу, як зазвичай. За великопостовим чином, читається (але не співається) тропар: «Господи, Ти, що Пресвятого Твого Духа...» зі своїми стихами (стих 1-ий: «Серце чисте сотвори в мені, Боже...», і стих 2-ий: «Не відкинь мене від лиця Твого...»). «Слава, і нині» – Богородичний часу: «Богородице, Ти єси виноградна лоза істинна...». «Господь Бог благословенний...», Трисвяте. Після «Отче наш» Священник – виголос. Читець – тропар: «Благословен єси, Христе Боже наш...», «Слава» – інший тропар, «І нині» – Богородичний: «Надіє і заступництво...». «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з 16 поклонами). Читець: «Амінь». Молитва: «Владико Боже...», і починається 6-ий час. 6-ИЙ ЧАС. «Прийдіть, поклонімось...» (тричі) і звичайні псалми. За великопостовим чином, читається (але не співається) тропар: «Ти, що в шостий день же і годину...» зі своїми стихами (стих 1-ий: «Вислухай, Боже, молитву мою...», і стих 2-ий: «Я до Бога взиваю...»). «Слава, і нині» – Богородичний часу: «Через превеликі гріхи наші сміливості не маємо...». Читець – тропар пророцтва (Тріоді), глас 3-ій: «Царю Святий...», «Слава, і нині» – той же тропар. Священник (або диякон): «Будьмо уважні». Читець – прокимен Тріоді, глас 6-ий: «Спаси, Господи, людей Твоїх...»; стих: «До Тебе, Господи, взиваю...» [4]. Священник (або диякон): «Премудрість». Читець: «Пророцтва Іоїля читання». Священник (або диякон): «Будьмо уважні». Читець читає Паремію Тріоді. Після закінчення читання Священник (або диякон): «Будьмо уважні». Читець – прокимен Тріоді, глас 7-ий: «Господь кріпость людям Своїм дасть...»; стих: «Принесіть Господеві, сини Божі...». Після співу прокимна читець: «Скоро пошли нам милосердя Твоє, Господи...», Трисвяте. Після «Отче наш» Священник – виголос. Читець – тропар: «Спасіння вчинив Ти...», «Слава» – інший тропар: «Пречистому Твоєму Образові...», «І нині» – Хрестобогородичний: «Препрославлена Ти, Богородице Діво...». «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Священник: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з 16-ма поклонами). Читець: «Амінь». Молитва: «Боже і Господи Сил...», і починається 9-тий час. 9-ИЙ ЧАС. «Прийдіть, поклонімось...» (тричі) і звичайні псалми. За великопостовим чином, читається (але не співається) тропар: «Ти, що о дев’ятій годині...» зі своїми стихами (стих 1-ий: «Нехай наблизиться молитва моя...», і стих 2-ий: «Нехай дійде благання моє...»). «Слава, і нині» – Богородичний часу: «Благий, що ради нас народився від Діви...». «Не залиш нас до кінця...», Трисвяте. Після «Отче наш» Священник – виголос. Читець – тропар: «Побачивши Начальника життя, що на хресті висів, розбійник мовив...», «Слава» – інший тропар: «Посеред двох розбійників...», «І нині» – Хрестобогородичний: «Агнця, і Пастиря...». «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з трьома великими поклонами). Читець: «Амінь». Молитва: «Владико, Господи Ісусе Христе, Боже наш...», і починаються зображальні. (За традицією, відкривається завіса Царських врат). ЗОБРАЖАЛЬНІ читаються: «Благослови, душе моя, Господа...», «Слава» – «Хвали, душе моя, Господа...», «І нині» – «Єдинородний Сину...». Блаженні без співу: «У Царстві Твоїм...». «Слава, і нині» – «Пом’яни нас, Господи...», «Пом’яни нас, Владико...», «Пом’яни нас, Святий...», «Хор Небесний...», «Приступіть до Нього...», «Хор Небесний...». «Слава» – «Хор святих Ангелів...», «І нині» – «Вірую...», «Полегши, відпусти, прости...», «Отче наш». Священник – виголос. Читець: «Амінь», і читає кондаки. Кондаки: У храмі Господському – кондак денний, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». У храмі Богородиці – кондак денний, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – кондак денний, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Читець: «Господи, помилуй» (40). «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Священник: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з 16-ма поклонами). І відразу починається ВЕЧІРНЯ (славослівна св. благовірному князю Ярославу Мудрому) (служба перенесена з п’ятниці на четвер). Читець: «Амінь» [5]. «Прийдіть, поклонімось...» (тричі), 103-ій псалом. Велика ектенія. Читається 12-а кафизма, після якої – мала ектенія. Примітка. Є багато видів славослівних богослужінь. Загалом їх поділяють на три типи. У більшості випадків славослівних служб святим належать до типу, коли вони поєднуються із Октоїхом. Отож саме перший тип є схемою для славослівної служби св. Ярославу Мудрому. На «Господи, взиваю» стихири на 6: благовірного, глас 6-ий – 6 (див. 5 березня – Мінея – березень, частина І). «Слава» – благовірному, глас 6-ий: «Хоч і на небесах...», «І нині» – Догматик: «Хто тебе не ублажить...». Входу немає. «Світло Тихе». Диякон (або Священник) виголошує (у вівтарі): «Будьмо уважні». Священник: «Мир всім» [6]. Читець: «І духові твоєму». Диякон (або Священник): «Премудрість. Будьмо уважні». Читець – прокимен Тріоді (дня), глас 5-ий: «Боже, в ім’я Твоє спаси мене...»; стих: «Боже, вислухай молитву мою...». Диякон (або Священник): «Премудрість». Читець: «Пророцтва Іоїля читання». Диякон (або Священник): «Будьмо уважні». Читець читає Паремію Тріоді. Диякон (або Священник): «Будьмо уважні». Читець – прокимен Тріоді, глас 6-ий: «Нехай надію покладає Ізраїль на Господа...»; стих: «Господи, не підносилось серце моє...». «Сподоби, Господи...». Ектенія прохальна: «Доповнімо вечірню молитву...», і голововклонна молитва. На стиховні стихири Тріоді, глас 3-ій (з приспівами звичайними). «Слава, і нині» – Богородичний Тріоді, глас той же: «Першосвята, Чиста...». Після Трисвятого – тропар благовірного, глас 6-ий: «Святу Софію...». «Слава» – інший тропар благовірного, глас 6-ий: «Благовірний княже Ярославе..», «І нині» – Богородичний за гласом тропаря, від менших: «Благословенною назвавши...» (воскресний богородичний за гласом другого тропаря благовірного). Потрійна ектенія: «Помилуй нас, Боже...». Священник – виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Примітка. Після виголосу ектенії: «Бо Ти милостивий...» – звичайний виголос: «Премудрість», хор: «Благослови», Священник: «Сущий благословенний...». Молитва: «Небесний Царю...» [або: «Утверди, Боже...»] [7], після чого – 3 великих поклони з молитвою прп. Єфрема Сиріна . Священник – молитву прп. Єфрема Сиріна (з трьома великими поклонами) за сучасною практикою. А за вказівкою Типікону священик із народом мочки творить три великих поклони без молитви прп. Єфрема Сиріна. Читець: «Амінь». Молитва: «Всесвята Тройце...». «Нехай буде благословенне ім’я Господнє...» (тричі), «Слава, і нині», «Благословлю Господа...» (псалом 33-й). Священник (або диякон): «Премудрість». Хор: «Достойно є...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст і, за звичаєм, многоліття. Виходимо в притвор і звершуємо звичайну літію за спочилих."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї співаються служби апп. від 70-х: Архипа та Филимона і мц. рівноап. Апфії (19 лютого) та прп. Тимофія, що в Символах (з 21 лютого). Примітка. «Повечір’я промовляємо мале, і співаємо на ряду канон Мінеї святого пам’ять якого має бути в суботу» (порівн.: Типікон, гл. 49, «Тієї ж сирної середи», «В середу ввечері»). Про порядок співу служб на повечір’ї див. 2 березня, у вівторок 2-ої седмиці Великого посту. Відповідно до третьої Маркової глави, якщо припадає славослів’я одному із святих, то служба іншого переноситься на повечір’я Порядок тропарів і кондаків: У храмі Господському, Богородиці, Архангелів або Предтечі – тропар храму, тропарі дня: «Апостоли святії...», «Правило віри...». «Боже отців наших...», «Ти, що у всьому світі...». «Слава» – «Зі святими упокой...», «І нині» – «Молитвами, Господи...». У храмі Апостолів [8] – тропарі дня: «Апостоли святії...», «Правило віри...». «Боже отців наших...», «Ти, що у всьому світі...». «Слава» – «Зі святими упокой...», «І нині» – «Молитвами, Господи...». У храмі святого – тропарі дня: «Апостоли святії...», «Правило віри...». Тропар храму [9], «Боже отців наших...», «Ти, що у всьому світі...». «Слава» – «Зі святими упокой...», «І нині» «Молитвами, Господи...». [1]. з Октоїха співаються обидва канони (1-ий – Хреста, 2-ий – Богородиці): в 1-ій, 6-ій та 7-ій піснях – з ірмосом на 4 (Ірмос 1-го канону раз, кожен канон на 2); в 4-ій і 5-ій піснях – з ірмосом на 6 (Ірмос 1-го канону раз, кожен канон на 3). [2]. Після Богородичного 2-го трипіснеця – ще додатковий тропар зі стихом: «Слава Тобі, Боже наш, слава Тобі». [3]. Скільки разів читати «Благо є...», Устав в даному випадку замовчує, але слід знати, що в звичайний час (і навіть при постовому богослужінні періоду співу Октоїха) Типікон призначає читати «Благо є...» один раз, а в постові дні святої Чотиридесятниці, коли немає особливого свята, – два рази (див.: Типікон, 14 листопада, 4-е «див», порівн. з 49- ою главою) [4]. Типікон про прокимни цього дня говорить, що читець повинен лише сказати який глас прокимна, але не співати його. Це слід розуміти, що читцю не заборонено виголошувати прокимен, але його співати просто на одній ноті. В древності прокимни розспівувались величаво, подібно як сьогодні розспівуємо великі прокимни: «Хто Бог великий...» чи «Дав насліддя тим...». Слово «промовляємо» в богослужбовому розумінні має два значення: речитатив та найпростіший спів на одній ноті. [5]. На заключне читання молитви прп. Єфрема Сиріна. [6]. На вечірні благословення «Мир всім» після «Світло Тихе» слід виголошувати в тих випадках, коли є вхід або паремії Також допустимо це благословення і на щоденній вечірні без паремій. [7]. Традиція, згідно з якою замість молитви «Небесний Царю...» співається: «Утверди, Боже...», є допустимою. [8]. Тропар храму Апостолів пропускається, оскільки замінюється денним тропарем. [9]. Якщо храм свт. Миколая, то його тропар вимовляється один раз, як денний."}]},
{"date":"02-19","weekday":"четвер","title":"Апп. від 70-х: Архипа та Филимона і мц. рівноап. Апфії (І). Мчч. Максима, Феодота, Ісихія, мц. Асклипіодоти (305 – 311). Прпп. Євгенія і Макарія, сповідників, пресвітерів Антіохійських (363). Прп. Досифея (VІІ), учня прп. авви Дорофея. Прп. Равули (бл. 530). Прп. Шіо Мгвимського (VІ, Груз.) (перехідне святкування у четвер сиропусного тижня). На цей день переноситься служба святому благовірному князю Київському Ярославу Мудрому.","readings":["Іуд., 78 зач., I, 11 – 25. Лк., 110 зач., XXIII, 1 – 34, 44 – 56."],"notes":"Служба благовірного князя Ярослава Мудрого славослівна, звершується разом зі службами Октоїха і Тріоді. Примітка. Є багато видів славослівних богослужінь. Загалом їх поділяють на три типи. У більшості випадків славослівних служб святим належать до типу, коли вони поєднуються із Октоїхом. Отож, перший тип є схемою для славослівної служби св. благовірному кн. Ярославу Мудрому.","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар благовірного, глас 6-ий (двічі). «Слава» – інший тропар благовірного, глас 6-ий: «Благовірний княже Ярославе...», і нині» – Богородичний за гласом тропаря, від менших: «Благословенною назвавши...» (воскресний богородичний по гласу другого тропаря благовірного) Кафизми 13-та і 14-та. Малі ектенії. Після першої кафизми – сідальний Мінеї, глас 4-ий. Після другої кафизми – сідальний благовірному глас 3-ій. «Слава» – Благовірному, глас 3-ій то й же. «І нині» – Богородичний Мінеї. Можливе читання повчання прп. Анастасія, ігумена Синайської гори опісля псалом 50-ий. Канони: 1-ша, 3-тя, 5-та, 6-та і 7-ма пісні: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 2, і благовірного на 6. 4-та, 8-ма і 9-та пісні: канон благовірного з ірмосом на 6 (ірмоси раз) 2 і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаймо...». Катавасія – після 4-ої, 8-ої та 9-ої – ірмоси другого трипіснеця Тріоді; а після, 1-ої, 3-ої, 5-ої, 6-ої і 7-ої – ірмоси канону благовірного. Після 3-ої пісні – сідальний Тріоді, глас 5-ий (той який не був прочитаний після другої кафизми). «Слава» – Благовірному, глас 3-ій: «Благочестивий угоднику...», «І нині» – Богородичний Тріоді, глас той же. Після 6-ої пісні – кондак благовірного, глас 4-ий та ікос. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні не співається «Достойно є». Світильний Мінеї (двічі): «Розквітнув ти розумом...» «Слава, і нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Стихири «на хваліте» благовірному на 4. «Слава» – Благовірному: «Богомудрий Ярославе..». «І нині» – богородичний Мінеї: «Як непорушну стіну...». Читається повсякденне славослів’я (особливість сирного тижня). На стиховні стихири Тріоді, глас 3-ій (з приспівами звичайними). «Слава, і нині» – Богородичний Тріоді, глас той же. Після Трисвятого – тропар благовірного, глас 6-ий: «Святу Софію..». «Слава» – інший тропар, глас то й же: «Благовірний княже...», «І нині» – Богородичний воскресний за гласом тропаря, від менших: «Благословенною назвавши...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар благовірного. «Слава» – інший тропар благовірного. Кондак благовірного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ зображальні антифони. «Блаженні» на 8: 3-тя пісня канону благовірного – 4, та 6-та пісня канону благовірного – 4. Після входу – тропарі та кондаки: У храмі Господському і Богородиці – тропар храму, тропар благовірного, інший тропар благовірного. «Слава» – кондак благовірного «І нині» – кондак храму. У храмі святого – тропар храму, тропар благовірного, інший тропар благовірного; кондак храму. «Слава» – кондак благовірного, «І нині» – «Заступнице християн...». Примітка. В Типіконі немає чіткої вказівки щодо порядку співу тропарів славослівному святому. Можуть співатися і денні тропарі, оскільки використовувався Октоїх на богослужінні. Прокимен, алилуарій і причасний – дня і благовірного. Апостол і Євангеліє – дня і благовірному."}]},
{"date":"02-20","weekday":"п’ятниця","title":"Прп. Лева, єп. Катанського (бл. 780). Блгв. кн. Київського Ярослава Мудрого (1054). Прп. Агафона, чудотворця Києво-Печерського, в Дальніх печерах (ХІІІ – ХІV). Сщмч. Садока, єп. Перського, і з ним 128 мчч. (342 – 344). Прп. Агафона, папи Римського (682). ЦЬОГО ДНЯ БОЖЕСТВЕННА ЛІТУРГІЯ НЕ ЗВЕРШУЄТЬСЯ.","notes":"На 6-му часі: Зах. VIII, 7 – 17. На веч.: Зах. VIII, 19 – 23 Служба преподобного Лева, єп. Катанського не має святкового знака, звершується разом зі службами Октоїха та Тріоді (подібно до служби в середу сирну).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 3-ій – 3, і преподобного, глас 8-ий – 3. «Слава, і нині» – Хрестобогородичний Мінеї, глас той же: «Коли Агниця і Діва...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 2-ий (зі звичайними приспівами). «Слава, і нині» – Хрестобогородичний Тріоді, глас той же. Після Трисвятого – тропарі, глас 4-ий: «Богородице Діво...» (поклін). «Слава» – «Хрестителю Христів...» (поклін), «І нині» – «Моліться за нас...» (поклін), «Під Твою милість...» (без поклону). Читець: «Господи, помилуй» (40), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник: «Сущий благословенний...». Читець: «Амінь». Молитва: «Небесний Царю...». Священник – молитву прп. Єфрема Сиріна: «Господи і Владико...» (з 16 поклонами). Читець: «Амінь». Кінцеве Трисвяте. Після «Отче наш» Священник – виголос. Читець: «Амінь», «Господи, помилуй» (12). Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник – великий відпуст. Примітка. Священник творить поклони на амвоні, перед закритими царськими вратами, обличчям до св. престолу. Одягнутий у рясу, єпитрахиль та поручі. Ієромонах в мантії та в клобуці. За традицією Києво-Печерської Лаври служебний ієромонах звершує богослужіння без клобука. Звершується ВЕЛИКЕ ПОВЕЧІР’Я з поклонами (на повечір’ї спів всюди замінюється читанням). Після «Достойно є...» і Трисвятого не співається «Господи Сил, будь з нами...», як упродовж Великого посту, але – читаються тропарі з малого повечір’я, а саме: У храмі Господському – денний тропар: «Спаси, Господи, людей Твоїх...». «Боже отців наших...», «Ти, що у всьому світі...». «Слава» – «Зі святими упокой...», «І нині» – «Молитвами, Господи...». У храмі Богородиці і святого – денний тропар: «Спаси, Господи...», тропар храму. «Боже отців наших...», «Ти, що у всьому світі...». «Слава» – «Зі святими упокой...», «І нині» – «Молитвами, Господи...». Читець: «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник – виголос: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з 16 поклонами). Читець: «Амінь». Кінцеве Трисвяте. Після «Отче наш» Священник – виголос. Читець: «Амінь», «Господи, помилуй» (12). Молитви: «Непорочна Пречиста...», «І дай нам, Владико...», «Преславна Приснодіво...», «Уповання моє...». Священник: «Слава Тобі, Христе Боже...». Хор або читець: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник – відпуст малий (але не «Владико Многомилостивий...»). Звичайне прощення від настоятеля і ектенії: «Помолимось за Блаженнішого Владику...», в кінці якої священник промовляє: «Промовмо і за себе самих». Хор: «Господи, помилуй» (тричі). Священник: «Молитвами святих отців наших...». Хор: «Амінь». ПОЛУНОШНИЦЯ повсякденна з «її поклонами» і молитвою прп. Єфрема Сирина (з 16 поклонами)."},{"svc":"РАННІЙ","text":"НА РАННІЙ після виголосу «Благословенний Бог наш...» – Трисвяте. Після «Отче наш» священник – виголос: «Бо Твоє є Царство...». Читець: «Амінь», «Господи, помилуй» (12), «Слава, і нині», «Прийдіть, поклонімось...», псалми 19-ий та 20-ий і все інше за чином (під час читання двохпсалмія священник звершує повне кадіння храму). Замість «Бог Господь» – «Алилуя» на глас Октоїха (в даному випадку 3-ій). Троїчний гласу (як під час Великого посту). Кафизми 19-а і 20-а. Малих ектеній немає. Після першої кафизми – сідальні Октоїха, глас 3-ій. Після другої кафизми – сідальні Тріоді, глас 7-ий. І читаємо слово святителя Василія Великого про піст: «Сказано: засурміть у новомісяччя трубою» (Постова Тріодь). Примітка. Слово свт. Василія Великого знаходиться у книзі «Святитель Василій Великий. Творіння» – Т. 1, книга 2 – К.2010 – с. 283. Псалом 50-ий. Біблійні пісні «Господеві співаймо...». Пісня 1-ша – Октоїха 1-ий канон [1] з ірмосом на 6 (Ірмос раз), Мінеї на 4 (без ірмоса, пісня 1-а), Тріоді повний канон на 4 (без ірмоса, пісня 1-а). Пісня 3-тя – Октоїха 1-ий канон з ірмосом на 6 (Ірмос раз), Мінеї на 4 (без ірмоса, пісня 3-я), Тріоді повний канон на 4 (без ірмоса, пісня 3-я). На катавасію – ірмос повного канону Тріоді, глас 8-ий: «Небесного кола...». Після 3-ої пісні – мала ектенія; сідальний преподобного, глас 3-ій. «Слава, і нині» – Хрестобогородичний Мінеї, глас той же. Пісня 4-та – Октоїха 1-ий канон з ірмосом, без мученичних, на 4 (ірмос раз), Мінеї на 6 (без ірмосів, пісня 4-а і 5-а (поєднуємо дві пісні канону святого в одну, без богородичних через трипіснець Тріоді 5 пісні)), Тріоді повний канон на 4 (без ірмосу, пісня 4-а). Пісня 5-та – Тріоді повний канон з ірмосом на 6 (ірмос раз), трипіснець Тріоді на 8 (без ірмосів) [2]. На катавасію – ірмос 2-го трипіснеця, глас 8-ий: «Навіщо покинув Ти мене...». Пісня 6-та – Октоїха 1-ий канон з ірмосом, без мученичних, на 4 (Ірмос раз), Мінеї на 6 (без ірмосів, пісня 6-а і 8-а (поєднуємо дві пісні канону святого в одну, без богородичних через трипіснець Тріоді 8 пісні), Тріоді повний канон на 4 (без ірмосу, пісня 6-а). На катавасію – ірмос повного канону Тріоді, глас 8-ий: «Очисти мене, Спасе...». Після 6-ої пісні – мала ектенія; кондак преподобного, глас 8-ий. Пісня 7-ма – Октоїха 1-ий канон з ірмосом, без мученичних, на 4 (ірмос раз), Мінеї на 6 (без ірмосів, пісня 7-а і 9-а (поєднуємо дві пісні канону святого в одну, без богородичних через трипіснець Тріоді 9 пісні), Тріоді повний канон на 4 (без ірмосу, пісня 7-а). Пісня 8-ма – Тріоді повний канон з ірмосом на 6 (Ірмос раз), трипіснеці Тріоді на 8 (без ірмосів). «Хвалимо, благословимо...». На катавасію – ірмос 2-го трипіснеця, глас 8-ий: «Ангели і Небеса...». На 9-ій пісні співаємо «Чеснішу». (Звершується звичайне кадіння). Пісня 9-а – Тріоді повний канон з ірмосом на 6 (Ірмос раз), трипіснець Тріоді на 8 (без ірмосів). На катавасію – ірмос 2-го трипіснеця, глас 8-ий: «Не властиве для матерів дівоцтво...». Після 9-ої пісні співається «Достойно є». Мала ектенія. Світильний Троїчний гласу (як під час Великого посту). «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. НастиховністихириТріоді,глас6-ий(зприспівамизвичайними).«Слава,інині»–ХрестобогородичнийТріоді,гластойже. «Благо є...» (один раз). Трисвяте. Після «Отче наш» священник – виголос: «Бо Твоє є Царство...». Після виголосу промовляє тропар: «Стоячи в храмі слави Твоєї...». «Господи, помилуй» (40), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник: «Сущий благословенний Христос...». Читець: «Амінь». Молитва: «Небесний Царю...». Священник – молитву прп. Єфрема Сиріна (з 16 поклонами). Читець: «Амінь», і відразу (без відпусту ранньої) – 1-ий час. Примітка. На часах кафизми не читаються. Ударів на кожному часі в дзвін, як це прийнято під час Великого посту, немає. 1-ИЙ ЧАС. «Прийдіть, поклонімось...» (тричі) і звичайні псалми. За великопостовим чином, читається (але не співається) тропар: «Зранку вислухай...» зі своїми стихами (стих 1-ий: «Вислухай Господи слова мої...», і стих 2-ий: «Бо до Тебе помолюся...»). «Слава, і нині» – Богородичний часу: «Як назвемо Тебе...». «Стопи мої направ...», «Нехай сповняться уста мої...», Трисвяте. Після «Отче наш» священник – виголос. Читець – тропар: «Скоро поспіши...». «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з 16-ма поклонами). Читець: «Амінь». Кінцеве Трисвяте. Після «Отче наш» священник – виголос. Читець: «Амінь», «Господи, помилуй» (12). Священник: «Христе, Світло Істинне...». Хор (за звичаєм): «Непереможній Воєводі...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст та многоліття. Виходимо в притвор і звершуємо звичайну літію за спочилих. 3-ІЙ ЧАС. Священник в єпитрахилі, перед царськими вратами (завіса не відкривається), зробивши три поясних поклони, виголошує виголос: «Благословен Бог наш...». Читець: «Амінь», «Слава Тобі, Боже наш...» та інша послідовність 3-го часу, як зазвичай. За великопостовим чином, читається (але не співається) тропар: «Господи, Ти, що Пресвятого Твого Духа...» зі своїми стихами (стих 1-ий: «Серце чисте сотвори в мені, Боже...», і стих 2-ий: «Не відкинь мене від лиця Твого...»). «Слава, і нині» – Богородичний часу: «Богородице, Ти єси виноградна лоза істинна...». «Господь Бог благословенний...», Трисвяте. Після «Отче наш» священник – виголос. Читець – тропар: «Благословен єси, Христе Боже наш...», «Слава» – інший тропар, «І нині» – Богородичний: «Надіє і заступництво...». «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з 16 поклонами). Читець: «Амінь». Молитва: «Владико Боже...», і починається 6-ий час. 6-ИЙ ЧАС. «Прийдіть, поклонімось...» (тричі) і звичайні псалми. За великопостовим чином, читається (але не співається) тропар: «Ти, що в шостий день же і годину...» зі своїми стихами (стих 1-ий: «Вислухай, Боже, молитву мою...», і стих 2-ий: «Я до Бога взиваю...»). «Слава, і нині» – Богородичний часу: «Через превеликі гріхи наші сміливості не маємо...». Читець – тропар пророцтва (Тріоді), глас 3-ій: «Царю Святий...», «Слава, і нині» – той же тропар. Священник (або диякон): «Будьмо уважні». Читець – прокимен Тріоді, глас 6-ий: «Спаси, Господи, людей Твоїх...»; стих: «До Тебе, Господи, взиваю...». Священник (або диякон): «Премудрість». Читець: «Пророцтва Іоїля читання». Священник (або диякон): «Будьмо уважні». Читець читає Паремію Тріоді. Після закінчення читання Священник (або диякон): «Будьмо уважні». Читець – прокимен Тріоді, глас 7-ий: «Господь кріпость людям Своїм дасть...»; стих: «Принесіть Господеві, сини Божі...». Після співу прокимна читець: «Скоро пошли нам милосердя Твоє, Господи...», Трисвяте. Після «Отче наш» священник – виголос. Читець – тропар: «Спасіння вчинив Ти...», «Слава» – інший тропар: «Пречистому Твоєму Образові...», «І нині» – Хрестобогородичний: «Препрославлена Ти, Богородице Діво...». «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Священник: «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з 16-ма поклонами). Читець: «Амінь». Молитва: «Боже і Господи Сил...», і починається 9-тий час. 9-ИЙ ЧАС. «Прийдіть, поклонімось...» (тричі) і звичайні псалми. За великопостовим чином, читається (але не співається) тропар: «Ти, що о дев’ятій годині...» зі своїми стихами (стих 1-ий: «Нехай наблизиться молитва моя...», і стих 2-ий: «Нехай дійде благання моє...»). «Слава, і нині» – Богородичний часу: «Благий, що ради нас народився від Діви...». «Не залиш нас до кінця...», Трисвяте. Після «Отче наш» священник – виголос. Читець – тропар: «Побачивши Начальника життя, що на хресті висів, розбійник мовив...», «Слава» – інший тропар: «Посеред двох розбійників...», «І нині» – Хрестобогородичний: «Агнця, і Пастиря...». «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Священник «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з трьома великими поклонами). Читець: «Амінь». Молитва: «Владико, Господи Ісусе Христе, Боже наш...», і починаються зображальні. (За традицією, відкривається завіса Царських врат). ЗОБРАЖАЛЬНІ читаються: «Благослови, душе моя, Господа...», «Слава» – «Хвали, душе моя, Господа...», «І нині» – «Єдинородний Сину...». Блаженні без співу: «У Царстві Твоїм...». «Слава, і нині» – «Пом’яни нас, Господи...», «Пом’яни нас, Владико...», «Пом’яни нас, Святий...», «Хор Небесний...», «Приступіть до Нього...», «Хор Небесний...». «Слава» – «Хор святих Ангелів...», «І нині» – «Вірую...», «Полегши, відпусти, прости...», «Отче наш». Священник – виголос. Читець: «Амінь», і читає кондаки. Кондаки: У храмі Господському – кондак денний, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». У храмі Богородиці – кондак денний, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – кондак денний, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступництво християн...». Читець: «Господи, помилуй» (40). «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Священник: «Боже, змилосердься над нами...». Читець: «Амінь». священник – молитву прп. Єфрема Сиріна (з 16-ма поклонами). І відразу починається ВЕЧІРНЯ. Читець: «Амінь» [3], «Прийдіть, поклонімось...» (тричі) і 103-ій псалом. Велика ектенія. Читається 18-та кафизма, після якої – мала ектенія. На «Господи, взиваю» стихири Тріоді (отців), глас 8-ий – 6 (кожна стихира – двічі). «Слава» – Тріоді (отців), глас 6-ий:, «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Входу немає. «Світло Тихе». Диякон (або священник) виголошує (у вівтарі): «Будьмо уважні». Священник: «Мир всім» [4]. Читець: «І духові твоєму». Диякон (або Священник): «Премудрість. Будьмо уважні». Читець – прокимен Тріоді (дня), глас 7-ий: «Боже, Ти Заступник мій...»; стих: «Визволи мене від ворогів моїх, Боже...». Диякон (або священник): «Премудрість». Читець: «Пророцтва Захарії читання». Диякон (або священник): «Будьмо уважні». Читець читає Паремії Тріоді. Диякон (або священник): «Будьмо уважні». Читець – прокимен Тріоді, глас 6-ий: «Нехай надію покладає Ізраїль на Господа...»; стих: «Господи, не підносилось серце моє...». «Сподоби, Господи...». Ектенія прохальна: «Доповнімо вечірню молитву...», і голововклінна молитва. На стиховні стихири Тріоді, глас 2-ий (зі звичайними приспівами). «Слава» – Тріоді (отців), глас 8-ий: «Монахів безліч...», «І нині» – Богородичний Тріоді, глас той же. Після Трисвятого – тропар Тріоді (отців), глас 4-ий: «Боже отців наших...». «Слава, і нині» – Богородичний недільний, глас той же: «Від віку утаємнене...». Ектенія сугуба: «Помилуй нас, Боже...». Священник – виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Примітка. Після виголосу ектенії: «Бо Ти милостивий...» – звичайний виголос: «Премудрість», хор: «Благослови», Священник: «Сущий благословенний...». Молитва: «Небесний Царю...» [або: «Утверди, Боже...»] [5]., після чого – 3 великих поклони з молитвою прп. Єфрема Сиріна . Священник – молитву прп. Єфрема Сиріна (з трьома великими поклонами) за сучасною практикою. За вказівкою Типікона священик творить доземних три поклони без молитви. Читець: «Амінь». Молитва: «Всесвята Тройце...». «Нехай буде благословенне ім’я Господнє...» (тричі), «Слава, і нині», «Благословлю Господа...» (псалом 33-й). Священник (або диякон): «Премудрість». Хор: «Достойно є...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст і, за звичаєм, Многоліття. Виходимо у притвор і звершуємо літію за спочилих. Примітка. «І буває трапеза за звичаєм, як і в середу сирну вказувалось. На трапезі читаємо Слово про піст святого Дорофея» (Типікон, гл. 49,»В п’ятницю сирну ввечері...»). У вечері цього НА МАЛОМУ ПОВЕЧІР’Ї співаються служби в честь ікони Божої Матері «Козельщанська» (з 21 лютого) та муч. що в Євгенії (з 22 лютого), а також канон за спочилих, Октоїха, глас 3-ій (без ірмосів). Примітка. Канон за спочилих береться із Октоїха ранньої суботи гласу тижня. Примітка. На розсуд настоятеля служби святим з 21 лютого та 22 лютого можуть бути відправлені і раніше. Примітка. Якщо випаде храмове свято, то служба святому буде звершуватися в неділю Сиропусну в поєднанні зі службою Октоїха і Тріоді. Після Трисвятого – кондак Тріоді (отців). [1] з Октоїха співаються обидва канони (1-ий – Хреста, 2-ий – Богородиці): в 1-ій і 3 ій піснях – з ірмосом на 6 (ірмос 1-го канону раз, кожен канон на 3); в 4-ій, 6-ій і 7-ій піснях – з ірмосом на 4 (Ірмос 1-го канону раз, кожен канон на 2). [2] Після Богородичного 2-го триспівця – ще додатковий тропар зі стихом: «Слава Тобі, Боже наш, слава Тобі». [3] На заключне читання молитви прп. Єфрема Сиріна. [4] На вечірні благословення «Мир всім» після «Світло Тихе» виголошується в тих випадках, коли є вхід або паремії Також допустимо це благословення і на повсякденній вечірні без паремій (Там же. С. 103). [5] Традиція, згідно з якою замість молитви «Небесний Царю...» співається: «Утверди, Боже...», є допустимою."}]},
{"date":"02-21","weekday":"субота","title":"Всіх преподобних отців, що в подвигу просяяли (перехідне святкування в суботу сиропусного тижня). Прп. Тимофія, що в Символах (795). Свт. Євстафія, архієп. Антіохійського (337). Свт. Георгія, єп. Амастридського (802 – 811). Козельщанської ікони Божої Матері (1881).","readings":["Рим., 115 зач., XIV, 19 – 26. Мф., 16 зач., VI, 1 – 13.","Прпп.: Гал., 213 зач., V, 22 – VI, 2. Мф., 43 зач., XI, 27 – 30."],"notes":"Звершується славослівна служба всіх преподобних отців, що в подвигу просяяли (за Тріоддю). Примітка. Рядова служба Мінеї (Прп. Тимофія) переноситься на мале повечір’я вечора сирної середи.","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Тріоді (отців), глас 4-ий: «Боже отців наших...» (двічі). «Слава, і нині» – Богородичний недільний, глас той же: «Від віку утаємнене...». Кафизми 16-а і 17-а [1]. Малі ектенії. Сідальні Тріоді (отців). Читаємо слово прп. Єфрема про спочилих отців. Примітка. Слово про спочилих отців знаходиться у книзі «Преподобний Єфрем Сирін. Творіння» – Т. 1. – К. 2013 – с. 254. Псалом 50-ий. Канони: храму з ірмосом на 6 (ірмоси по двічі) і Тріоді (отців) на 8. Біблійні пісні: «Співаймо Господеві...» або «Господеві співаймо...». Примітка. Типікон вказує співати біблійні пісні у святковій редакції: «Співаймо Господеві...», в Тріоді Постовій міститься вказівка ​​ на буденну редакцію біблійних пісень: «Господеві співаймо...» [2]. Катавасія Тріоді: «Пісню заспіваймо, люди...». На 2-ій пісні – канон Тріоді (отців): Ірмос («Бачите, бачите...») один раз [3], тропарі без повторень; до тропарів канону приспів: «Преподобні отці, моліть Бога за нас». На катавасію – той же ірмос: «Бачите, бачите...». Після 3-ої пісні – сідальний Тріоді (отців), глас 4-ий; інший сідальний Тріоді (отців), глас 8-ий. «Слава» – інший сідальний Тріоді (отців), глас той же, «І нині» – Богородичний Тріоді, глас той же. Після 6-ої пісні – кондак та ікос Тріоді (отців), глас 8-ий. Читаємо Санаксар (Стих: Душам праведним...). На 9-ій пісні співаємо «Чеснішу». (Звершується звичайне кадіння). Після 9-ої пісні «Достойно є» не співається. Світильний Тріоді (отців):. «Слава, і нині» – Тріоді. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Тріоді (отців), глас 8-ий – 4. «Слава» – Тріоді (отців), глас 6-ий, «І нині» – Богородичний, глас той же: «Богородице, Ти єси виноградна лоза...» (див. Часослов, Слава, і нині 3-го часу). Велике славослів’я. Після Трисвятого – тропар Тріоді (отців), глас 4-ий: «Боже отців наших...». «Слава, і нині» – Богородичний недільний, глас той же: «Від віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Тріоді (отців)."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Тріоді (отців), пісня 3-тя – 4 (з ірмосом), і пісня 6-та – 4. На вході – «...Дивний у святих єси...». Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар Тріоді (отців). «Слава» – кондак Тріоді (отців), «І нині» – кондак храму. У храмі святого – тропар Тріоді (отців), тропар храму; кондак храму. «Слава» – кондак Тріоді (отців), «І нині» – «Заступнице християн...». Прокимен – Тріоді (отців), глас 4-ий. Апостол і Євангеліє – дня і отців. Алилуарій – Тріоді (отців), глас 2-ий. Причасний – Тріоді (отців): «Радуйтеся, праведні...»."}]},
{"date":"02-22","weekday":"неділя","title":"Неділя сиропусна, прощена. Спомин Адамового вигнання з раю. Глас 4-й. Мчч. Маврикія і 70-ох воїнів: Фотина, Федора, Филипа та інших (бл. 305). Знайдення мощів мучеників, що в Євгенії (395 – 423). Прпп. Фаласія, Лимнія і Варадата, пустельників сирійських (V). Прп. Афанасія, спов. (821). На цей день переноситься полієлейна служба на честь першого і другого знайдення голови Іоана Предтечі.","glas":4,"readings":["Ран. – Єв. 4-е, Лк., 112 зач., XXIV, 1 – 12.","Літ. – Рим., 112 зач., XIII, 11 – XIV, 4. Мф., 17 зач., VI, 14 – 21.","Предтечі: 2 Кор., 176 зач., IV, 6 – 15. Мф., 40 зач., XI, 2 – 15."],"notes":"За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню. Мала вечірня служиться лише за Октоїхом.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири, глас 4-ий – 4. (перша стихира – двічі (на початку, та в кінці як четверта). «Слава, і нині» – богородичний (догматик малої вечірньої), глас 4-ий: «Безсіменно Ти зачала...» Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. Перша стихира недільна, а інші стихири Пресвятої Богородиці зі своїми приспівами. На стиховні стихири глас 4-ий: «Стражданням Твоїм Христе...» із своїми приспівами. «Слава, і нині» – Богородичний, глас то й же: «Хмарою вічного світла...». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар недільний, глас 4-ий «Світлу Воскресіння проповідь.» «Слава, і нині» – Богородичний за гласом тропаря: «Від початку віку утаємнене...». Після співу тропаря з богородичним священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, що воскрес із мертвих, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 4-ий – 4, Тріоді, глас 6-ий – 3 і Предтечі, глас 5-ий – 3. «Слава» – Тріоді, 6-ий: «Вигнаний був Адам з раю...», «І нині» – догматик, глас 4-ий: «Тебе ради...». Вхід. Прокимен дня. Паремії пророка – 3. На літії стихира храму. «Слава» – Тріоді, глас 5-ий: «Горе мені, – Адам ридаючи взивав...», і друга стихира Тріоді: «Шлях чеснот...» (див в Тріоді на хваліте...). Слава» – Тріоді, глас 6-ий: «Сонце промені заховало, місяць із зірками кров’ю наповнились, гори жахнулися, пагорби затремтіли, коли рай закрився. Виходячи Адам руками бив по лицю промовляючи: Милостивий, помилуй мене впалого.», «І нині» – Богородичний Тріоді, глас той же: «Таємниче оспівуємо Тебе Богородице Маріє бо Ти стала престолом великого Царя, оселе все свята, ширша небес, коліснице херувимів, палато слави вища за серафимів, бо з тебе вийшов втілившись Бог усіх. Його моли, щоб спаслися душі наші.». На стиховні стихири недільні, глас 4-ий. «Слава» – Предтечі, глас 2-ий «Божественне провидіння ...», «І нині» – Тріоді, глас 6-ий: «Вигнаний був Адам...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 4-ий (двічі). «Слава» – тропар Предтечі, глас 4-ий: «Із землі засяявши...». «І нині» – Богородичний недільний, по гласу «Слави»: «Від початку віку утаємнене..». Кафизми 2-а і 3-я. Малі ектенії. Сідальні недільні. Полієлей. До двох полієлейних псалмів приєднується псалом136-ий:«Нарікахвавилонських...».Величанняпророку. Псалом вибраний: «Господь охороняє душі преподобних своїх». «Ангельський собор...». Іпакої гласу, сідальні пророка після першої і другої кафизми. Степенні і прокимен – гласу. Євангеліє недільне – 4-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – Тріоді, глас 8-й: «Покаяння відкрий мені двері...», «І нині» – Богородичний Тріоді, глас той же: «На стежки спасіння...». Глас 6-й: «Помилуй мене, Боже...», і стихира Тріоді, глас той же: «Множество вчинених...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Богородиці Октоїха на 2 Тріоді на 4 і Предтечі на 4 (Предтечі на 4 – особливість сиропусної неділі). Біблійні пісні «Співаймо Господеві...». Катавасія Тріоді: «Як по сухому...». Після 3-ої пісні – кондак та ікос пророка, глас 6-ий, сідальний Тріоді, глас 4-ий (двічі). «Слава і нині» – сідальний Тріоді, глас 4-ий: «Нині час подвигу настав...». Після 6-ої пісні – кондак і ікос Тріоді, глас 6-ий і читаємо Санаксар. На 9-ої пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 4-й. «Слава» – світильний Предтечі, «І нині» – світильний Тріоді: «Мене вигнаного колись із раю...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 4-ий – 4, Предтечі, глас 4-ий – 4, далі співається стих: «Воскресни Господи Боже мій, нехай піднесеться рука Твоя, не забуть убогих Твоїх до кінця» і стихира Тріоді, глас 6-ий: «Адам із раю...». «Слава» – Тріоді, глас 6-ий: «Настав час...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар недільний: «Воскрес із гробу...». Перед 1-им часом на «Слава, і нині» – стихира євангельська 4-та. При співі цієї стихири буває вихід в притвор , де читається Оголошені прп. Федора Студита, після чого співається тропар преподобного Федора, глас 8-ий, без богородичного і читається перший час, який закінчується малим відпустом: «Христос, що воскрес із мертвих...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний і Предтечі. Кондаки Тріоді і Предтечі читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ за чином свт. Іоанна Золотоустого заготовлюються два Агнця: для середи і п’ятниці. Примітка. Приготування Агнців на Літургії відбувається наступним чином. Проскомидія в Неділю звершується звичайним порядком. Після заготовлення першого Агнця точно так само заготовлюються й інші два, над кожним з яких священик промовляє молитви: «На спомин...», «Як вівця...», «І як Агнець...», «У смиренні Його...», «А про рід Його...»,«Бо візьметься...», «Приноситься в жертву Агнець...» і «Один з воїнів...». Всі три Агнця покладаються на дискос разом. Далі проскомидія звершується звичайним чином. Під час євхаристійного канону священик вимовляє: «Хліб цей...», а не «Хліби ці...». При виголошуванні «Святеє святим» священик возносить не один Агнець, а всі три разом. Для причастя роздроблюється звичайним порядком тільки перший Агнець, а решта два напуваються Святою кров’ю. Для цього священик бере правою рукою лжицю, вмокає її в Святу Кров, а лівою рукою бере другий Агнець і напуває Його над Чашею хрестоподібно, після чого покладає Агнець в дарохранительницю. Так само заготовлюється і третій Агнець. Блаженні на 12: гласу – 4, і Тріоді, пісня 3-тя – 4 і Предтечі, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар неділі, тропар Предтечі. «Слава» – кондак Предтечі, «І нині» – кондак Тріоді. У храмі Богородиці – тропар неділі, тропар храму, тропар Предтечі. Кондак Предтечі. «Слава» – кондак Тріоді, «І нині» – кондак храму. У храмі святого – тропар неділі, тропар Предтечі, тропар храму. Кондак Предтечі, «Слава» – кондак храму, «І нині» – кондак Тріоді. Прокимен і алилуарій – Неділі сиропусної та Предтечі. Апостол і Євангеліє – Неділі сиропусної та Предтечі. Причасний – недільний: «Хваліте Господа з Небес...» і Предтечі: «В пам’ять вічну...». Зразок звершення вечірні напередодні понеділка Чотиридесятниці. Увечері в Неділю сиропусну священник (перед царськими вратами): «Благословен Бог наш...». Читець: «Амінь», «Слава Тобі, Боже наш, слава Тобі», і читається 9-ий час – за звичаєм. В кінці 9-го часу Священник виголошує виголос: «Боже, змилосердься над нами...». Читається молитва: «Владико, Господи Ісусе Христе, Боже наш...». ВЕЧІРНЯ. Священник (перед царськими вратами): «Благословен Бог наш...». Читець: «Амінь». «Прийдіть, поклонімось...» (тричі) і початковий псалом (священник читає на амвоні світильничні молитви). Велика ектенія. Кафизми немає. На «Господи, взиваю» стихири [1] на 10: Октоїха покаянні, глас 4-ий – 4 (2 з стихир на стиховні на вечірні в Неділю вечора і 2 зі стихир на стиховні ранньої понеділка)[2], Тріоді, глас 2-ий – 3, і Мінеї (свящмч. Полікарпа, з 23 лютого) – 3. «Слава, і нині» – Богородичний Мінеї: «Гріховним павутинням...». Увага! Якщо трапиться пам’ять двох малих святих, то співаються стихири першого святого, а стихири другого святого з «Господи, взиваю» переносяться на хвалітні ранньої. Вхід з кадилом [3]. «Світло Тихе». Прокимен великий, глас 8-й: «Не відверни лиця Твого від отрока Твого, бо я терплю; скоро почуй мене, поглянь на душу мою і спаси її»; стих 1-й: «Поміч Твоя, Боже, нехай визволить мене»; стих 2-ий: «Побачатьце принижені і звеселяться»; стих 3-ий: «Шукайте Бога, і жива буде душа ваша». Примітка. Великий прокимен «Не відверни лиця Твого...» співається також на вечірні в 2-у і 4-у Неділю посту. У 1-у, 3-ю і 5-ю Неділю співається прокимен великий, глас 8-ий: «Дав мені насліддя з тими, що бояться імені Твого»; стих 1-ий: «Від краю землі взиваю до Тебе»; стих 2-ий: «Знайду спокій під покровом крил Твоїх»; стих 3-й: «Я буду співати імені Твоєму повіки». Потрійна ектенія «Промовмо всі...» не виголошується. Після виконання прокимна читається: «Сподоби, Господи...» [4]. Ектенія прохальна: «Доповнімо вечірню молитву...», і голововклонна молитва. На стиховні стихири Тріоді, глас 4-ий (зі звичайними приспівами). «Слава, і нині» – Богородичний Тріоді, глас той же. «Нині відпускаєш...». Трисвяте. Після «Отче наш» священник – виголос: «Бо Твоє є Царство...» [5]. Після виголосу священника хористи співають тропарі, глас 4-ий: «Богородице Діво...» (поклін). «Слава» – «Хрестителю Христів...» (поклін), «І нині» – «Моліться за нас, святі апостоли...» (поклін), «Під Твою милість...» (без поклону). Читець: «Господи, помилуй» (40), «Слава, і нині» – «Чеснішу від херувимів...», «Іменем Господнім...». Священник: «Сущий благословенний...». Читець: «Амінь». Молитва: «Небесний Царю...». Священник (або настоятель) – молитву прп. Єфрема Сиріна: «Господи і Владико життя мого...» (з трьома поклонами) [6]. Після третього поклону – «Слава Тобі, Христе Боже...», і робить відпуст, після якого хор співає многоліття: «Владику і отця нашого...». Примітка. За традицією Свято-Михайлівського Золотоверхого монастиря, перед відпустом вечірньої Предстоятель на колінах читає дві молитви на початок Великого посту із требника. Перед кожною молитвою диякон виголошує: «Господу помолимось», а хор співає «Господи помилуй». По закінченні другої молитви творить відпуст. На момент читання молитов священнослужителі та ченці знімають головні убори, стаючи на коліна. Літія за спочилих після цієї вечірні не звершується. Після відпусту, за традицією, відбувається чин прощення. На солію, або під солією виносяться і покладаються на аналоях напрестольний Хрест, ікони Спасителя і Богородиці. Настоятель творить земні поклони перед ними і цілує їх. Потім він звертається до присутніх з настановою про християнське проведення посту і просить прощення гріхів у причту і народу, промовляючи: «Благословіть мене, отці святі і браття, і простіть мені, грішному, все, чим згрішив я в цей день і в усі дні життя мого словом, ділом, думкою і всіма моїми почуттями». Сказавши це, він доземно вклоняється народу. Всі відповідають йому земним поклоном і промовляють: «Бог простить тебе, святий отче. Прости і нас, грішних, і благослови» [7]. На це службовий священик (як правило, настоятель, а в обителях – намісник) відповідає: «Благодаттю Своєю Бог нехай простить і помилує всіх нас». Потім настоятель бере напрестольний Хрест. Всі священнослужителі в порядку старшинства прикладаються до ікон на аналої, підходять до настоятеля, цілують Хрест і цілували з настоятелем та один з одним в плечі, взаємно просячи прощення. За ними йдуть миряни, прикладаються до Хреста, цілують ікони, які зазвичай тримають священнослужителі, і просять прощення в причту і один у одного. Під час чину прощення прийнято співати: «Покаяння відкрий мені двері...», «На ріках вавилонських...» та ін [8]. Особливості архієрейської вечірньої напередодні Великого посту. У кафедральних соборах останніми десятиліттями архієреями сформувалась традиція звершувати архієрейську вечірню. Проте Типікон такої вечірні не передбачає. Перед початком 9 часу відбувається зустріч кліриками архієрея в притворі. Служебний священник зустрічає з хрестом. Єпископ облачившись в архірейську мантію звичайного кольору (єпископи, архієпископи – фіолетову, митрополити – блакитну, Блаженійший митрополит Київський – бордову), цілує хрест, також дає цілувати хрест духовенству і тоді заходить до храму, піднімається на амвон, цілує намісні ікони, диякон під час цілування ікон нічого не промовляє. Хор співає протяжно «Достойно є..» Опісля єпископ повертається до народу і благословляє присутніх жезлом та рукою і повертається на кафедру. На кафедрі іподиякони знімають мантію та облачають архієрея в повне облачення світлого кольору. Диякони під час облачення лише виголошують «Господу помолимось», «Господи помилуй». По завершенні облачення іподиякони виносять архієрею трикирій і дикирій. Диякон виголошує: «Нехай просвітлиться світло...» Хор співає: «Тон деспоті...». Архірей благословляє вірних трикирієм і дикирієм на чотири сторони. Далі паламарі виносять стілець і ставлять на кафедру. Архієрей дає виголос на 9-тий час. Читець читає 9-тий час. Клірики з благословення архірея заходять у вівтар боковими дверями, архієрей залишаться на кафедрі. На молитві «Ти що кожного часу...» клір приходить на середину храму до кафедри. По закінченні 9-го часу іподиякони відкривають завісу і царські врата і архієрей знову виголошує «Благословен Бог наш...». Хор: Амінь. Царські врата закриваються. Читець: Прийдіть поклонімось... і 103 псалом. Архієрей знімає митру і читає світильничні молитви. Священики також читають молитви про себе на храмі біля кафедри. Після 103-го псалма іподиякони відкривають царські врата і диякон розпочинає Велику ектенію. На виголосі «Бо Тобі належить ...» усі священики хрестяться, кланяються архієрею і заходять боковими дверима у вівтар, цілують престіл, кланяються архірею, один до одного. Диякони після цього беруть благословення на кадіння храму. Царські врата закриваються. На «Господи взиваю..» єпископ сидить на кафедрі. На «Слава, і нині» відкриваються царські врата, старший священник дає Євангеліє диякону і духовенство виходить до кафедри через північні двері. Диякон підходить до архієрея і просить благословити святий вхід, після цього архієрей цілує Євангеліє і диякон виголошує: «Премудрість, станьмо побожно...». Духовенство співає урочистим наспівом «Світе тихий». Єпископ благословляє народ трикирієм і дикирієм, піднімається на амвон знову благословляє вірних, віддає трикирій дияконові, цілує намісні ікони і заходить у вівтар. Хор також співає швидким наспівом «Світе Тихий...» А архієрей цілує престіл і починає звершувати кадіння вівтаря. Духовенство продовжує співати «Достойний єси в усі часи оспіваним бути голосами преподобними, Сину Божий, що життя даєш; тому світ Тебе славить». Далі хор співає «Іс полла еті Деспота...». Духовенство після хору у вівтарі також співає «Іс полла еті...». Диякон виголошує «Будьмо уважні». Архієрей обертається до народу і промовляє «Мир усім». Опісля цього диякон поблизу горнього місця розспівує великий прокимен. Усе духовенство з єпископом іде на горне місце. По завершенні прокимна повертаються до престолу і цілують трапезу престолу. Царські врата закриваються. Читець повільно читає «Сподоби Господи...». Після закриття царських врат усі панікадила в храмі загашуються, окрім лампад, семисічника у вівтарі та свічок. З єпископа іподиякони знімають облачення, одягають в архієрейську мантію чорного кольору, а також єпитрахиль, поручі, малий омофор та клобук. Духовенство одягається в ряси та камилавки. Архірей може благословити священику сказати виголоси прохальної ектенії. Перед початком Трисвятого усі виходять з вівтаря на храм. Архієрей царськими вратами виходить на амвон, а духовенство боковими і сходить під солію. Далі усі звершують поклони відповідно до уставу вечірньої служби. Після молитви «Небесний Царю» архієрей читає молитву прп. Єфрема Сиріна з трьома поклонами і чинить відпуст. Після відпусту виголошує проповідь і далі розпочинається чин прощення. Архірей першим просить прощення в присутніх з доземним поклоном, після цього цілує ікони і дає цілувати св. хрест вірним. По завершенні чину прощення царськими повертається у вівтар. Примітка. «Після вечірні ж на трапезі велика утіха для братії» (Типікон, гл. 49-а, «В ту ж Неділю сирну ввечері»). Увечері в Неділю сиропусну і в інші Неділі Чотиридесятниці належить звершувати МАЛЕ ПОВЕЧІР’Я з каноном і поклонами. Примітка. Якщо напередодні звершувалось бдіння, то канон Богородиці (Октоїха) на повечір’ї не співається. Порядок малого повечір’я такий самий, як і в період співу Октоїха, але з такими особливостями. Замість виголосу: «Молитвами святих отців...» виголошується: «Боже, змилосердься над нами...». Після виголосу б’ються три великих поклони з молитвою прп. Єфрема Сиріна: «Господи і Владико...», 12 малих поклонів з молитвою «Боже, очисти мене грішного», і один великий поклін з молитвою «Господи і Владико...». Після поклонів – кінцеве Трисвяте. Після «Отче наш» – виголос: «Бо Твоє є Царство...», «Амінь», «Господи, помилуй» (12). Молитва: «Непорочна, Пречиста...», та інше за звичаєм. Відпуст та ектенія «Помолимось...». Примітка. Якщо хтось відійде у вічність в ці святі дні, то панахида на третій чи дев’ятий день не звершується за ним, а переноситься на п’ятницю увечері. [1] Під час співу псалмів і стихир – звичайне кадіння. [2] Октоїх на стиховні вечірні та утрені містить по три стихири (дві покаянні і мученику) з Богородичним. З кожного циклу стихир беруться перші дві – покаянні. [3] Цієї неділі і в наступні п’ять (до Неділі Вербної) на вечірні відбувається вхід заради великих прокимнів. [4] Співом великого прокимна завершується святкове недільне богослужіння, і від «Сподоби, Господи...» починається великопісне. Існує практика, за якою священнослужителі після закриття царських врат переоблачаються в темний одяг, і диякон [або священник в єпитрахилі (в парафіяльних храмах – і в фелоні, якщо він служить один без диякона)] виходить для виголошення прохальної ектенії на солію перед царськими вратами, хористи ж співають цю ектенію не звичайним, але великопісним наспівом. [5] Священник виголошує цей виголос, стоячи на солії перед царськими вратами. Тут же він залишається до відпусту вечерні, творить поклони при співі тропарів: «Богородице Діво» та ін., Виголошує виголос: «Сущий благословенний...» і молитву прп. Єфрема Сирина, з належними великими поклонами, і звершує відпуст. [6] У недільні дні Великого посту на вечірні належить бити тільки три великих поклони, а не 16, як в седмичні дні. [7] У деяких храмах і монастирях говорять інакше: «Бог простить тебе, святий отче. Помолися за нас, грішних», що цілком узгоджується з Уставом. [8] У Типіконі нічого не сказано про спів будь-яких пісень під час чину прощення. Коротка вказівка: «І цілуємо святі і чесні ікони» передбачає здійснення цього обряду в мовчанні. Проте в старовинних соборних чиновниках, вказується співати під час цілування святинь піснеспіви молитовно-покаянного змісту: «Покаяння відкрий мені двері...», «На стежки спасіння...», «Множество вчинених...», «Владичице, прийми молитви...», стихиру Успіння: «О дивне чудо...» і молитву Святому Духу: «Царю Небесний...». У деяких храмах прийнято також співати стихири Пасхи, закінчуючи словами: «І так заспіваймо»."}]},
{"date":"02-23","weekday":"понеділок","title":"1-й тиждень Великого посту. Сщмч. Полікарпа, єп. Смирнського (167). Прпп. Іоана, Антіоха, Антоніна, Мойсея, Зевина, Поліхронія, іншого Мойсея і Даміана, пустельників сирійських (V). Прп. Олександра, засновника обителі «Невсипущих» (бл. 430).","notes":"На 6-му часі: Іс. I, 1 – 20. На веч.: Бут. I, 1 – 13. Притч. I, 1 – 20. У будні дні Великого посту служба звершується за Мінеєю та Тріоддю. Із Октоїха в будні дні беруться тільки Троїчні, сідальні і світильні гласу тижня. Цього року першого тижня Великого посту гласом тижня є третій глас Октоїха. У перші чотири дні цього тижня на великому повечір’ї читається канон прп. Андрія Критського. По понеділках, вівторках і четвергах святої Чотиридесятниці літургії не звершуються. Зразок звершення ранньої в понеділок, вівторок, середу, четвер і п’ятницю св. Чотиридесятниці, якщо не припадають в ці дні свята храмові або полієлейні Перед початком ПОВСЯКДЕННОЇ ПОЛУНОШНИЦІ дзвоніння – за звичаєм, 12 ударів у дзвін; після виголосу: «Боже, змилосердься над нами...» – три великих поклони з молитвою прп. Єфрема Сиріна (стільки поклонів на полуношниці буває тільки в 1-й день Великого посту, а в інші дні – 16). Після закінчення полуношниці, перед ранньою дзвоніння – за звичаєм, в два дзвони.","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ священник, одягнувши фелонь [1] і відкривши завісу царських врат, кадить перед престолом хрестоподібно і виголошує: «Благословенний Бог наш...» [2]. Читець: Трисвяте. Після «Отче наш» священник – виголос: «Бо Твоє є Царство...». Читець: «Амінь», «Господи, помилуй» (12). «Слава, і нині» – «Прийдіть, поклонімось...» (тричі), псалми 19-ий та 20-ий, Трисвяте. «Отче наш» – виголос і тропар: «Спаси, Господи, людей Твоїх...». «Слава» – «Ти що вознісся на Хрест...», «І нині» – «Заступнице християн...». Під час читання псалмів священник кадить вівтар і весь храм, потім, повернувшись до вівтаря, виголошує малу потрійну ектенію: «Помилуй нас, Боже...» (з кадилом перед престолом) і виголос: «Бо Ти Милостивий...». Хор: «Амінь», «Іменем Господнім...». Священник, стоячи перед престолом, виголошує: «Слава Святій, і Єдиносушній, і Животворчій, і Нероздільній Тройці...», при цьому творить хрест кадилом. Читається шестипсалміє (священник читає ранні молитви Служебника). Після закінчення шестипсалмія – велика ектенія. Потім «Алилуя» на глас Октоїха, який випадає, зі стихами (в даному випадку глас4-ий). Хор співає: «Алилуя», по тричі на кожен з чотирьох стихів. Потім три Троїчних тропаря (див. в додатку Тріоді). Примітка. На практиці Троїчні тропарі читаються, а закінчення (приспіви) їх співаються. У понеділок до першого Троїчного тропаря приспів: «Свят, свят, свят єси, Боже наш, заступництвом безплотних Твоїх помилуй нас»; до другого – «Свят, свят, свят єси, Боже наш, молитвами всіх святих Твоїх помилуй нас»; до третього – «Свят, свят, свят єси, Боже наш, молитвами Богородиці, помилуй нас». Приспів до першого тропаря особливий для кожного дня тижня, приспіви до другого і третього тропарям – постійні. Потім читаються кафизми 4-та, 5-та і 6-та, з поділом на три «Слави» і зі співом великопостовим розспівом. Читання кафизми починається з хорового співу «заходу»: «Господи, помилуй» (тричі), «Слава». Читець: «І нині», і читає кафизму. Малих ектеній після кафизм у всю Чотиридесятницю, крім субот і неділь, немає (якщо припаде свято, то перед святковими сідальними виголошується мала ектенія). Після 1-ої кафизми – сідальні рядового гласу Октоїха (див. Додаток Тріоді). Якщо в Мінеї у рядового святого є кондак, то в сідальні, перед Богородичним, співається мученичий поточного гласу з приспівом: «Дивний Бог у святих Своїх, Бог Ізраїлів». Якщо в Мінеї кондака у рядового святого немає, то мученичий співається після 6-ої пісні канону (тоді в сідальні цей мученичний пропускається). Читається слово прп. Єфрема Сиріна. Після 2-ої і 3-ої кафизм – сідальні Тріоді (на ряду). За звичаєм, хор – заспів: «Господи, помилуй» (тричі), «Слава». Читець – «І нині», і читає Лавсаїк. По його завершені псалом 50-ий. Священник (або диякон) на амвоні виголошує молитву: «Спаси, Боже, людей Твоїх...» (див. На літії великої вечірні). Хор: «Господи, помилуй» (12). Священник: «Милістю і милосердям...». Хор: «Амінь», і співається канон. На великопостовій ранній три канони – з Мінеї (повний) і два триспіснеці з Тріоді. Триспіснеці складаються: в понеділок – з 1-ої, 8-ої і 9-ої пісні; у вівторок – з 2-ої, 8-ої і 9-ої пісні; в середу – з 3-ої, 8-ої і 9-ої пісні; в четвер – з 4-ої, 8-ої і 9-ої пісні; в п’ятницю – з 5-ої, 8-ої і 9-ої пісні [3]. Пісні, до складу яких входять трипіснеці, співаються на 14: канон Мінеї з ірмосом на 6 (Ірмос раз), потім трипіснеці на 8. Крім того, 2-ий трипіснець Тріоді містить один або два тропаря, що не входять в число 14; ці тропарі повинні співатися з приспівом: «Слава Тобі, Боже наш, слава Тобі». Пісні, в яких немає трипіснеців, співаються на 4, без ірмосу, тобто ірмоси в цей рахунок не входять. У 1-ій, 4-ій, 5-ій і 7-ій піснях ірмоси співаються перед тропарями, а в 3-ій (крім середи) і 6-ій служать катавасією і співаються тільки після закінчення тропарів. Пісні, які мають в своєму складі трипіснеці, неодмінно закінчуються катавасією – ірмос другого трипіснеця. Канон читається з біблійними піснями (Біблійні пісні містяться в Псалтирі). Повністю текст біблійної пісні виповнюється тільки в піснях з трипіснецями. (Таким чином, за тиждень цілком проспівується весь цикл Пісень Святого Писання). В інших піснях як приспіви до тропарів використовується тільки необхідна кількість решти стихів. Якщо трапляться два святих, то в піснях з трипіснецями два канони Мінеї співаються на 6, шляхом поєднання в обох канонах двох тропарів в один. Слава, і нині першого канону пропускається. Примітка. Обидва канони Мінеї співаються на 6 (з ірмосом) наступним чином: Ірмос канону першого святого, два тропаря цього канону за один, тропар перед Богородичним (Богородичний пропускається); з канону другого святого – два тропаря за один, тропар перед Богородичним і Слава, і нині. Про спів канонів двох святих в піснях без трипіснеців Типікон замовчує. Відповідно до розповсюдженої практики, обидва канони Мінеї співаються на 8. Стихи біблійних пісень після ірмоса співаються від помітки «на 8». В 3 (крім середи) і в 6 піснях ірмос першого канону Мінеї співається на початку пісні, а другого канону святого на катавасію. Відповідно до загальних вказівок Типікону щодо чину співу канону великопостової ранньої, в понеділок пісня 1-а канону читається від стиха: «Співаймо Господеві...» до «Згусла вода, як стіна...». Після стиха «Згусла вода, як стіна...» співається ірмос канону Мінеї. Хор – стих: «Ворог сказав...». Читець – 1-ий тропар канону Мінеї. Хор: «Ти дихнув духом Твоїм...». Читець – 2-ий тропар. Хор: «Хто подібний до Тебе...». Читець – 3-ій тропар. Хор: «Ти простягнув...». Читець – 4-й тропар. Хор: «Ти привів...». Читець – Слава, і нині канону. Хор: «Тоді засмутилися владики едомські...». Читець – 1-ий і 2-ий тропарі першого трипіснеця Тріоді (за один). Хор: «Нехай нападе на них страх...». Читець – 3-ій тропар. Хор: «Доки пройдуть...». Читець – 4-ий тропар. Хор: «Введи його і насади його...». Читець – Богородичний 1-го трипіснеця. Хор: «Господь, царює повік віку...». Читець – 1-ий тропар 2-го трипіснеця Тріоді. Хор: «То повернув на них воду морську...». Читець – 2-ий тропар. Хор: «Слава». Читець – Троїчний: «Одинице проста...». Хор: «І нині». Читець – Богородичний: «Божу Святу Гору оспіваймо...». Хор: «Слава Тобі, Боже наш...». Читець – тропар: «Колісниця вогненна...». Хор: «Слава Тобі, Боже наш...». Читець – останній тропар: «Адам спожив забороненого плоду...». Потім на катавасію співається ірмос 2-го трипіснеця Тріоді, глас 2-ий: «Грядіть, люди...». Примітка. Пісня 2-а в понеділок не співається. Вона співається по вівторках Чотиридесятниці. Пісня 3-тя (з Мінеї) починається співом біблійних стихів. Відразу після катавасії 1-ої пісні хор – стих: «Той, хто хоче хвалитися...». Читець – 1-ий тропар канону. Хор – стих: «І дасть силу...». Читець – 2-ий тропар. Хор: «Слава». Читець – 3-ій тропар. Хор: «І нині». Читець – Богородичний Мінеї. Хор – ірмос 3-ій пісні Мінеї. Відмінність від звичайного виконання канону в тому, що тут ірмос співається не на початку пісні, але – її в кінці, покриваючи пісню, як катавасія. Після 3-ої пісні – ектенія мала. Сідальний Мінеї. «Слава, і нині» – Богородичний Мінеї. Читання Лавсаїка (за вказівкою Тріоді). Пісня 4-я (з Мінеї). Хор – ірмос 4-ої пісні Мінеї і стих: «Господь Бог – сила моя...». Читець – 1-ий тропар. Хор – стих: «І на висоти мої...». Читець – 2-ий тропар. Хор: «Слава». Читець – 3-ій тропар. Хор: «І нині». Читець Богородичний. Пісня 5-а (з Мінеї). Хор – Ірмос 5-ої пісні і стих: «Воскреснуть мертві...». Читець – 1-ий тропар. Хор – стих: «Бо роса Твоя...». Читець – 2-ий тропар. Хор: «Слава». Читець – 3-ий тропар. Хор: «І нині». Читець – Богородичний. Пісня 6-а (з Мінеї) співається так само, як 3-тя. Відразу ж після Богородичного 5-ої пісні співається стих: «Шанувальники суєтних...». Читець – 1-ий тропар. Хор – стих: «А я голосом хвали...». Читець – 2-ий тропар. Хор: «Слава». Читець – 3-й тропар. Хор: «І нині». Читець – Богородичний. Хор – ірмос 6-ої пісні канону Мінеї на катавасію. Після 6-ої пісні – мала ектенія. Кондак і ікос Мінеї (якщо є). Примітка. Якщо в Мінеї кондака у рядового святого немає, то після 6-ої пісні співається мученичний Октоїха. Читається Санаксар (за вказівкою Тріоді). Пісня 7-а (з Мінеї). Хор – ірмос 7-ий пісні Мінеї і стих: «Благословенний Ти на престолі слави...». Читець – 1-й тропар. Хор: «Благословенний Ти на тверді...». Читець – 2-ий тропар. Хор: «Слава». Читець – 3-ій тропар. Хор: «І нині». Читець – Богородичний Мінеї. Пісня 8-а співається як 1-а. Хор або читець співають підряд стихи 8-ої пісні від стиха: «Благословляйте, усі діла Господні...» і до «Благословіть, вогонь і жар Господа...». Після цього стиха співається ірмос канону з Мінеї і стих: «Благословіть, роси та іній...». Читець – 1-ий тропар Мінеї. Хор: «Благословляйте, ночі і дні...». Читець – знову 1-й тропар. Хор: «Благословляйте, світло і темрява...». Читець – 2-ий тропар. Хор: «Нехай благословляє земля...». Читець – 3-ій тропар. Хор: «Благословляйте джерела...». Читець – Богородичний Мінеї. Хор: «Благословляйте, всі птахи небесні...». Читець – 1-ий тропар 1-го триспіснеця Тріоді. Хор: «Благословляйте, сини людські...». Читець – 2-ий тропар. Хор: «Благословляйте, священики Господні...». Читець – 3-й тропар. Хор: «Благословляйте, духи і душі...». Читець – Богородичний 1-го трипіснеця. Хор: «Благословляйте, Ананія, Азарія, Мисаїл...». Читець – 1-ий тропар 2-го трипіснеця. Хор: «Благословляйте, апостоли...». Читець – 2-ий тропар. Хор: «Благословимо Отця і Сина і Святого Духа, Господа». Читець – Троїчний трипіснеця. Хор: «І нині». Читець – Богородичний трипіснеця. Хор: «Слава Тобі, Боже наш, слава Тобі». Читець – тропар трипіснеця. Хор: «Хвалимо, благословимо... та ірмос 2-го трипіснеця на катавасію, глас 2-ий: «Господа, Який колись пролив...». На 9-ій пісні звершується звичайне кадіння. Співаємо «Чеснішу (з поклоном на кожен приспів). Потім ірмос 9-ої пісні з Мінеї і стих: «Благословен Господь Бог Ізраїлів...». Читець – 1-ий тропар з канону Мінеї. Хор – стих: «І підніс ріг спасіння нам...». Читець – і знову 1-ий тропар. Хор: «Як провістив...». Читець – 2-ій тропар. Хор: «Що спасе нас від ворог наших...». Читець – 3-й тропар. Хор: «сотворить милість...». Читець Богородичний канону Мінеї. Хор: «Дати нам клятву...». Читець – 1-й тропар 1-го трипіснеця. Хор: «служили Йому...». Читець – 2-й тропар. Хор: «І ти, дитя...». Читець – 3-ій тропар. Хор: «Дати розуміння...». Читець – Богородичний 1-го трипіснеця. Хор: «з ласкавого милосердя...». Читець – 1-ий тропар 2-го трипіснеця. Хор: «Спрямувати ноги наші...». Читець – 2-ий тропар. Хор: «Слава». Читець – Троїчний трипіснеця. Хор: «І нині». Читець – Богородичний трипіснеця. Хор: «Слава Тобі, Боже наш, слава Тобі». Читець – останній тропар трипіснеця. Хор – ірмос 2-го триспіснеця на катавасію, глас 2-ий: «Богородицю, що надприродно зачала в утробі й породила Слово...». Потім – «Достойно є» (поклін). Ектенія мала. Світильний Троїчний поточного гласу. За звичаєм, закінчення Світильного співаються за розспівом Троїчних тропарів. Після 1-го виконання Світильного – закінчення: «заступництвом безплотних Твоїх, і спаси мене» (в понеділок). «Слава» – той же світильний, з закінченням: «Молитвами, Господи, святих Твоїх, і спаси мене», «І нині» – знову той же світильний, з закінченням: «Молитвами, Господи, Богородиці, і спаси мене». (Перше закінчення світильного особливе для кожного дня седмиці, друге і третє закінчення – постійні). Примітка. У Світильного 6-го гласу замість закінчення змінюється початок (наприклад, перший в понеділок: «заступництво, Господи, Безплотних Твоїх, пошли душам нашим Своє світло присносущне» і т. д.). Після Світильного читець – хвалітні псалми: «Хваліте Господа з Небес...» та інші стихи (за звичаєм). Після псалмів – «Слава, і нині», «Тобі слава подобає...», і далі – виголошує читець «Слава Тобі, що показав нам світло», «Слава в вишніх Богу...» (повсякденне славослів’я). Примітка. Упродовж тижнів Великого посту (понеділок-п’ятниця) завжди читається повсякденне славослів’я, навіть в день свята Благовіщення Пресвятої Богородиці. Прохальна ектенія, і головоприклонна молитва. На стиховні стихири Тріоді, глас 5-й (зі звичайними приспівами). «Слава, і нині» – Богородичний Тріоді, глас той же: «Тебе, як Божу Матір...». Примітка. Якщо святий має на ранній стихиру на «Слава», то «Слава» – святого, «І нині» – Богородичний за гласом «Слави», а в середу і п’ятницю – Хрестобогородичний Мінеї на ряду. Якщо в Мінеї немає, то «Слава, і нині» – Богородичний Тріоді (на ряду). Читається «Благо є...» (двічі) і Трисвяте. Після «Отче наш» і виголос: «Бо Твоє є Царство...» – читається тропар Часослова: «Стоячи в храмі слави Твоєї...». «Господи, помилуй» (40). «Слава, і нині» – «Чеснішу від херувимів...». «Іменем Господнім...». Священник перед царськими вратами: «Сущий благословенний...». Читається молитва: «Небесний Царю...». Священник – молитву прп. Єфрема Сиріна: «Господи і Владико життя мого...» і 3 великих поклони; 12 малих поклонів з молитвою: «Боже, очисти мене грішного», і ще раз – «Господи і Владико життя мого...» і поклін один великий. Читець: «Амінь», і без відпусту ранньої читається 1-ий час. Відпуст ранньої відбувається після 1-го часу. Священник, за звичаєм, повертається до вівтаря, закриває завісу і знімає фелонь. Зразок звершення першого часу в понеділок, вівторок, середу, четвер і п’ятницю св. Чотиридесятниці. НА 1-МУ ЧАСІ – після трьох псалмів і «Алилуя» (тричі), у вівторок, середу і четвер читається звичайна кафизма. Перед нею «захід на кафизму»: «Господи, помилуй» (тричі), «Слава, і нині» – читається, а не співається. На «слава» кафизма переривається співом, як на ранній, тобто так звані «оспіви» кафизми співаються. Примітка. Кафизми на 1-му часі немає у понеділок та в п’ятницю упродовж Великого посту. Після кафизми (а якщо її немає, то після псалмів часу) читець: «Слава, і нині», «Алилуя» (тричі), «Господи, помилуй» (тричі). Потім священник (або «призначений читець»), ставши перед царськими вратами, співає тропар часу, на глас 6-ий: «Зранку вислухай голос моління мого, Царю мій і Боже мій», і творить земний поклін. Хор – той же тропар. Священик (або «призначений читець») – стих: «Господи почуй слова мої, зрозумій взивання моє». Хор: «Зранку вислухай голос моління мого...». Священник (або «призначений читець»): «Бо до Тебе помолюся, Господи». Хор: «Зранку вислухай голос мій...». Коли священик (або «призначений читець») промовляє тропар або стих, хор і народ творять поклін; коли ж хористи співають, тоді Священник творить поклін. Священник: «Слава» (поклону немає). Читець: «І нині» – Богородичний часу. Потім хор: «Стопи мої направ за словом Твоїм, і нехай не оволодіє мною всяке беззаконня» (двічі). Так само (по двічі) співаються наступні стихи: «Визволи мене від наклепів людських, і буду зберігати заповіді Твої»; «Лице Твоє просвіти на раба Твого і навчи мене заповітів Твоїх». Потім: «Нехай наповняться уста мої хвалою Твоєю, Господи, щоб я оспівував славу Твою, весь день велич Твою» (тричі). Примітка. Стихи часу (особливі тропарі Часослова після Богородичного часу і перед трисвятим) співаються тільки на 1-му часі, на інших часах вони читаються. Читець – Трисвяте. Після «Отче наш». Священник – виголос: «Бо Твоє є Царство...». Читець – Богородичний дня (в понеділок, вівторок і четвер – «Преславну Божу Матір...»; в середу і п’ятницю – «Поспіши на допомогу...»). «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині» – «Чеснішу від херувимів...», «Іменем Господнім...». Священник (на солії): «Боже, змилосердься над нами...». Читець: «Амінь». Священник: «Господи і Владико життя мого...», з 16 поклонами. Читається кінцеве Трисвяте. Після «Отче наш» священник – виголос. Читець: «Амінь», «Господи, помилуй» (12). Священник: «Христе, Світло Істинне...». Хор (за звичаєм): «Непереможній Воєводі...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст великий (ранньої) і многоліття. За Уставом, після закінчення 1-го часу звершується заупокійна літія, яка, на думку Типікону, є невід’ємною частиною ранкового богослужіння. Заупокійна літія по закінченні 1-го часу визначається Типіконом в усі седмичні дні. У суботу, неділю і в святкові дні цієї літії немає. Така ж літія передбачається Уставом і після відпусту вечірні в тому випадку, якщо вечірня не з’єднується з Літургією Ранішеосвячених Дарів, тобто в понеділок, вівторок і четвер. (У середу і п’ятницю вечірня служиться в поєднанні з Літургією Ранішосвячених Дарів). Не звершується заупокійна літія і після вечірні понеділка, яка служиться в неділю ввечері. Таким чином, в період Святої Чотиридесятниці Типікон призначає літії після закінчення 1-го часу і після відпусту вечірні. Вони відрізняються лише тим, що на літії після 1-го часу читають слово прп. Феодора Студита (в середу і п’ятницю). На практиці літію звершують наступним чином. У притворі (або у відповідному місці храму) заздалегідь встановлюється панахидний стіл (тетрапод). Після закінчення 1-го часу або вечірні священик бере кадило і в супроводі двох свічконосців виходить в притвор північними вратами (царські врата і завіса не відчиняються). За ним при співі самогласної стихири йдуть хористи та вірні. Стихира для співу береться зі служби престольного свята, якщо літія буде служитися в приділі храму, то стихиру співають із служби престольного свята приділу. Якщо храм чи приділ освячений в честь Воскресіння Христового, то стихиру можна брати зі служби «Оновлення храму Воскресіння Христового в Єрусалимі», а не Пасхи. Самогласною стихирою може бути стихира після 50-го псалма чи інша стихира. До прикладу: У Михайлівському Золотоверхому соборі панахидний стіл знаходиться у Варваринському приділі собору. Тоді самогласну стихиру хор буде брати зі служби святої великомучениці Варвари, а не архистратига Михаїла. Священник виголошує: «Благословен Бог наш...». Хор: «Амінь». Читець: Трисвяте по «Отче наш» священник – виголос. Хор: «Амінь» і тропарі, глас 4-ий: «З духами спочилих праведників...», «В оселях Твоїх, Господи...». «Слава» – «Ти єси Бог», «І нині» – «Єдина, Чиста...». Священник виголошує «заупокійну ектенію: «Помилуй нас, Боже...», «Ще молимося за упокоєння..», «Щоб Господь Бог...», «Милості Божої...». «Господу помолимось». Хор: «Господи, помилуй». Священник читає тихо молитву: «Боже духів...», і виголошує: «Бо Ти єси Воскресіння...». «Слава Тобі, Христе Боже...» і т. д. Відпуст: «Христос, що воскрес із мертвих...». Після відпусту виголошується і співається особливий стих: «Вічная ваша пам’ять, достоблаженні отці і матері, брати і сестри наші, приснопам’ятні» (тричі). Під час цього стиха священик навколо кадить тетрапод (тричі), потім промовляє: «Нехай Бог ублажить і упокоїть їх а нас помилує, як Благий і Людинолюбний» (один раз). Зразок звершення 3-го, 6-го і 9-го часу в понеділок, вівторок, середу, четвер і п’ятницю св. Чотиридесятниці. Великопостові часи 3-ій, 6-ий і 9-ий зазвичай звершуються разом із зображальними і вечірньою (якщо не звершується Літургія Ранішеосвячених Дарів). За традицією, перед кожним часом вдаряють у дзвін відповідно 3, 6 або 9 разів, перед зображальними – 12 разів, перед вечірньою – дзвонять у два дзвони. 3-ІЙ ЧАС. Священник в єпитрахилі, перед царськими вратами (завіса не відкривається) зробивши три поклони (поясних), виголошує виголос: «Благословен Бог наш...». Читець: «Амінь», «Слава Тобі, Боже наш...» та іншу послідовність 3-го часу, як зазвичай. Після закінчення третього псалма – «Слава, і нині», «Алилуя» – і читається звичайна (в понеділок – 7-ма) кафизма, розділена на три «Слави» (порядок читання той же, що зазначений на 1-му часі). Після кафизми священник (або «призначений читець») перед царськими вратами співає тропар часу, глас 6-ий: «Господи, Ти що Пресвятого Твого Духа...» і стих: «Серце чисте створи в мені, Боже...»; «Не відкинь мене від лиця Твого...». Після виконання тропаря і поклонів священник (або «призначений читець»): «Слава». Читець: «І нині» – Богородичний часу: «Богородице, Ти єси виноградна лоза істинна...». Після молитви «Ти, що кожного часу...» священник (на солії) виголошує виголос: «Боже, змилосердься над нами...». Читець: «Амінь». Священник читає молитву прп. Єфрема Сиріна з 16 поклонами. Молитва: «Владико Боже...», і починається 6-ий час. 6-ИЙ ЧАС. Псалми і кафизма (в понеділок – 8-а) читаються в тому ж порядку, що і на 3-му часі. Після кафизми, як і на 3-му часі, співається тропар часу, глас 2-й: «Ти, що в шостий день же і годину...». Стих: «Вислухай, Боже, молитву мою...»; «Я до Бога взивав...». «Слава». Читець: «І нині» – Богородичний часу: «Через превеликі гріхи наші сміливості не маємо...». Тропар пророцтва (з Тріоді). «Слава, і нині» – той же тропар. Священник (або диякон): «Будьмо уважні». Читець – прокимен (Тріоді, зі стихом. Священник (або диякон): «Премудрість». Читець: «Пророцтва Ісаї читання». Священник (або диякон): «Будьмо уважні». Читається паремія Тріоді. Після закінчення читання паремії священник (або диякон): «Будьмо уважні». Читець – прокимен (Тріоді), із стихом. Після співу прокимну читець: «Скоро пошли нам...», Трисвяте. Після «Отче наш» священник – виголос. Читець – тропар: «Спасіння вчинив єси...», «Слава» – «Пречистому Образу Твоєму...». На «І нині» – в понеділок, вівторок і четвер – «Богородице, Ти єси Джерело милосердя...»; в середу і п’ятницю – Хрестобогородичний: «Препрославлена Ти, Богородице Діво...». «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Священник (на солії): «Боже, змилосердься над нами...» і читає молитву прп. Єфрема Сиріна з 16 поклонами. Молитва: «Боже і Господи Сил...», і починається 9-ий час. 9-ИЙ звершується так само, як і попередні (в понеділок на 9-му часі – 9-а кафизма). Тропар 9-го часу, глас 8-ий: «Ти, що в дев’ятій годині...». Стих: «Нехай наблизиться молитва моя...»; «Нехай дійде благання моє...». В кінці 9-го часу, після «Боже, змилосердься над нами...», священник читає молитву прп. Єфрема Сиріна з трьома великими поклонами. Молитва: «Владико, Господи Ісусе Христе, Боже наш...», і починаються зображальні. Зразок звершення зображальних в понеділок, вівторок і четвер св. Чотиридесятниці ЗОБРАЖАЛЬНІ. Після молитви 9-го часу священник, за традицією, одягається в фелонь, як на ранній і залишається в облаченні до закінчення вечірньої. За звичаєм, відкривається завіса Царських врат. Хор співає: «У Царстві Твоїм пом’яни нас, Господи, коли прийдеш у царство Твоє». В кінці на «Слава» – «Пом’яни нас, Господи...», на «І нині» – «Пом’яни нас, Господи...». Потім повільно і голосно (з трьома земними поклонами): «Пом’яни нас, Господи, коли прийдеш у царство Твоє», «Пом’яни нас, Владико, коли прийдеш у царство Твоє», «Пом’яни нас, Святий, коли прийдеш у царство Твоє». Читець: «Хор Небесний...». Стих: «Приступіть до Нього і просвітіться...», «Хор Небесний...», «Слава» – «Хор святих Ангелів і Архангелів...», «І нині» – «Вірую...», «Полегши, відпусти...», «Отче наш». Священник – виголос: «Бо Твоє є Царство...». Кондаки на зображальних: У храмі Господському (в понеділок, вівторок, четвер) – кондак храму, кондак дня (в четвер – два), кондак рядового святого Мінеї (якщо є). «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». У храмі Богородиці – кондак дня (в четвер – два), кондак рядового святого Мінеї (якщо є). «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – кондак дня (в четвер – два), кондак храму, кондак рядового святого Мінеї (якщо є). «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Примітка. У вівторок кондак храму Предтечі не читається, а в четвер – кондак апостольського храму або свт. Миколая, оскільки вони замінюються денними. Примітка. Якщо на ранній кондак рядового святого був відсутній, то на зображальних він також не читається. «Господи, помилуй» (40), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Священник (перед царськими вратами): «Боже, змилосердься над нами...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна з 16 поклонами. Зразок звершення вечірні в св. Чотиридесятницю, коли не буває Літургії Ранішосвячених Дарів. ВЕЧІРНЯ повсякденна, що звершується в понеділок, вівторок і четвер Чотиридесятниці, слідує за зображальними без початкового виголосу. Після поклонів з молитвою прп. Єфрема Сиріна, призначених в кінці зображальних, читець: «Амінь». «Прийдіть, поклонімось...» (тричі) і Початковий псалом: «Благослови, душе моя, Господа...» (священник читає перед царськими вратами світильничні молитви). Після псалмів – велика ектенія. Потім кафизма 18-та. Кафизму на вечірній починають читати без так званого «заходу», тобто немає «Господи, помилуй» (тричі) і «Слава і нині». А далі на «Славах» хор співає. Третю «Славу» читає читець. Після кафизми – мала ектенія. «Господи, взиваю» на глас стихир Тріоді. Під час співу стихир звершується звичайне кадіння. Стихири на 6: Тріоді, глас 2-ий і глас 5-ий – 3, і Мінеї – 3 (24 лютого прп. Еразма Печерського). «Слава, і нині» – Богородичний Мінеї. Примітка. Службу прп. Еразма Печерського відправляємо за загальною Мінеєю – служба преподобному одному, або можна використати службу загальну преподобному Печерському одному, що міститься в Мінеї за вересень. Примітка. За вказівкою Типікона Служба першого і другого знайдення чесної голови Іоана Предтечі переноситься на сиропусну неділю. Входу немає. Читець (або хор): «Світло Тихе...». Диякон виголошує (у вівтарі): «Будьмо уважні». Священник: «Мир всім». Читець: «І духові твоєму». Диякон: «Премудрість. Будьмо уважні». Читець – прокимен першої паремії Тріоді, зі стихом. Диякон: «Премудрість». Читець: «Буття читання». Диякон: «Будьмо уважні». Читання першої паремії. Після закінчення паремії диякон: «Будьмо уважні». Читець – прокимен другий паремії Тріоді, зі стихом. Диякон: «Премудрість». Читець: «Притч читання». Диякон: «Будьмо уважні». Читання другої паремії. Примітка. Протягом всієї св. Чотиридесятниці на вечірніх читаються: перша паремія – з Буття, друга – з книги Притч. Після закінчення паремій читається: «Сподоби, Господи...». Прохальна ектенія, і голововклонна молитва. Після виголосу хористи співають стихири на стиховні з Тріоді, глас 3-ій (з звичайними приспівами). «Слава, і нині» – Богородичний Тріоді, глас той же. Після стихир читається: «Нині відпускаєш», Трисвяте. Після «Отче наш» священник – виголос (на солії): «Бо Твоє є Царство...». Хор: «Амінь». І співають тропарі, глас 4-ий: «Богородице Діво...» (поклін). «Слава» – «Хрестителю Христів...» (поклін), «І нині» – «Моліться за нас...» (поклін). Потім – «Під Твою милість...» (без поклону). Читець: «Господи, помилуй» (40), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Священник: «Сущий благословенний...» (на солії). Читається молитва: «Небесний Царю...». Священник – молитву прп. Єфрема Сиріна: «Господи і Владико життя мого...», і творимо звичайні поклони (16). Священник повертається у вівтар. Читається кінцеве Трисвяте. Після «Отче наш» священник – виголос. Читець: «Амінь», «Господи, помилуй» (12). Молитва: «Всесвята Тройце...». «Нехай буде благословенне ім’я Господнє...» (тричі), «Слава, і нині», псалом 33-й: «Благословлю Господа на всякий час...» (повністю). Священник (або диякон): «Премудрість». Хор: «Достойно є...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник – великий відпуст, на якому згадується святий наступного дня (в даному випадку – 24 лютого – прп. Еразма Печерського). Хор – многоліття. Закривається завіса Царських врат. Звершується заупокійна літія. ВЕЛИКЕ ПОВЕЧІР’Я. Під час Великого посту, ввечері тих днів, коли не було повної Літургії (за винятком вечора середи і п’ятниці 5-го тижня), завжди звершується велике повечір’я. Велике повечір’я служиться окремо від вечірні. У понеділок – четвер 1-го тижня на великому повечір’ї співається Великий канон прп. Андрія Критського. Перед повечір’ям вдаряють в дзвін – 12 ударів. Священник в єпитрахилі, створивши перед царськими вратами (при закритій завісі) три поклони, виголошує: «Благословен Бог наш...». Читець: «Амінь», «Слава Тобі, Боже наш, слава Тобі», «Царю Небесний», Трисвяте. Після «Отче наш» Священник – виголос: «Бо Твоє є Царство...». Читець: «Амінь», «Господи, помилуй» (12), «Слава, і нині», «Прийдіть, поклонімось...» (тричі) і псалом 69-ий: «Боже, на поміч мені прийди...». Примітка. Цей псалом читається на початку повечір’я тільки в перші чотири дні 1-го тижня Великого посту в зв’язку з покладеним тут співом Великого канону прп. Андрія Критського. В інші дні він читається на своєму місці – після молитви «Владико, Боже Отче Вседержителю...». Примітка. Враховуючи реалії сучасного життя, а також значення для вірних Великого покаянного канону прп. Андрія Критського, то з благословення настоятеля можна канон прочитати на великому повечір’ї після 142 псалма і повсякденного славослів’я. За традицією, під час читання псалма священник в єпитрахилі виходить на середину храму, де стоїть аналой з приготованим текстом Великого канону прп. Андрія Критського. Ієромонахи в єпитрахилі та в мантії. Після закінчення псалма хор співає ірмос: «Помічник і Покровитель...», і далі йде канон (ірмоси по двічі, тропарі всі, скільки є). Хористи співають ірмоси і приспівами. Ектеній і катавасій немає. Після 6-ої пісні – «Господи, помилуй» (тричі), «Слава, і нині», і кондак Великого канону, глас 6-ий: «Душе моя, душе моя...». Після 9-ої пісні повторюється ірмос: «Безсіменного зачаття...» (і поклін). Примітка. Устав передбачає, що всі тропарі канону прп. Андрія Критського мають співатися. Така традиція сьогодні існує лише в деяких монастирях. На практиці тропарі канону читає священнослужитель. Після закінчення канону продовжується повечір’я від псалма «Коли взиваю я...». Після псалма 90-го – спів (за Уставом, антифонний): «З нами Бог...» з приспівом: «Бо з нами Бог» на кожен стих. Після стиха «Отець будучого віку» і приспіву «Бо з нами Бог» хор співає перший стих: «З нами Бог...» (з приспівом), потім співається (обома хорами): «З нами Бог, розумійте, народи, і покоряйтеся, бо з нами Бог». Потім «Слава» – перший хор: «З нами Бог...», «І нині» – другий хор: «З нами Бог...». І на завершення – обидва хори: «Бо з нами Бог». Після «З нами Бог...» – тропар: «День проживши, дякую...». «Слава» – «День проживши, славословлю...», «І нині» – «День проживши, прославляю...», «безплотне єство Херувимське...» і «Вірую...». Після «Вірую...» співаються стихи: «Пресвята Владичице Богородице і все інше за Уставом.: «Пресвята Владичице Богородице, моли про нас, грішних» (поклін). «Всі Небесні Сили святих Ангелів і Архангелів, моліть за нас, грішних» (поклін). «Святий Іоане, Пророче і Предтечі і Хрестителю Господа нашого Ісуса Христа, моли за нас, грішних» (поклін). «Святі славні апостоли, пророки і мученики, і всі святі, моліть за нас, грішних» (поклін). «Преподобні і богоносні отці наші, пастирі і вчителі вселенські, моліть за нас, грішних» (поклін). «Преподобні і богоносні отці наші, Антонію і Феодосію, та інші чудотворці Печерські моліть за нас грішних» (поклін). Стих із згадкою храмового святого (поклін). «Непереможна, і незбагненна, і Божественна сило Чесного і Животворчого Хреста, не покинь нас, грішних» (поклін). «Боже, очисти нас, грішних» (поклін). «Боже, очисти нас, грішних, і помилуй нас» (поклін). Потім читець – Трисвяте (це Трисвяте в чині великого повечір’я називається першим). Після «Отче наш» і виголосу священника співаємо тропарі: в понеділок і середу – на глас 2-ий: «Просвіти очі мої, Христе Боже...». «Слава» – «Боже будь Заступником душі моєї...», «І нині»... У вівторок і четвер – на глас 8-ий: «Невидимих ворогів моїх...»; стих: «Зглянься і вислухай мене, Господи, Боже мій...»; «Бо страшний суд Твій, Господи...». «Слава» – «Сльози мені дай, Боже...», «І нині»... «Господи, помилуй» (40). «Іменем Господнім...». Священник: «Молитвами святих отців наших...». Молитва свт. Василія Великого: «Господи, Господи...». «Прийдіть, поклонімось...», псалом 50-ий, псалом 101-ий, молитва царя Манасії і Трисвяте (це Трисвяте в Типіконі називається другим). Після «Отче наш» і виголос священника спів тропарів, глас 6-ий: «Помилуй нас, Господи...». «Слава» – «Господи, помилуй нас...», «І нині» – «Милосердя двері...». Читець: «Господи, помилуй» (40). «Слава, і нині» – «Чеснішу», «Іменем Господнім...». Священник: «Молитвами святих отців наших...». Молитва: «Владико Отче...». «Прийдіть, поклонімось...». Примітка. Далі, – крім перших чотирьох днів Великого посту, – читається псалом 69-ий: «Боже, на поміч мені прийди...». У понеділок – четвер 1-го тижня цей псалом тут пропускається, оскільки прочитується на початку повечір’я. Псалом 142-ий: «Господи, почуй молитву мою...», повсякденне славослів’я: «Слава в вишніх Богу...». Примітка. Після прочитання славослів’я, з благословення настоятеля, заради блага вірних тут може читатися Великий покаянний канон Андрія Критського. Про особливості виконання канону дивись вище. Примітка. У седмичні дні св. Чотиридесятниці, крім перших чотирьох днів 1-го тижня, після «Слава в вишніх Богу...» читається канон Богородиці Октоїха і канон (зі стихирами) рядового святого, а по закінченні їх – «Достойно є...». Потім читець – Трисвяте (це Трисвяте в чині великого повечір’я називається третім). Після «Отче наш» і виголосу священника співаємо на глас 6-ий: «Господи Сил, будь з нами...». Це співають з п’ятьма хвалітніми стихами співається, за Уставом, антифонно. А після виконання п’яти стихів повторюється перший стих і тропар. Потім: «Слава» – «Господи, якщо б ми не мали святих Твоїх молитовників...», «І нині» – «Велика безліч моїх, Богородице, гріхів...», «Всесвята Богородиці, під час життя мого не покинь мене...», «Все уповання моє на Тебе покладаю...». Читець: «Господи, помилуй» (40). Молитва: «Ти що кожного часу...». «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Священник (на солії): «Боже, змилосердься над нами і благослови нас...», і молитву прп. Єфрема Сиріна: «Господи і Владико життя мого...» (з 16 поклонами). Священник повертається у вівтар. Читається кінцеве Трисвяте. Після «Отче наш» і виголосу – «Господи, помилуй» (12), молитва: «Непорочна, Пречиста...», «І дай нам, Владико...», «Преславна Приснодіво...», та інше. Священник (на солії): «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник з непокритою головою, на колінах повернувшись до присутніх в храмі читає молитву відпусту: «Владико Многомилостивий...» (за вказівкою Типікону на колінах стоять лише вірні, а священник говорить молитву стоячи). Після молитви, Священник творить поклін до народу промовляючи: «Благословіть, отці святі, дорогі браття і сестри і простіть мені грішному все чим згрішив я перед вами у всі дні життя мого, словом, ділом і думкою та всіма моїми почуттями». Присутні відповідають: «Бог нехай простить тебе, отче святий» (або «Бог нехай простить тобі, отче святий, помолися за нас, грішних»). Священник, звернувшись до вівтаря, виголошує прохання ектенії: «Помолимось за Блаженнішого Владику і отця нашого...», «За Богом бережену Україну нашу...», «За тих, хто ненавидить і любить нас» і все інше за Уставом (Див. Часослов). Після кожного стиха хор: «Господи, помилуй» тихо по одному разу. В кінці Священник підвищеним голосом промовляє: «Промовмо і за себе самих», хор голосніше співає – «Господи, помилуй» (тричі). Священник: «Молитвами святих отців наших...». Хор: «Амінь». [1] Священник перебуває одягненим в єпитрахиль, фелонь і, за традицією, в поручі до кінця ранній. [2] «Священник... входить у святий вівтар, і прийнявши кадило, промовляє і молитву кадила. І ставши перед престолом, кадить хрестоподібно, і виголошує: Благословенний Бог наш, завжди, нині і повсякчас, і на віки віків. [3] В суботи Великого посту в Тріоді є четверопіснеці (що складаються з 6-ої, 7-ої, 8-ої і 9-ої пісні), виняток становить Субота 1-го тижня Великого посту."}]},
{"date":"02-24","weekday":"вівторок","title":"Перше (ІV) і друге (452) знайдення голови Іоана Предтечі. Прп. Еразма Києво-Печерського, в Ближніх печерах (бл. 1160).","notes":"На 6-му часі: Іс. I, 19 – II, 3. На веч.: Бут. I, 14 – 23. Притч. I, 20 – 33. Примітка. Якщо у вівторок, середу, четвер або п’ятницю 1-го тижня посту припаде храмове або Полієлейне свято, то служба свята переноситься на суботу 1-ї седмиці посту і поєднується зі службою влмч. Феодора Тирона (див. Типікон, 31-а і 32-а Храмові глави, 8-а Маркова глава за 24 лютого).","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ вся служба звершується, як зазначено в понеділок. Особливості наступні: приспів до закінчення першого Троїчного тропаря: «Свят, свят, свят єси, Боже наш, молитвами Предтечі Твого помилуй нас». На «Слава» і на «І нині» закінчення Троїчного ті ж, що і в понеділок. Кафизми 10-та, 11-та і 12-та. Скорочена загальна схема виконання канону у вівторок (якщо один канон Мінеї): Співається ірмос 1-ої пісні канону з Мінеї і стих (на 4): «Господь, царює повік віку». Читець – 1-ий тропар канону Мінеї. Хор: «То повернув на них Господь...». Читець – 2-ий тропар. Хор: «Слава». Читець – 3-ій тропар. Хор: «І нині». Читець – Богородичний канону Мінеї. Далі – «швидко» 2-а біблійна пісня: «Слухайте, небеса, і промовлятиму...» (повністю) [1]. Потім хор співає ірмос 2-ої пісні Тріоді (трипіснець по вівторках складається з 2-ої, 8-ої і 9-ої пісень), на 2-ий глас: «Бачите, бачите...» і потім – «Слава Тобі, Боже наш, слава Тобі», і читається тропар Тріоді. Перед наступними двома тропарями також співається: «Слава Тобі, Боже наш, слава Тобі». Перед Богородичним співається: «Пресвята Богородице, спаси нас». Після Богородичного хор: «Слава Тобі, Боже наш, слава Тобі», і промовляє тропар 2-го трипіснеця. Так само і перед наступним тропарем. Потім хор: «Слава». Читець – Троїчний. Хор: «І нині». Читець – Богородочний. Хор: «Слава Тобі, Боже наш, слава Тобі». Читець – тропар. Хор – ірмос 2-го трипіснеця, глас 5-ий: «Бачите, бачите...». У вівторок на 2-і пісні покладені два ірмоса: один (2- го гласу) – на початку, другий (5-го гласу) – на катавасію. Наступні пісні канону, з 3-ої по 9-у, виконуються як в понеділок. Після 3-ої пісні – сідальний Мінеї. «Слава, і нині» – Богородичний Мінеї,. Після 6-й пісні – кондак Мінеї Світильний у вівторок має закінчення: «... молитвами, Господи, Предтечі Твого, і спаси мене». На «Слава» та «І нині» закінчення ті ж, що і в понеділок. На стиховні стихири Тріоді, глас 3-ій (з звичайними приспівами). «Слава, і нині» – Богородичний Тріоді, глас той же: «Богородице, Заступнице всіх...». Інше – як в понеділок. Часи 1-ий, 3-ій, 6-ий і 9-ий відбуваються як в понеділок. На 1-му часі – кафизма 13-та; на 3-му часі – кафизма 14-та; на 6-му часі – кафизма 15-та; на 9-му часі – кафизма 16-та. На 6-му часі – 1-ий прокимен, глас 4-ий: «Вислухай голос моління мого, Царю мій і Боже мій»; стих: «Вислухай слова мої...». 2-ий прокимен, глас той же: «Господи, не суди мене в ярості Твоїй і не карай мене у гніві Твоїм»; стих: «Помилуй мене, Господи...». Зображальні. Детальний виклад порядку богослужіння зображальних і вечірні див. 23 лютого. Кондаки на зображальних: У храмі Господському – кондак храму, кондак дня, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». У храмі Богородиці – кондак дня, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – кондак дня, кондак храму, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Примітка. Кондак храму Предтечі не читається."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири на 6: Тріоді, глас 2-ий – 3, і Мінеї, глас 2-ий – 3 (25 лютого, свт. Тарасія Константинопольського). «Слава, і нині» – Хрестобогородичний Мінеї, глас той же: «Дозріле гроно...». Паремії Тріоді читаються з Прокимнами: 1-ий прокимен, глас 6-ий: «Господи, Боже мій! Я на Тебе надіюся, спаси мене», стих: «Від усіх гонителів моїх визволи мене.»; 2-ий прокимен, глас 5-ий: «Господи Боже наш, яке величне ім’я Твоє по всій землі», стих: «Слава Твоя піднеслася вище небес». Стихири на стиховні Тріоді, глас 8-ий (з звичайними приспівами). «Слава, і нині» – Хрестобогородичний Тріоді, глас той же: «О преславне чудо!..». Закінчення вечірні – див. Понеділок ввечері 1-го тижня 23 лютого. ВЕЛИКЕ ПОВЕЧІР’Я з каноном прп. Андрія Критського за чином понеділка 1-го тижня 3 березня. [1]. Стихи 2-ої біблійної пісні співаються тільки по вівторках святої Чотиридесятниці."}]},
{"date":"02-25","weekday":"середа","title":"Свт. Тарасія, архієп. Константинопольського (806). Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. II, 3 – 11. На веч.: Бут. I, 24 – II, 3. Притч. II, 1 – 22. Детальний виклад порядку богослужіння ранньої і часів див 23 лютого. РАННЯ звершується, як зазначено в понеділок. Особливості: до першого Троїчного тропаря закінчення: «Свят, свят, свят єси, Боже наш, силою Хреста Твого збережи нас, Господи». Кафизми 19-та, 20-та і 1-ша. Трипіснець складається з 3-ої, 8-ої і 9-ої пісень. 1-а пісня канону співається так само, як у вівторок (Ірмос Мінеї і тропарі зі стихами на 4). 2-а пісня не співається. 3-тя пісня співається подібно до 1-ої в понеділок (оскільки з’єднується з трипіснецями). Пісні з 4-ої по 9-у співаються як в понеділок. Після 3-ої пісні – сідальний преподобних, глас 8-ий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той же. Після 6-ої пісні – кондак святителя, глас 3-ій. До Світильного перше закінчення: «... силою, Господи, Хреста Твого і спаси мене». На стиховні стихири Тріоді, глас 8-ий (зі звичайними приспівами). «Слава, і нині» – Хрестобогородичний Тріоді, глас той же. Інше – як в понеділок. ЧАСИ 1-ИЙ, 3-ІЙ, 6-ИЙ І 9-ИЙ звершуються як в понеділок. На 1-му часі – кафизма 2-га, на 3-му часі – кафизма 3-тя, на 6-му часі – кафизма 4-та, на 9-му часі – кафизма 5-та. На 6-му часі 1-ий прокимен, глас 4-ий: «Славитиму Тебе, Господи, всім серцем моїм»; стих: «Буду веселитися й хвалитися Тобою». 2-ий прокимен, глас 6-й: «Праведний Господь, і любить правду. На праведних дивиться лице Його»; стих: «На Господа я надіюся, як же ви кажете душі моїй...». Зображальні. Детальний виклад порядку зображальних 23 лютого. У храмі Господському – кондак денний: «Вознісся на Хрест...», кондак Мінеї, глас 3-ій: «Чистотою поживши на землі...». «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...», а кондак храму опускається. Кондаки в храмі Богородиці і святого – в тому ж порядку, що і в понеділок. Зразок завершення послідовності зображальних в середу і п’ятницю (перед Літургією Ранішосвячених Дарів) Після молитви прп. Єфрема Сиріна з 16 поклонами читається кінцеве Трисвяте. Після «Отче наш» священник – виголос. Читець: «Амінь», «Господи, помилуй» (12). Молитва: «Всесвята Тройце...». священник на солії при закритих царських вратах звершує відпуст наступним чином. священник (або диякон): «Премудрість». Хор: співає «Достойно є...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник виголошує відпуст: «Христос, істинний Бог наш...». Хор – «Господи, помилуй» (тричі). Многоліття, за традицією, не співаються. Священник повертається у вівтар. Практика служіння літургії Ранішосвячених Дарів священичим чином Примітка. Літургія Ранішосвячених Дарів звершується по середах і п’ятницях Великого посту, а на п’ятому тижні посту – і в четвер (коли на «Маріїному стоянні» читається Великий покаянний канон прп. Андрія Критського) і в понеділок, вівторок та середу Страсного тижня, храмове або полієлейне свято, які випадають на 2-му, 3-му, 4-му, 5-му, 6-му тижні, окрім суботи та неділі. Але, в силу різних обставин, вона може служитися і в інші дні Святої Чотиридесятниці, за винятком тих днів, коли за уставом належить служити повну літургію. Звершення даної літургії в інших випадках, наприклад, заради поховання або поминання покійних, буде неприпустимим і невиправданим порушенням Уставу, оскільки за сучасною практикою на літургії Ранішосвячених Дарів немає самих важливих і дієвих поминань: в кінці анафори (Євхаристійного канону) та виймання частинок в пам’ять спочилих і обмиванням їх в Крові Христовій. Саме тому, що літургія Ранішосвячених Дарів не може бути заупокійною, в її чинопослідуванні не передбачається виголошення заупокійної ектенії і приєднання будь-яких заупокійних співів (за вийнятком стихир на вечірні на «Господи, взиваю...» в п’ятниці 2-го, 3-го і 4-готижнів, оскільки в суботи цих тижнів відбувається поминання спочилих. За своїм призначенням літургія Ранішосвячених Дарів тісно пов’язана з Великим постом, святою Чотиридесятницею. Древність посту вказує і на древність богослужіння, яке суттєво відносилось до цього священного періоду життя Церкви. Якщо випаде потреба звершити заупокійну Літургію з понеділка до п’ятниці у зв’язку із упокоєнням священнослужителя, необхідно отримати благословення правлячого єпископа на її служіння. Якщо похорон священика буде в середу чи п’ятницю, і був напередодні заготовлений агнець, тоді звершується Літургія Ранішеосвячених Дарів, але без заупокійного апостола, Євангелія та ектенії. Літургія Ранішoсвячених Дарів має такі особливості: в ній немає Проскомидії; літургії передують 3-ій, 6-ий, 9-ий часи з послідуванням Зображальних. Симеон Солунський, говорячи про послідування Зображальних, зазначає: «Послідування Зображальних так називається тому, що зображує певним чином священну літургію...». До цього слід додати, що Зображальні і за значенням своїм доволі близькими є до Божественної літургії, сповна виправдовують свою назву – «пролітургія», тобто служба, яка звершується перед літургією, або замість неї. Після відпусту Зображальних розпочинається Вечірня, яка замінює початкову частину літургії оголошених (остання її частина є і в літургії Ранішосвячених Дарів); На літургії вірних немає молитов і піснеспівів, що відносяться до приготування і перетворення Святих Дарів. Для кожної літургії Ранішосвячених Дарів священик заготовляє святого Агнця на проскомидії попередньої літургії в неділю. Заготовляючи святого Агнця на проскомидії, священик спочатку заготовляє святого Агнця для літургії, яку має звершувати, а тоді для літургії Ранішосвячених Дарів, вирізуючи, виймаючи та виколюючи святого Агнця з окремих просфор, і промовляє над кожним слова: «На спомин Господа і Бога, і Спаса нашого Ісуса Христа (тричі). Як ягня на заколення ведено Його. І як агнець непорочний перед тим, що стриже його, мовчить, – так і Він не відкриває уст Своїх. У смиренні Його суд над Ним відбувся. Але про рід Його хто оповість? Бо візьметься від землі життя Його. Приноситься в жертву Агнець Божий, що бере гріхи світу ради життя світу і спасіння. Один із воїнів списом проколов Йому ребра, і зараз витекла кров і вода. І той, що бачив, засвідчив, і свідчення Його правдиве». Далі священик творить все, як звичайно: вливає в святу чашу вино і воду, накриває їх покрівцями, читає молитви і т. д. На літургії під час святої Євхаристії, після призивання Святого Духа, священик, коли показує на Святий Хліб, то каже: «Хліб цей...» (в однині, Христос – Єдиний, тому не можна казати: Хліби ці). Коли священик творить піднесення Хліба, то при словах Святеє святим підноситься усе разом, а тоді розломлює першого святого Агнця, для літургії, що звершується, кладе частинки, вливає теплоту та ін., як звичайно. Далі правою рукою бере лжицю, а лівою – святого Агнця для літургії Ранішосвячених Дарів і лжицею, змоченою в святій Крові, хрестовино торкається святого Агнця з хрестовидно надрізаного боку. Тоді кладе святого Агнця в дарохранительницю (кивот). Так само чинить і над кожним святим Агнцем, що заготовляється для літургії Ранішосвячених Дарів, кладе його в дарохранительницю. Далі молиться, причащається і взагалі священнодіє, як звичайно на літургії. Примітка. Священик приготовляє себе до звершення літургії Ранішосвячених Дарів тими молитвами, що й перед повною літургією, а також виконує всі інші вимоги. Перед літургією Ранішoсвячених Дарів вхідні молитви відбуваються так: з початком співу «У Царстві Твоїм...» відкривається завіса; священик і диякон боковими дверима виходять з вівтаря до Царських врат і, вчинивши перед ними три поясних поклони, здійснюють звичайний початок та іншу послідовність вхідних молитов (починають з «Помилуй нас Господи...», а не з Благословен Бог наш...). Потім підходять до ікони Спасителя, читаючи тропар: «Пречистому Образу Твоєму...», роблять два земних поклони (так за Уставом; однак, за усталеною практикою, поклони робляться поясні), цілують ікону і роблять третій земний поклін. У такому ж порядку вони кланяються і цілують ікону Богородиці, читаючи тропар: «Богородице, Ти єси джерело милосердя!...». Також кланяються і цілують ікони храму і свята (якщо є). До складу вхідних молитов входять ті ж молитви, що і на повній літургії, за винятком: «Господи, простягни руку Твою...», якою подається від Господа допомога на звершення Безкровної Жертви. Скуфії та камилавки та клобуки прийнято знімати, як і перед повною літургією, при цілуванні святих ікон. Після поклоніння святим іконам священик і диякон, ставши перед царськими вратами, читають: «Послаб, прости...» і роблять один поясний поклін. Потім, повернувшись до народу, творять також поясний поклін, просячи прощення, і входять у вівтар. Після входу у вівтар священнослужителі двічі поклоняються перед святим престолом до землі, цілують престіл, хрест на ньому і Євангеліє і, зробивши третій поклін, кланяються один одному, а потім одягаються в священничі одежі (молитви на одягання облачення не читаються). Священнослужителі облачаються до відпусту Зображальних. Священник благословляє рукою кожну приналежність риз, цілує на ній хрест і вимовляє тихо: «Господу помолимось.». По завершенні Зображальних священник на солії творить відпуст і повертається у вівтар. Зразок Літургії подаємо за редакцією Служебника Православної Церкви України. Священник з дияконом роблять три малих поклони перед святим престолом і моляться: «Боже, очисти мене грішного». Диякон мовчки приймає благословення від священика, виходить північними дверима на солію, а священник відкриває царські врата. Диякон помолившись, виголошує: «Благослови, владико». Священник, стоячи перед престолом і творячи хрест Євангелієм, вимовляє початковий виголос: «Благословенне Царство...». Хор: «Амінь.». Священник закриває царські врата і виходить північними дверима до диякона. Читець: «Прийдіть, поклонімось...» (тричі) і 103-ій (початковий) псалом: «Благослови душе моя Господа». Під час читання псалма священик таємно читає з непокритою головою перед царськими вратами світильничні молитви, починаючи з 4-ї: «Ти, в невмовкних піснях і безупинних славословленнях святими Силами оспівуваний...». Три перші молитви тут не читаються, оскільки вони будуть прочитані пізніше. Після виконання псалма. Священник відкриває царські врата. – Велика ектенія. Хор співає: «Господи, помилуй» великопостовим розспівом. Під час ектенії священик читає (таємно) молитву 1-го антифону (1-у світильничну молитву): «Господи Щедрий і Милостивий...». По закінченні ектенії священник виголошує: «Бо Тобі належить усяка слава...». Царські врата закривають. Кафизма 18-та,особливість читання якої полягає в тому, що після кожного антифону кафизми на вечірні Літургії Ранішосвячених Дарів виголошується мала ектенія. Під час 1-го антифону священник відставляє Євангеліє, що лежить на святому антимінсі, на праву сторону престолу, розкриває антимінс і поставляє на нього дискос, відкриває дарохранительницю, яка стоїть на горньому місці престолу і, зробивши з дияконом земний поклін покладає із благоговінням Ранішосвячений Агнець на дискос (в деяких храмах – за допомогою копія і лжиці), за вказівкою служебника після покладення св. Агнеця на дискос поклону не потрібно робити. До цього часу читець закінчує перший антифон: «Слава, і нині...». «Алилуя» (тричі). Відкривають царські врата. Диякон виголошує малу ектенію, під час якої священик у вівтарі читає (таємно) молитву 2-го антифону (2-гу світильничну молитву): «Господи, не суди нас в суворості Твоїй і не карай нас у гніві Твоїм...». Після закінчення ектенії священник виголошує: «Бо Твоя влада...». Хор: «Амінь.». Царські врата закривають. Читець – 2-ий антифон кафизми. Під час 2-го антифону звершується кадіння Святого Агнця, що знаходиться на престолі. Після виголосу «Бо Твоя влада і Твоє є Царство...». Потім Священник з кадилом, диякон зі свічкою тричі здійснюють кадіння навколо престолу. Царські врата відкривають. . Диякон виголошує малу ектенію, під час якої Священник читає (таємно) молитву третього антифону (третю світильничну молитву): «Господи Боже наш, пом’яни нас, грішних і негідних рабів Твоїх...». Після закінчення ектенії Священник виголошує: «Бо Ти Благий і Людинолюбний Бог єси...». Хор: «Амінь.». Читець – 3-ій антифон кафизми. Царські врата закривають. Під час 3-го антифону відбувається перенесення Святого Агнця на жертовник. Священник творить земний поклін перед Святими Дарами, потім, тримаючи дискос перед собою. Перед священиком йде диякон із свічкою в лівій руці і кадилом у правій, переносить дискос на жертовник, йдучи через горнє місце. У цей час всі, що моляться у вівтарі стають на коліна. За благочестивим звичаєм, під час читання третього антифону всі, хто молиться в храмі, також схиляють коліна. Священник біля жертовника вливає в чашу вино з водою, кадить спочатку звіздицю, ставить її на дискос, потім кадить малі покрівці, покриває ними, як звичайно, дискос і чашу (потир). Потім, обкадивши великий воздух, покриває ним дискос і чашу разом, не вимовляючи ніяких проскомидійних молитов. При кожному священнодіянні священник промовляє тільки: «Господу помолимось», «Господи, помилуй». Після покриття воздухом священних сосудів священник тихо виголошує: «Молитвами святих отців наших, Господи Ісусе Христе, Боже наш, помилуй нас». Диякон ставить запалений підсвічник на жертовник, якщо це ставник, то перед жертовником, і далі перед Святими Дарами і промовляє: «Амінь.». Священник кадить Святі Дари і творить земний поклін. Після перенесення Святих Дарів на жертовник, відкривають царські врата і диякон виголошує малу ектенію, а священник повертається до престолу, згортає антимінс і знову покладає на нього Євангеліє і після закінчення ектенії виголошує: «Бо Ти єси Бог наш, Бог, щоб милувати і спасати...». Хор: «Амінь.». Царські врата закривають. Після кафизми співається «Господи, взиваю...» (Пс.140). Стихири на 10: Тріоді – 6 і Мінеї ((перша стихира – двічі), тобто з наступного дня) – 4. «Слава, і нині» – Богородичний Мінеї. Під час співу стихир відбувається звичайне кадіння всього храму. Під час співу останньої стихири на «Слава, і нині» відкриваються царські врата і звершується вхід з кадилом. Якщо на Літургії Ранішосвячених Дарів є за Уставом читання Євангелія (наприклад, в храмове або полієлейне свято, в перші три дні Страсної седмиці), то вхід звершується з Євангелієм. Диякон бере кадило і просить у предстоятеля благословення: «Благослови владико кадило». Священик, благословляючи кадило, осіняє його хресним знаменням і читає молитву: «Кадіння Тобі приносимо...». Отримавши благословення, диякон одночасно зі священиком осіняє себе хресним знаменням, цілує престіл, та йде перед священиком через горнє місце північними дверима на солію слідом за двома свічконосцями. При цьому проходячи через горнє місце, свічконосці, диякон та священик осіняють себе хресним знаменням, кланяються предстоятелю, котрий відповідає взаємним поклоном. За іншою практикою, саме під час взаємного поклоніння на горньому місці диякон, підносячи кадило, просить у предстоятеля благословення: «Благослови, владико кадило...», а священик читає молитву на благословення кадила. Вийшовши з вівтаря, священик стає на амвоні, навпроти царських врат, а диякон стає з правого боку від нього, свічконосці біля намісних ікон Спасителя і Богородиці. Всі одночасно хрестяться. Диякон і свічконосці кланяються предстоятелю. Потім диякон, схиливши голову і тримаючи трьома пальцями орар, як під час виголошення ектенії, повернувшись до священика тихо промовляє: «Господу помолимось». Священик тихо читає молитву входу: «Ввечері, вранці, опівдні...». Диякон обкаджує царські врата, намісні ікони Спасителя і Богородиці, потім обкадивши предстоятеля, показує орарем на схід і схиливши голову, тихо промовляє: «Благослови, владико святий вхід». Священик благословляючи, тихо промовляє: «Благословенний вхід святих твоїх завжди, нині, і повсякчас, і на віки віків» Диякон відповідає: «Амінь». Диякон: «Премудрість, станьмо побожно», заходить у вівтар царськими вратами, кадить престіл, горнє місце і стає з лівої сторони престолу, лицем до заходу, кадячи предстоятеля, котрий входить також до вівтаря. Хор співає гімн: «Світло Тихе...». Під час співу цього старовинного гімну, священик осіняє себе хресним знаменням і творить поясний поклін, підходить та цілує ікону Спасителя, яка знаходиться збоку, біля царських врат, потім знову хреститься і кланяється перед цією іконою. Далі, за сучасною практикою, священик повертається лицем на захід і благословляє свічконосців, котрі в цей час стають на солії, навпроти царських врат, лицем на схід. Свічконосці поклонившись предстоятелю та один одному, заходять дияконськими дверима до вівтаря. В той час священик підходить до іншої сторони царських врат, хреститься і цілує ікону Божої Матері, потім знову хреститься і кланяється перед цією іконою. Слід зазначити, що 2 глава Типікону пропонує священику на вході цілувати «святі двері», тобто царські врата, однак, за традицією нашої церкви, по боках врат вішаються невеликі образи Спасителя і Богоматері. На вході саме їх і цілує предстоятель. Після цього він заходить у вівтар, цілує одночасно престіл і разом з ним іде на горнє місце. Туди ж підходять і свічконосці. Всі одночасно хрестяться на схід, диякон і свічконосці вклоняються предстоятелю, в свою чергу священик кланяється до них. Свічконосці погасивши свічки, повертаються на свої місця, до того ж один з них бере кадило в диякона. Священик з дияконом стоять на горньому місці лицем на захід (священик справа, диякон зліва). Диякон голосно виголошує: «Будьмо уважні». Священник благословляючи правою рукою виголошує: «Мир усім». Читець: «І духові твоєму». Диякон: «Премудрість». Читець: виголошує прокимен Тріоді (за звичайним чином). Всі прокимни та паремії надруковані в Постових тріодях. Після виконання прокимна (зі стихом) диякон: «Премудрість». Читець виголошує назву 1-ї паремії Тріоді: «Буття читання». Диякон: «Будьмо уважні». Читається перша паремія Тріоді (царські врата зачиняються). Після закінчення паремії диякон: «Будьмо уважні», царські врата відкриваються. Співається другий прокимен Тріоді. Після виконання якого диякон виголошує: «Повеліть!». Священик при служінні без диякона слово «Повеліть!» не виголошує. Священник, взявши обома руками кадило і підсвічник зі свічкою, стоячи обличчям до престолу, творить ними над Євангелієм знак Хреста і голосно виголошує: «Премудрість, станьмо побожно». Після цього, повернувшись на захід, до народу, він підносить свічку з кадилом і виголошує: «Світло Христове просвітлює усіх». В цей час ті, що моляться, через глибоке благоговіння перед Господом Ісусом Христом – Світлом істини, схиляються до землі. Читець виголошує назву 2-ої паремії Тріоді: «Притч читання». Диякон: «Будьмо уважні». Читається друга паремія Тріоді (царські врата зачиняються). Після закінчення паремії царські врата, за звичаєм, відкриваются. Священник, благословляючи читця, промовляє: «Мир тобі». Диякон: «Премудрість». І слідує спів стихів великого прокимна: «Нехай піднесеться молитва моя...». «Нехай возненесеться молитва моя...» – давній великий прокимен великопостових урочистих служб. Тому Устав вказує читцю, на відміну від паремійних прокимнів, не виголошувати його, а співати (схема виконання така ж, як і у всіх великих прокимнів). Після прочитання паремій, священник промовляє: «Мир тобі. І диякон: «Премудрість.». Читець: «Нехай піднесеться молитва моя...». Тоді співці правого і лівого хору, і присутні на богослужінні люди стоять на колінах молячись. І після співу читця, 1-ий хор співає також: «Нехай вознесеться молитва моя...» І читець, і інша частина хору, і всі присутні, стоять на колінах, поки не доспівають. Потім читець співає 1-ий стих: «Господи, взиваю до Тебе, вислухай мене...» І після співу стиха, співає 2-ий хор: «Нехай вознесеться молитва моя...» Тоді читець, і 1-ий хор, і всі присутні в храмі припадають на коліна. Також читець співає 2-ий стих: «Постав, Господи, охорону устам моїм...». І 1-ий хор знову співає: «Нехай вознесеться молитва моя...». І читець, і 2-ий хор, і всі присутні, знову схиляють коліна. І читець співає третій стих: «Не схили серця мого...», і 2-ий хор співає: «Нехай вознесеться молитва моя...». І читець, і 1-ий хор, і народ схиляє коліна. І знову читець співає: «Нехай вознесеться молитва моя, наче кадіння перед Тобою...». І тоді обидва хори, і всі присутні в церкві люди припадають на коліна, і стоять, поки читець співає. І піднявшись, доспівують на кліросі: «...піднесення рук моїх – як жертва вечірня.». І після виконання творимо 3 поклони. Священник під час співу цих стихів, стоячи (стоять і всі священики, які звершують соборне служіння) перед престолом, звершує кадіння. При співі на кліросі «Нехай вознесеться молитва моя...» після стиха: «Не схили серця мого...» священник переходить до жертовника і кадить перед жертовником. Потім віддає кадило дияконові і, благоговійно вклонившись святині (поясний поклін), відходить до престолу. При заключному співі «Нехай піднесеться молитва моя...» предстоятель (і всі священики, які звершують соборне служіння) схиляє коліна перед престолом, а диякон продовжує кадити Святі Дари до закінчення співу. Після закінчення співу «Нехай вознесеться молитва моя...» священик, за звичаєм, промовляє молитву прп. Єфрема Сиріна (з трьома великими поклонами). На цьому, власне, вечірня закінчується. Коли буває читання Апостола та Євангелія, то одразу за молитвою – прокимен, Апостол, алилуарій і Євангеліє, якщо є за Уставом. Якщо ж немає Апостола і Євангелія, царські врата залишаються відкритими. На Страсному тижні читається тільки Євангеліє. Ектенія «Промовмо всі...». Священник розгортає повністю святий антимінс. За традицією Православної Церкви України ектенія за оголошених опускається. Також із середи 4 тижня Великого посту опускається ектенія і молитва за тих, хто готується до Святого Просвічення (Хрещення). Після цього починається літургія вірних. Священик тихо читає першу молитву вірних: «Боже Великий і достойний хвали...». Тоді диякон виголошує ектенію: «Заступи, спаси, помилуй...». Священик тихо читає другу молитву вірних: «Владико Святий і Преблагий...». Виголос священика є завершенням таємної молитви. Коли священик служить без диякона, він, так само, як і на повній літургії, виголошує тільки перше і останнє прохання другої ектенії. Але не буде помилкою, якщо він виголосить ектенію повністю. Після виголосу диякона: «Заступи, спаси, помилуй...» хор співає: «Господи, помилуй» і диякон виголошує «Премудрість». Цим виголосом віруючим нагадується про особливу важливість подальшого Богослужіння, про час перенесення Ранішосвячених св. Дарів зі св. Жертовника на св. Престіл. Священик проголошує закінчення другої молитви вірних: «Через Дар Христа Твого...». На літургії Ранішосвячених Дарів замість Херувимської пісні співається особливий піснеспів: «Нині сили Небесні з нами невидимо служать...». Диякон заходить північними дверима у вівтар і, взявши кадильницю, кадить святий престіл, жертовник, вівтар, а також священиків і дияконів. Іконостас і присутніх вірних диякон не кадить. При звершенні кадіння диякон таємно читає 50-ий Покаянний псалом. Потім священник, стоячи з дияконом перед престолом, здіймає руки до гори і молиться: «Нині сили Небесні...» (тричі), і цілує престіл. Потім йде до жертовника, тричі кланяється зі словами: «Боже, очисти мене грішного», тричі кадить Святі Дари і, віддавши кадило дияконові, покладає на його плече воздух. А сам правою рукою бере дискос і тримає його на рівні чола, в ліву руку бере чашу та тримає її біля грудей і переносить Святі Дари з жертовника на престіл, виходячи північними дверима і входячи у вівтар Царськими вратами. Диякон йде перед священиком обличчям до Святих Дарів з кадилом і кадить часто, а перед дияконом, як і на повній Літургії, йдуть свічконосці. Ніяких зупинок на солії і поминань немає. Проте існує практика, коли священник проходячи через Царські врата, тихо промовляє: «З вірою і любов’ю приступимо...». Під час проходження священиком через солію всі моляться і стають на коліна, схиливши голову до землі. Після входу у вівтар священник ставить Святі Дари на антимінс. Ті, що моляться, встають, хор співає: «З вірою і любов’ю приступимо...». Священник відкладає покрівці, покриває воздухом (попередньо обкадивши його) Святі Дари і кадить їх. Під час цих священнодійств нічого не промовляється. Диякон мовчки приймає благословення від священника. Після закінчення співу «З вірою і любов’ю...» б’ються три великих поклони. При цьому священник виголошує у вівтарі молитву прп. Єфрема Сиріна. Слід зазначити, що в Типіконі немає вказівок на виголошення в цьому місці служби молитви прп. Єфрема Сиріна, але звичай читання її є дуже поширеним. Царські врата зачиняються, завіса закривається наполовину. Диякон виголошує ектенію «Доповнимо вечірню молитву нашу Господу...». Виголос: «І сподоби нас, Владико...». Хор: «Отче наш...». Священник: «Бо Твоє є Царство...». Хор: «Амінь». Священник: «Мир всім.». Хор: «І духові твоєму». Диякон: «Голови наші вклонімо перед Господом». Хор: «Тобі, Господи.». Священник: «Благодаттю і милосердям...». Хор протяжно співає: «Амінь.». Закривається повністю завіса царських врат. Диякон: «Будьмо уважні». Священник вкладає праву руку під воздух, «з благоговінням і страхом» доторкаючись до Святого Агнця, і виголошує: «Ранішосвячене Святеє святим». Хор: «Єдиний Свят...» і запричастний стих: «Споживіть і пізнайте, що благий Господь», «Алилуя» (тричі). Якщо читалися Апостол і Євангеліє святого, то співається і причасний святого. Священник відкладає воздух і знімає звіздицю. Диякон входить у вівтар і промовляє: «Розломи, владико, Святий Хліб». Священик зі словами: «Розломлюється і розділяється Агнець Божий...», роздроблює Святий Агнець на чотири частини і вкладає частинку з найменуванням «ІС» в потир, нічого не промовляючи. Теплота вливається в потир теж в мовчанні. Тоді священик ділить частину з написом «ХС» і промовляє: «Дияконе, приступи.». Диякон, підійшовши, чинить поклін, побожно прохаючи прощення, і промовляє: «Ось приступаю...», після чого священик подає часточку Святих Таїн дияконові і промовляє: «Священнодиякону (ім’я) подається...». Диякон приймає Святий Хліб на долоню правої руки, підкладаючи ліву руку під неї, далі цілує руку священика, відходить за святий престіл і, вклонивши голову, молиться: «Вірую, Господи, і визнаю...». Так само священик промовляє: «Чесне, і пресвяте, і пречисте...», після чого, взявши одну часточку Святих Таїн, вклоняє голову і молиться: «Вірую, Господи, і визнаю...». І так причащаються з великою обережністю. Тоді Священник бере губку і, обтираючи руку, тричі промовляє: «Слава Тобі, Боже.». Поцілувавши губку, кладе її на місце. Особливістю причащання є те, що коли літургія Ранішосвячених Дарів звершується священиком з дияконом, то диякон, прийнявши частину Святих Таїн, не випиває з чаші і не споживає антидора, оскільки він здійснює це після споживання Святих Дарів. Так само чинить священик, якщо служить без диякона. Священик промовляє молитву подяки: «Дякуємо Тобі, Спасителеві всіх, Богу...». Диякон кладе до чаші часточки з дискоса, покриває чашу покрівцем, кладе звіздицю і другий покрівець на дискос, тричі вклоняється, відкриває катапетасму і відчиняє Царські врата. Вклонившись побожно один раз, диякон бере від священика святу чашу, підходить до Царських врат, звертається до народу і, підносячи чашу, виголошує: «Зі страхом Божим і вірою і любов’ю приступіть». Хор: «Благословлю Господа повсякчас, хвала Його в устах моїх». Причащання народу відбувається за звичайним чином. Священник: «Спаси, Боже, людей Твоїх...». Хор: «Хліб Небесний і Чашу Життя споживіть і пізнайте, що благий Господь». «Алилуя» (тричі). Перед віднесенням на жертовник священик тричі кадить Святі Дари, але слова: «Вознесися на небеса, Боже...» не промовляє. Після виголосу священник «Завжди, нині і повсякчас...» – Хор: «Нехай сповняться уста наші...». Після заамвонної молитви: «Владико Вседержителю, Ти все творіння премудро сотворив...» хор співає: «Амінь.». «Нехай буде ім’я Господнє...» (тричі). «Слава, і нині». Псалом 33-ий: «Благословлю Господа...». Під час читання або співу тридцять третього псалма священник роздає антидор, що зберігався з повної літургії, для всіх, хто був присутній. Потім священник, благословляючи народ, виголошує: «Благословення Господнє на вас...». Хор: «Амінь.». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник творить відпуст, на якому після апостолів святого храму (якщо є) і святого наступного дня. Якщо літургія Ранішосвячених Дарів служилася з нагоди полієлейного свята, то на святковому відпусті спочатку згадується полієлейний святий, а потім святий наступного дня. За служебником ім’я свт. Григорія Двоєслова на відпусті не згадується. Хор співає уставне многолітня. Далі читаються молитви подяки після святого Причастя. Щодо авторства Літургії Ранішосвяченних Дарів. Довгий час побутувала думка, що цю Літургію написав свт. Григорій Двоєслов, але це не підтверджується рукописами, жоден рукопис грецького чи слов’янського походження до XVI ст. не називає свт. Григорія автором чину; як правило, послідування Літургії Ранішосвячених Дарів не надписане ніяким іменем, інколи зустрічаються імена свт. Василія Великого, Епіфанія Кіпрського, Германа Константинопольського. В творах свт. Григорія немає подібного тексту Літургії. Святитель Григорій був літургістом Західної Церкви, він не міг писати тексти для Сходу, розвивати чини візантійської Літургії. Зважаючи на ці факти Літургічна комісія вилучила ім’я свт. Григорія Двоєслова із відпустових святих. ВЕЛИКЕ ПОВЕЧІР’Я з третьою частиною канону прп. Андрія Критського за зразком понеділка першого тижня Великого посту.","sections":[],"special":true},
{"date":"02-26","weekday":"четвер","title":"Свт. Порфирія, архієп. Газького (420). Мч. Севастіана (бл. 66).","notes":"На 6-му часі: Іс. II, 11 – 21. На веч.: Бут. II, 4 – 19. Притч. III, 1 – 18. Детальний виклад порядку богослужіння ранньої і часів див. 23 лютого. РАННЯ. Особливості служби: до першого Троїчного – закінчення: «Свят, свят, свят єси, Боже наш, молитвами святих апостолів Твоїх і святителя Миколая, помилуй нас». Кафизми 6-та, 7-ма і 8-ма. Трипіснець складається з 4-ої, 8-ої і 9-ої пісень. Порядок співу канону при службі одного малого святого: 1-а пісня канону співається так само, як у вівторок. 2-га пісня не співається. 3-тя пісня співається так само, як в понеділок. 4-а пісня, внаслідок наявності в ній двох трипіснеців, співається подібно до 1-ої пісні в понеділок. Пісні 5-а, 6-а, 7-а, 8-а, 9-а співаються так само, як в понеділок. Після 3-ої пісні – кондак і сідальний Мінеї святителя, глас 3-ій. «Слава, і нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос святителя, глас 2-ий. До світильного перше закінчення: «...молитвами, Господи, апостолів Твоїх і святителя Миколая, і спаси мене». На стиховні стихири Тріоді, глас 3-ій (зі звичайними приспівами). «Слава, і нині» – Богородичний Тріоді, глас той же: «Богородице, Заступнице всіх...». Все інше – як в понеділок. ЧАСИ 1-ИЙ, 3-ІЙ, 6-ИЙ і 9-ИЙ звершуються як в понеділок. На 1-му часі – кафизма 9-та; на 3-му часі – кафизма 10-та; на 6-му часі – кафизма 11-та; на 9-му часі – кафизма 12-та. На 6-му часі – 1-й прокимен, глас 1-ий: «Коли поверне Господь з неволі народ Свій»; стих: «Сказав безумний у серці своїм: Бога нема». 2-ий прокимен, глас 4-ий: «Господи, хто може жити в оселі Твоїй?»; стих: «Той, хто ходить непорочно і чинить правду». Детальний виклад порядку богослужіння зображальних і вечірні див. 23 лютого. На зображальних порядок Кондаків див. В понеділок 23 лютого.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. Примітка. Якщо настоятель благословить звершувати службу прп. Тита, пресвітера Києво-Печерського, в Ближніх печерах. Прп. Тита Києво-Печерського, колишнього воїна, що в Дальніх печерах, то її відправляємо за чином «Загальна служба багатьом преподобним Печерським». Ця служба міститься в Мінеї за вересень місяць, однак можна брати кондаки преподобним із Мінеї за 27 лютого. Великопостова вечірня із службою прп. Прокопія Декаполіта. На «Господи, взиваю» стихири на 6: Тріоді, глас 2-ий – 3, і Мінеї, глас 4-й – 3 (з 27 лютого прп. Прокопія) «Слава, і нині» – Хрестобогородичний Мінеї, глас той же: «Коли побачила...». Прокимен, глас 4-ий: «Славитиму Господа, що просвітив мене»; вірш: «Охорони мене, Господи, бо я на Тебе надіюся». Після 1-ї паремії прокимен, глас 4-ий: «Збережи мене, Господи, як зіницю ока»; стих: «Почуй, Господи, правду мою». На стиховні стихири Тріоді, глас 4-ий (зі звичайними приспівами). «Слава, і нині» – Хрестобогородичний Тріоді, глас той же: «Коли Агниця і Мати Твоя побачила Тебе, Господи, на хресті розіп’ятим...». ВЕЛИКЕ ПОВЕЧІР’Я з четвертою частиною канону прп. Андрія Критського – за чином понеділка 1-го тижня 23 лютого."}]},
{"date":"02-27","weekday":"п’ятниця","title":"Прп. Прокопія Декаполіта, спов. (бл. 750). Прп. Тита, пресвітера Києво-Печерського, в Ближніх печерах (1190). Прп. Тита Києво-Печерського, колишнього воїна, що в Дальніх печерах (ХІV). Прп. Фалалея Сирійського (бл. 460). Прп. Єфрема Катунакського (1998). Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. III, 1 – 14. На веч.: Бут. II, 20 – III, 20. Притч. III, 19 – 34. Детальний виклад порядку богослужіння ранньої і часів див. 23 лютого. Після заамвонної молитви співається молебний канон вмч. Феодору Тирону і благословляється коливо.","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ до першого Троїчного приспів: «Свят, свят, свят єси, Боже наш, силою Хреста Твого збережи нас, Господи». Кафизми 13-та, 14-та і 15-та. Триспіснець складається з 5-ої, 8-ої і 9-ої пісень. Порядок співу канону при типу служби одного малого святого: 1-ша пісня канону співається так само, як у вівторок. 2-га пісні не співається. 3-тя і 4-а пісні співаються так само, як в понеділок. 5-та пісня співається подібно 1-ої в понеділок. Після 3-ої пісні – сідальний Мінеї (преподобного), глас 4-ий. «Слава і нині» – Хрестобогородичний Мінеї, глас той же. 6-та пісня співається з початку, від стиха: «До Господа Бога взивав я у скорботі моїй...» і до «Шанувальники суєтних і неправдивих богів...» включно. Після цього стиха – 1-ий тропар канону Мінеї. Далі: «А я голосом хваління принесу Тобі жертву...», і 2-ий тропар канону Мінеї. «Слава» – 3-ій тропар канону Мінеї, «І нині» – Богородичний Мінеї. На катавасію – ірмос канону Мінеї. Після 6-ої пісні – кондак Мінеї (преподобного), глас 4-ий. 7-ма пісня співається з початку, від стиха: «Благословен єси, Господи, Боже отців наших...» і до «Благословенний Ти, що бачить безодні...» включно. Після цього стиха співається ірмос канону Мінеї. Далі: «Благословенний Ти на престолі...», і 1-ий тропар канону Мінеї. «Благословенний Ти на тверді...», і 2-ий тропар канону Мінеї. «Слава» – 3-ій тропар канону Мінеї, «І нині» – Богородичний Мінеї. 7-а пісня ірмосом не закривається, але відразу співається 8-а пісня. Примітка. Співання 6-ої і 7-ої біблійних пісень повністю в цьому випадку є необхідним з тієї причини, що на ранній суботи 1-ої седмиці передбачається співання біблійних пісень не у великопостовій редакції, а за розділами Ірмологія «Господеві співаймо» або «Співаймо Господеві», в яких 6-а і 7-а біблійні пісні повністю не виконуються, а, отже, протягом 1-го тижня посту були б повністю виконані не всі дев’ять біблійних пісень. Тому Типікон пропонує повністю співати 6-у і 7-у пісні в п’ятницю (Типікон, гл. 49, п’ятницю ввечері 1-го тижня, 2-е «зри»; гл. 48, 24 лютого, 9-а Маркова глава; гл. 48, 24 березня, 3-е і 4-е «зри»). У богослужінні субот 2-го, 3-го та 4-ого тижнів Великого посту 6-а і 7-а біблійні пісні повинні повністю (у великопостовій редакції) виконуватися на ряду на ранній. У п’ятницю 5-го і 6-го тижня рекомендується чинити так само, як і на 1-ій седмиці Великого посту. Пісні 8-а і 9-а співаються так само, як в понеділок До світильного перше закінчення: «... силою, Господи, Хреста Твого, і спаси мене». На стиховні стихири Тріоді, глас 8-ий (зі звичайними приспівами). «Слава, і нині» – Хрестобогородичний Тріоді, глас той же. ЧАСИ 1-ИЙ, 3-ІЙ, 6-ИЙ і 9-ИЙ відбуваються як в понеділок. На 1-му і 9-му часах по п’ятницях протягом всієї св. Чотиридесятниці кафизми не читаються. На 3-му часі – кафизма 19-та; на 6-му часі – кафизма 20-та. На 6-му часі – 1-ий прокимен, глас 7-ий: «Возлюблю Тебе, Господи, кріпосте моя, Господь – твердиня моя»; стих: «Бог мій, Поміч моя». 2-ий прокимен, глас 6-ий: «Господи, Твердине моя і Спасителю мій»; стих: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь...». Детальний виклад порядку зображальних див. 23 лютого. (закінчення зображальних див. 25 лютого). Порядок Кондаків на зображальних в храмі Господському див. в середу, 25 лютого; в храмі Богородиці і святого – див. в понеділок, 23 лютого. Детальний виклад порядку богослужіння вечірні в поєднанні з Літургією Ранішосвячених Дарів див. 25 лютого."},{"svc":"ВЕЧІРНІ ІЗ ЛІТУРГІЄЮ","text":"НА ВЕЧІРНІ ІЗ ЛІТУРГІЄЮ РАНІШОСВЯЧЕНИХ ДА- РІВ – кафизма 18-та. На «Господи, взиваю» стихири на 10: Тріоді самогласний дня, глас 5-ий: «Прийдіть, вірні...» (двічі), мученичний Октоїха, глас 4-ий – 4 [1], і вмч. Феодора Тирона (з Тріоді), глас 2-ий – 4. «Слава» – вмч. Феодора, глас 6-ий:, «І нині» – догматик, глас 4-ий: «Пророк Давид...». Вхід з кадилом. «Світло Тихе». Читання паремій Тріоді (прокимен 1-ої паремії, глас 5-й: «Вислухає тебе Господь в день скорботи»; стих: «Захистить тебе ім’я Бога Якова». Прокимен 2-ої паремії, глас 6-ий: «Піднесися, Господи, силою Твоєю! Будемо співати й прославляти могутність Твою»; стих:«Господи, силою Твоєю звеселиться цар»). «Нехай піднесеться молитва моя...», та інше послідування Літургії Ранішосвячених Дарів (за звичаєм). Після заамвонної молитви священник з дияконом виходять на солію до приготованого столу, на якому стоїть блюдо з коливом, і звершують чин молебного співу великомученику Феодору Тирону. Читець – псалом 142-ий: «Господи, почуй молитву мою...». На «Бог Господь» – тропар вмч. Феодора, глас 2-ий: «Великої віри взірець...». «Слава» – той же тропар, «І нині» – Богородичний, глас той же: «Всі незбагненні, всі преславні Твої, Богородице, таїнства...». Читець – псалом 50-ий. Під час псалма відбувається кадіння. За звичаєм, диякон кадить навколо столу з коливом і священнослужителів. Примітка. Устав дає такі вказівки щодо кадіння: «... Псалом 50-ий. І кадить священик коливо, і настоятеля, і хори, за чином» (Типікон, гл. 49,«В п’ятницю ввечері [1-го тижня]»). Після 50-го псалма – співається канон вмч. Феодора, глас 8-ий, на 4 (без ірмосів). Хор співає заспіви: «Святий великомученику Феодору, моли Бога за нас» до двох перших тропарів канону, потім «Слава», «І нині». священник, за звичаєм, читає тропарі канону. Після 6-ої пісні – «Господи, помилуй» (тричі), «Слава, і нині» – кондак вмч. Феодора, глас 8-ий. Після 9-ої пісні замість «Достойно» – ірмос 9-ї пісні: «Тебе, Неневісну Матір...». Читець: Трисвяте. Після «Отче наш...» – виголос: «Бо Твоє є Царство...», і тропар вмч. Феодора, глас 2-й: «Великої віри взірець...». «Слава» – кондак вмч. Феодора, глас 8-ий: «Віру Христову...», «І нині» – Богородичний, глас той же: «Тебе всі грішні мають заступницею...». Диякон: «Господу помолимось». Хор: «Господи, помилуй». Священник читає молитву над коливом (порівн.: Служебник, Чин благословення колива): Господи, Ти все сотворив словом Твоїм, і звелів землі вирощувати різноманітні плоди на насолоду і поживу нам, ними ж Ти трьох отроків і Даниїла, що у в Вавилоні, оживляв, показавши їх світлішими від тих, що споживали ласощі! Сам, Всеблагий Царю, і зерна ці з різними плодами благослови і всіх, що їх споживають освяти, бо принесені вони рабами Твоїми на славу Твою і на честь святого великомученика Феодора Тирона, і в пам’ять тих, що у благочестивій вірі спочили. А тим, що приоздобили це і творять пам’ять, подай Господи, все, що вони просять для спасіння, і насолоду вічних Твоїх благ, молитвами Пречистої Владичиці нашої Богородиці і Приснодіви Марії, і Святого великомученика Феодора Тирона, його ж і пам’ять творимо, і всіх святих Твоїх. Бо Ти все благословляєш і освячуєш, Боже наш, і Тобі славу возсилаємо, Ьезначальним Твоїм Отцем і Пресвятим, і Благим, і Животворчим Твоїм Духом, нині і повсякчас, і на віки віків. Хор: «Амінь». «Нехай буде благословенне ім’я Господнє...» (тричі). Псалом 33-ий: «Благословлю Господа...». Відпуст за звичаєм. Примітка. «І входимо в трапезу, і споживаємо вина та єлею, заради святого. Це прийняли в Лаврі преподобного отця нашого Сави, і кіновії преподобного великого Євфимія: але не творимо цього нині через чесність днів, однак їмо варення зі сливами без єлею...: а ті, хто може перебувають у сухоядінні, як і в середу» (Типікон, гл. 49, «В п’ятницю ввечері [1-го тижня]»). [1]. У службі Октоїха 1-7 гласів 1-ий мученичний знаходиться в 1-ій групі стихир на «Господи, взиваю» (див. В Октоїху в п’ятницю ввечері); інші три мученичні – у 2-ій групі стихир. [У службі 8-го гласу розташування текстів інше: в 1-ій групі стихир на «Господи, взиваю» дано 3 мученична, а четвертого мученична немає (2-а група стихир не містить мученичних). Таким чином, при звершенні служби Октоїха 8-го гласу слід співати мученічні 1-ої групи стихир, повторюючи перший з них: «Мученики Господні...».]"}]},
{"date":"02-28","weekday":"субота","title":"Вмч. Федора Тирона (бл. 306) (перехідне святкування в суботу 1-го тижня Великого посту). Свт. Арсенія (Мацієвича), митр. Ростовського (1772). Прп. Василія, спов. (750). Сщмч. Протерія, патр. Олександрійського (457). Сщмч. Нестора, єп. Магідійського (250). Прпп. Марини і Кіри (бл. 450). Прп. Касіяна Римлянина (435) (пам’ять переноситься з 29 лютого). Прп. Касіяна, затворника Києво-Печерського, у Дальніх печерах (XIII – ХІV) (пам’ять переноситься з 29 лютого). Прп. Іоана, названого Варсонофієм, єп. Дамаського (V); прп. Феоктириста, спов., ігум. Пелікітського (VІІІ) (пам’ять переноситься з 29 лютого). Свт. Мелетія, архієп. Харківського (1840) (пам’ять переноситься з 29 лютого). Літургія за чином свт. Іоана Золотоустого.","readings":["Євр., 303 зач., I, 1 – 12. Мк., 10 зач., II, 23 – III, 5.","Вмч.: 2 Тим., 292 зач., II, 1 – 10. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"Звершується служба вмч. Феодора Тирона (з Тріоді). ВЕЛИКЕ ПОВЕЧІР’Я без поклонів: Після 1-го Трисвятого – тропар вмч. Феодора, глас 2-ий. «Слава, і нині» – Богородичний недільний, глас той же: «Вище всякого розуму.». Після 2-го Трисвятого – тропарі Часослова, глас 6-ий: «Помилуй нас, Господи...». Після «Слава в вишніх...» співається звичайна служба дня з Мінеї (з 28 лютого; прп. Василія сповідника та служба прп. Касіана Римлянина з 29 лютого), а також – заупокійний канон Октоїха, 4-го гласу з ранньої суботи (без ірмосів). Примітка. «Нехай буде відомо, про те, що послідовність Мінеї, тих святих, пам’ять яких припадає в суботи і Неділі святої Чотиридесятниці, співається на повечір’ї, або коли зволить екклісіарх» (див .: Типікон, гл. 49, «В п’ятницю ввечора [1-го тижня]», 3-тє «див»). «А Канони з Мінеї цієї суботи та Неділі співаємо, коли зволить екклісіарх: один співаємо на повечір’ї п’ятниці, а другий канон співаємо на повечір’ї Неділі» (див.: Тріодь Постова, в п’ятницю ввечері 1-го тижня). Після канонів – «Достойно є». Після 3-го Трисвятого – кондак вмч. Феодора, глас 8-ий (замість «Господи Сил...»). «Господи, помилуй» (40). Молитва: «Ти, що кожного часу...». «Господи, помилуй» (тричі). «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Виголос: «Молитвами святих отців наших...». Читець: «Амінь». Молитва: «Непорочна, Пречиста...», «І дай нам, Владико...», «Преславна Приснодіво...», «Уповання моє Отець...». Священник: «Слава Тобі, Христе Боже...». «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст малий: «Христос, істинний Бог наш...». Звичайне прощення. Ектенія: «Помолимось...». ПОЛУНОШНИЦЯ звичайна – суботня. РАННЯ. Початок суботньої ранньої: після виголосу «Благословенний Бог наш...», читець: «Прийдіть, поклонімось...» (тричі) і звичайні псалми 19-ий та 20-ий (на яких відбувається кадіння всього храму). Примітка. Суботнє богослужіння святої Чотиридесятниці не має особливостей седмичних великопостових служб. На «Бог Господь» – тропар вмч. Феодора, глас 2-ий (двічі). «Слава, і нині» – Богородичний недільний, глас той же: «Вище всякого розуму...». Кафизми 16-та і 17-та. [1]. Після 16-ої кафизми – мала ектенія. Сідальні Октоїха, глас 4-ий. Після 17-ої кафизми – мала ектенія. Сідальний вмч. Феодора, глас 3-ій. «Слава» – інший сідальний вмч. Феодора, глас той же, «І нині» – Богородичний Тріоді, глас той же. І читаємо житіє і страждання великомученика (див. Постова Тріодь). Псалом 50-ий. (Молитва: «Спаси, Боже, людей Твоїх...» не виголошується). Канони: храму з ірмосом на 6 (ірмоси по двічі) і вмч. Феодора на 8. Біблійні пісні: «Господеві співаймо...» або «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний вмч. Феодора, глас 8-ий. «Слава» – інший сідальний вмч. Феодора, глас той же, «І нині» – Богородичний Тріоді, глас той же. Після 6-ої пісні – кондак та ікос вмч. Феодора, глас 8-ий. Читаємо Синаксар: Коливом годує Тирон місто... (див. Постова Тріодь). На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – світильний вмч. Феодора. «Слава, і нині» – Богородичний Тріоді. («Достойно є» не співається). «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири вмч. Феодора, глас 1-ий – 4. «Слава» – вмч. Феодора, глас 6-ий: «Священний дар...», «І нині» – Богородичний Тріоді, глас той же: «Богородице, Ти єси виноградна лоза...». Після прочитання стихир «Тобі слава подобає...» не виголошується, але одразу: «Слава Тобі, що показав нам світло», і читається повсякденне славослів’я. Ектенія: «Доповнімо ранню молитву...», і голововклонна молитва. На стиховні стихири вмч. Феодора, глас 4-ий (з приспівами своїми – 1-ий: «Праведник, яко фінік розцвіте і як кедр що в Ливані, примножиться», 2-ий: «Насаджені в домі Господньому, у дворах Бога нашого процвітуть»). «Слава» – вмч. Феодора, глас 8-ий: «Страдницькою мужністю благочесно озброївшись...», «І нині» – Богородичний, глас той же: «Владичице, прийми молитви рабів Твоїх, і визволи нас від усякої недолі і скорботи». Після Трисвятого – тропар вмч. Феодора, глас 2-й. «Слава, і нині» – Богородичний недільний, глас той же: «Вище всякого розуму...».","sections":[{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак вмч. Феодора. ЛІТУРГІЯ за чином святителя Іоана Золотоустого. Блаженні вмч. Феодора, пісня 3-тя – 4 (з ірмосом 1-го канону), і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар вмч. Феодора. «Слава» – кондак вмч. Феодора, «І нині» – кондак храму. У храмі святого – тропар храму, тропар вмч. Феодора; кондак храму. «Слава» – кондак вмч. Феодора, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – вмч. Феодора (Тріоді). Апостол і Євангеліє – суботи 1-го тижня і вмч. Феодора. Примітка. «На трапезі читаємо похвальне слово святому Феодору, святого Григорія Ниського. І їмо відварені боби, з маслинами білими і чорними. Споживаємо і варення також олію і коливо; і вина випиваємо по красовулі [2], заради святого. Це ж прийняли з лаври преподобного отця нашого Сави і від богоносного отця нашого Євфимія. [Див.] Слід знати, що двічі можна їсти рибу в цей Великий піст: у свято Благовіщення і Вербну неділю». [1]. На 17-ій кафизмі Священник звершує повне кадіння храму, як на «Господи, взиваю»; царські врата залишаються закритими (порівн.: Типікон, гл. 12). [2]. Красовуля – чаша для пиття, що вживається в грецьких монастирях, яка вміщує приблизно 409,5 грама. Типікон дозволяє в суботні та недільні дні Великого посту, а так само в деякі свята, які припадають в цей період, випивати на трапезі по одній, дві і навіть три красовулі вина. При цьому Типікон зауважує, що дозвіл дано заради людської немочі, оскільки ченцеві найкраще зовсім не пити вина. Красовуля – це сосуд, в який вміщається стиснений кулак; таким чином, міра ця умовна і залежить від статури людини. Сучасний Типікон, Церковний устав, за яким живе Православна Церква, є, в основному, уставом Єрусалимської Лаври Сави Освяченого. У цьому регіоні, де вина більш ніж достатньо, майже не знали напоїв, виготовлених із зерна злаків. Тому про пиво Типікон нічого не говорить. Однак, в північних країнах, де виноград не виростав і дороге вино використовувалося виключно для звершення Євхаристії, на трапезі його замінювали саме пивом. Технологія перегонки вина так само не була відома в епоху написання Уставу. Тому вино, яке Типікон дозволяє вживати, це або сухе виноградне вино, яке на Сході пили повсякденно замість води, або трохи більш міцне солодке вино, яке зберігали спеціально для свят. Немочі, заради яких, ченцям дозволяється споживання вина, це не моральні слабкості, не звичка до нестриманості, а звичайні фізичні недуги. За відсутності спеціальних ліків вино залишалося єдиним засобом, здатним підтримати фізичні сили хворої людини. А вживання міцних напоїв під час посту є неприпустимим."}]},
{"date":"03-01","weekday":"неділя","title":"1-ша неділя Великого посту. Торжество Православ’я. Глас 5-й. Прмц. Євдокії (бл. 160 – 170). Мчч. Нестора і Тривімія (ІІІ). Мц. Антоніни (ІІІ – ІV). Мчч. Маркела і Антонія. Прп. Домніни Сирійської (бл. 450 – 460). Літургія за чином свт. Василія Великого.","glas":5,"readings":["Ран. – Єв. 5-е, Лк., 113 зач., XXIV, 12 – 35.","Літ. – Євр., 329 зач. (від половини), XI, 24 – 26, 32 – XII, 2. Ін., 5 зач., I, 43 – 51.","На молебні: Рим. 121 зач., ХVІ, 17 – 24. Мф. 75 зач., ХVІІІ, 10 – 20."],"notes":"Недільна служба Октоїха звершується у поєднанні зі службою Тріоді. За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню. Мала вечірня служиться цього дня лише за Постовою Тріоддю.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири, творіння Миколая глас 1-ий – 4: Стих: Від ранньої зорі до ночі, від ранньої зорі нехай уповають люди на Господа. Сьогодні світло благочестя всім засяяло, розганяючи оману нечестя як хмару, просвітлюючи серця благочестивих. Прийдемо усі благочестиво та мудро поклонимось чесним іконам православні. Стих: Бо в Господа милість і велике в Нього визволення. Він визволить нас від усіх беззаконь наших. Священними образами сьогодні прикрашається Христова Церква наче невіста. Всіх скликує святкувати духовно, зберемось в однодумності та вірі, радісно величаючи Господа. Стих: Хваліть Господа всі народи, прославляйте Його всі люди. Весь світе веселися, бо Господь скинув з висоти нечестя державу невимовним промислом. Сьогодні смиренно піднесімось до віри православної, наставлені благочестивою царицею. Стих: Бо велика милість Його над нами, істинна Його перебуває повік. Честь ікони до первообразу підноситься, каже Василій: заради цього любов’ю шануємо ікони Христа Спаса і всіх святих, щоб зібравши їх ніколи не спокуситися єрессю. Слава Отцю, і Сину, і Святому Духові нині і повсякчас, і на віки віків. Амінь. Богородичний: Безначальний і Божественною природою Невидимий, через безмежне Милосердя від чистої крові побачений Отроковицею Людиною. Плоті Його подобу зобразивши, всі вірні істинно поклоняємось і побожно величаємо. Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири Тріоді, глас 2-ий: Згуби розтлінної обмовців уникнули, сяйвом Православ’я вірні серця просвітімо, славлячи Бога. Стих: Принесіть Господу славу і честь. Нечиста омана Арія знищилась, Македонія, Петра, Севера і Піра світлом Трисонячного Світла. Стих: Поклонімось Йому в дворах святих Його. Вже єретики не похваляться темним вченням, бо Бог православним дає жезл сили, волею Феодори. Слава Отцю, і Сину, і Святому Духові нині і повсякчас, і на віки віків. Амінь. Богородичний: Ти піднесла ріг смиренних Богородице, породивши Бога Слово, тому істинно Тебе всі шануючи величаємо. Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар, глас 1-ий: Пречистому Твоєму образу поклоняємося Милосердний, благаючи прощення провин наших, Христе Боже; бо Ти з волі Своєї зійшов Тілом на Хрест, щоб визволити створених тобою з неволі ворожої; тому вдячно співаємо Тобі: Ти радістю наповнив усе, Спасе наш, прийшовши спасти світ. Після співу тропаря священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 5-ий – 6, Тріоді, глас 6-ий – 4 «Слава» – Тріоді, глас 2-ий: «Благодать істини засяяла...», «І нині» – догматик, глас 5-ий:»У Червоному морі..». Вхід. Прокимен дня. На літії стихира храму. «Слава» – Тріоді – «Радуйтеся, чесні пророки глас 2-ий», «І нині» – Богородичний «Вся надія моя...» На стиховні стихири недільні, глас 5-ий. «Слава» – Тріоді, глас 2-ий: «Від нечестя до благочестя...» «І нині» – Богородичний гласу неділі «О чудо нове...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар свята Тріоді, глас 2-ий: «Пречистому Образу Твоєму...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар неділі, глас 5-ий (двічі). «Слава» – тропар свята Тріоді глас 2-ий: «Пречистому Образу Твоєму...» «І нині» – Богородичний недільний за гласом: «Все вище розуму...» Кафизми 2-га і 3-тя. Малі ектенії. Сідальні Октоїха. Непорочні (17 кафизма співається на 5-тий глас незалежно від гласу неділі, після псалма співається «Ангельський собор». В сучасній богослужбовій практиці в багатьох храмах співають полієлей цілий рік). «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє недільне 5-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – Тріоді, глас 8-й: «Покаяння відкрий мені двері...», «І нині» – Богородичний Тріоді, глас той же: «На стежки спасіння...». Глас 6-й: «Помилуй мене, Боже...», і стихира Тріоді, глас той же: «Множество вчинених...». Канони: воскресний гласу з ірмосом на 4 (ірмоси раз), Хрестовоскресний на 2, Богородиці Октоїха на 2 і на Тріоді на 6. Біблійні пісні «Співаємо Господеві...». Примітка. На практиці на Недільних Всенічних використовуються на каноні не Біблійні пісні, а так звані молебні заспіви, наприклад: «Слава Господи святому Воскресінню Твоєму», до канону Воскресного, «Пресвята Богородице спаси нас» до Богородичного, Тріоді – «Помилуй мене Боже, помилуй мене», «Слава Тобі Боже наш, слава Тобі», Катавасія Тріоді: «Моря Червоного безодню...». Після 3-ої пісні – сідальний Тріоді глас 1: «Божественний Твій вигляд...», «Слава» – інший сідальний Тріоді, глас 1-ий. «І нині» – сідальний Тріоді, глас то й же. Після 6-ої пісні – кондак та ікос свята Тріоді, глас 2-ий. Читаємо Синаксар. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 5-ий. «Слава» – світильний Тріоді. «І нині» – Богородичний Тріоді. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, стихири недільні, глас 5-ий – 5 (чотири стихири недільні і Анатолієва одна), Тріоді, глас 4-ий – 3, потім стих: «Воскресни, Господи Боже мій...», і самогласний Тріоді, глас 6-ий: «Мойсей під час посту...». «Слава» – той же самогласний, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: Сьогодні спасіння...». Перед 1-им часом на «Слава, і нині» – стихира євангельська 5-та."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний. «Слава» – тропар свята Тріоді: «Пречистому Образу Твоєму...». Кондак свята Тріоді: «Неописане Слово Отцеве...» (кондак гласу пропускається). ЛІТУРГІЯ за чином свт. Василія Великого. Заготовляються два Агнці на середу та п’ятницю наступного тижня. Примітка. Якщо протягом тижня припадає пам’ять бдінного, або полієлейного святого, то Агнець заготовлюється і на цей день. Блаженні гласу – 6, Тріоді пісня 6-та – 4 (за Типіконом). Увага! Відповідно до рішення №41 Священного Синоду Української Православної Церкви (Православної Церкви України) від 7 листопада 2024 р. «Про надання благословення на богослужбові тексти» . Священний Синод вирішив: Надати благословення на використання на розсуд настоятеля на святкових службах особливих антифонів замість звичайних, як це є в грецькій церковній традиції та включити зазначені тексти до богослужбових книг Православної Церкви України. Антифон 1 Стих 1: Господь воцарився, / у красу зодягнувся (Пс. 92:1А). Молитвами Богородиці, / Спасе спаси нас. Стих 2: Бо Він утвердив вселенну / і не похитнеться вона (Пс. 92:1В). Молитвами Богородиці, / Спасе спаси нас. Стих 3: Хто висловить могутність Господа, / звістить усі хвали Його (Пс. 105:2). Молитвами Богородиці, / Спасе спаси нас. Стих 4: Так нехай скажуть визволені Господом, / яких Він визволив із руки ворога (Пс. 106:2). Молитвами Богородиці, / Спасе спаси нас. Слава, і нині. Молитвами Богородиці, / Спасе спаси нас. Антифон 2 Стих 1: Нехай же прославляють Господа за милість Його, / і за дивні діла Його для синів людських (Пс. 106:8). Спаси нас, Сину Божий, / що воскрес із мертвих співаємо Тобі. Алилуя. Стих 2: Нехай вихваляють Його в зібранні людей / і прославляють Його на зборах старійшин (Пс. 106:32). Спаси нас, Сину Божий, / що воскрес із мертвих, співаємо Тобі. Алилуя. Стих 3: Бо ось очі Господні на тих, / що надіються на милість Його (Пс. 32:18). Спаси нас, Сину Божий, / що воскрес із мертвих, співаємо Тобі. Алилуя. Стих 4: Щоб почути стогін ув’язнених, / звільнити синів, на смерть засуджених (Пс. 101:21). Спаси нас, Сину Божий, / що воскрес із мертвих, співаємо Тобі. Алилуя. Слава, і нині. Єдинородний Сину: Антифон 3 Стих 1: Нехай хвалять Його небеса і земля (Пс. 68:35). Тропар, глас 2: Пречистому Твоєму образу поклоняємося, Благий, благаючи прощення провин наших, Христе Боже; Ти бо з волі Своєї зійшов тілом на хрест, щоб визволити створених Тобою з неволі ворожої; тому вдячно співаємо: Ти радістю наповнив усе, Спасе наш, прийшовши спасти світ. Стих 2: Радіймо і веселімось в нім. Тропар: Пречистому Твоєму образу... Стих 3: Буду вихваляти Тебе, Господи Боже мій (Пс. 85:12А). Тропар: Пречистому Твоєму образу... Після входу – тропар воскресний, тропар свята Тріоді, глас 2-ий: «Пречистому Твоєму Образу...». «Слава, і нині» – кондак Тріоді. Прокимен і алилуарій – Неділі Православ’я (Отців). Апостол і Євангеліє – Неділі Православ’я. Замість «Достойно є» – «Тобою радується...». Причасний – недільний: «Хваліте Господа з Небес...», і Неділі Православ’я: «В пам’ять вічну буде праведник...» Після Літургії звершується Послідування Неділі Православ’я лише архієрейському служінні. В інших храмах цей чин не звершується. Послідування в неділю Торжества Православ’я Після закінчення Літургії архієрей йде на кафедру в облаченні, з вівтаря виходять архімандрити, ігумени, священики, диякони; священики виносять ікони Спасителя і Богородиці та кладуть посеред церкви на аналої. Протодиякон починає: Благослови, владико! Архієрей: Благословенний Бог наш завжди, нині і повсякчас і на віки віків. Хор: Амінь. Протодиякон виголошує: Слава Тобі, Боже наш, слава Тобі! І співають: Царю Небесний, Утішителю, Душе істини, що всюди єси і все наповняєш, Скарбе добра і життя Подателю, прийди і вселися в нас, і очисти нас від усякої скверни, і спаси, Благий, душі наші. Читець: Трисвяте по «Отче наш», «Господи, помилуй» (12 разів), Прийдіть, поклонімось Цареві нашому, Богу. Прийдіть поклонімось і припадімо до Христа Царя нашого Бога. Прийдіть, поклонімось і припадімо до Самого Христа, Царя і Бога нашого Псалом 74-ий Славимо Тебе, Боже, прославляємо Тебе, і призиваємо ім’я Твоє, про нього сповіщають чудеса Твої. «Коли виберу час, каже Господь, Я буду судити за правдою. Хоч захиталася земля і всі, що живуть на ній, Я утверджу стовпи її». Я кажу нечестивцям: «Не беззаконствуйте!» І до злих: «Не надійтеся на силу свою! Не підносьте високо ріг ваш і [не] говоріть [на Бога] неправду.» Бо не від сходу й не від заходу, і не з гір пустелі піднесення. А Бог є Суддя: одного принижує, а іншого підносить. Бо чаша в руці Господній, в ній кипить вино, повне приправ, і Він наливає з неї; а гущу його вижмуть і вип’ють усі грішники землі. Я ж буду радіти повік, буду співати Богу нашому. Всі роги нечестивців зломлю, і піднесеться сила праведного. «Слава, і нині», «Алилуя, алилуя, алилуя. Слава Тобі, Боже!» (тричі). Диякон виголошує Велику Ектенію – В мирі Господу помолимось. – Господи, помилуй (і так після кожного прохання). – За мир з неба і спасіння душ наших Господу помолимось. – За мир усього світу, за добрий стан святих Божих Церков і за з’єднання всіх Господу помолимось. – За Владику і отця нашого Блаженнішого Митрополита (ім’я), і владику нашого Високопреосвященнійшого (митрополита, архієпископа, єпископа) (ім’я правлячого архієрея), чесне пресвітерство, у Христі дияконство, за ввесь причет і людей Господу помолимось. – За Богом бережену Україну нашу, владу і військо її Господу помолимось. – За місто наше (село наше, або святий монастир наш) і за всяке місто, село і країну, і за тих, що по вірі живуть у них, Господу помолимось. – За добре поліття, за врожай плодів земних і за часи спокійні Господу помолимось. – За подорожніх, за недужих, знеможених та поневолених і за спасіння їх Господу помолимось. – Щоб милостивим оком споглянув на Церкву Свою Святу і зберіг її неушкодженою та нездоланною від єресей і марновірств, і миром Своїм охоронив, – Господу помолимось! – Щоб припинив розділення її і силою Святого Духа навернув всіх відступників до пізнання істини та приєднав до обраної пастви Своєї, – Господу помолимось! – Щоб просвітив думки невірством потьмарених світлом Богопізнання Свого і вірних Своїх укріпив та непохитними у Правовір’ї зберіг, – Господу помолимось! – Щоб визволитися нам від усякої скорботи, гніву, небезпеки та недолі, Господу помолимось. – Заступи, спаси, помилуй і охорони нас, Боже, Твоєю благодаттю. – Пресвяту, Пречисту, Преблагословенну, Славну Владичицю нашу Богородицю і Приснодіву Марію зо всіма святими пом’янувши, самі себе, і один одного, і все життя наше Христу Богові віддамо. Виголос архієрея: – Бо Тобі належить усяка слава, честь і поклоніння, Отцю і Сину і Святому Духу, нині і повсякчас і на віки віків. Хор: Амінь. Після цього співається «Бог Господь...» із звичайними стихами і тропар: Тропар глас 4: Дякуємо Тобі, недостойні раби Твої, Господи,/ за великі добродійства Твої,/ що їх ми зазнали, прославляючи Тебе,/ хвалимо, благословимо, дякуємо,/ оспівуємо і величаємо Твоє милосердя/ і, як раби, з любов’ю взиваємо до Тебе:/ Благодателю, Спасе наш, слава Тобі Слава, глас 3: Твоїх добродійств та дарів/ не по заслузі,/ як раби негідні, сподобившись,/ до Тебе, Владико, ревно припадаємо,/ і подяку по-сильно приносимо,/ і Тебе, як Доброчинця і Творця, прославляючи, взиваємо:/ слава Тобі, Боже Премилосердний. І нині, глас 4: Немов красу Вишнього Неба,/ показав Ти і земну красу святої оселі слави Своєї, Господи;/ утверди її повік-віку і прийми наші в ній моління,/ які ми невпинно приносимо Тобі,/ І молитвами Богородиці/ всіх Життя і Воскресіння! Протодиякон: – Будьмо уважні! Архієрей: – Мир усім! Читець: – І духові твоєму! Протодиякон: – Премудрість. Будьмо уважні! Читець: – Прокимен, глас 4-ий: – Насаджені в домі Господньому, у дворах дому Бога нашого процвітуть. Стих: Звеселиться праведник у Господі і уповатиме на Нього. Апостол – до Римлян зачало 121-е. Браття Благаю вас, остерiгайтесь тих, що чинять розбрат та спокуси всупереч вченню, якого ви навчилися, i ухиляйтесь вiд них; бо такi люди служать не Господевi нашому Iсусу Христу, а своєму череву, i ласкавими словами та красномовством зваблюють серця простодушних. Ваша покiрнiсть вiрi усiм вiдома; тому я радію за вас: тільки бажаю, щоб ви були мудрi у доброму i простi у злому. Бог же миру знищить незабаром сатану пiд ногами вашими. Благодать Господа нашого Iсуса Христа з вами! Амiнь. Євангеліє – від Матфея зачало 75-е. Сказав Господь стережіться, щоб ви не зневажили жодного з цих малих: бо кажу вам, що ангели їхні на небесах повсякчас бачать лице Отця Мого Небесного. Бо Син Людський прийшов знайти і спасти загибле. Як вам здається, коли буде в якогось чоловіка сто овець, і одна з них заблукає, чи не покине він у горах дев’яносто дев’ять і не піде шукати ту, що заблукала? І якщо трапиться знайти її, істинно кажу вам, він радіє за неї більше, ніж за дев’яносто дев’ять, що не заблукали. Так само немає волі Отця вашого Небесного, щоб загинув один з малих цих. Якщо ж згрішить проти тебе брат твій, піди і викрий його між тобою і ним одним. Якщо послухає тебе, то придбав ти брата твого. Якщо ж тебе не послухає, візьми з собою ще одного або двох, щоб устами двох чи трьох свідків підтвердилося кожне слово. Якщо ж не послухає їх, скажи церкві, якщо ж і церкви не послухає, то нехай він буде тобі як язичник і митар. Істинно кажу вам: що ви зв’яжете на землі, те буде зв’язане на небі, і що розв’яжете на землі, те буде розв’язане на небі. Тоді Потрійна ектенія: – Помилуй нас, Боже, з великої милості Твоєї, молимось Тобі, вислухай і помилуй. – Ще молимось За Владику і отця нашого Блаженнішого Митрополита (ім’я), і владику нашого Високопреосвященнійшого (митрополита, архієпископа, єпископа) (ім’я правлячого архієрея), і за все у Христі братство наше. – Ти Що не хочеш смерті грішників, але чекаєш їх навернення і покаяння, наверни всіх відступників до Святої Своєї Церкви, – молимося Тобі, Милосердний Господи, вислухай і помилуй . – Ти Що створив світ цей для слави Своєї, вчини, щоб і ті які противляться слову Твоєму, навернулися і разом з усіма вірними істинною вірою та благочестям Тебе, Бога нашого, прославляли, – молимося Тобі, Всесильний Творче, вислухай і помилуй! – Ти, Що дав заповідь Свою нам любити Тебе, Бога нашого, і ближнього свого, вчини, щоб ненависть, ворожнеча, кривди, хабарництво, клятвопереступи та інші беззаконня припинилися, істинна ж любов щоб царювала в серцях наших, – молимося Тобі, Спасителю наш, вислухай і милостиво помилуй . Архієрей виголошує: – Вислухай нас, Боже, Спасителю наш, надія всіх кінців землі і тих, що в морі далеко, і, Милостивий, будь милостивим, Владико, до гріхів наших і помилуй нас, бо Ти Милостивий і Людинолюбний Бог є, і Тобі славу возсилаємо, Отцю, і Сину, і Святому Духові, нині, і повсякчас, і на віки віків. Хор: – Амінь. Протодиякон: – Господу помолимось! Хор: – Господи, помилуй! Молитва Всевишній Боже, Владико і Творче всього творіння, Що наповняєш все величністю Своєю і утримуєш силою Своєю, Тобі, Вседаровитому Господу нашому, ми, не достойні, подяку приносимо за те, що не відвертаєшся від нас через беззаконня наші, але незбагненно попереджуєш нас милосердям Своїм. Ти задля визволення нашого послав Єдинородного Сина Свого і благовістив безмірну милість Свою до роду людського: що вельми бажаєш і чекаєш, аби навернулися до Тебе і спасенні були. Ти, зважаючи на неміч єства нашого, зміцнюєш нас всесильною благодаттю Святого Свого Духа, втішаєш спасительною вірою і досконалою надією вічних благ, та, скеровуючи [рукою Своєю] обраних Твоїх до Горнього Сиону, зберігаєш як зіницю ока. Прославляємо, Господи, велике Твоє і безприкладне чоловіколюбство і милосердя! Але, бачачи злі наміри багатьох. Всеблагий Господи, ревно, молимо Тебе: зглянься на Церкву Свою і побач, що хоч Твоє спасительне благовістя ми радісно і прийняли, але терня суєти і пристрастей робить його в декого малоплідним, в декого ж і безплідним, та, після збільшення беззаконь, одні єресями, інші розколом противлячись Євангельській істині Твоїй, відступають від насліддя Твого, відкидають Твою благодать і піддають себе суду пресвятого Твого слова. Премилосердний і Всесильний, Що до кінця не гніваєшся, Господи! Будь милостивим, благає Тебе Церква Твоя, – знаючи Тебе як Начальника і Звершителя спасіння нашого, Ісуса Хориста, – будь милостивим до нас, укріпи нас в Правовір’ї силою Своєю; а тим, що помиляються, просвіти очі розуму Божественним світлом Своїм, щоб зрозуміли істину Твою; пом ‘якши жорстокість їх і відкрий слух, щоб пізнали голос Твій і навернулися до Тебе, Спасителя Нашого. Виправ, Господи, в декого розбещеність і життя, яке не відповідає християнському благочестю; вчини, щоб всі ми свято і непорочно жили, – нехай спасительна віра вкоріниться і плідною в серцях наших перебуватиме. Не відверни Лиця Свого від нас, Господи, поверни нам радість спасіння Тобою; подай, Господи, і пастирям Церкви Твоєї святу ревність, та піклування їх про спасіння і навернення заблудлих, духом євангельським розчини, – щоб так ми всі, спрямовувані Тобою, досягли звершення віри, сповнення надії та істинної любові [в Царстві Твоїм] і там з ликами Чесних Небесних Сил прославили Тебе, Господа нашого, Отця і Сина і Святого Духа, повік-віку. Амінь. Тоді протодиякон, ставши на відповідному місці (на амвоні, біля ікони Спасителя, повернувшись обличчям до людей), виголошує: – Хто Бог великий, як Бог наш Ти єси Бог, що твориш чудеса Єдиний Також підвищуючи голос: – Хто Бог великий, як Бог наш Ти єси Бог, що твориш чудеса Єдиний І знову, ще вищим голосом: – Хто Бог великий, як Бог наш Ти єси Бог, що твориш чудеса Єдиний І далі продовжує: – Православ’я день святкуючи, православні люди, найбільше прославимо Причинця всіх благ – Бога, Який благословенний повіки. – Цей Бог наш, промишляючи і утверджуючи улюблене насліддя Своє – Церкву Святу, коли праотців, що через переступ [від Нього] відпали, втішав правдивим словом Своїм, – ще в раю основу її поклав. – Цей Бог наш, скеровуючи [все] до [сповнення] цієї спасительної обітниці, не залишив Себе без свідчень, але спасіння, що мало статися, провістив спочатку через праотців і пророків, зображаючи в різних образах. – Цей Бог наш, Що багаторазово і в багатьох образах у давнину говорив до отців через пророків, в останні ці дні говорив нам через Сина, Що Ним і віки сотворив, Який звістив Отче до нас благовоління, відкрив Таїнства Небесні, запевнив силою Святого Духа істину благовістя, послав Апостолів по всьому світу проповідувати Євангеліє Царства і ствердив його різноманітними силами і чудесами. – Це спасительне одкровення наслідуючи, цього благовістя тримаючись: Віруємо в Єдиного Бога Отця, Вседержителя, Творця неба і землі, всього видимого і невидимого. І в Єдиного Господа Ісуса Христа, Сина Божого, Єдинородного, що від Отця народився перше всіх віків; Світло від Світла, Бога істинного від Бога істинного, рожденного, несотворенного, єдиносущного з Отцем, що через Нього все сталося. Він для нас, людей, і ради нашого спасіння зійшов з небес, і воплотився від Духа Святого і Марії Діви, і став людиною. І розп’ятий був за нас при Понтії Пилаті, і страждав, і був похований. І воскрес на третій день, за Писанням. І вознісся на небеса, і сидить праворуч Отця. І знову прийде у славі судити живих і мертвих, і Царству Його не буде кінця. І в Духа Святого, Господа Животворчого, що від Отця ісходить, що Йому з Отцем і Сином однакове поклоніння і однакова слава, що говорив через пророків. В Єдину, Святу, Соборну і Апостольську Церкву. Визнаю одне хрещення на відпущення гріхів. Чекаємо воскресіння мертвих і життя майбутнього віку. Амінь. Ця віра апостольська, ця віра отцівська, ця віра православна, ця віра вселену ствердила. – І Собори Святих Отців, їх передання і писання, що Божественному Одкровенню відповідають, – приймаємо і стверджуємо! – Всім же, хто в Православ’ї подвизався словами, писаннями, вченнями, стражданнями і богоугодним життям, як захисникам та поборникам його, Христова Церква, щороку пам’ять творячи, виголошує: Святійшим православним Патріархам Константинопольським, Олександрійським, Антіохійським, Єрусалимським та іншим патріархам, преосвященним митрополитам, архієпископам і єпископам православним: вічна пам’ять (хор тут і далі співає: Вічна пам’ять, тричі). Святим рівноапостольним імператору Костянтину і матері його Олені вічна пам’ять. Святому рівноапостольному великому князю Київському Володимиру і рівноапостольній великій княгині Ользі вічна пам’ять. Усім, хто постраждав за православну віру, українському козацтву і всім православним християнам, які в істинній вірі і благочесті, і в надії на воскресіння спочили, вічна пам’ять. Православна Церква Христова, урочисто святкую-чи пам’ять тих, хто у благочесті подвизався, і це всім своїм вірним для уподібнення представляючи, прославляє подвиги їхні, готуючи себе і нині спасительною вірою і доброчинствами до вічного блаженства, і утверджує Православ’я. Далі протодиякон проголошує: Владиці і отцю нашому (ім’я), Блаженнійшому Митрополиту Київському і всієї України, многая літа (хор тут і далі співає: Многії літа, тричі). Святійшим православним патріархам Константинопольському, Олександрійському, Антіохійському, Єрусалимському та іншим православним патріархам, Блаженнійшим митрополитам і архієпископам, Предстоятелям Православних Церков многії літа. Владиці нашому (ім’я), преосвященному митрополиту (або архієпископу, або єпископу) (титул), многії літа. Преосвященним православним митрополитам, архієпископам і єпископам і всьому всечесному собору многії літа. Богом береженій Україні нашій, владі, війську і народу ї ї многії літа. Всім православним християнам, які вірно зберігають спасительну віру і підкоряються Христовій Церкві, подай, Господи, мир, благоденство, достаток пло дів земних і многії літа. – Святая Тройце, цих прослав і утверди до кінця в Правовір’ї; тих же, хто спотворює і хулить Православну Віру та Христову Церкву і не підкоряється їй – до неї наверни, і вчини, щоб прийшли [вони] до пізнання вічної Твоєї істини, за молитвами Пресвятої Владичиці нашої Богородиці і Приснодіви Марії та всіх святих. Амінь. І після цієї молитви архієрей відразу промовляє: Слава Тобі, Богу, Благодійнику нашому, на віки віків! Хор: Амінь. І співає пісню святого Амвросія Медіоланського. Під час співу архієрей, архімандрити, протоієреї і все священне зібрання цілують святі ікони на аналоях. Тебе Бога хвалимо,/ Тебе Господа, сповідуємо./ Тебе Предвічного Отця,/ вся земля величає,/ Тобі всі ангели,/ Тобі всі небеса і всі сили,/ Тобі Херувими і Серафими/ безперестанно голосами викликують/ Свят, Свят, Свят Господь Бог Саваоф,/ повні небеса і земля величі Твоєї;/ Тебе преславний апостольський хор/ Тебе пророків хвалить число./ Тебе хвалить пресвітле мучеників воїнство/ Тебе по всій вселенній сповідує Свята Церква,/ Отця неосягненої величі/ поклоняємого Твого Істинного і Єдинородного Сина/ і Святого Утішителя Духа./ Ти, Царю Слави Христе,/ Ти Отця Предвічний Син єси./ Ти для спасіння людини дівочою утробою не погордив,/ Ти переміг смерті жало,/ відкрив єси для віруючих Царство Небесне/ Ти праворуч Бога сидиш/ у славі Отчій судити прийдеш/ Тебе просимо, поможи рабам Твоїм,/ що їх дорогоцінною Кров’ю викупив Єси./ Сподоби зі святими Твоїми/ у вічній славі Твоїй царствувати/ Спаси людей Твоїх, Господи, і благослови насліддя Твоє./ Провадь і вознеси їх на віки./ У всі дні благословимо Тебе/ і хвалитимемо Ім’я Твоє навіки віків./ Сподоби, Господи, в день цей без гріха зберегтися нам/ помилуй нас, Господи, помилуй нас,/ нехай буде милість Твоя, Господи, на нас,/ бо ми надіємось на Тебе,/ щоб не осоромитися нам на віки віків Амінь. Примітка. Під час співу священнослужителі цілують ікони на аналоях. Потім чиниться звичайний відпуст. На трапезі: споживаємо їжу з оливою без риби і вживаємо вина на славу Божу (Типікон, гл. 49). Примітка. У сучасній богослужбовій практиці Української Православної Церкви поширений звичай звершувати ввечері чотирьох недільних днів Великого посту (як правило, починаючи не з Неділі Торжества Православ’я, а з 2-ої неділі – свт. Григорія Палами, за винятком тих випадків, коли на понеділок припаде Благовіщення, 1-ше і 2-ге Знайдення глави Іоана Предтечі, пам’ять 40 мучеників, храмове або Полієлейне свято) чинопослідовність пасії [1]. Подаємо два найбільш розповсюджені в Українській Православній Церкві варіанти чину Пасії. Перший варіант Пасії: перед вечірнею, яку звершують в неділю ввечері, на середині храму ставиться велике Розп’яття. Початок вечірні звичайний. Після «Світло Тихе...» звершується вхід з кадилом – заради великого прокимна. На стиховні, на «Славу» або на «І нині» (або на «Слава, і нині»), співається стихира Великої П’ятниці: «Тебе, що зодягаєшся...». Під час співу цієї стихири відкриваються царські врата і з вівтаря виноситься Святе Євангеліє: предстоятель несе Євангеліє, перед ним йде свічконосець; за предстоятелем йдуть інші священики за старшинством. Євангеліє кладеться на аналої перед Хрестом, і звершується повне кадіння храму. Зазвичай потім співають акафіст Страстям Христовим, причому 1-ий кондак хор починає співати відразу після стихири «Тебе, що зодягаєшся...». Після закінчення кадіння священнослужителі знімають головні убори. Під час читання акафісту диякон безперервно кадить Хрест, а на 11-му Ікосі зазвичай відбувається мале кадіння. Далі прокимен, глас 4-ий: «Розділили ризи Мої собі, і за одежу Мою кидали жереб», стих: «Боже, Боже Мій! Вислухай Мене, чому залишив Ти Мене?». Перед читанням Євангелія хор співає: «Слава страстям Твоїм, Господи!». Євангельське оповідання про Страсті Христові прийнято у такій редакції: на 1-ій пасії – з Євангелія від Матфея, глави 26 і 27, зачала 107–114 (в деяких храмах читається тільки глава 27, зачала 110–114); на 2-ій пасії – з Євангелія від Марка, глави 14 і 15, зачала 63–69 (або тільки глава 15, зачала 66–69); на 3-ій пасії – з Євангелія від Луки, глави 22 і 23, зачала 108–111 (або тільки глава 23, зачала 110–111); на 4-ій пасії – з Євангелія від Іоана, голови 18 і 19, зачала 58–62. Після прочитання Євангелія, хор: «Слава довготерпінню Твоєму, Господи!». Потім (зворушливим розспівом) співається 15-ий антифон служби Великої П’ятниці «Днесь висить на Дереві...». Коли спів закінчиться, на солії (царські врата залишаються відкритими) зазвичай виголошується проповідь про страждання Спасителя (іноді проповідь виголошується в кінці богослужіння). Далі йде мала сугуба ектенія «Помилуй нас, Боже...», потім виголос «Бо Ти милостивий і чоловіколюбний Бог єси...», і священник схиливши коліна читає молитву. Потім хор співає стихиру Великої Суботи: «Прийдіть, вшануймо Йосифа...». Священнослужителі, зробивши три земні поклони, прикладаються до Хреста і йдуть до вівтаря (попереду йдуть молодші священнослужителі, потім старші). Предстоятель з амвона благословляє народ Євангелієм і забирає його у вівтар. Священнослужителі прикладаються до престолу. Царські врата зачиняються. Всі вірні прикладаються до Хреста. Вечірня закінчується за звичайним чином вечора Неділь Святої Чотиридесятниці: після «Нині відпускаєш...» – спів великопостових тропарів «Богородице Діво...», «Слава: Хрестителю Христів...», «І нині: Моліться за нас...» з поклонами, «Під Твою милість...» без поклону, і далі за чином. Відпуст звичайний. Другий варіант: Перед початком Пасії звершується недільна Вечірня за Великопостовим чином до молитви прп. Єфрема Сиріна. Після того, як священник виголосить на солії молитву Прп. Єфрема Сиріна він заходить до Вівтаря і разом з іншими кліриками поцілувавши св. Престіл взявши Євангеліє виходить через Царські Врата на середину храму, де вже поставлено Голгофу. Перед Голгофою ставиться аналой на якому кладуть Євангеліє. Вийшовши, духовенство хреститься перед Голгофою і кланяються настоятелю. Настоятель, або паламар роздає всім священикам запалені свічки. Всі вірні в храмі також запалюють свічки і моляться із запаленими свічками. Під час виходу священиків хор співає: Алилуя, Алилуя, Алилуя (тричі). Настоятель приймає від диякона кадило і звершує велике кадіння храму. Під час кадіння Хор співає тропар Великого Четверга: Коли славні ученики умиванням ніг на вечері просвіщалися, тоді Іуда злочестивий недугою грошолюбства засліплювався і беззаконним суддям Тебе, Праведного Суддю продав. Глянь, скарбів ревнителю, того, що через них повісився. Тікай від тієї ненаситної душі, що на Вчителя так наважилася. Милосердний до всіх Господи слава Тобі. (тричі). Після того, як обкаджено храм, священики і хор співають заспіви: Духовенство: Слава страстям Твоїм Господи. Хор: Слава страстям Твоїм Господи. Духовенство: Слава Отцю і Сину і Святому Духу. Хор: І нині, і повсякчас, і на віки віків. Амінь. Заспіви співаються двічі. Після заспівів хор співає Ірмос 3-ої пісні канону Великої Суботи: «Тебе, що на водах усю землю повісив недержимо, побачивши розіп’ятим на лобнім місці, творіння з жаху великого тремтіло, взиваючи: нема святого, крім Тебе, Господи». Після ірмосу диякон виголошує малу ектенію. Ще і ще в мирі Господу помолимось. Заступи, спаси, помилуй і збережи нас, Боже, Твоєю благодаттю. Пресвяту, Пречисту і Преблагословенну, славну Владичицю нашу Богородицю і Приснодіву Марію зі всіма святими пом’янувши самих себе і один одного і все життя наше Христу Богові віддамо. Священик: Бо ти є Бог наш і Тобі славу возсилаємо: Отцю, і Сину, і Святому Духу, нині і повсякчас, і на віки віків. Хор: Амінь. І співається: «Спасіння вчинив Ти посеред землі, Христе Боже, на Хресті розпростерши пречисті руки Свої, збираючи всі народи, що взивають: Господи слава Тобі». Після «Спасіння вчинив...» духовенство і хор знову співають заспіви: Духовенство: Слава страстям Твоїм Господи. Хор: Слава страстям Твоїм Господи. Духовенство: Слава Отцю і Сину і Святому Духу. Хор: І нині, і повсякчас, і на віки віків. Амінь. Заспіви співаються двічі. Після заспівів хор співає Ірмос 6-ої пісні канону Великої Суботи: Взятий був, але не втриманий у пащі китовій Іона, Твій прообраз, Христе, що на страждання й поховання віддав Себе, мов із чертога, із звіра вийшов; дорікав же й варті Своїй: стережете даремно і марно, а милість Божу зневажили. Після Ірмосу диякон виголошує малу ектенію. Ще і ще в мирі Господу помолимось. Заступи, спаси, помилуй і збережи нас, Боже, Твоєю благодаттю. Пресвяту, Пречисту і Преблагословенну, славну Владичицю нашу Богородицю і Приснодіву Марію зо всіма святими пом’янувши самих себе і один одного і все життя наше Христу Богові віддамо. Священик: Бо Ти є Цар миру і Спас душ наших, і Тобі славу возсилаємо: Отцю, І Сину, і Святому Духу нині і повсякчас, і на віки віків. Хор. Амінь. І співається: «Спасіння вчинив Ти посеред землі, Христе Боже, на Хресті розпростерши пречисті руки Свої, збираючи всі народи, що взивають: Господи слава Тобі». Після «Спасіння вчинив...» духовенство і хор знову співають заспіви: Духовенство: Слава страстям Твоїм Господи. Хор: Слава страстям Твоїм Господи. Духовенство: Слава Отцю, і Сину, і Святому Духу. Хор: І нині, і повсякчас, і на віки віків. Амінь. Заспіви співаються двічі. Після заспівів хор співає Ірмос 9-ої пісні канону Великої Суботи: Не ридай по Мені, Мати, бачачи у гробі Сина, що Його в утробі безсіменно зачала єси: встану бо, і прославлюся, і назавжди піднесу із славою, як Бог, тих, що з вірою й любов’ю Тебе величають. Після закінчення співу диякон: Будьмо уважні! Премудрість! Прокимен глас 4-ий: Розділили ризи Мої собі, і за одежу Мою кидали жереб. Стих: Боже, Боже Мій, вислухай Мене нащо Ти покинув Мене! Диякон: «Господу помолимось». Хор: «Господи помилуй». Священик: «Бо Ти Святий є Боже наш і в святих перебуваєш, і Тобі славу возсилаємо Отцю, і Сину, і Святому Духу нині і повсякчас і на віки віків». Хор: «Амінь». Диякон: «Все, що дише нехай хвалить Господа». Хор: «Все, що дише...». Диякон: «Хваліть Бога у святих Його, хваліть Його у твердині сили Його. Хор: «Все, що дише...». Диякон: «Все, що дише» Хор: (закінчує) «нехай хвалить Господа». Диякон: «І щоб сподобитися нам вислухати Святого Євангелія Господа Бога молимо». Хор: «Господи помилуй» (тричі). Диякон: «Премудрість! Станьмо побожно! Вислухаймо Святого Євангелія! Священик: «Мир усім!» Хор: «І духові твоєму». Священик: «Від (ім’я євангелиста) Святого Євангелія читання. Хор: «Слава страстям Твоїм Господи!» Диякон: «Будьмо уважні». Євангельське оповідання про Страсті Христові прийнято у такій редакції: на 1-ій пасії – з Євангелія від Матфея, глави 26 і 27, зачала 107–114 (в деяких храмах читається тільки глава 27, зачала 110 – 114); на 2-ій пасії – з Євангелія від Марка, глави 14 і 15, зачала 63 – 69 (або тільки глава 15, зачала 66 – 69); на 3-ій пасії – з Євангелія від Луки, глави 22 і 23, зачала 108 – 111 (або тільки глава 23, зачала 110–111); на 4-ій пасії – з Євангелія від Іоана, голови 18 і 19, зачала 58 – 62. Після прочитання Євангелія хор співає: «Слава довготерпінню Твоєму Господи!» Всі гасять свічки. І співається: «Спасіння вчинив Ти посеред землі, Христе Боже, на Хресті розпростерши пречисті руки Свої, збираючи всі народи, що взивають: Господи слава Тобі». Після «Спасіння вчинив...» духовенство і хор знову співають заспіви: Духовенство: Слава страстям Твоїм Господи. Хор: Слава страстям Твоїм Господи. Духовенство: Слава Отцю, і Сину, і Святому Духу. Хор: І нині, і повсякчас, і на віки віків. Амінь. Заспіви співаються двічі. Після заспівів хор співає тропар Великої Суботи, глас 2-ий: Благообразний Йосиф, з древа знявши пречистеє тіло Твоє, плащаницею чистою обгорнувши і пахощами в гробі новім покривши, поклав. Диякон виголошує коротку потрійну ектенію: Помилуй нас Боже, з великої милості Твоєї, молимось Тобі вислухай і помилуй. Хор: Господи помилуй (тричі) Диякон: Ще молимось за Владику і Отця нашого Блаженнішого Митрополита (ім’я)і владику нашого (Високо) Преосвященнійшого(ім’я), і за все у Христі братство наше. Хор: Господи помилуй (тричі) Диякон: Ще молимось за Богом бережену Україну нашу, владу і військо її, щоб ми тихе і мирне життя прожили у всякому благочесті і чистоті. Хор: Господи помилуй (тричі) Диякон: Ще молимось за братів наших священиків, священномонахів і за все у Христі братство наше. Хор: Господи помилуй (тричі) Диякон: Ще молимось за ієрархів православних, за благочестивих і повікнезабутніх фундаторів святого храму цього (в монастирі – святого монастиря цього) і всіх спочилих отців і братів наших, що тут і повсюди лежать, – православних. Хор: Господи помилуй (тричі) Диякон: Ще молимось за тих, що дари приносять і добро діють у святому і всечесному храмі цьому; за тих, що трудяться, співають, і за всіх присутніх людей, що сподіваються від Тебе великої і багатої милости. Хор: Господи помилуй (тричі) Священик: Бо Ти Милостивий і Людинолюбний Бог єси, і Тобі славу возсилаємо, Отцю, і Сину, і Святому Духові, нині, і повсякчас, і на віки віків. Хор: Амінь. Диякон: Ще і ще, схиливши коліна, до Господа нашого Ісуса Христа помолимось! Хор: Слава страстям Твоїм, Господи! Всі присутні стають на коліна і священик читає молитву: Господи Ісусе Христе, Сину Бога Живого Сотворителю неба і землі, Спасителю світу! Ось ми, недостойні, найгрішніші смиренно коліна сердець наших перед славою величності Твоєї вклонивши, оспівуємо Хрест і страждання Твої, подяку Тобі, Царю всіх і Богу приносимо, бо Ти зволив всі труди і всілякі біди, нещастя і муки, як Людина понести, щоб усім нам у всіляких скорботах, бідах і напастях бути співстраждучим Помічником і Спасителем. Знаємо, Всесильний Владико, що все це Тобі не було потрібне, але тільки заради спасіння людства Хрест і страждання перетерпів Ти, щоб усіх нас визволити з-під лютого рабства диявола. Чим відплатимо Тобі, Людинолюбче, за всі страждання Твої за нас грішних? Не знаємо! Бо душі і тіла і все добре у нас від Тебе, і все наше – Твоє, і ми Твої. Тільки на безмежне Твоє Милосердя, Господи, надію покладаючи, оспівуємо Твоє невимовне довготерпіння, величаємо недовідоме приниження, славимо Твою безмірну милість, поклоняємось страстям Твоїм, і з любов’ю цілуючи рани Твої, взиваємо: помилуй нас грішних, вчини, щоб не безплідним був у нас Хрест Твій Святий, щоб ставши тут з вірою спільниками Твоїх страждань, сподобилися ми бачити і славу Царства Твого на Небесах. Хор: Амінь. Всі роблять земний поклін і підіймаються з колін. Диякон: Премудрість. Священик: Пресвята Богородице спаси нас. Хор: Чеснішу від херувимів і незрівнянно славнішу від серафимів, що без істління Бога Слово породила, сущу Богородицю, Тебе величаємо. Священик:: Слава Тобі, Христе Боже, надія наша, слава Тобі. Хор: Слава: І нині. Господи, помилуй (тричі). Благослови. Священик чинить відпуст. Христос, Істинний Бог наш, що заради нас, людей, і заради нашого спасіння страшні муки, і Животворчий Хрест, і добровільне погребіння тілом прийняти зволив, молитвами Пречистої Своєї Матері... Хор: Амінь. Слава страстям Твоїм, Господи! Після відпусту хор співає стихиру: Прийдіть, вшануймо Йосифа приснопам’ятного, що вночі до Пилата прийшов і Життя всіх випросив: «Дай мені Цього Подорожнього, що не має де голови прихилити; дай мені Цього Подорожнього, Його ж бо ученик лукавий на смерть продав; дай мені Цього Подорожнього, що Його Мати, бачачи на хресті розп’ятим, ридаючи, голосила і по-материнськи промовляла: «О горе Мені, Світло Моє і Серце Моє улюблене! Симеоном бо провіщене в церкві нині сталося: Моє серце меч пройняв. Ти ж на радість воскресінням Твоїм Мій плач оберни». Поклоняємось страстям Твоїм, Христе; поклоняємось страстям Твоїм, Христе; поклоняємось страстям Твоїм, Христе, і святому Воскресінню. А потім й інші належні церковні пісні. Під час співу всі люди вклоняються перед Голгофою зі смиренням і благоговінням цілуючи її, а потім тихо і побожно виходять з церкви, роздумуючи про великі і страшні Страсті Христові, які Він перетерпів у повній покорі до Свого Отця."}]},
{"date":"03-02","weekday":"понеділок","title":"2-й тиждень Великого посту. Сщмч. Феодота, єп. Киринейського (бл. 326). Свт. Іова (Борецького), митр. Київського і всієї Руси (1631) (службу святителю дивись 15 березня). Мц. Євфалії (257). Мч. Троадія (ІІІ). Прп. Агафона Єгипетського (V). Мчч. 440 італійських (579). Свт. Арсенія, єп. Тверського (1409).","notes":"На 6-му часі: Іс. IV, 2 – V, 7. На веч.: Бут. III, 21 – IV, 7. Притч. III, 34 – IV, 22.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ. Дивись зразок звершення вечірньої 22 лютого. Кафизми немає. На «Господи, взиваю» стихири на 10: 4 стихири покаянні Октоїха, глас 5-ий (дві – зі стихир на стиховні вечора, дві інші – зі стиховних стихир ранньої), Тріоді, глас 4-ий і глас 6-ий – 3, і стихири свящмч Феодота, глас 4-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той же: «Засудження позбав...». Вхід з кадилом. «Світло Тихе». Співається великий прокимен, глас 8-ий: «Дав єси насліддя...», зі стихами (за звичаєм). Під час читання «Сподоби Господи...» священник облачається в облачення багряного (сучасній практиці – чорного) кольору. На стиховні стихири Тріоді, глас 8-ий «Слава, і нині» – Богородичний Тріоді, глас то й же «Небеса оспівують Тебе...». Молитва прп. Єфрема Сиріна читається із трьома великими поклонами (без малих). Закінчення вечірні великопостове (22 лютого). Після вечірні заупокійної літії немає."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в неділю ввечері співається служба святих пророків, глас 5-ий зі стихирами, глас 1-ий (див. Постова Тріодь), і служба прпмч. Євдокії (з 1 березня). Примітка. Канон Богородиці на повечір’ї в неділю ввечері не співається, оскільки напередодні звершувалося всенічне бдіння."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 5-ий з приспівами понеділка. Кафизми 4-та, 5-та, 6-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. 3-тя, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на чотири. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 1-ша, 8-ма, 9-та – ірмос другого трипіснеця Тріоді. 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 4-ий: «Святительський одяг...» «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – кондак свящмч., глас 3-ій. На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 5-ий: «Дивна зброя – піст і молитва..» «Слава і нині» – Богородичний Тріоді: «Тобі молимось...». Далі великопостове закінчення ранньої. На 1-му часі – кафизми немає. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 7-ма. На 6-му – кафизма 8-ма. Прокимни та паремія Тріоді. На 9-му – кафизма 9-та. Про читання Євангелія на часах під час Великого посту Устав надає особливого значення прочитанню на часах в понеділок, вівторок і середу Страсного тижня всіх чотирьох Євангелій. У цьому позначається глибока відмінність Страсної седмиці від інших тижнів Великого посту, коли за Уставом в будні дні не читаються Євангельські читання. Однак з огляду на те, що належне за Уставом читання Євангелія всіх чотирьох євангелистів на часах перших трьох днів Страсного тижня дуже збільшує тривалість і без того не коротких служб цих днів, з давніх часів у багатьох храмах і обителях встановилася практика читання Євангелія перших трьох євангелистів на часах 6-го тижня. У сучасній практиці існує також звичай починати читання Євангелія на великопостових часах з 2-го тижня Великого посту, хоча це і надає для буденних великопостових служб невластиву для них за Уставом урочистість. З огляду на сформовану практику, пропонуємо можливі варіанти розподілу євангельських уривків для читання на великопостових часах протягом 2-го – 6-ого тижнів св. Чотиридесятниці і для читання на 6-му тижні Великого посту. Порядок читання Євангелія на великопостових часах в середу і п’ятницю протягом 2-го-6-го тижня: 2-ий тиждень: Сер. 3-ій час – Мф., Зач. 1–8 (1, 1 – 4, 17). 6-ий час – Мф., Зач. 9–20 (4, 18 – 7, 11). 9-ий час – Мф., Зач. 21–34 (7, 12 – 10, 8). Пт. 3-ій час – Мф., Зач. 35–46 (10, 9 – 12, 30). 6-ий час – Мф., Зач. 47–57 (12, 30 – 14, 13). 9-ий час – Мф., Зач. 58–70 (14, 14 – 17, 9). 3-ій тиждень: Сер. 3-ій час – Мф., Зач. 71-80 (17, 10 – 20, 16). 6-ий час – Мф., Зач. 81–90 (20, 17 – 22, 22). 9-ий час – Мф., Зач. 91–103 (22, 23 – 24, 51). Пт. 3-ій час – Мф., Зач. 104–108 (25, 1 – 26, 56). 6-ий час – Мф., Зач. 109–116 (26, 57 – 28, 20). 9-ий час – Мк., Зач. 1–12 (1, 1 – 3, 19). 4-ий тиждень: Сер. 3-ій час – Мк., Зач. 13–22 (3, 20 – 6, 7). 6-ий час – Мк., Зач. 23–32 (6, 7 – 8, 10). 9-ий час – Мк., Зач. 33–44 (8, 11 – 10, 16). Пт. 3-ій час – Мк., Зач. 45–55 (10, 17 – 12, 27). 6-ий час – Мк., Зач. 56–64 (12, 28 – 14, 42). 9-ий час – Мк., Зач. 65-71 (14, 43 – 16, 20). 5-ий тиждень: Оскільки 25 березня – свято Благовіщення Пресвятої Богородиці припадає цього року на середу 5-того тижня, то читання переноситься на четвер. Чт. 3-ій час – Лк., Зач. 1–5 (1, 1 – 2, 20). 6-ий час – Лк., Зач. 6–15 (2, 20 – 4, 36). 9-ий час – Лк., Зач. 16–28 (4, 37 – 7, 1). Пт. 3-ій час – Лк., Зач. 29–38 (7, 1 – 8, 39). 6-ий час – Лк., Зач. 39–50 (8, 40 – 10, 15). 9-ий час – Лк., Зач. 51–62 (10, 16 – 12, 1). 6-ий тиждень: Сер. 3-ій час – Лк., Зач. 63–73 (12, 2 – 13, 35). 6-ий час – Лк., Зач. 74–83 (14, 1 – 17, 4). 9-ий час – Лк., Зач. 84–95 (17, 3 – 19, 28). Пт. 3-ій час – Лк., Зач. 96–107 (19, 29 – 21, 36). 6-ий час – Лк., Зач. 108–109 (21, 37 – 23, 1). 9-ий час – Лк., Зач. 110–114 (23, 2 – 24, 53). Порядок читання Євангелія на великопостових часах щодня протягом 2-го-6-ого тижнів: 2-ий тиждень: Пн. 3-ій час – Мф., Зач. 1–4 (1, 1 – 2, 23). 6-ий час – Мф., Зач. 5–8 (3, 1 – 4, 17). 9-ий час – Мф., Зач. 9–11 (4, 18 – 5, 19). Вт. 3-ій час – Мф., Зач. 12–17 (5, 20 – 6, 21). 6-ий час – Мф., Зач. 18–22 (6, 22 – 7, 21). 9-ий час – Мф., Зач. 23–28 (7, 21 – 9, 1). Сер. 3-ій час – Мф., Зач. 29–34 (9, 1 – 10, 8). 6-ий час – Мф., Зач. 35–43 (10, 9 – 11, 30). 9-ий час – Мф., Зач. 44–46 (12, 1 – 12, 30). Чт. 3-ій час – Мф., Зач. 47–49 (12, 30 – 13, 3). 6-а час – Мф., Зач. 50–54 (13, 4 – 13, 43). 9-ий час – Мф., Зач. 55–56 (13, 44 – 13, 58). Пт. 3-ій час – Мф., Зач. 57–59 (14, 1 – 14, 34). 6-ий час – Мф., Зач. 60–64 (14, 35 – 15, 39). 9-ий час – Мф., Зач. 65–70 (16, 1 – 17, 9). 3-ій тиждень: Пн. 3-ій час – Мф., Зач. 71–73 (17, 10 – 18, 4). 6-ий час – Мф., Зач. 74–75 (18, 1 – 18, 20). 9-ий час – Мф., Зач. 76–80 (18, 18 – 20, 16). Вт. 3-ій час – Мф., Зач. 81–82 (20, 17 – 20, 34). 6-ий час – Мф., Зач. 83–84 (21, 1 – 21, 22). 9-ий час – Мф., Зач. 85–88 (21, 23 – 21, 46). Сер. 3-ій час – Мф., Зач. 89–90 (22, 1 – 22, 22). 6-ий час – Мф., Зач. 91–93 (22, 23 – 23, 12). 9-ий час – Мф., Зач. 94–96 (23, 13 – 23, 39). Чт. 3-ій час – Мф., Зач. 97–98 (24, 1 – 24, 13). 6-ий час – Мф., Зач. 99 (24, 13 – 24, 28). 9-ий час – Мф., Зач. 100–104 (24, 27 – 25, 13). Пт. 3-ій час – Мф., Зач. 105–106 (25, 14 – 25, 46). 6-ий час – Мф., Зач. 107–109 (26, 1 – 26, 75). 9-ий час – Мф., Зач. 110–116 (27, 1 – 28, 20). 4-ий тиждень: Пн. 3-ій час – Мк., Зач. 1–5 (1, 1 – 1, 35). 6-ий час – Мк., Зач. 6–9 (1, 35 – 2, 22). 9-ий час – Мк., Зач. 10–12 (2, 23 – 3, 19). Вт. 3-ій час – Мк., Зач. 13–16 (3, 20 – 4, 23). 6-ий час – Мк., Зач. 17–22 (4, 24 – 6, 7). 9-ий час – Мк., Зач. 23–29 (6, 7 – 7, 24). Сер. 3-ій час – Мк., Зач. 30–32 (7, 24 – 8, 10). 6-ий час – Мк., Зач. 33–38 (8, 11 – 9, 9). 9-ий час – Мк., Зач. 39–44 (9, 10 – 10, 16). Чт. 3-ій час – Мк., Зач. 45–48 (10, 17 – 10, 52). 6-ий час – Мк., Зач. 49–51 (11, 1 – 11, 26). 9-ий час – Мк., Зач. 52–55 (11, 27 – 12, 27). Пт. 3-ій час – Мк., Зач. 56–60 (12, 28 – 13, 23). 6-ий час – Мк., Зач. 61–64 (13, 24 – 14, 42). 9-ий час – Мк., Зач. 65–71 (14, 43 – 16, 20). 5-ий тиждень: Пн. 3-ій час – Лк., Зач. 1–5 (1, 1 – 2, 20). 6-ий час – Лк., Зач. 6–9 (2, 20 – 3, 18). 9-ий час – Лк., Зач. 10–12 (3, 19 – 4, 15). Вт. 3-ій час – Лк., Зач. 13–15 (4, 16 – 4, 36). 6-ий час – Лк., Зач. 16–20 (4, 37 – 5, 32). 9-ий час – Лк., Зач. 21–24 (5, 33 – 6, 23). Оскільки 25 березня – свято Благовіщення Пресвятої Богородиці припадає цього року на середу 5-того тижня, то читання переноситься на четвер. Чт. 3-ій час – Лк., Зач. 25–32 (6, 24 – 7, 35). 6-ий час – Лк., Зач. 33–38 (7, 36 – 8, 39). 9-ий час – Лк., Зач. 39–48 (8, 40 – 9, 56). Пт. 3-ій час – Лк., Зач. 49–50 (9, 57 – 10, 15). 6-ий час – Лк., Зач. 51–56 (10, 16 – 11, 13). 9-ий час – Лк., Зач. 57–62 (11, 14 – 12, 1). 6-ий тиждень: Пн. 3-ій час – Лк., Зач. 63–68 (12, 2 – 12, 48). 6-ий час – Лк., Зач. 69–70 (12, 48 – 13, 9). 9-ий час – Лк., Зач. 71–73 (13, 10 – 13, 35). Вт. 3-ій час – Лк., Зач. 74–77 (14, 1 – 14, 35). 6-ий час – Лк., Зач. 78–80 (15, 1 – 16, 9). 9-ий час – Лк., Зач. 81–83 (16, 10 – 17, 4). Сер. 3-ій час – Лк., Зач. 84–86 (17, 3 – 17, 25). 6-ий час – Лк., Зач. 87–89 (17, 26 – 18, 14). 9-ий час – Лк., Зач. 90–95 (18, 15 – 19, 28). Чт. 3-ій час – Лк., Зач. 96–98 (19, 29 – 19, 48). 6-ий час – Лк., Зач. 99–101 (20, 1 – 20, 26). 9-ий час – Лк., Зач. 102–103 (20, 27 – 21, 4). Пт. 3-ій час – Лк., Зач. 104–107 (21, 5 – 21, 36). 6-ий час – Лк., Зач. 108–109 (21, 37 – 23, 1). 9-ий час – Лк., Зач. 110–114 (23, 2 – 24, 53). Порядок читання Євангелія на великопостових часах лише на 6-ому тижні: Пн. 3-ій час – Мф., Зач. 1–17 (1, 1 – 6, 21). 6-ий час – Мф., Зач. 18–42 (6, 22 – 11, 26). 9-ий час – Мф., Зач. 43–66 (11, 27 – 16, 12). Вт. 3-ій час – Мф., Зач. 67–83 (16, 13 – 21, 17). 6-ий час – Мф., Зач. 84–105 (21, 18 – 25, 30). 9-ий час – Мф., Зач. 106–116 (25, 31 – 28, 20). Сер. 3-ій час – Мк., Зач. 1–25 (1, 1 – 6, 45). 6-ий час – Мк., Зач. 26–51 (6, 45 – 11, 26). 9-ий час – Мк., Зач. 52–71 (11, 27 – 16, 20). Чт. 3-ій час – Лк., Зач. 1–16 (1, 1 – 4, 44). 6-ий час – Лк., Зач. 17–38 (5, 1 – 8, 39). 9-ий час – Лк., Зач. 39–62 (8, 40 – 12, 1). Пт. 3-ій час – Лк., Зач. 63–82 (12, 2 – 16, 18). 6-ий час – Лк., Зач. 83–105 (16, 19 – 21, 11). 9-ий час – Лк., Зач. 106–114 (21, 12 – 24, 53)."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня, кондак свящмч. Феодота, глас 3-тій. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, кондак свящмч. Феодота, глас 3-тій. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак свящмч. Феодота, глас 3-тій. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (в понеділок увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 8-ий – 3, Мінеї – мучч., глас 1-ий – 3 (з 3 березня). «Слава, і нині» – Богородичний Мінеї. Входу немає. Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 3-тій. «Слава, і нині» – Богородичний Тріоді, глас то й же. Закічення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-03","weekday":"вівторок","title":"Мчч. Євтропія, Клеоника і Василіска (бл. 308). Прп. Піами, діви (337). Свв. Зинона і Зоїла.","notes":"На 6-му часі: Іс. V, 7 – 16. На веч.: Бут. IV, 8 – 15. Притч. V, 1 – 15.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у понеділок ввечері – канон Богородиці і Прп. Йосифа Піснеписця (з 4 квітня) – святого, в день якого припала Лазарева субота. УВАГА! Служби святим НА ПОВЕЧІР’Ї звершуються наступним чином. Після закінчення повсякденного славослів’я: «Слава в вишніх Богу...» (на великому повечір’ї) або ж після Символу віри (на малому повечір’ї) співається канон Богородиці з Октоїха (без ірмосів) і канон святого з Мінеї (без ірмосів) з «Молебними» приспівами «Пресвята Богородице, спаси нас», «Преподобний отче (ім’я), моли Бога за нас», або «Святі апостоли, моліть Бога за нас» і т. д.; в кінці: «Слава» – тропар, «І нині» – Богородичний. Таким чином виконуються всі пісні канону. Після 3-ої пісні – кондак і сідальний Мінеї. Після 6-ої пісні – сідальний Богородиці (див. Типікон, гл. 49, «У понеділок 2-ої седмиці посту», 1-е «див»), після 9-ої пісні – стихири святого з «Господи, взиваю» (з тими ж приспівами, що і на каноні). «Слава, і нині» – Богородичний або Хрестобогородичний. Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя, глас 5-ий з приспівами вівторка. Кафизми 10-та, 11-та, 12-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 2 пісня тільки з Тріоді на 8. 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 2-га, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 1-ий: «Тройцю Пресвяту..» «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – Мученичий Октоїха (кондак рядових святих відсутній). На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 5-ий: «Навіщо впадаєш у безнадійність..» «Слава і нині» – Богородичний Тріоді: «Ублажаємо Тебе...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 13-та. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 14-та. На 6-му – кафизма 15-та. Прокимни та паремія Тріоді. На 9-му – кафизма 16-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Примітка. Оскільки в службі рядових святих Мінеї кондак мучеників відсутній, то на зображальних він не читається, його не варто замінювати загальним кондаком чи мученичним із Октоїха. Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у вівторок увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 1-ий – 3, Мінеї – преподобного, глас 8-ий – 3 (з 4 березня). «Слава, і нині» – Хрестобогородичний Мінеї: «Тебе Ісусе бачачи...». Входу немає. Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 3-тій. «Слава, і нині» – Хрестобогородичний Тріоді, глас то й же. Закінчення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-04","weekday":"середа","title":"Прп. Герасима, що на Йордані (475). Мч. Павла і мц. Юліанії (бл. 273). Прп. Якова, посника (VІ). Перенесення мощів блгв. кн. В’ячеслава Чеського (938). Прп. Герасима Київського, ігум. Вологодського (1178). Свт. Григорія, єп. Констанції Кіпрської. Прмч. Іоасафа Снітногорського (1299). Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. I, 19 – II, 3. На веч.: Бут. I, 14 – 23. Притч. I, 20 – 33.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у вівторок ввечері – канон Богородиці і служба свящмч. Агафона (з 5 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя, глас 5-ий з приспівами середи. Кафизми 19-та, 20-та і 1-ша. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 3-тя, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 3-тя, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 4-ий: «Демонів підступи ти преподобний переміг..» «Слава, і нині» – Хрестобогородичний Мінеї, глас то й же: «На древі піднесеним бачачи». Після 6-тої – Кондак преподобного, глас 4: «Запалившись любов’ю...». На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні (Октоїха). Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 7-ий: «Хрестом Твоїм Господи..» «Слава і нині» – Хрестобогородичний Тріоді: «Коли побачила на древі розп’ятого...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 2-га. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 3-тя. На 6-му – кафизма 4-та. Прокимни та паремія Тріоді. На 9-му – кафизма 5-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Твориться відпуст зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у середу увечері) – кафизма 18-та. «Господи взиваю» – стихири на 10: Тріоді, глас 1-ий – 6 (самогласна стихира двічі), Мінеї – мученика Конона, глас 8-ий – 4 (з 5 березня), перша стихира мученику співається двічі. «Слава, і нині» – Богородичний Мінеї: «Радуйся вмістилище Божественного світла...». Вхід з кадилом. «Світе Тихий». Паремії Тріоді – 2. Далі продовження Літургії Ранішосвячених Дарів. Детальний виклад порядку вечірні в поєднанні з Літургією Ранішосвячених Дарів див. 25 лютого. Після Літургії заупокійної літії немає."}]},
{"date":"03-05","weekday":"четвер","title":"Мч. Конона Ісаврійського (І). Мч. Онисія (І). Мч. Конона, градаря (землероба) (ІІІ). Прп. Марка (V). Прп. Ісихія (бл. 790). Мц. Іраїди. Мч. Євлогія, що в Палестині. Мч. Євлампія.","notes":"На 6-му часі: Іс. VI, 1 – 12. На веч.: Бут. V, 1 – 24. Притч. VI, 3 – 20.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у середу ввечері – канон Богородиці і свт. Євтихія (з 6 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 5-ий з приспівами четверга. Кафизми 6-та, 7-ма, 8-ма. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 4-та, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 4-та, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 8-ий: «Озброївшись Христовою зброєю...» «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – кондак мученика, глас 3-тій: «Чистотою поживши...». На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Октоїха. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 8-ий: «Покаяння час..» «Слава і нині» – Богородичний Тріоді: «Діво Пресвята...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 9-та. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 10-та. На 6-му – кафизма 11-та. Прокимни та паремія Тріоді. На 9-му – кафизма 12-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня, інший кондак дня, кондак мученика. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, інший кондак дня, кондак мученика. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, інший кондак дня, кондак храму, кондак мученика. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Примітка. Якщо денний кондак співпадає з кондаком храму, то він читається лише один раз. Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у четвер увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 4-ий – 3, Мінеї – мученикам, глас 4-ий – 3 (з 6 березня). «Слава, і нині» – Хрестобогородичний Мінеї: «Не ридай за Мною Мати...». Входу немає. Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 5-тий. «Слава» – мучеників, глас 6-ий: «Полк боговінчаний..», і нині» – Хрестобогородичний Тріоді, глас то й же. Закінчення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-06","weekday":"п’ятниця","title":"Мчч. 42 в Амморії: Костянтина, Аетія, Феофіла, Федора, Мелісена, Каліста, Васоя та інших з ними (бл. 845). Знайдення чесного Хреста і цвяхів св. царицею Оленою в Єрусалимі (326). Прмч. Конона і сина його Конона (270 – 275). Прп. Аркадія Кіпрського (бл. 361). Ікон Божої Матері Ченстоховської, Шестоківської і «Благодатне небо». Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. VII, 1 – 14. На веч.: Бут. V, 32 – VI, 8. Притч. VI, 20 – VII, 1.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї в четвер увечері – канон Богородиці і служба прп. Георгія, сповідника (з 7 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 5-ий з приспівами п’ятниці. Кафизми 13-та, 14-та і 15-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 4-та, 6-та, 7-ма пісні: Мінеї на 4. 5-та, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 5-та, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – перший кондак мучеників, глас 4-ий: «На землі заради Христа..». Сідальний, глас 8-ий: «Демонів підступи ти преподобний переміг..» «Слава, і нині» – Хрестобогородичний Мінеї, глас то й же: «Агнця і Пастиря...». Після 6-тої – кондак мучеників, глас 2-ий: «Новоявленні зірки віри...» та ікос. На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Октоїха Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 8-ий: «Теперішній піст..» «Слава і нині» – Хрестобогородичний Тріоді: «Що дивне і прекрасне...». Далі великопостове закінчення ранньої. На 1-му часі – кафизми немає. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 19-тя. На 6-му – кафизма 20-та. Прокимни та паремія Тріоді. На 9-му – кафизми немає."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак дня, кондак мучеників, інший кондак мучеників. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, кондак мучеників, інший кондак мучеників. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак мучеників, інший кондак мучеників. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Твориться відпуст зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у п’ятницю увечері) – кафизма 18-та. «Господи взиваю» – стихири на 10: Тріоді, глас 4-ий – 6 (самогласна стихира двічі): «Сьогодні час сприятливий, сьогодні спасіння день, відвідай душу мою з великої милості Твоєї, і тягар гріхів моїх полегши, Єдиний Людинолюбче», і мученичні Октоїха, глас 5-ий, Мінеї – священномучеників Херсонеських, глас4-ий – 4 (з 7 березня), перша стихира священомучеників співається двічі. «Слава» – померлим, 5-го гласу: «Пом’янув пророка, який взиває, я є земля і попіл; і знову розглянув гроби і побачив голі кістки, і знову сказав: хто є цар, або воїн, або багатий, або праведник, або грішник? Але упокой з праведними рабів Твоїх, як Людинолюбець». «І нині» – догматик: «У Червному морі...». Вхід з кадилом. «Світе Тихий. Читання паремій Тріоді (прокимен 1-ий паремії, глас 4-ий: «Милість та істина Твоя...», зі стихом; прокимен 2-ий паремії, глас 6-ий: «Я сказав: Господи, помилуй мене...», зі стихом). «Нехай піднесеться молитва моя...», Далі продовження Літургії Ранішосвячених Дарів. Детальний виклад порядку вечірні в поєднанні з Літургією Ранішосвячених Дарів див. 25 лютого. Після Літургії заупокійної літії немає."}]},
{"date":"03-07","weekday":"субота","title":"Священномучеників, які в Херсонесі були єпископами: Василія, Єфрема, Капітона, Євгенія, Єферія, Елпідія та Агафодора (ІV). Прп. Павла Препростого (ІV). Свт. Павла, спов., єп. Прусіадського (ІХ). Прп. Еміліана Італійського. Ікони Божої Матері «Споручниця грішних». Поминання померлих. Літургія свт. Іоана Золотоустого.","readings":["Євр., 309 зач., III, 12 – 16. Мк., 6 зач., I, 35 – 44.","За упокій: 1 Сол., 270 зач., IV, 13 – 17. Ін., 16 зач., V, 24 – 30."],"notes":"Цієї суботи і в дві прийдешні заупокійна служба з Тріоді з’єднується зі службами Мінеї та Октоїха. ВЕЛИКЕ ПОВЕЧІР’Я (без поклонів): Після 1-го Трисвятого – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар глас той же: «Пом’яни, Господи...», «І нині» – Богородичний, глас той же: «Мати Свята...». Після 2-го Трисвятого – тропарі Часослова (звичайні), глас 6-ий: «Помилуй нас, Господи...». Після «Слава в вишніх...» – співається служба прп. Прп. Феофілакта, спов., єп. Нікомидійського (з 8 березня), і заупокійний канон Октоїха, глас 5-ий (з ранньої суботи, без ірмосів). Канон Богородиці не співається, так як замінюється заупокійним. Після канонів – «Достойно є». Після 3-го Трисвятого – кондак, глас 8-ий: «Зі святими упокой...» (замість «Господи Сил...»). «Господи, помилуй» (40), «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Виголос: «Молитвами святих отців наших...». Читець: «Амінь». Молитва: «Непорочна, Пречиста...», «І дай нам, Владико...», «Преславна Приснодіво...», «Уповання моє Отець...». Священник: «Слава Тобі, Христе Боже...». «Слава, і нині». «Господи, помилуй» (тричі). «Благослови». Відпуст малий: «Христос, істинний Бог наш...». Звичайне прощення. Ектенія: «Помолимось...». ПОЛУНОШНИЦЯ звичайна – суботня. РАННЯ починається звичайним порядком (див. 28 лютого). Замість «Бог Господь» – «Алилуя», глас 2-ий, із заупокійними стихами: 1-ий – «Блаженні, ті кого обрав і прийняв Ти, Господи»; 2-й – «Пам’ять про них з роду в рід»; 3-ій – «Душі їх у блаженстві перебуватимуть». Тропар, глас 2-ий: «Апостоли, мученики і пророки...» (двічі). «Слава» – інший тропар, глас той же: «Пом’яни, Господи...», «І нині» – Богородичний, глас той же: «Мати Свята...». Читається 16-та кафизма. Мала ектенія (звичайна, а не заупокійна). Сідальні Октоїха, глас 5-ий (три мученичних: 2-ий, 3-тій. 4-ий, а перший опускається). «Слава, і нині» – Богородичний недільний поточного гласу; «Радуйтесь Двері Господні..». (див. Після 1-ої кафизми). Після сідального читається шестиднев свт. Іоана Золотустого (Типікон, гл. 49). На практиці читання опускають, і відразу (нічого не промовляючи) співаємо (за Уставом, на 5-ий глас) непорочні (17-ту кафизму), розділяючи на дві частини (статті), з приспівом до 1-ої: «Благословен єси, Господи, навчи мене заповітів Твоїх». Перша стаття закінчується 93-м стихом, перед словом: «Середина». Після першої статті не вимовляється: «Слава, і нині», але з приспівом співаються (тричі) заключні 92-ий і 93-ій стихи: «Якби не закон Твій...» і «Навіки не забуду повелінь Твоїх...». Примітка. Щодо закінчення першої і другої статті 17-ої кафизми при заупокійному богослужінні існують такі думки: 1) кожен з двох останніх стихів першої і другої статті співається по тричі з відповідним приспівом; 2) в кожній статті два останніх стиха об’єднуються «як один» і співаються з приспівом тричі. Виголошується мала заупокійна ектенія: «Ще і ще...», хор: «Господи, помилуй» (один раз); «Ще молимося за упокій душ спочилих рабів Божих праотців, отців, і братів наших...», хор: «Господи, помилуй» (один раз); «Щоб Господь Бог оселив душі їхні...», хор: «Господи, помилуй» (один раз); «Милості Божої...», хор: «Подай, Господи». «Господу помолимось». Хор тихо: «Господи, помилуй» (40). Священник таємно читає молитву: «Боже духів...». Виголос: «Бо Ти єси Воскресіння...». Хор: «Амінь». Друга стаття 17-ої кафизми: «Твій – я, спаси мене...» співається з приспівом до кожного стиха: «Спасе, спаси мене». В кінці тричі співаються з приспівом заключні 175-ий і 176-ий стихи: «Нехай живе душа моя...» і «я блукаю, наче ягня загублене...». Далі тропарі після Непорочних, глас 5-ий: «Собор святих...», з приспівом «Благословен єси, Господи, навчи мене заповітів Твоїх». Мала заупокійна ектенія (див. Після 1-ої статті). «Господи, помилуй» (40). Священник таємно читає молитву: «Боже духів...». Після виголосу хор: «Амінь», і сідальний, глас 5-ий: «Упокой, Спасе наш...», «Слава» – кінець цього піснеспіву: «І всі, свідомі і не свідомі, Чоловіколюбче», «І нині» – Богородичний, глас той же: «Христе Боже, що від Діви засяяв...». Псалом 50-ий. (Молитва: «Спаси, Боже, людей Твоїх...» не промовляється). Канони: У храмі Господському і Богородиці – канон храму з ірмосом на 6 (ірмоси раз), канон Мінеї на 4 (свящмч. Херсонеських). Починаючи з 6-ої пісні канон храму пропускається, і співається спочатку канон Мінеї з ірмосом на 6 (ірмоси раз), потім два четверопіснеця Тріоді – на 10. У храмі святого – канон Мінеї з ірмосом на 6 (ірмоси раз), канон храму святого на 4. Починаючи з 6-ої пісні канону храму пропускається, співаються канон Мінеї і четверопісцем так само, як в храмі Господському і Богородиці. Біблійні пісні Ірмологія за великопостовим розділом. Примітка. Початкові стихи пісень Святого Писання, з 1-ої по 5-у, не співаються, а починають читатися тільки після ірмосу і 1-го тропаря, з напису «на 8» (всього на 10). 13 стихів 6-ої і 9-ої біблійних пісень (включаючи «Слава» та «І нині») починають співатися, чергуючись з тропарями канону Мінеї і четвероспівців Тріоді, – після ірмосу канону Мінеї (всього, включаючи ірмос канону Мінеї, на 14, і на закінчення ще 2 додаткових тропаря 2-го четвероспіснеця з особливими приспівами). 7-а і 8-а біблійні пісні читаються від початку до кінця; після стиха з написом «на 14» співається ірмос канону Мінеї і далі тропарі, чергуючись зі стихами (всього, включаючи ірмос Мінеї, на 14, і на закінчення ще 2 додаткових тропаря 2-го четвероспіснеця з особливими приспівами). Катавасія після 3-ої пісні – ірмос 3-ої пісні останнього канону, а після 6-ої, 7-ої, 8-ої і 9-ої – ірмоси другого четверопіснеця. Після 3-ої пісні – мала ектенія (звичайна, а не заупокійна); кондак свящмчч., глас 2-ий: «Коли настав світлоносний день...» сідальний свящмч., глас 3-ій. «Слава, і нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – мала заупокійна ектенія (див. Після 1-ої статті 17-ої кафизми). Кондак, глас 8-ий: «Зі святими упокой...», та ікос, глас той же. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний гласу 4-го. Примітка. Світильний запозичується з додатку Октоїха «Світильний денний на всю седмицю» і береться за рядовим гласом Октоїха (в даному випадку 5-го гласу). Світильний виповнюється двічі (через «Слава, і нині»), перший раз закінчуючись словами: «Молитвами, Господи, святих Твоїх, і спаси мене», а другий – «Молитвами, Господи, Богородиці, і спаси мене». У Світильних 6-го гласу замість закінчення змінюється початок, тому світильні 6-го гласу в суботу виконуються наступним чином: «Молитвами, Господи, святих Твоїх, пошли душам нашим Своє світло присносущне» [або: «Молитвами, Господи, всіх святих, пошли душам нашим Своє світло присносущне», – порівн.: Тріодь Постова]; «Слава, і нині» – Молитвами, Господи, Богородиці, пошли душам нашим Своє світло присносущне». «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Октоїха (мученичні), глас 5-ий – 4. «Слава» – мертвих Октоїха, глас той же: «Ти, що створим мене, Господи...» (див. на хвалитніх...), «І нині» – Богородичний Октоїха, глас той же. «Тобі слава подобає...» не промовляється, але відразу: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. Стихири на стиховні Октоїха, глас 5-ий зі своїми приспівами. «Слава, і нині» – Богородичний Октоїха, глас той же. «Благо є» (один раз). Трисвяте. Після «Отче наш» – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар, глас той же: «Пом’яни, Господи...», «І нині» – Богородичний, глас той же: «Мати Свята...». Після потрійної ектенії «Помилуй нас, Боже...» – Священник: «Премудрість». Хор: «Благослови». Священник: «Сущий благословенний...». Хор: «Амінь». «Утверди, Боже...», і відразу 1-ий час.","sections":[{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропарі: «Апостоли, мученики і пророки...». «Слава» – «Пом’яни, Господи, як благий...». Кондак: «Зі святими упокой...». ЛІТУРГІЯ за чином свт. Іоана Золотоустого. Блаженні гласу – 6. Після входу – тропарі, глас 2-ий: «Апостоли, мученики і пророки...», «Пом’яни, Господи, як благий...». «Слава» – кондак, глас 8-ий: «Зі святими упокой...», «І нині» – Богородичний, глас той же: «Тебе і стіну, і пристанище...». Прокимен – дня (суботи), глас 8-ий: «Веселіться у Господі...», стих: «Блаженні, кому прощено беззаконня...»; і заупокійний, глас 6-ий: «Душі їх у блаженстві перебуватимуть». Апостол і Євангеліє – суботи 2-го тижня і заупокійні. Алилуарій – дня (суботи): «Взивали праведні...», стих: «Багато скорбот у праведних...»; і заупокійний: «Блаженні, ті кого обрав...». Причасний – дня (суботи): «Радуйтеся, праведні...», і заупокійний: «Блаженні, ті кого обрав...»."}]},
{"date":"03-08","weekday":"неділя","title":"Неділя 2-га Великого посту. Глас 6-ий. Свт. Григорія Палами, архієп. Фесалонікійського (перехідне святкування в 2-гу неділю Великого посту). Собор усіх преподобних отців Києво-Печерських (перехідне святкування в 2-гу неділю Великого посту). Прп. Феофілакта, спов., єп. Нікомидійського (842 – 845). Ап. Єрма (І). Сщмч. Феодорита, пресвітера Антіохійського (361 – 363). Прп. Дометія (363). Літургія за чином свт. Василія Великого.","glas":6,"readings":["Ран. – Єв. 6-е, Лк., 114 зач., XXIV, 36 – 53.","Літ. – Євр., 304 зач., I, 10 – II, 3. Мк., 7 зач., II, 1 – 12.","Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16.","Прпп.: Гал., 213 зач., V, 22 – VІ, 2. Лк., 24 зач., VІ, 17 – 23 (під зачало)."],"notes":"Увага! В понеділок буде звершуватися полієлей св. 40 Севастійських мучеників, то потрібно заготовити ще третій Агнець. Недільна служба звершується за Октоїхом, Тріоддю та Мінеєю. Примітка. В період співу Постової Тріоді починаючи від Неділі митаря і фарисея у недільні дні Мінея не використовується окрім пам’яті святих, що мають полієлей або бдіння. Києво-Печерські угодники особливо шануються Українською Православною Церквою, тому недільна службу слід звершувати за Октоїхом, Тріоддю та Мінеєю. За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню. Мала вечірня служиться лише за Октоїхом.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири, глас 6-ий – 4. (перша стихира – двічі (на початку, та в кінці як четверта). «Слава, і нині» – богородичний (догматик малої вечірньої), глас 6-ий: «Достойно є воістину...» Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. Перша стихира недільна, а інші стихири Пресвятої Богородиці зі своїми приспівами. На стиховні стихири глас 6-ий: «Воскресіння Твоє...» із своїми приспівами. «Слава, і нині» – Богородичний, глас то й же: «Прийдіть усі люди...». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар недільний, глас 6-ий «Ангельські сили...» «Слава, і нині» – Богородичний за гласом тропаря: «Благословенною назвавши...». Після співу тропаря з богородичним священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, що воскрес із мертвих, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 6-ий – 3, і Тріоді (свт. Григорія) – 3, преподобних глас той же – 4. «Слава» – Тріоді (свт. Григорія), глас 6-й: «Преподобний, преблаженний...», «І нині» – догматик, глас 6-ий: «Хто тебе не ублажить...». Вхід. Прокимен дня. Паремії преподобних 3. На літії стихира храму. «Слава» преподобних глас 1: «Прийдіть похвалімо вірні» (Стихира на «Слава» із стихир на «Господи взиваю»), і нині» – Богородичний недільний за гласом стихири храму, із стихир на стиховні. На стиховні стихири воскресні, глас 6-ий. «Слава» – Мінеї (Преподобних Печерських), глас 2-ий: «Преподобні отці світу красу...», «І нині» – Тріоді (Стихира на «Славу» Святителя Григорія), глас 8: «Безнесвітна Діво...». Після Трисвятого – «Богородице Діво...» (двічі), преподобних Печерських (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар неділі, глас 6-ий (двічі). «Слава» – тропар Преподобних Печерських, глас 4-ий: «Стовп вогнеподібний...», «І нині» – Богородичний недільний, глас той же: «Від початку віку утаємнене...» Кафизми 2-га і 3-тя. Малі ектенії. Сідальні недільні. Читання Шестидневу (див. Постова Тріодь). Полієлей. Величання преподобних: «Величаємо вас,/ преподобні отці наші Печерські,/ і шануємо святу пам’ять вашу,/ бо ви молите за нас// Христа Бога нашого» (таке величання подає Мінея) і псалом вибраний: «Терплячи потерпів перед Господом, але смерті не віддав мене». «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє недільне 5-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – Тріоді, глас 8-ий: «Покаяння відкрий мені двері...», «І нині» – Богородичний Тріоді, глас той же: «На стежки спасіння...». Глас 6-й: «Помилуй мене, Боже...», і стихира Тріоді, глас той же: «Множество вчинених...». Примітка. Якщо храм в честь Собору Преподобних Печерських: то прокимен та Євангеліє – преподобних. Після 50 псалма «Слава» – молитвами препобоних... «Покаяння двері...» опускається. Канони: неділі з ірмосом на 4 (ірмоси раз), Богородиці (Октоїха) на 2 Тріоді – 1-ий (про блудного сина другої неділі Великого посту) на 2 і 2-й (свт. Григорія) на 2, і преподобних Печерських 4. Біблійні пісні «Співаймо Господеві...». Примітка. На практиці на Недільних Всенічних використовуються на каноні не Біблійні пісні, а так звані молебні заспіви, наприклад: «Слава Господи святому Воскресінню Твоєму» – до канону неділі, «Пресвята Богородице спаси нас» – до Богородичного, Тріоді – «Помилуй мене Боже, помилуй мене», «Святителю отче Григорію моли Бога за нас», Мінеї – «Преподобні отці наші Києво-Печерські моліть Бога за нас» і тд. Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак і ікос преподобних, сідальний преподобних, кондак Тріоді, глас 4-й: «Нині час подвигу настав...»;. «Слава» – сідальний Тріоді (свт. Григорія), глас той же: «Оману нечестивих спалив ти...», «І нині» – Богородичний Тріоді, глас той же: «Скоро прийми, Владичице, моління наші...». Після 6-ої пісні – кондак Тріоді (свт. Григорія), глас 8-ий: «Тебе священний...». Ікос, глас той же: «Ангелом невимовно явився ти...». Читаємо синаксар. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 6-ий. «Слава» – світильний: «Тріоді (свт. Григорія): «Радуйся, отців похвало...», «І нині» – Богородичний Тріоді: «Владичице всіх, вища від усіх, Владичице,/ що перевершуєш усі воїнства небесні,/ простягни державну руку, і збережи світ / священиків, що Тобі священнодіють благослови,/ ченців і мирян, молимось до Тебе./ Всіх людей, що помирають, і в бідах перебувають:/ воїнство укріпи під час бою:/ місто наше збережи, свята Богородице./ І нині нас сподоби бачити Небесне Царство, і райські двері,/ коли сяде Суддя судити вселенну/ під час другого пришестя і страшного суду, Владичице ангелів». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири недільні, на 8 глас 6-ий – 3 (дві стихири недільні і Анатолієва одна), і Тріоді (свт. Григорія), глас 1-ий – 2; потім стих: «Воскресни, Господи Боже мій...», і самогласний Тріоді, глас 6-й: «Тим, що в темряві гріхів, ходять...» і преподобних Печерських глас 1-ий, подібний «Прехвальні мученики». «Слава» преподобних глас 8-ий: «Преподобні отці...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар недільний: «Воскрес із гробу...». Перед 1-им часом на «Слава, і нині» – стихира євангельська 6-та. НА 1-МУ і 6-МУ ЧАСІ – тропар недільний гласу. «Слава» – тропар Тріоді (свт. Григорія). Кондак Тріоді, глас 4-ий: «Нині час подвигу настав...». НА 3-МУ і 9-МУ ЧАСІ – тропар недільний гласу. «Слава» – тропар Мінеї (Преподобних Печерських). Кондак Тріоді (свт. Григорія), глас 8-й. ЛІТУРГІЯ за чином свт. Василія Великого. На проскомидії заготовлюються три Агнця – для понеділка, середи і п’ятниці. Примітка. Якщо літургія Ранішосвячених Дарів протягом тижня звершується і в інші дні окрім середи і п’ятниці, то заготовлюється відповідна кількість агнців. Блаженні на 10: гласу – 3, Тріоді (свт. Григорія), пісня 3-тя – 3, Мінеї (Преподобних) – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар недільний гласу, тропар Тріоді (свт. Григорія), тропар преподобних глас 4-ий: «Стовп вогнеподібний...». Кондак недільний, кондак Тріоді (свт. Григорія), «Слава» – кондак Преподобних, глас 8-ий: «І нині» – кондак Тріоді, глас 4-ий: «Нині час подвигу настав...». У храмі Богородиці – тропар недільний гласу, тропар храму, тропар преподобних глас 4-ий, тропар Тріоді (свт. Григорія); кондак недільний, кондак Тріоді, глас 4-й: «Нині час подвигу настав...», кондак Тріоді (свт. Григорія). «Слава» – кондак Преподобних, глас 8: «Отці всечесні...» «І нині» – кондак храму. У храмі святого – тропар недільний, тропар храму, тропар преподобних, тропар Тріоді (свт. Григорія); кондак храму, кондак Тріоді (свт. Григорія) «Слава» – кондак Преподобних, «І нині» – кондак Тріоді, глас 4-й: «Нині час подвигу настав...». Прокимен – Неділі 2-ої Великого посту (глас 5-ий: «Ти, Господи, збережеш нас...»; стих: «Спаси мене, Господи...»), і свт. Григорія (глас 1-ий: «Уста мої промовлятимуть премудрість...»). Алилуарій – неділі рядового гласу і святителя. Апостол і Євангеліє – Неділі 2-ої Великого посту, свт. Григорія та Преподобних Києво-Печерських Примітка. Апостол і Євангеліє святителю Григорію і преподобним Києво-Печерським читаються як одне, під зачало. Замість «Достойно є» – «Тобою радується...». Причасний – недільний: «Хваліте Господа з Небес...», і Преподобних: «Радуйтеся праведні...». Примітка. «На трапезі ж їмо, те саме чим в 1-у Неділю задовольнялися, на славу Божу» (Типікон, гл. 49, «Неділя 2-га святого посту»)."}]},
{"date":"03-09","weekday":"понеділок","title":"3-й тиждень Великого посту. 40 мчч., що в Севастійському озері мучилися: Кіріона, Кандида, Домна, Ісихія, Іраклія, Смарагда, Євноїка, Валента, Вивіана, Клавдія, Пріска, Феодула, Євтихія, Іоана, Ксанфія, Іліана, Сисинія, Ангія, Аетія, Флавія, Акакія, Екдикія (Екдита), Лісимаха, Олександра, Ілія, Горгонія, Феофіла, Дометіана, Гая, Леонтія, Афанасія, Кирила, Сакердона, Миколая, Валерія, Філоктимона, Северіана, Худіона, Мелітона і Аглаїя (бл. 320). Мч. Урпасіана (бл. 295). Св. Кесарія, брата свт. Григорія Богослова (бл. 369). Прав. Тарасія Лікаонійського. Звершується полієлейна служба 40 Севастійських мучеників з великопісною службою третього тижня Великого посту.","readings":["На ранній – Мф., 44 зач., I, 39 – 49, 56."],"notes":"На 6-му часі: Іс. VIII, 13 – IX, 7. На веч.: Бут. VI, 9 – 22. Притч. VIII, 1 – 21. Прп. – Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ після закінчення 9-го часу, священник виголошує: «Благословен Бог наш...» Читець. Амінь «Прийдіть поклонімось...» і читає 103-ій псалом. Велика ектенія і співається «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 10: Тріоді, глас 4-ий і глас 6-ий – 4, мучеників, глас 2-ий – 6 (перших дві стихири – двічі). «Слава» мучеників, глас 2: «Терплячи теперішнє...», «І нині» – Догматик глас той же «Коли минула тінь...». Вхід з кадилом. «Світло Тихе». Співається великий прокимен, глас 8-ий: «Не відверни лиця Твого...», зі стихами (за звичаєм). Паремії Мучеників – 3. Після паремій читається «Сподоби Господи..» і благальна ектенія На стиховні стихири Тріоді, глас 8-ий. «Слава» – мучеників, глас 6-ий: «В піснях прославимо», «І нині» – Богородичний Мінеї: «Ти істинна виноградна лоза...». «Нині відпускаєш...». Трисвяте по Отче наш. Після виголосу тропар мучеників, глас 1-ий: «Болістями святих...», «Слава» – інший тропар мучеників глас 1-ий: «Страстотерпці всечесні...», «І нині» – Богородичний «Коли Гавриїл звістив...». Потрійна ектенія. Після виголосу: «Бо Ти Милостивий...» – виголос: «Премудрість», хор: «Благослови», священник: «Сущий благословенний...». Читець молитву: «Небесний Царю...». Священник промовляє молитву прп. Єфрема Сиріна читається із трьома великими поклонами (без малих). Після третього поклону священник – «Слава, Тобі Христе Боже...» і відпуст. Заупокійна літія не звершується."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в неділю ввечері в 2-гу Неділю Великого посту, напередодні понеділка 3-го тижня, співається служба апп. Іродіона, Агава (з 8 квітня). Примітка. Канон Богородиці на повечір’ї в неділю ввечері не співається, оскільки напередодні звершувалося всенічне бдіння. Після Трисвятого – кондак мучеників, глас 6-ий. Замість виголосу: «Молитвами святих отців наших...» виголошується «Боже, змилосердься над нами...» і молитва прп. Єфрема Сиріна із трьома великими поклонами. Кінцеве Трисвяте не читається, а одразу після третього покліну – молитва: «Нескверна...» після чого звершується малий відпуст та прощення з ектенією: «Помолимось..» наприкінці ектенії, виголос: «Молитвами святих отців наших...». Хор: «Амінь»."},{"svc":"ПОЛУНОШНИЦІ","text":"НА ПОЛУНОШНИЦІ кафизма 17-та, звичайні повсякденні тропарі та молитва прп. Єфрема Сиріна із трьома великими поклонами."},{"svc":"РАННІЙ","text":"НА РАННІЙ після виголосу: «Благословен Бог наш...» читець: «Прийдіть поклонімось...» і 19 та 20 псалми. Священик звершує повне кадіння храму. На «Бог Господь» – тропар мучеників, глас1-ий: «Болістями святих..» (двічі) «Слава і нині» – Богородичний воскресний, глас то й же: «Гавриїл звістив...». Кафизми 4-та, 5-та і 6-та. Після першої кафизми – малої ектенії немає. Сідальний Тріоді, глас 8-ий: «Вогнем стримання...» (див. в Тріоді після 2-ої кафизми). Після другої кафизми – малої ектенії немає. Сідальний Тріоді, глас 8-ий: «Тройце свята...» (див в Тріоді, після 3-ьої кафизми). Після третьої кафизми – мала ектенія і сідальні мучеників глас 4-ий: «Мучеників твердь...» Полієлей. Величання мучеників і вибраний псалом. Сідальний мучеників після полієлею, глас 5-ий: «Святих мучеників похвала..». Степений – 1 антифон 4-го гласу: «Від юності моєї...» Прокимен мучеників, глас 4-ий: «Пройшли крізь вогонь і воду, і вивів нас у спокій»; стих: «Ти розпалив нас, як розпалюється срібло». Євангеліє від Луки, зач. 106-те. Після 50-го псалма: «Слава» – молитвами святих мучеників і стихира мучеників, глас 2-ий: «Як пророк Давид взиває...». Ектенія «Спаси Боже, людей Твоїх..», «Господи, помилуй» – 12 разів. Священник: «Милістю і милосердям...». Канони: 1-ша, 8-ма і 9-та пісні – мучеників (два канони) із ірмосом на 6 (ірмоси 1-го канону по двічі) і трипіснеці Тріоді на 8; 3-тя, 4-та, 5-та, 6-та і 7-ма пісні – мучеників (один канони) із ірмосом на 8 (ірмос 1-го канону по двічі). Біблійні пісні у святковій редакції: «Співаємо Господеві..» Катавасія після 1-шої, 8-ої і 9-ої пісень – ірмос 2-го трипіснеця Тріоді, глас 7-ий: «Співаємо Господу...». Після 3-ьої, 4-ої, 5-ої, 6-ої і 7-ої пісень – «Відкрию уста мої...» Після 3-ої пісні – сідальний мучеників, глас 8-ий: «Стали воїнами» (двічі). «Слава і нині» – Богородичний Мінеї. Після 6-ої пісні – кондак мучеників, глас 6-ий: «Все воїнство земне залишили...» та ікос. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний мучеників. «Слава» – інший світильний мучеників. «І нині» – Богородичний Мінеї: «Владику всього творіння...» «Хваліте Господа з небес...» і хвалитні псалми. На хвалітних стихири мучеників-, глас 5-ий – 4 (перша стихира двічі) «Слава» – мучеників, глас то й же. «І нині» – Богородиці: «Ублажаємо Тебе...». Читець: «Слава Тобі, що показав нам світло (Тобі слава належить не читається)» і читає повсякденне славослів’я. Ектенія: «Доповнимо ранню молитву нашу Господу». На стиховні стихири Тріоді, глас 4-ий (зі звичайними приспівами). «Слава» – мучеників, глас 2-ий: «Чашею істини». «І нині» – Богородичний Мінеї: «Непрохідні врата..». «Благо є» (один раз). Трисвяте по «Отче наш» – тропар мучеників, глас 1-ий. «Слава» – інший тропар мучеників, глас то й же, «І нині» – Богородичний: «Гавриїл звістив...». Потрійна ектенія. Після виголосу: «Бо Ти Милостивий...» – виголос: «Премудрість», хор: «Благослови», священник: «Сущий благословенний...». Читець молитву: «Небесний Царю...». Священник промовляє молитву прп. Єфрема Сиріна із трьома великими поклонами (без малих). Читець: «Амінь», без відпусту ранньої одразу починають читати 1-ий час. НА 1-МУ ЧАСІ – кафизми немає. Тропар мучеників (перший). Стихи часу: «Стопи мої направ..» і «Нехай наповняться..» – читаються. Після «Отче наш» – кондак мучеників. Після виголосу: «Боже змилосердься над нами..» – молитва прп. Єфрема Сиріна (з трьома великими поклонами). Кінцеве Трисвяте не читається. Після поклонів священик читає молитву: «Христе, Світло істинне..». Хор співає «Непереможній Воєводі». Священник: «Слава Тобі, Христе Боже...» і чинить великий відпуст ранньої. Хор співає Многоліття. Заупокійної літії немає. Примітка. Коли співається полієлей, на часах дзвонами не дзвонимо. НА 3-МУ ЧАСІ – кафизма 7-ма; НА 6-МУ ЧАСІ – кафизма 8-ма; тропар пророцтва (Тріоді), 1-ий прокимен Тріоді, паремія Тріоді, 2-ий прокимен Тріоді. НА 9-МУ ЧАСІ – кафизма 9-та. На 3-му, 6-му і 9 часах – тропарі мучеників поперемінно (в Мінеї їх є два), після «Отче наш» – кондак мучеників та молитва прп. Єфрема Сиріна із трьома поклонами."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ блаженні читаємо без співу. Кондаки: В храмі Господському – кондак храму «Слава і нині» – кондак мучеників; В храмі Богородиці – кондак мучеників «Слава, і нині» – кондак храму; В храмі святого – кондак храму «Слава» – кондак мучеників, «І нині» – «Заступництво християн». Читець: «Господи, помилуй» 40 раз. «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім ...». Священник (перед царськими вратами): «Боже, змилосердься над ми...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна з 3 поклонами. Молитва: «Всесвята Тройце ...». Священник на солії при закритих царських вратах звершує відпуст наступним чином. Священник (або диякон): «Премудрість». Хор: «Достойно є ...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів ...». Священник: «Слава Тобі, Христе Боже ...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник виголошує відпуст: «Христос, істинний Бог наш ...». Хор – «Господи, помилуй» (тричі). Многоліття, за традицією, не співаються. Священник повертається у вівтар."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ з літургією Ранішосвячених Дарів. Кафизма – 18 та. На «Господи, взиваю» стихири на 10, Тріоді, глас 1-ий і глас 3-ій – 6 (самогласний дня, глас 3-ій і мученичний глас 2-ий, стихира прп. Феодора, глас 8-ий, див. стихири «Господи взиваю»), і стихири мучеників на 4 (див. стихири на «Господи взиваю» самого свята мучеників). «Слава, і нині» – Богородичний Мінеї, глас той же: «Все уповання моє...». Примітка. Стихири вечірньої з «Господи взиваю» мчч. Кодрата та з ним Кипріана, Діонісія будуть співатися на хвалітних ранньої наступного дня. Вхід з Євангелієм. «Світло Тихе». Прокимни читання паремій Тріоді Після молитви прп. Єфрема Сиріна, одразу диякон виголошує: «Будьмо уважні». Священник: «Мир усім». Читець: «І духові твоєму». Диякон: «Премудрість» і співають прокимен мучеників, глас 5-ий: «Ти Господи збережеш нас..» (зі стихом) далі читається Апостол, Алилуарій та Євангеліє – мучеників. Після прочитання Євангелія продовжується літургія Ранішосвячених Дарів. Причасний – «Вкусіть і побачите» та мучеників: «Радуйтесь праведні в Господі...»."}]},
{"date":"03-10","weekday":"вівторок","title":"Мчч. Кодрата та з ним Кипріана, Діонісія, Анекта, Павла, Крискента, Діонісія (іншого), Вікторина, Віктора, Никифора, Клавдія, Діодора, Серафіона, Папія, Леоніда і мцц. Харієси, Нунехії, Василіси, Ніки, Галі, Галини, Феодори та інших багатьох (бл. 258). Мчч. Кодрата Нікомидійського, Саторина, Руфина та інших (ІІІ). Прп. Анастасії (567 – 568).","notes":"На 6-му часі: Іс. IX, 9 – X, 4. На веч.: Бут. VII, 1 – 5. Притч. VIII, 32 – IX, 11.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у понеділок ввечері – канон Богородиці і мч. Євпсихія з 9 квітня. Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 6-ий з приспівами вівторка. Кафизми 10-та, 11-та, 12-та. Після першої кафизми – сідальні Октоїха (без мученичного). Після 2-гої і 3-ьої – сідальні Тріоді. Псалом 50-ий. Ектенія «Спаси Боже людей Твоїх..» Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 2 пісня тільки з Тріоді на 8. 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 2-га, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 4-ий: «Терпінням страждань...» «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – Мученичий Октоїха (кондак рядових святих відсутній): «Подвиг страстотерпців...» (див. сідальний Октоїх після другої кафизми у вівторок на ранній 6-го гласу). На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні. Хвалитні псалми і співаються стихири мч. Кодрата (з «Господи взиваю..»), глас 1-ий – 4. (перша стихира двічі). «Слава, і нині» – богородичний Мінеї: «Охоплений безнадійними гріхами...». Примітка. Після стихир «на хваліте» «Тобі слава подобає...» не читається, а одразу читець «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 7-ий: «Згрішив, сповідуюсь Тобі..» «Слава і нині» – Богородичний Тріоді: «Народився Ти від Діви...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 13-та. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 14-та. На 6-му – кафизма 15-та. Прокимни та паремія Тріоді. На 9-му – кафизма 16-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Примітка. Оскільки в службі рядових святих Мінеї кондак мучеників відсутній, то на зображальних він не читається, його не варто замінювати загальним кондаком чи мученичним із Октоїха. Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у вівторок увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 3-ій – 3, Мінеї – святителя, глас 4-ий – 3 (з 11 березня). «Слава, і нині» – Хрестобогородичний Мінеї: «Коли побачилаТебе на Хресті...». Входу немає. Прокимни, Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 2-ий. «Слава, і нині» – Хрестобогородичний Тріоді, глас то й же: «Коли Тебе Спасе...». Закінчення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-11","weekday":"середа","title":"Свт. Софронія, патр. Єрусалимського (639). Прп. Софронія, затворника Києво-Печерського, в Дальніх печерах (ХІІІ). Сщмч. Піонія, пресвітера Смирнського, та інших з ним (250). Перенесення мощів мч. Епимаха. Свт. Софронія, єп. Врачанського (1813, Болг.). Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. X, 12 – 20. На веч.: Бут. VII, 6 – 9. Притч. IX, 12 – 18.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у вівторок ввечері – канон Богородиці і служба мчч. Терентія, Помпія (з 10 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 6-ий з приспівами середи. Кафизми 19-та, 20-та і 1-ша. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. 50 Псалом. Ектенія «Спаси Боже..» Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 3-тя, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 3-тя, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 4-ий: «Словами ти прикрасив Церкву Христову...», «Слава, і нині» – Хрестобогородичний Мінеї, глас то й же: «Коли побачила Тебе Пречиста...». Після 6-тої – Кондак святителя, глас 8-ий: «Ти був спонуканий...». На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні (Октоїха). Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 2-ий: «Будучи в синівській шані..». «Слава і нині» – Хрестобогородичний Тріоді: «Многі болісті перетерпіла Ти...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 2-га. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 3-тя. На 6-му – кафизма 4-та. Прокимни та паремія Тріоді. На 9-му – кафизма 5-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак дня, кондак святителя. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, кондак святителя. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Твориться відпуст зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у середу увечері) – кафизма 18-та. «Господи взиваю» – стихири на 10: Тріоді, глас 4-ий і глас 6-ий – 6 (самогласна стихира двічі), Мінеї – святителя Григорія, глас 6-ий – 4 (з 12 березня). «Слава» – святителя, глас 3-ій: «Прийнявши від Христа кермо», «І нині» – Богородичний Мінеї: «Прийми молитви рабів твоїх...». Вхід з кадилом. «Світе Тихий». Прокимни, Паремії Тріоді – 2. Далі продовження Літургії Ранішосвячених Дарів. Детальний виклад порядку вечірні в поєднанні з Літургією Ранішосвячених Дарів див. 25 лютого. Після Літургії заупокійної літії немає."}]},
{"date":"03-12","weekday":"четвер","title":"Прп. Феофана, спов., Сигріанського (818). Прав. Фінеєса (бл. 1500 р. до Р. Х.). Свт. Григорія Двоєслова, папи Римського (604). Прп. Симеона Нового Богослова (1021). Ліддської [нерукотворної] (в Лідді на стовпі) ікони Божої Матері (І).","notes":"На 6-му часі: Іс. XI, 10 – XII, 2. На веч.: Бут. VII, 11 – VIII, 3. Притч. X, 1 – 22.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у середу ввечері – канон Богородиці і свящмч. Антипи (з 11 квітня) та прп. Симеона, нового Богослова (з 12 березня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 6-ий з приспівами четверга. Кафизми 6-та, 7-ма, 8-ма. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. 50 псалом. Ектенія «Спаси Боже...» Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 4-та, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 4-та, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 5-ий: «Повсякчас славного святителя..» «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – кондак святителя, глас 3-тій: «Подобоначальником і пастероначальником...» та ікос. На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Октоїха. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 6-ий: «Блудний я...» «Слава і нині» – Богородичний Тріоді: «Богородице, Ти єси виноградна лоза...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 9-та. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 10-та. На 6-му – кафизма 11-та. Прокимни та паремія Тріоді. На 9-му – кафизма 12-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня, інший кондак дня, кондак святителя. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, інший кондак дня, кондак святителя. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, інший кондак дня, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн...». Примітка. Якщо денний кондак співпадає з кондаком храму, то він читається лише один раз. Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у четвер увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 5-ий, і глас 1-ий – 3, Мінеї – святителя Никифора, глас 1-ий – 3 (з 13 березня). «Слава, і нині» – Хрестобогородичний Мінеї: «Коли бачила Тебе Агниця...». Входу немає. Прокимни і паремії Тріоді – 2. На стиховні стихири Тріоді, глас 6-тий. «Слава, і нині» – Хрестобогородичний Тріоді, глас то й же: «Бачачи Тебе Христе...». Закінчення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-13","weekday":"п’ятниця","title":"Перенесення мощів свт. Никифора, патр. Константинопольського (846). Мч. Савина (287). Мчч. Африкана, Публія і Терентія (ІІІ). Мч. Олександра (305 – 311). Мц. Христини Перської (ІV). Прп. Аніна Халкідонського, пресвітера. Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. XIII, 2 – 13. На веч.: Бут. VIII, 4 – 21. Притч. X, 31 – XI, 12.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї в четвер увечері – канон Богородиці і служба прп. Василія, сповідника (з 12 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 6-ий з приспівами п’ятниці. Кафизми 13-та, 14-та і 15-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. 50 псалом. Ектенія «Спаси Боже...» Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 4-та, 6-та, 7-ма пісні: Мінеї на 4. 5-та, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія –5-та, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 3-ій: «Перемогами вінчав ти Церкву..» «Слава, і нині» – Хрестобогородичний Мінеї, глас то й же: «Нескверна Агниця...». Після 6-тої – кондак мучеників, глас 6-ий: «Зібрання патріархів...». На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Октоїха. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 8-ий: «Багатство батьківського дару..» «Слава і нині» – Хрестобогородичний Тріоді: «Пречиста, коли побачила Тебе...». Далі великопостове закінчення ранньої. На 1-му часі – кафизми немає. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 19-тя. На 6-му – кафизма 20-та. Прокимни та паремія Тріоді. На 9-му – кафизми немає."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак дня, кондак святителя. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, кондак святителя. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Твориться відпуст зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у п’ятницю увечері) – кафизма 18-та. «Господи взиваю» – стихири на 10: Тріоді, глас 4-ий – 6 (самогласна стихира двічі): «Як блудний відступив я...», і мученичні Октоїха, глас 6-ий, Мінеї – преподобного Венедикта, глас, 2-ий – 4 (з 14 березня), перша стихира преподобного співається двічі. «Слава» – померлим, 6-го гласу: «Початком моїм і складом було Твоє творче повеління: бо Ти благозволив сотворити мене живим із невидимого і видимого єства, із землі тіло сотворив, душу ж мені дав Твоїм божественним і Животворчим подихом; тому Спасе, рабів Твоїх упокой у країні живих і в оселях праведних». «І нині» – догматик: «Хто Тебе не ублажить..». Вхід з кадилом. «Світе Тихий. Читання паремій Тріоді (прокимен 1-ий паремії, глас 4-ий: «Пошли нам поміч...», зі стихом; прокимен 2-ий паремії, глас 6-ий: «Боже, почуй молитву мою...», зі стихом). «Нехай вознесеться молитва моя...», Далі продовження Літургії Ранішосвячених Дарів. Детальний виклад порядку вечірні в поєднанні з Літургією Ранішосвячених Дарів див. 25 лютого. Після Літургії заупокійної літії немає."}]},
{"date":"03-14","weekday":"субота","title":"Прп. Венедикта (543). Свт. Феогноста, митр. Київського і всієї Руси (1353). Блгв. вел. кн. Київського Ростислава, у хрещенні Михаїла (1167). Свт. Євсхимона, спов., єп. Лампсакійського (ІХ). Ікони Божої Матері «Споручниця грішних». Поминання померлих. Літургія свт. Іоана Золотоустого.","readings":["Заупокійне: 1 Сол., 270 зач., IV, 13 – 17. Ін., 16 зач., V, 24 – 30.","Ряд.: Євр., 325 зач., X, 32 – 38. Мк., 8 зач., II, 14 – 17."],"notes":"Цієї суботи і в наступну заупокійна служба з Тріоді з’єднується зі службами Мінеї та Октоїха. ВЕЛИКЕ ПОВЕЧІР’Я (без поклонів): Після 1-го Трисвятого – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар глас той же: «Пом’яни, Господи...», «І нині» – Богородичний, глас той же: «Мати Свята...». Після 2-го Трисвятого – тропарі Часослова (звичайні), глас 6-ий: «Помилуй нас, Господи...». Після «Слава в вишніх...» – співається служба Мч. Агапія та з ним семи мчч.: Публія, Тимолая, Ромила, двох Олександрів та двох Діонісіїв (з 15 березня), і заупокійний канон Октоїха, глас 6-ий (з ранньої суботи, без ірмосів). Канон Богородиці не співається, так як замінюється заупокійним. Після канонів – «Достойно є». Після 3-го Трисвятого – кондак, глас 8-ий: «Зі святими упокой...» (замість «Господи Сил...»). «Господи, помилуй» (40), «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Виголос: «Молитвами святих отців наших...». Читець: «Амінь». Молитва: «Непорочна, Пречиста...», «І дай нам, Владико...», «Преславна Приснодіво...», «Уповання моє Отець...». Священник: «Слава Тобі, Христе Боже...». «Слава, і нині». «Господи, помилуй» (тричі). «Благослови». Відпуст малий: «Христос, істинний Бог наш...». Звичайне прощення. Ектенія: «Помолимось...». ПОЛУНОШНИЦЯ звичайна – суботня. РАННЯ починається звичайним порядком (див. 28 лютого). Замість «Бог Господь» – «Алилуя»», глас 2-ий, із заупокійними стихами: 1-ий – «Блаженні, ті кого обрав і прийняв Ти, Господи»; 2-й – «Пам’ять про них з роду в рід»; 3-ій – «Душі їх у блаженстві перебуватимуть». Тропар, глас 2-ий: «Апостоли, мученики і пророки...» (двічі). «Слава» – інший тропар, глас той же: «Пом’яни, Господи...», «І нині» – Богородичний, глас той же: «Мати Свята...». Читається 16-та кафизма. Мала ектенія (звичайна, а не заупокійна). Сідальні Октоїха, глас 6-ий мученичні «Слава, і нині» – Богородичний поточного гласу; «Ти що назвав Твою Матір благословенною..». (див. Після 1-ої кафизми). Після сідального читається шестиднев свт. Іоана Золотустого (Типікон, гл. 49). На практиці читання опускають, і відразу (нічого не промовляючи) співаємо (за Уставом, на 5-ий глас) непорочні (17-ту кафизму), розділяючи на дві частини (статті), з приспівом до 1-ої: «Благословен єси, Господи, навчи мене заповітів Твоїх». Перша стаття закінчується 93-м стихом, перед словом: «Середина». Після першої статті не вимовляється: «Слава, і нині», але з приспівом співаються (тричі) заключні 92-ий і 93-ій стихи: «Якби не закон Твій...» і «Навіки не забуду повелінь Твоїх...». Примітка. Щодо закінчення першої і другої статті 17-ої кафизми при заупокійному богослужінні існують такі думки: 1) кожен з двох останніх стихів першої і другої статті співається по тричі з відповідним приспівом; 2) в кожній статті два останніх стиха об’єднуються «як один» і співаються з приспівом тричі. Виголошується мала заупокійна ектенія: «Ще і ще...», хор: «Господи, помилуй» (один раз); «Ще молимося за упокій душ спочилих рабів Божих праотців, отців, і братів наших...», хор: «Господи, помилуй» (один раз); «Щоб Господь Бог оселив душі їхні...», хор: «Господи, помилуй» (один раз); «Милості Божої...», хор: «Подай, Господи». «Господу помолимось». Хор тихо: «Господи, помилуй» (40). Священник таємно читає молитву: «Боже духів...». Виголос: «Бо Ти єси Воскресіння...». Хор: «Амінь». Друга стаття 17-ої кафизми: «Твій – я, спаси мене...» співається з приспівом до кожного стиха: «Спасе, спаси мене». В кінці тричі співаються з приспівом заключні 175-ий і 176-ий стихи: «Нехай живе душа моя...» і «я блукаю, наче ягня загублене...». Далі тропарі після Непорочних, глас 5-ий: «Собор святих...», з приспівом «Благословен єси, Господи, навчи мене заповітів Твоїх». Мала заупокійна ектенія (див. Після 1-ої статті). «Господи, помилуй» (40). Священник таємно читає молитву: «Боже духів...». Після виголосу хор: «Амінь», і сідальний, глас 5-ий: «Упокой, Спасе наш...», «Слава» – кінець цього піснеспіву: «І всі, свідомі і не свідомі, Людинолюбче», «І нині» – Богородичний, глас той же: «Христе Боже, що від Діви засяяв...». Псалом 50-ий. (Молитва: «Спаси, Боже, людей Твоїх...» не промовляється). Канони: У храмі Господському і Богородиці – канон храму з ірмосом на 6 (ірмоси раз), канон Мінеї на 4 (преподобного Венедикта). Починаючи з 6-ої пісні канон храму пропускається, і співається спочатку канон Мінеї з ірмосом на 6 (ірмоси раз), потім два четверопіснеця Тріоді – на 10. У храмі святого – канон Мінеї з ірмосом на 6 (ірмоси раз), канон храму святого на 4. Починаючи з 6-ої пісні канону храму пропускається, співаються канон Мінеї і четверопісцем так само, як в храмі Господському і Богородиці. Біблійні пісні Ірмологія за великопостовим розділом. Примітка. Початкові стихи пісень Святого Писання, з 1-ої по 5-у, не співаються, а починають читатися тільки після ірмосу і 1-го тропаря, з напису «на 8» (всього на 10). 13 стихів 6-ої і 9-ої біблійних пісень (включаючи «Слава» та «І нині») починають співатися, чергуючись з тропарями канону Мінеї і четвероспівців Тріоді, – після ірмосу канону Мінеї (всього, включаючи ірмос канону Мінеї, на 14, і на закінчення ще 2 додаткових тропаря 2-го четвероспіснеця з особливими приспівами). 7-а і 8-а біблійні пісні читаються від початку до кінця; після стиха з написом «на 14» співається ірмос канону Мінеї і далі тропарі, чергуючись зі стихами (всього, включаючи ірмос Мінеї, на 14, і на закінчення ще 2 додаткових тропаря 2-го четвероспіснеця з особливими приспівами). Катавасія після 3-ої пісні – ірмос 3-ої пісні останнього канону, а після 6-ої, 7-ої, 8-ої і 9-ої – ірмоси другого четверопіснеця. Після 3-ої пісні – мала ектенія (звичайна, а не заупокійна); кондак преподобного, глас 6-ий: «Благодаттю Божою...» сідальний прп., глас 1-ий. «Слава, і нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – мала заупокійна ектенія (див. Після 1-ої статті 17-ої кафизми). Кондак, глас 8-ий: «Зі святими упокой...», та ікос, глас той же. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний гласу 6-го. Примітка. У Світильних 6-го гласу замість закінчення змінюється початок, тому світильні 6-го гласу в суботу виконуються наступним чином: «Молитвами, Господи, святих Твоїх, пошли душам нашим Своє світло присносущне» [або: «Молитвами, Господи, всіх святих, пошли душам нашим Своє світло присносущне», – порівн.: Тріодь Постова]; «Слава, і нині» – Молитвами, Господи, Богородиці, пошли душам нашим Своє світло присносущне». «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Октоїха (мученичні), глас 6-ий – 4. «Слава» – мертвих Октоїха, глас той же: «Хворобою стало...» (див. на хвалитніх...), «І нині» – Богородичний Октоїха, глас той же. «Тобі слава подобає...» не промовляється, але відразу: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. Стихири на стиховні Октоїха, глас 6-ий зі своїми приспівами. «Слава, і нині» – Богородичний Октоїха, глас той же. «Благо є» (один раз). Трисвяте. Після «Отче наш» – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар, глас той же: «Пом’яни, Господи...», «І нині» – Богородичний, глас той же: «Мати Свята...». Після потрійної ектенії «Помилуй нас, Боже...» – Священник: «Премудрість». Хор: «Благослови». Священник: «Сущий благословенний...». Хор: «Амінь». «Утверди, Боже...», і відразу 1-ий час.","sections":[{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропарі: «Апостоли, мученики і пророки...». «Слава» – «Пом’яни, Господи, як благий...». Кондак: «Зі святими упокой...». ЛІТУРГІЯ за чином свт. Іоана Золотоустого. Блаженні гласу – 6. Після входу – тропарі, глас 2-ий: «Апостоли, мученики і пророки...», «Пом’яни, Господи, як благий...». «Слава» – кондак, глас 8-ий: «Зі святими упокой...», «І нині» – Богородичний, глас той же: «Тебе і стіну, і пристанище...». Прокимен – дня (суботи), глас 8-ий: «Веселіться у Господі...», стих: «Блаженні, кому прощено беззаконня...»; і заупокійний, глас 6-ий: «Душі їх у блаженстві перебуватимуть». Апостол і Євангеліє – суботи 2-го тижня і заупокійні. Алилуарій – дня (суботи): «Взивали праведні...», стих: «Багато скорбот у праведних...»; і заупокійний: «Блаженні, ті кого обрав...». Причасний – дня (суботи): «Радуйтеся, праведні...», і заупокійний: «Блаженні, ті кого обрав...»."}]},
{"date":"03-15","weekday":"неділя","title":"Неділя 3-тя Великого посту, хрестопоклонна. Глас 7-ий. Мч. Агапія та з ним семи мчч.: Публія, Тимолая, Ромила, двох Олександрів та двох Діонісіїв (303). Сщмч. Олександра, пресвітера в Сиді (270 – 275). Мч. Никандра (бл. 302). Літургія за чином свт. Василія Великого.","glas":7,"readings":["Ран. – Єв. 7-е, Ін., 63 зач., XX, 1 – 10.","Літ. – Євр., 311 зач., IV, 14 – V, 6. Мк., 37 зач., VIII, 34 – IX, 1."],"notes":"Недільна служба Октоїха звершується разом зі службою Тріоді. За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню. Мала вечірня служиться лише за Тріоддю.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири Тріоді, глас 6-ий – 4. (перша стихира – двічі (на початку, та в кінці як четверта). «Слава, і нині» – богородичний, глас 6-ий: «Коли на Хресті розп’ятого побачила Слово Боже, що безсімено Тебе породила, взиваючи викликувала: Дитино моя Найсолодша, яке Твоє смирення Боже мій, як безпристрасний страждання терпиш через неправедний суд; оспівую Твою надзвичайну поблажливість». Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. Стихири Тріоді. На стиховні стихири глас 2-ий: «Через Хрест вірні визволилися від кайданів древнього осуду, на ньому розп’ятого Христа славимо». Стих: Возносіте Господа Бога нашого, і поклоняйтеся підніжжю ніг Його, бо воно святе. Сьогодні з нами Давиде прийди, грай на цівниці. Христа оспівуйте, вірні поклоніться підніжжю ніг Його. Стих: Бог же Цар наш споконвіку учинив спасіння посеред землі. Піднесімо люди древо, що лежить, бо в через нього спасіння нам Христос подає, вірою поцілуємо. Слава і нині. Хрестобогородичний: «Піднесена на хрест через людей, бачачи Твого Сина Діво, зі сльозами промовляла: слава Милосердю Твоєму». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропа Хресту, глас 1-ий «Спаси Господи...». Після співу тропаря священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після малої вечірні або, на практиці, безпосередньо перед початком всенічної священник переносить Хрест на престол. Перенесення Хреста з жертовника на престол відбувається при співі тропаря Хреста, глас 1-й: «Спаси, Господи, людей Твоїх...», і на «Слава, і нині» – кондак Хреста. Типікон не уточнює, який саме кондак співається при перенесенні Хреста з жертовника на престол в Неділю Хрестопоклонну – кондак, глас 4-й: «Вознісся на Хрест волею...», або кондак, глас 7-ий: «Зброя вогненна вже не стереже врат Едему...». Вказівка ​​ Типікону в Неділю 3-ю посту про те, що перенесення відбувається «так само як приписано в 13-ий день вересня, ввечері», непрямим чином свідчить про спів кондака Воздвиження Хреста, глас 4-й: «Вознісся на Хрест волею...». Примітка. Після відпусту малої вечірньої і перенесення хреста в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 7-ий – 6, Тріоді (Хреста), глас 5-ий – 4. «Слава» – Тріоді (Хреста), глас 3-ій: «Христе Боже наш...». «І нині» – догматик, глас 7-ий:»Матір’ю наприродно...». Вхід. Прокимен дня. На літії стихира храму. «Слава, і нині» – Тріоді (Хреста), глас 5-ий: «Слава, і нині, глас 5-ий: Все творіння, бачачи, Тебе нагим висячого на Хресті/, Творця і Сотворителя всього,/ в страху змінилося й засмутилося:/ сонце померкло і земля захиталася,/ гори ж попадали і розривалася блискуча завіса храму,/ мертві повставали з гробниць/ і Ангельські воїнства дивувалися і викликували:/ «О чудо! Суддя піддається суду,/ страждає добровільно/ для спасіння світу і оновлення!»». На стиховні стихири недільні, глас 7-ий. «Слава, і нині» – Тріоді (Хреста), глас 4-й: «Господи, лагідному Давиду...». Після Трисвятого – «Богородице Діво...» (двічі), і тропар Тріоді (Хреста), глас 1-ий: «Спаси, Господи, людей Твоїх...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар неділі, глас 7-ий (двічі). «Слава» – тропар Тріоді (Хреста), глас 1-ий: «Спаси, Господи, людей Твоїх...», «І нині» – Богородичний недільний, глас той же: «Коли Гавриїл...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні Октоїха. Непорочні [1] (на практиці, замінюються на полієлей, який відбувається у вівтарі, при цьому величання зі стихами не співається). «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє недільне 7-е (за традицією, читається у вівтарі). «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – Тріоді, глас 8-ий: «Покаяння відкрий мені двері...», «І нині» – Богородичний Тріоді, глас той же: «На стежки спасіння...». Глас 6-й: «Помилуй мене, Боже...», і стихира Тріоді, глас той же: «Множество вчинених...». (За звичаєм, помазання єлеєм відбувається після винесення Хреста). Канони: недільний з ірмосом на 4 (ірмоси раз), Богородиці (Октоїха) на 2 і Тріоді (Хреста) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія Тріоді: «Божественний Мойсей у давнині прообразував Хрест Твій...». Після 3-ої пісні – сідальний Тріоді (Хреста), глас 6-ий: «Хрест Твій, Господи...», стих: «Возносьте Господа Бога нашого...» – інший сідальний Тріоді (Хреста), глас той же: «Нині здійснилося слово пророче...». «Слава» – інший сідальний Тріоді (Хреста), глас той же: «Коли поставили древо Хреста Твого, Христе...», «І нині» – Богородичний Тріоді, глас той же: «Богородице Діво моли Сина Твого...». Після 6-ої пісні – кондак Тріоді (Хреста), глас 7-ий: «Зброя вогненна вже не стереже врат Едему...». Ікос, глас той же: «Три хрести поставив на Голгофі Пилат...». Читаємо Синаксар. На 9-й пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 7-й. «Слава» – світильний Тріоді (Хреста): «Бачачи перед собою сьогодні чесний Хрест Христів...», «І нині» – Богородичний Тріоді: «Древу, на якому Всечиста...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири недільні, глас 7-ий – 4, і Тріоді (Хреста), глас 4-ий – 4 (зі своїми стихами і з повторенням першої стихири [2]), потім стих: «Воскресни, Господи Боже мій...», і самогласний Тріоді , глас 8-ий: «Господь притчею навчав усіх уникати гордовитого розуму...». «Слава» – той же самогласний Тріоді, «І нині» – «Преблагословенна єси...». Відкриваються царські врата. Велике славослів’я співається тихо. (Недільний тропар після славослів’я не співається). До співу славослів’я (зазвичай під час канону або хвалітніх стихир) предстоятель одягається в усі священичі одежі (без читання відповідних молитов [3]). Після виголосу «Слава Тобі, що показав нам світло», прийнявши кадило, предстоятель кадить престол і Хреста, що лежить на ньому три рази навколо. Потім на блюді, покритому воздухом, піднімає Хрест на свою голову [4]; при співі останнього Трисвятого він у супроводі двох свічок і кадила через північні двері виносить Хрест з вівтаря і зупиняється проти відчинених царських врат [5]. Після закінчення Трисвятого священник виголошує: «Премудрість, станьмо побожно» [6]. Священнослужителі співають тропар Тріоді (Хреста), глас 1-ий: «Спаси, Господи, людей Твоїх...» (тричі). Священник підходить до приготовленого і поставленого навпроти царських врат (нижче амвона) аналою, покладає на нього блюдо з Хрестом і кадить навколо нього тричі, а по звершенні кадіння тричі співає: «Хресту Твоєму поклоняємось, Владико...». Цей спів тричі повторює хор, і відбувається цілування Хреста [7]. При цьому співаються особливі стихири Тріоді на поклоніння Хресту, глас 2-ий і глас 8-ий: «Прийдіть, вірні...» та ін. Звичайні ектенії (потрійна: «Помилуй нас, Боже...»; прохальна: «Доповнімо ранню молитву...», голововклонна молитва) і відпуст:»Христос, що воскрес із мертвих, істинний Бог наш, молитвами Пречистої Своєї Матері, силою Чесного і Животворчого Хреста...». Перед 1-им часом на «Слава, і нині» – стихира євангельська 7-ма."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний гласу. «Слава» – тропар Тріоді (Хреста). Кондак Тріоді (Хреста). ЛІТУРГІЯ за чином свт. Василія Великого. На прокомидії заготовлюються два агнця для середи і п’ятниці. Примітка. Якщо буде звершуватися полієлейна служба прп. Олексію, людині Божій (17 березня), то необхідно заготувати ще третій агнець. Блаженні на 10: гласу – 6, і Тріоді (Хреста), пісня 3-я – 4 (за Типіконом вказано брати тропарі 6 пісні Тріоді на 4). Увага! Відповідно до рішення №41 Священного Синоду Української Православної Церкви (Православної Церкви України) від 7 листопада 2024 р. «Про надання благословення на богослужбові тексти» Священний Синод вирішив: Надати благословення на використання на розсуд настоятеля на святкових службах особливих антифонів замість звичайних, як це є в грецькій церковній традиції та включити зазначені тексти до богослужбових книг Православної Церкви України. Антифон 1 Стих 1: Ти явив нам / світло лиця Твого, Господи (Пс. 4:8). Молитвами Богородиці, / Спасе спаси нас. Стих 2: Дай же знамення тим, що бояться Тебе, / щоб вони могли втекти від стріли ворожої (Пс. 59:6). Молитвами Богородиці, / Спасе спаси нас. Стих 3: Ти зійшов на висоту, / полонив полон (Пс.67:19). Молитвами Богородиці, / Спасе спаси нас. Стих 4: Дав мені насліддя з тими, / що бояться імені Твого (Пс. 60:6). Молитвами Богородиці, / Спасе спаси нас. Слава, і нині: Молитвами Богородиці, / Спасе Спаси нас. Антифон 2 Стих 1: Побачили всі кінці землі / спасіння Бога нашого (Пс. 97:3Б). Спаси нас. Сину Божий, / що воскрес із мертвих, співаємо Тобі. Алилуя. Стих 2: Поклонімося / підніжжю ніг Його (Пс. 131:7). Спаси нас, Сину Божий, / що воскрес із мертвих, співаємо Тобі. Алилуя. Стих 3: Бог же, Цар наш, / раніше віків учинив спасіння посеред землі (Пс. 73:12). Спаси нас, Сину Божий, / що воскрес із мертвих, співаємо Тобі. Алилуя. Стих 4: Піднесуся між народами / і прославлюся на землі (Пс. 45:11). Спаси нас, Сину Божий, / що воскрес із мертвих, співаємо Тобі. Алилуя. Слава, і нині: Єдинородний Сину: Антифон 3 Стих 1: Возносьте Господа Бога нашого і поклоняйтеся підніжжю ніг Його, бо Він святий (Пс. 98:5). Тропар, глас 1: Спаси, Господи, людей Твоїх і благослови насліддя Твоє, перемогу православним християнам над супротивниками подай і Хрестом Твоїм охороняй нас, громаду Твою. Стих 2: Спаси, Господи, людей Твоїх і благослови насліддя Твоє (Пс. 27:9А). Тропар, глас 1: Спаси, Господи, людей Твоїх: Стих 3: Паси їх і піднось їх повіки (Пс. 27:9Б). Тропар, глас 1: Спаси, Господи, людей Твоїх: На вході – «Прийдіть поклонімось... що воскрес із мертвих...». Після входу – тропар недільний гласу, тропар Тріоді (Хреста). «Слава, і нині» – кондак Тріоді (Хреста). Замість Трисвятого – «Хресту Твоєму...». Прокимен і алилуарій [8] – Неділі Хрестопоклонної. Апостол і Євангеліє – Неділі Хрестопоклонної. Замість «Достойно» – «Тобою радується...». Причасний – Неділі Хрестопоклонної: «Ти явив нам світло лиця Твого, Господи (Пс. 4, 7).». Примітка. «На трапезі споживаємо, теж саме, що вказано в 1-у Неділю Православ’я» (Типікон, гл. 49, «Неділя третя святого посту...»). Примітка. Устав не уточнює, де повинен знаходитися аналой – «четвероножець» зі святим Хрестом до віднесення Хреста назад у вівтар в п’ятницю Хрестопоклонної седмиці. Проте за встановленою традицією Хрест залишається на середині храму до п’ятниці і священик у визначений час виходить на середину храму для поклоніння Чесному Хресту». [1] 118-й псалом (17-я кафизма) співається на 5-ий глас, незалежно від тижневого гласу, і відразу після нього тропарі «Ангельський собор...». У парафіяльній практиці замість Непорочних на недільних всенічних відправах, зазвичай, співається полієлей. [2] Перша стихира Тріоді (Хреста) повторюється після стихири «Всечесний Хресте, ти Церкви твердиня...» і співається в якості четвертої стихири (зі стихом: «Бог же, Цар наш споконвіку учинив спасіння посеред землі»). [3] Молитви на кожен елемент облачення Священник читає тільки перед звершенням повній Літургії. В інших випадках, коли Устав або богослужбова практика передбачає одягання в усі священичі одежі (Літургія Ранішосвячених Дарів; винесення Хреста в Неділю Хрестопоклонну, 1 серпня і на Воздвиження Хреста Господнього; вечірні Великої П’ятниці і 1-го дня Пасхи, на ранній Великої Суботи і т. д.), Священник відповідних молитов не промовляє. [4] За усталеною практикою, після триразового кадіння престолу (з лежачим на ньому Хрестом), під час співу хором «Святий Боже...» в кінці славослів’я, все духовенство у вівтарі здійснює три земні поклони, а потім вже настоятель кладе Хрест на свою голову. [5] В деяких храмах є звичай обносити Хрест по периметру храму зі співом похоронного «Святий Боже...». [6] Зазвичай під час виголошення «Премудрість, станьмо побожно» службовий священик творить Хрестом хресне знамення в царських вратах. [7] Зазвичай під час цілування Хреста відбувається помазання освяченим єлеєм. [8] Тріодь Постова вказує співати алилуарій Неділі Хрестопоклонної на 1-ий глас (порівн. Зі святом Воздвиження Хреста). Згідно з Типіконом і Апостолом, цей алилуарій повинен співатися на 8-ий глас."}]},
{"date":"03-16","weekday":"понеділок","title":"4-й тиждень Великого посту. Ап. Аристовула, єп. Вританійського (Британського, І). Мч. Савина (287). Мч. Папи (305 – 311). Сщмч. Олександра, єпископа Римського (119). Мч. Юліана Аназаврського (305 – 311). Сщмчч. Трофима і Фала, пресвітерів Лаодикійських (бл.300).","notes":"На 6-му часі: Іс. XIV, 24 – 32. На веч.: Бут. VIII, 21 – IX, 7. Притч. XI, 19 – XII, 6.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ. Дивись зразок звершення вечірньої 22 лютого. Кафизми немає. На «Господи, взиваю» стихири на 10: 4 стихири покаянні Октоїха, глас 7-ий (дві – зі стихир на стиховні вечора, дві інші – зі стиховних стихир ранньої), Тріоді, глас 8-ий і глас 3-ій – 3, і стихири мчч. Савина і Папи, глас 8-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той же: «Кому уподібнилася...». Вхід з кадилом. «Світло Тихе». Співається великий прокимен, глас 8-ий: «Дав єси насліддя...», зі стихами (за звичаєм). Під час читання «Сподоби Господи...» священник облачається в облачення багряного (сучасній практиці – чорного) кольору. На стиховні стихири Тріоді, глас 8-ий «Слава, і нині» – Богородичний Тріоді, глас то й же «Небеса оспівують Тебе...». Молитва прп. Єфрема Сиріна читається із трьома великими поклонами (без малих). Закінчення вечірні великопостове (22 лютого). Після вечірні заупокійної літії немає."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в неділю ввечері співається служба свящмч. Артемона (з 13 квітня). Примітка. Канон Богородиці на повечір’ї в неділю ввечері не співається, оскільки напередодні звершувалося всенічне бдіння."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 7-ий з приспівами понеділка. Кафизми 4-та, 5-та, 6-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. 50 псалом. Молитва «Спаси Боже...» Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. 3-тя, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 1-ша, 8-ма, 9-та – ірмос другого трипіснеця Тріоді. 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 8-ий: «Зв’язаний любов’ю..» «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – кондак мучеників, глас 2-ий: «»Божественне народження. На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 6-ий: «Особливий шлях...» «Слава і нині» – Богородичний Тріоді: «Архангельське слово...». Далі великопостове закінчення ранньої. На 1-му часі – кафизми немає. Після Богородичного: «Як Тебе назвати...» замість «Стопи мої направ...» співають «Хресту Твоєму поклоняємось Владико...» і стихири на поклоніння Хресту. Священик і вірні поклоняються і цілують Хрест. Кондак Тріоді «Полум’яна зброя...» По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 7-ма. Кондак Тріоді «Полум’яна зброя...» На 6-му – кафизма 8-ма. Прокимни та паремія Тріоді. Кондак Тріоді «Полум’яна зброя..» На 9-му – кафизма 9-та. Кондак Тріоді «Полум’яна зброя...»"},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: По «Отче наш...» читається лише кондак Тріоді «Полум’яна зброя...». Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (в понеділок увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 8-ий – 3, Мінеї – преподобного Олексія, глас 1-ий – 3 (з 17 березня). «Слава, і нині» – Богородичний Мінеї. Входу немає. Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 8-ий. «Слава» – преподобного: «Ти вірою і любов’ю...» «І нині» – Богородичний Тріоді, глас то й же. Закічення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-17","weekday":"вівторок","title":"Прп. Олексія, людини Божої (411). Свт. Патрикія, просвітителя Ірландії (після 460). Мч. Марина.","notes":"На 6-му часі: Іс. XXV, 1 – 9. На веч.: Бут. IX, 8 – 17. Притч. XII, 8 – 22.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у понеділок ввечері – канон Богородиці і свт. Мартина, сповідника і мчч. Антонія, Іоана і Євстафія Литовських (з 14 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 7-ий з приспівами вівторка. Кафизми 10-та, 11-та, 12-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 2-га пісня тільки з Тріоді на 8. 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 2-га, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 3-ій: «Красу світу ти залишив..». «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – кондак, глас 2-ий: «Дім батьків Твоїх став для тебе чужим..» та ікос. На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні. Хвалитні псалми і хвалитні стихири преподобного, на глас 4-ий, і глас 1-ий на 8. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 8-ий: «Душе моя помишляй...» «Слава» – преподобного: «»Земний ангел..». «І нині» – Богородичний Тріоді: «Покров Твій...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 13-та. По завершенні часу служиться заупокійна літія. На 3-му – кафизма 14-та. На 6-му – кафизма 15-та. Прокимни та паремія Тріоді. На 9-му – кафизма 16-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у вівторок увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 6-ий, глас 1-ий. – 6. «Слава, і нині» – Тріоді (Хресту): «Нині владика Творіння...». Примітка. Служби рядового святого Мінеї переносяться на повечір’я. Входу немає. Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 3-тій. «Слава, і нині» – Хрестобогородичний Тріоді, глас то й же. Закінчення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-18","weekday":"середа","title":"Свт. Кирила, архієп. Єрусалимського (386). Мчч. Трофима і Євкарпія (бл. 300). Прп. Аніна, ченця. Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. XXVI, 21 – XXVII, 9. На веч.: Бут. IX, 18 – X, 1. Притч. XII, 23 – XIII, 9.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у вівторок ввечері – канон Богородиці і служба Кирила Єрусалимського (з цього дня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 7-ий з приспівами середи. Кафизми 19-та, 20-та і 1-ша. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Увага! Відповідно до вказівок Типікону співається канон Хресту з ірмосом на 6. Канони: 1-ша, 4-та, 5-та, 6-та, 7-ма пісні: канон Хреста на 4. 3-тя, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 3-тя, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 6-та – ірмос канону Хреста. Після 3-тої пісні – Сідальний, глас 6-ий: «Нині справдилось пророче слово..» «Слава» – «Хрест Твій Господи...», «І нині» – Тріоді глас то й же: «Тільки но встановлено було...». Після 6-тої – Кондак Хреста, глас 7-ий: «Вогненна зброя...» та ікос. На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильний гласу і екзапостиларій Тріоді: «В переполовення посту» «Слава і нині» – Хрестобогородичний Тріоді: «Безневісна і Пречиста...» Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 8-ий: «Ми пройшли половину дороги прощення..» «Слава і нині» – Хрестобогородичний Тріоді: «Переполовинивши безодню стримання...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 2-га. Після Богородичного: «Як Тебе назвати...» замість «Стопи мої направ...» співають «Хресту Твоєму поклоняємось Владико...» і стихири на поклоніння Хресту. Священик і вірні поклоняються і цілують Хрест. Кондак Тріоді «Полум’яна зброя...». По завершенні часу служиться заупокійна літія. На всіх часах – кондак Хресту: «Вогненна зброя...» На 3-тьому – кафизма 3-тя. На 6-му – кафизма 4-та. Прокимни та паремія Тріоді. На 9-му – кафизма 5-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: Кондак Тріоді – «Вогненна зброя...» Твориться відпуст зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у середу увечері) – кафизма 18-та. «Господи взиваю» – стихири на 10: Тріоді, глас 4-ий, глас 5-и1 і глас 1-ий – 6, Мінеї – Мч. Хрисанфа і мц. Дарії, глас 4-ий – 4 (з 19 березня), перша стихира мученикам співається двічі. «Слава, і нині» – Богородичний Мінеї: Неміч і розслаблення душі моєї...». Вхід з кадилом. «Світе Тихий». Паремії Тріоді – 2. Далі продовження Літургії Ранішосвячених Дарів. Детальний виклад порядку вечірні в поєднанні з Літургією Ранішосвячених Дарів див. 25 лютого. Після Літургії заупокійної літії немає."}]},
{"date":"03-19","weekday":"четвер","title":"Мч. Хрисанфа і мц. Дарії (283) і з ними мчч. Клавдія, трибуна, Іларії, дружини його, Ясона і Мавра, синів їхніх, сщмчч. Діодора, пресвітера, і Мар’яна, диякона. Мч. Панхарія (бл. 302).","notes":"На 6-му часі: Іс. XXVIII, 14 – 22. На веч.: Бут. X, 32 – XI, 9. Притч. XIII, 20 – XIV, 6.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у середу ввечері – канон Богородиці і апостолів Аристарха, Пуда і Трофима (15 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 7-ий з приспівами четверга. Кафизми 6-та, 7-ма, 8-ма. Після першої кафизми – сідальні Октоїха (без мученичного). Після 2-гої і 3-ої – сідальні Тріоді. 50 псалом. Молитва: «Спаси Боже...» Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 4-та, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 4-та, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 3-ій: «Прекрасну доброту.» «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – Мученичний Октоїха: «Мученики Твої Господи...» (див. глас 7-ий у четвер на ранній після другої кафизми). Примітка. Перед мученичним Октоїха читаємо приспів: «Дивний Бог у святих своїх, Бог Ізраїлів» . На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Октоїха. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 7-ий: «Поревнуймо вірні..». «Слава і нині» – Богородичний Тріоді: «Подай мир молитвами Богородиці...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 9-та. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 10-та. На 6-му – кафизма 11-та. Прокимни та паремія Тріоді. На 9-му – кафизма 12-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня, інший кондак дня. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, інший кондак дня. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, інший кондак дня, кондак храму. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Примітка. Якщо денний кондак співпадає з кондаком храму, то він читається лише один раз. Примітка. Кондак мчч. Хрисанфу і Дарії відсутній в Мінеї, його не варто замінювати загальним кондаком мученикам. Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у четвер увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 4-ий – 3, Мінеї – Прмчч. Іоана, Сергія, Патрикія та інших, які в обителі св. Сави були вбиті, глас 4-ий – 3 (з 20 березня). «Слава, і нині» – Хрестобогородичний Мінеї: «Коли побачила Тебе...». Примітка. Стихири преподобномучеників з «Господи взиваю» не переносяться на Повечір’я, оскільки в Тріоді відсутні додаткові стихири Хресту. Хоч деякі літургісти вважають, що не можна розривати службу рядового святого, яка має служитися на Повечір’ї. Вони вказують, що в цьому випадку потрібно брати додаткові стихири Хресту, які співались у вівторок увечері. Проте Постова Тріодь вказує, що необхідно брати стихири рядового святого Мінеї на «Господи взиваю». Входу немає. Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 6-тий. «Слава, і нині» – Хрестобогородичний Тріоді, глас то й же. Закінчення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-20","weekday":"п’ятниця","title":"Прмчч. Іоана, Сергія, Патрикія та інших, які в обителі св. Сави були вбиті (796). Мц. Фотини (Світлани), самарянки, її синів мчч. Віктора, названого Фотином, та Іосії (І). Мцц. Анатолії, Фото, Фотиди, Параскеви, Киріакії, Домніни і мч. Севастіана (бл. 66). Мцц. Олександри, Клавдії, Євфрасії, Мотрони, Юліанії, Євфимії і Феодосії (310). Свт. Микити, спов., архієп. Аполоніадського (бл. 813 – 820). Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. XXIX, 13 – 23. На веч.: Бут. XII, 1 – 7. Притч. XIV, 15 – 26.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї в четвер увечері – канон Богородиці і служба прмчч. Іоана, Сергія, Патрикія та інших, які в обителі св. Сави були вбиті (з цього дня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 7-ий з приспівами п’ятниці. Кафизми 13-та, 14-та і 15-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. 50 псалом. Молитва: «Спаси Боже...». Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 4-та, 6-та, 7-ма пісні: Тріоді (Хресту) на 4. 5-та, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія –5-та, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Тріоді (Хресту). Після 3-тої пісні – Сідальний Хресту, глас 6-ий: «Коли тільки було встановлено...» «Слава, і нині» – Хрестобогородичний Тріоді, глас то й же: «Нині збулося пророче слово...». Після 6-тої – кондак Хресту, глас 7-ий: «Вогненна зброя...» та ікос. На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Октоїха. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 4-ий: «Істини випробовувач...» «Слава і нині» – Самогласний Тріоді: «Нині владика Творіння...». Далі великопостове закінчення ранньої. На всіх часах читається кондак Хресту «Вогненна зброя...» На 1-му часі – кафизми немає. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 19-тя. На 6-му – кафизма 20-та. Прокимни та паремія Тріоді. На 9-му – кафизми немає."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: Священник під час зображальних облачається в повне облачення. Після «Отче наш» читається лише кондак Хресту: «Вогненна зброя...». Після молитви прп. Єфрема Сиріна читається кінцеве Трисвяте по Отче наш. Священник після виголосу «Бо Твоє є Царство...» відкриває царські врата і виходить до аналоя, де лежить чесний хрест. Хор співає «Спаси Господи людей Твоїх...» (тричі). Священик Тричі обкаджує Хрест. Далі хор співає тричі «Хресту Твоєму поклоняємось Владико...». Далі хор співає стихири «Прийдіть вірні...», усі присутні в храмі підходять і цілують хрест. Опісля священик цілує хрест і побожно несе через царські врата у вівтар, також за традицією на амвоні Хрестом благословляє народ. Опісля царські врата закриваються. Читець продовжує молитву: «Всесвята Тройце...». Священник «Премудрість». Хор «Достойно є» співає до половини. Священник: Пресвята Богородице, спаси нас. Хор: Чеснішу від херувимів... Священник: «Слава Тобі Христе Боже...» Хор: «Слава, і нині», «Господи помилуй» (тричі), «Благослови». Священник творить малий відпуст зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у п’ятницю увечері) – кафизма 18-та. «Господи взиваю» – стихири на 10: Тріоді, глас 7-ий – 6 (самогласна стихира двічі): і мученичні Октоїха, глас 7-ий, Мінеї – преподобного Якова, сповідника, глас 4-ий – 4 (з 21 березня), перша стихира преподобного співається двічі. «Слава» – померлим, 7-го гласу: «Упокой Спасе наш, Життєдавче, братію нашу, яку Ти представив від тимчасового життя, що взиває: Господи, слава Тобі». «І нині» – догматик: «Матір’ю надприродно...». Вхід з кадилом. «Світе Тихий. Читання паремій Тріоді (прокимен 1-ий паремії, глас 4-ий: «Пастирю Ізраїлю...», зі стихом; прокимен 2-ий паремії, глас 6-ий: «Радісно співайте Богу...», зі стихом). «Нехай вознесеться молитва моя...», Далі продовження Літургії Ранішосвячених Дарів. Детальний виклад порядку вечірні в поєднанні з Літургією Ранішосвячених Дарів див. 25 лютого. Після Літургії заупокійної літії немає."}]},
{"date":"03-21","weekday":"субота","title":"Прп. Якова, єп. Катанського, спов. (VІІІ). Свт. Кирила, єп. Катанського (І – ІІ). Свт. Фоми, патр. Константинопольського (610). Поминання померлих. Літургія свт. Іоана Золотоустого.","readings":["Заупокійне: 1 Кор., 163 зач., ХV, 47 – 57. Ін., 16 зач., V, 24 – 30.","Ряд.: Євр., 313 зач., VI, 9 – 12. Мк., 31 зач., VII, 31 – 37."],"notes":"Цієї суботи заупокійна служба з Тріоді з’єднується зі службами Мінеї та Октоїха. ВЕЛИКЕ ПОВЕЧІР’Я (без поклонів): Після 1-го Трисвятого – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар глас той же: «Пом’яни, Господи...», «І нині» – Богородичний, глас той же: «Мати Свята...». Після 2-го Трисвятого – тропарі Часослова (звичайні), глас 6-ий: «Помилуй нас, Господи...». Після «Слава в вишніх...» – співається свящмч. Василія Анкирського (з 22 березня), і заупокійний канон Октоїха, глас 7-ий (з ранньої суботи, без ірмосів). Канон Богородиці не співається, так як замінюється заупокійним. Після канонів – «Достойно є». Після 3-го Трисвятого – кондак, глас 8-ий: «Зі святими упокой...» (замість «Господи Сил...»). «Господи, помилуй» (40), «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава, і нині», «Чеснішу від херувимів...», «Іменем Господнім...». Виголос: «Молитвами святих отців наших...». Читець: «Амінь». Молитва: «Непорочна, Пречиста...», «І дай нам, Владико...», «Преславна Приснодіво...», «Уповання моє Отець...». Священник: «Слава Тобі, Христе Боже...». «Слава, і нині». «Господи, помилуй» (тричі). «Благослови». Відпуст малий: «Христос, істинний Бог наш...». Звичайне прощення. Ектенія: «Помолимось...». ПОЛУНОШНИЦЯ звичайна – суботня. РАННЯ починається звичайним порядком (див. 28 лютого). Замість «Бог Господь» – «Алилуя»», глас 2-ий, із заупокійними стихами: 1-ий – «Блаженні, ті кого обрав і прийняв Ти, Господи»; 2-й – «Пам’ять про них з роду в рід»; 3-ій – «Душі їх у блаженстві перебуватимуть». Тропар, глас 2-ий: «Апостоли, мученики і пророки...» (двічі). «Слава» – інший тропар, глас той же: «Пом’яни, Господи...», «І нині» – Богородичний, глас той же: «Мати Свята...». Читається 16-та кафизма. Мала ектенія (звичайна, а не заупокійна). Сідальні Октоїха, глас 7-ий мученичні «Слава, і нині» – Богородичний поточного гласу; «Як скарбницю нашого воскресіння...» (див. Після 1-ої кафизми). Після сідального читається шестиднев свт. Іоана Золотустого (Типікон, гл. 49). На практиці читання опускають, і відразу (нічого не промовляючи) співаємо (за Уставом, на 5-ий глас) непорочні (17-ту кафизму), розділяючи на дві частини (статті), з приспівом до 1-ої: «Благословен єси, Господи, навчи мене заповітів Твоїх». Перша стаття закінчується 93-м стихом, перед словом: «Середина». Після першої статті не вимовляється: «Слава, і нині», але з приспівом співаються (тричі) заключні 92-ий і 93-ій стихи: «Якби не закон Твій...» і «Навіки не забуду повелінь Твоїх...». Примітка. Щодо закінчення першої і другої статті 17-ої кафизми при заупокійному богослужінні існують такі думки: 1) кожен з двох останніх стихів першої і другої статті співається по тричі з відповідним приспівом; 2) в кожній статті два останніх стиха об’єднуються «як один» і співаються з приспівом тричі. Виголошується мала заупокійна ектенія: «Ще і ще...», хор: «Господи, помилуй» (один раз); «Ще молимося за упокій душ спочилих рабів Божих праотців, отців, і братів наших...», хор: «Господи, помилуй» (один раз); «Щоб Господь Бог оселив душі їхні...», хор: «Господи, помилуй» (один раз); «Милості Божої...», хор: «Подай, Господи». «Господу помолимось». Хор тихо: «Господи, помилуй» (40). Священник таємно читає молитву: «Боже духів...». Виголос: «Бо Ти єси Воскресіння...». Хор: «Амінь». Друга стаття 17-ої кафизми: «Твій – я, спаси мене...» співається з приспівом до кожного стиха: «Спасе, спаси мене». В кінці тричі співаються з приспівом заключні 175-ий і 176-ий стихи: «Нехай живе душа моя...» і «я блукаю, наче ягня загублене...». Далі тропарі після Непорочних, глас 5-ий: «Собор святих...», з приспівом «Благословен єси, Господи, навчи мене заповітів Твоїх». Мала заупокійна ектенія (див. Після 1-ої статті). «Господи, помилуй» (40). Священник таємно читає молитву: «Боже духів...». Після виголосу хор: «Амінь», і сідальний, глас 5-ий: «Упокой, Спасе наш...», «Слава» – кінець цього піснеспіву: «І всі, свідомі і не свідомі, Людинолюбче», «І нині» – Богородичний, глас той же: «Христе Боже, що від Діви засяяв...». Псалом 50-ий. (Молитва: «Спаси, Боже, людей Твоїх...» не промовляється). Канони: У храмі Господському і Богородиці – канон храму з ірмосом на 6 (ірмоси раз), канон Мінеї на 4 (преподобного Якова). Починаючи з 6-ої пісні канон храму пропускається, і співається спочатку канон Мінеї з ірмосом на 6 (ірмоси раз), потім два четверопіснеця Тріоді – на 10. У храмі святого – канон Мінеї з ірмосом на 6 (ірмоси раз), канон храму святого на 4. Починаючи з 6-ої пісні канону храму пропускається, співаються канон Мінеї і четверопісцем так само, як в храмі Господському і Богородиці. Біблійні пісні Ірмологія за великопостовим розділом. Примітка. Початкові стихи пісень Святого Писання, з 1-ої по 5-у, не співаються, а починають читатися тільки після ірмосу і 1-го тропаря, з напису «на 8» (всього на 10). 13 стихів 6-ої і 9-ої біблійних пісень (включаючи «Слава» та «І нині») починають співатися, чергуючись з тропарями канону Мінеї і четвероспівців Тріоді, – після ірмосу канону Мінеї (всього, включаючи ірмос канону Мінеї, на 14, і на закінчення ще 2 додаткових тропаря 2-го четвероспіснеця з особливими приспівами). 7-а і 8-а біблійні пісні читаються від початку до кінця; після стиха з написом «на 14» співається ірмос канону Мінеї і далі тропарі, чергуючись зі стихами (всього, включаючи ірмос Мінеї, на 14, і на закінчення ще 2 додаткових тропаря 2-го четвероспіснеця з особливими приспівами). Катавасія після 3-ої пісні – ірмос 3-ої пісні останнього канону, а після 6-ої, 7-ої, 8-ої і 9-ої – ірмоси другого четверопіснеця. Після 3-ої пісні – мала ектенія (звичайна, а не заупокійна); сідальний прп., глас 4-ий: «Ти пішов за Христом...». «Слава, і нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – мала заупокійна ектенія (див. Після 1-ої статті 17-ої кафизми). Кондак, глас 8-ий: «Зі святими упокой...», та ікос, глас той же. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний гласу 7-го. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Октоїха (мученичні), глас 7-ий – 4 (перша стихира двічі). «Слава» – мертвих Октоїха, глас той же: «У країні праведних...» (див. на хвалитніх...), «І нині» – Богородичний Октоїха, глас той же: «Моли Діво..». «Тобі слава подобає...» не промовляється, але відразу: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. Стихири на стиховні Октоїха, глас 7-ий зі своїми приспівами. «Слава, і нині» – Богородичний Октоїха, глас той же. «Благо є» (один раз). Трисвяте. Після «Отче наш» – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар, глас той же: «Пом’яни, Господи...», «І нині» – Богородичний, глас той же: «Мати Свята...». Після потрійної ектенії «Помилуй нас, Боже...» – Священник: «Премудрість». Хор: «Благослови». Священник: «Сущий благословенний...». Хор: «Амінь». «Утверди, Боже...», і відразу 1-ий час.","sections":[{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропарі: «Апостоли, мученики і пророки...». «Слава» – «Пом’яни, Господи, як благий...». Кондак: «Зі святими упокой...». ЛІТУРГІЯ за чином свт. Іоана Золотоустого. Блаженні гласу – 6. Після входу – тропарі, глас 2-ий: «Апостоли, мученики і пророки...», «Пом’яни, Господи, як благий...». «Слава» – кондак, глас 8-ий: «Зі святими упокой...», «І нині» – Богородичний, глас той же: «Тебе і стіну, і пристанище...». Прокимен – дня (суботи), глас 8-ий: «Веселіться у Господі...», стих: «Блаженні, кому прощено беззаконня...»; і заупокійний, глас 6-ий: «Душі їх у блаженстві перебуватимуть». Апостол і Євангеліє – суботи 4-го тижня і заупокійні. Алилуарій – дня (суботи): «Взивали праведні...», стих: «Багато скорбот у праведних...»; і заупокійний: «Блаженні, ті кого обрав...». Причасний – дня (суботи): «Радуйтеся, праведні...», і заупокійний: «Блаженні, ті кого обрав...»."}]},
{"date":"03-22","weekday":"неділя","title":"Неділя 4-та Великого посту. Глас 8. Прп. Іоана Ліствичника (перехідне святкування в 4-ту неділю Великого посту). Сщмч. Василія, пресвітера Анкирського (362 – 363). Мц. Дросиди, дочки царя Траяна (104 – 117). Прп. Ісаакія Далматського (ІV). Літургія за чином свт. Василія Великого.","glas":8,"readings":["Ран. – Єв. 8-е, Ін., 64 зач., XX, 11 – 18.","Літ. – Євр., 314 зач., VI, 13 – 20. Мк., 40 зач., IX, 17 – 31.","Прп.: Еф., 229 зач., V, 8 – 19. Мф., 10 зач., IV, 25 – V, 12."],"notes":"Недільна служба Октоїха звершується разом зі службою Тріоді. Примітка. Служба свящмч. Василія Анкирського з 22 березня переноситься на велике повечір’я на вечір п’ятниці 4-го тижня. За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню. Мала вечірня цієї неділі служиться лише за Октоїхом.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири, глас 8-ий – 4. «Слава, і нині» – богородичний (догматик малої вечірньої), глас 8-ий: «Як ублажимо Тебе Богородице? ...». Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. Перша стихира недільна, а інші стихири Пресвятої Богородиці зі своїми приспівами. На стиховні стихири глас 8-ий: «На хрест зійшов Ти Ісусе...» із своїми приспівами. «Слава, і нині» – Богородичний, глас то й же: «Той, Кого небо не вміщає...». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар недільний, глас 8-ий «З висоти зійшов ти Благоутробний...» «Слава, і нині» – Богородичний за гласом тропаря: «Ти, що ради нас народився...». Після співу тропаря з богородичним священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 8-ий – 7, і Тріоді (прп. Іоана), глас 8-ий – 3. «Слава» – Тріоді (прп. Іоана), глас 5-ий: «Преподобний отче...», «І нині» – догматик, глас 8-ий: «Цар Небесний...». Вхід. Прокимен дня. На літії стихира храму. «Слава, і нині» – Богородичний недільний за гласом стихири храму, зі стиховних. На стиховні стихири недільні, глас 8-ий. «Слава» – Тріоді (прп. Іоана), глас 2-ий: «Прославимо Іоана – ангела на землі і на небесах чоловіка Божого...», «І нині» – Богородичний недільний, глас той же: «О нове чудо, вище за всі давні чудеса!...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар неділі, глас 8-ий (двічі). «Слава» – тропар Тріоді (прп. Іоана), глас 1-й: «Пустельним жителем...», «І нині» – Богородичний воскресний, глас той же: «Коли Гавриїл звістив...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні недільні (Октоїха) Непорочні [1] (див. Типікон, гл. 17). «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє недільне 8-ме. «Воскресіння Христове бачивши...». Після 50- го псалма: «Слава» – Тріоді, глас 8-ий: «Покаяння відкрий мені двері...», «І нині» – Богородичний Тріоді, глас той же: «На стежки спасіння...». Глас 6-ий: «Помилуй мене, Боже...», і стихира Тріоді, глас той же: «Множество вчинених...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Богородиці (Октоїха) на 2, Тріоді – 1-ий (про того, що потрапив до рук розбійників) на 4 і 2-ий (прп. Іоана) на 4. Примітка. «Канони: неділі (гласу) з Богородичним на 6: і Тріоді на 4, глас 5-й: і святого на 4, глас 8-й» (Типікон, гл. 49, «Неділя 4-та святого посту»). Дане розпорядження Уставу може бути пояснене як вказівка на спів трьох канонів: недільного з ірмосом і Богородичного на 6 (ірмоси раз), Тріоді – 1-го (про того, що потрапив до рук розбійників) на 4 і 2-го (прп. Іоана) на 4. (Порівн.: Типікон, гл. 49, «В Неділю 5-ту святого посту»). Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос Тріоді (прп. Іоана), глас 4-ий; сідальний Тріоді, глас 5-ий: «Пречистий Хрест Твій Спасе...». «Слава» – сідальний Тріоді (прп. Іоана), глас 4-ий: «Засяявши чеснотами до небес...», «І нині» – Богородичний Тріоді, глас той же: «Той, Хто на престолі...». Після 6-ої пісні – кондак та ікос неділі, глас 8-ий. І читаємо Синаксарій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 8-ий. «Слава» – світильний Тріоді (прп. Іоана): «Шкідливих пристрасних принад світу уникнув ти, отче преподобний...», «І нині» – Богородичний Тріоді: «Як істинну Богородицю...». «Все що дише...» і хвалітні псалми. На хвалітніх стихири недільні, глас 8-ий – 8; потім стих: «Воскресни, Господи Боже мій, нехай піднесеться рука Твоя,/ не забудь убогих Твоїх до кінця», і самогласний Тріоді, глас 1-й: «Прийдіть, потрудімось...». «Слава» – той же самогласний, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар недільний: «Воскрес із гробу..». Перед 1-им часом на «Слава, і нині» – стихира євангельська 8-ма. НА 1-МУ і 6-МУ часі – тропар недільний (гласу). «Слава» – тропар Тріоді (прп. Іоана). Кондак Тріоді (прп. Іоана). НА 3-МУ і 9-МУ часі – тропар недільний (гласу). «Слава» – тропар Тріоді (прп. Іоана). Кондак гласу. ЛІТУРГІЯ за чином свт. Василія Великого. На проскомидії заготовлюються агнець вівторка. Примітка. Агнець для п’ятниці затовляється на Літургії за чином свт. Іоана Золотоустого у свято Благовіщення Пресвятої Богородиці 25 березня, що цього року припадає на середу 5-го тижня Великого посту. Блаженні гласу – 8. Після входу – тропарі і кондаки: У храмі Господському – тропар недільний, тропар Тріоді (прп. Іоана). «Слава» – кондак Тріоді (прп. Іоана), «І нині» – кондак недільний. У храмі Богородиці – тропар недільний, тропар храму, тропар Тріоді (прп. Іоана); кондак недільний. «Слава» – кондак Тріоді (прп. Іоана), «І нині» – кондак храму. У храмі святого – тропар недільний, тропар храму, тропар Тріоді (прп. Іоана); кондак недільний, кондак храму. «Слава» – кондак Тріоді (прп. Іоана), «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – неділі і прп. Іоана. Апостол і Євангеліє – Неділі 4-ої Великого посту і прп. Іоана. Замість «Достойно є» – «Тобою радується...». Примітка. «На трапезі споживається така сама їжа, як і в попередні Неділі» (Типікон, гл. 49, «Неділя 4-а святого посту»). [1] На практиці замість Непорочних на недільних всенічних зазвичай співається полієлей."}]},
{"date":"03-23","weekday":"понеділок","title":"5-й тиждень Великого посту. Прмч. Никона Сицилійського, єп., і мчч. 199 учнів його (251). Прп. Никона, ігумена Києво-Печерського (1088). Мчч. Філита, Лідії, дружини його, Македона, Феопрепія, Кроніда і Амфілохія (117 – 138). Звершується великопісна служба п’ятого тижня зі службою передсвята Благовіщення. Примітка. Якщо свято Благовіщення припаде в середу 5 тижня Великого посту, то співаємо службу передсвята в понеділок. Службу рядового святого Мінеї співаємо на Повечір’ї.","notes":"На 6-му часі: Іс. XXXVII, 33 – XXXVIII, 6. На веч.: Бут. XIII, 12 – 18. Притч. XIV, 27 – XV, 4. ВЕЧІРНЯ. Детальний виклад порядку богослужіння в Неділю вечора 2 березня Кафизми немає. На «Господи, взиваю» стихири на 10: 4 стихири покаянні Октоїха, глас 8-ий (дві – зі стихир на стиховні вечора, дві інші – зі стиховних стихир ранньої), Тріоді, глас 3-ій і глас 7-ий – 3, і стихири передсвята глас 4-ий – 3. «Слава, і нині» – Передсвята: «Благовіствує нині Гавриїл...». Вхід з кадилом. «Світло Тихе». Співається великий прокимен, глас 8-ий: «Не відверни лиця Твого...», зі стихами (за звичаєм). На стиховні стихири Тріоді, глас 7-ий і глас 6-ий (зі звичайними приспівами). «Слава, і нині» – Передсвята, глас 2-ий: «Таїнство від віку..». Молитва прп. Єфрема Сиріна читається із трьома великими поклонами (без малих). Закінчення вечірні великопостове.","sections":[{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в неділю ввечері співається служба прп. преподобномученика Никона з цього дня. Примітка. Канон Богородиці на повечір’ї у неділю уввечері не співається, оскільки напередодні звершувалося всенічне бдіння."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 8-ий з приспівами понеділка. Кафизми 4-та, 5-та, 6-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-ої і 3-ої – сідальні Тріоді. 50 псалом. Молитва «Спаси Боже...» Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. 3-тя, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. Біблійні пісні «Господеві співаємо» (великопостова редакція). Примітка. Типікон не вказує співати біблійні пісні за святковою редакцією в передсвято Благовіщення. Катавасія – 1-ша, 8-ма, 9-та – ірмос другого трипіснеця Тріоді. 3-тя і 6-та – ірмос Передсвята. Після 3-тої пісні – Сідальний, глас 4-ий: «Нашестя Духа Всесвятого...» «Слава, і нині» – інший сідальний, глас то й же. Після 6-тої – кондак передсвята, глас 8-ий: «Всім земнородним..». На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні гласу 8-го. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 8-ий: «Я уподібнився тому...» «Слава і нині» – передсвята, глас 4-ий: «Язик якого не знала...». Далі великопостове закінчення ранньої. Увага! Устав не дає чітких вказівок щодо кондаків на часах і зображальних. Існують різні думки з цього приводу. Будемо використовувати великопісний чин звершення часів і зображальних через вказівки Типікону про спів Алилуйя на ранній і 16 поклонів. На 1-му часі – кафизми 7-ма. По завершенні часу заупокійна літія не звершується. На 3-тьому – кафизма 8-ма. На 6-му – кафизма 9-та. Прокимни та паремія Тріоді. На 9-му – кафизма 10-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак дня. «Слава» – «Зі святими упокой...». «І нині» – кондак передсвята. В храмі Богородиці – кондак дня. «Слава» – «Зі святими упокой...». «І нині» – кондак передсвята. В храмі святого – кондак дня, кондак храму. «Слава» – «Зі святими упокой...». «І нині» – кондак передсвята. Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (в понеділок увечері) – кафизма 11-та. «Господи взиваю» – стихири Тріоді, глас 3-ій – 3 (починаємо від стиха: Коли знемагав дух мій. Стихири містяться в Тріоді в понеділок увечері 5-го тижня) і далі 24 стихири Великого канону (містяться в середу 5 тижня Великого посту). «Слава» – «О невимовне Твоє милосердя...», і нині» – Богородичний Тріоді: «О незбагнене Твоє сходження...». Входу немає. Прокимни і Паремії Тріоді – 2 (з понеділок увечері). На стиховні стихири Тріоді, глас 7-ий, і глас 4-ий. «Слава, і нині» – Богородичний Тріоді, глас то й же: «Від усіх бід...». Закічення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-24","weekday":"вівторок","title":"Передсвято Благовіщення Пресвятої Богородиці. Прп. Захарії, ченця. Свт. Артемія (Артемона), єп. Солунського (Селевкійського, І – ІІ). Прп. Захарії, посника Києво-Печерського, в Дальніх печерах (ХІІІ – ХІV). Прп. Якова, єп. Катанського, спов. (VІІІ – ІХ). Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. XL, 18 – 31. На веч.: Бут. XV, 1 – 15. Притч. XV, 7 – 19. За Уставом (див. Типікон, 26 березня, 7-я Маркова глава), коли свято Благовіщення Пресвятої Богородиці співпадає із середою 5-го тижня Великого посту спів Великого канону прп. Андрія Критського («стояння Марії Єгипетської») переноситься на ранню вівторка 5-го тижня Великого посту. Служба звершується за Тріоддю. Примітка. Служба передсвята Благовіщення переноситься на 23 березня. МАЛЕ ПОВЕЧІР’Я здійснюється напередодні в понеділок увечері без канонів і поклонів. Кондак Тріоді (Великого канону), глас 6-й: «Душе моя, душе моя...». Примітка. «Повечір’я ж промовляємо мале в келіях без поклонів. Після Трисвятого кондак канону Андрія. Так само й полунощницю» (Типікон, гл. 49,«В середу п’ятої седмиці ввечері»). Полуношниця без поклонів. РАННЯ. Священник виголос: «Благословен Бог наш...». Читець [1]: «Амінь», «Слава Тобі, Боже наш, слава Тобі», «Царю Небесний...», Трисвяте. по «Отче наш...» священник – виголос: «Бо ТвоєєЦарство...».Читець:«Амінь»,«Господи,помилуй»(12разів), «Слава, і нині», «Прийдіть, поклонімось...» (тричі) і звичайне двопсалміє. Звершується звичайне кадіння всього храму. Шестипсалміє. Священник з непокритою головою читає ранні молитви Велика ектенія. «Алилуя»» і Троїчний 8-го гласу. Приспів до закінчення першого Троїчного тропаря: «Свят, свят, свят єси, Боже наш, молитвами Предтечі Твого, помилуй нас». Читається 12-та кафизма. Малої ектенії немає. Сідальні Октоїха, глас 8-ий: «Як блудниця припадаю до Тебе...» стих: «Господи не викривай мене» – «Вік мій закінчується...»; стих: «Дивний Бог у святих Своїх, Бог Ізраїлів» – мученичний: «Світилами духовними явилися ви..». «Слава, і нині» – Богородичний, глас той же: «Пречиста Діво, Мати Христова...». І читається перша половина Житія прп. Марії Єгипетської [2]. Читець: «Житіє преподобної матері нашої Марії Єгипетської благослови, чесний отче, прочитати». Священник: «Її ж молитвами, Господи Ісусе Христе, Боже наш, помилуй нас». Читець: «Амінь». І читає житіє. (Якщо читає сам священник, то він спочатку промовляє: «Житіє преподобної матері нашої Марії Єгипетської. – Її ж молитвами, Господи Ісусе Христе, Боже наш, помилуй нас»). Після прочитання першої половини житія – «Господи, помилуй» (тричі), «Слава, і нині» – псалом 50-ий. Примітка. «Також псалом 50-ий. І відразу починаємо великий канон розчуленим співом і благоговійно, творіння святого Андрія Критського, Єрусалимського, глас 6-ий. Ірмос: Помічник і покровитель: по двічі. Потім тропарі, творячи на кожен по 3 поясних поклони, і співаючи: «Помилуй мене, Боже, помилуй мене». І відразу [3] Великий канон прп. Андрія Критського, з додаванням до кожної пісні тропарів канону прп. Марії Єгипетської і по одному тропарю прп. Андрія Критського. На 2-ій, 8-ій і 9-ій піснях – припіснеці Тріоді (див. на ранній вівторка 5-го тижня). Ірмоси Великого канону співаються по двічі на початку пісень, а після 3-ьої, 6-ої, 8-ої і 9-ої пісень – і на катавасію. На 2-ій і 3-ій піснях – по два ірмоси (співаються по разу), на катавасію після 3-ої пісні співається другий ірмос. Ірмоси співаються перед тропарями Великого канону, але не перед трипіснеці, з яких починаються 2-а, 8-а і 9-а пісні [4]. Пісні Священного Писання при співі канонів не промовляються, але до тропарів Великого канону співається приспів: «Помилуй мене, Боже, помилуй мене», до тропарів канону прп. Марії Єгипетської: «Преподобна мати Маріє, моли Бога за нас», до тропарів прп. Андрія Критського: «Преподобний отче Андрію, моли Бога за нас». На закінчення кожної пісні – «Слава», «І нині». До тропарів трипіснеці приспів: «Слава Тобі Боже наш, слава Тобі»; в кінці їх «Слава», «І нині» не читаються (до Троїчних трипіснеців приспів: «Пресвята Тройце, Боже наш, слава Тобі»; до Богородичних трипіснеців приспів: «Пресвята Богородице, спаси нас»). Зазвичай читає тропарі трипіснеця диякон або читець. Після 3-ої пісні і малої ектенії – сідальний Тріоді, глас 3-ій: «Теплотою віри...». (див. Після 2-ої кафизми на ранній вівторка 5-го тижня), «Слава» – інший сідальний Тріоді, глас 2-й: «Препославлена благодать». (див. після 3-ої кафизми на ранній вівторка 5-го тижня), «І нині» – Богородичний Тріоді, глас той же: «Незбориму молитву...». (див. після 3-ої кафизми на ранній вівторка 5-го тижня). Після 6-ої пісні і малої ектенії – кондак Тріоді (Великого канону), глас 6-ий: «Душе моя, душе моя...», та ікос, глас той же. Після синаксарія – блаженні Тріоді (Великого канону), глас 6-ий [5]. На 9-ій пісні співаємо «Чеснішу». Звершується звичайне кадіння всього храму. Після 9-ої пісні і малої ектенії – світильний гласу. Після 1-го виконання Світильного – закінчення: «... молитвами, Господи, Предтечі Твого, і спаси мене». «Слава» – той же світильний, з закінченням: «Молитвами, Господи, святих Твоїх, і спаси мене», «І нині» – знову той же світильний, із закінченням: «Молитвами, Господи, Богородиці, і спаси мене». «Достойно є» зазвичай не співається. «Хваліте Господа з Небес...» і хвалітні псалми. «Слава, і нині», «Тобі слава подобає...», «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. Ектенія прохальна: «Доповнімо ранню молитву...», і голововклонна молитва. Стихири на стиховні Тріоді, глас 7-ий: «Зранену і смиренну душу мою..» (зі звичайними приспівами). «Слава, і нині» – Богородичний Тріоді, глас той же: «Оспівуємо Тебе...». «Благо є» (двічі) [6]. Трисвяте. Після «Отче наш» Священник – виголос: «Бо Твоє є Царство...». Читець: «Амінь». Тропар Часослова: «Стоячи в храмі...». «Господи, помилуй» (40). «Слава, і нині» – «Чеснішу від херувимів...». «Іменем Господнім...». Священник (перед царськими вратами): «Сущий благословенний...». Молитва: «Небесний Царю...». Священник – молитву прп. Єфрема Сиріна з трьома поклонами. Читець: «Амінь», і відразу без відпусту ранньої читається 1-ий час [7]. 1 ЧАС читається без кафизми. Тропар 1-го часу: «Зранку вислухай...» зі стихами промовляється читцем в звичайному порядку, але тільки без співу. Стихи часу: «Стопи мої направ...» і «Нехай сповняться уста мої...» – читаються. Після Трисвятого – кондак Тріоді (Великого канону): «Душе моя, душе моя...». В кінці – молитва прп. Єфрема Сиріна (з трьома великими поклонами). Кінцеве Трисвяте і «Господи, помилуй» (12) не читаються. Безпосередньо після поклонів священик вимовляє молитву: «Христе, Світло Істинне...». За традицією, співається «Непереможній Воєводі...». Відпуст великий і многоліття. Після 1-го часу заупокійної літії немає. НА 3-МУ ЧАСІ – кафизма 13-та. НА 6-МУ ЧАСІ – кафизма 14-та. Прокимни і Паремії 6 часу Тріоді вівторка 5-го тижня. НА 9-МУ ЧАСІ – кафизма 15-та. На всіх часах молитва прп. Єфрема Сиріна з трьома поклонами. Читається кондак Тріоді (Великого канону): «Душе моя...»","sections":[{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ – блаженні швидко, без співу; після «Отче наш...» – кондак Тріоді (Великого канону): «Душе моя, душе моя...». Зображальні слід закінчувати наступним чином: після кондака – читець: «Господи, помилуй» (40), «Слава, і нині» – «Чеснішу від херувимів...». «Іменем Господнім...». Священник: «Боже, змилосердсься...». Читець: «Амінь». Священник – молитву прп. Єфрема Сиріна (з трьома поклонами). Читець: «Амінь». Молитва: «Всесвята Тройце...». Священник (або диякон): «Премудрість». Хор: «Достойно є...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст: «Христос, істинний Бог наш...». Хор: «Господи, помилуй» (тричі). Многоліття за традицією, не співаються."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ – кафизми немає (у великий піст починаємо вечірню Благовіщення без кафизми). На «Господи, взиваю» стихири на 10: Тріоді – 5: самогласний дня, глас 5-ий (один раз), інший самогласний дня, глас 8-ий. – один раз, ці стихири Тріоді див. на стиховні вечірні у вівторок вечора 5-го тижня); і подібні Тріоді, глас той же, і глас 2-ий: «Живоносний Твій Хрест...» (ці стихири Тріоді див. на «Господи, взиваю» вечірні у вівторок вечора 5-го тижня); і стихири свята Благовіщення, глас 4-ий – 5 (див. в службі Мінеї 25 березня); перша стихира – двічі, друга стихира: «З’являєшся до Мене...» (двічі)., третя стихира: «Бог, де хоче, перемагає закон природи..» (один раз). «Слава, і нині» – свята Благовіщення, глас 2-ий: «Посланий був з небес Гавриїл...». Вхід з кадилом. Читання двох паремій Тріоді (за звичаєм) з їх прокимнами, і 3 паремії – Благовіщення (зі звичайними виголосами «Премудрість» і «Будьмо уважні»). Після «Нехай вознесеться молитва моя...» і молитви прп. Єфрема Сиріна (з трьома великими поклонами) – ектенії: «Промовмо всі...», та інша послідовність Літургії Ранішосвячених Дарів (за звичаєм). Заупокійної літії немає. Мала вечірня свята Благовіщення не звершується. Примітка. На трапезі дозволяється вино і олива в який би день заради Пресвятої Богородиці (Типікон) [8]. [1] «Священник... входить у святий вівтар, і взявши кадильницю, промовляє і молитву кадила. І ставши перед престолом, кадить хрестоподібно, і виголошує: Благословенний Бог наш, завжди, нині і повсякчас, і на віки віків. Читець: Амінь. Також поставлений читець читає...» (Типікон, гл. 49, «Початок святого і Великого посту», початок ранньої). [2] Якщо Житіє читається з Четьїх-Міней, то перша половина Житія закінчується словами «... щоб мені одержати яку-небудь милість в День Судний». З нового абзацу, зі слів «Старець із нестримними сльозами...» до кінця, – друга половина Житія. [3] Зазвичай молитва «Спаси, Боже, людей Твоїх...» не промовляється. [4] На думку деяких літургістів ірмоси триспівців вичитуються. На думку свт. Афанасія (Сахарова), в подібних випадках ірмоси взагалі не читаються і не співаються, а наводяться в Тріоді повністю для того, щоб служити в якості подібних для співу наступних тропарів триспівців, оскільки в давнину тропарі канонів співалися на глас і подібні ірмоса; співаються ірмоси лише в тих випадках, коли співаються біблійні пісні або коли на те є спеціальна вказівка Типікону. [5] Спів Блаженних з тропарями є особливістю ранньої четверга Великого канону і утрені Великої П’ятниці (з читанням 12-ти Євангелій), а тому ні в якому разі не повинний пропускатися. [6] Оскільки служба, відповідно до Уставу, завершується швидко, допустимо і одноразове читання «Благо є». [7] У зв’язку з відсутністю в Типіконі певних вказівок про завершення ранньої четверга 5-ої седмиці св. Чотиридесятниці, закінчення ранньої в богослужбових довідниках викладається по-різному. Розбіжності про закінчення ранньої пов’язані з різним тлумаченням слів Уставу про звершення служб четверга 5-ої седмиці швидко. Термін «поскору», що використовується Типіконом також при викладі богослужіння Благовіщення в будній день посту і богослужіння полієлейного святого «в один з днів пісних», стосується таких особливостей: а) скорочення кількості поклонів з молитвою прп. Єфрема Сиріна на ранній, часах і зображальних з 16 до 3; б) скасування кінцевого Трисвятого; в) виконання текстів, які співаються на часах і зображальних «без співу». [8] Типікон 25 березня."}]},
{"date":"03-25","weekday":"середа","title":"БЛАГОВІЩЕННЯ ПРЕСВЯТОЇ ВЛАДИЧИЦІ НАШОЇ БОГОРОДИЦІ І ПРИСНОДІВИ МАРІЇ. Ікони Благовіщення Божої Матері (ХVІ). Літургія за чином свт. Іоана Золотоустого.","readings":["Ран. – Лк., 4 зач., I, 39 – 49, 56."],"notes":"На 6-му часі: Іс. XLI, 4 – 14. На веч.: Бут. XVII, 1 – 9. Притч. XV, 20 – XVI, 9. Благовіщення: Вих. III, 1 – 8. Притч. VIII, 22 – 30. Літ. – Євр., 306 зач., II, 11 – 18. Лк., 3 зач., I, 24 – 38. На трапезі дозволяється риба. Всенічне бдіння на свято Благовіщення складається з великого повечір’я з літією, ранньої та 1-ого часу. За Уставом, богослужіння повинно починатися «1-ої години ночі», за нашим відліком – близько 7 години вечора (див. Типікон, 25 березня). Перед його початком буває благовіст і дзвоніння у всі дзвони. Священики звершують святкове богослужіння в облаченнях блакитного кольору. Відкриваються царські врата. Священник із дияконом цілує престіл. Диякон дає священику кадило, а сам бере дияконську свічку. Священник повній тиші звершує кадіння престолу та вівтаря. Диякон зі свічкою в ріках виходить через царські врата на солію і виголошує «Благослови Владико». Священник одразу виголошує «Благословен Бог наш» (саме такий виголос священика за вказівкою Типікону). Хор «Амінь». Диякон або читець «Слава Тобі Боже». За традицією хор може проспівати «Царю Небесний..» і далі читець читає ВЕЛИКЕ ПОВЕЧІР’Я. Священик із дияконом звершують повне кадіння храму, а по його завершенні закриваються царські врата. Завіса залишається відкритою. На співи «З нами Бог...», тропаря Благовіщення та кондака свята Царські врата відкриваються за традицією. Після 1-го Трисвятого – урочистий спів тропаря свята на глас 4-ий. Після 2-го Трисвятого – кондак свята, гласу 8-го. По завершенні славослів’я – вихід до притвору для звершення літії. На літії хор співає стихири свята глас 1-ий «Слава, і нині» – свята на глас 2-ий «Благовістить Гавриїл...» (стихира, що міститься в Мінеї «на славі» – співатиметься на стиховні ранньої). Ектенії літії. На стиховні стихири свята, глас 4-ий (Зі своїми приспівами). «Слава, і нині» – свята: «Нині радість Благовіщення...». «Нині відпускаєш...». Трисвяте. Після «Отче наш...» (на благословення хлібів) – тропар свята, глас 4-ий (тричі). «Нехай буде ім’я благословенне..» (тричі) та 33 псалом. Після якого священник виголошує «Благословення Господнє на вас...». Хор співає «Слава вишніх Богу...» Закриваються царські врата.","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава, і нині» – той же тропар. Кафизми 16-та, 19-та і 20-та1. Після 1-ої кафизми – малої ектенії немає. Сідальний Тріоді, глас 8-ий: «адам скуштував древо не на добро...» (див. Після 2-ої кафизми). «Слава, і нині» – інший сідальний Тріоді, глас 2-ий: «Оспівуючи Пресвяте древо хресне...» (див. Після 3-ої кафизми). Після 2-ої кафизми – мала ектенія, виголос: «Бо Твоя влада...». Сідальний свята, глас 1-й: «Великий воєвода...». «Слава, і нині» – той же сідальний. Після 3-ої кафизми – мала ектенія, виголос: «Бо Ти благий і Людинолюбний...». Сідальний свята, глас 3-ій: «Сьогодні все творіння радується...». «Слава, і нині» – той же сідальний. Полієлей. Величання свята: «Архангельський глас/ взиваємо Тобі, Чиста: Радуйся, Благодатна, Господь з Тобою», і вибраний псалом. Ектенія мала, виголос: «Бо благословилося ім’я Твоє...». Сідальний свята після полієлею, глас 4-й. «Слава, і нині» – інший сідальний свята, глас той же. Степенна – 1-ий антифон 4-го гласу. Прокимен свята, глас 4-ий: «Благовістіть день у день про спасіння Бога нашого»; стих: «Співайте Господеві пісню нову, співай Господеві, вся земле». Євангеліє свята – Лк., Зач. 4. Після 50-го псалма: «Слава» – «Молитвами Богородиці...», «І нині» – той же стих. Стихира свята, глас 2-ий: «Благовістить Гавриїл Благодатній нині...». Молитва: «Спаси, Боже, людей Твоїх...», «Господи, помилуй» (12). Священник: «Милістю і милосердям...». Хор: «Амінь». Канони: 1-ша, 4-та, 5-та, 6-та і 7-ма пісні – канон свята з ірмосом на 14 (ірмоси по двічі). Катавасія – свята (ірмоси святкового канону). 3-тя, 8-ма і 9-та пісні – канон свята з ірмосом на 6 (ірмоси по двічі) і триспіснеці Тріоді на 8. Катавасія – ірмоси 2-го трипіснеця. Біблійні пісні – «Співаймо Господеві». Примітка. У тих храмах, де припис про поєднання канону зі співом біблійних пророчих пісень неможливо виконати, допустимо стихи з пісень Святого Писання замінювати особливими приспівами. Приспів до тропарів канону свята Благовіщення – «Пресвята Богородице, спаси нас»; або ж в каноні Благовіщення до слів ангела: «Ангел звістив», а до слів Богородиці: «Діва промовила» до тропарів трипіснеців – приспів: «Слава Тобі, Боже наш, слава Тобі» [1]; до Богородичних 1-го трипіснеця – приспів: «Пресвята Богородице, спаси нас»; до передостаннього тропаря в пісні – «Слава» (в 8-ій пісні – «Благословимо Отця, і Сина, і Святого Духа, Господа»), до останнього – «І нині...». Після 3-ої пісні – сідальний свята, глас 8-ий. «Слава, і нині» – інший сідальний свята, глас той же. Після 6-ої пісні – кондак та ікос свята, глас 8-ий. На 9-ій пісні – звичайне кадіння. «Чеснішу» не співаємо, але співаємо приспів свята: «Благовісти, земле, радість велику, хваліть, Небеса, Божу славу» [2]. До тропарів трипіснеців приспів: «Слава Тобі, Боже наш, слава Тобі» [3]; до Богородичних трипіснеців – приспів свята: «Благовісти, земле, радість велику, хваліть небеса Божу славу». В кінці 9-ій пісні: Ірмос 2-го трипіснеця Тріоді; приспів свята: «Благовісти, земле, радість велику...», й ірмос канону свята: «Як до одухотвореного Божого кивоту...». Після 9-ої пісні «Достойно є...» не співається. Світильний свята (двічі). «Слава, і нині» – інший світильний свята. «Все що дише...» [4] і хвалітні псалми. На хвалітніх стихири свята, глас 1-ий – 4. «Слава, і нині» – свята, глас 2-ий: «Одвічне таїнство...». Читець: «Слава Тобі, що показав нам світло» («Тобі слава подобає...» не промовляється), і читається повсякденне славослів’я. Ектенія прохальна: «Доповнімо ранню молитву...», і голововклонна молитва. На стиховні стихири Тріоді, глас 3-й (зі звичайними приспівами; див. Часослов). «Слава, і нині» – свята, глас 8-й: «Нехай веселяться небеса...». «Благо є...» (один раз). Трисвяте. Після «Отче наш» – тропар свята, глас 4-ий (один раз). Ектенія потрійна: «Помилуй нас, Боже...». Священник – виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Примітка. Після виголосу ектенії: «Бо Ти Милостивий...» – звичайний виголос: «Премудрість», хор: «Благослови», Священник: «Сущий благословенний...». Молитва: «Небесний Царю...» або: «Утверди Боже...» [5], після чого – 3 великих поклони з молитвою прп. Єфрема Сирина. Священник – молитву прп. Єфрема Сиріна (з трьома великими поклонами). Читець: «Амінь», і відразу, без відпусту ранньої, читається 1-ий час. НА 1-МУ ЧАСІ – кафизма 1-ша. Тропар і кондак свята. Стихи часу: «Стопи мої направ...» і «Нехай сповняться уста мої...» – читаються [6]. Після виголосу: «Боже, змилосердься над нами...» – молитва прп. Єфрема Сиріна (з трьома великими поклонами). (Кінцеве Трисвяте не промовляється). Безпосередньо після поклонів Священник читає молитву: «Христе, Світло Істинне...». За традицією, співається «Непереможній Воєводі...». Відпуст великий, і многоліття. НА 3-МУ ЧАСІ [7] – кафизма 2-га. НА 6-МУ ЧАСІ – кафизма 3-тя; тропар пророцтва (Тріоді), 1-й прокимен Тріоді, читання паремії Тріоді, 2-й прокимен Тріоді. НА 9 ЧАСІ – кафизма 4-та. На всіх часах – тропар і кондак свята, кінцевий виголос священника – «Боже, змилосердься над нами..», молитва прп. Єфрема Сиріна (з трьома великими поклонами) [8]."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ «У Царстві Твоїм...» [9] та інше читається «швидко» (без співу і без поклонів). Кінцеві молитви зображальних наступні [10] : «Послаб, прости...»; після «Отче наш» – кондак свята, глас 8-ий; «Господи, помилуй» (40), «Слава, і нині»; «Чеснішу від херувимів...», «Іменем Господнім...», виголос: «Боже, змилосердься над нами...», молитва прп. Єфрема Сиріна (з трьома великими поклонами), молитва: «Всесвята Тройце...». священник (або диякон): «Премудрість». Хор: «Достойно є...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священик: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник виголошує відпуст: «Христос, істинний Бог наш...». Хор – «Господи, помилуй» (тричі). Многоліття за традицією не співається. ВЕЧІРНЯ (в поєднанні з Літургією за чином свт. Іоана Золотоустого) відбувається «без кафизми, і без поклонів». Священник у вівтарі, стоячи перед престолом, виголошує: «Благословенне Царство...», при цьому він зазвичай творить Євангелієм хрест над престолом. Хор: «Амінь». Читець: «Прийдіть, поклонімось» (тричі) [11] і Початковий псалом. (Священик читає світильничні молитви). Велика ектенія. Кафизми немає. На «Господи, взиваю» стихири на 11: Тріоді – 5 (по одному разу кожну стихиру, див. Тріодь в середу увечері), і стихири свята Благовіщення – 3, Архангелу – 3. До 11 стихири приспів: «Ти, що твориш духів ангелами своїми, і слугами Своїми вогненне полум’я» і співаємо стихиру: «Будучи сповнений світлом...» «Слава, і нині» – свята, глас 6-ий: «Посланий був Гавриїл...». Під час співу стихир на «Господи, взиваю» завершується проскомидія. На проскомидії заготовлюється Агнець для п’ятниці. Вхід з Євангелієм [12]. «Світло Тихе». Прокимен Тріоді, глас 4-ий: «Боже помсти...» (зі стихом), і 1-а паремія Тріоді; 2-й прокимен Тріоді, глас 4-ий: «Прийдіть у радості заспіваємо...» (зі стихом), і 2-а паремія Тріоді. Потім – читання двох паремій свята (1-а – Виходу читання; 2-а – Притч читання; зі звичайними виголошеннями: «Премудрість» і «Будьмо уважні»). Мала ектенія, виголос: «Бо Ти Святий Боже наш...». Співається Трисвяте, і далі Літургія за чином свт. Іоана Золотоустого. Прокимен, Апостол, алилуарій, Євангеліє і причасний – свята. Задостойник свята – приспів: «Благовісти земле радість велику...» та ірмос: «Як до одухотвореного...». Примітка. На трапезі дозволяється риба. «На трапезі велика утіха для братії: їмо рибу, і п’ємо вино, в який би день не трапилось, один раз вдень, окрім суботи та Неділі» (Типікон, 26 березня, порівн.: Типікон, гл. 33). [1] Порівн.: Типікон, 25 березня. [2] За традицією, 1-й приспів співає священик або диякон. [3] Порівн.: Типікон, 25 березня. [4] Співання «Все що дише...» перед хвалітніми псалмами при читанні на ранній повсякденного славослів’я є особливістю богослужіння свята Благовіщення. [5] Традиція, згідно з якою замість молитви «Небесний Царю...» співається: «Утверди Боже...», є допустимою. [6] Див.: книги про церковний устав. [7] Перед початком часів священнослужителі, за традицією, звершують вхідні молитви, одягаються і починають проскомидію. [8] За Уставом, часи звершуються «без поклонів». Скасування поклонів не поширюється на три поклони з молитвою прп. Єфрема Сиріна, оскільки вчинення цих поклонів в свято вказано на 1-му часі і на зображальних. «В кінці кожного часу по три великих поклони» наказує Типікон і при співпаданні Благовіщення з Понеділком і Вівторком Страсної седмиці, богослужіння яких відбувається за зразком великопосних служб (див. 26 березня, 12-а і 13-а Маркова глава). За Уставом скасування поклонів на постовому богослужінні не стосується поклонів з молитвою прп. Єфрема Сиріна. Наприклад, в день Благовіщення ввечері «повечір’я співаємо мале в притворі швидко, без поклонів і канону, тільки на Слава в вишніх... 3 поклони, і після Трисвятого 3 поклони, і після Чеснішу... 3 великих поклони з молитвою: Господи і Владико... й інші 12-ть, і на останньому Трисвятому 3 поклони, і відпуст» (26 березня, 3-тє «див»). Схожа вказівка є про полуношницю в 1-ий день св. Чотиридесятниці: «співаємо полунощницю без поклонів; тільки після Чеснішу від херувимів... 3 великі поклони, з молитвою Господи і Владико життя мого... Це ж буває тільки в 1-ий день. А в інші дні святого і Великого посту співаємо полунощницю всю з поклонами» (Типікон, гл. 49). [9] зображальні починаються з «У Царстві Твоїм...». [10] Про читання Символу віри на Зображальних Типікон замовчує, однак древні Устави в послідованні Зображальних в свято Благовіщення призначають на «І нині» – «Вірую в єдиного Бога...» [11] Якщо вечірня з Літургією свт. Іоана Золотоустого звершується окремо від часів і Зображальних, то після початкового виголосу «Благословенне Царство...» має читатися звичайний початок: «Слава Тобі, Боже наш, слава Тобі», «Царю Небесний...» та ін. [12] Якщо служать два диякона, то молодший йде першим з кадилом, потім старший диякон з Євангелієм."}]},
{"date":"03-26","weekday":"четвер","title":"Четвер великого канону. Віддання свята Благовіщення Пресвятої Богородиці. Собор архангела Гавриїла. Сщмч. Іринея, єп. Сирійського (304). Мчч. Вафусія і Верка, пресвітерів, Арпили, ченця, мирян Авіва, Агна, Реаса, Ігафракса, Іскоя, Сили, Сигиця, Сонирила, Суимвла, Ферма, Фила та мцц. Анни, Алли, Лариси, Моїко, Маміки, Уїрко, Анімаїси (Анімаїди), Гаафи, цариці Готської, і Дукліди (бл. 375). Прп. Малха Сирійського (ІV). Прп. Василія Нового (бл. 944).","notes":"На 6-му часі: Іс. XLII, 5 – 16. На веч.: Бут. XVIII, 20 – 33. Притч. XVI, 17 – XVII, 17.","sections":[{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в четвер ввечері канони не співають. Оскільки Устав не дає вказівок, що стосуються тропарів і кондаків малого повечір’я в день Благовіщення ввечері, можливі наступні варіанти: 1) Після Трисвятого – кондак Архангела, глас 8-ий (див. 26 березня, після 6-ої пісні канону на ранній). Порівн.: Типікон, 7 січня. 2) Після Трисвятого – кондак Архангела, глас 8-ий (див. 26 березня, після 6-ої пісні канону на ранній). «Слава, і нині» – кондак свята, глас той же. Молитва прп. Єфрема Сиріна з 16 поклонами. ПОЛУНОШНИЦЯ повсякденна – за великопостовим чином."},{"svc":"РАННІЙ","text":"НА РАННІЙ – за великопостовим чином (докладний виклад загального порядку богослужіння див. 23 лютого; особливості його див. 26 лютого). Замість «Бог Господь» – «Алилуя»» на глас Октоїха (8-ий) Троїчних гласу. Кафизми 5-та, 6-та і 7-ма. Малих ектеній немає. Після 1-ої кафизми – сідальні Октоїха з мученичним. Після 2-ої і 3-ої кафизми – сідальні Тріоді четверга 5-то тижня. Псалом 50-ий. Молитва: «Спаси, Боже, людей Твоїх...», «Господи, помилуй» (12), «Милістю і милосердям...». Канони: 1-а, 3-а, 5-а, 6-а і 7-а пісні – канон свята (див. 26 березня), глас 6-ий, зі ірмосом на 6 (за вказівками Мінеї – на 4) і канон Архангела, глас 4-ий, на 6. 4-а, 8-а і 9-а пісні – канони Мінеї (свята і Архангела) на 6 (з ірмосом канону свята) і трипіснеці Тріоді на 8. Біблійні пісні – великопостові. Катавасія: після 3-ої і 6-ої пісні – ірмос канону Архангела; після 4-ої, 8-ої і 9-ої пісні – ірмос 2-го трипіснеця Тріоді. Після 3-ої пісні – сідальний Архангела, глас 4-ий: «Серед безплотних служителів...». «Слава, і нині» – той же сідальний. Після 6-ої пісні – кондак Архангела, глас 8-ий: «Пресвітлої і чесної...». На 9-ій пісні співаємо «Чеснішу». Після 9-ій пісні може співатися «Достойно є». Світильний Троїчний гласу. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Архангела, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята, глас 2-ий: «Благовіствує Гавриїл...». Читець: «Слава Тобі, що показав нам світло» («Тобі слава подобає...» не виголошується), і читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 8-ий: «В розбійницькі пута..»(зі звичайними приспівами). «Слава, і нині» – Богородичний Тріоді, глас той же: «Прийми голоси рабів Твоїх...» (Див. Постова Тріодь в четвер 5-го тижня на ранній). Закінчення ранньої – за великопостовим чином. Часи і зображальні звершуються за великопостовим чином (докладний виклад загального порядку богослужіння див. 23 лютого. Примітка. Устав замовчує про особливості часів і зображальних у віддання Благовіщення в седмичний день св. Чотиридесятниці, кажучи тільки, що «все інше співаємо з поклонами». НА 1-МУ ЧАСІ – кафизма 8-ма. Заупокійної літії немає. НА 3-МУ ЧАСІ – кафизма 9-та. НА 6-МУ ЧАСІ – кафизма 10-та; тропар пророцтва (з Тріоді), 1-ий прокимен Тріоді, читання паремії Тріоді, 2-ий прокимен Тріоді (Див Постова Тріодь в четвер 5-го тижня). НА 9-МУ ЧАСІ – кафизма 11-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: Кондак архангелу, а кондак Благовіщення не читається, оскільки він був відсутній на каноні ранньої."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ – кафизма 12-та. На «Господи, взиваю» на 6: стихири Тріоді на 3: самогласний, глас 8-ий (двічі), мученичний, глас той же: «Мученики Господні...» (один раз), і прп. Матрони (з 27 березня), глас той же –3. «Слава, і нині» – Хрестобогородичний Мінеї, глас 4-ий: «Коли побачила Тебе...» Входу немає. Читання паремій Тріоді (за звичаєм). Стиховні на стихири Тріоді, самогласні, глас 5-ий: «Послизнувся на правій путі...», інша стихира, глас 8-ий: «З Єрусалима...», мученичний «Слава, і нині» – Хрестобогородичний Тріоді: «Господи, сонце, коли побачило Тебе». (Дивись ці стихири на вечірній у вівторок 5-то тижня). Після вечірньої звершується заупокійна літія. Примітка. «На трапезі дозволяється вино і олія». (Типікон, 26 березня). (див.: Типікон, гл. 49, «В п’ятницю 5-го тижня ввечері»)."}]},
{"date":"03-27","weekday":"п’ятниця","title":"Мц. Мотрони Солунської (ІІІ – ІV). Мчч. Мануїла і Феодосія (304). Прп. Іоана, прозорливого, Єгипетського (бл. 395). Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. XLV, 11 – 17. На веч.: Бут. XXII, 1 – 18. Притч. XVII, 17 – XVIII, 5.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї в четвер увечері – канон Богородиці і прп. Іларіона Нового, ігум. Пелікітського (з 28 березня)."},{"svc":"РАННІЙ","text":"НА РАННІЙ – «Алилуя», глас 8-ий з приспівами п’ятниці. Кафизми 13-та. Сідальні Окотоїха (без мученичного). 14-та і 15-та. – сідальні Тріоді. 50 псалом. Молитва «Спаси Боже...». Канони: 1-ша, 3-тя, 4-та, 6-та і 7-ма пісні Мінеї на 4. 5-та, 8-ма і 9-та пісні: Мінеї на 6 (з ірмосом), і трипіснеці Тріоді на 8. Катавасія – 5-та, 8-ма і 9-та – ірмос другого трипіснеця Тріоді; 3-тя і 6-та – ірмос Мінеї. Біблійні пісні: «Господеві співаймо» (постова редакція). Після 3-ої пісні – сідальний мучениці, глас 5-ий: «Благочесно підкорилася...». «Слава, і нині» – Хрестобогородичний Мінеї: «Бачачи Тебе Христе..». Після 6-ої пісні – Мученичний Октоїха: «Світлом небесним» (Дивись в Октоїху сідальний після 2-гої кафизми). Примітка. Перед прочитання мученичного читаємо стих: «Дивний Бог у святих Своїх, Бог Ізраїлів...». На 9-ій пісні співаємо «Чеснішу». Після 9-ій пісні може співатися «Достойно є». Світильний Троїчний гласу. Хвалитні псалми. Читець: «Слава Тобі, що показав нам світло» («Тобі слава подобає...» не виголошується), і читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 8-ий: «В з розбійниками розіп’явся...»(зі звичайними приспівами). «Слава, і нині» – Хрестобогородичний Тріоді, глас той же: «О преславне чудо...». Закінчення ранньої – за великопостовим чином. НА 1-МУ ЧАСІ кафизми немає; Після 1-го часу є заупокійна літія. НА 3-МУ ЧАСІ – кафизма 19-та; НА 6-МУ ЧАСІ – кафизма 20-та; Прокимни і паремія Тріоді. НА 9-МУ ЧАСІ на 9-му часі кафизми немає."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак дня. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Примітка. Якщо денний кондак співпадає з кондаком храму, то він читається лише один раз. Примітка. Кондак мц Матрони Солунської відсутній в Мінеї, його не варто замінювати загальним кондаком мучениці. Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у п’ятницю увечері) – кафизма 18-та. На «Господи взиваю» стихири Тріоді на 10 – самогласний дня, глас 6-ий: «Як від Єрусалиму..» (двічі), мученичний, глас то й же: «Мученики твої Господи...» (один раз), і 7 стихир Похвали Пресвятої Богородиці. «Слава і нині» – Похвали: «Від віку таїнство...» (догматик гласу не співається). Вхід з кадилом. Паремії Тріоді. Далі послідування Літургії Ранішосвячених Дарів. Заупокійної літії немає."}]},
{"date":"03-28","weekday":"субота","title":"Похвала Пресвятої Богородиці (субота акафістна). Прп. Іларіона Нового, ігум. Пелікітського (бл. 754). Прп. Стефана Чудотворця, спов., ігум. Триглійського (бл. 815). Мчч. Іони, Варахисія та ін. з ними (бл. 330). Мч. Бояна, кн. Болгарського (830). Прмч. Євстратія Києво-Печерського, в Ближніх печерах (1097). Літургія за чином свт. Іоана Золотоустого.","readings":["Євр., 322 зач., IX, 24 – 28. Мк., 35 зач., VIII, 27 – 31.","Богородиці: Євр., 320 зач., IX, 1 – 7. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Примітка. Служба прп. Іларіона Нового співалася на Великому повечір’ї у четвер ввечері (див. 26 березня). Служба звершується за Тріоддю. Напередодні в п’ятницю ввечері відбувається мале повечір’я в келіях без канонів і поклонів. Кондак на повечір’ї – Суботи Акафіста, глас 8-ий: «Непереможній Воєводі...». Примітка. «Мале повечір’я і полуношницю співаємо в келіях. Канон Заупокійний гласу співаємо в гробницях» (Типікон, гл. 49, «В п’ятницю 5-го тижня увечері»).","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ Примітка. «До ранньої вдаряють в 4-ій годині ночі, заради молебного Послідування Акафіста» (Типікон, гл. 49, «У суботу 5-ої седмиці посту»). Священник виголос: «Благословенний Бог наш...». Читець [1]: «Амінь», «Слава Тобі, Боже наш, слава Тобі», «Царю Небесний...», Трисвяте. Після «Отче наш...» священник – виголос: «Бо Твоє є Царство...». Читець: «Амінь», «Господи, помилуй» (12 разів), «Слава, і нині», «Прийдіть, поклонімось...» (тричі) і звичайні псалми 19-й та 20-й (під час читання яких звершується кадіння всього храму). Шестипсалміє. (Священник читає ранкові молитви). Велика ектенія. «Бог Господь» на 8-ий глас, повільно, особливим розспівом, і тропар свята Богородиці (Тріоді) [2]: (двічі). «Слава, і нині» – той же тропар. Кафизма 16-та кафизма. Мала ектенія. Після неї протяжно і мелодійно співається кондак Акафіста: «Непереможній Воєводі...». Примітка. Акафіст Божої Матері складається з 12 ікосів і 12 кондаків (всього 24, за кількістю букв грецького алфавіту); після кожного ікосу співається: «Радуйся, Невісто Неневісная», після кожного кондака: «Алилуя»». Акафіст розділяється на чотири частини, по 3 ікоси і 3 кондака в кожній. За усталеною практикою, Акафіст читається священник на середині храму перед іконою Пресвятої Богородиці (якщо є собор священиків, 1-шу і 4-ту частини Акафіста зазвичай читає предстоятель, а 2-гу і 3-тю – інші священики за старшинством). На початку кожної частини Акафіста співається 1-й кондак «Непереможній Воєводі...», при цьому відкриваються царські врата; священнослужителі виходять через царські врата, які залишаються відкритими; після прочитання кожної частини Акафіста священнослужителі йдуть до вівтаря, і царські врата зачиняються. Під час співу 1-го кондака на початку 1-ої і 4-ої частин Акафіста предстоятель в супроводі диякона зі свічкою звершує повне кадіння храму; при співі 1-го кондака на початку 2-ої і 3-ої частин Акафіста звершується мале кадіння (при соборному служінні його звершують інші священики за старшинством, в супроводі диякона, а якщо нема собору священиків, мале кадіння може звершувати диякон). Під час читання акафісту диякон безперервно кадить перед аналоєм з іконою. Примітка. В описі Типікону спів акафісту дещо відрізняється від усталеної практики: перший кондак «Непереможній Воєводі...» співається «на середині» храму, кондаки й ікоси «читаються священником у святому вівтарі», кадіння на «Непереможній Воєводі...» звершує диякон (порівн.: Типікон, гл. 49, «У суботу 5-го тижня посту»). Після співу 1-го кондака «Непереможній Воєводі...» читається 1-ша частина акафісту – з 1-го ікоса по 4-й кондак. Потім знову співається: «Непереможній Воєводі...». Читається 17-та кафизма. Мала ектенія. Співається: «Непереможній Воєводі...». Читається 2-га частина акафісту – з 4-го ікосу по 7-й кондак, знову співається: «Непереможній Воєводі...». «Господи, помилуй» (тричі), «Слава, і нині» – псалом 50-ий. Примітка. У храмі Похвали Богородиці після другого читання ікосів та кондаків співається полієлей, як це зазначено в 49 гл. Типікону («В суботу 5-го тижня посту»). Канони (в 1-ій – 5-ій піснях): У храмі Господському – канон храму з ірмосом на 6 (ірмоси по двічі) і свята Богородиці (Тріоді) на 6. У храмі Богородиці – канон свята Богородиці (Тріоді) з ірмосом на 12 (ірмоси по двічі). У храмі святого [3] – канон свята Богородиці (Тріоді) з ірмосом на 6 (ірмоси по двічі) і храму на 6. Біблійні пісні: «Співаймо Господеві...». Катавасія (в 1-ій – 5-ій піснях): «Відкрию уста мої...» (див. в Тріоді). Після 3-ої пісні і малої ектенії співається кондак «Непереможній Воєводі...». Читається 3-тя частина акафісту – з 7-го ікосу по 10-ий кондак, в кінці знову співається: «Непереможній Воєводі...». Сідальний свята Богородиці (Тріоді), глас 1-ий: «Великий воїн...», «Слава, і нині» – той же сідальний. Починаючи з 6-ої пісні, канон храму не співається, але до канону свята Богородиці (Тріоді) з ірмосом на 6 (ірмоси по двічі) приєднуються два чотирипіснеці Тріоді на 8 [4], на катавасію – ірмос другого чотирипіснеця (див. в Тріоді). Після 6-ої пісні і малої ектенії співається кондак: «Непереможній Воєводі...». Читається 4-а частина акафісту – з 10-го ікосу по 13-ий кондак, причому 13-ий кондак: «О Всехвальная Мати...» співається або читається тричі, після нього знову читається 1-ий ікос: «Ангел предстатель...», і співається 1-ий кондак: «Непереможній Воєводі...», після акафісту читаємо Синаксар, починаючи зі стиха: піснями неусипними дякуємо... На 9-ій пісні співаємо «Чеснішу». (Звершується звичайне кадіння). Після 9-ої пісні «Достойно є» не співається. Мала ектенія. Світильний свята Богородиці з Тріоді (двічі). «Слава, і нині» – той же світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята Богородиці (Тріоді), глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята Богородиці (Тріоді). Велике славослів’я. Після Трисвятого – тропар свята Богородиці (Тріоді), глас 8-й (один раз). Ектенії і відпуст."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята Богородиці (Тріоді). ЛІТУРГІЯ за чином свт. Іоана Золотоустого. Блаженні з канону Акафіста, пісні 3-тя (з ірмосом) і 6-та – 8. Після входу – тропар свята Богородиці (Тріоді). «Слава, і нині» – кондак свята Богородиці (Тріоді). Прокимен, алилуарій і причасний – Богородиці (порівн. в Тріоді). Апостол і Євангеліє – суботи 5-ї седмиці і Богородиці. Примітка. «На трапезі їмо два варення (варена їжа) з олією і п’ємо вино, дякуючи Пресвятій Владичиці нашій Богородиці за чудо, яке було створене Нею» (Типікон, гл. 49, «У суботу 5-го тижня посту»). [1] «І зібравшись до церкви, після благословення священика, починаємо ранню, як і вказано [в четвер п’ятого тижня святого посту]» (Типікон, гл. 49, «У суботу 5-го тижня посту»). [2] «Після шестипсалмія Бог Господь, на глас 8-ий, і співаємо тропарі...» (Типікон, гл. 49, «У суботу 5-го тижня посту»). [3] Порівн.: книги із церковного уставу. [4] Кожен чотирипіснець містить по чотири тропаря; крім того, у другому чотирипіснеці є (після Богородичного) ще два додаткових тропаря, які співаються з особливими приспівами (див. в Тріоді)."}]},
{"date":"03-29","weekday":"неділя","title":"5-та неділя Великого посту. Глас 1-й. Прп. Марії Єгипетської (перехідне святкування в 5-ту неділю Великого посту). Сщмчч. Марка, єп. Арефусійського, Кирила, диякона, та інших багатьох (бл. 364). Прп. Іоана, пустельника (ІV). Свт. Євстафія, спов., єп. Вифинійського (ІХ). Літургія за чином свт. Василія Великого.","glas":1,"readings":["Ран. – Єв. 9-е, Ін., 65 зач., XX, 19 – 31.","Літ. – Євр., 321 зач. (від половини), IX, 11 – 14. Мк., 47 зач., X, 32 – 45.","Прп.: Гал., 208 зач., III, 23 – 29. Лк., 33 зач., VII, 36 – 50."],"notes":"Недільна служба Октоїха звершується зі службою Тріоді. Примітка. Служба свщмчч. Марка, єп. Арефусійського, Кирила, диякона, та інших багатьох буде звершуватися на Малому повечір’ї в неділю увечері. За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню. Мала вечірня служиться лише за Октоїхом.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири, глас 1-ий – 4. (перша стихира – двічі (на початку, та в кінці як четверта). «Слава, і нині» – богородичний (догматик малої вечірньої), глас 1-ий: «Сьогодні браття, торжество дівства! ...» Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. Перша стихира недільна, а інші стихири Пресвятої Богородиці зі своїми приспівами. На стиховні стихири глас 1-ий: «Стражданням Твоїм Христе...» із своїми приспівами. «Слава, і нині» – Богородичний, глас то й же: «Хмарою вічного світла...». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар недільний, глас 1-ий «Хоч камінь запечатали юдеї...» «Слава, і нині» – Богородичний за гласом тропаря: «Коли Гавриїл звістив...». Після співу тропаря з богородичним священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 1-ий – 6, Тріоді (прп. Марії Єгипетської), глас 6-ий – 4 (перша стихира – двічі) . «Слава» – Тріоді (прп. Марії Єгипетської), глас 4-ий: «Сила Хреста Твого Христе...», «І нині» – догматик, глас 1-ий: «Всесвітню славу...». Вхід. Прокимен дня. На літії стихира храму. «Слава, і нині» – Богородичний недільний за гласом стихири храму, зі стиховних. На стиховні стихири недільні, глас 1-ий. «Слава» – Тріоді, прп. Марії Єгипетської, глас 2-ий: «Душевні спокуси і тілесні». «І нині» – богородичний недільний гласу 2-го: «О нове чудо...» (богородчний взятий за гласом «Слави»). Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 1-ий (двічі). «Слава» – Тріоді (прп. Марії Єгипетської) «І нині» – Богородичний недільний, глас той же: «Ти, що заради нас народився...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні Октоїха. Непорочні (див. типікон, гл. 17). «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє недільне 9-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – Тріоді, глас 8-й: «Покаяння відкрий мені двері...», «І нині» – Богородичний Тріоді, глас той же: «На стежки спасіння...». Глас 6-ий: «Помилуй мене, Боже...», і стихира Тріоді, глас той же: «Множество вчинених...». Канони: недільний гласу з ірмосом на 4 (ірмоси раз), Богородиці (Октоїха) на 2, Тріоді – 1-ий (про багатого і Лазаря) на 4 і 2-ий (прп. Марії Єгипетської) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак Тріоді (прп. Марії Єгипетської), глас 3-ий: «Різними гріхами раніше сповнена...», та ікос, глас той же: «Агницю Христову...»; сідальний Тріоді (прп. Марії Єгипетської), глас 8-ий: «Приборкавши всі тілесні похоті подвигом посту...». «Слава, і нині» – Богородичний Тріоді, глас той же: «Прославимо двері небесні і ковчег...». Після 6-ої пісні – кондак та ікос неділі, глас 1-ий. Примітка. Цієї неділі синаксар відсутній, оскільки напередодні звершувалась служба Великого канону. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 9-ий. «Слава» – світильний Тріоді (прп. Марії Єгипетської): «Як образ покаяння...», «І нині» – Богородичний Тріоді: «Насолодо Ангелів...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири неділі, глас 1-ий – 8; потім стих: «Воскресни, Господи, Боже мій...», і самогласний Тріоді, глас 1-ий: «Царство Боже не в їжі й питті...». «Слава» – той же самогласний, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар недільний: «Спасіння світу..». Перед 1-им часом на «Слава, і нині» – стихира євангельська 9-та."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар Тріоді (прп. Марії Єгипетської). Кондаки Тріоді (прп. Марії Єгипетської) і неділі читаються поперемінно. ЛІТУРГІЯ за чином свт. Василія Великого. На проскомидії заготовлюються два Агнці для середи і п’ятниці – Літургій Ранішосвячених Дарів за уставом. Блаженні гласу 1-го – 8. Після входу – тропарі і кондаки: У храмі Господському – тропар недільний, тропар Тріоді (прп. Марії Єгипетської). «Слава» – кондак Тріоді (прп. Марії Єгипетської), «І нині» – кондак недільний. У храмі Богородиці – тропар недільний, тропар храму, тропар Тріоді (прп. Марії Єгипетської); кондак недільний, «Слава» – кондак Тріоді (прп. Марії Єгипетської), «І нині» – кондак храму. У храмі святого – тропар недільний, тропар храму, тропар Тріоді (прп. Марії Єгипетської); кондак недільний, кондак храму. «Слава» – кондак Тріоді (прп. Марії Єгипетської), «І нині» – «Заступнице християн...». Прокимен – недільний рядового гласу (зі стихом), і прп. Марії Єгипетської, глас 4-й: «Дивний Бог у святих Своїх...». Апостол і Євангеліє – Неділі 5-ої Великого посту і прп. Марії Єгипетської. Алилуарій – недільний рядового гласу (на підставі спільного уставу, може бути ще другий алилуарій – преподобних жон загальний, глас 1-й: «Терплячи, надіявся я на Господа, і Він зглянувся на мене, і вислухав молитву мою») Замість «Достойно є...» – «Тобою радується...». Причасний – недільний: «Хваліть Господа...», і прп. Марії Єгипетської: «В пам’ять вічну...». Примітка. «На трапезі ж споживають ті ж продукти, що й в попередню Неділю» (Типікон, гл. 49, «В Неділю 5-ту святого посту»)."}]},
{"date":"03-30","weekday":"понеділок","title":"6-й тиждень Великого посту (вербний тиждень). Прп. Іоана Ліствичника (649). Прор. Іоада (Х ст. до Р. Х.). Апп. Сосфена, Аполоса, Кифи, Кесаря і Епафродита. Св. Євули, матері вмч. Пантелеймона (бл. 303). Прп. Іоана, безмовника (VІ). Прп. Зосими, єп. Сиракузького (бл. 662). Свт. Софронія (Кришталевського), єп. Іркутського (1771).","notes":"На 6-му часі: Іс. XLVIII, 17 – XLIX, 4. На веч.: Бут. XXVII, 1 – 41. Притч. XIX, 16 – 25.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ. Дивись зразок звершення вечірньої 22 лютого. Кафизми немає. На «Господи, взиваю» стихири на 10: 4 стихири покаянні Октоїха, глас 1-ий (дві – зі стихир на стиховні вечора, дві інші – зі стиховних стихир ранньої), Тріоді, глас 1-ий – 3, і стихири прп. Іоана, глас 8-ий – 3. «Слава» – прп. Іоана, глас 6-ий: «Преподобний отче..», «І нині» – Богородичний Мінеї, глас той же: «Безнадійним відома надія...». Вхід з кадилом. «Світло Тихе». Співається великий прокимен, глас 8-ий: «Дав єси насліддя...», зі стихами (за звичаєм). Під час читання «Сподоби Господи...» священник облачається в облачення багряного (сучасній практиці – чорного) кольору. На стиховні стихири Тріоді, глас 1-ий «Слава» – преподобного, глас 8-ий: «Ченців безліч...», «І нині» – Богородичний Тріоді, глас 1-ий:«Небесних чинів...». Молитва прп. Єфрема Сиріна читається із трьома великими поклонами (без малих). Закінчення вечірні великопостове (22 лютого). Після вечірні заупокійної літії немає."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї в неділю ввечері співається служба свщмчч. Марка, єп. Арефусійського, Кирила, диякона, та інших багатьох (з 29 березня). Примітка. З благословення настоятеля можна ще співати додатково службу Стрітення Пресвятої Владичиці нашої Богородиці і Приснодіви Марії і святої праведної Єлисавети, матері святого Іоана Предтечі (служба знаходиться в мінеї за березень, 30 день). Примітка. Канон Богородиці на повечір’ї в неділю ввечері не співається, оскільки напередодні звершувалося всенічне бдіння."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 1-ий з приспівами понеділка. Кафизми 4-та, 5-та, 6-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. 50 псалом. Молитва: «Спаси Боже...» Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. 3-тя, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 1-ша, 8-ма, 9-та – ірмос другого трипіснеця Тріоді. 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Кондак, глас 1-ий: «Присносущі плоди...», сідальний, глас 8-ий: «Видіннями і діяннями наприродно засяяв..» «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – кондак преподобного, глас 4-ий: «На висоті істинного стримання...» та ікос. На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 5-ий: «Не засуди мене Христе...» «Слава і нині» – Богородичний Тріоді: «Обрадувана, Твоїми молитвами заступи...». Далі великопостове закінчення ранньої. На 1-му часі – кафизми немає. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 7-ма. На 6-му – кафизма 8-ма. Прокимни та паремія Тріоді. На 9-му – кафизма 9-та. Якщо Євангеліє читається лише на 6-му тижні, то буде наступний порядок читання Євангелія на великопостових часах лише на 6-ому тижні: Пн. 3-ій час – Мф., Зач. 1 – 17 (1, 1 – 6, 21). 6-ий час – Мф., Зач. 18 – 42 (6, 22 – 11, 26). 9-ий час – Мф., Зач. 43 – 66 (11, 27 – 16, 12). Вт. 3-ій час – Мф., Зач. 67 – 83 (16, 13 – 21, 17). 6-ий час – Мф., Зач. 84 – 105 (21, 18 – 25, 30). 9-ий час – Мф., Зач. 106 – 116 (25, 31 – 28, 20). Сер. 3-ій час – Мк., Зач. 1 – 25 (1, 1 – 6, 45). 6-ий час – Мк., Зач. 26 – 51 (6, 45 – 11, 26). 9-ий час – Мк., Зач. 52 – 71 (11, 27 – 16, 20). Чт. 3-ій час – Лк., Зач. 1 – 16 (1, 1 – 4, 44). 6-ий час – Лк., Зач. 17 – 38 (5, 1 – 8, 39). 9-ий час – Лк., Зач. 39 – 62 (8, 40 – 12, 1). Пт. 3-ій час – Лк., Зач. 63 – 82 (12, 2 – 16, 18). 6-ий час – Лк., Зач. 83 – 105 (16, 19 – 21, 11). 9-ий час – Лк., Зач. 106 – 114 (21, 12 – 24, 53)."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня, кондак преподобного Іоана інший кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..» В храмі Богородиці – кондак дня, кондак преподобного Іоана, інший кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак преподобного Іоана, інший кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Примітка. Служба преподобного Іоана має два кондаки. Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (в понеділок увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 6-ий, і глас 5-ий – 3, Мінеї – прп. Іпатія, глас 8-ий – 3 (з 31 березня). «Слава, і нині» – Богородичний Мінеї: «Дівства сосуд...». Входу немає. Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 4-ий. «Слава, і нині» – Богородичний Тріоді, глас то й же: «Визволи нас від бід наших...». Закічення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"03-31","weekday":"вівторок","title":"Сщмч. Іпатія, єп. Гангрського (бл. 326). Прп. Іпатія, цілителя Києво-Печерського, в Дальніх печерах (ХІV). Прп. Аполонія Єгипетського (ІV). Сщмчч. Авди, єп. Перського, і Веніаміна, диякона (418 – 424). Прп. Іпатія, ігумена в Руфіянах (бл. 446). Прмц. Марії Паризької (1945).","notes":"На 6-му часі: Іс. XLIX, 6 – 10. На веч.: Бут. XXXI, 3 – 16. Притч. XXI, 3 – 21.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у понеділок ввечері – канон Богородиці і мцц. Агафії, Ірини та Хіонії (з 16 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 1-ий з приспівами вівторка. Кафизми 10-та, 11-та, 12-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. 50 псалом. Молитва: «Спаси Боже...» Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 2 пісня тільки з Тріоді на 8. 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 2-га, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 1-ий: «Засяяв ти..». «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – кондак, глас 2-ий: «Римської вітчизни світильник..». На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 5-ий: «Послизнувшись на провинах...» «Слава, і нині» – Богородичний Тріоді: «Тобі молимось...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 13-та. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 14-та. На 6-му – кафизма 15-та. Прокимни та паремія Тріоді. На 9-му – кафизма 16-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня кондак священномученика. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». В храмі Богородиці – кондак дня, кондак священномученика. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у вівторок увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 2-ий, глас 3-ій. – 3 і Мінеї, глас 6-ий (прп. Марії Єгипетської з 1 квітня). «Слава» – преподобної, глас 2-ий: «Душевні спокуси...», «І нині» – Хрестобогородичний Мінеї: «Бачачи Тебе Ісусе..». Входу немає. Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 1-ий. «Слава, і нині» – Хрестобогородичний Тріоді, глас то й же: «Меч пройняв серце моє...». Закінчення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"04-01","weekday":"середа","title":"Прп. Марії Єгипетської (522). Прп. Геронтія, канонарха Києво-Печерського, в Дальніх печерах (ХІV). Прп. Макарія, ігумена Пелікитської обителі (бл. 830). Мчч. Геронтія і Василіда (ІІІ). Прав. Ахаза. Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. LVIII, 1 – 11. На веч.: Бут. XLIII, 26 – 31; XLV, 1 – 16. Притч. XXI, 23 – XXII, 4.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у вівторок ввечері – канон Богородиці і служба свящмч. Симеона Перського (з 17 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 1-ий з приспівами середи. Кафизми 19-та, 20-та і 1-ша. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 4-та, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 3-тя, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 3-тя, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 6-та – ірмос канону Мінеї. Після 3-тої пісні – кондак, глас 3-ій: «Раніше переповнена всяким блудом..». Сідальний, глас 8-ий: «Всі плотські загравання..» «Слава, і нині» – Хрестобогородичний Мінеї, глас то й же: «Бачачи на Хресті...». Після 6-тої – Кондак преподобної, глас 4: «Імли гріха уникнувши...» та ікос. На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Троїчні (Октоїха). Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 1-ий: «Ізраїль одягався в порфиру..» «Слава і нині» – Хрестобогородичний Тріоді: «Коли побачила Тебе Христе...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 2-га. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 3-тя. На 6-му – кафизма 4-та. Прокимни та паремія Тріоді. На 9-му – кафизма 5-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак дня, кондак преподобної, інший кондак преподобної. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». В храмі Богородиці – кондак дня, кондак преподобної, інший кондак преподобної. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак преподобної, інший кондак преподобної. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн...». Примітка. Служба прп. Марії має два кондаки. Твориться відпуст зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у середу увечері) – кафизма 18-та. «Господи взиваю» – стихири на 10: Тріоді, глас 1-ий, глас 5-ий, глас 6-ий – 6 (самогласна стихира двічі), Мінеї – преподобного Тита, глас 8-ий – 4 (з 2 квітня), перша стихира мученику співається двічі. «Слава, і нині» – Богородичний Мінеї: «Помисли нечисті...». Вхід з кадилом. «Світе Тихий». Паремії Тріоді – 2. Далі продовження Літургії Ранішосвячених Дарів. Детальний виклад порядку вечірні в поєднанні з Літургією Ранішосвячених Дарів див. 25 лютого. Після Літургії заупокійної літії немає."}]},
{"date":"04-02","weekday":"четвер","title":"Прп. Тита, чудотворця (ІХ). Мчч. Амфіана і Едесія (306). Мч. Полікарпа Олександрійського (ІV).","notes":"На 6-му часі: Іс. LXV, 8 – 16. На веч.: Бут. XLVI, 1 – 7. Притч. XXIII, 15 – XXIV, 5.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї у середу ввечері – канон Богородиці і прп. Іоана, учня прп. Григорія Декаполіта (з 18 квітня). Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 1-ий з приспівами четверга. Кафизми 6-та, 7-ма, 8-ма. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. Канони: 1-ша, 3-тя, 5-та, 6-та, 7-ма пісні: Мінеї на 4. 4-та, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія – 4-та, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 1-ий: «Постившись на землі...» «Слава, і нині» – Богородичний Мінеї, глас то й же. Після 6-тої – кондак преподобного, глас 4-ий: «Суєтне житіє...». На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Октоїха. Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 5-ий: «Прийдіть вся братіє...» «Слава і нині» – Богородичний Тріоді: «Наперед обрана з усіх родів...». Далі великопостове закінчення ранньої. На 1-му часі – кафизма 9-та. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 10-та. На 6-му – кафизма 11-та. Прокимни та паремія Тріоді. На 9-му – кафизма 12-та."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак храму, кондак дня, інший кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». В храмі Богородиці – кондак дня, інший кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, інший кондак дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Примітка. Якщо денний кондак співпадає з кондаком храму, то він читається лише один раз. Одразу після зображальних починається вечірня, без відпусту зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у четвер увечері) – кафизма 18-та. «Господи взиваю» – стихири на 6: Тріоді, глас 4-ий і глас 8-ий. – 3, Мінеї – преподобного, глас 2-ий – 3 (з 3 квітня). «Слава, і нині» – Хрестобогородичний Мінеї: «Коли непорочна Агниця побачила Свого Агнця...». Входу немає. Паремії Тріоді – 2. На стиховні стихири Тріоді, глас 8-ий. «Слава і нині» – Хрестобогородичний Тріоді, глас то й же.: «О преславне чудо...» Закінчення вечірньої – великопостове. Після відпусту вечірньої звершується заупокійна літія."}]},
{"date":"04-03","weekday":"п’ятниця","title":"Прп. Микити, сповідника, ігум. обителі Мидикійської (824). Мц. Феодосії, діви (307 – 308). Прп. Ілірика. Мчч. Елпідофора, Дія, Віфонія і Галика. Ікони Божої Матері «Нев’янучий цвіт». Літургія Ранішосвячених Дарів.","notes":"На 6-му часі: Іс. XLVI, 10 – 24. На веч.: Бут. XLIX, 33 – L, 26. Притч. XXXI, 8 – 32.","sections":[{"svc":"ВЕЛИКОМУ ПОВЕЧІР’Ї","text":"НА ВЕЛИКОМУ ПОВЕЧІР’Ї в четвер увечері – канон Богородиці і служба прп. Іоана Давньопечерника (з 19 квітня). Примітка. Сьогодні завершується спів служб, пам’ять яких припадала від суботи праведного Лазаря до неділі Антипасхи, що відправлялись на повечір’ях, починаючи із 2-го тижня Великого посту. Полуношниця, рання та часи із зображальними. Детальний виклад загального порядку богослужіння та його особливості його див. в схемах першого тижня Великого посту."},{"svc":"РАННІЙ","text":"НА РАННІЙ «Алилуя», глас 1-ий з приспівами п’ятниці. Кафизми 13-та, 14-та і 15-та. Після першої кафизми – сідальні Октоїха з мученичним. Після 2-гої і 3-ьої – сідальні Тріоді. Примітка. Для зручності виконання канонів з біблійними піснями бажано використовувати книгу «Перший тиждень посту», змінюючи лише тропарі Тріоді та Мінеї відповідного дня. 50 псалом. Молитва «Спаси Боже...». Канони: 1-ша, 3-тя, 4-та, 6-та, 7-ма пісні: Мінеї на 4. 5-та, 8-ма і 9-та – Мінеї на 6 (з іромосом), і трипіснеці Тріоді на 8. Біблійні пісні «Господеві співаємо» (великопостова редакція). Катавасія –5-та, 8-ма, 9-та – ірмос другого трипіснеця Тріоді, а 3-тя і 6-та – ірмос канону Мінеї. Після 3-тої пісні – Сідальний, глас 4-ий: «Оселився ти в горах у безмовності...» «Слава, і нині» – Хрестобогородичний Мінеї, глас то й же: «Діво Пренепорочна...». Після 6-тої – кондак преподобного, глас 2-ий: «Придбавши небесний розум...». На 9-тій пісні співаємо «Чеснішу». Після 9-тої пісні – «Достойно є». Світильні Октоїха Хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 1-ий: «Зневаживши душе моя...» «Слава і нині» – Хрестобогородичний Тріоді: «Душе корисний завершуючи піст...». Далі великопостове закінчення ранньої. На 1-му часі – кафизми немає. По завершенні часу служиться заупокійна літія. На 3-тьому – кафизма 19-тя. На 6-му – кафизма 20-та. Прокимни та паремія Тріоді. На 9-му – кафизми немає."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ: В храмі Господському – кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». В храмі Богородиці – кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – кондак храму. В храмі святого – кондак дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...». «І нині» – «Заступництво християн..». Твориться відпуст зображальних."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ (у п’ятницю увечері) – кафизма 18-та. «Господи взиваю» – стихири Тріоді, глас 8-ий, глас 6-ий на 10. «Слава» – Тріоді, глас 8-ий: «Прийшовши до гробу Лазаря..». «І нині» – Тріоді: «Душе корисний великий піст завершуючи...» (догматик гласу не співається). Вхід з кадилом. «Світе Тихий. Читання паремій Тріоді (прокимен 1-ий паремії, глас 6-ий: «Поміч наша...», зі стихом; прокимен 2-ий паремії, глас 4-ий: «Ті, що надіються на Господа...», зі стихом). «Нехай вознесеться молитва моя...», Далі продовження Літургії Ранішосвячених Дарів. Детальний виклад порядку вечірні в поєднанні з Літургією Ранішосвячених Дарів див. 25 лютого. Після Літургії заупокійної літії немає. Примітка. «Нехай буде відомо: що від цього дня, ні мученичний, ані Богородичний, ані Октоїха не співається, аж до понеділка святого Фоми» (Типікон, гл. 49, «В п’ятницю Квітну ввечері», 2-е «див»)."}]},
{"date":"04-04","weekday":"субота","title":"Лазарева субота. Воскрешення прав. Лазаря. Прп. Йосифа Піснеписця (883). Прп. Георгія, що в Малеї (ІХ). Прп. Йосифа Багатохворобливого, Києво-Печерського, в Дальніх печерах (ХІV). Прп. Зосими (бл. 560). Мцц. Фервуфи, діви, сестри та рабині її (341 – 343). Ікони Божої Матері, званої «Герондиса». Літургія за чином свт. Іоана Золотоустого.","readings":["Євр., 333 зач. (від половини), XII, 28 – XIII, 8. Ін., 39 зач., XI, 1 – 45."],"notes":"Служба тільки за Тріоддю. Примітка. З цього дня Мінея не використовується до понеділка Фоминої седмиці, крім служб великих святих. Напередодні в п’ятницю ввечері звершується ВЕЛИКЕ ПОВЕЧІР’Я (без поклонів), на якому співаємо канон прп. Андрія Критського, глас 1-ий: «Пісню переможну співаємо всі Богові...» (з Тріоді). Замість «Достойно» – ірмос 9-ї пісні: «Створи державу силою Своєю...». Після 1-ого Трисвятого – тропар Тріоді, глас 1-й: «Загальне воскресіння...». Після 2-ого Трисвятого – тропарі звичайні, глас 6-й: «Помилуй нас, Господи, помилуй нас...». Після 3-ого Трисвятого – кондак Тріоді, глас 2-й: «Радість усіх – Христос...». Відпуст малий.","sections":[{"svc":"ПОЛУНОШНИЦІ","text":"НА ПОЛУНОШНИЦІ після 1-го Трисвятого – тропар Тріоді, глас 1-ий: «Загальне воскресіння...». Після 2-го Трисвятого – кондак Тріоді, глас 2-ий: «Радість усіх – Христос...», «Господи, помилуй» (12), і відпуст (заупокійна молитва «Пом’яни, Господи...» не промовляється)."},{"svc":"РАННІЙ","text":"НА РАННІЙ[1] на «Бог Господь» – тропар Тріоді, глас 1-ий: «Загальне воскресіння...» (двічі). «Слава, і нині» – той же тропар. Кафизми 16-та і 17-та [2]. Після 16-ої кафизми і малої ектенії – сідальний Тріоді, глас 1-ий: «Змилосердившись над сльозами Марфи і Марії...». «Слава, і нині» – той же сідальний. Після 17-й кафизми – тропарі воскресні, глас 5-ий: «Ангельський собор...». Ектенія мала. Сідальний Тріоді, глас 5-ий: «Джерело премудрості...». «Слава, і нині» – той же сідальний. «Воскресіння Христове бачивши...». Псалом 50-ий [3]. До 6-ої пісні співаються два канони Тріоді: 1-ий (творіння прп. Феофана), глас 8-ий, зі ірмосом на 8 (ірмоси по двічі) і 2-ий (творіння прп. Іоана), глас той же, на 6. Біблійні пісні «Співаймо Господеві...». Катавасія Тріоді: «Воду пройшовши...». Після 3-ої пісні – сідальний Тріоді, глас 4-ий: «Разом стали перед Христом...». «Слава, і нині» – сідальний Тріоді, глас 8-ий: «Провидче усього...». З 6-ої пісні співаються два чотириспівця Тріоді (на ряду): 1-ий (творіння прп. Косми), глас 8-ий, з ірмосом на 8 (ірмоси по двічі) і 2-ий (творіння прп. Іоана), глас той же, на 6. Катавасія – ірмоси 2-го чотириспівця Тріоді, глас 8-ий. Після 6-ої пісні – кондак Тріоді, глас 2-ий: «Радість усіх – Христос...». Ікос, глас той же: «Сотворитель усього провістив ученикам...». Читаємо синаксар: Стихи: Ти плачеш, Ісусе, – це від людської природи, А товариша воскрешаєш – Божественною (Твоєю) силою... На 9-й пісні – звичайне кадіння. «Чеснішу» не співаємо. Примітка. Від цього дня і до Неділі Антипасхи включно на 9-ій пісні канону «Чеснішу» не співаємо (див.: Типікон, гл. 49, «У суботу святого і праведного Лазаря», 1-е «див»). Звершується кадіння храму на 9-ій пісні. Після 9-ої пісні, на 1-й глас – «Свят Господь Бог наш» (зі звичайними стихами; тричі). («Достойно є» не співається). Світильний Тріоді: «Словом Твоїм...» (двічі). «Слава, і нині» – інший світильний Тріоді: «Лазарем тебе Христос...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: Тріоді, глас 1-ий і глас 4-ий – 6; також приспів: «Воскресни, Господи, Боже мій, і нехай піднесеться рука Твоя», і стихира Тріоді, глас 8-й: «Лазаря померлого у Віфанії...»; інший приспів: «Славитиму Тебе, Господи, всім серцем моїм, розповідатиму про всі чудеса Твої», і стихира Тріоді, глас той же: «Як сказав Ти, Господи...». «Слава» – Тріоді, глас 2-ий: «Велике і преславне чудо...», «І нині» – «Преблагословенна єси...». Примітка. Перші шість стихир співаються з стихами хвалітніх псалмів, а останні дві – з додатковими воскресними стихами: 1-ий – «Воскресни, Господи Боже мій, нехай піднесеться рука Твоя,/ Не забудь убогих Твоїх до кінця»; 2-ий – «Прославлятиму Тебе, Господи, всім серцем моїм,/ розповім про всі чудеса Твої». Велике славослів’я. Після Трисвятого – тропар Тріоді, глас 1-ий: «Загальне воскресіння...» (один раз). Ектенії і відпуст. Примітка. Відпуст утрені і Літургії: «Христос, істинний Бог наш...» зі згадуванням імені св. прав. Лазаря Чотириденного, єп. Китійського."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Тріоді. ЛІТУРГІЯ за чином свт. Іоана Золотоустого. Блаженні з канону свята, пісні 3-тя (з ірмосом) і 6-а – 8. На вході – «Прийдіть поклонімось... Дивний у святих єси...». Після входу – тропар Тріоді, глас 1-ий: «Загальне воскресіння...». «Слава, і нині» – кондак Тріоді, глас 2-ий: «Всіх Радість – Христос...». Замість Трисвятого – «Усі ті, що в Христа хрестилися...». Прокимен, глас 3-ій: «Господь – Просвічення моє...»; стих: «Господь – оборонець життя мого...». Алилуарій, глас 5-ий: «Господь воцарився, у красу зодягнувся»; стих: «Бо Він утвердив вселену...». Апостол і Євангеліє – суботи Лазаревої. Може співатися задостойник «Чисту Богородицю, що непорочно прийняла вогонь Божества в утробу, славно шануємо, люди, в піснях величаючи.» [4]. Причасний: «Із уст дітей і немовлят вчинив єси хвалу (Пс. 8, 3)». Після «Спаси, Боже, людей Твоїх...» співаємо: «Ми бачили Світло Істинне...». Примітка. На трапезі дозволяється споживання рибної ікри: «На трапезі дозволяється варення (варена їжа) з олією. Якщо ж маємо й ікру, то дається кожному брату по три онгії [5]: і вино п’ємо» (Типікон, гл. 49, «У суботу святого і праведного Лазаря»). [1] У богослужінні Лазаревої суботи присутні особливості, характерні тільки для цього дня. [2] Відразу після закінчення 17-ої кафизми співаються тропарі: «Ангельський собор»; Священник кадить весь храм, починаючи з вівтаря, при закритих царських вратах. [3] В храмі прав. Лазаря співається полієлей (порівн.: Типікон, гл. 49, «У суботу святого і праведного Лазаря», 2-е «зри»). [4] У сучасній редакції Типікон про Задостойник на цей день нічого не говориться, але в стародруку редакції Уставу зазначено співати задостойник «Чисту Богородицю, що непорочно прийняла вогонь Божества в утробу, славно шануємо, люди, в піснях величаючи». [5] Одна онгія дорівнює 1/12 фунта (приблизно 34 грама)."}]},
{"date":"04-05","weekday":"неділя","title":"Неділя 6-та Великого посту, ваїй, цвітоносна, вербна. ВХІД ГОСПОДНІЙ В ЄРУСАЛИМ. Сщмч. Агафопода, диякона, мчч. Феодуа, читця, та інших з ними (бл. 303). Прп. Пуплія Єгипетського (ІV). Прпп. Феони, Симеона і Форвина (ІV). Прп. Марка Афінського (400). Прп. Платона, спов., Студійського (814). Прп. Феодори Солунської (892). Літургія за чином свт. Іоана Золотоустого.","readings":["Ран. – Мф., 83 зач., XXI, 1 – 11, 15 – 17.","Літ. – Флп., 247 зач., IV, 4 – 9. Ін., 41 зач., XII, 1 – 18."],"notes":"Примітка. Якщо храмове свято, припаде на Страсному тижні до Великої П’ятниці, переноситься на Вербну Неділю, а якщо в П’ятницю або в Суботу Страсного тижня, або в день Пасхи, то переноситься на понеділок або вівторок Світлої седмиці (порівн.: Типікон, храмові глави 45 і 46). Служба лише свята Входу Господнього. Примітка. Недільні піснепіви («Ангельський собор...», «Воскресіння Христове бачивши...»), не співаються. За уставом перед Всенічною необхідно звершувати 9-тий час і малу вечірню. Мала вечірня служиться лише за Тріоддю.","sections":[{"svc":"МАЛІЙ ВЕЧІРНІ","text":"НА МАЛІЙ ВЕЧІРНІ завіса царських врат не відкривається. За Типіконом малу вечірню звершує лише священик без диякона. Священник в єпитрахилі розпочинає служити малу вечірню перед царськими вратами виголосом: «Благословен Бог наш...». Читець: Амінь. «Прийдіть поклонімось...» (тричі) і читає 103 псалом «Благослови душе моя Господа» (світильничі молитви священиком не читаються). По закінченню псалма: «Слава, і нині». Алилуя, Алилуя, Алилуя, слава Тобі, Боже (тричі). Господи, помилуй (тричі), «Слава, і нині». Одразу співають «Господи взиваю...» (Не виголошується велика ектенія, кафизми і малої ектенії після неї не буває. Стихи псалмів 140, 141 і 129 опускаються. Кадіння на «Господи взиваю» не звершується). На «Господи взиваю» стихири, глас 6-ий – 4. «Слава, і нині» – Тріоді, глас 6-ий: «То й, що на херувимах...» Входу немає. Читець читає «Світе Тихий...» Священик: «Будьмо уважні». «Мир усім». «Премудрість» і прокимен дня: «Господь воцарився...» Після співу прокимна читається «Сподоби Господи...», і одразу без благальної ектенії співають на стиховні стихири. На стиховні стихири Тріоді, глас 2-ий: «Світися Сионе...» із своїми приспівами. «Слава, і нині» – Тріоді, глас то й же: «Оспівую зі страхом Твоє всевідання...». Далі читається «Нині відпускаєш...», Трисвяте по Отче наш. Священник «Бо Твоє є Царство...» Хор: «Амінь» і співає тропар, глас 1-ий «Загальне воскресіння...» «Слава, і нині» – тропар, глас 4-ий: «З тобою через хрещення поховані...». Після співу тропарів священник перед закритими царськими вратами виголошує коротку потрійну ектенію: «Помилуй нас Боже...» (чотири прохання). Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі). «Благослови». Священник: Христос, що заради нас сів на осля, істинний Бог наш, молитвами Пречистої Своєї Матері, преподобних і богоносних отців наших, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний. Хор: «Амінь» і далі співає многоліття. Примітка. Після відпусту малої вечірньої в монастирях відбувається вечірня трапеза. Опісля розпочинається Велика вечірня."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири Тріоді, глас 6-ий – 10 (кожна стихира – двічі). «Слава» – Тріоді, глас той же: «Нині благодать Святого Духа...», «І нині» – та ж стихира. Вхід. Прокимен дня. Паремії свята – 3. На літії стихири Тріоді, глас 1-ий і глас 2-ий. «Слава, і нині» – Тріоді, глас 3-ій: «За шість днів до Пасхи...». На стиховні стихири Тріоді, глас 8-ий (зі своїми приспівами). «Слава» – Тріоді, глас 6-ий: «Нині благодать Святого Духа...», «І нині» – та ж стихира. Після Трисвятого – тропар свята, глас 1-ий: «Загальне воскресіння...» (двічі), і інший тропар свята, глас 4-ий: «З Тобою через хрещення...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий: «Загальне воскресіння...» (двічі). «Слава, і нині» – інший тропар свята, глас 4-ий: «З Тобою через хрещення...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні Тріоді. Полієлей. Величання свята: «Величаємо Тебе, Життєдавче Христе, осанна в вишніх, і ми співаємо Тобі: Благословен, Хто йде в ім’я Господнє», і вибраний псалом. Сідальний Тріоді після полієлею, глас 8-ий: «Той, Хто на престолі Херувимському...». «Слава, і нині» – той же сідальний. Степенна – 1-ий антифон 4-го гласу. Прокимен свята, глас 4-ий: «Із уст дітей і немовлят вчинив єси хвалу»; стих: «Господи Боже наш, яке величне ім’я Твоє по всій землі». Євангеліє – свята (Мф., 83 зач.). («Воскресіння Христове бачивши...» не співається). Псалом 50-ий. Під час 50-го псалма «священник взявши кадило, кадить хрестоподібно» приготовлені заздалегідь віття. Диякон: «Господу помолимось». Хор: «Господи, помилуй». Священник читає молитву на благословення верби: «Господи Боже наш, що сидиш на Херувимах...». Після молитви священник окроплює віття святою водою [1] з виголошенням слів: «освячуються віття ці, окропленням води цієї свяченої, в ім’я Отця і Сина і Святого Духа. Амінь»(тричі), а потім, на єлеопомазанні, роздає віття верби народу. «Слава» – глас 2-ий: «Нині Христос...», «І нині» – той же стих. «Помилуй мене, Боже...», і стихира свята, глас 6-ий: «Нині благодать Святого Духа...». Молитва: «Спаси, Боже, людей Твоїх...». «Господи, помилуй» (12), «Милістю і милосердям...». Примітка. Згідно загальнопоширеною практикою, Євангеліє кладеться на аналой для цілування разом з іконою свята. «Коли ж цілують братія Святе Євангеліє, приходячи поклоняються ігумену, і від руки його беруть віття зі свічками» (Типікон, гл. 49, «У суботу Квітну ввечері»). Канон свята, творіння прп. Косми, глас 4-ий, на 14 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси канону свята (після кожної пісні). Після 3-ої пісні – іпакої свята, глас 6-ий: «З віттям раніше прославили...» (один раз). Після 6-ої пісні – кондак свята, глас 6-ий: «На престолі на небесах...». Ікос, глас той же: «Тому, що Ти, Безсмертний...». Читаємо Синаксар: Стихи: На безсловесну тварину возсів Той, що створив словом небеса, людей звільняючи від уподібнення тваринам. На 9-ій пісні «Чеснішу» не співаємо, але ірмос: «Бог Господь, і явився нам...» (і інше за звичаєм). (Звершується звичайне кадіння). Після 9-ої пісні замість світильного співаємо на 4-ий глас: «Свят Господь Бог наш» (зі звичайними стихами; тричі). «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 4-ий – 6 (перші дві стихири – двічі). «Слава, і нині» – свята, глас 6-ий: «За шість днів до Пасхи...». Велике славослів’я. Після Трисвятого – тропар свята, глас 1-ий: «Загальне воскресіння...» (один раз). Відпуст святковий: «Христос, істинний Бог наш, що на осля сісти зволив, заради нашого спасіння, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і Людинолюбний»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята: «Загальне воскресіння...». «Слава» – інший тропар свята. Кондак свята. Примітка. «На 1-му часі тропар: «Загальне воскресіння..», Слава: «З Тобою через хрещення..». І нині, Богородичний часу... Після Трисвятого кондак свята: На престолі на небесах... та інше, і робимо відпуст. В храмі заупокійної літії немає. ЛІТУРГІЯ за чином свт. Іоана Золотоустого. На проскомидії заготовляються три Агнця – для Понеділка, Вівторка і Середи Страсного тижня. Антифони свята. Вхідний стих: «Благословен, Хто йде в ім’я Господнє; благословляємо вас з дому Господнього; Бог Господь, і явився нам». Примітка. Перед виголошенням вхідного стиха слід промовляти «Премудрість, станьмо побожно». Після входу – тропар свята, глас 1-ий: «Загальне воскресіння...». «Слава» – інший тропар свята, глас 4-ий: «З Тобою через хрещення...», «І нині» – кондак свята, глас 6-ий: «На престолі на небесах...». Співається Трисвяте. Прокимен, Апостол, алилуарій, Євангеліє, задостойник і причасний – свята. Після «Спаси, Боже, людей Твоїх...» співаємо: «Ми бачили Світло Істинне...». Відпуст в кінці Літургії – як на ранній, зі згадуванням імені свт. Іоана Золотоустого. Примітка. «На трапезі втіха, їмо рибу і п’ємо вино, дякуючи Богові» (Типікон, гл. 49, «У суботу Квітну увечері»). [1] Церковний Устав вважає, що благословення верби відбувається через кадіння і читання молитви. Ніяких інших дій він не вказує. Але у нас з давніх-давен ввійшло в звичай ще окроплювати віття верби святою водою. (Порівн.: Настольная книга священнослужителя. Т. 4. С. 550.)."}]},
{"date":"04-06","weekday":"понеділок","title":"Страсний тиждень. Великий понеділок. Свт. Євтихія, архієп. Константинопольського (582). Свт. Мефодія, архієп. Моравського (885). Прп. Платоніди (308). Мчч. 120 перських (344 – 347). Мч. Єремія та сщмч. Архилія, пресвітера (ІІІ). Літургія Ранішосвячених Дарів.","readings":["Ран. – Мф., 84 зач., XXI, 18 – 43. Літ. – Мф., 98 зач., XXIV, 3 – 35."],"sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ – кафизми немає. На «Господи, взиваю» стихири Тріоді, глас 8-ий (ті ж, що співалися на стиховні великої вечірні в Неділю Вербну) – 6 (кожна стихира – двічі). «Слава» – Тріоді, глас 8-ий: «Радуйся і веселися...», «І нині» – Тріоді, глас той же: «Ти, Якого херувими носять...». Вхід з кадилом. «Світло Тихе». Прокимен дня (а не великий), глас 8-ий: «Прославляйте нині Господа...» (зі стихом). Читається: «Сподоби, Господи». Ектенія: «Доповнімо вечірню...», і голововклонна молитва. На стиховні стихири самогласний Тріоді, глас 2-ий, глас 3-ій і глас 7-ий (зі своїми приспівами). «Слава» – Тріоді, глас 2-ий: «Від віття і пальм...», «І нині» – Тріоді, глас 3-ій: «Страшно стати на суд Бога Живого...». «Нині відпускаєш». Трисвяте. Після «Отче наш» священник – виголос: «Бо Твоє є Царство...». Після виголосу священника хор співає тропарі, глас 4-ий: «Богородице Діво...» (поклін). «Слава» – «Хрестителю Христів...» (поклін), «І нині» – «Моліться за нас, святі апостоли...» (поклін) [1]. Потім – «Під Твою милість...» (без поклону). Читець: «Господи, помилуй» (40), «Слава, і нині»; «Чеснішу від херувимів...», «Іменем Господнім...». Священник: «Сущий благословенний...». Молитва: «Небесний Царю...». Священник – молитву прп. Єфрема Сиріна: «Господи і Владико життя мого...» (з трьома поклонами). Після третього поклону – «Слава Тобі, Христе Боже...» і відпуст: «Господь, що йде на добровільні страждання, заради нашого спасіння, Христос, істинний Бог наш, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і Людинолюбець» (увесь Страсний тиждень святі храму і дня на відпустах добових служб не поминаються), після цього хор співає многоліття: «Блаженнішого Владику...». МАЛЕ ПОВЕЧІР’Я зі співом трипіснеця прп. Андрія Критського з Тріоді (1-а, 8-а і 9-а пісні). Ірмоси по двічі, тропарі – скільки є (без повторень). На закінчення кожної пісні знову той же ірмос (на катавасію). Після 1-ої пісні – «Господи, помилуй» (тричі), «Слава, і нині» – сідальний, глас 4-ий. Перед катавасією 8-ої пісні співається: «Хвалимо, благословимо, поклоняємося Господеві...». Після катавасії 9-ої пісні («Достойно є» не співається) і Трисвятого – замість звичайних тропарів і кондаків – кондак Тріоді, глас 8-ий: «Яків ридав...» (див. на ранній Великого Понеділка), «Господи, помилуй» (40), молитва: «Ти що кожного...» і далі за великопостовим чином з молитвою прп. Єфрема Сиріна (16 поклонів). Відпуст малий: «Христос, істинний Бог наш...» (а не «Господь, що йде на добровільні страждання...»), і священик за звичаєм просить прощення. Ектенія: «Помолимось...». РАННЯ. Початок звичайний. Після великої ектенії – «Алилуя»», глас 8-ий зі стихами, і співаємо «розчулено» тропар, глас той же: «Ось Жених гряде опівночі...». «Слава» – той же тропар, «І нині» – той же тропар. Кафизми 4-та, 5-та і 6-та. Малих ектеній немає. Сідальні Тріоді (по двічі). Примітка. Протягом Страсного тижня Псалтир прочитується повністю тільки один раз: в перші три дні (понеділок, вівторок і середу) на ранній – по три кафизми, на часах (3-му і 6-му) – по одній на кожному, на 1-му і 9-му часах кафизм немає. На вечірніх читається 18-а кафизма. У Велику Суботу на ранній співається 17-та кафизма (Непорочні) з похвалами. «І щоб сподобитися нам...». священник відкриває царські врата і читає Євангеліє у вівтарі (біля престолу) – Мф., Зач. 84 (кінець – в зачалі 88: «І дане буде народові, який буде приносити плоди його...»). Після закінчення Євангелія царські врата зачиняються. Псалом 50-ий. «Спаси, Боже, людей Твоїх...», «Господи, помилуй» (12), виголос: «Милістю і милосердям...». Хор: «Амінь». Трипіснець Тріоді, творіння прп. Косми, глас 2-ий. Ірмоси по двічі, тропарі на 12. Біблійні пісні не читаються протягом Страсного і Світлого тижня. До тропарів приспів: «Слава Тобі, Боже наш, слава Тобі». (Цей приспів – на весь Страсний тиждень). Після кожної пісні на катавасію – ірмос трипіснеця (обидва хори разом). Після 1-ої пісні – мала ектенія. Виголос: «Бо Ти Цар миру...». Кондак Тріоді, глас 8-ий: «Яків ридав...», та ікос, глас той же: «Нині ридання додамо...». Читаємо Синаксар Стихи (на Йосифа Прекрасного): Йосиф цнотливий став справедливим правителем і хліба роздавачем. О, вмістилище чеснот! Стихи (на всохлу смоковницю): Єврейське зібрання проображаючи, Христос своїм прокляттям висушує Смоковницю, позбавлену плодів духовних, Тож уникаймо ми її нещастя. Співається ірмос 8-ої пісні: «Вжахнулися юнаки благочестиві...». На 9-й пісні – кадіння («Чеснішу» не співаємо). Після 9-ої пісні «Достойно є» не співається. Мала ектенія. Виголос: «Бо Тебе хвалять...». Екзапостиларій Тріоді: «Чертог Твій...». «Слава» – той же, «І нині» – той же. Примітка. «Світильний самогласний, промовляється тричі [побожно та з розчуленням – порівн.: Тріодь Постова]: Чертог Твій бачу... Співає спочатку сам канонарх посеред церкви перший раз. Потім Слава, на кліросі; І нині, на другому. І так промовляємо протягом всього тижня» (Типікон, гл. 49,«В Святий і Великий понеділок на ранній»). «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх самогласні Тріоді, глас 1-ий і глас 5-ий – 4 (кожна стихира – двічі). «Слава, і нині» – Тріоді, глас 5-ий: «Господи, що грядеш на страждання...». Читець: «Слава Тобі, що показав нам світло» («Тобі слава подобає...» не промовляється), і читається повсякденне славослів’я. Стихири на стиховні Тріоді, глас 5-ий і глас 8-ий (зі звичайними денними приспівами, див. Часослов). «Слава, і нині» – Тріоді, глас 8-ий: «Іншу Єву знайшов змій – єгиптянку...». «Благо є сповідуватися...» (двічі). Трисвяте. Після «Отче наш» священник – виголос: «Бо Твоє є Царство...». Після виголосу – виголошується тропар Часослова: «Стоячи в храмі слави Твоєї...»; «Господи, помилуй» (40), «Слава, і нині»; «Чеснішу від херувимів...», «Іменем Господнім...». Священник перед царськими вратами: «Сущий благословенний...». Молитва: «Небесний Царю...». Молитва прп. Єфрема Сиріна (з 16 поклонами). Читець: «Амінь», і відразу, без відпусту ранньої, читається 1-ий час. 1-ий час за великопостовим чином. Кафизми немає. Тропар часу: «Зранку вислухай...» (зі стихами). Після «Отче наш» – кондак Тріоді: «Яків ридав...». Відпуст короткий: «Господь що йде на добровільні страждання...» (святі храму і дня не поминаються). Часи, зображальні та вечірня з Літургією Ранішосвячених Дарів. Часи 3-ій, 6-ий і 9-ий звершуються за великопостовим чином з великопостовими тропарями і поклонами. На 3-му часі – кафизма 7-а; на 6-му часі – кафизма 8-а, паремія Тріоді (Єзекіїля) з тропарем пророцтва і Прокимни (за звичаєм); на 9-му часі кафизми немає. На часах і зображальних після «Отче наш» – кондак Тріоді: «Яків ридав...». Особливості часів у перші три дні Страсного тижня У понеділок, вівторок і середу Страсного тижня на 3-му, 6-му і 9-му часах читається Четвероєвангеліє. Перед читанням 3-го часу посеред церкви ставиться прикрашений аналой, відкриваються царські врата, і священик, виносить на середину храму Євангеліє, паламар виносить перед ним свічку і кадило. (Священник має бути одягнений в єпітрахиль і фелонь). Поклавши Євангеліє на аналой, за яким ставиться запалений світильник, Священник виголошує виголос на початок часів. Потім священик з дияконом кадить навкруги Євангелія, потім вівтар, іконостас, настоятеля, хори, молільників і весь храм. Під час читання псалмів 6-го часу звершується мале кадіння, тобто кадиться (навкруги) Євангеліє, іконостас, настоятель, хори і народ (з амвона). На 9-му часі звершується повне кадіння храму, як і на 3-му часі. Винесене Євангеліє залишається на середині храму на час читання всіх часів, священник стоїть перед ним і тут же за звичаєм вимовляє тропарі часів і молитву прп. Єфрема Сиріна з поклонами. Євангельські читання починаються на 3-му і 9-му часах після Богородичного часу, а на 6-му – після паремії Тріоді і 2-го прокимна Тріоді. Всіх євангельських читань – 9. Євангеліє від Матфея читається в два прийоми, тобто, на 3-му і 6-му часах в понеділок. Євангеліє від Марка також в два прийоми – в понеділок на 9-му часі і у вівторок на 3-му. Євангеліє від Луки читається в три прийоми, тобто. У вівторок на 6-му і 9-му часах і в середу на 3-му. Євангеліє від Іоана читається не повністю, а до 1-го Євангелія Страстей («Нині прославився Син Людський...») – перше читання в середу на 6-му часі і друге на 9-му. Перед першим читанням євангелиста диякон виголошує виголос: «І щоб сподобитися нам вислухати святе Євангеліє...». Хор: «Господи, помилуй» (тричі). Диякон: «Премудрість, станьмо побожно, вислухаймо святого Євангелія». Священник: «Мир всім». Хор: «І духові Твоєму». Священник: «Від (ім’я) святого Євангелія читання». Хор: «Слава Тобі, Господи, слава Тобі». Диякон: «Будьмо уважні». Священник читає Євангеліє, в кінці хор: «Слава Тобі, Господи, слава Тобі». Перед другим або третім читанням того ж євангелиста виголос: «І щоб сподобитися нам вислухати святого Євангелія...» не промовляється, але тільки: «Премудрість, станьмо побожно, вислухаймо святого Євангелія». Перед читанням нового євангелиста зазначені молитви повторюються зі слів: «І щоб сподобитися нам...», і далі порядок той же. Після читання Євангелія на 9-му часі Священник забирає Євангеліє у вівтар. Царські врата і завіса закриваються. За вказівкою Типікону, Євангелія від Матфея, Марка та Іоана діляться кожне на дві частини, а Євангеліє від Луки – на три (порівн.: Типікон, гл. 49, «У Святий і Великий понеділок на утрені», 2-е «дивись»). Відповідно до цих вказівок вони можуть бути розділені, наприклад, так: Понеділок На 3-му часі – Мф., Зач. 1–66 (1, 1 – 16, 12). На 6-му часі – Мф., Зач. 67–116 (16, 13 – 28, 20). На 9-му часі – Мк., Зач. 1–39 (1, 1 – 9, 16). Вівторок На 3-му часі – Мк., Зач. 40–71 (9, 17 – 16, 20). На 6-му часі – Лк., Зач. 1–38 (1, 1 – 8, 39). На 9-му часі – Лк., Зач. 39–82 (8, 40 – 16, 18). Середа На 3-му часі – Лк., Зач. 83–114 (16, 19 – 24, 53). На 6-му часі – Ін., Зач. 1–26 (1, 1 – 7, 36). На 9-му часі – Ін., Зач. 27–46 (7, 37 – 13, 32). Якщо Євангелія перших трьох євангелистів прочитані раніше, то Євангеліє від Іоана на Страсний тиждень слід читати приблизно в такому порядку: Понеділок На 3-му часі – Ін., Зач. 1–7 (1, 1 – 2, 25). На 6-му часі – Ін., Зач. 8–12 (3, 1 – 4, 46). На 9-му часі – Ін., Зач. 13–18 (4, 47 – 6, 13). Вівторок На 3-му часі – Ін., Зач. 19–25 (6, 14 – 7, 13). На 6-му часі – Ін., Зач. 26–30 (7, 14 – 8, 30). На 9-му часі – Ін., Зач. 31–34 (8, 31 – 9, 38). Середа На 3-му часі – Ін., Зач. 35–38 (9, 39 – 10, 42). На 6-му часі – Ін., Зач. 39–41 (11, 1 – 12, 18). На 9-му часі – Ін., Зач. 42–46 (12, 19 – 13, 32). ЗОБРАЖАЛЬНІ звершуються за великопостовим чином. Після «Отче наш» – кондак Тріоді: «Яків ридав...». Відпуст короткий: «Господь що йде на добровільні страждання...». Святі храму і дня на відпусті не поминаються. (Зображальні в понеділок і вівторок Страсного тижня можуть завершуватися і звичайним малим відпустом). ВЕЧІРНЯ з Літургією Ранішосвячених Дарів за звичайним чином. Кафизма 18-та. На «Господи, взиваю» стихири Тріоді, глас 1-ий, глас 5-ий і глас 8-ий (ті ж, що співалися на хвалітніх і на стиховні ранньої) – 10 (перші чотири стихири – двічі). «Слава, і нині» – Тріоді, глас 8-ий: «Іншу Єву...». Вхід з Євангелієм. «Світло Тихе». Читання двох паремій Тріоді (Виходу та Іова) з Прокимнами, за звичаєм. 1-ий прокимен, глас 6-ий: «Нехай благословить тебе Господь від Сиону, і побачиш блаженство Єрусалиму», стих: «Блаженні всі, що бояться Господа. Ті, що ходять путями Його»; 2-ий прокимен, глас 6-ий: «Благословення Господнє на вас», стих: «Багато разів бороли мене від юності моєї». Після «Нехай вознесеться молитва моя...» і молитви прп. Єфрема Сиріна (з трьома великими поклонами) диякон виходить з Євангелієм через царські врата на амвон. Диякон (або Священник): «Премудрість, станьмо побожно, вислухаймо...» і все інше (Якщо немає диякона, священик читає Євангеліє біля престолу). Євангеліє – Мф., Зач. 98. Ектенія: «Промовмо всі...», та інша послідовність Літургії Ранішосвячених Дарів (за звичаєм). Відпуст короткий: «Господь, що йде на добровільні страждання...» (святі храму і дня на відпусту не поминаються). Примітка. «На трапезі ж їмо суху їжу, і цим задовольняємось. І як протягом 1-го тижня святого цього посту, так і в ці дні: у Великий понеділок, у Вівторок та в Середу належить поститися» (Типікон, Великий понеділок увечері, 2-е «див»). «Слід знати що, шостий Великий Собор встановив спасительні Страсні дні в пості і молитві і з розчуленим серцем провадити вірним. Опівночі ж Великої Суботи припиняти піст» (Типікон, Великий понеділок ввечері, 3-е «див»). ВЕЛИКЕ ПОВЕЧІР’Я (в понеділок увечері) зі звичайними тропарями. Після «Слава в вишніх Богу...» – трипіснець Тріоді, творіння прп. Андрія Критського, глас 8-ий (пісні 2-га, 8-ма і 9-та), ірмоси по двічі, тропарі без повторень. Катавасія – ірмос трипіснеця. (2-а пісня має два ірмоси, на катавасію співається другий ірмос). Після 2-ої пісні – «Господи, помилуй» (тричі), «Слава, і нині» – сідальний, глас 2-ий: «Милосердям натхненний, Христе...». Перед катавасією 8-ої пісні співається: «Хвалимо, благословимо, поклоняємось Господеві...». Після катавасії 9-ої пісні («Достойно є» не співається) і Трисвятого – кондак Тріоді, глас 2-й: «Час кінця, душе, усвідомивши...» (див. На ранній Великого Вівторка). Після кондака – «Господи Сил, будь з нами...» та інше за звичаєм. Молитва прп. Єфрема Сиріна (з 16 поклонами). Молитва: «Владико Многомилостивий...» (за звичаєм), і чин прощення. Ектенія: «Помолимось...». [1] Співи «Богородице Діво...», «Хрестителю Христів...», «Моліться за нас, святі апостоли...» і «Під Твою милість...» увечері в усі Тижні святої Чотиридесятниці і у Вербну Неділю співаються «мелодійно», а в дні Страсної седмиці – «швидко промовляються» (див.: Типікон, гл. 49, «У Неділю Квітну увечері», 1-е «див»)."}]},
{"date":"04-07","weekday":"вівторок","title":"Великий вівторок. Прп. Георгія, сповідника, митр. Мітиленського (після 820). Мч. Каліопія (304). Сщмч. Руфина, диякона, мц. Акилини і з ними 200 воїнів (бл. 310). Прп. Серапіона, ченця. Прп. Юстина (Поповича), Челійського (1978, Серб.). Служба звершується за зразком богослужіння у Великий понеділок. Літургія Ранішосвячених Дарів.","readings":["Ран. – Мф., 90 зач., XXII, 15 – XXIII, 39. Літ. – Мф., 102 зач., XXIV, 36 – XXVI, 2."],"notes":"РАННЯ. Початок звичайний. Після великої ектенії – «Алилуя», глас 8-ий (зі стихами»). Тропар, глас той же: «Ось Жених...». «Слава» – той же тропар, «І нині» – той же тропар. Кафизми 9-та, 10-та і 11-та. Малих ектеній немає. Сідальні Тріоді (по двічі). Євангеліє – Мф., Зач. 90-е: «Тоді радились всі фарисеї проти Ісуса...», без переступки (кінець – в зачалі 96-му: «Благословен, Хто йде в ім’я Господнє»). Псалом 50-ий. «Спаси, Боже, людей Твоїх...», «Господи, помилуй» (12). Виголос: «Милістю і милосердям...», і відразу мала ектенія. Виголос: «Бо Ти є Цар миру...». Кондак Тріоді, глас 2-ий: «Час кінця, душе, усвідомивши...», та ікос, глас той же: «Чого сумуєш, душе моя окаянна,...». Читаємо синаксар: Стихи: Великий Вівторок нам представляє десять дів, Які почули від непідкупного Владики вирок. Двопіснець Тріоді, творіння прп. Косми, глас 2-ий. Ірмоси по двічі, тропарі на 12. Після кожної пісні катавасія – ірмос двоспіснеця. На 9-ій пісні – кадіння. («Чеснішу» не співаємо). Після 9-ої пісні «Достойно є...» не співається. Мала ектенія. Екзапостиларій: «Чертог Твій...». «Слава» – той же, «І нині» – той же. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 1-ий і глас 2-ий – 4 (кожна стихира – двічі). «Слава, і нині» – Тріоді, глас 4-ий: «Ти чула про осудження того, хто закопав талант...». Читець: «Слава Тобі, що показав нам світло» («Тобі слава подобає...» не вимовляється), і читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 6-ий (зі звичайними денними приспівами, див. Часослов). «Слава, і нині» – Тріоді, глас 7-й: «Ось тобі талант...». Закінчення ранньої – за великопостовим чином. Часи звершуються за великопостовим чином. НА 1-МУ ЧАСІ кафизми немає. Відпуст короткий: «Господь, що йде на добровільні страждання...». Примітка. «Час 3-ій і 6-ий, співаємо з кафизмами, у свій час, і з поклонами... Разом співаємо також і 9-ий час без кафизми... і Блаженні співаємо... та інше все, як вказано в понеділок» (Типікон, гл. 49,«У Святий і Великий вівторок»). НА 3-МУ ЧАСІ – кафизма 12-а. НА 6-МУ ЧАСІ – кафизма 13-а, паремія Тріоді (Єзекіїля) з тропарем пророцтва і Прокимни (за звичаєм). НА 9-МУ ЧАСІ кафизми немає. На часах (3-му, 6-му і 9-му) читається Четвероєвангеліє. На всіх часах і зображальних – кондак Тріоді: «Час, душе...». Зображальні – за великопостовим чином. Відпуст короткий: «Господь що йде на добровільні страждання...». (Допустимо виголошувати малий звичайний відпуст). ВЕЧІРНЯ з Літургією Ранішосвячених Дарів за звичайним чином. Кафизма 18-та. На «Господи, взиваю» стихири Тріоді, глас 1-ий, глас 2-ий, глас 4-й і глас 6-ий (ті ж, що співалися на хвалітніх і на стиховні ранньої) – 10 (перші чотири стихири – двічі). «Слава, і нині» – глас 7-ий: «Ось тобі талант...». Вхід з Євангелієм. «Світло Тихе...». Читання двох паремій Тріоді (Виходу та Іова) з Прокимнами, за звичаєм. 1-ий прокимен, глас 6-ий: «Воскресни, Господи, в спокій Твій, Ти і кивот святині Твоєї», стих: «Пом’яни, Господи, Давида і всю лагідність його»; 2-ий прокимен, глас 4-ий: «Як то добре і як то гарно, коли брати живуть у згоді», стих: «Як миро на голові, що сходить на бороду, на бороду Ааронову». Після «Нехай вознесеться молитва моя...» і молитви прп. Єфрема Сиріна (з трьома великими поклонами) читається Євангеліє – Мф., Зач. 102-е: «Про день же і годину пришестя Сина Людського ніхто не знає...». Ектенія: «Промовмо всі...», та інша черговість Літургії Ранішосвячених Дарів. Відпуст короткий: «Господь що йде на добровільні страждання...». ВЕЛИКЕ ПОВЕЧІР’Я (у вівторок увечері) зі звичайними тропарями. Після «Слава в вишніх Богу...» – трипіснець Тріоді, творіння прп. Андрія Критського, глас 2-ий (пісні 3-тя, 8-а і 9-а), ірмоси по двічі, тропарі без повторень. Катавасія – ірмос трипіснеця. Після 3-ої пісні – «Господи, помилуй» (тричі), «Слава, і нині» – сідальний, глас 1-ий: «Ось лукава рада...». Перед катавасією 8-ої пісні співається: «Хвалимо, благословимо, поклоняємось Господеві...». Після катавасії 9-ої пісні («Достойно є...» не співається) і після Трисвятого – кондак Тріоді, глас 4-ий: «Більше блудниці...» (див. На ранній Великої Середи). Після кондака – «Господи Сил, будь з нами...» та інше за звичаєм. Молитва прп. Єфрема Сиріна (з 16 поклонами). Молитва: «Владико Многомилостивий...» (за звичаєм), і чин прощення. Ектенія: «Помолимось...».","sections":[],"special":true},
{"date":"04-08","weekday":"середа","title":"Велика середа. Апп. Іродіона, Агава, Асинкрита, Руфа, Флегонта, Єрма та інших з ними (І). Прп. Руфа, затворника Києво-Печерського, в Дальніх печерах (ХІV). Мч. Павсилипа (117 – 138). Свт. Целестина, папи Римського (432). Свт. Нифонта Києво-Печерського, єп. Новгородського (1156). Служба звершується за зразком богослужіння у Великий понеділок. Літургія Ранішосвячених Дарів.","readings":["Ран. – Ін., 41 зач. (від пол.), XII, 17 – 50. Літ. – Мф., 108 зач., XXVI, 6 – 16."],"notes":"РАННЯ. Початок звичайний. Після великої ектенії – «Алилуя», глас 8-ий (зі стихами...»). Тропар, глас той же: «Ось Жених...». «Слава» – той же тропар, «І нині» – той же тропар. Кафизми 14-та, 15-та і 16-та. Малих ектеній немає. Сідальні Тріоді (по двічі). Євангеліє – Ін., Зач. 41-е, від половини, (кінець в зач. 43-м «... що Я говорю, то говорю так, як сказав Мені Отець»). Псалом 50-ий. «Спаси, Боже, людей Твоїх...», «Господи, помилуй» (12). Виголос: «Милістю і милосердям...». Трипіснець Тріоді, творіння прп. Косми, глас 2-ий. Ірмоси по двічі, тропарі на 12. Після кожої пісні катавасія – ірмос трипіснеця. Після 3-ої пісні – мала ектенія. Виголос: «Бо Ти є Цар миру...». Кондак Тріоді, глас 4-ий: «Більше блудниці...», та ікос, глас той же: «Жона, яка була першою блудницею...». Читаємо синаксар: Стихи: Жінка, помазавши Христове тіло миром, Передвіщає смирну і алое Никодима. На 9-ій пісні – кадіння. («Чеснішу» не співаємо). Після 9-ої пісні «Достойно є...» не співається. Мала ектенія. Екзапостиларій Тріоді: «Чертог Твій...». «Слава» – той же, «І нині» – той же. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 1-ий – 4. «Слава» – Тріоді, глас 2-ий: «Грішна йде купити дорогоцінне миро...», «І нині» – Тріоді, глас 6-ий: «Занурена в гріхи...». Читець: «Слава Тобі, що показав нам світло» («Тобі слава подобає...» не вимовляється), і читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 6-ий – 4 (зі своїми приспівами). «Слава, і нині» – Тріоді, глас 8-ий: «Господи, жона, що впала в тяжкі гріхи...». Примітка. Перші два стиха до стихир на стиховні – звичайні денні (з Часослова), а останній стих – «Прославлятиму Тебе, Господи, всім серцем моїм, розповім про всі чудеса Твої». Закінчення ранньої – за великопостовим чином. Часи і зображальні звершуються за великопостовим чином. На 1-му часі кафизми немає. Відпуст короткий: «Господь. що йде на добровільні страждання...». Примітка. «В годині ж 5-ій дня, вдаряє параклисіарх в било: і зібравшись до церкви, після благословення священика, співаємо 3-ій час, і 6-ий... також співаємо і 9-ий час... Потім співаємо Блаженні...» (Типікон, гл. 49, «В Святу і Велику Середу на ранній»). На 3-му часі – кафизма 19-та. На 6-му часі – кафизма 20-та, паремія Тріоді (Єзекіїля) з тропарем пророцтва і Прокимни (за звичаєм). На 9-му часі кафизми немає. На часах (3-му, 6-му і 9-му) читається Четвероєвангеліє. На всіх часах – кондак Тріоді: «Більше блудниці...».","sections":[{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ кондаки в наступному порядку: У храмі Господському – кондак Тріоді: «Більше блудниці...». «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». У храмі Богородиці – кондак Тріоді: «Більше блудниці...». «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – кондак Тріоді: «Більше блудниці...», кондак храму. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». І наступне послідування зображальних за звичаєм. Молитва прп. Єфрема Сиріна (з 16 поклонами). В кінці зображальних замість відпусту настоятелем читається молитва літії: «Владико Многомилостивий...», під час якої всі повинні молитися, на колінах. Після прочитання її – чин прощення. Священник виголошує: «Благословіть, отці святі, і простіть мені, грішному, все чим згрішив я в усі дні життя мого і протягом Святої Чотиридесятниці, словом, ділом, думкою і всіма моїми почуттями». І поклоняється перед всіма до землі. Всі ж присутні, також поклоняючись до землі, відповідають йому: «Нехай Бог простить тебе, чесний отче». Примітка. «І прийнявши прощення, йдемо до наших келій, і мовчимо до години вечірньої. А в соборних і парафіяльних храмах, не розходимось, але після прощення дзвонимо в два дзвони» (Типікон, гл. 49,«В Святу і Велику Середу на ранній»). ВЕЧІРНЯ з Літургією Ранішосвячених Дарів. Кафизма 18-а – без поклонів (див.: Типікон, гл. 49, «В святу і велику середу увечері»). На «Господи, взиваю» стихири Тріоді, глас 1-ий, глас 2-ий і глас 6-ий (ті ж, що співалися на хвалітніх і на стиховні ранньої) – 10. «Слава, і нині» – Тріоді, глас 8-ий: «Господи, жона, що впала в тяжкі гріхи...». Вхід з Євангелієм. «Світло Тихе». Читання двох паремій Тріоді (Виходу та Іова) з Прокимнами, за звичаєм. 1-ий прокимен, глас 4-ий: «Прославляйте Бога Небесного, бо благий, бо повіки милість Його», стих: «Прославляйте Бога богів, бо повіки милість Його»; 2-ий прокимен, глас 4-ий: «Господи, милість Твоя повік, творіння рук Твоїх не зневаж», стих: «Сповідуюсь Тобі, Господи, всім серцем моїм і перед Ангели оспівую Тебе». Після «Нехай вознесеться молитва моя...» і молитви прп. Єфрема Сиріна (з трьома великими поклонами) читається Євангеліє – Мф., Зач. 108-е: «Коли Ісус був у Вифанії...». Ектенія: «Промовмо всі...», та інша послідовність Літургії Ранішосвячених Дарів. Після «Нехай буде ім’я Господнє благословенне...» – три великих поклони. (Зазвичай вони творяться з читанням молитви прп. Єфрема Сиріна). Примітка. І поклони припиняються до дня Святої Тройці, окрім поклонів перед Плащаницею. Відпуст короткий: «Господь, що йде на добровільні страждання...». У середу увечері служиться МАЛЕ ПОВЕЧІР’Я. На ньому трипіснець Великого Четверга з Тріоді, творіння прп. Андрія Критського, глас 6-ий (пісні 4-а, 8-а і 9-а). Ірмоси по двічі; тропарі – скільки є. В кінці кожної пісні – Ірмос на катавасію. Піля 4-ої пісні – «Господи, помилуй» (тричі), «Слава, і нині» – сідальний Тріоді, глас 4-ий: «Споживаючи їжу, Владико...». Після Трисвятого – кондак Тріоді, глас 2-ий: «Хліб святий прийнявши...» (див. на ранній Великого Четверга), та іншу послідовність малого повечір’я. Відпуст малий: «Христос, істинний Бог наш...» (але не «Господь що йде на добровільні страждання...»). З цього дня і до Неділі Антипасхи на службах добового кола кафизм немає, за винятком 17-ої кафизми на ранній Великої Суботи."}]},
{"date":"04-09","weekday":"четвер","title":"Великий четвер. Спомин Таємної вечері. Мч. Євпсихія (362). Сщмчч. Дісана, єп., Маріава, пресвіт., мчч. Авдієса та ін. 270-х (362 – 364). Прмч. Вадима, архім. (376). Літургія за чином свт. Василія Великого.","readings":["Ран. – Лк., 108 зач., ХХІІ, 1 – 39.","Літ. – 1 Кор., 149 зач., ХІ, 23 – 32. Єв. (складене): Мф., 107 зач., ХХVІ, 1 – 20. Ін., ХІІІ, 3 – 17; Мф. ХХVІ, 21 – 39;"],"notes":"Лк., ХХІІ, 43 – 45; Мф., ХХVІ, 40 – ХХVІІ, 2. На обмиванні ніг – Ін., 44 зач., ХІІІ, 1 – 11. Після обмивання ніг: Ін., 45 зач., ХІІІ, 12 – 17. РАННЯ. Примітка. За Уставом, рання починається «о 7-ій годині ночі», тобто, близько першої години ночі: «О 7-ій годині ночі вдаряє параклісіарх, і зібравшись до церкви, священник починає: Благословенний Бог наш... починаємо за звичаєм, як написано в четвер 5-го тижня» (див.: Типікон, гл. 49,«У Святий і Великий четвер»). Священник виголос: «Благословенний Бог наш...». Читець [1]: «Амінь», «Слава Тобі, Боже наш, слава Тобі», «Царю Небесний...», Трисвяте. Після «Отче наш...» священник – виголос: «Бо Твоє є Царство...». Читець: «Амінь», «Господи, помилуй» (12 разів), «Слава, і нині», «Прийдіть, поклонімось...» (тричі) і двопсалміє (під час псалмів – звичайне кадіння). Шестипсалміє. (священник читає ранкові молитви). Велика ектенія. «Алилуя»», глас 8-ий (зі стихами). Тропар, глас той же: «Коли славні ученики...». «Слава» – той же, «І нині» – той же. Після закінчення співу тропаря відкриваються царські врата, і диякон виголошує: «І щоб сподобитися нам вислухати...». Євангеліє – Лк., Зач. 108, від половини: «Наближалося свято опрісноків...» (кінець в зач. 109: «За Ним пішли ученики Його»). Кафизм немає. Псалом 50-ий. Молитва «Спаси, Боже, людей Твоїх...» не читається, але відразу канон Тріоді, глас 6-ий, творіння прп. Косми Маюмського: «Жезлом розсікається море Червоне...» (ірмоси по двічі, тропарі на 6), з приспівом: «Слава Тобі, Боже наш, слава Тобі» (біблійні пісні не промовляються). По кожній пісні катавасія – ірмос канону. Після 3-ої пісні – мала ектенія, сідальний Тріоді, глас 1-ий: «Сотворитель озер, джерел і морів,...». «Слава» – інший сідальний, глас 3-ий: «Смиряючись ради милосердя, ноги умив єси ученикам Твоїм...», «І нині» – інший сідальний, глас 4-й: «Споживаючи їжу, Владико, з учениками Твоїми...». Після 6-ої пісні – мала ектенія, кондак Тріоді, глас 2-ий: «Хліб святий прийнявши в руки...», та ікос, глас той же: «До Тайної Трапези у страху наблизившись...». Читаємо синаксар стихи: Учням на вечері мив ноги Бог, Нога Якого потім на древо спиралася, колись заборонене в Едемі... На 9-ій пісні – кадіння. («Чеснішу» не співаємо). Після 9-ої пісні «Достойно є» не співається. Мала ектенія. Екзапостиларій Тріоді: «Чертог Твій...». «Слава» – той же, «І нині» – той же. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 2-ий – 4. «Слава, і нині» – Тріоді, глас той же: «Агнець, про Якого пророкував Ісая...». Читець: «Слава Тобі, що показав нам світло» («Тобі слава подобає...» не промовляється), і читається повсякденне славослів’я. Ектенія прохальна: «Доповнимо ранню...», виголос: «Бо Ти, Бог милості...», і звичайна голововклонна молитва (з виголосом: «Бо Твоє є...»). Стихири на стиховні Тріоді, глас 8-ий – 4 (з особливими приспівами). «Слава» – Тріоді, глас той же: «Норов твій лукавством сповнюється, беззаконний Юдо!...», «І нині» – Тріоді, глас 5-ий: «Відкриваючи таїну Своїм ученикам, навчав Ти...». «Благо є» (один раз). Після Трисвятого співається тропар, глас 8-ий: «Коли славні ученики...». Потрійна ектенія: «Помилуй нас, Боже...». Виголос: «Бо Ти милостивий...». Диякон: «Премудрість». Хор: «Благослови». Священник: «Сущий благословенний...». Хор: «Утверди Боже», і відразу, без відпусту ранньої читається 1-ий час. НА 1-МУ ЧАСІ тропар: «Коли славні ученики...». Після Богородичного: «Як нам назвати Тебе...» – тропар пророцтва (Тріоді), глас 3-ій: «Ти, Господи, був зневажений за рід людський...», «Слава, і нині» – той же тропар. 1-ий прокимен (Тріоді), глас 1-ий: «Нехай зрозуміють народи, що ім’я Тобі Господь»; стих: «Боже, хто уподібниться Тобі?», і паремія Тріоді (Єремії). Потім 2-ий прокимен (Тріоді), глас 8-ий: «Помоліться і віддайте хвалу Господеві, Богові нашому»; стих: «Знаний Бог в Юдеї, в Ізраїлі велике ім’я Його». Далі читець: «Стопи мої...» (без співу і повторень). Після Трисвятого і Отче наш – кондак Тріоді: «Хліб святий прийнявши...», та інше за звичаєм (але не як у Великий піст). Відпуст: «Христос, Істинний Бог наш, що з надмірної благості найкращу путь смирення нам показав, коли ноги учеників умив, і аж до хреста і погребіння дійшов, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і» (святі храму і дня не поминаються) [2]. Примітка. «Слід знати, що літії за упокій в притворі не звершуємо до Неділі Фоминої» (Типікон, гл. 49, «У Святий і Великий Четвер», 1-е «дивись»). Відповідно до цієї вказівки Типікону, у всі наступні дні Страсного і Пасхального тижнів не слід промовляти заупокійних ектеній і звершувати будь-які поминання померлих, крім таємного на проскомидії і на Літургії після освячення Дарів. Не звершуються ні панахиди, ні літії. Вхідні молитви, за звичаєм, священнослужителі творять на молитві 9-го часу, і проскомидія звершується під час співу «Господи, взиваю». Але якщо буде багато поминань, проскомидія може бути розпочатою під час часів і закінчена під час співу «Господи, взиваю» [3]. Примітка. «В годину ж 3-ю дня вдаряє параклісіарх в било, і співаємо часи 3-ій, 6-ий, і 9-ий, за звичаєм просто в притворі... І Блаженні скоро без співу...» (Типікон, гл. 49, «У Святий і Великий Четвер»). Часи 3-ій, 6-ий і 9-ий – без кафизм. На часах – тропар: «Коли славні ученики...», і кондак: «Хліб святий прийнявши...». Приєднується, як завжди, послідовність ЗОБРА- ЖАЛЬНИХ [4]. Блаженні скоро, без співу. «Пом’яни нас, Господи...», «Пом’яни нас, Владико...», «Пом’яни нас, Святий...», «Хор Небесний прославляє Тебе...», «Приступіть до Нього...», «Хор Небесний прославляє Тебе...». «Слава» – «Хор святих Ангелів...», «І нині» – «Вірую...», «Послаб, прости...», «Отче наш», після виголосу: «Бо Твоє є Царство...» – кондак: «Хліб святий прийнявши...». «Господи, помилуй» (40). Молитва: «Всесвята Тройце...». священник (або диякон): «Премудрість». Хор: «Достойно є...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст. ЛІТУРГІЯ за чином свт. Василія Великого починається вечірнею. Примітка. За Уставом, вечірня з Літургією свт. Василія Великого починається «о 8-ій годині дня», тобто, близько 2-ої години після полудня: «О 8-ій годині дня вдаряє параклісіарх, і зібравшись до церкви, після благословення священика, починаємо вечірню без кафизми. Царю Небесний: Трисвяте: Господи, помилуй, 12. Прийдіть, поклонімось: тричі. І псалом: Благослови, душе моя, Господа...» (див.: Типікон, гл. 49,«У Святий і Великий Четвер ввечері»). Виголос: «Благословенне Царство...». Звичайний початок (з «Царю Небесний...»), псалом 103-ій (священик читає світильничні молитви перед царськими вратами). Велика ектенія. Кафизми немає. Примітка. «Також Господи, взиваю на глас 2-ий, читаємо 10 стихів. Священик зодягнувши священичий одяг, виходить, і кадить, і коли повертається, звершує проскомидію» (Тріодь Постова, «У Святий і Великий Четвер ввечері»). На «Господи, взиваю» стихири Тріоді, глас 2-ий [5] – 10 (кожна стихира – двічі). «Слава, і нині» – Тріоді, глас 6-ий: «Дійсно, Іуда є породження єхидни...». В цей час закінчується чин проскомидії, на якому готуються два Агнця: один для даної Літургії, а інший – для приготування запасних Святих Дарів на весь рік. Вхід з Євангелієм. «Світло Тихе». 1-ий прокимен Тріоді, глас1-ий:«Спасимене,Господи,відлюдейлукавих;захисти Мене, від гнобителів»; стих: «Вони замишляють неправду в серці; щодня готуються до битви», і читається 1-а паремія Тріоді (Виходу). 2-ий прокимен Тріоді, глас 7-ий: «Визволи мене від ворогів моїх, Боже мій, від тих, що повстали на мене, захисти мене»; стих: «Спаси мене від тих, хто чинить беззаконня», і читаються дві паремії Тріоді (Іова та Ісаї) [6]. Мала ектенія. Виголос: «Бо свят єси, Боже наш...» [7]. Трисвяте. Прокимен Апостола, глас 7-ий: «Князі людські змовляються разом проти Господа і проти Христа Його»; стих: «Навіщо бунтуються народи і люди замишляють марне». Апостол – 1 Кор., Зач. 149. Алилуарій, глас 6-ий: «Блаженний, хто дбає про вбогих і бідних, в день скорботи спасає його Господь»; стих: «Вороги мої в злобі кажуть про мене: коли він помре та згине ім’я його?»; стих: «Той, хто їв мій хліб, підняв проти мене п’яту свою». Євангеліє (складене) [ 8] – Мф., Зач. 107: «Сказав Господь Своїм ученикам: ви знаєте, що через два дні буде Пасха...». Далі за чином Літургія свт. Василія Великого. Замість Херувимської пісні – «Вечері Твоєї тайної...» (тричі): двічі до перенесення Святих Дарів (без «Алилуя»), втретє – після перенесення Дарів (з «Алилуя»). Примітка. «Замість Херувимської пісні, співаємо на глас 6-ий: Вечері Твоєї тайної: тричі, хори поперемінно: в кінці ж Алилуя тричі» (Типікон, гл. 49, «У Святий і Великий Четвер увечері»). Задостойник – ірмос 9-ої пісні канону Великого Четверга: «Прийдіть вірні, гостинністю Владики...». Замість причасного, під час причастя і замість «Нехай сповняться...» – «Вечері Твоєї тайної...», «Алилуя»» (тричі). Після «Спаси, Боже, людей Твоїх...» співаємо: «Ми бачили Світло Істинне...». Відпуст короткий: «Христос, що з надмірної благості..., Істинний Бог наш...» (святі дня і храму не поминаються). Примітка. «Потім входимо до трапезної і їмо варення (варена їжа) з олією. П’ємо ж і вино, та інше сухоядіння, оскільки співається Алилуя. Студійської ж обителі Типік велить у Великий Святий Четвер їсти одне варення, і сочиво, і ошпарені боби, П’ємо ж і вино. Святої ж Гори Типік велить у Святий Великий Четвер їсти варення два з єлеєм і вина по три чаші» (Типікон, гл. 49,«У Святий і Великий Четвер увечері»). У четвер увечері служиться МАЛЕ ПОВЕЧІР’Я. На ньому трипіснець Великої П’ятниці з Тріоді, творіння прп. Андрія Критського, глас 8-ий (пісні 5-а, 8-а і 9-а). Ірмоси по двічі; тропарі, скільки їх є. В кінці кожної пісні – Ірмос на катавасію. Після Трисвятого – кондак Тріоді, глас 8-ий: «Заради нас розіп’ятого, прийдіть, усі оспіваємо, Його ж бо бачила Марія на хресті і промовляла: хоч і терпиш Ти розп’яття, але Ти – Син Мій і Бог Мій» (див. на ранній Великої П’ятниці), та інша послідовність малого повечір’я. Відпуст малий. Примітка. Заради зворушливого трипіснеця це повечір’я не слід пропускати і в тому випадку, коли послідовність святих Страстей відбувається в четвер ввечері. [1] Див. У четвер 5-го тижня Великого посту. [2] Так за Служебником. У книзі «Служби на кожен день Страсного тижня» у Великий четвер на ранній і на зображальних вказано відпуст «Господь, що йде на добровільні страждання...», що менше відповідає змісту богослужіння ранньої цього дня. [3] В цьому випадку вхідні молитви відбуваються перед початком богослужіння. [4] Зображальні починаються з «У Царстві Твоїм...». [5] Ті ж стихири, що співалися на хвалітніх ранньої. [6] Під час співу прокимнів царські врата, за традицією, відкриті; на читання паремій царські врата зачиняються. [7] Виголос «Бо Ти святий єси, Боже наш...» виголошується на Літургії і тоді, коли вона звершується з вечірнею. [8] Складені євангельські читання Страсного тижня, а також 12 Євангелій Святих Страстей на ранній Великої П’ятниці, наводяться повністю в додатку богослужбових Євангелій.","sections":[],"special":true},
{"date":"04-10","weekday":"п’ятниця","title":"Велика п’ятниця. Спомин святих спасительних страстей Господа нашого Ісуса Христа. Мчч. Терентія, Помпія, Африкана, Максима, Зинона, Олександра, Федора та інших 33 (бл. 249 – 251). Сщмчч. Якова, пресвітера, Азадана і Авдикія, дияконів Перських (бл. 380). Блгв. гетьмана Петра (Конашевича-Сагайдачного) (1622). Прмчч. священної обителі Пантократора, які в Дау Пенделі (Аттика) постраждали (бл. 1680). Сщмч. Григорія V, патр. Константинопольского (1821).","readings":["Ран. – Євангелія Послідування святих страстей Господа нашого Ісуса Христа:","1-е: Ін., 46 зач., XIII, 31 – XVIII, 1.","2-е: Ін., 58 зач., XVIII, 1 – 28.","3-е: Мф., 109 зач., XXVI, 57 – 75.","4-е: Ін., 59 зач., XVIII, 28 – XIX, 16.","5-е: Мф., 111 зач., XXVII, 3 – 32.","6-е: Мк., 67 зач., XV, 16 – 32.","7-е: Мф., 113 зач., XXVII, 33 – 54.","8-е: Лк., 111 зач., XXIII, 32 – 49.","9-е: Ін., 61 зач., XIX, 25 – 37.","10-е: Мк., 69 зач., XV, 43 – 47.","11-е: Ін., 62 зач., XIX, 38 – 42.","12-е: Мф., 114 зач., XXVII, 62 – 66."],"notes":"Літургія не звершується. На 1-му часі: Гал., 215 зач. (від пол.), VI, 14 – 18. Мф., 110 зач., XXVII, 1 – 56. На 3-му часі: Рим., 88 зач. (від пол.), V, 6 – 11. Мк., 67 зач., XV, 16 – 41. На 6-му часі: Євр., 306 зач., II, 11 – 18. Лк., 111 зач., XXIII, 32 – 49. На 9-му часі: Євр., 324 зач., X, 19 – 31. Ін., 59 зач., XVIII, 28 – XIX, 37. На веч.: 1 Кор., 125 зач., I, 18 – II, 2. Єв. складене: Мф., 110 зач., XXVII, 1 – 44; Лк., XXIII, 39 – 43; Мф., XXVII, 45 – 54; Ін., XIX, 31 – 37; Мф., XXVII, 55 – 61. Строгий піст. Зазвичай в четвер увечері звершується рання з читанням 12-ти Євангелій Святих Страстей Господа нашого Ісуса Христа. 1-ий час до ранньої не приєднується. Відпуст в кінці ранньої: «Христос, Істинний Бог наш, що для спасіння світу обплювання, побиття, хрест і смерть перетерпів, молитвами...». Вранці в п’ятницю звершується Послідовність часів Великої П’ятниці із зображальними. У другій половині дня звершується вечірня, в кінці якої під час співу тропарів після «Нині відпускаєш» з вівтаря через північні двері виноситься Свята Плащаниця. Відпуст часів і зображальних та вечірні: «Христос, Істинний Бог наш, що задля нас, людей, і задля нашого спасіння страшні муки, і Животворчий Хрест, і добровільне погребіння тілом прийняти зволив, молитвами...». Після відпусту вечірні – мале повечір’я з каноном «Про розп’яття Господа і на плач Пресвятої Богородиці». Відпуст повечір’я – малий. Під час цілування Плащаниці прийнято співати стихиру «Прийдіть, вшануймо Йосифа приснопам’ятного...». ПОЛУНОШНИЦЮ «співаємо в келіях» (Типікон, гл. 49, «У Святий і Великий Четвер увечері»). РАННЯ Великої П’ятниці (з читанням 12-ти Євангелій), що називається за Уставом «Послідовність Святих і спасительних Страстей Господа нашого Ісуса Христа», відбувається зазвичай у Великий Четвер увечері. За Типіконом, вона повинна починатися о 2-ій годині ночі, тобто, за нашим часом, о 8-ій годині вечора у Великий четвер. Примітка. «О 2-ій годині ночі вдаряє параеклісіарх. І збираємось в храмі, Священник з кадилом благословляє, промовляємо за звичаєм, як приписано в четвер 5-го тижня» (Типікон, гл. 49,«Послідовність Святих і спасительних Страстей...»,«У Святу і Велику П’ятницю ранку»). Священник виголос: «Благословен Бог наш...». Читець [1]: «Амінь», «Слава Тобі, Боже наш, слава Тобі», «Царю Небесний...», Трисвяте. Після «Отче наш...» священник – виголос: «Бо Твоє є Царство...». Читець: «Амінь», «Господи, помилуй» (12 разів), «Слава, і нині», «Прийдіть, поклонімось...» (тричі) і двопсалміє (під час псалмів – звичайне кадіння). Шестипсалміє. (священник читає ранкові молитви). Велика ектенія. «Алилуя»», глас 8-й (зі стихами), і тропар «мелодійно та з розчуленням», глас той же: «Коли славні ученики...». «Слава» – той же, «І нині» – той же. Примітка. «А після тропарів входить настоятель з дияконом у святий вівтар, і одягнувшись в священні одежі, кадить святу трапезу хрестоподібно, і весь святий вівтар, і хори, і братію за чином» (Типікон, гл. 49, «Послідовність Святих і спасительних Страстей...»,«У Святу і Велику П’ятницю ранку»). Церковний Устав вказує читати Євангелія Святих Страстей у вівтарі (причому Євангеліє залишається на престолі), але вже твердо встановився звичай читати їх на середині храму. На початку співу тропаря відкриваються царські врата, і предстоятель в фелоні виносить Євангеліє на середину церкви. Запалюють свічки священнослужителі і молільники. Свічки після прочитання кожного Євангелія гасяться і запалюються перед початком наступного Євангелія [2]. Далі, під час протяжного співу тропаря, предстоятель звершує повне кадіння всього храму. Після закінчення тропаря і кадіння – мала ектенія [3], виголос: «Бо Твоя влада і Твоє є Царство...». Потім: «І Щоб сподобитися нам...» 4, «Премудрість, станьмо побожно...», «Мир всім» та інше за звичаєм. Примітка. За традицією, перед читанням кожного Євангелія вдаряють у великий дзвін відповідно до черговості читань (1 раз – перед першим, 2 рази – перед другим і т. д.). Після закінчення 12-го Євангелія – ​​коротке дзвоніння. Перед читанням Євангелія, за традицією, хор співає: «Слава страстям Твоїм, Господи» (але Типікон не дає такої вказівки). Після прочитання Євангелія хор: «Слава довготерпінню Твоєму, Господи» (цей приспів вказується Типіконом). Після кожного з п’яти перших Євангелій співаються зворушливі антифони, які доповнюють євангельське читання, розкриваючи глибокий духовний зміст згадуваної події. Якщо буде важко всіх їх проспівати, то необхідно прочитати, причому кожен тропар цих антифонів співається або читається по двічі; особливість такого виконання спеціально обговорена Уставом (див. Типікон, гл. 49, «Послідування Святих і спасительних Страстей...», «У Святу і Велику П’ятницю ранку»). Після 3-го, 6-го, 9-го, 12-го і 15-го антифону – малі ектенії, потім співаються сідальні [5], під час яких, за усталеною традицією, відбуваються малі кадіння (починаючи з Євангелія, що лежить на аналої). Типікон наказує диякону або священику кадити тільки святу трапезу, тобто Престол, але так буває лише в тих випадках, коли Євангеліє читається не на середині храму, а у вівтарі. Після того, як сідальний буде проспіваний, співається: «Слава», і кінець сідального, потім: «І нині», і весь сідальний вдруге. 1-е Євангеліє – Ін., Зач. 46. ​​ Антифони 1-ий, 2-ий, 3-ій. Виголос після ектенії: «Бо Тобі належить усяка слава...». Сідальний, глас 7-ий: «На вечері учеників годуючи...». Примітка. «1-е Євангеліє читає настоятель, а інші один за одним священики» (порівн.: Типікон, гл. 49, «Послідовність Святих і спасительних Страстей...», «У Святу і Велику П’ятницю ранку»). Типікон, також, вказує що 12-те Євангеліє читає настоятель. 2-е Євангеліє – Ін., Зач. 58. Антифони 4-ий, 5-ий, 6-ий. Виголос після ектенії: «Бо благословилося і прославилося всечесне і величне ім’я Твоє, Отця, і Сина, і Святого Духа, нині, і повсякчас, і на віки віків». Сідальний, глас 7-ий: «Що примусило тебе, Іудо зробитися зрадником Спасителя...». 3-є Євангеліє – Мф., Зач. 109. Антифони 7-ий, 8-ий, 9-ий. Виголос після ектенії: «Бо Ти є Бог наш, і Тобі славу возсилаємо...» [6]. Сідальний, глас 8-ий: «О, як Іуда...». 4-е Євангеліє – Ін., Зач. 59. Антифони 10-ий, 11-ий, 12- ий. Виголос після ектенії: «Нехай буде влада Царства Твого благословенна, і найславніша, Отця, і Сина, і Святого Духа нині, і повсякчас, і на віки віків». Сідальний, глас 8-ий: «Коли Ти, Боже, став перед Каяфою...». 5-е Євангеліє – Мф., Зач. 111. Антифони 13-ий, 14-ий, 15-ий. Виголос після ектенії: «Бо благословилося Всесвяте Ім’я Твоє, і прославилося Царство Твоє, Отця, і Сина, і Святого Духа нині, і повсякчас, і на віки віків». Сідальний, глас 4-ий: «Викупив Ти нас Господи...». 6-е Євангеліє – Мк., Зач. 67. Після 6-ого Євангелія – співаються Блаженні Тріоді (з тропарями) [7]. На блаженних – мале кадіння. Мала ектенія. Виголос: «Бо Тебе хвалять всі Сили Небесні...». «Будьмо уважні». «Премудрість». Прокимен, глас 4-ий: «Розділили ризи Мої собі і за одежу Мою кидали жереб»; стих: «Боже, Боже Мій, почуй Мене! Нащо покинув Ти Мене?». 7-е Євангеліє – Мф., Зач. 113. Псалом 50-й [8]. 8-е Євангеліє – Лк., Зач. 111. Трипіснець Тріоді, творіння прп. Косми, глас 6-ий, ірмоси по двічі, тропарі на 12, з приспівом: «Слава Тобі, Боже наш, слава Тобі» (Біблійні пісні не читаються). Катавасія – той же ірмос. Після 5-ої пісні – ектенія мала. Виголос: «Бо Ти є Цар миру...». Кондак Тріоді, глас 8-ий: «Прийдіть, усі оспіваємо заради нас розіп’ятого...», та ікос, глас той же: «Коли побачила Агниця Агнця...». Читаємо синаксар Стихи на розп’яття: Ти, Боже, живий – і умертвлений на древі; О, оголений мертвець – і Син Бога Живого! «Чеснішу» не співаємо. На 9-ій пісні – звичайне кадіння храму (починається, як правило, у вівтарі в кінці 8-ої пісні канону і закінчується біля престолу). Після 9-ої пісні «Достойно є» не співається. Мала ектенія [9]. Виголос: «Бо Тебе хвалять...». Екзапостиларій Тріоді: «Розбійника благорозумного...», «Слава» – той же, «І нині» – той же. 9-е Євангеліє – Ін., Зач. 61. «Все, що дише...» [10] і хвалітні псалми. На хвалітніх стихири Тріоді, глас 3-ій – 4 (перша стихира – двічі). «Слава» – Тріоді, глас 6-й: «Зняли з Мене ризи Мої...», «І нині» – Тріоді, глас той же: «Плечі Мої Я віддав на рани...». 10-е Євангеліє – Мк., Зач. 69. Читець: «Слава Тобі, що показав нам світло» («Тобі слава подобає...» не промовляється), і читається повсякденне славослів’я. Ектенія: «Доповнімо ранню молитву...», виголос: «Бо Ти Бог милості...», і звичайна голововклонна молитва (з виголосом: «Бо Твоє є...») [11]. 11-е Євангеліє – Ін., Зач. 62. На стиховні стихири Тріоді, глас 1-ий і глас 2-ий – 4 (зі своїми приспівами). «Слава» – Тріоді, глас 8-ий: «Господи, коли сходив Ти на Хрест...», «І нині» – Тріоді, глас 6-ий: «Ось уже вмочується тростина...». Примітка. Під час співу стиховних стихир (перед 12-им Євангелієм) звершується повне кадіння всього храму, як і на початку (перед 1-им Євангелієм): «Потім диякон кадить, як і на початку, храм весь» (порівн.: Типікон, гл. 49, «Послідування Святих і спасительних Страстей...», «У Святу і Велику П’ятницю ранку»). 12-е Євангеліє – Мф., Зач. 114. Священник забирає Євангеліє у вівтар. Царські врата зачиняються. «Благо є» (один раз). Трисвяте. Після «Отче наш» – співається тропар, глас 4-й: «Викупив Ти нас Господи...». Ектенія: «Помилуй нас, Боже...». Виголос: «Бо Ти Милостивий і Людинолюбний...». Хор: «Амінь». Диякон: «Премудрість». Хор: «Благослови». Священник: «Сущий благословенний...». Хор: «Амінь», «Утверди Боже...». Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст: «Христос, що для спасіння світу обплювання, биття, хрест і смерть перетерпів, істинний Бог наш, молитвами, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і Людинолюбний» (святі храму і дня не поминаються). Співаються многоліття. 1-ий час до ранньої не приєднується, оскільки входить в службу часів Великої П’ятниці. У Велику П’ятницю царські часи (див. в Постовій Тріоді на ряду) і зображальні звершуються за тим же чином, що і в навечір’я Різдва Христового і Богоявлення [12]. Примітка. За Уставом, царські часи починаються «о 2-ій годині дня», тобто, близько 8-ої години ранку: «о 2-ій годині дня, [дзвін у два, одинарний довгий.] І збираємось в церкві. Коли одягнеться Священник у священні ризи, диякон же в стихар. Співаємо часи, 1, 3, 6 і 9» (порівн.: Типікон, гл. 49,«Послідовність часів святої Великої П’ятниці»). На царських часах читаються особливі псалми, паремії, Апостоли і Євангелія. Примітка. На 3-му часі читається розповідь про Страсті Христові за Євангелієм від Марка. Згідно богослужбового Євангелія, читання починаються з 67-го зачала (Мк., 67 – 68 зач., XV, 16 – 41): «В той час, воїни повели Ісуса до середини двору, тобто в преторію...»; Типікон і Тріодь Постова вказують початок читання з 66-го зачала (Мк., 66 – 68 зач., XV, 1 – 41): «В той час, первосвященики і старійшини...». На всіх часах кінцевий виголос священника – «Боже, змилосердься над нами...». Закінчення зображальних: на «І нині» – Символ віри. «Послаб, прости...». «Отче наш...». Виголос: «Бо Твоє є Царство...». «Амінь». Кондак Тріоді, глас 8-ий: «Заради нас розіп’ятого...». «Господи, помилуй» (40). Молитва: «Всесвята Тройце...». «Нехай буде благословенне ім’я Господнє...» (тричі), «Слава, і нині», псалом 33-ій: «Благословляю Господа...». Диякон: «Премудрість». Хор: «Достойно є...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст: «Христос, що для нас, людей, і для нашого спасіння страшні муки, і Животворчий Хрест, і добровільне погребіння тілом прийняти зволив, Істинний Бог наш,молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і Людинолюбний». Співається многоліття. Літургія у Велику П’ятницю не звершується. Примітка. «Слід знати, про те, що прийняли в Палестині, в цей день Великої П’ятниці, не звершувати літургії Ранішосвячених, ані повної Літургії, трапези не готуємо і нічого не їмо в цей день Розп’яття. Якщо ж хто буде дуже немічним або престарілим, і не в змозі перебувати в пості, дається йому хліб і вода, після заходу сонця» (Типікон, гл. 49,«Послідовність часів Святої Великої П’ятниці»). ВЕЧІРНЯ ВЕЛИКОЇ П’ЯТНИЦІ. Вечірня звершується зазвичай у другій половині дня. Примітка. За Уставом, вечірня починається «о 10-ій годині дня», тобто, близько 4-ої годин після полудня: «О 10-ій годині дня клеплять (дзвонять) в велике, і зібравшись до церкви, починаємо вечірню» (порівн.: Типікон, гл. 49, «У Святу і Велику п’ятницю увечері»). До початку вечірні свята Плащаниця із зображенням положення Господа до гробу покладається на святому престолі на місце Євангелія, а саме Євангеліє ставиться в горі престолу, як на Літургії. Плащаниця кладеться так, щоб Голова Спасителя була на північній стороні. Якщо є живі квіти, то на Плащаницю покладають вінок з таких квітів [13], і якщо є запашне масло або трояндова вода, то ними намащують Плащаницю. Класти на Плащаницю вінки зі штучних квітів, намащувати ї ї духами або одеколоном, виготовленим на спирту, не слід. Закривати лик Спасителя на Плащаниці Покрівцями теж не потрібно [14]. На Плащаницю кладеться Євангеліє (бажано невеликого розміру). На середині храму встановлюється спеціальна підставка (у вигляді гробниці) або столик для Плащаниці. Примітка. Священику варто звертати увагу й на місцеві традиції парафії, якщо вони не суперечать основі уставу богослужіння, то їх не викорінювати. Службовий священник, а при соборній служінні один предстоятель, одягається в усі священичі одежі (без читання відповідних молитов) – заради виносу Плащаниці (втім, предстоятель може одягатися на стихирах на стиховні або під час читання паремій). Виголос: «Благословен Бог наш...». Читець (за Уставом, «предстоятель промовляє»): «Слава Тобі, Боже наш...», «Царю Небесний», Трисвяте. Після «Отче наш» священник – виголос: «Бо Твоє є Царство...». «Амінь», «Господи, помилуй» (12), «Слава, і нині», «Прийдіть, поклонімось» (тричі), і читається Початковий псалом: «Благослови, душе моя, Господа...» (священик читає світильничні молитви перед царськими вратами). Велика ектенія. Кафизми немає. На «Господи, взиваю» стихири Тріоді, глас 1-ий, глас 2-ий і глас 6-ий – 6 (перша стихира – двічі). «Слава» – Тріоді, глас 6-ий: «О, як беззаконне зборище засудило на смерть Царя світу...», «І нині» – Тріоді, глас той же: «Страшна і преславна таїна...». Вхід з Євангелієм. «Світло Тихе». Прокимен паремії Тріоді, глас 4-ий: «Розділили ризи Мої собі і за одежу Мою кидали жереб»; стих: «Боже, Боже мій! Зглянься на мене! Нащо Ти покинув мене?» [15]. Після прокимна, за звичаєм, царські врата зачиняються. Читаються три паремії Тріоді (Виходу, Іова та Ісаї). Після закінчення 1-ої паремії Тріоді (Виходу) – прокимен Тріоді, глас 4-ий: «Господи! Будь Суддею тих, що змагаються зі мною, і побори тих, що бажають побороти мене» [16]; стих: «Візьми зброю Твою і щит і стань на поміч мені», потім – 2-а паремія Тріоді (Іова). Після закінчення 3-ої паремії Тріоді (Ісаї) царські врата відчиняються. «Будьмо уважні», «Мир всім», і інше (як на Літургії). Прокимен Апостола, глас 6-ий: «Ти поклав мене у рові преісподнім, у темряві і тіні смертній»; стих: «Господи, Боже спасіння мого, вдень я взиваю і вночі перед Тобою». Примітка. За звичаєм, перед читанням Євангелія звершується кадіння, як на повній Літургії. Апостол – 1 Кор., Зач. 125. Алилуарій, глас 1-ий (за Типіконом – глас 5-ий): «Спаси мене, Боже, бо води дійшли до душі моєї»; стих: «Зневага і страждання крушать серце моє»; стих: «Нехай потемніють очі їхні, щоб не бачили, і спини їхні назавжди зігни». Євангеліє [17] (складене) [18] – Мф., Зач. 110. (За звичаєм, Євангеліє читається дияконом на амвоні). Після читання Євангелія царські врата зачиняються. Ектенія потрійна: «Промовмо всі...». «Сподоби, Господи». Ектенія прохальна: «Доповнімо вечірню молитву...», і голововклонна молитва. На стиховні стихири Тріоді, глас 2-ий – 4 (зі своїми приспівами: «Господь воцарився...», «Бо Він утвердив вселенну...», «дому Твоєму належить слава...»). «Слава, і нині» – Тріоді, глас 5-ий: «Тебе, що зодягаєшся світлом, наче ризою...» (за звичаєм, під час співу цієї стихири відкриваються царські врата, і предстоятель з дияконом звершують триразове кадіння навколо престолу на котрому лежить плащаниця). «Нині відпускаєш». Трисвяте. Після «Отче наш» священник – виголос: «Бо Твоє є Царство...», і співаються тропарі, глас 2-ий: «Благообразний Йосиф...». «Слава, і нині» – «Мироносиці жони...». Під час співу тропарів предстоятель, зробивши три земні поклони, Підіймає з престолу Плащаницю і через північні врата [19] (у супроводі свічконосців і диякона зі свічкою і кадилом) виносить її над головою на середину храму і кладе на приготовану гробницю. При соборному служінні настоятель йде під Плащаницею, несучи Євангеліє над головою або в руках. Якщо священик один, Євангеліє благоговійно несе в лівій руці диякон, тримаючи в правій кадило. Якщо немає диякона, священик благословляє кому-небудь з благочестивих мирян нести Євангеліє загорнутим в плат. Євангеліє в цих випадках несуть попереду Плащаниці. Потім Євангеліє кладеться на Плащаницю. Далі відбувається триразове кадіння навколо Плащаниці, після чого священнослужителі звершують поклоніння і цілування Плащаниці. Примітка. У тих храмах, де мале повечір’я у Велику П’ятницю після вечірні не звершується, існує практика співу канону Тріоді «Про розп’яття Господа і на плач Пресвятої Богородиці» (див. На малому повечір’ї) після виносу Плащаниці на вечірні (після тропарів перед відпустом). Після катавасії 9-ої пісні канону – «Премудрість» і закінчення вечірні. За тропарях – «Премудрість». Хор: «Благослови». Священник: «Сущий благословенний...». Хор: «Утверди, Боже...». Священик: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст: «Христос, Істинний Бог наш, що для нас, людей, і для нашого спасіння страшні муки, і Животворчий Хрест, і добровільне погребіння тілом прийняти зволив, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і Людинолюбний». Хор – многолітня [20]. За звичаєм, після відпусту виголошується проповідь [21] . Потім відразу – МАЛЕ ПОВЕЧІР’Я [22]. На повечір’ї – канон Тріоді «Про розп’яття Господа і на плач Пресвятої Богородиці», творіння Симеона Логофета, глас 6-ий (ірмоси по двічі, тропарі на 4). Канон, по можливості, краще читати самому настоятелю перед Плащаницею. Після кожної пісні катавасія – той же ірмос. Після 6-ої пісні – «Господи, помилуй» (тричі), «Слава, і нині» – кондак Тріоді, глас 8-ий: «Прийдіть усі заради нас розіп’ятого...», та ікос, глас той же: «Коли побачила Агниця Агнця...». Після «Отче наш» – кондак Тріоді, глас 8-й: «Прийдіть усі заради нас розіп’ятого...», та іншу послідовність малого повечір’я. Відпуст малий: «Христос, істинний Бог...». І відбувається цілування Плащаниці народом. Під час цілування прийнято співати стихиру, глас 5-ий: «Прийдіть, вшануймо Йосифа приснопам’ятного...». Помазання єлеєм не відбувається. [1] Див. У четвер 5-го тижня Великого посту. [2] «Тоді настоятель церкви роздає свічі ​​ братії, які запалюють перед кожним Євангелієм» (Типікон, гл. 49, «Послідовність Святих і спасительних Страстей...», «У Святу і Велику П’ятницю ранку»). [3] «Ці ектенії промовляють диякони, або священики перед сідальним до 8-го Євангелія» (Типікон, гл. 49, «Послідовність Святих і спасительних Страстей...», «У Святу і Велику П’ятницю ранку»). [4] Промовляється перед читанням кожного Євангелія. [5] «Сідальний... співається посеред церкви канонархом. Слава: кінець, І нині: знову весь. На них же не сидимо, але стоячи співаємо, тоді Священник або диякон кадить святу трапезу (Престол)» (Типікон, гл. 49, «Послідовність Святих і спасительних Страстей...», «У Святу і Велику П’ятницю ранку»). [6] Служби Великого посту. [7] Стихи Блаженних і тропарі слід співати. У тих храмах, де виконання цієї уставної традиції є неможливими, допускається стихи Блаженних співати, а тропарі до них – читати. Спів Блаженних з тропарями є особливістю ранньої Великого канону і утрені Великої П’ятниці (з читанням 12-ти Євангелій), а тому ні в якому разі не має пропускатися. [8] У Типіконі сказано: «З цього моменту диякон перестає кадити, і ектенії сідальних не промовляють» (див.: Типікон, гл. 49, «Послідування Святих і спасительних Страстей...», «У Святу і Велику П’ятницю ранку»). [9] Типікон про цю ектенію нічого не говорить, але це звичайне замовчування. [10] Для повсякденної ранньої не характерний спів хвалитніх псалмів зі слів: «Все, що дише...», але на ранній Великої П’ятниці «Все, що дише...» перед хвалітніми псалмами прямо вказується Типіконом і Постовою Тріоддю і є особливістю богослужіння цього дня. [11] Типікон про голововклонну молитву замовчує: «Після цього священник ектенію: Доповнімо ранню молитву, та інше за звичаєм. І після виголосу: Бо Ти Бог милості, читає Євангеліє 11-е, Іоана, зачало 62». Повсюдно ж в богослужбовій практиці після виголосу ектенії слідує звичайне благословення: Мир всім, і голововклонна молитва (з виголосом «Бо Твоє є...»). [12] зображальні у Велику П’ятницю починаються з «У Царстві Твоїм...». [13] Більш правильно живі квіти класти на Плащаницю тоді, коли вона вже винесена на середину храму, інакше під час ходи вони можуть збитися або впасти. [14] Настільна книга священнослужителів. [15] Прокимен «Розділили ризи Мої собі...» виголошує диякон (або священик). [16] На спів прокимна царські врата, за традицією, відкриваються. [17] Про читання Євангелія на вечірні Великої П’ятниці див. В додатку до «богослужбових вказівок на 1999 рік» (с. 597 – 598). [18] Складені євангельські читання Страсного тижня, а також 12 Євангелій Святих Страстей на ранній Великої П’ятниці, наводяться повністю в додатку богослужбових Євангелій. [19] На архієрейській службі Плащаниця виноситься також через північні врата. [20] Богослужіння Страсного тижня. [21] Для того, щоб ті, що моляться в побожній тиші могли чути зворушливий канон повечір’я, поклоніння і цілування Плащаниці відбувається не після відпусту вечерні, а після повечір’я. [22] «Повечір’я ж співаємо в келіях» (порівн.: Постова Тріодь).","sections":[],"special":true},
{"date":"04-11","weekday":"субота","title":"Велика субота. Сщмч. Антипи, єп. Пергама Асійського (бл. 68). Мчч. Прокеса і Мартиніана (бл. 67). Прп. Фармуфія (ІV). Прп. Іоана, учня прп. Григорія Декаполіта (820 – 850). Свт. Калиника Черникського (1868, Рум.). Літургія за чином свт. Василія Великого.","readings":["Ран. – Ап. складений: 1 Кор., 133 зач., V, 6 – 8; Гал., 206 зач., III, 13 – 14. Мф., 114 зач., XXVII, 62 – 66.","Літ. – Рим., 91 зач., VI, 3 – 11. Мф., 115 зач., XXVIII, 1 – 20."],"notes":"ПОЛУНОШНИЦЮ «співаємо в келіях, і промовляємо кафизму 9-ту» (Типікон, гл. 49, «У Святу і Велику п’ятницю ввечері», 2-е «див»). Після 1-ого Трисвятого – тропар, глас 2-ий: «Благообразний Йосиф...». Після 2-го Трисвятого – кондак Тріоді, глас 6-ий: «Той, Хто безодню замкнув, мертвим стає...» (див на ранній Великої Суботи). «Господи, помилуй» (12), і відпуст (заупокійна молитва «Пом’яни, Господи...» не промовляється). Примітка. За Уставом, рання Великої Суботи починається «о 7-ій годині ночі», тобто, близько 1-ої години ночі (порівн.: Типікон, гл. 49, «У Святу і Велику Суботу»). Початок РАННЬОЇ звичайний (з «Царю Небесний...»). Псалми 19-ий і 20-ий (під час псалмів – звичайне кадіння). Шестипсалміє. (священник читає ранкові молитви [1]). Ектенія велика. Примітка. У Велику Суботу – на ранній, часах, вечірні, Літургії – все, що зазвичай читається на солії, як-то: ектенії, Апостол, Євангеліє, вхідні (а також Заамвонна) молитви – промовляється перед Плащаницею. Малий і великий входи відбуваються також перед Плащаницею. Причастя мирян і відпуст – на амвоні. На «Бог Господь» – тропар, глас 2-ий: «Благообразний Йосиф...». «Слава» – інший тропар, глас той же: «Коли зійшов Ти...», «І нині» – інший тропар, глас той же: «Мироносицям жонам...». Примітка. «Потім настоятель роздає свічі братії: і починаємо співати непорочні з розчуленням... Тоді настоятель кадить всю церкву, і братію за чином» (Типікон, гл. 49,«У Святу і Велику Суботу»). З початком співу тропарів відкриваються царські врата, священнослужителі виходять до Плащаниці. Предстоятель роздає запалені свічки співслужителям. Запалюють свічки і всі присутні. Предстоятель з дияконом кадять Плащаницю навкруги (тричі) і звершують, за традицією, повне кадіння храму. Безпосередньо після закінчення тропарів починається спів Непорочних (на 5-ий глас, і на той же глас – похвали). За Уставом, повинна співатися вся 17-а кафизма (з похвалами), але зазвичай хор співає кілька перших стихів з їх похвалами, потім співають тільки стихи псалмів, а похвали читають священнослужителі. При соборному служінні стихи псалмів можуть співати всі священнослужителі. Також існує практика, за якою і стихи псалмів, і похвали читаються. Якщо священик один, то читець читає стихи псалмів, а священик – похвали [2]. Після 1-ої статті – ектенія мала. Виголос: «Бо благословилося Ім’я Твоє, і ​​ прославилося Царство Твоє Отця, і Сина, і Святого Духа, нині, і повсякчас, і на віки віків». З початком 2-ої статті звершується мале кадіння. За традицією, малі кадіння робить священик з дияконом. Примітка. «І покадивши, починає 2-у статтю. Другий хор співає приспів: Достойно є величати Тебе, Життєдавця... Також священник кадить тільки ікони, і хори» (Типікон, гл. 49,«У Святу і Велику Суботу») [3]. Друга стаття виконується, як і перша. Після закінчення її – мала ектенія. Виголос: «Бо Ти святий, Боже наш, що на Престолі Слави Херувимської перебуваєш, і Тобі славу возсилаємо, з Безначальним Твоїм Отцем, і з Пресвятим, і Благим, і Животворчим Твоїм Духом, нині і повсякчас, і на віки віків». На початку 3-ої статті, яка, за Уставом, співається на 3-ій глас – мале кадіння. Примітка. «І починаємо 3-ю статтю, кадінням настоятеля» (Типікон, гл. 49, «У Святу і Велику Суботу»). Після закінчення 3-ої статті – тропарі недільні, співаються після Непорочних, глас 5-ий: «Ангельський собор...» (зі звичайним приспівом: «Благословен єси, Господи...»). У цей час, за традицією, відбувається повне кадіння всього храму [4]. Мала ектенія. Виголос: «Бо Ти є Цар миру, Христе Боже наш, і Тобі славу возсилаємо, з Безначальним Твоїм Отцем, і з Пресвятим, і Благим, і Животворчим Твоїм Духом, нині і повсякчас, і на віки віків». Після виголосу – сідальний Тріоді, глас 1-ий: «Випросивши у Пилата, Йосиф обгортає плащаницею чистою пречисте тіло...». «Слава» – той же сідальний [5], «І нині» – інший сідальний, глас той же: «Вжахнулися собори ангелів...» [6]. Псалом 50-ий. (Священнослужителі йдуть до вівтаря. Царські врата зачиняються. «Воскресіння Христове бачивши...» не співається. Молитва: «Спаси, Боже, людей Твоїх...» не читається). Канон Великої Суботи з Тріоді, глас 6-ий: «Того, Хто хвилею морською...», з ірмосом на 14 (ірмоси по двічі, тропарі на 12). Приспіви до тропарів: «Слава Тобі, Боже наш, слава Тобі». Біблійні пісні не читаються. Катавасія після кожної пісні – ірмоси того ж канону. Після 3-ої пісні – сідальний Тріоді, глас 1-ий: «Воїни, що стерегли гріб Твій, Спасе...». «Слава, і нині» – той же сідальний. Після 6-ої пісні – кондак Тріоді, глас 6-ий: «Той, Хто безодню замкнув...», та ікос, глас той же: «Вседержитель світу на хрест піднесений...». Читаємо синаксар стихи: Даремно, стороже, охороняєш гріб: Не втримає могила Самобутнього Життя... На 9-ій пісні – звичайне кадіння («Чеснішу» не співаємо). Після 9-ої пісні «Достойно є...» не співається. Замість Світильного співається на 2-ий глас: «Свят Господь Бог наш...», зі стихами (тричі). Примітка. До початку співу великого славослів’я (зазвичай під час канону або хвалітніх стихир) предстоятель одягається в усі священичі ризи (без читання відповідних молитов). «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 2-ий і глас 6-ий – 4. «Слава» – Тріоді, глас 6-ий: «Цей великий день Мойсей таємно прообразував,...», «І нині» – Богородичний, глас 2-ий: «Преблагословенна єси, Богородице Діво...». На спів «І нині» хвалітніх стихир відкриваються царські врата, і священнослужителі царськими вратами виходять до Плащаниці (предстоятель – в повному облаченні). Виголос на славослів’я предстоятель виголошує перед Плащаницею. У давнину існувала також наступна практика: під час співу хвалітних стихир Плащаницю несли в вівтар і клали на престолі. Під час великого славослів’я звершували кадіння престолу навколо тричі і через північні врата виносили Плащаницю на хресний хід. Після закінчення хресного ходу Євангеліє клали на престол, а Плащаницю на приготовану гробницю; Євангеліє читалося у вівтарі, а не перед Плащаницею, як це прийнято зараз повсюдно. Співається велике славослів’я. Предстоятель з дияконом звершують триразове кадіння навколо Плащаниці. З початком співу Трисвятого всі священнослужителі роблять три земні поклони. Потім вони беруть Плащаницю; предстоятель йде під Плащаницею з малим Євангелієм на чолі. Якщо є один священик, то він піднімає Плащаницю і передає її побожним мирянам, а сам з Євангелієм входить під Плащаницю; або сам над своєю головою несе Плащаницю, а Євангеліє передає диякону. Відбувається хресний хід навколо храму. Під час хресного ходу повільно співається «Святий Боже...», і буває передзвін (від великого дзвону до малих, але не навпаки), а коли хід увійде в храм, відбувається коротке дзвоніння. Після входу в храм Плащаницю підносять до царських врат. Предстоятель після закінчення співу «Святий Боже...» виголошує, підносячи Євангеліє: «Премудрість, станьмо побожно», і Плащаниця відноситься на середину храму. Звершується кадіння навколо Плащаниці (тричі). У цей час співаються [7]. тропар Тріоді, глас 2-ий: «Благообразний Йосиф...» (один раз). Далі тропар пророцтва, глас 2-ий: «Ти, що тримаєш кінці землі...», «Слава [8], і нині» – той же тропар. Диякон: «Будьмо уважні». Читець – прокимен паремії Тріоді, глас 4-ий: «Воскресни, Господи, поможи нам, і визволи нас імені Твого»; стих: «Боже, вухами нашими чули ми, і батьки наші сповістили нам». Диякон: «Премудрість». Читець: «Пророцтва Єзекиїля читання». Диякон: «Будьмо уважні». І читання паремії Тріоді. Диякон: «Будьмо уважні». Читець – прокимен Апостола, глас 7-ий: «Воскресни, Господи Боже мій, нехай піднесеться рука Твоя, і не забудь убогих Твоїх до кінця»; стих: «Сповідуюсь Тобі, Господи, всім серцем моїм, розповім всі чудеса Твої». Диякон: «Премудрість». Апостол (складений) – 1 Кор., Зач. 133. Алилуарій, глас 5-ий: «Нехай воскресне Бог, і розвіються вороги Його»; стих: «Як щезає дим, нехай щезнуть, як тане віск від лиця вогню»; стих: «Так нехай загинуть грішники від лиця Божого, а праведники нехай звеселяться». Євангеліє – Мф., Зач. 114 (читається, за традицією, предстоятелем біля Плащаниці). Ектенії: повна потрійна – «Промовмо всі...», і благальна – «Доповнімо ранню молитву...» (з голововклонною молитвою), та інше за звичаєм. Великий відпуст виголошується з амвона: «Христос, що заради нас людей, і заради нашого спасіння страшні муки, і Животворчий Хрест, і добровільне погребіння тілом прийняти зволив, істинний Бог наш молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і Людинолюбний». Після відпусту хор співає многоліття, потім – стихиру Тріоді на цілування Плащаниці, глас 5-ий: «Прийдіть, вшануймо Йосифа приснопам’ятного...», і відбувається цілування Плащаниці. Примітка. «І відбувається цілування плащаниці покладеної у гробі. А де немає плащаниці, цілують образ. А хор співає стихиру, глас 5-ий: Прийдіть, вшануймо: і 1-ий час» (Типікон, гл. 49,»У Святу і Велику Суботу»). «А Перший час співається в притворі» (Тріодь Постова, «У Святу і Велику Суботу»). Час 1-ий приєднується до ранньої і закінчується малим відпустом. Окремо звершуються часи 3-ій, 6-ий і 9-ий і зображальні [9]. Примітка. «В годині ж 4-ій дня. Вдаряє параеклісіарх в мале било. І зібравшись співаємо час 3, 6, і 9... в притворі» (Типікон, гл. 49,«У Святу і Велику Суботу»). Перед початком часів священнослужителі, за традицією, читають вхідні молитви (за звичаєм, перед Плащаницею), одягаються і починають проскомидію.","sections":[{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Тріоді: «Благообразний Йосиф...». Кондак Тріоді: «Той, Хто безодню замкнув, мертвим стає...»."},{"svc":"ЗОБРАЖАЛЬНИХ","text":"НА ЗОБРАЖАЛЬНИХ – Блаженні «скоро», без співу (як у Великий Четвер). На «І нині» – «Вірую...». «Послаб, прости...». Після «Отче наш» і виголос: «Бо Твоє є Царство...» – кондак Тріоді: «Той, Хто безодню замкнув, мертвим стає...», «Господи, помилуй» (12). Молитва: «Всесвята Тройце...». Священник (або диякон): «Премудрість». Хор: «Достойно є...» до слів: «і Матір Бога нашого» (включно). Священник: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Священник: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Відпуст малий: «Христос, істинний Бог...». ВЕЧІРНЯ з’єднується з Літургією за чином свт. Василія Великого. Примітка. За Уставом, вечірня з Літургією свт. Василія Великого починається «о 10-ій годині дня», тобто, близько 4-ої години після полудня (порівн.: Типікон, гл. 49, «У Святу і Велику Суботу вечора»). Виголос: «Благословенне Царство...». Звичайний початок (з «Царю Небесний...»), псалом 103-ї (священик читає світильничні молитви [10]). Велика ектенія. Кафизми немає. «Господи, взиваю», глас 1-ий. В цей час закінчується проскомидія, і звершується кадіння всього храму. На «Господи, взиваю» стихири Тріоді на 8: недільні, глас 1-ий – 4, і Великої Суботи, глас 8-ий – 4 (перша стихира – двічі). «Слава» – Тріоді, глас 6-ий: «Цей великий день Мойсей таємно прообразував...», «І нині» – догматик, глас 1-ий: «Всесвітню славу...». Вхід з Євангелієм (перед Плащаницею). «Світло Тихе...». Прокимна немає. Царські врата зачиняються, і відразу починається читання 15 паремій Тріоді (за традицією, перед Плащаницею). Спочатку читаються 1-6 паремії. В кінці 6-ої паремії царські врата, за традицією, відкриваються. Читець виголошує: «Співаймо Господеві». Хор співає на 5-ий глас: «Славно бо прославився». Читець виголошує такі стихи з пісні пророка Мойсея, хористи розділившись на два хори після кожного стиха співають: «Славно бо прославився». Після всіх стихів, читець: «Слава...». Хор: «Славно бо прославився». Читець: «І нині...». Хор: «Славно бо прославився». І на закінчення сам читець співає: «Славно бо прославився». Царські врата зачиняються. Читаються 7 – 15 паремії. В кінці 15-ої паремії, на словах: «Благословенний Ти на тверді небесній, і прехвальний, і преславний повіки», царські врата, за традицією, відчиняються, і співається пісня трьох отроків (в такому ж порядку, як виконувалася по 6-ій паремії пісня пророка Мойсея). Співається: «Господа оспівуйте і прославляйте по всі віки»; далі читець виголошує стихи пісні, а хор до кожного стиха приспівує: «Господа оспівуйте і прославляйте по всі віки». До стиха «Нехай благословляє земля Господа, нехай оспівує і прославляє Його повіки». Після стиха «Благословимо Отця і Сина і Святого Духа» слід співати: «Господа оспівуйте і прославляйте по всі віки». Потім читець: «І нині». Хор: «Господа оспівуйте і прославляйте по всі віки». Останній стих, за традицією, співає сам читець: «Хвалимо, благословимо, поклоняємося Господеві, оспівуючи і прославляючи по всі віки». Мала ектенія. Виголос: «Бо Ти святий єси, Боже наш...» [11]. Замість Трисвятого – «Усі ті, що в Христа хрестилися...». Прокимен, глас 5-ий: «Вся земля нехай поклониться Тобі і співає Тобі нехай, співає ж імені Твоєму, Всевишній»; стих: «Викликніть Господу, вся земле! Співайте ж імені Його, віддайте славу й хвалу Йому». Апостол (читається, за традицією, перед Плащаницею) – Рим., Зач. 91. Алилуарій не співається, але читець виголошує замість «Алилуя»»: «Глас сьомий», і виголошує (або співає) стихи 81-го псалма: «Воскресни, Боже, суди землю, бо Ти успадкував усі народи»; стих: «Бог став у сонмі богів, посеред них, щоб богів судити»; стих: «Доки будете судити неправедно і догоджати грішникам?»; стих: «Судіть сироту і вбогого по правді, смиренного і бідного виправдайте»; стих: «Визволіть бідного й убогого, від руки грішника звільніть його»; стих: «Не пізнали і не зрозуміли, бо в темряві ходять»; стих: «Нехай захитаються всі основи землі. Я сказав: ви – боги і сини Всевишнього всі, але вмираєте, як люди, і, як кожен князь, падаєте». Хор співає приспів: «Воскресни, Боже, суди землю, бо Ти успадкував усі народи», до кожного стиха цього псалма. Під час співу «Воскресни, Боже...» царські врата зачиняються, і закривається завіса, священнослужителі переоблачаються в білі ризи, і все облачення в храмі замінюються світлим [12]. До читання Євангелія Царські врата відчиняються. Євангеліє (читається дияконом перед Плащаницею, а ієреєм без диякона – біля престолу) – Мф., Зач. 115. І далі – за чином Літургія свт. Василія Великого. Замість «Херувимської» – «Нехай мовчить всяка плоть людська...». Задостойник – ірмос 9-ої пісні канону Великої Суботи: «Не ридай по Мені, Мати...». Причасний: «Встав немов зі сну, Господь, і воскрес, спасаючи нас». Після «Спаси, Боже, людей Твоїх...» співаємо: «Ми бачили Світло Істинне...» [13]. Відпуст Літургії: «Христос, істинний Бог наш, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і Людинолюбець». Виголошувати недільний відпуст: «Христос, що воскрес із мертвих,...» не слід, бо це не відповідає змісту богослужіння Великої Суботи [14]. Після відпусту відбувається благословення хлібів та вина. Примітка. «І відпуст. Потім відбувається звичайне благословення хлібів, і вина. Приходить Священник, покадивши їх, промовляє звичайну молитву благословення: Господи Ісусе Христе, Боже наш, що благословив п’ять хлібів...: Амінь» (Типікон, гл. 49,»У Святу і Велику Суботу ввечері»). Приготований столик з хлібами і вином ставиться перед Плащаницею, в деякому віддаленні від неї, так, щоб навколо нього можна було зробити кадіння. За більш поширеною практикою столик з хлібами ставиться на солії. За звичаєм, співаються тропарі, глас 2-й: «Благообразний Йосиф...», «Слава» – «Коли зійшов ти...», «І нині» – «Мироносицям жонам...». Звершується триразове кадіння навколо столу з хлібами, потім виголошується: «Господу помолимось», хор: «Господи, помилуй», і священик читає молитву: «Господи Ісусе Христе, Боже наш, що благословив п’ять хлібів і п’ять тисяч наситив, Сам благослови хліби і вино, і примнож їх у місті цьому (або в селі цього, або у святому монастирі цьому) і в усьому світі Твоєму, і вірних що їх споживають освяти. Бо Ти все благословляєш і освячуєш, Христе Боже наш, і Тобі славу возсилаємо, з безначальним Твоїм Отцем, і Всесвятим, і Благим, і Животворчим Твоїм Духом, нині і повсякчас, і на віки віків». Хор: «Амінь». Хліби роздроблюються і роздають віруючим. У Велику Суботу на трапезі дозволяється їжа без олії і вино. Якщо освячення пасок відбувається до Світлої ранньої, то при цьому слід співати тільки недільний тропар 2-го гласу: «Коли зійшов ти до смерті...». МАЛЕ ПОВЕЧІР’Я не звершується. Після прибирання храму починається «читання велике з Діянь святих Апостолів від початку». Читець: «Діяння святих апостол благослови, отче, прочитати». Священник: «Молитвами святих апостолів, Господи Ісусе Христе, Боже наш, помилуй нас». Читець: «Амінь», і починає читання. Аналой для читання Діянь ставиться перед Плащаницею. [1] За звичаєм, перед Плащаницею. [2] Під час співу 17-ої кафизми з похвалами диякон невпинно кадить Плащаницю. [3] Устав Православної Церкви. [4] Устав замовчує про кадіння під час тропарів по Непорочних («Ангельський собор...»). [5] Згідно з Постовою Тріоддю, на «Славу» співається закінчення сідального. [6] «І читання в тлумаченні Золотоустого на Євангеліє Матфея, зачало 114» (Типікон, гл. 49, «У Святу і Велику Суботу»). [7] «І ми тропар раз: Благообразний Йосиф...» (Тріодь Постова, «У Святу і Велику Суботу»). «Промовляє настоятель: Премудрість, станьмо побожно. І читець знову тропар Благообразний Йосиф... один раз» (Типікон, гл. 49,«У Святу і Велику Суботу»). [8] Згідно з Постовою Тріоддю, на «Славу» повторюється закінчення тропаря. [9] Зображальні починаються з «У Царстві Твоїм...». [10] За звичаєм, перед Плащаницею. [11] Виголос «Бо Ти святий єси, Боже наш...» виголошується на Літургії і тоді, коли вона відбувається з вечірнею. [12] Переоблачення священнослужителів в світлий одяг – це хрещальна особливість, що зберіглася в сучасному богослужінні від давньої практики Хрещення в цей день оголошених (як і апостольське і євангельське читання Літургії Великої Суботи). [13] Існує практика співати замість «Ми бачили Світло Істинне...» воскресний тропар, глас 2-ий: «Коли зійшов ти до смерті...» однак, богослужбові книги не дають підстав для подібної заміни. [14] Служебник, про відпусти. [15] Красовуля – чаша для пиття, що вживається в грецьких монастирях, яка вміщує приблизно 409,5 грама."}]},
{"date":"04-12","weekday":"неділя","title":"СВІТЛЕ ХРИСТОВЕ ВОСКРЕСІННЯ. ПАСХА. ВЕЛИКДЕНЬ. Прп. Василія, спов., єп. Парійського (після 754). Сщмч. Зинона, єп. Веронійського (бл. 260). Прп. Ісаака Сиріна, у Сполеті Італійському (550). Прмчч. Мини, Давида та Іоана (після 636). Прп. Анфуси, діви (801). Прп. Афанасії, ігумені (860). Бєлиницької (ХІІІ) ікони Божої Матері. Літургія за чином свт. Іоана Золотоустого.","readings":["Літ. – Діян., 1 зач., I, 1 – 8. Ін., 1 зач., I, 1 – 17.","На веч.: Ін., 65 зач., XX, 19 – 25."],"notes":"Після читання Діянь святих апостолів служимо полуношницю. На 9-й пісні канону, коли співають катавасію «Не ридай за Мною, Мати...», святу Плащаницю кадимо і потім на словах «...встану і прославлюся...» підіймаємо і вносимо царськими вратами у вівтар, і кладемо на престіл, врата зачиняються, полуношниця продовжується. Відпуст короткий «Христос, істинний Бог наш...». Опівночі починається хресний хід навколо храму зі співом стихири «Воскресіння Твоє, Христе Спасе...». Пасхальна рання починається перед зачиненими західними (вхідними) дверима храму виголосом «Слава Святій...», під час цього виголосу священник трисвічником і хрестом зображує хресне знамення не один, як за звичай, а тричі і далі за пасхальним чином. Кадіння на кожній пісні канону і мала ектенія. Після стихир Пасхи читається повчальне слово свт. Іоана Золотоустого і співається йому тропар. Часи співаються пасхальні. На Літургії – антифони Пасхи. Вхідний стих: «В церквах благословіте Бога, Господа від джерел Ізраїлевих». Замість трисвятого – «Всі ви, що в Христа хрестилися...». Задостойник – «Ангел звістив...», «Світися, світися...». Замість «Благословенний, Хто йде...», «Тіло Христове прийміть...», «Ми бачили Світло істинне...», «Нехай наповняться уста наші...» співається «Христос воскрес із мертвих...» (один раз), а замість «Нехай буде ім’я Господнє...» і 33-го псалма співається «Христос воскрес із мертвих...» (багато разів). Після заамвонної молитви освячується артос. Відпуст Літургії пасхальний, без згадки святих. На вечірні: служимо у повному облаченні, вхід із Євангелієм. Після великого прокимна священник читає Євангеліє в царських вратах обличчям до народу. ЧИН ПОЛУНОШНИЦІ. При закритих царських вратах і завісі ієрей творить початок: «Благословенний Бог наш...». «Царю Небесний» не читається. Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». «Господи, помилуй» (12), «Слава, і нині», «Придіть, поклонімось...» (3), і псалом 50-ий. Канон Великої Суботи (з Постової Тріоді): «Хвилею морською...». Ірмоси по двічі, тропарі на 12, і катавасія – той самий ірмос (по кожній пісні). Канон, за традицією, читає один із священнослужителів перед Плащаницею. Після 3-ої пісні – сідальний Великої Суботи, глас 1-ий: «Воїни, що охороняли гріб Твій, Спасе...». «Слава, і нині...» – той самий сідальний. Після 6-ої пісні – кондак Великої Суботи, глас 6-ий: «Той, хто закрив безодню, стає мертвим...», і ікос, глас той самий: «Вседержитель світу на хрест піднесений...» На початку 9-ої пісні, за традицією, відкриваються царські врата. Священик, який звершує полуношницю, разом з дияконом зробивши кадіння навколо Плащаниці, при співі катавасії 9-ої пісні на словах: «Встану бо і прославлюся...» піднімає Плащаницю і вносить у вівтар. Після цього царські врата зачиняються. Плащаницю кладуть на святий престол, де вона має залишатися до відання Пасхи. Після катавасії 9-ої пісні – Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Хор співає тропар, глас 2-ий: «Коли зійшов Ти...». Ієрей виголошує коротку потрійну ектенію, як на початку ранньої: «Помилуй нас, Боже...». Після виголосу ектенії «Бо Ти Милостивий і Людинолюбний...» – хор: «Амінь». Ієрей: «Слава Тобі, Христе Боже...». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Ієрей виголошує короткий відпуст: «Христос, Істинний Бог наш, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як Благий і Людинолюбний», після чого хор співає «Господи, помилуй» (тричі). РАННЯ. Примітка. «У ранню годину параеклесіарх бере благословення у настоятеля, виходить і дзвонить у дзвін довго. Ввійшовши до храму, засвічує лампади і свічки; готує дві посудини з розпаленим вугіллям, кладе в них ладан запашний і ставить одну посудину посеред церкви, а другу у вівтарі, щоб уся церква наповнилася пахощами. Далі настоятель входить у святі врата зі священиками та дияконами й облачається у світлі ризи; роздає свічки братії і бере чесний хрест, кадило ж бере диякон, священик бере святе Євангеліє, інший священик – ікону Воскресіння Христового і стають обличчям на захід. І закривають Західні церковні врата. Виходять настоятель зі священиками (диякони ідуть попереду зі свічками) і обидва кліроси у притвор, співаючи стихиру, глас 6-ий: «Воскресіння Твоє, Христе Спасе, ангели оспівують на небесах, і нас на землі сподоби чистим серцем Тебе славити». Далі дзвонять в усі дзвони довго. І, ввійшовши у притвор, стають з Євангелієм та іконою обличчям на захід, як було сказано раніше. Потім настоятель бере кадило від диякона у праву руку, а хрест в ліву, і кадять ікону, кліроси і братію за звичаєм. Диякон же носить перед настоятелем запалену свічку. Братія стоїть зі своїми свічками, уважно молячись мовчки. Після закінчення кадіння настоятель стає перед великими дверима церкви і кадить диякона, який стоїть зі свічкою. Тоді диякон бере кадило і кадить самого настоятеля. І знову бере настоятель кадило, стає перед церковними дверима, дивлячись на схід, і знаменує хрестовидно кадилом великі двері церкви (зачинені) тричі, тримаючи в лівій руці хрест (підсвічники стоять з обох боків), і гучним голосом виголошує: «Слава Святій...» (порівн.: Типікон, гл. 50, «У Святу і Велику Неділю Пасхи»). Пасхальну ранню зазвичай починають о 12-ій годині ночі. Починати пасхальне торжество раніше півночі не рекомендують канонічні правила. Але правила ці не вказують, коли саме після півночі, в який час, або в яку половину години, або чверть години, слід розпочинати торжество Воскресіння Господа нашого з мертвих, з огляду на те, що і в самому Євангелії немає точної вказівки на годину Воскресіння. Тому не слід дивуватися, що в Типіконі про початок пасхальної ранньої йдеться не цілком виразно: «в годину ранню». В Українській Церкві встановився звичай починати пасхальне торжество рівно опівночі. Тому при наближенні півночі всі священнослужителі в повному облаченні стають за чином перед престолом. Предстоятель роздає свічки співслужителям. В цей же час запалюють свічки і всі присутні вірні. Предстоятель приймає в ліву руку хрест з пасхальним трисвічником, в праву – кадило. Опівночі при закритих царських вратах священнослужителі співають стихиру: «Воскресіння Твоє, Христе Спасе, Ангели оспівують на небесах, і нас на землі сподоби чистим серцем Тебе славити». Стихира співається тричі: за звичаєм, перший раз вона співається тихо при закритих царських вратах і завісі, другий раз – трохи голосніше при відкритій завісі, втретє – голосно при відкритих царських вратах (які після цього залишаються відкритими до кінця Світлого тижня). При кожному співі стихири предстоятель, а перед ним диякони зі свічками, звершує кадіння навколо престолу. Втретє стихира співається духовенством до половини: «Воскресіння Твоє, Христе Спасе, Ангели оспівують на небесах». Хористи, які стоять на середині храму, закінчують: «І нас на землі сподоби...». Починається хресний хід, під час якого хористи безперервно співають ту ж саму стихиру. У хресній ході попереду несуть ліхтар, за ним несуть парою запрестольні Хрест і ікону Божої Матері, далі йдуть двома рядами, попарно, хоругвоносці, хористи, свічконосці зі свічками, диякони зі своїми свічками і кадильницями і за ними священики, молодші попереду. В останній парі священиків той, що йде справа, несе Євангеліє, той що йде зліва – ікону Воскресіння Христового. Завершує хід предстоятель із трисвічником і хрестом. Там, де служить один священик, допускається мирянам нести на рушниках ікону Воскресіння Христового і Євангеліє. (Артос на цьому хресному ході не носять, оскільки він ще не освячений). Хресний хід в звичайному порядку йде навколо храму при безперервному дзвонінні. Увійшовши в притвор, хресний хід зупиняється перед закритими західними дверима храму. Ті, що несуть святині зупиняються біля дверей обличчям до заходу в наступному порядку: ліхтар (по центру, безпосередньо перед дверима), потім (від південного боку до північного) запрестольний Хрест, Євангеліє, ікона Воскресіння, запрестольна ікона Божої Матері, по сторонам стають хоругвоносці і свічконосці. Предстоятель із співслужителями-священиками стають перед святинями за чином. Дзвоніння припиняється. Настоятель, прийнявши від диякона кадило, при повній тиші звершує кадіння святинь, духовенства, хористів, присутніх і, на закінчення, диякона. Диякон приймає кадило, кадить предстоятеля і повертає йому кадило. Предстоятель, тричі (а не один раз) хрестоподібно осінивши кадилом зачинені церковні двері, голосно виголошує: «Слава Святій, Єдиносущній, і Животворчій, і Нероздільній Тройці, завжди, нині і повсякчас, і на віки віків». Хор: «Амінь». Далі – пасхальний початок, яким починається вечірня, рання і Літургія в усі дні Світлого тижня. Священнослужителі голосно співають тропар Пасхи: «Христос воскрес із мертвих, смертю смерть подолав і тим, що в гробах, життя дарував» (тричі). Хор повторює той самий тропар (тричі). Священнослужителі співають стихи: 1. «Нехай воскресне Бог, і розвіються вороги Його, і нехай біжать від лиця Його ненависники Його». 2. «Як щезає дим, нехай щезнуть, як тане віск від лиця вогню». 3. «Так нехай щезнуть грішники від лиця Божого, а праведники нехай звеселяться». 4. «В цей день, його ж створив Господь, радіймо і звеселімось в нім». 5. «Слава...». 6. «І нині...». На кожен стих хор співає тропар: «Христос воскрес із мертвих...» (один раз). На завершення всі священнослужителі співають голосно: «Христос воскрес із мертвих, смертю смерть подолав». Хор закінчує: «І тим, що в гробах, життя дарував». Відкриваються церковні двері (за Уставом, самим настоятелем), і хресний хід прямує до храму. Велика ектенія. Виголос: «Бо Тобі належить...», і пасхальний канон – творіння прп. Іоана Дамаскіна, глас 1-ий: «Воскресіння день...» (див. в Квітній Тріоді). За Уставом, «творить... початок канону на кожну пісню завжди предстоятель», зазвичай ірмоси кожної пісні співають всі священнослухжителі. Ірмоси співаються на 4, тропарі на 12, з приспівом до кожного з них: «Христос воскрес із мертвих». (Богородичні пасхального канону в перший день Пасхи не співаються). Катавасія – ті ж ірмоси (тричі), і після катавасії тропар: «Христос воскрес із мертвих...» (тричі, зазвичай швидким розспівом). На кожній пісні канону звершується кадіння. За Типіконом, настоятель «кадить на початку канону святі ікони і обидва кліроси і братію за чином». Це – вказівка на повне кадіння всього храму, яке має відбуватися тільки один раз – на 1-ій пісні канону. Але, за твердо встановленим здавна звичаєм, на кожній пісні відбувається мале кадіння. При соборному служінні кадіння звершують всі ієреї по черзі (а при великій кількості ієреїв – попарно). Після кожної пісні – мала ектенія, яку диякон виголошує перед вівтарем. (Якщо богослужіння звершує один священик, то він всі ектенії виголошує у вівтарі). Для виголошення ектеній та звершення кадіння диякон (зі свічкою в руці) в усіх випадках виходить з вівтаря царськими вратами (протягом всього Світлого тижня). Виголоси священика після малих ектеній: Після 1-ої пісні – «Бо Твоя держава і Твоє є Царство, і сила, і слава, Отця, і Сина, і Святого Духа, нині, і повсякчас, і на віки віків». Після 3-ої пісні – «Бо ти єси Бог наш, і Тобі славу возсилаємо, Отцю, і Сину, і Святому Духу, нині і повсякчас, і на віки віків». Після 4-ої пісні – «Бо Ти благий і людинолюбний Бог єси, і Тобі славу возсилаємо, Отцю, і Сину, і Святому Духу, нині і повсякчас, і на віки віків». Після 5-ої пісні – «Бо освятилося і прославилося пречесне і величне Ім’я Твоє, Отця, і Сина, і Святого Духа, нині, і повсякчас, і на віки віків». Після 6-ої пісні – «Бо Ти єси Цар миру і Спас душ наших, і Тобі славу возсилаємо, Отцю, і Сину, і Святому Духу, нині і повсякчас, і на віки віків». Після 7-ої пісні – «Нехай буде держава Царства Твого благословенна і препрославлена, Отця, і Сина, і Святого Духа, нині, і повсякчас, і на віки віків». Після 8-ої пісні – «Бо благословилося Ім’я Твоє і прославилося Царство Твоє, Отця, і Сина, і Святого Духа, нині, і повсякчас, і на віки віків». Після 9-ої пісні – «Бо Тебе хвалять усі сили небесні, Отця, і Сина, і Святого Духа, і Тобі славу возсилаємо, нині, і повсякчас, і на віки віків». Після 3-ої пісні – іпакої Пасхи, глас 4-ий: «Світанок попередивши...». Після 6-ої пісні – кондак Пасхи, глас 8-ий: «Хоч і до гробу...» і ікос: «Того, Хто Сонце, що раніше сонця...». «Воскресіння Христове...» (тричі), «Воскрес Ісус із гробу...» (тричі). У 8-ій пісні є Троїчний. Він співається чотири рази з приспівом: «Пресвята Тройце, Боже наш, слава Тобі». На 9-ій пісні приспів: «Христос воскрес із мертвих» не співається, але до ірмоса і до тропарів – особливі приспіви. 9-та пісня в 1-ий день Пасхи повинна бути виконана в наступному порядку: Диякон: «Величає душа моя Воскреслого триденно із гробу Христа Життєдавця», 1-ий хор: «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою»; 2-ий хор – повторює той самий приспів та ірмос; 1-ий хор: «Величає душа моя Того, Хто добровільно страждав і був похований, і воскрес триденно із гробу», «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою»; 2-ий хор – той самий приспів та ірмос; 1-ий хор: «Христос – нова Пасха, жертва жива, Агнець Божий, що взяв гріхи світу», «О Божественне, о любе, пресолодке слово Твоє; з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 2-ий хор – той самий приспів і тропар; 1-ий хор: «Ангел звістив Благодатній: Чистая Діво, радуйся, і знову кажу: радуйся! Твій Син воскрес на третій день із гробу і мертвих воскресив; люди, веселіться», «О Божественне, о любе, пресолодке слово Твоє: з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 2-ий хор – той самий приспів і тропар; 1-ий хор: «Розбудив Ти, заснувши, мертвих від віку, по-царськи рикнувши, як лев від Іуди», «О Божественне, о любе, пресолодке слово Твоє: з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 2-ий хор: «Магдалина Марія, прийшовши до гробу і Христа побачивши, як садівника, запитувала», «О Божественне, о любе, пресолодке слово Твоє: з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 1-ий хор: «Ангел сяючий до жінок взивав: припиніть плакати, бо Христос воскрес!», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 2-ий хор: «Христос воскрес, смерть подолав і мертвих воскресив, люди, веселіться», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 1-ий хор: «Нині все творіння веселиться і радується: бо Христос воскрес і пекло полонилось», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 2-ий хор: «Нині Владика полонив пекло, визволив ув’язнених, що від віку там силою утримувались», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 1-ий хор: «Величає душа моя Триіпостасного і нероздільного Божества державу», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 2-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 1-ий хор: «Величає душа моя Воскреслого триденно із гробу Христа Життєдавця», «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою»; 2-ий хор: «Величає душа моя Того, Хто добровільно страждав і був похований, і воскрес триденно із гробу», «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою». Потім обидва кліроси разом співають ірмос: «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою», і тропар: «Христос воскрес...» (тричі). На 9-ій пісні кадіння, за звичаєм, звершує не ієрей, а диякон зі свічкою (при соборному служінні – два диякона). Після 9-ої пісні – екзапостиларій Пасхи: «Плоттю заснувши, як мертвий, Царю і Господи, на третій день воскрес єси, Адама з тління підняв і смерть подолав. Пасха нетлінна, світу спасіння» (тричі). «Все, що дише...» на глас 1-ий та хвалітні псалми. На хвалітніх стихири воскресні (див. в Квітній Тріоді), глас 1-ий – 4. Потім стихири Пасхи, глас 5-ий, з приспівами: «Нехай воскресне Бог...». Остання стихира закінчується тропарем: «Христос воскрес із мертвих...», який входить до складу стихири, після чого, у якості тропаря в кінці утрені, «Христос воскрес із мертвих...» співається ще три рази. Так закінчується спів стихир Пасхи протягом всього Світлого тижня на вечірні і ранній. Під час співу стихир Пасхи священнослужителі починають христосатися між собою у вівтарі. За Уставом, «цілування настоятеля з іншими ієреями і дияконами у святому вівтарі відбувається так: той хто вітає, промовляє «Христос воскрес!», той хто відповідає – «Воістину воскрес». Після цілування настоятель або еклесіарх читає Огласительне слово Іоана Золотоустого ; під час читання ми не сидимо, а стоячи уважно слухаємо. Далі співається тропар святого, глас 8-ий: «Уст твоїх благодать, засяявши як світло вогню, освітила увесь світ, не скарби сріблолюбства світові здобула, а показала нам висоту смиренномудрости: своїми ж словами навчаючи, отче Іоане Золотоустий, моли Слово, Христа Бога, спасти душі наші». Потім диякон виголошує ектенії «Помилуй нас, Боже...» і «Доповнимо ранню молитву нашу Господеві...» Після виголосу священика – диякон: «Премудрість». Хор: «Благослови». Настоятель: «Сущий благословенний Христос Бог наш завжди, нині, і повсякчас, і на віки віків». Хор: «Амінь. Утверди, Боже...». Настоятель, тримаючи хрест і трисвічник (замість: «Слава Тобі, Христе Боже...») співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що у гробах, життя дарував». Настоятель виголошує відпуст: «Христос, що воскрес із мертвих, смертю смерть подолав і тим, що у гробах, життя дарував, є істиний Бог наш, молитвами Пречистої Своєї Матері і всіх святих помилує і спасе нас, бо Він благий і Людинолюбний». Потім підносить хрест і промовляє: Христос воскрес! (тричі). Далі співаємо кінцеве: «Христос воскрес...» (тричі весь тропар). І після нього співаємо: «І нам дарував життя вічне, поклоняємось Його триденному воскресінню». Потім Многоліття. І цілуємо чесний хрест, що його тримає настоятель. І час перший. ЧАСИ СВЯТОЇ ПАСХИ І ВСЬОГО СВІТЛОГО ТИЖНЯ Треба знати, що з цього дня святої і великої неділі Пасхи аж до суботи часи і повечір’я і полуношниці співаються так:. Священик: «Благословенний Бог наш...» Співці: «Амінь. Христос воскрес із мертвих, смертю смерть подолав і тим, що в гробах, життя дарував» (тричі) Потім: «Воскресіння Христове бачивши, поклонімось Святому Господеві Ісусу, Єдиному Безгрішному. Хресту Твоєму поклоняємось, Христе, і Святе Воскресіння Твоє оспівуємо і славимо, бо Ти єси Бог наш, крім Тебе, іншого не знаємо, ім’я Твоє призиваємо. Прийдіть, усі вірні, поклонімось Святому Христовому Воскресінню, бо через Хрест прийшла радість усьому світові. Завжди благословляючи Господа, оспівуємо Воскресіння Його, бо, перетерпівши розп’яття, Він смертю смерть переміг» (тричі). Іпакої: «Світання попередивши і знайшовши камінь, одвалений од гробу, ті, що були з Марією, від ангела почули: чому шукаєте серед мертвих, як людину, Того, Хто у світлі вічному перебуває? Погляньте на похоронні пелени, поспішіть і світові звістіть, що воскрес Господь, умертвивши смерть. Він бо є Син Бога, що спасає рід людський». Кондак: «Хоч і до гробу зійшов Ти, Безсмертний, проте пекельну зруйнував єси силу, й воскрес єси, як Переможець, Христе Боже, жонам-мироносицям звістивши: радуйтеся; і Твоїм апостолам мир даруєш, а померлим подаєш воскресіння». Потім ці тропарі: «У гробі тілом, у пеклі душею, як Бог, в раю ж з розбійником, і на Престолі був Ти, Христе, з Отцем і Духом, все наповняючи, Неописанний». «Слава...» – «Як життєносець, як кращий від раю і воістину світліший від усякої палати царської, явився, Христе, гріб Твій джерелом нашого воскресіння». «І нині...» – «Свята Божественна оселе Всевишнього, радуйся, бо через Тебе, Богородице, дано радість тим, що взивають: благословенна Ти в жонах, Пренепорочна Владичице!» Потім: «Господи, помилуй» (40 разів). «Слава, і нині». «Чеснішу...». «Іменем Господнім благослови, отче». Священик: «Молитвами святих отців...». Співці: «Амінь. Христос воскрес із мертвих, смертю смерть подолав і тим, що в гробах, життя дарував» (тричі). «Слава, і нині...». «Господи, помилуй» (тричі). «Благослови». І відпуст малий (за традицією, з хрестом): «Христос що воскрес із мертвих є істинний Бог наш...». Так само правляться часи 3-ій, 6-ий, 9-ий. Під час Пасхальних часів перед Літургією священик з дияконом звершують проскомидію, після чого диякон зі свічкою в руці звершує повне кадіння храму (як зазвичай). Перед початком Літургії до відання Пасхи замість «Царю небесний» священик тричі промовляє тропар Пасхи і звичайні стихи «Слава в вишніх Богу...» (двічі) та «Господи, відкрий уста мої...» (один раз). ЧИН ЛІТУРГІЇ, ЯКА ВІДПРАВЛЯЄТЬСЯ ДУЖЕ РАНО Диякон починає: Благослови, владико. Настоятель виголошує: Благословенне Царство Отця, і Сина, і Святого Духа, нині, і повсякчас, і на віки віків. Хор: Амінь. Настоятель з хрестом-трисвічником та кадилом в руках співає разом з іншими священнослужителями у святому вівтарі: «Христос воскрес із мертвих, смертю смерть подолав і тим, що в гробах, життя дарував» (тричі). Хор повторює той самий тропар (тричі). Настоятель співає стихи: 1. «Нехай воскресне Бог, і розвіються вороги Його, і нехай біжать від лиця Його ненависники Його». Хор співає тропар «Христос воскрес...» на кожен стих (один раз). 2. «Як щезає дим, нехай щезнуть, як тане віск від лиця вогню». 3. «Так нехай щезнуть грішники від лиця Божого, а праведники нехай звеселяться». 4. «В цей день, його ж створив Господь, радіймо і звеселімось в нім». 5. «Слава...». 6. «І нині...». Настоятель співає гучним голосом: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що у гробах, життя дарував». Далі диякон промовляє велику ектенію. Після ектенії і виголосу священика хор співає антифон 1, псалом 65, глас 2-ий: Стих: «Викликніть Господу, вся земле». Приспів: «Молитвами Богородиці, Спасе, спаси нас». Другий клірос: «Викликніть Господу, вся земле. Співайте ж імені Його, віддайте славу й хвалу Йому». «Молитвами Богородиці, Спасе, спаси нас». Стих 2: «Промовляйте Богові: як величні діла Твої, перед множеством сили Твоєї скоряться Тобі вороги Твої». «Молитвами Богородиці, Спасе, спаси нас». Стих 3: «Вся земля нехай поклониться Тобі і співає Тобі, нехай співає імені Твоєму, Вишній!» «Молитвами Богородиці, Спасе, спаси нас». «Слава, і нині» – обидва кліроси голосно співають: «Молитвами Богородиці, Спасе, спаси нас». Далі мала ектенія. Антифон другий, псалом 66, глас той самий: Стих 1: «Боже, ущедри нас і благослови нас». Приспів: «Спаси нас, Сину Божий, що воскрес із мертвих, співаємо Тобі: алилуя». Другий клірос: «Боже ущедри нас і благослови нас, просвіти лице Твоє на нас і помилуй нас». «Спаси нас, Сину Божий...» . Стих 2: «Щоб пізнали ми на землі путь Твою, в усіх народах – спасіння Твоє». «Спаси нас, Сину Божий...». Стих 3: «Вся земля нехай поклониться Тобі і співає Тобі, нехай же співає імені Твоєму, Всевишній». «Спаси нас, Сину Божий...». «Слава, і нині» – обидва кліроси разом: «Єдинородний Сину...» Далі ектенія. Антифон третій, псалом 67, глас 5: Стих 1: «Нехай воскресне Бог, і розвіються вороги його». Тропар: «Христос воскрес із мертвих...» (на кожен стих один раз). Другий клірос: «Нехай воскресне Бог і розвіються вороги Його; нехай побіжать від лиця Його ненависники Його». «Христос воскрес...». Стих 2: «Як щезає дим, хай щезнуть, як тане віск від лиця вогню». «Христос воскрес...». Стих 3: «Так нехай згинуть грішники від лиця Божого, а праведники нехай звеселяться.» «Христос воскрес...» І відбувається вхід. Диякон, якщо є, а якщо нема – священик виголошує: «Премудрість, станьмо побожно». Вхідне: «В церквах благословляйте Бога, Господа від джерел Ізраїлевих». Співаємо тропар: «Христос воскрес...» (один раз), іпакої, глас 4-ий: «Світання попередивши...». «Слава, і нині...» – кондак Пасхи, глас 8-ий: «Хоч і до гробу зійшов Ти, Безсмертний...». Замість Трисвятого: «Всі ті, що в Христа хрестилися, у Христа зодягнулися. Алилуя». Належить знати, що цей початок Літургії, і антифони, і «Всі ті, що в Христа хрестилися...» співаємо протягом усього світлого тижня, аж до наступної неділі; також і причасний. Прокимен, глас 8: «Цей день, його ж створив Господь, радіймо і веселімось в нім». Стих: «Сповідуйтеся Господеві, бо Він благий, бо повіки милість Його». Діянь святих апостолів читання, зачало 1. Алилуя, глас 4-ий: «Ти, Господи, воскрес, ущедривши Сион». Стих: «Господь з неба на землю поглянув». Коли надходить час читання святого Євангелія, перший диякон, який буде читати, промовляє: «Благослови, владико, благовістителя...» Настоятель говорить: «Бог молитвами святого славного...» і далі, як сказано у Служебнику. І виходить диякон на звичайне місце прямо перед Царськими вратами, і стає обличчям на схід. Настоятель виголошує перед престолом: «Премудрість, станьмо побожно, вислухаймо святе Євангеліє». Те ж саме і всі священики, які служать. Після цього читають різними мовами Євангеліє, ставши на різних місцях – від престолу і до західних дверей церковних, один за одним. Посередині ж усіх стоїть архидиякон, і читають усі після настоятеля один за одним по частинах, як настоятель розділить. Настоятель починає: «Від Іоана святого Євангелія читання», інші – те саме. Настоятель: «Будьмо уважні», інші – те саме. Настоятель, стоячи перед престолом обличчям на схід, читає: «Споконвіку було Слово...» і далі; інші – те саме. Примітка. І на кожному виголосі або частині Євангелія б’ють в церкві у дзвін по одному разу. Параеклесіарх же ззовні церкви б’є у великий дзвін; на останньому виголосі б’ють в усі дзвони. Євангеліє від Іоана, зачало 1 І далі за чином Божественна літургія св. Іоана Золотоустого. Замість «Достойно є...» співаємо: «Ангел звістив Благодатній», потім ірмос: «Світися, світися...» Причасний: «Тіло Христове прийміте...», Алилуя (тричі). Настоятель виголошує: «Зі страхом Божим і вірою приступіть». Хор замість «Благословенний, хто йде в ім’я Господнє» співає: «Христос воскрес...» (один раз). Настоятель: «Спаси, Боже, людей Твоїх...» Хор: «Христос воскрес...» (один раз). Коли священик виголошує: «Завжди, нині, і повсякчас» хор: «Амінь. Христос воскрес...» (один раз). Далі ектенія. По заамвонній молитві, за традицією, освячується артос. На солії перед царськими вратами на приготовленому столі або аналої кладеться артос. Звершується кадіння навколо артоса. Диякон: «Господу помолимось». Хор: «Господи помилуй». Священик читає молитву на освячення артоса (з Требника) і окроплює артос освяченою водою, промовляючи: «Благословляється і освячується артос цей, окропленням води цієї святої...» (тричі). Замість «Нехай буде Ім’я Господнє благословенне...» і псалма «Благословлю Господа...» співаємо: «Христос воскрес...» (12 разів). Далі настоятель: «Благословення Господнє на вас...» Хор: «Амінь». Настоятель: (замість «Слава Тобі, Христе Боже...») співає «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що у гробах, життя дарував». Далі настоятель промовляє відпуст з хрестом і трисвічником в руках, як указано на ранній. Потім підносить хрест і промовляє: Христос воскрес! (тричі). Далі співається кінцеве: «Христос воскрес...» (тричі весь тропар). І після нього: «І нам дарував життя вічне, поклоняємось Його триденному воскресінню». Потім Многоліття. Царські врата і дияконські двері по всіх церквах увесь Світлий тиждень не зачиняються і під час причастя у вівтарі. По завершенню Літургії за звичаєм освячуються принесення, тобто ті продукти, які протягом Святої Чотиридесятниці і Страсного тижня були заборонені для споживання (молочні продукти, м’ясні вироби, яйця та паски). ВЕЛИКА ВЕЧІРНЯ В ДЕНЬ ПАСХИ Після часу дев’ятого настоятель в повному священицькому облаченні, ставши перед престолом з хрестом-трисвічником та кадилом в руках, знаменує хрестовидно і виголошує: Благословенний Бог наш завжди, нині, і повсякчас, і на віки віків. Хор: Амінь. Священик починає: «Христос воскрес із мертвих, смертю смерть подолав і тим, що у гробах, життя дарував» (тричі). Хор співає той самий тропар тричі. Настоятель виголошує стихи: Стих 1: «Нехай воскресне Бог...»; Хор на кожен стих співає: «Христос воскрес...» (один раз). Стих 2: «Як щезає дим...»; Стих 3: «Так нехай згинуть грішники...»; Стих 4: «В цей день, його ж створив Господь...»; «Слава...»; «І нині...»; І знову настоятель: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що у гробах, життя дарував». Велика ектенія: «В мирі Господу помолимось...» «Господи, взиваю до Тебе...», глас 2-ий. Стихири воскресні з Тріоді глас 2-ий – 6. «Слава» – Тріоді, глас той самий: «Спасительну пісню співаючи...», «І нині» – догматик, глас той самий: «Минула тінь закону...». Вхід з Євангелієм. «Світло тихе...» Далі прокимен великий, глас 7-ий: «Хто Бог великий, як Бог наш? Ти єси Бог, що твориш чудеса» з приспівами. Після прокимна диякон виголошує: «І щоб сподобитися нам вислухати святе Євангеліє, Господа Бога молимо». Хор: «Господи, помилуй» (тричі) Далі настоятель читає Євангеліє у вівтарі (за традицією – в царських вратах лицем до народу). Євангеліє від Іоана, зачало 65. Потім ектенія «Промовимо всі...». «Сподоби Господи, у вечір цей...». Ектенія «Доповнимо вечірню молитву...». Після виголосу співається стихира воскресна, глас 2-ий: «Воскресіння Твоє, Христе Спасе, всю просвітило вселенну...». Далі стихири Пасхи, глас 5-ий: «Нехай воскресне Бог...», «Пасха священна...» з їх приспівами. «Слава, і нині» – «Воскресіння день...». «Христос воскрес...» (тричі). Диякон: «Премудрість». Хор: «Благослови». Настоятель: «Сущий благословенний Христос Бог наш...». Хор: «Амінь. Утверди, Боже...». Настоятель (замість: «Слава Тобі, Христе Боже...») співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що у гробах, життя дарував». Настоятель промовляє відпуст з хрестом і трисвічником: «Христос воскрес із мертвих...» і все інше, як сказано про закінчення ранньої. І цілуємо хрест. Замість малого повечір’я звершується послідування пасхальних часів.","sections":[],"special":true},
{"date":"04-13","weekday":"понеділок","title":"Пасхальний тиждень. Загальниця. Світлий понеділок. Сщмч. Артемона, пресвітера Лаодикійського (303). Мч. Крискента з Мир Лікійських. Мц. Фомаїди Єгипетської (476).","readings":["Діян., 2 зач., I, 12 – 17, 21 – 26. Ін., 2 зач., I, 18 – 28."],"notes":"Порядок служби, як у перший день Пасхи. Початок ранньої у вівтарі. На каноні додаються Богородичні. Ектенія після 3-ої, 6-ої і 9-ої пісень. Кадіння – на 1-ій, 4-ій, 7-ій і 9-ій піснях канону. Часи пасхальні. На Літургії антифони Пасхи, Вхідний стих: «В церквах благословіте Бога, Господа від джерел Ізраїлевих», замість Трисвятого – «Всі ви, що в Христа хрестилися...», задостойник Пасхи. Закінчення Літургії – як у перший день Пасхи. З такими ж особливостями звершуються служби в усі дні світлого тижня. Звершується служба пасхальним чином (з Квітної Тріоді). Замість полуношниці звершується послідування пасхальних часів.","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ. До початку богослужіння параеклесіарх (паламар) запалює лампади і свічки, дзвонить у великий дзвін та інше. Братія збирається в храмі, ієромонах чинить звичайний поклін настоятелю, іде у святий вівтар, бере кадило, стає перед престолом, облачений тільки в єпитрахиль поверх мантії (у фелонь не облачається), кадить хрестовидно і виголошує: «Слава святій і єдиносущній...» і співає тропар: «Христос воскрес...» (тричі). Клірос повторює тропар тричі. Далі: «Христос воскрес...» як сказано у святу Пасху на ранній і на вечірні. В інших храмах, не в монастирях, священик облачається в ризу. Велика ектенія. Канон Пасхи: «Воскресіння день...» з ірмосом і Богородичними тропарями на 14 (ірмоси по двічі, тропарі на 10, на «Слава» і на «І нині» – Богородичний). Приспів: «Христос воскрес із мертвих». Біблійні пісні не співаються. Примітка. З понеділка пасхальний канон співається з особливими Богородичними (творіння прпп. Феофана і Йосифа). У Квітній Тріоді вони поміщені у послідуванні Неділі жінок-мироносиць, а у виданій окремій книзі «Послідування у Святу і Велику Неділю Пасхи» друкуються в каноні на ряду в перший день Пасхи. Про малі ектенії на каноні в Уставі не згадується, тому що з понеділка Пасхи щодо ектеній чин ранньої звичайний: ектенії виголошуються тільки після 3-ої, 6-ої і 9-ої пісень. Катавасія після кожної пісні – ірмос канону Пасхи (один раз) і «Христос воскрес...» (тричі; за звичаєм, швидким розспівом). Кадіння, за традицією, звершується лише на 1-ій, 4-ій, 7-ій і 9-ій піснях канону (протягом всього Світлого тижня). Катавасія «Воскресіння день...». Після 3-ої пісні – іпакої Пасхи, глас 4-ий: «Світання попередивши...». Після 6-ої пісні – кондак Пасхи, глас 8-ий: «Хоч і до гробу...», та ікос, глас той самий. «Воскресіння Христове...» і «Воскрес Ісус із Гробу...» – по тричі. У понеділок, вівторок, середу, четвер і суботу Світлої седмиці, якщо не трапиться служба полієлейному святому, 9-та пісня виконується в наступному порядку: Диякон: «Величає душа моя Воскреслого триденно із гробу Христа Життєдавця». 1-ий хор: «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою»; 2-ий хор – «Величає душа моя Того, Хто добровільно страждав і був похований, і воскрес триденно із гробу», «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою»; 1-ий хор: «Христос – нова Пасха, жертва жива, Агнець Божий, що взяв гріхи світу», «О Божественне, о любе, пресолодке слово Твоє; з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 2-ий хор – той самий приспів і тропар; 1-ий хор: «Ангел звістив Благодатній: Чистая Діво, радуйся, і знову кажу: радуйся! Твій Син воскрес на третій день із гробу і мертвих воскресив; люди, веселіться», «О Божественне, о любе, пресолодке слово Твоє: з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 2-ий хор – той самий приспів і тропар; 1-ий хор: «Розбудив Ти, заснувши, мертвих від віку, по-царськи рикнувши, як лев від Іуди», «О Божественне, о любе, пресолодке слово Твоє: з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 2-ий хор: «Магдалина Марія, прийшовши до гробу і Христа побачивши, як садівника, запитувала», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 1-ий хор: «Ангел сяючий до жінок взивав: припиніть плакати, бо Христос воскрес!», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 2-ий хор: «Христос воскрес, смерть подолав і мертвих воскресив, люди, веселіться», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 1-ий хор: «Нині все творіння веселиться і радується: бо Христос воскрес і пекло полонилось», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 2-ий хор: «Нині Владика полонив пекло, визволив ув’язнених, що від віку там силою утримувались», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 1-ий хор: «Величає душа моя Триіпостасного і нероздільного Божества державу», і Богородичний: «Єдиногласно, Діво, Тебе ублажаємо, вірні; радуйся, двері Господні; радуйся, граде одухотворений; радуйся, бо заради Тебе засяяло нам світло із Тебе народженого, із мертвих воскресіння»; 2-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу», і Богородичний: «Веселіться і радуйтеся, Божественні двері світла, бо Ісус, Який зійшов у гріб, засяяв світліше від сонця і всіх вірних просвітив, Богорадувана Владичице»; Потім обидва кліроси разом співають перший приспів: «Величає душа моя Воскреслого триденно із гробу Христа Життєдавця» та ірмос: «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою», і тропар: «Христос воскрес...» (тричі, за звичаєм, швидким розспівом). Після 9-ої пісні – екзапостиларій Пасхи: «Плоттю заснувши, як мертвий, Царю і Господи, на третій день воскрес єси, Адама з тління підняв і смерть подолав. Пасха нетлінна, світу спасіння» (тричі). «Все, що дише...» та хвалітні псалми. На хвалітніх стихири воскресні (див. в Тріоді), глас 2-ий – 4, і стихири Пасхи, глас 5-ий (зі своїми приспівами). «Слава, і нині» – Пасхи, глас той самий: «Воскресіння день...» І відразу ж «Христос воскрес із мертвих...» (тричі) в якості тропаря в кінці ранньої. Ектенії і пасхальний відпуст з хрестом і трисвічником, як вказано вище на ранній у день святої Пасхи. ЧАСИ ПАСХИ. Вхідні молитви перед Літургією протягом Світлого тижня прийнято здійснювати в такий спосіб. Після звичайного початкового виголосу «Благословенний Бог наш...» читається «Христос воскрес із мертвих...» (тричі), іпакої і кондак Пасхи. Замість покаянних тропарів «Помилуй нас, Господи, помилуй нас...» читаються тропарі пасхальних часів: «У гробі плоттю...», «Слава» – «Як Життєносець...», «І нині» – Богородичний «Всевишнього оселе...». Потім: «Пречистому Образу Твоєму поклоняємось, Благий...», «Богородице Ти єси Джерело милосердя...». Молитва: «Господи, простягни руку Твою...»; псалом «Увійду в дім Твій...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони Пасхи та інше, як в перший день. Вхідний Пасхи. Після входу тропар, глас 5-ий: «Христос воскрес із мертвих...» (один раз), іпакої, глас 4-ий: «Світання попередивши...». «Слава, і нині...» – кондак Пасхи, глас 8-ий: «Хоч і до гробу...». Замість Трисвятого – «Усі ті, що в Христа хрестилися...» Прокимен, Апостол, алилуарій і Євангеліє дня (понеділка Світлої седмиці). Задостойник Пасхи. Причасний Пасхи «Тіло Христове...» Відпуст – як в перший день Пасхи."}]},
{"date":"04-14","weekday":"вівторок","title":"Світлий вівторок. Іверської ікони Божої Матері (перехідне святкування у вівторок Світлого тижня). Свт. Мартина, спов., папи Римського (655). Мчч. Антонія, Іоана і Євстафія Литовських (1347). Мч. Ардаліона (305 – 311). Мчч. 1000 перських і Азата, скопця (бл. 341). Мчч. Христодула й Анастасії Патрських, вбитих в Ахаї (1821). Прмчч. отців Давидо-Гареджийських (ХVІІ, Груз.) (перехідне святкування у вівторок Світлого тижня).","readings":["Діян., 4 зач., II, 14 – 21. Лк., 113 зач., XXIV, 12 – 35."],"notes":"Співається 9-ий час за пасхальним чином.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ ієрей у ризі, ставши перед престолом з кадилом в правій руці і з хрестом-трисвічником в лівій, творить хрест кадилом і виголошує: «Благословенний Бог наш...». Священик починає: «Христос воскрес із мертвих, смертю смерть подолав і тим, що у гробах, життя дарував» (тричі). Хор співає той самий тропар тричі. Настоятель виголошує стихи: Стих 1: «Нехай воскресне Бог...»; Хор на кожен стих співає: «Христос воскрес...» (один раз). Стих 2: «Як щезає дим...»; Стих 3: «Так нехай згинуть грішники...»; Стих 4: «В цей день, його ж створив Господь...»; «Слава...»; «І нині»; І знову настоятель: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що у гробах, життя дарував». Велика ектенія. На «Господи, взиваю» стихири на 6: воскресні (див. в Тріоді). «Слава» – Тріоді, «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Вхід з кадилом. Прокимен великий, глас 7-ий: «Бог наш на небесах і на землі...» з приспівами. Ектенія потрійна: «Промовимо всі...», «Сподоби, Господи...», ектенія прохальна: «Доповнимо вечірню молитву...» і голововклонна молитва. На стиховні співається одна стихира воскресна (див. в Тріоді), глас 3-ій: «Стражданням Твоїм, Христе...», потім стихири Пасхи, глас 5-ий, з приспівами: «Нехай воскресне Бог...». «Христос воскрес із мертвих...» (один раз, як закінчення стихири). І тричі тропар «Христос воскрес із мертвих...» Ієрей: «Премудрість». Хор: «Благослови». Ієрей: «Сущий благословенний...». Хор: «Амінь. Утверди, Боже...». Ієрей співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що в гробах, життя дарував». Ієрей з хрестом і трисвічником в руках виголошує відпуст: «Христос, що воскрес із мертвих...». Потім підносить хрест і промовляє: Христос воскрес! (тричі). Далі співається кінцеве: «Христос воскрес...» (тричі весь тропар). І після нього: «І нам дарував життя вічне, поклоняємось Його триденному воскресінню». Потім Многоліття. Звершується послідування пасхальних часів за мале повечір’я та за полуношницю (перед ранньою)."},{"svc":"РАННІЙ","text":"НА РАННІЙ Предстоятель з хрестом-трисвічником і кадилом розпочинає ранню виголосом: «Слава Святій, Єдиносущній...», хор: «Амінь». Співається пасхальний початок – тропар «Христос воскрес із мертвих...» зі стихами. Велика ектенія. Канон Пасхи: «Воскресіння день» з ірмосом та з Богородичними на 14 (ірмоси двічи) з приспівом: «Христос воскресе із мертвих». Катавасія після кожної пісні – ірмоси канону Пасхи «Воскресіння день...» (один раз). Після кожної пісні тричі співається тропар Пасхи «Христос воскрес...» (швидким розспівом). Кадіння, за традицією, звершується на 1-ій, 4-ій, 7-ій і 9-ій піснях канону. Малі ектенії по 3-ій, 6-ій і 9-ій піснях. Після 3-ої пісні – іпакої Пасхи, глас 4: «Світання попередивши...». Після 6-ої пісні – кондак Пасхи, глас 8-ий: «Хоч і до гробу...», та ікос глас той самий. «воскресіння Христове бачивши...» і «Воскрес Ісус..» – тричі. 9-та пісня – див. в понеділок. Після 9-ої пісні – екзапостиларій Пасхи: «Плоттю заснувши...» тричі. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні (див. Триодь), глас 3-ій- 4, а стихири Псахи, глас 5-ий. Ектенія потрійна: «Помилуй нас, Боже...», ектенія прохальна: «Доповнимо ранню молитву...» і голововклонна молитва. Ієрей: «Премудрість». Хор: «Благослови». Ієрей: «Сущий благословенний...». Хор: «Амінь. Утверди, Боже...». Ієрей співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що в гробах, життя дарував». Ієрей з хрестом-трисвічником в руках виголошує відпуст: «Христос, що воскрес із мертвих...» Потім підносить хрест і промовляє: Христос воскрес! (тричі). Далі співається кінцеве: «Христос воскрес...» (тричі весь тропар). І після нього: «І нам дарував життя вічне, поклоняємось Його триденному воскресінню». Многоліття. ЧАСИ ПАСХИ."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони Пасхи та інше, як в перший день. Вхідний Пасхи. Замість Трисвятого – «Усі ті, що в Христа хрестилися...» Прокимен дня (вівторка Світлої седмиці) – глас 3-ій, пісня Богородиці: «Величає душа моя Господа...» зі стихом «Бо зглянувся на смирення Раби Своєї...». Апостол, Алилуарій, Євангеліє – дня Задостойник Пасхи. Причасний Пасхи «Тіло Христове Закінчення Літургії та відпуст – як в перший день Пасхи."}]},
{"date":"04-15","weekday":"середа","title":"Світла середа. Вишгородської (Володимирської) ікони Божої Матері (І). Апп. від 70-х Аристарха, Пуда і Трофима (бл. 67). Мцц. Василіси й Анастасії (бл. 68). Мчч. Месукевійських Сухія і воїнів його: Андрія, Анастасія, Талале, Феодорита, Івхиріона, Йордана, Кіндрата, Лукіана, Мимненоса, Нерангіоса, Полієвкта, Якова, Фоки, Доментіана, Віктора, Зосими (100 – 130, Груз.). Мч. Сави Готського (372). Блгв. кн. Мстислава Володимировича (1132). Собор преподобних отців, які на горі Синай подвизалися (перехідне святкування в середу Світлого тижня). Віленської ікони Божої Матері. Касперівської ікони Божої Матері (перехідне святкування в середу Світлого тижня).","readings":["Літ. – Діян., 5 зач., II, 22 – 36. Ін., 4 зач., I, 35 – 51.","Богородиці: Флп., 240 зач., II, 5 – 11. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"До Пасхальної відправи додається полієлейна служба іконі Пресвятій Богородиці «Вишгородській» з Мінеї. Співається 9-ий час за пасхальним чином.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ Ієрей у ризі, ставши перед престолом з кадилом в правій руці і з хрестом-трисвічником в лівій, творить хрест кадилом і виголошує: «Благословенний Бог наш...». Священик починає: «Христос воскрес із мертвих, смертю смерть подолав і тим, що у гробах, життя дарував» (тричі). Хор співає той самий тропар тричі. Настоятель виголошує стихи: Стих 1: «Нехай воскресне Бог...»; Хор на кожен стих співає: «Христос воскрес...» (один раз). Стих 2: «Як щезає дим...»; Стих 3: «Так нехай згинуть грішники...»; Стих 4: «В цей день, його ж створив Господь...»; «Слава...»; «І нині»; І знову настоятель: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що у гробах, життя дарував». Велика ектенія. На «Господи, взиваю» стихири на 6: воскресні (див. в Тріоді), глас 4-ий – 3 та Богородиці, глас 4-ий – 3. «Слава, і нині» – догматик, глас 4-ий: «Пророк Давид, що через Тебе, Богородице, богоотцем став...». Вхід з кадилом. Прокимен великий, глас 8-ий: «Голосом моїм до Господа взиваю...» з приспівами. Паремії Богородиці – 3. Ектенія потрійна: «Промовимо всі...», «Сподоби, Господи...», ектенія прохальна: «Доповнимо вечірню молитву...» і голововклонна молитва. Літія не звершується. На стиховні співається одна стихира воскресна (див. в Тріоді), глас 4-ий: «Господи, зійшовши на хрест...», потім стихири Пасхи, глас 5-ий, з приспівами: «Нехай воскресне Бог...», «Слава» – Богородиці, глас 8-ий: «Нехай радіє народ наш...», «І нині» – Пасхи, глас 5-ий: «Воскресіння день...». «Христос воскрес із мертвих...» (один раз, як закінчення стихири). І тричі тропар «Христос воскрес із мертвих...», «Слава» – тропар Богородиці, глас 4-ий, «І нині» – Богородичний воскресний, глас 4-ий: «Від початку віку утаємнене...». Ієрей: «Премудрість». Хор: «Благослови». Ієрей: «Сущий благословенний...». Хор: «Амінь. Утверди, Боже...». Ієрей співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що в гробах, життя дарував». Ієрей з хрестом і трисвічником в руках виголошує відпуст: «Христос, що воскрес із мертвих...» та інше. Потім підносить хрест і промовляє: Христос воскрес! (тричі). Далі співається кінцеве: «Христос воскрес...» (тричі весь тропар). І після нього: «І нам дарував життя вічне, поклоняємось Його триденному воскресінню». Потім Многоліття. Звершується послідування пасхальних часів за мале повечір’я та за полуношницю (перед ранньою)."},{"svc":"РАННІЙ","text":"НА РАННІЙ предстоятель у ризі, з хрестом-трисвічником і кадилом в руках розпочинає ранню виголосом: «Слава Святій, Єдиносущній...», хор: «Амінь». Настоятель тричі співає тропар Пасхи «Христос воскрес із мертвих...», хор повторює його тричі. Настоятель виголошує стих 1: «Нехай воскресне Бог...»; Хор на кожен стих співає: «Христос воскрес...» (один раз). Стих 2: «Як щезає дим...»; Стих 3: «Так нехай згинуть грішники...»; Стих 4: «В цей день, його ж створив Господь...»; Хор: «Слава» – тропар великомученику, глас 4-ий, «І нині» – Богородичний воскресний, глас 4-ий: «Від початку віку утаємнене...». Настоятель співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що у гробах, життя дарував». Велика ектенія. Відразу ж після ектенії співається полієлей. Величання Богородиці: «Величаємо Тебе, Пресвятая Діво, Богом обрана Отроковице, і шануємо образ Твій святий, ним же подаєш зцілення всім, хто з вірою звертається до Тебе» або «Достойно є величати Тебе, Богородице, чеснішу від Херувимів і незрівнянно славнішу від Серафимів». Мала ектенія та сідальний Богородиці після полієлея, глас 1-ий. «Слава, і нині...» – той самий. Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Пом’яну ім’я Твоє...». Євангеліє Богородиці. «Воскресіння Христове бачивши...» (тричі). 50-ий псалом не читається, але відразу ж співаємо «Слава» – «Молитвами Богородиці...», «І нині» – «Молитвами Богородиці...». Та стихира великомученика, глас 6-ий: «Тобі всі людські родиприносять похвальні дари...» (з стихир на «Господи взиваю»). Молитва «Спаси, Боже, людей Твоїх...», хор: «Господи, помилуй» (12). Після виголосу «Милістю та щедротами...» співаємо канон Пасхи «Воскресіння день...» з ірмосом та з Богородичними тропарями на 8 (ірмоси по двічі) з приспівом: «Христос воскрес із мертвих» та канон Богородиці на 6. Катавасія після кожної пісні – ірмоси канону Пасхи «Воскресіння день...» (один раз). Після кожної пісні тричі співається тропар Пасхи «Христос воскрес...» (швидким розспівом). Кадіння, за традицією, звершується на 1-ій, 4-ій, 7-ій і 9-ій піснях канону. Малі ектенії по 3-ій, 6-ій і 9-ій піснях. Після 3-ої пісні – кондак Пасхи, глас 8-ий: «Хоч і до гробу...», та ікос Пасхи, глас той самий: «Того, Хто Сонце, що раніше сонця...». Інший кондак Богородиці, глас 8: «До непереможної Воєводи...» , «Слава...» – Сідальний Богородиці, глас 4: «Боголюбиві народи, «і нині...» – іпакої Пасхи, глас 4-ий: «Світання попередивши...». Після 6-ої пісні – кондак і ікос Богородиці, глас 8-ий та стихира «Воскрес Ісус із Гробу...», глас 6-ий (тричі). 9-та пісня співається в наступному порядку: Диякон: «Величає душа моя Воскреслого триденно із гробу Христа Життєдавця», 1-ий хор: «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою»; 2-ий хор – «Величає душа моя Того, Хто добровільно страждав і був похований, і воскрес триденно із гробу», «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою»; 1-ий хор: «Христос – нова Пасха, жертва жива, Агнець Божий, що взяв гріхи світу», «О Божественне, о любе, пресолодке слово Твоє; з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 2-ий хор – «Ангел звістив Благодатній: Чистая Діво, радуйся, і знову кажу: радуйся! Твій Син воскрес на третій день із гробу і мертвих воскресив; люди, веселіться», «О Божественне, о любе, пресолодке слово Твоє: з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 1-ий хор: «Розбудив Ти, заснувши, мертвих від віку, по-царськи рикнувши, як лев від Іуди», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 2-ий хор: «Магдалина Марія, прийшовши до гробу і Христа побачивши, як садівника, запитувала», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 1-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу», і Богородичний: «Єдиногласно, Діво, Тебе ублажаємо, вірні; радуйся, двері Господні; радуйся, граде одухотворений; радуйся, бо заради Тебе засяяло нам світло із Тебе народженого, із мертвих воскресіння»; 2-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу», і Богородичний: «Веселіться і радуйтеся, Божественні двері світла, бо Ісус, Який зійшов у гріб, засяяв світліше від сонця і всіх вірних просвітив, Богорадувана Владичице»; 1-ий хор: «Пресвята Богородиця, спаси нас» і тропар: «Радості Клопотальнице...»; 2-ий хор: той самий приспів і тропар; 1-ий хор: той самий приспів і тропар; 2-ий хор: «Пресвята Богородице, спаси нас» і тропар: «Нехай прославляють Тебе...» 1-ий хор: «Пресвята Богородице, спаси нас» і тропар: «Зібравшись нині...» 2-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу» і Богородичний: «Ту була ранком...» Потім обидва кліроси разом співають перший приспів: «Величає душа моя Воскреслого триденно із гробу Христа Життєдавця» та ірмос: «Світися, світися, новий Єрусалиме...» і тропар: «Христос воскрес...» (тричі, швидким розспівом). Після 9-ої пісні – екзапостиларій Пасхи: «Плоттю заснувши...», «Слава» – світильний Богородиці, «І нині» – екзапостиларій Пасхи: «Плоттю заснувши...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: воскресні (див. в Тріоді), глас 4-ий – 3, і Богородиці, глас 4-ий – 3. Потім стихири Пасхи, глас 5-ий, з приспівами: «Нехай воскресне Бог...». «Слава» – Богородиці, глас 8-ий: «Той, Хто їздив на Херувимах...», «І нині» – Пасхи, глас 5-ий: «Воскресіння день...». «Христос воскрес із мертвих...» (один раз, як закінчення стихири). І тричі тропар «Христос воскрес із мертвих...», «Слава» – тропар Богородиці, глас 4-ий, «І нині» – Богородичний воскресний, глас 4-ий: «Від початку віку утаємнене...». Ектенія потрійна: «Помилуй нас, Боже...», ектенія прохальна: «Доповнимо ранню молитву...» і голововклонна молитва. Ієрей: «Премудрість». Хор: «Благослови». Ієрей: «Сущий благословенний...». Хор: «Амінь. Утверди, Боже...». Ієрей співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що в гробах, життя дарував». Ієрей з хрестом і трисвічником в руках виголошує відпуст: «Христос, що воскрес із мертвих...». Потім підносить хрест і промовляє: Христос воскрес! (тричі). Далі співається кінцеве: «Христос воскрес...» (тричі весь тропар). І після нього: «І нам дарував життя вічне, поклоняємось Його триденному воскресінню». Многоліття. ЧАСИ ПАСХИ."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони Пасхи та інше, як в перший день. Вхідний Пасхи. Після входу тропар «Христос воскрес із мертвих...» (тричі), тропар Богородиці, «Слава» – кондак Богородиці, «І нині» – кондак Пасхи. Замість Трисвятого – «Усі ті, що в Христа хрестилися...» Прокимен середи Світлої седмиці, глас 6-ий: «Пом’яну ім’я Твоє у всякому роді і роді», стих: «Слухай, Дочко, і споглянь, і прихили вухо Твоє» і Богородиці. Апостол, Алилуарій, Євангеліє – дня і Богородиці. Задостойник Пасхи. Причасний – «Тіло Христове...» та Богородиці. Закінчення Літургії та відпуст – як в перший день Пасхи."}]},
{"date":"04-16","weekday":"четвер","title":"Світлий четвер. Мцц. Агафії, Ірини та Хіонії (304). Мч. Леоніда і мцц. Харієси, Ніки, Галини, Каліси, Нунехії, Василіси, Феодори, Ірини та інших (258). Іллінсько-Чернігівської ікони Божої Матері (1658).","readings":["Літ. – Діян., 6 зач., II, 38 – 43. Ін., 8 зач., III, 1 – 15."],"notes":"Всі служби добового кола звершуються за зразком 13 та 14 квітня. Співаються стихири 5-ого гласу.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ Вхід з кадилом. Прокимен великий, глас 7-ий: «Вислухай, Боже, молитву мою...» з приспівами."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони Пасхи та інше, як в перший день. Вхідний Пасхи. Замість Трисвятого – «Усі ті, що в Христа хрестилися...» Прокимен четверга Світлої седмиці, глас 3-ій: «Співайте Богові нашему, співайте, співайте Цареві нашому, співайте», стих: «Всі народи, заплещіть руками...» Апостол, Алилуарій, Євангеліє – дня. Задостойник Пасхи. Причасний – «Тіло Христове...» Закінчення Літургії та відпуст – як в перший день Пасхи."}]},
{"date":"04-17","weekday":"п’ятниця","title":"Світла п’ятниця. Ікони Божої Матері «Живоносне джерело» (перехідне святкування у п’ятницю Світлого тижня). Сщмчч. Симеона, єп. Перського, і з ним Авделая і Ананії, пресвітерів, мчч. Хусдазата (Усфазана), євнуха, Фусика, Азата, мц. Аскитреї та інших багатьох (344). Прп. Акакія, єп. Мелітинського (бл. 435). Мч. Адріана (251). Свт. Агапіта, папи Римського (536).","readings":["Літ. – Діян., 7 зач., III, 1 – 8. Ін., 7 зач., II, 12 – 22.","Богородиці: Флп., 240 зач., II, 5 – 11. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"До Пасхальної відправи додається служба Пресвятій Богородиці на честь її ікони «Живоносне джерело» (див. у Тріоді квітній). Після Літургії, за звичаєм, звершується мале освячення води. Співається 9-ий час за пасхальним чином.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ Ієрей у ризі, ставши перед престолом з кадилом в правій руці, з хрестом та трисвічником в лівій, творить хрест кадилом і виголошує: «Благословенний Бог наш...». Священик починає: «Христос воскрес із мертвих, смертю смерть подолав і тим, що у гробах, життя дарував» (тричі). Хор співає той самий тропар тричі. Настоятель виголошує стихи: Стих 1: «Нехай воскресне Бог...»; Хор на кожен стих співає: «Христос воскрес...» (один раз). Стих 2: «Як щезає дим...»; Стих 3: «Так нехай згинуть грішники...»; Стих 4: «В цей день, його ж створив Господь...»; «Слава...»; «І нині»; І знову настоятель: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що у гробах, життя дарував». Велика ектенія. На «Господи, взиваю» стихири на 10: воскресні (див. в Тріоді), глас 6-ий – 6 та Богородиці, глас той самий – 4 (перша стихира двічі). «Слава» – Богородиці, глас той самий: «Хто висловить силу Джерела Твого...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Вхід з кадилом. Прокимен великий, глас 7-ий: «Любитиму Тебе, Господи, сило моя; Господь – твердиня моя» з приспівами. Ектенія потрійна: «Промовимо всі...», «Сподоби, Господи...», ектенія прохальна: «Доповнимо вечірню молитву...» і голововклонна молитва. На стиховні співається одна стихира воскресна (див. в Тріоді), глас 6-ий: «Воскресіння Твоє, Христе Спасе...», далі стихири Богородиці (зі своїми приспівами), глас 5-ий. «Слава» – Богородиці, глас той самий: «Засурмімо, святолюбці, піснями...», «І нині» – Пасхи, глас той самий: «Воскресіння день...». «Христос воскрес із мертвих...» (один раз, як закінчення стихири). І тричі тропар «Христос воскрес із мертвих...». Ієрей: «Премудрість». Хор: «Благослови». Ієрей: «Сущий благословенний...». Хор: «Амінь. Утверди, Боже...». Ієрей співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що в гробах, життя дарував». Ієрей з хрестом-трисвічником в руках виголошує відпуст: «Христос, що воскрес із мертвих...» та інше (див. у понеділок Світлого тижня на вечірні). Звершується послідування пасхальних часів за мале повечір’я та за полуношницю (перед ранньою)."},{"svc":"РАННІЙ","text":"НА РАННІЙ Початок пасхальний з приспівами та кадінням (див. у понеділок Світлого тижня). Велика ектенія. Канон Пасхи з ірмосом на 8 (ірмоси по двічі, Богородичні Пасхального канону не співаються) і канон Богородиці (Живоносного Джерела) з Тріоді на 6 (тропарі канону співаються). Приспів до тропарів канону Пасхи – «Христос воскрес із мертвих», до тропарів канону Живоносного Джерела – «Пресвятая Богородице, спаси нас», до передостаннього тропаря – «Слава...», до останнього – «І нині...». Катавасія після кожної пісні – ірмоси канону Пасхи «Воскресіння день...» (один раз). Після кожної пісні тричі співається тропар Пасхи «Христос воскрес...» (швидким розспівом). Кадіння, за традицією, звершується на 1-ій, 4-ій, 7-ій і 9-ій піснях канону. Малі ектенії по 3-ій, 6-ій і 9-ій піснях. Після 3-ої пісні – кондак Пасхи, глас 8-ий: «Хоч і до гробу...», та ікос Пасхи, глас той самий: «Того, Хто Сонце, що раніше сонця...». Сідальний Богородиці, глас той самий: «Приснотекуче Джерело і живоносне...». Після 6-ої пісні – кондак і ікос Богородиці, глас 8-ий. Далі «Воскресіння Христове бачивши...» (тричі), «Воскрес Ісус із Гробу...» (тричі). 9-та пісня співається в наступному порядку: Диякон: «Величає душа моя Воскреслого триденно із гробу Христа Життєдавця», 1-ий хор: «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою»; 2-ий хор – «Величає душа моя Того, Хто добровільно страждав і був похований, і воскрес триденно із гробу», «Світися, світися, новий Єрусалиме, слава бо Господня над тобою зійшла, радій нині і веселися, Сионе, а Ти, Чистая, красуйся, Богородице, бо воскрес Народжений Тобою»; 1-ий хор: «Христос – нова Пасха, жертва жива, Агнець Божий, що взяв гріхи світу», «О Божественне, о любе, пресолодке слово Твоє; з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 2-ий хор – «Ангел звістив Благодатній: Чистая Діво, радуйся, і знову кажу: радуйся! Твій Син воскрес на третій день із гробу і мертвих воскресив; люди, веселіться», «О Божественне, о любе, пресолодке слово Твоє: з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 1-ий хор: «Розбудив Ти, заснувши, мертвих від віку, по-царськи рикнувши, як лев від Іуди», «О Божественне, о любе, пресолодке слово Твоє: з нами бо правдиво обіцяв Ти бути до кінця віку, Христе. Його ж утвердженням надії маючи, ми, вірні, радіємо»; 2-ий хор: «Магдалина Марія, прийшовши до гробу і Христа побачивши, як садівника, запитувала», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 1-ий хор: «Ангел сяючий до жінок взивав: припиніть плакати, бо Христос воскрес!», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 2-ий хор: «Христос воскрес, смерть подолав і мертвих воскресив, люди, веселіться», «О Пасха велика і найсвятіша, Христе, о Мудросте й Слово Боже і Сило, дай нам істинно причащатися Тебе, у невечірній день Царства Твого»; 1-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу», і перший тропар з канону Живоносного Джерела: «Всі води перевершує, Богоотроковице Чиста...». 2-ий хор: той самий стих та тропар; 1-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу», і другий тропар з канону Живоносного Джерела: «Це новий Силоам...». 2-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу», і третій тропар з канону Живоносного Джерела: «Хто шукає здоров’я...». 1-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу», і четвертий тропар з канону Живоносного Джерела: «Піднялася джерела Твого вода...». 2-ий хор: «Радуйся, Діво, радуйся; радуйся, Благословенна, радуйся Препрославлена, бо Твій Син воскрес триденний із гробу», і п’ятий тропар з канону Живоносного Джерела: «Радуєш, Діво, царя надприродно...». Потім обидва кліроси разом співають перший приспів: «Величає душа моя Воскреслого триденно із гробу Христа Життєдавця» та ірмос: «Світися, світися, новий Єрусалиме...» і тропар: «Христос воскрес...» (тричі, швидким розспівом). Після 9-ої пісні – екзапостиларій Пасхи: «Плоттю заснувши...» (двічі), «Слава, і нині...» – світильний Богородиці: «Ти воістину єси Джерело води живої, Владичице...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8 (див. в Тріоді): воскресні, глас 6-ий – 4, і Богородиці, глас 2-ий – 4. Потім стихири Пасхи, глас 5-ий, з приспівами: «Нехай воскресне Бог...». І тричі тропар «Христос воскрес із мертвих...» на завершення ранньої. Ектенія потрійна: «Помилуй нас, Боже...», ектенія прохальна: «Доповнимо ранню молитву...» і голововклонна молитва. Ієрей: «Премудрість». Хор: «Благослови». Ієрей: «Сущий благословенний...». Хор: «Амінь. Утверди, Боже...». Ієрей співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор: «І тим, що в гробах, життя дарував». Ієрей з хрестом-трисвічником в руках виголошує відпуст: «Христос, що воскрес із мертвих...» та інше (див. у понеділок Світлого тижня на ранній). ЧАСИ ПАСХИ."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони Пасхи та інше, як в перший день. Вхідний Пасхи. Після входу тропар «Христос воскрес із мертвих...» (один раз), іпакої Пасхи, глас 4-ий, «Слава, і нині...» – кондак Пасхи, глас 8-ий. Замість Трисвятого – «Усі ті, що в Христа хрестилися...» Прокимен п’ятниці Світлої седмиці глас 8-ий: «По всій землі розійшлось віщування їх, і в кінці вселенної слова їх». Стих: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь» та глас 3-ій, пісня Богородиці: «Величає душа моя Господа...» Алилуарій дня і Богородиці. Апостол, Алилуарій та Євангеліє – дня і Богородиці. Задостойник Пасхи. Причасний – «Тіло Христове...» та Богородиці «Чашу спасіння...» Закінчення Літургії та відпуст – як в перший день Пасхи. Примітка. За звичаєм, після Літургії звершується мале освячення води. При його звершенні слід враховувати богослужбові особливості Світлого тижня (порівн.: Типікон, гл. 50, «Слід знати, якщо співається молебень на Святу Пасху»). Існує традиція поєднання чину водосвяття з хресним ходом, який відбувається після Літургії."}]},
{"date":"04-18","weekday":"субота","title":"Світла субота. Прп. Іоана, учня прп. Григорія Декаполіта (820 – 850). Мчч. Віктора, Зотика, Зинона, Акиндина і Северіана (303). Свт. Косми, спов., єп. Халкідонського, і прп. Авксентія (815 – 820). Мч. Іоана Нового з Яніни (1526). Максимівської ікони Божої Матері (1299).","readings":["Діян., 8 зач., III, 11 – 16. Ін., 11 зач., III, 22 – 33."],"notes":"Після заамвонної молитви на Літургії читається молитва на роздроблення артоса, і відбувається роздроблення та роздається артос вірним. Перед 9-м часом зачиняються царські врата. Всі служби добового кола звершуються за зразком Світлого понеділка (13 квітня) та Світлого вівторка (14 квітня). Співаються стихири 8-го гласу.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ у п’ятницю прокимен великий, глас 8-ий: «Дав єси насліддя...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ прокимен, глас 3-ій: «Господь – Просвічення моє і Спаситель мій. Кого убоюся?»; стих: «Господь – захисник життя мого. Кого устрашуся?». Апостол і Євангеліє – дня (суботи Світлого тижня). Після заамвонної молитви читається молитва на роздроблення артоса, і відбувається роздроблення та роздавання артоса. Перед 9-им часом зачиняються Царські врата (9-ий час звичайний, трипсалмний; на ньому читаються тропар та кондак воскресні 8-го гласу). Загальні особливості богослужіння від Фоминої Неділі до віддання Пасхи 1) Від Фоминої неділі до віддання Пасхи всі церковні служби і треби починаються триразовим співом або читанням тропаря «Христос воскрес із мертвих...». 2) На всенічній «Христос воскрес із мертвих...» (тричі) співається, за традицією, замість «Прийдіть, поклонімось» і після «Благословення Господнє на вас...» перед початком шестипсалмія. 3) На недільній всенічній, після закінчення стихир Пасхи на стиховні вечірні, співається тропар «Христос воскрес із мертвих...» (один раз): він входить в останню стихиру, будучи її завершенням. 4) на Літургії «Христос воскрес із мертвих...» (тричі) співається після «Благословенне Царство...». Примітка. Зазвичай на початку Всенічної і Літургії священнослужителі співають тропар два рази повністю, а третій раз закінчуючи словами: «...смертю смерть подолав», а співці закінчують: «І тим, що в гробах, життя дарував». У деяких храмах тропар «Христос воскрес...» (один раз) співають священнослужителі, а потім (по разу) повторюють його обидва хори. Перед шестипсалмієм зазвичай «Христос воскрес...» всі три рази співає хор. 5) «Христос воскрес із мертвих...» (тричі) читається на початку часів, вечірні, повечір’я, полуношниці і утрені: на 3-му, 9-му часі, повечір’ї та полуношниці – замість «Царю Небесний...», а на 1-му, 6-му часах та вечірні (якщо безпосередньо перед її початком прочитаний 9-ий час), за традицією, замість «Прийдіть, поклонімось...». 6) На Літургії «Христос воскрес із мертвих...» співається (один раз) замість «Ми бачили Світло Істинне...». Вхідний: «Прийдіть, поклонімось... що воскрес із мертвих...». 7) В кінці Літургії, після виголосу: «Слава Тобі, Христе Боже, надіє наша, слава Тобі», хор співає: «Христос воскрес із мертвих...» (тричі). На всіх інших службах після виголосу: «Слава Тобі, Христе Боже, надіє наша, слава Тобі» закінчення за звичаєм. Відпуст на всіх службах починається словами: «Христос, що воскрес із мертвих...». 8) В неділю, після відпусту Літургії, за стародавнім звичаєм, ієрей тричі осіняє народ хрестом і виголошує: «Христос воскрес», як і в дні Світлого тижня. Хор співає заключне «Христос воскрес із мертвих...» (тричі), «І нам дарував життя вічне, поклоняємось Його триденному воскресінню» (один раз). У седмичні дні осінення хрестом не буває. 9) Тропар «Христос воскрес із мертвих...» співається також на початку молебнів, панахид, хрещення, відспівування і інших треб. 10) «Царю Небесний...» не читається й не співається до дня Святої Трійці. 11) Служби святих, що припадають в усі недільні дні Святої П’ятдесятниці (крім вмч. Юрія, ап. Іоана Богослова, свт. Миколая, свв. Рівноапостольних Костянтина і Єлени, храмових і полієлейних свят) не поєднуються з воскресною службою, а звершуються на повечір’ї разом з каноном Богородиці з Октоїха і трипіснцями Квітної Тріоді. 12) «Воскресіння Христове бачивши...» на недільній ранній співається тричі, а в інші дні на ранній, перед 50-м псалмом, один раз. 13) Канон Пасхи співається на недільній ранній в Неділі жінок-мироносиць, про розслабленого, про самарянку і про сліпого з усіма тропарями і Богородичними, без заключного «Христос воскрес із мертвих...». 14) У всі Неділі до віддання Пасхи на недільній ранній «Чеснішу» не співається. На 9-й пісні канону звершується звичайне кадіння храму. 15) Екзапостиларій «Плоттю заснувши...» співається на недільній ранній в ті Неділі, коли співається канон Пасхи. 16) Після 1-го часу в усі дні від Неділі Фоминої до Вознесіння прийнято замість «Непереможній Воєводі...» співати кондак Пасхи, глас 8-ий: «Хоч і до гробу...». 17) На Літургії в усі дні до Вознесіння, крім свята Переполовення і віддання його, співається задостойник: «Ангел звістив...» і «Світися, світися...». 18) Причасний Пасхи «Тіло Христове прийміть...» співають в усі дні до віддання Пасхи, крім седмиці Фоминої, свята Переполовення та віддання Переполовення. 19) Земні поклони до дня Святої Трійці Уставом скасовуються. Про поєднання Тріоді з Мінеєю в седмичні дні від Неділі Фоминої до віддання Пасхи, крім субот і неділь Служби Квітної Тріоді поєднуються з Мінеєю, причому при співі стихир, тропарів і канону виконуються спочатку піснеспіви Тріоді, а потім Мінеї. Першим співається канон Тріоді, до якого приєднуються тропарі канону святого. Катавасія, якщо служба з великим славослів’ям, – Пасхи, а не Мінеї. Якщо служба без великого славослів’я, то катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Слід пам’ятати, що під «святом» в Квітній Тріоді мається на увазі служба минулого недільного дня, або свята Переполовення, Вознесіння і П’ятдесятниці (в самі ці свята і в їх післясвята). Найменування «свято» жодним чином не відноситься до свята Пасхи або свята Мінеї. І. На Літургії в седмичні дні виконують: 1) На блаженних – пісні святкового канону на 6: в понеділок – 1-ша пісня, у вівторок – 4-та, в середу – 5-та, в четвер – 7-ма, в п’ятницю – 8-ма, в суботу – 9-та. 2) Після входу – тропарі і кондаки: а) На Фоминій седмиці – тропар свята (Антипасхи), тропар храму Богородиці або храму святого, тропар рядового святого (якщо є), тропар іншого рядового святого (якщо два святих, і обидва з тропарями); кондак храму святого, кондак першого рядового святого. «Слава» – кондак другого рядового святого, «І нині» – кондак свята (Антипасхи). б) У седмицю святих жінок-мироносиць – тропар свята: «Благообразний Йосиф...», недільний: «Коли зійшов Ти...», свята: «Мироносицям жінкам...», тропар храму Богородиці або храму святого, тропар рядового святого (одного або двох); кондак храму святого, кондак рядового святого. «Слава» – кондак іншого рядового святого (якщо їх два), «І нині» – кондак свята: «Радіти мироносицям...». в) У віддання свята Переполовення – тропар свята, тропар храму Богородиці або храму святого, тропар рядового святого (одного або двох), кондак храму святого, кондак рядового святого. «Слава» – кондак іншого рядового святого (якщо їх два), «І нині» – кондак свята. г) У всіх інших випадках – так само, як у віддання свята Переполовення, тільки замість тропаря свята – тропар воскресний. Таким чином, тропар свята співається всю седмицю. Тропар і кондак храму Господського, а також кондак храму Богородиці у всю П’ятидесятницю не співають. При звершенні служби одному полієлейному святому в усі седмиці – тропар свята (або недільний), тропар храму Богородиці або храму святого, тропар рядового святого; кондак храму святого. «Слава» – кондак рядового святого, «І нині» – кондак свята. При звершенні служби двом святим: шестеричному та великому святому – тропар свята (або недільний), тропар великого святого, тропар шестеричного святого; кондак великого святого. «Слава» – кондак шестеричного святого, «І нині» – кондак свята. В цьому випадку тропар і кондак храму святого не співаються, оскільки Типікон передбачає бдіння. 3) Апостол і Євангеліє – спочатку дня, потім святого (якщо є). ІІ. Стихири на вечірні і на ранній: 1) На «Господи, взиваю...» спочатку співаються стихири свята з Тріоді – 3, потім святого Мінеї – 3. «Слава» – святого, якщо є, «І нині» – свята; якщо «Слави» святого немає, то «Слава, і нині» – свята. 2) На стиховні стихири Тріоді дня. «Слава» – святого, «І нині» – свята. Якщо «Слави» святого немає, то «Слава, і нині» – свята. При звершенні служби двом святим, що мають кожен свої стихири, на «Господи, взиваю...» співаємо стихири обох святих на 6. «Слава» – святого, «І нині» – свята. Якщо «Слави» святого немає, то «Слава, і нині» – свята. Стихири Тріоді, зазначені на «Господи, взиваю» в такому випадку співаються на стиховні зі святковими стиховними приспівами (див. на стиховні ранньої). Примітка. На думку В. Розанова, приспіви беруться з Тріоді з вечірніх стихир на стиховні цього дня. «Слава» – святого, якщо є, а якщо немає, то «Слава, і нині» – свята. Стихири на стиховні що містяться в Тріоді, які по суті належать до системи Октоїха, в даному випадку не співаються. Якщо святий полієлейний, то на «Господи, взиваю» стихири свята Тріоді – 3 і святого – 5. «Слава» – святого, «І нині» – свята. На стиховні стихири святого зі своїми приспівами. «Слава» – святого, «І нині» – свята. Якщо святкується пам’ять двох святих, один з яких співається на 6, а інший має полієлей, то на «Господи, взиваю...» стихири на 10: свята Тріоді – 3, шестеричного святого – 3 і полієлейного святого – 4. «Слава» – полієлейного святого, «І нині» – свята Тріоді. Вхід. Паремії полієлейного святого – 3. На стиховні стихири і «Слава» – полієлейного святого, «І нині» – свята. 3) На хвалітніх (якщо святий має власні стихири на хвалітніх) співаємо стихири Тріоді дня – 3 (недільну, покаянну і мученичний) і святого з Мінеї – 3. «Слава» – святого, «І нині» – свята. 4) На стиховні ранньої – стихири Тріоді з приспівами своїми. «Слава» – святого, якщо є. Якщо немає, то «Слава, і нині» – свята. 5) Якщо святий полієлейний (або славослівний), то на хвалітніх стихири на 6: Тріоді – 3 (зі стиховні утрені) і святого – 3. «Слава» – святого, «І нині» – Тріоді. В даному випадку хвалітні стихири Тріоді, які по суті належать до системи Октоїха, не співаються. ІІІ. Тропарі на вечірні і ранній (після кінцевого Трисвятого): 1) Протягом Фоминого тижня і віддання свята Переполовення, при святому, що має тропар, після Трисвятого – тропар святого. «Слава, і нині» – свята. При двох святих – тропар першого святого, «Слава» – тропар другого святого, «І нині» – свята. При відсутності тропаря святого – тропар свята (один раз). 2) Протягом 3-го тижня (святих жінок-мироносиць) – тропар свята: «Благообразний Йосиф...». «Слава» – святого, «І нині» – «Мироносицям жінкам...». Або ж – тропар воскресний: «Коли зійшов Ти до смерті...» – «Слава» – святого, «І нині» – «Мироносицям жінкам...». При наявності тропаря святого тропарі «Благообразний Йосиф...» і воскресний «Коли зійшов Ти до смерті...» слід чергувати протягом дня: на вечірні – тропар свята, на ранній – тропар воскресний (або навпаки, на вечірній – тропар воскресний, на ранній – тропар свята). Якщо всі служби Мінеї, що припадають на будні дні після Неділі мироносиць, містять тропар, можна співати в понеділок, середу і п’ятницю один тропар мироносиць, у вівторок, четвер і суботу – інший. 3) Протягом 4-го, 5-го, 6-го тижнів після Пасхи – тропар воскресний. «Слава» – святого, «І нині» – Богородичний воскресний за гласом «Слави...». IV. Тропарі на ранній на «Бог – Господь...»: 1) Протягом Фоминого тижня і віддання свята Переполовення – тропар свята (двічі). «Слава» – святого, «І нині» – свята. Якщо немає тропаря святого – тропар свята (тричі). При двох святих, кожен з яких має свій тропар, – тропар свята (один раз), тропар першого святого (один раз). «Слава» – тропар другого святого, «І нині» – тропар свята. 2) Протягом тижня жінок-мироносиць – тропар свята «Благообразний Йосиф...» (один раз), тропар воскресний «Коли зійшов Ти до смерті...» (один раз). «Слава» – святого, «І нині» – «Мироносицям жінкам...». Якщо немає тропаря святого – «Благообразний Йосиф...» (двічі). «Слава» – «Коли зійшов Ти до смерті...», «І нині» – «Мироносицям жінкам...». При двох святих, кожен з яких має свій тропар, – «Благообразний Йосиф...» (один раз), тропар першого святого (один раз). «Слава» – тропар другого святого, «І нині» – «Мироносицям жінкам...». 3) Протягом 4-го, 5-го та 6-го тижня після Пасхи – тропар воскресний (двічі). «Слава» – святого, «І нині» – Богородичний воскресний за гласом «Слави». Якщо немає тропаря святого: «Слава, і нині» – Богородичний воскресний за гласом тропаря. При двох святих, кожен з яких має свій тропар, – тропар воскресний (один раз), тропар першого святого (один раз). «Слава» – тропар другого святого, «І нині» – Богородичний воскресний за гласом тропаря другого святого. V. Канони: 1) Якщо святий не має святкового знаку – канон свята Тріоді на 8 (ірмоси по двічі) і святого з Мінеї на 4. Після 3-ої пісні – кондак, ікос та сідальний святого. «Слава, і нині» – сідальний свята. Після 6-ої пісні – кондак і ікос свята. 2) Якщо святий шестеричний – канон свята Тріоді з ірмосом на 6 (ірмоси по двічі) і святого на 6. Після 3-ої пісні – кондак і ікос свята, сідальний святого (двічі). «Слава, і нині...» – сідальний свята. Після 6-ої пісні – кондак і ікос святого. 3) Якщо в Мінеї два святих – канон свята з ірмосом на 6 (ірмоси двічі) і святих два канони на 8. 4) При полієлейному святому – канон свята з ірмосом на 6 (ірмоси по двічі) і святого на 8. Після 3-ої пісні – кондак і ікос свята, сідальний святого (двічі). «Слава, і нині» – сідальний свята. Після 6-ої пісні – кондак і ікос святого. 5) При двох святих, один з яких шестеричний, а інший полієлейний, – канон свята з ірмосом на 4 (ірмоси по двічі), шестеричного святого на 4 та полієлейного святого на 6. Або: канон свята з ірмосом на 4 (ірмоси по двічі), полієлейного святого на 6 та шестеричного святого на 4 (порівн.: Типікон, 8 травня). Після 3-ої пісні – кондак і ікос шестеричного святого. Сідальний полієлейного святого. «Слава» – сідальний шестеричного святого, «І нині» – сідальний свята. Після 6-ої пісні – кондак і ікос великого святого. Від Неділі Пасхи до віддання – катавасія «Воскресіння день...». У день Переполовення П’ятдесятниці і на його віддання – катавасія Переполовення «Море висушив Ти...». В Неділю 6-ту після Великодня (про сліпого) та на відання Пасхи – катавасія Вознесіння «Спасителю Богу...». VI. Тропарі та кондаки на часах: 1) Протягом Фоминого тижня і на віддання свята Переполовення на часах тропар свята. «Слава» – святого. Кондак свята. При славослівному, полієлейному або бдінному святому – кондаки свята і святого чергуються. При двох святих – тропарі святих на «Слава» чергуються. 2) В седмицю жінок-мироносиць: на 1-му часі тропар «Благообразний Йосиф...», на 3-му – «Коли зійшов Ти...», на 6-му – «Мироносицям жінкам...», на 9-му –«Благообразний Йосиф...». На «Слава» на всіх часах тропар святого (при двох святих – тропарі на «Слава» чергуються). Кондак свята (при славослівному, полієлейному або бдінному святому кондаки свята і святого чергуються). 3) В усі інші седмиці Пасхи на часах тропар воскресний. «Слава» – святого. Кондак свята. При славослівному, полієлейному або бдінному святому кондаки свята і святого чергуються. При двох святих – тропарі святих на «Слава» чергуються. Про поєднання Тріоді зі службами святих у 2-гу, 3-тю, 4-ту та 5-ту суботи П’ятдесятниці І. Стихири: 1) На «Господи, взиваю...»: а) При звершенні служби святого, що не має святкового знаку, в п’ятницю ввечері стихири Тріоді (свята) – 3 і святого з Мінеї – 3. «Слава» – Тріоді (або святого, якщо є), «І нині» – догматик гласу, що віддається (минулої неділі). б) Якщо трапляться два святих, стихири Тріоді (свята) – 3 і стихири першого святого – 3. Вечірні стихири другого святого переносяться на хвалітні. в) Якщо трапиться великий святий, який має полієлей, стихири Тріоді (свята) – 4 і святого – 4. «Слава» – святого, «І нині» – догматик гласу, що віддається (минулої неділі). 2) На стиховні завжди незмінно (навіть в пам’ять полієлейного або бдінного святого) – чотири стихири воскресні гласу з Тріоді з воскресними приспівами «Господь воцарився...». «Слава» – святого, «І нині» – свята Тріоді. 3) На хвалітніх стихири воскресні з Тріоді – 3 і святого з Мінеї – 3. «Слава» – святого, «І нині» – свята. 4) На стиховні ранньої, якщо немає славослів’я, стихири Тріоді з їхніми приспівами. «Слава» – святого (якщо є), «І нині» – свята. II. Тропарі: 1) Устав тропарів на вечірні та ранній (після кінцевого Трисвятого) – той же, що і в седмичні дні. Особливість полягає в тому, що в суботу 5-го тижня на «І нині» співається воскресний Богородичний гласу минулої неділі (що віддається), а не за гласом тропаря святого. 2) Устав тропарів на ранній на «Бог Господь...» – той самий, що і в седмичні дні. В суботу 5-го тижня після Пасхи на «І нині...», як і в седмичні дні, співається Богородичний 1-ий за гласом тропаря святого, а Богородичний 1-ий поточного гласу – після сідального 1-ої кафізми. Якщо немає тропаря святого, то «Слава, і нині...» – Богородичний 1-ий поточного гласу. 3) Устав тропарів і кондаків на часах, а також на Літургії після входу – той самий, що і в седмичні дні. III. Канони: 1) При святому, служба якого не має святкового знаку – канон Тріоді (свята) з ірмосом на 6 (ірмоси по двічі, тропарі на 4), канон храмового святого на 4 і святого Мінеї на 4. Після 3-ої пісні – кондак, ікос та сідальний святого. «Слава, і нині» – сідальний Тріоді (свята). Після 6-ої пісні – кондак і ікос свята. В храмі Господському або Богородиці – канон Тріоді (свята) з ірмосом на 8 (ірмоси по двічі, тропарі на 6) та святого Мінеї на 4. Канони храму Господського і Богородиці в суботи всієї П’ятдесятниці не співаються (крім Троїцької батьківської суботи). 2) При службі шестеричному святому – канон свята з ірмосом на 6 (ірмоси по двічі) та святого на 6. Канон храму не співається. 3) При службі двом святим – канон Тріоді (свята) з ірмосом на 6 (ірмоси по двічі) і святих обидва канони на 8. Після 3-ої пісні – кондак і ікос першого святого, кондак і ікос другого святого (якщо є), сідальний першого святого, «Слава» – сідальний другого святого, «І нині» – сідальний Тріоді (свята). Після 6-ої пісні – кондак і ікос свята. 4) При святому, що має полієлей – канон свята з ірмосом на 6 (ірмос двічі) і святого на 8. Після 3-ої пісні – кондак і ікос свята, сідальний святого (двічі). «Слава, і нині» – сідальний Тріоді (свята). Після 6-ої пісні – кондак і ікос святого. Крім того, як в седмичні, так і в суботні дні після читання кафізм завжди виголошуються малі ектенії, оскільки в числі сідальнів після 1-ої кафізми завжди є воскресний, а після 2-ої – святковий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. У дні, в які не співається велике славослів’я, після хвалітніх стихир не читається «Слава, і нині» – «Тобі слава подобає...» ,бо на «Слава» і на «І нині» були проспівані стихири."}]},
{"date":"04-19","weekday":"неділя","title":"Антипасха. 2-га неділя після Пасхи, апостола Фоми. Прп. Іоана Давньопечерника (VІІІ). Мчч. Феони, Христофора й Антоніна (303). Сщмч. Пафнутія, єп. Єрусалимського. Свт. Георгія, спов., єп. Антіохії Пісідійської (813 – 820). Свт. Трифона, патр. Константинопольського (933). Прп. Никифора, ігумена.","readings":["Ран. – Єв. 1-е, Мф., 116 зач., XXVIII, 16 – 20.","Літ. – Діян., 14 зач., V, 12 – 20. Ін., 65 зач., XX, 19 – 31."],"notes":"Від сьогодні щодня до віддання Пасхи богослужіння після виголосу священника починається триразовим читанням або співом «Христос воскрес із мертвих...». В усі недільні дні до віддання Пасхи «Чеснішу..» не співаємо. На ранній величання «Величаємо Тебе, Життєдавче Христе, що заради нас у пекло зійшов і з Собою всіх воскресив». Після Євангелія у всі неділі до віддання Пасхи – «Воскресіння Христове бачивши...» – (тричі). Пасхальний канон в цю неділю не співається. На Літургії задостойник «Ангел звістив...», «Світися, світися...» (так щодня, крім Переполовення і його віддання). Замість «Ми бачили Світло істинне...» – «Христос воскрес...» (один раз), а перед відпустом після «Слава Тобі, Христе Боже, надіє наша, слава Тобі» співається тричі. Відпуст воскресний: «Христос, що воскрес із мертвих, істинний Бог наш...» (так і у всі дні до віддання Пасхи включно). Вечірня в неділю Антипасхи із входом і великим прокимном. У суботу ввечері перед 9-им часом (і малою вечірнею) зачиняються царські врата. 9-ий час читається звичайний трьохпсалмний. На ньому тропар воскресний 8-го гласу: «З висоти зійшов Ти...», і кондак Пасхи: «Хоч і до гробу...».","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ після виголосу: «Слава Святій, Єдиносущній...» співається «Христос воскрес із мертвих...» (тричі), і початковий 103-ій псалом. («Прийдіть, поклонімось», за традицією, не співається). «Блажен муж» – кафізма вся. На «Господи, взиваю...» стихири на 10: свята Тріоді, глас 1-ий і глас 2-ий «Слава, і нині» – Тріоді, глас 6-ий: «Коли двері були замкнені...» (догматик гласу не співається). Вхід. «Світло Тихе». Прокимен дня. На літіі стихири свята Тріоді, глас 4-ий і глас 8-ий, та преподобного, глас 1-ий. «Слава, і нині» – Тріоді, глас той самий: «Коли двері були замкнені, ученики зібрані...». На стиховні стихири свята Тріоді, глас 4-ий (зі своїми приспівами). «Слава і нині» – Тріоді, глас 5-ий: «Людинолюбче, велике і безмірне багатство...» (стихири Пасхи не співаються). Після Трисвятого – тропар свята Тріоді (Антипасхи), глас 7-ий: «Коли гріб був запечатаний...» (тричі). Після виголосу «Благословення Господнє на вас...» хор: «Амінь». Примітка. Тут, за Уставом, слід читати «Книгу Діянь від початку або бесіди Золотоустого від початку» (Типікон, гл. 50, «Неділя Антипасхи»). «Нехай буде відомо, що від Неділі Святоі Пасхи, аж до Неділі всіх святих, після благословення хлібів, читають Діяння святих апостолів. А в інші неділі всього року читають сім Соборних Послань апостольських, і чотирнадцять Послань святого Павла, і Одкровення святого апостола Іоана Богослова» (Типікон, гл. 2, 1-ше «див.»). Порядок читання Типікон при цьому не описує. Читання відбувається наступним чином. Читець: «Діяння святих апостол благослови, отче, прочитати». Священик: «Молитвами святих отців наших...». Читець: «Амінь», і починається читання. Після закінчення читання читець: «Богу нашому слава завжди, нині, і повсякчас, і на віки віків». Інший читець (за Типіконом – предстоятель): «Амінь». «Христос воскрес із мертвих...» (тричі), і починається шестипсалміє: «Слава в вишніх Богу...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята Тріоді (Антипасхи), глас 7-ий (двічі). «Слава, іІ нині» – тропар той же. Кафізми 2-га і 3-тя. Малі ектенії. Сідальні свята (Тріоді). Полієлей. Величання свята (Тріоді): «Величаємо Тебе, / Життєдавче Христе, / що заради нас до пекла зійшов // і з Собою всіх воскресив», і вибраний псалом Антипасхи (недільні тропарі «Ангельський собор...» не співаються). Сідальний Тріоді після полієлея, глас 1-ий: «Побачивши Мої ребра...», «Слава, і нині» – той самий сідальний. Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Прославляй, Єрусалиме, Господа, хвали Бога твого, Сионе»; стих: «Як укріпив ти засуви врат твоїх». Євангеліє воскресне 1-ше. «Воскресіння Христове бачивши...» (тричі). Після 50-го псалма: «Слава» – «Молитвами апостолів...», «І нині» – «Молитвами Богородиці...». «Помилуй мене, Боже...» і стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...» (один раз). Канони: свята Тріоді (Антипасхи), глас 1-ий: «Співаємо всі люди...» з ірмосом на 14 (ірмоси двічі). Біблійні пісні «Співаймо Господеві...». Катавасія Пасхи: «Воскресіння день.» Після 3-ої пісні – іпакої Антипасхи, глас 6-ий: «Як прийшов Ти, Спасе, до учеників Твоїх...». Після 6-ої пісні – кондак свята Тріоді (Антипасхи), глас 8-ий: «Допитливою рукою...» та ікос. На 9-ій пісні «Чеснішу» не співаємо. (Звершується звичайне кадіння). Після 9-ої пісні – «Свят Господь Бог наш» на глас 1-ий. Світильний Тріоді: «Ти випробував своєю рукою рани Моїх рук і ніг...». «Слава, і нині» – другий світильний Тріоді: «Нині весна благозапашна...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята Тріоді, глас 1-ий – 4 (перша стихира двічи) «Слава» – Тріоді, глас 6-ий: «На восьмий день...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар свята. Ектенії та відпуст: «Христос, що воскрес із мертвих є істинний Бог наш, молитвами Пречистоі Своєі Матері, святого славного апостола Фоми і всіх святих...» (святий храму не згадується). Перед 1-им часом на «Слава, і нині» – стихира євангельська 1-ша, глас 1-ий: «Коли йшли ученики на гору...» (див. у Тріоді). Часи – звичайні, трипсалмні."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар і кондак Антипасхи. ЛІТУРГІЯ свт. Іоана Золотоустого. Примітка. «Літургія буває раненько, заради труда бдінного» (Типікон, гл. 50, «Неділя Антипасхи»). Після виголосу «Благословенне Царство...» – «Христос воскрес...» (тричі). На спів тропаря, за традицією, відкриваються царські врата. Примітка. «Нехай буде відомо, що від Неділі Новоі і до віддання свята Пасхи початок Літургіі такий: після виголосу диякона «Благослови, владико». Ієрей: «Благословенне Царство...» і співає ієрей: «Христос воскрес...» тричі, весь тропар, крім стихів: «Нехай воскресне Бог..» (Типікон, гл. 50, «Неділя Антипасхи»). Велика ектенія. Антифони зображальні. Блаженні свята Тріоді, пісня 3-тя – 4 (з ірмосом), і пісня 6-та – 4. На вході: «Прийдіть, поклонімось... що воскрес із мертвих...»."}]},
{"date":"04-20","weekday":"понеділок","title":"2-й тиждень після Пасхи (Проводи). Прп. Федора Трихіни. Свтт. Григорія (593) і Анастасія Синаїта (599), патріархів Антіохійських. Прп. Анастасія, ігум. Синайської гори (695). Мч. дитяти Гавриїла Білостоцького (1690). Кіпрської ікони Божої Матері (392).","readings":["Діян., 9 зач., III, 19 – 26. Ін., 6 зач., II, 1 – 11."],"notes":"Від сьогодні у будні до віддання Пасхи перед каноном співається «Воскресіння Христове бачивши...» (один раз). Співається «Чеснішу...». Катавасія, коли співається велике славослів’я, – «Воскресіння день...». «Царю Небесний...» не читається до П’ятдесятниці. У період Тріоді квітної на літургії у всі дні Апостол і Євангеліє дня читається першим, потім читання святим. Цього тижня за традицією звершується поминання померлих. Служба преподобного Федора трихіна повсякденна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ Після виголосу «Благословенний Бог наш...» читець: «Амінь». «Христос воскрес...» тричі та псалом 103-ій. Кафізми немає. На «Господи, взиваю...» стихири на 6: свята, глас 1-ий – 3, і преподобному, глас 8-ий – 3. «Слава, і нині» – свята, глас 1: «Коли двері були замкнені...». Вхід з кадилом. Прокимен великий, глас 7-ий: «Хто Бог великий...» з приспівами. Ектенія потрійна: «Промовимо всі...», «Сподоби, Господи...», ектенія прохальна: «Доповнимо вечірню молитву...» і голововклонна молитва. На стиховні стихири Тріоді, глас 1-ий з приспівами (див. на «Господи, взиваю»). «Слава, і нині» – Тріоді, глас той самий: «На восьмий день воскресіння Твого, Господи...» Після Трисвятого – тропар преподобного, глас 4-ий, «Слава, і нині...» – тропар Антипасхи, глас 7-ий. Після закінчення тропаря диякон: «Премудрість» – хор: «Благослови» і далі. Відпуст проголошується у відкритих царських вратах. Многоліття."},{"svc":"РАННІЙ","text":"НА РАННІЙ після возгласу «Слава Святій...»: «Амінь», «Христос воскрес...» співається тричі (протяжно), під час співу звершується повне кадіння храму і відразу ж «Слава в Вишніх Богу...» та Шестипсалміє. На «Бог – Господь» – тропар Антипасхи, глас 7-ий (двічі). «Слава» – тропар преподобного, глас 4-ий, «І нині» – тропар Антипасхи. Кафізми 4-та і 5-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: Антипасхи з ірмосом на 8 (ірмоси двічі) , преподобному на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону преподобного. Після 3-ої пісні – кондак преподобного, глас 4-ій. «Слава» сідальний преподобного, глас 4-ий «І нині» – іпакої Антипасхи, глас 6-ий. Після 6-ої пісні – кондак і ікос Антипасхи, глас 8-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є...» не співається. Світильний Антипасхи. «Слава, і нині» – інший світильний Антипасхи. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 1-ий – 4 (перша стихира двічі). «Слава, і нині» – глас той самий: «Фома, званий близнюком...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 2-ий з приспівами. «Слава, і нині» – Тріоді, глас 1-ий: «Коли ученики сумнівалися...». Після Трисвятого – тропар преподобного, глас 4-ій, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Антипасхи. «Слава» – тропар преподобного. Кондак тільки Антипасхи."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону Антипасхи, пісня 1-ша – 6 (з ірмосом). Після входу тропарі та кондаки: У храмі Господському – тропар Антипасхи, тропар преподобного, «Слава» – кондак преподобного, «І нині» – кондак Антипасхи. У храмі Богородиці – тропар Антипасхи, тропар храму, тропар преподобного, «Слава» – кондак преподобного, «І нині» – кондак Антипасхи (кондак храму не співається). У храмі святого – тропар Антипасхи, тропар храму, тропар преподобного, кондак храму, «Слава» – кондак преподобного, «І нині» – кондак Антипасхи. Прокимен, алилуарій і причасний – Антипасхи. Апостол і Євангеліє – дня. Задостойник Пасхи."}]},
{"date":"04-21","weekday":"вівторок","title":"Сщмч. Януарія, єп., і з ним сщмчч. Прокула, Соссія і Фавста, дияконів, мчч. Дисидерія, читця, Євтихія і Акутіона (бл. 305). Мчч. Федора, що в Пергії, матері його Филипії, Діоскора, Сократа і Діонісія (138 – 161). Мчч. Ісаакія, Аполоса і Кіндрата (303). Свт. Максиміана, патріарха Константинопольського (434).","readings":["Діян., 10 зач., IV, 1 – 10. Ін., 10 зач., III, 16 – 21."],"notes":"Служба святих свящмуч. Януарія і тих що з ним постраждали повсякденна , звершується зі службою Тріоді. Поминання померлих звершується на панахиді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 6-та. На «Господи, взиваю» стихири на 6: Антипасхи, глас 4-ий – 3, і мученика, глас 4-ий – 3. «Слава, і нині» – Антипасхи, глас 1: «Коли ученики сумнівалися...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 1-ий з приспівами (див. на «Господи, взиваю»). «Слава, і нині» – Тріоді, глас 2-ий: «Після воскресіння Твого, Господи...». Після Трисвятого – тропар мучеників, глас 4-ий, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ після возгласу «Слава Святій...»: «Амінь», «Христос воскрес...» співається тричі (протяжно), під час співу звершується повне кадіння храму і відразу ж «Слава в Вишніх Богу...» та Шестипсалміє. На «Бог – Господь» – тропар Антипасхи, глас 7-ий (двічі). «Слава» – тропар мучеників, глас 4-ий, «І нині» – тропар Антипасхи. Кафізми 7-ма і 8-ма. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: Антипасхи з ірмосом на 8 (ірмоси двічі), священномученику Януарію на 4 і священномученика Федора на 4.. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону священномученика Федора. Після 3-ої пісні – кондак мучеників, глас 3-ий. Сідальний мучеників, глас 4-ий, «Слава...» мученику, глас 4-ий, «І нині» – іпакої Антипасхи, глас 6-ий. Після 6-ої пісні – кондак і ікос Антипасхи, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний Антипасхи. «Слава, і нині» – інший світильний Антипасхи. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 1-ий – 4 (перша – двічі). «Слава, і нині» – глас 2-ий: «Коли двері були закриті...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 2-ий з приспівами. «Слава, і нині» – Тріоді, глас 6-ий: «Коли двері були закриті...» Після Трисвятого – тропар мучеників, глас 4-ий, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар Антипасхи. «Слава» – тропар мучеників. Кондак тільки Антипасхи."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону Антипасхи, пісня 4-та – 6 (з ірмосом). Після входу тропарі та кондаки: У храмі Господському – тропар Антипасхи, тропар мучеників, «Слава» – кондак мучеників, «І нині» – кондак Антипасхи. У храмі Богородиці – тропар Антипасхи, тропар храму, тропар мучеників, «Слава» – кондак мучеників, «І нині» – кондак Антипасхи (кондак храму не співається). У храмі святого – тропар Антипасхи, тропар храму, тропар мучеників, кондак храму, «Слава» – кондак мучеників, «І нині» – кондак Антипасхи. Прокимен, алилуарій і причасний – Антипасхи. Апостол і Євангеліє – дня. Задостойник Пасхи."}]},
{"date":"04-22","weekday":"середа","title":"Апп. Нафанаїла, Луки та Климента (І). Прп. Федора Сикеота, єп. Анастасіупольського (613). Прп. Віталія (609 – 620).","readings":["Діян., 11 зач., IV, 13 – 22. Ін., 15 зач., V, 17 – 24."],"notes":"Служба прп. Феодора Сикеота повсякденна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири на 6: Антипасхи, глас 1-ий – 3, і преподобного, глас 5-ий, – 3. «Слава, і нині» – Антипасхи, глас 4: «Ти, Господи, осяяний нестерпним Божественним сяйвом»... Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 1-ий з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «Доторкнися, Фомо...». Після Трисвятого – тропар преподобного, глас 2-ий, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар Антипасхи, глас 7-ий (двічі). «Слава» – тропар преподобного, глас 2-ий, «І нині» – тропар Антипасхи. Кафізми 10-та і 11-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: Антипасхи з ірмосом на 8 (ірмоси двічі) – і преподобного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону преподобного. Після 3-ої пісні – кондак і ікос Антипасхи, глас 8-ий, кондак преподобного, глас 3-ий , «Слава», сідальний преподобного, глас 8-ий, «І нині» – іпакої Антипасхи, глас 6-ий. Після 6-ої пісні – кондак і ікос Антипасхи, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний преподобного (двічі). «Слава, і нині» – світильний Антипасхи (за вибором). «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 1-ий – 4 (перша – двічі). «Слава, і нині» – глас 8-ий: «Коли двері були замкнені, ученики зібрані...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 2-ий з приспівами. «Слава, і нині» – Тріоді, глас 2-ий: «Дивися розумом...». Після Трисвятого – тропар преподобного, глас 2-ий, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар Антипасхи. «Слава» – тропар преподобного. Кондак тільки Антипасхи."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону Антипасхи, пісня 5-та – 4 (з ірмосом) та з канону преподобного, пісня 3-тя – 4. Після входу тропарі та кондаки: У храмі Господському – тропар Антипасхи, тропар преподобного, «Слава» – кондак преподобного, «І нині» – кондак Антипасхи. У храмі Богородиці – тропар Антипасхи, тропар храму, тропар преподобного, «Слава» – кондак преподобного, «І нині» – кондак Антипасхи (кондак храму не співається). У храмі святого – тропар Антипасхи, тропар храму, тропар преподобного, кондак храму, «Слава» – кондак преподобного, «І нині» – кондак Антипасхи. Прокимен, алилуарій і причасний – Антипасхи. Апостол і Євангеліє – дня. Задостойник Пасхи."}]},
{"date":"04-23","weekday":"четвер","title":"Вмч. Юрія Переможця (303). Мц. цариці Олександри (303). Мчч. Анатолія і Протолеона (303).","readings":["Ран. – Лк., 63 зач., XII, 2 – 12.","Літ. – Діян., 12 зач., IV, 23 – 31. Ін., 16 зач., V, 24 – 30.","Вмч.: Діян., 29 зач., XII, 1 – 11. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"Служба вмч. Юрію полієлейна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: Антипасхи, глас 1-ий – 3, і святому, глас 4-ий, – 5. «Слава» – святому, глас 6-ий: «Достойно імені твого прожив ти...» «І нині» – Антипасхи, глас 4: «О преславного чуда!...»... Вхід. Прокимен дня. Паремії святого. На стиховні стихири святого, глас 4-ий з приспівами. «Слава» святому глас 4-ий: «Розумного адаманта терпіння...», «І нині» – Тріоді, глас 4-ий: «О преславного чуда!...». Після Трисвятого – тропар святого, глас 4-ий, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар Антипасхи, глас 7-ий (двічі). «Слава» – тропар святого, глас 4-ий, «І нині» – тропар Антипасхи. Кафізми 13-та і 14-та. Малі ектенії. Після 1-ої кафізми сідальний Триоді. Після 2-ої кафізми сідальний святого: «Ось, засяяла весна...», «Слава», інший сідальний : «Ти, мученику, воїнство земне...», і нині», сідальний Триоді. Полієлей. Величання святому і вибраний псалом великомученику. Сідальний святому, глас 3-ий: «Любов’ю Владичною...», «Слава, і нині» Тріоді. Ступенева 1-ий антифон 4-го гласу. Прокимен святому, глас 4-ий: «Праведник, як фінікс...», стих: «Насаджені в домі...». Євангеліе святому – Лк., зач. 63. «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами великомученика Юрія...». Стихира святого, глас 6: «Сьогодні вся вселенна...». Канони: Антипасхи з ірмосом на 6 (ірмоси двічі) – і святого на 8. Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси канону Пасхи «Воскресіння день». Після 3-ої пісні – кондак і ікос Антипасхи, глас 8-ий, сідальний святого, глас 8-ий, «Слава», інший сідальний святого, «І нині» – іпакої Антипасхи, глас 6-ий. Після 6-ої пісні – кондак і ікос святого, глас 4-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний святому (двічі). «Слава» інший святого, «І нині» – світильний Антипасхи (за вибором). «Все що дише...» і хвалітні псалми. На хвалітніх стихири на 6: Тріоді, глас 1-ий – 3, і святому, глас 2-ий – 3. «Слава» святому, глас 2-ий: «Нехай подають праведні...», і нині» – глас 4-ий: «О преславного чуда!...». Велике славослів’є. Після Трисвятого – тропар святому, глас 4-ий, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар Антипасхи. «Слава» – тропар святого. Кондак поперемінно Антипасхи та святого."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону Антипасхи, пісня 5-та – 4 (з ірмосом) та з канону святого, пісня 3-тя – 4. Після входу тропарі та кондаки: У храмі Господському – тропар Антипасхи, тропар святого, «Слава» – кондак святого, «І нині» – кондак Антипасхи. У храмі Богородиці – тропар Антипасхи, тропар храму, тропар святого, «Слава» – кондак святого, «І нині» – кондак Антипасхи (кондак храму не співається). У храмі святого – тропар Антипасхи, тропар храму, тропар святого, кондак храму, «Слава» – кондак святого, «І нині» – кондак Антипасхи. Прокимен, алилуарій і причасний – Антипасхи та святого. Апостол і Євангеліє – дня та святого. Задостойник Пасхи. Причасний – Пасхи, і святого: «В пам’ять вічну...»."}]},
{"date":"04-24","weekday":"п’ятниця","title":"Мчч. Сави Стратилата і з ним 70-х воїнів (272). Прп. Сави Києво-Печерського, в Ближніх печерах (ХІІІ). Прп. Олексія, затворника Києво-Печерського, в Ближніх печерах (ХІІІ). Мчч. Пасикрата і Валентина (228). Мчч. Євсевія, Неона, Леонтія, Лонгина та інших (303). Прп. Фоми, юродивого (546 – 560). Прп. Єлизавети, чудотвориці (VІ – VІІІ). Молченської ікони Божої Матері (1405).","readings":["Діян., 13 зач., V, 1 – 11. Ін., 17 зач., V, 30 – VI, 2."],"notes":"Служба мученика Савви Стратилата не має святкового знаку, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 15-та. На «Господи, взиваю» стихири на 6: Антипасхи, глас 1-ий – 3, і апостолів, глас 4-ий, – 3. «Слава, і нині» – Антипасхи, глас 2-ий: «Коли двері були замкнені...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 1-ий з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «Доторкнися, Фомо, до ребра рукою...». Після Трисвятого – тропар мученика, глас 4-ий, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар Антипасхи, глас 7-ий (двічі). «Слава» – тропар мученика, глас 4-ий, «І нині» – тропар Антипасхи. Кафізми 19-та і 20-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: Антипасхи з ірмосом на 8 (ірмоси двічі) і мученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мученика. Після 3-ої пісні – кондак мученика, глас 4-ий. Сідальний мученика, глас 4-ий, «Слава, і нині» – іпакої Антипасхи, глас 6-ий. Після 6-ої пісні – кондак і ікос Антипасхи, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний Антипасхи. «Слава, і нині» – інший світильний. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 1-ий – 4 (перша – двічі). «Слава, і нині» – глас 8-ий: «Коли двері були замкнені...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 4-ий з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «Доторкнися, Фомо, до ребра рукою...». Після Трисвятого – тропар мученика, глас 4-ій, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар Антипасхи. «Слава» – тропар мученика. Кондак тільки Антипасхи."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону Антипасхи, пісня 8-ма – 6 (з ірмосом). Після входу тропарі та кондаки: У храмі Господському – тропар Антипасхи, тропар мученика, «Слава» – кондак мученика, «І нині» – кондак Антипасхи. У храмі Богородиці – тропар Антипасхи, тропар храму, тропар мученика, «Слава» – кондак мученика, «І нині» – кондак Антипасхи (кондак храму не співається). У храмі святого – тропар Антипасхи, тропар храму, тропар мученика, кондак храму, «Слава» – кондак мученика, «І нині» – кондак Антипасхи. Прокимен, алилуарій і причасний – Антипасхи. Апостол і Євангеліє – дня. Задостойник Пасхи."}]},
{"date":"04-25","weekday":"субота","title":"Апостола і євангеліста Марка (63). Царгородської ікони Божої Матері (1071).","readings":["Ран. – Лк., 50 зач., X, 1 – 15.","Літ. – Діян., 15 зач., V, 21 – 33. Ін., 19 зач., VI, 14 – 27.","Ап.: 1 Пет., 63 зач., V, 6 – 14. Мк., 23 зач., VI, 7 – 13."],"notes":"Служба апостола і євангеліста Марка полієлейна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ «Блажен муж» – 1-ий антіфон. На «Господи, взиваю» стихири на 8: Антипасхи, глас 1-ий – 3, і святому, глас 1-ий, – 5. «Слава» – святому, глас 6-ий: «Вилилася благодать із вуст твоїх...» «І нині» – догматик, глас 1-ий: «Всесвітню славу...»... Вхід. Прокимен дня. Паремії святого. На стиховні стихири святого, глас 1-ий з приспівами. «Слава» святому глас 8-ий: «Прийдіть усі, прославимо псалмами і піснями...», «І нині» – Тріоді, глас 5-ий: «Людинолюбство, велике і безмірне...». Після Трисвятого – тропар святого, глас 3-ій, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар Антипасхи, глас 7-ий (двічі). «Слава» – тропар святого, глас 3-ій, «І нині» – тропар Антипасхи. Кафізми 16-та і 17-та. Малі ектенії. Після 1-ої кафізми сідальний святого: глас 1-ий, «Слава, і нині», сідальний Триоді. Після 2-ої кафізми сідальний святого: глас 4-ий, «Слава, і нині», сідальний Триоді. Полієлей. Величання апостолу і вибраний псалом. Сідальний святому, глас 8-ий: «Ідольську гординю ти знищив...», «Слава, і нині» Тріоді. Ступенева 1-ий антифон 4-го гласу. Прокимен святому, глас 4-ий: «По всій землі розійшлося...», стих: «Небеса повідають славу Божу...». Євангеліе святому – Лк., зач. 50. «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами святого апостола і євангелиста Марка ...». Стихира святого, глас 6: «Вилилася благодать...». (написанп на «господи взиваю...» Канони: Антипасхи з ірмосом на 6 (ірмоси двічі) – і святого на 8. Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси свята Пасхи: «Воскресіння день».. Після 3-ої пісні – кондак і ікос Антипасхи, глас 8-ий, сідальний святого, глас 1-ий, «Слава, і нині» – іпакої Антипасхи, глас 6-ий. Після 6-ої пісні – кондак і ікос святого, глас 2-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний святому (двічі). «Слава, і нині» – світильний Антипасхи (за вибором). «Все що дише...» і хвалітні псалми. На хвалітніх стихири на 6: Тріоді, глас 1-ий – 3, і святому – 3, глас 1-ий. «Слава» святому, глас 6-ий: «Премудрий ловчий, святий ученику...», і нині» – глас 6-ий: «На восьмий день після Твого воскресіння...». Велике славослів’є. Після Трисвятого – тропар святому, глас 3-ий, «Слава, і нині» – тропар Антипасхи, глас 7-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар Антипасхи. «Слава» – тропар святого. Кондак поперемінно Антипасхи та святого."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону Антипасхи, пісня 5-та – 4 (з ірмосом) та з канону святого, пісня 3-тя – 4. Після входу тропарі та кондаки: У храмі Господському – тропар Антипасхи, тропар святого, «Слава» – кондак святого, «І нині» – кондак Антипасхи. У храмі Богородиці – тропар Антипасхи, тропар храму, тропар святого, «Слава» – кондак святого, «І нині» – кондак Антипасхи (кондак храму не співається). У храмі святого – тропар Антипасхи, тропар храму, тропар святого, кондак храму, «Слава» – кондак святого, «І нині» – кондак Антипасхи. Прокимен, алилуарій і причасний – Антипасхи та святого. Апостол і Євангеліє – дня та святого. Задостойник Пасхи. Причасний – Пасхи, і святого: «По всій землі розійшлось...»."}]},
{"date":"04-26","weekday":"неділя","title":"3-тя неділя після Пасхи, святих жінок-мироносиць. Свв. жінок-мироносиць: Марії Магдалини, Марії Клеопової, Соломії, Іоанни, Марфи і Марії, Сусанни та інших; праведних Йосифа Аримафейського і Никодима (перехідне святкування в 3-тю неділю після Пасхи). Сщмч. Василія, єп. Амасійського. Прав. Глафіри, діви (322). Прп. Іоаникія Дівиченського (ХІІІ, Серб.). Блгв. Тамари, цариці Грузинської (перехідне святкування в 3-тю неділю після Пасхи). Львівської ікони Божої Матері (перехідне святкування в неділю після 23 квітня).","readings":["Ран. – Єв. 3-є, Мк., 71 зач., XVI, 9 – 20.","Літ. – Діян., 16 зач., VI, 1 – 7. Мк., 69 зач., XV, 43 – XVI, 8."],"notes":"З цього дня у всі недільні дні до віддання Пасхи канонам на ранній передує спів пасхального (без приспівів на 9-ій пісні) і Богородичного канонів. Служба святих жінок-мироносиць поєднується з воскресною службою Тріоді.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – Кафізма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 2-ий – 7 і свята (Неділі мироносиць), глас той самий – 3. «Слава» – свята, глас 6-ий: «Мироносиці жінки...», «І нині» – догматик, глас 2-ий: «Минула тінь закону...». Вхід. Прокимен дня. На літії стихири свята, глас 1-ий. «Слава» – стихира свята, глас 6-ий, «І нині» – Богородичний воскресний, глас той самий: «Творець і Ізбавитель мій...». На стиховні стихира воскресна, глас 2-ий: «Воскресіння Твоє, Христе Спасе, весь світ просвітило...», і стихири Пасхи, глас 5-ий (з їхніми приспівами). «Слава» – свята, глас той самий: «Тебе, що зодягнувся у світло, як у ризу...», «І нині» – стихира Пасхи, глас той самий: «Воскресіння день...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 2-ий: «Коли зійшов Ти...» (двічі). «Слава» – тропар свята (Неділі мироносиць), глас той самий: «Благообразний Йосиф...». «І нині» – інший тропар свята (Неділі мироносиць), глас той самий: «Мироносицям-жінкам...». Кафізми 2-га і 3-тя. Малі ектенії. Сідальні воскресні (див. в Тріоді). «Непорочні». «Ангельський собор...». Іпакої, глас 2-ий: «Після страждань прийшли жони до гробу...». Степенний – антифони 2-го гласу. Прокимен воскресний, глас 2-ий: «Воскресни, Господи Боже мій...». Євангеліє воскресне 3-тє. «Воскресіння Христове бачивши...» (тричі). Після 50-го псалма: «Слава» – «Молитвами апостолів...», «І нині» – «Молитвами Богородиці...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: Пасхи «Воскресіння день...» з ірмосом і Богородичними тропарями на 6 (ірмоси по двічі), і свята Тріоді (Неділі мироносиць) на 8. Примітка. У каноні мироносиць кількість тропарів по факту перевищує 8; при виборі тропарів для виконання на ранній в жодному разі не треба випускати останні 4 тропарі в кожній пісні канону, в двох з яких оспівуються праведні Йосиф, Никодим та жінки-мироносиці. Цей самий принцип стосується підбору тропарів у канонах Тріоді на ранній в 4-ту, 5-ту та 6-ту Неділі після Пасхи, де в тропарях, що передують Троїчному та Богородичному в кожнії пісні, оспівується подія свята. Біблійні пісні «Співаймо Господеві...». Катавасія Пасхи: «Воскресіння день...». Після 3-ої пісні – кондак і ікос Пасхи, глас 8-ий, сідальний свята, глас 2-ий, «Слава, і нині» – інший сідальний свята, глас той самий. Після 6-ої пісні – кондак і ікос свята (Неділі мироносиць), глас 2-ий. На 9-ій пісні «Чеснішу» не співаємо. (Звершується звичайне кадіння). Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій Пасхи: «Плоттю заснувши...». «Слава» – світильний свята: «Жінки, почуйте...», «І нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні (див. в Тріоді), глас 2-ий – 8. «Слава» – євангельська стихира, глас 2-ий. (див. в Тріоді), «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний «Воскрес із гробу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний: «Коли зійшов Ти...». «Слава» – тропар свята: «Благообразний Йосиф...». Кондак свята: «Радіти мироносицям...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4 (див. в Тріоді), і з канону свята (Неділі мироносиць), пісня 6-та – 4 (бажано останні 4 тропаря пісні). Після входу – тропар воскресний, глас 2-ий: «Коли зійшов Ти...», тропар свята, глас той самий: «Благообразний Йосиф...», «Слава» – кондак свята Тріоді, глас той самий: «Радіти мироносицям...», «І нині» – кондак Пасхи, глас 8-ий. Прокимен – Неділі мироносиць, глас 6-ий: «Спаси, Господи, людей Твоїх...», стих: «До Тебе, Господи, взиваю...». Апостол і Євангеліє – Неділі мироносиць. Алилуарій – Неділі мироносиць, глас 8-ий: «Ти благоволив, Господи, до землі Твоєї, повернув єси з полону Якова». Задостойник Пасхи. Причасний – Пасхи «Тіло Христове...» і дня «Хваліть Господа...»."}]},
{"date":"04-27","weekday":"понеділок","title":"3-й тиждень після Пасхи. Ап. від 70-х і сщмч. Симеона, родича Господнього (107). Прп. Стефана, ігум. Києво-Печерського, єп. Володимирського (1094). Прав. Євлогія, гостинного (ІV).","readings":["Діян., 17 зач., VI, 8 – VII, 5, 47 – 60. Ін., 13 зач., IV, 46 – 54.","Ап.: 1 Кор., 131 зач., IV, 9 – 16. Мф., 56 зач., XIII, 54 – 58."],"notes":"Служба сщмч. Симеона, родича Господнього, шестирична, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізми немає. На «Господи, взиваю» стихири на 6: свята Тріоді, глас 5-ий – 3, і святого, глас 4-ий, – 3. «Слава, і нині» – свята Тріоді, глас 1-ий: «Мироносиці-жони...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 2-ий з приспівами. «Слава, і нині» – Тріоді, глас 1-ий: «Зі страхом прийшли жінки до гробу...». Після Трисвятого – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...», «Слава» – тропар воскресний, глас той самий: «Коли зійшов Ти...», «І нині» – інший тропар свята (Неділі мироносиць), глас той самий: «Мироносицям-жінкам...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...» (двічі), «Слава» – тропар воскресний, глас той самий: «Коли зійшов Ти...», «І нині» – інший тропар свята (Неділі мироносиць), глас той самий: «Мироносицям-жінкам...». Кафізми 4-та і 5-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: свята Тріоді (Мироносиць) з ірмосом на 6 (ірмоси двічі), і святого на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучениці. Після 3-ої пісні – Кондак святого, глас 4-ий. Сідальний святого, глас 4-ий, «Слава, і нині» – сідальний мироносиць, глас 2-ий: «Жони тепло приносять миро до гробу...». Після 6-ої пісні – кондак і ікос Мироносиць, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний Мироносиць. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 2-ий – 4 (перша – двічі). «Слава, і нині» – стихира Тріоді, глас 2-ий. «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 6-ий з приспівами. «Слава, і нині» – Тріоді, глас 2-ий: «Жінки зі сльозами миро на гріб Твій вилили...». Після Трисвятого – тропар свята, глас 2-ий: «Благообразний Йосиф...», «Слава» – тропар воскресний, глас той самий: «Коли зійшов Ти...», «І нині» – інший тропар свята, глас той самий: «Мироносицям-жінкам...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропарі чергуються: На 1-му та 9-му – «Благообразний Йосиф...», на 3-му – «Коли зійшов Ти...», на 6-му – «Мироносицям-жінкам...». На всіх часах кондак Мироносиць: «Радіти мироносицям повелів Ти...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону свята Тріоді, пісня 1-ша – 6 (з ірмосом). Після входу тропарі та кондаки: Тропар свята (Мироносиць), глас 2-ий: «Благообразний Йосиф...», тропар воскресний, глас той самий: «Коли зійшов Ти...», інший тропар свята, глас той самий: «Мироносицям-жінкам...», тропар храму Богородиці або храму святого, кондак храму святого. «Слава» – кондак святого, глас 1-ій, «І нині» – кондак свята (Мироносиць), глас 2-ий: «Радіти мироносицям повелів Ти...». (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен та алилуарій – свята Тріоді (Мироносиць). Апостол і Євангеліє – дня. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...»."}]},
{"date":"04-28","weekday":"вівторок","title":"Апп. від 70-х Ясона і Сосипатра, мц. Керкири, діви, та інших, які з ними постраждали (І). Мчч. Дади, Максима і Квинтиліана (286). Мчч. Саторнія, Якисхола, Фавстіана, Януарія, Марсалія, Єфрасія, Маммія, Мурина, Зинона, Євсевія, Неона і Віталія (бл. 63). Свт. Кирила, єп. Турівського (1183).","readings":["Діян., 18 зач., VIII, 5 – 17. Ін., 20 зач., VI, 27 – 33."],"notes":"Служба Апп. від 70-х Ясона і Сосипатра та інших шестирична, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ 6-та. На «Господи, взиваю» стихири на 6: свята Тріоді, глас 5-ий – 3, і святих, глас 8-ий, – 3. «Слава, і нині» – свята Тріоді, глас 1-ий: «Мироносиці-жони...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 2-ий з приспівами. «Слава, і нині» – Тріоді, глас 1-ий: «Зі страхом прийшли жінки до гробу...». Після Трисвятого – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...», «Слава» – тропар воскресний, глас той самий: «Коли зійшов Ти...», «І нині» – інший тропар свята (Неділі мироносиць), глас той самий: «Мироносицям-жінкам...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...» (двічі), «Слава» – тропар воскресний, глас той самий: «Коли зійшов Ти...», «І нині» – інший тропар свята (Неділі мироносиць), глас той самий: «Мироносицям-жінкам...». Кафізми 7-ма і 8-ма. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: свята Тріоді (Мироносиць) з ірмосом на 6 (ірмоси двічі), і святих на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучениці. Після 3-ої пісні – Кондак апостолів, глас 4-ий. Сідальний апостолів, глас 8-ий, «Слава» інший сідальний, глас 1-ий, «І нині» – сідальний мироносиць, глас 2-ий: «Жони тепло приносять миро до гробу...». Після 6-ої пісні – кондак і ікос Мироносиць, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний Мироносиць. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 2-ий – 4 (перша – двічі). «Слава, і нині» – стихира Тріоді, глас 2-ий. «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 6-ий з приспівами. «Слава, і нині» – Тріоді, глас 2-ий: «Жінки зі сльозами миро на гріб Твій вилили...». Після Трисвятого – тропар свята, глас 2-ий: «Благообразний Йосиф...», «Слава» – тропар воскресний, глас той самий: «Коли зійшов Ти...», «І нині» – інший тропар свята, глас той самий: «Мироносицям-жінкам...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропарі чергуються: На 1-му та 9-му – «Благообразний Йосиф...», на 3-му – «Коли зійшов Ти...», на 6-му – «Мироносицям-жінкам...». На всіх часах кондак Мироносиць: «Радіти мироносицям повелів Ти...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону свята Тріоді, пісня 1-ша – 6 (з ірмосом). Після входу тропарі та кондаки: Тропар свята (Мироносиць), глас 2-ий: «Благообразний Йосиф...», тропар воскресний, глас той самий: «Коли зійшов Ти...», інший тропар свята, глас той самий: «Мироносицям-жінкам...», тропар храму Богородиці або храму святого, кондак храму святого. «Слава» – кондак апостолів, глас 4-ій, «І нині» – кондак свята (Мироносиць), глас 2-ий: «Радіти мироносицям повелів Ти...». (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен та алилуарій – свята Тріоді (Мироносиць). Апостол і Євангеліє – дня. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...»."}]},
{"date":"04-29","weekday":"середа","title":"Дев’ятьох мчч. Кизицьких: Феогнида, Руфа, Антипатра, Феостиха, Артеми, Магна, Феодота, Фавмасія і Филимона (286 – 299). Прп. Мемнона, чудотворця. Мчч. Діодора і Родопіана, диякона (284 – 305). Свт. Василія, єп. Захолмського (ХVІ, Серб.). Мч. Іоана Валаха (Румун.).","readings":["Діян., 19 зач., VIII, 18 – 25. Ін., 21 зач., VI, 35 – 39."],"notes":"Служба дев’ятьох мучеників Кизицьких шестирична, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири на 6: мучеників, глас 8-ий, – 3, преподобного, глас той самий, – 3. «Слава, і нині» – свята Тріоді, глас 6-ий: «Мироносиці-жінки досягли Твого гробу...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 2-ий з приспівами. «Слава, і нині» – Тріоді, глас 6-ий: «Випросив Йосиф тіло Ісусове...». Після Трисвятого – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...», «Слава» – тропар воскресний, глас той самий: «Коли зійшов Ти...», «І нині» – інший тропар свята (Неділі мироносиць), глас той самий: «Мироносицям-жінкам...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...» (двічі), «Слава» – тропар воскресний, глас той самий: «Коли зійшов Ти...», «І нині» – інший тропар свята (Неділі мироносиць), глас той самий: «Мироносицям-жінкам...». Кафізми 10-та і 11-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: свята Тріоді (Мироносиць) з ірмосом на (ірмоси двічі) на 6, мучеників на 4 і преподобному на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону преподобного. Після 3-ої пісні – кондак мучеників, глас 2-ий. Сідальний мучеників, глас 1-ий, «Слава» преподобного, глас 8-ий, «І нині» – сідальний мироносиць, глас 2-ий: «Жони тепло приносять миро до гробу...». Після 6-ої пісні – кондак і ікос Мироносиць, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний Мироносиць. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 2-ий – 4 (перша – двічі). «Слава, і нині» – стихира Тріоді, глас 1-ий: «Зі страхом прийшли жінки до гробу...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 2-ий з приспівами. «Слава, і нині» – Тріоді, глас 5-ий: «Тебе, що зодягнувся у світло, як у ризу...». Після Трисвятого – тропар свята, глас 2-ий: «Благообразний Йосиф...», «Слава» – тропар воскресний, глас той самий: «Коли зійшов Ти...», «І нині» – інший тропар свята, глас той самий: «Мироносицям-жінкам...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропарі чергуються: На 1-му та 9-му – «Благообразний Йосиф...», на 3-му – «Коли зійшов Ти...», на 6-му – «Мироносицям-жінкам...». Кондак Мироносиць: «Радіти мироносицям повелів Ти...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону свята Тріоді, пісня 5-та – 6 (з ірмосом). Після входу тропарі та кондаки: Тропар свята (Мироносиць), глас 2-ий: «Благообразний Йосиф...», тропар воскресний, глас той самий: «Коли зійшов Ти...», інший тропар свята, глас той самий: «Мироносицям-жінкам...», тропар храму Богородиці або храму святого, кондак храму святого, тропар мученикам, глас 8-ий. «Слава» – кондак мученикам, «І нині» – кондак свята (Мироносиць), глас 2-ий: «Радіти мироносицям повелів Ти...». (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен та алилуарій – свята Тріоді (Мироносиць). Апостол і Євангеліє – дня. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...»."}]},
{"date":"04-30","weekday":"четвер","title":"Ап. Якова Зеведеєва (44). Свт. Доната, єп. Єврії (бл. 387). Знайдення мощів сщмч. Василія, єп. Амасійського (ІV). Знайдення мощів свт. Микити Києво-Печерського, єп. Новгородського (1558). Мч. Максима.","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – Діян., 20 зач., VIII, 26 – 39. Ін., 22 зач., VI, 40 – 44.","Ап.: Діян., 29 зач., XII, 1 – 11. Лк., 17 зач., V, 1 – 11."],"notes":"Служба апостола Якова полієлейна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: Триоді, глас 2-ий – 3, і апостола, глас 4-ий, – 5. «Слава» – апостола, глас 8-ий: «Прийдіть усі, прославимо псаломськими піснями Якова...» «І нині» – Мироносиць, глас 4: «Мироносиці, що були рано...». Вхід. Прокимен дня. Паремії апостола. На стиховні стихири апостола, глас 8-ий з приспівами. «Слава» апостолу глас 1-ий: «Христу послідував ти...», «І нині» – свята Тріоді, глас 2-ий: «О учениці! Чому миро розбавляєте сльозами?...» (див. у стихирах на стиховні). Після Трисвятого – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...», «Слава» – тропар апостола, глас 3-ий, «І нині» – інший тропар свята (Неділі мироносиць), глас 2-ий: «Мироносицям-жінкам...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...» (один раз), тропар воскресний, глас той самий: «Коли зійшов Ти...», «Слава» – тропар апостола, глас 3-ий, «І нині» – інший тропар свята (Неділі мироносиць), глас 2-ий: «Мироносицям-жінкам...». Кафізми 14-та і 15-та. Малі ектенії. Після 1-ої кафізми сідальни Тріоді. Після 2-ої кафізми сідальний апостола: «Як сонячний промінь...», «Слава, і нині», сідальний Триоді. Полієлей. Величання апостолу: «Величаємо тебе, / апостоле Христів Якове / і шануємо страждання і труди твої, / що ними потрудився ти // у благовісті Христовім» і вибраний псалом апостолу. Сідальний апостолу, глас 8-ий; «Зорями звище наповнився...», «Слава, і нині» Тріоді. Ступенева 1-ий антифон 4-го гласу. Прокимен апостолу, глас 4-ий: «По всій землі розійшлося віщування їх...», стих: «Небеса повідають славу Божу...». Євангеліе апостолу – Ін., зач. 67. «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами апостола Якова...». Стихира апостола, глас 1: «Христу послідував ти...» (див. на стиховні). Канони: свята Тріоді (Мироносиць) з ірмосом на 6 (ірмоси двічі) і апостола на 8. Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси канону Пасхи «Воскресіння день». кондак і ікос Мироносиць, глас 2-ий. Сідальний апостола, глас 2-ий (двічі), «Слава, і нині» – сідальний мироносиць, глас 2-ий: «Собор учеників Твоїх радується...». Після 6-ої пісні – кондак і ікос апостола, глас 2-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний апостола (двічі). «Слава, і нині» – світильний Мироносиць. «Все що дише...» і хвалітні псалми. На хвалітніх стихири свята Тріоді (Мироносиць), глас 2-ий – 3 (див. їх на стиховні ранньої) та апостола, глас 6-ий – 3 (див. їх на стиховні вечірньої). «Слава» – апостола, глас той самий: «Премудрий ловителю...», «І нині» – стихира Тріоді, глас 1-ий: «Зі страхом прийшли жінки до гробу...» (див. її в Тріоді на стиховні ранньої; замість неї можна заспівати стихиру 2-го гласу «Мироносиці-жінки, рано-вранці, взявши пахощі...» (див. її в Тріоді на хвалітніх)). Велике славослів’є. Після Трисвятого – тропар воскресний, глас 2-ий: «Коли зійшов Ти...», «Слава» – тропар апостола, глас 3-ій, «І нині» – інший тропар свята, глас 2-ий: «Мироносицям-жінкам...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропарі чергуються: На 1-му та 9-му – «Благообразний Йосиф...», на 3-му – «Коли зійшов Ти...», на 6-му – «Мироносицям-жінкам...». На всіх часах на «Слава» – тропар апостола. Кондаки Мироносиць: «Радіти мироносицям повелів Ти...» та рівноапостольних чергуються."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону свята Тріоді (Мироносиць), пісня 4-та – 4 (з ірмосом) та апостола, пісня 3-тя – 4. Після входу тропарі та кондаки: Тропар свята (Мироносиць), глас 2-ий: «Благообразний Йосиф...», тропар воскресний, глас той самий: «Коли зійшов Ти...», інший тропар свята, глас той самий: «Мироносицям-жінкам...», тропар храму Богородиці або храму святого, тропар апостола, глас 3-ій, кондак храму святого. «Слава» – кондак апостола, глас 2-ий, «І нині» – кондак свята (Мироносиць), глас 2-ий: «Радіти мироносицям повелів Ти...». (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен, алилуарій і причасний – Антипасхи та апостола. Апостол і Євангеліє – дня та апостола. Задостойник Пасхи. Причасний – Пасхи, і апостола: «По всій землі...»."}]},
{"date":"05-01","weekday":"п’ятниця","title":"Прор. Єремії (VІ ст. до Р. Х.). Сщмч. Макарія, митр. Київського і всієї Руси (1497). Прмчч. Афонських: Євфимія (1814), Ігнатія (1814) та Акакія (1816). Прмч. Вати Персянина (ІV). Блгв. Тамари, цариці Грузинської (1213). Ікони Божої Матері, званої «Несподівана радість».","readings":["Ран. – Ін., 35 зач. (від половини), X, 1 – 9.","Літ. – Діян., 21 зач., VIII, 40 – IX, 19. Ін., 23 зач., VI, 48 – 54.","Сщмч.: Євр., 334 зач., ХІІІ, 7 – 16. Ін., 36., Х, 9 – 16."],"notes":"Служба священномученика Макарія полієлейна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: свята Тріоді (Мироносиць), глас 2-ий – 3, і святого, глас 5-ий, – 5 (перша та друга стихира – двічі). «Слава» – святого, глас 6-ий: «Преблаженний, премудрий і благий отче...», «І нині» – свята Тріоді, глас 2-ий: «Мироносиці, що були рано...». Вхід. Прокимен дня. Паремії святого. На стиховні стихири святого, глас 2-ий з приспівами. «Слава» святому глас 8-ий: «О воїне Христів безстрашний...», «І нині» – свята Тріоді, глас 2-ий: «О учениці! Чому миро розбавляєте сльозами?...» (див. у стихирах на стиховні). Після Трисвятого – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...», «Слава» – тропар святого, глас 8-ий, «І нині» – інший тропар свята (Неділі мироносиць), глас 2-ий: «Мироносицям-жінкам...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...» (один раз), тропар воскресний, глас той самий: «Коли зійшов Ти...», «Слава» – тропар святого, глас 8-ий, «І нині» – інший тропар свята (Неділі мироносиць), глас 2-ий: «Мироносицям-жінкам...». Кафізми 19-та і 20-та. Малі ектенії. Після 1-ої кафізми сідальний святого: «Настала пам’ять священномученика...», «Слава, і нині», сідальний Триоді. Після 2-ої кафізми сідальний святого: «Живоносному твоєму предстоячи гробу...», «Слава, і нині», сідальний Триоді. Полієлей. Величання святому і вибраний псалом святого. Сідальний святому, глас 1-ий: «Прийдіть, ті, що відкидають молитви...», «Слава, і нині» Тріоді. Ступенева 1-ий антифон 4-го гласу. Прокимен святому, глас 4-ий: «Чесна перед Господом смерть...», стих: «Що воздам Господеві...». Євангеліе святому – Ін., зач. 36. «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами священномученика Макарія...». Стихира святого, глас 4: «Нехай відкриються серця наші...». Канони: Тріоді (Мироносиць) з ірмосом на 6 (ірмоси двічі) – і святого на 8. Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси канону Пасхи «Воскресіння день». Після 3-ої пісні – кондак і ікос Тріоді (Мироносиць), глас 2-ий, сідальний святого, глас 4-ий, «Слава, і нині» – сідальний мироносиць, глас 2-ий: «Собор учеників Твоїх радується...». Після 6-ої пісні – кондак і ікос святого, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний святому (двічі). «Слава, і нині» – світильний Тріоді). «Все що дише...» і хвалітні псалми. На хвалітніх стихири свята Тріоді (Мироносиць), глас 2-ий – 3 (див. їх на стиховні ранньої) та святого, глас 4-ий – 3. «Слава» – святого, глас 2-ий: «Сьогодні прославляється пам’ять...», «І нині» – стихира Тріоді, глас 1-ий: «Зі страхом прийшли жінки до гробу...» (див. її в Тріоді на стиховні ранньої; замість неї можна заспівати стихиру 2-го гласу «Мироносиці-жінки, рано-вранці, взявши пахощі...» (див. її в Тріоді на хвалітніх)). Велике славослів’є. Після Трисвятого – тропар воскресний, глас 2-ий: «Коли зійшов Ти...», «Слава» – тропар святого, глас 8-ий, «І нині» – інший тропар свята, глас 2-ий: «Мироносицям-жінкам...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропарі чергуються: На 1-му та 9-му – «Благообразний Йосиф...», на 3-му – «Коли зійшов Ти...», на 6-му – «Мироносицям-жінкам...». На всіх часах на «Слава» – тропар святого. Кондаки Мироносиць: «Радіти мироносицям повелів Ти...» та святого чергуються."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону свята Тріоді (Мироносиць), пісня 4-та – 4 (з ірмосом) та святого, пісня 3-та – 4. Після входу тропарі та кондаки: Тропар свята (Мироносиць), глас 2-ий: «Благообразний Йосиф...», тропар воскресний, глас той самий: «Коли зійшов Ти...», інший тропар свята, глас той самий: «Мироносицям-жінкам...», тропар храму Богородиці або храму святого, тропар святого, глас 8-ий, кондак храму святого. «Слава» – кондак святого, глас 3-ій, «І нині» – кондак свята (Мироносиць), глас 2-ий: «Радіти мироносицям повелів Ти...». (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен, алилуарій і причасний – Тріоді (Мироносиць) та святого. Апостол і Євангеліє – дня та святого. Задостойник Пасхи. Причасний – Пасхи, і святого: «В пам’ять вічну...»."}]},
{"date":"05-02","weekday":"субота","title":"Свт. Афанасія Великого, архієп. Олександрійського (373). Перенесення мощів блгвв. князів страстотерпців Бориса і Гліба, у св. хрещенні Романа і Давида (1072 і 1115). Свт. Афанасія, патр. Константинопольського, Лубенського чудотворця (1654). Мчч. Еспера і Зої та дітей їх Киріака і Феодула (ІІ). Блгв. і рівноап. царя Бориса, у св. хрещенні Михаїла, просвітителя болгар (907, Болг.).","readings":["Ран. – Лк., 106 зач., XXI, 12 – 19.","Літ. – Діян., 22 зач., IX, 19 – 31. Ін., 52 зач., XV, 17 – XVI, 2.","Блгвв. кнн.: Рим., 99 зач., VIII, 28 – 39. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"На ранній величання: «Величаємо вас, святі страстотерпці Борисе і Глібе, і шануємо чесні страждання ваші, бо ви молите за нас Христа Бога нашого». Служба святих мучеників і страстотерпців Бориса і Гліба полієлейна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: Тріоді (Мироносиць), глас 2-ий – 3, і святим, глас 5-ий, – 5. «Слава» – святим, глас 6-ий: «Прийдіть, складімо хор і прославимо...», «І нині» – догматик, глас 2-ий: «Минула тінь закону...». Вхід. Прокимен дня. Паремії святих. На стиховні стихири святих, глас 2-ий з приспівами. «Слава» святому глас 6-ий: «Прийдіть, прославимо чудотворців і мучеників...», «І нині» – свята Тріоді, глас 5-ий: «Тебе, що зодягнувся у світло, як у ризу...». Після Трисвятого – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...», «Слава» – тропар святим, глас 4-ий, «І нині» – інший тропар свята (Неділі мироносиць), глас 2-ий: «Мироносицям-жінкам...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (Неділі мироносиць), глас 2-ий: «Благообразний Йосиф...» (один раз), тропар воскресний, глас той самий: «Коли зійшов Ти...», «Слава» – тропар святим, глас 4-ий, «І нині» – інший тропар свята (Неділі мироносиць), глас 2-ий: «Мироносицям-жінкам...». Кафізми 16-та і 17-та. Малі ектенії. Примітка. Повне кадіння храму під час читання 17-ої кафізми не звершується, так як переноситься на полієлей. Після 1-ої кафізми сідальний святих: «Зірки незаходимі...», «Слава» інший сідальний: «Сьогодні земля ваша...», «і нині», сідальний Триоді. Після 2-ої кафізми сідальний святих: «Заздрості ради ви погублені вашим братом...», «Слава» інший сідальний: «Зі святими нині оселилися...»,» і нині», сідальний Триоді. Полієлей. Величання святим: «Величаємо вас, святі страстотерпці Борисе і Глібе, і шануємо страждання ваші, ви бо молите за нас Христа Бога нашого» і вибраний псалом. Сідальний святим, глас 8-ий: «Блаженна та земля, яка прийняла кров вашу...», «Слава» інший сідальний: «До божественної краси...», «і нині» Тріоді. Ступенева 1-ий антифон 4-го гласу. Прокимен святим, глас 4-ий: «Чесна перед Господом смерть...», стих: «Що воздам Господеві...». Євангеліе святим – Ін., зач. 36. «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами святих мучеників і страстотерпців Бориса і Гліба...». Стихира святих, глас 6: «Сьогодні зійшовшись...». Канони: Тріоді (Мироносиць) з ірмосом на 6 (ірмоси двічі) – і святих на 8. Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси канону Пасхи «Воскресіння день». Після 3-ої пісні – кондак і ікос Тріоді (Мироносиць), глас 2-ий, кондак святих, глас 3-ій: «Прийдіть, усі собори землі нашої...», та інший кондак святих, глас 4-ий: «Від гробу знамення...», сідальний святих, глас 8-ий, «Слава, і нині» – сідальний мироносиць, глас 2-ий: «Собор учеників Твоїх радується...». Після 6-ої пісні – кондак і ікос святих, глас 4-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний святому (двічі). «Слава, і нині» – світильний Тріоді. «Все що дише...» і хвалітні псалми. На хвалітніх стихири на 6: Тріоді, глас 2-ий – 3, і святим, глас 1-ий – 3. «Слава» святому, глас 6-ий: «Вас, на землі ангелів і на небесах людей Божих...», «І нині» – стихира Тріоді, глас 1-ий: «Прийшли до гробу Магдалина і друга Марія...». Велике славослів’є. Після Трисвятого – тропар воскресний, глас 2-ий: «Коли зійшов Ти...», «Слава» – тропар святих, глас 4-ий, «І нині» – інший тропар свята, глас 2-ий: «Мироносицям-жінкам...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропарі чергуються: На 1-му та 9-му – «Благообразний Йосиф...», на 3-му – «Коли зійшов Ти...», на 6-му – «Мироносицям-жінкам...». На всіх часах «Слава» – тропар святим. Кондаки Мироносиць: «Радіти мироносицям повелів Ти...» та святим чергуються."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону Тріоді (Мироносиць), пісня 9-та – 4 (з ірмосом) та з канону святих, пісня 3-тя – 4. Після входу тропарі та кондаки: Тропар свята (Мироносиць), глас 2-ий: «Благообразний Йосиф...», тропар воскресний, глас той самий: «Коли зійшов Ти...», інший тропар свята, глас той самий: «Мироносицям-жінкам...», тропар храму Богородиці або храму святого, тропар святих, кондак храму святого. «Слава» – кондак святих, «І нині» – кондак свята (Мироносиць), глас 2-ий: «Радіти мироносицям повелів Ти...». (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен, алилуарій і причасний – свята Тріоді (Мироносиць) та святих. Апостол і Євангеліє – дня та святих. Задостойник Пасхи. Причасний – Пасхи, і святих: «Радуйтеся, праведні, в Господі...»."}]},
{"date":"05-03","weekday":"неділя","title":"4-та неділя після Пасхи, про паралізованого. Мчч. Тимофія і Маври (бл. 286). Прп. Феодосія, ігум. Києво-Печерського (1074). Прп. Петра, чудотворця, єп. Аргоського (Х). Перенесення мощів мч. Авраамія Болгарського (1230) (перехідне святкування в 4-ту неділю після Пасхи). Прав. Тавифи (І) (перехідне святкування в 4-ту неділю після Пасхи). Ікон Божої Матері: Успіння Києво-Печерської, принесеної з Константинополя (1073), Києво-Печерської (з Антонієм і Феодосієм) (1085).","readings":["Ран. – Єв. 4-е, Лк., 112 зач., XXIV, 1 – 12.","Літ. – Діян., 23 зач., IX, 32 – 42. Ін., 14 зач., V, 1 – 15.","Прп.: Євр., 334 зач., XIII, 7 – 16. Мф., 43 зач., XI, 27 – 30."],"notes":"Служба звершується за Тріоддю та мінеєю. По 4ій Марковій главі Типікона: «Якщо буде пам’ять вмч. Юрія Переможця в Неділю мироносиць, паралізованого чи самарянки»","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафізма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 3-ій – 3, свята (про паралізованого), глас 1-ий – 3 (перша стихира – двічі), і святого, глас 5-ий – 4. «Слава» – свята (про паралізованого), глас 5-ий: «Прийшов Ісус в Єрусалим до овечої купальні...», «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Вхід. Прокимен дня. Паремії святого – 3. На літії стихира храму. «Слава» – свята (про розслабленого), глас 5-ий: «Біля овечої купальні чоловік лежав немічний...», «І нині» – Богородичний воскресний, глас той самий: «Храм і двері Ти...». На стиховні стихира воскресна, глас 3-ій: «Стражданням Твоїм, Христе...», і стихири Пасхи, глас 5-ий (з їхніми приспівами). «Слава» – святого, глас 8-ий: «Наставника безлічі ченців...», «І нині» – Пасхи, глас 5-ий: «Воскресіння день». Після Трисвятого – «Богородице Діво...» (двічи), тропар преподобного, глас 8 (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 3-ій: «Нехай веселяться небесні...» (двічі). «Слава», тропар преподобного, глас 8-ий, «І нині» – Богородичний воскресний, глас той самий: «Тебе оспівуємо, Богородице Діво...». Кафізми 2-га і 3-тя. Малі ектенії. Сідальні воскресні (див. в Тріоді). Полієлей. Величання преподобного. Непорочні. «Ангельський собор...». Іпакої, глас 3-ій: «Світлий ангел, дивуючи своєю появою...». Сідальний преподобного по 1-ій кафизми: «За покликанням...», сідальний по 2-ій кафизми: «Сліз потоками...», сідальний преподобного після полієлея: «Від утроби матері...», «Слава, і нині», глас 8-ий: «В Соломоновім притворі лежало багато немічнх...» (див. стиховні стихири). Ступеневі – антифони 3-го гласу. Прокимен, глас 3-ій: «Скажіть народам...». Євангеліє воскресне 4-те. «Воскресіння Христове бачивши...» (тричі). Після 50-го псалма: «Слава» – «Молитвами апостолів...», «І нині» – «Молитвами Богородиці». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: Пасхи «Воскресіння день...» з ірмосом і Богородичними тропарями на 6 (ірмоси по двічі), святого на 4 і свята Тріоді (про паралізованого) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія Пасхи: «Воскресіння день...». Після 3-ої пісні – кондак і ікос преподобного, глас 3-ий; сідальний преподобного, глас 4-ий, «Слава, і нині» – Богородичний Тріоді, глас 3-ій: «Одне слово підняло розслабленого...». Після 6-ої пісні – кондак свята (про паралізованого), глас 3-ій: «Душу мою, Господи...», та ікос, глас той самий: «Ти, що долонями рук Твоїх...». На 9-ій пісні «Чеснішу» не співаємо. (Звершується звичайне кадіння). Після 9-ої пісні – «Свят Господь Бог наш». Екзапостіларій Пасхи: «Плоттю заснувши...». «Слава», світильний преподобного, «І нині» – світильний свята (про розслабленого). «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні (див. в Тріоді), глас 3-ій – 4, і святого, глас 2-ий – 4, «Слава» – свята (про паралізованого), глас 8-ий: «Господи, розслабленого не купальня зцілила...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Днесь спасіння...» Перед 1-им часом на «Слава, і нині» – євангельська стихира, глас 3-ій."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар воскресний, «Слава», тропар преподобного. Кондаки свята (про паралізованого): «Душу мою, Господи...» і преподобного – читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4 (див. в Тріоді), і з канону свята (про розслабленого), пісня 6-та – 4, і з канону преподобного, пісня 3-тя – 4. Після входу – тропар воскресний, глас 3-ій. «Слава» – кондак преподобного, «І нині» – кондак свята (про паралізованого), глас 3-ій: «Душу мою, Господи...». Прокимен – Неділі про розслабленого, глас 1-ий: «Нехай буде, Господи, милість Твоя...», стих: «Радуйтеся, праведні...», і преподобного, глас 7: «Чесна перед Господом..» Апостол і Євангеліє – Неділі про паралізованого і святого. Алилуарій – Неділі про паралізованого, глас 5-ий: «Милість Твоя, Господи...», і святого, глас 2-ий: «Священники Твої зодягнуться...» Задостойник Пасхи. Причасний воскресний «Хваліте Господа з Небес...» і святого: «В пам’ять вічну...»."}]},
{"date":"05-04","weekday":"понеділок","title":"4-й тиждень після Пасхи. Мц. Пелагії, діви Тарсійської (бл. 290). Сщмч. Еразма, єп. Формійського (303). Сщмч. Альвіана, єп. Анейського, та учнів його (304). Сщмч. Сильвана, єп. Газького, і з ним 40 мучеників (311).","readings":["Діян., 24 зач., X, 1 – 16. Ін., 24 зач., VI, 56 – 69."],"notes":"Служба мц. Пелагії не має святкового знаку, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізми немає. На «Господи, взиваю» стихири на 6: свята Тріоді, глас 8-ий – 3, і мучениці, глас 2-ий, – 3. «Слава, і нині» – свята Тріоді, глас 5-ий: «Біля овечої купальні чоловік лежав немічний...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 3-ій з приспівами. «Слава, і нині» – Тріоді, глас 1-ий: «Рукою пречистою Ти створив людину...». Після Трисвятого – тропар воскресний, глас 3-ій: «Нехай веселяться небесні...». «Слава, і нині» – Богородичний воскресний, глас той самий: «Тебе оспівуємо, Богородице Діво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 3-ій: «Нехай веселяться небесні...» (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Тебе оспівуємо, Богородице Діво...». Кафізми 4-та і 5-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: свята Тріоді (про паралізованого) з ірмосом на 8 (ірмоси двічі) і мучениці на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучениці. Після 3-ої пісні – кондак мучениці, глас 3-ій, «Слава», сідальний мучениці, глас 1-ий, «І нині» – сідальний свята (паралізованого), глас 3-ій: «Одне слово підняло розслабленого...». Після 6-ої пісні – кондак і ікос свята (паралізованого), глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 3-ій – 4 (перша – двічі). «Слава, і нині» – стихира Тріоді, глас 1-ий: «Як не похований померлий, розслаблений...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 3-ій з приспівами. «Слава, і нині» – Тріоді, глас 5-ий: «Прийшов Ісус в Єрусалим до овечої купальні...». Після Трисвятого – тропар воскресний, глас 3-ій: «Нехай веселяться небесні...». «Слава, і нині» – Богородичний воскресний, глас той самий: «Тебе оспівуємо, Богородице Діво...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар воскресний. Кондак свята Тріоді (про паралізованого)."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону свята Тріоді, пісня 1-ша – 6 (з ірмосом). Після входу тропарі та кондаки: Тропар воскресний, тропар храму Богородиці або храму святого, кондак храму святого. «Слава, і нині» – кондак свята (паралізованого). (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен та алилуарій – свята Тріоді (паралізованого) Апостол і Євангеліє – дня. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...»."}]},
{"date":"05-05","weekday":"вівторок","title":"Вмц. Ірини (І – ІІ). Ікони Божої Матері «Невипивана чаша» (1878).","readings":["Діян., 25 зач., X, 21 – 33. Ін., 25 зач., VII, 1 – 13."],"notes":"Служба вмц. Ірини не має святкового знаку, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 6-та. На «Господи, взиваю» стихири на 6: свята Тріоді, глас 1-ий – 3 (перша стихира двічі), і мучениці, глас 1-ий, – 3. «Слава, і нині» – свята Тріоді, глас 5-ий: «Прийшов Ісус в Єрусалим...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 3-ій з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «В Соломоновім притворі...». Після Трисвятого – тропар воскресний, глас 3-ій: «Нехай веселяться небесні...». «Слава» – тропар мучениці, глас 4-ий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 3-ій: «Нехай веселяться небесні...» (двічі). «Слава» – тропар мучениці, глас 4-ий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...». Кафізми 7-ма і 8-ма. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: свята Тріоді (про паралізованого) з ірмосом на 8 (ірмоси двічі) і мучениці на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучениці. Після 3-ої пісні – кондак мучениці, глас 4-ий, сідальний мучениці, глас 8-ий, «Слава, і нині» – сідальний свята (паралізованого), глас 3-ій. Після 6-ої пісні – кондак і ікос свята (паралізованого), глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 3-ій – 4 (перша стихира двічі). «Слава, і нині» – Тріоді, глас 8-ий: «Господи, розслабленого не купальня зцілила...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 3-ій з приспівами. «Слава, і нині» – Тріоді, глас 5-ий: «Біля овечої купальні чоловік лежав немічний...». Після Трисвятого – тропар воскресний, глас 3-ій: «Нехай веселяться небесні...». «Слава» – тропар мучениці, глас 4-ий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар воскресний. «Слава» – тропар мучениці. Кондак тільки свята Тріоді (про розслабленого)."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону свята Тріоді, пісня 9-та – 6 (з ірмосом). Після входу тропарі та кондаки: Тропар воскресний, глас 3-ій, тропар храму Богородиці або храму святого, тропар мучениці, кондак храму святого. «Слава» – кондак мучениці, «І нині» – кондак свята (паралізованого). (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен та алилуарій – свята Тріоді (паралізованого) Апостол і Євангеліє – дня. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...»."}]},
{"date":"05-06","weekday":"середа","title":"Переполовення П’ятдесятниці. Прав. Іова Багатостраждального (бл. 2000 – 1500 до Р. Х.). Прп. Іова Почаївського (1651). Мчч. Варвара, воїна, Вакха, Калимаха та Діонісія (бл. 362). Мч. Парфенія. Мч. Варвара, колишнього розбійника.","readings":["Ран. – Лк., 24 зач., VI, 17 – 23.","Літ. – Діян., 34 зач., XIV, 6 – 18. Ін., 26 зач., VII, 14 – 30.","Прав.: Як., 54 зач., III, 1 – 10. Мф., 10 зач., ІV, 25 – V, 12.","Прп.: Євр., 334 зач., XIII, 7 – 16. Мф., 43 зач., XI, 27 – 30."],"notes":"Цього дня, традиційно, звершується мале освячення води. Служба свята Переполовення П’ятдесятниці звершується за Тріоддю в поєднання з полієлейною службою прп. Іова Почаївського. (згідно з Марковою главою під 23 квітня: «Якщо припаде пам’ять великомученика Георгія у середу Переполовення П’ятидесятниці).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири свята Переполовення (з Тріоді), глас 4-ий – 3, святому, глас 8-ий – 3). «Слава» – преподобного, глас 3-ій: «Твоїх слів, Господи дотримувався...», «І нині» – свята, глас 6-ий: «Свято переполовинилося Твого, Христе, воскресіння...». Вхід. Прокимен дня. Паремії Переполовення – 3, та преподобному – 3. Ектенія потрійна: «Промовимо всі...». «Сподоби, Господи». Ектенія прохальна: «Доповнимо вечірню...» і голововклонна молитва. На стиховні стихири свята, глас 1-ий і глас 2-ий (зі своїми приспівами). «Слава» – преподобного, глас 8-ий: «Тебе, як численних ченців наставника...», «І нині» – свята, глас 8-ий: «Коли переполовинилося свято...». Після Трисвятого – тропар преподобному, глас – 4-ий, «Слава, і нині», тропар Переполовення, глас 8-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар Переполовення (двічі). «Слава», тропар преподобного, глас – 4-ий, «І нині» – тропар Переполовення. Кафізми 10-та і 11-та. Малі ектенії. Після першої кафізми сідальний преподобного, глас 4-ій: «За покликанням Господнім пішовши...» (двічі), «Слава, і нині» – сідальний Тріоді. Після другої кафізми сідальний преподобного, глас 5-ий: «Печерного затворника...», «Слава, і нині» – сідальний Тріоді. Полієлей. Величання преподобного: «Ублажаємо тебе, преподобний отче наш Іове, і шануємо святу пам’ять твою, наставнику ченців і співрозмовнику ангелів.» та вибранний псалом. Після полієлея сідальний преподобного, глас 8-ий: «Пастирську мудрість...» (двічі), «Слава, і нині» – сідальний Тріоді: «Владика всіх у храмі стояв...» (див. у сідальних після другої кафізми в Тріоді). Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Чесна перед Господом...». Стих: «Що віддам Господу за все...». Євангеліє преподобного. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Псалом 50-ий. «Слава» – «Молитвами преподобного отця нашого Іова...», «І нині» – «Молитвами Богородиці...», Стихира преподобного, глас 6-ий: «Преподобний отче...». Канони свята Переполовення: 1-ий канон, глас 4-ий, з ірмосом на 6 (ірмоси по двічі), і канон преподобному, на 4, 2-ий канон святу, на глас 8-ий, на 4. Біблійні пісні «Співаймо Господеві...». Катавасія Переполовення: «Море висушив Ти...». Після 3-ої пісні – кондак і ікос преподобного, глас 4-ій, сідальний свята, глас 8-ий: «Стоячи посеред святилища...», «Слава, і нині» – інший сідальний свята, глас той самий: «Премудрости воду...». Після 6-ої пісні – кондак свята Переполовення, глас 4-ий: «У переполовення свята законного...» та ікос, глас той самий: «Зледенілу через гріхи і беззаконня...». На 9-ій пісні – звичайне кадіння. «Чеснішу» не співаємо. Після 9-ої пісні «Достойно є» не співається. Світильний свята Тріоді: «Маючи чашу невичерпних дарів...», «Слава», преподобному, «І нині», свята Тріоді. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята Тріоді, глас 4-ий – 4 (перша стихира – двічі). «Слава» – преподобного, глас 8-ий: «Не можуть слова наші прославити...», «І нині» – свята, глас той самий: «Просвітившись, браття...». Велике славослів’я. Після Трисвятого – тропар преподобному, глас 4-ий, «Слава, і нині», тропар свята."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята, «Слава», тропа преподобному. Кондак свята Переполовення та преподобного читаютьсяпоперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні на 8: свята Переполовення пісня 3-тя – 4 (з ірмосом), та преподобному пісня 6-та – 4. На вході: «...що воскрес із мертвих...» Після входу – тропар свята, тропа преподобного «Слава», кондак преподобного, «І нині» – кондак свята. Співається Трисвяте. Прокимен та алилуарій Переполовення та преподобному. Апостол і Євангеліє – дня і преподобного. Задостойник – ірмос 9-ої пісні 2-го канону Переполовення: «Невластиве матерям дівство...». Примітка. Цей же задостойник співається і в віддання свята Переполовення, в інші ж дні післясвята Переполовення – задостойник Пасхи. Причасний Переполовення: «Хто споживає Тіло Моє...». Примітка. Після Літургії (або перед нею), за традицією, звершується чин малого освячення води. На трапезі утіха братії. Свято Переполовення святкується 8 днів."}]},
{"date":"05-07","weekday":"четвер","title":"Згадування появи на небі Хреста Господнього в Єрусалимі (351). Мч. Акакія, сотника (303). Прпп. Іоана Зедазнійського та учнів його: Авіва, єп. Некреського, Антонія Марткобського, Давида Гареджийського, Зинона Ілкатського, Фадея Степанцмидського, Ісе (Ієсея), єп. Цилканського, Йосифа, єп. Алавердського, Ісидора Самтавійського, Михаїла Улумбійського, Пірра Бретського, Стефана Хирського та Шіо Мгвимського (VІ, Груз.). Любецької (ХІ) та Жировицької (1470) ікон Божої Матері.","readings":["Діян., 26 зач., X, 34 – 43. Ін., 29 зач., VIII, 12 – 20."],"notes":"Служба Хрестане має святкового знаку, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 12-та. На «Господи, взиваю» стихири на 6: свята Тріоді (Переполовення), глас 4-ий – 3, і Хресту, глас 4-ий, – 3. «Слава» мінеї, глас 8-ий: «Сповістили небеса славу Твою...», «І нині» – свята, глас 2-ий: «Коли Ти, Христе Боже...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 3-ій з приспівами. «Слава, і нині» – Тріоді, глас той самий: «В переполовення свята...». Після Трисвятого – тропар Хресту, глас 8-ий, «Слава, і нині», тропар свята Переполовення, глас 8-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята Переполовення (двічі). «Слава», тропар Хресту, «І нині» – тропар свята Переполовення. Кафізми 13-та і 14-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: свята Переполовення 1-ий з ірмосом на 6 (ірмоси двічі) і Хреста на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Хреста. Після 3-ої пісні – кондак і ікос Хреста, глас 4-ий, сідальний Хреста, глас 4-ий, «Слава, і нині» – сідальний Переполовення, глас 8-ий: «Стоячи посеред святилища...». Після 6-ої пісні – кондак і ікос Переполовення, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний Хреста. «Слава, і нині» – світильний свята Переполовення. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 3-ій – 4 (перша стихира двічі). «Слава, і нині» – Тріоді, глас той самий: «Господи, раніше Чесного Твого Хреста...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 2-ий з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «В переполовення свята...». Після Трисвятого – тропар Хресту, глас 8-ий, «Слава, і нині», тропар свята Переполовення, глас 8-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар святу Переполовення, «Слава», тропар Хресту. Кондак Переполовення і Хресту читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з 1-го канону Переполовення, пісня 1-ша – 6 (з ірмосом). Після входу тропарі та кондаки: Тропар Переполовення, тропар Хресту, тропар храму Богородиці або храму святого, кондак храму святого. «Слава» – кондак Хресту, «І нині» – кондак Переполовення. (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен, алилуарій та причасний – Переполовення. Апостол і Євангеліє – дня. Задостойник Пасхи."}]},
{"date":"05-08","weekday":"п’ятниця","title":"Апостола і євангеліста Іоана Богослова (98 – 117). Прп. Арсенія Великого (449 – 450). Прпп. Арсенія Працелюбного (ХІV) та Пимена, посника, (ХІІ) Києво-Печерських, в Дальніх печерах. Поминання загиблих у ІІ Світовій війні.","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – Діян., 27 зач., X, 44 – XI, 10. Ін., 30 зач., VIII, 21 – 30.","Ап.: 1 Ін., 68 зач., I, 1 – 7. Ін., 61 зач., XIX, 25 – 27; XXI, 24 – 25."],"notes":"Служба апостола і євангеліста Іоана Богослова бдінна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: свята Тріоді (Переполовення), глас 5-ий – 4 , і апостола, глас 1-ий, – 4. «Слава» – апостолу, глас 2-ий: «Сина громового...», «І нині» – свята, глас 6-ий: «Свято переполовинилося...». Вхід. Прокимен дня. Паремії апостола – 3. На стиховні стихири свята з Тріоді, глас 3-ій (з приспівами своїми) – 4. «Слава» – апостола, глас 6-ий: «Апостоле Христів, Євангелисте і Богослове...», «І нині» – Тріоді, глас 8-ий: «Коли переполовинилось свято...». На літії стихира апостолу. «Слава» апостолу, «І нині» святу Переполовення. Після Трисвятого – тропар свята (Переполовення (двічі) та апостолу."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята Переоловення (двічі), «Слава», тропар апостолу, «І нині», святу Переполовення. Кафізми 19-та і 20-та. Малі ектенії. Після 1-ої кафізми: Сідальний апостолу, глас 8-ий: «Ти сином назвався...» (двічі), «Слава, і нині», сідальні свята Тріоді. Після 2-ої кафізми: Сідальні апостолу, глас 8-ий: «Море риболовлі залишивши...», «Слава, і нині», сідальні свята Тріоді. Полієлей. Величання апостолу: «Величаємо тебе, / апостоле Христів і Євангелісте Іоане Богослове, / і шануємо болісті й труди твої, / коли ти трудився у благовісті Христовому.» і вибраний псалом: «Небеса повідають славу Божу...». Після полієлея сідальний апостолу, глас 8-ий: «Возліг ти на груди Ісусові...», «Слава, і нині» – сідальний свята Переполовення, глас 4-ий: «Ти, що знаєш помисли сердець...» (див. сідальний після 1-ої кафизми в середу Переполовення). Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «По всій землі розійшлося...». Стих: «Небеса повідають славу Божу...». Євангеліє апостолу. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. «Слава» – «Молитвами апостола і євангелиста Іоана Богослова...». Стихира апостола, глас 5-ий: «Богослове дівственику...». Канони: свята Переполовення 1-ий з ірмосом на 4 (ірмоси двічі), апостолу на 6, 2-ий канон святу Переполовення на 4.. Біблійні пісні «Співаймо Господеві...». Катавасія Пасхи «Воскресіння день...» Після 3-ої пісні – кондак і ікос Переполовення, глас 4-ий. Сідальний апостолу, глас 8-ий, «Слава, і нині» – сідальний Переполовення, глас 8-ий: «Стоячи посеред святилища...». Після 6-ої пісні – кондак і ікос апостола. На 9-ій пісні співаємо «Чеснішу». Світильний апостолу. «Слава» – інший світильний апостолу, «І нині» – світильний Переполовенню. «Все, що дишить...» і хвалітні псалми. На хвалітніх воскресні стихири Тріоді, глас 4-ий – 3 та апостолу, глас 8-ий – 3. «Слава» – апостолу, глас 8-ий: «Благовіснику Іоане...», «І нині» – стихира Тріоді, глас 4-ий: «Просвітившись, браття, Воскресінням Спаса Христа...». Велике славослів’я. Після Трисвятого – тропар апостолу, «Слава, і нині», святу Переполовення."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар Переполовенню, «Слава» – тропар апостолу. Кондаки Переполовенню та апостолу чергуються."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону свята Тріоді,пісня 3-тя – 4 (з ірмосом) та апостолу, пісня 6-та – 4. Після входу тропарі та кондаки: Тропар свята Переполовення, тропар апостолу,, «Слава», кондак апостола, «І нині», кондак свята Переполовення. Прокимен та алилуарій – свята Тріоді та апостолу. Апостол і Євангеліє – дня та апостолу. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...» та апостолу: «По всій землі розійшлося...»."}]},
{"date":"05-09","weekday":"субота","title":"Перенесення мощів святителя і чудотворця Миколая з Мир Лікійських у м. Бар (1087). Прор. Ісаї (VІІІ ст. до Р. Х.). Мч. Христофора (бл. 250). Прп. Шіо Мгвимського (VІ, Груз.). Прп. Йосифа Оптинського (1911).","readings":["Ран. – Ін., 35 зач. (від половини), X, 1 – 9.","Літ. – Діян., 29 зач., XII, 1 – 11. Ін., 31 зач., VIII, 31 – 42.","Свт.: Євр., 335 зач., XIII, 17 – 21. Мф., 11 зач., V, 14 – 19."],"notes":"Служба святителя Миколая бдінна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: свята Тріоді Переполовення, глас 4-ий – 4 (перша – двічі), і святителя, глас 8-ий, – 4. «Слава» – святителя, глас 6-ий: «Святителів красу і отців славу...», «І нині» – тріоді, глас 6-ий: «Свято переполовинилось...». Вхід. Прокимен дня. Паремії святителя – 3. Стихири на літії святителя, глас 2-ий: «Отче Миколаю...», «Слава», святиеля, глас 6-ий: «Благий і вірний рабе...», «і нині», Тріоді. На стиховні стихири з Тріоді, глас 1-ий (з приспівами своїми) – 4. «Слава» – святителя, глас 6-ий: «Чоловіче Божий і вірний рабе...», «І нині» – свята Тріоді, глас 8-ий: «Коли переполовинилось свято...». Після Трисвятого – тропар святителя (двічі), тропар Переполовення."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята Переполовення, глас 8-ий, «Слава» – тропар святителя, глас 4-ий, «І нині» – тропар свята Переполовення. Кафізми 16-та і 17-та. (Кадіння на 17-ій кафізмі не звершується, воно переноситься на полієлей). Малі ектенії. Після 1ої кафізми сідальні Тріоді. Після 2-ої кафізми сідальний святителя, глас 4-ий: «Дивним показав Ти, Владико...», «Слава, і нині», сідальний тріоді. Полієлей. Величання Предтечі: «Величаємо тебе, / святителю отче Миколаю, і шануємо святу пам’ять твою, / ти бо молиш за нас Христа Бога нашого», і вибраний псалом. Після полієлея сідальний святителя, глас 1-ий: «Освятивши себе життям довершеним...», «Слава, і нині» – сідальний Тріоді. Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Чесна перед Господом смерть...». Стих: «Що воздам Господеві за все...». Євангеліє святителя. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. «Слава» – «Молитвами святителя Миколая...». Стихира святителя, глас 6-ий: «Насліднику Божий...». Канони: свята Переполовення 1-ий з ірмосом на 4 (ірмоси двічі), святителю на 6, 2-ий канон святу Переполовення на 4.. Біблійні пісні «Співаймо Господеві...». Катавасія Пасхи «Воскресіння день...» Після 3-ої пісні – кондак і ікос Переполовенню, глас 4-ий. Сідальний святителя, глас 1-ий: «Перенесення чесних твоїх мощей...», «Слава, і нині» – сідальний Переполовення, глас 5-ий: «Владика всіх у храмі...» (див. сідальний після 2-ої кафизми). Після 6-ої пісні – кондак і ікос святителя, глас 3-ий. На 9-ій пісні співаємо «Чеснішу». Світильний святителя. «Слава, і нині» – світильний Переполовення. «Все, що дишить...» і хвалітні псалми. На хвалітніх воскресні стихири Переполовення, глас 4-ий – 3 та святителя, глас 1-ий – 3. «Слава» – святителя, глас 5-ий: «Засурмімо сурмою пісні...», «І нині» – стихира Тріоді, глас 4-ий: «Просвітившись, браття...». Велике славослів’я. Після Трисвятого – тропар святителя, глас 4-ий, «Слава, і нині» – тропар свята, глас 8-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар Переполовенню, «Слава» – тропар святителю. Кондаки Переполовенню та святителю чергуються."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону свята Тріоді Переполовення, пісня 3-тя – 4 (з ірмосом) та святителя, пісня 3-я – 4. Після входу тропарі та кондаки: Тропар свята Переполовення, тропар святителя, «Слава», кондак святителя, «І нині», кондак свята Переполовення. Прокимен та алилуарій – свята Тріоді та святителя. Апостол і Євангеліє – дня та святителя. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...» та святителя: «В пам’ять вічну...»."}]},
{"date":"05-10","weekday":"неділя","title":"5-та неділя після Пасхи, про самарянку. Апостола Симона Зилота (І). Свт. Симона Києво-Печерського, єп. Володимирського і Суздальського, у Ближніх печерах (1226). Мчч. Алфія, Філадельфа, Кипріана, Онисима, Еразма та інших (251). Мч. Ісихія Антіохійського (ІV). Прп. Ісидори, юродивої (ІV). Блж. Таїсії Єгипетської (V). Києво-Братської ікони Божої Матері (1654).","readings":["Ран. – Єв. 7-е, Ін., 63 зач., XX, 1 – 10.","Літ. – Діян., 28 зач., XI, 19 – 26, 29 – 30. Ін., 12 зач., IV, 5 – 42.","Ап.: 1 Кор., 131 зач., IV, 9 – 16. Мф., 56 зач., XIII, 54 – 58."],"notes":"Служба воскресна та самарянки звершується за Тріоддю, також додається полієлейна служба святого апостола Симона Зилота. (за Марковою главою під 23 квітня: «Якщо припаде пам’ять великомученика Юрія у Неділю про самаряну»). Служба післясвята Переполовенню опускається. Примітка. Піснеспіви Неділі про самарянку співаються у неділю, четвер, п’ятницю та суботу 5-ої седмиці після Пасхи, оскілки у понеділок та вівторок звершується служба Переполовення, а у середу – віддання Переполовення","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафізма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 4-ий – 3, самарянки, глас 1-ий та глас 2-ий – 3 та апостолу, глас 4-ий – 4.. «Слава» – самарянки, глас 6-ий: «Біля колодязя Якова...», «І нині» – догматик, глас 4-ий: «Пророк Давид, що через Тебе, Богородице, богоотцем став...». Вхід. Прокимен дня. Паремії апостолу. На літії стихира храму. «Слава, і нині» – самарянки, глас 3-ій: «Нехай нині радіють світло небо і земля...». На стиховні стихира воскресна, глас 4-ий: «Господи, зійшовши на хрест...», і стихири Пасхи, глас 5-ий (з їхніми приспівами).«Слава»–апостолу,глас6-ий:«Творіння,якорелвисокопарнй...», «І нині» – Пасхи, глас 5-ий: «Воскресіння день». Після Трисвятого – «Богородице Діво...» (тричі). Примітка. Можливий варіант виконання тропарів після Трисвятого: «Богородице Діво...» (двічі) та тропар апостола, глас 3-ій (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 4-ий: «Світлу воскресіння проповідь...» (двічі). «Слава», тропар апостолу, глас 3-ій, «І нині» – Богородичний недільний глас 3-ій; «Тебе оспівуємо, Богородице Діво...»; Кафізми 2-га і 3-тя. Малі ектенії. Сідальні воскресні (див. в Тріоді). Полієлей. Величання апостолу. «Ангельський собор...». Сідальни апостолу після 1-ої, 2-ої кафизми, «Слава», сідальний апостола після полієлею, «І нині», Іпакої, глас 4-ий: «Мироносиці, що раніше прийшли...». Степенний – антифони 4-го гласу. Прокимен, глас 4-ий: «Воскресни, Господи, поможи нам...». Євангеліє воскресне 7-ме. «Воскресіння Христове бачивши...» (тричі). Після 50-го псалма: «Слава» – «Молитвами апостолів...», «І нині» – «Молитвами Богородиці». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: Пасхи «Воскресіння день...» з ірмосом і Богородичними тропарями на 6 (ірмоси по двічі), 2-ий канон апостолу на 4 і самарянки на 4. Біблійні пісні «Співаймо Господеві...». Катавасія Пасхи: «Воскресіння день...». Після 3-ої пісні – кондак і ікос апостолу, глас 2-ий; «Слава», сідальний апостолу, глас 3-ій: «Світлосяйністю Божественного Духа», «І нині», сідальний самарянки, глас 4-ий: «Нехай радіє небо...», Після 6-ої пісні – кондак і ікос самарянки, глас 8-ий. На 9-ій пісні «Чеснішу» не співаємо. (Звершується звичайне кадіння). Після 9-ої пісні – «Свят Господь Бог наш». Екзапостіларій Пасхи: «Плоттю заснувши...». «Слава» – світильний апостола: «Течію твоїх прекрасних ніг...», «І нині», сідальний самарянки: «Ти, що євреям виточив воду із каменя...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Тріоді на 8: воскресні, глас 4-ий – 4, і апостолу, глас 8-ий – 4 (разом з стихирою апостолу на «Славу»), «Слава» – самарянки, глас 6-ий: «Ісус, Спас наш, Джерело життєначала...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...» Перед 1-им часом на «Слава, і нині» – євангельська стихира, глас 7-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар апостола. Кондаки апостола та самарянки чергуються."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4 (див. в Тріоді), з канону самарянки, пісня 3-тя – 4 та апостолу, пісня 6-та – 4. Після входу – тропар воскресний, тропар апостолу, «Слава», кондак апостолу, «І нині» – кондак самарянки. Прокимен – Неділі про самарянку, глас 3-ій: «Співайте Богу нашому, співайте...». Стих: «Всі народи, заплещіть руками...» та апостолу, глас – 8-ий: «По всій землі...» Апостол і Євангеліє – Неділі про самарянку та апостолу. Алилуарій – Неділі про самарянку, глас 4-ий: «Натягни лук і встигай, і царюй...». Стих: «Ти полюбив правду...» та апостолу: «Сповідують Небеса чудеса Твої...» Задостойник Пасхи. Причасний Пасхи «Тіло Христове...» і апостолу: «По всій землі розійшлося...»."}]},
{"date":"05-11","weekday":"понеділок","title":"5-й тиждень після Пасхи. Сщмч. Мокія (бл. 295). Рівноапп. Кирила (869) та Мефодія (885), вчителів слов’янських. Прп. Софронія, затворника Києво-Печерського, в Дальніх печерах (ХІІІ). Свт. Никодима, архієп. Сербського (1325).","readings":["Ран. – Ін., 35 зач. (від половини), X, 1 – 9.","Літ. – Діян., 30 зач., XII, 12 – 17. Ін., 32 зач., VIII, 42 – 51.","Рівноапп.: Євр., 318 зач., VII, 26 – VIII, 2. Мф., 11 зач., V, 14 – 19."],"notes":"Служба рівноапп. Кирила та Мефодія полієлейна, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: Тріоді (Переполовення), глас 1-ий – 4 (перша – двічі), і святих, глас 2-ий, – 4. «Слава» – святих, глас 6-ий, «І нині» – свята, глас 8-ий: «В переполовення свята...». Вхід. Прокимен дня. Паремії святих – 3. На стиховні стихири воскресні з Тріоді, глас 3-ий – 4. «Слава» – святих, глас 8-ий: «Радуйся, двойце священна...», «І нині» – Тріоді, глас 1-ий: «До храму прийшов Ти, Премудрість Божа...». Після Трисвятого – тропар святих, глас 4-ий. «Слава, і нині» – тропар Переполовення, глас 8-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар Переполовення (двічі). «Слава» – тропар святих, «І нині» – тропар Переполовення. Кафізми 4-та і 5-та. Малі ектенії. Сідальні Тріоді. Полієлей. Величання рівноапостольних: «Величаємо вас, святі рівноапостольні Мефодію і Кириле, що всі слов’янські країни ученням вашим просвітили і до Христа привели» і вибраний псалом. Після полієлея сідальні святих, глас 4-ий: «Прийдіть, похвалами побожно вшануймо...», сідальний святих, глас 3-ій: «Тройці Живоначальній...» (див. після 1-ої кафізми), «Слава» – сідальний святих, глас 5-ий: «Нехай радуютьсяґ...» (див. після 2-ої кафізми), «І нині» – сідальний Переполовення, глас 8-ий: «Переполовинилося свято законне...» (див. у сідальних після другої кафізми в Тріоді). Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Священники твої зодягнуться...». Стих: «Слухайте це, всі народи...». Євангеліє святих (Ін., зач. 35, від половини). «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. «Слава» – «Молитвами святих рівноапостольних Мефодія і Кирила...». Стихира святих, глас 6-ий: «Апостолам єдинодушних...». Канони: свята Переполовення 1-ий з ірмосом на 6 (ірмоси двічі) і святих на 8. Біблійні пісні «Співаймо Господеві...». Катавасія Пасхи «Воскресіння день...» Після 3-ої пісні – кондак і ікос Переполовення, глас 4-ий. Сідальний святих, глас той самий (двічі), «Слава, і нині» – сідальний Переполовення, глас 8-ий: «Стоячи посеред святилища...». Після 6-ої пісні – кондак та ікос святих, глас 3-ій. Світильний святих (двічі). «Слава, і нині» – світильний Переполовення. «Все, що дишить...» і хвалітні псалми. На хвалітніх воскресні стихири Тріоді, глас 3-ій – 3 святих, глас 4-ий – 3. «Слава» – святих, глас 6-ий, «І нині» – стихира Тріоді, глас 4-ий: «Просвітившись, браття, Воскресінням Спаса Христа...». Велике славослів’я. Після Трисвятого – тропар святих, «Слава, і нині» – тропар Переполовення."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар Переполовення. «Слава» – тропар святих. Кондаки Переполовення та святих чергуються."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з 1-го канону Переполовення, пісня 5-та – 6 та святих, пісня 6-та – 4. Після входу тропарі та кондаки: Тропар Переполовення, тропар храму Богородиці або храму святого, тропар святих, кондак храму святого. «Слава» – кондак святих, «І нині» – кондак Переполовення. (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен, алилуарій та причасний – Переполовення та святих. Апостол і Євангеліє – дня та святих. Примітка. У суботи періоду П’ятдесятниці на Літургіях завжди першим проголошується рядове читання, і лише потім – читання святого. Задостойник Пасхи."}]},
{"date":"05-12","weekday":"вівторок","title":"Свт. Епіфанія, єп. Кіпрського (403). Свт. Германа, патр. Константинопольського (740). Свтт. Савина, архієп. Кіпрського (V), і Полувія, єп. Ринокирського (V). Прп. Амфілохія Почаївського, в малій схимі Йосифа, чудотворця Іловецького. (1971). День тезоіменитства Блаженнійшого Митрополита Київського і всієї України Епіфанія.","readings":["Ран. – Лк., 24 зач., VI, 17 – 23.","Літ. – Діян., 31 зач., XII, 25 – XIII, 12. Ін., 33 зач., VIII, 51 – 59.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Мф., 43 зач., XI, 27 – 30."],"notes":"* Апостол і Євангеліє прп. Амфілохію Почаївському читаються тільки якщо йому звершується служба. * Апостол і Євангеліє свт. Епіфанію Кіпрському читаються тільки якщо йому звершується служба. Служба прп. Амфілохія Почаївського полієлейна, звершується разом зі службою свята з Тріоді (варіант «А»). Наводимо також порядок звершення полієлейної служби свт. Епіфанію Кіпрському разом зі службою свята (варіант «Б»). ВАРІАНТ «А».","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю...» стихири на 8: свята Тріоді, глас 1-ий і – 3, і преподобного, глас 8-ий – 5. «Слава» – преподобного, глас той самий: «Безсрібренику і чудотворче, преподобний Амфілохію...», «І нині» – свята, глас 2-ий: «Коли Ти прийшов...». Вхід. «Світло Тихе». Прокимен дня. Паремії преподобного – 3. На стиховні стихири преподобного, глас 1-ий (зі своїми приспівами). «Слава» – преподобного, глас 8-ий: «Славним поборником Тройці...», «І нині» – Тріоді, глас 3-ій: «В переполовення свята славимо Тебе...». Після Трисвятого – тропар Переполовення, глас 8-ий, «Слава» – тропар преподобного, глас 4-ий, «І нині», Богородичний недільний, глас 4: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар Переполовення, глас 8-ий (двічі). «Слава» – тропар преподобного, глас 4-ий, «І нині» – Богородичний недільний, глас 4: «Від початку віку утаємнене...». Кафізми 7-ма і 8-ма. Малі ектенії. По 1-ій кафизмі: Сідальний преподобному, глас 1-ий, «Слава», інший седальний преподобному, глас той самий, «І нині», Сідальний свята (Тріоді). По 2-ій кафизмі: Сідальний преподобному, глас 2-ий, «Слава», інший седальний преподобному, глас той самий, «І нині», Сідальний свята (Тріоді). Полієлей. Величання преподобного і вибраний псалом святого. Сідальний преподобного, глас 2-ий: «Прийдіть зібрання посників...», «Слава, і нині» – сідальний свята Тріоді. Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Прославляй, Єрусалиме, Господа, хвали Бога твого, Сионе»; стих: «Як укріпив ти засуви врат твоїх». Євангеліє преподобного. «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами преподобного Амфілохія...», «І нині» – «Молитвами Богородиці...». «Помилуй мене, Боже...» і стихира преподобного, глас 7-ий: «Сьогодні благодать Святого Духа...». Канони: свята Тріоді, 2-ий, з ірмосом на 6 (ірмоси двічі) і преподобного на 8. Біблійні пісні «Співаймо Господеві...». Катавасія Пасхи: «Воскресіння день.» Після 3-ої пісні – кондак і ікос свята Тріоді, глас 4, інший кондак преподобного, глас 2-ий: «З волі Діви Пречистої...», сідальний преподобного, глас 3-ій: «Сповнений Христовою любов’ю...» (двічі), «Слава, і нині» – сідальний Переполовення, глас 8-ий: «Премудрости воду...». Після 6-ої пісні – кондак свята преподобного, глас 3-ій: «Як віри православної ревнитель...» та ікос. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – Світильний преподобного: «Подвигом добрим подвизаючись...», «Слава, і нині» – світильний Переполовенню. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: свята Тріоді, глас 4-ий – 3, та преподобного, глас 5-ий – 3. «Слала», стихира преподобного, глас 8-ий: «Блаженний отче Амфілохію...» «І нині», глас 4-ий – Тріоді: «Господи, раніше Чесного Твого Хреста...». Велике славослів’я. Після Трисвятого – тропар свята Переполовення, «Слава», тропар преподобного, глас 4-ий, «і нині» – Богородичний, глас 4-ий: «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар Переполовення, «Слава» – тропар преподобного. Кондаки Переполовення та преподобного чергуються. ЛІТУРГІЯ свт. Іоана Золотоустого. Блаженні свята Тріоді, пісня 3-тя – 4 (з ірмосом), і преподобного, пісня 6-та – 4. Після входу – тропар свята, тропар храма, тропар преподобного, кондак храма, «Слава» – кондак преподобного, «І нині» – кондак свята Переполовення. Прокимен, Апостол, алилуарій та Євангеліє – дня та преподобного. Задостойник Пасхи: «Ангел звістив...». Причасний – Пасхи та преподобного «В пам’ять вічну...». ВАРІАНТ «Б». Примітка. У Мінеї міститься служба свт. Епіфанію у поєднанні зі службою свт. Герману Константинопольському, що не має святкового знаку, тому декотрі богослужбові тексти треба запозичувати зі служби святителю одному в Загальній Мінеї."},{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю...» стихири на 8: свята Тріоді, глас 1-ий – 3, та святителя, глас 5-ий – 5 (перші дві стихири двічі). «Слава» – святителя, глас 8-ий: «Чеснотами твоїми, преподобний отче...» (див. у Загальній Мінеї). «І нині» – свята, глас 2-ий: «Коли Ти прийшов...». Вхід. «Світло Тихе». Прокимен дня. Паремії святителя – 3 (див. у загальній Мінеї). На стиховні стихири святителя, глас 8-ий (зі своїми приспівами, див. у загальній Мінеї). «Слава...» – святителя, глас 8-ий: «Ти єси пастир добрий...» (див. у Загальній Мінеї), «І нині» – Тріоді, глас 3-ій: «В переполовення свята славимо Тебе...». Після Трисвятого тропа свята Тріоді, глас 8-ий, «Слава», тропар святителя, глас 4-ий, «І нині», Богородичний, глас той самий; «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята Тріоді, глас 8-ий (двічі), «Слава» – тропар святителя, глас 4-ий, «І нині» – Богородичний, глас той самий; «Від початку віку утаємнене...». Кафізми 7-ма і 8-ма. Малі ектенії. По По 1-ій кафизмі: Сідальний святителя, глас 1-ий, «Слава, і нині», Сідальний свята (Тріоді). По 2-ій кафизмі: Сідальний святителя, глас 4-ий, «Слава, і нині», Сідальний свята (Тріоді). Полієлей. Величання святителя і вибраний псалом. Після полієлея сідальний святителя, глас 8: «Подолавши пристрасті тілесні...», «Слава, і нині», сідальний Тріоді Переполовення (після кафизм). Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 1: «Уста мої промовлятимуть премудрість, і повчання серця мого – розум», стих: «Слухайте це, всі народи, почуйте всі, хто живе по вселенній». Євангеліє святителя. «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами святителя Епіфанія...», «І нині» – «Молитвами Богородиці...». «Помилуй мене, Боже...» і стихира святителя, глас 6-ий: «Насліднику Божий...». Канони: свята Тріоді Переполовення з ірмосом на 6 (ірмоси двічі) та святителя на 8. Біблійні пісні «Співаймо Господеві...». Катавасія Пасхи: «Воскресіння день.» Після 3-ої пісні – кондак і ікос Переполовення, глас 4-ий, сідальний святителя, глас 4ий, «Слава, і нині» – сідальний свята Тріоді. Після 6-ої пісні – кондак святителя, глас 4-ий: «Дивну двоїцю...» та ікос. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – Світильний святителя: «Прийдіть, вірні, вшануємо...» (двічи), «Слава, і нині» – світильний Переполовення. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: свята Тріоді, глас 4-ий – 3, та святителя, глас 8-ий – 3 (див. їх у Загальній Мінеї): «Святителю отче Епіфанію...», «Отче дивний Епіфанію...», «Отче отців Епіфанію...»; «Слава», святителя, глас 6-ий: «Преподобний і преблаженний святителю...» (див. її у загальній Мінеї), «і нині», Тріоді, глас 4-ий: «Господи, раніше Чесного Твого Хреста...». Велике славослів’я. Після Трисвятого – тропар Переполовення, глас 8-ий, «Слава», святителя, глас 4-ий, «і нині» – Богородичний, глас 4-ий: «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар свята Переполовення, «Слава» – тропар святителя. Кондаки Переполовення та святителя чергуються. ЛІТУРГІЯ свт. Іоана Золотоустого. Блаженні свята Тріоді, пісня 3-тя – 4 (з ірмосом), і святителя, пісня 6-та – 4. Після входу – тропар свята Переполовення, тропар храму, тропар святителя, кодкак храму, «Слава» – кондак святителя, «І нині» – кондак Переполовення. Прокимен, Апостол, алилуарій та Євангеліє – свята Тріоді та святителя. Причасний Пасхи та святителя «В пам’ять вічну...»."}]},
{"date":"05-13","weekday":"середа","title":"Віддання свята Переполовення П’ятдесятниці. Мц. Глікерії, діви, і з нею мч. Лаодикія, сторожа в’язничного (бл. 117). Перенесення мощів прмч. Макарія, архім. Канівського, ігум. Пінського, Переяславського чудотворця (1688). Мч. Олександра Римського (284 – 305). Свт. Павсикакія, єп. Синадського (606). Свв. Георгія, спов., з дружиною Іриною і дітьми (ІХ). Прп. Євфимія Іверського (1028, Груз.).","readings":["Діян., 32 зач., XIII, 13 – 24. Ін., 18 зач., VI, 5 – 14."],"notes":"Славослівна служба віддання свята Переполовення П’ятдесятниці звершується за Тріоддю. Служба прмч. Макарія переноситься на повечір’я.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири свята Переполовення (з Тріоді), глас 4-ий – 6 (кожна стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «Свято переполовинилося Твого, Христе, воскресіння...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 1-ий і глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Коли переполовинилося свято...». Після Трисвятого – тропар Переполовення, глас 8-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар Переполовення (двічі). «Слава, і нині» – той самий тропар. Кафізми 10-та і 11-та. Малі ектенії. Сідальні свята Тріоді (по двічі) (див. у середу 4-ої седмиці після Пасхи). «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони свята Переполовення: 1-ий канон, глас 4-ий, з ірмосом на 8 (ірмоси по двічі), і 2-ий канон, глас 8-ий, на 6. Біблійні пісні «Співаймо Господеві...». Катавасія Переполовення: «Море висушив Ти...». Після 3-ої пісні – сідальний Переполовення, глас 8-ий, «Слава, і нині» – інший сідальний свята, глас той самий. Після 6-ої пісні – кондак і ікос Переполовення, глас 4-ий. На 9-ій пісні – звичайне кадіння. «Чеснішу» не співаємо. Після 9-ої пісні «Достойно є» не співається. Світильний свята Тріоді: «Маючи чашу невичерпних дарів...». «Слава, і нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята Тріоді, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята, глас той самий: «Просвітившись, браття...». Велике славослів’я. Після Трисвятого – тропар свята (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята Переполовення."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з обох канонів Переполовення, пісня 9-та на 8 (1-го канону з ірмосом). На вході: «...що воскрес із мертвих...» Після входу – тропар свята. «Слава, і нині» – кондак свята. Співається Трисвяте. Прокимен та алилуарій Переполовення. Апостол і Євангеліє – дня. Задостойник – ірмос 9-ої пісні 2-го канону Переполовення: «Невластиве матерям дівство...». Причасний Переполовення: «Хто споживає Тіло Моє...»."}]},
{"date":"05-14","weekday":"четвер","title":"Мч. Ісидора (251). Прп. Микити, затворника Києво-Печерського, єп. Новгородського (1108). Мч. Максима (бл. 250). Прп. Серапіона Синдоніта (V). Свт. Леонтія, патр. Єрусалимського (1175).","readings":["Діян., 35 зач., XIV, 20 – 27. Ін., 35 зач., IX, 39 – X, 9."],"notes":"З цього дня до суботи – післясвято Неділі про самарянку. Служба муч. Ісидора не має святкового знаку, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 12-та. На «Господи, взиваю» стихири на 6: свята (Самарянки), глас 4-ий – 3 та мученика, глас 4-ий – 3, «Слава, і нині» – самарянки, глас 1-ий: «До джерела прийшов Ти, Джерело чудес...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 4-ий (див. на «Господи, взиваю...») з приспівами. «Слава, і нині» – самарянки, глас 2-ий: «Коли прийшов Господь до колодязя...». Після Трисвятого – тропар воскресний, глас 4-ий: «Світлу воскресіння проповідь...», «Слава» – тропар мученика, глас той самий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 4-ий: «Світлу воскресіння проповідь...» (двічі), «Слава» – тропар мученика, глас той самий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...». Кафізми 13-та і 14-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: самарянки, глас 4-ий («Ти уразив Єгипет...», див. на ранній у неділю 5-ту після Пасхи) з ірмосом на 8 (ірмоси двічі), мученика на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мцченика. Після 3-ої пісні – кондак мученика, глас 4-ий, «Слава» – сідальний мученика, глас 3-ій, «І нині» – сідальний самарянки, глас той самий: «Нехай радіє небо, нехай веселиться земля...». Після 6-ої пісні – кондак і ікос самарянки, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний самарянки. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 4-ий – 4 (перша стихира двічі). «Слава, і нині» – Тріоді, глас 2-ий: «Співбезначальний і співприсносущий Сину...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 4-ий з приспівами. «Слава, і нині» – Тріоді, глас 3-ій: «Нехай нині радіють світло, небо і земля...». Після Трисвятого – тропар воскресний, «Слава» – тропар мученика, «І нині» – Богородичний воскресний «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар воскресний, «Слава» – тропар мученика. Кондак самарянки."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону самарянки, пісня 1-ша – 6 (з ірмосом). Після входу тропарі та кондаки: Тропар воскресний, тропар храму Богородиці або храму святого, тропар мученика, кондак храму святого. «Слава» – кондак мученика, «І нині» – кондак самарянки. (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен і алилуарій – Неділі про самарянку. Апостол і Євангеліє – дня. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...»."}]},
{"date":"05-15","weekday":"п’ятниця","title":"Прп. Пахомія Великого (348). Свт. Ісаї Києво-Михайлівського, єп. Ростовського, чудотворця (1090). Прп. Ісаї Києво-Печерського (1115). Прп. Ахилія, єп. Лариссійського (ІІ).","readings":["Діян., 36 зач., XV, 5 – 34. Ін., 37 зач., X, 17 – 28.","Прп.: 2 Кор., 176 зач., ІV, 6 – 15. Лк., 77 зач., XІV, 25 – 35."],"notes":"Служба свт. Ісаї шестерична, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 15-та. На «Господи, взиваю» стихири на 6: свята Тріоді (самарянки), глас 4-ий – 3, і святителя, глас 4-ий, – 3. «Слава, і нині» – самарянки, глас 6-ий: «Біля колодязя Якова...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 4-ий з приспівами. «Слава» святителю, глас 6, «І нині» – Тріоді, глас 6-ий: «Так говорить Господь самарянці...». Після Трисвятого – тропар воскресний, глас 4-ий: «Світлу воскресіння проповідь...», «Слава» – тропар святителю, глас 8-ий, «І нині» – Богородичний воскресний, глас той самий: «Ти, що ради нас народився від Діви ...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 4-ий: «Світлу воскресіння проповідь...» (двічі), «Слава» – тропар святителя, глас 8-ий, «І нині» – Богородичний воскресний, глас той самий: «Ти, що ради нас народився від Діви ...». Кафізми 19-та і 20-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: самарянки, глас 4-ий («Ти уразив Єгипет...», див. на ранній у неділю 5-ту після Пасхи) з ірмосом на 8 (ірмоси двічі) і святителя на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону святителя. Після 3-ої пісні – кондак і ікос святителя, глас 3-ій, інший кондак святителя, глас 4-ий, «Слава», сідальний святителя, глас 8-ий, «І нині» – сідальний самарянки, глас 4-ий: «Нехай радіє небо, нехай веселиться земля...». Після 6-ої пісні – кондак і ікос самарянки, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний святителя. «Слава, і нині» – світильний самарянки. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 4-ий – 4 (перша стихира двічі). «Слава», святителю, глас 8-ий: «Святителю Христів...», «І нині» – Тріоді, глас 6-ий: «Ісус, Спас наш, Джерело життєначала...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 4-ий з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «Коли з’явився Ти у плоті, Христе Боже...». Після Трисвятого – тропар воскресний, «Слава» – тропар святителя, «І нині» – Богородичний воскресний «Ти, що ради нас народився від Діви ...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар воскресний, «Слава» – тропар святителя. Кондак самарянки і святителя поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону самарянки, пісня 6-та – 6 (з ірмосом). Після входу тропарі та кондаки: У храмі Господському – тропар воскресний, тропар святителя, «Слава», кондак святителя, «І нині» – кондак самарянки. У храмі Богородиці – тропар воскресний, тропар храму, тропар святителя, «Слава», кондак святителя, «І нині» – кондак самарянки. У храмі святого – тропар воскресний, тропар храму, тропар святителя, кондак храму, «Слава» – кондак святителя, «І нині» – кондак самарянки. (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен і алилуарій – Неділі про самарянку. Апостол і Євангеліє – дня. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...»."}]},
{"date":"05-16","weekday":"субота","title":"Прп. Федора Освяченого (368). Прпп. отців, які в лаврі св. Сави були вбиті (614). Свт. Олександра, єп. Єрусалимського (213 – 250). Мчч. Віта, Модеста і мц. Крискентії (бл. 303). Блж. отроковиці Музи (V). Свт. Георгія ІІ, єп. Мітиленського (ІХ).","readings":["Діян., 37 зач., XV, 35 – 41. Ін., 38 зач., X, 27 – 38."],"notes":"Служба прп.. Феодора Освяченого шестерична, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 18-та. На «Господи, взиваю» стихири на 6: свята Тріоді (самарянки), глас 1-ий та глас 2-ий – 3, і преподобного, глас 6-ий, – 3. «Слава, і нині» – догматик, глас 4-ий: «Пророк Давид, що через Тебе, Богородице, богоотцем став...» Входу немає. Прокимен дня. На стиховні воскресні стихири Тріоді, глас 4-ий – 4 (з приспівами воскресними). «Слава, і нині» – Тріоді, глас 8-ий: «Коли з’явився Ти у плоті, Христе Боже...». Після Трисвятого – тропар воскресний, глас 4-ий: «Світлу воскресіння проповідь...», «Слава» – тропар преподобного, глас 1-ий, «І нині» – Богородичний воскресний, глас той самий: «Коли Гавриїл звістив Тобі, Діво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний «Світлу воскресіння проповідь...» (двічі), «Слава» – тропар преподобного, «І нині» – Богородичний воскресний «Коли Гавриїл звістив Тобі, Діво...». Кафізми 16-та і 17-та. Примітка. Під час читання 17-ої кафізми ієрей звершує повне кадіння храму. Царські врата при цьому залишаються закритими (зр. Типікон, гл. 12). Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: самарянки, глас 4-ий («Ти уразив Єгипет...», див. на ранній у неділю 5-ту після Пасхи) з ірмосом на 6 (ірмоси двічі) і преподобному на 6 (канон храму святого не співається). Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону преподобного. Після 3-ої пісні – кондак преподобного, глас 2-ий, сідальний преподобного, глас 3-ій (двічі), «Слава, і нині» – сідальний самарянки, глас 4-ий: «Нехай радіє небо, нехай веселиться земля...». Після 6-ої пісні – кондак і ікос самарянки, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний самарянки (двічі), «Слава, і нині» – світильний самарянки. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх воскресні стихири Тріоді, глас 4-ий – 4. «Слава, і нині» – Тріоді, глас 6-ий: «Ісус, Спас наш, Джерело життєначала...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 4-ий з приспівами. «Слава, і нині» – Тріоді, глас 6-ий: «Так говорить Господь самарянці...». Після Трисвятого – тропар воскресний, «Слава» – тропар преподобного, «І нині» – Богородичний воскресний «Коли Гавриїл звістив Тобі, Діво ...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар воскресний, «Слава» – тропар преподобного. Кондак самарянки."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону самарянки, пісня 9-та – 6 (з ірмосом). Після входу тропарі та кондаки: Тропар воскресний, тропар храму Богородиці або храму святого, тропар преподобного, кондак храму святого, «Слава» – кондак преподобного, «І нині» – кондак самарянки. (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен і алилуарій – Неділі про самарянку та преподобного. Апостол і Євангеліє – дня та преподобного. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...» та преподобного «В пам’ять вічну...»."}]},
{"date":"05-17","weekday":"неділя","title":"6-та неділя після Пасхи, про сліпого. Ап. Андроніка і св. Юнії (І). Мчч. Солохона, Памфамира і Памфалона, воїнів (284 – 305). Свт. Стефана, патр. Константинопольського (893).","readings":["Ран. – Єв. 8-е, Ін., 64 зач., XX, 11 – 18.","Літ. – Діян., 38 зач., XVI, 16 – 34. Ін., 34 зач., IX, 1 – 38."],"notes":"На ранній катавасія «Спасителю Богу...». Примітка. Піснеспіви Неділі про сліпого співаються у неділю, понеділок, вівторок та середу 6-ої седмиці після Пасхи.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафізма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 5-ий – 7, та свята Тріоді (про сліпого), глас 2-ий – 3 (перша стихира двічі). «Слава» – свята Тріоді, глас 5-ий: «Господи, проходячи дорогою...», «І нині» – догматик, глас той самий: «У червоному морі...». Вхід. Прокимен дня. На літії стихира храму. «Слава» – свята Тріоді, глас 4-ий: «Сліпий, для якого все життя було ніччю...». «І нині» – Богородичний воскресний, глас той самий: «Зглянься на рабів Твоїх, Всенепорочна...». На стиховні стихира воскресна, глас 5-ий: «Тебе, Спаса Христа...», і стихири Пасхи, глас той самий (з їхніми приспівами). «Слава» – свята Тріоді, глас 8-ий: «Сонце правди, Христе Боже...», «І нині» – Пасхи, глас 5-ий: «Воскресіння день». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 5-ий: «Співбезначальне Слово Отцеві і Духові...» (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Радуйся, двері Господні непрохідні...». Кафізми 2-га і 3-тя. Малі ектенії. Сідальні воскресні (див. в Тріоді). Непорочні. «Ангельський собор...». Іпакої, глас 5-ий: «Мироносиці засмучені...». Степенний – антифони 5-го гласу. Прокимен, глас 5-ий: «Воскресни, Господи, Боже мій, нехай піднесеться рука Твоя...». Євангеліє воскресне 8-ме. «Воскресіння Христове бачивши...» (тричі). Після 50-го псалма: «Слава» – «Молитвами апостолів...», «І нині» – «Молитвами Богородиці». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: Пасхи «Воскресіння день...» з ірмосом і Богородичними тропарями на 8 (ірмоси по двічі) і свята Тріоді (про сліпого) на 6. Біблійні пісні «Співаймо Господеві...». Катавасія Вознесіння, глас 5-ий: «Спасителю Богу...». Після 3-ої пісні – кондак і ікос Пасхи, глас 8-ий; сідальний свята Тріоді (про сліпого), глас 8-ий: «Проходячи, Владика всіх і Творець...», «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак і ікос свята Тріоді (про сліпого), глас 4-ий. На 9-ій пісні «Чеснішу» не співаємо. (Звершується звичайне кадіння). Після 9-ої пісні – «Свят Господь Бог наш». Екзапостіларій Пасхи: «Плоттю заснувши...». «Слава» – світильний свята Тріоді (про сліпого): «Розумові мої очі, Господи...», «І нині» – другий світильний Тріоді: «Проходячи мимо, Спас наш...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні (див. в Тріоді), глас 5-ий – 7, далі стих Тріоді: «Зглянься на мене, і помилуй мене» і стихира свята Тріоді (про сліпого), глас 8-ий: «Заради милости милосердя втілившись...» (один раз). «Слава» – Тріоді, глас той самий: «Хто опише силу Твою, Христе?...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Днесь спасіння...» Перед 1-им часом на «Слава, і нині» – євангельська стихира 8-ма."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. Кондак свята Тріоді (про сліпого)."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4 (див. в Тріоді) і з канону Тріоді (про сліпого), пісня 6-та – 4. Після входу – тропар воскресний, «Слава» – кондак Неділі про сліпого, «І нині» – кондак Пасхи. Прокимен – Неділі про сліпого, глас 8-ий: «Помоліться і воздайте Господу Богу нашому». Стих: «Відомий в Юдеї Бог, в Ізраїлі велике ім’я Його». Алилуя, глас 8-ий: «Зглянься на мене, і помилуй мене». Стих: «Стопи мої спрямуй за словом Твоїм». Апостол і Євангеліє – Неділі про сліпого. Задостойник Пасхи. Причасний Пасхи «Тіло Христове...» і воскресний «Хваліте Господа з Небес...»."}]},
{"date":"05-18","weekday":"понеділок","title":"6-й тиждень після Пасхи. Пам’ять свв. отців сімох Вселенських соборів. Мчч. Феодота Анкирського, Петра, Діонісія, Андрія, Павла, мц. Христини (249 – 251) і мцц. сімох дів: Олександри, Текуси, Клавдії, Фаїни, Євфрасії, Мотрони і Юлії (303). Мчч. Симеона, Ісаака і Вахтисія (ІV), Іраклія, Павлина, Венедима, Давида і Таричана (693, Груз.).","readings":["Діян., 39 зач., XVII, 1 – 15. Ін., 40 зач., XI, 47 – 57."],"notes":"Служба мч. Феодора Анкірського і тих, що з ним не має святкового знаку, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізми немає. На «Господи, взиваю» стихири на 6: свята Тріоді (про сліпого), глас 5-ий – 3, і мученика, глас 1-ий, – 3. «Слава, і нині» – Тріоді, глас 2-ий: «Той, хто народився сліпим, сам собі говорив...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 5-ий з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «Проходячи мимо храму, Ісус побачив чоловіка...». Після Трисвятого – тропар воскресний, глас 5-ий: «Співбезначальне Слово...» (один раз), «Слава, і нині» – Богородичний воскресний, глас той самий: «Радуйся, двері Господні непрохідні...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний: «Співбезначальне Слово...» (двічі), «Слава, і нині» – Богородичний: «Радуйся, двері Господні непрохідні...». Кафізми 4-та і 5-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: свята Тріоді (про сліпого) з ірмосом на 8 (ірмоси двічі) і мученика на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону 2-ого канону мученика. Після 3-ої пісні – кондак мученика, глас – 2-ий, сідальний мученика, глас 4-ий, «Слава, і нині» – сідальний свята Тріоді (про сліпого), глас 8-ий: «Проходячи, Владика всіх і Творець...». Після 6-ої пісні – кондак і ікос свята Тріоді (про сліпого), глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний свята Тріоді (про сліпого): «Розумові мої очі, Господи...», «Слава, і нині» – другий світильний Тріоді: «Проходячи мимо, Спас наш...». «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 5-ий – 4 (перша стихира двічі). «Слава, і нині» – Тріоді, глас 2-ий: «Сліпий, для якого все життя було ніччю...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 5-ий з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «Господи, проходячи дорогою...». Після Трисвятого – тропар воскресний, глас 5-ий: «Співбезначальне Слово...», «Слава, і нині» – Богородичний, глас той самий: «Радуйся, двері Господні непрохідні...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар та кондак Свята Тріоді (про сліпого)."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону про сліпого, пісня 1-ша – 6 (з ірмосом). Після входу тропарі та кондаки: У храмі Господському – тропар воскресний, «Слава, і нині» – кондак Свята Тріоді (про сліпого). У храмі Богородиці – тропар воскресний, тропар храму. «Слава, і нині» – кондак Свята Тріоді (про сліпого). У храмі святого – тропар воскресний, тропар храму, «Слава» – кондак храму, «І нині» – кондак Свята Тріоді (про сліпого). (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен, алилуарій та причасний – Свята Тріоді (про сліпого). Апостол і Євангеліє – дня. Задостойник Пасхи."}]},
{"date":"05-19","weekday":"вівторок","title":"Сщмчч. Патрикія, єп. Пруського, і з ним трьох пресвітерів: Акакія, Менандра і Полієна (бл. 100). Мч. Парфенія Жовківського, Римського (250). Мч. Калуфа Єгиптянина (284 – 303). Прп. Іоана, єп. Готського (VІІІ).","readings":["Діян., 40 зач. (від половини), XVII, 19 – 28. Ін., 42 зач., XII, 19 – 36."],"notes":"Служба сщмчч. Патрикія і з ним трьох пресвітерів не має святкового знака, звершується зі службою Тріоді.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізми 6-та. На «Господи, взиваю» стихири на 6: свята Тріоді (про сліпого),глас5-ий–3,ісвятих,глас1-ий,–3.«Слава,інині»–Тріоді, глас 2-ий: «Той, хто народився сліпим, сам собі говорив...». Входу немає. Прокимен дня. На стиховні стихири Тріоді, глас 5-ий з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «Проходячи мимо храму, Ісус побачив чоловіка...». Після Трисвятого – тропар воскресний, глас 5-ий: «Співбезначальне Слово...» (один раз), «Слава, і нині» – Богородичний воскресний, глас той самий: «Радуйся, двері Господні непрохідні...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний: «Співбезначальне Слово...» (двічі), «Слава, і нині» – Богородичний: «Радуйся, двері Господні непрохідні...». Кафізми 7-ма і 8-ма. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: свята Тріоді (про сліпого) з ірмосом на 8 (ірмоси двічі) і святих на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону святих. Після 3-ої пісні – кондак святих, глас 4-ий, сідальний святих, глас 8-ий, «Слава, і нині» – сідальний свята Тріоді (про сліпого), глас 8-ий: «Проходячи, Владика всіх і Творець...». Після 6-ої пісні – кондак і ікос свята Тріоді (про сліпого), глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний свята Тріоді (про сліпого): «Розумові мої очі, Господи...», «Слава, і нині» – другий світильний Тріоді: «Проходячи мимо, Спас наш...». «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 5-ий – 4 (перша стихира двічі). «Слава, і нині» – Тріоді, глас 2-ий: «Сліпий, для якого все життя було ніччю...». «Тобі слава подобає...» не читається, але відразу ж читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Тріоді, глас 5-ий з приспівами. «Слава, і нині» – Тріоді, глас 8-ий: «Господи, проходячи дорогою...». Після Трисвятого – тропар воскресний, глас 5-ий: «Співбезначальне Слово...», «Слава, і нині» – Богородичний, глас той самий: «Радуйся, двері Господні непрохідні...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар та кондак Свята Тріоді (про сліпого)."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону про сліпого, пісня 1-ша – 6 (з ірмосом). Після входу тропарі та кондаки: У храмі Господському – тропар воскресний, «Слава, і нині» – кондак Свята Тріоді (про сліпого). У храмі Богородиці – тропар воскресний, тропар храму. «Слава, і нині» – кондак Свята Тріоді (про сліпого). У храмі святого – тропар воскресний, тропар храму, «Слава» – кондак храму, «І нині» – кондак Свята Тріоді (про сліпого). (Тропар та кондак храму Господського та кондак храму Богородиці не співаються). Прокимен, алилуарій та причасний – Свята Тріоді (про сліпого). Апостол і Євангеліє – дня. Задостойник Пасхи."}]},
{"date":"05-20","weekday":"середа","title":"Віддання свята Пасхи. Мчч. Фалалея, Олександра і Астерія (бл. 284). Мч. Аскалона (бл. 287). Знайдення мощів святителя Олексія, митр. Київського і всієї Руси, чудотворця (1431).","readings":["Діян., 41 зач., XVIII, 22 – 28. Ін., 43 зач., XII, 36 – 47."],"notes":"Початок вечірні, ранньої і Літургії – пасхальний. На ранній катавасія «Спасителю Богу...». Часи звичайні. Закінчення Літургії та відпуст – пасхальні. Існує також традиція звершувати вечірню й ранню за пасхальним чином. Звершується славослівна служба віддання свята Пасхи.(А) У грецькій Квітній Тріоді, крім того чинопослідування, яке міститься в слов’янській Тріоді, дається також інше для вівторка та середи цього тижня, в якому у вівторок співається служба віддання Неділі про сліпого, а в середу – віддання Пасхи. З цього чинопослідування, служба віддання Пасхи на ранній і на Літургії у всьому подібна до пасхальної служби. На вечірні співаються стихири на «Господи, взиваю» воскресні, глас 1-ий, на 6. «Слава, і нині» – «Всесвітню славу...». На стиховні – стихира 1-го гласу «Стражданням Твоїм, Христе...», потім стихири Пасхи. Відпуст вечірні пасхальний. Це чинопослідування призначене для того, щоб надати відданню Пасхи ту ж урочистість, яку мають всі віддання великих свят. Часи також співаються пасхальні. Про передсвятковий канон Вознесіння сказано, що він співається, коли забажає настоятель. (Б) А. НА ВЕЧІРНІ початок такий самий, як в 1-ий день Пасхи. Ієрей у ризі, з пасхальним трисвічником і хрестом в лівій руці, з кадилом у правій руці, після початкового виголосу: «Слава Святій...» (при відкритих царських вратах), співає тропар Пасхи: «Христос воскрес...» (тричі). Хор також тричі повторює тропар. Ієрей співає стихи пасхального початку: «Нехай воскресне Бог...» та ін. Хор після кожного стиха: «Христос воскрес...» (по одному разу). Під часу співу пасхального початку звершується повне кадіння храму. Потім читається 103-ій псалом. Велика ектенія. Кафізма 9-та. На «Господи, взиваю» стихири свята Тріоді (про сліпого) 2-го, 4-го, 5-го і 8-го гласів – 6. «Слава, і нині» – Тріоді, глас 8-ий: «Сонце правди, Христе Боже...». Входу немає. Прокимен дня. На стиховні стихира воскресна Тріоді, глас 5-ий: «Тебе, Спаса Христа, що тіло прийняв...», і стихири Пасхи, глас той самий (з їхніми приспівами). «Слава, і нині» – Пасхи: «Воскресіння день...». Після Трисвятого – тропар воскресний, глас 5-ий: «Співбезначальне Слово...», «Слава, і нині» – Богородичний воскресний, глас той самий: «Радуйся, двері Господні непрохідні...».","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ після виголосу «Слава Святій...» і пасхального початку з кадінням (як і на вечірні) відразу: «Слава в вишніх Богу...» і шестипсалміє. На «Бог – Господь» тропар воскресний «Співбезначальне Слово...» (двічі), «Слава, і нині» – Богородичний «Радуйся, двері Господні непрохідні...». Кафізми 10-та і 11-та. Малі ектенії. Сідальні Тріоді. «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. Канони: Пасхи «Воскресіння день...» (без Богородичних тропарів) з ірмосом на 6 (ірмоси по двічі, приспів до тропарів канону – «Христос воскрес із мертвих»), свята Тріоді (про сліпого) на 4 і передсвята Вознесіння (див. у Тріоді) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія Вознесіння «Спасителю Богу...». Після 3-ої пісні – кондак і ікос свята Тріоді (про сліпого), глас 4-ий, сідальний свята Тріоді (про сліпого), глас 1-ий: «Ти, Христе, повернув зір...», «Слава, і нині» – сідальний передсвята Вознесіння, глас той самий: «Народився Ти, Спасе мій...». Після 6-ої пісні – кондак і ікос Пасхи, глас 8-ий. На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспіви Пасхи. (Звершується звичайне кадіння). Після 9-ої пісні «Достойно є» не співається. Екзапостиларій Пасхи «Плоттю заснувши...» (двічі). «Слава, і нині» – світильний Тріоді (про сліпого): «Розумові мої очі...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: свята Тріоді (про сліпого) – 4: глас 2-ий: «Той, хто народився сліпим, сам собі говорив...», глас той самий: «Проходячи мимо храму...», глас 4-ий: «Сліпий, для якого все життя було ніччю...» та глас 5-ий: «Господи, проходячи дорогою...» (див. їх на «Господи, взиваю...» на вечірні у вівторок 6-ої седмиці після Пасхи) та стихири Пасхи, глас 5-ий (зі своїми приспівами). «Слава, і нині» – Пасхи, глас той самий: «Воскресіння день...». Велике славослів’я. Після Трисвятого – тропар воскресний, глас 5-ий: «Співбезначальне Слово...». «Слава, і нині» – Богородичний воскресний, глас той самий: «Радуйся, двері Господні непрохідні...». Ектенії і відпуст воскресний без хреста: «Христос, що воскрес із мертвих...» ЧАСИ звичайні (трьохпсалмні). На часах – тропар воскресний «Співбезначальне Слово...», кондак свята Тріоді (про сліпого)."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ після виголосу «Благословенне Царство...» – пасхальний початок при відкритих царських вратах з кадінням, як зазначено на вечірні і ранній. Антифони зображальні. Блаженні з канону Пасхи на 8: пісня 3-я – 4 (з ірмосом), і пісня 6-та – 4. На вході: «...спаси нас, Сину Божий, що воскрес із мертвих...». Після входу – тропар воскресний, «Слава» – кондак свята Тріоді (про сліпого), «І нині» – кондак Пасхи. Співається Трисвяте. Прокимен Пасхи, глас 8-ий: «Цей день, його ж створив Господь...». Стих: «Прославляйте Господа...». Алилуарій, глас 4-ий: «Ти, Господи, воскрес, ущедривши Сион». Стих: «Господь з неба на землю поглянув». Апостол і Євангеліє – дня. Задостойник Пасхи. Причасний Пасхи: «Тіло Христове...». Закінчення Літургії: після виголосу «Благословення Господнє на вас...» Хор: «Амінь». Настоятель замість виголосу «Слава Тобі, Христе Боже...» співає: «Христос воскрес із мертвих, смертю смерть подолав». Хор закінчує: «І тим, що у гробах, життя дарував». Настоятель, тримаючи хрест з трисвічником в руках, виголошує відпуст: «Христос, що воскрес із мертвих, смертю смерть подолав і тим, що у гробах, життя дарував, є істиний Бог наш, молитвами Пречистої Своєї Матері і всіх святих помилує і спасе нас, бо Він благий і Людинолюбний». Потім підносить хрест і промовляє: Христос воскрес! (тричі). Хор співає кінцеве «Христос воскрес...» (тричі), «І нам дарував життя вічне, поклоняємось Його триденному воскресінню». Многоліття. Б. УСТАВ ВІДДАННЯ ПАСХИ ЗА ГРЕЦЬКОЮ ТРАДИ- ЦІЄЮ У грецькому Пентакостаріоні, крім того чинопослідування, яке є в слов’янській Квітній Тріоді, для вівторка та середи 6-ї седмиці після Пасхи дається й інше, в якому у вівторок належить робити віддання Неділі про сліпого, а в середу – віддання Пасхи. У цьому чинопослідуванні служба віддання Пасхи в усьому подібна до пасхальної служби. Звідси, всібогослужіння, в тому числі й требні, молитовні правила та інше, в цейдень (від початку вечірні й до відпусту 9-го часу) звершуються, як у Світлий тиждень. Царські врата відкриваються перед початком вечірні й залишаються відкритими до відпусту 9-го часу. Також, існує давній звичай в день віддання Пасхи виносити Плащаницю. Про це згадується зокрема й у давніх Київських церковних книгах. Тож, наводимо устав звершення такого Богослужіння. 9-й час звичайний (не пасхальний). На часі – тропар воскресний, глас 5-й: «Співбезпочаткове Слово...» і кондак Неділі про сліпого, глас 4-й: «На душевні очі осліплений...». ВЕЛИКА ВЕЧІРНЯ Після закінчення 9-го часу починається велика вечірня. Очолюючий священник, за традицією, у повному облаченні. Відкривши Царські врата й ставши перед престолом з кадилом в правій руці, та з пасхальним хрестом (мається на увазі напрестольний хрест із зображенням воскреслого Спасителя замість розп’яття та з прикріпленим до нього трисвічником) в лівій, священник творить знак хреста кадилом і виголошує: «Благословен Бог наш...». Співці: «Амінь». Священнослужителі співають: «Христос воскрес із мертвих...» (тричі), співці – той самий тропар (тричі). Священник виголошує стихи «Нехай воскресне Бог...» та іншу почерговість пасхального початку, відповідно кадячи чотири сторони Престолу, вівтар, іконостас та присутніх. Велика ектенія. Кафизми немає. На «Господи, взиваю» (псалми співаються) стихири воскресні 1-го гласу: «Вечірні наші молитви прийми...» та ін. (див. Октоїх, глас 1-й, у суботу ввечері) – на 6. «Слава, і нині» – догматик, глас той самий: «Всесвітню славу...». Вхід з кадилом. «Світло тихе» (співається). Прокимен великий, глас 7-й: «Хто Бог великий, як Бог наш...» зі стихами (див. Тріодь, у Неділю Пасхи ввечері). Ектенія сугуба: «Промовмо всі...». «Сподоби, Господи...» (співається). Ектенія прохальна: «Доповнімо вечірню молитву...» і головоприклонна молитва. На стиховні співається одна стихира воскресна, глас 1-й: «Стражданням Твоїм, Христе...» (див. Октоїх, глас 1-й, у суботу ввечері), потім стихири Пасхи, глас 5-й, зі стихами: «Нехай воскресне Бог...». «Слава, і нині» – Пасхи, глас той самий: «Воскресіння день...». Під час співу останньої стихири священник тричі обкаджує Престіл з Плащаницею. Коли починають співати тропар Пасхи, священник підіймає з престолу Плащаницю і виносить її через північні двері. Примітка! Якщо у храмі, як для винесення, так і для служіння на ній Літургії, використовується одна і та ж Плащаниця, то священик бере цю Плащаницю з Престолу. Якщо ж для винесення використовується спеціальна виносна Плащаниця, то ще перед вечірнею священик покладає її на Престіл поверх Антимінса, а зверху кладе покрівець і Євангеліє. Ця виносна Плащаниця виноситься на середину храму, а напрестольна так і залишається на Престолі. При соборному служінні настоятель іде під Плащаницею, несучи над головою Євангеліє. Якщо священник один, але у співслужінні диякона, Євангеліє благоговійно несе у лівій руці диякон, тримаючи у правій кадило. Якщо ж немає й диякона, священник передає Євангеліє, загорнуте у плат, комусь із благочестивих мирян. В таких випадках Євангеліє несуть перед Плащаницею. Якщо священник один, то, винісши Плащаницю на середину храму, передає її благоговійним мирянам, а сам бере Євангеліє і стає з ним під Плащаницю. Відбувається хресний хід навколо храму. Попереду несуть ікону Воскресіння. Під час хресного ходу багаторазово співається тропар Пасхи, і дзвонять тридзвоном. Після входу в храм Плащаницю покладають на гробницю (Плащаницю не підносять до Царських врат, як у Велику Суботу; «Премудрість! Станьмо побожно!» не виголошується). На Плащаницю кладеться покрівець і Євангеліє, не закриваючи лик Спасителя. Здійснюється кадіння навколо Плащаниці (тричі). В цей час все ще співається тропар Пасхи. Поцілувавши Плащаницю, священнослужителі заходять у вівтар. Диякон: «Премудрість». Співці: «Благослови». Священник: «Сущий благословенний...». Співці: «Амінь. Утверди, Боже...». Священнослужителі співають: «Христос воскрес із мертвих, смертю смерть подолав», а співці продовжують: «І тим, що в гробах, життя дарував». Священник з пасхальним хрестом творить відпуст: «Христос, що воскрес із мертвих, смертю смерть подолав...». Після цього осіняє пасхальним хрестом три сторони, голосно виголошуючи при кожному осіненні: «Христос воскрес!». Всі відповідають: «Воістину воскрес!». На завершення, за звичаєм (замість многоліття), співають тропар «Христос воскрес із мертвих...» (тричі), а в кінці – «І нам дарував життя вічне, поклоняємось Його триденному Воскресінню». Звершується послідування пасхального часу за мале повечір’я. Царські врата не закриваються. РАННЯ. Перед Ранньою звершується послідування пасхального часу за опівнічницю. Ця Рання, за традицією, звершується перед Плащаницею. Очолюючий священник, за традицією, у повному облаченні. Священник з пасхальним хрестом і кадилом перед Плащаницею виголошує: «Слава Святій, Єдиносущній...». Співається пасхальний початок – тропар: «Христос воскрес із мертвих...» зі стихами і кадінням (як на початку Вечірні). Велика ектенія. Відразу після ектенії співається канон Пасхи: «Воскресіння день...». На «Слава» та на «І нині» співаються Богородичні пасхального канону. Примітка. З благословення настоятеля до канону Пасхи можна додати й канон передсвята Вознесіння, глас 5-й: «Вгору до Отця Христос сходить...». В такому випадку всі тропарі канону передсвята також варто співати. Тоді, перед Богородичними пасхального канону приспів «Пресвята Богородице, спаси нас», а перед тропарями канону передсвята «Слава Тобі, Боже наш, слава Тобі». Катавасія після кожної пісні – ірмос відповідної пісні і «Христос воскрес із мертвих...» тричі поскору. Мала ектенія тільки після 3-ї, 6-ї і 9-ї пісень. Кадіння, за традицією, на 1-й, 4-й, 7-й і 9-й піснях канону. Після 3-ї пісні – іпакої Пасхи, глас 4-й: «Світання попередивши...». Після 6-ї пісні – кондак Пасхи, глас 8-й: «Хоч і до гробу...», та ікос, глас той самий. «Воскресіння Христове бачивши...» і «Воскрес Ісус із Гробу...» – по тричі. Після 8-ї пісні диякон перед Плащаницею, творячи кадилом знакХреста, виголошує: «Величає душа моя Воскреслого...», співці: «Світися, світися...» і 9-у пісню з приспівами. Звершується кадіння всього храму. Після 9-ї пісні – екзапостиларій Пасхи: «Тілом заснувши...» (тричі). «Все, що дише...» і хвалітні псалми (псалми співаються повністю). На хвалітніх стихири воскресні (див. Тріодь на Ранній у Неділю Пасхи), глас 1-й – 4, і стихири Пасхи, глас 5-й (зі своїми стихами). «Слава, і нині» – Пасхи, глас той самий: «Воскресіння день...» та «Христос воскрес із мертвих...» один раз, як закінчення стихири і відразу тричі, як тропар в кінці Ранньої. Тут знову може відбуватись хресний хід з Плащаницею, якщо забажає настоятель. Священнослужителі заходять у вівтар. Ектенії потрійна й прохальна. Диякон: «Премудрість». Співці: «Благослови». Священник: «Сущий благословенний...». Співці: «Амінь. Утверди, Боже...». Священнослужителі співають: «Христос воскрес із мертвих, смертю смерть подолав», а співці продовжують: «І тим, що в гробах, життя дарував». Відпуст з пасхальним хрестом і закінчення богослужіння, як вказано в кінці вечірні. Співається пасхальний 1-й час. Царські врата залишаються відкритими. ЛІТУРГІЯ. Молитовне правило до причастя – як у Світлий тиждень. Вхідні молитви (як і всі інші Літургійні дії, такі як малий та великий вхід, замвонна молитва, та ін.) звершуються перед Плащаницею. Перед Літургією співаються пасхальні часи 3-й і 6-й. Літургіязвершується за Пасхальним чином. Пасхальний початок. Антифони Пасхи. Вхідний: «В церквах благословляйте Бога, Господа від джерелІзраїлевих». Після входу – тропар Пасхи, глас 5-й: «Христос воскрес із мертвих...» (один раз); іпакої Пасхи, глас 4-й: «Світання попередивши...»; «Слава, і нині» – кондак Пасхи, глас 8-й: «Хоч і до Гробу...». Замість Трисвятого – «Всі, що в Христа хрестилися...». Прокимен, глас 8-й: «Цей день, що його створив Господь, радіймо й веселімось в нім», стих: «Прославляйте Господа, бо Він благий, бо повіки милість Його». Апостол – дня (рядовий): Дії., 41 зач., XVIII, 22-28. Аллилуарій, глас 4-й: «Ти, Господи, воскрес, ущедривши Сион»; стих: «Господь з неба на землю наглянув». Євангеліє – дня (рядове): Ін., 43 зач., XII, 36-47. Задостойник Пасхи: «Ангел звістив...». Причасний Пасхи: «Тіло Христове...». Замість «Благословен, хто йде...», «Ми бачили Світло Істинне...» і «Нехай сповняться...» співається по одному разу тропар Пасхи: «Христос воскрес із мертвих...». Замість «Нехай буде ім’я Господнє...» – «Христос воскрес із мертвих...» (тричі). Священник: «Благословення Господнє на вас...». Чин віддання Пасхи Чином віддання Пасхи є особливий пасхальний молебень із занесенням Плащаниці. Наприкінці Літургії, після виголосу «Благословення Господнє на вас...» священннослужителі виходять до Плащаниці і співають тричі «Христос воскрес із мертвих...» і далі пасхальний початок з кадінням. Далі – канон Пасхи без повторень, без Богородичних і без катавасії. Кожна пісня завершується триразовим «Христос воскрес із мертвих...». Кадіння звершується на 1-й, 4-й, 7-й і 9-й піснях. Після 3-ї пісні – коротка потрійна ектенія (та, що на двопсалмії); іпакої: «Світання попередивши...». Після 6-ї пісні – тричі поскору; мала ектенія; кондак та ікос Пасхи. Після цього – прокимен, глас 5: «Цей день, що його створив Господь, радіймо й веселімось в нім», стих: «Прославляйте Господа, бо Він благий, бо повіки милість Його». «Все, що дише...» та ін.. Євангеліє від Луки, зачало 114. «Воскресіння Христове бачивши...» і «Воскрес Ісус із Гробу...» по одному разу. Далі 7-ма пісня. Після 8-ї пісні диякон, творячи перед Плащаницею кадилом знак Хреста, виголошує: «Величай, душе моя, Воскреслого...» і співається 9-та пісня. Після 9-ї пісні – приспів «Ангел звістив...» та ірмос «Світися...»; «Христос воскрес із мертвих...» тричі поскору; мала ектенія; екзапостиларій Пасхи: «Плоттю заснувши...» один раз. Потім – «Нехай воскресне Бог...» і стихири Пасхи. «Слава, і нині» – «Воскресіння день...». Під час співу останньої стихири священник тричі обкаджує Плащаницю, а потім, під спів «Христос воскрес із мертвих...», взявши Плащаницю, звершується Хресний хід навколо храму, як на вечірні. Повернувшись до храму, Плащаницю заносять у вівтар через Царські врата і кладуть на Престіл. Після останнього співу «Христос воскрес із мертвих...» співають іпакої Пасхи: «Світання попередивши...»; «Слава, і нині» – кондак Пасхи: «Хоч і до Гробу...», в цей час священик тричі кадить навколо Престіл з Плащаницею. Після цього потрійна ектенія, як на молебні: «Помилуй нас, Боже...». Священик співає: «Христос воскрес із мертвих, смертю смерть подолав», а співці продовжують: «І тим, що в гробах, життя дарував». І відпуст Літургії, як вказано в кінці вечірні. Царські врата залишаються відкритими до відпусту 9-го часу. 9-й ЧАС Пасхальний час 9-й звершується безпосередньо перед Всенічним Бдінням (або перед малою Вечірнею, якщо така служиться). Священник повинен стояти перед Престолом у фелоні. Відпуст – великий, звершується з пасхальним хрестом, як на вечірні. Цим підкреслюється остаточне завершення пасхального періоду й припинення використання пасхальної атрибутики. Після триразового привітання «Христос воскрес» з благословенням співці востаннє тричі співають тропар «Христос воскрес із мертвих...». Під час співу «І нам дарував життя вічне...» Царські врата зачиняються. З цього часу пасхальні піснеспіви припиняються. До початку Всенічного Бдіння, або малої Вечірні, якщо вона звершується, священник тричі кадить навколо престолу Плащаницю, потім, співаючи тропар і кондак Вознесіння, забирає її (їх) з Престолу і покладає на те місце у вівтарі чи ризниці, де вона зберігається протягом року."}]},
{"date":"05-21","weekday":"четвер","title":"ВОЗНЕСІННЯ ГОСПОДНЄ. Рівноапп. імператора Костянтина (337) і матері його імператриці Олени (327). Блгв. кн. Костянтина (1129) та дітей його Михаїла і Федора, Чернігівських і Муромських чудотворців. Мучеників, що в долині Ферейдан (Іран) від персів постраждали (XVII) (Груз.) (перехідне свято в день Вознесіння Господнього).","readings":["Ран. – Мк., 71 зач., XVI, 9 – 20.","Літ. – Діян., 1 зач., I, 1 – 12. Лк., 114 зач., XXIV, 36 – 53.","Рівноапп.: Гал., 200 зач., I, 11 – 19. Ін., 35 зач. (від половини), X, 1 – 9 (апостол і Євангеліє рівноапостольним, читається лише у храмах на честь цих святих)."],"notes": "На ранній величання: «Величаємо Тебе, Життєдавче Христе, і шануємо на небеса з пречистою Твоєю плоттю Божественне вознесіння». Після Євангелія – «Воскресіння Христове бачивши...». Замість «Чеснішу...» співаються приспіви свята. 1-й приспів: «Величай, душе моя, Христа Життєдавця, Який вознісся від землі на Небо». На Літургії антифони свята. Вхідний стих: «Зійшов Бог при окликах радості, Господь – при звуках сурмних». Після вхідного стиха відразу співається тропар свята, «Слава і нині» – кондак свята, а на архієрейській Літургії після вхідного стиха співається: «Прийдіть, поклонімось... спаси нас, Сину Божий, що вознісся у славі...», а тоді тропар і кондак. Співається Трисвяте. Замість «Достойно...» – «Величай, душе моя... Тебе, вищу розуму...». Замість «Ми бачили Світло істинне...» – «Вознісся ти у славі...» (до віддання). Увечері на свято відправляється вечірня із входом і великим прокимном. Всенічне бдіння свята Вознесіння Господнього звершується за Тріоддю. Служба рівноапп імператора Костянтина і матері його імператриці Олени переноситься на інший день.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ кафізми немає («Блажен муж» не співається). На «Господи, взиваю» стихири свята, глас 6-ий – 10 (кожна стихира – двічі). «Слава, і нині» – свята, глас той самий: «Від лона Отчого...». Вхід. Прокимен дня. Паремії свята – 3. На літії стихири свята, глас 1-ий і глас 4-ий. «Слава, і нині» – свята, глас 4-ий: «Господи, таїнство від віків...». На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 6-ий: «Зійшов Бог...». Після Трисвятого – тропар свята, глас 4-ий: «Вознісся Ти у славі...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята, глас 4-ий: «Вознісся Ти у славі...» (двічі). «Слава, і нині» – той самий тропар. Кафізми 13-та і 14-та. Малі ектенії. Після 1-ої кафізми – сідальний свята, глас 1-ий: «Ангели дивувалися...». «Слава, і нині» – той самий сідальний. Після 2-ої кафізми – сідальний свята, глас 3-ій: «Предвічний Бог...». «Слава, і нині» – той самий сідальний. Полієлей. Величання свята: «Величаємо Тебе, / Життєдавче Христе, / і шануємо на небеса / з пречистою Твоєю Плоттю // Божественне вознесіння» і вибранний псалом свята. Сідальний свята після полієлея, глас 5-ий: «Той, Хто зійшов з небес...». «Слава, і нині» – той самий сідальний. Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Зійшов Бог при окликах радости, Господь – при звуках сурмних». Стих: «Всі народи, заплещіть руками, викликніть Богові голосом радости». Євангеліє – Мк., зач. 71. «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира свята, глас 6-ий: «Днесь на небесах...». Канони: свята 1-ий, глас 5-ий, з ірмосом на 8 (ірмоси по двічі) і 2-ий, глас 4-ий, з ірмосом на 6 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія П’ятдесятниці, глас 4-ий: «Божественним покритий мороком...». Після 3-ої пісні – сідальний свята, глас 8-ий: «Сівши на хмари...». «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак свята, глас 6-ий: «Сповнивши наше спасіння...» та ікос, глас той самий: «Ті, що земне для землі залишили...». На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспіви свята. Перший приспів: «Величай, душе моя, Христа Життєдавця, що вознісся від землі на Небо». Після 9-ої пісні «Достойно є» не співається. Світильний свята (тричі). «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 1-ий – 4 (перша стихира двічі). «Слава, і нині» – свята, глас 2-ий: «Народився Ти...». Велике славослів’я. Після Трисвятого – тропар свята, глас 4-ий: «Вознісся Ти у славі...» (один раз). Ектенії і відпуст: «Христос, істинний Бог наш, що у славі вознісся від нас на Небо і сів праворуч Бога і Отця, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як Благий і Людинолюбний»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони свята. Вхідний стих: «Зійшов Бог при окликах радости, Господь – при звуках сурмних». Примітка. Перед виголошенням вхідного стиха слід виголошувати «Премудрість, станьмо побожно». Після входу – тропар свята. «Слава, і нині» – кондак свята. Співається Трисвяте. Прокимен, глас 7-ий: «Вознесися на Небеса, Боже, і по всій землі слава Твоя». Стих: «Готове серце моє, Боже...». Апостол – Діян., зач. 1. Алилуарій, глас 2-ий: «Зійшов Бог при окликах радости, Господь – при звуках сурмних». Стих: «Всі народи заплещіть руками...». Євангеліє – Лк., зач. 114. Задостойник свята – приспів та ірмос 9-ої пісні канону свята: «Тебе вищу розуму...» (і до віддання). Причасний свята: «Зійшов Бог при окликах радости, Господь – при звуках сурмних». Замість «Ми бачили Світло Істинне...» в період від свята Вознесіння до його віддання, за традицією, співається тропар Вознесіння."}]},
{"date":"05-22","weekday":"п’ятниця","title":"Мч. Василіска (бл. 308). Пам’ять ІІ Вселенського собору (381). Мч. Іоана-Володимира, кн. Сербського (1015).","readings":["Діян., 42 зач., XIX, 1 – 8. Ін., 47 зач., XIV, 1 – 11."],"notes":"З цього дня на ранній, коли співається велике славослів’я, катавасія «Спасителю Богу...», крім 7-ої неділі після Пасхи і віддання Вознесіння. На Літургії після входу у будні дні до віддання: «Прийдіть, поклонімось... спаси нас, Сину Божий, що вознісся у славі...». Прокимен, алилуарій і причасний свята (до віддання). Служба мученика Василіска не має святкового знаку, звершується зі службою післясвята Вознесіння (за Тріоддю).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ кафізми немає. На «Господи, взиваю» стихири на 6: свята, глас 6-ий – 3 і мученика, глас 4-ий – 3. «Слава, і нині» – свята, глас 2-ий: «Народився Ти...». Вхід. Прокимен великий, глас 7-ий: «Бог наш на небесах і на землі...» з приспівами. Ектенія потрійна: «Промовимо всі...», «Сподоби, Господи...», ектенія прохальна: «Доповнимо вечірню молитву...» і голововклонна молитва. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава,І нині» – свята, глас 6-ий: «Зійшов Бог при окликах...». Після Трисвятого – тропар свята, глас 4-ий. «Премудрість» – «Благослови» та інше. Відпуст свята."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар Вознесіння, глас 4-ий (двічі), , «Слава, і нині» – тропар Вознесіння. Кафізми 19-та і 20-та. Малі ектенії. Сідальні свята з Тріоді (по двічі). Псалом 50-й. Канони: свята Вознесіння 1-ий з ірмосом на 8 (ірмоси по двічі),мученика на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мученика. Після 3-ої пісні – кондак мученика, глас 8-ий, «Слава» – сідальний мученика, глас 1-ий, «І нині» – сідальний Вознесіння, глас 8-ий: «Сівши на хмари небесні...». Після 6-ої пісні – кондак і ікос свята, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята (тричі). «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 5-ий: «Господи, вознісся Ти...». Після Трисвятого – тропар Вознесіння."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Вознесіння. Кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з 1-го канону свята Вознесіння, пісня 1-ша – 6 (з ірмосом). На вході – «...вознісся у славі...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, «Слава, і нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, «Слава, і нині» – кондак свята. В храмі святого – тропар свята, тропар храму, «Слава, і нині» – кондак свята. Прокимен, алилуарій та причасний – свята. Апостол і Євангеліє – дня. Задостойник Вознесіння."}]},
{"date":"05-23","weekday":"субота","title":"Прп. Михайла, спов., єп. Синадського (821). Прмч. Михаїла, ченця (ІХ). Знайдення мощів свт. Леонтія Києво-Печерського, єп. Ростовського (1164). Прп. Єфросинії, ігум. Полоцької (1173).","readings":["Діян., 43 зач., XX, 7 – 12. Ін., 48 зач., XIV, 10 – 21."],"notes":"Служба свт. Леонтія шестерична, звершується зі службою післясвята Вознесіння (за Тріоддю).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ Кафизма 18-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3 і святого, глас 5-ий – 3. «Слава, і нині» – свята, глас 6-ий: «Господи, звершивши таїнство провидіння...». Вхід. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 6-ий: «Зійшов Бог при окликах радосі...». Після Трисвятого – тропар святителя, глас 4-ий, «Слава, і нині» – тропар свята, глас той самий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (двічі), «Слава» – тропар святителя, «І нині» – тропар свята. Кафізми 16-та і 17-та. Примітка. Повне кадіння храму під час читання 17-ої кафізми.. Малі ектенії. Після 1-ої кафізми – сідальний свята, глас той самий: «Ангели дивувалися незвичайному зшестю...», «Слава, і нині», сідален той самий. Після 2-ої кафізми – сідальний свята, глас 1-ий: «Пекло полонив Ти...», «Слава, і нині», сідальний той самий. Псалом 50-ий. Канони: свята 2-ий, глас 4-ий, з ірмосом на 6 (ірмоси по двічі) і святителя на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-оі, 6-ої, 8-ої і 9-ої піснях – ірмоси канону святителя. Після 3-ої пісні – кондак і ікос святителя, глас 4-ий, сідальний святителя, глас 8-ий, «Слава, і нині» – сідальний свята, глас 8-ий: «Сівши на хмари...». Після 6-ої пісні – кондак і ікос Вознесіння, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята Вознесіння, «Слава», світильний святителя, «І нині» – святилен свята.. «Хваліте Господа з небес..» і хвалітні псалми. Чиатається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 5-ий: «Господи, вознісся Ти...». Після Трисвятого – тропар святителя, «Слава, і нині» – тропар свята."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святителя. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з 2-го канону свята, пісня 3-тя – 4 (з ірмосом) та пісня 6-та – 4. На вході – «...вознісся у славі...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, тропар святителя, «Слава, і нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, тропар святителя, «Слава, і нині» – кондак свята. В храмі святого – тропар свята, тропар храму, тропар святителя, «Слава» – кондак храму, «І нині» – кондак свята. Прокимен, алилуарій та причасний – свята. Апостол і Євангеліє – дня. Задостойник Вознесіння."}]},
{"date":"05-24","weekday":"неділя","title":"7-ма неділя після Пасхи, святих отців І Вселенського собору. Глас 6-й. Прп. Симеона стовпника на Дивній горі (596). Мчч. Мелетія Стратилата, Стефана, Іоана, Серапіона, єгиптянина, Калиника, волхва, Федора і Фавста та з ними 1218 воїнів з дружинами і дітьми (218).","glas":6,"readings":["Ран. – Єв. 10-е, Ін., 66 зач., XXI, 1 – 14.","Літ. – Діян., 44 зач., XX, 16 – 18, 28 – 36. Ін., 56 зач., XVII, 1 – 13."],"notes":"На ранній катавасія «Божественним покритий...», співаємо «Чеснішу». На Літургії після входу тропар воскресний, Вознесіння і отцям, «Слава...» кондак отцям, «І нині...» – кондак Вознесіння. Прокимен, Апостол, алилуарій і Євангеліє отцям. Задостойник свята. Причасний «Хваліть Господа...» і «Радуйтеся, праведні...». Воскресна служба звершується разом зі службами післясвята Вознесіння і святих отців (за Тріоддю).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафізма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 6-ий – 3, свята, глас той самий – 3, і отців, глас той самий – 4. «Слава» – отців, глас той самий: «Таємничі сурми Духа...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії отців – 3. На літії стихира свята, глас 1-ий: «Піднісшись на небеса...». «Слава» – отців, глас 3-ій: «Ви, святі отці, були охоронителями апостольських передань...», «І нині» – свята, глас 6-ий: «Господи, звершивши провидіння таїнство...». На стиховні стихири воскресні, глас 6-ий зі своїми приспівами. «Слава» – отців, глас 4-ий: «Молитовну пам’ять...», «І нині» – свята, глас той самий: «Господи, таїнство від віків...». Після Трисвятого – тропар отців, глас 8-ий: «Препрославлений Ти, Христе Боже наш...» (двічі), і тропар свята, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 6-ий (двічі). «Слава» – тропар отців, глас 8-ий, «І нині» – тропар свята, глас 4-ий. Кафізми 2-га і 3-тя. Малі ектенії. Сідальні воскресні з Тріоді. Непорочні. «Ангельський собор...». Іпакої, глас 6-ий: «Вільною і животворчою Твоєю смертю, Христе...». Степенний – антифони 6-го гласу. Прокимен, глас 6-ий: «Господи, підніми силу Твою...». Євангеліє воскресне 10-те. «Воскресіння Христове бачивиши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси один раз), свята Вознесіння 1-ий на 4 і отців на 6. Біблійні пісні «Співаймо Господеві...». Катавасія П’ятдесятниці: «Божественним покритий мороком...». Після 3-ої пісні – кондак і ікос Вознесіння, глас 6-ий; сідальний отців, глас 4-ий, «Слава» – інший сідальний отців, глас той самий, «І нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак і ікос отців, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 10-ий (див. в Тріоді). «Слава» – світильний отців, «І нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 6-ий – 4, і отців, глас той самий – 4 (перша – двічі) з приспівами до двох останніх стихир: «Благословенний Ти, Господи Боже отців наших, і хвальне і прославлене Ім’я Твоє повіки» і «Зберіть до Мене святих Моїх, що вступили в завіт зі Мною при жертві». «Слава» – отців, глас 8-ий: «Святих отців Собор...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...». Відпуст воскресний: «Христос, що воскрес із мертвих...». Перед 1-им часом на «Слава, і нині» – стихира євангельська 10-та, глас 6-ий: «Після Твого зішестя...» (див. в Тріоді)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – На 1-му і 6-му часі – тропар воскресний. «Слава» – тропар свята. Кондак отців. На 3-му і 9-му часі – тропар воскресний. «Слава» – тропар отців. Кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4 (див. в Тріоді), 1-го канону свята Вознесіння, пісня 4-та – 4, і отців, пісня 6-та – 4. На вході – «...що воскрес із мертвих...». Після входу – тропар воскресний, тропар Вознесіння, тропар отців. «Слава» – кондак отців, «І нині» – кондак Вознесіння. Прокимен – пісня отців, глас 4-ий: «Благословенний Ти, Господи Боже отців наших...». Стих: «Бо праведний Ти у всьому, що створив». Апостол і Євангеліє – Неділі 7-ої після Пасхи. Алилуарій, глас 1-ий: «Бог богів, Господь, промовив...». Стих: «Зберіть до Мене святих Моїх...». Задостойник Вознесіння. Причасний воскресний: «Хваліте Господа з Небес...», і отців: «Радуйтеся, праведні...». Відпуст воскресний: «Христос, що воскрес із мертвих...»."}]},
{"date":"05-25","weekday":"понеділок","title":"7-й тиждень після Пасхи. Третє знайдення глави Предтечі і Хрестителя Господнього Іоана (бл. 850). Сщмч. Ферапонта, єп. Кіпрського (ІV). Свт. Інокентія, архієп. Херсонського (1857).","readings":["Ран. – Лк., 31 зач., VII, 17 – 30.","Літ. – Діян., 45 зач., XXI, 8 – 14. Ін., 49 зач., XIV, 27 – XV, 7.","Предтечі: 2 Кор., 176 зач., IV, 6 – 15. Мф., 40 зач., XI, 2 – 15."],"notes":"Служба знайдення глави Предтечі Господього Іоана полієлейна, звершується зі службою післясвята Вознесіння (за Тріоддю).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: свята, глас 6-ий – 3 і Предтечі, глас 8-ий – 5 (перша та друга стихири – двічі). «Слава» – Предтечі, глас 6-ий: «Скарб Божественних дарів...», «І нині» – свята, глас 6-ий: «Від лона Отчого...». Вхід. Прокимен дня. Паремії Предтечі – 3. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава» – Предтечі, глас той самий: «Як Божественне провидіння...», «І нині» – свята, глас 6-ий: «Зійшов Бог при окликах радості...». Після Трисвятого – тропар Предтечі, глас 4-ий, «Слава, і нині» – тропар свята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (двічі), «Слава» – тропар Предтечі, «І нині» – тропар свята. Кафізми 4-та і 5-та. Малі ектенії. Після 1-ої кафізми – сідальний Предтечі, глас 4-ий: «Із землі засяявши...» (двічі). «Слава, і нині» – сідальний свята, глас 1-ий: «Ангели дивувалися незвичайному...». Після 2-ої кафізми – сідальний Предтечі, глас 4-ий: «Виокремилась, як золото від руди...» (двічі). «Слава, і нині» – сідальний свята, глас 3-ій: «Превічний Бог і безначальний...». Полієлей. Величання Предтечі і вибраний псалом. Після полієлея сідальний Предтечі, глас 4-ий: «Ірод беззаконня чинив...» (двічі). «Слава, і нині» – сідальний Вознесіння, глас 5-ий: «Той, Хто зійшов з небес на землю...» (див. після полієлея на ранній у сам день свята). Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Там вирощу ріг Давидові...». Стих: «Пом’яни, Господи, Давида...». Євангеліє Предтечі (Лк, зач. 31). Після 50-го псалма: «Слава» – «Молитвами Предтечі і Хрестителя Господього Іоана...». Стихира Предтечі, глас 6-ий: «Та, що спочатку на блюді викрила...». Канони: свята Вознесіння 2-ий, глас 4-ий, з ірмосом на 6 (ірмоси по двічі) і Предтечі на 8. Біблійні пісні «Співаймо Господеві...». Катавасія Вознесіння, глас 5-ий: «Спасителю Богу...». Після 3-ої пісні – кондак і ікос свята, глас 6-ий, сідальний Предтечі, глас 4-ий (двічі). «Слава, і нині» – сідальний свята, 8-ий. Після 6-ої пісні – кондак і ікос Предтечі, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний Предтечі, «Слава» інший сідальний Предтечі, «І нині» – свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: свята, глас 6-ий – 3 (див. на стиховні ранньої) і Предтечі, глас 5-ий – 3. «Слава» – Предтечі, глас 6-ий: «Всечесну главу Хрестителя Твого...», «І нині» – свята, глас 6-ий: «Від лона Отчого Ти не відлучався» (див. на стиховні ранньої). Велике славослів’я. Після Трисвятого – тропар Предтечі, «Слава, і нині» – тропар свята."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар Предтечі. Кондаки свята і Предтечі чергуються."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з 2-го канону свята, пісня 7-ма – 4 (з ірмосом) та Предтечі, пісня 3-тя – 4. На вході – «...вознісся у славі...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, тропар Предтечі, «Слава» – кондак Предтечі, «І нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, тропар Предтечі, «Слава» – кондак Предтечі, «І нині» – кондак свята. В храмі святого – тропар свята, тропар храму, тропар Предтечі, кондак храму, «Слава» – кондак Предтечі, «І нині» – кондак свята. Прокимен, алилуарій та причасний – свята і Предтечі. Апостол і Євангеліє – дня і Предтечі. Задостойник Вознесіння."}]},
{"date":"05-26","weekday":"вівторок","title":"Апп. від 70-х Карпа й Алфея (І). Мч. Аверкія та мц. Олени (І). Прп. Іоана Психаїта, сповідника (ІХ). Мч. Георгія Нового (1515).","readings":["Діян., 46 зач., XXI, 26 – 32. Ін., 53 зач., XVI, 2 – 13."],"notes":"Служба апп. Карпа й Алфея не має святкового знаку, звершується зі службою післясвята Вознесіння (за Тріоддю).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 6-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3 і апостола, глас 1-ий – 3. «Слава, і нині» – свята, глас 4-ий: «Коли прийшов Ти, Христе...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 4-ий: «Впале єство Адамове...». Після Трисвятого – тропар апостола, глас 3-ій, «Слава, і нині» – тропар свята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (двічі), «Слава» – тропар апостола, «І нині» – тропар свята. Кафізми 7-ма і 8-ма. Малі ектенії. Сідальні свята з Тріоді (по двічі). Псалом 50-й. Канони: свята Вознесіння 1-ий з ірмосом на 8 (ірмоси по двічі), і апостола на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону апостола. Після 3-ої пісні – кондак апостола, глас 4-ий, сідальний апостола, глас 3-ій, «Слава, і нині» – сідальний Вознесіння, глас 8-ий: «Сівши на хмари небесні...». Після 6-ої пісні – кондак і ікос свята, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний апостола. «Слава, і нині» – світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 4-ий: «Коли вознісся Ти у славі, Христе Боже...». Після Трисвятого – тропар апостола, «Слава, і нині» – тропар свята."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Вознесіння. «Слава» – тропар апостола. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з 1-го канону свята Вознесіння, пісня 6-та – 6 (з ірмосом). На вході – «...вознісся у славі...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, тропар апостола, «Слава» – кондак апостола, «І нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, тропар апостола, «Слава» – кондак апостола, «І нині» – кондак свята. В храмі святого – тропар свята, тропар храму, тропар апостола, кондак храму, «Слава» – кондак апостола, «І нині» – кондак свята. Прокимен, алилуарій та причасний – свята. Апостол і Євангеліє – дня. Задостойник Вознесіння."}]},
{"date":"05-27","weekday":"середа","title":"Сщмч. Ферапонта, єп. Сардійського (ІІІ). Мц. Феодори, діви, і мч. Дидима, воїна (304). Знайдення мощів свтт. Київських: Кипріана та Фотія (1472). Прав. Іоана Русина, сповідника (1730). Прп. Додо Давидо-Гареджийського (596, Груз.) (перехідне святкування в середу після Вознесіння).","readings":["Діян., 47 зач., XXIII, 1 – 11. Ін., 54 зач., XVI, 15 – 23."],"notes":"Служба прав. Іоана Русина шестерична, звершується зі службою післясвята Вознесіння (за Тріоддю).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3 і праведного, глас 4-ий – 3. «Слава» – праведного, глас 1-ий: «Як не похвалити нам...», «І нині» – свята, глас 4-ий: «Коли прийшов Ти, Христе...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава» – праведного, глас 6-ий: «Маючи благий помисел...», «І нині» – свята, глас 4-ий: «Впале єство Адамове...». Після Трисвятого – тропар праведного, глас 4-ий, «Слава, і нині» – тропар свята, глас той самий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (двічі), «Слава» – тропар праведного, «І нині» – тропар свята. Кафізми 10-та і 11-та. Малі ектенії. Сідальні свята з Тріоді (по двічі). Псалом 50-й. Канони: свята Вознесіння 1-ий з ірмосом на 6 (ірмоси по двічі), і праведного на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону праведного. Після 3-ої пісні – кондак і ікос праведного, глас 8-ий інший кондак праведного, глас 4-ий, «Слава» – сідальний праведного, глас 4-ий, «І нині» – сідальний Вознесіння, глас 8-ий: «Сівши на хмари небесні...». Після 6-ої пісні – кондак і ікос свята, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний праведного. «Слава, і нині» – світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 4-ий: «Коли вознісся Ти у славі, Христе Боже...». Після Трисвятого – тропар праведного, «Слава, і нині» – тропар свята."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Вознесіння. «Слава» – тропар праведного. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з 1-го канону свята Вознесіння, пісня 6-та – 6 (з ірмосом). На вході – «...вознісся у славі...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, тропар праведного, «Слава» – кондак праведного, «І нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, тропар праведного, «Слава» – кондак праведного, «І нині» – кондак свята. В храмі святого – тропар свята, тропар храму, тропар праведного, кондак храму, «Слава» – кондак праведного, «І нині» – кондак свята. Прокимен, алилуарій та причасний – свята. Апостол і Євангеліє – дня. Задостойник Вознесіння."}]},
{"date":"05-28","weekday":"четвер","title":"Прп. Микити, спов., єп. Халкідонського (ІХ). Сщмч. Євтихія, єп. Мелітинського (І), Мц. Єликониди (244). Сщмч. Елладія, єпископа (VІ – VІІ).","readings":["Діян., 48 зач., XXV, 13 – 19. Ін., 55 зач., XVI, 23 – 33."],"notes":"Служба прп. Микити не має святкового знаку, звершується зі службою післясвята Вознесіння (за Тріоддю).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 12-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3 і преподобного, глас той самий – 3. «Слава, і нині» – свята, глас 6-ий: «Зійшов Бог при окликах радости...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 1-ий: «Піднісшись на небеса, звідкіля і зійшов Ти...». Після Трисвятого – тропар преподобного, глас 4-ий, «Слава, і нині» – тропар свята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (двічі), «Слава» – тропар преподобного, «І нині» – тропар свята. Кафізми 13-та і 14-та. Малі ектенії. Сідальні свята з Тріоді (по двічі). Псалом 50-й. Канони: свята Вознесіння 1-ий з ірмосом на 8 (ірмоси по двічі), і преподобного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону преподобного. Після 3-ої пісні – кондак преподобного, глас 8-ий, сідальний преподобного, глас 4-ий, «Слава, і нині» – сідальний Вознесіння, глас 8-ий: «Сівши на хмари небесні...». Після 6-ої пісні – кондак і ікос свята, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 7-ий: «Прийшов Ти на гору Єлеонську...». Після Трисвятого – тропар преподобного, «Слава, і нині» – тропар свята."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Вознесіння. «Слава» – тропар преподобного. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з 1-го канону свята Вознесіння, пісня 8-та – 6 (з ірмосом). На вході – «...вознісся у славі...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, тропар преподобного, «Слава» – кондак преподобного, «І нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, тропар преподобного, «Слава» – кондак преподобного, «І нині» – кондак свята. В храмі святого – тропар свята, тропар храму, тропар преподобного, кондак храму, «Слава» – кондак преподобного, «І нині» – кондак свята. Прокимен, алилуарій та причасний – свята. Апостол і Євангеліє – дня. Задостойник Вознесіння."}]},
{"date":"05-29","weekday":"п’ятниця","title":"Віддання свята Вознесіння Господнього. Мц. Феодосії, діви Тирської (307 – 308). Пам’ять І Вселенського собору (325). Прмч. Феодосії, діви (726 – 730). Ікон Божої Матері, званих «Споручниця грішних» та «Невтомне Око».","readings":["Діян., 50 зач., XXVII, 1 – 44. Ін., 57 зач., XVII, 18 – 26."],"notes":"Служба за Тріоддю. На ранній катавасія «Божественним покритий...». «Чеснішу...» не співається, а приспіви свята. Співається велике славослів’я. Звершується славослівна служба віддання свята Вознесіння (за Тріоддю). Служба мч. Феодосіі переноситься на повечір’я.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 15-та. На «Господи, взиваю» стихири свята, глас 6-ий – 6 (перша стихира – двічі). «Слава, і нині» – свята, глас той самий: «Від лона Отчого...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 6-ий: «Зійшов Бог...». Після Трисвятого – тропар свята, глас 4-ий: «Вознісся Ти у славі...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята, глас 4-ий: «Вознісся Ти у славі...» (двічі). «Слава, і нині» – той самий тропар. Кафізми 19-та і 20-та. Малі ектенії. Сідальні свята з Тріоді (по двічі). Псалом 50-ий. Канони: свята 1-ий, глас 5-ий, з ірмосом на 8 (ірмоси по двічі) і 2-ий, глас 4-ий, з ірмосом на 6 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія П’ятдесятниці, глас 4-ий: «Божественним покритий мороком...». Після 3-ої пісні – сідальний свята, глас 8-ий. «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак і ікос свята, глас 6-ий. На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспіви свята. Перший приспів: «Величай, душе моя, Христа Життєдавця, що вознісся від землі на Небо». Після 9-ої пісні «Достойно є» не співається. Світильний свята (тричі). «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 1-ий – 4 (перша стихира двічі). «Слава, і нині» – свята, глас 2-ий: «Народився Ти...». Велике славослів’я. Після Трисвятого – тропар свята (один раз). Ектенії і святковий відпуст."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні з обох канонів свята Вознесіння, пісня 9-та – 8 (першого канону – з ірмосом). На вході – «...вознісся у славі...». Після входу – тропар свята. «Слава, і нині» – кондак свята. Прокимен, алилуарій та причасний – свята. Апостол і Євангеліє – дня. Задостойник Вознесіння."}]},
{"date":"05-30","weekday":"субота","title":"Троїцька поминальна субота. Звершуємо пам’ять всіх від віку спочилих православних християн – отців, матерів, братів і сестер наших. Прп. Ісаакія, спов., ігумена обителі Далматської (383).","readings":["Ряд.: Діян., 51 зач., XXVIII, 1 – 31. Ін., 67 зач., XXI, 15 – 25.","Заупокійне: 1 Кор., 163 зач., XV, 47 – 57. Ін., 16 зач., V, 24 – 30."],"notes":"Служба тільки з Тріоді. На вечірні замість прокимна – «Алилуя» із заупокійними стихами. На ранній замість «Бог Господь..» – «Алилуя» із заупокійними стихами. Канон храму і Тріоді (з 2-ю піснею). Катавасія Тріоді. На Літургії «Достойно є...». Замість «Ми бачили світло істинне...» – тропар «Глибиною мудрості...». Служба звершується за Квітною Тріоддю. Примітка. Заупокійна служба Троїцької батьківської суботи, згідно з Типіконом, звершується «у всьому подібно до того, як вказано в суботу м’ясопусну», включаючи співвідношення заупокійних текстів Тріоді зі співанням системи Октоїха. Щорічно Троїцька поминальна субота припадає на один і той самий день періоду співу Квітної Тріоді – суботу 7-го тижня після Пасхи, тому заупокійні піснеспіви Тріоді щорічно з’єднуються зі співами Октоїха 6-го гласу, чинного в дану седмицю.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 18-та. На «Господи, взиваю» стихири на 6: мученичні з Тріоді, глас 6-ий – 3, і заупокійні Тріоді, глас 8-ий – 3. «Слава» – Тріоді, глас той самий: «Плачу і ридаю...», «І нині» – догматик, глас 6-ий: «Хто Тебе не ублажить...». Входу немає. Замість прокимна – «Алилуя», на 8-ий глас, із заупокійними стихами – стих 1-ий: «Блаженні, ті, кого обрав і прийняв ти, Господи»; стих 2-ий: «Пам’ять про них з роду в рід». На стиховні стихири з Тріоді, глас 6-ий (із заупокійними приспівами, див. Тріодь). «Слава» – Тріоді, глас той самий: «Початком і складовою моєї істоти...», «І нині» – Богородичний Тріоді, глас той самий: «Молитвами Тієї, що народила Тебе, Христе...». Після Трисвятого – тропар, глас 8-ий: «Глибиною мудрості...» (один раз). «Слава, і нині» – Богородичний, глас той самий: «Тебе стіну, і пристановище...». Примітка. Після відпусту вечірні за Уставом звершується панахида за спочилими; на ній співається заупокійний канон з Октоїха 6-го гласу (див. в Тріоді)."},{"svc":"РАННІЙ","text":"НА РАННІЙ замість «Бог – Господь» – «Алилуя» на глас 8-ий (зазвичай співається тричі по тричі), із заупокійними стихами: – стих 1-ий: «Блаженні, ті, кого обрав і прийняв ти, Господи»; стих 2-ий: «Пам’ять про них з роду в рід»; стих 3-ій: «Душі їх у блаженстві перебуватимуть». Тропар, глас 8-ий: «Глибиною мудрості...» (двічі). «Слава, і нині» – Богородичний, глас той самий: «Тебе стіну і пристановище...» Кафізма 16-та. Мала ектенія (звичайна, не заупокійна). Сідальні з Тріоді, глас 6-ий. Кафізма 17-та ділиться на дві статті, співається, за Уставом, на 5-ий глас, без «заходу» («Господи, помилуй» (3), «Слава, і нині»). До кожного стиха 1-ої статті додається приспів: «Благословен єси, Господи, навчи мене заповітів Твоїх», до стихів 2-ої статті приспів: «Спасе, спаси мене». Перша стаття починається співом: «Блаженні непорочні...». Після 91-го стиха хор співає (з приспівом) 92-ий і 93- ий стихи. Потім виголошується мала заупокійна ектенія (за звичаєм, з кадилом). Після виголосу: «Бо ти єси Воскресіння...» хор починає співати другу статтю: «Твій – я, спаси мене...». Ієрей з дияконом (або диякон) звершують, за традицією, мале кадіння (тетрапод навкруги, іконостас, хори, народ, місцеві ікони іконостасу, тетрапод спереду, тобто з західної сторони). Останні стихи: 175-ий і 176-ий – по тричі, і відразу – заупокійні тропарі після Непорочних, глас 5-ий: «Собор святих...», під час яких священик з дияконом звершують, за звичаєм, повне кадіння храму. Потім виголошується мала заупокійна ектенія (за звичаєм, з кадилом). Після виголосу співається сідальний Тріоді, глас 5-ий: «Упокой, Спасе наш...». «Слава, і нині» – Богородичний, глас той самий: «Христе Боже, Ти від Діви засяяв...». Псалом 50-ий. Канони: храму з ірмосом на 6 (ірмоси по двічі) і Тріоді заупокійний на 8. Біблійні пісні «Господеві співаймо...». Катавасія Тріоді, глас 8-ий: «Пісню заспіваймо...». Співається 2-га пісня канону, на 8 (ірмос двічі, тропарі на 6, приспів до тропарів: «Упокой, Господи, душі спочилих рабів Твоїх», до останніх тропарів – «Слава» і «І нині»). В кінці 2-ої пісні катавасія – той самий ірмос. Після 3-ої пісні – мала ектенія (звичайна, не заупокійна). Сідальний Тріоді, глас 5-ий. «Слава» – той самий сідальний, «І нині» – Богородичний Тріоді, глас той самий. Після 6-ої пісні – мала заупокійна ектенія (за звичаєм, з кадилом). Кондак, глас 8-ий: «Зі святими упокой...», та ікос, глас той самий. На 9-й пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Мала ектенія (звичайна, не заупокійна). Екзапостиларій Тріоді: «Пам’ять звершуючи...». «Слава, і нині» – Богородичний Тріоді: «Солодкість Ангелів...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Тріоді, глас 6-ий – 4. «Слава» – Тріоді, глас 2-ий: «Як квітка в’яне...», «І нині» – Богородичний Тріоді, глас 6-ий: «Ти єси Бог наш...». «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири з Тріоді, глас 6-ий (із заупокійними стихами, див. Тріодь). «Слава» – Тріоді, глас той самий: «Болістю стало для Адама...», «І нині» – Богородичний Тріоді, глас той самий: «Стала Ти...». Після Трисвятого – тропар заупокійний, глас 8-ий: «Глибиною мудрості...». «Слава, і нині» – Богородичний, глас той самий: «Тебе стіну і пристановище...». Ектенія потрійна: «Помилуй нас, Боже...». Диякон: «Премудрість». Хор: «Благослови». Ієрей: «Сущий благословенний...». Хор: «Амінь. Утверди, Боже...». Читається 1-ий час, і відпуст."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар «Глибиною мудрості...», кондак: «Зі святими упокой...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні з заупокійного канону Тріоді на 8: пісня 3-тя (з ірмосом) – 4 і 6-та – 4. На вході – «...спаси нас, Сину Божий, у святих Дивний Ти...». Після входу – тропар, глас 8-ий: «Глибиною мудрості...». «Слава» – кондак, глас той самий: «Зі святими упокой...», «І нині» – Богородичний, глас той самий: «Тебе стіну...». Прокимен заупокійний, глас 6-ий: «Душі їх у блаженстві перебуватимуть». Стих: «До Тебе, Господи, підношу душу мою...». Апостол дня – Діян., зач. 51, і за упокій – 1 Кор., зач. 163. Алилуарій: «Блаженні, ті, кого обрав...» зі стихом. Євангеліє дня – Ін., зач. 67, і за упокій – Ін., зач. 21. Примітка. У додатках до богослужбових Апостола та Євангелія вказані інші Літургійні заупокійні читання для Троїцької поминальної суботи – 1 Сол., зач. 270 та Ін., зач. 16. Причасний: «Блаженні, ті кого обрав...». Замість «Ми бачили Світло Істинне...» прийнято співати тропар «Глибиною мудрості...»."}]},
{"date":"05-31","weekday":"неділя","title":"8-ма неділя після Пасхи. ДЕНЬ СВЯТОЇ ТРОЙЦІ, П’ЯТДЕСЯТНИЦЯ. Ап. від 70-х Єрма (І). Мч. Єрмія (ІІ). Мч. Філософа (ІІІ). Святкування відновлення Михайлівського Золотоверхого собору (2000) в місті Києві (перехідне святкування в останню неділю травня).","readings":["Ран. – Ін., 65 зач., XX, 19 – 23.","Літ. – Діян., 3 зач., II, 1 – 11. Ін., 27 зач., VII, 37 – 52; VIII, 12."],"notes":"На ранній величання «Величаємо Тебе, Життєдавче Христе, і шануємо Всесвятого Духа Твого, що Його від Отця послав Ти, божественним учням Твоїм». «Воскресіння Христове бачивши...» не співаємо. У Тріоді для 9-ої пісні канону приспівів немає, але в Тріоді нотного співу для задостойника в день П’ятдесятниці вказується такий приспів: «Апостоли, зішестя Утішителя бачивши, здивувалися, як у вигляді вогняних язиків явився Дух Святий». «Свят Господь Бог наш» не промовляється. На Літургії – антифони свята. Вхідний стих: «Піднесися, Господи, силою Твоєю! Будемо співати й прославляти могутність Твою». Замість трисвятого – «Всі ви, що в Христа хрестилися...», замість «Достойно є...» – «Радуйся, Царице...». Після «Спаси, Боже...» співаємо «Ми бачили світло істинне...». Після відпусту Літургії царські врата зачиняються, звершуємо 9-й час і починаємо вечірню з виголосу «Благословенний Бог наш...». «Царю Небесний...», як правило, співається народом. На вечірні після 103 псалма – велика ектенія з додаванням особливих прохань, вхід з кадилом, великий прокимен і читання коліновклонних молитов. Відпуст вечірні при відчинених царських вратах «Христос, що з Отчого і Божественного лона...». З цього дня і до віддання П’ятдесятниці на ранній, коли співається велике славослів’я, катавасія «Божественним покритий...». Після свята П’ятдесятниці тижні починаються з понеділка, а закінчуються неділею. Всенічне бдіння свята П’ятдесятниці звершується за Тріоддю.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафізма вся. На «Господи, взиваю» стихири свята, глас 1-ий і глас 2-ий – 10 (перша і четверта стихира – двічі). «Слава, і нині» – свята, глас 8-ий: «Прийдіть, люди...». Вхід. Прокимен дня. Паремії свята – 3. На літії стихири свята, глас 2-ий. «Слава, і нині» – свята, глас 8-ий: «Коли Ти, Господи, послав Духа Твого апостолам...». На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Колись змішав Бог мови народів...». Після Трисвятого – тропар свята, глас 8-ий: «Благословен єси, Христе Боже наш...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята, глас 8-ий (двічі). «Слава, і нині» – той самий тропар. Кафізми 2-га і 3-тя. Малі ектенії. Сідальні свята (по двічі). Полієлей. Величання свята: «Величаємо Тебе, / Життєдавче Христе, / і шануємо Всесвятого Духа Твого, / що Його від Отця послав єси // Божественним ученикам Твоїм», і вибраний псалом свята. Сідальний свята після полієлея, глас 8-ий. «Слава, і нині» – той самий сідальний. Степенний – 1-ий антифон 4-го гласу. Прокимен свята, глас 4-ий: «Дух Твій Благий наставить мене на землю правди». Стих: «Вислухай, Боже, молитву мою, і не зневаж мене». Євангеліє свята – Ін., зач. 65. «Воскресіння Христове бачивши...» не співається, але відразу ж після прочитання Євангелія – псалом 50-ий. Після 50-го псалма: «Слава» – «Молитвами апостолів...», «І нині» – «Молитвами Богородиці...». Стихира свята, глас 6-ий: «Царю Небесний...». Канони: свята 1-ий, глас 7-ий, з ірмосом на 8 (ірмоси по двічі), і 2-ий, глас 4-ий, з ірмосом на 8 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія після кожної пісні – спочатку ірмос 1-го канону (в першій пісні – «Морем покрив...»), потім 2-го (в першій пісні – «Божественним покритий...»). Після 3-ої пісні – сідальний свята, глас 8-ий: «Спасові улюблені ученики...». «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак свята, глас 8-ий: «Коли Ти зійшов, мови змішав...», та ікос, глас той самий: «Швидке й необхідне подай утішення...». На 9-й пісні «Чеснішу» не співаємо. (Звершується звичайне кадіння). Примітка. За традицією, приспів до 9-ої пісні канону: «Апостоли, зішестя Утішителя бачачи, здивувалися, як у вигляді вогненних язиків явився Дух Святий». Після 9-ої пісні «Свят Господь Бог наш» не виголошується, а співається світильний свята: «Всесвятий Душе...» (двічі). «Слава, і нині» – інший світильний свята: «Світло – Отець, Світло – Син, Світло – і Дух...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 4-ий – 6 (кожна стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «Царю Небесний...». Велике славослів’я. Після Трисвятого – тропар свята, глас 8-ий (один раз). Ектенії і відпуст свята: «Христос, істинний Бог наш, що у вигляді вогненних язиків з Неба послав Пресвятого Духа на святих Своїх учеників і апостолів, молитвами Пречистої Своєї Матері, святих славних і всехвальних апостолів, і всіх святих, помилує і спасе нас, як Благий і Людинолюбний»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони свята. Вхідний стих: «Вознесися, Господи, силою Твоєю, будемо оспівувати і прославляти сили Твої». Примітка. Перед виголошенням вхідного стиха слід виголошувати «Премудрість, станьмо побожно». Після входу – тропар свята, «Слава, і нині» – кондак свята. Замість Трисвятого – «Усі ті, що в Христа хрестилися...». Прокимен, глас 8-ий: «По всій землі розійшлося віщування їх і в кінці вселенної слова їх». Стих: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь». Апостол – Діян., зач. 3. Алилуя, глас 1-ий: «Словом Господнім небеса утвердилися, і Духом уст Його вся сила їх». Стих: «З Неба поглянув Господь і побачив усіх синів людських». Євангеліє – Ін., зач. 27. Задостойник – ірмос 9-ої пісні 2-го канону свята: «Радуйся, Царице...» (до віддання). Причасний – свята: «Дух Твій Благий наставить мене на землю правди». Після «Спаси, Боже, людей Твоїх...» співаємо: «Ми бачили Світло Істинне...». Відпуст свята: «Христос, істинний Бог наш, що у вигляді вогненних язиків...» (як на ранній). За сформованою давньою богослужбовою практикою, одразу після відпусту Літургії царські врата і завіса закриваються, і звершується 9-ий час та ВЕЛИКА ВЕЧІРНЯ. Примітка. В 2026 році день пам’яті преп. Агапіта Печерського випадає на День Святого Духа, тому на великий вечірні П’ятдесятниці окрім піснеспівів свята співаються стихири та тропар преподобному, а також читаються паремії преподобного. Служба звершується за 56-ою храмовою главою Типікону; також при описі порядку служби враховуються загальні вказівки щодо служіння полієлейному святому у післясвято Двунадесятого Господського свята (зр.: Типікон, гл. 48, 14- те січня, 9-те серпня). (варіант Б) Якщо не плануєте звершувати службу прп. Агапіту, тоді слід звершувати вечірню П’ятидесятниці за Тріоддю. (варіант А) Варіант А. В кінці 9-ого часу відкривається завіса. Перед великою вечірнею дзвонять, як у великі свята. Початковий виголос вечірні: «Благословенний Бог наш...». Читець: «Царю Небесний». Початковий псалом (читається). Ієрей читає світильничні молитви на солії перед царськими вратами. Ектенія велика з додаванням після прохання «За подорожніх...» особливих прохань про схиляючих коліна перед Господом (див. в Квітній Тріоді). Кафізми немає. На «Господи, взиваю» стихири свята П’ятдесятниці, глас 4-ий – 6 (див. на хвалітніх ранньої, кожна стихира двічи). «Слава, і нині...» – П’ятдесятниці, глас той самий: «Царю Небесний...». Вхід. Прокимен великий, глас 7-ий: «Хто Бог великий, як Бог наш? Ти єси Бог, що твориш чудеса...», з приспівами. Після паремій відкриваються царські врата і диякон виголошує: «Ще і ще, схиливши коліна, Господу помолимось». Хор: «Господи, помилуй» (тричі). Ієрей читає першу молитву лицем до народу, стоячи на колінах у царських вратах. Ектенія потрійна: «Промовмо всі...». Виголос: «Бо Ти милостивий...» Диякон: «Ще і ще, схиливши коліна...». Хор: «Господи, помилуй» (тричі). Ієрей читає другу молитву. «Сподоби, Господи...». Диякон: «Ще і ще, схиливши коліна...». Хор: «Господи, помилуй» (тричі). Ієрей читає третю молитву. Царські врата зачиняються. Ектенія прохальна «Доповнимо вечірню..» і голововклонна молитва. На стиховні стихири П’ятдесятниці, глас 3-ій: «Нині явним знаменням...» (зі своїми приспівами). «Слава, і нині...» – П’ятдесятниці, глас 8-ий: «Прийдіть, люди...». Після Трисвятого – тропар П’ятдесятниці, глас 8-ий: «Благословен єси, Христе Боже наш...». На спів тропаря, за звичаєм, відкриваються царські врата. Виголос: «Премудрість», та інше. Відпуст з відкритих царських врат: «Христос, що з Отчого і Божественного лона принизив Себе і з небес на землю зійшов, і все наше єство прийняв та обожив його, після ж цього на небеса знову вознісся і сів праворуч Бога і Отця, а Божественного, і Святого, і єдиносущного, і рівносильного, і рівночесного, і співвічного Духа послав на святих Своїх учеників і апостолів і цим просвітив їх, а через них і світ увесь, – істинний Бог наш, молитвами Пречистої і пренепорочної святої Своєї Матері, святих славних і всехвальних богопроповідників та духоносних апостолів і всіх святих, помилує і спасе нас як благий і Людинолюбець». Многоліття. Варіант Б В кінці 9-ого часу відкривається завіса. Перед великою вечірнею дзвонять, як у великі свята. Початковий виголос вечірні: «Благословенний Бог наш...». Читець: «Царю Небесний». Початковий псалом (читається). Ієрей читає світильничні молитви на солії перед царськими вратами. Ектенія велика з додаванням після прохання «За подорожніх...» особливих прохань про схиляючих коліна перед Господом (див. в Квітній Тріоді). Кафізми немає. На «Господи, взиваю» стихири на 8: П’ятдесятниці, глас 4-ий – 3 (див. на хвалітніх ранньої) і преподобному, глас той самий – 5. «Слава» – преподобному, глас 2-ий: «Благодать зцілень звище прийнявши...», «І нині...» – П’ятдесятниці, глас той самий: «Царю Небесний...». Вхід. Прокимен великий, глас 7-ий: «Хто Бог великий, як Бог наш? Ти єси Бог, що твориш чудеса...», з приспівами. Паремії преподобному – 3. Після паремій відкриваються царські врата і диякон виголошує: «Ще і ще, схиливши коліна, Господу помолимось». Хор: «Господи, помилуй» (тричі). Ієрей читає першу молитву лицем до народу, стоячи на колінах у царських вратах. Ектенія потрійна: «Промовмо всі...». Виголос: «Бо Ти милостивий...» Диякон: «Ще і ще, схиливши коліна...». Хор: «Господи, помилуй» (тричі). Ієрей читає другу молитву. «Сподоби, Господи...». Диякон: «Ще і ще, схиливши коліна...». Хор: «Господи, помилуй» (тричі). Ієрей читає третю молитву. Царські врата зачиняються. Ектенія прохальна «Доповнимо вечірню..» і голововклонна молитва. На стиховні стихири П’ятдесятниці, глас 3-ій: «Нині явним знаменням...» (зі своїми приспівами). «Слава» – преподобному, глас 3-ій: «Від духовних дарувань струмки зцілень виливаєш...», «І нині...» – П’ятдесятниці, глас той самий: «Прийдіть, люди...». Після Трисвятого – тропар преподобному, глас 5-ий (один раз). «Слава, і нині» – тропар П’ятдесятниці, глас 8-ий: «Благословен єси, Христе Боже наш...». На спів тропаря, за звичаєм, відкриваються царські врата. Виголос: «Премудрість», та інше. Відпуст з відкритих царських врат: «Христос, що з Отчого і Божественного лона принизив Себе і з небес на землю зійшов, і все наше єство прийняв та обожив його, після ж цього на небеса знову вознісся і сів праворуч Бога і Отця, а Божественного, і Святого, і єдиносущного, і рівносильного, і рівночесного, і співвічного Духа послав на святих Своїх учеників і апостолів і цим просвітив їх, а через них і світ увесь, – істинний Бог наш, молитвами Пречистої і пренепорочної святої Своєї Матері, святих славних і всехвальних богопроповідників та духоносних апостолів, преподобного Агапіта Печерського, лікаря безсрібного і всіх святих, помилує і спасе нас як благий і Людинолюбець». Многоліття."}]},
{"date":"06-01","weekday":"понеділок","title":"1-й тиждень після П’ятдесятниці. Загальниця. День Святого Духа. Мчч. Юстина Філософа та іншого Юстина, і з ними Харитона, Харити, Євелпіста, Ієракса, Пеона і Валеріана (166). Прп. Агапіта Києво-Печерського, лікаря безвідплатного, в Ближніх печерах (бл. 1095). Кіпрської ікони Божої Матері (перехідне святкування в День Святого Духа).","readings":["Ран. – Мф., 43 зач., XI, 27 – 30.","Літ. – Еф., 229 зач., V, 8 – 19. Мф., 75 зач., XVIII, 10 – 20.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"На ранній замість «Чеснішу...» співається ірмос «Радуйся, Царице...». На Літургії вхідний стих: «Піднесися, Господи, силою Твоєю! Будемо співати й прославляти могутність Твою». Співається трисвяте. Замість «Достойно є...» – «Радуйся, Царице...» (до віддання). Відпуст вечірні, ранньої та літургії у всі дні до віддання – «Христос, що у вигляді вогняних язиків...». У середу і п’ятницю посту немає. Примітка. В 2026 році на День Святого Духа припадає день пам’яті преподобного Агапіта Печерського. Тому можливо звершення полієлейного богослужіння преподобному в поєднанні зі службою свята П’ятидесятниці. (варіант Б) Або тільки за Тріоддю. (варіант А) Варіант А Служба звершується по Тріоді.","sections":[{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї співається канон Святому Духу (див. в Квітній Тріоді)."},{"svc":"ПОЛУНОШНИЦІ","text":"НА ПОЛУНОШНИЦІ після 1-го Трисвятого – тропар свята, глас 8-ий. Після 2-го Трисвятого – кондак П’ятдесятниці, глас 8-ий. «Господи, помилуй» (12) і малий відпуст (заупокійна молитва «Пом’яни, Господи...» не промовляється)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар П’ятдесятниці, глас 8-ий (двічі). «Слава, і нині» – тропар П’ятдесятниці. Кафизми 4-та і 5-та. Малі ектенії. Після 1-ої кафізми – сідальний П’ятдесятниці, глас 4-ий: «Післясвяткове і кінцеве свято святкуємо...» «Слава, і нині» – той самий сідальний. Після 2-ої кафізми – сідальний П’ятдесятниці, глас 8-ий: «Духа джерело зійшло на землю...» «Слава, і нині» – той самий сідальний. Псалом 50-ий. Канони: П’ятдесятниці 1-ий з ірмосом на 8 (ірмоси по двічі), і П’ятдесятниці 2-ий на 6 (ірмоси двічи). Біблійні пісні «Співаймо Господеві...». Катавасія П’ятдесятниці: «Божественним покритий...». Після 3-ої пісні – сідальний П’ятдесятниці, глас 8-ий: «Всесвятий Дух нині зійшов на апостолів...» (див. в Тріоді на ранній Понеділка Святого Духа), «Слава, і нині», сідальний той самий. Після 6-ої пісні – кондак і ікос свята, глас 8-ий. На 9-ій пісні «Чеснішу» не співаємо. (Звершується звичайне кадіння). Примітка. За традицією, приспів до тропарів 9-ої пісні канонів свята: «Апостоли, зішестя Утішителя бачачи, здивувалися, як у вигляді вогненних язиків явився Дух Святий». Після 9-ої пісні «Достойно є» не співається. Світильний П’ятдесятниці «Всесвятий Душе...», «Слава, і нині» – інший світильний П’ятдесятниці: «Світло – Отець, Світло – Син, Світло – і Дух...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири П’ятдесятниці (див. в Тріоді на ранній Понеділка Святого Духа), глас 2-ий – 4, «Слава, і нині» – П’ятдесятниці, глас 8-ий: «Колись народи...». Велике славослів’я. Після Трисвятого – тропар П’ятдесятниці, глас 8-ий (один раз). Ектенії, і відпуст свята: «Христос, істинний Бог наш, що у вигляді вогненних язиків...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ –тропарП’ятдесятниці.КондакиП’ятдесятниці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні з обох канонів П’ятдесятниці, пісня 3-тя – 4 (першого канону з ірмосом) і пісня 6-та – 4. Вхідний стих П’ятдесятниці: «Вознесися, Господи, силою Твоєю, будемо оспівувати і прославляти сили Твої». Примітка. Перед виголошенням вхідного стиха слід виголошувати «Премудрість, станьмо побожно». Після входу – тропар П’ятдесятниці, «Слава, і нині» – кондак П’ятдесятниці. Співається Трисвяте. Прокимен, глас 6-ий: «Спаси, Господи, людей Твоїх і благослови насліддя Твоє». Стих: «До Тебе, Господи, взиватиму, Боже мій не відвертайся мовчки від Мене». Апостол – дня (Еф., зач. 229). Алилуарій, глас 2-ий: «Помилуй мене, Боже, з великої милости Твоєї». Стих: «Не відкинь мене від лиця Твого і Духа Твого Святого не відніми від мене». Євангеліє – дня (Мф., зач. 75). Задостойник П’ятдесятниці. Причасний свята «Дух Твій Благий...». Відпуст свята: «Христос, істинний Бог наш, що у вигляді вогненних язиків...». Примітка. У тиждень П’ятдесятниці на повечір’ї канон Пресвятої Богородиці не співається» (див.: Квітна Тріодь, «У понеділок Святого Духа», «див»). Варіант Б. Служба прп. Агапіта Печерського полієлейна звершується у поєднанні зі службою післясвята П’ятидесятниці. Деякі тексти служби преподобного запозичуються з Загальної Мінеї (див. службу преподобному одному)."},{"svc":"МАЛОМУ ПОВЕЧІР’Ї","text":"НА МАЛОМУ ПОВЕЧІР’Ї співається канон Святому Духу (див. в Квітній Тріоді). Після Трисвятого – кондак преподобному, глас 3-ій: «Раніше неплідна нині Предтечу Христового народжує...», «Слава, і нині» – кондак П’ятдесятниці, глас 8-ий: «Благословен єси, Христе Боже наш...»."},{"svc":"ПОЛУНОШНИЦІ","text":"НА ПОЛУНОШНИЦІ після 1-го Трисвятого – тропар Предтечі, глас 5-ий, «Слава, і нині» – тропар П’ятдесятниці, глас 8-ий. Після 2-го Трисвятого – кондак преподобного, глас 6-ий, «Слава, і нині» – кондак П’ятдесятниці, глас 8-ий. «Господи, помилуй» (12) і малий відпуст (заупокійна молитва «Пом’яни, Господи...» не промовляється)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар П’ятдесятниці, глас 8-ий (двічі). «Слава» – тропар преподобного, глас 5-ий, «І нині» – тропар П’ятдесятниці. Кафизми 4-та і 5-та. Малі ектенії. Після 1-ої кафізми – сідальний П’ятдесятниці, глас 4-ий: «Післясвяткове і кінцеве свято святкуємо...» «Слава, і нині» – той самий сідальний. Після 2-ої кафізми – сідальний П’ятдесятниці, глас 8-ий: «Духа джерело зійшло на землю...» «Слава, і нині» – той самий сідальний. Полієлей. Величання преподобного: «Ублажаємо тебе, / преподобний отче наш Агапіте Печерський, / і шануємо святу пам’ять твою, / наставнику монахів // і співрозмовнику ангелів» і вибраний псалом преподобного. Після полієлея сідальні преподобного, глас 4-ий: «За покликом Господа твого...» (див. після 1-ої кафізми у Загальній Мінеї), сідальний преподобного, глас 5-ий: «Подвижника Господнього піснями вшануймо...» (див. після 2-ої кафізми у Загальній Мінеї), «Слава» – сідальний преподобного після полієлею, глас 1-ий: «Подолав ти спокуси пристрастей...», «І нині» – сідальний свята, глас 8-ий: «Після воскресіння із гробу...». Степенний – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Чесна перед Господом...». Стих: «Що віддам Господу за все...». Євангеліє Преподобного (Мф., зач. 43). «Воскресіння Христове бачивши...» (один раз). Псалом 50-ий. «Слава» – «Молитвами преподобного і богоносного отця нашого Агапіта...». Стихира преподобного, глас 6-ий: «По всій землі розійшлася слава...» (див. у Загальній Мінеї після 50-го псалма). Канони: П’ятдесятниці 1-ий з ірмосом на 4 (ірмоси по двічі), преподобному на 6 і П’ятдесятниці 2-ий на 4. Біблійні пісні «Співаймо Господеві...». Катавасія П’ятдесятниці: «Божественним покритий...». Після 3-ої пісні – кондак преподобному, глас 6-ий: «Будучи прекрасним лікарем...», сідальний преподобного, глас 4-ий: «Я той, що задарма...», «Слава, і нині» – сідальний П’ятдесятниці, глас 8-ий: «Всесвятий Дух нині зійшов на апостолів...» (див. в Тріоді на ранній Понеділка Святого Духа). Після 6-ої пісні – кондак і ікос свята, глас 8-ий. На 9-ій пісні «Чеснішу» не співаємо. (Звершується звичайне кадіння). Примітка. За традицією, приспів до тропарів 9-ої пісні канонів свята: «Апостоли, зішестя Утішителя бачачи, здивувалися, як у вигляді вогненних язиків явився Дух Святий». Після 9-ої пісні «Достойно є» не співається. Світильний П’ятдесятниці «Всесвятий Душе...», «Слава» – світильний преподобного: «Тлінне світу цього ти залишив...», «І нині» – інший світильний П’ятдесятниці: «Світло – Отець, Світло – Син, Світло – і Дух...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: П’ятдесятниці (див. в Тріоді на ранній Понеділка Святого Духа), глас 2-ий – 3 і преподобному, глас 4-ий – 3. «Слава» – преподобного, глас 2-ий: «Нескінченна Твоя, Христе Царю...» «І нині» – П’ятдесятниці, глас 8-ий: «Колись народи...». Велике славослів’я. Після Трисвятого – тропар преподобного, глас 5-ий, «Слава, і нині» – тропар П’ятдесятниці, глас 8-ий. Ектенії, і відпуст свята: «Христос, істинний Бог наш, що у вигляді вогненних язиків...» зі згадуванням імені прп. Агапіта Печерського."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар П’ятдесятниці, «Слава» – тропар преподобного. Кондаки П’ятдесятниці та преподобного чергуються."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні з обох канонів П’ятдесятниці, пісня 3-тя – 4 (першого канону з ірмосом) і преподобного, пісня 6-та – 4. Вхідний стих П’ятдесятниці: «Вознесися, Господи, силою Твоєю, будемо оспівувати і прославляти сили Твої». Примітка. Перед виголошенням вхідного стиха слід виголошувати «Премудрість, станьмо побожно». Після входу – тропар П’ятдесятниці, тропар преподобного, «Слава» – кондак преподобного, «І нині» – кондак П’ятдесятниці. Співається Трисвяте. Прокимен, алилуарій і причасниц свята і преподобного. Апостол і Євангеліє – дня і преподобного Задостойник П’ятдесятниці. Відпуст свята: «Христос, істинний Бог наш, що у вигляді вогненних язиків...» зі згадуванням імені прп. Агапіта Печерського. Примітка. У тиждень П’ятдесятниці на повечір’ї канон Пресвятої Богородиці не співається» (див.: Квітна Тріодь, «У понеділок Святого Духа», «див»)."}]},
{"date":"06-02","weekday":"вівторок","title":"Свт. Никифора, спов., патр. Константинопольського (828). Вмч. Іоана Нового, Сучавського (1330 – 1340). Сщмч. Пофина, єп. Ліонського, і тих, що з ним постраждали (177). Мц. Бландини і мч. Понтика Ліонських (177). Києво-Братської ікони Божої Матері (1654).","readings":["Рим., 79 зач., I, 1 – 7, 13 – 17. Мф., 10 зач., IV, 25 – V, 13."],"notes":"З цього дня співається «Чеснішу...» (крім віддання П’ятдесятниці). Служба свт. Никифора шестирична, звершується зі службамою післясвята П’ятдесятниці (за Тріоддю).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 6-та. На «Господи, взиваю» стихири на 6: П’ятидесятниці, глас 1-ий – 3, святителя, глас 4-ий – 3. «Слава, і нині» – свята, глас 1-ий: «П’ятдесятницю святкуємо...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 1-ий: «Мовами чужими...». Після Трисвятого – тропар свята, глас 8-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (двічи), «Слава, і нині» – тропар свята. Кафізми 7-ма і 8-ма. Малі ектенії. Сідальні свята з Тріоді (по двічі). Псалом 50-й. Канони: свята П’ятдесятниці 1-ий з ірмосом на 6 (ірмоси по двічі) і святителя на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону святителя. Після 3-ої пісні – кондак і ікос святителю, глас 4-ий, сідальний святителю, глас 8-ий, «Слава, і нині» – сідальний свята, глас 8-ий: «Спасові улюблені ученики...». Після 6-ої пісні – кондак і ікос П’ятидесятниці, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний святителю: «Як прекрасний переможець пристрастей..», «Слава, і нині», світильний свята: «Всесвятий Душе...». «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 1-ий: «Все подає Дух Святий...». Після Трисвятого – тропар свята (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з обох канонів свята, пісня 1-ша – 6 (першого канону – з ірмосом). На вході – «...спаси нас, Утішителю Благий...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, «Слава, і нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, Слава, і нині» – кондак свята. В храмі святого – тропар свята, тропар храму, «Слава» – кондак храму, «І нині» – кондак свята. Прокимен, алилуарій та причасний – свята. Апостол і Євангеліє – дня. Задостойник свята."}]},
{"date":"06-03","weekday":"середа","title":"Мчч. Лукиліана, Клавдія, Іпатія, Павла, Діонісія і мц. Павли, діви (270 – 275). Сщмчч. Лукіана, єп., Максіана, пресвітера, Юліана, диякона, мчч. Маркеліана і Сатурнина в Бельгії (81 – 96).","readings":["Рим., 80 зач., I, 18 – 27. Мф., 12 зач., V, 20 – 26."],"notes":"Служба мчч. Лукіана і тих, що з ним постраждали не має святкового знаку, звершується зі службою свята П’ятдесятниці (за Тріоддю).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири на 6: свята, глас 1-ий – 3 і мучеників, глас 1-ий – 3. «Слава, і нині» – свята, глас 2-ий: «Ми бачили Світло істинне...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 4-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 6-ий: «Господи, апостоли Твої, сповнившись зішестя Духа...». Після Трисвятого – Тропар свята (один раз)"},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (двічі), «Слава, і нині» – тропар свята. Кафізми 10-та і 11-та. Малі ектенії. Сідальні свята з Тріоді (по двічі). Псалом 50-й. Канони: свята П’ятдесятниці 2-ий з ірмосом на 8 (ірмоси по двічі) та мучеників на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучеників. Після 3-ої пісні – сідальний мучеників, глас 1-ий, «Слава, і нині» – сідальний свята, глас 8-ий: «Спасові улюблені ученики...». Після 6-ої пісні – кондак і ікос свята, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята «Світло – Отець, Світло – Син, Світло – і Дух...», «Слава, і нині», той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 6-ий: «Царю Небесний...». Після Трисвятого – тропар свята (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з обох канонів свята, пісня 4-та – 6 (першого канону – з ірмосом). На вході – «...спаси нас, Утішителю Благий...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, «Слава, і нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, «Слава, і нині» – кондак свята. В храмі святого – тропар свята, тропар храму, «Слава» – кондак храму, «І нині» – кондак свята. Прокимен, алилуарій та причасний – свята. Апостол і Євангеліє – дня. Задостойник свята."}]},
{"date":"06-04","weekday":"четвер","title":"Свт. Митрофана, патр. Константинопольського (бл. 326). Мчч. Фронтасія, Северина, Северіана і Силана (І). Мч. Конкордія (бл. 175). Сщмч. Астія, єп. Диррахійського (ІІ). Прп. Зосими, єп. Вавилона Єгипетського (VІ). Ікони Божої Матері «Споручниця грішних», Корецької (1622) (перехідне святкування в четвер 1-го тижня після П’ятдесятниці).","readings":["Рим., 81 зач., I, 28 – II, 9. Мф., 13 зач., V, 27 – 32."],"notes":"Служба свт. Митрофана не має святкового знаку, звершується зі службою свята П’ятдесятниці (за Тріоддю).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 12-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3 і святителя, глас 6-ий – 3. «Слава, і нині» – свята, глас 7-ий: «Маючи Утішителя...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 1-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Коли Ти, Господи, послав Духа Твого апостолам...». Після Трисвятого – тропар святителя, глас 4-ий, «Слава, і нині» – тропар свята, глас 8-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (двічі), «Слава» – тропар святителя, «І нині» – тропар свята. Кафізми 13-та і 14-та. Малі ектенії. Сідальні свята з Тріоді (по двічі). Псалом 50-й. Канони: свята П’ятдесятниці 1-ий з ірмосом на 8 (ірмоси по двічі) та святителя на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону святителя. Після 3-ої пісні – кондак і ікос святителя, глас 4-ий, інший кондак святителя, глас 2-ий, сідальний святителя, глас 8-ий, «Слава, і нині» – сідальний свята, глас 8-ий: «Спасові улюблені ученики...». Після 6-ої пісні – кондак і ікос свята, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний святителя. «Слава, і нині» – світильний свята «Всесвятий Душе...». «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 2-ий: «В оселях Твоїх, Господи...». Після Трисвятого – тропар святителя. «Слава, і нині» – тропар свята."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святителя. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з обох канонів свята, пісня 5-та – 6 (першого канону – з ірмосом). На вході – «...спаси нас, Утішителю Благий...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, тропар святителя, «Слава» – кондак святителя, «І нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, тропар святителя, «Слава» – кондак святителя, «І нині» – кондак свята. В храмі святого – тропар свята, тропар храму, тропар святителя, кондак храму, «Слава» – кондак святителя, «І нині» – кондак свята. Прокимен, алилуарій та причасний – свята і святителя. Апостол і Євангеліє – дня і святителя. Задостойник свята."}]},
{"date":"06-05","weekday":"п’ятниця","title":"Сщмч. Дорофея, єп. Тирського (бл. 362). Перенесення мощів блгв. Ігоря, кн. Чернігівського і Київського (1150). Свт. Костянтина, митр. Київського і всієї Руси (1159). Мчч. Маркіана, Никандра, Іперехія, Аполона, Леоніда, Арія, Горгія, Селінія, Іринія і Памвона (305 – 311). Прп. Федора, чудотворця (бл. VІ). Прп. Анувія, пустельника Єгипетського (ІV – V). Прп. Дорофея, з обителі авви Серида (620). Ігорівської ікони Божої Матері (1147).","readings":["Рим., 82 зач., II, 14 – 29. Мф., 14 зач., V, 33 – 41."],"notes":"Служба сщмч. Дорофея не має святкового знака, звершується зі службою свята П’ятдесятниці (за Тріоддю).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 15-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3 і святого, глас 8-ий – 3. «Слава, і нині» – свята, глас 2-ий: «Тройцю єдиносущну оспівуємо...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 1-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 6-ий: «Маємо Утішителя...». Після Трисвятого – тропар святого, глас 4-ий, «Слава, і нині» – тропар свята, глас 8-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар свята (двічі), «Слава» – тропар святого, «І нині» – тропар свята. Кафізми 19-та і 20-та. Малі ектенії. Сідальні свята з Тріоді (по двічі). Псалом 50-й. Канони: свята П’ятдесятниці 2-ий з ірмосом на 8 (ірмоси по двічі), святого на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону святителя. Після 3-ої пісні – кондак святого, глас 5-ий, сідальний святого, глас 3-ій, «Слава, і нині» – сідальний свята, глас 8-ий: «Спасові улюблені ученики...». Після 6-ої пісні – кондак і ікос свята, глас 8-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята «Світло – Отець, Світло – Син, Світло – і Дух...», «Слава, і нині», той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Коли Ти, Господи, послав Духа Твого апостолам...». Після Трисвятого – тропар святого. «Слава, і нині» – тропар свята."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святого. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з обох канонів свята, пісні 7-ма і 8-ма – 6 (першого канону – з ірмосом). На вході – «...спаси нас, Утішителю Благий...» Після входу – тропарі і кондаки: В храмі Господському – тропар свята, тропар святого, «Слава» – кондак святого, «І нині» – кондак свята. В храмі Богородичному – тропар свята, тропар храму, тропар святого, «Слава» – кондак святого, «І нині» – кондак свята. В храмі святого – тропар свята, тропар храму, тропар святого, «Слава» – кондак святого, «І нині» – кондак свята. Прокимен, алилуарій та причасний – свята. Апостол і Євангеліє – дня. Задостойник свята."}]},
{"date":"06-06","weekday":"субота","title":"Віддання свята П’ятдесятниці. Прп. Віссаріона, чудотворця Єгипетського (ІV). Прп. Іларіона Нового (845). Прмцц. дів Архелаї, Фекли і Сусанни (293).","readings":["Рим., 79 зач. (від половини), I, 7 – 12. Мф., 15 зач., V, 42 – 48."],"notes":"Уся служба за Тріоддю. На ранній замість «Чеснішу...» співається ірмос «Радуйся, Царице...». Співається велике славослів’я. Звершується славослівна служба віддання свята П’ятдесятниці.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ Кафизма 18-та. На «Господи, взиваю» стихири П’ятдесятниці, глас 1-ий і глас 2-ий – 6 (див. в Тріоді на вечірні у суботу 7-му після Пасхи), «Слава, і нині...» – П’ятдесятниці, глас 8-ий: «Прийдіть, люди, Триіпостасному Божеству поклонімося...». Входу немає. Прокимен дня. Паремій немає. На стиховні стихири П’ятдесятниці, глас 6-ий (зі своїми приспівами). «Слава, і нині» – П’ятдесятниці, глас 8-ий: «Колись змішав Бог мови народів...». Після Трисвятого – тропар П’ятдесятниці, глас 8-ий: «Благословен єси, Христе Боже наш...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар П’ятдесятниці (двічі). «Слава, і нині» – тропар П’ятдесятниці. Кафизми 16-та і 17-та. Малі ектенії. Сідальні свята (двічи). Псалом 50-ий. Канони: П’ятдесятниці 1-ий з ірмосом на 8 (ірмоси по двічі), і П’ятдесятниці 2-ий на 6. Біблійні пісні «Співаймо Господеві...». Катавасія П’ятдесятниці: «Божественним покритий...». Після 3-ої пісні – сідальний П’ятдесятниці, глас 8-ий: «Спасові улюблені ученики...», «Слава, і нині», той самий сідальний Після 6-ої пісні – кондак і ікос свята, глас 8-ий. На 9-ій пісні «Чеснішу» не співаємо. (Звершується звичайне кадіння). Примітка. За традицією, приспів до тропарів 9-ої пісні обох канонів свята: «Апостоли, зішестя Утішителя бачачи, здивувалися, як у вигляді вогненних язиків явився Дух Святий». Після 9-ої пісні «Достойно є» не співається. Світильний П’ятдесятниці «Всесвятий Душе...», «Слава, і нині» – інший світильний П’ятдесятниці: «Світло – Отець, Світло – Син, Світло – і Дух...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири П’ятдесятниці, глас 4-ий – 4, «Слава, і нині» – П’ятдесятниці, глас 6-ий: «Царю Небесний...». Велике славослів’я. Після Трисвятого – тропар П’ятдесятниці. Ектенії, і відпуст свята: «Христос, істинний Бог наш, що у вигляді вогненних язиків...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак П’ятдесятниці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні з обох канонів П’ятдесятниці, пісня 9-та – 8 (першого канону з ірмосом). На вході – «...спаси нас, Утішителю Благий...». Після входу – тропар П’ятдесятниці, «Слава, і нині» – кондак П’ятдесятниці. Співається Трисвяте. Прокимен, алилуарій і причастний – свята. Апостол і Євангеліє – дня. Задостойник П’ятдесятниці. Причасний свята «Дух Твій Благий...» і апостолів: «По всій землі...». Відпуст свята: «Христос, істинний Бог наш, що у вигляді вогненних язиків...»."}]},
{"date":"06-07","weekday":"неділя","title":"1-ша неділя після П’ятдесятниці. Всіх святих. Глас 8-й. Мч. Феодота Анкирського (303). Сщмч. Маркеліана, єп. Римського, і мчч. Клавдія, Кирина і Антоніна (304). Сщмчч. Маркела, єп. Римського, Сисинія і Киріака, дияконів, мчч. Смарагда, Ларгія, Апроніана, Сатурніна, Папія і Мавра, воїнів, і Крискентіана, мцц. Прискіли, Лукини і Артемії, царівни (304 – 310). Мцц. Калерії (Валерії), Киріакії і Марії в Кесарії Палестинській (ІV). Ікон Божої Матері Тернопільської та «Пом’якшення злих сердець» (Семистрільна) (перехідні святкування в неділю всіх святих).","glas":8,"readings":["Ран. – Єв. 1-е, Мф., 116 зач., XXVIII, 16 – 20.","Літ. – Євр., 330 зач., XI, 33 – XII, 2. Мф., 38 зач., X, 32 – 33, 37 – 38; XIX, 27 – 30."],"notes":"Заговини на Петрів піст. Вся служба з Тріоді. З цього дня і до 1-го серпня на святкових ранніх (коли співається велике славослів’я) катавасія «Відкрию уста мої...». Звершується служба Неділі всіх святих (за Тріоддю Квітною).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 8-ий – 6, і всіх святих, глас 6-ий – 4. «Слава» – всіх святих, глас той самий, «І нині» – догматик, глас 8-ий: «Цар небесний...». Вхід. Прокимен дня. Паремії всіх святих – 3. На літії стихира храму і стихири всіх святих, глас 1-ий. «Слава» – всіх святих, глас 5-ий, «І нині» – Богородичний воскресний, глас той самий. На стиховні стихири воскресні, глас 8-ий. «Слава» – всіх святих, глас 6-ий: «Прийдіть, вірні...», «І нині» – Богородичний воскресний, глас той самий: «Творець і Визволитель мій...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар всіх святих, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог – Господь» – тропар воскресний, глас 8-ий (двічі). «Слава» – тропар всіх святих, глас 4-ий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...». Кафізми 2-га і 3-тя. Малі ектенії. Сідальні воскресні (Тріоді). Непорочні. «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє воскресне 1-ше. «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами апостолів...», «І нині» – «Молитвами Богородиці...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони (в Тріоді): воскресний з ірмосом на 4 (ірмоси один раз), хрестовоскресний на 2, Богородиці на 2 і всіх святих на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний всіх святих, глас 8-ий. «Слава» – той самий сідальний, «І нині» – Богородичний Тріоді, глас той самий: «Небесні двері і кивот...». Після 6-ої пісні – кондак і ікос всіх святих, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 1-ий. «Слава» – світильний всіх святих, «І нині» – Богородичний Тріоді. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8 (з Тріоді): воскресні, глас 8-ий – 5, і всіх святих, глас 4-ий – 3 (зі своїми приспівами). «Слава» – стихира євангельська 1-ша, глас 1-ий: «Коли ученики поспішали на гору...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар всіх святих. Кондак всіх святих."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4 (див. у Тріоді), і всіх святих, пісня 6-та – 4. Після входу – тропар воскресний, тропар всіх святих. «Слава, і нині» – кондак всіх святих. Прокимен воскресний, глас 8-ий: «Помоліться і воздайте...» зі стихом, і всіх святих, глас 4-ий: «Дивний Бог у святих Своїх...». Апостол – Євр., зач. 330. Алилуарій всіх святих, глас 4-ий: «Взивали праведні...». Євангеліє – Мф., зач. 38. Причасний воскресний: «Хваліть Господа...», і всіх святих: «Радуйтеся, праведні...»."}]},
{"date":"06-08","weekday":"понеділок","title":"2-й тиждень після П’ятдесятниці. Вмч. Федора Стратилата (319). Прп. Єфрема, патр. Антіохійського (545). Прп. Зосими Фінікійського (VІ). Свт. Федора, єп. Суздальського (1023). Ікони Божої Матері «Далешівська».","readings":["Рим., 83 зач., II, 28 – III, 18. Мф., 19 зач., VI, 31 – 34; VII, 9 – 11.","Вмч.: 2 Тим., 292 зач., II, 1 – 10. Мф., 36 зач., Х, 16 – 22."],"notes":"Початок Петрового посту. З цього дня співається Октоїх. Устав повсякденної служби викладений у 9-й главі Типікона, а в 11-й подається порядок співання канонів усього тижня при різних варіантах поєднання служб Октоїха і Мінеї. Устав суботньої служби міститься в 12-й главі Типікона, а особливості суботніх служб – у 15-й. Примітка. Визначаючи склад і порядок богослужіння седмічних днів малих постів періоду співу Октоїха (Різдвяного, Петрового і Успенського), Типікон розрізняє дні, коли співається «Бог Господь», і дні, коли співається «Алилуя». У певні дні спів «Алилуя» з Троїчними Октоїха замінює співання «Бог Господь» (див. Типікон, гл. 51; гл. 48, 14 листопада). У послідовностях цих днів сказано: «Алилуя або тропар». Але якщо алилуйна служба співпаде з суботою або Неділею, то вона відміняється (взагалі, коли алилуйна служба співпадає з суботою, то відповідно до Типікону, гл. 12, 1-е «див», якщо святий не має тропаря, повинна звершуватися заупокійна служба, за 13-ою главою). Крім того, алилуйна служба призначається в перший день Різдвяного і Петрового постів. Подаємо зразки звершення служб з «Бог Господь». Служба вмч. Феодора Стратилата шестирична, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири великомученика, глас 2-ий і глас 4-ий – 6. «Слава» – великомученика, глас 5-ий: «Нині засяяла краще...», «І нині» – Богородичний Мінеї, за гласом «Слави», від менших: «Страшне, і преславне...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава» – великомученика, глас той самий: «Як тезоіменитого Божих дарів...», «І нині» – Богородичний Мінеї, за гласом «Слави», від менших: «Прийнявши глас Архангела...». Після Трисвятого – тропар великомученика, глас 4-ий: «Істинною боротьбою...». «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована у храмі...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар великомученика, глас 4-ий: «Істинною боротьбою...» (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована у храмі...». Кафизми 4-та і 5-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси один раз), 2-й на 4, і великомученика на 6. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону великомученика. Після 3-ої пісні – сідальний великомученика, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос великомученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний великомученика, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава» – великомученика, глас той самий: «Зважившись на страдницький подвиг...», «І нині» – Богородичний Мінеї, за гласом «Слави», від менших: «Небесні сили...». Після Трисвятого – тропар великомученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти вища...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4, і великомученика, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар великомученика; кондак дня, кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар великомученика; кондак дня, кондак храму, кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і великомученика. Апостол і Євангеліє – дня і великомученика."}]},
{"date":"06-09","weekday":"вівторок","title":"Свт. Кирила, архієп. Олександрійського (444). Мцц. Фекли, Марфи і Марії в Персії (346).","readings":["Рим., 86 зач., IV, 4 – 12. Мф., 22 зач., VII, 15 – 21.","Свт.: Євр., 334 зач., XIII, 7 – 16. Мф., 11 зач., V, 14 – 19."],"notes":"Служба свт. Кирила архієп. Олександрійського, шестирична, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 6-та. На «Господи, взиваю» стихири святителя, глас 4-ий – 6 (кожна стихира двічі). «Слава» – святителя, глас 6-й: «Благий і вірний рабе...», «І нині» – Богородичний за гласом «Слави», від менших: «Ніхто з тих...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава» – святителя, глас 6-ий: «Людина Божа...», «І нині» – Богородичний за гласом «Слави»: «Ніхто з тих...». Після Трисвятого – тропар святителя, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Непохитне утвердження...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар святителя, глас 8-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Непохитне утвердження...». Кафизми 7-ма і 8-ма. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-й з ірмосом, без мученичних, на 4 (ірмоси один раз), 2-й на 4 і святителя на 6. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний святителя, глас 3-ій (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос святителя, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний святителя, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава» – святителя, глас 6-ий: «Спадкоємцю Божий...», «І нині» – Богородичний за гласом «Слави», від менших: «Великих дарів...». Після Трисвятого – тропар святителя, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Діво Пречиста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4 і святителя, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар святителя; кондак дня, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар святителя; кондак дня, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"06-10","weekday":"середа","title":"Сщмч. Тимофія, єп. Пруського (361 – 363). Свт. Іоана (Максимовича), митр. Тобольського (1715). Прп. Силуана, схимника Києво-Печерського, в Дальніх печерах (ХІІІ – ХІV). Мчч. Олександра, Антоніни, діви (бл. 313). Прп. Феофана Антіохійського (369). Свт. Вассіана, єп. Лавдійського (409).","readings":["Рим., 87 зач., IV, 13 – 25. Мф., 23 зач., VII, 21 – 23.","Свт.: Євр., 335 зач., XIII, 17 – 21. Ін., 36 зач., X, 9 – 16."],"notes":"Служба Сщмч. Тимофія, єп. Пруського не має святкового знаку, звершується разом зі службою Октоїха (А). Також наводимо зразок звершення славослівної служби свт. Іоану Тобольському (Б). А. НА ВЕЧІРНІ кафізма 9-та. На«Господи,взиваю»стихирина6:Октоїха,глас8-ий–3,і священномученика, глас 4-ий – 3. «Слава, і нині» – Хрестобогородичний Мінеї, глас той же: «Коли побачила Тебе...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той же: «Господи, коли побачило сонце...». Після Трисвятого – тропар священномученика (загальний), глас 4-й: «І співучасником звичаїв...». «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...».","sections":[{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар священномученика (загальний), глас 4-й: «І співучасником звичаїв...» (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...». Кафизми 10-та і 11-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-й з ірмосом на 6 (ірмоси один раз), 2-й на 4, і священномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний священномученика, глас 5-ий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той же. Після 6-ої пісні – кондак священномученика (загальний), глас 4-ий: «Як святитель благочесно...». На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава і нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас самий: «На хресті розіп’ятого...». Після Трисвятого – тропар священномученика (загальний), глас 4-ий: «І співучасником звичаїв...». «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському – тропар дня: «Спаси, Господи...», тропар священномученика; кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар священномученика; кондак дня: «Вознісся на Хрест...», кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар священномученика; кондак дня: «Вознісся на Хрест...», кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня. Б. НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири святителя, глас 4-ий – 6 (перша стихира – двічі). «Слава» – святителя, глас 7-ий: «Святителів окрасу...», «І нині» – догматик, глас той самий: «Матір’ю надприродно...». Входу немає. Прокимен дня. На стиховні стихири святителя, глас 5-ий (зі своїми приспівами). «Слава» – святителя, глас 8-ий: «Святителю Христів...», «І нині» – Богородичний за гласом «Слави», від менших: «Богородице, Ти єси лоза...». Після Трисвятого – тропар святителя, глас 8-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Ти, що заради нас...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 8-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Ти, що заради нас...». Кафизми 10-та і 11-та. Малі ектенії. Сідальні святителя. Псалом 50-ий. Канони Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси один раз), 2-ий на 4 і святителя на 6. Біблійні пісні «Господеві співаймо...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний святителя, глас 6-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос святителя, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний святителя (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири святителя, глас 8-ий – 4. «Слава» – святителя, глас 6-ий, «І нині» – Богородичний за гласом «Слави»: «Ти є лоза...». Велике славослів’я. Після Трисвятого – тропар святителя, глас 8-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Ти, що заради нас...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні святителя, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"06-11","weekday":"четвер","title":"Апп. Варфоломія і Варнави (І). Свт. Луки, архієп. Сімферопольського, спов. (1961). Ікони Божої Матері «Достойно є» («Милуюча») (Х).","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – Рим., 89 зач., V, 10 – 16. Мф., 27 зач., VIII, 23 – 27.","Апп.: Діян., 28 зач., XI, 19 – 26, 29 – 30. Лк., 51 зач., X, 16 – 21."],"notes":"Звершується полієлейна служба апп. Варфоломія і Варнави.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: ап. Варфоломія, глас 4-ий – 5 (перші дві стихири – двічі), і ап. Варнави, глас той же – 3. «Слава» – ап. Варнави, глас 6-ий: «Варнаво пре хвальний...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії апостолів – 3 (за традицією, новозавітні паремії читаються при відкритих царських вратах). На стиховні стихири апостолів, глас 1-ий (зі своїми приспівами). «Слава» – ап. Варнави, глас 8-ий: «Апостоле Спасів Варнаво...», «І нині» – Богородичний воскресний, глас той же: «Безневісна Діво...». Після Трисвятого – тропар апостолів, глас 3-ій. «Слава, і нині» – Богородичний воскресний, глас той самий: «Тебе, заступницю спасіння...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостолів, глас 3-ій (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Тебе, заступницю спасіння...». Кафизми 13-та і 14-та. Малі єктенії. Сідальні апостолів (по двічі). Полієлей. Величання апостолів і вибраний псалом. Сідальний ап. Варфоломія після полієлея, глас 8-ий (двічі). «Слава, і нині» – Богородичний, глас той же (див. в Мінеї загальній): «Небесні двері і кивот...». Степенна – 1-ий антифон 4-го гласу. Прокимен апостолів, глас 4-ий: «По всій землі...». Євангеліє апостолів. Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира апостолів, глас 1-ий: «По всій землі...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі), ап. Варфоломія на 4 і ап. Варнави на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос ап. Варнави, глас 3-ій; сідальний ап. Варфоломія, глас 8-ий. «Слава» – сідальний ап. Варнави, глас той самий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос ап. Варфоломія, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний апостолів (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостолів, глас 4-ий – 4 (перша стихира – двічі). «Слава» – апостолів, глас 5-ий: «Премудрість Божа...», «І нині» – Богородичний, глас той же: «Ублажаємо Тебе, Богородице Діво...» (див. Додаток. 2-й). Велике славослів’я. Після Трисвятого – тропар апостолів, глас 3-ій. «Слава, і нині» – Богородичний воскресний, глас той самий: «Тебе, заступницю спасіння...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар апостолів. Кондаки ап. Варнави і ап. Варфоломія читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні ап. Варфоломія, пісня 3-тя – 4 (з ірмосом), і ап. Варнави, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар апостолів; кондак ап. Варфоломія. «Слава» – кондак ап. Варнави, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостолів; кондак храму, кондак ап. Варфоломія. «Слава» – кондак ап. Варнави, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – апостолів. Апостол і Євангеліє – апостолів і дня."}]},
{"date":"06-12","weekday":"п’ятниця","title":"Прп. Онуфрія Великого (ІV). Прп. Петра Афонського (734). Прпп. Іоана, Андрія, Іраклемона і Феофіла (ІV).","readings":["Рим., 90 зач., V, 17 – VI, 2. Мф., 31 зач., IX, 14 – 17.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Мф., 43 зач., XI, 27 – 30."],"notes":"Служба прп. Онуфрія і прп. Петра шестирична, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 15-та. На «Господи, взиваю» стихири на 6: прп. Онуфрія, глас 8-ий – 3, і прп. Петра, глас той самий – 3. «Слава» – преподобних, глас 6-ий, «І нині» – Хрестобогородичний Мінеї, глас той же: «Сонце затьмарилося...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава» – преподобних,глас6-ий«Те,щозаобразом...»,«Інині»–Хрестобогородичний Мінеї, глас той самий: «Зачаття Твоє...». Після Трисвятого – тропар преподобних, глас 4-ий: «Боже отців наших...». «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар преподобних, глас 4-й: «Боже отців наших...» (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...». Кафизми 19-та і 20-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), прп. Онуфрія на 4, і прп. Петра на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (прп. Петра). Після 3-ої пісні – кондак та ікос прп. Петра, глас 2-ий; сідальний прп. Онуфрія, глас 4-ий. «Слава» – сідальний прп. Петра, глас 1-ий, «І нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос прп. Онуфрія, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха, світильний прп. Онуфрія. «Слава» – світильний прп. Петра, «І нині» – Хретобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава» – преподобних,гластойсамий:«Безлічченців...»,«Інині»–Хрестобогородичний Мінеї, глас той же: «Агниця нескверна...». Після Трисвятого – тропар преподобних, глас 4-й: «Боже отців наших...». «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобних. Кондаки прп. Онуфрія і прп. Петра читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні прп. Петра , пісня 3-тя – 4 (з ірмосом) і прп. Онуфрія, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар дня: «Спаси, Господи...», тропар преподобних; кондак прп. Онуфрія, кондак прп. Петра. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар преподобних; кондак дня: «Вознісся на Хрест...», кондак прп. Онуфрія, кондак прп. Петра. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар преподобних; кондак дня: «Вознісся на Хрест...», кондак храму, кондак прп. Онуфрія, кондак прп. Петра. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобних. Апостол і Євангеліє – дня і преподобних."}]},
{"date":"06-13","weekday":"субота","title":"Мц. Акилини (293). Свт. Трифилія, єп. Левкусії Кіпрської (бл. 370). Мц. Антоніни Нікейської (284 – 305). Прп. Анни (826) і сина її Іоана.","readings":["Рим., 84 зач., III, 19 – 26. Мф., 20 зач., VII, 1 – 8."],"notes":"Служба мц. Акилини і свт. Трифилія не має святкового знаку, звершується разом зі суботньою службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 18-та. На «Господи, взиваю» стихири на 6: мучениці, глас 4-ий – 3 і святителя, глас 8-ий – 3. «Слава, і нині» – догматик, глас 8-й: «Цар Небесний...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-й (мученичні із числа стихир на «Господи взиваю» – 1-ша: «Мученики Господні...», 2-га: «Мученики Твої, Господи...», 3-тя: «Які чесноти...», приспіви звичайні зі стиховних з Часослова). «Слава, і нині» – Богородичний Октоїха, глас той же: «Чиста Діво...» (у стихирах на стиховні). Після Трисвятого – тропар мучениці, глас 4-ий. «Слава» – тропар святителя, глас той самий, «І нині» – Богородичний воскресний, глас 8-й: «Ти, що ради нас...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар мучениці, глас 4-ий (двічі). «Слава» – тропар святителя, глас той самий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 16-та і 17-та (на 17-тій кафізмі ієрей звершує кадіння храму, як на «Господи взиваю», Царські врата залишаються закритими). Малі єктенії. Сідальні Октоїха. Псалом 50-й. Канони: У храмі Господському, Богородиці і святого – канон мучениці з ірмосом на 6 (ірмоси по двічі), святителя на 4 і Октоїха (мученикам) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичного канону Октоїха. Після 3-ої пісні – інший кондак святителя, глас 8-ий; сідальний мучениці, глас той самий. «Слава» – святителя, глас 3-ій, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мучениці, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха, «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий (мученичні із числа стихир на хвалитніх – 1-ша: «Великий подвиг ваш...», 2-га: «Мученики Христові непереможні...», 3-тя: «У броню віри...»; приспіви звичайні зі стиховних з Часослова). «Слава, і нині» – Богородичний Октоїха, глас той самий: «Я, Діво Пресвята...» (у стихирах на хвалитніх). Після Трисвятого – тропар мучениці, глас 4-ий. «Слава» – тропар святителя, глас той самий, «І нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар мучениці, «Слава» – тропар святителя. Кондаки мучениці і святителя читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня: «Апостоли, мученики...», тропар мучениці, тропар святителя; кондак храму, кондак мучениці, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». У храмі святого – тропар дня: «Апостоли, мученики...», тропар мучениці, тропар святителя; кондак мучениці, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». Примітка. У храмі святого в суботу тропар і кондак храму не співається, тому що всі святі найменовані у тропарі і кондаку дня. Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"06-14","weekday":"неділя","title":"2-га неділя після П’ятдесятниці. Всіх святих землі Української. Глас 1-й. Новомучеників та сповідників, які в Україні та в інших землях у ХХ ст. за Христа і православну віру постраждали (перехідне святкування в 2-гу неділю після П’ятдесятниці). Прор Єлисея (ІX ст. до Р. Х.). Свт. Мефодія, патр. Константинопольського (847). Блгв. кн. Мстислава, у св. хрещенні Георгія, Хороброго (1180). Прп. Єлисея Сумського (ХV – ХVІ). Всіх преподобних і богоносних отців, що на Святій Горі Афонській просяяли (перехідне святкування в 2-гу неділю після П’ятдесятниці).","glas":1,"readings":["Ран. – Єв. 2-е, Мк., 70 зач., XVI, 1 – 8.","Літ. – Рим., 81 зач. (від половини), II, 10 – 16. Мф., 9 зач., IV, 18 – 23.","Свв.: Євр., 330 зач., XI, 33 – XII, 2. Мф., 10 зач., IV, 25 – V, 12."],"notes":"Недільна служба Октоїха звершується у поєднанні зі службою Всіх святих землі Української. В цей день, по завершенні літургії звершуються поминання козаків і селян, що життя своє поклали на полі Берестецької битви за віру Православну і Батьківщину.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 1-ий – 4, і українських святих, глас 3-ій і глас 8-ий – 6. «Слава» – українських святих, глас 1-ий: «Веселися у Господі...», «І нині» – догматик, глас той самий: «Всесвітню славу...». Вхід. Прокимен дня, глас 6-ий: «Господь воцарився...», зі стихами (за звичаєм). Паремії українських святих – 3. На літії стихира храму і стихири українських святих, глас 8-ий і гласи 1-ий – 8-ий. «Слава, і нині» – Богородичний воскресний, глас 8-ий: «Радуйтеся з нами...», або Богородичний воскресний, глас 8-ий: «Безневісна Діво...». На стиховні стихири воскресні, глас 1-ий. «Слава» – українських святих, глас 2-ий: «Новий доме Єфрафів...» [1], «І нині» – Богородичний Мінеї (на ряду), глас 2-ий: «Вишні собори...»; або глас 8-ий: «О, преславне чудо...»; або Богородичний воскресний за гласом «Слави»: «О нове чудо...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар українських святих, глас 8-ий (один раз)."},{"svc":"УТРЕНІ","text":"НА УТРЕНІ на «Бог Господь» – тропар воскресний, глас 1-ий (двічі). «Слава» – тропар тропар українських святих, глас 8-ий, «І нині» – Богородичний воскресний, глас той самий: «Ти, що ради нас...». Кафизми 2-га і 3-тя. Малі єктенії. Сідальні воскресні. Полієлей. Величання українських святих: «Ублажаємо вас, чудотворці наші славні, що землю українську чеснотами вашими осяяли і образ спасіння нам ясно показали» і вибраний псалом. Без заключного «Слава, і нині», відразу після останнього стиха вибраного псалма і величання, співаємо тропарі воскресні, глас 5-ий: «Ангельський собор...». Іпакої гласу: «Покаяння розбійника...». Сідальні українських святих після 1-ої і 2-ої кафизми (один раз, (без Богородичних): від 1-го стихослів’я – глас 3-ий: «Мужайся, Христова Церкво...»; від 2-го стихослів’я – глас 1-ий: «Якщо і говорять...») і полієлейний сідальний, глас 5-ий: «Прикрашайся, світися, Русь-Україна православна...». «Слава» – інший полієлейний сідальний, глас 3-ий українських святих: «Радісно святкуючи нинішнє торжество...», «І нині» – Богородичний, глас 4-ий: «Як незбориму стіну...». Степенні гласу. Прокимен воскресний, глас 1-ий: «Нині воскресну, говорить Господь...». Євангеліє воскресне 2-ге. «Воскресіння Христове бачивши...». Після 50-ого псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...» [2]. Канони: воскресний з ірмосом на 4 (ірмоси 1 раз), Богородиці (Октоїха) на 2, українських святих на 8. Біблійні пісні «Співаймо Господеві...». Примітка. Зазвичай в богослужбовій приходській практиці біблійні стихи на недільних всенічних не використовуються, а беруться молебні приспіви, наприклад: «Слава Господи святому Воскресінню Твоєму», «Пресвята Богородице, спаси нас», «Всі святі землі української моліть Бога за нас». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос українських святих, глас 3-ий; сідальний українських святих, глас 7-ий: «Коли нічна темрява згущається...», «Слава і нині» – сідальний ризі Господній, глас 4-ий: «Поспішаймо, вірні...». Після 6-ої пісні – кондак та ікос воскресні, глас 1-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 2-ий. «Слава» – світильний україських святих: «В піснях прославмо...», «І нині» – Богородичний Мінеї (на ряду) «Світлом лиця Твого...»; або Богородичний воскресного екзапостиларія «Перед Твоїм зачаттям...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 1-ий – 4, і українських святих, глас 5-ий і глас 4-ий – 4. «Слава» – стихира євангельська 2-га, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар українських святих. Кондаки українських святих і воскресний читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6, українських святих (в Мінеї на ряду) – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар воскресний, тропар українських святих. «Слава» – кондак українських святих, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар українських святих; кондак воскресний. «Слава» – кондак українських святих, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар українських святих; кондак воскресний. «Слава» – кондак українських святих, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні і українських святих. Апостол і Євангеліє – дня і українських святих. [1] Існує звичай співати стихири «Земле Українська...», «Церкво Українська...», «Соборе святих українських...», «Новий доме Євфрафів...» як одну стихиру (поспіль, без стихів) на «Славу». [2] У храмах, освячених на честь Всіх святих, що в землі Українській просіяли, співаються антифони гласу, а прокимен і Євангеліє – українських святих. Після 50-го псалма: «Слава» – «Молитвами всіх святих українських...», «І нині» – «Молитвами Богородиці...». Стихира українських святих."}]},
{"date":"06-15","weekday":"понеділок","title":"3-й тиждень після П’ятдесятниці. Прор. Амоса (VІІІ ст. до Р. Х.). Свт. Михаїла, першого митр. Київського і всієї Руси (992). Мчч. Віта, Модеста і Крискентії, годувальниці (бл. 303). Мч. Дули Килікійського (305 – 313). Прп. Дули, страстотерпця, Єгипетського. Прп. Ієроніма Блаженного Стридонського (420). Свт. Августина Блаженного, єп. Іпонійського (430). Перенесення мощів прп. Федора Сикеота, єп. Анастасіупольського (бл. ІХ). Блгв. кн. Лазаря Сербського (1389). Свт. Єфрема ІІ, патр. Сербського (ХІV).","readings":["Ран. – Ін., 35 зач. (від половини), X, 1 – 9.","Літ. – Рим., 94 зач., VII, 1 – 13. Мф., 34 зач., IX, 36 – X, 8.","Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16."],"notes":"Звершується полієлейна служба свт. Михаїла, першого митр. Київського і всієї Руси.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири святителя, глас 5-ий – 6 (кожна стихира двічі). «Слава» – святителя, глас 3-ий: «Свідка істини...», «І нині» – догматик, глас той самий: «Як нам не дивуватися...». Вхід. Прокимен дня. Паремії святителя – 3. На стиховні стихири святителя, глас 2-ий (з приспівами своїми). «Слава» – святителя, глас 6-ий: «Божественний Дух...», «І нині» – Богородичний воскресний, глас той же: «Богородице, Ти єси лоза...» (Часослов, Богородичний 3-го часу). Після Трисвятого – тропар святителя, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 4-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...». Кафизми 4-та і 5-та. Малі єктенії. Сідальні святителя (по двічі). Полієлей. Величання святителя і вибраний псалом. Сідальний святителя після полієлея, глас 8-ий: «Як начальнику архієреїв...» (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий: «Як істинна утіха...». Степенна – 1-ий антифон 4-го гласу. Прокимен святителя, глас 4-ий: «Чесна перед Господом смерть преподобних Його». Стих: «Що віддам Господеві за все, що Він воздав мені». Євангеліє – святителя. Після 50-го псалма: «Слава» – «Молитвами святителя Михаїла...». Стихира святителя, глас 6-ий: «Божественний Дух...» (славник у стихирах на стиховні) або глас 3-й: «Свідка істини» (славник на «Господи взиваю»). Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і святителя на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ї пісні – сідальний святителя, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ї пісні – кондак та ікос святителя, глас 2-ий. На 9-й пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний святителя (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири святителя, глас 1-ий – 4 (перша стихира – двічі). «Слава» – святителя, глас 2-ий: «З небес прийнявши...», «І нині» – Богородичний, глас той самий: «Спаси від бід...». Велике славослів’я. Після Трисвятого – тропар святителя, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар та кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні святителя, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар святителя.«Слава»–кондаксвятителя,«Інині»–кондакхраму. У храмі святого – тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"06-16","weekday":"вівторок","title":"Свт. Тихона, єп. Амафунтського (425). Сщмч. Тигрія, пресвітера, і мч. Євтропія, читця (бл. 404).","readings":["Рим., 95 зач., VII, 14 – VIII, 2. Мф., 35 зач., X, 9 – 15."],"notes":"Служба свт. Тихона, єп. Амафунтського не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 6-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 1-ий – 3, і святителя, глас 8-ий – 3. «Слава і нині» – Богородичний Мінеї, глас той же: «Народивши нестерпний вогонь...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. «Слава і нині» – Богородичний Октоїха, глас той самий: «Діво Всехвальна...». Після Трисвятого – тропар святителя, глас 1-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Благодатна Богородице...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар святителя, глас 1-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Благодатна Богородице...». Кафизми 7-ма і 8-ма. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і святителя на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – інший кондак святителя, глас 8-ий, сідальний святителя, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак святителя, глас 3-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий. «Слава і нині» – Богородичний Октоїха, глас той самий: «Блудницю і блудного...». Після Трисвятого – тропар святителя, глас 1-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Того, Якого, без матері...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар святителя; кондак дня, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар святителя; кондак дня, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"06-17","weekday":"середа","title":"Мчч. Мануїла, Савела та Ісмаїла (362).","readings":["Рим., 96 зач., VIII, 2 – 13. Мф., 36 зач., X, 16 – 22.","Мчч.: Еф., 233 зач., VI, 10 – 17. Лк., 106 зач., XXI, 12 – 19."],"notes":"Служба мчч. Мануїла, Савела та Ісмаїла не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 1-ий – 3, і мучеників, глас 4-ий – 3. «Слава» – мучеників, глас 8-ий: «Чисто полюбивши Тебе...», «І нині» – Хрестобогородичний Мінеї, глас той же: «Що це за видіння...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той самий: «Коли побачила...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар мучеників, глас 4-ий (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...». Кафизми 10-та і 11-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і мучеників на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний мучеників, глас 1-ий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос мучеників, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний мучеників, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той самий: «Біля хреста Твого...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мучеників."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському – тропар дня: «Спаси, Господи...», тропар мучеників; кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар мучеників; кондак дня: «Вознісся на Хрест...», кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар мучеників; кондак дня: «Вознісся на Хрест...», кондак храму, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і мучеників. Апостол і Євангеліє – дня і мучеників."}]},
{"date":"06-18","weekday":"четвер","title":"Мчч. Леонтія, Іпатія та Феодула (70 – 79). Прп. Леонтія, канонарха Києво-Печерського, в Дальніх печерах (ХІV).","readings":["Рим., 98 зач., VIII, 22 – 27. Мф., 37 зач., X, 23 – 31."],"notes":"Служба мч. Леонтія не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 12-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 1-ий – 3, і мученика, глас 8-ий – 3. «Слава» – мученика, глас 1-ий: «Страстотерпче Леонтію...», «І нині» – Богородичний Мінеї, за гласом «Слави», від менших: «Радуйся, радосте праотців...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. «Слава» – мученика, глас 4-ий: «Страстотерпче Леонтію...», «І нині» – Богородичний Мінеї, за гласом «Слави», від менших: «Маючи Тебе, Богородице...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Слово Отче...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар мученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Слово Отче...». Кафизми 13-та і 14-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і мученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний мученика, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос мученика, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – мученика, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий. «Слава і нині» – Богородичний Октоїха, глас той самий: «Радуйся, Богородице...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Богородице, ти вища...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, інший тропар дня, тропар мученика; кондак дня, інший кондак дня, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, інший тропар дня, тропар храму, тропар мученика; кондак дня, інший кондак дня, кондак храму, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і мученика. Апостол і Євангеліє – дня і мученика."}]},
{"date":"06-19","weekday":"п’ятниця","title":"Апостола Іуди, брата Господнього по плоті (бл. 80). Мч. Зосими (ІІ). Прп. Паїсія Великого (V). Прп. Іоана Палестинського, пустельника (VІ). Прп. Паїсія Хіландарського (ХVІІІ, Болг.).","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – Рим., 101 зач., IX, 6 – 19. Мф., 38 зач., X, 32 – 36; XI, 1.","Ап.: Іуд., 77 зач., I, 1 – 10. Ін., 48 зач. (від половини), XIV, 21 – 24."],"notes":"Звершується полієлейна служба ап. Іуди, брата Господнього.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири апостола, глас 1-ий – 8. «Слава» – апостола, глас 8-ий: «Ти, що ясно...», «І нині» – догматик, глас той самий: «Цар Небесний...». Вхід. Прокимен дня. Паремії апостола – 3 (за традицією, новозавітні паремії читаються при відкритих царських вратах). На стиховні стихири апостола, глас 4-ий (зі своїми приспівами). «Слава» – апостола, глас 2-ий: «Ревністю Божественною...», «І нині» – Богородичний воскресний, глас той самий: «О, нове чудо...». Після Трисвятого – тропар апостола, глас 1-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Коли Гавриїл...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 1-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Коли Гавриїл...». Кафизми 19-та і 20-та. Малі єктенії. Сідальні апостола (по двічі). Полієлей. Величання апостола і вибраний псалом. Сідальний апостола після полієлея, глас 8-ий (двічі). «Слава, і нині» – Богородичний, глас той самий: «Небесні сили...». Степенна – 1-ий антифон 4-го гласу. Прокимен апостола, глас 4-ий: «По всій землі...». Євангеліє апостола. Після 50- го псалма: «Слава» – «Молитвами апостола...». Стихира апостола, глас 1-ий: «По всій землі...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і апостола на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – інший кондак апостола, глас 2-ий; сідальний апостола, глас 8-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний апостола (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостола, глас 5-ий – 4 (перша стихира – двічі). «Слава» – апостола, глас 2-ий: «Залишивши земне...», «І нині» – Богородичний, глас той самий: «Спаси від бід...». Велике славослів’я. Після Трисвятого – тропар апостола, глас 1-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Коли Гавриїл...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар апостола. Кондаки апостола читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні апостола, пісня 3-тя – 4 (з ірмосом), і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар апостола; кондак апостола. «Слава» – інший кондак апостола, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостола; кондак храму, кондак апостола. «Слава» – інший кондак апостола, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – апостола. Апостол і Євангеліє – дня і апостола."}]},
{"date":"06-20","weekday":"субота","title":"Сщмч. Мефодія, єп. Патарського (312). Мчч. Інни, Пінни та Римми (І – ІІ). Сщмчч. Аристоклія, пресвітера, Димитріана, диякона, і мч. Афанасія, читця (бл. 306). Свт. Левкія, спов., єп. Врунтисіопольського (V). Свт. Мини Києво-Печерського, єп. Полоцького (1116). Прав. Миколая Кавасили (1397/98).","readings":["Рим., 85 зач., III, 28 – IV, 3. Мф., 24 зач., VII, 24 – VIII, 4."],"notes":"Служба сщмч. Мефодія, єп. Патарського не має святкового знаку, звершується разом із суботньою службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 18-та. На «Господи, взиваю» стихири священномученика, глас 4-ий – 6 (кожна стихира – двічі). «Слава, і нині» – догматик, глас 1-ий: «Всесвітню славу...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий (мученичні із числа стихир на «Господи взиваю» – 2-га: «Молитвами, Господи...», 3-тя: «Ваше сповідання...», 4-та: «О, добра ваша...», приспіви звичайні зі стиховних з Часослова). «Слава, і нині» – Богородичний Октоїха, глас той самий: «Воістину незбагненна...» (у стихирах на стиховні). Після Трисвятого – тропар священномученика, глас 1-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Коли Гавриїл...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 1-ий (двічі). «Слава, і нині» – Богородичний воскресний, за гласом тропаря: «Коли Гавриїл...». Кафизми 16-та і 17-та (на 17-тій кафізмі ієрей звершує кадіння храму, як на «Господи взиваю», Царські врата залишаютьсязакритими).Малієктенії.СідальніОктоїха.Псалом50-й. Канони: У храмі Воскресіння Христового – канон воскресний рядового гласу (з попередньої неділі) з ірмосом на 6 (ірмоси по двічі, тропарі на 4: два воскресних тропарі, один Хрестовоскресний і один Богородичний), священномученика на 4 і Октоїха (мученичний) на 4. У храмі Господському і Богородиці – канон храму з ірмосом на 6 (ірмоси по двічі), священномученика на 4 і Октоїха (мученичний) на 4. У храмі святого – канон священномученика з ірмосом на 6 (ірмоси по двічі), храму на 4 і Октоїха (мученичний) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичного канону Октоїха. Після 3-ої пісні – сідальний священномученика, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак священномученика, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха, «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий (мученичні із числа стихир на хвалитніх – 1-ша: «Прийдіть, всі люди...», 2-га: «Ці воїни...», 3-тя: «Вас, всехвальні...»; приспіви звичайні зі стиховних з Часослова). «Слава, і нині» – Богородичний Октоїха, глас той самий: «Радуйся за нас...» (у стихирах на хвалитніх). Після Трисвятого – тропар священномученика, глас 1-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Того, Хто без матері...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня: «Апостоли, мученики...», тропар священномученика; кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». У храмі святого – тропар дня: «Апостоли, мученики...», тропар священномученика; кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». Примітка. У храмі святого в суботу тропар і кондак храму не співається, тому що всі святі найменовані у тропарі і кондаку дня. Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"06-21","weekday":"неділя","title":"3-тя неділя після П’ятдесятниці. Глас 2-й. Мч. Юліана Тарсійського (бл. 305). Сщмч. Терентія, єп. Іконійського (І). Прпп. Юлія, пресвітера, і Юліана, диякона (V). Мчч. Арчила ІІ, царя Іверського (744), і Луарсаба ІІ, царя Карталинського (1622, Груз.).","glas":2,"readings":["Ран. – Єв. 3-є, Мк., 71 зач., XVI, 9 – 20.","Літ. – Рим., 88 зач., V, 1 – 10. Мф., 18 зач., VI, 22 – 33."],"notes":"Служба мч. Юліана Тарсійського не має святкового знаку, звершується разом з недільною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 2-ий – 7 і мученика, глас 4-ий – 3. «Слава» – мученика, глас 6-ий: «Преподобні отці...», «І нині» – догматик, глас 2-ий: «Минула тінь закону...». Вхід. Прокимен дня. На літії стихира храму і Богородичні стихири Павла Аморейського, глас 6-й (на «Господи взиваю» у воскресній службі 2-го гласу в Октоїху, без стихів). «Слава, і нині» – його ж стихира, глас той же: «Радуйся, Непостидна Заступнице...». На стиховні стихири воскресні, глас 2-ий. «Слава» – мученика, глас 6-й: «Прийдіть, любителі...», «І нині» – Богородичний воскресний за гласом «Слави»: «Творець і Визволитель мій...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"УТРЕНІ","text":"НА УТРЕНІ на «Бог Господь» – тропар воскресний, глас 2-ий (двічі). «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 2-га і 3-тя. Малі єктенії. Сідальні воскресниі. Непорочні (У сучасній практиці замінюються співом полієлею). «Ангельський собор...». Іпакої, степенні і прокімен – гласу. Євангеліє воскресне 3-те. «Воскресіння Христове бачивши...». Після 50-ого псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-й: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси один раз), Хрестовоскресний на 3, Богородиці на 3, і мученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос мученика, глас 2-ий; сідальний, глас 1-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 2-ий. На 9-й пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 3-ій. «Слава» – світильний мученика. «І нині» – Богородичний Мінеї (на ряду) «Світлом лиця Твого...»; або Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 2-ий – 8. «Слава» – стихира євангельська 3-тя, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар мученика. Кондак тільки воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 8. Після входу – тропарі і кондаки: У храмі Господському – тропар воскресний, тропар мученика. «Слава» – кондак мученика, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар мученика; кондак воскресний. «Слава» – кондак мученика, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар мученика; кондак воскресний, кондак храм. «Слава» – кондак мученика, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні. Апостол і Євангеліє – дня."}]},
{"date":"06-22","weekday":"понеділок","title":"4-й тиждень після П’ятдесятниці. Сщмч. Євсевія, єп. Самосатського (380). Мчч. Зинона та Зіни (304). Мчч. Галактіона та Юліанії.","readings":["Рим., 102 зач., IX, 18 – 33. Мф., 40 зач., XI, 2 – 15."],"notes":"Служба сщмч. Євсевія, єп. Самосатського не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: Октоїха, глас 2-ий – 3, і священномученика, глас 8-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той же: «Народивши нестерпнмй вогонь...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Радуйся, Маріє Богородице...». Після Трисвятого – тропар священномученика (загальний), глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика (загальний), глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована...». Кафизми 4-та і 5-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і священномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний священномученика, глас 4-й. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак священномученика, глас 4-й. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «На Тебе, Богородице...». Після Трисвятого – тропар священномученика (загальний), глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти вища...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар священномученика; кондак дня, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар священномученика; кондак дня, кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"06-23","weekday":"вівторок","title":"Мц. Агрипини Римлянки (ІІІ). Сщмч. Євстохія, пресвітера, мчч. Гая, Провія, Лолія, Урвана та інших (ІV).","readings":["Рим., 104 зач., X, 11 – XI, 2. Мф., 41 зач., XI, 16 – 20 (за вівторок).","Рим., 105 зач., XI, 2 – 12. Мф., 42 зач., XI, 20 – 26 (за середу)."],"notes":"Служба мч. Агрипини не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 6-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 2-ий – 3, і мучениці, глас 4-ий – 3. «Слава і нині» – Богородичний Мінеї, глас той самий: «Бісівськими підступами...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава і нині» – Богородичний Октоїха, глас той самий: «Все уповання...». Після Трисвятого – тропар мучениці, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «До Богородиці щиро...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучениці, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «До Богородиці щиро...». Кафизми 7-ма і 8-ма. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і мучениці на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний мучениці, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мучениці, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава і нині» – Богородичний Октоїха, глас той самий: «Радуйся, Маріє Богородице...». Після Трисвятого – тропар мучениці, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мучениці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар мучениці; кондак дня, кондак мучениці. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар мучениці; кондак дня, кондак храму, кондак мучениці. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня (вівторка) і середи."}]},
{"date":"06-24","weekday":"середа","title":"Різдво чесного славного пророка, Предтечі та Хрестителя Господнього Іоана. Мчч. сімох братів: Орентія, Фарнакія, Єроса, Фірмоса, Фірмина, Киріака і Лонгина (ІV).","readings":["Ран. – Лк., 3 зач., I, 24 – 25, 57 – 68, 76, 80.","Літ. – Предтечі: Рим., 112 зач., XIII, 11 – XIV, 4. Лк., 2 зач., I, 5 – 25, 57 – 68, 76, 80."],"notes":"Звершується бдінна служба Різдва Іоана Предтечі","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: Предтечі, глас 4-ий – 8 (перша стихира двічі). «Слава» – Предтечі, глас 6-ий: «Сьогодні світильник світла...», «І нині» – Мінеї, глас той самий: «Єлизавета зачала Предтечу...». Вхід. Прокимен дня. Паремії Предтечі – 3. На літії стихири Предтечі, глас 1-ий. «Слава» – Предтечі, глас 5-ий: «Кінець пророків...», «І нині» – Богородичний воскресний, глас той самий: «Ти храм і двері...». На стиховні стихири Предтечі, глас 2-ий (зі своїми приспівами). «Слава» – Предтечі, глас 8-ий: «Нині сповнилося пророка...», «І нині» – Мінеї, глас той самий: «Послухай, що говорить Єлизавета Діві Марії...». Після Трисвятого – тропар Предтечі, глас 4-ий (двічі), і «Богородице Діво...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Предтечі, глас 4-ий (двічі). «Слава і нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 10-та і 11-та. Малі єктенії. Сідальні Предтечі (по двічі). Полієлей. Величання Предтечі: «Величаємо тебе, Предтече Спасів Іоане, і шануємо від неплідної преславне народження твоє» і вибраний псалом. Сідальний Предтечі, глас 8-ий: «Нехай радіє батько...» (двічі). «Слава і нині» – Богородичний Мінеї, глас той самий: «Завжди дякуємо Тобі...». Степенна – 1-ий антифон 4-го гласу. Прокимен Предтечі, глас 4-ий: «І ти, дитя, пророком Вишнього назвешся». Стих: «Благословенний Господь Бог Ізраїлів, що відвідав і визволив людей Своїх». Євангеліє – Лк., Зач. 3. Після 50-го псалма: «Слава» – «Молитвами святого славного Пророка, Предтечі і Хрестителя Іоана...». Стихира Предтечі, глас 2-ий: «Той, хто в утробі матері освятився...». Канони: Предтечі 1-ий з ірмосом на 8 (ірмоси по двічі) і 2-ий на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний Предтечі, глас 8-ий. «Слава» – інший сідальний Предтечі, глас 4-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак і ікос Предтечі, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний Предтечі: «Сьогодні радісне Предтечеве народження...» (двічі). «Слава і нині» – Богородичний Мінеї: «Пророки проповідували...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Предтечі, глас 8-ий – 4. «Слава» – Предтечі, глас 6-ий: «Зірка зірок, Предтеча...», «І нині» – Богородичний, глас той самий: «Богородице, Ти єси виноградна лоза...» (Часослов, Богородичний 3-го часу). Велике славослів’я. Після Трисвятого – тропар Предтечі, глас 4-ий. «Слава і нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Предтечі."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ: Блаженні Предтечі: 1-го канону пісня 3-тя – 4 (з ірмосом), і 2-го канону пісня 6-та на 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар Предтечі; «Слава» – кондак Предтечі, «І нині» – кондак храму. У храмі святого – тропар Предтечі. «Слава» – кондак Предтечі, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – Предтечі. Рядові читання переносяться на вівторок 23 червня."}]},
{"date":"06-25","weekday":"четвер","title":"Прмц. Февронії, діви (бл. 304). Манявської ікони Божої Матері «Визволителька» (1788).","readings":["Рим., 106 зач., XI, 13 – 24. Мф., 43 зач., XI, 27 – 30.","Прмц.: 2 Кор., 181 зач., VI, 1 – 10. Лк., 33 зач., VII, 36 – 50."],"notes":"Служба віддання Різдва Іоана Предтечі і прмц. Февронії, діви не має святкового знаку, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізми немає. На «Господи, взиваю» стихири на 6: Предтечі (див. в Мінеї 25 червня), глас 4-ий – 3, і преподобномучениці, глас той самий – 3. «Слава, і нині» – Мінеї, глас 8-ий: «Подивись на Єлисавету...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава, і нині» – Мінеї, глас 6-ий: «Єлисавета зачала Предтечу...». Після Трисвятого – тропар Предтечі, глас 4-ий. «Слава» – тропар преподобномучениці, глас той самий, «І нині» – Богородичний за гласом «Слави», від менших: «Слово Отче...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Предтечі, глас 4-ий (двічі). «Слава» – тропар преподобномучениці, глас той самий, «І нині» – Богородичний за гласом «Слави», від менших: «Слово Отче...». Кафизми 13-та і 14-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), Предтечі (у Мінеї за 25 червня) на 4 і преподобномучениці на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобномучениці). Після 3-ої пісні – кондак преподобномучениці, глас 6-ий; сідальний Предтечі, глас 8-ий. «Слава» – сідальний преподобномучениці, глас той самий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос Предтечі, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – Світильний Предтечі (Мінеї), «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава» – Предтечі, глас 2-ий: «Пророка із пророків...», «І нині» – Богородичний по гласу «Слави», від менших: «Все уповання моє...». Після Трисвятого – тропар Предтечі, глас 4-ий. «Слава» – тропар преподобномучениці, глас той самий, «І нині» – Богородичний по гласу «Слави», від менших: «Богородице, Ти вища...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Предтечі. «Слава» – тропар преподобномучениці. Кондаки преподобномучениці і Предтечі читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар Предтечі (Мінеї), тропар дня, інший тропар дня, тропар преподобномучениці; кондак Предтечі (Мінеї), кондак дня, інший кондак дня, кондак преподобномучениці. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар Предтечі (Мінеї), тропар дня, інший тропар дня, тропр храму, тропар преподобномучениці; кондак Предтечі (Мінеї), кондак дня, інший кондак дня, кондак храму, кондак преподобномучениці. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобномучениці. Апостол і Євангеліє – дня і преподобномучениці."}]},
{"date":"06-26","weekday":"п’ятниця","title":"Прп. Давида Солунського (бл. 540). Прп. Іоана, єп. Готського (VІІІ). Свт. Діонісія Києво-Печерського, архієп. Суздальського (1385). Ліддської (Римської) (І), Тихвинської (1383) та Нямецької (1399) ікон Божої Матері.","readings":["Рим., 107 зач., XI, 25 – 36. Мф., 44 зач., XII, 1 – 8."],"notes":"Служба прп. Давида Солунського не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 15-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 2-ий – 3, і преподобного, глас 8-ий – 3. «Слава» – преподобного, глас 6-ий, «І нині» – Хрестобогородичний Мінеї, глас той самий: «Сонце затьмарилося...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава» – преподобного, глас 8-ий «Монахів безліч...», «І нині» – Хрестобогородичний Мінеї, глас той самий. Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця, і Пастиря...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 8-ий (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця, і Пастиря...». Кафизми 19-та і 20-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний преподобного, глас 8-ий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преодобного, глас 1-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний преподобного, «І нині» – Хретобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава» – преподобного, глас 5-ий, «І нині» – Хрестобогородичний Мінеї. Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Плід утроби Твоєї...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі і кондаки: У храмі Господському – тропар дня: «Спаси, Господи...», тропар преподобного; кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар преподобного; кондак дня: «Вознісся на Хрест...», кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар преподобного; кондак дня: «Вознісся на Хрест...», кондак храму, кондак преподобних. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"06-27","weekday":"субота","title":"Прп. Самсона, гостинного (бл. 530). Прав. Іоани, мироносиці (І). Прп. Севіра, пресвітера (VІ). Прп. Георгія Іверського Святогорця (1065, Груз.). Прп. Мартина Турівського (1150). Сщмч. Кирила (Лукаріса), патр. Константинопольського (1638).","readings":["Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 67 зач., XII, 32 – 40.","Ряд.: Рим., 92 зач., VI, 11 – 17. Мф., 26 зач., VIII, 14 – 23."],"notes":"Служба прп. Самсона, гостинного, не має святкового знаку, звершується разом із суботньою службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 18-та. На «Господи, взиваю» стихири преподобного, глас 1-ий – 6 (кожна стихира двічі). «Слава, і нині» – догматик, глас 2-й: «Минула тінь закону...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий (мученичні із числа стихир на «Господи взиваю» – 2-га: «Ви, страстотерпці...», 3-тя: «Молитвами за нас...», 4-та: «Собори мучеників...», приспіви звичайні зі стиховних з Часослова). «Слава, і нині» – Богородичний Октоїха (із стихир на стиховні): «Спаси від бід...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – Богородичний воскресний, глас 2-ий: «Все вище розуму...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 8-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Ти, що зарази нас...». Кафизми 16-а і 17-а (на 17-тій кафізмі ієрей звершує кадіння храму, як на «Господи взиваю», Царські врата залишаютьсязакритими).Малієктенії.СідальніОктоїха.Псалом50-й. Канони: У храмі Воскресіння Христового – канон воскресний рядового гласу (з попередньої неділі) з ірмосом на 6 (ірмоси по двічі, тропарі на 4: два воскресні тропарі, один Хрестовоскресний і один Богородичний), преподобного на 4 і Октоїха (мученикам) на 4. У храмі Господському і Богородиці – канон храму з ірмосом на 6 (ірмоси по двічі), преподобного на 4 і Октоїха (мученикам) на 4. У храмі святого – канон преподобного з ірмосом на 6 (ірмоси по двічі), храму на 4 і Октоїха (мученикам) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичного канону Октоїха. Після 3-ої пісні – сідальний преподобного, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий (мученичні із числа стихир на хвалитніх – 1-ша: «За Христа постраждавши...», 2-га: «Всякі міста і країни...», 3-тя: «Хрест Христів...»; приспіви звичайні зі стиховних з Часослова). «Слава, і нині» – Богородичний Октоїха, глас той самий: «Прийдіть, піснями невмовкними...» (у стихирах на хвалитніх). Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Діво Пречиста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня: «Апостоли, мученики...», тропар преподобного; кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». У храмі святого – тропар дня: «Апостоли, мученики...», тропар преподобного; кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». Примітка. У храмі святого в суботу тропар і кондак храму не співається, тому що всі святі найменовані у тропарі і кондаку дня. Прокимен, алилуарій і причасний – преподобного і дня. Апостол і Євангеліє – преподобного і дня."}]},
{"date":"06-28","weekday":"неділя","title":"4-та неділя після П’ятдесятниці. Глас 3-й. Перенесення мощів мчч., безсрр. та чудотворців Кира та Іоана (412). Прп. Ксенофонта Робейського, ігумена (1262). Прп. Павла, лікаря (VII).","glas":3,"readings":["Ран. – Єв. 4-е, Лк., 112 зач., XXIV, 1 – 12.","Літ. – Рим., 93 зач., VI, 18 – 23. Мф., 25 зач., VIII, 5 – 13.","Безсрібн.: 1 Кор., 153 зач., XII, 27 – XIII, 8. Мф., 34 зач. (від половини), X, 1, 5 – 8."],"notes":"Звершується недільна служба Октоїха у поєднанні із службою мчч., безсрр. та чудотворців Кира та Іоана, без святкового знаку.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 3-ій – 7, мучеників, глас 4-ий – 3. «Слава» – мучеників, глас 8-ий: «Безліч ченців»; «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Вхід. Прокимен дня. На літії стихира храму і Богородичні стихири Павла Аморрейського, глас 3-ій (На «Господи, взиваю» у воскресній службі 3-го гласу в Октоїху, без стихів). «Слава, і нині» – його ж стихира, глас той же: «Всі чистою совістю...». На стиховні стихири воскресні, глас 3-ій. «Слава» – мучеників, глас 2-ий: «Прийдіть нині...», «І нині» – Богородичний воскресний, глас той самий: «О, нове чудо...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 3-ій (двічі). «Слава» – тропар мучеників, глас 5-ий, «І нині» – Богородичний воскресний, глас той самий: «Радуйся, двері Господні...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні воскресні. Непорочні. «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє воскресне 4-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Хрестовоскресний на 3, Богородиці на 3 і мучеників на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос мучеників, глас 3-ій, інший кондак мучеників, глас той самий; сідальний мучеників, глас 4-ий. «Слава і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 4-ий. «Слава» – світильний мучеників, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 3-ій – 8. «Слава» – стихира євангельська 4-та, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «У день спасіння світу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар мучеників. Кондак тільки воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 8. Після входу – тропарі та кондаки: У храмі Господському – тропар воскресний, тропар мучеників, кондак мучеників. «Слава» – інший кондак мучеників, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар мучеників; кондак воскресний, кондак мучеників. «Слава» – інший кондак мучеників, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар мучеників; кондак воскресний, кондак храму, кондак мучеників. «Слава» – інший кондак мучеників, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні і мучеників. Апостол і Євангеліє – дня і мучеників."}]},
{"date":"06-29","weekday":"понеділок","title":"5-й тиждень після П’ятдесятниці. Славних і всехвальних першоверховних апостолів Петра і Павла (бл. 67). Свт. Григорія, митр. Іраклійського (1925). Касперівської ікони Божої Матері (ХІХ).","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – Апп.: 2 Кор., 193 зач., XI, 21 – XII, 9. Мф., 67 зач., XVI, 13 – 19."],"notes":"Звершується всенічне бдіння на честь свв. первоверховних апостолів Петра і Павла.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири апостолів, глас 2-ий на 8 (перші дві стихири – тричі, третя стихира – двічі). «Слава» – апостолів, глас 4-ий: «Трикратним запитанням...», «І нині» – догматик, глас той самий: «Пророк Давид,...». Вхід. Прокимен дня. Паремії апостолів – 3 (за традицією, новозавітні паремії читаються при відкритих царських вратах). На літії стихири апостолів, глас 2-ий і глас 3-ій. «Слава» – апостолів, глас 5-ий: «Ви, всехвальні апостоли...», «І нині» – Богородичний, глас той самий: «Ублажаємо Тебе, Богородице...». На стиховні стихири апостолів, глас 1и-й (зі своїми приспівами). «Слава» – апостолів, глас 6-ий: «Радісне свято засяяло...», «І нині» – Богородичний воскресний, глас той самий: «Творець і Визволитель...». Після Трисвятого – тропар апостолів, глас 4-ий (двічі), і «Богородице Діво...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостолів, глас 4-ий (двічі). «Слава і нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...». Кафизми 4-та і 5-та. Малі єктенії. Сідальні апостолів. Полієлей. Величання апостолів: «Величаємо вас, святі першоверховні апостоли Петре i Павле, що весь світ ученням своїм просвiтили і всі краї землі до Христа привели» і вибраний псалом. Сідальний апостолів після полієлея, глас 8-ий (двічі). «Слава і нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен апостолів, глас 4-ий: «По всій землі розійшлося віщування їх і в кінці вселенної слова їх»; стих: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь». Євангеліє апостолів. Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира апостолів, глас 6-ий: «Благочестя істинних проповідників...». Канони: ап. Петра з ірмосом на 6 (ірмоси по двічі) і ап. Павла на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – іпакої апостолів, глас 8-ий: «Яка в’язниця не мала тебе в’язнем?..» (один раз). Після 6-ої пісні – кондак та ікос апостолів, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний апостолів (двічі). «Слава і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири: апостолів, глас 4-ий – 4. «Слава» – апостолів, глас 6-ий: «Прийшло для Церкви Христової...», «І нині» – Богородичний, глас той самий: «Богородице, Ти єси виноградна лоза...» (Часослов, Богородичний 3-го часу). Велике славослів’я. Після Трисвятого – тропар апостолів, глас 4-ий. «Слава і нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостолів."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні апостолів, 1-го канону (ап. Петра) пісня 3-тя – 4 (з ірмосом) і 2-го канону (ап. Павла) пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар апостолів. «Слава» – кондак апостолів, «І нині» – кондак храму. У храмі святого – тропар апостолів. «Слава» – кондак апостолів, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – апостолів. Апостол і Євангеліє – апостолів. Рядові Апостол і Євангеліє переносяться на вівторок 30 червня."}]},
{"date":"06-30","weekday":"вівторок","title":"Собор славних і всехвальних 12-ох апостолів: Петра, Андрія Першозванного, Якова Зеведеєвого, Іоана Богослова, Филипа, Варфоломія, Фоми, Матфея, Якова Алфеєвого, Іуди Якового, Симона Зилота і Матфія. Волинської (ХХ ст.), Баликінської (1711) та Горбанівської (1786) ікон Божої Матері.","readings":["Рим., 109 зач., XII, 4 – 5, 15 – 21. Мф., 45 зач., XII, 9 – 13 (за понеділок, під зачало).","Рим., 114 зач., XIV, 9 – 18. Мф., 46 зач., XII, 14 – 16, 22 – 30 (за вівторок).","Апп.: 1 Кор., 131 зач., IV, 9 – 16. Мк., 12 зач., III, 13 – 19."],"notes":"Служба собору свв. 12-ти апостолів славослівна, звершується по Мінеї.","sections":[{"svc":"ПОВСЯКДЕННІЙ ВЕЧІРНІ","text":"НА ПОВСЯКДЕННІЙ ВЕЧІРНІ кафізми немає. На «Господи, взиваю» стихири на 6: апп. Петра і Павла, глас 2-ий – 3, і апостолів, глас 4-ий – 3. «Слава» – апп. Петра і Павла, глас 6-ий: «Всечесне свято...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири апп. Петра і Павла, глас 4-ий (зі своїми приспівами). «Слава» – апп. Петра і Павла, глас 6-ий: «Свято радості...», «І нині» – Богородичний по глас той самий: «Богородице, Ти єси лоза...» (Часослов, Богородичний 3-го часу). Після Трисвятого – тропар апостолів, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостолів, глас 4-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 7-ма і 8-ма. Малі єктенії. Сідальні апостолів (по двічі). Псалом 50-й. Канони: апп. Петра і Павла (у Мінеї за 30 червня) з ірмосом на 8 (ірмоси по двічі) і 12-ти апостолів на 6. Біблійні пісні «Співаємо Господеві...». Катавасія «Відкрию уста мої». Після 3-ої пісні – сідальний апостолів, глас 4-ий. «Слава» – сідальний апп. Петра і Павла, глас 8-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостолів, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний апостолів. «Слава» – інший світильний апостолів, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалитніх стихири апп. Петра і Павла і апостолів, глас 4-ий – 4. «Слава» – апостолів, глас 8-ий: «Все творіння просвітили...», «І нині» – Богородичний, глас той самий: «Владичице, прийми...». Велике славослів’я. Після Трисвятого – тропар апостолів, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостолів."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні з канону 12-ти апостолів, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар апостолів. «Слава» – кондак апостолів, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостолів; кондак храму. «Слава» – кондак апостолів, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – апостолів. Апостол і Євангеліє – дня (понеділка і вівторка, під зачало) і апостолів."}]},
{"date":"07-01","weekday":"середа","title":"Безсрр. Косми та Даміана, які в Римі постраждали (284). Мч. Потита (ІІ). Прп. Петра, патрикія (854). Перенесення мощів прп. Іоана Рильського (1469). Прп. Никодима Святогорця (1809).","readings":["Рим., 117 зач., XV, 7 – 16. Мф., 48 зач., XII, 38 – 45.","Безсрібн.: 1 Кор., 153 зач., XII, 27 – XIII, 8. Мф., 34 зач. (від половини), X, 1, 5 – 8."],"notes":"Служба безсрр. Косми та Даміана, що в Римі постраждали, шестирична, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та. На «Господи, взиваю» стихири безсрібників, глас 1-ий і глас 4-ий – 6. «Слава» – безсрібників, глас 6-ий: «Безскінечною є благодать...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Нескверна Агниця...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава» – безсрібників, глас 6-ий: «Завжди маючи Христа...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Бачачи Тебе...». Після Трисвятого – тропар безсрібників, глас 8-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця, і Пастиря...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар безсрібників, глас 8-ий (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця, і Пастиря...». Кафизми 10-та і 11-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси один раз), 2-ий на 4, і безсрібників на 6. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний безсрібників, глас 8-ий. «Слава» – інший сідальний безсрібників, глас той самий, «І нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос безсрібників, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний безсрібників, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалитніх (від позначки «на 4») стихири безсрібників, глас 1-ий і глас 2-ий – 6 (до двох останніх стихир приспіви з Мінеї). «Слава» – безсрібників, глас 4-ий: «Маючи джерело зцілень...», «І нині» – Хрестобогородичний Мінеї за гласом «Слави»: «Бачачи розіпнутого...». Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава» – безсрібників, глас 8-ий: «Хто не здивується...», «І нині» – Хрестобогородичний Мінеї за гласом «Слави»: «Агниця нескверна...». Після Трисвятого – тропар безсрібників, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Плід утроби Твоєї...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак безсрібників."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4 і безсрібників, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси, Господи...», тропар безсрібників; кондак безсрібників. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар безсрібників; кондак дня: «Вознісся на Хрест...», кондак безсрібників. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар безсрібників; кондак дня: «Вознісся на Хрест...», кондак храму, кондак безсрібників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і безсрібників. Апостол і Євангеліє – дня і безсрібників."}]},
{"date":"07-02","weekday":"четвер","title":"Покладення чесної ризи Пресвятої Богородиці у Влахерні (V). Свт. Ювеналія, патр. Єрусалимського (бл. 458). Свт. Фотія, митр. Київського і всієї Руси (1431). Свт. Іоана (Максимовича), архієп. Шанхайського і Сан-Франциського, чудотворця (1966). Охтирської (1739) та Пожайської (ХVІІ) ікон Божої Матері.","readings":["Рим., 118 зач., XV, 17 – 29. Мф., 49 зач., XII, 46 – XIII, 3.","Богородиці: Євр., 320 зач., IX, 1 – 7. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершується славослівна служба покладення чесної ризи Пресвятої Богородиці.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. На «Господи, взиваю» стихири Богородиці, глас 4-ий – 6 (перші дві стихири – двічі). «Слава, і нині» – Богородиці, глас 2-ий: «Очистивши розум і помисли...». Входу немає. Прокимен дня. На стиховні стихири Богородиці, глас 1-ий (з приспівами своїми). «Слава, і нині» – Богородиці, глас 2-ий: «Як пресвітлим вінцем...». Після Трисвятого – тропар Богородиці, глас 8-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Богородиці, глас 8-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 13-та і 14-та. Малі ектенії. Сідальні Богородиці (по двічі). Псалом 50-ий. Канони: Богородиці з Мінеї 1-ий з ірмосом на 8 (ірмоси по двічі) і 2-ий на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний Богородиці, глас 4-ий. «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос Богородиці, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний Богородиці. «Слава, і нині» – інший світильний Богородиці. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Богородиці, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – Богородиці, глас 2-ий: «Очистивши розум...». Велике славослів’я. Після Трисвятого – тропар Богородиці, глас 8-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Богородиці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Богородиці, пісня 3-тя – 4 (1-го канону з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар храму, тропар Богородиці (ризи). «Слава» – кондак храму, «І нині» – кондак Богородиці (ризи). У храмі Богородиці – тропар Богородиці (ризи). «Слава, і нині» – кондак Богородиці (ризи). У храмі святого – тропар Богородиці (ризи), тропар храму. «Слава» – кондак храму, «І нині» – кондак Богородиці (ризи). Прокимен, алилуарій і причасний – Богородиці (ризи). Апостол і Євангеліє – дня і Богородиці (ризи)."}]},
{"date":"07-03","weekday":"п’ятниця","title":"Мч. Якинфа (108). Мчч. Діомида, Євлампія, Аскліпіодота і мц. Голіндухи (ІІ). Прпп. Анатолія, затворника, у Ближніх печерах (ХІІ), та іншого Анатолія, затворника, у Дальніх печерах (ХІІІ). Мчч. Мокія і Марка (ІV). Прп. Олександра, засновника обителі «Невсипущих» (бл. 430). Свт. Анатолія, патр. Константинопольського (458).","readings":["Рим., 120 зач., XVI, 1 – 16. Мф., 50 зач., XIII, 3 – 9."],"notes":"Служба мч. Якинфа не має святкового знаку, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 15-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 3-ій – 3, і мученика, глас 8-ий – 3. «Слава, і нині» – Хрестобогородичний Мінеї, глас той самий: «Шоце за видіння...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той самий: «Дивлячись на Тебе...». Після Трисвятого – тропар мученика, глас 4-ий: «Мученик Твій, Господи...». «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця, і Пастиря...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мученика, глас 4-ий: «Мученик Твій, Господи...» (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця, і Пастиря...». Кафизми 19-та і 20-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і мученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – кондак інший мученика, глас 4-ий, сідальний мученика, глас 3-ий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мученика, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава і нині» – Хрестобогородичний Октоїха, глас той самий: «Бачачи розіп’ятим...». Після Трисвятого – тропар мученика, глас 4-ий: «Мученик Твій, Господи...». «Слава, і нині» – Богородичний за гласом тропаря, від менших: «плід утроби Твоєї...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар мученика. Кондаки мученика читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси, Господи...», тропар мученика; кондак мученика, інший кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар мученика; кондак дня: «Вознісся на Хрест...», кондак мученика, інший кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар мученика; кондак дня: «Вознісся на Хрест...», кондак храму, кондак мученика, інший кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"07-04","weekday":"субота","title":"Свт. Андрія, архієп. Критського (740). Прп. Марфи, матері Симеона Дивногорця (551). Мчч. Феодота і Феодотії (108). Сщмч. Федора, єп. Киринейського (310). Галатської ікони Божої Матері.","readings":["Свт.: Євр., 318 зач. (від пол.), VIII, 3 – 6. Мф., 21 зач., VII, 12 – 21.","Ряд.: Рим., 97 зач., VIII, 14 – 21. Мф., 30 зач., IX, 9 – 13."],"notes":"Служба свт. Андрія, архієп. Критського і прп. Марфи не має святкового знаку, звершується разом із суботньою службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: святителя, глас 1-ий – 3, і преподобної, глас 4-ий – 3. «Слава» – преподобної, глас той самий: «Духовною благодаттю...», «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій (мученичні із числа стихир на «Господи, взиваю» – 2-га: «Велика сила...», 3-тя: «Велика сила...», 4-та: «Пророки, і апостоли...», приспіви звичайні зі стиховних з Часослова). «Слава» – святителя, глас 8-ий: «Ченців безліч...», «І нині» – Богородичний за гласом «Слави», від менших: «Чиста Діво...». Після Трисвятого – тропар святителя, глас 4-ий: «Правилом віри...». «Слава» – тропар преподобної, глас 8-ий: «У тобі, мати...», «І нині» – Богородичний воскресний, глас 3-ій: «Тебе, заступницю...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 4-ий: «Правилом віри...» (двічі). «Слава» – тропар преподобної, глас 8-ий: «У тобі, мати...», «І нині» – Богородичний воскресний, глас той самий: «Ти, що заради нас...». Кафизми 16-та і 17-та (на 17-тій кафізмі ієрей звершує кадіння храму, як на «Господи, взиваю», царські врата залишаються закритими). Малі ектенії. Сідальні Октоїха. Псалом 50-ий. Канони: в храмі Господньому, Богородиці і святого – канон святителя з ірмосом на 6 (ірмоси по двічі), преподобної на 4 і Октоїха (мученичний) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичного канону Октоїха. Після 3-ої пісні – кондак преподобної, глас 2-ий; сідальний святителя, глас 4-ий. «Слава» – сідальний преподобної, глас той самий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак святителя, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний святителя. «Слава» – екзапостиларій Октоїха, «І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій (мученичні із числа стихир на хвалитніх – 1-ша: «Прийдіть, усі люди...», 2-га: «Воїни Христові...», 3-тя: «Чини святих...»; приспіви звичайні зі стиховних з Часослова). «Слава» – святителя, глас 6-ий: «Преподобний отче...», «І нині» – Богородичний за гласом «Слави», від менших: «Бога, Який із Тебе...». Після Трисвятого – тропар святителя, глас 4-ий: «Правилом віри...» (двічі). «Слава» – тропар преподобної, глас 8-ий: «У тобі, мати...», «І нині» – Богородичний за гласом «Слави», від менших: «Діво Пречиста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар святителя. «Слава» – тропар преподобної. Кондаки преподобної і святителя читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня: «Апостоли, мученики...», тропар святителя, тропар преподобної; кондак храму, кондак святителя, кондак преподобної. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». У храмі святого – тропар дня: «Апостоли, мученики...», тропар святителя, тропар преподобної; кондак святителя, кондак преподобної. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». Прокимен, алилуарій і причасний – святителя і дня. Апостол і Євангеліє – святителя і дня."}]},
{"date":"07-05","weekday":"неділя","title":"5-та неділя після П’ятдесятниці. Глас 4-й. Прп. Афанасія Афонського (1000). Мцц. Агнії (Анни) Римської і Кирилли (304). Прп. Лампада Іринопольського (Х). Ікони Божої Матері, званої «Економісса».","glas":4,"readings":["Ран. – Єв. 5-е, Лк., 113 зач., XXIV, 12 – 35.","Літ. – Рим., 103 зач., X, 1 – 10. Мф., 28 зач., VIII, 28 – IX, 1.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Недільна служба Октоїха звершується у поєднанні зі славослівною службою прп. Афанасія Афонського.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 4-ий – 4, і преподобного, глас 1-ий – 6 (кожна стихира двічі). «Слава» – преподобного, глас 6-й: «Тезоіменитого безсмертю...», «І нині» – догматик, глас 4-ий: «Пророк Давид...». Вхід. Прокимен дня. На літії стихира храму і стихири Павла Аморейського, глас 7-ий (на «Господи, взиваю» у воскресній службі 3-го гласу в Октоїху, без стихів). «Слава, і нині» – його ж стихира, глас той самий: «Чистою совістю...». На стиховні стихири воскресні, глас 4-й. «Слава» – преподобного, глас 2-ий, «І нині» – Богородичний воскресний, за гласом «Слави»: «О, нове чудо...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 3-ій (двічі). «Слава» – тропар преподобного, глас той самий, «І нині» – Богородичний воскресний, глас той самий: «Тебе, заступницю...». Кафизми 2-а і 3-я. Малі єктенії. Сідальні воскресні. Полієлей. «Ангельський собор...». Іпакої, степенні і прокимен гласу. Євангеліє воскресне 5-те. «Воскресіння Христове бачивши...». Після 50-ого псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси 1 раз), Хрестобогородичний на 2, Богородиці (Октоїха) на 2 і преподобного на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос преподобного, глас 8-ий, сідальний преподобного, глас той самий (двічі). «Слава і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 5-ий. «Слава» – світильний преподобного, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 4-ий – 8. «Слава» – стихира євангельська 5-та, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар преподобного. Кондаки преподобного і воскресний читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і преподобного, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар воскресний, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар преподобного; кондак воскресний. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар преподобного; кондак воскресний, кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"07-06","weekday":"понеділок","title":"6-й тиждень після П’ятдесятниці. Прп. Сисоя Великого (429). Прп. Сисоя, схимника Києво-Печерського, у Дальніх печерах (ХVІ). Знайдення мощів прав. діви Юліанії, кн. Ольшанської (ХІІІ). Мчч. Марина, Марфи, Авдифакса, Авакума, Кирина, Валентина, пресвітера, Астерія та інших багатьох у Римі (269). Сщмч. Ісавра, диякона, мчч. Інокентія, Фелікса, Єрмія, Василія, Перегрина, Руфа та Руфина (ІІІ). Мч. Коїнта Фригійського (бл. 283). Мц. Лукії, діви, і з нею мчч. Рикса, Антонія, Лукіана, Ісидора, Діона, Діодора, Кутонія, Ароноса, Капика і Сатура (301).","readings":["Рим., 121 зач., XVI, 17 – 24. Мф., 51 зач., XIII, 10 – 23.","Прав. діви: Гал., 208 зач., III, 23 – IV, 5. Мф., 104 зач., XXV, 1 – 13."],"notes":"Служба прп. Сисоя Великого не має святкового знаку, звершується разом із суботньою службою Октоїха (А). Приводимо також порядок звершення славослівної служби прав. діви Юліанії, кн. Ольшанської (Б). (А). НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири Октоїха, глас 4-ий – 3, і преподобного, глас той самий. «Слава» – преподобного, глас 8-ий: «Засяяла нині...», «І нині» – Богородичний за гласом «Слави», від менших: «прийнявши глас...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 4-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Радуйся, хмаро світла...». Після Трисвятого – тропар преподобного, глас 2-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти є джерело...».","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 2-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти є джерело ...». Кафизми 4-ма і 5-ма. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – інший кондак преподобного, глас 8-ий, сідальний преподобного, глас 4-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 4-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Богородице, Царице всіх...». Після Трисвятого – тропар преподобного, глас 2-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе, як Матір...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобного. Кондаки преподобного читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар преподобного; кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар преподобного; кондак дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня. (Б). НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири праведної, глас 4-ий – 6. «Слава» – праведної, глас 6-ий: «праворуч Спаса...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири праведної, глас 4-ий (зі своїми приспівами). «Слава» – праведної, глас 6-ий: «Князівська висота...», «І нині» – Богородичний Мінеї, глас той самий: «Творець і Визволитель...». Після Трисвятого – тропар праведної, глас 8-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Ти, що заради нас...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар праведної, глас 8-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Ти, що заради нас...». Кафизми 4-та і 5-та. Малі ектенії. Сідальні праведної (по двічі). Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси один раз), 2-ий на 4, і праведної на 6. Біблійні пісні «Господеві співаймо...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – інший кондак праведної, глас 8-ий, сідальний праведної, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос праведної, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний праведної (двічі). «Слава і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири праведної, глас 4-ий – 4 (перша стихира двічі). «Слава» праведної, глас 2-ий: «Прийдіть, собори вірних...», «І нині» – Богородичний Мінеї, глас той самий: «Все уповання моє...» Велике славослів’я. Після Трисвятого – тропар праведної, глас 8-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Ти, що заради нас...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар праведної. Кондаки праведної читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні праведної, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар праведної. «Слава» – кондак праведної, «І нині» – кондак храму. У храмі святого – тропар храму, тропар праведної; кондак храму. «Слава» – кондак праведної, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і праведної. Апостол і Євангеліє – дня і праведної."}]},
{"date":"07-07","weekday":"вівторок","title":"Прпп. Іова (1621) та Феодосія (1629) Манявських. Прп. Фоми, що в Малеї (Х). Прп. Акакія, про якого розповідається в Ліствиці (VІ). Мчч. Перегрина, Лукіана, Помпея, Ісихія, Папія, Саторнина і Германа (ІІ). Сщмч. Епіктета, пресвітера, і прмч. Астіона, ченця (290). Мч. Євангела (ІІІ – ІV). Мц. Киріакії Нікомидійської (ІV). Влахернської ікони Божої Матері.","readings":["Ран. – Мф., 43 зач., XI, 27 – 30.","Літ. – 1 Кор., 122 зач., I, 1 – 9. Мф., 52 зач., XIII, 24 – 30.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Звершується полієлейна служба преподобних Іова і Феодосія Манявських (За загальною Мінеєю).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири преподобних, глас 8-ий – 8 (перші дві стихири – тричі, третя – двічі). «Слава» – преподобних, глас 6-ий: «Преподобні отці...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії преподобних – 3. На стиховні стихири преподобних, глас 4-ий (зі своїми приспівами). «Слава» – преподобних, глас 8-ий: «Преподобні отці...», «І нині» – Богородичний воскресний, глас той самий: «Неневісна Діво...». Після Трисвятого – тропар преподобних, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобних, глас 4-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 7-ма і 8-ма. Малі ектенії. Сідальні преподобних (по двічі). Полієлей. Величання преподобних: «Ублажаємо вас, преподобні отці наші Іове і Феодосію Манявські, і шануємо святу пам’ять вашу, наставники монахів і співрозмовники ангелів» і вибраний псалом. Сідальний преподобних після полієлею, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен преподобних, глас 4-ий: «Чесна перед Господом смерть преподобних Його». Євангеліє преподобних. Після 50-го псалма: «Слава» – «Молитвами преподобних...». Стихира преподобних, глас 6-ий: «Ви, будучи на землі ангелами...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і преподобних на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний преподобних, глас 4-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобних, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний преподобних (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири преподобних, глас 4-ий – 4 (перша стихира – двічі). «Слава» – преподобного, глас 8-ий, «І нині» – Богородичний Мінеї за гласом «Слави»: «Владичице прийми молитви...». Велике славослів’я. Після Трисвятого – тропар преподобних, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобних."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні преподобного, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар преподобних. «Слава» – кондак преподобних, «І нині» – кондак храму. У храмі святого – тропар храму, тропар преподобних; кондак храму. «Слава» – кондак преподобних, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобних. Апостол і Євангеліє – дня і преподобних."}]},
{"date":"07-08","weekday":"середа","title":"Вмч. Прокопія (303). Ікони Божої Матері «Одигітрія Влахернська-Казанська» (1579).","readings":["1 Кор., 127 зач., II, 9 – III, 8. Мф., 53 зач., XIII, 31 – 36.","Вмч.: 2 Тим., 292 зач., II, 1 – 10. Мф., 39 зач., Х, 37 – ХІ, 1."],"notes":"Служба вмч. Прокопія шестирична, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири великомученика на 6: глас 4-ий – 3, і інші великомученика, глас той самий – 3. «Слава» – великомученика, глас 6-ий: «Засяяла нині...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Коли побачила...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 4-ий. «Слава» – великомученика, глас 8-ий: «Таємничим сяянням...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Бачачи Тебе...». Після Трисвятого – тропар великомученика, глас 4-й: «Мученик Твій...». «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар великомученика, глас 4-й: «Мученик Твій...». (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...». Кафизми 10-та і 11-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-й з ірмосом на 6 (ірмоси один раз), 2-й на 4, і великомученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний великомученика, глас 1-ий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос великомученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний великомученика, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири великомученика, глас 2-ий, глас 3-ій, глас 4-ий, глас 5-ий – 4. «Слава» – великомученика, глас 8-й: «Як Павло, від Бога...», «І нині» – Хрестобогородичний Мінеї, глас той самий, від менших: «Бачачи розіпнутого...». Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 4-ий. Потім приспів «Дивний Бог...» і стихира великомученика, глас 6-ий: «Прийдіть, усі краї...». «Слава» – великомученика, глас 8-й: «Як Павло, від Бога...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Не терплю, Сину...». Після Трисвятого – тропар великомученика, глас 4-ий: «І співучасником звичаїв...». «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4, і великомученика, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар дня: «Спаси, Господи...», тропарвеликомученика;кондаквеликомученика.«Слава»–«Зі святимиупокой...»,«Інині»–кондакдня:«ВозніссянаХрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар великомученика; кондак дня: «Вознісся на Хрест...», кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар великомученика; кондак дня: «Вознісся на Хрест...», кондак храму, кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"07-09","weekday":"четвер","title":"Сщмч. Панкратія, єп. Тавроменійського (І). Сщмч. Кирила, єп. Гортинського (ІІІ – ІV). Прмчч. Патермуфія, Копрія і мч. Олександра (ІV). Свт. Федора, єп. Едеського (ІХ).","readings":["1 Кор., 129 зач., III, 18 – 23. Мф., 54 зач., XIII, 36 – 43."],"notes":"Служба сщмч. Панкратія, не має святкового знаку, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. На «Господи, взиваю» стихири Октоїха, глас 4-ий – 3, і священномученика, глас 2-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той самий: «Єдина невмістимого Бога...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 4-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Визволи нас...». Після Трисвятого – тропар священномученика), глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Слово Отче...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Слово Отче ...». Кафизми 13-та і 14-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і священномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний священномученика, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос священномученика, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 4-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Тебе, Богородице Пречиста...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Богродице, Ти вища...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякдені антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар священномученика; кондак дня, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар священномученика; кондак дня, кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"07-10","weekday":"п’ятниця","title":"Мчч. 45-ох в Нікополі Вірменському: Леонтія, Маврикія, Даниїла, Антонія, Олександра, Яникита, Сисинія, Менея, Вирилада та інших (бл. 319). Прп. Антонія Києво-Печерського, засновника українського чернецтва (1073). Прп. Силуана, схимника Києво-Печерського, в Дальніх печерах (ХІІІ – ХІV). Мч. Аполлонія (ІІІ). Мчч. Віанора й Силуана (ІV). Прмчч. пустельників єгипетських, вогнем і димом закатованих (бл. 398).","readings":["Ран. – Мф., 43 зач., XI, 27 – 30.","Літ. – 1 Кор., 130 зач. (від половини), IV, 5 – 8. Мф., 55 зач., XIII, 44 – 54.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Мф., 10 зач., IV, 25 – V, 12."],"notes":"Звершується полієлейна служба прп. Антонія Києво-Печерського.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири преподобного, глас 4-ий і глас 5-ий – 8 (перші дві стихири – двічі). «Слава» – преподобного, глас 6-ий: «Суворе твоє житіє...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії преподобного – 3. На стиховні стихири преподобного, глас 1-ий (зі своїми приспівами). «Слава» – преподобного, глас 6-ий: «Сміливе прохання...», «І нині» – Богородичний воскресний, глас той самий: «Творець і Визволитель...». Після Трисвятого – тропар святого, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святого, глас 4-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 19-та і 20-та. Малі ектенії. Сідальні преподобного (по двічі). Полієлей. Величання преподобного: «Ублажаємо тебе, преподобний отче наш Антонію, і шануємо святу пам’ять твою, наставнику монахів і співрозмовнику ангелів» і вибраний псалом. Сідальний преподобного після полієлея, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен преподобного, глас 4-ий: «Чесна перед Господом смерть преподобних Його». Євангеліє преподобного. Після 50-го псалма: «Слава» – «Молитвами преподобного...». Стихира преподобного, глас 6-ий. Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і преподобного (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний преподобного, глас 4-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний преподобного (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири преподобного, глас 2-ий – 4 (перша стихира – двічі). «Слава» – преподобного, глас 8-ий, «І нині» – Богородичний Мінеї за гласом «Слави»: «Владичице прийми молитви...». Велике славослів’я. Після Трисвятого – тропар святого, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні преподобного, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар храму, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"07-11","weekday":"субота","title":"Згадування чуда вмц. Євфимії Всехвальної, через яке православ’я утвердилось (451). Рівноап. Ольги, княгині Київської, у святому хрещенні Олени (969). Сщмч. Кіндея, пресвітера (ІІІ – ІV).","readings":["Ран. – Мф., 104 зач., ХХV, 1 – 13.","Літ. – Рим., 100 зач., IX, 1 – 5. Мф., 32 зач., IX, 18 – 26.","Рівноап.: Діян., 39 зач., ХVІ, 1 – 15. Лк., 33 зач., VII, 36 – 50."],"notes":"Звершується полієлейна служба рівноап. Ольги, вел. кн. Київської.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири рівноап. Ольги, глас 4-ий – 8 (кожна стихира – двічі). «Слава» – рівноап. Ольги, глас 6-ий: «Прийдіть, люди українські...», «І нині» – догматик, глас 4-ий: «Пророк Давид...». Вхід. Прокимен дня. Паремії рівноап. Ольги – 3. На стиховні стихири рівноап. Ольги, глас 8-ий (зі своїми приспівами). «Слава» – рівноап. Ольги, глас той самий: «Велика слава твоя...», «І нині» – Богородичний воскресний, глас той самий: «Неневісна Діво...». Після Трисвятого – тропар рівноап. Ольги, глас 1-ий. «Слава, і нині» – Богородичний воскресний, глас 4-ий: «Від початку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар рівноап. Ольги, глас 1-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас 4-ий: «Від початку...». Кафизми 16-та і 17-та (кадіння на 17-ій кафізмі не звершується, а переноситься на полієлей). Малі ектенії. Сідальні рівноап. Ольги (по двічі). Полієлей. Величання рівноап. Ольги: «Величаємо тебе, свята рівноапостольна княгине Ольго, як зорю ранню, що на землі нашій засяяла і світло віри православної народу своєму сповістила» і вибраний псалом. Сідальний рівноап. Ольги після полієлея, глас 5-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен рівноап. Ольги, глас 4-ий: «По всій землі розійшлося віщування їх, і в кінці вселенної слова їх». Стих: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь». Євангеліє рівноап. Ольги, від Матфея, зач 104. Після 50-го псалма: «Слава» – «Молитвами святої рівноапостольної Ольги...». Стихира рівноап. Ольги, глас 6-ий: «Провісницею віри...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і рівноап. Ольги на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний рівноап. Ольги, глас 3-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос рівноап. Ольги, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний рівноап. Ольги (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири рівноап. Ольги, глас 3-ий – 4 (перша стихира – двічі). «Слава» – рівноап. Ольги, глас 8-ий: «О, мати наша...», «І нині» – Богородичний Мінеї, глас той самий: «Богородице, Мати Безневісна...». Велике славослів’я. Після Трисвятого – тропар рівноап. Ольги, глас 1-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Коли Гавриїл...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак рівноап. Ольги."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні рівноап. Ольги, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар рівноап. Ольги. «Слава» – кондак рівноап. Ольги, «І нині» – кондак храму. У храмі святого – тропар храму, тропар рівноап. Ольги; кондак храму. «Слава» – кондак рівноап. Ольги, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – рівноап. Ольги. Апостол і Євангеліє – дня і рівноап. Ольги."}]},
{"date":"07-12","weekday":"неділя","title":"6-та неділя після П’ятдесятниці. Глас 5-й. Мчч. Прокла та Іларія (ІІ). Прп. Михаїла Малеїна, ігумена (962). Мчч. Федора, варяга, і сина його Іоана, в Києві (983). Мц. Голіндухи Перської, у св. хрещенні Марії (591). Прп. Іоана (1005) і Гавриїла (Х) Святогорців (Груз.). Прп. Паїсія Святогорця (1994). Ікони Божої Матері «Троєручиця» (VІІІ).","glas":5,"readings":["Ран. – Єв. 6-е, Лк., 114 зач., XXIV, 36 – 53.","Літ. – Рим., 110 зач., XII, 6 – 14. Мф., 29 зач., IX, 1 – 8.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Служба мчч. Прокла та Іларія і прп. Михаїла Малеїна не має святкового знаку, звершується разом із службою Октоїха (А). Також подаємо порядок звершення недільнї служби Октоїха звершується у поєднанні зі славослівною службою прп. Паїсія Святогорця (за загальною Мінеєю) (Б). (А). НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 5-ий – 4, мучеників, глас 1-ий – 3, і преподобного, глас 5-ий – 3. «Слава» – преподобного, глас 6-ий: «Преподобний отче...»; «І нині» – догматик, глас 5-ий: «У Червоному морі...». Вхід. Прокимен дня. На літії стихира храму і Богородичні стихири Павла Аморрейського, глас 8-ий (На «Господи, взиваю» у воскресній службі 3-го гласу в Октоїху, без стихів). «Слава, і нині» – його ж стихира, глас той же: «Радуйся, Богомати Пречиста...». На стиховні стихири воскресні, глас 5-ий. «Слава» – преподобного, глас 8-ий: «Безліч ченців...»; «І нині» – Богородичний воскресний, за гласом «Слави»: «Неневісна Діво...». Після Трисвятого – «Богородице Діво...» (тричі).","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 5-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний воскресний, глас той самий: «Ти, що заради нас...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні воскресні. Непорочні. «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє воскресне 6-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Богородиці (Октоїха) на 2, мучеників на 4 і преподобного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос преподобного, глас 2-ий, інший кондак мучеників, глас 4-ий; сідальний преподобного, глас 8-ий. «Слава і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 5-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 6-ий. «Слава» – світильний преподобного, «І нині» – Богородичний воскреслого екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 5-ий – 8. «Слава» – стихира євангельська 6-та, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «У день спасіння світу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар преподобного. Кондак тільки воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 8. Після входу – тропарі та кондаки: У храмі Господському – тропар воскресний, тропар преподобного, кондак преподобного. «Слава» – кондак мучеників, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар преподобного; кондак воскресний, кондак преподобного. «Слава» – кондак мучеників, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар преподобного; кондак воскресний, кондак храму, кондак преподобного. «Слава» – кондак мучеників, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні. Апостол і Євангеліє – дня. (Б). На ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 4-ий – 4, і преподобного, глас 1-ий – 6 (кожна стихира двічі, із загальної Мінеї). «Слава» – преподобного, глас 6-й: «Те, що було...», «І нині» – догматик, глас 5-ий: «У Червоному морі...». Вхід. Прокимен дня. На літії стихира храму і Богородичні стихири Павла Аморрейського, глас 8-ий (На «Господи, взиваю» у воскресній службі 3-го гласу в Октоїху, без стихів). «Слава, і нині» – його ж стихира, глас той же: «Радуйся, Богомати Пречиста...». На стиховні стихири воскресні, глас 5-ий. «Слава» – преподобного, глас 8-ий: «Тебе, як наставника...» (із загальної Мінеї); «І нині» – Богородичний воскресний, за гласом «Слави»: «Неневісна Діво...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"УТРЕНІ","text":"На УТРЕНІ на «Бог Господь» – тропар воскресний, глас 5-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний воскресний, глас той самий: «Ти, що заради...». Кафизми 2-га і 3-тя. Малі єктенії. Сідальні воскресні. Полієлей. «Ангельський собор...». Іпакої, степенні і прокимен гласу. Євангеліє воскресне 6-те. «Воскресіння Христове бачивши...». Після 50-ого псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси 1 раз), Хрестобогородичний на 2, Богородиці (Октоїха) на 2 і преподобного на 6 (із загальної Мінеї). Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос преподобного, глас 2-ий, сідальний преподобного, глас 1-ий (двічі). «Слава і нині» – Богородичний Мінеї, глас той самий (із загальної Мінеї). Після 6-ої пісні – кондак та ікос воскресні, глас 5-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 5-ий. «Слава» – світильний преподобного, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 5-ий – 8. «Слава» – стихира євангельська 6-та, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «У день спасіння...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар преподобного. Кондаки преподобного і воскресний читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і преподобного, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар воскресний, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар преподобного; кондак воскресний. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар преподобного; кондак воскресний, кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"07-13","weekday":"понеділок","title":"7-й тиждень після П’ятдесятниці. Собор архангела Гавриїла. Прп. Стефана Саваїта (794). Свт. Юліана, єп. Кеноманійського (І). Мч. Серапіона (ІІ – ІІІ). Мч. Маркіана (258). Прославлення свт. Софронія (Кришталевського), єп. Іркутського (1918).","readings":["1 Кор., 134 зач., V, 9 – VI, 11. Мф., 56 зач., XIII, 54 – 58.","Арханг.: Євр., 315 зач., VІІ, 1 – 6. Лк., 51 зач., X, 16 – 21."],"notes":"Служба Собору архангела Гавриїла і прп. Стефана Саваїта шестирична, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: Архангела, глас 4-ий – 3, і преподобного, глас 8-ий – 3. «Слава» – Архангела, глас 6-ий: «Радуються з нами...», «І нині» – Богородичний Мінеї, за гласом «Слави», від менших: «З Архангелом заспіваймо...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 5-ий. «Слава і нині» – Архангела, глас 8-ий: «Як чиноначальник...». Після Трисвятого – тропар Архангела, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Архангела, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована...». Кафизми 4-та і 5-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси один раз), Архангела на 6, і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону великомученика. Після 3-ої пісні – інший кондак Архангела, глас 2-ий; сідальний Архангела, глас 4-ий. «Слава» – сідальний преподобного, глас 3-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос Архангела, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний Архангела, «І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 6-ий. «Слава» – Архангела, глас 5-ий: «Там, де осіяє твоя благодать...», «І нині» – Богородичний Мінеї, за гласом «Слави», від менших: «Обрадувана, заступайся...». Після Трисвятого – тропар Архангела, глас 4-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Богородице, Ти вища...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Архангела. Кондаки Архангела читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4, і Архангела, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар Архангела; кондак дня, кондак храму, кондак Архангела, інший кондак Архангела. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар Архангела; кондак дня, кондак храму, кондак Архангела, інший кондак Архангела. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Примітка. Тропар і кондак дня (понеділка) співпадає з тропарем і кондаком Архангела. За виключенням граматичних форм однини і множини, на порядок співу тропарів і кондаків після входу це не впливає. Прокимен, алилуарій і причасний – дня і Архангела. Апостол і Євангеліє – дня і Архангела."}]},
{"date":"07-14","weekday":"вівторок","title":"Апостола від 70-х Акили (І). Мч. Юста Римського (І). Прп. Елія, ченця (ІV). Прп. Онисима Магнезійського, чудотворця (ІV). Блгв. Оскольда, першомуч. Київського, у св. хрещенні Миколая (882). Прп. Стефана Махрицького (1406).","readings":["1 Кор., 136 зач., VI, 20 – VII, 12. Мф., 57 зач., XIV, 1 – 13.","Блгв.: Гал., 213 зач., V, 22 – VI, 2. Мф., 10 зач., IV, 25 – V, 12."],"notes":"Звершується славослівна служба блгв. Оскольда, першомуч. Київського (За загальною Мінеєю, служба мученику одному).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-та. На «Господи, взиваю» стихири першомученика, глас 1-ий – 6 (кожна стихира – двічі). «Слава» – першомученика, глас 6-ий: «Нині вся вселенна...», «І нині» – догматик, глас 6-ий: «Хто Тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири першомученика, глас 4-ий (зі своїми приспівами). «Слава» – першомученика, глас 6-ий: «Прийдіть, мучениколюбці...», «І нині» – Богородичний Мінеї, глас той самий: «Богородице, Ти єси...». Після Трисвятого – тропар першомученика, глас 4-ий. «Слава, і нині» – Богородичний воскресний, за гласом тропаря: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар першомученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний воскресний, за гласом тропаря: «Від початку віку...». Кафизми 7-ма і 8-ма. Малі ектенії. Сідальні першомученика. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси один раз), 2-ий на 4 і першомученика на 6. Біблійні пісні «Господеві співаємо...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний першомученика, глас 5-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос першомученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний першомученика (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири першомученика, глас 4-ий – 4 (перша стихира – двічі). «Слава» – першомученика, глас 1-ий, «І нині» – Богородичний Мінеї, за гласом «Слави»: «Радуйся, Богородице Діво...». Велике славослів’я. Після Трисвятого – тропар першомученика, глас 4-ий. «Слава, і нині» – Богородичний воскресний, за гласом тропаря: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак першомученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні першомученика, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар першомученика. «Слава» – кондак першомученика, «І нині» – кондак храму. У храмі святого – тропар храму, тропар першомученика; кондак храму. «Слава» – кондак першомученика, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і першомученика. Апостол і Євангеліє – дня і першомученика."}]},
{"date":"07-15","weekday":"середа","title":"Рівноап. князя Київського Володимира, у св. хрещенні Василія (1015). Мчч. Кирика і матері його Улити (бл. 305). Мч. Авудима Тенедоського (ІV). День хрещення Руси-України.","readings":["Ран. – Ін., 36 зач., X, 9 – 16.","Літ. – Рівноап.: Гал., 200 зач., I, 11 – 19. Ін., 35 зач. (від половини), X, 1 – 9."],"notes":"Звершується бдінна служба рівноап. вел. кн. Володимира.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири рівноап. Володимира, глас 4-ий – 8 (кожна стихира – двічі). «Слава» – рівноап. Володимира, глас 8-ий: «Прийдіть, зберімося всі...», «І нині» – догматик, глас той самий: «Цар Небесний...». Вхід. Прокимен дня. Паремії рівноап. Володимира – 3. На літії стихири рівноап. Володимира, глас 2-ий. «Слава» – рівноап. Володимира, глас 6-ий: «Прийдіть, зберімося, всі вірні...», «І нині» – Богородичний воскресний, глас той же: «Творець і Визволитель...». На стиховні стихири рівноап. Володимира, глас 8-ий (зі своїми приспівами). «Слава» – рівноап. Володимира, глас той самий: «Начальника благочестя...», «І нині» – Богородичний, глас той самий: «Владичице, прийми молитви рабів Твоїх...». Після Трисвятого – тропар рівноап. Володимира, глас 4-ий (двічі), і «Богородице Діво...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар рівноап. Володимира, глас 4-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 10-та і 11-та. Малі ектенії. Сідальні рівноап. Володимира (по двічі). Полієлей. Величання рівноап. Володимира: «Величаємо тебе, святий рівноапостольний великий княже Володимире, і шануємо святу пам’ять твою, ідолів ти знищив і всю нашу землю святим хрещенням просвітив» і вибраний псалом. Сідальний рівноап. Володимира після полієлею, глас 4-ий. «Слава» – інший сідальний рівноап. Володимира, глас той самий, «І нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен рівноап. Володимира, глас 4-ий: «Підніс обраного від людей Моїх»; стих: «Бо рука Моя захистить його і сила Моя укріпить його». Євангеліє равноап. Володимира. Після 50-го псалма: «Слава» – «Молитвами святого рівноапостольного великого князя Володимира...». Стихира рівноап. Володимира, глас 8-ий: «Рівного з апостолами Володимира...». Канони: рівноап. Володимира 1-ий з ірмосом на 8 (ірмоси по двічі) і 2-ий на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний рівноап. Володимира, глас 2-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос рівноап. Володимира, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний рівноап. Володимира (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири рівноап. Володимира, глас 4-ий – 4 (перша стихира – двічі). «Слава» – рівноап. Володимира, глас 2-ий: «Не від людей ти прийняв покликання...», «І нині» – Богородичний за гласом «Слави», від менших (за вибором), або, за традицією: «Всю надію мою покладаю на Тебе Мати Божа збережи мене під покровом Твоїм». Велике славослів’я. Після Трисвятого – тропар рівноап. Володимира, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак рівноап. Володимира."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні рівноап. Володимира, 1-го канону пісня 3-тя – 4 (з ірмосом), і 2-го канону пісня 6-та – 4. (Або антифони святкові, див. у додатку). Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар рівноап. Володимира. «Слава» – кондак рівноап. Володимира, «І нині» – кондак храму. У храмі святого – тропар рівноап. Володимира. «Слава» – кондак рівноап. Володимира, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – рівноап. Володимира. Апостол і Євангеліє – рівноап. Володимира (читання дня переносяться на наступний день)."}]},
{"date":"07-16","weekday":"четвер","title":"Сщмч. Афіногена Севастійського, єп., і десятьох учнів його (бл. 311). Мч. Павла і мцц. Алевтини (Валентини) та Хіонії (308). Мч. Антіоха Севастійського, лікаря (ІV). Мц. Юлії, діви (бл. 440 або 613). Пам’ять свв. отців IV Вселенського собору (451). Прп. Іоана Вишенського, Святогорця (після 1620).","readings":["1 Кор., 137 зач., VII, 12 – 24. Мф., 60 зач., XIV, 35 – XV, 11 (за середу).","1 Кор., 138 зач., VII, 24 – 35. Мф., 61 зач., XV, 12 – 21 (за четвер)."],"notes":"Служба сщмч. Афіногена, єп., і десятьох учнів його не має святкового знаку, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири Октоїха, глас 5-ий – 3, і священномученика, глас 8-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той самий: «Спаси мене...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 5-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Все уповання...». Після Трисвятого – тропар священномученика, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Духовні врата ...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 8-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Духовні врата...». Кафизми 13-та і 14-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і священномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний священномученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак священномученика, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 5-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Ублажаємо, Тебе...». Після Трисвятого – тропар священномученика, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Діво Пречиста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякдені антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, інший тропар дня, тропар священномученика; кондак дня, інший кондак дня, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, інший тропар дня, тропар храму, тропар священномученика; кондак дня, інший тропар дня, кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – середи і чертверга."}]},
{"date":"07-17","weekday":"п’ятниця","title":"Вмц. Марини (Маргарити) Антіохійської (ІV). Перенесення мощів прп. Лазаря Галисійського.","readings":["1 Кор., 139 зач., VII, 35 – VIII, 7. Мф., 63 зач., XV, 29 – 31."],"notes":"Служба вмц. Марини шестирична, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 15-та. На «Господи, взиваю» стихири великомучениці, глас 8-ий – 6 (Кожна стихира – двічі). «Слава» – великомучениці, глас 2-ий: «У граді Бога...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Безневісна, бачачи...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 5-ий. «Слава» – великомучениці, глас 2-ий: «Голосами радості...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Коли Нескверна...». Після Трисвятого – тропар великомучениці, глас 4-ий: «Мучениця Твоя, Господи...». «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар великомучениці, глас 4-ий: «Мучениця Твоя, Господи...» (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...». Кафизми 19-та і 20-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси один раз), 2-ий на 4, і великомучениці на 6. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний великомучениці, глас 4-ий (двічі). «Слава, і нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос великомучениці, глас 3-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний великомучениці, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 5-ий. «Слава» – великомучениці, глас 1-ий: «Як на камені...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Свого Агнця...». Після Трисвятого – тропар великомучениці, глас 4-ий: «Мучениця Твоя, Господи...». «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомучениці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха 4, і великомучениці, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси, Господи...», тропар великомучениці; кондак великомучениці. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар великомучениці; кондак дня: «Вознісся на Хрест...», кондак великомучениці. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар великомучениці; кондак дня: «Вознісся на Хрест...», кондак храму, кондак великомучениці. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і великомучениці. Апостол і Євангеліє – дня і великомучениці."}]},
{"date":"07-18","weekday":"субота","title":"Мч. Еміліана (363). Мч. Якинфа Амастридського (ІV). Прп. Іоана Багатостраждального, Києво-Печерського, в Ближніх печерах (1160). Прп. Памви, затворника Києво-Печерського, в Дальніх печерах (1241). Прп. Памви Нітрійського, пустельника (ІV).","readings":["Рим., 108 зач., XII, 1 – 3. Мф., 39 зач., X, 37 – XI, 1."],"notes":"Служба Мч. Еміліана не має святкового знаку, звершується разом із суботньою службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири мученика, глас 4-ий – 6 (кожна стихира – двічі). «Слава, і нині» – догматик, глас 5-ий: «У Червоному морі...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 5-ий (мученичні із числа стихир на «Господи, взиваю» – 2-га: «У щит віри...», 3-тя: та ж сама, 4-та: «Усе земне...», приспіви звичайні зі стиховних з Часослова). «Слава, і нині» – Богородичний Октоїха, глас той самий: «Обрадувана, заступайся...» (у стихирах на стиховні). Після Трисвятого – тропар мученика, глас 4-ий, «Слава, і нині» – Богородичний воскресний, глас 5-ий: «Радуйся, двері Господні...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мученика, глас 4-ий. «Слава, і нині» – Богородичний воскресний, за гласом «Слави»: «Від початку віку...». Кафизми 16-та і 17-та (на 17-тій кафізмі ієрей звершує кадіння храму, як на «Господи, взиваю», царські врата залишаються закритими). Малі ектенії. Сідальні Октоїха. Псалом 50-ий. Канони: У храмі Воскресіння Христового – канон воскресний рядового гласу (з попередньої неділі) з ірмосом на 6 (ірмоси по двічі, тропарі на 4: два воскресні тропарі, один Хрестовоскресний і один Богородичний), мученика (Мінеї) на 4 і Октоїха (мученикам) на 4. У храмі Господньому і Богородиці – канон храму з ірмосом на 6 (ірмоси по двічі), мученика (Мінеї) на 4 і Октоїха (мученикам) на 4. У храмі святого – канон мученика (Мінеї) з ірмосом на 6 (ірмоси по двічі), храму на 4 і Октоїха (мученикам) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичного канону Октоїха. Після 3-ої пісні – кондак мученика, глас 8-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мученика, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Екзапостиларій Октоїха, «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 5-ий (мученичні із числа стихир на хвалитніх – 1-ша: «Благословенне воїнство...», 2-га: «Страстоносці Твої, Господи...», 3-тя: «Святі мученики...»; приспіви звичайні зі стиховних з Часослова). «Слава, і нині» – Богородичний Октоїха, глас той самий: «О, душе окаянна...» (у стихирах на хвалитніх). Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня: «Апостоли, мученики...», тропар мученика; кондак храму, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». У храмі святого – тропар дня: «Апостоли, мученики...», тропар мученика; кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"07-19","weekday":"неділя","title":"7-ма неділя після П’ятдесятниці. Глас 6-й. Пам’ять святих отців шістьох Вселенських соборів (перехідне святкування в неділю, найближчу до 16 липня). Прп. Макрини, сестри свт. Василія Великого (380). Прп. Дія Константинопольського, ігум. (бл. 430). Прп. Паїсія Києво-Печерського, в Дальніх печерах (ХІV). Блгвв. кн. Стефана (1427) і матері його кн. Милиці (1405), правителів Сербських. Знайдення мощів прп. Серафима, Саровського чудотворця (1903).","glas":6,"readings":["Ран. – Єв. 7-е, Ін., 63 зач., XX, 1 – 10.","Літ. – Рим., 116 зач., XV, 1 – 7. Мф., 33 зач., IX, 27 – 35.","Свв. отців: Євр., 334 зач., XIII, 7 – 16. Ін., 56 зач., XVII, 1 – 13."],"notes":"Звершується недільна служба Октоїха разом зі службою святих отців шістьох Вселенських Соборів (у Мінеї під 16 липня). Служби Мінеї (19 липня) співаються на повечір’ї чи переносяться на інший день.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 6-ий – 4, і отців, глас той самий – 6 (кожна стихира – двічі). «Слава» – отців, глас той самий: «Прославимо нині таємничі сурми Духа», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії отців – 3. На літії стихира храму. «Слава» – отців, глас 3-ий: «Апостольських передань...», «І нині» – Богородичний воскресний, глас той самий: «Без сімені від Божественного Духа...». На стиховні стихири воскресні, глас 6-ий. «Слава» – отців, глас 4-ий: «Нині ми святкуємо молитовну пам’ять...», «І нині» – Богородичний воскресний, глас той самий: «Зглянься на моління...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар отців, глас 8-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 6-ий (двічі). «Слава» – тропар отців, глас 8-ий, «І нині» – Богородичний воскресний, глас той самий: «Ти що ради нас...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні воскресні. Непорочні. «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє воскресне 7-ме. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Богородиці на 2 і отців (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос воскресні, глас 6-ий; сідальний отців, глас 4-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос отців, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 7-ий. «Слава» – світильний отців, «І нині» – Богородичний Мінеї: «Радуйся, Божа палато...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 6-ий – 4, і отців, глас той самий – 4 (перша стихира – двічі; з приспівами своїми). «Слава» – отців, глас 8-ий: «Святих отців собор...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...». Перед 1-м часом на «Слава, і нині» – євангельська стихира 7-ма."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар отців. Кондаки воскресний і отців читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і отців, пісня 3-тя – 4. Після входу – тропарі та кондаки: У храмі Господському – тропар воскресний, тропар отців. «Слава» – кондак отців, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар отців; кондак воскресний. «Слава» – кондак отців, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар отців; кондак воскресний. «Слава» – кондак отців, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні і отців. Апостол і Євангеліє – дня і отців."}]},
{"date":"07-20","weekday":"понеділок","title":"8-й тиждень після П’ятдесятниці. Прор. Іллі (ІХ ст. до Р. Х.). Знайдення мощів прмч. Афанасія Берестейського (1649).","readings":["Ран. – Лк., 14 зач., IV, 22 – 30.","Літ. – 1 Кор., 142 зач., IX, 13 – 18. Мф., 65 зач., XVI, 1 – 6.","Прор.: Як., 57 зач., V, 10 – 20. Лк., 14 зач., IV, 22 – 30."],"notes":"Звершується полієлейна служба святого пророка Іллі.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири пророка, глас 1-ий і глас 2-ий – 8 (перші дві стихири – двічі). «Слава» – пророка, глас 6-ий: «Прийдіть, православних зібрання...», «І нині» – догматик, глас 2-ий: «Минула тінь закону...». Вхід. Прокимен дня. Паремії пророка – 3. На стиховні стихири пророка, глас 8-ий (зі своїми приспівами). «Слава» – пророка, глас 6-ий: «Пророче, проповіднику Христів...», «І нині» – Богородичний воскресний, глас той самий: «Творець і Визволитель...». Після Трисвятого – тропар пророка, глас 4-ий. «Слава, і нині» – Богородичний воскресний за гласом тропаря: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар пророка, глас 4-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Від віку утаємнене...». Кафизми 4-та і 5-та. Малі єктенії. Сідальні пророка (по двічі). Полієлей. Величання пророка: «Величаємо тебе, пророче славний Іллє, і шануємо твоє на небеса з плоттю вогненне вознесіння» і вибраний псалом: «Блажен муж, що боїться Господа, заповідей його дуже бажає». Сідальний пророка після полієлею, глас 8-ий: «Полюбивши премудрість...» (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен пророка, глас 4-ий: «Ти ієрей повік за чином Мелхиседековим»; стих: «Сказав Господь Господеві моєму: сиди праворуч Мене, доки не покладу ворогів Твоїх підніжжям ніг твоїх». Євангеліє пророка Лк., 14 зач. Після 50-го псалма: «Слава» – «Молитвами святого пророка Іллі...». Стихира пророка, глас 4-ий: «На колісниці вогняній...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і пророка (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний пророка, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос пророка, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний пророка. «Слава» – інший світильний пророка, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири пророка, глас 8-ий і глас 1-ий – 6. «Слава» – пророка, глас 8-ий: «Пророків верховних і всесвітлих світильників вселенної...», «І нині» – Богородичний Мінеї, глас той самий: «Владичице, прийми...». Велике славослів’я. Після Трисвятого – тропар пророка, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак пророка."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні пророка, 1-го канону пісня 3-тя – 4 (з ірмосом), і 2-го канону пісня 6-та – 4. У храмі Господському і Богородиці – тропар храму, тропар пророка. «Слава» – кондак пророка, «І нині» – кондак храму. У храмі святого – тропар храму, тропар пророка, кондак храму. «Слава» – кондак пророка, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – пророка і дня. Апостол і Євангеліє – пророка і дня."}]},
{"date":"07-21","weekday":"вівторок","title":"Прор. Єзекиїля (VІ ст. до Р. Х.). Прпп. Симеона, юродивого заради Христа, та Іоана, співпосника його (бл. 590). Прпп. Онуфрія Мовчазного й Онисима, затворника, Києво-Печерських, у Ближніх печерах (ХІІ – ХІІІ).","readings":["1 Кор., 144 зач., X, 5 – 12. Мф., 66 зач., XVI, 6 – 12."],"notes":"Служба прор. Єзекиїля, прпп. Симеона, юродивого заради Христа, та Іоана, співпосника його не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-та. На «Господи, взиваю» стихири Мінеї на 6: преподобних, глас 4-ий – 3, і пророка, глас 8-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той самий: «Радуйся, просвічення душ...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 6-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Ніхто, що звертається...». Після Трисвятого – тропар преподобних, глас 4-ий. «Слава» – тропар пророка, глас 2-ий: «Пророка Твого...», «І нині» – Богородичний за гласом «Слави», від менших: «Через Тебе, Богородице...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобних, глас 4-ий (двічі). «Слава» – тропар пророка, глас 2-ий: «Пророка Твого...», «І нині» – Богородичний за гласом «Слави», від менших: «Через Тебе, Богородице ...». Кафизми 7-ма і 8-ма. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), преподобних на 4, і пророка на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (пророка). Після 3-ої пісні – кондак пророка, глас 4-ий; сідальний преподобних, глас 5-ий. «Слава» – сідальний пророка, глас 3-ій, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак преподобних, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 6-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Великих дарувань...». Після Трисвятого – тропар преподобних, глас 4-ий. «Слава» – тропар пророка, глас 2-ий: «Пророка Твого...», «І нині» – Богородичний за гласом «Слави», від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобних. «Слава» – тропар пророка. Кондаки пророка і преподобних читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякдені антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар преподобних, тропар пророка; кондак дня, кондак преподобних, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар преподобних, тропар пророка; кондак дня, кондак храму, кондак преподобних, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"07-22","weekday":"середа","title":"Мироносиці рівноап. Марії Магдалини (І). Перенесення мощів сщмч. Фоки, єп. Синопського (403 – 404).","readings":["1 Кор., 145 зач., X, 12 – 22. Мф., 68 зач., XVI, 20 – 24.","Рівноап.: 1 Кор., 141 зач., IX, 2 – 12. Ін., 64 зач., ХХ, 11 – 18 або Лк., 34 зач., VIІІ, 1 – 3."],"notes":"Служба рівноап. Марії Магдалини і сщмч. Фоки шестирічна, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та. На «Господи, взиваю» стихири на 6: рівноапостольної, глас 8-ий – 3, і священномученика, глас 4-ий – 3. «Слава» – рівноапостольної, глас 6-ий: «Першою побачивши...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Коли побачила Агниця...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 6-ий. «Слава» – рівноапостольної, глас 8-ий: «Марія Магдалина...», і нині» – Хрестобогородичний Мінеї, глас той самий: «Побачивши Тебе, Ісусе...». Після Трисвятого – тропар рівноапостольної, глас 1-ий. «Слава» – тропар священномученика, глас 4-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Діво пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар рівноапостольної, глас 1-ий (двічі). «Слава» – тропар священномученика, глас 4-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Діво пренепорочна...». Кафизми 10-та і 11-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), рівноапостольної на 4, і священномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (священномученика). Після 3-ої пісні – кондак та ікос священномученика, глас 6-ий; сідальний рівноапостольної, глас 8-ий. «Слава» – сідальний священномученика, глас 4-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос рівноапостольної, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха, світильний рівноапостольної. «Слава» – світильний священномученика, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 6-ий. «Слава» – священномученика, глас 4-ий: «З дитинства ти...», «І нині» – рівноапостольної, глас 8-ий: «Марія Магдалина...». Після Трисвятого – тропар рівноапостольної, глас 1-ий. «Слава» – тропар священномученика, глас 4-ий, «І нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар рівноапостольної. «Слава» – тропар священномученика. Кондаки священномученика і рівноапостольної читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4 і рівноапостольної, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси, Господи...», тропар рівноапостольної, тропар священномученика; кондак рівноапостольної, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар рівноапостольної, тропар священномученика; кондак дня: «Вознісся на Хрест...», кондак рівноапостольної, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар рівноапостольної, тропар священномученика; кондак дня: «Вознісся на Хрест...», кондак храму, кондак рівноапостольної, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і рівноапостольної. Апостол і Євангеліє – дня і рівноапостольної."}]},
{"date":"07-23","weekday":"четвер","title":"Почаївської ікони Божої Матері (1675). Сщмч. Аполлінарія, єп. Равенійського (бл. 75). Мчч. Трофима, Феофіла і з ними 13 мчч. (ІV).","readings":["Ран. – Лк., 4 зач., I, 39 – 49, 56.","Літ. – 1 Кор., 147 зач., X, 28 – XI, 7. Мф., 69 зач., XVI, 24 – 28.","Богородиці: Євр., 320 зач., IX, 1 – 7. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершується полієлейна служба на честь Почаївської ікони Божої Матері.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8 (перші дві сихири двічі): Богородиці, глас 5-ий – 4 і глас 2-ий – 4. «Слава, і нині» – Богородиці, глас 2-ий: «Непрохідні врата...». Вхід. Прокимен дня. Паремії Богородиці – 3. На стиховні стихири Богородиці, глас 1-ий (зі своїми приспівами). «Слава, і нині» – Богородиці, глас 8-ий: «Той, що сидить на Херувимах...». Після Трисвятого – тропар Богородиці, глас 5-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Богородиці, глас 5-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 13-та і 14-та. Малі ектенії. Сідальні Богородиці (по двічі). Полієлей. Величання Богородиці: «Величаємо Тебе, Пресвятая Діво і шануємо ікону Твою святу, її ж від літ древніх, на горі Почаївській прославила єси» і вибраний псалом. Сідальний Богородиці після полієлея, глас 6-ий. «Слава, і нині» – той самий сідальний. Степенна – 1-ий антифон 4-го гласу. Прокимен Богородиці, глас 4-ий: «Пом’яну ім’я Твоє у всякому роді і роді»; стих: «Слухай, дочко, і споглянь, і прихили вухо Твоє». Євангеліє Богородиці. Після 50-го псалма: «Слава» – «Молитвами Богородиці...». Стихира Богородиці, глас 5-ий: «Прийдіть, українські собори...». Канон: Богородиці з ірмосом на 14 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний Богородиці, глас 6-ий. «Слава» – І нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос Богородиці, глас 1-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є...» не співається. Світильний Богородиці. «Слава, і нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Богородиці, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – Богородиці, глас 8-ий: «Твоїми знаменнями, Богородице Владичице, славиться гора Почаївська...». Велике славослів’я. Після Трисвятого – тропар Богородиці, глас 5-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Богородиці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Богородиці, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар Богородиці (ікони); «Слава» кондак храму. «І нині» – кондак Богородиці (ікони). У храмі Богородиці – тропар Богородиці (ікони) «Слава і нині» – кондак Богородиці (ікони). У храмі святого – тропар Богородиці (ікони), тропар храму; «Слава» – кондак храму. «І нині» – кондак Богородиці (ікони). Прокимен, алилуарій і причасний – Богородиці. Апостол і Євангеліє – Богородиці та дня."}]},
{"date":"07-24","weekday":"п’ятниця","title":"Вмц. Христини (бл. 300). Мчч. блгвв. кнн. Бориса і Гліба, у св. хрещенні Романа і Давида (1015). Прп. Полікарпа, архім. Києво-Печерського (1182).","readings":["Ран. – Лк., 106 зач., XXI, 12 – 19.","Літ. – 1 Кор., 148 зач., XI, 8 – 22. Мф., 71 зач., XVII, 10 – 18.","Блгвв. кнн.: Рим., 99 зач., VIII, 28 – 39. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"Звершується полієлейна служба мчч. блгвв. кнн. Бориса і Гліба, у св. хрещенні Романа і Давида.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири благовірних князів, глас 8-ий і глас 2-ий – 8 (перші дві стихири – двічі). «Слава» – благовірних князів, глас 6-ий: «Прийдіть, вірні...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії благовірних князів – 3. На стиховні стихири благовірних князів, глас 4-ий (зі своїми приспівами). «Слава» – благовірних князів, глас 8-ий: «Прийдіть, прославимо...», «І нині» – Богородичний воскресний, глас той самий: «Безневісна Діво...». Після Трисвятого – тропар благовірних князів, глас 2-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Все вище розуму...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар благовірних князів, глас 2-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Все вище розуму...». Кафизми 19-та і 20-та. Малі ектенії. Сідальні благовірних князів (по двічі). Полієлей. Величання благовірних князів і вибраний псалом. Сідальний благовірних князів після полієлея, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен благовірних князів, глас 4-ий: «Взивали праведні, і Господь почув їх». Стих: «Багато скорбот у праведного, та від них усіх визволить його Господь». Євангеліє благовірних князів – Лк., зач. 106. Після 50-го псалма: «Слава» – «Молитвами святих благовірних князів...». Стихира благовірних князів, глас 8-ий. Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і благовірних князів (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний благовірних князів, глас 1-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос благовірних князів, глас 3-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний благовірних князів. «Слава» – інший світильний благовірних князів, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири благовірних князів, глас 1-ий – 4 (перша стихира – двічі). «Слава» – благовірних князів, глас 4-ий, «І нині» – Богородичний Мінеї за гласом «Слави»: «Тебе, Богородице...». Велике славослів’я. Після Трисвятого – тропар благовірних князів, глас 2-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Все вище розуму...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак благовірних князів."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні преподобного, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар благовірних князів. «Слава» – кондак благовірних князів, «І нині» – кондак храму. У храмі святого – тропар храму, тропар благовірних князів; кондак храму. «Слава» – кондак благовірних князів, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – благовірних князів. Апостол і Євангеліє – дня і благовірних князів."}]},
{"date":"07-25","weekday":"субота","title":"Успіння прав. Анни, матері Пресвятої Богородиці. Свв. жінок Олімпіади, диякониси (408 – 410), та Євпраксії, діви Тавенської (413). Пам’ять V Вселенського собору (553).","readings":["Прав.: Гал., 210 зач., IV, 22 – 31. Лк., 36 зач., VIII, 16 – 21.","Ряд.: Рим., 111 зач., XIII, 1 – 10. Мф., 47 зач., XII, 30 – 37."],"notes":"Служба св. прав. Анни славослівна, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири святої, глас 4-ий і глас 1-ий – 6. «Слава» – святої, глас 8-ий: «Із неплідної утроби...»; «І нині» – догматик, глас 6-ий: «Хто Тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири святої, глас 5-ий (зі своїми приспівами). «Слава, і нині» – святої, глас 8-ий: «Прийдіть, усі створіння...». Після Трисвятого – тропар святої, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святої, глас 4-ий (двічі), «Слава, і нині» – той самий тропар. Кафизми 16-та і 17-та (на 17-тій кафізмі ієрей звершує кадіння храму, як на «Господи, взиваю», царські врата залишаються закритими). Малі ектенії. Сідальні святої (по двічі). Псалом 50-ий. Канони: У храмі Господському і Богородиці – канон храму з ірмосом на 6 (ірмоси по двічі) і святої на 8. У храмі святого – канон Богородиці (з попередньої неділі) з ірмосом на 6 (ірмоси по двічі) і святої на 8. Біблійні пісні «Співаємо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний святої, глас 8-ий. «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос святої, глас 2-ий. На 9-і пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний святої (двічі). «Слава, і нині» – Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири святої, глас 1-ий – 4 (перша стихира двічі). «Слава і нині» – святої, глас 2-ий: «Прийдіть, усі любителі дівства...» Велике славослів’я. Після Трисвятого – тропар святої, глас 4-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святої."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні святої, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар святої. «Слава» – кондак святої, «І нині» – кондак храму. У храмі Богородиці – тропар святої. «Слава» – кондак святої, «І нині» – кондак храму (тропар храму не співається). У храмі святого – тропар святої, тропар храму; кондак святої. «Слава» – кондак храму, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – святої і дня. Апостол і Євангеліє – святої і дня."}]},
{"date":"07-26","weekday":"неділя","title":"8-ма неділя після П’ятдесятниці. Глас 7-й. Сщмчч. Єрмолая, Єрмипа і Єрмократа, пресвітерів Нікомидійських (бл. 305). Прмц. Параскеви Римської (ІІ). Прп. Мойсея Угрина, Києво-Печерського, в Ближніх печерах (бл. 1043). Прп. Мойсея, чудотворця Києво-Печерського, в Дальніх печерах (ХІІІ – ХІV). Свт. Йосифа (Нелюбовича-Тукальського), митр. Київського, Галицького і всієї Руси (1675).","glas":7,"readings":["Ран. – Єв. 8-е, Ін., 64 зач., XX, 11 – 18.","Літ. – 1 Кор., 124 зач., I, 10 – 18. Мф., 58 зач., XIV, 14 – 22.","Свт.: Євр., 335 зач., ХІІІ, 17 – 21. Ін., 36 зач., Х, 9 – 16."],"notes":"Служба сщмчч. Єрмолая, Єрмипа і Єрмократа не має святкового знаку, звершується разом з недільною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 7-ий – 7, священномученика, глас 8-ий – 3. «Слава» – священномученика, глас 6-ий: «Нині настав день...»; «І нині» – догматик, глас 7-ий: «Матір’ю надприродно...». Вхід. Прокимен дня. На літії стихира храму і Богородичні стихири Павла Аморрейського, глас 2-ий (На «Господи, взиваю» у воскресній службі 7-го гласу в Октоїху, без стихів). «Слава, і нині» – його ж стихира, глас той же: «втихомир плоті моєї...». На стиховні стихири воскресні, глас 7-ий. «Слава і нині» – Богородичний воскресний, глас той самий: «Усі ми, земнородні...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 7-ий (двічі). «Слава» – тропар священномученика, глас 4-ий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні воскресні. Непорочні. «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє воскресне 8-ме. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Хрестовоскресний на 3, Богородиці (Октоїха) на 3 і священномученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак священномученика, глас 4-ий; сідальний священномученика, глас 8-ий. «Слава і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 7-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 8-ий. «Слава і нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 7-ий – 8. «Слава» – стихира євангельська 8-ма, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «У день спасіння світу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар священномученика. Кондак тільки воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 8. Після входу – тропарі та кондаки: У храмі Господському – тропар воскресний, тропар священномученика. «Слава» – кондак священномученика, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар священномученика; кондак воскресний. «Слава» – кондак священномученика, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар священномученика; кондак воскресний, кондак храму. «Слава» – кондак священномученика, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні. Апостол і Євангеліє – дня."}]},
{"date":"07-27","weekday":"понеділок","title":"9-й тиждень після П’ятдесятниці. Вмч. і цілителя Пантелеймона (305). Прпп. Анфіси, ігумені, і 90 сестер її (VІІІ). Рівноапп. Климента, єп. Охридського (916), Наума, Сави, Горазда й Ангеляра (ІХ-Х, Болг.). Прп. Германа Аляскинського (1837).","readings":["Ран. – Лк., 106 зач., XХІ, 12 – 19.","Літ. – 1 Кор., 150 зач., XI, 31 – XII, 6. Мф., 74 зач., XVIII, 1 – 11.","Вмч.: 2 Тим., 292 зач., II, 1 – 10. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"Звершується полієлейна служба св. вмч. Пантелеймона.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири великомученика, глас 4-ий і глас 2-ий – 8 (перші дві стихири – двічі). «Слава» – великомученика, глас 6-ий: «Засяяла сьогодні...», «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Вхід. Прокимен дня. Паремії великомученика – 3. На стиховні стихири великомученика, глас 1-ий (зі своїми приспівами). «Слава» – великомученика, глас 8-ий: «Полюбивши віру матері...», «І нині» – Богородичний воскресний, глас той самий: «Безневестна Діво...». Після Трисвятого – тропар великомученика, глас 3-ій. «Слава і нині» – Богородичний воскресний, глас той самий: «Тебе оспівуємо, Богородице...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар великомученика, глас 3-ій (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Тебе оспівуємо, Богородице...». Кафизми 4-та і 5-та. Малі ектенії. Сідальні великомученика (по двічі). Полієлей. Величання великомученика: «Величаємо тебе, святий великомученику і цілителю Пантелеймоне, і шануємо чесні страждання твої, що їх за Христа перетерпів ти» і вибраний псалом. Сідальний великомученика після полієлею, глас 4-ий: «Прославляють нині...» (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий: «Матір Божу...». Степенна – 1-ий антифон 4-го голосу. Прокимен великомученика, глас 4-ий: «Праведник, як фінік, розцвітне і, як кедр, що в Ливані, примножиться»; стих: «Насаджені в домі Господньому у дворах Бога нашого процвітуть». Євангеліє великомученика: Лк., 106 зач. Після 50-го псалма: «Слава» – «Молитвами великомученика...». Стихира великомученика, глас 3-ий: «Засяяла нині...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і великомученика на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний великомученика, глас 4-ий. «Слава» – інший сідальний великомученика, глас той самий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос великомученика, глас 5-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний великомученика(двічі).«Слава,інині»–БогородичнийМінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири великомученика, глас 8-ий і глас 5-ий – 4. «Слава» – великомученика, глас 4-ий: «Сьогодні засяяла нам пам’ять...», «І нині» – Богородичний Мінеї, глас той самий: «Богородицю піснями...». Велике славослів’я. Після Трисвятого – тропар великомученика, глас 3-ій. «Слава, і нині» – Богородичний воскресний, глас той же: «Тебе оспівуємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні великомученика, пісня 3-я – 4 (з ірмосом), і пісня 6-а – 4. У храмі Господському і Богородиці – тропар храму, тропар великомученика. «Слава» – кондак великомученика, «І нині» – кондак храму. У храмі святого – тропар храму, тропар великомученика; кондак храму. «Слава» – кондак великомученика, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і великомученика. Апостол і Євангеліє – дня і великомученика."}]},
{"date":"07-28","weekday":"вівторок","title":"Апп. від 70-х: Прохора, Никанора, Тимона і Пармена, дияконів (І). Мчч. Юліана (І), Євстафія (бл. 316) та Акакія (бл. 321). Прп. Іова Угольського (1985). Смоленської ікони Божої Матері «Одигітрія» («Провідниця», принесена з Царгорода у 1046 році).","readings":["1 Кор., 152 зач., XII, 12 – 26. Мф., 76 зач., XVIII, 18 – 22; XIX, 1 – 2, 13 – 15."],"notes":"Служба апп. від 70-х: Прохора, Никанора, Тимона і Пармена, дияконів не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 7-ий – 3 і апостолів, глас 1-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той самий: «Гнилою вдачею...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Радуйся, сонця духовного...». Після Трисвятого – тропар апостолів, глас 3-ій. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Пристановище і сила наша ...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостолів, глас 3-ій (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Пристановище і сила наша...». Кафизми 7-ма і 8-ма. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4 і апостолів на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний апостолів, глас 3-ій. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак апостолів, глас 1-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Світло, Христе...». Після Трисвятого – тропар апостолів, глас 3-ій. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Кожен, де бачить спасіння...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостолів."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякдені антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар апостолів; кондак дня, кондак апостолів. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар апостолів; кондак дня, кондак храму, кондак апостолів. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"07-29","weekday":"середа","title":"Мч. Калиника Кілікійського (ІІІ – ІV). Мц. Серафими, діви (ІІ). Мц. Феодотії і трьох дітей її (бл. 304). Прмч. Михаїла Едеського, ченця (ІХ). Мч. Євстафія Мцхетського (589, Груз.). Мч. Даниїла (Кушніра), Мліївського (1766).","readings":["1 Кор., 154 зач., XIII, 4 – XIV, 5. Мф., 80 зач., XX, 1 – 16."],"notes":"Служба мч. Калиника не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири Октоїха, глас 7-ий – 3, і мученика, глас 8-ий – 3. «Слава» – мученика, глас той самий: «Благочестя поборника...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Що це за видіння...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – ХрестобогородичнийОктоїха,гластойсамий:«СвогоСина...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Діво пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Діво пренепорочна ...». Кафизми 10-та і 11-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4 і мученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний мученика, глас 3-ій. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той самий: «Коли побачила...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богродице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякдені антифони. Після входу – тропарі і кондаки: У храмі Господському – тропар дня: «Спаси, Господи...», тропар мученика; кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар мученика; кондак дня: «Вознісся на Хрест...», кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар мученика; кондак дня: «Вознісся на Хрест...», кондак храму, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...».. Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"07-30","weekday":"четвер","title":"Апп. від 70-х: Сили, Силуана, Крискента, Епенета і Андроніка (І). Мч. Іоана Воїна (ІV). Сщмчч. Поліхронія, єп. Вавилонського, Парменія, Єлими і Хрисотеля, пресвітерів, Луки і Муко, дияконів, мчч. Авдона і Сеніса, князів Перських, та Олімпія і Максима (бл. 251). Сщмч. Валентина (Уалентина), єпископа Італійського, і трьох учнів його – мчч. Прокули, Єфива та Аполлонія і прав. Авундія (бл. 273). Прп. Ангеліни, правительки Сербської (1520)","readings":["1 Кор., 155 зач., XIV, 6 – 19. Мф., 81 зач., XX, 17 – 28.","Мч.: Рим., 116 зач., XV, 1 – 7. Мф., 69 зач., ХVІ, 24 – 28."],"notes":"Служба апп. від 70-х: Сили, Силуана, Крискента, Єпенета й Андроника не має святкового знаку, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. На «Господи, взиваю» стихири Октоїха, глас 7-ий – 3, і апостолів, глас 4-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той самий: «Радуйся, сонцевидний променю...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Єдину після Різдва...». Після Трисвятого – тропар апостолів, глас 3-ій. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Пророки проповідували...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар апостолів, глас 3-ій (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Пророки проповідували ...». Кафизми 13-та і 14-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і апостолів на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний апостолів, глас 3-ій. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак апостолів, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Народився Ти, Христе...». Після Трисвятого – тропар апостолів, глас 3-ій. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Кожен, де бачить...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостолів."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякдені антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, інший тропар дня, тропар апостолів; кондак дня, інший кондак дня, кондак апостолів. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, інший тропар дня, тропар храму, тропар апостолів; кондак дня, інший кондак дня, кондак храму, кондак апостолів. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"07-31","weekday":"п’ятниця","title":"Передсвято винесення древ чесного і животворчого Хреста Господнього. Прав. Євдокима Кападокійця (ІХ). Мц. Юлити Кесарійської (304 – 305).","readings":["1 Кор., 157 зач., XIV, 26 – 40. Мф., 83 зач. (друге), XXI, 12 – 14, 17 – 20.","Прав.: Гал., 213 зач., V, 22 – VI, 2. Мф., 43 зач., XI, 27 – 30."],"notes":"Заговини на Успенський піст. Служба Хреста і прав. Євдокима Каппадокіянина шестирічна, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 15-та. На «Господи, взиваю» стихири на 6: Хреста, глас 1-ий – 3, і святого, глас 8-ий – 3. «Слава» – святого, глас 1-ий: «Як не дивуватися...», «І нині» – Хреста (з Мінеї), глас той самий: «Нині воістину...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – Хреста (з Мінеї), глас 2-ий: «Ти є мій державний покров...». Після Трисвятого – тропар святого, глас 4-ий. «Слава, і нині» – тропар Хреста, глас 1-ий: «Спаси, Господи...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар Хреста, глас 1-ий (двічі). «Слава» – тропар святого, глас 4-ий, «І нині» – тропар Хреста, глас 1-ий. Кафизми 19-та і 20-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), Хреста на 4, і святого на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (святого). Після 3-ої пісні – сідальний святого, глас 4-ий. «Слава, і нині» – Хреста, глас той самий. Після 6-ої пісні – кондак та ікос святого, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний святого, «І нині» – світильний Хреста. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий. «Слава» – святого, глас 1-ий: «Як нам не дивуватися...», «І нині» – Хреста, глас 6-ий: «Пророчі голоси...». Після Трисвятого – тропар святого, глас 4-ий. «Слава, і нині» – тропар Хреста, глас 1-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Хреста. «Слава» – тропар святого. Кондак святого."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. На вході – «у святих дивний Сий...». Після входу – тропарі і кондаки: У храмі Господському – тропар Хреста: «Спаси, Господи...», тропар святого; кондак святого. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар Хреста: «Спаси, Господи...» , тропар храму, тропар святого; кондак дня: «Вознісся на Хрест...», кондак святого. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар Хреста: «Спаси, Господи...», тропар храму, тропар святого; кондак дня: «Вознісся на Хрест...», кондак храму, кондак святого. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і святого. Апостол і Євангеліє – дня, суботи (під зачало) і святого. Примітка. З цього дня розпочинається піст, оскільки передсвято винесення Чесни Древ випадає на п’ятницю, і триває до свята Успіння Пресвятої Богородиці. Рибу ж їмо лише у свято Преображення Господнього (Типікон, 31 липня)."}]},
{"date":"08-01","weekday":"субота","title":"Винесення чесних древ животворчого Хреста Господнього. Сімох мчч. Маккавеєвих: Авима, Антоніна, Гурія, Єлеазара, Євсевона, Аліма і Маркела, матері їхньої мц. Соломонії та вчителя їхнього мч. Єлеазара (166 р. до Р. Х.). Мчч. в Пергії Памфілійській: Леонтія, Атія, Олександра, Киндея, Минсифея, Киріака, Минеона, Катуна і Евклея (ІІІ).","readings":["Хреста: 1 Кор., 125 зач., I, 18 – 24. Ін., 60 зач., XIX, 6 – 11, 13 – 20, 25 – 28, 30 – 35.","Ряд. (під зачало): Рим., 113 зач., XIV, 6 – 9. Мф., 64 зач., XV, 32 – 39.","Мчч.: Євр., 330 зач., XI, 33 – XII, 2. Мф., 38 зач., X, 32 – 36; XI, 1.","На водосвятті: Євр., 306 зач., II, 11 – 18. Ін., 14 зач., V, 1 – 4."],"notes":"Початок Успенського посту. Служба Чесних Древ Животворчого Хреста Господнього і мучеників Маккавеїв славослівна, звершується разом зі службою Октоїха. Примітка. Перед початком вечірні ієрей виносить з сосудохранительниці (ризниці) Чесний Хрест, кладе його на жертовник на блюді, покритому покрівцем, і прикрашає Хрест вінком з живих квітів. Безпосередньо перед початком вечірні ієрей та диякон в облаченні підходять до жертовника. Диякон виголошує тихо: «Благослови, владико». Ієрей: «Благословен Бог наш...». Трисвяте. по «Отче наш...» – виголос: «Бо Твоє є Царство...». Після виголосу співають (тихо) тропар Хреста, глас 1-ий: «Спаси, Господи, людей Твоїх...», «Слава, і нині» – кондак Хреста, глас 4-ий: «Вознісся на Хрест волею...». Під час співу ієрей кладе на главу блюдо з Хрестом, переносить Хрест на престол у супроводі свічконосця зі свічкою і диякона з кадилом і кладе його на євангельське місце, а Євангеліє (зазвичай заздалегідь, до перенесення) ставлять на горньому місці престолу, куди воно ставиться після читання на Літургії. Перед престолом ставиться підсвічник. З цього дня до віддання Воздвиження (крім віддання свята Преображення Господнього, передсвята Успіння Пресвятої Богородиці, самого свята Успіння, його віддання свята і віддання) на ранній, коли співається велике славослів’я, катавасія «Хрест накреслив...».","sections":[{"svc":"ПОВСЯКДЕННІЙ ВЕЧІРНІ","text":"НА ПОВСЯКДЕННІЙ ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Хреста (Мінеї), глас 4-ий – 3, і мучеників, глас 1-ий – 3. «Слава» – мучеників, глас 8-ий: «Святі Маккавеї...», «І нині» – догматик, глас 7-ий: «Матір’ю надприродно...». (Або ж Хреста (Мінеї), глас 8-ий: «Його ж у давнину Мойсей прообразував...».). Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий (мученичні із числа стихир на «Господи, взиваю» – 2-га: «Спасе, не осором...», 3-тя: «Слава Тобі...», 4-та: «Святі мученики...», приспіви звичайні зі стиховних з Часослова). «Слава» – мучеників, глас 8-ий: «Душі праведних...», «І нині» – Хреста, глас той самий: «Слово пророка...». Після Трисвятого – тропар мучеників глас 1-ий. «Слава, і нині» – тропар Хреста, глас той самий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Хреста, глас 1-ий (двічі). «Слава» – тропар мучеників, глас той самий, «І нині» – тропар Хреста, глас той самий. Кафизми 16-та і 17-та (на 17-тій кафізмі ієрей звершує кадіння храму, як на «Господи, взиваю», царські врата залишаються закритими). Малі ектенії. Сідальні Октоїха. Псалом 50-ий. Канони: У храмі Господньому і Богородиці – канон храму з ірмосом на 4 (ірмоси по двічі), Креста (Мінеї) на 6 і мучеників на 4. У храмі святого – канон Богородиці (з попередньої неділі) з ірмосом на 4 (ірмоси по двічі), Хреста (Мінеї) на 6 і мучеників на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Примітка. З цього дня і до Преображення Господнього (включно), а також в день віддання свята Преображення, якщо на ранній співається велике славослів’я, катавасія свята Воздвиження: «Хрест накреслив...» (див. Типікон, гл. 19). Після 3-ої пісні – кондак та ікос мучеників, глас 2-ий; сідальний мучеників, глас 8-ий. «Слава, і нині» – сідальний Хреста, глас 6-ий: «Хрест Твій, Господи...». Після 6-ої пісні – кондак та ікос Хреста, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний мучеників, «Слава, і нині» – світильний Хреста (Мінеї). Примітка. До співу великого славослів’я (зазвичай під час співу канону або хвалітніх стихир) предстоятель одягається в усі священичі одежі (без читання відповідних молитов). «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: Хреста (Мінеї) глас 1-ий – 3, і мучеників, глас 1-ий, глас 4-ий і глас 5-ий – 3. «Слава» – мучеників, глас 4-ий: «Прийдіть вірні, побачимо мужність...», «І нині» – Хреста (Мінеї), глас той самий: «Господи, Ти допоміг...». Велике славослів’я. Під час співу славослів’я предстоятель (одягнений у всі священні одежі) звершує з дияконом триразове кадіння навколо престолу. Після закінчення великого славослів’я, при співі Трисвятого, поклонившись до землі тричі, предстоятель кладе Хрест на голову (при співі заключного: «Святий Боже...») і виходить (через горнє місце) північними дверима (перед ним йдуть свічконосець зі свічкою і диякон з кадилом) до царських врат. Після закінчення Трисвятого предстоятель виголошує в царських вратах: «Премудрість, станьмо побожно». За звичаєм, предстоятель творить Хрестом хресне знамення в царських вратах. Хор співає тричі тропар Хреста: «Спаси, Господи, людей Твоїх...». Ієрей у супроводі свічконосця і диякона йде на середину храму, де кладе Хрест на заздалегідь приготовлений аналой і звершує навколо нього триразове кадіння. Духовенство тричі співає: «Хресту Твоєму...» (кожен раз завершуючи спів земним поклоном), хор повторює тричі також цей піснеспів. Відбувається поклоніння Хресту і цілування його під час співу стихир, глас 2-ий, глас 5-ий і глас 8-ий: «Прийдіть, вірні...» та ін. Зазвичай під час цілування Хреста відбувається помазання освяченим єлеєм. Звичайні єктенії – потрійна: «Помилуй нас, Боже...», і благальна: «Доповнімо ранню молитву...» (з голововклонною молитвою). Відпуст: «Христос, істинний Бог наш, молитвами Пречистої Своєї Матері, силою Чесного і Животворчого Хреста...» (на відпусті поминаються свв. Мчч. Маккавеї)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Хреста. «Слава» – тропар мучеників. Кондаки Хреста і мучеників читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Хреста, пісня 3-я – 4 (з ірмосом), і мучеників, пісня 6-а – 4. На вході – «...у святих дивний Сий...». Після входу – тропар Хреста, тропар мучеників; «Слава» – кондак мучеників, «І нині» – кондак Хреста. Співається Трисвяте. Прокимен і алилуарій – Хреста (Мінеї) і мучеників. Апостол і Євангеліє – Хреста і мучеників (рядове читання переноситься на п’ятницю 31 липня). Причасний – Хреста: «Яви нам світло лиця Твого, Господи...», і мучеників: «Радуйтеся, праведні, у Господі...». У цей день відбувається чин малого освячення води. За звичаєм,також освячення меду нового збору. Примітка. Хрест заноситься у вівтар увечері після відпусту малої вечірні, перед початком Всенічного бдіння. Примітка. За Уставом, освячення води відбувається на ранній після Винесення Хреста, перед поклонінням йому, або перед часами і Літургією (див. Типікон, гл. 48, 1 серпня). На практиці, освячення води, зазвичай, відбувається після Літургії. Примітка. «Про піст Пресвятої Богородиці слід знати: В піст Святої Владичиці нашої Богородиці Успіння 15 днів, крім Преображення Христового, постимо до 9-ої години дня. Понеділок, середу і п’ятницю – сухоядіння; і творимо поклони, також перед Причастям. У вівторок і четвер варена їжа без олії. А в суботу і Неділю варена їжа з олією, і п’ємо вино; рибу ж не їмо до Успіння Пресвятої Богородиці, окрім Преображення Христового, коли їмо рибу, двічі на день» (Типікон, гл. 33)."}]},
{"date":"08-02","weekday":"неділя","title":"9-та неділя після П’ятдесятниці. Глас 8-й. Перенесення з Єрусалима до Константинополя мощів першомученика архідияк. Стефана (бл. 428) і знайдення мощів правв. Никодима, Гамаліїла і сина його Авіва. Сщмч. Стефана, єпископа Римського, та інших з ним (257).","glas":8,"readings":["Ран. – Єв. 9-е, Ін., 65 зач., XX, 19 – 31.","Літ. – 1 Кор., 128 зач., III, 9 – 17. Мф., 59 зач., XIV, 22 – 34.","Першомч.: Діян., 17 зач., VI, 8 – 15; VII, 1 – 5, 47 – 60. Мф., 87 зач., XXI, 33 – 42."],"notes":"Служба першомученика архідияк. Стефана шестерична, звершується разом із недільною службою Октоїха. Примітка. Після відпусту малої вечірні (на практиці після завершення 9 Часу, перед початком Всенічного бдіння) відкриваются царські врата. Ієрей в фелоні і диякон в стихарі виходять до Хреста, який лежить на аналої. Ієрей у супроводі диякона зі свічкою звершує кадіння Хреста (триразово), потім співається тропар Хреста, «Слава, і нині» – кондак Хреста. Хрест вноситься через царські врата у вівтар, кладеться на престолі, і відбувається хрестоподібне обкадження престолу. Потім Хрест відноситься до ризниці.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 8-ий – 6 і першомученика, глас 8-ий і глас 2-ий – 4. «Слава» – першомученика, глас 6-ий: «Першим серед мучеників...», «І нині» – догматик, глас 8-ий: «Цар Небесний...». Вхід. Прокимен дня. На літії стихира храму і Богородичні стихири Павла Аморрейського, глас 4-ий (На «Господи, взиваю» у воскресній службі 8-го гласу в Октоїху, без стихів). «Слава, і нині» – його ж стихира, глас той же: «Коли поставлять престоли...». На стиховні стихири воскресні, глас 8-ий. «Слава» – першомученика, глас 8-ий: «Радуйся у Господі...», «І нині» – Богородичний воскресний, глас той самий: «Неневісна Діво...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 8-ий (двічі). «Слава» – тропар першомученика, глас 4-ий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні воскресні. Непорочні. «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє воскресне 9-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси один раз), Хрестовоскресний на 2, Богородиці на 2 і першомученика на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – кондак та ікос першомученика, глас 6-ий; сідальний першомученика, глас 1-ий (двічі). «Слава і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 9-ий. «Слава» – світильний першомученика, «І нині» – Богородичний воскреслого екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 8-ий – 4, і першомученика, глас 4-ий – 4 (приспіви до двох останніх стихир у Мінеї, з прокімна Літургії). «Слава» – стихира євангельська 9-та, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар першомученика. Кондак тільки воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і першомученика, піня 3-тя – 4. Після входу – тропарі та кондаки: У храмі Господському – тропар воскресний, тропар першомученика. «Слава» – кондак першомученика, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар першомученика; кондак воскресний. «Слава» – кондак першомученика, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар першомученика; кондак воскресний, кондак храму. «Слава» – кондак першомученика, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні і першомученика. Апостол і Євангеліє – дня і першомученика."}]},
{"date":"08-03","weekday":"понеділок","title":"10-й тиждень після П’ятдесятниці. Прпп. Ісаакія, Далмата і Фавста (ІV – V). Мч. Раждена, перса (457, Груз.). Прп. Косми, пустельника (VІ).","readings":["1 Кор., 159 зач., XV, 12 – 19. Мф., 84 зач., XXI, 18 – 22."],"notes":"Служба прпп. Ісаакія, Далмата і Фавста не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: Октоїха, глас 8-ий – 3 і преподобних, глас 8-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той самий: «горе тому...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Сприйнявши голос...». Після Трисвятого – тропар преподобних, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар преподобних, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована ...». Кафизми 4-та і 5-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і преподобних на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний преподобних, глас 8-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак преподобних, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Небесні сили...». Після Трисвятого – тропар преподобних, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти вища...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобних."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякдені антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар преподобних; кондак дня, кондак преподобних. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар преподобних; кондак дня, кондак храму, кондак преподобних. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"08-04","weekday":"вівторок","title":"Сімох отроків у Ефесі: Максиміліана, Ямвлиха, Мартиніана, Іоана, Діонісія, Ексакустодіана (Костянтина) та Антоніна (бл. 250; 408 – 450). Прмц. Євдокії (362 – 364). Мч. Єлевферія (ІV).","readings":["1 Кор., 161 зач., XV, 29 – 38. Мф., 85 зач., XXI, 23 – 27."],"notes":"Служба сімох отроків у Ефесі не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 6-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 8-ий – 3 і святих, глас 1-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той самий: «Жезлом Твоєї молитви...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Радуйся, вселенної похвало...». Після Трисвятого – тропар святих, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «До Богородиці щиро...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святих, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «До Богородиці щиро...». Кафизми 7-ма і 8-ма. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і святих на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – інший кондак святих, глас 4-ий, сідальний святих, глас той самий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак святих, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний святих, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Покров Твій...». Після Трисвятого – тропар святих, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святих."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякдені антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар святих; кондак дня, кондак святих. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар святих; кондак дня, кондак храму, кондак святих. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"08-05","weekday":"середа","title":"Передсвято Преображення Господнього. Мч. Євсигнія Антіохійського (362). Сщмчч. Анфіра (236) і Фабіана (250), єпископів Римських. Мч. Понтія Римлянина (бл. 257). Мчч. Кантидія, Кантидіана і Сивела, в Єгипті. Прав. Нонни, диякониси, матері свт. Григорія Богослова (374). Прп. Феоктиста Печерського, єп. Чернігівського († 1123).","readings":["1 Кор., 165 зач., XVI, 4 – 12. Мф., 86 зач., XXI, 28 – 32 (за середу).","2 Кор., 167 зач., I, 1 – 7. Мф., 88 зач., XXI, 43 – 46 (за четвер)."],"notes":"Примітка. З цього дня і до 23 серпня (включно) Октоїх не співається (крім недільних днів). Звершується шестерична служба передсвята Преображення і мученика Евсигнія.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та. На «Господи, взиваю» стихири на 6: передсвята, глас 4-ий – 3, і мученика, глас той самий – 3. «Слава, і нині» – передсвята, глас 5-ий: «Прийдіть, зійдемо на гору Господню...» Входу немає. Прокимен дня. На стиховні стихири передсвята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – передсвята, глас той самий: «Ти на горі Фаворській...». Після Трисвятого – тропар передсвята, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 10-та і 11-та. Малі єктенії. Сідальні передсвята (по двічі). Псалом 50-ий. Канони: пісні 1-ша, 8-ма і 9-та – канон передсвята з ірмосом на 6 (ірмоси по двічі), трипіснець на 4 і мученика на 4; пісні 3-тя, 4-та, 5-та, 6-та і 7-ма – канон передсвята з ірмосом на 8 (ірмоси по двічі) і мученика на 4. Біблійні пісні «Співаємо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (мученика). Після 3-ої пісні – сідальний мученика, глас 4-ий. «Слава, і нині» – сідальний передсвята, глас той самий: «Готуйся нині, Фаворе...» . Після 6-ої пісні – кондак та ікос передсвята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний передсвята. «Слава, і нині» – інший світильний передсвята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири передсвята, глас 1-ий (зі своїми приспівами). «Слава, і нині» – передсвята, глас 5-ий: «Тебе, Христе, Творця і Виконавця...». Після Трисвятого – тропар передсвята, глас 4-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак передсвята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні передсвята, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар передсвята. «Слава, і нині» – кондак передсвята. У храмі Богородиці – тропар передсвята, тропар храму. «Слава» – кондак передсвята, «І нині» – кондак храму. У храмі святого – тропар передсвята, тропар храму. «Слава» – кондак храму, «І нині» – кондак передсвята. Прокимен, алилуарій і причасний – мученика (загальні) або дня (вівторка). Апостол і Євангелія – дня (середи і четверга). Співається «Достойно є...»."}]},
{"date":"08-06","weekday":"четвер","title":"ПРЕОБРАЖЕННЯ ГОСПОДА БОГА І СПАСИТЕЛЯ НАШОГО ІСУСА ХРИСТА.","readings":["Ран. – Лк., 45 зач., IX, 28 – 36.","Літ. – 2 Пет., 65 зач., I, 10 – 19. Мф., 70 зач., XVII, 1 – 9."],"notes":"Бдінна служба свята Преображення Господнього звершується за Мінеєю.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ кафизми немає («Блажен муж» не співається). На «Господи, взиваю» стихири свята, глас 4-ий – 8 (кожна стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «Прообразуючи Воскресіння Твоє...». Вхід. Прокимен дня. Паремії свята – 3. На літії стихири свята, глас 2-ий. «Слава» – свята, глас 5-ий: «Прийдіть, вірні, зійдемо на гору Господню...», «І нині» – свята, глас той самий: «Закону і пророків...». На стиховні стихири свята, глас 1-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 6-ий: «Петру, Якову, та Іоану...». Після Трисвятого – тропар свята, глас 7-ий (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 7-ий (двічі). «Слава, і нині» – той же тропар. Кафизми 13-та і 14-та. Малі єктенії. Сідальні свята (по двічі). Полієлей. Величання свята: «Величаємо Тебе, Житєдавче Христе, і шануємо Пречистої Плоті Твоєї преславне преображення», і вибраний псалом. Сідальний свята після полієлею, глас 4-ий: «Піднявся Ти з учениками...». «Слава, і нині» – інший сідальний свята після полієлею, глас 8-ий: «Утаємничену блискавку...». Степенна – 1-ий антифон 4-го гласу. Прокимен свята, глас 4-ий: «Фавор та Єрмон ім’ям Твоїм радітимуть»; стих: «Твої є небеса, і Твоя є земля». Євангеліє – свята. Після 50-го псалма: «Слава» – «Все сьогодні сповнилося радостю: Христос преобразився перед учениками», «І нині» – той же стих. Стихира, глас 5-ий: «Божества Твого, Спасе...». Канони: свята 1-ий з ірмосом на 8 (ірмоси по двічі) і 2-ий на 8 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – сідальний свята, глас 4-ий. «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос свята, глас 7-ий. На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспіви свята; 1-ий: «Величай, душе моя, Господа, що преобразився на Фаворі» (за традицією, 1-ий приспів співає священик або диякон, звершується звичайне кадіння). Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава» – той самий світильний, «І нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята, глас 8-ий: «Взяв Христос Петра, Якова та Іоана...». Велике славослів’я. Після Трисвятого – тропар свята, глас 7-ий (один раз). Відпуст свята: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як Благий і Людинолюбець»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони свята. Вхідний стих: «Господи, пошли світло та істину Свою, і вони наставлять і поведуть мене на гору святу Твою». Примітка. Перед проголошенням вхідного стиха слід промовляти «Премудрість, станьмо побожно». Після вхідного стиха відразу співається тропар свята, «Слава і нині» – кондак свята, а на архієрейській Літургії після вхідного стиха співається: «Прийдіть, поклонімось... спаси нас, Сину Божий, що преобразився на горі...», а тоді тропар і кондак. Після входу – тропар свята. «Слава, і нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – свята. Задостойник – приспів: «Величай, душе моя...» і ірмос: «Різдво Твоє нетлінним явилося...» (і до віддання). ПІСЛЯ ЗААМВОННОЇ МОЛИТВИ – за традицією, освячення винограду та плодів. Перед читанням молитви – кадіння плодів при співі тропаря свята і на «Слава, і нині» – кондака свята. Диякон: «Господу помолимось». Хор: «Господи, помилуй». Священик читає молитву із Требника «На освячення плодів»: «Благослови, Господи, цей новий виноград і плоди ці...». Хор: «Амінь». Диякон: «Господу помолимось». Хор: «Господи, помилуй». Священик читає молитву Требника: «Владико, Господи Боже наш...». Хор: «Амінь». Священик кропить святою водою приготовлені виноград і плоди, промовляючи: «Благословляються і освячуються плоди ці благодаттю Пресвятого Духа, окропленням водою цією освяченою, в ім’я Отця, і Сина, і Святого Духа. Амінь» (тричі). Хор: «Нехай буде ім’я Господнє благословенне...» (тричі) і 33-й псалом. Відпуст Літургії – як на ранній, але із згадуванням імені свт. Іоана Золотоустого. З 7 по 12 серпня – післясвято Преображення Господнього. 13 серпня – віддання свята Преображення Господнього. На трапезі дозволяється риба."}]},
{"date":"08-07","weekday":"п’ятниця","title":"Післясвято Преображення Господнього. Прмчч. Дометія Перського, ієродияк. та двох учнів його (363). Прп. Пимена Багатохворобливого, Києво-Печерського, в Ближніх печерах (1110). Прп. Пимена, посника Києво-Печерського, в Дальніх печерах (ХІІІ – ХІV). Прп. Меркурія Києво-Печерського, єп. Смоленського, в Ближніх печерах (1239). Мчч. Марина і Астерія (260). Прп. Ора Фіваїдського (бл. 390). Прмц. Потамії, чудотвориці. Прп. Феодосія Нового, лікаря (IX–X). Свт. Ієрофея, єп. Угорського (X). Св. Стефана I, короля Угорщини (1038). Прп. Феодори Сихлівської (XVIII, Рум.).","readings":["2 Кор., 169 зач., I, 12 – 20. Мф., 91 зач., XXII, 23 – 33.","Прмчч.: Еф., 233 зач., VI, 10 – 17. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"Служба прпмч. Дометія не має святкового знаку, звершується разом із службою післясвята Преображення.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: свята Преображення, глас 4-ий – 3, і преподобномученика, глас 6-ий – 3. «Слава, і нині» – свята Преображення, глас той самий: «Прообразуючи Воскресіння Твоє...». Вхід. Прокимен великий, глас 7-ий: «Бог наш на Небесах і на землі...», зі стихами (за звичаєм). Єктенія потрійна: «Промовмо всі...». «Сподоби, Господи». Єктенія прохальна: «Доповнімо вечірню...», і голововклонна молитва. На стиховні стихири свята Преображення, глас 6-ий (з своїми приспівами). «Слава і нині» – свята Преображення, глас 5-ий: «Прийдіть, вірні, зійдемо на гору Господню...». Після Трисвятого – тропар преподобномученика, глас 4-ий. «Слава, і нині» – тропар Преображення, глас 7-ий. Відпуст (у відкритих царських вратах): «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 7-ий (двічі). «Слава» – тропар преподобномученика, глас 4-ий, «І нині» – тропар свята, глас 7-ий. Кафизми 19-та і 20-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмосом на 8 (ірмоси по двічі) і преподобномученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої, 9-ої: ірмоси канону Мінеї (преподобномученика). Після 3-ої пісні – кондак преподобномученика, глас 6-ий; сідальний преподобномученика, глас 8-ий. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята Преображення, глас 7-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліть Господа з небес...» і хвалітні псалми. Читається повсякдене славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава, і нині» – свята, глас – 5-ий: «Тебе, Христе...». Після Трисвятого – тропар преподобномученика, глас 4-ий. «Слава, і нині» – тропар Преображення, глас 7-ий. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар преподобномученика. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята 1-го і 2-го канонів, пісня 1-ша – 6 (1-го канону із ірмосом). На вході – «Прийдіть поклонімось... що преобразився на горі...» (до віддання, крім неділі). Після входу – тропарі і кондаки: У храмі Господському – тропар свята, тропар преподобномученика. «Слава» – кондак преподобномученика, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар преподобномученика; кондак свята. «Слава» – кондак преподобномученика, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар преподобномученика; кондак храму. «Слава» – кондак преподобномученика, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і преподобномученика. Апостол і Євангеліє – дня і преподобномученика. Задостойник свята. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."}]},
{"date":"08-08","weekday":"субота","title":"Свт. Еміліана, спов., єп. Кизицького (815 – 820). Прп. Григорія, іконописця Києво-Печерського, в Ближніх печерах (ХІІ). Свт. Мирона, чудотворця, єп. Критського (бл. 350). Мчч. Єлевферія та Леоніда. Прп. Григорія Синаїта (ХІV).","readings":["Рим., 119 зач., XV, 30 – 33. Мф., 73 зач., XVII, 24 – XVIII, 4."],"notes":"Служба свт. Еміліана не має святкового знаку, звершується разом із службою післясвята Преображення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ Кафизма 18-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3, і святителя, глас той самий – 3. «Слава» – свята Преображення глас 1-ий: «Той, Хто колись розмовляв з Мойсеєм...», «І нині» – догматик, глас 8-ий: «Цар Небесний...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 1-ий: «Твого Єдинородного Сина...». Після Трисвятого – тропар свята, глас 7-ий (один раз). (Тропар святому у Мінеї відсутній)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 7-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 16-та і 17-та (на 17-тій кафізмі ієрей звершує кадіння храму, як на «Господи, взиваю», царські врата залишаються закритими). Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 2-ий з ірмосом на 8 (ірмоси по двічі) і святителя на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої, 9-ої: ірмоси канону Мінеї (святителя). Після 3-ої пісні – кондак святителя, глас 3-ий; сідальний святителя, глас той самий. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята Преображення, глас 7-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліть Господа з небес...» і хвалітні псалми. Читається повсякдене славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас – 1-ий: «Нестримане сяяння...». Після Трисвятого – тропар свята, глас 7-ий (один раз). Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак тільки свята. Оскільки в Мінеї святому відсутній тропар, то кондак святого на часах також не читається."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята 1-го і 2-го канонів, пісня 3-тя – 6 (1-го канону із ірмосом). На вході – «Прийдіть поклонімось... що преобразився на горі...». Після входу – тропарі і кондаки: У храмі Господському – тропар свята. «Слава» – кондак святителя, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму; кондак свята. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму; кондак храму. «Слава» – кондак святителя, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."}]},
{"date":"08-09","weekday":"неділя","title":"10-та неділя після П’ятдесятниці. Глас 1-й. Апостола Матфія (бл. 63). Мч. Антонія Олександрійського. Прп. Псоя Єгипетського (ІV). Мчч. Юліана, Маркіана, Іоана, Якова, Олексія, Димитрія, Фотія, Петра, Леонтія, Марії, патрикії, та ін. (730).","glas":1,"readings":["Ран. – Єв. 10-е, Ін., 66 зач., XXI, 1 – 14.","Літ. – 1 Кор., 131 зач., IV, 9 – 16. Мф., 72 зач., XVII, 14 – 23.","Ап.: Діян., 2 зач., I, 12 – 17, 21 – 26. Лк., 40 зач., IX, 1 – 6."],"notes":"Служба ап. Матфія полієлейна, звершується разом із недільною службою Октоїха та службою післясвята Преображення.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 1-ий – 3, свята Преображення, глас 2-ий – 3 (у службі апостола Матфія), і апостола, глас 1-ий – 4 (перша стихира – двічі). «Слава» – апостола, глас 6-ий: «Вилилася благодать...», «І нині» – догматик, глас 1-ий: «Всесвітню славу...». Вхід. Прокимен дня. Паремії апостола – 3 (за традицією, новозавітні паремії читаються при відкритих Царських вратах). На літії стихири свята, глас 6-ий (Див. на стиховні вечірні без приспівів). «Слава» – апостола, глас 2-ий: «Залишивши земне...» (славник на хвалитніх ранньої), «І нині» – свята, глас той самий: «побачили на горі...» (Див. на хвалитніх ранньої у служюі апостола). На стиховні стихири воскресні, глас 1-ий: «Слава» – апостола, глас 2-ий: «Сповнений Божественної ревності...», «І нині» – свята, глас той самий: «Ти, що на горі...». Після Трисвятого – «Богородице Діво» (двічі)» і тропар Преображення, глас 7-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 1-ий (двічі). «Слава» – тропар апостола, глас 3-ий, «І нині» – тропар свята Преображення, глас 7-ий. Кафизми 2-га і 3-тя. Малі єктенії. Сідальні воскресні Октоїха. Полієлей. Величання великомученика і вибраний псалом. «Ангельський собор...». Іпакої гласу. Сідальний апостола після 1-ої кафізми, глас 2-ий: «Уловивши народи...», сідальний апостола після 2-ої кафізми, глас 4-ий: «Показуючи людську зміну...», «Слава» – сідальний апостола після полієлею, глас 8-ий: «Ідольську гординю...», «І нині» – свята, глас 4-ий: «На горі Фаворській...». Степенні і прокимен – гласу. Євангеліє воскресне 9-те. Співається «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмос один раз), свята Преображення 1-ий на 4 і апостола на 6. Біблійні пісні «Співаймо Господеві,...». Катавасія Преображення: «Зібрання ізраїльські...». Після 3-ої пісні – кондак та ікос свята, глас 7-ий; кондак та ікос апостола, глас 4-ий, сідальний апостола, глас 8-ий. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 1-ий. На 9-й пісні співаємо «Чеснішу». Після 9-ої пісні «Свят Господь наш...». Екзапостиларій недільний 10-ий. «Слава» – світильний апостола, «І нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 1-ий – 4, апостола, глас 4-ий і глас 2-ий – 4 (зі славником і приспівами своїми). «Слава» – стихира Євангельська 10-та, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар недільний: «У день спасіння...». Відпуст: «Христос, що воскрес із мертвих...». НА 1 ЧАСІ – тропар воскресний. «Слава» – тропар свята. Кондак свята. НА 3 ЧАСІ – тропар воскресний. «Слава» – тропар апостола. Кондак воскресний. НА 6 ЧАСІ – тропар воскресний. «Слава» – тропар свята. Кондак апостола. НА 9 ЧАСІ – тропар воскресний. «Слава» – тропар апостола. Кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4, і свята, пісня 4-та – 4, і апостола, пісня 6-та – 4. На вході: «Прийдіть поклонімось... що воскрес із мертвих...». Після входу – тропарі і кондаки: У храмі Господському – тропар воскресний, тропар свята, тропар апостола, кондак воскресний. «Слава» – кондак апостола, «І нині» – кондак свята. У храмі Богородиці і святого – тропар воскресний, тропар свята, тропар храму, тропар апостола; кондак воскресний, кондак храму. «Слава» – кондак апостола, «І нині» – кондак свята. Прокимен, алилуарій і причасний – воскресні і апостола. Апостол і Євангеліє – дня і апостола. Задостойник свята. Відпуст: «Христос, що воскрес із мертвих...»."}]},
{"date":"08-10","weekday":"понеділок","title":"11-й тиждень після П’ятдесятниці. Сщмчч. Лаврентія, архідиякона, Сикста ІІ, єпископа, Фелікисима й Агапіта, дияконів, мч. Романа, Римських (258).","readings":["2 Кор., 171 зач., II, 3 – 15. Мф., 94 зач., XXIII, 13 – 22."],"notes":"Служба мч. Лаврентія не має святкового знаку, звершується разом зі службою післясвята Преображення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3, і мученика, глас 1-ий – 3. «Слава, і нині» – свята, глас 4-ий: «Раніше Хреста Твого...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 4-ий: «Раніше Хреста Твого, Господи...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – тропар свята, глас 7-ий. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 7-ий (двічі). «Слава» – тропар мученика, глас 4-ий, «І нині» – тропар свята, глас 7-ий. Кафизми 4-та і 5-та Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 2-ий з ірмосом на 8 (ірмоси по двічі) і мученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (мученика). Після 3-ої пісні – кондак та ікос мученика, глас 2-ий; сідальний мученика, глас 8-ий. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 7-ий. На 9-ій пісні співаймо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами): «Засявши невимовно від Пресвятої Діви...» . «Слава, і нині» – свята, глас той самий: «Владичице Чиста...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – тропар свята, глас 7-ий. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар мученика. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята 1-го і 2-го канонів, пісня 5-та, – 6 (1-го канону з ірмосом). На вході: «Прийдіть поклонімось... преобразився на горі...». Після вході – тропарі і кондаки: У храмі Господському – тропар свята, тропар мученика. «Слава» – кондак мученика, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар мученика; кондак свята. «Слава» – кондак мученика, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар мученика; кондак храму. «Слава» – кондак мученика, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."}]},
{"date":"08-11","weekday":"вівторок","title":"Сщмч. Євпла, архідиякона (304). Прмчч. Федора і Василія Києво-Печерських, в Ближніх печерах (1098). Прп. Федора, кн. Острозького, Києво-Печерського, в Дальніх печерах (бл. 1438). Мц. Сусанни, діви, і з нею сщмчч. Гая, єпископа Римського, Гавинія, пресвітера, мчч. Клавдія, Максима, Препедигни, Олександра і Куфія (295 – 296).","readings":["2 Кор., 172 зач., II, 14 – III, 3. Мф., 95 зач., XXIII, 23 – 28."],"notes":"Служба мч. Євпла не має святкового знаку, звершується разом зі службою післясвята Преображення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 6-та. На «Господи, взиваю» стихири на 6: свята, глас 1-ий – 3, і мученика, глас 4-ий – 3. «Слава, і нині» – свята, глас той самий: «Гора, колись покрита...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 4-ий: «На горі високій...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – тропар свята, глас 7-ий. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 7-ий (двічі). «Слава» – тропар мученика, глас 4-ий, «І нині» – тропар свята, глас 7-ий. Кафизми 7-ма і 8-ма. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмосом на 8 (ірмоси по двічі) і мученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (мученика). Після 3-ої пісні – кондак мученика, глас 1-ий; сідальний мученика, глас той самий. «Слава, і нині» – сідальний свята, глас 4-ий. Після 6-ої пісні – кондак та ікос свята, глас 7-ий. На 9-ій пісні співаймо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас той самий: «Голос з неба...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – тропар свята, глас 7-ий. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар мученика. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята 1-го і 2-го канонів, пісня 6-та, – 6 (1-го канону з ірмосом). На вході: «Прийдіть поклонімось... що преобразився на горі...». Після вході – тропарі і кондаки: У храмі Господському – тропар свята, тропар мученика. «Слава» – кондак мученика, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар мученика; кондак свята. «Слава» – кондак мученика, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар мученика; кондак храму. «Слава» – кондак мученика, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."}]},
{"date":"08-12","weekday":"середа","title":"Мчч. Фотія й Аникити та багатьох із ними (305 – 306). Сщмч. Олександра, єп. Команського (ІІІ). Мчч. Памфіла й Капітона.","readings":["2 Кор., 173 зач., III, 4 – 11. Мф., 96 зач., XXIII, 29 – 39."],"notes":"На цей день переноситься з 13 серпня служба прп. Максима Сповідника (Типікон, 12 серпня). Служба мчч. Фотія і Аникити і прп. Максима Сповідника не має святкового знаку, звершується разом зі службою післясвята Преображення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та. На «Господи, взиваю» стихири на 6: мучеників, глас 4-ий – 3, і преподобного, глас той самий – 3. «Слава» – преподобного, глас 8-ий: «Безліч ченців...», «І нині» – свята, глас той самий: «Морок закону прийняв...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий. «Слава» – преподобного, глас 6-ий: «Преподобний отче...», «І нині» – свята, глас 5-ий: «Малу зорю Твого Божества...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – тропар свята, глас 7-ий. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 7-ий (один раз), тропар мучеників, глас 4-ий (один раз). «Слава» – тропар преподобного, глас 8-ий, «І нині» – тропар свята, глас 7-ий. Кафизми 10-та і 11-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 2-ий з ірмосом на 6 (ірмоси по двічі), мучеників на 4 і преподобного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої піснях – ірмоси канону Мінеї (преподобного). Після 3-ої пісні – кондак та ікос преподобного, глас 6-ий; сідальний мучеників, глас 4-ий. «Слава» – сідальний преподобного, глас 3-ій, «І нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 7-ий. На 9-ий пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний преподобного. «Слава, і нині» – світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас той же: «Гора Божа Фавор...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – тропар свята, глас 7-ий. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропарі мучеників і преподобного читаються поперемінно. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята 1-го і 2-го канонів, пісня 7-ма (1-го канону з ірмосом) і 8-ма – 6. На вході: «Прийдіть поклонімось... що преобразився на горі...». Після входу – тропарі і кондаки: У храмі Господському – тропар свята, тропар мучеників, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар мучеників, тропар преподобного; кондак свята. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар мучеників, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."}]},
{"date":"08-13","weekday":"четвер","title":"Віддання свята Преображення Господнього. Прп. Максима Сповідника (662). Мчч. Іполита, Іринея, Авундія і мц. Конкордії в Римі (258).","readings":["2 Кор., 175 зач., IV, 1 – 6. Мф., 99 зач., XXIV, 13 – 28."],"notes":"Звершується славослівна служба віддання свята Преображення. Служби рядових святих переносяться на інший день (див. 12 серпня).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. На «Господи, взиваю» стихири свята, глас 4-ий – 6 (перші дві стихири – двічі). «Слава, і нині» – свята, глас 6-ий: «Прообразуючи Воскресіння Твоє...». Входу немає. Прокимен дня. Паремій немає. На стиховні стихири свята, глас 1-ий. «Слава, і нині» – свята, глас 6-ий «Петру, і Якову та Іоану...». Після Трисвятого – тропар свята, глас 7-ий (один раз). Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 7-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 13-та і 14-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмос на 8 (ірмоси по двічі) і 2-ий без ірмосів на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – сідальний свята, глас 4-ий. «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос свята, глас 7-ий. На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспів свята: «Величай, душе моя, Господа, що преобразився на Фаворі» (звершується звичайне кадіння). Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята, глас 8-ий: «Взяв Христос Петра, Якова та Іоана...». Велике славослів’я. Після Трисвятого – тропар свята, глас 7-ий (один раз). Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні свята, 1-го і 2-го канонів, пісня 9-а – 8 (1-го канону – з ірмосом). На вході: «Прийдіть поклонімось... що преобразився на горі...». Після входу – тропар свята. «Слава, і нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Відпуст: «Христос, що на горі Фаворській преобразився у славі, перед святими Своїми учениками і апостолами, істинний Бог наш, молитвами...»."}]},
{"date":"08-14","weekday":"п’ятниця","title":"Передсвято Успіння Пресвятої Богородиці. Прор. Михея (VІІІ ст. до Р. Х.). Перенесення мощів прп. Феодосія Києво-Печерського (1091). Сщмч. Маркела, єп. Апамейського (бл. 389).","readings":["2 Кор., 177 зач., IV, 13 – 18. Мф., 100 зач., XXIV, 27 – 33, 42 – 51 (за п’ятницю).","1 Кор., 123 зач., I, 3 – 9. Мф., 78 зач., XIX, 3 – 12 (за суботу, під зачало).","Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Звершується славослівна служба прп. Феодосія Києво-Печерського в поєднанні із шестиричною службою прор. Михея і передсвята Успіння.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-та. На «Господи, взиваю» стихири на 6: преподобного, глас 4-ий – 3, і пророка, глас той самий – 3. «Слава» – преподобного, глас 6-ий: «Прийшло нині свято...», і нині» – передсвята, глас 4-ий: «Всечесне Твоє успіння...» (в службі пророка Михея). Входу немає. Прокимен дня. На стиховні стихири передсвята, глас 2-ий (зі своїми приспівами). «Слава» – преподобного, глас 8-ий: «Ченців безліч...», і нині» – передсвята, глас 2-ий: «Будучи вищою за небеса...» (в службі пророка Михея). Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – тропар передсвята, глас 4-ий (в службі пророка Михея)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – тропар передсвята, глас 4-ий. Кафизми 19-та і 20-та. Малі єктенії. Сідальні преподобного (по двічі). «Слава, і нині» – сідальні передсвята (в службі пророка Михея). Псалом 50-ий. Канони: передсвята (в службі пророка Михея) з ірмосом на 4 (ірмоси по двічі), преподобного на 6 і пророка на 4. Біблійні пісні «Співаємо Господеві...». Катавасія Успіння: «Прикрашена Божественною славою...». Примітка. З цього дня і до віддання свята Успіння на ранній, коли співається велике славослів’я, катавасія Успіння: «Прикрашена Божественною славою...». Після 3-ої пісні – кондак та ікос передсвята, глас 4-ий (в службі пророка Михея); сідальний преподобного, глас той самий. «Слава» – сідальний пророка, глас 1-ий, «І нині» – сідальний передсвята, глас 4-ий: «Діви отроковиці...» (в службі пророка Михея). Після 6-ої пісні – кондак та ікос преподобного, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний передсвята: «Ангели і пастирі...» (в службі пророка Михея). «Слава» – світильний преподобного, «І нині» – інший світильний передсвята: «Пресвітлу пам’ять...» (в службі пророка Михея). «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: передсвята, глас 6-ий – 3 (див. на стиховні ранньої, у службі пророка Михея), і преподобного, глас 8-ий – 3. «Слава» – преподобного, глас 6-ий: «Нині архієреї...», «І нині» – перед свята, глас 3-ій: «Прийдіть, усі краї землі...» (в службі пророка Михея). Велике славослів’я. Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – тропар передсвята, глас 4-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар передсвята. «Слава» – тропар преподобного. Кондаки перед свята і преподобного читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні передсвята, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар передсвята, тропар преподобного, кондак храму. «Слава» – кондак преподобного, «І нині» – кондак передсвята. У храмі Богородиці – тропар передсвята, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак передсвята. У храмі святого – тропар передсвята, тропар храму, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – кондак передсвята. Прокимен, алилуарій і причасний – преподобного. Апостол і Євангелія – дня (п’ятниці і суботи, під зачало) і преподобного."}]},
{"date":"08-15","weekday":"субота","title":"УСПІННЯ ПРЕСВЯТОЇ ВЛАДИЧИЦІ НАШОЇ БОГОРОДИЦІ І ПРИСНОДІВИ МАРІЇ. Ікони Успіння Божої Матері Києво-Печерської (1073). Ацкурської (І), Цилканської (ІV), Влахернської (Груз.), Бахчисарайської ікон Божої Матері.","readings":["Ран. – Лк., 4 зач., I, 39 – 49, 56.","Літ. – Богородиці: Флп., 240 зач., II, 5 – 11. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Всенічне бдіння свята Успіння Пресвятої Богородиці звершується за Мінеєю. Примітка. У деяких храмах існує така практика: в переддень свята Успіння, перед всенічною, Плащаниця Божої Матері прикрашається живими квітами і кладеться на престолі, перед яким запалюється світильник, після чого буває кадіння престолу і Плащаниці. Під час ранньої, на полієлеї, Плащаниця з вівтаря виноситься царськими вратами і кладеться посеред храму, де і перебуває до богослужіння, на якому звершується чин Погребіння Божої Матері. Якщо винесення Плащаниці було здійснене в сам день свята, то на службі Погребіння Божої Матері виносу Плащаниці не буває, але свого часу відбувається чин Погребіння з хресним ходом. Втім, у багатьох храмах Плащаниця виноситься в день Погребіння, під час співу особливих тропарів свята на «Бог Господь...».","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири: Успіння, глас 1-ий – на 8 (перших дві стихири – тричі, третя – двічі). «Слава, і нині» – Успіння, глас той самий: «Богоначальним повелінням...». Вхід. Прокимен дня. Паремії Успіння – 3. На літії стихири Успіння, глас 1-ий, глас 2-ий і глас 3-ій. «Слава» – свята, глас 5-ий: «Прийдіть, вірних собори...», «І нині» – свята, глас той самий: «Оспівуйте, люди Матір Бога нашого...». На стиховні стихири Успіння, глас 4-ий (зі своїми приспівами). «Слава, і нині» – Успіння, глас той самий: «Коли відійшла Ти Богородице...». Після Трисвятого – тропар Успіння, глас 1-ий (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Успіння, глас 1-ий (двічі). «Слава, і нині» – тропар той самий. Кафизми 16-та і 17-та (кадіння на 17-ій кафізмі не звершується, а переноситься на полієлей). Малі єктенії. Сідальні свята (по двічі). Полієлей. Величання свята: «Величаємо Тебе, Пренепорочна Мати Христа Бога нашого, і всеславне славимо Успіння Твоє» і вибраний псалом: «Викликуй Господеві, вся земле». Сідальний Успіння після полієлею, глас 4-ий: «Взивай, Давиде...». Степенна – 1-ий антифон 4-го гласу. Прокимен Успіння, глас 4-ий: «Пом’яну ім’я Твоє у всякому роді і роді»; стих: «Слухай, дочко, і споглянь, і прихили вухо Твоє». Євангеліє Богородиці – Лк., Зач. 4. Після 50-го псалма: «Слава» – «Молитвами Богородиці...». Стихира Успіння, глас 6-ий: «Коли наблизилося преставлення пречистого тіла Твого...». Канони: Успіння 1-ий (глас 1-ий) з ірмосом на 8 (ірмоси по двічі) і 2-ий (глас 4-ий) з ірмосом на 8 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси обох канонів свята Успіння. Після 3-ої пісні – іпакої Успіння, глас 8-ий: «Ублажаємо Тебе, Богородице Діво...» (один раз). Після 6-ої пісні – кондак та ікос Успіння, глас 2-ий. На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспіви свята; 1-ий: «Ангели, Успіння Пречистої бачачи, здивувалися, як Діва возноситься від землі на небо» (за традицією, 1-ий приспів співає священик або диякон, звершується звичайне кадіння). Після 9-ої пісні – «Достойно є» не сівається. Світильний Успіння. «Слава» – той самий світильний, «І нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Успіння, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині...» – Успіння, глас 6-ий: «На безсмертне Твоє успіння...». Велике славослів’я. Після Трисвятого – тропар Успіння, глас 1-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Успіння."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони святкові (див. у додатку). (Або антифони зображальні. Тоді блаженні Успіння: 1-го канону, пісня 3-тя (з ірмосом) – 4, і 2-го канону пісня 6-та – 4). На вході – «Прийдіть поклонімось... молитвами Богородиці...» (до віддання, крім неділі). Після входу – тропар Успіння. «Слава, і нині» – кондак Успіння. Прокимен, алилуарій і причасний – Успіння. Апостол і Євангеліє – Успіння (рядові читання переносяться на п’ятницю). Задостойник свята – приспів: «Ангели, Успіння...» та ірмос: «Перемагаються закони природи...» (і до віддання). З 16 по 22 серпня – післясвято Успіння Пресвятої Богородиці. 23 серпня – відання свята Успіння Пресвятої Богородиці."}]},
{"date":"08-16","weekday":"неділя","title":"11-та неділя після П’ятдесятниці. Глас 2-й. Післясвято Успіння. Перенесення з Едеси до Константинополя Нерукотворного образу (убруса) Господа Ісуса Христа (944). Мч. Діомида, лікаря (298). Мчч. 33-ох палестинських. Прп. Херимона Єгипетського (ІV). Мч. кн. Костянтина (1714, Рум.). Прп. Йосифа Ісихаста (1959). Ікони Божої Матері, названої «Додання розуму» (перехідне святкування в першу неділю після 15 серпня).","glas":2,"readings":["Ран. – Єв. 11-е, Ін., 67 зач., XXI, 15 – 25.","Літ. – 1 Кор., 141 зач., IX, 2 – 12. Мф., 77 зач., XVIII, 23 – 35.","Образу: Кол., 250 зач., I, 12 – 18. Лк., 48 зач. (від половини), IX, 51 – 56; X, 22 – 24."],"notes":"Служба Образа Господнього (Убруса) славослівна, звершується разом із недільною службою та службою післясвята Успіння. Служба святого мученика Діомида переноситься на Мале повечір’я.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 2-ий – 3, свята, глас 2-ий – 3 (див. Мінея Серпень, частина друга, 16 серпня, на «Господи, взиваю»), і Образу, глас 2-ий – 4 (перша стихира – двічі). «Слава» – свята, глас 4-ий: «Прийдіть, люди...», «І нині» – догматик, глас 2-ий: «Минула тінь закону...». Вхід. Прокимен дня. На літії стихири свята, глас 4-ий (див. у Мінеї 16 серпня, на стиховні вечірні, без приспівів). «Слава» – Образу, глас той самий (славник на хвалитніх на ранній), «І нині» – свята, глас 5-ий (див. на літії у день свята). На стиховні стихири воскресні, глас 2-ий. «Слава» – Образу, глас 6-ий: «Господи, втілився Ти..», «І нині» – свята, глас 8-ий: «Маючи віру...» Після Трисвятого – тропар свята, глас 1-ий (двічі) і тропар Образу, глас 2-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 2-ий (двічі). «Слава» – тропар Образу, глас той самий, «І нині» – тропар свята, глас 1-ий. Кафизми 2-а і 3-я. Малі єктенії. Сідальні воскресні. Непорочні. «Ангельський собор...» Іпакої, степені і прокимен – гласу. Євангеліє воскресне 11-те. «Воскресіння Христове бачивши...». Після 50-го псалма «Слава» – «Молитвами апостолів...», «І нині» – «Молитвами Богородиці...». Стихира воскресна, глас 6-ий «Воскрес Ісус із гробу...». Канони: воскресний з іромосом на 4 (ірмос один раз), свята 1-ий на 4, і Образу на 6. Біблійні пісні «Співаймо Господеві...». Катавасія Успіння: «Прикрашена Божественною славою...». Після 3-ої пісні – кондак та ікос свята, глас 2-ий; сідальний Образу, глас 1-ий. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос Образу, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Свят, Господь наш...». Екзапостиларій воскресний 11-ий. «Слава – світильний образу, «І нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас – 2-ий – 4, і Образу, глас 4-ий – 4 (зі славником і присівами своїми). «Слава» – стихира євангельська 11-та, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар недільний «Воскрес із гробу...». Відпуст: «Христос, що воскрес із мертвих...». НА 1 ЧАСІ – тропар воскресний. «Слава» – тропар Образу. Кондак воскресний. НА 3 ЧАСІ – тропар воскресний. «Слава» – тропар свята. Кондак Образу. НА 6 ЧАСІ – тропар воскресний. «Слава» – тропар Образу. Кондак свята. НА 9 ЧАСІ – тропар воскресний. «Слава» – тропар свята. Кондак воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4, і свята, пісня 1-ша – 4, і Образу, пісня 6-та – 4. На вході: «...що воскрес із мертвих...». Після входу – тропар воскресний, тропар Образу, тропар свята; кондак воскресний. «Слава» – кондак Образу, «І нині» – кондак свята. Прокимен, причасний і алилуарій – воскресний і Образу. Апостол і Євангеліє – дня і Образу. Задостойник свята. Відпуст: «Христос, що воскрес із мертвих...»."}]},
{"date":"08-17","weekday":"понеділок","title":"12-й тиждень після П’ятдесятниці. Сщмч. Мирона, пресвітера (250). Прп. Аліпія, іконописця Києво- Печерського, в Ближніх печерах (бл. 1114). Мч. Павла, мц. Юліанії та ін. (бл. 273). Мчч. Фірса, Левкія, Короната і воїнів їхніх (249 – 251). Мч. Патрокла (270 – 275). Мчч. Стратона, Филипа, Євтихіана і Кипріана (бл. 303).","readings":["2 Кор., 179 зач., V, 10 – 15. Мк., 2 зач., I, 9 – 15."],"notes":"У деяких храмах заради особливого вшанування свята Успіння Пресятої Богородиці в один із найближчих днів періоду післясвята (зазвичай напередодні третього дня свята ввечері або ж в день свята увечері) здійснюється служба Погребіння Божої Матері (А). У тих храмах, де ця служба не відбувається, співається служба сщмч. Мирона, пресвітера, без святкового знаку зі службою післясвята Успіння (Б). А. Служба Погребіння Божої Матері являє собою всенічне бдіння, яке складається з Великої Вечірні з входом і літією, Утрені зі співом непорочних і похвал Пресвятої Богородиці і 1-го Часу. До початку служби Плащаниця із зображенням Успіння Божої Матері з належним благоговінням покладається на престол (це буває тільки у разі, якщо винесення Плащаниці не було в сам день Успіння). Перед престолом ставиться виносний свічник зі свічкою. Здійснюється кадіння навкруги престолу та Плащаниці.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"На ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: свята Успіння, глас 1-ий – 3 («О, дивне чудо...», «Дивні Твої тайни, Богородице...», «Твоє Успіння...»), і Єрусалимського чинопослідування – 5: глас 6-ий: «Сьогоднішній день...»; глас 2-ий: «Будучи життям...», «Коли Ти, Маріам...», «Коли три святителі..», і глас 5-ий: «Тебе, Матір Сина Божого...». «Слава, і нині» – Успіння, глас 1-ий: «Богоначальним повелінням...». Вхід. Прокимен, глас 2-ий: «Воскресни, Господи, у спокій Твій...»; стих: «Кляться Господь Давиду істиною...». Паремії Богородиці – 3. На літії стихири Успіння, глас 1-ий, глас 2-ий і глас 3-ій. «Слава» – свята, глас 5-ий: «Прийдіть, вірних собори...», «І нині» – свята, глас той самий: «Оспівуйте, люди Матір Бога нашого...». На стиховні стихири Успіння, глас 4-ий (зі своїми приспівами). «Слава, і нині» – Успіння, глас той самий: «Коли відійшла Ти Богородице...». На благословенні хлібів – тропар Успіння, глас 1-ий (тричі)."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропарі Єрусалимського чинопослідування, глас 2-ий: «Благовидних учеників...» (двічі). «Слава» – «Коли зійшла Ти до смерті...», «І нині» – «Святим ученикам...». При співі «Бог Господь» і тропарів відкриваються царські врата, Плащаниця виноситься з вівтаря до приготованої гробниці на середину храму. Предстоятель – у повному облаченні (за іншою практикою, предстоятель облачається в повне облачення на хвалитніх, перед виходом до гробниці і Хресною ходою), роздає свічки священикам і звершує повне кадіння раму, починаючи з Плащаниці. (Євангеліє на Плащаницю Божої Матері не покладається). Якщо винесення Плащаниці було здійснено в день свята Успіння, то під час співу тропарів священнослужителі виходять з вівтаря на середину храму до Плащаниці. Потім «Непорочні» з похвалами на священне Успіння Богоматері – на три статті. Як правило, похвали читаються священиком, а вірші псалма співаються хором чи теж читаються; втім, є й інша практика виконання непорочних, де і вірші псалма, і похвали співаються. Диякон безперервно кадить перед Плащаницею. Дві останні похвали кожної статті співаються на «Слава» і на «І нині», після чого знову співається перша похвала цієї статті. Після 1-ої статті – мала ектенія, виголос: «Бо благословилося ім’я Твоє і прославилося Царство Твоє...». Після 2-ої статті – мала ектенія, виголос: «Бо освятилося і прославилося всечесне і величне ім’я Твоє...». Після малих ектеній наприкінці 1-ої та 2-ої статей священик звершує мале кадіння. Після 3-ої статті – тропарі Благословенні, глас 5-ий, з особливим приспівом: «Благословенна Владичице, просвіти мене світлом Сина Твого», – «Ангельський собор здивувався...». На Благословенних звершується кадіння всього храму. (Непорочні скасовують спів полієлею, величання також не співається). Потім мала ектенія, виголос: «Бо Тебе хвалять усі сили Небесні...». Степенна – 1-ий антифон 4-го гласу. Прокимен Успіння, глас 4-ий: «Пом’яну ім’я Твоє у всякому роді і роді»; стих: «Слухай, дочко, і споглянь, і прихили вухо Твоє». Євангеліє Богородиці – Лк., Зач. 4. Після 50-го псалма: «Слава» – «Молитвами Богородиці...». Стихира Успіння, глас 6-ий: «Коли наблизилося преставлення пречистого тіла Твого...». Молитва: «Спаси, Боже, людей Твоїх...», «Господи, помилуй» (12 разів). Виголос: «Милістю, милосердям...». Канони: Успіння 1-ий (глас 1-ий) з ірмосом на 8 (ірмоси по двічі) і 2-ий (глас 4-ий) з ірмосом на 8 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси обох канонів свята Успіння. Після 3-ої пісні – іпакої Успіння, глас 8-ий: «Ублажаємо Тебе, Богородице Діво...» (один раз). Після 6-ої пісні – кондак та ікос Успіння, глас 2-ий. На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспіви свята; 1-ий: «Ангели, Успіння Пречистої бачачи, здивувалися, як Діва возноситься від землі на небо» (за традицією, 1-ий приспів співає священик або диякон, звершується звичайне кадіння). Після 9-ої пісні – «Достойно є» не сівається. Світильний Успіння. «Слава» – той самий світильний, «І нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Успіння, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині...» – Успіння, глас 6-ий: «На безсмертне Твоє успіння...». Наприкінці співу стихир на хвалитніх духовенство царськими вратами виходить із вівтаря до Плащаниці. Перед Плащаницею виголошується «Слава Тобі, що показав нам світло». Співається велике славослів’я. Під час співу славослів’я відбувається триразове кадіння Плащаниці, а при співі погребального «Святий Боже...» священнослужителі, поклавши перед Плащаницею три поклони, піднімають її і з хресним ходом (який відбувається звичайним порядком) при тривалому передзвоні обносять навколо храму. Після завершення хресного ходу – тридзвін. Після внесення Плащаниці до храму її покладають на гробницю. (Плащаницю не підносять до царських врат, як у Велику Суботу; «Премудрість, станьмо побожно» не виголошується). Під час покладання Плащаниці на гробницю хор співає тропар свята Успіння, і звершується кадіння тричі навколо гробниці, відбувається помазання єлеєм при цілуванні Плащаниці. Єктенії та відпуст. Примітка. Існує практика, згідно з якою Плащаниця після хресного ходу вноситься до вівтаря (при співі тропаря свята Успіння), покладається на престолі, після чого відбувається кадіння престолу та Плащаниці. Потім вимовляються звичайні ектенії та відпуст утрені. (Помазання єлеєм в такому разі не відбувається). Після закриття царських врат та завіси Плащаниця благоговійно покладається на місці її зберігання."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Успіння. На 1-му Часі замість «Непереможній Воєводі...» прийнято співати кондак Успіння, глас 2-ий: ВУ молитвах невсипущу Богородицю...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, 1-го канону, пісня 3-тя – 4 (з ірмосом), і Образу, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята. «Слава» – кондак храму, «І нині» – кондак свята. У храмі Богородиці – тропар свята. «Слава, і нині» – кондак свята. У храмі святого – тропар свята, тропар храму. «Слава» – кондак храмуу, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. Після відпусту Літургії духовенство виходить до Плащаниці з вівтаря царськими вратами. Тричі покадивши Плащаницю, під час співу тропаря: «У Різдві...», «Слава, і нині» – кондака: «В молитвах невсипущу...», вносять її у вівтар, покладають на престолі, і відбувається кадіння престолу та Плащаниці. Царські врата і завіса зачиняються, і Плащаниця благоговійно покладається на місці її зберігання (Це відбувається, якщо Плащаниця не була занесена в кінці служби Погребіння Божої Матері). У деяких храмах Плащаниця Божої Матері перебуває на храмі аж до дня віддання свята і заноситься за цим чином після Літургії в день віддання свята Успіння Пресвятої Богородиці. Б. НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3, і мученика, глас 2-ий – 3. «Слава, і нині» – свята, глас той самий: «Ти, будучи вищою...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас той самий: «Всенепорочна Невіста...». Після Трисвятого – тропар свята, глас 1-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 4-та і 5-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 2-ий з ірмосом на 8 (ірмоси по двічі) і мученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої, 9-ої – ірмоси канону Мінеї (мученика). Після 3-ої пісні кондак мученика, глас 4-ий. Сідальний мученика, глас 1-ий. «Слава, і нині» – свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 2-ий. На 9-ій пісні – співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співаємо. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліте Господа з небес...» і хвалитні псалми. Читається повсякденне славослів’я. Стихири на стиховні свята глас 6-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 3-ій: «Прийдіть, усі краї...». Після Трисвятого – тропар свята, глас 1-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята.."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, першого і другого канонів, пісня 3-тя – 6 (1-го канону з ірмосом). Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята; кондак храму. «Слава» – кондак мученика, «І нині» – кондак свята. У храмі Богородиці – тропар свята. «Слава» – кондак мученика, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму; кондак храму. «Слава» – кондак мученика, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. За достойник свята."}]},
{"date":"08-18","weekday":"вівторок","title":"Мчч. Флора і Лавра (ІІ). Мчч. Єрма, Серапіона і Полієна (ІІ). Сщмчч. Еміліана, єпископа, і з ним Іларіона, ієром., мчч. Діонісія і Єрмипа (бл. 300). Свтт. Іоана (674) та Георгія (683), патріархів Константинопольських. Прп. Макарія, ігумена Пелікитського (бл. 830). Прп. Іоана Рильського (946, Болг.). Ікони Божої Матері, названої «Всецариця» (XVII).","readings":["2 Кор., 180 зач., V, 15 – 21. Мк., 3 зач., I, 16 – 22.","Мчч.: Еф., 233 зач., VI, 10 – 17. Лк., 63 зач., XII, 2 – 12."],"notes":"Служба мчч. Флора і Лавра не має святкового знаку, звершується разом зі службою післясвята Успіння.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-та. На «Господи, взиваю» стихири на 6: свята, глас 2-ий – 3, і мучеників, глас 4-ий – 3. «Слава» – мучеників, глас 2-ий: «Святі ревнителі...», «І нині» – свята, глас 4-ий: «Прийдіть, люди...» . Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас той самий: «Давидову пісню...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар мучеників, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 7-ма і 8-ма. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмосом на 8 (ірмоси по двічі) і мучеників на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої та 9-ої пісень – ірмоси канону Мінеї (мучеників). Після 3-ої пісні – кондак мучеників, глас 8-ий; сідальний мучеників, глас той самий. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 4-й: «Всечесне Твоє успіння...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар мучеників. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, 1-го і 2-го канонів, пісня 4-та – 6 (1-го канону з ірмосом). Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята, тропар мучеників; кондак храму. «Слава» – кондак мучеників, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар мучеників. «Слава» – кондак мучеників, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар мучеників; кондак храму. «Слава» – кондак мучеників, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і мучеників. Апостол і Євангеліє – дня і мучеників. Задостойник свята."}]},
{"date":"08-19","weekday":"середа","title":"Мч. Андрія Стратилата і з ним 2593 мучеників (284 – 305). Мчч. Тимофія, Агапія і мц. Фекли (бл. 304).","readings":["2 Кор., 182 зач., VI, 11 – 16. Мк., 4 зач., I, 23 – 28.","Мч.: Еф., 233 зач., VI, 10 – 17. Лк., 106 зач., XXI, 12 – 19."],"notes":"Служба мч. Андрія Стратилата не має святкового знаку, звершується разом зі службою післясвята Успіння.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3, і мученика, глас 1-ий – 3. «Слава, і нині» – свята, глас 4-ий: «Коли відійшла Ти, Богородице Діво...» . Входу немає. Прокимен дня. На стиховні стихири свята, глас 1-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 5-ий: «Прийдіть собор любителів свята...». Після Трисвятого – тропар мученика, глас 5-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар мученика, глас 5-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 10-та і 11-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 2-ий з ірмосом на 8 (ірмоси по двічі) і мученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої та 9-ої пісень – ірмоси канону Мінеї (мученика). Після 3-ої пісні – кондак мученика, глас 2-ий; сідальний мученика, глас 1-ий. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – той самий світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 5-й: «Оспівуйте люди...». Після Трисвятого – тропар мученика, глас 5-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар мученика. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, 1-го і 2-го канонів, пісня 5-та – 6 (1-го канону з ірмосом). Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята, тропар мученика; кондак храму. «Слава» – кондак мученика, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар мученика. «Слава» – кондак мученика, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар мученика; кондак храму. «Слава» – кондак мученика, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і мученика. Апостол і Євангеліє – дня і мученика. Задостойник свята."}]},
{"date":"08-20","weekday":"четвер","title":"Прор. Самуїла (ХІ ст. до Р. Х.). Сщмч. Севира, пресвітера і мч. Мемнона та з ними 37 мучеників (304).","readings":["2 Кор., 183 зач., VII, 1 – 10. Мк., 5 зач., I, 29 – 35."],"notes":"Служба прор. Самуїла не має святкового знаку, звершується разом зі службою післясвята Успіння.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. На «Господи, взиваю» стихири на 6: свята, глас 6-ий – 3, і пророка, глас 4-ий – 3. «Слава, і нині» – свята, глас 6-ий: «На безсмертне Твоє успіння...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 6-ий (зі своїми прспівами). «Слава, і нині» – свята, глас той самий: «Коли готувалося предсталення пречистого Твого тіла...». Після Трисвятого – тропар пророка, глас 2-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар пророка, глас 2-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 13-та і 14-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмосом на 8 (ірмоси по двічі) і пророка на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (пророка). Після 3-ої пісні – кондак пророка, глас 8-ий; сідальний пророка, глас 3-ій. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний пророка. «Слава, і нині» – світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас той самий: «Всі земнородні...». Після Трисвятого – тропар пророка, глас 2-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар пророка. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, 1-го і 2-го канонів, пісня 6-та – 6 (1-го канону з ірмосом). Після входу – тропарі та кондаки: У храмі Господському – тропар храму, тропар свята, тропар пророка; кондак храму. «Слава» – кондак пророка, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар пророка. «Слава» – кондак пророка, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар пророка; кондак храму. «Слава» – кондак пророка, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята."}]},
{"date":"08-21","weekday":"п’ятниця","title":"Ап. від 70-х Фадея (бл. 44). Мц. Васси та її дітей: мчч. Феогнія, Агапія і Піста (305 – 311). Прп. Авраамія Працелюбного, Печерського, в Ближніх печерах (ХІІ – ХІІІ).","readings":["2 Кор., 184 зач., VII, 10 – 16. Мк., 9 зач., II, 18 – 22."],"notes":"Служба ап. Фадея і мц. Васси не має святкового знаку, звершується разом зі службою післясвята Успіння.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-та. На «Господи, взиваю» стихири на 6: апостола, глас 8-ий – 3, і мучениці, глас 4-ий – 3. «Слава, і нині» – свята, глас 6-ий: «Прийдіть, вірні...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Дівственні лики...». Після Трисвятого – тропар апостола, глас 3-ій. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар апостола, глас 3-ій, «І нині» – тропар свята, глас 1-ий. Кафизми 19-та і 20-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 2-ий з ірмосом на 6 (ірмоси по двічі), апостола на 4 і мучениці на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (мучениці). Після 3-ої пісні – кондак апостола, глас 4-ий; сідальний апостола, глас 8-ий. «Слава» – сідальний мучениці, глас 1-ий, «І нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний апостола. «Слава, і нині» – світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас той самий: «Всі небесні лики...». Після Трисвятого – тропар апостола, глас 3-ій. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар апостола. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, 1-го і 2-го канонів, пісня 7-ма – 6 (1-го канону з ірмосом). Після входу – тропарі та кондаки: У храмі Господньому – тропар храму, тропар свята, тропар апостола; кондак храму. «Слава» – кондак апостола, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар апостола. «Слава» – кондак апостола, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар апостола; кондак храму. «Слава» – кондак апостола, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята."}]},
{"date":"08-22","weekday":"субота","title":"Мчч. Агафоника, Зотика, Феопрепія (Боголіпа), Акиндина, Северіана та інших (305 – 311). Сщмч. Афанасія, єп. Тарсійського (270 – 275), прп. Анфуси (бл. 298) та її слуг: мчч. Харисима і Неофіта (270 – 275). Мц. Євлалії, діви (бл. 303). Сщмч. Горазда, єп. Богемського і Мораво-Силезького (1942, Чех.). Грузинської ікони Божої Матері (1650).","readings":["1 Кор., 125 зач. (від половини), I, 26 – 29. Мф., 82 зач., XX, 29 – 34."],"notes":"На цей день переноситься з 23 серпня служба мч. Луппа (Типікон, 22 серпня). Служби мч. Агафоника і мч. Луппа (з 23 серпня) не мають святкового знаку, звершуються разом із службою післясвята Успіння.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: мч. Агафоника, глас 4-ий – 3, і муч. Луппа, глас той самий – 3. «Слава» – мч. Агафоника, глас 1-ий: «Тезоіменно був названий...», «І нині» – догматик, глас 2-ий: «Минула тінь закону...». Входу. Прокимен дня. На стиховні стихири свята, глас 8-ий (зі своїми приспівами). «Слава» – мч. Агафоника, глас 8-ий: «Тезоіменне найменування...», «І нині» – свята, глас той самий: «Віру стверджує Ісус...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар мучеників, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 16-та і 17-та (на 17-тій кафізмі ієрей звершує кадіння храму, як на «Господи, взиваю», царські врата залишаються закритими). Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмосом на 6 (ірмоси по двічі) мч. Агафоника на 4 і мч. Луппа на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (мч. Луппа). Після 3-ої пісні – кондак та ікос мч. Агафоника, глас 1-ий; сідальний мч. Агафоника, глас 8-ий. «Слава» – сідальний мч. Луппа, глас 1-ий: «Стражданнями просвітившись...», «І нині» – сідальний свята, глас той самий: «Лик божественних апостолів...». Після 6-ої пісні – кондак та ікос свята, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний мч. Агафоника: «Як тезоіменитий блага...». «Слава, і нині» – світильний свята: «Апостоли, зберіться поховати...». «Хваліте Господа з небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас той же: «Всі земнородні...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – Тропар свята. «Слава» – тропар мучеників. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, 1-го і 2-го канонів, пісня 8-ма – 6 (першого канону із ірмосом). Після входу – тропарі та кондаки: У храмі Господньому – тропар храму, тропар свята, тропар мучеників; кондак храму. «Слава» – кондак мч. Агафоника, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар мучеників. «Слава» – кондак мч. Агафоника, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар мучеників; кондак храму. «Слава» – кондак мч. Агафоника, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята."}]},
{"date":"08-23","weekday":"неділя","title":"12-та неділя після П’ятдесятниці. Глас 3-й. Віддання свята Успіння Пресвятої Богородиці. Сщмч. Іринея, єп. Ліонського (202). Мч. Луппа Салонікійського (ІV). Прпп. Євтихія, ігумена (бл. 540) та Флорентія (547). Свт. Калиника, патр. Константинопольського (705).","glas":3,"readings":["Ран. – Єв. 1-е, Мф., 116 зач., XXVIII, 16 – 20.","Літ. – 1 Кор., 158 зач., XV, 1 – 11. Мф., 79 зач., XIX, 16 – 26."],"notes":"Недільна служба Октоїха звершується у поєднанні із славослівною службою віддання свята Успіння. Служби рядових святих переносяться на інший день (див. 22 серпня).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 3-ій – 4, свята, глас 1-ий – 6 (кожна стихира – двічі). «Слава» – свята, глас той самий: «Богоначальним повелінням ...», «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Вхід. Прокимен дня. Паремій немає. На літії стихири свята, глас 1-ий, глас 2-ий і глас 3-ій (див. на літії). «Слава» – свята, глас 5-ий: «Прийдіть, вірних собори...», «І нині» – свята, глас той самий: «Оспівуйте, люди Матір Бога нашого...». На стиховні стихири воскресні, глас 3-ій. «Слава і нині» – свята, глас 4-ий: «Коли відійшла Ти Богородице...». Після Трисвятого – «Богородице Діво» (двічі) і тропар свята, глас 1-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 3-ій (двічі). «Слава, і нині» – тропар свята, глас 1-ий. Кафизми 2-а і 3-я. Малі єктенії. Сідальні воскресні. Непорочні. «Ангельський собор...» Іпакої, степені і прокимен – гласу. Євангеліє воскресне 1-ше. «Воскресіння Христове бачивши...». Після 50-го псалма «Слава» – «Молитвами апостолів...», «І нині» – «Молитвами Богородиці...». Стихира воскресна, глас 6-ий «Воскрес Ісус із гробу...». Канони: воскресний з іромосом на 4 (ірмоси один раз), Богородиці (Октоїха) на 2 і свята (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія Успіння: «Прикрашена Божественною славою...». Після 3-ої пісні – кондак та ікос свята, глас 2-ий; іпакої Успіння, глас 8-ий: «Ублажаємо Тебе, Богородице Діво...» (один раз). Після 6-ої пісні – кондак та ікос воскресні, глас 3-ій. На 9-ій пісні співаємо «Чеснішу» (приспіви свята не співаються). Після 9-ої пісні «Свят, Господь наш...». Екзапостиларій воскресний 1-шй. «Слава, і нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас – 3-ій – 4, і свята, глас 4-ий і глас 6-ий – 4 (зі славником і присівами своїми, приспіви в Мінеї на стиховні вечірні). «Слава» – стихира євангельська 1-ша, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар недільний «У день спасіння...». Відпуст: «Христос, що воскрес із мертвих...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар свята. Кондаки свята і воскресний читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні гласу – 6, і свята 1-го і 2-го канонів, пісня 9-та – 4. На вході: «...що воскрес із мертвих...». Після входу – тропар воскресний, тропар свята. «Слава» – кондак воскресний, «І нині» – кондак свята. Прокимен, причасний і алилуарій – воскресний і свята. Апостол і Євангеліє – дня і свята. Задостойник свята. Відпуст: «Христос, що воскрес із мертвих...»."}]},
{"date":"08-24","weekday":"понеділок","title":"13-й тиждень після П’ятдесятниці. Сщмч. Євтихія, єпископа, учня ап. Іоана Богослова (І). Мч. Татіона (305). Мц. Сіри, діви Перської (558). Прп. Георгія Лимніота (бл. 716). Рівноап. прмч. Косми Етолійського, ієром. (1779).","readings":["2 Кор., 186 зач., VIII, 7 – 15. Мк., 11 зач., III, 6 – 12."],"notes":"Служба сщмч. Євтихія без святкового знаку, звршується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: Октоїха, глас 3-ій – 3, і священномученика, глас 8-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той самий: «Спаси мене...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-1й. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Владичице, заступнице всіх...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тій, що вихована...». Кафизми 4-та і 5-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4 і священномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний священномученика, глас 3-ій. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак і ікос священномученика, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний священномученика, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Будучи першою святою...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти вища...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар священномученика; кондак дня, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар священномученика; кондак дня, кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"08-25","weekday":"вівторок","title":"Перенесення мощів ап. Варфоломія (VІ). Ап. від 70-х Тита, єп. Критського (І). Свтт. Варсиса і Євлогія, єпископів Едеських, і Протогена, єп. Карійського, сповідника (ІV). Свт. Мини, патр. Константинопольського (536 – 552).","readings":["2 Кор., 187 зач., VIII, 16 – IX, 5. Мк., 12 зач., III, 13 – 19.","Апп.: Тит., 300 зач., I, 1 – 4; II, 15 – III, 3, 12 – 13, 15. Мф., 11 зач., V, 14 – 19."],"sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-та. На «Господи, взиваю» стихири на 6: ап. Варфоломія, глас 4-ий – 3, і ап. Тита, глас той самий – 3. «Слава» – ап. Варфоломія, глас 2-ий: «Залишивши земне...», «І нині» – Богородичний за гласом «Слави», від менших: «Непрохідні ворота...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Свята серед жон...». Після Трисвятого – тропар апостолів, глас 3-ій. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Пристановище і сила...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостолів, глас 3-ій (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Пристановище і сила ...». Кафизми 7-ма і 8-ма. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), ап. Варфоломія на 4 і ап. Тита на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (ап.. Тита). Після 3-ої пісні – кондак ап. Тита, глас 2-ий, сідальний ап. Варфоломія, глас 3-ій. «Слава» – сідальний ап. Тита, глас 8-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак і ікос ап. Варфоломія, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний апостолів, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Без сімені зачала...». Після Трисвятого – тропар апостолів, глас 3-ій. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Кожен, де бачить...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар апостолів. Кондаки апостолів читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар апостолів; кондак дня, кондак ап. Варфоломія, кондак ап. Тита. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар апостолів; кондак дня, кондак храму, кондак ап. Варфоломія, кондак ап. Тита. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і апостолів. Апостол і Євангеліє – дня і апостолів."}]},
{"date":"08-26","weekday":"середа","title":"Мчч. Адріана і Наталії (305 – 311).","readings":["2 Кор., 189 зач., IX, 12 – X, 7. Мк., 13 зач., III, 20 – 27."],"notes":"Служба свв. мчч. Адріана і Наталії не має святкового знаку, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафізма 9-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 3-ій – 3, і мучеників, глас 4-ий – 3. «Слава» – мучеників, глас 6-ий: «О чоловіче святий...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Зброя, як сказав Симеон...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава» – мучеників, глас 1-ий: «Ревність благочестивого чоловіка...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Стоячи перед Хрестом...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава» – інший тропар мч. Адріану, глас 3-ий, «І нині» – Богородичний за гласом тропаря, від менших: «Як жезл сили...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучеників, глас 4-ий (двічі). «Слава» – тропар мч. Адріану, глас 3-ій. «І нині» – Богородичний за гласом тропаря, від менших: «Як жезл сили...». Кафизми 10-та і 11-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4 і мучеників на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї мучеників. Після 3-ої пісні – кондак мученика Адріана, глас 4-ий, сідальний мучеників, глас той самий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак і ікос мучеників, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний мучеників, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава, і нині» – Хрестобогородичний Октоїха, глас той самий: «Дивлячись на Тебе...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава» – інший тропар мч. Адріану, глас 3-ий. «І нині» – Богородичний за гласом тропаря, від менших: «Пристановище і сила...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар мучеників. «Слава» – тропар мч. Адріана. Кондак мучеників і мч. Адріана читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси, Господи...», тропар мучеників, тропар мч. Адріана; кондак мучеників, кондак мч. Адрана. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар мучеників, тропар мч. Адріана; кондак дня: «Вознісся на Хрест...», кондак мучеників, кондак мч. Адріана. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар мучеників, тропар мч. Адріана; кондак дня: «Вознісся на Хрест...», кондак храму, кондак мучеників, кондак мч. Адріана. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"08-27","weekday":"четвер","title":"Прп. Пимена Великого (бл. 450). Прпп. сщмч. Кукші й учня його мч. Никона, Пимена, посника, Києво-Печерських, в Ближніх печерах (після 1114). Свт. Осії, спов., єп. Кордовського (359). Свт. Ліверія, спов., єпископа Римського (366). Прп. Пимена Палестинського (бл. 602). Мц. Анфіси Нової. Прп. Сави Венефальського.","readings":["2 Кор., 190 зач., X, 7 – 18. Мк., 14 зач., III, 28 – 35.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Мф., 10 зач., IV, 25 – V, 12."],"notes":"Служба прп. Пимена Великого не має святкового знаку, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. На «Господи, взиваю» стихири Октоїха, глас 3-ій – 3, і преподобного, глас 8-ий – 3. «Слава» – преподобного, глас 6-ий: «Преподобний отче...», «І нині» – Богородичний Мінеї, глас той самий: «Око мого серця...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава» – преподобного, глас 8-ий: «Ченців безліч...», «І нині» – Богородичний Мінеї, глас той самий: «Я, Діво свята...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Духовні врата життя...»."},{"svc":"РАННІЙ","text":"На РАННІЙ на «Бог Господь» – тропар преподобного, глас 8-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Духовні врата життя ...». Кафизми 13-та і 14-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4, і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний преподобного, глас 3-ій. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний преподобного, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Без сімені зачала...». Після Трисвятого – преподобного, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Діво Пречиста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякдені антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, інший тропар дня, тропар преподобного; кондак дня, інший кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, інший тропар дня, тропар храму, тропар преподобного; кондак дня, інший тропар дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"08-28","weekday":"п’ятниця","title":"Прп. Мойсея Мурина (бл. 400). Собор прпп. отців Києво-Печерських, що в Дальніх печерах (прп. Феодосія) спочивають: Феодосія (1074), Мойсея, чудотворця (ХІІІ – ХІV), Лаврентія, затворн. (ХІІІ – ХІV), Іларіона, схимн. (1066), Пафнутія, затворн. (ХІІІ), Мартирія, дияк. (ХІV), Федора, кн. Острозького (бл. 1438), Афанасія, затворн. (ХІІІ), Діонісія, ієром., затворн. (ХV), Феофіла, єп. Новгородського (бл. 1482), Зинона, посн. (ХІV), Григорія, затворн. (ХІV), Іпатія, цілителя (ХІV), сщмч. Лукіана (1243), Йосифа Багатохворобливого (ХІV), Павла Послушного (ХІІІ), Сисоя, схимн. (ХІІІ), Нестора, некнижн. (ХІV), Памви, затворн. (1241), Федора, мовчальн. (ХІІІ), Софронія, затворн. (ХІІІ), Панкратія, ієромон., затворн. (ХІІІ), Анатолія, затворн. (ХІІІ), Аммона, затворн. (ХІІІ), Мардарія, затворн. (ХІІІ), Піора, затворн. (ХІІІ), Мартирія, затворн. (ХІІІ – ХІV), Руфа, затворн. (ХІV), Веніамина, затворн. (ХІV), Касіяна, затворн. (ХІІІ – ХІV), Арсенія Працелюбного (ХІV), Євфимія, схимн. (ХІV), Тита, колишнього воїна (ХІV), Ахили, дияк. (ХІV), Паїсія (ХІV), Меркурія, посн. (ХІV), Макарія, дияк. (ХІV), Пимена, посн. (ХІІ), Леонтія і Геронтія, канонархів (ХІV), Захарії, посн. (ХІІІ – ХІV), Силуана, схимн. (ХІІІ – ХІV), Агафона, чудотв. (ХІІІ – ХІV), Ігнатія, архім. (1435) і Лонгина, воротаря (ХІІІ – ХІV), Акиндина, архім. (1235), Амфілохія, єп. (1122), Даниїла, старця (ХІV), Досифея, архім. (1218), Євлогія, старця (ХІV), Ісидора, затв. (ХІІ – ХІІІ), Тимофія, ігумена (1132), свт. Філарета, митр. Київського (1857). Знайдення мощів прп. Іова Почаївського (1659). Прав. Анни, пророчиці, дочки Фануїлової, що зустріла Господа Ісуса Христа в храмі Єрусалимському (І). Вмц. Шушаніки (Сусанни), цариці Ранської (V, Груз.).","readings":["Ран. – Мф., 10 зач., IV, 25 – V, 12.","Літ. – 2 Кор., 192 зач., XI, 5 – 21. Мк., 15 зач., IV, 1 – 9 (за п’ятницю).","1 Кор., 126 зач., II, 6 – 9. Мф., 90 зач., XXII, 15 – 22 (за суботу, під зачало).","Прпп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Звершується полієлейна служба прп. Іова Почаївського. За тією ж самою схемою може звершуватися полієлейна служба собору прпп. отців Києво-Печерських, що в Дальніх печерах (прп. Феодосія) спочивають.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири преподобного, глас 1-ий і глас 2-ий – 8 (перші дві стихири – двічі). «Слава» – преподобного, глас 3-ій: «Твоїх слів...», «І нині» – догматик, глас той самий: «Як нам не дивуватися...». Вхід. Прокимен дня. Паремії преподобного – 3. На стиховні стихири преподобного, глас 5-ий (зі своїми приспівами). «Слава» – преподобного, глас 8-ий: «Тебе, як численних ченців...», «І нині» – Богородичний Мінеї, глас той самий: «Безневісна Діво...». Після Трисвятого – тропар святого, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святого, глас 4-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 19-та і 20-та. Малі ектенії. Сідальні преподобного (по двічі). Полієлей. Величання преподобного: «Ублажаємо тебе, преподобний отче наш Іове, і шануємо святу пам’ять твою, наставнику монахів і співрозмовнику ангелів» і вибраний псалом. Сідальний преподобного після полієлея, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен преподобного, глас 4-ий: «Чесна перед Господом смерть преподобних Його». Євангеліє преподобного. Після 50-го псалма: «Слава» – «Молитвами преподобного...». Стихира преподобного, глас 6-ий: «Преподобний отче...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і преподобного на 8. Біблійні пісні «Хрест накреслив...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний преподобного, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний преподобного (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири преподобного, глас 4-ий – 4 (перша стихира – двічі). «Слава» – преподобного, глас 8-ий: «Не можуть слова наші...», «І нині» – Богородичний Мінеї за гласом «Слави»: «Владичице прийми молитви...». Велике славослів’я. Після Трисвятого – тропар святого, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні преподобного, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар храму, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"08-29","weekday":"субота","title":"Усікновення голови пророка, Предтечі і Хрестителя Господнього Іоана.","readings":["Ран. – Мф., 57 зач., XIV, 1 – 13.","Літ. – Діян., 33 зач., XIII, 25 – 32. Мк., 24 зач., VI, 14 – 30."],"notes":"Пісний день. Поминання загиблих захисників України. Звершується всенічне бдіння на честь свята Усікновення глави Іоана Предтечі.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири Предтечі, глас 6-ий – 8 (кожна стихира – двічі). «Слава» – Предтечі, глас той самий: «В день народження безсоромного Ірода...», «І нині» – Мінеї, глас той самий: «Хто Тебе не ублажить...» (догматик гласу не співається). Вхід. Прокимен дня. Паремії Предтечі – 3. На літії стихири Предтечі, глас 1-ий і глас 4-ий. «Слава» – Предтечі, глас 5-ий: «Викриття беззаконних діянь Ірод хотів уникнути...», «І нині» – Богородичний Мінеї, глас той самий: «Оспівуйте, люди...». На стиховні стихири Предтечі, глас 2-ий (зі своїми приспівами). «Слава» – Предтечі, глас 8-ий: «Предтече Спасів...», «І нині» – Богородичний воскресний, за гласом «Слави»: «Безневісна Діво...». Після Трисвятого – тропар Предтечі, глас 2-ий (двічі), і «Богородице Діво...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Предтечі, глас 2-ий (двічі). «Слава, і нині» – Богородичний воскресний, за гласом «Слави»: «Все вище розуму...». Кафизми 16-та і 17-та. Малі єктенії. Сідальні Предтечі. Полієлей. Величання Предтечі: «Величаємо тебе, Хрестителю Спасів Іоане, і шануємо всі чесної Твоєї глави усікновення» і вибраний псалом: «Блажен муж, що боїться Господа; в заповідях Його ходить завжди». Сідальний Предтечі після полієлею, глас 8-ий: «Предтеча, Хреститель і ангел...», «І нині» – Богородичний Мінеї, глас той самий: «Слово Отче...». Ступеневі – 1-й антифон 4-го гласу. Прокимен Предтечі, глас 4-ий: «Чесна перед Господом...». Євангеліє Предтечі. Після 50-го псалма: «Слава» – «Молитвами святого славного Пророка...». Стихира Предтечі, глас 6-ий: «Танцюючи, учениця...». Канони: Предтечі 1-ий, глас 8-ий, з ірмосом на 8 (ірмоси по двічі), і 2-ий, глас той самий, на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – сідальний Предтечі, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос Предтечі, глас 5-ий. На 9-ій пісні співаймо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний Предтечі. «Слава» – інший світильний Предтечі, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Предтечі, глас 8-ий – 4 (перша стихира двічі) Слава» – Предтечі, глас 6-ий: «Знову Іродіада лютує...», «І нині» – «Богородице, Ти єси виноградна лоза...». Велике славослів’я. Після Трисвятого – тропар Предтечі, глас 2-ий. «Слава, і нині...» – Богородичний воскресний, глас 2-ий: «Все вище розуму...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Предтечі."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Предтечі, 1 канону пісня 3-тя – 4 (із ірмосом) і 2-го канону пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар Предтечі. «Слава» – кондак Предтечі, «І нині» – кондак храму. У храмі і святого – тропар Предтечі. «Слава» – кондак Предтечі, «І нині» – «Заступництво християн...». Прокимен, алилуарій і причасний – Предтечі. Апостол і Євангеліє – Предтечі. Примітка. Міркування Типікону про трапезу в цей день див. в гл. 48, 29 серпня."}]},
{"date":"08-30","weekday":"неділя","title":"13-та неділя після П’ятдесятниці. Глас 4-й. Свтт. Олександра (340), Іоана Посника (595) і Павла Нового (784), патріархів Константинопольських. Прп. Христофора Римлянина (VІ). Прп. Фантина Солунського, чудотворця (ІХ – Х). Свтт. Сербських: Сави І (1237), Арсенія (1266), Сави ІІ (1271), Євстафія (бл. 1285), Якова (1292), Никодима (1325), Даниїла (1338), архієпископів; Іоаникія (1354), Єфрема (після 1395), Спиридона (1388), Макарія (1574), Гавриїла (1659), патріархів, і Григорія, єпископа. Прп. Олександра Свірського (1533). Свт. Варлаама, митр. Молдовського (1657, Рум.).","glas":4,"readings":["Ран. – Єв. 2-е, Мк., 70 зач., XVI, 1 – 8.","Літ. – 1 Кор., 166 зач., XVI, 13 – 24. Мф., 87 зач., XXI, 33 – 42."],"notes":"Служба свт. Олександра, Іоана і Павла Нового, Патріархів Константинопольських, без святкового знаку, звершується із недільною службою Октоїха і службою віддання свята Усікновення.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 4-ий – 4, Предтечі, глас той самий – 3 і святителів, глас 1-ий – 3. «Слава» – Предтечі, глас 6-ий: «Знову Іродіада біснується...» «І нині» – догматик, глас 4-ий: «Пророк Давид...». Вхід. Прокимен дня. На літії стихира храму і Богородичні стихири Павла Аморрейського, глас 8-ий (На «Господи, взиваю» у воскресній службі 4-го гласу в Октоїху, без стихів). «Слава, і нині» – його ж стихира, глас той же: «Радуйся, Богомати...». На стиховні стихири воскресні, глас 8-ий. «Слава» – Предтечі, глас 4-ий: «Народження негідне...», «І нині» – Богородичний воскресний, глас той самий: «Зглянься на благання...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 4-ий (один раз). Тропар Предтечі, глас той самий. «Слава» – тропар святителів, глас той самий, «І нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні воскресні. Непорочні. «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє воскресне 2-ге. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Богородиці (Октоїха) на 2, Предтечі (з Мінеї, у день свята) на 4 і святителям на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив Мойсей...». Після 3-ої пісні – кондак та ікос Предтечі, глас 4-ий, кондак святителів, глас той самий; сідальний Предтечі, глас 8-ий. «Слава» – сідальний святителів, глас 4-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 2-ий. «Слава» – світильний Предтечі, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 4-ий – 8. «Слава» – стихира євангельська 2-га, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...». НА 1 і 6 ЧАСАХ – тропар воскресний. «Слава» – тропар Предтечі. Кондак воскресний. НА 3 і 9 ЧАСАХ – тропар воскресний. «Слава» – тропар святителів. Кондак воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 8. Після входу – тропарі та кондаки: У храмі Господньому – тропар воскресний, тропар Предтечі, тропар святителів; кондак Предтечі. «Слава» – кондак святителів, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар Предтечі, тропар святителів; кондак воскресний, кондак Предтечі. «Слава» – кондак святителів, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар Предтечі, тропар святителів; кондак воскресний, кондак храму, кондак Предтечі. «Слава» – кондак святителів, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні. Апостол і Євангеліє – дня."}]},
{"date":"08-31","weekday":"понеділок","title":"14-й тиждень після П’ятдесятниці. Покладення чесного пояса Пресвятої Богородиці (395 – 408). Сщмч. Кипріана, єп. Карфагенського (258). Свт. Геннадія, патр. Константинопольського (471). Свт. Іоана ІІ, митр. Київського і всієї Руси († 1089). Пам’ять відновлення православної ієрархії Київської Митрополії (1620).","readings":["2 Кор., 195 зач., XII, 10 – 19. Мк., 16 зач., IV, 10 – 23.","Богородиці: Флп., 240 зач., II, 5 – 11. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершується славослівна служба Покладення чесного пояса Пресвятої Богородиці.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири Богородиці, глас 4-ий – 6 (кожна стихира – двічі). «Слава» – Богородиці, глас 2-ий: «Як вінцем пресвітлим...», «І нині» – догматик, глас 8-ий: «Цар Небесний...». Входу немає. Прокимен дня. На стиховні стихири Богородиці, глас 4-ий (зі своїми приспівами). «Слава, і нині» – Богородиці, глас 2-ий: «Думки очистивши і розум...». Після Трисвятого – тропар Богородиці, глас 8-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Богородиці, глас 8-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 4-та 5-та. Малі єктенії. Сідальні Богородиці (по двічі). Псалом 50-ий. Канони: Богородиці (Мінеї) 1-ий з ірмосом на 8 (ірмоси по двічі) і 2-ий на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – інший кондак Богородиці, глас 2-ий; сідальний Богородиці, глас 4-ий. «Слава, і нині» – інший сідальний Богородиці, глас той самий. Після 6-ої пісні – кондак та ікос Богородиці, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний Богородиці. «Слава, і нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Богородиці, глас 4-ий – 4 (перша стихира – двічі). «Слава, і нині» – Богородиці, глас 2-ий: «Думки очистивши і розум...». (див. На стиховні на вечірні). Велике славослів’я. Після Трисвятого – тропар Богородиці, глас 8-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар Богородиці. Кондаки Богородиці читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Богородиці, пісня 3-я – 4 (1-го канону з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар храму, тропар Богородиці (пояса); кондак храму. «Слава» – кондак Богородиці (пояса), «І нині» – інший кондак Богородиці (поясу). У храмі Богородиці – тропар Богородиці (пояса). «Слава» – кондак Богородиці (пояса), «І нині» – інший кондак Богородиці (пояса). У храмі святого – тропар Богородиці (пояса), тропар храму; кондак Богородиці (пояса). «Слава» – кондак храму, «І нині» – інший кондак Богородиці (пояса). Прокимен, алилуарій і причасний – Богородиці (пояса). Апостол і Євангеліє – дня і Богородиці (пояса)."}]},
{"date":"09-01","weekday":"вівторок","title":"Початок індикту – церковне новоліття. Прп. Симеона Стовпника (459) і матері його Марфи (бл. 428). Собор Вінницьких святих. Сщмч. Аїфала Перського, диякона (380). Мцц. 40 дів, посниць, і сщмч. Амуна, диякона, їхнього вчителя (ІV). Мц. Калісти та братів її, мчч. Євода та Єрмогена (309). Прав. Ісуса Навина (ХVІ ст. до Р. Х.). Собор Пресвятої Богородиці в Міасинській обителі (в пам’ять знайдення Її ікони, 864).","readings":["2 Кор., 196 зач., XII, 20 – XIII, 2. Мк., 17 зач., IV, 24 – 34. (Під зачало)","Новоліттю: 1 Тим., 282 зач., II, 1 – 7. Лк., 13 зач., IV, 16 – 22.","Прп.: Кол., 258 зач., ІІІ, 12 – 16. Мф. 43, ХI, 27 – 30."],"notes":"Звершуємо славослівну службу за Мінеєю. Примітка. Служба святих мучениць «співається коли еклесіарх розсудить» (дивитися типікон, 1 вересня, маркова глава). Примітка. За Типіконом, служба на «Початок індикту, тобто нового року» має знак полієлея, але на ранній полієлей не служиться. На великій вечірні співається «Блажен муж» (1-ий антифон), читаються паремії, а рання звершується з великим славослів’ям.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 10: індикту, глас 1-ий – 3, преподобного, глас 5-ий – 3, і інші стихири преподобного, глас 2-ий – 4. «Слава» – преподобного, глас 6-ий : «Божественна благодать...», «І нині» – індикту, глас той самий: «Ти, що з’єднаний з Духом Святим...». Вхід. Прокимен дня. Паремії індикту – 2 і преподобного – 1. На стиховні стихири індикту, глас 1-ий і глас 2-ий – 4 (з приспівами своїми). «Слава» – преподобного, глас 5-ий: «Преподобний отче...», «І нині» – індикту, глас той самий: «Ти, Царю, присносущний...». Після Трисвятого – тропар індикту, глас 2-ий. «Слава» – тропар святого, глас 1-ий, «І нині» – тропар Богородиці, глас той самий: «Радуйся, Обрадувана...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар індикту, глас 2-ий (двічі). «Слава» – тропар святого, глас 1-ий, «І нині» – тропар Богородиці, глас той самий: «Радуйся, Обрадувана...». Кафизми 7-ма і 8-ма. Малі єктенії. Після 1-ої кафизми – сідальний індикту, глас 4-ий: «Як до Владики всіх...». «Слава» – сідальний преподобного, глас 8-ий: «Хрест Господній взявши...», «І нині» – сідальний індикту, глас 4-й: «Як до Владики всіх...». Примітка. «З цього дня починається читання Метафраста Логофета Симеона, і Маргарита Золотоустого, і тлумачення Послань святого апостола Павла» (Типікон, 1 вересня, 1-е «див»). Після 2-ої кафизми – сідальний преподобного, глас 8-ий: «Стриманням, і трудами...». «Слава» – сідальний мц. Каллісти, глас 4-ий: «Пішла ти на подвиг...», «І нині» – Богородичний, глас той же: «Поспіши, Владичице...». Псалом 50-ий. Увага! Полієлей співається тільки в храмі прп. Симеона Стовпника. Полієлей і величання преподобного з псалмом вибраним. Мала єктенія і сідальні преподобного після полієлея (як зазначено в Мінеї). Степенна – 1-ий антифон 4-го гласу. Прокимен і Євангеліє – преподобного, стихира після 50-го псалма – храму (преподобного) (дивитися.: Мінея, 1 вересня). Канони: індикту з ірмосом на 6 (Ірмос по двічі), мучениць на 4 і преподобного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – кондак індикту, глас 2-ий; сідальний індикту, глас 8-ий, сідальний преподобного, глас той самий. «Слава» – сідальний святих жон, глас 1-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Примітка. Ієрей же, покадивши святий престіл, виголошує: «Богородицю і Матір Світла в піснях величаємо». І покадивши святий вівтар і всю церкву, і братію, яка завжди на 9-ій пісні ранньої не залишається. Ми ж співаємо 9-ту пісню велегласно, на глас 6-ий. «Величає Душа моя Господа...». Приспівуємо ж: «Чеснішу від Херувимів...». (на 9-ій пісні, якщо є свято Господнє, то завжди, хоч і велике славослів’я, або буде храм святого, співаємо «Чеснішу...»). Після 9-ої пісні – катавасія: «Таємний Ти, Богородице, рай...» та «Споживою древа...». «Достойно є» не співається. Світильний індикту. «Слава» – світильний преподобного, «І нині» – інший світильний індикту. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 4: індикту, глас 3-ій і глас 4-ий – 3, і мучениць, глас 2-ий – 1. «Слава» – преподобного, глас 2-ий: «Від дблагого кореня...», «І нині» – індикту, глас 8-ий: «Невимовною премудрістю Ти створив усе...». Велике славослів’я. Після Трисвятого – тропар індикту, глас 2-ий. «Слава» – тропар преподобного, глас 1-ий, «І нині» – тропар Богородиці, глас той самий: «Радуйся, Обрадувана...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар індикту. «Слава» – тропар преподобного. Кондаки індикту і преподобного читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні індикту, пісня 3-тя – 4 (з ірмосом), і преподобного, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар індикту, тропар Богородиці: «Радуйся, Обрадувана...», тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак індикту. У храмі Богородиці – тропар індикту, тропар Богородиці: «Радуйся, Обрадувана...», тропар святого; кондак індикту. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар індикту, тропар Богородиці: «Радуйся, Обрадувана...», тропар храму, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – кондак індикту. Прокимен, алилуарій – індикту і преподобного. Апостол і Євангеліє – дня (під зачало), індикту і преподобного."}]},
{"date":"09-02","weekday":"середа","title":"Прпп. Антонія (1073) і Феодосія (1074) Києво-Печерських. Мч. Маманта (275), батька його Феодота і матері Руфіни (ІІІ). Прп. Іоана Посника, патр. Константинопольського (595). Мчч. 3628 в Нікомидії (ІІІ – ІV).","readings":["Ран.: Мф., 43 зач., XI, 27 – 30.","Літ. – Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Звершуємо бдінну службу прпп. Антонія і Феодосія Києво-Печерських. Увага! Службу беремо з Мінеї місячної Вересень 1-ша частина та Воскресний Октоїх і Загальна Мінея (служба загальна преподобним дваом або багатьом. Ст. 436).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-й антифон. На «Господи, взиваю» стихири преподобних, глас 2-ий – 8 (перша і друга стихири – тричі, третя – двічі). «Слава» – преподобних, глас 4-ий: «Як ділателів Христових...», «І нині» – догматик, на глас 4-ий «Пророк Давид...». Вхід. Прокимен дня. Паремії преподобних – 3. (Загальна Мінея ст. 438). На літії стихири храму і стихири преподобним. (літійні стихири, беремо з Загальна Мінея на стиховні стихири, глас 4-ий. «Слава» – глас 8-ий: «Преподобні отці...», «І нині» – Богородичний глас той самий: «Неневісна Діво...»). На стиховні стихири преподобних, глас 4-ий (зі своїми приспівами). «Слава» – преподобних, глас 8-ий: «Хто достойно прославить...», «І нині» – Богородичний недільний, глас той самий «Неневісна Діво...». Після Трисвятого – тропар преподобних, глас 4-ий (двічі) «Богородице Діво...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобних, глас 4-ий (двічі). «Слава, і нині» – Богородичний недільний глас той самий: «Від початку віку...». Кафізми 10-та і 11-та. Малі єктенії. Сідальні преподобних (по двічі). Полієлей. Величання святих: «Ублажаємо вас,/ преподобні отці наші Антонію і Феодосію,/ і шануємо святу пам’ять вашу,/ наставники монахів,// і співбесідники ангелів» і вибраний псалом: «Терплячи, потерпів перед Господом і визволив мене, і почув молитву мою». Сідальний преподобних після полієлея, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Ступеневі – 1-ий антифон 4-го гласу. Прокимен глас 7-ий «Чесна перед Господомсмерть преподобних Його». Стих: «Що віддам Господу за все, що Він воздав мені?». Євангеліє – преподобних (див. в Загальній Мінеї). Після 50-го псалма: «Слава» – «Молитвами преподобних...». Стихира преподобних глас 6-ий «Ви, будучи на землі ангелами...» (див. в Загальній Мінеї). Канони: Богородиці з ірмосом на 6 (ірмоси по-двічі) і преподобним (два канона) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – інший кондак та інший ікос преподобних, глас 2-ий; сідальний преподобних, глас 4-ий. «Слава» – інший сідальний преподобних, глас 2-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобних, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний преподобних (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири преподобних, глас 2-ий – 4 (перша стихира – двічі). «Слава» – преподобних, глас той самий: «Думки очистивши...», «І нині» – Богородичний Мінеї, глас той самий: «Спаси від бід...». Велике славослів’я. Після Трисвятого – тропар преподобних, глас 4-ий. «Слава, і нині» – Богородичний недільний глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобних. Кондаки преподобних читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Зображальні. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар преподобних; кондак преподобних. «Слава» – інший кондак преподобних, «І нині» – кондак храму. У храмі святого – тропар преподобних; кондак преподобних. «Слава» – інший кондак преподобних, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – преподобних. Апостол і Євангеліє – преподобних."}]},
{"date":"09-03","weekday":"четвер","title":"Сщмч. Анфіма, єп. Нікомидійського, і з ним сщмч. Феофіла та Мигдонія, дияконів, мчч. Дорофея, Мардонія, Петра, Індиса, Горгонія, Зинона, Євфимія і мц. Домни, діви (302). Прп. Феоктиста Палестинського, ігум., співпосника прп. Євфимія Великого (467). Св. Фіви Коринфської, диякониси (І). Мц. Василіси Нікомидійської (309). Сщмч. Аристіона, єп. Олександрійського. Свт. Іоаникія, патр. Сербського (1354). Пісидійської Мироточивої ікони Божої Матері (VI).","readings":["2 Кор., 197 зач., XIII, 3 – 13. Мк., 18 зач., IV, 35 – 41 (за середу, під зачало).","Гал., 198 зач., I, 1 – 10, 20 – II, 5. Мк., 19 зач., V, 1 – 20 (за четвер).","Сщмч.: Євр., 334 зач., XIII, 7 – 16. Ін., 36 зач., X, 9 – 16."],"notes":"Служба сщмч. Анфіма і прп. Феоктиста не має святкового знаку, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: священномученика, глас 1-ий – 3 і преподобного глас 8-ий – 3. «Слава» – священномученика, глас 6-ий: «Ти, блаженний анфіме...», «І нині» – Богородичний за гласом «Слави», від менших: «Око серця мого зводжу до Тебе...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 4-ий. «Слава» – преподобного, глас 6-ий: «Преподобний отче...», «І нині» – Богородичний за гласом «Слави», від менших: «Око серця мого зводжу до Тебе ...» Після Трисвятого – тропар священномученика, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Духовні врата життя...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Духовні врата життя...». Кафизми 13-та і 14-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6, (ірмоси один раз), священномученика на 4 і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобного). Після 3-ої пісні – кондак преподобного; сідальний священномученика, глас 1-ий. «Слава» – сідальний преподобного, глас 4-ий, «І нині» – Богородичний мінеї глас той самий. Примітка. Типікон нічого нам не розповідає про кондак преподобного Феоктиста, на глас 4-ий «В подвигах посту...» (але він вказується у мінеї після 3-ої пісні). Після 6-ої пісні – кондак та ікос священномученика, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний священномученика, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 4-ий. «Слава» – священномученика, глас той самий: «Нікомідійському великому граду...», «І нині» – Богородичний за гласом «Слави», від менших: «У Тобі Богородице Пречиста...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Діво Пречиста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар священномученика. «Слава» – тропар преподобного; Кондак священномученика і преподобного змінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха, – 4 і священномученика пісня 3-тя – 4. Після вході – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, інший тропар дня, тропар священномученика, тропар преподобного; кондак дня, інший кондак дня, кондак священномученика, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, інший тропар дня, тропар храму, тропар священномученика, тропар преподобного; кондак дня, інший кондак дня, кондак храму, кондак священномученика, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і священномученика. Апостол і Євангеліє – за середу (під зачало), дня і священномученика."}]},
{"date":"09-04","weekday":"п’ятниця","title":"Сщмч. Вавили, єп. Антіохійського, і з ним трьох отроків: Урвана, Прилідіана, Еполонія та матері їхньої Христодули (бл. 251). Прор. Мойсея Боговидця (1531 до Р. Х.). Знайдення мощів свт. Іоасафа (Горленка), єп. Білгородського (1911). Мц. Єрміонії, дочки ап. Филипа, диякона (бл. 117). Мч. Вавили Нікомидійського і з ним 84 учнів (ІV). Мчч. Федора, Міана, Юліана та Кіона (305 – 311). Ікони Божої Матері «Неопалима купина».","readings":["Гал., 201 зач., II, 6 – 10. Мк., 20 зач., V, 22 – 24, 35 – VI, 1.","Прор.: Як., 57 зач., V, 10 – 20. Лк., 14 зач., IV, 22 – 30."],"notes":"Служба сщмч. Вавили і прор. Мойсея шестерична, звершуємо службу разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-та. На «Господи, взиваю» стихири на – 6, священномученика, глас 6-ий – 3 і пророка, глас 4-ий – 3. «Слава» – священномученика, глас 6-ий: «Сходини придбала Церква...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Зачаття Твоє безмужнє...» Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 4-ий. «Слава» – священномученика, глас 6-ий: «Стоячи на судилищі мучителів...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Люди беззаконні...» Після Трисвятого – тропар священномученика, глас 4-ий. «Слава» тропар пророку, глас 2-ий, «І нині» – Хрестобогородичний по гласу «Слави», від менших: «Препрославлена Ти, Богородице Діво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-ий (двічі). «Слава» – тропар пророка, глас 2-ий, «І нині» – Хрестобогородичний по гласу «Слави», від менших: «Препрославлена Ти, Богородице Діво...». Кафизми 19-та і 20-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 4 (ірмос один раз) священномученику на 4 і пророку на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої та 9-ої пісні – ірмос канону Мінеї (пророка) Після 3-ої пісні – кондак пророка, глас 2-ий, сідальний священномученика, глас 3-ій. «Слава» – сідальний пророка, глас 4-ий, «І нині» – Хрестобогородичний, глас той самий. Після 6-ої пісні – кондак та ікос священномученику, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є». Екзапостиларій Октоїха. «Слава» – Світильний священномученика, «І нині» – Хрестобогородичний Октоїха. Читається повсякденне славослів’я На стиховні стихири Октоїха, глас 4-ий. «Слава, і нині» – Хрестобогородичний Октоїха глас той самий: «Коли побачила Тебе розп’ятого...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава» тропар пророку, глас 2-ий, «І нині» – Хрестобогородичний по гласу «Слави», від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар священномученика. «Слава» – тропар пророка; Кондак священномученика і пророка по черзі."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4, і пророка пісня 3-тя –4. Після вході – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси, Господи...», тропар священномученика, тропар пророка; кондак священномученика, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар священномученика, тропар пророка; кондак дня: «Вознісся на Хрест...», кондак священномученика, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар священномученика, тропар пророка; кондак дня: «Вознісся на Хрест...», кондак храму, кондак священномученика, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і пророка. Апостол і Євангеліє – дня і пророка."}]},
{"date":"09-05","weekday":"субота","title":"Прор. Захарії і прав. Єлизавети, батьків св. Іоана Предтечі (І). Прмч. Афанасія, ігум. Берестейського (1648). Кончина блгв. кн. Гліба, в хрещенні Давида (1015). Мчч. Фифаїла і сестри його Фівеї (Вивеї) (98 – 138). Мч. Сарвила. Мц. Раїси (Іраїди) (бл. 308). Мчч. Ювентина і Максима, воїнів (361 – 363). Мчч. Урвана, Федора, Медимна і з ними 77 чоловіків з церковного чину, які в Нікомидії постраждали (370). Мч. Авдія (Авида) Перського (V).","readings":["1 Кор., 130 зач., IV, 1 – 5. Мф., 93 зач., XXIII, 1 – 12.","Прор.: Євр., 314 зач., VI, 13 – 20. Мф., 96 зач., XXIII, 29 – 39 або Лк., 2 зач., І, 5 – 25, 57 – 68, 76, 80."],"notes":"Служба пророка Захарії шестерична, звершуємо разом із службою Октоїха","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири пророка, глас 4-ий – 6 (кожна стихира – двічі). «Слава» – пророка, глас 8-ий: «Ти законно був одягнений...», «І нині» – догматик, глас 4-ий: «Пророк Давид...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 4-ий. (мученичі з числа стихир на «Господи, взиваю» – 1-ий: «Жертви одухотворені...», 2-ий: «Чесна смерть святихТвоїх...», 3-ій: «Маючи сміливість перед Спасом...». Приспіви звичайні зі стиховні – дивитися в Часослові). «Слава» – пророка, глас 2-ий: «Як чистий ієрей...», «І нині» – Богородичний за гласом «Слави», від менших: «Спаси від бід рабів Твоїх...». Після Трисвятого – тропар пророка, глас 4-ий. «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар пророка, глас 4-ий (двічі). «Слава, і нині» – Богородичний воскресний, глас той самий: «Від початку віку утаємнене...». Кафизми 16-та і 17-та. Малі ектенії. Сідальні Октоїха. Псалом 50-ий.Канони: Примітка. Про спів канононів у храмі Воскресіння Христового в суботу, дивитися Октоїх частина 1-ша с.831. У храмі Воскресіння Христового – канон воскресний рядового гласу (з пройдешньої Неділі) з ірмосом на 4 (ірмос один раз), пророка на 6 і Октоїха (мученикам) на 4. У храмі Господньому і Богородиці – канон храму з ірмосом на 4 (ірмоси двічі), пророка на 6 і Октоїха (мученикам) на 4. У храмі святого – канон пророка з ірмосом на 6 (ірмос двічі), храму на 4 і Октоїха (мученикам) на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичного канону Октоїха. Після 3-ої пісні – сідальний пророка, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос пророка, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Світильний пророка. «Слава» – екзапостиларій Октоїха, «І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 4-ий. (мученичні з числа стихир на хвалітніх – 1-ий: «Хто не вжахається...», 2-ий: «святі мученики...», 3-ій: «як не дивуватися вашим подвигам...», приспіви звичайні зі стиховні – дивитися в Часослові). «Слава» – пророка, глас 8: «Жертви приносячи...», «І нині» – Богородичний за гласом «Слави», від менших: «Владичице, прийми молитви рабів Твоїх...». Після Трисвятого – тропар пророка, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак пророка."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні пророка, пісня 3-тя – 4 (з ірмосом) і Октоїха – 4. Після вході – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня: «Апостоли, мученики і пророки...», тропар пророка; кондак храму, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». У храмі святого – тропар дня: «Апостоли, мученики і пророки...», тропар пророка; кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». Прокимен, алилуарій і причасний – пророка і дня. Апостол і Євангеліє – пророка і дня."}]},
{"date":"09-06","weekday":"неділя","title":"14-та неділя після П’ятдесятниці. Глас 5-й. Спомин чуда архістратига Михаїла в Хонах (Колосах) (ІV). Мчч. Євдоксія, Зинона і Макарія (311 – 312). Прп. Архипа в Хонах (ІV). Мчч. Ромила Римського і з ним багатьох інших (105 – 115). Сщмч. Кирила, єп. Гортинського (ІІІ – ІV). Сщмчч. Фавста, пресвітера, Авіва, диякона, і з ними 11 мучеників: Киріака та інших (бл. 250). Прп. Давида Гермопольського (VІ). Свтт. Михаїла († бл. 1073) і Марина († бл. 1095), єпп. Юр’ївських. Свтт. Лазаря († 1117) та Сильвестра († 1123), єпп. Переяславських, ігумм. Видубицьких. Києво-Братської (1654) й Арапетської (Аравійської) ікон Божої Матері.","glas":5,"readings":["Ран. – Єв. 3-е, Мк., 71 зач., XVI, 9 – 20.","Літ. – 2 Кор., 170 зач., I, 21 – II, 4. Мф., 89 зач., XXII, 1 – 14.","Архангела: Євр., 305 зач., II, 2 – 10. Лк., 51 зач., X, 16 – 21."],"notes":"Після Літургії звершується молебень за збереження довкілля. Служба Архангела Михаїла, шестерична звершуємо разом з недільною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 5-ий – 6 і Архангела, глас 4-ий – 4(перша стихира двічі). «Слава» – Архангела, глас 6-ий: «Співрадіють усі ангельські чиноначалія...», «І нині» – Догматик, глас 5-ий: «У червоному Морі...». Вхід. Прокимен дня. На літії стихири храму. На стиховні стихири воскресні, глас 5-ий. «Слава, і нині» – Архангела, глас 8-ий: «Як чиноначальник, і поборник...». Після Трисвятого – «Богородице Діво» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 5-ий (двічі). «Слава» – тропар Архангела, глас 4-ий. «І нині» – Богородичний воскресний, глас той самий: «Від початку віку...». Кафизми 2-га і 3-тя. Малі єктенії. Сідальні недільні. Непорочні. «Ангельський собор...». Іпакої, ступеневі і прокимен – гласу. Євангеліє воскресне 3-тє. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира недільна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси раз), хрестовоскресний на 2, Богородиці (Октоїха) на 2 і архангела на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив Мойсей...». Після 3-ої пісні – кондак та ікос архангела, глас 2-ий; сідальний архангела, глас 8-ий. «Слава» інший сідальний архангела, глас 1-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос неділі, глас 5-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 3-ій. «Слава» – світильний архангела, «І нині» – Богородичний недільного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: недільні, глас 5-ий – 4, архангела, глас 1-ий – 4 (перша стихира двічі, зі своїми приспівами): «Слава» – стихира євангельська 3-тя, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар недільний: «У день спасіння світу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний. «Слава» тропар апостола. Кондак тільки недільний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласа – 6 і архангела, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар недільний, тропар архангела. «Слава» – кондак архангела, «І нині» – кондак недільний. У храмі Богородиці – тропар недільний, тропар храму, тропар архангела; кондак недільний. «Слава» – кондак архангела, «І нині» – кондак храму. У храмі святого – тропар недільний, тропар храму, тропар архангела; кондак недільний, кондак храму. «Слава» – кондак архангела, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – неділі і архангелу. Апостол і Євангеліє – дня і архангелу."}]},
{"date":"09-07","weekday":"понеділок","title":"15-й тиждень після П’ятдесятниці. Передсвято Різдва Пресвятої Богородиці. Мч. Созонта (бл. 304). Прмч. Макарія, архім. Канівського, Овруцького, Переяславського чудотворця (1678). Апп. від 70-х Євода (66) й Онисифора (після 67). Мч. Євпсихія Кесарійського (ІІ). Прп. Луки Каппадокійського (Х). Ікони Божої Матері «Віницька» («Вінницько-Ріжецька») (XVIII). Порядок читання за календрем: Гал., 202 зач., II, 11 – 16. Мк., 21 зач., V, 24 – 34 (за понеділок). Гал., 204 зач., II, 21 – III, 7. Мк., 22 зач., VI, 1 – 7 (під зачало, за вівторок). Прмч.: Еф., 233 зач., VI, 10 – 17. Ін., 52 зач., XV, 17 – XVI, 2. Служба прмч. Макарія Канівського, славослівна звершуємо разом із шестеричною службою передсвята Різдва Пресвятої Богородиці.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ: кафизми немає. На «Господи, взиваю» стихири на 6: передсвята, глас 1-ий – 3, і преподобномученика, глас 2-ий – 3. «Слава» – преподобномученика: «Царства Небесного...», «І нині» – передсвята, глас 4-ий: «Всечесне Твоє Різдво...». Входу немає. Прокимен дня. На стиховні стихири передсвята, глас 8-ий (зі своїми приспівами). «Слава» преподобномученика, глас той самий: «Доки, душе моя, потопатимеш у гріхах...». «І нині» – передсвята, глас 4-ий: «Всесвітня радість...». Після Трисвятого – тропар преподобномученика, глас 8-ий. «Слава, і нині» – тропар передсвята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий (двічі). «Слава» – тропар преподобномученика, глас той самий, «І нині» – тропар передсвята, глас той самий. Кафизми 4-та і 5-та. Малі єктенії. Сідальні передсвята, (по двічі). Псалом 50-ий. Канони: передсвята (в службі мученика Созонта) з ірмосом на 8 (ірмоси по двічі) і преподобномученика на 6. Біблійні пісні «Співаймо Господеві...». Катавасія: «Хрест накреслив...». Після 3-ої пісні – кондак та ікос передсвята, глас 3-ій; сідальний преподобномученика, глас 8-ий. «Слава, і нині» – сідальний передсвята, глас той самий. Після 6-ої пісні – кондак та ікос преподобномученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний передсвята: «Адаме, оновись, і Єво, звеличся...». «Слава, і нині» – світильний преподобномученика: «Великого подвижника віриі благочестя...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 4: передсвята, глас 4-ий – «Слава» – преподобномученика, глас 8-ий: «Господи, коли Ти перебував на землі...», «І нині» – передсвята «Проречена Цариця всіх...». Велике славослів’я. Після Трисвятого – тропар преподобномученика, глас 4-ий. «Слава, і нині» – тропар передсвята, глас той самий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар передсвята. «Слава» – тропар преподобномученика. Кондак тільки передсвята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні передсвята, пісня 3-тя – 4 (з ірмосом), і преподобномученика, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар храму, тропар передсвята, тропар преподобномученика; кондак храму. «Слава» – кондак преподобномученика, «І нині» – кондак передсвята. У храмі Богородиці – тропар передсвята, тропар преподобномученика. «Слава» – кондак преподобномученика, «І нині» – кондак передсвята. У храмі святого – тропар передсвята, тропар храму, тропар преподобномученика; кондак храму. «Слава» – кондак преподобномученика, «І нині» – кондак передсвята. Прокимен, Алилуарій і причасний – дня і преподобномученика. Апостол і Євангеліє – дня, за вівторок (під зачало) і преподобномученика."}]},
{"date":"09-08","weekday":"вівторок","title":"РІЗДВО ПРЕСВЯТОЇ ВЛАДИЧИЦІ НАШОЇ БОГОРОДИЦІ І ПРИСНОДІВИ МАРІЇ. Ікони Софії – Премудрості Божої (Київської). Почаївської (1559), Домницької (1696), Холмської, Ліснинської та Кам’янка-Струмилової (XVII) ікон Божої Матері.","readings":["Ран. – Лк., 4 зач., I, 39 – 49, 56.","Літ. – Флп., 240 зач., II, 5 – 11. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершуємо всенічне бдіння свята Різдва Пресвятої Богородиці","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 8: глас 6-ий (3-тя і 4-та стрихири двічі). «Слава, і нині» – свята, глас той самий: «Нині Бог, що на Небесному престолі спочиває...». Вхід. Прокимен дня. Паремії свята – 3. На літії стихири свята, глас 1-ий і глас 2-ий. «Слава, і нині» – свята, глас 8-ий: «В благознаменний день...». На стиховні стихири свята, глас 4-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Прийдіть, усі вірні...». Після Трисвятого – тропар свята, глас 4-ий (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (тричі). Кафизми 7-ма і 8-ма. Малі єктенії. Сідальні свята (двічі). Полієлей. Величання свята: «Величаємо Тебе,/ Пресвята Діво,/ і шануємо святих Твоїх батьків,// і всеславне славимо різдво Твоє», і вибраний псалом. Сідальний свята після полієлея, глас 8-ий: «Нехай радіє небо...». «Слава, і нині» – «Оновись, Адаме, радуйся, Єво...» Степенна 1-ий антифон, глас 4-ий. Прокимен свята, глас 4-й: «Пом’яну ім’я Твоє у всякому роді і роді»; стих: «Вилилось із серця мого слово благе, кажу я Цареві про мої діла». Євангеліє – свята (Лк., Зач. 4). Після 50-го псалма: «Слава» – «Молитвами Богородиці...», «І нині» – той самий стих. Стихира свята, глас 6-й: «В цей день Господній радійте, люди...». Канони: 2 (ірмоси обох канонів по двічі), на 12. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – сідальний свята, глас 4-ий. «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні – замість «Чеснішу». Співаємо приспіви свята разом з ірмосом: «Величай, душе моя, преславне народження Божої Матері». Після 9-ої пісні – «Достойно є» не співається. Катавасія «Таємний Ти, Богородице, рай...». Світильний – свята: «Від неплідної Анни...» (двічі). «Слава, і нині» – інший світильний свята: «Адам оновився...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 1-ий – 4 (зі своїми приспівами; приспіви дивитися на стиховні вечірня в мінеї; перша стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «В цей день Господній радійте, люди...». Велике славослів’я. Після Трисвятого – тропар свята (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні свята: першого канону пісня 3-тя – 4 (з ірмосом), і 2-го канону, пісня 6-та – 4. Після входу – тропар свята. «Слава, і нині» – кондак свята. Прокимен, алелуарій і причасний – свята. Апостол і Євангеліє – свята. Задостойник свята – приспів: «Величай, душе моя...», та ірмос: «Чуже матерям дівство...» (і до віддання). З 9 по 11 вересня – Післясвято Різдва Пресвятої Богородиці. 12 вересня – віддання свята Різдва Пресвятої Богородиці."}]},
{"date":"09-09","weekday":"середа","title":"Післясвято Різдва Пресвятої Богородиці. Правв. Богоотців Іоакима й Анни. Мч. Северіана Севастійського (320). Знайдення і перенесення мощів свт. Феодосія, архієп. Чернігівського (1896). Прп. Феофана, сповідника і посника (бл. 300). Мчч. Харитона і Стратора (Стратоніка). Св. Микити Константинополького (ХІІ). Пам’ять ІІІ Вселенського собору (431).","readings":["Гал., 207 зач., III, 15 – 22. Мк., 23 зач., VI, 7 – 13.","Богоотців: Гал., 210 зач. (від половини), IV, 22 – 31. Лк., 36 зач., VIII, 16 – 21."],"notes":"Після Літургії звершується молебень за сім’ю. Звершуємо шестеричну службу святих Богоотців Іоакима і Анни, зі службою післясвята.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: післясвята, глас 1-ий – 3, і святих, глас 4-ий – 3. «Слава, і нині» – післясвята, глас 5-ий: «О, блаженна двоїця...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Та, що в неплідному лоні...». Після Трисвятого – тропар святих (за вибором), «Слава, і нині» – тропар свята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава» – тропар святих (за вибором), «І нині» – тропар свята, глас 4-ий. Кафизми 10-та і 11-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмосом на 6 (ірмоси по двічі) і святих на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої, і 9-ої пісні – ірмос канону святих. Після 3-ої пісні – кондак та ікос свята, глас 4-ий. «Слава, і нині» – Сідальний святих, глас 5-ий. Після 6-ої пісні – кондак та ікос святих, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний світильний святих «Та, що знищила клятву...». «Слава, і нині» – світильний свята «Як від сонця сонце...». «Все, що дише...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 2-ий: «Нині Всенепорочна і Чиста...» Після Трисвятого – тропар святих (за вибором), «Слава, і нині» – тропар свята, глас 4-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – святих. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, 1-го канону пісня 1-ша – 4 (з ірмосом), і святих, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар храму, тропар свята, тропар святих; кондак храму. «Слава» – кондак святих, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар святих. «Слава» – кондак святих, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар святих; кондак храму. «Слава» – кондак святих, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і святих. Апостол і Євангеліє – дня, і святих. Задостойник свята."}]},
{"date":"09-10","weekday":"четвер","title":"Мцц. Минодори, Митродори й Німфодори (305 – 311). Прп. Павла Послушного, Києво-Печерського, в Дальніх печерах (ХІІІ – ХІV). Апп. від 70-х: Аполоса (Апелія), Лукія і Климента (І). Мч. Варипсава (ІІ). Блгв. Пульхерії, імператриці Візантійської (453). Свтт. Петра і Павла, єпп. Нікейських (ІХ).","readings":["Гал., 208 зач., III, 23 – IV, 5. Мк., 25 зач., VI, 30 – 45."],"notes":"Служба мцц. Минодори, Митродори і Німфодори, шестерична, звешується із службою післясвята Різдва Пресвятої Богородиці.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. На «Господи, взиваю» стихири на 6: свята глас 8-ий – 3, і мучениць, глас 4-ий – 3. «Слава І нині» глас 2-ий: «Чому буває голос святкуючих?...». Входу немає Прокимен дня. На стиховні, свята глас 1-ий (зі своїми приспівами), «Слава, і нині» – свята, глас 2-ий: «Провіщена Цариця всіх...». Після Трисвятого – тропар свята, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята глас 4-ий (двічі), «Слава, і нині» – той самий. Кафизми 13-та і 14-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий Канони: свята 2-ий з ірмосом на 6 (ірмоси по двічі) і мучениць на 6. Біблійні пісні «Співаймо Господеві...». Катавасія 3-ої, 6-ої, 8-ої, і 9-ої пісені – ірмоси канона мучениць. Після 3-ої пісні – кондак мучениць, глас 4-ий, сідальний мучениць, глас той самий. «Слава, і нині» – сідальний свята. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу» Після 9-ої пісні «Достойно є» не співається. – світильний свята – «Сонце духовне...». «Слава і нині» той самий. «Все, що дише...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 4-ий: «Всесвітня радіст...». Після Трисвятого – тропар свята глас 4-ий (один раз)"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні свята, пісня 4-та – 4 (з ірмосом) і пісня 5-та – 4. Після входу: тропарі і кондаки. У храмі Господньому – тропар храму, тропар свята; кондак храму. «Слава» – кондак мучениць, «І нині» – кондак свята. У храмі Богородиці – тропар свята. «Слава» – кондак мучениць, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму; кондак храму, «Слава» – кондак мучениць, «І нині» – кондак свята. Прокимен, Алилуарій і Причасний – свята. Апостол і Євангеліє – дня. Задостойник свята."}]},
{"date":"09-11","weekday":"п’ятниця","title":"Прп. Феодори Олександрійської (474 – 491). Мчч. Димитрія, Єванфії, дружини його, і Димитріана, сина їхнього (І). Мчч. Діодора і Дидима, Сирійських. Мц. Євдокії (Ії) Римлянки (362 – 364). Прп. Єфросина Палестинського (ІХ).","readings":["Гал., 210 зач., IV, 8 – 21. Мк., 26 зач., VI, 45 – 53.","Прп.: Гал., 208 зач., III, 23 – 29. Ін., 28 зач., VIІІ, 3 – 11."],"notes":"Служба преподобної Феодори без святкового знаку звершуємо зі службою післясвята Різдва Пресвятої Богородиці.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-та. На «Господи, взиваю» стихири на 6: преподобної, глас 4-ий – 3, священеномученика, глас той самий – 3. «Слава, і нині» – свята: «Провіщенням ангела...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-й. «Слава, і нині» – свята, глас 4-ий: «Неплідна і бездітна Анна...». Після Трисвятого – тропар преподобної, глас 8-ий. «Слава, і нині» – тропар свята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава» – тропар преподобної, глас 8-ий. «І нині» – тропар свята. Кафизми 19-та і 20-та. Малі єктенії. Сідальні свята. 50-ий псалом. Канони: свята 1-й з ірмосом на 6 (ірмоси раз), преподобної на 4 і священномученика Автонома на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (священномученика). Після 3-ої пісні – кондак преподобної, глас 2-ий, кондак священномученика, глас той самий; сідальний преподобної, глас 5-ий. «Слава» – священномученика, глас 4-ий. «І нині» – сідальний свята, глас 5-ий. Після 6-ої пісні – кондак та ікос свята, глас 4-ий На 9-ій пісні співаємо «Чеснішу» (приспіви свята не співають). Після 9-ої пісні – «Достойно є» не співається. Світильний свята. «Хваліте Господа з небес...» і хвалитні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 1-ий (зі своїми приспівами) «Слава, і нині» – свята, глас 8-ий. Після Трисвятого – тропар преподобної, глас 8-ий: «Слава і нині...» – тропар свята."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар преподобної. Кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні свята, пісня 7-ма і 8-ма – 8. Після входу: У храмі Господньому – тропар храму, тропар свята, тропар преподобної, кондак храму. «Слава» – кондак преподобної, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар преподобної, кондак храму. «Слава» – кондак преподобної, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар преподобної, кондак храму. «Слава» – кондак преподобної, «І нині» – кондак свята. Прокимен, Алилуарій і Причасний – свята. Апостол і Євангеліє – дня і преподобної. Задостойник свята."}]},
{"date":"09-12","weekday":"субота","title":"Субота перед Воздвиженням. Віддання свята Різдва Пресвятої Богородиці. Сщмч. Автонома, єп. Італійського (313). Сщмч. Юліана, пресвітера і з ним 40 мучеників (ІV). Сщмч. Федора, єп. Олександрійського. Сщмч. Корнута, єп. Нікомидійського (249 – 259).","readings":["Суботи перед Воздвиженням: 1 Кор., 126 зач., II, 6 – 9. Мф., 39 зач., X, 37 – XI, 1."],"notes":"Звершується славослівна служба віддання свята Різдва Пресвятої Богородиці. НА ВЕЧІРНІЙ кафизма 18-та. На «Господи, взиваю» стихири свята, глас 6-ий – 6. «Слава» – свята, глас : «Нині Бог, що на Небесному престолі...», «І нині» – Догматик, глас 5-ий: «У червоному морі...». Входу немає. Прокимен дня. Паремій немає. На стиховні стихири свята, глас 4-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Прийдіть усі вірні...». Після Трисвятого – тропар свята, глас 4-ий (один раз).","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 16-та і 17-та. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 1-ий з ірмосом на 8 (ірмоси по двічі) і 2-ий з ірмосом на 6 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія: «Хрест накреслив...». Після 3-ої пісні – сідальний свята, глас 4-ий. «Слава і нині...» той самий сідальний. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні «Чеснішу» не співаємо, але співаємо приспіви свята. 1-ий приспів: «Величай душе моя, преславне народження Божої Матері». (Звершується звичайне кадіння). Після 9-ої пісні «Достойно є» не співається. Катавасія: «Таємний Ти Богородице рай...». Світильний свята. «Слава, і нині» – інший світильний свята; «Адам оновився...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 1-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «В цей день Господній радійте...». Велике славослів’я. Після Трисвятого – тропар свята, глас 4-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, 1-го і 2-го канонів, пісня 9-та – 8 (1-го канону з ірмосом). Після входу – тропар свята. «Слава, і нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – суботи перед Воздвиженням. Задостойник свята."}]},
{"date":"09-13","weekday":"неділя","title":"15-та неділя після П’ятдесятниці, перед Воздвиження. Глас 6-й. Передсвято Воздвиження чесного Хреста Господнього. Пам’ять оновлення (освячення) храму Воскресіння Христового в Єрусалимі (335). Сщмч. Корнилія Сотника, єп. (І). Мчч. Кроніда, Леонтія і Серапіона (бл. 237). Мчч. Селевка і Стратоніка (ІІІ). Мчч. Макровія і Гордіана (320). Сщмч. Юліана, пресвітера (ІV). Мчч. Іллі, Зотика, Лукіана і Валеріана (320). Прп. Петра в Атрої (ІХ). Вмц. Кетевані, цариці Кахетинської (1624, Груз.).","glas":6,"readings":["Ран. – Єв. 4-е, Лк., 112 зач., XXIV, 1 – 12.","Літ. – неділі перед Воздвиженням: Гал., 215 зач., VI, 11 – 18. Ін., 9 зач., III, 13 – 17.","Оновленню: Євр., 307 зач., III, 1 – 4. Мф., 67 зач., XVI, 13 – 18."],"notes":"Недільну службу Октоїха звершуємо зі службою Оновлення і службою передсвята Воздвиження. Примітка. По Марковій главі Типікона на 13 вересня: «якщо припаде свято Оновлення в неділю, то служба святому Корнилію опускається і співається у інший день, коли благословить настоятель».","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 6-ий – 4, Оновлення, глас той самий – 3, і передсвята, глас 5-ий – 3 (дивитися на стиховні вечора, без приспівів). «Слава» – Оновлення, глас 6-ий:, «І нині» – Догматик, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії Оновлення – 3. На літії стихири храму і стихири Оновлення. На стиховні стихири недільні, глас 6-ий. «Слава» – Оновлення, глас 2-ий: «Звершуючи оновлення святого храму...», «І нині» – передсвята, глас той самий: «Божественний скарб...». Після Трисвятого – «Богородице Діво» (двічі) і тропар Оновлення, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар недільний, глас 6-ий (двічі). «Слава» – тропар Оновлення, глас 4-ий, «І нині» – тропар передсвята, глас той самий. Кафизми 2-га і 3-тя. Малі єктенії. Сідальні недільні Октоїха. «Слава, і нині» – сідальні Оновлення (сідальні Богородичні з Октоїха опускаються). Непорочні. «Ангельський собор...». Іпакої, степенні і прокимен – гласу. Євангеліє недільне 4-те. «Воскресіння Христове бачивши...». 50 псалом: «Слава» – «Молитвами апостолів...». Стихира недільна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: Воскресний з ірмосом на 4 (ірмоз раз), Богородиці (Октоїха) На 2, Оновлення на 4 і передсвята на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – кондак Оновлення, глас 2-ий: «Оновлення Духа в серцях...» і ікос Оновлення, глас 2-ий (дивитися після 6-ої пісні канону). сідальний Оновлення, глас 8-ий. «Слава, і нині» – сідальний передсвята, глас 4-ий: «Простягнув руки Мойсей...». Після 6-ої пісні – кондак та ікос недільний, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 4-ий. «Слава» – світильний Оновлення, «І нині» – світильний передсвята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: недільні, глас 6-ий – 4, Оновлення, глас 4-ий – 2: «Нині світло оновлюється...», «Засяяла звище...»; приспів: «Дому Твоєму належить святість, Господи, на довгі дні» – стрихира Оновлення (на «Слава»), глас 3-ій: «До себе повертайся, людино...», приспів: «Господь воцарився, у красу зодягнувся» і стихира передсвята (хвалітніх на «І нині»), глас той самий: «Христе Боже, вільне Твоє розп’яття...». «Слава» – стихира євангельська 4-та, «І нині» – «Преблагословенна Ти...». Велике славослів’я. Після Трисвятого – тропар недільний: «Воскрес із гробу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний. «Слава» – тропар Оновлення. Кондаки недільний і Оновлення читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласа – 6 і Оновлення, пісня 3-тя – 4. Після входу – тропар недільний, тропар Оновлення, тропар передсвята, тропар священномученика; Кондак недільний. «Слава, і нині» – кондак Оновлення, глас 2-ий. Прокимен, алилуарій і причасний – неділі перед Воздвиженням і Оновлення. Апостол і Євангеліє – неділі перед Воздвиженням і Оновлення."}]},
{"date":"09-14","weekday":"понеділок","title":"16-й тиждень після П’ятдесятниці. ВОЗДВИЖЕННЯ ЧЕСНОГО І ЖИВОТВОРЧОГО ХРЕСТА ГОСПОДНЬОГО. Упокоєння свт. Іоана Золотоустого (407). Ліснинської ікони Божої Матері (1683).","readings":["Ран. – Ін., 42 зач. (від половини), XII, 28 – 36.","Літ. – 1 Кор., 125 зач., I, 18 – 24. Ін., 60 зач., XIX, 6 – 11, 13 – 20, 25 – 28, 30 – 35."],"notes":"Звершуємо бдінну службу свята Воздвиження Чесного і Животворчого Хреста Господнього. Пісний день. Стародавній православний звичай воздвигати Хрест Христовий, що дав назву для свята, бере свій початок з IV століття. Для чину Воздвиження рекомендується особливий, спеціально для цього призначений Хрест, який не буває в звичайному вживанні в іншу пору року. Найкраще, якщо Хрест буде великий за розміром, писаний на дереві або різьблений дерев’яний, щоб самим своїм матеріалом нагадувати про «Триблаженне Древо, на якому був розп’ятий Христос». Перед початком малої вечірні священник виносить із сосудохранительниці Чесний Хрест, кладе його на жертовник на блюді, покритому покрівцем, і прикрашає Хрест вінком з живих квітів. Після малої вечірні або, на практиці, безпосередньо перед початком всенічної священик і диякон в облачені підходять до жертовника. Диякон виголошує тихо: «Благослови, владико». Священик: «Благословен Бог наш...». Трисвяте. Після «Отче наш...» – виголос: «Бо Твоє є Царство...». Після виголосу співають (тихо) тропар Хреста, глас 1-ий: «Спаси, Господи, людей Твоїх...». «Слава, і нині» – кондак Хреста, глас 4-ий: «Вознісся на Хрест волею...». Під час співу священик кладе на голову блюдо з Хрестом, в супроводі свічконосця зі свічкою і диякона з кадилом переносить Хрест на престіл і кладе його на євангельське місце, а Євангеліє (зазвичай заздалегідь, до перенесення) ставить на горнє місце престолу, куди воно ставиться після читання на Літургії. Перед престолом ставиться підсвічник із запаленою свічкою.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири свята, глас 6-ий – 8 (перші дві стихири – тричі, третя – двічі). «Слава, і нині» – свята, глас 2-ий: «Прийдіть, усі народи...». Вхід. Прокимен дня. Паремії свята – 3. На літії стихири свята, глас 1-ий, глас 2-ий і глас 4-ий. «Слава, і нині» – свята, глас 4-ий: «Чесного Хреста, Христе...». На стиховні стихири свята, глас 5-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 8-ий: «Тебе Мойсей прообразував собою...». Після Трисвятого – тропар свята, глас 1-ий (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 4-та і 5-та. Малі єктенії. Сідальні свята. Полієлей (за традицією, відбувається у вівтарі). Величання свята: «Величаємо Тебе,/ Життєдавче Христе,/ і шануємо Хрест Твій Святий,/ ним же нас спас// від неволі ворожої», і вибраний псалом. (Величання співається у вівтарі перед Хрестом, який лежить на престолі). Сідальний після полієлея, глас 8-ий. «Слава, і нині» – той самий сідальний. Степенна – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «Побачили всі кінці землі спасіння Бога нашого»; стих: «Співайте Господеві пісню нову, бо дивне сотворив Господь». Євангеліє – Ін., Зач. 42, від половини (читається у вівтарі). «Воскресіння Христове бачивши...» (один раз). Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира свята, глас 6-ий: «Хресте Христів...». (Помазання святим єлеєм відбувається, за традицією, після виносу Хреста). Примітка. Царські врата зачиняються після виголосу: «Милістю і милосердям...» (перед каноном). Канон свята на 14 (ірмоси по двічі). на 9-ій пісні – 1-ий канон з ірмосом на 8 (Ірмос двічі), 2-ий канон з ірмосом на 8 (Ірмос двічі). Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». В 9-ій пісні катавасія – ірмоси: «Таємний Ти...» і «Спожива древа...» (з приспівами). Після 3-ої пісні – сідальний свята, глас 4-ий. «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-й пісні – приспіви свята і звичайне кадіння. («Чеснішу» не співаємо). 1-ий приспів: «Величай, душе моя, Пречесний Хрест Господній». Після 9-ої пісні «Достойно є» не співається. Світильний свята: «Хрест – охоронитель усієї вселенної...» (двічі). «Слава, і нині» – інший світильний свята: «Нині воздвигається Хрест...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 8-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «Нині підноситься...». Примітка. До співу великого славослів’я (зазвичай під час співу канону або хвалітніх стихир) предстоятель одягається в усі священичі одежі (без читання відповідних молитов). Велике славослів’я. Під час співу славослів’я предстоятель звершує з дияконом триразове кадіння навколо престолу, на якому лежить Хрест. Після закінчення великого славослів’я при співі Трисвятого, поклонившись земно тричі, предстоятель кладе Хрест на голову (при співі заключного: «Святий Боже...») і виходить (через горнє місце) північними дверима (перед ним йдуть свічконосець зі свічкою і диякон з кадилом) до царських врат. Після закінчення Трисвятого предстоятель виголошує в царських вратах: «Премудрість, станьмо побожно». За звичаєм, предстоятель творить Хрестом хресне знамення в царських вратах. Хор співає тричі тропар Хреста, глас 1-ий: «Спаси, Господи, людей Твоїх...». Священик у супроводі свічконосця і диякона йде на середину храму, де кладе Хрест на заздалегідь приготовлений аналой і звершує навколо нього триразове кадіння. Чин Воздвиження Хреста У соборах і в парафіяльних храмах, з благословення єпархіального архієрея, здійснюється чин Воздвиження Хреста. Після виносу Хреста священик з дияконом роблять три земні поклони (в якій би день седмиці не трапилось свято Воздвиження). Предстоятель бере Хрест, прикрашений живими квітами, і стає обличчям на схід (до вівтаря), починаючи перше воздвиження. Диякон стоїть перед Хрестом, на деякій відстані від нього, тримаючи в лівій руці свічку, а в правій кадило, і вимовляє велемовно єктенію: «Помилуй нас, Боже...», що складається з п’яти прохань, на кожному з яких здійснюється чин воздвиження. Диякон: «Помилуй нас, Боже, з великої милості Твоєї, молимось Тобі, вислухай нас, Господи, і помилуй, промовмо всі». Хор співає 100 раз: «Господи, помилуй». На початку співу «Господи, помилуй» предстоятель тричі осіняє Хрестом на схід і при співі першої половини сотні (50 разів) повільно схиляє свою голову з Хрестом, наскільки може низько, «на п’ядь від землі». У міру опускання Хреста, голоси співаючих знижуються, стихають. При співі другої половини сотні (50 разів) предстоятель повільно піднімається. З такою ж поступовістю спів підноситься, переходить на більш високі ноти, посилюється і закінчується велемовно триразовим урочистим: «Господи, помилуй». При співі в 97- ий раз «Господи, помилуй» предстоятель випрямляється і, стоячи прямо, знову тричі осіняє Хрестом на схід. При соборному служінні два священика-співслужителя підтримують предстоятеля під руки, а один або два інших священика зливають безперервно і повільно, помалу, з сосудів воду на Хрест. Вода зливається в миску, яку тримає ще один священик, або хтось із братії. У воду можна додати кілька крапель трояндової олії або інших ароматів, але не духів або одеколону. За звичаєм, цю воду розбирають віряни після служби. Після цього предстоятель звертається з Хрестом лицем на захід. Диякон переходить на протилежну сторону і, стоячи перед Хрестом, продовжує єктенію, виголошуючи: «Ще молимось за милість, життя і відпущення гріхів Блаженнійшого владики і Отця нашого Митрополита Епіфанія, і всього у Христі братства нашого, за здоров’я і за спасіння, промовмо всі». Предстоятель здійснює друге воздвиження, як і перше. Третє воздвиження, обличчям на південь, відбувається як і перше. Диякон виголошує: «Ще молимось за Богом бережену Україну нашу, за владу і військо її, щоб тихе і мирне життя прожили ми в усякому благочесті й чистоті». Четверте воздвиження, обличчям на північ, відбувається як і перше. Диякон виголошує: «Ще молимось за всяку душу християнську, скорботну і пригноблену, що здоров’я, спасіння і відпущення гріхів потребує, промовмо всі». П’яте воздвиження, знову обличчям на схід, відбувається як і перше. Диякон промовляє: «Ще молимось за всіх, хто служить і служили у святій обителі цій (або: храмі цьому), отців і братів наших, за здоров’я і спасіння, і відпущення гріхів їхніх, промовмо всі». Після п’ятого воздвиження співається: «Слава, і нині» – кондак Хреста, глас 4-ий: «Вознісся на Хрест волею...». При цьому священик кладе Хрест на аналой. Потім співається: «Хресту Твоєму поклоняємось, Владико...», із земними поклонами, і стихири Хреста, і, за традицією, відбувається помазання єлеєм. Диякон виголошує прохальну єктению: «Доповнімо ранню молитву...», а єктенія: «Помилуй нас, Боже...» може бути пропущена, оскільки вже звучала під час самого чину воздвиження Хреста. Далі закінчення служби за звичаєм. Якщо чин Воздвиження не здійснюється, то священик, обкадивши аналой зі святим Хрестом, тричі співає: «Хресту Твоєму...» (кожен раз завершуючи спів земним поклоном). Цей спів тричі повторюють хористи, здійснюється поклоніння Хресту, цілування його і, за традицією, помазання єлеєм при співі стихир, глас 2-ий, глас 5-ий, глас 6-ий і глас 8-ий: «Прийдіть, вірні...» та ін. Ектенії: «Помилуй нас Боже...», і «Доповнимо ранню молитву...» і відпуст: «Христос, Істинний Бог наш, молитвами Пречистої Своєї Матері, силою Чесного і Животрочого Хреста, і всіх святих, помилує і спасе нас, бо Він Благий і Людинолюбний»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони свята. Вхідний стих: «Возносьте Господа Бога нашого і поклоняйтеся підніжжю ніг Його, бо воно святе». Примітка. Перед проголошенням вхідного стиха слід промовляти «Премудрість, станьмо побожно». Після входу – тропар свята. «Слава, і нині» – кондак свята. Замість Трисвятого – «Хресту Твоєму поклоняємось, Владико...». Прокимен, Апостол, алилуарій, Євангеліє і причасний – свята. Замість «Достойно» – приспів: «Величай, душе моя...» і ірмос: «Таємний Ти, Богородице, рай...» (і до віддання). Примітка. «На трапезі ж буває утіха братії, від єлею і вина, і інших наїдків овочевих. Сиру ж і яєць і риби, торкнутися не насмілюймось» (Типікон, 14 вересня). З 15 по 20 вересня – післясвято Воздвиження Хреста Господнього. 21 вересня – віддання свята Воздвиження Хреста Господнього. Служби звершуються тільки за Мінеєю (крім неділі)."}]},
{"date":"09-15","weekday":"вівторок","title":"Післясвято Воздвиження. Вмч. Микити (бл. 372). Знайдення мощів свт. Акакія, спов., єп. Мелітинського (ІІІ). Мчч. Максима, Феодота, мц. Аскліади (Аскліпіодоти) (305 – 311). Мч. Порфирія Ефеського (361). Знайдення мощів першомученика архідияк. Стефана (415). Прп. Філофея, пресвітера, в Малій Азії (Х). Свт. Йосифа, єп. Алавердського (570, Груз.). Свт. Симеона, архієп. Солунського (1429). Новомикитської ікони Божої Матері (372).","readings":["Гал., 211 зач., IV, 28 – V, 10. Мк., 27 зач., VI, 54 – VII, 8 (за понеділок, під зачало).","Гал., 212 зач., V, 11 – 21. Мк., 28 зач., VII, 5 – 16 (за вівторок).","Вмч.: 2 Тим., 292 зач., II, 1 – 10. Мф., 36 зач., Х, 16 – 22."],"notes":"Служба вмч. Микити шестерична, звершуємо разом зі службою після свята Воздвиження.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: свята глас 5-ий – 3 і великомученика, глас 1-ий – 3. «Слава» – великомученика, глас 6-ий: «Пізнали тебе світильника мучеників...», «І нині» – свята, глас той самий: «Пророчі слова провістили...» Вхід. Прокимен великий глас 7-ий: «Бог наш на небесах і на землі, все, що хотів, сотворив», зі стихами (за звичаєм). На стиховні стихири свята, глас 6-ий, (зі своїми приспівами). «Слава» – великомученика, глас 8-ий: «Перемоги тезоіменним став ти...», «І нині» – свята, глас той самий: «Сповнилося слово пророка Твого Мойсея, Господи...». Після Трисвятого – тропар великомученика, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар великомученика, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 7-ма і 8-ма. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята зт ірмосом на 6 (ірмоси по двічі) і великомученика на 6. Біблійні пісні «Співаймо Господеві...». Катавасія свята: після 3-ої, 6-ої, 8-ої і 9-ої пісні – ірмоси канону великомученика. Після 3-ої пісні – кондак та ікос свята, глас 4-ий; сідальний великомученика, глас той самий «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос великомученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. світильний великомученика: (двічі) «Зброєю чесного Твого Хреста...», «І нині» – світильний свята: «Хрест нині воздвигається...». «Все, що дише...» і хвалітні псалми. Читається посвсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава» – великомученика, глас 6-ий: «Нині вся вселенна...», «І нині» – свята, глас той самий: «Нині сад життя...». Після Трисвятого – тропар великомученика, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар великомученика. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята пісня 1-ша – 4 (з ірмосом) і великомученика, пісня 6-та – 4. На вході: «Прийдіть поклонімось... що Плоттю розп’явся...». Після входу – тропарі і кондаки: У храмі Господньому – Тропар свята, тропар великомученика. «Слава» – кондак великомученика, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар великомученика; кондак свята. «Слава» – кондак великомученика, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар великомученика; кондак храму. «Слава» – кондак великомученика, «І нині» – кондак свята. Співається Трисвяте. Прокимен,алилуарійіпричасний–святаівеликомученика. Апостол і Євангеліє – понеділку (під зачало), дня та великомученика. Задостойник свята. На відпусті: «...силою Чесного і Животворого Хреста...»."}]},
{"date":"09-16","weekday":"середа","title":"Вмц. Євфимії Всехвальної (304). Мц. Севастіани (І). Мц. Мелітини (ІІ). Мчч. Віктора і Сосфена (бл. 304). Прп. Дорофея, пустельника Єгипетського (ІV). Мц. Людмили, кн. Чеської (927). Мчч. братів Йосифа та Ісака (808, Груз.). Свт. Кипріана, митр. Київського і всієї Руси, чудотворця (1406). Ікони Божої Матері, званої «Зглянься на смирення» (1420).","readings":["Гал., 214 зач., VI, 2 – 10. Мк., 29 зач., VII, 14 – 24.","Вмц.: 2 Кор., 181 зач., VI, 1 – 10. Лк., 33 зач., VII, 36 – 50."],"notes":"Служба великомучениці Євфимії шестерична, звершуємо разом зі службою післясвята Воздвиження.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3, і великомучениці, глас той самий – 3. «Слава» – великомучениці, глас 6-ий: «Розквітнувши чеснотами...». «І нині» – свята глас той самий: «Чотирокінечний світ...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава» – великомучениці, глас 8-ий: «Всякий язик...», «І нині» – свята, глас той самий: «Його у давнину Мойсей прообразував собою...». Після Трисвятого – тропар великомучениці, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. На відпусті: «...силою Чесного і Животворчого Хреста...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар великомучениці, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 10-та і 11-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята з ірмосом на 6 (ірмоси по двічі) і великомучениці на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (великомучениці). Після 3-ої пісні – кондак та ікос свята, глас 4-ий; сідальний великомучениці, глас 8-ий. «Слава, і нині» – сідальний свята, глас той самий (двічі). Після 6-ої пісні – кондак та ікос великомучениці, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний великомучениці (двічі). «Слава, і нині» – світильний свята: «Світлосяйним сяянням...». «Хваліте Господа з Небес...» і хвалитні псалми. На хвалітніх стихири великомучениці, глас 3-ій – 4 (перша стихира – двічі). «Слава» – великомучениці, глас 6-ий: «Праворуч Спаса предстала діва...», «І нині» – свята, глас той самий: «Нині воздвигається Хрест Господній...». «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається посвсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава» – великомучениці, глас 1-ий: «Нині собор отців...», «І нині» – свята, глас той самий: «Нині воістину...». Після Трисвятого – тропар великомучениці, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. На відпусті 1-го часу: «... силою Чесного і Животворчого Хреста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар великомучениці. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 3-тя – 4 (з ірмосом), і великомучениці, пісня 6-та – 4. На вході: «Прийдіть поклонімось... що Плоттю розіп’явся...». Після входу – тропарі і кондаки: У храмі Господньому – тропар свята, тропар великомучениці. «Слава» – кондак великомучениці, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар великомучениці; кондак свята. «Слава» – кондак великомучениці, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар великомучениці; кондак храму. «Слава» – кондак великомучениці, «І нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята і великомучениці. Апостол і Євангеліє – дня і великомучениці. Задостойник свята. На відпусті: «...силою Чесного і Животворчого Хреста...»."}]},
{"date":"09-17","weekday":"четвер","title":"Мцц. Віри, Надії, Любові та матері їх Софії (бл. 137). Мцц. Феодотії (бл. 230) і Агафоклії. Мчч. 156: сщмчч. Пелія та Ніла, єпп. Єгипетських, Зинона, пресвітера, мчч. Патермуфія, Іллі та інших (310). Свт. Іоакима (Пані), патр. Олександрійського (1567). Константинопольської ікони Божої Матері (1071).","readings":["Еф., 216 зач., I, 1 – 9. Мк., 30 зач., VII, 24 – 30.","Мцц.: 2 Кор, 182 зач., VI, 1 – 10. Мф., 62 зач., ХV, 21 – 28."],"notes":"Служба мцц. Віри, Надії, Любові і матері їх Софії славослівна, звершуємо разом зі службою післясвята Воздвиження. Примітка. Деякі стихири беремо із Загальної Мінеї (служба загальна мученицям двом або багатьом). ТРОПАР МУЧЕНИЦЯМ: глас 4-ий, «Торжествує Церква первородних і веселиться, приймаючи матір, що за дітей радіє, бо вона, тезоіменна Премудрості, народила рівночисельно Святій Тройці; вона разом із мудрими дівами зустріли Жениха Бога Слово, з ними ж. і ми, духовно святкуючи їх пам’ять взиваємо: Тройці поборниці, Віро, Любове й Надіє, у вірі, любові й надії утверджуйте нас». Тропар подається з Часослова. ст. 356.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. На «Господи, взиваю» стихири на 6: свята, глас 1-ий – 3 і мучениць, глас 4-ий – 3. «Слава» – мучениць, глас 8-ий: «Всякі уста нехай подвигнуться...» (стихира з Мінеї загальної ст.563), «І нині» – свята, глас1-ий: «Насаджене на лобному місці Древо...» Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава» – мучениць, глас 4-ий: «Життя, що тягне до низькості...» (стихира з Мінеї загальної ст.567), «І нині» – свята, глас 1-ий: «Прообразуючи Хрест Твій...». Після Трисвятого – тропар мучениць, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. На відпусті: «...силою Чесного і Животворчого Хреста...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар мучениць, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 13-та і 14-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята з ірмосом на 8 (ірмоси по двічі) і мучениць на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після – «Хрест накреслив...». Після 3-ої пісні – кондак мучениць, глас 1-ий; сідальний мучениць, глас той самий. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний мучениць: «Бачити бажаючи всю красу...» (стихира з Мінеї загальної ст.576). «Слава, і нині» – світильний свята: «Хрест – охоронитель усієї вселенної...». «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири на 4: мучениць, глас 4-ий (перша стихира двічі). «Слава» – мучениць, глас 2-ий: «Житіє чистими проживши...» (стихири з Мінеї загальної ст.576), «І нині» – свята, глас той самий: «Прийдіть, усі народи...» (славник на стиховні стихир). Велике славослів’я. Після Трисвятого – тропар мучениць, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. На відпусті 1-го часу: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропарі свята. «Слава» – тропар мучениць; кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 4-та (з ірмосом) – 6 імучениць, пісня 6-та – 4. На вході: «Прийдіть поклонімось... що плоттю розіп’явся...». Після входу – тропарі і кондаки: У храмі Господньому – тропар свята, тропар мучениць. «Слава» – кондак мучениць, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар мучениць; кондак свята. «Слава» – кондак мучениць, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар мучениць; кондак храму. «Слава» – кондак мучениць, «І нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята і мучениць. Апостол і Євангеліє – дня і мучениць. Задостойник свята. На відпусті: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."}]},
{"date":"09-18","weekday":"п’ятниця","title":"Прп. Євменія, єп. Гортинського (VІІ). Мц. Аріадни Фригійської (ІІ). Мцц. Софії та Ірини (ІІІ). Мч. Кастора. Мчч. Бидзини, Шалви і Елізбара, князів Ксанських (1660, Груз.). Молченської ікони Божої Матері (1405).","readings":["Еф., 217 зач., I, 7 – 17. Мк., 32 зач., VIII, 1 – 10."],"notes":"Служба преподобного Євменія шестерична, звершумо разом зі службою післясвята Воздвиження","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3, і преподобного, глас той самий – 3. «Слава, і нині» – свята, глас 2-ий: «Божественний скарб...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 4-ий: «Дійство чесного Хреста...». Після Трисвятого – тропар свята, глас 1-ий (один раз). На відпусті: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 19-та і 20-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята з ірмосом на 8 (ірмоси по двічі) і преподобного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобного). Після 3-ої пісні – кондак преподобного, глас 2-ий; сідальний преподобного, глас 5-ий. «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава, і нині» – світильний той самий. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава, і нині» – свята, глас 4-ий: «Світлосяйними зірками...». Після Трисвятого – тропар свята, глас 1-ий (один раз). На відпусті 1-го часу: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 5-та (з ірмосом) і 6-та – 6. На вході: «Прийдіть поклонімось... що плоттю розіп’явся...». Після входу – тропарі і кондаки: У храмі Господньому – тропар свята. «Слава» – кондак преподобного, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму; кондак свята. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму; кондак храму. «Слава» – кондак преподобного, «І нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня. Задостойник свята. На відпусті: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."}]},
{"date":"09-19","weekday":"субота","title":"Субота після Воздвиження. Мчч. Трофима, Саватія і Доримедонта (276). Прмч. Зосими, пустельника (ІV). Блгв. кн. Ігоря Чернігівського та Київського (1147).","readings":["Суботи після Воздвиження: 1 Кор., 125 зач. (від половини), I, 26 – 29. Ін., 30 зач., VIII, 21 – 30.","Блгв.: Діян., 17 зач., VІ, 8 – VІІ, 5, 58 –60. Ін., 52 зач., XV, 17 – XVI, 2.","Ряд.: 1 Кор., 146 зач., X, 23 – 28. Мф., 101 зач., XXIV, 34 – 44 (під зачало)."],"notes":"Служба благовірного великого князя Ігоря шестерична, звершується разом зі службою післясвята Воздвиження.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: свята, глас 4-ий – 3 (стихири свята дивитися на той самий день, служба святих мучеників на «Господи, взиваю») і благовірного князя, глас 2-ий – 3. «Слава» – благовірного, глас 6-ий: «Радується нині град Чернігів...», «І нині» – Догматик, той самий: «Хто Тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 1-ий (зі своїми приспівами). «Слава» – благовірного, глас 6-ий: «Прийдіть, усі...», «І нині» – свята, глас 5-ий: «Слово пророків Твоїх...». (стихири свята дивитися на той самий день, служба святих мучеників, на стиховні вечора) Після Трисвятого – тропар благовірного, глас 4-ий. (тропар на вибір) «Слава, і нині» – тропар свята, глас 1-ий. На відпусті: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар благовірного, глас 4-ий (тропар на вибір), «І нині» – тропар свята, глас 1-ий. Кафизми 16-та і 17-та. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята з ірмосом на 8 (ірмоси по двічі) і благовірного на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (благовірного). Після 3-ої пісні – кондак благовірного, глас 6-ий; сідальний благовірного, глас 5-ий. «Слава, і нині» – сідальний свята, глас 1-ий (сідальний свята дивитися на той самий день, служба святих мучеників, після 3-ої пісні). Після 6-ої пісні – кондак та ікос свята, глас 4-ий (кондак та ікос дивитися на той самий день, служба святих мучеників, після 6-ої пісні). На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний благовірного. «Слава, і нині» – світильний свята (світильний дивитися на той самий день, служба святих мучеників, після 9-ої пісні). «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава» – благовірного, глас той самий: «Нині славний град Чернігів...» (славник на хвалітніх), «І нині» – свята, глас 5-ий (стихири дивитися на той самий день, служба святих мучеників, стихири на ранній). Після Трисвятого – тропар благовірного, глас 4-ий. «Слава, і нині» – тропар свята, глас 1-ий. На відпусті 1-го часу: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар благовірного. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 7-ма – 6 (з ірмосом). На вході: «Прийдіть поклонімось... Плоттю розіп’явся...». Після входу – тропарі і кондаки: У храмі Господньому – тропар свята, тропар благовірного. «Слава» – кондак благовірного, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар благовірного; кондак свята. «Слава» – кондак благовірного, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар благовірного; кондак храму. «Слава» – кондак благовірного, «І нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – суботи після Воздвиження, благовірного і дня (під зачало). Задостойник свята. На відпусті: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."}]},
{"date":"09-20","weekday":"неділя","title":"16-та неділя після П’ятдесятниці, після Воздвиження. Глас 7-й. Вмч. Євстафія Плакиди, дружини його Феопістії та синів їхніх Агапія та Феопіста (бл. 118). Мчч. та сповв. Михаїла, кн. Чернігівського, і боярина його Федора, чудотворців (1245). Прп. і блгв. кн. Чернігівського Олега Романовича (бл. 1285). Перенесення мощів мч. Парфенія Жовківського, Римського на Галичину (1784) (перехідне свято у неділю після Воздвиження).","glas":7,"readings":["Ран. – Єв. 5-е, Лк., 113 зач., XXIV, 12 – 35.","Літ. – неділі після Воздвиження: Гал., 203 зач., II, 16 – 20. Мк., 37 зач., VIII, 34 – IX, 1.","Ряд.: 2 Кор., 181 зач., VI, 1 – 10. Мф., 105 зач., XXV, 14 – 30 (під зачало).","Вмч.: Еф., 233 зач., VI, 10 – 17. Лк., 106 зач., XXI, 12 – 19."],"notes":"Служба вмч. Євстафія шестерична в поєднанні зі службою післясвята Воздвиження і недільною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 7-ий – 3, свята, глас 4-ий – 3 і великомученика, глас 8-ий – 4. «Слава» – великомученика, глас 2-ий: «Другий Іов...», «І нині» – догматик глас 7-ий: «Матір’ю надприродностала Ти...». Вхід. Прокимен дня. На литії стихира свята, глас 2-ий (дивитися в Мінеї 20 вересня, на стиховні вечірні, без приспівів). «Слава» – великомученика, глас 8-ий: «Як Павло, прийняв покликання не від людей...» (дивитися на стиховні на ранній), «І нині» – свята, глас той самий: «Слова пророка Твого Мойсея...» (дивитися на стиховні на ранній). На стиховні стихири недільні, глас 7-ий. «Слава» – великомученика, глас 6-ий: «Адамант душею...», «І нині» – свята, глас той самий: «Хресте Христів...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар свята, глас 1-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар недільний, глас 7-ий (двічі). «Слава» – тропар великомученика, глас 4-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 2-га і 3-тя. Малі єктенії. Сідальні недільні. Непорочні. «Ангельський собор...». Іпакої, ступеневі і прокимен – гласу. Євангеліє воскресне 5-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира недільна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: недільний з ірмосом на 4 (ірмоси раз), Богородиці (Октоїха) на 2, свята на 4 і великомученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». Після 3-ої пісні – кондак та ікос свята, глас 4-ий, кондак та ікос великомученика, глас 2-ий; сідальний великомученика, глас 8-ий, «Слава, і нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос неділі, глас 7-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 5-ий. «Слава» – Світильний великомученика: «Безсмертну славу...», «І нині» – світильний свята: «Ми, на Тебе уповаючи...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: недільні, глас 7-ий – 4, і великомученика, глас 4-ий, глас 6-ий і 8-ий: (Зі славником: «Начальствування над земним...» і своїми приспівами). «Слава» – стихира євангельська 5-та, «І нині» – «Преблагословенна Ти...». Велике славослів’я. Після Трисвятого – тропар недільний: «У день спасіння...». Відпуст недільний: «Христос, що воскрес із мертвих, істинний Бог наш, молитвами Пречистої Своєї Матері, силою Чесного і Животворчого Хреста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ На 1-му та 6му часі – тропар недільний. «Слава» тропар свята. Кондак свята На 3-му та 9-му часі – тропар недільний. «Слава» тропар великомученика. Кондак недільний"},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласа – 4, свята, пісня 8-ма – 4, і великомученик, пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар недільний, тропар свята, тропар великомученика. Кондак недільний, «Слава» – кондак великомученика, «І нині» – кондак свята. У храмі Богородиці і святого – тропар недільний, тропар свята, тропар храму, тропар великомученика; кондак недільний, кондак храму. «Слава» – кондак великомученика, «І нині» – кондак свята. Прокимен, алилуарій – неділі після возвиження (тобто святу) і великомученика. Апостол і Євангеліє – неділі після Воздвиження, дня (під зачало) і великомученика. Задостойник свята. Причасний – недільний і великомученика."}]},
{"date":"09-21","weekday":"понеділок","title":"17-й тиждень після П’ятдесятниці. Віддання свята Воздвиження Животворчого Хреста Господнього. Ап. від 70-х Кодрата (бл. 130). Знайдення мощів свт. Димитрія (Туптала), митр. Ростовського (1752). Сщмчч. Іпатія, єпископа, та Андрія, пресвіт. (бл. 730 – 735). Свтт. Ісакія і Мелетія, єпп. Кіпрських. Мчч. Євсевія і Приска.","readings":["Ран. – Ін., 35 зач. (від пол.), X, 1 – 9.","Літ. – Еф., 219 зач., I, 22 – II, 3. Мк., 48 зач., X, 46 – 52.","Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16."],"notes":"Звершуємо славослівну службу відання свята Воздвиження з полієлйною службою святителя Димитрія (Туптала).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 10: свята, глас 6-ий – 6 (кожна стихира – двічі), і святителя, глас 8-ий – 4 (перша стихира двічі). «Слава» – святителя, глас той самий: «Прекрасні ноги, які благовістують мир...», «І нині» – свята, глас 6-ий: «Прийдіть, усі народи...» Вхід. Прокимен дня. Паремії святителя – 3. На стиховні стихири свята, глас 5-ий (з приспівами своїми). «Слава» – святителя, глас 4-ий: «Радіймо тзібрання вірних...», «І нині» – свята, глас 8-ий: «Тебе Мойсей прообразував собою...». Після Трисвятого – тропар святителя, глас 8-ий. «Слава, і нині» – тропар свята, глас 1-ий. На відпусту: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 1-ий (двічі). «Слава» – тропар святителя, глас 8-ий, «І нині» – тропар свята, глас 1-ий. Кафизми 4-та і 5-та. Малі єктенії. Сідальні свята. Полієлей. Величання святителя і вибраний псалом. Сідальний святителя (після 1-ої кафізми), глас 3-ій «Марфа і Марія...», сідальний святителя (після 2-ої кафізми), глас 8-ий «Як на сідалищі сіли...». «Слава» – сідальний святителя після полієлея, глас 7-ий: «Як фінікс, розквітнув...», «І нині» – сідальний свята після полієлея, глас 8-ий: «В раю мене спочатку...». Ступеневі, 4-го гласу, антифон 1-ий. Прокимен святителя, глас 4-ий. Євангеліє – святителя. Після 50-го псалма: «Слава» – «Молитвами святителя...». Стихира святителя, глас 6-ий: «Вилилася благодать...». Канони: свята з ірмосом на 8 (ірмоси по двічі) і святителя на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Хрест накреслив...». В 9-ій пісні катавасія – ірмоси: «Таємний Ти, Богородице рай...» і «Спожива древа...» (з приспівами). Після 3-ої пісні кондак і ікос святителя, глас 8-ий, сідальний святителя, глас той самий. «Слава, і нині» – сідальний свята, глас 4-ий. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні «Чеснішу» не співаємо, але до канонів свята Воздвиження Хреста Господнього співаємо приспіви свята (див. на ранній в сам день свята). 1-й приспів: «Величай, душе моя, Пречесний Хрест Господній». (Звершується звичайне кадіння). Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава» – світильний святителя, «І нині» – інший світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: свята, глас 8-ий – 3 і святителя, глас 6-ий – 3, «Слава» – святителя, глас той самий: «Заспівай Русь, Господеві...», «І нині» – свята, глас той самий: «Нині підноситься хрест Господній...». Велике славослів’я. Після Трисвятого – тропар святителя, глас 8-ий. «Слава, і нині» – тропар свята, глас 1-ий. На відпусту: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святителя; кондак свята і святителя читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні свята, пісня 9-та – 8 (з ірмосом 1-го канону). І святителя, пісня 3-тя – 4. На вході: «Прийдіть поклонімось... що Плоттю Розіп’явся...». Після входу – тропар свята, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята і святителя. Апостол і Євангеліє – дня і святителя. Задостойник свята. На відпусту: «Христос Істинний Бог наш... силою Чесного і Животворчого Хреста...». Після відпусту Літургії священик виходить через царські врата з кадилом, у супроводі диякона зі свічкою, і тричі кадить Хрест на аналої; за традицією, хор в цей час співає тропар свята, «Слава, і нині» – кондак свята. Потім ієрей кладе Чесний Хрест на главу і в супроводі диякона зі свічкою і кадилом царськими вратами вносить Хрест у вівтар, кладе на престолі і кадить навколо престолу. Після закриття царських врат і завіси Хрест благоговійно відноситься до місця його зберігання. Примітка. Після віддання свята Воздвиження, після 21 вересня (і до 20 грудня), на ранній береться три кафизми; на вечірні – кафизма 18-а. Якщо припаде пам’ять святого, який має полієлей, на ранній береться дві рядові кафизми, а на вечірні (замість 18-ої) – третя, звичайна. Читання Псалтиря починається з неділі. Див. Типікон, 21 вересня, 1-е «див». У недільні дні в період після 21 вересня до 20 грудня на ранній береться дві кафизми, до яких приєднується полієлей. У недільні дні в період після 20 грудня до 14 січня (віддання свята Богоявлення) полієлей не співається, окрім тих днів, коли припаде пам’ять великого святого, який має полієлей. Після 14 січня полієлей співається в усі неділі, до неділі сиропусної включно (див. Типікон, 21 вересня, 1-е «див»), крім неділі про митаря і фарисея (див. Типікон, гл. 49). Катавасія після 21 вересня до 21 листопада – «Відкрию уста мої...»."}]},
{"date":"09-22","weekday":"вівторок","title":"Прор. Іони (VІІІ ст. до Р. Х.). Сщмч. Фоки, єп. Синопського (117). Прп. Іони, пресвітера (ІХ), батька сщмч. Феофана, єп., творця канонів, і прмч. Федора, Накреслених. Мч. Фоки Синопського, садівника (бл. 320). Прав. Петра, колишнього митаря (VІ).","readings":["Еф., 222 зач., II, 19 – III, 7. Мк., 50 зач., XI, 11 – 23.","Сщмч.: Євр., 311 зач., IV, 14 – V, 6. Ін., 36 зач., X, 9 – 16."],"notes":"Служби ап. Кодрата (з 21 вересня) і сщмч. Фоки не мають святкового знака, звершуємо зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-та. На «Господи, взиваю» стихири на 6: апостола, глас 4-ий – 3, і священномученика, глас 1-ий – 3. «Слава» – священномученика, глас 4-ий: «З дитинства ти полюбив Господа...», «І нині» – Богородичний, по гласу «Слави», від менших: «Визволи нас від бід наших...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Радуйся, сонця духовного...». Після Трисвятого – тропар апостола, глас 3-ій. «Слава» – тропар священномученика, глас 4-ий, «І нині» – Богородичний за гласом тропаря, від менших: «До Богородиці, щиро нині звернімося ми...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 3-ій (двічі). «Слава» – тропар священномученика, глас 4-ий, «І нині» – Богородичний за гласом тропаря, від менших: «До Богородиці, щиро нині звернімося ми...». Кафизми 7-ма, 8-ма і 9-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), апостола на 4, і священномученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісні – ірмоси канону Мінеї (священномученика). Після 3-ої пісні – кондак та ікос священномученика, глас 6-ий; сідальний апостола, глас 3-ій. «Слава» – сідальний священномученика, глас 1-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос папостола, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха, світильний апостола. «Слава» – світильний священномученика, «І нині» – Хрестобогородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар апостола, глас 3-ій. «Слава» – тропар священномученика, глас 4-ий, «І нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар апостола. «Слава» – тропар священномученика. Кондаки священномученика і апостола читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар апостола, тропар священномученика; кондак дня, кондак апостола, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар апостола, тропар священномученика; кондак дня, кондак храму, кондак апостола, священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і священномученика. Апостол і Євангеліє – дня і священномученика."}]},
{"date":"09-23","weekday":"середа","title":"Зачаття чесного славного пророка, Предтечі і Хрестителя Іоана. Прпп. жінок Ксанфипи та Поліксенії (109). Мц. Іраїди (Раїси), діви (бл. 308). Мчч. Андрія, Іоана і синів Іоанових Петра та Антоніна (ІХ).","readings":["Еф., 223 зач., III, 8 – 21. Мк., 51 зач., XI, 23 – 26.","Предтечі: Гал., 210 зач. (від половини), IV, 22 – 31. Лк., 2 зач., I, 5 – 25."],"notes":"Служба Зачаття Іоана Предтечі славослівна, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири Предтечі, глас 4-ий – 6 (кожна стихира – двічі). «Слава» – Предтечі, глас 6-ий: «Нині від неплідної утроби...», «І нині» – Догматик, глас той самий: «Хто тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири Предтечі, глас 6-ий (зі своїми приспівами). «Слава» – Предтечі, глас той самий: «Ангелом з неплідної утроби народився ти, Хрестителю...», «І нині» – Богородичний Мінеї, глас той самий: «Ніхто, з тих, що приходять до Тебе...». Після Трисвятого – тропар Предтечі, глас 4-ий. «Слава, і нині» – Богородичний недільний за гласом тропаря: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Предтечі, глас 4-ий (двічі). «Слава, і нині» – Богородичний недільний за гласом тропаря: «Від початку віку...». Кафизми 10-та, 11-та і 12-та. Малі ектенії. Сідальні Предтечі (двічі). Примітка. При славослівній службі (зі співом Октоїха), читання 3-ої рядової кафизми на ранній не відмінююється, після 1-ої і 2-ої – кафизми мала ектенія і сідальні предтечі (по двічі); після 3-ої кафизми ектенії немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичих, на 4 (ірмос один раз), 2-ий на 4 і Предтечі на 6. Біблійні пісні «Господеві співаймо...» (див. Типікон, 23 вересня, 1-ше «див»). Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний Предтечі, глас 4-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос Предтечі, глас 1-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний Предтечі (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Предтечі, глас 1-ий – 4. «Слава, і нині» – Предтечі, глас 6-ий: «Єлисавета зачала Предтечу благодаті...». Велике славослів’я. Після Трисвятого – тропар Предтечі, глас 4-ий. «Слава, і нині» – Богородичний недільний за гласом тропаря: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Предтечі."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Предтечі, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар Предтечі. «Слава» – кондак Предтечі, «І нині» – кондак храму. У храмі святого – тропар храму, тропар Предтечі; кондак храму. «Слава» – кондак Предтечі, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і Предтечі. Апостол і Євангеліє – дня і Предтечі."}]},
{"date":"09-24","weekday":"четвер","title":"Рівноап. Фекли, першомц. (І). Прп. Феодосія Манявського (1629). Прп. Копрія Палестинського (530). Св. кн. Стефана Сербського (1224) та сина його св. кн. Владислава Сербського (1230 – 1239). Прп. Силуана Афонського (1938).","readings":["Еф., 225 зач., IV, 14 – 19. Мк., 52 зач., XI, 27 – 33.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Служба переподобного Феодосія Манявського славослівна, звершуємо разом зі службою Октоїха. Службу можна відправляти за Загальною Мінеєю преподобному одному.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири преподобного, глас 8-ий – 6 (всі стихири по двічі). «Слава» – преподобного, глас 6-ий: «Те, що було образом...», «І нині» – догматик, глас той самий: «Хто тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири преподобного, глас 1-ий (зі своїми приспівами). «Слава» – преподобного, глас 8-ий: «Тебе як наставника...», «І нині» – Богородичний недільний за гласом «Слави»: «Неневісна Діво...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Ти, що заради нас...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 8-ий (двічі). «Слава, і нині» – Богородичний недільний, глас той самий: «Ти, що заради нас...». Кафизми 13-та, 14-та і 15-та. Малі єктенії. Сідальні преподобного (по двічі). Примітка. При славослівній службі (зі співом Октоїха), читання 3-ої рядової кафизми на ранній не відмінююється, після 1-ої і 2-ої – кафизми мала ектенія і сідальні преподобного (по двічі); після 3-ої кафизми ектенії немає. Сідальні Октоїха. Канони: Октоїха 1-ий з ірмосом, без мученичих, на 4 (ірмос один раз), 2-ий на 4 і преподобного на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний преподобного, глас 1-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний преподобного (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири преподобного, глас 6-ий – 4 (перша стихира – двічі). «Слава» – преподобного, глас 2-ий: «Преподобний отче...», «І нині» – Богородичний Мінеї, глас той самий: «Все уповання на тебепокладаю...». Велике славослів’я. Після Трисвятого – тропар преподобних, глас 8-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Ти, що заради нас...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні преподобного, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар храму, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"09-25","weekday":"п’ятниця","title":"Прп. Єфросинії Олександрійської (V). Прп. Сергія, ігум. Радонезького, чудотворця (1392). Прмч. Пафнутія єгиптянина і з ним 546 мчч. (ІІІ). Прп. Єфросинії, княжни Чернігівської, ігум. Суздальської (1250).","readings":["Еф., 226 зач., IV, 17 – 25. Мк., 53 зач., XII, 1 – 12 (за п’ятницю).","1 Кор., 156 зач., XIV, 20 – 25. Мф., 104 зач., XXV, 1 – 13 (за суботу)."],"notes":"Служба Преп. Єфросинії Олександрійської немає святкового знаку звершуємо зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 7-ий – 3, і преподобної, глас 5-ий – 3. «Слава» – преподобної, глас 2-ий: «Чистий скарб...», «І нині» – Хрестобогородичний Мінеї глас той самий: «Гроно дозріле...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава» – стихира преподобної, глас 6-ий. «І нині» – Хрестобогородичний Мінеї, глас той самий: «Агниця нескверна і непорочна...». Після Трисвятого – тропар преподобної, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Агнці і Пастиря...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобної, глас 8-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Агнця і Пастиря...». Кафизми 19-та, і 20-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4, і преподобної на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобної). Після 3-ої пісні – сідальний преподобної, глас 5-ий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобної, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний преподобної, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той самий. Після Трисвятого – тропар преподобної, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Плід утроби Твоєї...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобної."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У храмі Господньому – тропар дня: «Спаси, Господи...», тропар преподобної; кондак преподобної. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар преподобної; кондак дня: «Вознісся на Хрест...», кондак преподобної. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар преподобної; кондак дня «Вознісся на Хрест...», кондак храму, кондак преподобної. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня і за суботу."}]},
{"date":"09-26","weekday":"субота","title":"Апостола і євангеліста Іоана Богослова (початок ІІ).","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – Ап.: 1 Ін., 73 зач. (від половини), IV, 12 – 19. Ін., 61 зач., XIX, 25 – 27; XXI, 24 – 25."],"notes":"Звершуємо всенічне бдіння апостола Іоана Богослова.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири апостола, глас 1-ий – 8 (дві перші стихири – тричі, третя стихира – двічі). «Слава» – апостола, глас 2-ий: «Сина громового...», «І нині» – Догматик, глас 7-ий: «Матір’ю надприродно стала Ти...». Вхід. Прокимен дня. Паремії апостола – 3. На літії стихира храму і стихири апостола, глас 1-ий. «Слава» – апостола, глас 4-ий: «Возліг ти на груди...», «І нині» – Богородичний Мінеї, глас той сами: «З Отцем і Духом рівнославний Син...». На стиховні стихири апостола, глас 4-ий (зі своїми приспівами) «Слава» – апостола, глас 6-ий: «Апостоле Христів...», «І нині» – Богородичний недільний за гласом «Слави»: «Творець і Визволитель...». Після Трисвятого – тропар апостола, глас 2-ий (двічі) і «Богородице Діво...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 2-ий, (двічі). «Слава» – «І нині» – Богородичний недільний, глас 7-ий: «Як скарб нашого воскресіння...». Кафизми 16-та і 17-та. Малі єктенії. Сідальні апостола (двічі). Полієлей. Величання апостола: «Величаємо тебе, апостоле Христовий і євангелисте Іоане Богослове, і шануємо страждання і труди твої, ними ж потрудився ти у благовісті Христовому» і вибраний псалом. Сідальний апостола після полієлея, глас 8-ий: «Возліг ти на груди...» (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий: «Небесні двері...». Степенна – 1-ий антифон 4-го гласу. Прокимен – апостола, глас 4-ий: «По всій землі розійшлося віщування їх, і до кінців вселенної слова їх». Стих: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь». Євангеліє апостола. Після 50-го псалма: «Слава» – «Молитвами апостола і євангелиста Іоана Богослова...». Стихира апостола, глас 2-ий: «Богослове дівственнку...». Канони: У храмі Господньому і Богородиці – канон храму з ірмосом на 6 (ірмос двічі) і апостола (два канона) на 8. У храмі святого – канон Богородиці (з пройдешньої неділі) з імосом на 6 (ірмос двічі) і апостола (два канона) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний апостола, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 2-ий. На 9-й пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний апостола. «Слава» – інший світильний апостола, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостола, глас 8-ий – 4. «Слава» – апостола, глас той самий, «І нині» – «Владичице прийми молитви...» (див. в 2-му додатку Мінеї, глас 8-ий, у суботу на ранній). Велике славослів’я. Після Трисвятого – тропар апостола, глас 2-ий. «Слава, і нині» – Богородичний недільний, глас 7-ий: «Як скарб нашого воскресіння...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостола."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні апостола, 1-го канону пісня 3-тя – 4 (з ірмосом), 2-го канону пісня 6-та – 4. Після входу – тропарі та кондаки: У храмі Господньому і Богородиці – тропар храму, тропар апостола. «Слава» – кондак апостола, «І нині» – кондак храму. У храмі святого – тропар апостола. «Слава» – кондак апостола, «І нині» – «Заступництво християн...». Прокимен, алилуарій і причасний – апостола. Апостол і Євангеліє – апостола."}]},
{"date":"09-27","weekday":"неділя","title":"17-та неділя після П’ятдесятниці. Глас 8-й. Мчч. Калістрата і воїнів його: Гімнасія та інших (304). Апп. від 70-х: Марка, Аристарха і Зіни (І). Мц. Єпихарії Римської (ІІІ). Прп. Ігнатія Каппадокійського, ігум. (Х).","glas":8,"readings":["Ран. – Єв. 6-е, Лк., 114 зач., XXIV, 36 – 53.","Літ. – 2 Кор., 182 зач., VI, 16 – VII,1. Мф., 62 зач., XV, 21 – 28."],"notes":"Служба мч. Калістрата та воїнів його не має святкового знаку, звершуємо разом з недільною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 8-ий – 7, і мучеників, глас 8-ий – 3. «Слава» – мучеників, глас 4-ий: «До розп’яття Твого на Хресті...», «І нині» – Догматик глас 8-ий: «Цар Небесний...». Вхід. Прокимен дня. На літії стихири храму. На стиховні стихири недільні, глас 8-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Неневісна Діво...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар недільний, глас 8-ий (двічі). «Слава» – тропар мучеників, глас 4-ий, «І нині» – Богородичний недільний, глас той самий: «Ві початку віку...». Кафизми 2-га і 3-тя. Малі єктенії. Сідальні недільні. Полієлей. «Ангельський собор...». Іпакої, ступеневі і прокимен – гласу. Євангеліє воскресне 6-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира недільна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: недільний з ірмосом на 4 (ірмоси раз), хрестовоскресний на 3, Богородиці на 3 і мучеників на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос мучеників, глас 4-ий, інший кондак мучеників, глас той самий; сідальний мучеників, глас 5-ий. «Слава і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос неділі, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 6-ий. «Слава» – світильний мучеників, «І нині» – Богородичний недільного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири недільні, глас 8-ий – 8: «Слава» – стихира євангельська 6-та, «І нині» – «Преблагословенна Ти...». Велике славослів’я. Після Трисвятого – тропар недільний: «Воскрес із гробу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний. «Слава» – тропар мучеників; кондак тільки недільний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 8. Після входу – тропарі і кондаки: У храмі Господньому – тропар недільний, тропар мучеників. Кондак мучеників, «Слава» – інший кондак мучеників, «І нині» – кондак недільний. У храмі Богородиці – тропар недільний, тропар храму, тропар мучеників; кондак недільний, кондак мучеників. «Слава» – інший кондак мучеників, «І нині» – кондак храму. У храмі святого – тропар недільний, тропар храму, тропар мучеників; кондак недільний, кондак храму, кондак мучеників. «Слава» – інший кондак мучеників, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – неділі. Апостол і Євангеліє – дня."}]},
{"date":"09-28","weekday":"понеділок","title":"18-й тиждень після П’ятдесятниці. Прп. Харитона Сповідника (бл. 350). Собор преподобних отців Києво-Печерських, які в Ближніх печерах (прп. Антонія) спочивають: Антонія, засновника Лаври (1073), Прохора, чудотворця (1107), Іоана, посника (ХІІ), Юліанії, діви, кн. Ольшанської (бл. 1550), прмчч. Василія і Федора (1098), Полікарпа, архім. Києво-Печерського (1182), Варлаама, ігум. Києво-Печерського (1065), Никона, ігум. Києво-Печерського (1088), Даміана, пресвіт., цілителя (1071), Никодима, просфорника (ХІІ), Лаврентія, затворн., єп. Турівського (ХІІ), Афанасія, затворн. (бл. 1176), Еразма (бл. 1160), Луки, іконома Києво-Печерського (ХІІІ), Агапіта, лікаря безвідплатного (бл. 1095), Феофіла, затворника (ХІІ – ХІІІ), Феофіла та Іоана (ХІІ), Нектарія (ХІІ), Григорія, іконописця (ХІІ), сщмч. Кукші (ХІІ), Євстратія (ХІІІ), Єфрема, пресвітера (ХІІІ), Ієроніма, затв., чудотворця (ХІІІ), Іларіона, митр. Київського (близько 1053), Іоана, отрока Київського, сина мч. Федора Варяга (983), Меладія, старця чудотв. (ХІІІ), Павла Послушного (ХІІІ), Георгія (ХІІІ), Симеона, сщмч. єп. Переяславського (1230), Феоктиста, єп. Чернігівського (1123). Олексія (ХІІІ), Сави (ХІІІ), Сергія Послушного (ХІІІ), Меркурія, єп. Смоленського (1239), Пимена Багатохворобливого (1110), Нестора Літописця (бл. 1114), прмч. Євстратія (1097), Елладія, затворн. (ХІІ – ХІІІ), Єремії, прозорливого (бл. 1070), прмч. Мойсея Угрина (1031 – 1043), Іоана Багатостраждального (1160), Марка, гробокопача (ХІІ), Миколи Святоші, кн. Чернігівського, чудотворця (1143), мч. Григорія, чудотворця (1093), Онисима, затворн. (ХІІ – ХІІІ), Матфея, прозорливого (бл. 1085), Ісаї, чудотворця (1115), Авраамія Працелюбного (ХІІ – ХІІІ), Нифонта, єп. Новгородського (1156), Сильвестра (ХІІ), Пимена, посника (ХІІ), Онуфрія мовчазного (ХІІ), Анатолія, затворн. (ХІІ), Аліпія, іконописця (1114), Сисоя, затворн. (ХІІ – ХІІІ), Арефи, затворн. (бл. 1195), Спиридона, просфорника (ХІІ), Онисифора, спов. (1148), Симона, єп. Суздальського (ХІІ), Феофана, посника (ХІІ). Макарія (ХІІ), прмч. Анастасія, дияк. (ХІІ), дванадцятьох майстрів зодчих (ХІ), Авраамія, затворн. (ХІІ – ХІІІ), Ісакія, затворн. (бл. 1090), мчч. Іоана, немовляти, Іллі Муромця (бл. 1188), Никона Сухого (ХІІ), Єфрема, єп. Переяславського (бл. 1098), Тита, пресвітера (1190). Прор. Варуха (VІ ст. до Р. Х.). Мчч. Олександра, Алфея, Зосими, Марка, пастуха, Никона, Неона, Іліодора та ін. (ІV). Блгв. кн. В’ячеслава Чеського (935).","readings":["Ран. – Мф., 43 зач., XI, 27 – 30.","Літ. – Еф., 227 зач., IV, 25 – 32. Лк., 10 зач., III, 19 – 22.","Прпп.: 2 Кор., 176 зач., IV, 6 – 15. Лк., 24 зач., VI, 17 – 23."],"notes":"Звершуємо полієлейну службу всіх преподобних отців Києво-Печерських, що в Ближніх печерах (прп. Антонія) спочивають.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири преподобних, глас 6-ий – 6 (кожна стихира – двічі). «Слава» – преподобних, глас 8-ий: «Хто висловить силу Господню...», «І нині» – догматик, глас той самий: «Цар Небесний...». Вхід. Прокимен дня. Паремії преподобних – 3. На стиховні стихири преподобних, глас 4-ий (зі своїми приспівами). «Слава» – преподобних, глас 6-ий: «Царю слави...», «І нині» – Богородичний недільний за гласом «Слави»: «Творець і Визволитель...». Після Трисвятого – тропар преподобних, глас 4-ий. «Слава, і нині» – Богородичний недільний, глас той же: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобних, глас 4-ий (двічі). «Слава, і нині» – Богородичний недільний, глас той же: «Від початку віку утаємнене...». Кафизми 4-та і 5-та. Малі єктенії. Сідальні преподобних (по двічі). Полієлей. Величання преподобних: «Ублажаємо вас,/ преподобні отці наші Києво-Печерські,/ і шануємо святу пам’ять вашу,/ бо ви молите за нас// Христа Бога нашого» і вибраний псалом: «Радуйтеся, праведні, у Господі, праведним подобає похвала». Сідальний преподобних після полієлея, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен преподобних, глас 4-ий: «Дивний Бог у святих Своїх, Бог Ізраїлів»; стих: «В церквах благословляйте Бога, Господа від джерел Ізраїлевих». Євангеліє – преподобних: Мф. Зач 10. Після 50-го псалма: «Слава» – «Молитвами преподобних отців наших Києво-Печерських...». Стихира преподобних, глас 8-ий: «Хто висловить силу Господню...», (дивитися на «Господи Взиваю» на вечірній). Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і преподобних на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний преподобних, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобних, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний преподобних (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири преподобних, глас 2-ий – 4 (перша стихира – двічі). «Слава» – преподобних, глас 8-ий: «З великою пошаною...», «І нині» – Богородичний Мінеї, глас той самий: «Владичице, прийми молитви рабів Твоїх, і визволи нас від усякої недолі і скорботи...». Велике славослів’я. Після Трисвятого – тропар преподобних, глас 4-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропарі і кондаки преподобних читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні преподобних, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар преподобних, інший тропар преподобних; інший кондак преподобних. «Слава» – кондак преподобних, «І нині» – кондак храму. У храмі святого – тропар храму, тропар преподобних, інший тропар преподобних; кондак храму; інший кондак преподобних. «Слава» – кондак преподобних, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – преподобних. Апостол і Євангеліє – преподобних і дня."}]},
{"date":"09-29","weekday":"вівторок","title":"Прп. Киріака, пустельника (556). Мчч. Дади, Гаведдая і Каздої (ІV). Прп. Феофана Милостивого.","readings":["Еф., 230 зач., V, 20 – 26. Лк., 11 зач., III, 23 – IV, 1."],"notes":"Служба прп. Киріака немає святкового знаку, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-та. (яка не була прочитана на ранній понеділка). На «Господи, взиваю» стихири Октоїха глас 8-ий – 3, і преподобного, глас той самий – 3. «Слава» – преподобного, глас той самий: «Ченців безліч наставника тебе шануємо...», «І нині» – Богородичний від менших за гласом «Слави»: «Радуйся, Владичице...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава» – преподобного, глас 6-ий: «Преподобний отче...», «І нині» – Богородичний від менших, за гласом «Слави»: «Ніхто, що звертається до Тебе...». Після Трисвятого – тропар преподобного, глас 1-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Благодатна Богородице...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 1-ий (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Благодатна Богородице...». Кафизми 7-ма, 8-ма і 9-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 6 (ірмоса один раз), 2-ий на 4 і преподобного на 4. Біблійні пісні «Господеві Співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісні – ірмос канону Мінеї. Після 3-ої пісні – інший кондак преподобного, глас 8-ий; сідальний преподобного, глас 5-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 5-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – Екзапостиларій Октоїха. «Слава» – світильний преподобного, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На стиховні стихири Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава» – преподобного, глас 5-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Благодатна, Твоїми молитвами...». Після Трисвятого – тропар преподобного, глас 1-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Того, Хто без матері на небесах...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобного. Кондаки преподобного поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4 і преподобного, пісня 3-тя – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар преподобного; кондак дня, кондак преподобного, інший кондак преподобного «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар преподобного; кондак дня, кондак храму, кондак преподобного, інший кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"09-30","weekday":"середа","title":"Сщмч. Григорія, єп., просвітителя Вірменії (бл. 335). Свт. Михаїла, першого митр. Київського і всієї Руси (992). Мцц. Рипсимії, Гаянії і з ними 35 святих дів (поч. ІV).","readings":["Ран. – Ін., 35 зач. (від пол.), X, 1 – 9.","Літ. – Еф., 231 зач., V, 25 – 33. Лк., 12 зач., IV, 1 – 15.","Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16."],"notes":"Звершуємо полієлейну службу свт. Михаїла, митрополита Київського.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири святителя, глас 5-ий – 6 (кожна стихира – двічі).«Слава» – святителя, глас 3-ій: «Свідка істини...», «І нині» – догматик, глас той самий: «Як нам не дивуватися...». Вхід. Прокимен дня. Паремії святителя – 3. На стиховні стихири святителя, глас 2-ий (зі своїми приспівами). «Слава» – святителя, глас 6-ий: «Божественний дух...», «І нині» – Богородичний: «Богородице, Ти єси лоза істинна...» (дивитися часослов, Богородичний 3-го часу). Після Трисвятого – тропар святителя, глас 4-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 4-ий (двічі). «Слава, і нині» – Богородичний недільний, глас той самий: «Від початку віку...». Кафизми 10-та і 11-та. Малі єктенії. Сідальні святителя (по двічі). Полієлей. Величання святителя: «Величаємо тебе,/ святителю отче Михаїле, і шануємо святу пам’ять твою,/ бо ти молиш за нас,// Христа Бога нашого» і вибраний псалом: «Блажен муж, що боїться Господа». Сідальний святителя після полієлея, глас 8-ий: «Як начальнику архієреїв...» (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий: «Як істина утіха всіх скорботних...». Степенна – 1-ий антифон 4-го гласу. Прокимен святителя, глас 4-ий: «Чесна перед Господом смерть преподобних Його». Стих: «Що воздам Господеві за все, що Він воздав мені?». Євангеліє святителя. Після 50-го псалма: «Слава» – «Молитвами святителя...». Стихира святителя, глас 6-ий: «До Духа Божественного...» (див. «Слава» на стиховні) або інша стихира на глас 3-ій: «Свідка істини...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і святителя на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний святителя, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос святителя, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ій пісні «Достойно є» не співається. Світильний святителя (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири святителя, глас 1-ий – 4 (перша стихира – двічі). «Слава» – святителя, глас 2-ий: «З Небес прийнявши духовне помазання...», «І нині» – Богородичний, глас той самий: «Спаси від бід рабів Твоїх...» (дивитися Богродичні що співаються на «Слава» 2-ий глас в п’ятницю вечора). Велике славослів’я. Після Трисвятого – тропар святителя, глас 4-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні святителя, пісня 3-тя – 4 (з ірмосом), і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"10-01","weekday":"четвер","title":"Покрова Пресвятої Владичиці нашої Богородиці і Приснодіви Марії. Ап. від 70-х Ананії (І). Прп. Романа Солодкоспівця, дияк. (бл. 556). Мч. Домніна Солунського (ІV). Прмч. Михаїла, ігумена Зовійського, і з ним 36 прмчч. (780 – 790). Святкування на честь хітона Господнього і Стовпа Животворчого (Груз.). Прп. Іоана Кукузеля, піснеписця (бл. 1360). Люблінської, Касперівської, Гербовецької, Барської та «Ласкава Станіславська» ікон Божої Матері.","readings":["Ран. – Лк., 4 зач., I, 39 – 49, 56.","Літ. – Богородиці: Євр., 320 зач., IX, 1 – 7. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершуємо бдінну службу свята Покрови Пресвятої Богородиці.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири Богородиці, глас 1-ий і глас 4-ий – 8 (перша стихира двічі). «Слава, і нині» – свята, глас 8-ий: «Радіють з нами всі...». Вхід. Прокимен дня. Паремії Богородиці – 3. На літії стихири Богородиці, глас 3-ій, глас 4-ій і глас 2-ий. «Слава, і нині» – Богородиці, глас 2-ий: «Розум очистивши...». На стиховні стихири Богородиці, глас 2-ий, глас 5-ий і глас 7-ий (зі своїми приспівами). «Слава, і нині» – Богородиці, глас 2-ий: «Як вінком пресвітлим...». Після Трисвятого – тропар Богородиці (Покрова), глас 4-ий (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Богородиці, глас 4-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 13-та і 14-та. Малі єктенії. Сідальні Богородиці (по двічі). Полієлей. Величання Богородиці: «Величаємо Тебе,/ Пресвята Діво,/ і шануємо покров Твій чесний,/Тебе бо святий Андрій бачив у повітрі,// як Ти за нас Христу молишся», і вибраний псалом. Сідальний свята після полієлея, глас 4-ий: «Воістину чесніший...». «Слава, і нині» – той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен свята, глас 4-ий: «Пом’яну ім’я Твоє у всякому роді і роді»; стих: «Лицю Твоєму помоляться багаті народи». Євангеліє – Богородиці (Лк., Зач. 4). Після 50-го псалма: «Слава» – «Молитвами Богородиці...», «І нині» – той самий. Стихира свята, глас 6-ий: «Радіють з нами всі...». Канони: канон Богородиці з ірмосом на 12 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний свята, глас 5-ий. «Слава, і нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос свята, глас 3-ій. На 9-ій пісні – співаємо «Чеснішу» Після 9-ої пісні «Достойно є» не співається. Світильний свята (двічі). «Слава, і нині» – світильний свята той самий. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 8-ий – 4 (перша стихира – двічі). «Слава, і нині» – свята, глас 6-ий: «Як бачив Тебе праведний Андрій...». Велике славослів’я. Після Трисвятого – тропар свята, глас 4-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні свята: пісня 3-тя і пісня 6-та – 8. Після входу – тропар Богородиці (Покрова). «Слава, і нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – свята."}]},
{"date":"10-02","weekday":"п’ятниця","title":"Сщмч. Кипріана, єп., мц. Юстини та мч. Феоктиста (304). Прав. Андрія Константинопольського, юродивого заради Христа (936). Мчч. Давида і Костянтина, князів Арагветських (740, Груз.).","readings":["Еф., 232 зач., V, 33 – VI, 9. Лк., 13 зач., IV, 16 – 22 (за четвер, під зачало).","Еф., 234 зач., VI, 18 – 24. Лк., 14 зач., IV, 22 – 30 (за п’ятницю).","Свв.: 1 Тим., 280 зач., I, 12 – 17. Ін., 36 зач., X, 9 – 16."],"notes":"Служба сщмч. Кипріана і мц. Юстини немає святкового знаку, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихир 6: Октоїха, глас 8-ий 3 і святих, глас 4-ий – 3. «Слава» – священномученика, глас 2-ий: «Ти відкинув ідольське вчення...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Побачивши Тебе, Ісусе...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава» – священномученика, глас 2-ий: «Богосяяного світильника...». «І нині» – Хрестобогородичний Мінеї, глас той самий: «Коли побачила нескверна Агниця...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-ий (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...». Кафизми 19-та і 20-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 6 (ірмоси раз), 2-ий на 4, і святих на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний священномученика, глас 8-ий (двічі). «Слава і нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос святих, глас 1-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний священномученика, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава» – святих, глас той самий: «Той, хто раніше був небезпечним поборником...» «І нині» – Хрестобогородичний Мінеї: «Що це за видіння...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар священномученика і кондак святих."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні октоїха – 4 і святих, пісня 3-тя – 4. Після вході – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси, Господи...», тропар священомученика; кондак святих. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар священномученика; кондак дня: «Вознісся на Хрест...», кондак святих. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар священномученика; кондак дня: «Вознісся на Хрест...», кондак храму, кондак святих. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і святих. Апостол і Євангеліє – за четвер (під зачало), дня і святих."}]},
{"date":"10-03","weekday":"субота","title":"Сщмчч. Діонісія Ареопагіта, єп. Афінського, Рустика, пресвітера, та Єлевферія, диякона (96). Прп. Діонісія, затворника Києво-Печерського, в Дальніх печерах (ХV). Прп. Іоана Хозевіта, єп. Кесарійського (VІ). Св. Ісихія Хоривіта (VІ).","readings":["Сщмчч.: Діян., 40 зач., XVII, 16 – 34. Мф., 55 зач., XIII, 44 – 54.","Ряд.: 1 Кор., 162 зач., XV, 39 – 45. Лк., 15 зач., IV, 31 – 36."],"notes":"Служба сщмч. Діонісія Ареопагіта шестерична, звершуємо разом з суботньою службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми 18-та. На «Господи, взиваю» стихири священномученика, глас 1-ий – 3 і інші стихири священномученика, глас той самий – 3. «Слава» – священномученика, глас 2-ий: «Прийдіть, вірні...», «І нині» – Догматик, глас 8-ий: «Цар Небесний...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий (мученичі з числа стихир на «Господи взиваю» – 1-ий «Мученики Господні...», 2-ий «Мученики Твої, Господи...», 3-ій «Які чесноти і яка похвала подобає святим...», приспіви звичайні зі стиховні – Часослова). «Слава» – священномученика, глас 4-ий: «Небесного знання...». «І нині» – Богородичний, за гласом «Слави», від менших: «Світильнику невгасимий...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Богородичний недільний, глас 8-ий: «Ти, що заради нас народився від Діви...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар священномученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний недільний, за гласом тропаря: «Від початку віку...». Кафизми 16-та і 17-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: У храмі Воскресіння Христового – конон воскресний рядового гласу (з пройдешньої неділі) з ірмосом на 4 (ірмоси раз), священномученика на 6 і Октоїха (мученичний) на 4. Примітка. Про спів канонів у храмі Воскресіння Христового в суботу дивитися Октох, частина 2, с.782. У храмі Господньому і Богородиці – канон храму з ірмосом на 4 (ірмоси двічі), священномученика на 6 і Октоїха (мученичий) на 4. У Храмі святого – канон священномученика з ірмосом на 6 (ірмоси двічі), храму на 4 і Октоїха (мученичий) на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичного канону Октоїха. Після 3-ої пісні – сідальний священномученика, глас 8-ий (двічі). «Слава і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос священномученика, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». світильний священномученика. «Слава» – екзапостиларій Октоїха, «І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий (мученичі з числа стихир на хвалітніх – 1-ий: «Великий подвиг ваш...», 2-ий: «Мученики Христові непереможні...», 3-ій: «У броню віри одягнувшись...»; приспіви звичайні зі стиховні – Часослова). «Слава» – священномученика, глас той самий, «І нині» – Богородичний за гласом «Слави», від менших: «Владичице, прийми молитви рабів Твоїх...». Після Трисвятого – тропар священномученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак священномученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні священномученика пісня 3-тя – 4 (з ірмосом) і Октоїха – 4. Після вході – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня: «Апостоли, мученики і пророки...», тропар священномученика; кондак храму, кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак: «Як первістки природи...». У храмі святого – тропар дня: «Апостоли, мученики і пророки...», тропар священномученика; кондак священномученика. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». Прокимен, алилуарій і причасний – священномученика і дня. Апостол і Євангеліє – священномученика і дня."}]},
{"date":"10-04","weekday":"неділя","title":"18-та неділя після П’ятдесятниці. Глас 1-й. Сщмч. Ієрофея, єп. Афінського (І). Сщмчч. Гая, Фавста, Євсевія і Херимона, дияконів (ІІІ). Сщмч. Петра Капітолійського, пресвіт. (ІІІ – ІV). Мцц. Домніни та дочок її Віринеї (Вероніки) і Проскудії (Просдоки) (305 – 306). Прп. Амона Нітрійського (бл. 350). Прп. Павла Препростого (ІV). Мч. Давикта (Адавкта) і дочки його св. Калісфенії (ІV). Блгв. кн. Володимира Ярославовича, Новгородського чудотворця (1052). Прпп. Елладія й Онисима, затворників Києво-Печерських, в Ближніх печерах (ХІІ – ХІІІ). Прп. Аммона, затворника Києво-Печерського, в Дальніх печерах (ХІІІ). Св. Стефана Щиляновича (1515, Серб.).","glas":1,"readings":["Ран. – Єв. 7-е, Ін., 63 зач., XX, 1 – 10.","Літ. – 2 Кор., 188 зач., IX, 6 – 11. Лк., 17 зач., V, 1 – 11."],"notes":"Служба сщмч. Єрофея, єп. Афінського без святкового знаку, звершуємо разом з недільною службою Октоїха. (Службу святого служимо із загальної Мінеї, с 489.).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 1-ий – 7, і священномученика, глас той самий – 3. «Слава» – священномученика, глас 6-й: «Священником істиним ти, блаженний...», «І нині» – догматик, глас 1-ий: «Всесвітню славу...». Вхід. Прокимен дня. На літії стихири храму. На стиховні стихири недільні, глас 1-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Ось сповнилося пророцтво Ісаї...». Після Трисвятого – «Богородице Діво» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар неділі, глас 1-ий (двічі). «Слава» – тропар священномученика, глас 4-ий, «І нині» – Богородичний недільний за глас той самий: «Від початку віку...». Кафизми 2-га і 3-тя. Малі єктенії. Сідальні недільні. Полієлей. «Ангельський собор...». Іпакої, Ступеневі і прокимен – гласу. Євангеліє недільне 7-ме. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира недільна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: недільний з ірмосом на 4 (ірмоси раз), Хрестовоскресний на 3, Богородиці (Октоїха) на 3 і священномученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відрию уста...». Після 3-ої пісні – кондак та ікос священномученика, глас 4-ий, сідальний священномученика, глас 3-ій. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос неділі, глас 1-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій неділі 7-ий. «Слава» – світильний священномученика, «І нині» – Богородичний недільного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири недільні, глас 1-ий – 8 «Слава» – євангельська стихира 7-ма, «І нині» – «Преблагословенна Ти...». Велике славослів’я. Після Трисвятого – тропар недільний: «У день спасіння...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний. «Слава» – тропар священномученика. Кондак тільки недільний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні гласу – 8. У храмі Господньому – тропар ніділі, тропар священномученика. «Слава» – кондак священномученика, «І нині» – кондак неділі. У храмі Богородиці – тропар неділі, тропар храму, тропар священномученика; кондак неділі. «Слава» – кондак священномученика, «І нині» – кондак храму. У храмі святого – тропар неділі, тропар храму, тропар священномученика; кондак недільний, кондак храму. «Слава» – кондак священномученика, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – Неділі. Апостол і Євангеліє – дня."}]},
{"date":"10-05","weekday":"понеділок","title":"19-й тиждень після П’ятдесятниці. Мц. Харитини (304). Прпп. Даміана, пресвіт., цілителя (1071), Єремії (бл. 1070) і Матфея (бл. 1085) прозорливих, Києво-Печерських, в Ближніх печерах. Сщмч. Діонісія, єп. Олександрійського (264 – 265). Мц. Мамелхви Перської (бл. 344). Прп. Григорія Хандзойського (861, Груз.).","readings":["Флп., 235 зач., I, 1 – 7. Лк., 16 зач., IV, 37 – 44."],"notes":"Служба мц. Харитини без святкового знака, звершуємо зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: Октоїха, глас 1-ий – 3 і мучениці, глас 4-ий – 3. «Слава, і нині» – Богородичний Мінеї, глас той самий: «Хмарами Пресвятого Духа...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар мучениці, глас 4-ий. «Слава, і нині» – Богородичний, по гласу тропаря: «Чудо чудес бачачи в Тобі...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучениці, глас 4-ий (двічі). «Слава, і нині» – Богородичний, по гласу тропаря: «Чудо чудес бачачи в Тобі...». Кафизми 4-та, 5-та і 6-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: 1-ий з Октоїха з ірмосом на 6 (ірмоси раз), 2-ий Октоїха на 4 і мучениці на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси останнього канону. Після 3-ої пісні – сідальний мучениці, глас 4-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мучениці, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є». Екзапостиларій Октоїха. «Слава і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар мучениці, глас 4-ий. «Слава, і нині» – Богородичний недільний за гласом тропаря: «Богородице, Ти вища від усіх творінь...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мучениці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха на 6. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар мучениці; кондак дня, кондак мучениці. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар мучениці; кондак дня, кондак храму, кондак мучениці. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"10-06","weekday":"вівторок","title":"Апостола Фоми (І). Сщмч. Никифора, архідияк., екзарха Константинопольського патріарха в Україні (1599).","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – Флп., 236 зач., I, 8 – 14. Лк., 18 зач., V, 12 – 16.","Ап.: 1 Кор., 131 зач., IV, 9 – 16. Ін., 65 зач., XX, 19 – 31."],"notes":"Звершуємо полієлейну службу апостола Фоми.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири апостола, глас 4-ий – 8, (перші дві стихири – тричі, третя стихира – двічі). «Слава» – апостола, глас 6-й: «Як служитель Слова...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії апостола – 3. На стиховні стихири апостола, глас 4-ий (зі своїми приспівами). «Слава» – апостола глас 6-ий: «Бачачи Божественну Христову мудрість...», «І нині» – Богородичний, глас той самий: «Богородице, Ти є лоза істинна...» (дивитися в Часослові – Богородичний, 3-го часу) Після Трисвятого – тропар апостола, глас 2-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Все вище розуму, Преславна Богородице...»"},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 2-ий (двічі). «Слава, і нині» – Богородичний недільний, глас той самий: «Все вище розуму, Преславна Богородице...». Кафизми 7-ма і 8-ма. Малі єктенії. Сідальні апостола. Полієлей. Величання апостола: «Величаємо тебе,/ апостоле Христів Фомо,/ і шануємо страждання і труди твої,/ що ними потрудився ти// у благовісті Христовім». і вибраний псалом: Сідальний апостола після полієлея, глас 3-ій (двічі). «Слава, і нині» – Богородичний мінеї, глас той самий: «Кожен, де спасається...». Степенна – 1-ий антифон 4-го гласу. Прокимен – апостола, глас 4-ий. Євангеліє – апостола. Після 50-го псалма: «Слава» – «Молитвами апостола...». Стихира апостола, глас 4-ий: «Христос, велике Сонце...». Канони: Богородиці з ірмосом на 6 (ірмоси двічі), і апостола на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний апостола, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний апостола. «Слава» – інший світильний апостола, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостола, глас 1-ий і глас 4-ий (перша стихира двічі). «Слава» – апостола, глас 6-ий «На колісниці чеснот їздячи...», «І нині» – Богорнодичний за гласом «Слави», від менших: «Великих дарів сподобилася Ти...». Велике славослів’я. Після Трисвятого – тропар апостола, глас 2-ий. «»Слава, і нині» – Богородичний недільний, глас той самий: «Все вище розуму...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостола."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні апостола, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. У храмі Господньому і Богородиці – тропар храму, тропар апостола. «Слава» – кондак апостола, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостола; кондак храму. «Слава» – кондак апостола, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – апостола. Апостол і Євангеліє – дня і апостола."}]},
{"date":"10-07","weekday":"середа","title":"Мчч. Сергія і Вакха (290 – 303). Прп. Сергія Послушного, Києво-Печерського, в Ближніх печерах (бл. ХІІІ). Сщмчч. Юліана, пресвітера, і Кесарія, диякона (І). Мц. Пелагеї, діви Тарсійської (290). Сщмч. Поліхронія, пресвітера (ІV).","readings":["Флп., 237 зач., I, 12 – 20. Лк., 21 зач., V, 33 – 39.","Мчч.: Євр., 330 зач., XI, 33 – XII, 2. Лк., 106 зач., XXI, 12 – 19."],"notes":"Служба мчч. Сергія і Вакха немає святкового знаку, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-та (яка не була прочитана у вівторок на ранній). На «Господи, взиваю» стихири на 6: Октоїха, глас 1-ий – 3 і мучеників, глас 6-ий – 3. «Слава» – мучеників, глас 4-ий: «Сергій і Вакх...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Бачачи розіпнутого Христа...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. «Слава» – мучеників, глас 8-ий, «І нині» – Хрестобогородичний Мінеї, глас той самий: «Що це за видіння...». Після Трисвятого – тропар мучеників, глас 5-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Хрестом Сина Твого...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучеників, глас 5-ий (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Хрестом Сина Твого...». Кафизми 10-та, 11-та і 12-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, на 6 (ірмоси раз), 2-ий на 4 і мучеників на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний мучеників, глас 8-ий. «Слава, і нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос мучеників, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Ексапостіларій Октоїха. «Слава» – світильний мучеників, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири мучеників, глас 1-ий і глас 4-ий – 4 (перша стихира – двічі). «Слава» – мучеників, глас 3-ій: «Що добре і що прекрасне...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Зброя пройшла серце Твоє...». «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий. «Слава» – мучеників, глас 2-ий, «І нині» – Хрестобогородичний Мінеї, глас той самий: «Коли непорочна Агниця...». Після Трисвятого – тропар мучеників, глас 5-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Христе Боже, що від Діви світові засяяв...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мучеників."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси Господи...», тропар мучеників; кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси Господи...», тропар храму, тропар мучеників; кондак дня: «Вознісся на Хрест...», кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси Господи...», тропар храму, тропар мучеників; кондак дня: «Вознісся на Хрест...», кондак храму, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і мучеників. Апостол і Євангеліє – дня і мучеників."}]},
{"date":"10-08","weekday":"четвер","title":"Прп. Пелагеї Палестинської (457). Прп. Таїсії Єгипетської (ІV). Мц. Пелагії, діви Антіохійської (303).","readings":["Флп., 238 зач., I, 20 – 27. Лк., 23 зач., VI, 12 – 19."],"notes":"Служба прп. Пелагеї не має святкового знака, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 1-ий – 3, і преподобній, глас 8-ий – 3. «Слава» – преподобній, глас 4-ий: «Там, де примножується гріх...», «І нині» – Богородичний за гласом «Слави», від менших: «Маючи Тебе, Богородице...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Радуйся, радосте прадідів...». Після Трисвятого – тропар преподобній, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Духовні врата життя...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобній, глас 8-ій (двічі). «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Духовні врата життя...». Кафизми 13-та, 14-та і 15-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4 і преподобній на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний преподобній, глас 8-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобній, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава, і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий. «Слава, і нині» – Богородичний Октоїха, глас той самий: «Радуйся, Богородице Діво...». Після Трисвятого – тропар преподобній, глас 8-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Діво Пречиста, спаси нас молитвами Твоїми...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобній."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, інший тропар дня, тропар преподобній; кондак дня, інший кондак дня, кондак преподобній. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, інший тропар дня, тропар храму, тропар преподобній; кондак дня, інший кондак дня, кондак храму, преподобній. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"10-09","weekday":"п’ятниця","title":"Апостола Якова Алфеєвого (І). Прпп. Андроніка та дружини його Афанасії (V). Прав. Авраама, праотця, і племінника його Лота (2000 до Р. Х.). Мчч. Євентія (Ювентина) і Максима, воїнів (361 – 363). Мц. Поплії (Публії), спов., диякониси Антіохійської (бл. 361 – 363). Прп. Петра Галатійського (ІХ).","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – Флп., 239 зач., I, 27 – II, 4. Лк., 24 зач., VI, 17 – 23.","Ап.: 1 Кор., 131 зач., IV, 9 – 16. Лк., 51 зач., X, 16 – 21."],"notes":"Звершуємо полієлейну службу святому апостолу Якову Алфеєву.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-й антифон. На «Господи, взиваю» стихири апостола, глас 4-ий – 8 (перші дві стихири – тричі, третя – двічі). «Слава» – апостола, глас той самий: «Явно прийнявши благодать Божественного Духа...», «І нині» – догматик, глас той самий: «Пророк Давид...». Вхід. Прокимен дня. Паремії апостола – 3. На стиховні стихири апостола, глас 4-ий (з приспівами своїми). «Слава» – апостола, глас 5-ий: «З вірою святкуємо...», «І нині» – Богородичний недільний, глас той самий: «Всечесна Діво, Ти – храм і двері...». Після Трисвятого – тропар апостола, глас 3-ій. «Слава, і нині» – Богородичний недільний, глас той жсамий: «Тебе, заступницю спасіння роду нашого...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 3-ій (двічі). «Слава, і нині» – Богородичний недільний, глас той самий: «Тебе, заступницю спасіння роду нашого...». Кафизми 19-та і 20-та. Малі єктенії. Сідальні апостола (по двічі). Полієлей. «Величаємо тебе,/ апостоле Христів Якове,/ і шануємо страждання і труди твої,/ що ними потрудився ти// у благовісті Христовім». І вибраний псалом: «Від сходу сонця і до заходу хвальне ім’я Господнє». Сідальний апостола після полієлея, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той же. Степенна – 1-ий антифон 4-го гласу. Прокимен, глас 4-ий: «По всій землі...». Євангеліє – апостола. Після 50-го псалма: «Слава» – «Молитвами святого апостола Якова...». Стихира апостола, глас 4-ий: «Як таїнник, і апостол...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і апостола на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний апостола, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ї пісні «Достойно є» не співається. Світильний апостола (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостола, глас 4-ий – 4 (перша стихира – двічі). «Слава» – апостола, глас 2-ий: «Залишивши земне...», «І нині» – Богородичний, глас той самий: «Все уповання моє...» (Дивитися у 2-му додатку Мінеї, у четвер на ранній). Велике славослів’я. Після Трисвятого – тропар апостола, глас 3-ій. «Слава, і нині» – Богородичний недільний, глас той самий: «Тебе, заступницю спасіння роду нашого...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостола."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні апостола, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар апостола. «Слава» – кондак апостола, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостола; кондак храму. «Слава» – кондак апостола, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – апостола. Апостол і Євангеліє – апостола і дня."}]},
{"date":"10-10","weekday":"субота","title":"Мч. Євлампія та мц. Євлампії (IV). Свт. Амфілохія Києво-Печерського, єп. Володимирського (1122). Собор Волинських святих. Мч. Феотекна Антіохійського (ІІІ – ІV). Прп. Вассіана Константинопольського, ігум. (V). Прп. Феофіла, спов. (VІІІ). Браїлівської ікони Божої Матері.","readings":["1 Кор., 164 зач., XV, 58 – XVI, 3. Лк., 19 зач., V, 17 – 26."],"notes":"Служба мч. Євлампія та мц. Євлампії без святкового знака, звершуємо зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми 18-та. На «Господи, взиваю» стихири мученикам, глас 4-ий – 6 (кожна стихира двічі). «Слава» – мученикам, глас 4-ий, «І нині» – Догматик, глас 1-ий: «Всесвітню славу...» Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. (мученичі з числа стихир на «Господи взиваю» – 1-ий «Молитвами, Господи, всіх святих...», 2-ий «Ваше сповідання, святії...», 3-ій «О, добра ваша купівля...», приспіви звичайні зі стиховні – Часослова). «Слава» – мученикам, глас 4-ий: «Троїчним світлом ...». «І нині» – Богородичний, за гласом «Слави», від менших: «Світильнику невгасимий...». Після Трисвятого – тропар мученикам, глас 4-ий. «Слава, і нині» – Богородичний недільний, глас 1-ий: «Коли Гавриїл звістив Тобі, Діво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мученикам, глас 4-ий (двічі). «Слава, і нині» – Богородичний недільний, за гласом тропаря: «Від початку віку...». Кафизми 16-та і 17-та. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: У храмі Воскресіння Христового – конон воскресний рядового гласу (з пройдешньої неділі) з ірмосом на 4 (ірмоси раз), мученикам на 4 і Октоїха (мученичний) на 4. Примітка. Про спів канонів у храмі Воскресіння Христового в суботу дивитися Октох, частина 1, с.831. У храмі Господньому і Богородиці – канон храму з ірмосом на 6 (ірмоси двічі), мученикам на 4 і Октоїха (мученичий) на 4. У Храмі святого – канон мученикам з ірмосом на 6 (ірмоси двічі), храму на 4 і Октоїха (мученичий) на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичного канону Октоїха. Після 3-ої пісні – сідальний мученикам, глас 8-ий (двічі). «Слава і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос мученикам, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». світильний мученикам. «Слава» – екзапостиларій Октоїха, «І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий (мученичі з числа стихир на хвалітніх – 1-ий: «Прийдіть, всі люди...», 2-ий: «Ці воїни Царя великого...», 3-ій: «Вас, всехвальні мученики...»; приспіви звичайні зі стиховні – Часослова). «Слава, і нині» – Богородичний Октоїха, глас той самий: «Христа ублагай...». Після Трисвятого – тропар мученикам, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мученикам."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6. Після вході – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня: «Апостоли, мученики і пророки...», тропар мученикам; кондак храму, кондак мученикам. «Слава» – «Зі святими упокой...», «І нині» – кондак: «Як первістки природи...». У храмі святого – тропар дня: «Апостоли, мученики і пророки...», тропар мученикам; кондак мученикам. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"10-11","weekday":"неділя","title":"19-та неділя після П’ятдесятниці. Глас 2-й. Пам’ять святих отців VІІ Вселенського собору (787) (перехідне святкування в неділю, найближчу до 11 жовтня). Ап. Филипа, одного з 7-ми дияконів (І). Прп. Феофана, сповідника, творця канонів, єп. Нікейського (бл. 850). Прп. Феофана, посника Києво-Печерського, в Ближніх печерах (ХІІ). Мцц. Зінаїди і Філоніли (І).","glas":2,"readings":["Ран. – Єв. 8-е, Ін., 64 зач., XX, 11 – 18.","Літ. – 2 Кор., 194 зач., XI, 31 – XII, 9. Лк., 26 зач., VI, 31 – 36.","Свв. отців: Євр., 334 зач., XIII, 7 – 16. Ін., 56 зач., XVII, 1 – 13."],"notes":"Недільна служба поєднується зі службою святим отцям VII Вселенського Собору (див. 11 жовтня в Мінеї). Служба Мінеї.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 2-ий – 4, і отців, глас 6-ий – 6 (перша стихира двічі). «Слава» – отців, глас той самий: «Нині прославимо богоносних отців, таємничі сурми Духа...», «І нині» – догматик, глас 2-ий: «Минула тінь закону...». Вхід. Прокимен дня. Паремії отців – 3. На літії стихира храму. «Слава» – отців, глас 3-ій: «Ви, святі отці...», «І нині» – Богородичний недільний, глас той самий: «Без мужа від Божественного Духа...». На стиховні стихири недільні, глас 2-ий. «Слава» – отців, глас 4-ий: «Нині молитовну пам’ять...», «І нині» – Богородичний недільний, глас той самий: «Зглянся на моління...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар отців, глас 8-ий: «Препрославлений Ти Христе Боже наш...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар недільний, глас 2-ий (двічі). «Слава» – тропар отців, глас 8-ий: «Препрославлений Ти Христе Боже наш...», «І нині» – Богородичний недільний, глас той самий: «Той, Хто заради нас народився від Діви...». Кафизми 2-га і 3-тя. Малі єктенії. Сідальні недільні. Полієлей. (Величання святих отців співається тільки в храмі на їх честь). «Ангельський собор...». Іпакої, степенні і прокимен – 2-го гласу. Євангеліє недільне 8-ме. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира недільна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси один раз), хрестовоскресний на 2, Богородиці (Октоїха) на 2 і отців на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос недільні, глас 2-ий; сідальний отців, глас 4-ий (двічі). «Слава, і нині» – Богоодичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос отців, глас 6-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 8-ий. «Слава» – світильний отців, «І нині» – Богородичний Мінеї: «Преблагий Господи, молитвами Твоєї Матері і святих отців...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: недільні, глас 2-ий – 4, і отців, глас 6-ий – 4 (перша стихира – двічі; з приспівами своїми (див. на ряду)). «Слава» – отців, глас 8-ий: «Святих отців Собор...», «І нині» – «Преблагословенна Ти...». Велике славослів’я. Після Трисвятого – тропар недільний: «Воскрес із гробу...». Перед 1-им часом на «Слава, і нині» – євангельська стихира 8-ма."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний. «Слава» – тропар отців. Кондаки недільний і отців читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і отців, пісня 3-тя – 4. Після входу – тропар недільний, тропар отців; кондак недільний. «Слава» – кондак отців, «І нині» – «Заступнице християн...» (в храмі Богородиці – кондак храму). Прокимен, алилуарій і причасний – неділі і отців. Апостол і Євангеліє – неділі і отців."}]},
{"date":"10-12","weekday":"понеділок","title":"20-й тиждень після П’ятдесятниці. Мчч. Прова, Тараха і Андроніка (304). Прп. Косми, єп. Маюмського, творця канонів (бл. 787). Мц. Домніки (286). Свт. Мартина Милостивого, єп. Турського (бл. 400). Єрусалимської (48), Рудненської (1687) ікон Божої Матері.","readings":["Флп., 241 зач., II, 12 – 16. Лк., 25 зач., VI, 24 – 30."],"notes":"Служба мчч. Прова, Тараха, Андроника і прп. Косми, єп. Маюмського, не має святкового знака, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: мучеників, глас 4-ий – 3, і преподобному, глас той самий – 3. «Слава» – мученикам, глас той самий: «Вооїни Христові...», «І нині» – Богородичний за гласом «Слави», від менших: «Радуйся, Маріє Богородице...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава» – мученикам, глас 1-ий: «Тричисельне зібрання...», «І нині» – Богородичний за гласом «Слави», від менших: «Пречиста Діво, радосте небесних чинів...». Після Трисвятого – тропар мучеників, глас 5-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Радуйся, бо Ти прийняла від ангела радість...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучеників, глас 5-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Радуйся, бо Ти прийняла від ангела радість...». Кафизми 4-та, 5-та і 6-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмос один раз), мучеників на 4 і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канона Мінеї (преподобного). Після 3-ої пісні – кондак преподобного, глас 8-ий. Сідальний мученикам, глас той самий. «Слава» – сідальний преподобного, глас той самий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос мучеників, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – Світильний мучеників, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ій. «Слава і нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар мучеників, глас 5-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Радуйся, врата Царя слави...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар мучеників, «Слава» – тропар преподобного. Кондаки читаються змінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар мучеників, тропар преподобного; кондак дня, кондак мучеників, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар мучеників, тропар преподобного; кондак дня, кондак храму, кондак мучеників, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"10-13","weekday":"вівторок","title":"Сщмчч. Карпа, єп. Фіатирського, Папили, диякона, мч. Агафодора і мц. Агафоніки (бл. 251). Прп. Веніаміна, затворника Києво-Печерського, в Дальніх печерах (ХІV). Мч. Флорентія Солунського (І – ІІ). Сщмч. Веніаміна, диякона (421 – 424). Прп. Микити, спов. (бл. 838). «Іверсько-Мирненської (Мироточивої)» ікони Божої Матері.","readings":["Флп., 242 зач., II, 16 – 23. Лк., 27 зач., VI, 37 – 45.","Богородиці: Флп., 240 зач., II, 5 – 11. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершуємо славослівну службу Богородиці зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ – кафизма 18-та. На «Господи, взиваю» стихири Богородиці, глас 1-ий –6, (перші дві стихири двічі). «Слава, і нині» – Богородичний Мінеї, глас 5-ий: «Прийдіть, люди...». Входу немає. Прокимен дня. На стиховні стихири Богородиці, глас 2-ий (зі своїми приспівами) «Слава, і нині» – Богородичний Мінеї, глас 6-ий: «Прийдемо до тихого пристановища...». Після Трисвятого – тропар Богородиці, глас 1-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Богородиці, глас 1-ий (двічі). «Слава, і нині» – тропар той самий. Кафизми 7-ма, 8-ма і 9-та. Малі єктенії. Сідальні Богородиці (після третьої кафизми, ектенії немає, сідальний Октоїха). 50-ий псалом. Канони: Октоїха 1-ий з ірмосом на 4 (без мученичних), 2-ий на 4 і Богородиці на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний Богородиці. «Слава, і нині» – той самий. Після 6-ої пісні – кондак та ікос Богородиці, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Екзапостиларій Богородиці «Слава, нині» – той самий. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Богородиці, глас 4-ий – 4, (перша стихира – двічі). «Слава, і нині» – «Твої слова виконуючи...». Велике славослів’я. Після Трисвятого – тропар Богородиці, глас 1-ий"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Богородиці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Після входу – тропарі і кондаки: У храмі Господньому – тропар храму, тропар Богородиці. «Слава» – кондак храму, «І нині» – кондак Богородиці. У храмі Богородиці – тропар Богородиці (ікони). «Слава, і нині» – кондак Богородиці (ікони). У храмі святого – тропар Богородиці, тропар храму. «Слава» – кондак храму, «І нині» – кондак Богородиці. Прокимен, алилуарій і причасний – дня і Богородиці. Апостол і Євангеліє – дня і Богородиці."}]},
{"date":"10-14","weekday":"середа","title":"Вишгородської ікони Божої Матері (І). Мчч. Назарія, Гервасія, Протасія, Келсія (І). Прп. Параскеви Сербської (ХІ). Прп. Миколи Святоші, кн. Чернігівського, Києво-Печерського чудотворця, в Ближніх печерах (1143). Сщмч. Сильвана, пресвітера Газького (ІV).","readings":["Ран. – Лк., 4 зач., I, 39 – 49, 56.","Літ. – Флп., 243 зач., II, 24 – 30. Лк., 28 зач., VI, 46 – VII, 1.","Богородиці: Євр., 320 зач., IX, 1 – 7. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершуємо полієлейну службу Богородиці. (Службу служимо з Мінеї Загальної, «служба загальна святам Богородичним» с. 319).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири Богородиці, глас 4-ий – 8 (перші дві стихири тричі, третя стихира двічі). «Слава, і нині» – Богородиці, глас 6-ий: «Як вінцем пресвітлим...» Вхід. Прокимен дня. Паремії Богородиці – 3 (паремії беремо з Мінеї місячної свято Покрова Пресвятої Богородиці. с. 7). На стиховні стихири Богородиці, глас 3-ий. (зі своїми приспівами) «Слава, і нині» – Богородиці, глас 2-ий: «Думки очистивши і розум...». Після Трисвятого – тропар Богородиці, глас 4-ий. (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Богородиці, глас 4-ий (двічі). «Слава, і нині» – той самий тропар. Кафизми 10-та і 11-та. Малі ектенії. Сідальні Богородиці (по двічі). Полієлей. Величання Богородиці: «Величаємо Тебе, Пресвятая Діво, Богом обрана Отроковице, і шануємо образ Твій святий, що ним подаєш зцілення всім, хто з вірою приходить» і вибраний псалом. Сідальний Богородиці після полієлея, глас 1-ий. «Слава, і нині» – той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен Богородиці, глас 4-ий: «Пом’яну ім’я Твоє у всякому роді і роді»; стих «Вилило серце моє слово благе». Євангеліє Богородиці. Після 50-го псалма: «Слава» – «Молитвами Богородиці...». Стихира Богородиці, глас 6-ий: «Нині небесні врата відкриваються...». Канони: Богородиці з ірмосом на 14 (ірмоси по двічі). Біблійні пісні «співаймо Господеві...». Катавасія «Відкрию уста мої...» Після 3-ої пісні – Кондак Богородиці, глас 1-ий: «Ти була чесною оселею...». «Слава, і нині» – сідальний Богородиці, глас 4-ий. Після 6-ої пісні – інший кондак та ікос Богородиці, глас 6-ий На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний Богородиці. «Слава, і нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Богородиці, глас 1-ий (перша стихира двічі). «Слава, і нині» – Богородиці, глас 8-ий: «Богородицю Марію всі прославимо...». Велике славослів’я. Після Трисвятого – тропар Богородиці, глас 4-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Богородиці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні Богородиці, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. На вході: «Прийдіть поклонімось... молитвами Богородиці...» Після входу – тропарі та кондаки: У храмі Господньому – тропар храму, тропар Богородиці. «Слава» – кондак храму, «І нині» – кондак Богородиці. У храмі Богородиці – тропар Богородиці. «Слава, і нині» – кондак Богородиці. У храмі святого – тропар Богородиці, тропар храму. «Слава» – кондак храму, «І нині» – кондак Богородиці. Прокимен, алилуарій і причасний – Богородиці. Апостол і Євангеліє – дня і Богородиці."}]},
{"date":"10-15","weekday":"четвер","title":"Прп. Євфимія Нового, Солунського, ієродияк. (898). Прмч. Лукіана, пресвітера Антіохійського (312). Сщмч. Лукіана, Києво-Печерського, в Дальніх печерах (1243). Мч. Сарвила та мц. Вевеї (ІІ). Свт. Савина, єп. Катанського (760). Ікони Божої Матері «Примноження хлібів» (ХІХ).","readings":["Флп., 244 зач., III, 1 – 8. Лк., 31 зач., VII, 17 – 30."],"notes":"Служба прп. Євфимія і прмч. Лукіана не має святкового знака, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та. (Яка не була прочитана на ранній в середу). На «Господи, взиваю» стихири на 6: преподобного, глас 4-ий – 3, і преподобномученика, глас той самий – 3. «Слава» – преподобномученика, глас 6-ий: «Преподобний отче...», «І нині» – Богородичний за гласом «Слави», від менших: «Око серця мого...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава» – преподобного, глас 5-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Ублажаємо Тебе, Богородице Діво...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава» – тропар преподобномученика, глас 4-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Слово Отче...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 8-ий (двічі). «Слава» – тропар преподобномученика, глас 4-ий, «І нині» – Богородичний за гласом «Слави» тропаря, від менших: «Слово Отче...». Кафизми 13-та, 14-та і 15-та. малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на – 6 (ірмоси один раз), преподобного на – 4 і преподобномученика на – 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (преподобномученика). Після 3-ої пісні – кондак преподобномученика, глас 2-ий: «У пості засяяв спочатку...»; Сідальний преподобному, глас 8-ий: «Зрікся ти плоті заради Христа...». «Слава» – сідальний преподобномученика, глас той самий: «Словами благодаті ти намащував серця вірних...», «І нині» – Богородичний Мінеї, глас той самий: «Хмара духовного Сонця...». Після 6-ої пісні – кондак та ікос преподобного, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний преподобному, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава» – преподобному, глас той самий: «Преподобний отче...», «І нині» – Богородичний по гласу «Слави», від менших: «Все уповання моє на Тебе покладаю...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава» – тропар преподобномученика, глас 4-ий, «І нині» – Богородичний по гласу «Слави», від менших: «Богородице, Ти вища від усіх творінь...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобному, «Слава» – тропар преподобномученику. Кондаки читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, інший тропар дня, тропар преподобного, тропар преподобномученика; кондак дня, інший кондак дня, кондак преподобного, кондак преподобномученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, інший тропар дня, тропар храму, тропар преподобного, тропар преподобномученика; кондак дня, інший кондак дня, кондак храму, кондак преподобного, кондак преподобномученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"10-16","weekday":"п’ятниця","title":"Мч. Лонгина, сотника, який був біля Хреста Господнього (І). Прп. Лонгина, воротаря Києво-Печерського, в Дальніх печерах (ХІІІ – ХІV).","readings":["Флп., 245 зач., III, 8 – 19. Лк., 32 зач., VII, 31 – 35.","Мч.: 2 Тим., 292 зач., II, 1 – 10. Мф., 113 зач., XXVII, 33 – 54."],"notes":"Служба мученика Лонгина, немає святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ – кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 2-ий – 3 і мученика, глас 8-ий – 3. «Слава» – мученика глас 6-ий: «В стражданнях Твоїх, Хритсе...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Коли побачила Нескверна Агниця...» Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава» – мученика, глас 6-ий: «Стоячи біля Хреста...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Бачачи Тебе, Христе, розіп’ятого...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мученика, глас 4-ий (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво пренепорочна...». Кафизми 19-та і 20-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4 і мученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний мученика, глас 8-ий, «І нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос мученика, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний мученика, «І нині» – Хрестобогородичний Октоїха. «Все, що дише...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той самий: «Коли нескверна Агниця побачила Свого Агнця...». Після Трисвятого – тропар мученика, глас 4-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському – тропар дня: «Спаси Господи...», тропар мученика; кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси Господи...», тропар храму, тропар мученика; кондак дня: «Вознісся на Хрест...», кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси Господи...», тропар храму, тропар мученика; кондак дня: «Вознісся на Хрест...», кондак храму, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і мученика. Апостол і Євангеліє – дня і мученика."}]},
{"date":"10-17","weekday":"субота","title":"Прор. Осії (820 до Р. Х.). Прмч. Андрія Критського (767). Мчч., безсрр. Косми і Даміана Аравійських і братів їхніх мчч. Леонтія, Анфіма і Євтропія (287 або 303). Перенесення мощів прав. Лазаря Чотириденного, єп. Китійського (898). Ікон Божої Матері, званих «До Різдва і після Різдва Діва» (1827) та «Визволителька» (біля 1889).","readings":["2 Кор., 168 зач., I, 8 – 11. Лк., 20 зач., V, 27 – 32."],"notes":"Служба прор. Осії і прмч. Андрія Критського не має святкового знака, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: пророка, глас 1-ий – 3, і преподобномученика, глас 4-ий – 3. «Слава і нині» – Догматик, глас 2-ий: «Минула тінь закону...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий (мученичі із числа стихир на «Господи, взиваю» – 1-ий: «Ви, страстотерпці, земну насолоду не полюбивши...», 2-ий: «Молитвами за нас святих мучеників...», 3-ій: «Собори мучеників, противлячись мучителям...», приспіви звичайні зі стиховні – Часослова). «Слава і нині» – Богородичний Октоїха, глас той самий: «Спаси від бід рабів Твоїх, Богородице Діво...». Після Трисвятого – тропар перподобномученика, глас 4-ий. «Слава, і нині» – Богородичний недільний, глас 2-ий: «Все вище розуму...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобномученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний недільний, глас той самий: «Від початку віку...». Кафизми 16-та і 17-та. Малі ектенії. Сідальні Октоїха. Псалом 50-ий. Канони: канон пророка з ірмосом на 6 (ірмоси по двічі), преподобномученика на 4 і Октоїха (мученичний) на 4. Біблійні пісні «Співаємо Господу...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канона Мінеї. (Преподобномученика). Після 3-ої пісні – кондак пророку, глас 2-ий, інший кондак пророку, глас 4-ий, кондак преподобномученику, глас 3-ій. Сідальний пророка, глас 8-ий. «Слава» – сідальний преподобномученика, глас 4-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобномученика, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний преподобномученика. «Слава» – Екзапостиларій Октоїха. «І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. (мученичі із числа стихир на хвалітніх – 1-ий: «За Христа постраждавши аж до смерті...», 2-ий: «Всякі міста і країни шанують ваші мощі...», 3-ій: «Хрест Христів узявши...». Приспіви звичайні зі стиховні – Часослова). «Слава, і нині» – Богородичний Октоїха, глас той самий: «Коли душа моя захоче розлучитися...». Після Трисвятого – тропар преподобномученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобномученика; кондаки преподобномученика і пророка, читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6.. Після входу – тропарі та кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня: «Апостоли, мученики і пророки...», тропар преподобномученика; кондак храму, кондак пророка, кондак преподобномученика. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». У храмі святого – тропар дня: «Апостоли, мученики і пророки...», тропар преподобномученика; кондак пророка, кондак преподобномученика. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"10-18","weekday":"неділя","title":"20-та неділя після П’ятдесятниці. Глас 3-й. Апостола і євангеліста Луки (І). Мч. Марина Аназарвського (ІV). Прп. Юліана Перського (ІV). Вмц. Злати (Хриси) Мегленської (1795, Болг.). Собор святих цілителів (перехідне святкування у неділю, найближчу до 17 – 18 жовтня).","glas":3,"readings":["Ран. – Єв. 9-е, Ін., 65 зач., XX, 19 – 31.","Літ. – Гал., 200 зач., I, 11 – 19. Лк., 30 зач., VII, 11 – 16.","Ап.: Кол., 260 зач. (від половини), IV, 5 – 9, 14, 18. Лк., 51 зач., X, 16 – 21."],"notes":"Звершуємо недільну службу Октоїха у поєднанні з полієлейною службою ап. і єв. Луки.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 3-ій – 4, і апостола, глас 8-ий – 6. «Слава» – апостола, глас 6-ий: «Апостоле Христів...», «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Вхід. Прокимен дня. Паремії апостола – 3. На літії стихири храму і стихири апостолу. На стиховні стихири недільні, глас 3-ій. «Слава» – апостола, глас 6-ий: «Всемудрий ловцю...», «І нині» – Богородичний недільний за гласом «Слави»: «Творець і Визволитель...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар недільний, глас 3-ій (двічі). «Слава» – тропар апостола, глас 5-ий, «І нині» – Богородичний недільний, за гласом тропаря: «Радуйся, двері Господні непрохідні...». Кафизми 2-га і 3-тя. Малі ектенії. Сідальні недільні. Полієлей. Величання апостола: «Величаємо тебе,/ святий апостоле і євангелисте Луко/ і шануємо страждання і труди твої,/ що ними потрудився ти/ у благовісті Христовім» і вибраний псалом. «Ангельський собор...». Іпакої гласу. Сідальний апостола (після першої кафизми), глас 3-ій: «Прийдіть усі, прославимо апостола Луку...», Сідальний апостола (після другої кафизми), глас той самий: «Подорожував ти після Воскресіння...». «Слава» – Сідальний апостола після полієлея, глас 4-ий: «Тростиною премудрого ловління...», «І нині» – Богородичний Мінеї, глас той самий: «Маючи Тебе, Богородице...». Степенна і прокимен гласу. Євангеліє – недільне 9-те. «Воскресіння Христове бачивши...». Після 50- го псалма: «Слава» – «Молитвами святого апостолів...». Стихира недільна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси один раз), Хрестовоскресний на 2, Богородиці (Октоїха) на 2 і апостола на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос апостола, глас 2-ий; сідальний апостола, глас 8-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос недільний, глас 3-ій. На 9-й пісні співаємо «Чеснішу». Після 9-ої пісні «Свят Господь Бог наш». Екзапостиларій воскресний 9-ий, світильний апостола. «Слава» – інший світильний апостола, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: недільні, глас 3-ій – 4, і апостола, глас 1-ий і глас 8-ий – 4 (зі своїми приспівами, приспіви дивитися на стиховні вечора). «Слава» – стихира євангельська 9-та, «І нині» – «Преблагословенна Ти...». Велике славослів’я. Після Трисвятого – тропар воскресний «У день спасіння...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний. «Слава» – тропар апостола. кондаки апостола і недільний читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласа – 6 і апостола пісня 3-я – 4. Після входу – тропарі і кондаки: У храмі Господньому – тропар недільний, тропар апостола. «Слава» – кондак апостола, «І нині» – кондак неділі. У храмі Богородиці – тропар неділі, тропар храму, тропар апостола; кондак неділі. «Слава» – кондак апостола, «І нині» – кондак храму. У храмі святого – тропар неділі, тропар храму, тропар апостола; кондак неділі, кондак храму. «Слава» – кондак апостола, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – неділі і апостола. Апостол і Євангеліє – дня і апостола."}]},
{"date":"10-19","weekday":"понеділок","title":"21-й тиждень після П’ятдесятниці. Прор. Іоїля (800 до Р. Х.). Мчч. Уара Єгипетського і з ним 7-ох учителів християнських (бл. 307). Свв. Клеопатри (327) та її сина Іоана (320). Сщмч. Садока, єп. Перського, і з ним 128 мчч. (342). Прп. Гавриїла Афонського (1901).","readings":["Флп., 248 зач., IV, 10 – 23. Лк., 33 зач., VII, 36 – 50."],"notes":"Служба пророка Іоіля і святого мученика Уара немає святкового знаку, звершу разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: пророка, глас 8-ий – 3, і мученика, глас 6-ий – 3. «Слава і нині» – Богородичний Мінеї, глас той самий: «Радуйся, кореню гінкий...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава і нині» – Богородичний Октоїха: «Владичице, заступнице всіх...». Після Трисвятого – тропар пророка, глас 2-ий. «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Тій, що вихована у храмі...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар пророка, глас 2-ий (двічі). «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Тій, що вихована у храмі...». Кафизми 4-та, 5-та і 6-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмос один раз), пророка на 4 і мученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученика Мінеї. Після 3-ої пісні – кондак пророка, глас 4-ий. Сідальний пророка, глас 2-ий. «Слава» – сідальний мученика, глас 1-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мученика, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава і нині» – Богородичний Октоїха, глас той самий: «Будучи першою святою і пречистою...». Після Трисвятого – тропар пророка, глас 2-ий. «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний за гласом слави, від менших: «Богородице, Ти вища від усіх творінь...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар пророка, «Слава» – тропар мученика. Кондаки читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар пророка, тропар мученика; кондак дня, кондак пророка, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар пророка, тропар мученика; кондак дня, кондак храму, кондак пророка, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"10-20","weekday":"вівторок","title":"Вмч. Артемія (362).","readings":["Кол., 249 зач., I, 1 – 2, 7 – 11. Лк., 34 зач., VIII, 1 – 3.","Вмч.: 2 Тим., 292 зач., II, 1 – 10. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"Служба вмч. Артемія немає святкового знаку, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ – кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 3-ій – 3 і великомученика, глас 4-ий – 3. «Слава» – великомученика, глас 2-ий: «Духовного світильника віри...», «І нині» – Богородичний за гласом «Слави», від менших: «Непрохідні врата, таємниче запечатані...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава» – великомученика, глас 6-ий: «За Христа законно постраждавши...», «І нині» – Богородичний за гласом «Слави», від менших: «Ніхто, що звертається до Тебе...». Після Трисвятого – тропар великомученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «До Богородиці щиро нині звернімося ми...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар великомученика, глас 4-ий (двічі). «Слава, і нині» – Богородичний за гласом «Слави», від менших: «До Богородиці щиро нині звернімося ми...». Кафизми 7-ма, 8-ма і 9-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичих на 6 (ірмоси один раз), 2-ий на 4 і великомученика на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний великомученика, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос великомученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний великомученика, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава» – великомученика, глас 6-ий «Нині вся вселенна просвіщається зорею...», «І нині» – Богородичний за гласом «Слави», від менших: «Великих дарів сподобилася Ти...». Після Трисвятого – тропар великомученика, глас 4-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, тропар великомученика; кондак дня, кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар великомученика; кондак дня, кондак храму, кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і великомученика (співпадають). Апостол і Євангеліє – дня і великомученика."}]},
{"date":"10-21","weekday":"середа","title":"Прп. Іларіона Великого (371 – 372). Мчч. Дасія, Гая і Зотика (303). Свт. Іларіона, митр. Київського (ХІ). Прп. Іларіона, схимника Києво-Печерського, в Дальніх печерах (ХІ). Перенесення мощів свт. Іларіона, єп. Меглинського (1206).","readings":["Кол., 251 зач., I, 18 – 23. Лк., 37 зач., VIII, 22 – 25.","Прп.: 2 Кор., 188 зач., IX, 6 – 11. Лк., 24 зач., VI, 17 – 23."],"notes":"Служба прп. Іларіона Великого немає святкового знаку, звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 3-ій – 3 і преподобного, глас 4-ий – 3. «Слава» – преподобного, глас 2-ий: «Від юності твоєї...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Побачивши Тебе, Ісусе...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава» – преподобного, глас 8-ий: «Духом Святим сповненний був ти...», «І нині» – Хрестобогородичний Мінеї: «Агниця нескверна...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця, і Пастиря, і Спасителя світу...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 8-ий (двічі). «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Агнця, і Пастиря, і Спасителя світу...». Кафизми 10-та, 11-та і 12-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичих на 6 (ірмоси один раз), 2-ий на 4 і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний преподобного, глас 8-ий (двічі). «Слава, і нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний святого, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава» – преподобного, глас 2-ий «Тихе твоє і чисте житіє...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Коли нескверна Агниця...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава, і нині» – Хрестобогородичний за гласом тропаря, від менших: «Плід утроби Твоєї...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси, Господи...», тропар преподобного; кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест...». У храмі Богородиці – тропар дня: «Спаси, Господи...», тропар храму, тропар преподобного; кондак дня: «Вознісся на Хрест...», кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси, Господи...», тропар храму, тропар преподобного; кондак дня: «Вознісся на Хрест...», кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"10-22","weekday":"четвер","title":"Рівноап. Аверкія, єп. Ієрапольського, чудотворця (бл. 167). Свт. Рафаїла (Заборовського), митр. Київського, Галицького і всієї Руси (1747). Сімох отроків у Ефесі: Максиміліана, Ямвлиха, Мартиніана, Іоана, Діонісія, Ексакустодіана (Костянтина) та Антоніна (бл. 250; 408 – 450). Сщмч. Олександра, єп. Адріанопольського, мч. Іраклія, воїна, та мцц. Анни, Єлизавети, Феодори та Глікерії (ІІ – ІІІ). Андрониківської (1281 – 1332) ікони Божої Матері.","readings":["Ран. – Ін., 35 зач. (від пол.), X, 1 – 9.","Літ. – Кол., 252 зач., I, 24 – 29. Лк., 41 зач., IX, 7 – 11.","Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16."],"notes":"Звершуємо полієлейну службу свт. Рафаїла (Заборовського), митр. Київського, Галицького і всієї Руси. (службу звершуємо з Мінеї Загальної с.384).","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-й антифон. На «Господи, взиваю» стихири святителя, глас 6-ий – 6 (кожна стихира двічі). «Слава» – святителя, глас 8-ий: «Чеснотами твоїми...», «І нині» – догматик, глас той самий: «Цар Небесний...». Вхід. Прокимен дня. Паремії святителя – 3. На стиховні стихири святителя, глас 8-ий (з приспівами своїми). «Слава» – святителя, глас той самий: «Ти єси пастир добрий...», «І нині» – Богородичний Мінеї, глас той самий «Неневісна Діво...». Після Трисвятого – тропар святителя, глас 4-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 4-ий (двічі). «Слава, і нині» – Богородичний недільний, глас той самий: «Від початку віку утаємнене...». Кафизми 13-та і 14-та. Малі єктенії. Сідальні святителя (по двічі). Полієлей. Величання святителя: «Величаємо тебе,/Святителю отче Рафаїле,/ і шануємо святу пам’ять вою,/ти бо молиш за нас//Христа Бога нашого». і вибраний псалом. Сідальний святителя після полієлея, глас 8-ий: «Подолавши пристрасті тілесні...» (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий: «Оспіваємо небесні двері і ковчег...». Степенна – 1-ий антифон 4-го гласу. Прокимен святителя, глас 1-ий: «Уста мої промовлятимуть премудрість, і повчання серця мого – розум». Стих: «Слухайте це, всі народи, почуйте всі, хто живе по вселенній». Євангеліє – святителя. Після 50-го псалма: «Слава» – «Молитвами святителя Рафаїла...». Стихира святителя, глас 6-й: «Насліднику Божий, спільнику Христів...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і святителя на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ї пісні – сідальний святителя, глас 4-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ї пісні – кондак та ікос святителя, глас 2-ий. На 9-й пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний святителя: «Нині славно прикрашається світлосяйне свято твоє...» (двічі). «Слава, і нині» – Богородичний Мінеї: «Після Бога на Тебе, Пречиста, уповання покладаємо...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири святителя, глас 8-ий – 4 (перша стихира – двічі). «Слава» – святителя, глас 6-ий: «Преподобний преблаженний святителю...», «І нині» – Богородичний, глас той самий: «Богом ми визнаємо Того...». Велике славослів’я. Після Трисвятого – тропар святителя, глас 4-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар та кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні святителя, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"10-23","weekday":"п’ятниця","title":"Апостола з 70-х Якова, брата Господнього за плоттю (бл. 63). Свт. Ігнатія, патр. Константинопольського (877 – 878).","readings":["Кол., 253 зач., II, 1 – 7. Лк., 42 зач., IX, 12 – 18.","Ап.: Гал., 200 зач., I, 11 – 19. Мф., 56 зач., XIII, 54 – 58."],"notes":"Звершуємо славослівну службу ап. Якова.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-та (яка не була прочитана у четвер на ранній). На «Господи, взиваю» стихири апостола, глас 4-ий – 6 (всі стихири по-двічі). «Слава» – апостола, глас 6-ий: «Мученицькою кров’ю...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири апостола, глас 1-ий (зі своїми приспівами). «Слава» – апостола, глас 8-ий: «Ти був братом Пастиреначальника Христа...», «І нині» – Богородичний Мінеї, глас той самий: «Владичице прийми молитви...». Після Трисвятого – тропар апостола, глас 2-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Все вище розуму...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 2-ий (двічі). «Слава, і нині» – Богородичний недільний, глас той самий: «Все вище розуму...». Кафизми 19-та і 20-та. Малі ектенії. Сідальні апостола (по двічі). Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних на 4 (ірмоси раз) 2-ий на 4 і апостола на 6. Біблійні пісні «Господеві співаємо...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний апостола, глас 8-ий. «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 4-ий. На 9-й пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний апостола (двічі). «Слава, і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостола, глас 8-ий – 4. «Слава» – апостола, глас 1-ий: «У вогняній зорі Божественного Духа просвітившись...», «І нині» – Богородичний, глас 8-ий: «Все уповання моє покладаю на Тебе, Мати, Божа, охорони мене покровом Твоїм». Велике славослів’я. Після Трисвятого – тропар апостола, глас 2-ий. «Слава, і нині» – Богородичний недільний, глас той самий: «Все вище розуму...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостола."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні апостола, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар апостола. «Слава» – кондак апостола, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостола; кондак храму. «Слава» – кондак апостола, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і апостола. Апостол і Євангеліє – дня і апостола."}]},
{"date":"10-24","weekday":"субота","title":"Димитрівська поминальна субота. Мч. Арефи і з ним 4299 мчч. (523). Прпп. Арефи (бл. 1195), Сисоя (ХІІ – ХІІІ) і Феофіла (ХІІ – ХІІІ), затворників Києво-Печерських, в Ближніх печерах. Св. Елезвоя, затв., царя Ефіопського (бл. 553 – 555). Мцц. Синклитікії та двох дочок її (VІ). Свт. Афанасія, патр. Константинопольського (1311). Ікони Божої Матері «Всіх скорботних радість» (1688).","readings":["Заупокійне: 1 Сол., 270 зач., IV, 13 – 17. Ін., 16 зач., V, 24 – 30.","Ряд.: 2 Кор., 174 зач., III, 12 – 18. Лк., 22 зач., VI, 1 – 10."],"notes":"Поминання померлих. На відміну від батьківських субот М’ясопусної і Троїцької, що мають загальноцерковне значення, про Димитрівську суботу Типікон замовчує, оскільки вона є благочестивим встановленням наших предків. Довідка: Рішенням Священного Синоду Православної Церкви України Журнал №24 від 21 серпня 2020 року визначили підставами для Дмитрівської поминальної суботи – звершення поминання всіх від віку спочилих отців, братів і сестер наших у суботу напередодні дня пам’яті святого великомученика Димитрія Солунського 26 жовтня (8 листопада за новим стилем) згадування пам’яті всіх, в Україні голодом заморених, вбитих під час Революції гідності та загиблих внаслідок агресії Російської Федерації на Сході України. Служба заупокійна. Служба мученика Арефи і з ним 4299 мучеників звершуємо (з мінеї Загальної с. 471) разом з суботньою службою Октоїха по 13-ій главі Типікону.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: мучеників, глас 4-ий – 3, і мученичні Октоїха, глас 3-ій – 3(2-ий: «Велика сила хреста Твого, Господи...», 3-ій: «Велика сила Твоїх мучеників, Хритсе...», 4-ий: «Пророки, і апостоли Христові...»; дивитися. на «Господи, взиваю»). «Слава, і нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Входу немає. Прокимен дня, глас 7-ий: «Боже, Ти Заступник мій...», зі стихом. На стиховні стихири Октоїха, глас 3-ій (із заупокійними приспівами: «Блаженні ті, кого обрав...», та ін.). «Слава І нині» – Богородичний Октоїха, глас той самий: «Серед жон Ти свята Богородице...». Примітка. «На стиховні мученичі 1-ий, і померлим два Иоанна Дамаскіна» (Типікон, гл. 13-та). В. Розанова (див. Його «Богослужебний Устав Православної Церкви»), якщо звершується суботня служба Октоїха 4-го, 5-го або 6-го гласу, де на стиховні вечірньої приводиться два мученичих і один померлим, потрібно, дотримуватися вказівок уставу, співати один мученичий (1-ий), а спочилий повторити двічі. Примітка. На суботньому богослужінні з «Алилуя» приспіви вечірніх стиховних стихир у службі 2-го та 8-го голосів наводяться в Октоїху на ряді. При здійсненні суботньої служби 1-го, 3-го – 7-го гласів приспіви запозичуються з ранкових стиховних стихир Октоїха. Після Трисвятого – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар, глас той самий: «Пом’яни, Господи, як Благий...», «І нині» – Богородичний, глас той самий: «Тебе, як Матір святу...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ замість «Бог Господь» – «Алилуя», глас 2-ий, із заупокійними стихами: 1-ий – «Блаженні ті, кого обрав і прийняв ти, Господи», 2-ий – «Пам’ять про них зроду в рід», 3-ій – «Душі їх у блаженстві перебуватимуть». Тропар, глас 2-ий: «Апостоли, мученики і пророки...» (двічі). «Слава» – інший тропар, глас той самий: «Пом’яни, Господи, як Благий...», «І нині» – Богородичний, глас той самий: «Тебе, як Матір святу...». Кафизма 16-та. Звичайна мала ектенія. Сідальні два з Октоїха, мученичі три, глас 3-ій: (перша стихира опускається) «Сяєте вірою, пресвітлі світила святі...»; стих: «Дивний Бог у святих Своїх, Бог Ізраїлів» і 2-ий: «Страстотерпці святі...», (дивитися після 2-ої кафизми) стих: «Блаженні ті, кого обрав...», «Коли, за словом Твоїм...». «Слава, і нині...» Богородичний: «Пророки проповідували...». (дивитись типікон, глава 13-та). Кафизма 17-а (Непорочні) за Уставом співається, на 2-ий глас; ця кафизма розділяється на дві частини, або статії. Приспів до стихів 1-ої статті: «Благословен єси, Господи, навчи мене заповітів Твоїх». В кінці статті «Слава, і нині» не співається, але замість цього тричі (з приспівом) останні стихи: «Коли б не закон Твій...», «Повік не забуду повелінь Твоїх...». Примітка. Щодо закінчення першої і другої статті 17-ої кафизми при заупокійному богослужінні існують такі думки: 1) кожен з двох останніх стихів першої і другої статті співається по тричі з відповідним приспівом; 2) в кожній статті два останніх стиха об’єднуються «в один» і співаються з приспівом тричі. Потім виголошується мала заупокійна ектенія: «Ще і ще...», хор: «Господи, помилуй» (один раз); «Ще молимося за упокоєння душ спочилих рабів Божих (імена)...», хор: «Господи, помилуй» (один раз); «Щоб Господь Бог оселив душі їх...», хор: «Господи, помилуй» (один раз); «Милості Божої...», хор: «Подай, Господи». «Господу помолимось», хор: «Господи, помилуй». Ієрей таємно читає молитву: «Боже духів і всякої плоті...». Виголос: «Бо Ти єси Воскресіння...». Хор: «Амінь». Після цього починається спів 2-ої статті: «Твій – я, спаси мене...» з приспівом до стихів: «Спасе, спаси мене»; останні стихи статті: «Нехай живе душа моя...», «Я блукаю, наче ягня загублене...», співаються (з приспівом) тричі. Потім на 5-ий глас співаються тропарі після Непорочних: «Собор святих...» та інше, з приспівом: «Благословен єси, Господи...». Виголошується мала заупокійна єктенія (див. Після 1-ої статті). Після виголосу співається сідальний, глас 5-ий: «Упокой, Спасе наш...». «Слава, і нині» – Богородичний, глас той самий: «Ти, що від Діви засяяв...». Псалом 50-ий. Канони: У храмі Господньому і Богородиці – храму з ірмосом на 6 (ірмоси по двічі), мучеників на 4 і Октоїха 1-ий (мученичний) на 4. Примітка. Про спів канонів у храмі Воскресіння Христового в суботу, дивитися Октоїх частина 1-ша, с. 831. У храмі святого – канон мучеників з ірмосом на 6 (ірмоси по двічі), храму на 4 і Октоїха 1-ий (мученичний) на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси 1-го (мученичного) канону Октоїха. Після 3-ої пісні – звичайна мала ектенія; кондак та ікос мучеників, глас 8-ий; «Слава» – сідальний мучеників, глас 4-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – мала заупокійна ектенія. Кондак, глас 8-ий: «Зі святими упокой...» та ікос, глас той самий: «Сам Один єси Безсмертний...». На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха: «Ти, що живими і мертвими володієш...». «Слава, і нині» – Богородичний Октоїха: «Ми Тобою хвалимося, Богородице...». «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Октоїха (мученичні), глас 3-ій – 4. «Слава» – померлим Октоїха, глас той самий, «І нині» – Богородичний Октоїха, глас той самий. «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій (зі своїми приспівами: «Блаженні ті, кого обрав...», та ін.). «Слава, і нині» – Богородичний глас той самий: «Всі ми знаємо Тебе, Богородице...». Після Трисвятого – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар, глас той самий: «Пом’яни, Господи, як благий...», «І нині» – Богородичний, глас той самий: «Тебе, як Матір святу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропарі: «Апостоли, мученики і пророки...». «Слава» – «Пом’яни, Господи, як благий...». Кондак: «Зі святими упокой...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні Октоїха – 6. Після входу – тропар, глас 2-ий: «Апостоли, мученики і пророки...», інший тропар, глас той самий: «Пом’яни, Господи, як благий...». «Слава» – кондак, глас 8-ий: «Зі святими упокой...», «І нині» – Богородичний, глас той самий: «Тебе і Стіну, і Пристановище...». Прокимен – дня і заупокійний, глас 6-ий: «Душі їх у блаженстві...». Апостол – дня і заупокійний. Алилуарій – дня (суботи): «Взивали праведні...», стих: «Багато скорбот у праведних...»; і заупокійний: «Блаженні ті, кого обрав...». Євангеліє – дня і заупокійне. Причасний – дня (суботи): «Радуйтеся, праведні...», і заупокійний: «Блаженні ті, кого обрав...»."}]},
{"date":"10-25","weekday":"неділя","title":"21-ша неділя після П’ятдесятниці. Глас 4-й. Мчч. Маркіана, читця і Мартирія, іподиякона (бл. 355). Прпп. Мартирія, диякона, і Мартирія, затворника, Києво-Печерських, в Дальніх печерах (ХІІІ – ХІV). Мч. Анастасія Аквілейського (ІІІ). Прав. Тавіфи Іопійської (І).","glas":4,"readings":["Ран. – Єв. 10-е, Ін., 66 зач., XXI, 1 – 14.","Літ. – Гал., 203 зач., II, 16 – 20. Лк., 35 зач., VIII, 5 – 15.","Мчч.: Еф., 224 зач. (від половини), IV, 7 – 13. Мф., 34 зач. (від половини), X, 1 – 8."],"notes":"Служба мчч. Маркіяна і Мартирія не має святкового знака, звершуємо разом з недільною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: недільні, глас 4-ий – 7, і стихири мучеників, глас той самий – 3. «Слава» – мучеників, глас 1-ий: «Будучи учениками і послідовниками...», «І нині» – Догматик, глас 4-ий: «Пророк Давид...». Вхід. Прокимен дня. На літії стихира храму. На стиховні стихири недільні, глас 4-ий. «Слава» – мучеників, глас 3-ій: «Духовні світильники Церкви...», «І нині» – Богородичний недільний, за гласом «Слави»: «Безсіменно від Божественного Духа...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар недільний, глас 4-ий (двічі). «Слава» – тропар мучеників, глас 1-ий, «І нині» – Богородичний недільний, по гласу «Слави»: «Коли Гавриїл звістив Тобі Діво...». Кафизми 2-га і 3-тя. Малі єктенії. Сідальні недільні Октоїха. Полієлей. «Ангельський собор...». Іпакої, ступеневі і прокимен – гласу. Євангеліє воскресне 10-те. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира недільна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: недільний з ірмосом на 4 (ірмоси раз), Хрестовоскресний на 3 Богородиці (Октоїха) на 3 і мучеників на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос мучеників, глас 4-ий; сідальний мучеників, глас 3-ій (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос недільні, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій недільний 10-ий. «Слава» – світильний мучеників, «І нині» – Богородичний недільного екзапостиларію. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири недільні, глас 4-ий – 8. «Слава» – стихира євангельська 10-та, «І нині» – «Преблагословенна Ти...». Велике славослів’я. Після Трисвятого – тропар недільний: «Воскрес із гробу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар недільний. «Слава» – тропар мучеників. Кондаки тільки недільний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 8. Після входу – тропарі і кондаки: У храмі Господньому – тропар неділі, тропар мучеників. «Слава» – кондак мучеників, «І нині» – кондак недільний. У храмі Богородиці – тропар неділі, тропар храму, тропар мучеників; кондак неділі. «Слава» – кондак мучеників, «І нині» – кондак храму. У храмі святого – тропар неділі, тропар храму, тропар мучеників; кондак неділі, кондак храму. «Слава» – кондак мучеників, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – неділі і мучеників. Апостол і Євангеліє – дня і мучеників."}]},
{"date":"10-26","weekday":"понеділок","title":"22-й тиждень після П’ятдесятниці. Вмч. Димитрія Солунського (бл. 306). Прп. Феофіла Києво-Печерського, єп. Новгородського, в Дальніх печерах (бл. 1482). Мч. Лупа Солунського (бл. 306). Прп. Афанасія Мидікійського (бл. 814). Прп. Димитрія Басарбовського (1685, Болг.).","readings":["Ран. – Мф., 36 зач., X, 16 – 22.","Літ. – Кол., 255 зач., II, 13 – 20. Лк., 43 зач., IX, 18 – 22.","Вмч.: 2 Тим., 292 зач., II, 1 – 10. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"Звершуємо полієлейну службу вмч. Димитрія.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири великомученика, глас 2-ий і глас 8-ий – 8 (стихира, глас 2-ий: «Ти завжди світиш вітчизні своїй...», і стихира, глас 8-ий: «О, преславне чудо! На небесах і на землі...» – двічі). «Слава» – великомученика, глас 6-ий: «Нині скликає нас...», «І нині» – догматик, глас 6-ий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії святому з Мінеї – 3. На стиховні стихири, глас 1-ий і глас 2-ий (стихири беремо з літії святому зі стихами Часослова). «Слава» – великомученика, глас 8-й: «Твоя божественна і непорочна душа...», «І нині» – Богородичний недільний, глас той самий: «Безневісна Діво...». Після Трисвятого – тропар великомученика, глас 3-ій. «Слава, і нині» – Богородичний недільний, за гласом тропаря: «Тебе, заступницю спасіння роду нашого...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар великомученика, глас 3-ій (двічі). «Слава, і нині» – Богородичний недільний, за гласом тропаря: «Тебе, заступницю спасіння роду нашого...». Кафизми 4-та і 5-та. Малі єктенії. Сідальні великомученика (по двічі). Полієлей. Величання великомученика: «Величаємо тебе,/ страстотерпче святий Димитрію,/ і шануємо чесні страждання твої,/ які за Христа// ти перетерпів» і вибраний псалом: «Бог нам пристановище і сила...». Сідальний великомученика після полієлея, глас 8-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен великомученика, глас 4-ий: «Дивний Бог у святих Своїх, Бог Ізраїлів»; стих: «Святим, що на землі Його, сотворив Господь усі бажання Свої в них». Євангеліє великомученика. Після 50-го псалма: «Слава» – «Молитвами святого великомученика Димитрія...». Стихира великомученика, глас 6-ий: «Нині скликає нас страстотерпця всесвітнє торжество...». (Стихира на «Слава» із стихир на «Господи взиваю»). Канони – канон Богородиці молебний на 6 (ірмоси по двічі) і великомученика (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний великомученика, глас 4-ий. «Слава, і нині» – той самий Після 6-ої пісні – кондак та ікос великомученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний великомученика. «Слава, і нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири великомученика, глас 4-ий і глас 5-ий – 6. «Слава» – великомученика, глас 4-ий: «Через списи ти успадкував благодать Спасову...», «І нині» – Богородичний Мінеї, глас той самий: «Визволи нас від недолі, Мати Христа Бога...». Велике славослів’я. Після Трисвятого – тропар великомученика, глас 3-ій. «Слава, і нині» – Богородичний недільний, глас той самий: «Тебе, заступницю спасіння роду нашого...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні великомученика, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар великомученика. «Слава» – кондак великомученика, «І нині» – кондак храму. У храмі святого – тропар храму, тропар великомученика; кондак храму. «Слава» – кондак великомученика, «І нині» – «Заступнице Християн...». Прокимен, алилуарій і причасний – великомученика. Апостол і Євангеліє – великомученика і дня."}]},
{"date":"10-27","weekday":"вівторок","title":"Мч. Нестора Солунського (бл. 306). Прп. Нестора Літописця, Києво-Печерського, в Ближніх печерах (бл. 1114). Прп. Нестора, некнижного, Києво-Печерського, в Дальніх печерах (ХІV). Мцц. Капітоліни та Єротиїди (304). Мч. Марка Фіваїдського та інших з ним.","readings":["Кол., 256 зач., II, 20 – III, 3. Лк., 44 зач., IX, 23 – 27.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Звершуємо славослівну службу прп. Нестора Літописця. (службу беремо з Мінеї Місячної 27 жовтня, та Мінеї Загальної служба преподобного одного с.418).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ – кафизма 6-та (яка не була прочитана у понеділок на ранній). На «Господи, взиваю» стихири преподобного, глас 4-ий – 6 (кожна стихира двічі). «Слава» – преподобного, глас 6-ий: «Скрижаль для Духа святого...», «І нині» – Догматик, глас той самий: «Хто тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири преподобного, глас 1-ий. (Мінея Загальна) «Слава» – преподобного, глас 5-ий (Мінея Місачна): «Пророчі слова виконав ти...», «І нині» – Богородичний недільний, за гласом «Слави»: «Всечесна Діво, Ти – храм і двері...». Після Трисвятого – тропар преподобного, глас 4-ий. «Слава, і нині» – Богородичний недільний, за гласом тропаря: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 4-ий. (двічі). «Слава, і нині» – Богородичний недільний, за гласом тропаря: «Від початку віку...». Кафизми 7-ма, 8-ма і 9-та. Малі єктенії. Сідальні Мінеї. (після третьої кафизми, ектенії немає, Сідальний Октоїха). Канони: Октоїха 1-ий з ірмосом без мученичних на 4 (ірмоси раз), 2-ий на 4 і преподобного на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкию уста мої...». Після 3-ої пісні – сідальний преподобного, глас 4-ий (двічі). «Слава, і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак преподобного, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні – «Достойно є» не співається. Світильний преподобного. «Слава, і нині» – Богородичний Мінеї. (з Мінеї Загальної). «Все, що дише...» і хвалітні псалми. На хвалітніх стихири преподобного глас 6-ий – 4. «Слава» – преподобного, глас 2-ий: «Очистившись чернечими діяннями...» (стихира святому славник з Мінеї Місячної славник на стиховні на ранній), «І нині» – Богородичний Мінеї, глас той самий: «Все уповання на Тебе покладаю...». Велике славослів’я. Після Трисвятого – тропар преподобного, глас 4-ий. «Слава, і нині» – Богородичний недільний, за гласом тропаря: «Від початку віку...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні канону преподобного, пісня 3-тя – 4 (з ірмосом) і пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар храму, тропар преподобного; кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"10-28","weekday":"середа","title":"Вмц. Параскеви-П’ятниці (ІІІ). Прп. Іова, ігум. Почаївського (1651). Свт. Димитрія (Туптала), митр. Ростовського (1709). Мч. Терентія, мц. Неоніли і дітей їхніх Сарвила, Фота, Феодула, Ієракса, Нита, Вила та Євникії (бл. 249 – 250). Прп. Стефана Саваїта, творця канонів (ІХ). Свт. Арсенія, архієп. Сербського (1266). Мчч. Африкана, Терентія, Максима, Помпія та інших 36-ти (ІІІ). Сщмч. Киріака, патр. Єрусалимського (363). Прп. Іоана Хозевіта, єп. Кесарійського (VІ). Сщмч. Неофіта, єп. Урбниського (VІІ, Груз.). Прп. Феофіла Київського, юродивого заради Христа (1853).","readings":["Ран. – Мф., 104 зач., ХХV, 1 – 13.","Літ. – Кол., 259 зач., III, 17 – IV, 1. Лк., 47 зач., IX, 44 – 50.","Вмц.: 2 Кор., 181 зач., VI, 1 – 10. Лк, 33 зач., VII, 36 – 50.","Якщо звершується полієлейна служба святителю Димитрію, то на ранній читання: Ін., 35 зач. (від половини), Х, 1 – 9, на","літургії: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16.","Якщо ж великомучениці Параскеві, то на ранній читання: Мф., 104 зач., ХХV, 1 – 13, на літургії: Кор., 181 зач., VI, 1 – 10.","Лк, 33 зач., VII, 36 – 50."],"notes":"Подаємо порядок звершення полієлейної служби вмц. Параскеві П’ятниці. За цією ж схемою можна звершувати полієлей прп. Іову Почаївському або свт. Димитрію, митр. Ростовському.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ Блажен муж 1-ий антифон. На Господи, взиваю стихири великомучениці, глас 4-ий на 8 (перші дві стихири двічі). «Слава» – великомучениці, глас 6-ий: «Праворуч Спаса, як співає Давид...», «І нині» Богородичний Догматик, глас той самий: «Хто Тебе не ублажить...». Вхід, прокимен дня. Паремії великомучениці – 3. На стиховні стихири, глас 4-ий зі своїми стихами. «Слава» – великомучениці, глас, 8-ий: «Так говорила Параскева мучителю...», «І нині» – Богородичний недільний, за гласом «Слави»: «Неневісна Діво...». Після Трисвятого – тропар великомучениці, глас 4-ий. «Слава і нині» – Богородичний недільний, за гласом тропаря: «Від початку віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар великомучениці, глас 4-ий (двічі). «Слава і нині» – Богородичний недільний, за гласом тропаря: «Від початку віку утаємнене...» Кафизми 10-та і 11-та. Малі ектенії. Сідальні великомучениці з Мінеї (по двічі). Полієлей. Величання великомучениці: «Величаємо тебе,/ свята великомученице Параскево,/ і шануємо чесні страждання твої,/ які за Христа// перетерпіла ти». Псалом вибраний: «Бог нам пристановище і сила». Після полієлея сідальний, глас глас 8: «Ставши невістою Богоугодною...». «Слава, і нині» – Богородичний Мінеї, глас той самий. Степенна, 1-ий антифон 4-го гласу. Прокимен, глас 4: «Дивний Бог у святих Своїх, Бог Ізраїлів». Стих: «В церквах благословіте Бога, ГосподавідджерелІзраїлевих»ЄвангелієвідМатфея,зачало104. Після 50-го псалма стихира, глас 1-ий: «До вишніх чинів...». Канон Богородиці з ірмосом на 6 (ірмоси по двічі) і великомучениці на 8. Біблійні пісні «Співаймо Господеві...». Катавасія: «Відкрию уста мої...». Після 3-ої пісні – сідальний великомучениці, глас 8-ий. «Слава» – інший сідальний, глас 4-ий, «І нині» – Богородичний Мінеї. Після 6-ої пісні – кондак та ікос великомучениці, глас 3-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний великомучениці (двічі). «Слава і нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири великомучениці на 6, глас 4-ий і глас 1-ий. «Слава» – глас 6: «Піснями вшануймо мученицю Христову...», «І нині» – Богородичний Мінеї. Велике славослів’я. Після Трисвятого – тропар великомучениці, глас 4-ий. «Слава і нині» – Богородичний по гласу тропаря: «Від початку віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомучениці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні великомучениці з першого канону пісня 3-тя – 4 (з ірмосом), з другого пісня 6-та – 4. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар великомучениці; «Слава» – кондак великомучениці, «І нині» – кондак храму. У храмі святого – тропар великомучениці. «Слава» – кондак великомучениці, «І нині» – «Заступнице християн...». Прокимен, Апостол, алилуарій і причасний – великомучениці. Апостол і Євангеліє – дня і великомучениці."}]},
{"date":"10-29","weekday":"четвер","title":"Прмч. Анастасії Римлянки (Солунської) (ІІІ). Прп. Авраамія, затворника, пресвіт. і св. Марії, племінниці його (бл. 360). Мчч. Клавдія, Астерія, Неона і Феоніли (285). Прп. Анни (826).","readings":["Кол., 260 зач., IV, 2 – 9. Лк., 48 зач., IX, 49 – 56."],"sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та (яка не була прочитана на ранній середи). На «Господи, взиваю» стихири на 6: преподобномучениці, глас 8-ий – 3, і преподобного, глас той самий – 3. «Слава і нині» – Богородичний Мінеї, глас той самий: «Радуйся, носило Божественного Світла...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 4-ий. «Слава і нині» – Богородичний Октоїха. Після Трисвятого – тропар преподобномучениці, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Духовні врата життя...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобномучениці, глас 4-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Духовні врата життя...». Кафизми 13-та, 14-та і 15-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмос один раз), преподобномучениці на 4 і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси преподобного Мінеї. Після 3-ої пісні – кондак преподобномучениці, глас 3-ий. Сідальний преподобномучениці, глас 8-ий. «Слава» – сідальний преподобного, глас 1-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобного, глас 3-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава і нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 4-ий. «Слава і нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар преподобномучениці, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом слави, від менших: «Діво Пречиста, спаси нас молитвами Твоїми...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар преподобномучениці, «Слава» – тропар преподобному. Кондаки читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня, інший тропар дня, тропар преподобномучениці, тропар преподобного; кондак дня, інший тропар дня, кондак преподобномучениці, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, інший тропар дня, тропар храму, тропар преподобномучениці, тропар преподобного; кондак дня, інший тропар дня; кондак храму, кондак преподобномучениці, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"10-30","weekday":"п’ятниця","title":"Сщмч. Зиновія, єп. Егейського, і сестри його мц. Зиновії (285). Апп. від 70-х: Тертія (Терентія), Марка, Юста (Варсави) і Артеми (І). Сщмч. Маркіана, єп. Сиракузького (ІІ). Мц. Євтропії Олександрійської (бл. 250). Свв. Стефана Милютина, короля Сербського (1320), брата його Драгутина (1316) і матері їхньої Олени (1306, Серб.). Озерянської ікони Божої Матері (ХVІ).","readings":["Кол., 261 зач., IV, 10 – 18. Лк., 50 зач., X, 1 – 15."],"notes":"Служба сщмч. Зіновія та мц. Зіновії без знаку, звершуємо разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 4-ий – 3, і мученика, глас той самий – 3. «Слава» – святих, глас 6-ий: «Лик співаків, заплещемо нині руками...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Бачачи наше Життя...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 4-ий. «Слава, і нині» – Хрестобогородичний Октоїха, глас той самий. Після Трисвятого – тропар святим, глас 4-ий, «Слава, і нині» Хрестобогородичний за гласом тропаря від менших: «Діво Пренепорочна, Мати Христа Бога...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святим, глас 4-ий (двічі), «Слава, і нині» Хрестобогородичний за гласом тропаря від менших: «Діво Пренепорочна, Мати Христа Бога...». Кафизми 19-та і 20-та. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, на 6 (ірмоси раз), 2-ий на 4 і святих на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї. Після 3-ої пісні – сідальний священномученика, глас 1-ий, «І нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак святих, глас 8-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний святих, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 4-ий. «Слава, і нині» – Хрестобогородичний Октоїха глас той самий. Після Трисвятого – тропар святих, глас 4-ий, «Слава, і нині» Хрестобогородичний за гласом тропаря від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святих."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господньому – тропар дня: «Спаси Господи...», тропар святих; кондак святих. «Слава» – «Зі святими упокой...», «І нині» – кондак дня: «Вознісся на Хрест волею...». У храмі Богородиці – тропар дня: «Спаси Господи...», тропар храму, тропар святих; кондак дня: «Вознісся на Хрест волею...», кондак святих, «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня: «Спаси Господи...», тропар храму, тропар святих; кондак дня: «Вознісся на Хрест волею...», кондак храму, кондак святих. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня. Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 60 зач., XI, 34 – 41. Служба прмц. Анастасії і прп. Аврамія немають святкового знаку звершуємо разом зі службою Октоїха."}]},
{"date":"10-31","weekday":"субота","title":"Апп. від 70-х: Стахія, Амплія, Урвана, Наркиса, Апелія та Аристовула (І). Мч. Епимаха (бл. 250). Прпп. Спиридона і Никодима, просфорників Києво-Печерських, в Ближніх печерах (ХІІ). Прп. Маври Константинопольської, диякониси (V). Прав. Петра (Калнишевського) Багатостраждального (1803).","readings":["Прав.: Еф., 233 зач., VI, 10 – 17. Мф., 11 зач., V, 14 – 19.","Ряд.: 2 Кор., 178 зач., V, 1 – 10. Лк., 29 зач., VII, 1 – 10."],"notes":"Звершуємо шестиричну службу праведного Петра (Калнишевського), звершуємо разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири праведного, глас 4-ий –6 (кожна стихира двічі). «Слава» – праведного, глас той самий: «Прийдіть, вірних собори...», «І нині» – Догматик, глас 4-ий: «Пророк Давид...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 4-ий (мученичні із числа стихир на «Господи, взиваю» – 2-ий: «Жертви одухотворені...», 3-ій: «Чесна смерть святих Твоїх...», 4-ий: «Маючи сміливість...», приспіви звичайні – з Часослова). «Слава, і нині» – Богородичний Октоїха. Після Трисвятого – тропар праведного, глас 5-ий. «Слава, і нині» – Богородичний недільний, глас 4-ий: «Від початку віку...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар праведного, глас 5-ий (двічі). «Слава, і нині» – Богородичний недільний, за гласом «Слави»: «Радуйся, двері Господні непрохідні...». Кафизми 16-та і 17-та. Малі ектенії. Сідальні Октоїха. Псалом 50-ий. Канони: У храмі Господньому і Богородиці: храму на 4 (ірмос двічі), праведного на 6, Октоїха (мученичний) на 4. У храмі святого: праведного на 6 (ірмоси двічі), храму на 4, Октоїха (мученичний) на 4. Біблійні пісні «Співаємо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичного канону Октоїха. Після 3-ої пісні – сідальний праведного, глас 4-ий. Після 6-ої пісні – кондак та ікос праведного, глас 8-ий. На 9-ий пісні співаємо «Чеснішу». Після 9-ої пісні співається «Достойно є». світильний праведного. «Слава» – Екзапостиларій Октоїха, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 4-ий (стихири мученичні з хвалітніх) «Слава» – праведного, глас 8-ий: «Радощів сповнюється сьогодні...» (стихиру дивитися «Слава» на хвалітніх праведного), «І нині» – Богородичний, за гласом «Слави», від менших: «Владичице, прийми молитви...». Після Трисвятого – тропар праведного, глас 5-ий. «Слава, і нині» – Богородичний за гласом тропаря, від менших: «Христе Боже...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак праведного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні праведного, пісня 3-тя – 4 і Октоїха – 4. Після входу – тропарі та кондаки: У храмі Господньому і Богородиці – тропар храму, тропар дня: «Апостоли, мученики і пророки...», тропар праведного; кондак храму, кондак праведного. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». У храмі святого – тропар дня: «Апостоли, мученики і пророки...», тропар праведного; кондак праведного. «Слава» – «Зі святими упокой...», «І нині» – «Як первістки природи...». Прокимен, алилуарій і причасний – праведного і дня. Апостол і Євангеліє – праведного і дня."}]},
{"date":"11-01","weekday":"неділя","title":"22-га неділя після П’ятдесятниці. Глас 5-й. Безсрр. і чудотворців Косми та Даміана Асійських і матері їхньої прп. Феодотії (ІІІ). Сщмчч. Іоана, єп., і Якова, пресвітера, які в Персії постраждали (бл. 345). Мцц. Кірієни та Юліанії (305 – 311). Мч. Ерминингельда, царевича Готського (586). Мчч. Кесарія, Дасія і з ними п’ятьох (VІІ).","glas":5,"readings":["Ран. – Єв. 11-е, Ін., 67 зач., XXI, 15 – 25.","Літ. – Гал., 215 зач., VI, 11 – 18. Лк., 83 зач., XVI, 19 – 31.","Безсрібників: 1 Кор., 153 зач., XII, 27 – XIII, 8. Мф., 34 зач. (від половини), X, 1, 5 – 8."],"notes":"Служба свв. Косми і Даміана шестерична, звершується разом з влскресною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж...» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 5-ий – 6 і безсрібників, глас 6-ий – 4. «Слава» – безсрібників, глас той самий: «Безкінечною є благодать святих...», «І нині» – догматик, глас 5-ий: «У Червоному морі...». Вхід. Прокимен дня. На літії стихира храму та безсрібників, глас 6-ий: «Світла і просвічена засяяла нині пам’ять...» (див. стихири на стиховні ранньої в Мінеї» і глас 8-ий: «Хто не дивується, хто не прославляє...» (див. «Слава» на стихирах на стиховних ранньої в Мінеї). «Слава» – безсрібників, глас 4-ий: «Маючи джерело зцілень...» (див. «Слава» хвалітніх стихир), «І нині» – Богородичний воскресний, глас той самий: «Зглянься на благання рабів Твоїх...». На стиховні стихири воскресні, глас 5-ий. «Слава» – безсрібників, глас 6-ий: «Завжди маючи Христа, Який діє у вас, святі безсрібники...», «І нині» – Богородичний воскресний, глас той самий: «Творець і Визволитель...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 5-ий (двічі). «Слава» – тропар безсрібників, глас 8-ий. «Слава: І нині» – Богородичний воскресний за гласом тропаря: «Ти, що заради нас народився від Діви...» Кафизми 2-а і 3-а. Малі ектенії. Сідальні воскресні. Полієлей. «Ангельський собор...». Іпакої, сідальні, степенні і прокимен гласу. Євангеліє воскресне 11-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний гласу з ірмосом на 4 (ірмос раз), Хрестовоскресний на 2, Богородиці на 2 і бесрібників на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос безсрібників, глас 2-ий; сідальний безсрібників, глас 8-ий. «Слава: І нині» – Богородичний Мінеї, глас той самий: «Як Всенепорочна Невіста Творця...». Після 6-ої пісні – кондак та ікос воскресні, глас 5-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-й пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 10-ий. «Слава:» – Світильний безсрібників, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 5-ий – 4 і безсрібників, глас 1-ий і глас 2-ий – 4. «Слава» – стихира євангельська 11-а, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «В день спасіння світу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар безсрібників. Кондак тільки воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і безсрібників, пісня 3-я – 4. На вході – «Прийдіть... що воскрес із мертвих...». Після входу – тропарі і кондаки: У храмі Господському – тропар воскресний, тропар безсрібників. «Слава» – кондак безсрібників, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар безсрібників; кондак воскресний. «Слава» – кондак безсрібників, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар безсрібників; кондак воскресний, кондак храму. «Слава» – кондак безсрібників, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресний та безсрібників. Апостол і Євангеліє – дня та безсрібників."}]},
{"date":"11-02","weekday":"понеділок","title":"23-й тиждень після П’ятдесятниці. Мчч. Акиндина, Пигасія, Афонія, Елпідофора, Анемподиста та інших з ними (бл. 341 – 345). Прп. Маркіана Киринейського (388).","readings":["1 Сол., 262 зач., I, 1 – 5. Лк., 52 зач., X, 22 – 24.","Мчч.: Еф., 233 зач., VI, 10 – 17. Мф., 36 зач., X, 16 – 22."],"notes":"Служба святих не має святкового знака, звершується разом з службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: стихири Октоїха, глас 5-ий – 3 і мучеників, глас 4-ий – 3. «Слава» – мучеників, глас 6-ий: «Нині п’ятисяйний лик мучеників...», «І нині» – Богородичний за гласом «Слави», від менших: «По-архангельськи прославмо..». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 5-ий; стих: «Дивний Бог у святих своїх, Бог Ізраїлів» і мучеників стихира, глас 1-ий: «П’ятисяйними проміннями засяяли мученики...». «Слава» – мучеників, глас 2-ий: «Прийдіть, радіймо в Господі...», «І нині» – Богородичний за гласом «Слави», від менших: «Радуйся, Маріє Богородице...». Після Трисвятого – тропар мучеників, глас 2-ий. «Слава І нині» – Богородичний за гласом «Слави», від менших: «Як джерело милосердя...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучеників, глас 2-ий (двічі). «Слава І нині» – Богородичний за гласом «Слави», від менших: «Як джерело милосердя...». Кафизми 4-а, 5-а і 6-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4 і мучеників на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої и 9-ої пісень – ірмоси канону мучеників. Після 3-ої пісні – сідальний мучеників, глас 8-ий. «Слава і нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос мучеників, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха, «Слава» – світильний мучеників, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 5-ий; стих: «Багато скорбот у праведних, і від усіх них визволить їх Господь» і стихира мучеників, глас 2-ий. «Слава» – мучеників, глас 4-ий: «П’ятисяйня свічка страстотерпців...», «І нині» – Богородичний за гласом «Слави», від менших: «Богородице, Царице всіх...». Після Трисвятого – тропар мучеників, глас 2-ий. «Слава: І нині» – Богородичний за гласом «Слави», від менших: «Тебе, як Матір святу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мучеників."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар мучеників; кондак дня, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар мучеників; кондак дня, кондак храму, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і мучеників. Апостол і Євангеліє – дня і мучеників."}]},
{"date":"11-03","weekday":"вівторок","title":"Сщмчч. Акепсима, єп., Йосифа, пресвіт., і Аїфала, дияк. (ІV). Оновлення храму вмч. Юрія (Георгія) в Лідді (ІV). Мчч. Атика, Агапія, Євдоксія, Катерія, Істукарія, Пактовія, Никтополіона та воїнів їх (бл. 320). Прп. Акепсима Антіохійського (ІV). Прав. Снандулії (ІV). Прп. Анни Всеволодівни, княжни Київської (1112).","readings":["1 Сол., 263 зач., I, 6 – 10. Лк., 55 зач., XI, 1 – 10.","Прп.: Гал., 208 зач., ІІI, 23 – 29. Мф., 21 зач., VIІ, 12 – 21."],"notes":"Служба преподобної княжни Анни не має святкового знака (із загальної Мінеї), звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири Октоїха, глас 5-ий – 3, і преподобної, глас 8-ий – 3. «Слава» – преподобної, глас: «Душевні спокуси і пристрасті тілесні ти мечем стримання посікла...», «І нині» – Богородичний Мінеї, глас той самий: «Спаси від бід рабів...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 5-ий. «Слава» – преподобної, глас 6: «Засяяло нині троє свято...», «І нині» – Богородичний Мінеї, від менших: «Богородице, Ти єси виноградна лоза...». Після Трисвятого – тропар преподобної, глас 8-ий. «Слава: І нині» – Богородичний за гласом «Слави», від менших: «Непохитне утвердження...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобної, глас 8-ий (двічі). «Слава: І нині» – Богородичний за гласом «Слави», від менших: «Непохитне утвердження...». Кафизми 7-а, 8-а і 9-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий (з ірмосом) на 6, 2-ий на 4 і преподобної на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої и 9-ої пісень – ірмоси канону Мінеї (преподобної). Після 3-ої пісні – сідальний преподобної, глас 4-ий. «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос преподобної, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний преподобної, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 5-ий; стих: «Взивали праведні...» і стихира мучеників, глас 2-ий. «Слава» – преподобної, глас 4-ий: «О преславне чудо...», «І нині» – Богородичний за гласом «Слави», від менших: «Від усіх бід рабів Твоїх оберігай...». Після Трисвятого – тропар преподобної, глас 8-ий. «Слава: І нині» – Богородичний за гласом «Слави», від менших: «Діво Пречиста, спаси нас молитвами Твоїми...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобної."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар преподобної; кондак дня, кондак преподобної. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар преподобної; кондак дня, кондак храму, кондак преподобної. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобної. Апостол і Євангеліє – дня і преподобної."}]},
{"date":"11-04","weekday":"середа","title":"Прп. Іоаникія Великого (846). Сщмчч. Никандра, єп. Мирського, і Єрмія, пресвіт. (І). Пам’ять освячення собору Святої Софії в Києві (ХІ). Прп. Меркурія, посника Києво-Печерського, в Дальніх печерах (ХІV). Свт. Павла (Конюшкевича), митр. Тобольського (1770). Ікони Божої Матері «Оранта-Непорушна стіна» (ХІ).","readings":["Ран. – Лк., 4 зач., I, 39 – 49, 56.","Літ. – 1 Сол., 264 зач., II, 1 – 8. Лк., 56 зач., XI, 9 – 13.","Богородиці: Флп., 240 зач., II, 5 – 11. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершується полієлейна служба ікони Божої Матері.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-й антифон. На «Господи, взиваю» стихири свята Богородиці, глас 4-ий – 8, (перші дві стихири по тричі, а третя – двічі). «Слава: І нині» – Богородиці, глас 6-й: «Як вінцем пресвітлим...». Вхід. Прокимен дня. Паремії свята – 3. На літії стихири храму. На стиховні стихири Богородиці, глас 3-ій (з своїми приспівами). «Слава: І нині» – свята, глас 2-ий: «Думки очистивши і розум...». Після Трисвятого – тропар Богороці, глас 4-ий: «До Богородиці щиро нині...». «Слава: І нині» – інший тропар, глас той самий: «Не замовкнемо ніколи...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» тропар Богороці, глас 4-ий: «До Богородиці щиро нині...» (двічі). «Слава: І нині» – інший тропар, глас той самий: «Не замовкнемо ніколи...» Кафизми 10-а і 11-а. Малі єктенії. Сідальні Богородиці (двічі). Полієлей. Величання Богородиці і вибраний псалом. Сідальний Богородиці після полієлея, глас 1-ий. «Слава: І нині» – той самий сідальний. Степена – 1-й антифон 4-го гласу. Прокимен Богородиці, глас 4-ий: «Слухай, дочко, і споглянь, і прихили вухо Твоє»; стих: «Вилилось із серця мого слово благе, кажу я про діла мої Цареві». Євангеліє Богородиці – Лк., Зач. 4. Після 50-го псалма: «Слава» – «Молитвами Богородиці...», «І нині» – той же стих. Стихира Богородиці, глас 6-ий: «Нині небесні врата...». Канони: Богородиці з ірмосом на 14 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний Богородиці, глас 4-ий. «Слава: І нині» – інший сідальний Богородиці, глас той самий. Після 6-ої пісні – кондак та ікос Богородиці, глас 6-ий. На 9-ій співаємо «Чеснішу...» По 9-ій пісні – Світильний Богородиці. «Слава: І нині» – той самий світильний Богородиці. «Все дише...» та хвалітні псалми. На хвалітніх стихири Богородиці, глас 1-ий – 4 (перша стихира двічі). «Слава: І нині» – Богородиці, глас 8-ий: «Богородицю Марію...». Велике славослів’я. Після Трисвятого – тропар Богороці, глас 4-ий: «До Богородиці щиро нині...». «Слава: І нині» – інший тропар, глас той самий: «Не замовкнемо ніколи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Богородиці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні Богородиці, пісня 3-тя – 4 (з ірмосом), пісня 6-та – 4. На вході – «Прийдіть... молитвами Богородиці...». Після входу – тропар Богородиці. «Слава: І нині» – кондак Богородиці. Прокимен, алилуарій і причасний – дня і Богородиці. Апостол і Євангеліє – дня і Богородиці."}]},
{"date":"11-05","weekday":"четвер","title":"Мч. Галактіона та мц. Єпістимії (ІІІ). Апп. від 70-х: Патрова, Єрма, Ліна, Гая, Філолога (І). Свт. Григорія, архієп. Олександрійського (ІХ).","readings":["1 Сол., 265 зач., II, 9 – 14. Лк., 57 зач., XI, 14 – 23."],"notes":"Служба мчч. Галактіона та Єпістимії не має святкового знака, звершується разом з службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма – 12-та (яка не була прочитана на ранній середи). На «Господи, взиваю» стихири на 6: Октоїха, глас 5-ий – 3 і мучеників, глас 8-ий – 3. «Слава: І нині» – Богородичний Мінеї: «Радуйся, душ спасіння...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 5-ий. «Слава: І нині» – Богородичний Октоїха. Після Трисвятого тропар мученикам, глас 4-ий, «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Слово Отче, Христа Бога нашого...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мученикам, глас 4-ий (двічі). «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Слово Отче, Христа Бога нашого...». Кафизми 13-а, 14-а, 15-а. Малі ектенії. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6, 2-й на 4, мучеників, глас той самий на 4. Біблійні пісні «Господеві співаймо...» Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучеників. Після 3-ої пісні – сідальний мучеників, глас 4-ий. «Слава: І нині» – Бородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мучеників, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...» Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава: І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 5-ий. «Слава: І нині» – Богородичний Октоїха. Після Трисвятого – Тропар мучеників, глас 4-й «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти вища від усіх творінь...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ тропар і кондак мучеників"},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар мучеників; кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар мучеників; кондак дня, кондак храму, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"11-06","weekday":"п’ятниця","title":"Сщмч. Павла, архієп. Константинопольського, спов. (350). Прп. Луки, іконома Києво-Печерського, в Ближніх печерах (ХІІІ). Мцц. Текуси, Олександри, Полактії, Клавдії, Євфрасії, Афанасії і Мотрони (ІІІ). Прп. Луки Тавроменійського (800 – 820).","readings":["1 Сол., 266 зач., II, 14 – 19. Лк., 58 зач., XI, 23 – 26."],"notes":"Служба святителю немає святкового знаку (береться із Загальної Мінеї (с. 384)) і звершується зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 5-ий – 3, і святителя, глас 6-ий – 3. «Слава» – святителя, глас 8-ий: «Чеснотами твоїми, преподобний отче...», «І нині» – Хрестобогородичний Мінеї, глас той самий: «Не можу стерпіти, Сину...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 5-ий. «Слава» – святителя, глас 8-ий: «Ти єси пастир добрий...», «І нині» – Хрестобогородичний Мінеї: «Бачачи Тебе розіп’ятим...». Після Трисвятого – тропар святителя, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 4-ий (двічі). «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...». Кафизми 19-а і 20-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), 2-ий на 4 і святителя на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (святителя). Після 3-ої пісні – Сідальний святителя, глас 4-ий. «Слава: І нині» – Хрестобогородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос святителя, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний святителя, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 5-ий. «Слава: І нині» – Хрестобогородичний Октоїха, глас той самий. Після Трисвятого – тропар святителю, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителю."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У Господньому храмі – тропар дня «Спаси, Господи...», тропар святителю, кондак святителю. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар святителю; кондак дня, кондак святителю. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар святителю; кондак дня, кондак храму, кондак святителю. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"11-07","weekday":"субота","title":"Мчч. постраждалих у Мелитині: Ієрона, Ісихія, Никандра, Афанасія, Маманта, Варахія, Калиника, Феогена, Никона, Лонгина, Федора, Валерія, Ксанфа, Феодула, Калимаха, Євгенія, Феодоха, Острихія, Епіфанія, Максиміана, Дукитія, Клавдіана, Феофіла, Гігантія, Дорофея, Феодота, Кастрикія, Аникити, Фемелія, Євтихія, Іларіона, Діодота й Амонита (ІІІ). Прп. Лазаря Галісійського, ієром. (1053). Мч. Феодота Анкирського, корчмар (303). Мчч. Меласипа і Касинії та сина їхнього Антоніна (363). Мчч. Авкта, Тавріона і Фесалонікії.","readings":["2 Кор., 185 зач., VIII, 1 – 5. Лк., 36 зач., VIII, 16 – 21."],"notes":"Служба 33-ох мучеників і прп. Лазаря не має святкового знаку, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: мучеників, глас 4-ий – 3, і преподобного, глас 6-ий – 3. «Слава» – преподобного, глас 5-ий: «Преподобний отче, ти не дав очам твоїм...», «І нині» – Богородичний воскресний, глас 5-ий: «У Червоному морі...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 5-ий (мученичі з числа стихир на «Господи, взиваю...»). «Слава» – преподобного, глас 6-ий: «Преподобний отче, по всій землі розійшлося віщування...», «І нині» – Богородичний за гласом «Слави», від менших: «Молитвами, народившої Тебе...». Після Трисвятого – тропар мучеників, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний воскресний, глас 5-ий: «Радуйся, двері Господні непрохідні...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучеників, глас 4-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний воскресний за гласом «Слави»: «Ти, що заради нас народився від Діви...» Кафизми 16-а, і 17-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: мучеників, на 6 (ірмос по двічі), преподобного, глас на 4 і Октоїха (мученичий) на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичого канону Октоїха. Після 3-ої пісні – кондак преподобного, глас 4-ий. Сідальний мучеників, глас 4-ий. «Слава» – сідальний преподобного, глас 3-ій, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мучеників, глас 8-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Світильний мучеників, світильний преподобного. «Слава» – Екзапостиларій Октоїха, «І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 5-ий (мученичі з числа хвалітніх стихир». «Слава: І нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар мучеників, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Діво Пречиста, спаси на молитвами Твоїми...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар мучеників. «Слава» – тропар преподобного. Кондаки преподобного і мучеників читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6. Після входу – тропарі та кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня тропар мучеників, тропар преподобного, кондак храму, кондак мучеників, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». У храмі святого – тропар дня «Апостоли, мученики...», тропар мучеників, тропар преподобного; кондак мучеників, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня і за суботу."}]},
{"date":"11-08","weekday":"неділя","title":"23-тя неділя після П’ятдесятниці. Глас 6-й. Собор архістратига Михаїла та інших небесних сил безплотних. Архангелів: Гавриїла, Рафаїла, Уриїла, Селафиїла, Ієгудиїла, Варахиїла та Ієремиїла.","glas":6,"readings":["Ран. – Єв. 1-е, Мф., 116 зач., XXVIII, 16 – 20.","Літ. – Еф., 220 зач., II, 4 – 10. Лк., 38 зач., VIII, 26 – 39.","Архістр.: Євр., 305 зач., II, 2 – 10. Лк., 51 зач., X, 16 – 21."],"notes":"Звершується бдінна служба Архістратига Михаїла та інших Небесних Сил безплотних у поєднанні з воскресною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафізма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 6-ий – 4 і Безплотних, глас 4-ий – 6. «Слава» – Безплотних, глас 6-ий: «Радійте з нами, всі ангельські чини...», «І нині» – догматик, глас 6-ий: «Хто тебе не ублажить Пресвята Діво...». Вхід. Прокимен дня. Паремії Безплотних – 3. На літії стихири Безплотних, глас 1-ий і глас 2-ий. «Слава» – Безплотних, глас 4-ий: «Вогняними вустами...», «І нині» – Богородичний Мінеї, глас той самий: «Нині Боговмістимий храм...». На стиховні стихири воскресні, глас 6-ий. «Слава : І нині» – Безплотних, глас 8-ий: «Як чиноначальник і перший воєвода...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар Безплотних, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 6-ий (двічі). «Слава» – тропар Безплотних, глас 4-ий, «І нині» – Богородичний воскресний за гласом тропаря: «Від віку утаємнене...». Кафізми 2-а і 3-я. Малі ектенії. Сідальні влскресні. Полієлей. Величання Безплотних: «Величаємо тебе, святий архістратисамий Божий Михаїле, і всі воїнства херувимів і серафимів, що прославляєте Господа». і вибраний псалом: «Сповідуюсь Тобі, Господи, всім серцем моїм і перед ангелами оспівую Тебе». «Ангельський собор...». Іпакої гласу. Сідальний Безплотних після першої кафізми, глас 1-ий: «Перед престолом страшним стоїте ви...», інший сідальний Безплотних після першої кафізми: «Собор ангельський...»; сідальний Безплотних після другої кафізми, глас 2-ий: «Серед полків ангельських...», інший сідальний Безплотних після другої кафізми, глас 2-ий: «Херувими і Серафими з многоочитим воїнством...»; Сідальний Безплотних полієлея, глас 8-ий. «Слава» – інший сідальний Безплотних після полієлея, глас 4-ий, «І нині» – Богородичний Мінеї, глас той самий. Степенні антифони і прокимен гласу. Євангеліє воскресне 1-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмос один раз), Богородиці (Октоїха) на 2 і безплотних (два канони) на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос Безплотних, глас 2-ий; сідальний Безплотних, глас 8-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 6-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Свят Господь Бог наш...». Екзапостиларій воскресний, світильний Безплотних. «Слава» – інший світильний Безплотних, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 6-ий – 4 і Безплотних, глас 1-ий і глас 4-ий – 4. «Слава» – рання євангельська стихира 1-а, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар «Воскрес із гробу...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар Безплотних. Кондаки воскресний та Безплотних читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і Безплотних, пісня 3-я – 4. На вході – «Прийдіть... що воскрес із мертвих...». Після входу – тропарі і кондаки: У храмі Господському і святого – тропар воскресний, тропар Безплотних. «Слава» – кондак Безплотних, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар Безплотних; кондак воскресний. «Слава» – кондак Безплотних, «І нині» – кондак храму. Прокимен, алилуарій і причасний – воскресні та Безплотних. Апостол і Євангеліє – дня і Безплотних."}]},
{"date":"11-09","weekday":"понеділок","title":"24-й тиждень після П’ятдесятниці. Мчч. Онисифора і Порфирія (бл. 284 – 305). Прп. Мотрони Константинопольської (бл. 492). Прп. Феоктисти (881). Прп. Онисифора, сповідника Києво-Печерського, в Ближніх печерах (1148). Мч. Олександра Солунського (ІV). Мч. Антонія Апамейського (V). Прп. Іоана Колова (V). Прпп. Євстолії (610) і Сосипатри (625). Свт. Нектарія Егінського, митр. Пентапольского, чудотворця (1920). Ікони Божої Матері «Скоропослушниця» (X).","readings":["Ран. – Лк., 4 зач., I, 39 – 49, 56.","Літ. – 1 Сол., 267 зач., II, 20 – III, 8. Лк., 59 зач., XI, 29 – 33.","Богородиці: Флп., 240 зач., II, 5 – 11. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершується полієлейна служба на честь ікони Божої Матері «Скоропослушниця».","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири Богородиці, глас 1-ий і глас 4-ий – 8. «Слава : І нині» – Богородиці, глас 7-ий: «Коли трапезар Дохіарський Ніл...». Вхід. Прокимен дня. Паремії Богородиці – 3. На стиховні стихири Богородиці, глас 5-ий (зі своїми приспівами). «Слава: І нині» – Богородиці, глас 8-ий: «О, многі чудеса Твої, Богоблагодатна...». Після Трисвятого – тропар Богородиці, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Богородиці, глас 4-ий (двічі). «Слава: І нині» – той самий тропар. Кафизми 4-а і 5-а. Малі ектенії. Сідальні Богородиці (по двічі). Полієлей. Величання Богородиці і вибраний псалом. Сідальний Богородиці після полієлея, глас 8-ий. «Слава: І нині» – той самий сідальний. Степенна – 1-ий антифон 4-го голосу. Прокимен і Євангеліє – Богородиці. Після 50-го псалма: «Слава» – «Молитвами Богородиці...». Стихира Богородиці, глас 7-ий: «Прохання рабів Твоїх виконай...». Канони: Богородиці 1-ий з ірмосом на 6 (ірмоси по двічі) і 2-ий на 8. Біблійні пісні «Співаємо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний Богородиці. «Слава: І нині» – той самий сідальний. Після 6-ої пісні – кондак та ікос Богородиці, глас 8-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний Богородиці. «Слава: І нині» – той самий світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Богородиці, глас 5-ий – 4 (перша стихира – двічі). «Слава: І нині» – Богородиці, глас 3-ій: «Радісне минуле свято...». Велике славослів’я. Після Трисвятого – тропар Богородиці, глас 4-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Богородиці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Богородиці, 1-го канону пісня 3-я – 4 (з ірмосом), і 2-го канону пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар Богородиці. «Слава» – кондак храму, «І нині» – кондак Богородиці. У храмі Богородиці – тропар Богородиці («Скоропослушниця»). «Слава: І нині» – кондак Богородиці («Скоропослушниця»). У храмі святого – тропар Богородиці, тропар храму. «Слава» – кондак храму, «І нині» – кондак Богородиці. Прокимен, алилуарій і причасний – дня і Богородиці. Апостол і Євангеліє – дня і Богородиці."}]},
{"date":"11-10","weekday":"вівторок","title":"Апп. від 70-х: Ераста, Олімпа, Родіона, Сосипатра, Куарта (Кварта) і Тертія (Терентія) (І). Мч. Ореста Тіанського, лікаря (304). Сщмч. Милія, єп. Перського, і двох учнів його (341). Прп. Феостирикта, що в Символах. Мч. Костянтина, кн. Грузинського (842). Колесування вмч. Георгія (303, Груз.).","readings":["1 Сол., 268 зач., III, 9 – 13. Лк., 60 зач., XI, 34 – 41."],"notes":"Служба апостолів та мч. Ореста не має святкового знака, звершується разом з службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-а (яка не була прочитана на ранній понеділка). На «Господи, взиваю» стихири на 6: апостолів, глас 1-ий – 3, і мученика, глас 1-ий – 3. «Слава: І нині» – Богородичний Мінеї, глас той самий (зі служби апостолів): «Всехвальна Владичице, надія вірних і утвердження, пристанище і допомога, Тебе молимо: від всякої біди рабів Твої оберігай, що з вірою поклоняються Різдву Твоєму. Його ж моли дарувати душам нашим мир і велику милість...» . (у нашій Мінеї (КП) він не написаний, а є лише в Мінеї, яку видала Житомирсько-Польська єпархія) Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 6-ий. «Слава: І нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар апостолів, глас 3-ій. «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний за гласом слави, від менших: «До Богородиці щиро нині звернімося...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостолів, глас 3-ій (двічі). «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний за гласом слави, від менших: «До Богородиці щиро нині звернімося...». Кафизми 7-а, 8-а і 9-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), апостолів, глас 1-ий на 4 і мученика, глас 2-ий на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мученика. Після 3-ої пісні – інший кондак апостолів, глас 4-ий; сідальний апостолів, глас 1-ий. «Слава» – сідальний мученика, глас 4-ий, «І нині» – Богородичний Мінеї, глас 1-ий (зі служби апостолів). Після 6-ої пісні – кондак та ікос апостолів, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний апостолів, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 5-ий. «Слава: І нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар апостолів, глас 3-ій. «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар апостолів. «Слава» – тропар мученика. Кондаки апостолів читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар апостолів; тропар мученика; кондак дня, кондак апостолів. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар апостолів, тропар мученика; кондак дня, кондак храму, кондак апостолів. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"11-11","weekday":"середа","title":"Вмч. Мини Фригійського, воїна (304). Мч. Віктора і мц. Стефаниди (ІІ). Сщмч. Вікентія Сарагоського, дияк. (304). Прп. Федора Студита, спов. (826). Мч. Стефана Дечанського (бл. 1336, Серб.).","readings":["1 Сол., 269 зач., IV, 1 – 12. Лк., 61 зач., XI, 42 – 46.","Прп.: Еф., 233 зач., VI, 10 – 17. Мф., 10 зач., ІV, 25 – V, 12."],"notes":"Звершується славослівна служба мчч. Мини, Віктора, Вікентія, мц. Стефанида і прп. Феодора Студита.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: мучеників, глас 4-ий – 3, і преподобного, глас 8-ий – 3. «Слава» – мучеників, глас 6-ий: «Знову засяяла нам...», «І нині» – Богородичний воскресний: «Хто Тебе не ублажить...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 6-ий; стих: «Праведник, як фінікс процвіте і як кедр, що в Лівані, примножиться» і стихира мученика, глас 8-ий: «За Життя всіх страждаєш...». «Слава» – преподобного, глас 6-ий: «Преподобний отче...», «І нині» – Богородичний воскресний: «Творець і Визволитель...». Після Трисвятого – тропар великомученика, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний воскресний за гласом «Слави»: «Ти, що заради нас народився від Діви...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар великомученика, глас 4-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний воскресний за гласом «Слави»: «Ти, що заради нас народився від Діви...». Кафизми 10-а і 11-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 2, мучеників на 6 і преподобного на 6. Біблійні пісні «Господеві співаймо...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – кондак та ікос преподобного, глас 2-ий; сідальний великомученика, глас 8-ий. «Слава» – сідальний преподобного, глас 3-ій, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос мучеників, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Світильний мучеників, інший світильний великомученика. «Слава» – світильний преподобного, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: мучеників, глас 4-ий – 3 і преподобного, 2-ий – 3. «Слава» – преподобного, глас 8-ий: «Безліч ченців наставника...», «І нині» – Богородичний Мінеї, глас той самий: «Владичице прийми...». Велике славослів’я. Після Трисвятого – тропар великомученика, глас 4-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний воскресний за гласом «Слави»: «Ти, що заради нас народився від Діви...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар великомученика. «Слава» – тропар преподобного. Кондаки преподобного і мучеників читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні мучеників, пісня 3-я (з ірмосом) на 4 і преподобного, пісня 6-а на 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар великомученика, тропар преподобного; кондак великомученика. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар храму, тропар великомученика, тропар преподобного; кондак великомученика, кондак преподобного. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"11-12","weekday":"четвер","title":"Свт. Іоана Милостивого, патр. Олександрійського (620). Прп. Ніла, посника (V). Прор. Ахії (960 до Р. Х.). Ікони Божої Матері «Милостива».","readings":["1 Сол., 271 зач., V, 1 – 8. Лк., 62 зач., XI, 47 – XII, 1 (за четвер).","1 Сол., 272 зач., V, 9 – 13, 24 – 28. Лк., 63 зач., XII, 2 – 12 (за п’ятницю).","Свт.: Євр., 311 зач., IV, 14 – V, 6. Мф., 16 зач., VІ, 1 – 13 (під зачало)."],"notes":"Служба свт. Іоана Милостивого та при. Ніла шестирична звершується з службою Октоїха","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-а (яка не була прочитана на ранній середи). На «Господи, взиваю» стихири на 6: святителя, глас 4-ий – 3, і преподобного, глас 8-ий – 3. «Слава» – святителя, глас 2-ий: «Милості джерело для убогих...», «І нині» – Богородичний за гласом «Слави», від менших: «Як плодовите оливкове дерево...» Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 6-ий. «Слава» – преподобного, глас 8-ий: «Безліч ченців наставника...», «І нині» – Богородичний за гласом «Слави», від менших: «Я, Діво Свята Богородице...». Після Трисвятого – тропар святителя, глас 8-ий. «Слава» – тропар преподобного, глас той самий, «І нині» – Богородичний за гласом «Слави», від менших: «Духовні врата життя...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 8-ий (двічі). «Слава» – тропар преподобного, глас той самий, «І нині» – Богородичний за гласом «Слави», від менших: «Духовні врата життя...». Кафизми 13-а, 14-а, 15-а . Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси по двічі), святителя на 4, канон преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону преподобного. Після 3-ої пісні – кондак та ікос преподобного, глас 8-ий, сідальний святителя, глас 8-ий. «Слава» – сідальний преподобного, глас 8-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос святителя, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. Світильний святителя. «Слава» – світильний преподобного, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 6-ий. «Слава» – преподобного, глас той самий: «Преподобний отче...», «І нині» – Богородичний за гласом «Слави», від менших: «Переміна скорботним...». Після Трисвятого – тропар святителя, глас 8-ий. «Слава» – тропар преподобного, глас той самий, «І нині» – Богородичний за гласом «Слави», від менших: «Діво Пречиста, спаси нас...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар святителя. «Слава» – тропар преподобного. Кондаки святителя і преподобного читаються змінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, два тропарі дня, тропар святителя, тропар преподобного, два кондаки дня, кондак святителя, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – два тропарі дня, тропар храму, тропар святителя, тропар преподобного; два кондаки дня, кондак храму, кондак святителя, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня (четверга) і святителя. Апостол і Євангеліє – дня (за четвер і п’ятниці, під зачало) і святителя."}]},
{"date":"11-13","weekday":"п’ятниця","title":"Свт. Іоана Золотоустого, архієп. Константинопольського (407). Сщмч. Антоніна, пресвітера, мчч. Никифора і Германа (308). Мц. Манефи (308).","readings":["Ран. – Ін., 35 зач. (від пол.), X, 1 – 9.","Літ. – Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16."],"notes":"Звершується бдінна служба свт. Іоана Золотоустого. ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири святителя, глас 4-ий – 8 (перші дві стихири – двічі). «Слава» – святителя, глас 6-ий: «Преподобний, треблаженний...», «І нині» – догматик, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії святителя – 3. На літії стихира храму і святителя, глас 1-ий, 2-ий і 4-ий. «Слава» – святителя, глас 4-ий: «Подобало мати царюючому граду...», «І нині» – Богородичний Мінеї: «Тебе придбали як стіну...». На стиховні стихири святителя, глас 5-ий (зі своїми приспівами). «Слава» – святителя, глас 6-ий: «Трубою золотоголосою явився ти...», «І нині» – Богородичний воскресний за гласом «Слави»: «Творець і Визволитель...». Після Трисвятого – тропар святителя, глас 8-ий (двічі) і «Богородице Діво...» (один раз).","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 8-ий (двічі). «Слава: І нині» – Богородичний воскресний, глас той самий: «Ти що ради нас...». Кафизми 19-а і 20-а. Малі ектенії. Сідальні святителя (по двічі). Полієлей. Величання святителя і вибраний псалом. Сідальний святителя після полієлея, глас 8-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен апостола, глас 1-ий: «Уста мої...». Євангеліє – святителя. Після 50-го псалма: «Слава» – «Молитвами святителя Іоана...». Стихира апостола, глас 6-ий: «Вилилася благодать...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і святителя на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний святителя, глас 8-ий. «Слава» – інший сідальний, глас 8-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 6-ий. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний святителя. «Слава» – інший сідальний святителя, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири святителя, глас 4-ий – 4. «Слава» – святителя, глас 8-ий: «Золотими словами і Боговіщанними повчаннями...», «І нині» – Богородичний Мінеї, глас той самий: «Владичице прийми...». Велике славослів’я. Після Трисвятого – тропар святителя, глас 8-ий. «Слава і нині» – Богородичний воскресний, глас той самий: «Ти, що ради нас...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні святителя, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – святителя. Апостол і Євангеліє – святителя."}]},
{"date":"11-14","weekday":"субота","title":"Апостола Филипа (І). Св. блгв. Візантійського імператора Юстиніана (565) та імператриці Феодори (548). Свт. Григорія Палами, архієп. Фессалонікійського (бл. 1360).","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – Ап.: 1 Кор., 131 зач., IV, 9 – 16. Ін., 5 зач., I, 43 – 51.","Ряд.: 2 Кор., 191 зач., XI, 1 – 6. Лк., 40 зач., IX, 1 – 6."],"notes":"Заговини на Різдвяний (Пилипів) піст. Звершується полієлейна служба апостолу Филипу.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири апостола, глас 6-ий – 8 (стихири – двічі). «Слава» – апостола, глас 6-ий: «Блищанням Великого Світла...», «І нині» – Богородичний воскресний, глас той самий: «Хто Тебе не ублажить...». Вхід. Прокимен дня. Паремії апостола – 3 [1]. На стиховні стихири апостола, глас 1-ий (зі своїми приспівами). «Слава» – апостола, глас 2-ий: «Хресним подвигом...», «І нині» – Богородичний воскресний за гласом «Слави»: «О, нове чудо...». Після Трисвятого – тропар апостола, глас 3-ій. «Слава: І нині» – Богородичний воскресний, глас 6-ий: «Провіщає Гедеон зачаття...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 3-ій (двічі). «Слава: І нині» – Богородичний воскресний, глас 3-ій: «Тебе оспівуємо, Богородице Діво...». Кафизми 16-а і 17-а. Малі ектенії. Сідальні апостола (по двічі). Полієлей. Величання апостола: «Величаємо тебе,/ святий апостоле Филипе/ і шануємо страждання і труди твої,/ що ними потрудився ти/ у благовісті Христовім» і вибраний псалом: «Від сходу сонця і до заходу хвальне ім’я Господнє». Сідальний апостола після полієлея, глас 8-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен апостола, глас 4-ий: «По всій землі...». Євангеліє – апостола. Після 50-го псалма: «Слава» – «Молитвами святого апостола Филипа...». Стихира апостола, глас 6-ий: «Премудрий ловче душ...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і апостола на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний апостола, глас 8-ий. «Слава» – інший сідальний, глас 8-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 8-ий. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний апостола. «Слава: І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостола, глас 2-ий і глас 8-ий – 4. «Слава» – апостола, глас 3-ій: «Ловління риби ти перетворив на ловління людей...», «І нині» – Богородичний Мінеї, глас той самий: «Богородице, Заступнице всіх...». Велике славослів’я. Після Трисвятого – тропар апостола, глас 3-ій. «Слава і нині» – Богородичний воскресний, глас 3-ій: «Тебе оспівуємо, Богородице Діво...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостола."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні апостола, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар апостола. «Слава» – кондак апостола, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостола; кондак храму. «Слава» – кондак апостола, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і апостола. Апостол і Євангеліє – дня і апостола. [1] За традицією, новозавітні паремії читаються при відкритих царських вратах."}]},
{"date":"11-15","weekday":"неділя","title":"24-та неділя після П’ятдесятниці. Глас 7-й. Мчч. і сповв. Гурія, Самона (299 – 306) і сщмч. Авіва, дияк. (322). Прп. Паїсія Величковського (1794). Мчч. Елпідія, Маркела і Євстохія (361 – 363). Мч. Димитрія (бл. 307). Куп’ятицької ікони Божої Матері (1182).","glas":7,"readings":["Ран. – Єв. 2-е, Мк., 70 зач., XVI, 1 – 8.","Літ. – Еф., 221 зач., II, 14 – 22. Лк., 39 зач., VIII, 41 – 56.","Прп.: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Служба прп. Паїсія Величковського (із Загальної Мінеї), славослівна, звершується з воскресною службою Октоїха. Початок Різдвяного посту.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж...» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 7-ий – 6 і преопдобного, глас 8-ий – 4 (перша стихира двічі). «Слава» – преподобного, глас 6-ий: «Те, що було образом Божим...», «І нині» – догматик, глас 7-ий: «Матір’ю надприродно стала Ти...». Вхід. Прокимен дня. На літії стихири храму. На стиховні стихири воскресні, глас 7-ий. «Слава» – преподобного, глас 8-ий: «Тебе як наставника множества ченців шануємо...», «І нині» – Богородичний воскресний за гласом «Слави»: «Безневісна Діво...». Після Трисвятого – «Богородице Діво...» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 7-ий (двічі). «Слава» – тропар преподобного, глас 8-ий, «І нині» – Богородичний воскресний за гласом «Слави»: «Ти, що заради нас...». Кафизми 2-а і 3-я. Малі єктенії. Сідальні воскресні. Полієлей. «Ангельський собор...». Іпакої, сідальні, степенні і прокимен гласу. Євангеліє воскресне 2-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний гласу з ірмосом на 4 (ірмоси раз), хрестовоскресний на 2, Богородиці на 2 і преподобного на 6. Біблійні пісні: «Співаймо Господеві...». Катавасія: «Відкрию уста мої...». Після 3-ої пісні – кондак і ікос преподобного, глас 2-ий, кондак; сідальний преподобного, глас 1-ий. «Слава: І нині» – Богородичний Мінеї. Після 6-й пісні – кондак та ікос воскресні, глас 7-ий. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 2-ий. «Слава:» – Світильний преподобного, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 7-ий – 4 і преподобного, глас 6-ий і 2-ий (зі славником). «Слава» – стихира євангельська 2-а, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «В день спасіння світу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар преподобного. Кондак тільки воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і преподобного, пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар воскресний, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар преподобного; кондак воскресний. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар преподобного; кондак воскресний, кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні та преподобного. Апостол і Євангеліє – дня і преподобного."}]},
{"date":"11-16","weekday":"понеділок","title":"25-й тиждень після П’ятдесятниці. Апостола і євангеліста Матфея (60). Прав. Фулвіана, кн. Ефіопського, у св. хрещенні Матфея (І).","readings":["Ран. – Ін., 67 зач., XXI, 15 – 25.","Літ. – 2 Сол., 274 зач., I, 1 – 10. Лк., 65 зач., XII, 13 – 15, 22 – 31.","Ап.: 1 Кор., 131 зач., IV, 9 – 16. Мф., 30 зач., IX, 9 – 13."],"notes":"Звершується полієлейна служба апостола і євангелиста Матфея.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири апостола, глас 4-ий – 8 (перші три стихири – двічі). «Слава» – апостола, глас той самий: «Ти, богоприємний, старанно пішов за Христом...», «І нині» – Богородичний воскресний, глас той самий: «Пророк Давид...». Вхід. Прокимен дня. Паремії апостола – 3. На стиховні стихири апостола, глас 4-ий (зі своїми приспівами). «Слава» – апостола, глас 6-ий: «Із безодні злоби на крайню висоту чеснот...», «І нині» – Богородичний воскресний, глас той самий: «Творець і Визволитель...». Після Трисвятого – тропар апостола, глас 3-ій. «Слава: І нині» – Богородичний воскресний, глас той самий: «Тебе оспівуємо, Богородице Діво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 3-ій (двічі). «Слава і нині» – Богородичний воскресний, глас той самий: «Тебе оспівуємо, Богородице Діво...». Кафизми 4-а і 5-а. Малі ектенії. Сідальні апостола (по двічі). Полієлей. Величання апостола: «Величаємо тебе,/ святий апостоле і євангелисте Матфею,/ і шануємо страждання і труди твої,/ ними ж ти потрудився єси,// у благовісті Христовім» і вибраний псалом: «Від сходу сонця і до заходу хвальне ім’я Господнє». Сідальний апостола після полієлея, глас 8-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той же. Степенна – 1-ий антифон 4-го гласу. Прокимен апостола, глас 4-ий: «По всій землі розійшлося віщування їх/ і в кінці вселенної слова їх»; стих: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь». Євангеліє – апостола: Ін. 67 Зач. Після 50-го псалма: «Слава» – «Молитвами апостола і євангелиста Матфея...». Стихира апостола, глас 6-ий: «Нині заплещімо в піснях, вірні...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і апостола, глас 4-ий на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Відкрию уста мої...». Після 3-ої пісні – сідальний апостола, глас 8-ий. «Слава» – інший сідальний апостола, глас той самий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 4-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний апостола. «Слава» – інший світильний апостола, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостола, глас 4-ий і глас 8-ий – 4. «Слава» – апостола, глас 2-ий: «Ярмо неправди залишив...», «І нині» – Богородичний Мінеї, глас той самий: «Спаси від бід рабі Твоїх...». Велике славослів’я. Після Трисвятого – тропар апостола, глас 3-ій. «Слава: І нині» – Богородичний воскресний, глас той самий: «Тебе оспівуємо, Богородице Діво...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостола."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні апостола, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар апостола. «Слава» – кондак апостола, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостола; кондак храму. «Слава» – кондак апостола, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і апостола. Апостол і Євангеліє – дня і апостола."}]},
{"date":"11-17","weekday":"вівторок","title":"Свт. Григорія Чудотворця, єп. Неокесарійського (бл. 266 – 270). Прп. Лазаря, іконописця (бл. 857). Мч. Гоброна, у св. хрещенні Михаїла, і з ним 133 воїнів (914, Груз.). Мчч. Аціскла і Вікторії Кордувійських (Кордубських) (IV).","readings":["2 Сол., 274 зач. (від половини), I, 10 – II, 2. Лк., 68 зач., XII, 42 – 48.","Свт.: 1 Кор., 151 зач., XII, 7 – 11. Мф., 34 зач. (від пол.), X, 1 – 8."],"notes":"Служба свт. Григорія Неокесарійського шестирична, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-а (яка не була прочитаною на ранній понеділка). На «Господи, взиваю» стихири святителя, глас 8-ий – 6 (перші дві стихири – двічі). «Слава» – святителя, глас 6-ий: «Увійшовши в глибину видінь...», «І нині» – Богородичний за гласом «Слави», від менших: «Ніхто, що звертається до тебе...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава» – святителя, глас 6-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Ніхто, що звертається до тебе...». Після Трисвятого – тропар святителя, глас 8-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Непохитне утвердження віри...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 8-ий (двічі). «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Непохитне утвердження віри...». Кафизми 7-а, 8-а і 9-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси раз), 2-ий на 4 і святителя на 6. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону святителя. Після 3-ої пісні – сідальний святителя, глас 3-ій. «Слава: І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос святителя, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний святителя, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий; стих: «Священики Твої зодягнуться...», і стихира святителя, глас 4-ий. «Слава» – святителя, глас 8-ий: «Преславного чудесами ієрарха...», «І нині» – Богородичний за гласом «Слави», від менших: «Покров Твій, Богородице Діво...». Після Трисвятого – тропар святителя, глас 8-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Діво Пречиста, спаси нас молитвами Твоїми...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 4 і святителя, пісня 3-тя – 4. Після вході – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар святителя; кондак дня, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар святителя; кондак дня, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій, причасний – дня і святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"11-18","weekday":"середа","title":"Мч. Платона Анкирського (302 або 306). Сщмч. Романа, диякона, і мч. отрока Варула (303). Сщмч. Закхея, дияк. Гадаринського, і мч. Алфея, читця Кесарійського (303).","readings":["2 Сол., 275 зач., II, 1 – 12. Лк., 69 зач., XII, 48 – 59."],"notes":"Служба святих мучеників не має святкового знаку і звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири на 6: мч. Платона, глас 8-ий – 3, і мч. Романа, глас 4-ий – 3. «Слава» – мч. Платона, глас 6-ий: «Страшна і преславна перемога мученика Твого, Господи...», «І нині» – Хрестобогородичний Мінеї: «Бачачи Тебе розіпнутого, Христе...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава: І нині» – Хрестобогородичний Октоїха, глас той самий. Після Трисвятого – тропар мучеників, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших, глас 4: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучеників, глас 4-ий (двічі). «Слава: І нині» – Хрестобогородичний за гласом «Слави», від менших, глас 4: «Діво Пренепорочна...». Кафизми 9-а, 10-а і 11-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси по двічі), мучеників Платона на 4 і Романа на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мученика Романа. Після 3-ої пісні – сідальний мч. Платона, глас 8-ий. «Слава» – сідальний мч. Романа, глас 4-ий, «І нині» – Хрестобогородичний Мінеї, глас той самий. По 6-й пісні – кондак та ікос мч. Платона, глас 3-ій. На 9-ій пісні співаємо «Чеснішу...». Після 9-й пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний мч. Платона, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий. «Слава: І нині» – Хрестобогородичний Октоїха, глас той самий. Після Трисвятого – тропар мучеників, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар мучеників і кондак мч. Платона."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському – тропар дня «Спаси, Господи...», тропар мучеників; кондак мч. Платона. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар мучеників; кондак дня, кондак мч. Платона. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар мучеників; кондак дня, кондак храму, кондак мч. Платона. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"11-19","weekday":"четвер","title":"Прор. Авдія, з 12-ох (ІХ ст. до Р. Х.). Мч. Варлаама (бл. 304). Прпп. Варлаама, пустельника та Іоасафа, царевича Індійського, і батька його Авеніра, царя (ІV). Прп. Варлаама, ігум. Києво-Печерського, в Ближніх печерах (1065). Мчч. Ази і з ним 150 воїнів (284 – 305). Мч. Іліодора Памфілійського (бл. 273). Прп. Іларіона, чудотворця (875, Груз.). Ікони Божої Матері «В скорботах і печалях утіха» (1863).","readings":["2 Сол., 276 зач., II, 13 – III, 5. Лк., 70 зач., XIII, 1 – 9."],"notes":"Служба пророка Авдія і мч. Варлаама не має святкового знаку, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири на 6: пророка, глас 1-ий – 3, і мученика, глас 4-ий – 3. «Слава: І нині» – Богородичний Мінеї: «Хмарами дощу Пресвятого Духа...» Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 7-ий. «Слава: І нині» – Богородичний Октоїха. Після Трисвятого – тропар пророка, глас 2-ий. «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний глас 4-ий, від менших: «Слово Отче, Христа Бога нашого...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар пророка, глас 2-ий (двічі). «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний глас 4-ий, від менших: «Слово Отче, Христа Бога нашого...». Кафизми 13-а, 14-а, 15-а . Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси по двічі), пророка, глас 5-ий на 4, канон мученика, глас 4-ий на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (мученика). Після 3-ої пісні – сідальний пророка, глас 1-ий. «Слава» – сідальний мученика, глас 4-ий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак мученика, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. Світильний святителя. «Слава» – світильний пророка, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 7-ий. «Слава: І нині» – Богородичний Октоїха. Після Трисвятого – тропар пророка, глас 2-ий. «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний за гласом слави, від менших: «...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар пророка «Слава» – тропар мученика. Кондак мученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, два тропарі дня, тропар пророка, тропар мученика, два кондаки дня, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – два тропарі дня, тропар храму, тропар пророка, тропар мученика; два кондаки дня, кондак храму, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"11-20","weekday":"п’ятниця","title":"Передсвято Введення в храм Пресвятої Богородиці. Прп. Григорія Декаполіта (бл. 842). Свт. Прокла, архієп. Константинопольського (446 – 447). Мч. Дасія Доростольського (284 – 305). Мчч. Євстафія, Феспесія і Анатолія (312). Сщмчч. Нирси, єп., та Йосифа, учня його, Іоана, Саверія, Ісакія та Іпатія, єпп. Перських; мчч. Азата, скопця, Сасонія, Фекли, Анни та інших багатьох чоловіків і жінок, які в Персії постраждали (343).","readings":["2 Сол., 277 зач., III, 6 – 18. Лк., 73 зач., XIII, 31 – 35 (за п’ятницю).","Гал., 199 зач., I, 3 – 10. Лк., 46 зач., IX, 37 – 43 (за суботу)."],"notes":"Служба прп. Григорія Декаполіта і світ. Прокла, без святкового знаку завершується разом з службою передсвята Введення в храм Пресвятої Богородиці.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а . На «Господи, взиваю» стихири на 6: свята, глас 1-ий – 3, і преподобного, глас 1-ий – 3. «Слава: І нині» – передсвята, глас 4-ий: «Нині Боговмістимий храм..». Входу нема. Прокимен дня. На стиховні стихири свт. Прокла, глас 4-ий (зі своїми приспівами). «Слава: І нині» – передсвята, глас той самий: «Прийдуть усі вірні...». Після Трисвятого – тропар преподобного, глас 3-ій. «Слава» – тропар святителя, глас 4, «І нині» – тропар передсвята, глас 4-ий: «Радість передвіщає всім нині Анна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий (один раз), тропар преподобного, глас 3-ій. «Слава» – тропар святителя, глас 4-ий, «І нині» – тропар передсвята, глас 4-ий: «Радість передвіщає всім нині Анна...». Кафизми 19-а і 20-а. Малі ектенії. Сідальні передсвята (по двічі). 50-й псалом. Канони: передсвята з ірмосом на 6 (ірмоси по двічі), преподобного на 4 і святителя на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісні – ірмос канону святителя . Після 3-ої пісні – ікос передсвята, кондак преподобного, глас 3-ій, кондак святителя, глас 4-ий, інший кондак святителя, глас 8-ий, сідальний преподобного, глас 4-ий. «Слава» – сідальний святителя, глас 3-ій, «І нині» – сідальний передсвята, глас 1-ий. Після 6-ої пісні – кондак та ікос передсвята, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний преподобного. «Слава: І нині» – світильний передсвята. «Хваліть Господа з небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири передсвята, глас 1-ий (зі своїми приспівами). «Слава: І нині» – передсвята, глас 4-ий: «Нехай нині радіє...». Після Трисвятого – тропар преподобного, глас 3-ій. «Слава» – тропар святителя, глас 4-ий, «І нині» – тропар передсвята, глас 4-ий: «Радість передвіщає всім нині Анна...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар апостолів. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 1-а (з ірмосом) – 6. На вході – «Прийдіть... у святих Дивний сий...». Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар передсвята, тропар преподобного, тропар святителя; кондак храму, кондак преподобного. «Слава» – кондак святителя, «І нині» – кондак передсвята. У храмі Богородиці – тропар передсвята, тропар преподобного, тропар святителя; кондак преподобного. «Слава» – кондак святителя, «І нині» – кондак передсвята. У храмі святого – тропар передсвята, тропар храму, тропар преподобного, тропар святителя; кондак храму, кондак преподобного. «Слава» – кондак святителя, «І нині» – кондак передсвята. Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – за п’ятницю і суботу."}]},
{"date":"11-21","weekday":"субота","title":"ВВЕДЕННЯ В ХРАМ ПРЕСВЯТОЇ ВЛАДИЧИЦІ НАШОЇ БОГОРОДИЦІ І ПРИСНОДІВИ МАРІЇ.","readings":["Ран. – Лк., 4 зач., I, 39 – 49, 56.","Літ. – Євр., 320 зач., IX, 1 – 7. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершується всенічне бдіння свята Введення в храм Пресвятої Богородиці. На трапезі дозволяється риба.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-й антифон. На «Господи, взиваю» стихири свята, глас 1-ий, глас 4-ий – 8, (перші стихири гласу по двічі). «Слава: І нині» – свята, глас 8-й: «Після народження Твого...». Вхід. Прокимен дня. Паремії свята – 3. На літії стихири свята, глас 1-ий і глас 4-ий. «Слава: І нині» – свята, глас 5-ий: «Возсіяв день радісний...». На стиховні стихири свята, глас 5-ий (з приспівами своїми). «Слава: І нині» – свята, глас 6-й: «Сьогодні зійшлися собори вірних...». Після Трисвятого – тропар свята, глас 4-ий (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава: І нині» – тропар свята, глас 4-ий. Кафизми 16-а і 17-а. Малі єктенії. Сідальні свята (двічі). Полієлей. Величання свята: «Величаємо Тебе, Пресвятая Дiво, Богообрана Отроковице, i шануємо у храм Господній входження Твоє». і вибраний псалом. Сідальний свята після полієлея, глас 8-ий: «Нехай радіє Давид...», «Слава і нині» – той самий сідальний. Степена – 1-й антифон 4-го гласу. Прокимен свята, глас 4-ий: «Слухай, дочко, і споглянь, і прихили вухо Твоє»; стих: «Вилилось із серця мого слово благе, кажу я про діла мої Цареві». Євангеліє Богородиці – Лк., Зач. 4. Після 50-го псалма: «Слава» – «Сьогодні Храм одухотворений...», «І нині» – той же стих. Стихира свята, глас 4-ий: «Сьогодні Боговмістимий храм...». Канони: свята 1-й з ірмосом на 8 (ірмоси по двічі), 2-ий свята з ірмосом на 8 (ірмоси по двічі). Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Примітка. Катавасія «Христос народжується» співається з цього дня і до віддання Різдва Христового в усі дні, в які Уставом призначається спів великого славослів’я. Після 3-ої пісні – сідальний свята, глас 4-ий. «Слава: І нині» – інший сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні не співаємо «Чеснішу...». До тропарів канону співають приспіви свята. 1-й приспів: «Ангели входження Пречистої, бачивши, здивувалися: як Діва входить у Святеє Святих». По 9-ій пісні – Світильний свята, «Слава» – той самий світильний, «І нині» – той самий світильний свята. «Все дише...» та хвалітні псалми. На хвалітніх стихири свята, глас 1-ий – 4 (зі своїми приспівами; приспіви див. на стиховні вечірні в Мінеї). «Слава: І нині» – свята, глас 2-ий: «Нині приводиться в храм...». Велике славослів’я. Після Трисвятого – тропар свята, глас 4-й (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони зображальні. Блаженні свята, пісня 3-тя – 4 (з ірмосом), пісня 6-та – 4. На вході – «Прийдіть... молитвами Богородиці...». Після входу – тропар свята. «Слава: І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – свята. Задостойник свята – приспів: «Ангели, входження Пречистої...», і ірмос 9-ої пісні: «Як до одухотвореного...» (і до віддання)."}]},
{"date":"11-22","weekday":"неділя","title":"25-та неділя після П’ятдесятниці. Глас 8-й. Післясвято Введення. Апп. від 70-х: Филимона й Архипа і мц. рівноап. Апфії (І). Блгв. Ярополка, у св. хрещенні Петра, кн. Володимирського (1086). Мц. Кикилії (Цецилії), мчч. Валеріана, Тивуртія і Максима (бл. 230). Мч. Прокопія Кесарійського, читця (303). Мч. Менигна (250). Прп. Агави Ізраїльтянина (V). Прав. Михаїла, воїна, болгарина (866).","glas":8,"readings":["Ран. – Єв. 3-е, Мк., 71 зач., XVI, 9 – 20.","Літ. – Еф., 224 зач., IV, 1 – 6. Лк., 53 зач., X, 25 – 37.","Апп.: Флм., 302 зач., I, 1 – 25. Лк., 50 зач., X, 1 – 15."],"notes":"Служба апостолів не має святкового знаку, звершується разом зі службою післясвята Введення та воскресною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж...» – кафізма вся. На «Господи, взиваю» стихири на 10: воскресні глас 8-ий – 4, свята, глас той самий – 3 і апостолів, глас 2-ий – 3. «Слава» – свята, глас 1-ий: «Нехай радіє нині небо...»; «І нині» – догматик, глас 8-ий: «Цар Небесний...». Вхід. Прокимен дня. На літії стихири свята, глас 2-ий (див. в Мінеї у службі апостолів на стихирах на стиховних вечірні, без приспівів). «Слава: І нині» – свята, глас 4-ий: «Нині Боговмістимий храм...» (див. в Мінеї у службі апостолів на стихирах на стиховних ранньої). На стиховні стихири воскресні, глас 8-ий. «Слава: І нині» – свята, глас 2-ий: «Нині в храм приводиться Всенепорочна Діва...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар свята, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 7-ий (двічі). «Слава» – тропар апостолів, глас 3-ій, «І нині» – тропар свята, глас 4-ий. Кафизми 2-а і 3-а. Малі ектенії. Сідальні Октоїха. Полієлей. «Ангельський собор...». Іпакої, степенні і прокимен гласу. Євангеліє воскресне 3-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4, Богородиці (Октоїха) на 2, свята, глас 2-ий на 4 і апостолів на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – кондак та ікос свята, глас 4-ий; кондак апостолів, глас 2-ий; сідальний апостолів, глас 8-ий. «Слава: І нині» – сідальний свята, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 8-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Свят Господь Бог наш...». Воскресний екзапостиларій 3-ій. «Слава: І нині» – світильний свята: «Тебе, Яку наперед...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 8-ий – 4 і свята, глас 6-ий (зі стихир на стиховних на ранній разом зі «Славником»). «Слава» – рання євангельська стихира 3-а, «І нині» – «Преблагословення єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...». НА 1-му і 6-му часі – тропар воскресний. «Слава» – тропар свята. Кондак свята. НА 3-му і 9-му часі – тропар воскресний. «Слава» – тропар апостолів. Кондак воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і свята, пісня 1-а – 4. На вході: «Прийдіть... що Воскрес із мертвих...». Після входу: У храмі Господському і Богородиці – тропар воскресний, тропар свята, тропар апостолів; кондак воскресний. «Слава» – кондак апостолів, «І нині» – кондак свята. У храмі святого – тропар воскресний, тропар свята, тропар храму, тропар апостолів; кондак воскресний, кондак храму. «Слава» – кондак апостолів, «І нині» – кондак свята. Прокимен, алилуарій і причасний – воскресні та апостолів. Апостол і Євангеліє – дня і апостолів. Задостойник свята."}]},
{"date":"11-23","weekday":"понеділок","title":"26-й тиждень після П’ятдесятниці. Свт. Амфілохія, єп. Іконійського (після 394). Свт. Григорія, єп. Акрагантійського (VІ – VІІ). Сщмч. Сисинія, єп. Кизицького (ІІІ), і мч. Федора Антіохійського (ІV). Прп. Олександра, засновника обителі «Невсипущих» (бл. 430).","readings":["1 Тим., 278 зач., I, 1 – 7. Лк., 75 зач., XIV, 12 – 15.","Свтт.: Євр., 334 зач., XIII, 7 – 16. Мф., 103 зач., ХХІV, 42 – 47."],"notes":"Звершується шестирична служба свт. Амфілохія, єп. Іконійського та свт. Григорія, єп. Акрагантійського разом з в службою післясвята Введення.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: свт. Амфілохія, глас 4-ий – 3, і свт. Григорія, глас 8-ий – 3. «Слава: І нині» – свята, глас 4-ий: «Прийдіть усі вірні...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 1-ий. «Слава: І нині» – свята, глас 5-ий: «Засяяло сьогодні радісне і всечесне свято...». Після Трисвятого – тропар святителів, глас 4-ий: «Боже отців наших...». «Слава: І нині» – тропар свята, глас той самий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава» – святителів глас той самий: «Боже отців наших...», «І нині» – тропар свята, глас той самий. Кафизми 4-а і 5-а. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята, глас 2-ий з ірмосом на 6 (ірмоси по двічі), свт. Амфілохія на 4 і свт. Григорія на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – кондак та ікос свята, глас 4-ий, кондак свт. Григорія, глас той самий, інший кондак свт. Григорія, глас 8-ий; сідальний свт. Амфілохія, глас той самий. «Слава» – сідальний свт. Григорія, глас 8-ий, «І нині» – сідальний свята, глас 4-ий. Після 6-ої пісні – кондак та ікос свт. Амфілохія, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свт. Амфілохія. «Слава» – світильний свт. Григорія; «І нині» – світильний свята. «Хваліте Господа з Небес...» і хвалітні псалми. «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири свята, глас 2-ий (з приспівами своїми). «Слава: І нині» – свята, глас 6-ий: «Нині зібрання вірних, зійшовшись...». Після Трисвятого – тропар святителів, глас 4-ий: «Боже отців наших...». «Слава: І нині» – тропар свята, глас той самий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святителів. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 7-а (з ірмосом) і 8-а – 4, і свт. Амфілохія, пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята, тропар святителів; кондак храму. «Слава» – кондак святителів, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар святителів; «Слава» – кондак святителів, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар святителів; «Слава» – кондак святителів, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і святителів. Апостол і Євангеліє – дня і святителів. Задостойник свята."}]},
{"date":"11-24","weekday":"вівторок","title":"Вмч. Меркурія (ІІІ). Вмц. Катерини (305 – 313). Прп. Меркурія, посника Києво-Печерського, в Дальніх печерах (ХІV). Мц. Августи Римської, мчч. Порфирія Стратилата і 200 воїнів (305 – 313). Прп. Мастридії Олександрійської. Прп. Меркурія Чернігівського, ігум. Бригинського (1956).","readings":["Ран. – Мф., 104 зач., ХХV, 1 – 13.","Літ. – 1 Тим., 279 зач., I, 8 – 14. Лк., 77 зач., XIV, 25 – 35.","Вмц.: 2 Кор., 181 зач., VI, 1 – 10. Лк., 106 зач., ХХI, 12 – 19.","Якщо звершується полієлейна служба преподобному Меркурію, то на ранній читання: Мф., 43 зач., XI, 27 – 30, на Літургії: Гал., 213 зач., V, 22 – VI, 2. Лк., 24 зач., VI, 17 – 23."],"notes":"Служба вмц. Катерини та прп. Меркурія Чернігівського ігум. Бригинського (служба прп. Меркурія із Загальної Мінеї) полієлейна у поєднанні зі службою післясвята Введення.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: свята, глас 1-ий – 2 (див. в сам день свята), вмц. Катерини, глас той самий – 3 і прп. Меркурія, глас 8-ий – 3. «Слава» – вмц. Катерини, глас 2-ий: «Радісно на свято богомудрої мучениці Катерини зберімося...», «І нині» – свята, глас 8-ий: «Після народження Твого, Богоневісто Владичице...». Вхід. Прокимен дня. Паремії великомучениці – 2 і преподобного – 1. На літії стихира свята, глас 1-ий, стихири вмц. Катерини, глас той самий, глас 2-ий, глас 4-ий і стихира прп. Меркурія, глас 1-ий (1-ша зі стихир на стиховні). «Слава» – вмц. Катерини, глас 6-ий, «І нині» – свята, глас 5-ий. На стиховні стихири свята, глас 1-ий. «Слава» – вмц. Катерини, глас 2-ий: «Житіє духовно проживши...». «І нині» свята, глас 8-ий: «Давид, проголошуючи Тебе...». Після Трисвятого – тропар вмц. Катерини, глас 4-ий, «Слава» – тропар прп. Меркурія, глас 8-ий; «І нині» – тропар свята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (один раз), тропар вмц. Катерини, глас той самий (один раз). «Слава» – тропар прп. Меркурія, глас 8-ий; «І нині» – тропар свята, глас 4-ий. Кафизми 7-а і 8-а. Малі ектенії. Після 1-ої кафизми – сідальний вмц. Катерини, глас 8-ий: «Струмками твоєї крові, мученице Христова...». «Слава» – сідальний прп. Меркурія, глас 4-ий: «За покликом Господа твого...», «І нині» свята, глас 1-ий: «Вихваляйте, діви...». Після 2-ої кафизми – сідальний вмц. Катерини, глас 4-ий: «Ту, що прийшла до Христа волею і прикрасила чеснотами серце...». «Слава» – сідальний прп. Меркурія, глас 5-ий: «Подвижника Господнього піснями вшануймо...», «І нині» свята, глас 1-ий: «Богородиця, будучи святою святих...». Полієлей. Величання великомучениці: «Величаємо тебе,/ свята великомученице Катерино,/ і шануємо чесні страждання твої,/ їх же за Христа перетерпіла єси»; і преподобного: «Ублажаємо тебе,/ преподобний отче наш Меркурію,/ і шануємо святу пам’ять твою,/ наставнику монахів// і співрозмовнику ангелів». Псалом вибраний: «Бог нам пристановище і сила, скора допомога в біді, що надходить на нас» і «Терплячи, потерпів від Господа і визволив мене». Після полієлея сідальний вмц. Катерини, глас 8-ий: «Воістину з небес, з уст Михаїла архангела прийнявши премудрість...», «Слава» прп. Меркурія, глас 1-ий: «Подолав ти спокуси пристрастей...», «І нині» свята, глас 4-ий: «Давиде, прийди раніше у храм Божий...» (див. в службі вмц. Катерини після 3-ої пісні канону). Степенні, антифон 1, глас 4-ий. Прокимен, глас 4-ий: «Дивний Бог у святих своїх, Бог Ізраїлів». Стих: «В церквах благословляйте Бога, Господа від джерел Ізраїлевих». Все, що дише... Євангеліє великомучениці від Матфея, зачало 104 (25, 1 – 13). Після 50-го псалма стихира вмц. Катерини, глас 2-ий: «Дівства твого краси зажадав Цар Слави Христос...». Канони: свята 1-ий з ірмосом на 6 (ірмоси по двічі), вмц. Катерини на 4 і прп. Меркурія на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – кондак та ікос свята, глас 4-ий, кондак та ікос прп. Меркурія, глас 2-ий; сідальний вмц. Катерини, глас 4-ий. «Слава» – сідальний прп. Меркурія, глас 1-ий, «І нині» – сідальний свята, глас 4-ий. Після 6-ої пісні – кондак та ікос вмц. Катерини, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний вмц. Катерини (двічі). «Слава» – світильний прп. Меркурія, «І нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: свята, глас 2-ий – 2, вмц. Катерини, глас 2-ий – 2, і прп. Меркурія, глас 6-ий – 2. «Слава» – вмц. Катерини, глас 2-ий: «Житіє духовне полюбивши...», «І нині» – свята, глас 6-ий: «Нині, собори вірних...». Велике славослів’я. Після Трисвятого – тропар вмц. Катерини, глас 4-ий. «Слава» – прп. Меркурія, глас 8-ий, «І нині» – тропар свята, глас 4-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – на 1-му і 3-му: тропар свята. «Слава» – тропар вмц. Катерини. Кондаки: на 1-му кондак свята; на 3-му вмц. Катерини. на 6-му і 9-му: тропар свята. «Слава» – тропар прп. Меркурія. Кондаки: на 6-му кондак свята; на 9-му прп. Меркурія."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 4-а (з ірмосом) і 5-а – 4, і вмц. Катерини пісня 6-а – 2 і прп. Меркурія, пісня 6-а – 2. На вході – «Прийдіть... молитвами Богородиці...». Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар свята, тропар вмц. Катерини, тропар прп. Меркурія; кондак храму, кондак прп. Меркурія. «Слава» – кондак вмц. Катерини, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар вмц. Катерини тропар прп. Меркурія; кондак прп. Меркурія. «Слава» – кондак вмц. Катерини, «І нині» – кондак свята. У храмі святого – тропар свята, тропар храму, тропар вмц. Катерини, тропар прп. Меркурія; кондак храму, кондак прп. Меркурія. «Слава» – кондак вмц. Катерини, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята і вмц. Катерини. Апостол і Євангеліє – дня, вмц. Катерини і прп. Меркурія (під зачало). Задостойник свята."}]},
{"date":"11-25","weekday":"середа","title":"Віддання свята Введення в храм Пресвятої Богородиці. Сщмчч. Климента, єпископа Римського (101), і Петра, архієп. Олександрійського (311). Прп. Петра Галатійського, мовчальника (бл. 429).","readings":["1 Тим., 281 зач., I, 18 – 20; II, 8 – 15. Лк., 78 зач., XV, 1 – 10.","Сщмчч.: Флп., 246 зач., ІІІ, 20 – IV, 3. Мф., 11 зач., V, 14 – 19.","Богородиці: Євр., 320 зач., IX, 1 – 7. Лк., 54 зач., X, 38 – 42; XI, 27 – 28."],"notes":"Звершується славослівна служба віддання свята Введення (Входу) у храм Пресвятої Богородиці разом зі службою сщмчч. Климента і Петра (без святкового знака).","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-а. На «Господи, взиваю» стихири на 6: свята, глас 1-ий – 3, і сщмч. Климента, глас 2-ий – 3. «Слава: І нині» – свята, глас 8-ий: «Після Народження Твого...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 5-ий (зі своїми приспівами). «Слава: І нині» – свята, глас 6-ий: «Сьогодні зійшлися собори вірних. Після Трисвятого – тропар святих, глас 4-ий: «Боже отців наших...». «Слава: І нині» – тропар свята, глас той самий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава» – тропар святих, глас той самий: «Боже отців наших...», «І нині» – тропар свята, глас той самий. Кафизми 10-а і 11-а. Малі ектенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята, глас 1-ий з ірмосом на 6 (ірмоси по двічі), сщмч. Климента на 4 і сщмч. Петра на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – кондак святих, глас 4-ий; сідальний сщмч. Климента, глас той самий. «Слава» – сідальний сщмч. Петра, глас 8-ий, «І нині» – сідальний свята, глас 4-ий. Після 6-ої пісні – кондак та ікос свята, глас 4-ий. На 9-ій пісні «Чеснішу...» не співаємо, але співаємо приспів свята: «Величай, душе моя, приведену в храм Господній, і благословлену руками священика». Після 9-ої пісні «Достойно є» не співається. Світильний святих. «Слава: І нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: свята, глас 1-ий – 2, сщмч. Климента, глас 5-ий – 2 і сщмч. Петра, глас 5-ий – 2. «Слава» – сщмч. Петра, глас 4-ий: «Рукою Божою був ти помазаний...», «І нині» – свята, глас 2-ий: «Нині в храм приводиться Всенепорочна Діва...». Велике славослів’я. Після Трисвятого – тропар святих, глас 4-ий: «Боже отців наших...». «Слава: І нині» – тропар свята, глас той самий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар святих. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, обох канонів пісня 9-а – 8 (1-го канону – з ірмосом). На вході – «Прийдіть... молитвами Богородиці...». Після входу – тропар свята, тропар святих. «Слава» – кондак святих, «І нині» – кондак свята. Прокимен, алилуарій і причасний – свята. Апостол і Євангеліє – дня і свята Богородиці. Задостойник свята."}]},
{"date":"11-26","weekday":"четвер","title":"Прп. Аліпія Стовпника (640). Прп. Стиліана Пафлагонського (V-VI ст.) Свт. Інокентія (Кульчицького), єп. Іркутського (1731). Прп. Якова Сирійського, пустельника (457). Освячення храму св. вмч. Юрія Переможця, що в Києві біля Золотих воріт (ХІ).","readings":["1 Тим., 283 зач., III, 1 – 13. Лк., 80 зач., XVI, 1 – 9.","Вмч.: Діян., 29 зач., XII, 1 – 11. Ін., 52 зач., XV, 17 – XVI, 2."],"notes":"Служба Освячення храму св. вмч. Юрія Переможця, що в Києві біля Золотих воріт (ХІ), шестирична, звершується разом із службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-а (яка не була прочитана на ранній середи). На «Господи, взиваю» стихири великомученика, глас 4-ий – 6 (кожна стихира двічі). «Слава» – великомученика, глас 6: «Прийдіть нині, собори любителів свята...», «І нині» – Богородичний за гласом «Слави», від менших: «Око серця мого...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава» – великомученика, глас 4-ий: «Прийдіть, собори вірних...», «І нині» – Богородичний за гласом «Слави», від менших: «Маючи Тебе, Богородице...». Після Трисвятого – тропар великомученика глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Слово Отче, Христа...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар пвеликомученика, глас 4-ий (двічі). «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Слово Отче, Христа...». Кафизми 13-а, 14-а, 15-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси раз), 2-ий на 4 і великомученика на 6. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону великомученика. Після 3-ої пісні – сідальний великомученика, глас 4-ий. «Слава: І нині» – Богородичний Мінеї. Після 6-ої пісні – кондак і ікос великомученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний великомученика, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава» – великомученика, глас 6-ий: «За Христа ти законно постраждав...», «І нині» – Богородичний за гласом «Слави», від менших: «Переміна скорботним...». Після Трисвятого – тропар великомученика, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти вища від усіх творінь...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, два тропарі дня, тропар великомученика; два кондаки дня, кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – два тропарі дня, тропар храму, тропар великомученика; два кондаки дня, кондак храму, кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і великомученика. Апостол і Євангеліє – дня і великомученика."}]},
{"date":"11-27","weekday":"п’ятниця","title":"Вмч. Якова Перського (421). Прп. Палладія Олександрійського (VІ – VІІ). Прмчч. 17 монахів в Індії (ІV). Прп. Романа Антіохійського (V). Знайдення мощів блгв. Всеволода, у св. хрещенні Гавриїла, кн. Новгородського, чудотворця (1192). Ікони Божої Матері «Знамення».","readings":["1 Тим., 285 зач., IV, 4 – 8, 16. Лк., 82 зач., XVI, 15 – 18; XVII, 1 – 4.","Вмч.: Еф., 233 зач., VI, 10 – 17. Ін., 50 зач., XV, 1 – 7."],"notes":"Служба вмч. Якова без святкового знаку завершується разом з службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми 18-а. На «Господи, взиваю» стихири на 6: Октоїха, глас 8-ий – 3, великомученика, глас 2-ий – 3. «Слава» – великомученика, глас 5-ий: «Здивував ти, Якове, всіх...», «І нині» – Хрестобогородичний Мінеї: «ангиця, коли побачила Свогго Агнця...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 8-ий. «Слава» – великомученика, глас 8-ий: «Нині з вірою зібравшись...», «І нині» – Хрестобогородичний Мінеї: «Що це за видіння...» Після Трисвятого – тропар великомученика, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар великомученика, глас 4-ий (двічі). «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Діво Пренепорочна...». Кафизми 19-а і 20-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси один раз), Октоїха 2-ий на 4 і великомученика, глас 2-ий на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону Мінеї (великомученика). Після 3-ої пісні – сідальний великомученика, глас 8-ий. «Слава: І нині» – Богородичний Мінеї. Після 6-ої пісні – кондак та ікос великомученика, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» співається. Екзапостиларій Октоїха. «Слава» – Світильний великомученика, «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий. «Слава» – великомучиника, глас 2-ий: «Терплячи страждання, мученику Якове...»; «І нині» – Хрестобогородичний Мінеї: «Коли непорочна Агниця...». Після Трисвятого – тропар великомученика, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомученика ."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі та кондаки: У храмі Господському – тропар дня «Спаси, Господи...», тропар великомученика; кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар великомученика; кондак дня, кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар великомученика; кондак дня, кондак храму, кондак великомученика. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і великомученика. Апостол і Євангеліє – дня і великомученика."}]},
{"date":"11-28","weekday":"субота","title":"Поминальна субота всіх, в Україні голодом заморених. Прмч. і спов. Стефана Нового (767). Мч. Іринарха Севастійського і святих сімох жінок (303). Мчч. Стефана, Василія, Григорія, іншого Григорія, Іоана та багатьох ін. (VІІІ).","readings":["За спокій: 1 Сол., 270 зач., IV, 13 – 17. Ін., 16 зач., V, 24 – 30.","Ряд.: Гал., 205 зач., III, 8 – 12. Лк., 49 зач., IX, 57 – 62."],"notes":"Служба преподобномученика Стефана не має святкового знаку, звершується разом із заупокійною суботньою службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ 18-та. На «Господи, взиваю» стихири на 6: преподобномученика, глас 6-ий – 3 і мученичні Октоїха, глас 8-ий – 3.«Слава» – преподобномученика, глас 6-ий: «З дитинства ти був відданий Богові...», «І нині» – догматик, глас 8-ий: «Цар Небесний...». Входу немає. Прокимен дня, глас 7-ий: «Боже, Ти Заступник мій...», зі стихом. На стиховні стихири Октоїха, глас 8-ий (із заупокійними приспівами: «Блаженні ті, кого обрав...», та ін.). «Слава» – преподобномученика, глас той самий: «Те, що за образом Божим...» І нині» – Богородичний за гласом «Слави», від менших: «Чиста Діво, врата Слова...». Після Трисвятого – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар, глас той самий: «Пом’яни, Господи, як Благий...», «І нині» – Богородичний, глас той самий: «Тебе, як Матір святу...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ замість «Бог Господь» – «Алилуя», глас 2-ий, із заупокійними стихами: 1-ий – «Блаженні ті, кого обрав і прийняв ти, Господи», 2-ий – «Пам’ять про них зроду в рід», 3-ій – «Душі їх у блаженстві перебуватимуть». Тропар, глас 2-ий: «Апостоли, мученики і пророки...» (двічі). «Слава» – інший тропар, глас той самий: «Пом’яни, Господи, як Благий...», «І нині» – Богородичний, глас той самий: «Тебе, як Матір святу...». Кафизма 16-та. Звичайна мала ектенія. Сідальні два з Октоїха, глас 8-ий. Кафизма 17-а (Непорочні) за Уставом співається, на 2-ий глас; ця кафизма розділяється на дві частини, або статі. Приспів до стихів 1-ої статті: «Благословен єси, Господи, навчи мене заповітів Твоїх». В кінці статті «Слава, і нині» не співається, але замість цього тричі (з приспівом) останні стихи: «Коли б не закон Твій...», «Повік не забуду повелінь Твоїх...». Примітка. Щодо закінчення першої і другої статті 17-ої кафизми при заупокійному богослужінні існують такі думки: 1) кожен з двох останніх стихів першої і другої статті співається по тричі з відповідним приспівом; 2) в кожній статті два останніх стиха об’єднуються «в один» і співаються з приспівом тричі. Потім виголошується мала заупокійна ектенія: «Ще і ще...», хор: «Господи, помилуй» (один раз); «Ще молимося за упокоєння душ спочилих рабів Божих (імена)...», хор: «Господи, помилуй» (один раз); «Щоб Господь Бог оселив душі їх...», хор: «Господи, помилуй» (один раз); «Милості Божої...», хор: «Подай, Господи». «Господу помолимось», хор: «Господи, помилуй». Ієрей таємно читає молитву: «Боже духів і всякої плоті...». Виголос: «Бо Ти є Воскресіння...». Хор: «Амінь». Після цього починається спів 2-ої статті: «Твій – я, спаси мене...» з приспівом до стихів: «Спасе, спаси мене»; останні стихи статті: «Нехай живе душа моя...», «Я блукаю, наче ягня загублене...», співаються (з приспівом) тричі. Потім на 5-ий глас співаються тропарі після Непорочних: «Собор святих...» та інше, з приспівом: «Благословен єси, Господи...». Виголошується мала заупокійна єктенія (див. Після 1-ої статті). Після виголосу співається сідальний, глас 5-ий: «Упокой, Спасе наш...». «Слава: І нині» – Богородичний, глас той самий: «Ти, що від Діви засяяв...». Псалом 50-ий. Канони: У храмі Господньому і Богородиці – храму з ірмосом на 6 (ірмоси по двічі), преподобномученика на 4 і Октоїха 1-ий (мученичний) на 4. Примітка. Про спів канонів у храмі Воскресіння Христового в суботу, дивитися Октоїх частина 1-ша. с. 831. У храмі святого – канон преподобномученика з ірмосом на 6 (ірмоси по двічі), храму на 4 і Октоїха 1-ий (мученичний) на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси 1-го (мученичного) канону Октоїха. Після 3-ої пісні – звичайна мала ектенія; кондак та ікос преподобномученика, глас 3-ій, інший кондак преподобномученика, глас 8-ий; сідальний преподобномученика, глас 1-ий, «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – мала заупокійна ектенія. Кондак, глас 8-ий: «Зі святими упокой...» та ікос, глас той самий: «Сам Один єси Безсмертний...». На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха: «Ти, що живими і мертвими володієш...». «Слава: І нині» – Богородичний Октоїха: «Ми Тобою хвалимося, Богородице...». «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири Октоїха (мученичні), глас 8-ий – 4. «Слава» – померлим Октоїха, глас той самий, «І нині» – Богородичний Октоїха, глас той самий. «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 8-ий (зі своїми приспівами: «Блаженні ті, кого обрав...», та ін.). «Слава: І нині» – Богородичний глас той самий: «Як зачавша безначальне Слово Бога Отця...». Після Трисвятого – тропар, глас 2-ий: «Апостоли, мученики і пророки...». «Слава» – інший тропар, глас той самий: «Пом’яни, Господи, як благий...», «І нині» – Богородичний, глас той самий: «Тебе, як Матір святу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропарі: «Апостоли, мученики і пророки...». «Слава» – «Пом’яни, Господи, як благий...». Кондак: «Зі святими упокой...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні Октоїха – 6. На вході – «Прийдіть... у святих Дивний сий...». Після входу – тропар, глас 2-ий: «Апостоли, мученики і пророки...», інший тропар, глас той самий: «Пом’яни, Господи, як благий...». «Слава» – кондак, глас 8-ий: «Зі святими упокой...», «І нині» – Богородичний, глас той самий: «Тебе і Стіну, і Пристановище...». Прокимен – заупокійний, глас 6-ий: «Душі їх у блаженстві...» і дня. Апостол – заупокійний і дня. Алилуарій – дня (суботи): «Взивали праведні...», стих: «Багато скорбот у праведних...»; і заупокійний: «Блаженні ті, кого обрав...». Євангеліє – заупокійне і дня."}]},
{"date":"11-29","weekday":"неділя","title":"26-та неділя після П’ятдесятниці. Глас 1-й. Мч. Парамона і з ним 370 мчч. (250). Мч. Філумена Анкирського (бл. 274). Прп. Акакія Синайського (VІ). Прп. Нектарія Києво-Печерського, в Ближніх печерах (ХІІ). Сщмч. Авіва, єп. Некреського (VІ, Груз.).","glas":1,"readings":["Ран. – Єв. 4-е, Лк., 112 зач., XXIV, 1 – 12.","Літ. – Еф., 229 зач., V, 8 – 19. Лк., 66 зач., XII, 16 – 21."],"notes":"Служба мученика Парамона без святкового знаку, звершується разом з воскреслою службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 1-ий – 7 і мученика, глас 4-ий – 3. «Слава: І нині» – догматик, глас 1-ий: «Всесвітню славу...». Вхід. Прокимен дня. На літії стихири храму. На стиховні стихири воскресні, глас 1-ий. «Слава: І нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – «Богородице Діво» (тричі)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 8-ий (двічі). «Слава» – тропар мученика, глас 4-ий, «І нині» – Богородичний воскресний, глас той самий: «Від віку утаємнене...». Кафизми 2-а і 3-я. Малі ектенії. Сідальні воскресні. Полієлей. «Ангельський собор...». Іпакої, степенні і прокимен – голосу. Євангеліє воскресне 4-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси раз), Хрестовоскресний на 4, Богородиці на 2 і мученика на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – кондак і ікос мученика, глас 2-ий (загальний); сідальний мученика, глас 4-ий. «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос воскресні, глас 1-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 4-ий. «Слава» – світильний мученика, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири воскресні, глас 1-ий – 8. «Слава» – стихира євангельська 4-а, «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «В день спасіння світу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар мученика. Кондак тільки воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і мученика, пісня 3-тя – 4. Після входу – тропарі та кондаки: У храмі Господському – тропар воскресний, тропар мученика. «Слава» – кондак мученика, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар мученика; кондак воскресний. «Слава» – кондак мученика, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар мученика; кондак воскресний, кондак храму. «Слава» – кондак мученика, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – воскресні. Апостол і Євангеліє – воскресні."}]},
{"date":"11-30","weekday":"понеділок","title":"27-й тиждень після П’ятдесятниці. Апостола Андрія Першозваного (62). Свт. Фрументія, архієп. Індійського (Ефіопського, бл. 380).","readings":["Ран. – Мф., 9 зач., IV, 18 – 23.","Літ. – Ап.: 1 Кор., 131 зач., IV, 9 – 16. Ін., 4 зач., I, 35 – 51."],"notes":"Звершується бдінна служба апостола Андрія Першозванного.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири апостола, глас 4-ий – 8 (перші дві стихири – тричі, третя стихира – двічі). «Слава» – апостола, глас той же: «Покинувши рибальство, ти, апостоле, ловиш людей палицею благовістя...», «І нині» – передсвята (Мінеї), глас той же: «Ісає, радій, Слово Боже прийми...». Вхід. Прокимен дня. Паремії апостола – 3. Примітка. За традицією, новозавітні паремії читаються при відкритих царських вратах. На літії стихира храму і стихири апостола, глас 1-ий і глас 8-ий. «Слава» – апостола, глас 8-ий: «Проповідника віри і слугу Слова, Андрія, прославмо...», «І нині» – Богородичний, глас той самий: «Владичице, прийми молитви рабів Твоїх і визволи нас від усякої недолі і печалі». На стиховні стихири апостола, глас 5-ий (зі своїми приспівами). «Слава» – апостола, глас 3-ій: «Брата Петрового й ученика Христового...», «І нині» – Мінеї, глас той же: «Йосифе, скажи нам...». Після Трисвятого – тропар апостола, глас 4-ий. «Слава і нині» – Богородичний воскресний, глас той самий: «Від віку утаємнене...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар апостола, глас 4-ий (двічі). «Слава і нині» – Богородичний воскресний, глас той самий: «Від віку утаємнене...». Кафизми 4-а і 5-а. Малі ектенії. Сідальні апостола (по двічі). Полієлей. Величання апостола: «Величаємо тебе,/ апостоле Христів Андрію Першозванний/ і шануємо страждання і труди твої,/ що ними потрудився ти у благовісті Христовім» і вибраний псалом: «Від сходу сонця і до заходу хвальне ім’я Господнє». Сідальний апостола після полієлея, глас 5-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той самий. Степенна – 1-ий антифон 4-го гласу. Прокимен апостола, глас 4-ий: «По всій землі розійшлося віщування їх і в кінці вселенної слова їх»; стих: «Небеса повідають славу Божу, творіння ж рук Його сповіщає твердь». Євангеліє – апостола. Після 50-го псалма: «Слава» – «Молитвами апостола Андрія Першозванного...». Стихира апостола, глас 8-ий: «Проповідника віри...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і апостола (два канони) на 8. Біблійні пісні «Співаємо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – сідальний апостола, глас 8-ий. «Слава» – інший сідальний апостола, глас той самий, «І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос апостола, глас 2-ий. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний апостола. «Слава» – інший світильний апостола, «І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири апостола, глас 1-ий – 4. «Слава» – апостола, глас 8-ий: «Проповідника віри...», «І нині» – Мінеї, глас той самий: «Стань, Вифлеєме, Божою митрополією...». Велике славослів’я. Після Трисвятого – тропар апостола, глас 4-ий. «Слава: І нині» – Богородичний воскресний, глас той самий: «Від віку утаємнене...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак апостола."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні апостола, пісня 3-я – 4 (з ірмосом), пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар апостола. «Слава» – кондак апостола, «І нині» – кондак храму. У храмі святого – тропар храму, тропар апостола; кондак храму. «Слава» – кондак апостола, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – апостола. Апостол і Євангеліє – апостола."}]},
{"date":"12-01","weekday":"вівторок","title":"Прор. Наума (VІІ ст. до Р. Х.). Прав. Філарета Милостивого (792). Мч. Ананії Перського.","readings":["1 Тим., 285 зач. (від половини), V, 1 – 10. Лк., 86 зач., XVII, 20 – 25 (за понеділок).","1 Тим., 286 зач., V, 11 – 21. Лк., 87 зач., XVII, 26 – 37 (за вівторок)."],"notes":"Подаємо зразок звершення шестиричної служби прав. Філарета Милостивого в поєднанні зі службою прор. Наума без святкового знаку та службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-а (яка не була прочитана на ранній понеділка). На «Господи, взиваю» стихири на 6: прав. Філарета, глас 4-ий – 3, і пророка глас 3-ій – 3. «Слава» – прав. Філарета, глас 2-ий: «Милости джерело, нужденним примножує...», «І нині» – Богородичний за гласом «Слави», від менших: «Непроходимі ворота, таємно запечатані...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. «Слава» – прав. Філарета, глас 8-ий: «Маючи милостиву душу...», «І нині» – Богородичний за гласом «Слави», від менших: «Діво Всехвальна, Тебе бо Мойсей...». Після Трисвятого – тропар прав. Філарета, глас 4-ий. «Слава» – тропар пророка, глас 2-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Тобою, Богородице Приснодіво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар прав. Філарета, глас 4-ий (двічі). «Слава» – тропар пророка, глас 2-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Тобою, Богородице Приснодіво...». Кафизми: 7-а, 8-а і 9-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом, без мученичних, на 4 (ірмоси раз), прав. Філарета на 6 і пророка на 4. Біблійні пісні «Господеві співаймо...» (див. Типікон, 23 вересня, 1-е «див»). Катавасія після 3-ої, 6-ої, 8-ої і 9-ої – ірмоси канону пророка. Після 3-ої пісні – кондак пророка, глас 4-ий; сідальний прав. Філарета. «Слава» – сідальний пророка, глас 5-ий, «І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос прав. Філарета, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» співається. Екзапостиларій Октоїха. Світильний прав. Філарета. «Слава» – інший світильний прав. Філарета, «І нині» – Богородичний Мінеї. Хвалітні псалми. На хвалітніх стихири прав. Філарета – 4, глас 4-ий. «Слава» – прав. Філарета, глас 8-ий: «На милість Бога...», «І нині» – Богородичний Мінеї, глас той же: «Владичице, прийми молитви рабів Твоїх...». «Тобі слава належить...» не виголошуємо, а одразу «Слава Тобі, що показав нам світло» і читаємо повсякденне славослів’я. Після Трисвятого – тропар прав. Філарета, глас 4-ий. «Слава» – тропар пророка, глас 2-ий, «І нині» – Богородичний за гласом «Слави», від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар прав. Філарета. «Слава» – тропар пророка. Кондаки пророка і прав. Філарета читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар прав. Філарета; тропар пророка; кондак дня, кондак прав. Філарета, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар прав. Філарета, тропар пророка; кондак дня, кондак храму, кондак прав. Філарета, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-02","weekday":"середа","title":"Прор. Авакума (VІІ ст. до Р. Х.). Прпп. Афанасія, затворника Києво-Печерського, в Ближніх печерах (бл. 1176), та іншого Афанасія, затворника Києво-Печерського, в Дальніх печерах (ХІІІ). Мц. Миропії Хіоської (бл. 251). Прпп. Іоана, Іраклемона, Андрія та Феофіла (ІV). Свт. Ісе (Ієсея), єп. Цилканського (VІ, Груз.). Св. Стефана Уроша, царя Сербського (1367). Сщмч. Порфирія, єп. Сімферопольського (1937). Прп. Олексія Карпаторуського (1947). Прп. Порфирія Кавсокалівіта (1991). Ікони Божої Матері «Герондиса».","readings":["1 Тим., 287 зач., V, 22 – VI, 11. Лк., 90 зач., XVIII, 15 – 17, 26 – 30."],"notes":"Служба прор. Авакума не має святкового знака, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 1-ий – 3, і пророка, глас 4-ий – 3. «Слава: І нині» – Хрестобогородичний Мінеї: «Агнця і Пастиря, Тебе...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. «Слава: І нині» – Хрестобогородичний Октоїха, глас той же. Після Трисвятого – тропар пророка, глас 2-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Препрославлена єси, Богородице Діво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар пророка, глас 2-ий (двічі). «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Препрославлена єси, Богородице Діво...». Кафизми 10-а, 11-а і 12-а. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмос один раз), 2-ий на 4, і пророка на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону пророка. Після 3-ої пісні – сідальний пророка, глас 4-ий. «Слава: І нині» – Хрестобогородичний Мінеї, глас той же. Після 6-ої пісні – кондак пророка, глас 8-ий. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава: І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий. «Слава: І нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар пророка, глас 2-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак пророка."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі і кондаки: У храмі Господському – тропар дня «Спаси, Господи...», тропар пророка, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар пророка; кондак дня, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар пророка; кондак дня, кондак храму, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-03","weekday":"четвер","title":"Прор. Софонії (635 – 605 до Р. Х.). Прп. Феодула Константинопольського (бл. 440). Прп. Іоана Мовчальника, колишнього єп. Колонійського (558). Сщмч. Федора, архієп. Олександрійського (606).","readings":["1 Тим., 289 зач., VI, 17 – 21. Лк., 92 зач., XVIII, 31 – 34."],"notes":"Служба прор. Софонії не має святкового знаку і звершується зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Октоїха, глас 1-ий – 3, і пророка, глас 4-ий – 3. «Слава: І нині» – Богородичний Мінеї: «У глибину моїх гріхів упав я...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 1-ий. «Слава: І нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар пророка, глас 2-ий. «Слава: І нині» – Богородичний за гласом тропаря: «Тобою, Богородице Приснодіво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар пророка, глас 2-ий (двічі). «Слава: І нині» – Богородичний за гласом тропаря: «Тобою, Богородице Приснодіво...». Кафизми 13-а, 14-а і 15-а. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4, і пророка на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону пророка. Після 3-ої пісні – сідальний пророка, глас 6-ий. «Слава: І нині» – Бородичний Мінеї, глас той же. Після 6-ої пісні – кондак пророка, глас 4-ий. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава: І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий. «Слава: І нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар пророка, глас 2-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи..»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак пророка."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, два тропарі дня, тропар пророка, два кондаки дня, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – два тропарі дня, тропар храму, тропар пророка; два кондаки дня, кондак храму, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол та Євангеліє – дня."}]},
{"date":"12-04","weekday":"п’ятниця","title":"Вмц. Варвари і мц. Юліанії (бл. 306). Прп. Іоана Дамаскина (бл. 780). Прп. Іоана, єп. Полівотського, спов. (VІІІ).","readings":["Ран. – Мф., 104 зач., XXV, 1 – 13.","Літ. – 2 Тим., 290 зач., I, 1 – 2, 8 – 18. Лк., 95 зач., XIX, 12 – 28.","Вмц.: Гал., 208 зач., III, 23 – 29. Мк., 21 зач., V, 24 – 34."],"notes":"Звершується полієлейна служба святої вмц. Варвари.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири великомучениці, глас 2-ий – 8 (перші дві стихири – тричі, третя – двічі). «Слава» – великомучениці, глас 6-ий: «Вітчизну, рід, багатство...», «І нині» – догматик, глас 6-ий: «Хто не ублажить...». Вхід. Прокимен дня. Паремії великомучениці – 3. На стиховні стихири великомучениці, глас 1-ий (зі своїми приспівами). «Слава» – великомучениці, глас 2-ий: «Як дорогоцінне миро...», «І нині» – Богородичний Мінеї, глас той же: «Все уповання моє...». Після Трисвятого – тропар великомучениці, глас 8-ий «Слава: І нині» – Богородичний воскресний за гласом тропаря: «Ти, що заради нас...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар великомучениці, глас 8-ий (двічі). «Слава: І нині» – Богородичний воскресний, глас той же: «Ти, що заради нас...». Кафизми 19-а і 20-а. Малі єктенії. Сідальні великомучениці (по двічі). Полієлей. Величання великомучениці і вибраний псалом. Сідальний великомучениці після полієлея, глас 6-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той же. Степенна – 1-ий антифон 4-го гласу. Прокимен і Євангеліє – великомучениці. Після 50-го псалма: «Слава» – «Молитвами великомучениці...». Стихира великомучениці, глас 6-ий: «Вітчизну, рід і багатство залишивши...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і великомучениці на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – сідальний великомучениці, глас 3-ій (двічі). «Слава: І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос великомучениці, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний великомучениці (двічі). «Слава: І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири великомучениці, глас 1-ий і глас 2-ий – 4. «Слава» – великомучениці, глас 6-ий: «Страдницьким ідучи шляхом...», «І нині» – Богородичний Мінеї, глас той же: «Ніхто, з тих, хто приходить до Тебе...». Велике славослів’я. Після Трисвятого – тропар великомучениці, глас 8-ий. «Слава: І нині» – Богородичний воскресний, глас той же: «Ти, що заради нас...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак великомучениці."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні великомучениці, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар великомучениці. «Слава» – кондак великомучениці, «І нині» – кондак храму. У храмі святого – тропар храму, тропар великомучениці; кондак храму. «Слава» – кондак великомучениці, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня та великомучениці. Апостол і Євангеліє – дня і великомучениці."}]},
{"date":"12-05","weekday":"субота","title":"Прп. Сави Освяченого (532). Мч. Анастасія Аквілейського. Прпп. Киріона, ченця, та сина його Захарії, єгиптян (ІV).","readings":["Ран. – Лк., 24 зач., VI, 17 – 23.","Літ. – Прп.: Гал., 213 зач., V, 22 – VI, 2. Мф., 43 зач., XI, 27 – 30.","Ряд.: Гал., 213 зач., V, 22 – VI, 2 (апостольські читання співпадають, отже не повторюємо двічі). Лк., 51 зач."],"notes":"(від половини), X, 19 – 21. Звершується полієлейна служба прп. Сави Освяченого.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири преподобного, глас 5-ий – 8 (перших дві стихири тричі, а третя – двічі). «Слава» – преподобного, глас 6-ий: «Його по образу...», «І нині» – Богородичний, глас 1-ий: «Всесвітню славу...». Вхід. Прокимен дня. Паремії преподобного – 3. На стиховні стихири преподобного, глас 5-ий (зі своїми приспівами). «Слава» – святителя, глас 8-ий: «Монахів безліч...», «І нині» – Мінеї, глас той же: «Безневістна Діво...». Після Трисвятого – тропар преподобного, глас 8-ий. «Слава: І нині» – Богородичний воскресний, глас 1-ий: «Коли Гавриїл...»"},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 8-ий (двічі). «Слава: І нині» – Богородичний воскресний, глас той же: «Ти, що заради нас...». Кафизми 16-а і 17-а. Малі єктенії. Сідальні преподобного. Полієлей. Величання преподобного і вибраний псалом. Сідальний преподобного після полієлея, глас 8-ий. «Слава: І нині» – Богородичний Мінеї, глас той же. Степенна – 1-ий антифон 4-го гласу. Прокимен святителя, глас 4-ий: «Чесна перед Господом смерть преподобних Його»; стих: «Що віддам Господу за все, що Він воздав мені?». Євангеліє – преподобного. Після 50-го псалма: «Слава» – «Молитвами преподобного отця нашого Сави...». Стихира преподобного, глас 6-ий: «Преподобний отче...». Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і преподобного на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – сідальний преподобного, глас 8-ий. «Слава» – інший сідальний преподобного, глас той же, «І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос преподобного, глас 8-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний преподобного. «Слава: І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми На хвалітніх стихири преподобного, глас 1-ий – 4. «Слава» – преподобного, глас 6-ий:, «І нині» – Богородичний Мінеї, глас той же: «Богородице, Ти єси виноградна лоза...». Велике славослів’я. Після Трисвятого – тропар преподобного, глас 8-ий. «Слава: І нині» – Богородичний воскресний, глас той же: «Ти, що заради нас...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні преподобного, пісня 3-я – 4 (з ірмосом), пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар преподобного. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар храму, тропар преподобного, кондак храму. «Слава» – кондак преподобного, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і преподобного. Апостол і Євангеліє – дня і преподобного (апостольські читання співпадають, тому не повторюємо двічі)."}]},
{"date":"12-06","weekday":"неділя","title":"27-ма неділя після П’ятдесятниці. Глас 2-й. Святителя Миколая, архієпископа Мир Лікійських, чудотворця (бл. 345).","glas":2,"readings":["Ран. – Єв. 5-е, Лк., 113 зач., XXIV, 12 – 35.","Літ. – Еф., 233 зач., VI, 10 – 17. Лк., 71 зач., XIII, 10 – 17.","Свт.: Євр., 335 зач., ХІII, 17 – 21. Мф., 11 зач., V, 14 – 19."],"notes":"Звершується бдінна служба свт. Миколая у поєднанні з Воскресною службою Октоїха.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 2-ий – 4 і святителя, глас той же – 6. «Слава» – святителя, глас 6-ий: «Святителів прикрасу...», «І нині» – Богородичний воскресний, глас 2-ий: «Минула тінь закону...». Вхід. Прокимен дня. Паремії святителя – 3. На літії стихира храму і стихири святителя, глас 2-ий, глас 4-ий і глас 8-ий. «Слава» – святителя, глас 6-ий: «Благий і вірний рабе...», «І нині» – Мінеї, глас той же: «Сионе, торжествуй...». На стиховні стихири восекресні, глас 2-ий. «Слава» – святителя, глас 6-ий: «Людино Божа...», «І нині» – Богородичний воскресний за гласом «Слави»: «О, чудо нове...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар святителя, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 2-ий (двічі). «Слава» – тропар святителя, глас 4-ий, «І нині» – Богородичний воскресний, за гласом «Слави»: «Від віку утаємнене...». Кафизми 2-а і 3-я. Малі єктенії. Сідальні Октоїха. Полієлей. Величання святителя: «Величаємо тебе,/ святителю отче Миколаю/ і шануємо святу пам’ять твою,/ бо ти молиш за нас// Христа Бога нашого» і вибраний псалом. «Ангельський собор...». Іпакої, сідальний святителя після 1-ої кафизми, глас 1-ий: «В Мирах ти жив тілесно...», сідальний святителя після 2-ої кафизми, глас 4-ий: «Ти, святителю, заступаєшся за вірних...», сідальний святителя після полієлею, глас 5-ий: «Премудрого святителя побожно прославимо всі...». «Слава» – інший сідальний святителя після полієлею, глас той же: «Ти, святителю Миколаю...», «І нині» – Богородичний Мінеї, глас той же: «Скоро прийми, Владичице, молитви наші...». Степенні і прокимен гласу. Євангеліє воскресне 5-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4, Богородиці на 2 і святителя на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – кондак та ікос святителя, глас 3-ій; сідальний святителя, глас 8-ий. «Слава» – інший сідальний святителя, глас той же, «І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос воскресні, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Свят Господь Бог наш...». Екзапостиларій воскресний. Світильний святителя. «Слава» – інший світильний святителя, «І нині» – Богородичний воскресного екзапостиларія. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 2-ий – 4 і святителя, глас 6-ий – 4. «Слава» – рання євангельська стихира 5-а, «І нині» – «Преблагословення єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний, «Слава» – тропар святителя. Кондак воскресний."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 6 і святителя, пісня 3-я на 4. На вході – «Прийдіть... що воскрес із мертвих...». Після входу – тропарі і кондаки: У храмі Господському – тропар воскресний, тропар святителя, кондак святителя. «Слава» – кондак святятителя, «І нині» – кондак воскресний. У храмі Богородиці – тропар воскресний, тропар храму, тропар святителя; кондак воскресний. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар воскресний, тропар храму, тропар святителя; кондак воскресний, кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – неділі і святителя. Апостол і Євангеліє – неділі і святителя."}]},
{"date":"12-07","weekday":"понеділок","title":"28-й тиждень після П’ятдесятниці. Свт. Амвросія, єп. Медіоланського (397). Прп. Іоана, посника Києво-Печерського, в Ближніх печерах (ХІІ). Мч. Афінодора Месопотамського (бл. 304). Прп. Павла Послушного. Мц. Філофеї (1060, Румун.).","readings":["2 Тим., 294 зач., II, 20 – 26. Лк., 97 зач., XIX, 37 – 44."],"notes":"Служба свт. Амвросія не має святкового знака, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири Октоїха, глас 2-ий – 3 і святителя, глас 1-ий – 3. «Слава: І нині» – Богородичний Мінеї, глас той же: «Норовом гнилим упав...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава: І нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар святителя, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Вихованій у храмі...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 4-ий (двічі). Слава: І нині» – Богородичний за гласом тропаря, від менших: «Вихованій у храмі...». Кафизми 4-а, 5-а і 6-а. Малих єктеній немає. Сідальні Октоїха. Псалом 50-й. Канони: Октоїха 1-ий (з ірмосом) на 6, 2-ий на 4 і святителя на 4 і. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону святителя. Після 3-ої пісні – сідальний святителя, глас 8-ий. «Слава: І нині» – Богородичний Мінеї, глас той же. За 6-й пісні – кондак святителя, глас 3-ій. На 9-ій пісні співаємо «Чеснішу...». Після 9-й пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава: І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава: І нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар святителя, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Богородице, Ти вища від усіх творінь...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар святителя; кондак дня, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар святителя; кондак дня, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн усердная...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-08","weekday":"вівторок","title":"Прп. Патапія Фівського (VІІ). Апп. від 70-х: Сосфена, Аполоса, Кифи, Тихика, Епафродита, Кесарія та Онисифора (І). Сщмчч. 62 ієреїв та мчч. 300 мирян, які в Африці від аріан постраждали (477). Мц. Анфіси Римської (V).","readings":["2 Тим., 297 зач., III, 16 – IV, 4. Лк., 98 зач., XIX, 45 – 48."],"notes":"Служба прп. Патапія не має святкового знака, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири на 6: Октоїха, глас 2-ий – 3, і преподобного, глас 1-ий – 3. «Слава: І нині» – Богородичний Мінеї, глас той же: «Вогонь Божества..». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава: І нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар святого, глас 8-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Непохитне утвердження віри...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святого, глас 8-ий (двічі). «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Непохитне утвердження віри...». Кафизми 7-а, 8-а і 9-а. Малих єктеній немає. Сідальні Октохха. Псалом 50-й. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4, і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону преподорбного. Після 3-ої пісні – сідальний преподобного, глас 8-ий. «Слава: І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак преподобного, глас 3-ій. На 9-ій пісні співаємо «Чеснішу...». Після 9-й пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава: І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 2-ий. «Слава: І нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар святого, глас 8-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Діво Пречиста, спаси нас молитвами Твоїми...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар святителя; кондак дня, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар святителя; кондак дня, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн усердная...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-09","weekday":"середа","title":"Зачаття прав. Анною Пресвятої Богородиці. Пророчиці Анни, матері прор. Самуїла (1100 до Р. Х.). Свт. Софронія, архієп. Кіпрського (VІ). Прп. Стефана Новосяючого (912). Ікони Божої Матері «Несподівана радість».","readings":["2 Тим., 299 зач., IV, 9 – 22. Лк., 99 зач., XX, 1 – 8.","Прав. Анни: Гал., 210 зач. (від половини), IV, 22 – 31. Лк., 36 зач., VIII, 16 – 21."],"notes":"Звершується славослівна служба Зачаття Пресвятої Богородиці.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-та. На «Господи, взиваю» стихири на 6: Зачаття, глас 4-ий – 6 (кожна стихира – двічі). «Слава: І нині» – Зачаття, глас 2-ий: «Незбагненне для ангелів і велике для людей...». Входу немає . Прокимен дня. На стиховні стихири Зачаття, глас 5-ий (зі своїми приспівами). «Слава: І нині» – Зачаття, глас 2-ий: «Нині із кореня Давидового Царська порфира зачинається...». Після Трисвятого – тропар Зачаття, глас 4-ий (один раз; цей тропар співається без Богородичного, див. Типікон, 9 грудня)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар Зачаття, глас 4-ий (двічі). «Слава: І нині» – той же тропар. Кафизми 10-а і 11-а. Малі єктенії. Сідальні Зачаття (по двічі). Псалом 50-й. Канони: прав. Анни: 1-ий з ірмосом на 8 (ірмоси по двічі) і 2-ий на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – сідальний Зачаття, глас 4-ий (двічі). «Слава: І нині» – інший сідальний, глас той же. Після 6-ої пісні – кондак та ікос Зачаття, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний Зачаття. «Слава: І нині» – той же світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири Зачаття, глас 1-ий – 4 (перша стихира – двічі). «Слава: І нині» – Зачаття, глас 8-ий: «Прийдіть, радісно днесь...». Велике славослів’я. Після Трисвятого – тропар Зачаття, глас 4-ий (один раз; цей тропар співається без Богородичного, див. Типікон, 9 грудня)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак Зачаття."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Зачаття, 1-го канону пісня 3-я – 4 (з ірмосом), і 2-го канону пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар храму, тропар Зачаття. «Слава» – кондак храму, «І нині» – кондак Зачаття. У храмі Богородиці – тропар Зачаття. «Слава: І нині» – кондак Зачаття. У храмі святого – тропар Зачаття, тропар храму. «Слава» – кондак храму, «І нині» – кондак Зачаття. Прокимен, алилуарій і причасний – дня і прав. Анни. Апостол і Євангеліє – дня і прав. Анни."}]},
{"date":"12-10","weekday":"четвер","title":"Мчч. Мини, Єрмогена та Євграфа Олександрійських (бл. 313). Свт. Іоасафа (Горленка), єп. Білгородського (1754). Мч. Гемела Пафлагонського (бл. 361). Прп. Фоми, ігум. (Х). Св. блгвв. Іоана (1503) та батьків його, Стефана (1446) і прп. Ангеліни, правителів Сербських.","readings":["Тит., 300 зач. (від половини), I, 5 – II, 1. Лк., 100 зач., XX, 9 – 18.","Свт.: Євр., 318 зач., VІІ, 26 – VІІІ, 2. Ін., 36 зач., Х, 9 – 16."],"notes":"Звершується славослівна служба свт. Іоасафа, єп. Білгородського із Загальної Мінеї.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-та (яка не була прочитана на ранній вівторка). На «Господи, взиваю» стихири святителя, глас 6-ий – 8 (перші дві стихири – двічі). «Слава» – святителя, глас 8-ий: «Чеснотами твоїми, преподобний отче...», «І нині» – Богородичний воскресний, глас той самий: «Цар Небесний...». Входу немає. Прокимен дня. На стиховні стихири святителя, глас 8-ий (зі своїми приспівами). «Слава» – святителя, глас 8-ий: «Ти єси пастир добрий...», «І нині» – Богородичний Мінеї: «Владичице, прийми...». Після Трисвятого – тропар святителя, глас 3-ій (див. Мінею місячну). «Слава: І нині» – Богородичний воскресний за гласом «Слави»: «Тебе оспівуємо, Богородице Діво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 3-ій (див. Мінею місячну) (двічі). «Слава: І нині» – Богородичний воскресний за гласом «Слави»: «Тебе оспівуємо, Богородице Діво...». Кафизми 13-а і 14-а. Малі ектенії. Сідальні святителя (по двічі). Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 4, 2-ий на 4 і святителя на 6. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – сідальний святителя, глас 4-ий. «Слава: І нині» – Богородичний Мінеї, глас той самий. Після 6-ої пісні – кондак та ікос святителя, глас 8-ий. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний святителя. «Слава: І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири святителя, глас 8-ий – 4. «Слава» – святителя, глас 6-ий: «Преподобний і треблаженний отче...», «І нині» – Богородичний Мінеї, глас той самий: «Богом ми визнаємо Того...». Велике славослів’я. Після Трисвятого – – тропар святителя, глас 3-ій (див. Мінею місячну). «Слава: І нині» – Богородичний воскресний за гласом «Слави»: «Тебе оспівуємо, Богородице Діво...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні святителя, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"12-11","weekday":"п’ятниця","title":"Прп. Даниїла Стовпника (489 – 490). Прп. Никона Сухого, Києво-Печерського, в Ближніх печерах (ХІІ). Мч. Миракса Єгипетського (VІІ). Мчч. Акепсія та Аїфала. Прп. Луки Стовпника, ієром. (бл. 970 – 980).","readings":["Тит., 301 зач., I, 15 – II, 10. Лк., 101 зач., XX, 19 – 26."],"notes":"Служба преподобного Даниїла Стовпника не має святкового знака, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 15-а (яка не була прочитана на ранній четверга) На «Господи, взиваю» стихири на 6: Октоїха, глас 2-ий – 3, і преподобного, глас 8-ий – 3. «Слава» – преподобного, глас 5-ий: «Довірений тобі талант від Христа ти добре використав...», «І нині» – Хрестобогородичний за гласом «Слави», від менших: «Бачати в давнині на хресті розіп’ятого Агнця...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 2-ий. «Слава: І нині» – Хрестобогородичний Октоїха. Після Трисвятого – тропар преподобного, глас 1-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Твоє заступництво маючи...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар преподобного, глас 1-ий: (двічі). «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Твоє заступництво маючи...». Кафизми 19-а і 20-а. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4 і преподобного на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої та 9-ої пісень – ірмоси канону преподобного. Після 3-ої пісні – сідальний преподобного, глас 1-ий. «Слава: І нині» – Хрестобогородичний Мінеї, глас той же. Після 6-ої пісні – кондак і ікос преподобного, глас 8-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний преподобного. «І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 1-ий. «Слава: І нині» – Хрестобогородичний Октоїха Після Трисвятого – тропар преподобного, глас 1-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Пречиста Богородице, на небесах благословення...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак преподобного."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському – тропар дня «Спаси, Господи...», тропар преподобного, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар преподобного; кондак дня, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар преподобного; кондак дня, кондак храму, кондак преподобного. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-12","weekday":"субота","title":"Свт. Спиридона, єп. Тримифунтського, чудотворця (бл. 348). Сщмч. Олександра, єп. Єрусалимського (251). Мч. Розумника (Синезія) (270 – 275).","readings":["Ран. – Ін., 35 зач. (від пол.), X, 1 – 9.","Літ. – Свт.: Євр., 335 зач., XIII, 17 – 21. Мф., 11 зач., V, 14 – 19.","Ряд.: Еф., 218 зач., I, 16 – 23. Лк., 67 зач., XII, 32 – 40."],"notes":"Звершується полієлейна служба святителя Спиридона.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири святителя, глас 5-ий – 6 (кожна стихира – двічі). «Слава» – святителя, глас 1-ий: «Преподобний отче, блаженний Спиридоне мудрий...», «І нині» – Богородичний воскресний, глас 2-ий: «Минула тінь закону...». Вхід. Прокимен дня. Паремії святителя – 3. На стиховні стихири святителя, глас 4-ий (зі своїми приспівами). «Слава» – святителя глас 2-ий: «Став Божественним сосудом...», «І нині» – Богородичний Мінеї, глас той же: «О, чудо нове...». Після Трисвятого – тропар святителя, глас 1-ий. «Слава: І нині» – Богородичний воскресний, глас 2-ий: «Все вище розуму...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 1-ий (двічі). «Слава: І нині» – Богородичний воскресний, глас 1-ий: «Коли Гавриїл...». Кафизми 16-а і 17-а. Малі єктенії. Сідальні святителя (по двічі). Полієлей. Величання святителя і вибраний псалом. Сідальний святителя після полієлея, глас 8-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той же. Степенна – 1-ий антифон 4-го гласу. Прокимен святителя, глас 4-ий: «Уста мої промовлятимуть...». Євангеліє – святителя. Після 50-го псалма: «Слава» – «Молитвами святителя Спиридона...». Стихира святителя, глас 2-й. Канони: Богородиці з ірмосом на 6 (ірмоси по двічі) і святителя на 8. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – сідальний святителя, глас 8-ий (двічі). «Слава: І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос святителя, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний святителя. «Слава: І нині» – Богородичний Мінеї. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири святителя, глас 8-ий – 4. «Слава» – святителя, глас 4-ий: «Преподобний отче, всехвальний святителю...», «І нині» – Богородичний, глас за гласом «Слави»: «Єдина Чиста і Пречиста Діво...». Велике славослів’я. тропар святителя, глас 1-ий. «Слава: І нині» – Богородичний воскресний, глас той же: «Коли Гавриїл...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар святителя. Кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні святителя, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар святителя. «Слава» – кондак святителя, «І нині» – кондак храму. У храмі святого – тропар храму, тропар святителя; кондак храму. «Слава» – кондак святителя, «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня і святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"12-13","weekday":"неділя","title":"28-ма неділя після П’ятдесятниці, святих праотців. Глас 3-й. Мчч. Євстратія, Авксентія, Євгенія, Мардарія та Ореста (284 – 305). Мц. Лукії Сіракузької (304). Прп. Аркадія Новоторзького (ХІ). Прп. Мардарія, затворника Києво-Печерського, в Дальніх печерах (ХІІІ). Прп. Арсенія Латрійського, ігум. (VІІІ – Х). Свт. Досифея, митр. Молдовського (1693, Рум.).","glas":3,"readings":["Ран. – Єв. 6-е, Лк., 114 зач., XXIV, 36 – 53.","Літ. – Кол. 257 зач.; ІІІ, 4 – 11 (апостольське читання 29-ї неділі). Лк., 76 зач., XІV, 16 – 24. (це євангельське"],"notes":"читання 28-ї неділі і неділі праотців). Мчч.: Еф., 233 зач., VI, 10 – 17. Лк., 106 зач., XXI, 12 – 19. Звершується воскресна служба Октоїха у поєднанні зі службою святих праотців та полієлейною службою святих мучеників.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: воскресні, глас 3-ій – 3, праотців, глас 8-ий – 3 і мучеників, глас 4-ий – 4. «Слава» – праотців, глас 6-ий: «Прославмо нині, вірні, отців, що жили до Закону...», «І нині» – догматик, глас 3-ій: «Як нам не дивуватися...». Вхід. Прокимен дня. Паремії мучеників – 3. На літії стихира храму, стихири мучеників (останні дві зі стихир на «Господи, взиваю...» та зі «Слави»). «Слава» – праотців, глас 1-ий: «Вельмипрославлені пророки..», «І нині» Богородичний воскресний, глас той же: «Ось сповнилося пророцтво Ісаї...». На стиховні стихири воскресні, глас 3-ій. «Слава» – мучеників, глас 5-ий: «Жорстокості мучителів не убоявшись...», «І нині» – праотців, глас 3-ій: «Праотців собор...». Після Трисвятого – «Богородице Діво...» (двічі) і тропар праотців, глас 2-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 3-ій (двічі). «Слава» – тропар мучеників, глас 4-ий, «І нині» – тропар праотців, глас 2-ий. Кафизми 2-а і 3-я. Малі єктенії. Сідальні воскресні. Полієлей. Величання мучеників і вибраний псалом. «Ангельський собор...». Іпакої гласу. Сідальний мучеників після 1-ої кафізми, глас 4-ий: «Мужністю віри у броню одягнувшись...», сідальний мучеників після 2-ої кафізми, глас той же: «Зброєю твоїх слів ти уразив мучителя...». «Слава» – сідальний мучеників після полієлея, глас 8-ий: «Троїчною вірою утвердившись...», «І нині» – сідальний праотців, глас 8-ий: «Авраама, Ісаака та Якова...». Степенні і прокимен – гласу. Євангеліє воскресне 6-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4 (ірмоси раз), мучеників на 3, юнаків на 3 і праотців на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – кондак та ікос мучеників, глас 3-ій, інший кондак мучеників, глас 2-ий; сідальний мучеників, глас 8-ий (двічі). «Слава: І нині» – іпакой праотців, глас 2-ий. Після 6-ої пісні – кондак та ікос праотців, глас 6-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний 6-ий, світильний праотців. «Слава» – світильний праотців «І нині» – Богородичний Мінеї (див. в службі праотців). «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 3-ій – 3, і праотців, глас 2-ий – 2 (з приспівами: «Благословенний Ти, Господи Боже отців наших, і хвальне і прославлене ім’я Твоє повіки», «Ти праведний у всьому, що створив єси нам. Будучи вкинутим у рів, пророк Даниїл пожив зі звірами, які не доторкнулися до нього»; перша стихира – двічі) і мучеників, глас 3-ій – 3. «Слава» – праотців, глас 7-ий: «Прийдіть, усі вірні...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «В день спасіння...». Перед 1-им часом на «Слава: І нині» – євангельська стихира 6-а."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ: На 1-у і 6-у часі – тропар воскресний. «Слава» – тропар праотців. Кондак праотців; На 3-у і 9-у часі – тропар воскресний. «Слава» – тропар мучеників. Кондак мученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4, праотців, пісня 3-я – 4, і мучеників, пісня 6-а – 4. На вході – «Прийдіть... що воскрес із мертвих...». Після входу – тропар воскресний, тропар праотців, тропар мучеників; кондак мученика. «Слава» – інший кондак мученика, «І нині» – кондак праотців. Прокимен і алилуарій – праотців і мучеників. Апостол і Євангеліє – неділі і праотців. Причасний – недільний і праотців."}]},
{"date":"12-14","weekday":"понеділок","title":"29-й тиждень після П’ятдесятниці. Мчч. Фірса, Левкія і Калиника (249 – 251). Мчч. Филимона, Аполонія, Аріана і Феотиха (286 – 287).","readings":["Євр., 308 зач., III, 5 – 11, 17 – 19. Лк., 102 зач., XX, 27 – 44."],"notes":"Служба мучеників не має святкового знака, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: Октоїха, глас 3-ій – 3 і мучеників, глас 4-ий – 3. «Слава: І нині» – Богородичний Мінеї: «Лежу на ложі довіри...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава: І нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар мучеників (загальний), глас 1-ий: «Болістями святих...». «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Чудо чудес, Благодатна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучеників (загальний), глас 1-й: «Болістями святих...» (двічі). «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Чудо чудес, Благодатна...». Кафизми 4-а, 5-а і 6-а. Малих єктений немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4 і мучеників на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої та 9-ої пісень – ірмоси канону мучеників. Після 3-ої пісні – сідальний мучеників, глас 4-ий. «Слава: І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак мучеників, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава: І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава: І нині» – Богородичний Октоїха, глас той же. Після Трисвятого – тропар мучеників (загальний), глас 1-ий: «Болістями святих...». «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Пречиста Богородице, на небесах благословенна...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мучеників."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар мучеників; кондак дня, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар мучеників; кондак дня, кондак храму, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-15","weekday":"вівторок","title":"Сщмч. Єлевферія, єп., матері його мц. Анфії та мч. Корива, єпарха (ІІ). Прп. Павла Латрійського (955). Свт. Стефана, спов., архієп. Сурозького (VІІІ). Собор Кримських святих. Мч. Єлевферія Візантійського (305 – 311). Прп. Парда, самітника (VІ).","readings":["Євр., 310 зач., IV, 1 – 13. Лк., 106 зач., XXI, 12 – 19.","Свт.: Євр., 318 зач., VІІ, 26 – VІІІ, 2. Ін., 36 зач., Х, 9 – 16."],"notes":"Звершується шестирична служба святителя Стефана, архієп. Сурожського разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири святителя, глас 4-ий і 2-ий – 6. «Слава» – святителя, глас 4-ий: «Подобає Сурожському роду...», «І нині» – Богородичний за гласом «Слави», від менших: «Визволи нас від бід наших...» . Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава» – святителя, глас 5-ий: «Засурмімо трубою пісень...», «І нині» – Богородичний за гласом «Слави», від менших: «Вгамуй болісті постійно зітхаючої душі моєї...». Після Трисвятого – тропар святителя, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «До Богородиці щиро нині...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар святителя, глас 4-ий (двічі). «Слава: І нині» – Богородичний за гласом тропаря, від менших: «До Богородиці щиро нині...». Кафизми 7-а, 8-а і 9-а. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси раз), 2-ий на 4 і святителя на 4. Біблійні пісні «Господеві співаймо...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону святителя. Після 3-ої пісні – сідальний святителя, глас 1-ий. «Слава: І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос святителя, глас 3-ій. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний святого, «І нині» – Богородичний Мінеї. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава» – святителя, глас 6-ий: «Преподобний і треблаженний...», «І нині» – Богородичний за гласом «Слави», від менших: «Великих дарувань сподобилася Ти...». Після Трисвятого – тропар святителя, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»"},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак святителя."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ повсякденні антифони. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, тропар дня, тропар святителя; кондак дня, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня, тропар храму, тропар святителя; кондак дня, кондак храму, кондак святителя. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн усердная...». Прокимен, алилуарій і причасний – дня і святителя. Апостол і Євангеліє – дня і святителя."}]},
{"date":"12-16","weekday":"середа","title":"Прор. Агея (500 до Р. Х.). Мч. Марина Римського (ІІІ). Св. блгв. імператриці Візантійської Феофанії (893 – 894).","readings":["Євр., 312 зач., V, 11 – VІ, 8. Лк., 104 зач., XXI, 5 – 7, 10 – 11, 20 – 24."],"notes":"Служба прор. Аггея не має святкового знака, звершується разом зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири Октоїха , глас 3-ій – 3 і пророка, глас 8-ий – 3. «Слава: І нині» – Хрестобогородичний Мінеї: «Агниця нескверна...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій. «Слава: І нині» – Хрестобогородичний Октоїха. Після Трисвятого – тропар пророка, глас 2-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших «Препрославлена єси, Богородице Діво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар пророка, глас 2-ий (двічі). «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших «Препрославлена єси, Богородице Діво...». Кафизми 10-а, 11-а і 12-а. Малих єктеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з іромосом на 6 (ірмос один раз), 2-ий на 4 і пророка на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону пророка. Після 3-ої пісні – сідальний пророка, глас 3-ій. «Слава: І нині» – Хрестобогородичний Мінеї, глас той же. Після 6-ої пісні – кондак та ікос пророка (загальний), глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава: І нині» – Хрестобогородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій «Слава: І нині» – Хрестобогородичний Октоїха. Після Трисвятого – тропар пророка, глас 2-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак пророка."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі і кондаки: У храмі Господському – тропар дня «Спаси, Господи...», тропар пророка, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар пророка; кондак дня, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар пророка; кондак дня, кондак храму, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-17","weekday":"четвер","title":"Прор. Даниїла та трьох отроків: Ананії, Азарії та Мисаїла (600 до Р. Х.). Прп. Даниїла Єгипетського, спов., у схимі Стефана (Х).","readings":["Євр., 315 зач., VІІ, 1 – 6. Лк., 107 зач., XXI, 28 – 33.","Свв.: Євр., 330 зач., XI, 33 – XII, 2. Лк., 62 зач., XI, 47 – XII, 1."],"notes":"Служба пророка Даниїла і трьох отроків шестирична звершується разом із службою Октоїха","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири на 6: пророка, глас 4-ий – 3 і отроків, глас той же – 3. «Слава» – пророка, глас 2-ий: «Нині духовно зібрав нас вірний ипророк...», «І нині» – передсвята, глас той самий: «Прийдіть усі, передсвяткуємо вірно...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій .«Слава: І нині» – Богородичний Мінеї, глас 6-ий: «Даниїл, муж бажань...». Після Трисвятого – тропар пророка, глас 2-ий. «Слава: І нині» – Богородичний за гласом тропаря від менших: «Тобою, Богородице Приснодіво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар пророка, глас 2-ий (двічі). «Слава: І нині» – Богородичний за гласом тропаря від менших: «Тобою, Богородице Приснодіво...». Кафизми 13-а, 14-а і 15-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси по двічі), пророка, глас 8-ий на 4, і отроків на 4, глас той же. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону трьох юнаків. Після 3-ої пісні – кондак і ікос пророка, глас 3-ій, сідальний отроків, глас 8-ий. «Слава» – інший сідальний пророка, «І нині» – Богородичний Мінеї, глас той же. Після 6-ої пісні – кондак і ікос отроків, глас 6-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава» – світильний пророка», «І нині» – Богородичний Мінеї: «Таємниче навчає, Пречиста...» «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава: І нині» – Богородичний Мінеї, глас 6-ий: «Духовному Сонцю правди...». Після Трисвятого – тропар пророка, глас 2-ий. «Слава: І нині» – Богородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак пророка."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі і кондаки: У храмі Господському і Богородиці – тропар храму, два тропарі дня, тропар пророка, два кондаки дня, кондак отроків, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – два тропарі дня, тропар храму, тропар пророка; два кондаки дня, кондак храму, кондак отроків, кондак пророка. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн усердная...». Прокимен, алилуарій і причасний – дня і святих. Апостол та євангеліє – дня і святих."}]},
{"date":"12-18","weekday":"п’ятниця","title":"Мчч. Севастіана Медіоланського та воїнів його: Никострата скарбника, дружини його Зої, Касторія, сщмчч. Транквилліна, пресвітера, та синів його Маркеліна та Марка, дияконів, мчч. Клавдія, начальника в’язниць, сина його Симфоріана, брата його Вікторина, Тивуртія і Кастула (бл. 287). Свт. Модеста, архієп. Єрусалимського (633 – 634). Прп. Флора, єп. Амійського (VІІ). Прп. Михаїла Синкела, сповідника (бл. 845).","readings":["Євр., 317 зач., VІІ, 18 – 25. Лк., 108 зач., XXI, 37 – XXII, 8."],"notes":"Служба мучеників не має святкового знака, звершується разом із службою Октоїха","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири на 6: Октоїха, глас 3-ій – 3, і мучеників, глас 1-ий – 3. «Слава: І нині» – Хрестобогородичний Мінеї, глас той же: «Діва пренепорочна, коли побачила на...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій .«Слава: І нині» – Хрестобогородичний Октоїха, глас той же. Після Трисвятого – тропар мучеників, глас 4-ий. «Слава: І нині» – Хрестобогородичний по гласу тропаря від менших: «Діво Пренепорочна...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мучеників, глас 4-ий (двічі). «Слава: І нині» – Хрестобогородичний по гласу тропаря від менших: «Діво Пренепорочна...». Кафизми 19-а і 20-а. Малих ектеній немає. Сідальні Октоїха. Псалом 50-ий. Канони: Октоїха 1-ий з ірмосом на 6 (ірмоси по двічі), 2-ий на 4, і мучеників на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучеників. Після 3-ої пісні – сідальний мучеників, глас 4-ий. «Слава: І нині» – Хрестобогородичний Мінеї, глас той же. Після 6-ої пісні – кондак і ікос мучеників (загальний), глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні співається «Достойно є». Екзапостиларій Октоїха. «Слава: І нині» – Богородичний Октоїха. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій. «Слава: І нині» – Хрестобогородичний Октоїха, глас той же. Після Трисвятого – тропар мучеників, глас 4-ий. «Слава: І нині» – Хрестобогородичний за гласом тропаря, від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мучеників."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ антифони повсякденні. Після входу – тропарі і кондаки: У храмі Господському – тропар дня «Спаси, Господи...», тропар мучеників, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак дня. У храмі Богородиці – тропар дня «Спаси, Господи...», тропар храму, тропар мучеників; кондак дня, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – кондак храму. У храмі святого – тропар дня «Спаси, Господи...», тропар храму, тропар мучеників; кондак дня, кондак храму, кондак мучеників. «Слава» – «Зі святими упокой...», «І нині» – «Заступнице християн...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-19","weekday":"субота","title":"Субота перед Різдвом Христовим. Мч. Воніфатія (290). Прп. Іллі Муромця, Києво-Печерського, в Ближніх печерах (бл. 1188). Мчч. Іллі, Прова та Ариса, єгиптян (308). Мч. Полієвкта і сщмч. Тимофія, диякона (ІV). Свт. Воніфатія Милостивого, єп. Ферентійського (VІ). Свт. Григорія, єп. Омиритського (бл. 552).","readings":["Суботи перед Різдвом Христовим: Гал., 205 зач., III, 8 – 12. Лк., 72 зач., XIII, 18 – 29.","Ряд.: Еф., 220 зач., ІІ, 11 – 13. Лк., 72 зач., XIII, 18 – 29 (євангельські читання співпадають, отже двічі не повторюємо)."],"notes":"Служба мч. Воніфатію немає святкового знаку і звершується зі службою Октоїха.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 18-а. На «Господи, взиваю» стихири мученика, глас 4-ий – 6 (кожна стихира – двічі). «Слава: І нині» – Богородичний воскресний, глас 3-ій: «Як нам не дивуватися...». Входу немає. Прокимен дня. На стиховні стихири Октоїха, глас 3-ій (мученичі з числа стихир на «Господи, взиваю»). «Слава: І нині» – Богородичний Октоїха, глас то йже. Після Трисвятого – тропар мученика, глас 4-ий. «Слава: І нині» – Богородичний воскресний, глас 3-ій: «Тебе оспівуємо, Богородице Діво...»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар мученика, глас 4-ий (двічі), «Слава: І нині» – Богородичний воскресний за гласом тропаря: «Від початку віку утаємнене...». Кафизми 16-а і 17-а. Малі єктенії. Сідальний Октоїха. Псалом 50-й. У храмі Господському та Богородиці: храму (ірмос двічі) на 6, мученикана 4 і Октоїха (мученичий) на 4. У храмі святого: мученика (ірмос двічі) на 6, храму на 4 і Октоїха (мученичий) на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси мученичого канону Октоїха. Після 3-ої пісні – кондак мученика, глас 4-ий; сідальний мученика, «Слава: І нині» – Богородичний Мінеї, глас то йже. Після 6-ої пісні – кондак мученика, глас 4-ий. На 9-й пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» співається. Екзапостиларій Октоїха. «Слава: І нині» – Богородичний Октоїха. «Хваліте Господа з небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири Октоїха, глас 3-ій (мученичі з числа стихир на хвалітніх). «Слава: І нині» – Богородичний Октоїха, глас той самий. Після Трисвятого – тропар мученика, глас 4-ий. «Слава: І нині» – Богородичний за гласом тропаря від менших: «Тебе величаємо, Богородице, взиваючи...»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак мученика."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні Октоїха – 6. Після входу – тропарі і кондаки: У храмі Господньому та Богородиці – тропар храму, тропар дня «Апостоли, мученики...», тропар мученика, кондак храму, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». У храмі святого – тропар дня «Апостоли, мученики...», тропар мученика, кондак мученика. «Слава» – «Зі святими упокой...», «І нині» – «Як початки єства...». Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – суботи перед Різдвом та дня (євангельські зачала співпадають)."}]},
{"date":"12-20","weekday":"неділя","title":"29-та неділя після П’ятдесятниці, перед Різдвом Христовим, святих отців. Глас 4-й. Передсвято Різдва Христового. Сщмч. Ігнатія Богоносця, єп. (107). Прп. Ігнатія, архім. Києво-Печерського, в Дальніх печерах (1435). Свт. Філогонія, єп. Антіохійського (323). Свт. Даниїла, архієп. Сербського (1338). Новодвірцівської і Леньківської (Новгород-Сіверської), званої «Спасителька потопаючих», ікон Божої Матері.","glas":4,"readings":["Ран. – Єв. 7-е, Ін., 63 зач., XX, 1 – 10.","Літ. – неділі перед Різдвом Христовим: Євр., 328 зач., XI, 9 – 10, 17 – 23, 32 – 40. Мф., 1 зач., I, 1 – 25."],"notes":"З цього дня до 14-го січня Октоїх у будні не співається. З 20-го по 24-те грудня на малому повечір’ї співаються трипіснці передсвяту. Подаємо порядок поєднання шестиричної служби священномученика Ігнатія Богоносця зі службою передсвята Різдва Христового. Примітка. З цього дня Октоїх не співається до віддання свята Богоявлення, за винятком недільних днів. У недільні дні не співається полієлей, крім пам’яті великих святих. На ранній в дні тижня читаються дві рядові кафизми, а на вечірні – третя звичайна. Біблійні пісні до віддання свята Богоявлення – «Співаймо Господеві...». У передсвята Різдва та Богоявлення на повечір’ї читаються особливі канони, складені за подобою канонів Страсного тижня (див. Типікон, 20 грудня, 3-е і 4-е «зри»). Воскресна служба з’єднується зі службою святим отцям. Порядок з’єднання вказаний в Типіконі і в Мінеї за 18 грудня.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: Октоїха, глас 4-ий – 4, передсвята, глас 6-ий – 3 і отців, глас 6-ий – 3,. «Слава» – отців, глас 6-ий: «Даниїл, богомудрий муж...», «І нині» – передсвята, глас 6-ий: «Вертепе прикрасся..». Вхід. Прокимен дня. Паремії отців – 3. На літії стихира храму і отців, глас 4-ий, «Слава» – отців, глас 3-ій: «Прийдіть, шанувальники свята, щоб прославити собор праотців...», «І нині» – передсвята, глас той же: «Прикрасся, Вифлеєме...». На стиховні стихири воскресні, глас 4-ий зі своїми приспівами. «Слава» – отців, глас 2-ий: «Радуйтеся, чесні пророки...», «І нині» – передсвята, глас той же: «Ось наближається час нашого спасіння...» (див. в службі отців). Після Трисвятого –«Богородице Діво» (двічі) і тропар отців «Великої віри подвижники...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 4-ий (двічі), «Слава» – тропар отців, глас 2-ий. «І нині» – тропар передсвята, глас 4-ий: «Колись було написане повеління...» Кафизми 2-а і 3-я. Малі єктенії. Сідальні воскресні. Непорочні. «Ангельський собор...». Сідальні отців, глас 8-ий: «Авраама, Ісаака...». «Слава: І нині» – Богородичний: «Ти, Людинолюбче, вийшов із лона отця...». Степенні і прокимен – гласу. Євангеліє воскресне 7-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: воскресний з ірмосом на 4, передсвята на 4 і отців на 6. Біблійні пісні: «Співаймо Господеві...». Катавасія: «Христос народжується...». Після 3-ої пісні – іпакої отців, глас 8-й (один раз). Після 6-ої пісні – кондак («Веселися, Вифлеєме...») та ікос отців, глас 1-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний. «Слава» – світильний отців. «І нині» – світильний передсвята: «Агниця нескверна». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 6: стихири воскресні, глас 4-ий – 4 і отців, глас 5-ий – 4 «Слава» – отців, глас 8-ий: «Зібрання вчителів у часи закону...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Після Трисвятого – тропар воскресний: «Воскрес із гробу...». Перед 1-им часом на «Слава: І нині» – стихира євангельська 7-а."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар отців. Кондак отців"},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу на 6 і отців, пісня 3-я на 4. На вході – «Прийдіть... що воскрес із мертвих...». Після входу – тропар воскресний, глас 4-ий, тропар отців. «Слава: І нині» – кондак отців Прокимен, пісня отців, глас 4-ий: «Благословен єси, Господи Боже отців наших...». Апостол – Неділі перед Різдвом Христовим. Алилуарій – отців, глас 4-ий: «Боже, вухами нашими чули ми...». Євангеліє – Неділі перед Різдвом Христовим. Причасний – недільний: «Хваліть Господа...», і отців: «Радуйтеся, праведні...». Відпуст недільний: «Христос, що воскрес із мертвих...»"}]},
{"date":"12-21","weekday":"понеділок","title":"30-й тиждень після П’ятдесятниці. Мц. Юліанії і з нею мчч. 500 чоловіків та мцц. 130 жінок, що в Нікомидії постраждали (304). Свт. Петра, митр. Київського і всієї Руси чудотворця (1326). Мч. Фемістоклея Мирлікійського (251). Свт. Філарета, митр. Київського і Галицького (1857).","readings":["Євр., 319 зач., VIII, 7 – 13. Мк., 33 зач., VIII, 11 – 21."],"notes":"Шестирична служба св. мч. Юліанії звершується зі службою передсвята Різдва Христового.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: передсвята, глас 4-ий – 3 і мучениці, глас той же – 3. «Слава: І нині» – передсвята, глас 6-ий: «Сионе торжествуй, Єрусалиме, веселися...». Входу немає. Прокимен дня. На стиховні стихири передсвята, глас 2-й (зі своїми приспівами). «Слава: І нині»– передсвята, глас 6-ий: «Безневісна Діво, звідкиля прийшла Ти...». Після Трисвятого – тропар святої, глас 4-ий. «Слава: І нині» – тропар передсвята, глас той же."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий (двічі). «Слава» – тропар святої, глас той же, «І нині» – тропар передсвята, глас 4-ий. Кафизми 4-а і 5-а. Малі єктенії. Сідальні передсвята. Псалом 50-ий. Канони: передсвята з ірмос на 8 (ірмоси по двічі) і святої на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону святої. Після 3-ої пісні – кондак святої, глас 3-ій; сідальний святої, глас 4-ий. «Слава: І нині» – сідальний передсвята, глас 3-ій. Після 6-ої пісні – кондак та ікос передсвята, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний передсвята. «Слава: І нині» – світильний передсвята. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири передсвята, глас 6-ий – 4. «Слава» – передсвята, глас той же: «Слово, Отцю Єдиносущне...», «І нині» – передсвята, глас той же: «Пророцтва волхва Валаама...». «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири передсвята, глас 2-ий (зі своїми приспівами). «Слава: І нині» – передсвята, глас 2-й: «Прийдіть земнородні...». Після Трисвятого – тропар святої, глас 4-ий. «Слава: І нині» – тропар передсвята, глас той же."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар передсвята. «Слава» – тропар святої. Кондак тільки передсвята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні передсвята, пісня 3-я – 4 (з ірмосом), і, пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар передсвята, тропар святої. «Слава» – кондак святої, «І нині» – кондак передсвята. У храмі Богородиці – тропар передсвята, тропар храму, тропар святої; кондак передсвята. «Слава» – кондак святої, «І нині» – кондак храму. У храмі святого – тропар передсвята, тропар храму, тропар святої; кондак храму. «Слава» – кондак святої, «І нині» – кондак передсвята. Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-22","weekday":"вівторок","title":"Вмц. Анастасії Узорішительниці (бл. 304). Мчч. Хрисогона, Феодотії, Євода, Євтихіана та інших (бл. 304).","readings":["Євр., 321 зач., IX, 8 – 10, 15 – 23. Мк., 34 зач., VIII, 22 – 26.","Вмц.: Гал., 208 зач., III, 23 – 29. Лк., 33 зач., VII, 36 – 50."],"notes":"Звершується шестирична служба вмц. Анастасії разом зі службою передсвята Різдва Христового.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-а. На «Господи, взиваю» стихири на 6: передсвята, глас 1-ий – 3, і мучениці, глас 8-ий – 3. «Слава» – мучениці, глас 2-ий: «Воскресіння дар придбала ти, всехвальна Анастасіє...», «І нині» – передсвята, глас 4-ий: «Вифлеєме, прикрашайся...». Входу немає. Прокимен дня. На стиховні стихири передсвята, глас 2-ий (зі своїми приспівами). «Слава» – мучениці, глас 4-ий: «Живоносного воскресіння Христового будучи тезоіменитою...», «І нині» – передсвята, глас той же: «Ісає, торжествуй і проречи...». Після Трисвятого – тропар мучениці, глас 4-ий. «Слава: І нині» – тропар передсвята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий (двічі). «Слава» – тропар мучениці, глас той же, «І нині» – тропар передсвята, глас той же. Кафизми 7-а і 8-а. Малі єктенії. Сідальні передсвята (по двічі). Псалом 50-ий. Канони: передсвята з ірмос на 8 (ірмоси по двічі) і мучениці на 6. Біблійні пісні: «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучениці. Після 3-ої пісні – кондак та ікос передсвята, глас 1-ий; сідальний мучениці, глас той же. «Слава: І нині» – сідальний передсвята, глас 8-ий. Після 6-ої пісні – кондак та ікос мучениці, глас 2-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний мучениці. «Слава: І нині» – світильний передсвята. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири передсвята, глас 6-ий – 4. «Слава» – передсвята, глас той же: «Жезлом залізним...», «І нині» – передсвята, глас той же: «Звеселися Давиде...». «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири передсвята, глас 2-ий (зі своїми приспівами). «Слава» – мучениці, глас 5-ий: «Передсвятковий день нині, «І нині» – передсвята, глас той же: «Не сумуй, Йосифе...». Після Трисвятого – тропар мучениці, глас 4-ий. «Слава: І нині» – тропар передсвята, глас той же."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар передсвята. «Слава» – тропар мучениці. Кондак тільки передсвята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні передсвята, пісня 3-я – 4 (з ірмосом), і мучениці, пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар передсвята, тропар мучениці. «Слава» – кондак мучениці, «І нині» – кондак передсвята. У храмі Богородиці – тропар передсвята, тропар храму, тропар мучениці; кондак передсвята. «Слава» – кондак мучениці, «І нині» – кондак храму. У храмі святого – тропар передсвята, тропар храму, тропар мучениці; кондак храму. «Слава» – кондак мучениці, «І нині» – кондак передсвята. Прокимен, алилуарій і причасний – дня і мучениці. Апостол і Євангеліє – дня і мучениці."}]},
{"date":"12-23","weekday":"середа","title":"Мчч. на Криті: Феодула, Саторнина, Евпора, Геласія, Евникіана, Зотика, Помпія, Агафопуса, Василіда та Евареста (ІІІ). Прп. Нифонта, єп. Кіпрського (ІV). Прп. Павла, єп. Неокесарійського (ІV).","readings":["Євр., 323 зач., X, 1 – 18. Мк., 36 зач., VIII, 30 – 34."],"notes":"Служба мучеників шестерична звершується разом зі службою передсвята.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-а. На «Господи, взиваю» стихири на 6: передсвята, глас 4-ий – 3, і мучеників, глас той же – 3. «Слава» – мучеників, глас 3-ій: «Передсвяткове нині настало свято мучеників...», «І нині» – передсвята, глас той же: «Благоприкрашайся, Вифлеєме...». Входу немає. Прокимен дня. На стиховні стихири передсвята, глас 6-ий (зі своїми приспівами). «Слава» – мучеників, глас 2-ий: «Крит нині передсвяткує...», «І нині» – передсвята, глас той же: «Ось наближається час нашого спасіння...». Після Трисвятого – тропар мучеників, глас 3-ій. «Слава: І нині» – тропар передсвята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар передсвята, глас 4-ий (двічі). «Слава» – тропар мучеників, глас 3-ій, «І нині» – тропар передсвята, глас 4-ий. Кафизми 10-а і 11-а. Малі єктенії. Сідальні передсвята (по двічі). Псалом 50-ий. Канони: передсвята з ірмос на 8 (ірмоси по двічі) і мучеників на 6. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучеників. Після 3-ої пісні – кондак та ікос передсвята, глас 3-ій; сідальний мучеників, глас 1-ий. «Слава: І нині» – сідальний передсвята, глас той же. Після 6-ої пісні – кондак та ікос мучеників, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний мучеників. «Слава: І нині» – світильний передсвята. «Хваліте Господа з Небес...» і хвалітні псалми. На хвалітніх стихири передсвята, глас 6-ий – 4. «Слава» – передсвята, глас той же: «Співай, новий Ізраїлю...», «І нині» – передсвята, глас той же: «Явився Ти на землі...». «Тобі слава подобає...» не читається, але відразу читець: «Слава Тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири передсвята, глас 2-ий (зі своїми приспівами). «Слава» – мучеників, глас 3-ій: «Мужні мученики за істину...», «І нині» – передсвята, глас 8-ий: «У Вифлеємі народжується...». Після Трисвятого – тропар мучеників, глас 3-ій. «Слава: І нині» – тропар передсвята, глас 4-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар передсвята. «Слава» – тропар мучеників. Кондак тільки передсвята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні передсвята, пісня 3-я – 4 (з ірмосом), і мучеників, пісня 6-а – 4. Після входу – тропарі і кондаки: У храмі Господському – тропар передсвята, тропар мучеників. «Слава» – кондак мучеників, «І нині» – кондак передсвята. У храмі Богородиці – тропар передсвята, тропар храму, тропар мучеників; кондак передсвята. «Слава» – кондак мучеників, «І нині» – кондак храму. У храмі святого – тропар передсвята, тропар храму, тропар мучеників; кондак храму. «Слава» – кондак мучеників, «І нині» – кондак передсвята. Прокимен, алилуарій і причасний – дня. Апостол і Євангеліє – дня."}]},
{"date":"12-24","weekday":"четвер","title":"Навечір’я Різдва Христового (Різдвяний святвечір). Прмц. Євгенії і з нею мчч. Прота, Якинфа та мц. Клавдії (бл. 262). Прп. Миколая, ченця (ІХ). Прп. Кукші Одеського (1964). Літургія за чином свт. Василія Великого.","readings":["На 1-му часі: Євр., 303 зач., I, 1 – 12. Мф., 2 зач., I, 18 – 25.","На 3-му часі: Гал., 208 зач., III, 23 – 29. Лк., 5 зач., II, 1 – 20.","На 6-му часі: Євр., 304 зач., I, 10 – II, 3. Мф., 3 зач., II, 1 – 12.","На 9-му часі: Євр., 306 зач., II, 11 – 18. Мф., 4 зач., II, 13 – 23.","Літ. – Євр., 303 зач., I, 1 – 12. Лк., 5 зач., II, 1 – 20."],"sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 12-а. На «Господи взиваю» стихири на 6: передсвята, глас 5-ий – 3, преподобномучениці – 3. «Слава: І нині» – передсвята, глас 2-ий: «Ось наблизився час нашого спасіння...». Входу немає. Прокимен дня. Стихири на стиховні передсвята, глас 1-ий. «Слава: І нині» – передсвята, глас 6-ий: «Сионе, торжествуй...». Після «Трисвятого» – тропар передсвята."},{"svc":"РАННІЙ","text":"НА РАННІЙ На «Бог Господь» – тропар предсвята (двічі). «Слава: І нині» – тропар передсвята Кафизми 13-а і 14-а. Малі ектенії. Сідальні передсвята. 50-ий псалом. Канони: передсвята з ірмосом на 8 і святої на 4. Біблійні пісні: «Співаймо Господеві...». Катавасія – ірмос канону преподобномучениці. Після 3-ої пісні: сідальні святої, глас 8-ий. «Слава: І нині» – сідальний передсвята. Після 6-ої пісні: кондак і ікос передсвята, глас 3-ій. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно» не співається. Світильний передсвята «Слава: І нині» інший світильний передсвята. «Хваліте Господа з небес...» і хвалітні псалми. На хваліте стихири передсвята, глас 6-ий – 4. «Слава» – передсвята, глас 8-ий: «Гряди, Вифлеєме...», «І нині» – передсвята, глас той же: «О, блаження Богоотроковиці утроба...». «Тобі слава подобає...» не читається, але одразу: «Слава тобі, що показав нам світло». Читається повсякденне славослів’я. На стиховні стихири передсвята, глас 2-ий (зі своїми приспівами). «Слава» – передсвята, глас той же: «Слава Тобі, Отче, Сину і Душе...». «І нині» – передсвята, глас той же: «Радуйся, бо Ти життя народила світу...». Після Трисвятого – тропар передсвята, глас 4-ий. Потрійна ектенія і відпуст. 1-ий час до ранньої не приєднується. Окремо від ранньої (за Уставом, «на початку другої години», тобто, за нашим часом, близько 8-ої години ранку) відбувається послідування часів навечір’я (царських часів – 1-го, 3-го, 6-го і 9-го) з приєднанням до них чину зображальних. Царські часи звершуються при відкритих царських вратах. Священик в єпитрахилі, фелоні і, за традицією, в поручах, з Євангелієм в руках (у супроводі свічконосця і диякона в облаченні, з кадилом і свічкою) виходить з вівтаря через царські врата до поставленого посеред церкви прямо навпроти Царських врат аналоя. Обійшовши навколо аналоя, свічконосець ставить свічку з його східної сторони. Ієрей, поклавши Євангеліє на аналой, виголошує початковий виголос 1-го часу: «Благословен Бог наш...». Читець: «Амінь», «Слава Тобі, Боже наш, слава Тобі», «Царю Небесний...», Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Читець: «Амінь», «Господи, помилуй» (12 разів), «Слава: І нині», «Прийдіть, поклонімось...» (тричі) і псалми 1-го часу (5-ий, 44-ий і 45-ий). З початком читання псалмів ієрей, в супроводі диякона зі свічкою, звершує кадіння навколо Євангелія, потім кадить вівтар, іконостас, весь храм і народ. Після закінчення 45-го псалма читець виголошує«Слава: І нині», «Алилуя, Алилуя, Алилуя, слава Тобі, Боже» (тричі), «Господи, помилуй» (тричі), «Слава» – хор або читець: тропар передсвята, глас 4-ий: «Записатися прийшла колись...», читець: «І нині» – Богородичний: «Як нам назвати Тебе, Благодатна?..». Після Богородичного часу хор співає (зазвичай стихирним наспівом) особливі тропарі свята зі стихами: 1-ий хор – тропар, глас 8-ий: «Віфлеєме, готуйся...», 2-ий хор – той же тропар. Читець – стих: «Бог від півдня прийде...», 1-ий хор – тропар, глас 3-ий: «Нині гряде сповнення провіщеного пророками...». Читець – стих: «Господи, почув слух Твій...», 2-й хор – той же тропар. «Слава» – 1-ий хор – тропар, глас 8-ий: «Так говорить Йосиф до Діви...», «І нині» – 2-ий хор – той же тропар. Після звершення тропарів диякон виголошує: «Будьмо уважні». Читець – прокимен, глас 4-ий: «Господь промовив до мене: Син мій єси Ти, Я нині родив Тебе.»; стих: «Проси в Мене, і дам Тобі народи в насліддя Твоє, і край землі – у володіння Твоє». Після виконання хором прокимна, читаються паремія і Апостол. Диякон: «Премудрість». Читець: «Пророцтва Михея читання». Диякон: «Будьмо уважні». Читець читає Паремію (глава 5). Диякон: «Премудрість». Читець: «До Євреїв послання святого апостола Павла читання». Диякон: «Будьмо уважні». Читець читає апостол (Євр., Зач. 303). Зазвичай після читання Апостола ієрей напівголосно вимовляє: «Мир тобі», на що читець також напівголоса відповідає: «І духові твоєму». «Алилуя» після Апостола не співається, але відразу диякон виголошує: «Премудрість, станьмо побожно, вислухаймо святого Євангелія». Ієрей: «Мир всім». Хор: «І духові твоєму». Ієрей: «Від Матфея святого Євангелія читання». Хор: «Слава Тобі, Господи, слава Тобі». Диякон: «Будьмо уважні». Священик читає Євангеліє (Мф., Зач. 2). Після закінчення Євангелія хор співає: «Слава Тобі, Господи, слава Тобі». Читець – тропарі: «Стопи мої направ...» і «Нехай наповняться уста мої...», Трисвяте. Після «Отче наш» священник – виголос: «Бо Твоє є Царство...». Читець або хор: «Амінь», і кондак передсвята, глас 3-й: «Діва днесь Предвічне Слово...». Читець: «Господи, помилуй» (40 разів), молитва: «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава: І нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Ієрей: «Боже, змилосердься над нами і благослови нас...». Читець: «Амінь». Ієрей: «Христе, Світло Істинне...». Читець: «Прийдіть, поклонімось...» (тричі), і починає 3-ій час. Під час читання псалмів 3-го часу (66-го, 86-го і 50-го) ієрей з дияконом (за Уставом – диякон) звершують мале кадіння храму: кадять навколо Євангеліє, іконостас, предстоятеля і моляться. Після закінчення 50-го псалма читець: «Слава: І нині», «Алилуя, Алилуя, Алилуя, слава Тобі, Боже» (тричі), «Господи, помилуй» (тричі), «Слава» – хор або читець: тропар передсвята, глас 4-й: «Записатися прийшла колись...», читець: «І нині» – Богородичний: «Богородице, Ти єси виноградна лоза істинна...». Хор співає тропарі зі стихами: 1-ий хор – тропар, глас 6-ий: «Цей Бог наш...», 2-ий хор – той же тропар. Читець – стих: «Бог від півдня прийде...», 1-ий хор – тропар, глас 8-ий: «Раніше Різдва Твого...». Читець – стих: «Господи, почув слух Твій...», 2-ий хор – той же тропар. «Слава» – 1-ий хор – тропар, глас 3-ій: «Йосифе, скажи нам...», «І нині» – 2-ий хор – той же тропар. Після виконання тропарів диякон: «Будьмо уважні». Читець – прокимен, глас 4-ий: «Дитя народилося нам...»; стих: «Влада Його на раменах Його». Після виконання хором прокимну читаються паремія і Апостол. Диякон: «Премудрість». Читець: «Пророцтва Варуха читання». Диякон: «Будьмо уважні». Читець читає Паремію (глави 3 і 4). Диякон: «Премудрість». Читець: «До Галатів Послання святого апостола Павла читання». Диякон: «Будьмо уважні». Читець читає апостол (Гал., Зач. 208). Ієрей: «Мир тобі». Читець: «І духові твоєму». Диякон: «Премудрість, станьмо побожно, вислухаймо святого Євангелія». Ієрей: «Мир всім». Хор: «І духові твоєму». Ієрей: «Від Луки святого Євангелія читання». Хор: «Слава Тобі, Господи, слава Тобі». Диякон: «Будьмо уважні». Ієрей читає Євангеліє (Лк., Зач. 5). Після закінчення Євангелія хор співає: «Слава Тобі, Господи, слава Тобі». Читець – тропар: «Господь Бог благословенний...», Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Читець або хор: «Амінь», і кондак передсвята, глас 3-ій: «Діва днесь Предвічне Слово...». Читець: «Господи, помилуй» (40 разів), молитва: «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава: І нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Ієрей: «Молитвами святих отців наших...». Читець – «Амінь» і молитву: «Владико, Отче Вседержителю...». Читець: «Прийдіть, поклонімось...» (тричі), і починає 6-ий час. Під час читання псалмів 6-го часу (71-го, 131-го і 90-го) ієрей з дияконом (за Уставом – диякон) звершують мале кадіння храму, як на 3-му часі. Після закінчення 90-го псалма читець: «Слава: І нині», «Алилуя, Алилуя, Алилуя, слава Тобі, Боже» (тричі), «Господи, помилуй» (тричі), «Слава» – хор або читець: тропар передсвята, глас 4-ий: «Записатися колись...», читець: «І нині» – Богородичний: «Через превеликі гріхи наші сміливості не маємо...». Хор співає тропарі зі стихами: 1-й хор – тропар, глас 1-ий: «Прийдіть, вірні...», 2-ий хор – той же тропар. Читець – стих: «Бог від півдня прийде...», 1-ий хор – тропар, глас 4-ий: «Слухай, Небо...». Читець – стих: «Господи, почув слух Твій...», 2-й хор – той же тропар. «Слава» – 1-ий хор – тропар, глас 5-ий: «Прийдіть, Христові люди...», «І нині» – 2-й хор – той же тропар. Після виконання тропарів диякон: «Будьмо уважні». Читець – прокимен, глас 4-й: «З утроби раніше віків родив Тебе...»; стих: «Сказав Господь Господеві моєму...». Після виконання хором прокимну читаються паремія і Апостол. Диякон: «Премудрість». Читець: «Пророцтва Ісаї читання». Диякон: «Будьмо уважні». Читець читає Паремію (глави 7 і 8). Диякон: «Премудрість». Читець: «До Євреїв послання святого апостола Павла читання». Диякон: «Будьмо уважні». Читець читає апостол (Євр., Зач. 304). Ієрей: «Мир тобі». Читець: «І духові твоєму». Диякон: «Премудрість, станьмо побожно, вислухаймо святого Євангелія». Ієрей: «Мир всім». Хор: «І духові твоєму». Ієрей: «Від Матфея святого Євангелія читання». Хор: «Слава Тобі, Господи, слава Тобі». Диякон: «Будьмо уважні». Ієрей читає Євангеліє (Мф., Зач. 3). Після закінчення Євангелія хор співає: «Слава Тобі, Господи, слава Тобі». Читець – тропар: «Скоро пошли нам щедроти Твої, Господи,...», Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Читець або хор: «Амінь», і кондак передсвята, глас 3-ій: «Діва днесь Предвічне Слово...». Читець: «Господи, помилуй» (40 разів), молитва: «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава: І нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Ієрей: «Молитвами святих отців наших...». Читець – «Амінь» і молитву: «Боже і Господи Сил...». Читець: «Прийдіть, поклонімось...» (тричі), і починає 9-тий час. Під час читання псалмів 9-го часу (109-го, 110-го і 85-го) ієрей з дияконом (за уставом – диякон) звершують кадіння всього храму, як на 1-му часі. Після закінчення 85- го псалма читець: «Слава: І нині», «Алилуя, Алилуя, Алилуя, слава Тобі, Боже» (тричі), «Господи, помилуй» (тричі), «Слава» – хор або читець: тропар передсвята, глас 4-й: «Записатися колись...», читець: «І нині» – Богородичний: «Ти, що нас ради народився...». Хор співає тропарі зі стихами: 1-й хор – тропар, глас 7-й: «Здивувався Ірод...», 2-й хор – той же тропар. Читець – стих: «Бог від півдня прийде...», 1-й хор – тропар, глас 2-й: «Коли Йосиф...». Читець – стих: «Господи, почув слух Твій...», 2-й хор – той же тропар. Канонарх (за Типіконом – диякон) читає голосно стихиру, глас 6-й: «Нині народжується від Діви...» (творимо три малих поклони). Після закінчення стихири ієрей або диякон виголошує многоліття. 1-е прохання: «Блаженнішому владиці...», 2-е прохання: «Всім православним християнам...». На кожне прохання хор співає: «Многії літа» (тричі). Якщо служба відбувається в монастирі, то до двох зазначених прохань додається третя: «Спаси, Христе Боже, преподобного отця нашого ігумена...», в цьому випадку хор починає співати зі слів «Спаси, Христе Боже...», співається цей піснеспів також тричі. Після закінчення многоліття обидва хори на «Слава: І нині»співають стихиру, глас 6-й: «Нині народжується від Діви...». Диякон: «Будьмо уважні». Читець – прокимен, глас 4-й: «Мати Сион промовляє...»; стих: «Основи Його на горах святих». Після виконання хором прокимну читаються паремія і Апостол. Диякон: «Премудрість». Читець: «Пророцтва Ісаї читання». Диякон: «Будьмо уважні». Читець читає Паремію (глава 9). Диякон: «Премудрість». Читець: «До Євреїв послання святого апостола Павла читання». Диякон: «Будьмо уважні». Читець читає апостол (Євр., Зач. 306). Ієрей: «Мир тобі». Читець: «І духові твоєму». Диякон: «Премудрість, будьмо уважні, вислухаймо святого Євангелія». Ієрей: «Мир всім». Хор: «І духові твоєму». Ієрей: «Від Матфея святого Євангелія читання». Хор: «Слава Тобі, Господи, слава Тобі». Диякон: «Будьмо уважні». Ієрей читає Євангеліє (Мф., Зач. 4). Хор: «Слава Тобі, Господи, слава Тобі». Після прочитання Євангелія ієрей у супроводі диякона вносить Євангеліє у вівтар, осінивши хрестоподібно, за звичаєм, ним народ з амвона. Диякон зачиняє царські врата, завіса ж залишається відкритою до відпусту зображальних (в деяких храмах завіса закривається і знову відкривається з початком зображальних). Читець – тропар: «Не залиш нас до кінця...», Трисвяте. Після «Отче наш» ієрей – виголос: «Бо Твоє є Царство...». Читець або хор: «Амінь», і кондак передсвята, глас 3-й: «Діва днесь Предвічне Слово...». Читець: «Господи, помилуй» (40 разів), молитва: «Ти, що кожного часу...», «Господи, помилуй» (тричі), «Слава: І нині», «Чеснішу від херувимів...», «Іменем Господнім благослови, отче». Ієрей: «Молитвами святих отців наших...». Читець – «Амінь» і молитву: «Владико Господи, Ісусе Христе...». Після заключної молитви 9-го часу починається читання зображальних: «Благослови, душе моя, Господа...», «Слава» – «Хвали, душе моя, Господа...», «І нині» – «Єдинородний Сину...», «У царстві Твоїм...»,«Слава, і нині» – «Пом’яни нас, Господи...», «Пом’яни нас, Владико...», «Пом’яни нас, Святий...», «Хор Небесний...», «Приступіть до Нього...», «Хор Небесний...», «Слава» – «Хор святих Ангелів...», «І нині» – «Вірую...»(Символ віри), «Полегши, прости...»,«Отче наш», виголос: «Бо Твоє є царство...»; хор або читець – кондак передсвята, глас 3-ій: «Діва днесь Предвічне Слово...», читець: «Господи, помилуй» (40 разів); молитва «Всесвята Тройце...». «Нехай буде ім’я Господнє...» (тричі), «Слава: І нині», псалом 33-ий. Диякон: «Премудрість». Хор: «Достойно є...», закінчуючи словами «і Матір Бога нашого». Ієрей: «Пресвята Богородице, спаси нас». Хор: «Чеснішу від херувимів...». Ієрей: «Слава Тобі, Христе Боже, надіє наша, слава Тобі». Хор: «Слава, і нині», «Господи, помилуй» (тричі), «Благослови». Священник творить відпуст (на амвоні, при зачинених царських вратах). Многоліття. Згідно церковної практики одразу після відпусту зоображальних звершується Літургія свт. Василія Великого, яка починається великою вечірнею."},{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ Перед початком Літургії ієрей з дияконом моляться у вівтарі перед престолом: «Царю Небесний...», «Слава ввишніх Богу...» після чого диякон на амвоні: «Благослови, владико». Ієрей: «Благословене Царство...». Хор: «Амінь». Початок звичайний і 103-ій псалом (священик читає світильничні молитви перед царськими вратами). Велика ектенія. Кафизми немає. На «Господи, взиваю» стихири свята, глас 2-ий – 8 (кожна стихира – двічі). «Слава: І нині» – свята, глас той же: «Коли Август став єдиним володарем на землі,...» (під час співання стихир священник закінчує проскомидію). Звершується звичайне кадіння. Вхід з Євангелієм. «Світло Тихе». Прокимен дня. Читання восьми паремій свята. Після 3-ої паремії, за звичаєм, відкриваються царські врата. Читець виголошує: «Глас шостий» і сам співає тропар: «Таємно народився Ти у вертепі...». Виконання цих тропарів зі стихами відбувається в наступному порядку: Читець виголошує тропар: «Таємно народився Ти у вертепі, але небо Тебе всім проповідує, як устами, зірку пропонуючи, Спасе, і привела вона до Тебе волхвів, що з вірою поклоняються Тобі», і сам співає: «З ними ж помилуй нас». Хор співає закінчення тропаря: «З ними ж помилуй нас». Читець виголошує 1-ий стих: «Основа Його на горах святих, любить Господь врата Сиона більше за всі поселення Якова; преславне говориться про тебе, граде Божий. Пом’яну Раав і Вавилон, що знають Мене. І вона привела до Тебе волхвів, що з вірою поклоняються Тобі». Хор співає закінчення тропаря: «З ними ж помилуй нас». Читець виголошує 2-й стих: «І ось іноплемінники, і Тир, і люди ефіопські були там. Мати Сион промовляє: людина, і людина народилася в ньому, і заснував його Вишній. І вона привела до Тебе волхвів, що з вірою поклоняються Тобі». Хор співає закінчення тропаря: «З ними ж помилуй нас». Читець виголошує 3-ій стих: «Господь сповістить Писанням людей, і князів їхніх, що були в ньому: бо оселя всіх, що радіють, у Тобі. І вона привела до Тебе волхвів, що з вірою поклоняються Тобі». Хор співає закінчення тропаря: «З ними ж помилуй нас». Читець виголошує: «Слава Отцю і Сину і Святому Духу. І вона привела до Тебе волхвів, що з вірою поклоняються Тобі». Хор співає закінчення тропаря: «З ними ж помилуй нас». Читець виголошує: «І нині, і повсякчас, і на віки віків. Амінь. І вона привела до Тебе волхвів, що з вірою поклоняються Тобі. Хор співає закінчення тропаря: «З ними ж помилуй нас». Читець виголошує тропар: «Таємно народився Ти у вертепі, але небо Тебе всім проповідує, як устами, зірку пропонуючи, Спасе, і вона привела до Тебе волхвів, що з вірою поклоняються Тобі», і сам співає: «З ними ж помилуй нас». Зачиняються царські врата. Так само виповнюється тропар і після 6-ої паремії. На кліросі співають завершальні його слова: «Життєдавче, слава Тобі». Після закінчення 8-ої паремії відкриваются царські врата. Єктенія мала. Виголос: «Бо Ти святий єси, Боже наш...». Трисвяте співається. Диякон: «Будьмо уважні». Ієрей: «Мир всім». Читець: «І духові твоєму». Диякон: «Премудрість». Читець: Прокимен, глас 1-ий: «Господь промовив до Мене: Син Мій єси Ти, Я сьогодні родив Тебе»; стих: «Проси в Мене, і дам Тобі народи в насліддя Твоє, і край землі у володіння Твоє». Апостол – Євр., Зач. 303. Алилуарій, глас 5-ий: «Сказав Господь Господеві моєму: Сиди праворуч Мене, доки не покладу ворогів Твоїх підніжжям ніг Твоїх»; стих: «Жезл сили пошле Тобі Господь від Сіону...»; стих: «Із утроби раніше віків породив Тебе». Примітка. Можливе кадіння перед читанням Євангелія як на Літургії. Євангеліє – Лк., Зач. 5. Після прочитання Євангелія царські врата закриваються. Потрійна ектенія: «Промовмо всі...» і далі Літургія по чину свт. Василія Великого Замість «Достойно...» – «Тобою радується...» Причасний: «Хваліте Господа з небес...» Відпуст (короткий святковий): «Христос, істинний Бог наш, що у вертепі народився і в яслах покладений був, заради нашого спасіння, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і людинолюбець». Після відпусту вечірні на середині храму ставиться запалений світильник, і біля нього вийшовши з вівтаря священнослужителі співають тропар свята Різдва Христового, глас 4-ий: «Різдво Твоє, Христе Боже наш...», «Слава: І нині» – кондак свята, глас 3-ій: «Діва днесь Предвічного народжує...». (Величання не співається). Потім співаються многоліття: «Блаженнійшого Владику...»."}]},
{"date":"12-25","weekday":"п’ятниця","title":"РІЗДВО ГОСПОДА БОГА І СПАСИТЕЛЯ НАШОГО ІСУСА ХРИСТА. Літургія за чином свт. Іоана Золотоустого.","readings":["Ран. – Мф., 2 зач., I, 18 – 25.","Літ. – Гал., 209 зач., IV, 4 – 7. Мф., 3 зач., II, 1 – 12."],"notes":"Примітка. Від Різдва Христового до Богоявлення скасовується піст і не буває земних поклонів – ні в церкві, ні в келіях (див. Типікон, 25 грудня, 4-е «див»). Звершується бдінна служба свята (за Мінеєю). ВСЕНІЧНЕ БДІННЯ на свято Різдва Христового складається з великого повечір’я з літією, ранньої та 1-ого часу. За Уставом, богослужіння має починатися «о 10-ій годині ночі», за нашим часом – о 4 годині ранку (див. Типікон, 25 грудня) Відкривається завіса і царські врата. Ієрей з дияконом творять початок, як в усі свята із бдінням, тобто спочатку звершують кадіння престолу і всього вівтаря. Диякон зі свічкою виходить на солію і виголошує: «Благослови, владико». Ієрей перед престолом: «Благословен Бог наш...» (при цьому творить кадилом хрест). Хор: «Амінь». Читець: «Слава Тобі, Боже наш...», «Царю Небесний», і читає велике повечір’я. Ієрей виходить з вівтаря в супроводі диякона зі свічкою і звершує повне кадіння всього храму, як на початку всенічної. Після закінчення кадіння царські врата зачиняються. Завіса залишається відкритою. На спів «З нами Бог...», спів тропаря і кондака після 1-го і 2-го Трисвятого, за традицією, відкриваються царські врата. Після 1-ого Трисвятого – тропар свята, глас 4-ий: «Різдво Твоє, Христе Боже наш...». Після 2-ого Трисвятого – кондак свята, глас 3-ій: «Діва днесь Предвічного народжує...». Після «Слава в вишніх Богу...» – вихід на літію. На літії стихири свята, глас 1-ий. «Слава» – свята, глас 5-ий: «Волхви, персидські царі...», «І нині» – свята, глас 6-ий: «Торжествують всі Ангели на небесах...». На стиховні стихири свята, глас 2-ий і глас 3-ій (зі своїми приспівами). «Слава» – свята, глас 4-ий: «Веселися, Єрусалиме...», «І нині» – свята, глас той же: «У вертепі оселився Ти...». Після Трисвятого – тропар свята, глас 4-й (тричі).","sections":[{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава: І нині» – той же тропар. Кафизми 19-а і 20-а. Малі єктенії. Сідальні свята (по двічі). Полієлей. Величання свята: «Величаємо Тебе,/ Життєдавче Христе,/ що заради нас нині плоттю Народився/ від Неневісної// і Пречистої Діви Марії», і псалом вибраний. Сідальний свята після полієлею, глас 4-й. «Слава, і нині» – той же сідальний. Степенні – 1-ий антифон 4-го гласу. Прокимен, глас 4-й: «З утроби раніше віків родив Тебе, клявся Господь і не зречеться»; стих: «Сказав Господь Господеві моєму: Сиди праворуч Мене, доки не покладу ворогів Твоїх до підніжжя ніг твоїх». Євангеліє – свята. Після 50-го псалма: «Слава» – «Все сьогодні сповнюється радості, Христос родився від Діви», «І нині» – «Все сьогодні сповнюється радості, Христос родився у Вифлеємі». Стихира свята, глас 6-й: «Слава в вишніх Богу...». Канони: свята два, на 14 (ірмоси 1-го канону: «Христос народжується...», по двічі, тропарі на 6, і ірмоси 2-го канону: «Чудодіючи Владика спас людей...», по двічі, тропарі на 6). Біблійні пісні «Співаймо Господеві...». Катавасія – ірмоси обох канонів (по кожній пісні). Після 3-ої пісні – іпакої свята, глас 8-ий (один раз). Після 6-ої пісні – кондак та ікос свята, глас 3-ій. На 9-ій пісні «Чеснішу...» не співаємо, але співаємо приспіви свята. (Звершується звичайне кадіння). 1-ий хор співає приспів 1-го канону: «Величай, душе моя, Чеснішу і славнішу Горніх воїнств Діву Пречисту Богородицю», та ірмос 1-го канону: «Таїнство дивне бачу...». 2-ий хор – те саме. 1-ий хор приспів: «Величай, душе моя, Бога, від Діви плоттю народженого.», тропар: «Коли побачили волхви дивний рух надзвичайної нової зірки, що засяяла на небі, зрозуміли, що народився на землі у Вифлеємі Христос Цар, на спасіння наше». 2-ий хор приспів: «Величай, душе моя, у вертепі народженого Царя», тропар: «Коли побачили волхви дивний рух надзвичайної нової зірки, що засяяла на небі, зрозуміли, що народився на землі у Вифлеємі Христос Цар, на спасіння наше». 1-ий хор приспів: «Величай, душе моя, Бога, Якому волхви поклоняються..», тропар: «Волхвів стали питати: де Немовля – Цар, про народження Якого сповістила зірка, бо ми прийшли поклонитися Йому? Ірод-богоборець, хвилюючись, у гніві намагався вбити Христа.». 2-ий хор приспів: «Величай, душе моя, зіркою волхвам Сповіщеного...», тропар: «Волхвів стали питати: де Немовля – Цар, про народження Якого сповістила зірка, бо ми прийшли поклонитися Йому? Ірод-богоборець, хвилюючись, у гніві намагався вбити Христа». 1-ий хор приспів: «Величай, душе моя, чисту Діву і єдину Богородицю, що народила Христа Царя.», тропар: «Ірод довідався про час, коли з’явилася зірка, ведені якою волхви прийшли до Вифлеєма з дарами поклонитися Христу; але, направлені нею у вітчизну, залишили посоромленим лютого дітовбивцю». 2-ий хор приспів: «Волхви і пастирі прийшли поклонитися Христу, що народився у Вифлеємі-граді.», тропар: «Ірод довідався про час, коли з’явилася зірка, ведені якою волхви прийшли до Вифлеєма з дарами поклонитися Христу; але, направлені нею у вітчизну, залишили посоромленим лютого дітовбивцю.». 1-ий хор співає приспів 2-го канону: «Нині Діва народжує Владику всередині вертепа.», й ірмос 2-го канону: «Любити нам зі страхом зручніше мовчання, як безбідне; любов’ю ж складати пісні, протяженноскладні, Діво, незручно є; але дай нам, Мати, силу, наскільки є благовоління». 2-ий хор приспів: «Нині народжується Владика, як Немовля, від Матері Діви.», і той же ірмос. 1-ий хор приспів: «Нині пастирі бачать Спаса, пеленами повитого, покладеного в яслах.», тропар: «Прообрази несвітлі, і тіні перемінні; Ти, Мати чиста, побачила Слово, що явилося із врат зачинених, – істинну світлість; достойно Твою прославляємо утробу». 2-ий хор приспів: «Нині Владика неосяжний пеленається руб’ям, як Немовля», тропар: «Прообрази несвітлі, і тіні перемінні; Ти, Мати чиста, побачила Слово, що явилося із врат зачинених, – істинну світлість; достойно Твою прославляємо утробу». 1-ий хор приспів: Нині все творіння веселиться і радується: бо Христос народився від Діви.», тропар: «Прообрази несвітлі, і тіні перемінні; Ти, Мати чиста, побачила Слово, що явилося із врат зачинених, – істинну світлість; достойно Твою прославляємо утробу». 2-ий хор приспів: «Небесні Сили народженого Спаса Господа і Владику сповіщають світу.», тропар: «Одержавши бажане, і сподобившись Божого пришестя, христоімениті люди нині утішаються духовним народженням; бо Ти, Діво чиста, подаєш живоносну благодать поклонятися славі.». 1-ий хор приспів (замість «Слави»): «Величай, душе моя, триіпостасного і нероздільного Божества державу.», тропар: «Одержавши бажане, і сподобившись Божого пришестя, христоімениті люди нині утішаються духовним народженням; бо Ти, Діво чиста, подаєш живоносну благодать поклонятися славі». 2-й хор приспів (замість «І нині»): «Величай, душе моя, Того, Хто визволив нас від клятви.», тропар: «Одержавши бажане, і сподобившись Божого пришестя, христоімениті люди нині утішаються духовним народженням; бо Ти, Діво чиста, подаєш живоносну благодать поклонятися славі». Потім обидва хори разом співають приспів 1-го канону: «Величай, душе моя, Чеснішу...», і ірмос 1-го канону: «Таїнство дивне бачу...», потім обидва хори приспів 2-го канону: «Нині народжується Владика, як Немовля, від Матері Діви», і ірмос 2-го канону:»«Любити нам зі страхом зручніше мовчання...». Після 9-ої пісні «Достойно є» не співається. Світильний свята: «Прийшов до нас з неба Спаситель наш...». «Слава» – той же світильний, «І нині» – той же світильний. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 4-ий – 4. «Слава» – свята, глас 6-ий: «Коли прийшов час Твого на землю пришестя...», «І нині» – свята, глас 2-ий: «Нині Христос у Вифлеємі народжується від Діви...». Велике славослів’я. Після Трисвятого – тропар свята, глас 4-ий (один раз). Відпуст: «Христос, істинний Бог наш, що у вертепі народився і в яслах покладений був, заради нашого спасіння, молитвами Пречистої Своєї Матері і всіх святих, помилує і спасе нас, як благий і Людинолюбець». (До віддання, крім неділі, великий відпуст починається словами: «Христос, істинний Бог наш, що у вертепі народився...»)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята. ЛІТУРГІЯ свт. Іоана Злотоустого Антифони свята. Вхідний стих – свята: «З утроби раніше віків родив Тебе, клявся Господь і не розкається: Ти – Ієрей повік за чином Мелхиседековим». Примітка. Перед проголошенням вхідного стиха слід виголошувати «Премудрість, станьмо побожно». Після входу – тропар свята, глас 4-ий, «Слава: І нині» – кондак свята, глас 3-ій. Замість Трисвятого – «Усі ті, що в Христа хрестилися...». Прокимен, Апостол, алилуарій, Євангеліє і причасний – свята. Задостойник – приспів: «Величай, душе моя...» й ірмос: «Любити нам зі страхом...» (і до віддання свята Різдва Христового). Відпуст в кінці Літургії – як на ранній, але зі згадуванням імені святого отця нашого Іоана Злотоустого, архієпископа Константинополського. За традицією, після відпусту Літургії посеред церкви перед іконою свята вийшовши з вівтаря священнослужителі співають тропар свята, «Слава: І нині» – кондак свята і, за звичаєм, величання."}]},
{"date":"12-26","weekday":"субота","title":"Субота після Різдва Христового. Післясвято Різдва Христового. Собор Пресвятої Богородицi. Сщмч. Євфимія, єп. Сардійського (бл. 840). Прп. Костянтина Синадського (VІІІ). Прп. Евареста Студита (825). Віленсько-Остробрамських, названих «Трьох радостей» та «Милостива» ікон Божої Матері.","readings":["Суботи після Різдва Христового: 1 Тим., 288 зач., VI, 11 – 16. Мф., 46 зач. (від половини), XII, 15 – 21.","Богородиці: Євр., 306 зач., II, 11 – 18. Мф., 4 зач., II, 13 – 23."],"notes":"Звершується славослівна Собору Пресвятої Богородиці.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири свята, глас 2-ий – 6, «Слава: І нині» – свята, глас той же: «Слава в вишніх Богу...» (див. в службі Собору Богородиці 26 грудня). Вхід з кадилом. Прокимен великий, глас 7-ий: «Хто Бог великий...» (зі стихами). Ектенія сугуба: «Промовмо всі...». «Сподоби, Господи...». Ектенія прохальна: «Доповнімо вечірню молитву...», і голововклонна молитва. На стиховні стихири свята, глас 8-ий (зі своїми приспівами; див. в службі Собору Богородиці 26 грудня). «Слава: І нині» – свята, глас той же: «До Вифлеєма зійшлися пастирі...» (див. в службі Собору Богородиці 26 грудня). Після Трисвятого – тропар свята, глас 4-ий: «Різдво Твоє, Христе Боже наш...» (один раз). «Премудрість» та інше за звичаєм. Відпуст святковий (при відкритих царських вратах): «Христос, істинний Бог наш, що у вертепі народився і в яслах покладений був, заради нашого спасіння, молитвами Пречистої Своєї Матері, і всіх святих, помилує і спасе нас, як Благий і Людинолюбець». Примітка. Про особливості повечір’я і полуношниці див. в Типіконі за 26 грудня, 2-е «див»."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий: «Різдво Твоє, Христе Боже наш...» (двічі). «Слава: І нині» – тропар свята. Кафизми 16-а і 17-а. Малі ектенії. Сідальні свята (по двічі; див. в службі Собору Богородиці 26 грудня). Псалом 50-ий. Канони: свята два на 14 (ірмоси 1-го канону: «Христос народжується...», по двічі, тропарі на 6, та ірмоси 2-го канону: «Чудодіючи Владика спас людей...», по двічі, тропарі на 6,). Біблійні пісні «Співаємо Господеві...». Катавасія – ірмоси обох канонів свята Різдва Христового (по кожній пісні). Після 3-ої пісні – кондак і ікос свята, глас 6-ий. «Слава: І нині» – іпакої свята, глас 8-ий: «Тобі, Немовляті,...» (один раз; див. в Мінеї 25 грудня). Після 6-ої пісні – кондак святих і ікос Богородиці. На 9-ій пісні «Чеснішу» не співаємо, але до канонів свята Різдва Христового співаємо приспіви свята (див. На ранній в сам день свята). 1-ий приспів: «Величай, душе моя, Чеснішу і славнішу Горніх воїнств Діву Пречисту Богородицю». (Звершується звичайне кадіння). Після 9-ої пісні «Достойно є...» не співається. Світильний свята, «Слава: І нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На хвалітніх стихири свята, глас 4-ий – 4. «Слава» – свята глас 6-й: «Нині невидиме єство...», «І нині» – свята, глас 2 й: «Нині Христос у Вифлеємі народжується...». Велике славослів’я. Після Трисвятого – тропар свята глас 4-ий: «Різдво Твоє, Христе Боже наш...». Відпуст святковий: «Христос, істинний Бог наш, що у вертепі народився і в яслах покладений був, заради нашого спасіння, молитвами Пречистої Своєї Матері, і всіх святих, помилує і спасе нас, як благий і Людинолюбець»."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята: «Різдво Твоє, Христе Боже наш...». Кондак Богородиці: «Той, Хто перше денниці...»."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ: Блаженні з канону свята, пісня 3-я – 4 (з ірмосом) і пісня 6-а – 4. На вході: «Прийдіть поклонімось... спаси нас, Сину Божий, що народився від Діви, співаємо Тобі: Алилуя» (і до віддання свята, крім неділі). Після входу – тропар свята, глас 4-ий: «Різдво Твоє, Христе Боже наш...». «Слава: І нині» – кондак Богородиці, глас 6-ий: «Той, Хто перше денниці...». Співається Трисвяте. Прокимен, алилуарій і причасний – суботи після Різдва. Апостол і Євангеліє – суботи після Різдва і Собору Богородиці. Задостойник свята."}]},
{"date":"12-27","weekday":"неділя","title":"30-та неділя після П’ятдесятниці, після Різдва Христового. Глас 5-й. Прав. Йосифа Обручника, Давида, царя, і Якова, брата Господнього. (перехідне святкування у неділю після Різдва Христового). Ап. першомч. та архідиякона Стефана (34). Прп. Федора Накресленого, спов. (бл. 840). Свт. Федора, архієп. Константинопольського (бл. 686).","glas":5,"readings":["Ран. – Єв. 8-е, Ін., 64 зач., XX, 11 – 18.","Літ. – неділі після Різдва Христового: Гал., 200 зач., I, 11 – 19. Мф., 4 зач., II, 13 – 23.","Свв. Богоотців: Гал., 200 зач., I, 11 – 19. Мф., 4 зач., II, 13 – 23 (читання співпадають, отже їх не повторюємо).","Першомч.: Діян., 17 зач., VI, 8 – 15; VII, 1 – 5, 47 – 60. Мф., 87 зач., XXI, 33 – 42."],"notes":"Воскресна служба Октоїха звершується разом зі службою післясвята Різдва Христового і святих Богоотців за Марковою главою на 26 грудня. Служба першомученика і архідиякона Стефана звершується на повечір’ї.","sections":[{"svc":"ВЕЛИКІЙ ВЕЧІРНІ","text":"НА ВЕЛИКІЙ ВЕЧІРНІ «Блажен муж» – кафизма вся. На «Господи, взиваю» стихири на 10: стихири воскресні глас 5-ий – 3, свята, глас 2-ий – 4, богоотців, глас 1-ий – 3. «Слава» – святих, глас 6-ий: «Пам’ять святкуємо Давида...», «І нині» – Богородичний воскресний, глас 5-ий: «У Червоному морі...». Вхід. Прокимен дня. На літії стихири свята. На стиховні стихири воскресні, глас 5-ий. «Слава» – отців, глас 6-ий: «Різдво Твоє стало пам’яттю святих...», «І нині» – свята, глас 4-ий: «Днесь невидима природа...». Після Трисвятого – тропар свята (двічі), і тропар святих, глас 2-ий: «Благовісти Йосифе...» (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар воскресний, глас 4-ий (двічі). «Слава» – тропар отців, глас 2-ий. «І нині» – тропар свята, глас 4-ий: «Різдво Твоє Христе Боже...» Кафизми 2-а і 3-я. Малі єктенії. Сідальні Октоїха. Полієлей. Непорочні. «Ангельський собор...». Іпакої. Степенні і прокимен – гласу 4-го. Євангеліє воскресне 8-е. «Воскресіння Христове бачивши...». Після 50-го псалма: «Слава» – «Молитвами апостолів...». Стихира воскресна, глас 6-ий: «Воскрес Ісус із гробу...». Канони: неділі (Октоїха) з ірмосом на 4 (ірмоси один раз), Богородиці на 2, свята на 4 і святих богоотців на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – кондак та ікос свята. Сідальні святих, глас 3-ій, «Слава» – інший сідальний святих, глас той самий, «І нині» – сідальний Мінеї. Після 6-ої пісні – кондак ікос святих, глас 3-ій. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні – «Свят Господь Бог наш». Екзапостиларій воскресний. «Слава» – світильний святих. «І нині» – світильний свята: «Прийшов до нас із неба Спаситель...». «Все, що дише...» і хвалітні псалми. На хвалітніх стихири на 8: воскресні, глас 4-ий – 4, і свята, глас 4-ий (зі своїми приспівами) – 4. «Слава» – святих, глас 8-ий: «Кров і вогонь...», «І нині» – «Преблагословенна єси...». Велике славослів’я. Тропар воскресний: «Воскрес із гробу...» Перед 1-им часом на «Слава: І нині» – стихира євангельська 8-а."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар воскресний. «Слава» – тропар свята, святих і преподобного читаються поперемінно. Кондаки свята, святих і преподобного також поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні гласу – 4, свята, 1-го канону пісня 9-я – 4, і святих, пісня 6-а – 4. На вході: «Прийдіть... спаси нас, Сину Божий, що воскрес із мертвих...». Після входу – тропар воскресний, тропар свята, тропар святих. «Слава» – кондак святих, «І нині» – кондак свята, глас 3-ій. Співається Трисвяте. Прокимен і Алилуарій – Неділі після Різдва і святих. Апостол і Євангеліє – Неділі після Різдва Христового і святих Боготців Задостойник свята Різдва Христового. Причасний – недільний: «Хваліть Господа...», і свята: «Радуйтеся, праведні...». Відпуст недільний: «Христос, що воскрес із мертвих...» Примітка. Два канони свята Різдва Христового в період віддання свята (починаючи з цього дня) співаються по черзі: в перший день – 1-ий, у другий день – 2-ий і т. д."}]},
{"date":"12-28","weekday":"понеділок","title":"31-й тиждень після П’ятдесятниці. Мчч. 20 000, що в Нікомидії були спалені: сщмч. Гликерія, пресвіт., мч. Зинона, сщмч. Феофіла, дияк., мчч. Дорофея, Мардонія, сщмч. Мигдонія, дияк., мчч. Індиса, Горгонія, Петра, Євфимія, мцц. Агафії, Домни, Феофіли та інших (302). Ап. від 70-х Никанора (34).","readings":["Євр., 329 зач., XI, 17 – 23, 27 – 31. Мк., 42 зач., IX, 42 – X, 1.","Мчч.: Рим., 96 зач. (від половини), VIII, 3 – 9. Лк., 51 зач. (від половини), X, 19 – 21."],"notes":"Служба мучеників не має святкового знака, звершується разом зі службою післясвята.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизми немає. На «Господи, взиваю» стихири на 6: свята, глас 5-ий – 3, і мучеників, глас 4-ий – 3. «Слава: І нині» – свята, глас 5-ий: «Нехай веселяться небеса...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава: І нині» – свята, глас 1-ий: «Слава в вишніх Богу...». Після Трисвятого – тропар мучеників, глас 2-ий. «Слава: І нині» – тропар свята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава» – тропар мучеників, глас 2-ий, «І нині» – тропар свята, глас 4-ий. Кафизми 4-а і 5-а. Малі єктенії. Сідальні свята (по двічі). Псалом 50-ий. Канони: свята 2-ий з ірмос на 8 (ірмоси по двічі) і мучеників на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону мучеників. Після 3-ої пісні – кондак мучеників, глас 2-ий; сідальний мучеників, глас 1-ий. «Слава: І нині» – сідальний свята, глас той же. Після 6-ої пісні – кондак та ікос свята, глас 3-ій. На 9-ій пісні співаємо «Чеснішу». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава: І нині» – той же світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава: І нині» – свята, глас 1-ий: «Небо і земля...». Після Трисвятого – тропар мучеників, глас 2-ий. «Слава: І нині» – тропар свята, глас 4-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята. «Слава» – тропар мучеників. Кондак тільки свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісні 4-а (з ірмосом) і 5-а – 6. На вході: «Прийдіть поклонімось... що народився від Діви...». Після входу – тропарі і кондаки: У храмі Господському – тропар свята, тропар мучеників. «Слава» – кондак мучеників, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар мучеників; кондак свята. «Слава» – кондак мучеників, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар мучеників; кондак храму. «Слава» – кондак мучеників, «І нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята і мучеників. Апостол і Євангеліє – дня і мучеників. Задостойник свята."}]},
{"date":"12-29","weekday":"вівторок","title":"Прп. Іова Манявського (1621). Мчч. 14 000 немовлят, яких Ірод убив у Вифлеємі (І). Прп. Маркела, ігумена обителі «Невсипущих» (485). Прпп. Марка, гробокопача, Феофіла та Іоана Києво-Печерських, в Ближніх печерах (ХІІ). Прп. Фадея Студита, спов. (818).","readings":["Євр., 333 зач., XII, 25 – 26; XIII, 22 – 25. Мк., 43 зач., X, 2 – 12.","Немовлят мчч.: 2 Кор., 180 зач., V, 15 – 21. Мф., 4 зач., II, 13 – 23.","Прп: Гал., 213 зач., V, 22 – VI, 2. Мф., 43 зач., XI, 27 – 30 (під зачало)."],"notes":"Звершується славослівна служба мучеників разом зі службою прп. Іова (із Загальної мінеї), без святкового знаку, та службою післясвята.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 6-а. На «Господи, взиваю» стихири на 6: мучеників, глас 4-ий – 3 і преподобного, глас 8-ий – 3. «Слава» – мучеників, глас 8-ий: «Ірод беззаконний, бачачи зірку...», «І нині» – свята, глас той же: «Преславне таїнство нині звершується...». Входу немає. Прокимен дня. На стиховні стихири свята, глас 6-ий. «Слава» – мучеників, глас 8-ий: «Ісус народився у Вифлеємі Юдейському...», «І нині» – свята, глас той же: «Господи, прийшовши у Вифлеєм...». Після Трисвятого – тропар мучеників, глас 1-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – тропар свята, глас 4-ий."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» тропар свята (один раз). тропар мучеників, глас 1-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – тропар свята, глас 4-ий. Кафизми 7-а і 8-а. Малі єктенії. Сідальні з Мінеї. Псалом 50-ий Канони: свята з ірмосом – на 4 (ірмоси по двічі), мучеників на 6 і преподобного – на 4. Катавасія свята після кожної пісні – «Христос народжується...». Після 3-ої пісні – кондак та ікос свята, глас 3-ій, кондак немовлят, глас 6-ий, кондак та ікос преподобного, глас 2-ий. сідальний немовлят. «Слава» – сідальний преподобного, «І нині» – сідальний свята, глас 4-ий. Після 6-ої пісні – кондак та ікос Мінеї, глас 4-ий. На 9-ій пісні співаємо «Чеснішу...». Світильний немовлят. «Слава» – світильний преподобного, «І нині» – світильний свята. «Все, що дише...» і хвалітні псалми. На «Хваліте» стихири мучеників, глас 1-ий – 4. «Слава» – преподобного, глас 2-ий: «Преподобний отче, змалку навчившись жити побожно...», «І нині» – свята, глас 5-ий: «Бачачи Тебе, все творіння...». Велике славослів’я. Після Трисвятого – тропар мучеників, глас 1-ий. «Слава» – тропар преподобного, глас 8-ий, «І нині» – тропар свята, глас 4-ий."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар свята, «Слава» – тропарі мучеників та преподобного поперемінно. Кондаки свята і мучеників читаються поперемінно."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ Блаженні, з канону свята, пісня 7-ма, – на 4 і мучеників, пісня 6-а – на 4. На вході: «Прийдіть поклонімось... спаси нас, Сину Божий, що народився від Діви, співаємо Тобі: Алилуя». Після входу тропарі та кондаки: У храмі Господському – тропар свята, тропар мучеників, тропар преподобного; кондак мучеників. «Слава» – кондак преподобного, «І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму, тропар мучеників, тропар преподобного; кондак свята, кондак мучеників. «Слава» – кондак преподобного, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму, тропар мучеників, тропар преподобного; кондак храму, кондак мучеників. «Слава» – кондак преподобного, «І нині» – кондак свята. Прокимен, Алилуя і причасний – свята і мучеників. Апостол і Євангеліє – дня, мучеників і преподобного (під зачало). Задостойник свята."}]},
{"date":"12-30","weekday":"середа","title":"Мц. Анісії Солунської (285 – 305). Сщмч. Зотика, пресвітера (ІV). Ап. від 70-х Тимона, єп. Бострійського (І). Мч. Філетера Нікомидійського (311). Прп. Феодори Кесарійської (VІІІ). Прп. Феодори Константинопольської (940).","readings":["Як., 50 зач., I, 1 – 18. Мк., 44 зач., X, 11 – 16."],"notes":"Служба мц. Анісії і прп. Меланії Римлянки (з 31 грудня) не має святкового знака, звершується разом зі службою післясвята.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ кафизма 9-а. На «Господи, взиваю» стихири на 6: мучениці, глас 4-ий – 3 і преподобної, глас той же – 3. «Слава: І нині» – свята, глас 1-ий: «Слава в вишніх Богу...» Входу немає. Прокимен дня. На стиховні стихири свята, глас 2-ий (зі своїми приспівами). «Слава: І нині» – свята, глас 1-ий: «За образом і подобою...». Після Трисвятого – тропар свята, глас 4-ий (один раз)."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята, глас 4-ий (двічі). «Слава, і нині» – той же тропар. Кафизми 10-а і 11-а. Малі єктенії. Сідальні свята. Псалом 50-ий. Канони: свята 2-ий з ірмосом на 6 (ірмоси по двічі), мучениці на 4 і преподобної на 4. Біблійні пісні «Співаймо Господеві...». Катавасія після 3-ої, 6-ої, 8-ої і 9-ої пісень – ірмоси канону преподобної. Після 3-ої пісні – сідальний мучениці, глас 4-ий. «Слава» – сідальний преподобної, глас той же, «І нині» – сідальний свята, глас той же. Після 6-ої пісні – кондак та ікос свята, глас 3-ій. На 9-ій пісні співаємо «Чеснішу...». Після 9-ої пісні «Достойно є» не співається. Світильний свята. «Слава: І нині» – той же світильний. «Хваліте Господа з Небес...» і хвалітні псалми. Читається повсякденне славослів’я. На стиховні стихири свята, глас 6-ий (зі своїми приспівами). «Слава: І нині» – свята, глас той же: «Сонце, Сина...». Після Трисвятого – тропар свята, глас 4-ий (один раз)."},{"svc":"ЧАСАХ","text":"НА ЧАСАХ – тропар і кондак свята."},{"svc":"ЛІТУРГІЇ","text":"НА ЛІТУРГІЇ блаженні свята, пісня 8-а – 6 (з ірмосом). На вході: «Прийдіть поклонімось... спаси нас, Сину Божий, що народився від Діви...». Після входу – тропарі і кондаки: У храмі Господському – тропар свята. «Слава: І нині» – кондак свята. У храмі Богородиці – тропар свята, тропар храму. «Слава» – кондак свята, «І нині» – кондак храму. У храмі святого – тропар свята, тропар храму. «Слава» – кондак храму, «І нині» – кондак свята. Співається Трисвяте. Прокимен, алилуарій і причасний – свята.. Апостол і Євангеліє – дня. Задостойник: свята."}]},
{"date":"12-31","weekday":"четвер","title":"Віддання свята Різдва Христового. Прп. Меланії Римлянки (439). Свт. Петра Могили, митр. Київського і Галицького, та всієї Руси (1647). Свт. Феофілакта, архієп. Болгарського (1107).","readings":["Ран. – Ін., 35 зач. (від пол.), X, 1 – 9.","Літ. – Як., 51 зач., I, 19 – 27. Мк., 45 зач., X, 17 – 27.","Свт.: Євр., 318 зач., VII, 26 – VIII, 2. Ін., 36 зач., X, 9 – 16."],"notes":"Звершується славослівна служба віддання свята Різдва Христового разом з полієлейною службою свт. Петра Могили (див. мінея за 1 січня). Служба прп. Меланії Римлянки переноситься на 30 грудня.","sections":[{"svc":"ВЕЧІРНІ","text":"НА ВЕЧІРНІ «Блажен муж» – 1-ий антифон. На «Господи, взиваю» стихири на 8: свята, глас 2-ий – 3 і святителя, глас 5-ий – 5. «Слава» – святителя, глас той же: «Ріка, духовними дарами наповнена...», «І нині» – свята, глас 2-ий: «Коли Август став єдиним володарем на землі...». Вхід з кадилом. Прокимен дня. Паремії святителя – 3. На стиховні стихири свята, глас 2-ий і глас 3-ій (зі своїми приспівами). «Слава» – святителя, глас 8-ий: «Богом наперед призначений...», «І нині» – свята, глас 4-ий: «У вертепі оселився Ти...». Після Трисвятого – тропар святителя, глас 4-ий «Слава: І нині» – тропар свята, глас той же."},{"svc":"РАННІЙ","text":"НА РАННІЙ на «Бог Господь» – тропар свята (двічі), глас 4-ий (двічі). «Слава» – тропар святителя, глас 4-ий; «І нині» – тропар свята, глас той же. Кафизми 13-а і 14-а. Малі єктенії. Сідальні святого. «Слава: І нині» – сідальні свята. Полієлей. Величання святителя і вибраний псалом. Після полієлею сідальний святителя після полієлея, глас 1-ий. «Слава: І нині» – сідальний свята, глас 4-ий. Степенні антифони, глас 4-ий. Прокимен і Євангеліє святителя. Псалом 50-ий. «Слава» «Молитвами святителя Петра...», стихира святителю, глас 6-ий: «Благодать Святого Духа вилилася...». Канони: свята 1-ий з ірмосом на 6 (ірмоси по двічі), і 2-ий з ірмосом на 4 (ірмоси по двічі), святителя на 4. Біблійні пісні «Співаймо Господеві...». Катавасія «Христос народжується...». Після 3-ої пісні – кондак і ікос святителя, глас 3-ій, сідальний святителя, глас 4-ий. «Слава: І нині» – іпакої свята, глас 8-ий (один раз). Після 6-ої пісні – кондак та ікос свята, глас 3-ій. На 9-ій пісні «Чеснішу...» не співаємо, але співаємо приспіви свята. (Звершується звичайне кадіння). 1-ий хор співає приспів 1-го канону: «Величай, душе моя, Чеснішу і славнішу Горніх воїнств Діву Пречисту Богородицю», й ірмос 1-го канону: «Таїнство дивне бачу...». 2-ий хор – те саме. 1-ий хор приспів: «Величай, душе моя, Бога, від Діви плоттю народженого», тропар: «Коли побачили волхви дивний рух надзвичайної нової зірки, що засяяла на небі, зрозуміли, що народився на землі у Вифлеємі Христос Цар, на спасіння наше». 2-ий хор приспів: «Величай, душе моя, у вертепі народженого Царя», тропар: «Коли побачили волхви дивний рух надзвичайної нової зірки, що засяяла на небі, зрозуміли, що народився на землі у Вифлеємі Христос Цар, на спасіння наше». 1-ий хор приспів: «Величай, душе моя, Бога, Якому волхви поклоняються..», тропар: «Волхвів стали питати: де Немовля – Цар, про народження Якого сповістила зірка, бо ми прийшли поклонитися Йому? Ірод-богоборець, хвилюючись, у гніві намагався вбити Христа.». 2-ий хор приспів: «Величай, душе моя, зіркою волхвам Сповіщеного...», тропар: «Волхвів стали питати: де Немовля – Цар, про народження Якого сповістила зірка, бо ми прийшли поклонитися Йому? Ірод-богоборець, хвилюючись, у гніві намагався вбити Христа». 1-ий хор приспів: «Величай, душе моя, чисту Діву і єдину Богородицю, що народила Христа Царя.», тропар: «Ірод довідався про час, коли з’явилася зірка, ведені якою волхви прийшли до Вифлеєма з дарами поклонитися Христу; але, направлені нею у вітчизну, залишили посоромленим лютого дітовбивцю». 2-ий хор приспів: «Волхви і пастирі прийшли поклонитися Христу, що народився у Вифлеємі-граді.», тропар: «Ірод довідався про час, коли з’явилася зірка, ведені якою волхви прийшли до Вифлеєма з дарами поклонитися Христу; але, направлені нею у вітчизну, залишили посоромленим лютого дітовбивцю.». 1-ий хор співає приспів 2-го канону: «Нині Діва народжує Владику всередині вертепа.», й ірмос 2-го канону: «Любити нам зі страхом зручніше мовчання, як безбідне; любов’ю ж складати пісні, протяженноскладні, Діво, незручно є; але дай нам, Мати, силу, наскільки є благовоління». 2-ий хор приспів: «Нині народжується Владика, як Немовля, від Матері Діви.», і той же ірмос. 1-ий хор приспів: «Нині пастирі бачать Спаса, пеленами повитого, покладеного в яслах.», тропар: «Прообрази несвітлі, і тіні перемінні; Ти, Мати чиста, побачила Слово, що явилося із врат зачинених, – істинну світлість; достойно Твою прославляємо утробу». 2-ий хор приспів: «Нині Владика неосяжний пеленається руб’ям, як Немовля», тропар: «Прообрази несвітлі, і тіні перемінні; Ти, Мати чиста, побачила Слово, що явилося із врат зачинених, – істинну світлість; достойно Твою прославляємо утробу». 1-ий хор приспів: Нині все творіння веселиться і радується: бо Христос народився від Діви.», тропар: «Прообрази несвітлі, і тіні перемінні; Ти, Мати чиста, побачила Слово, що явилося із врат зачинених, – істинну світлість; достойно Твою прославляємо утробу». 2-ий хор приспів: «Небесні Сили народженого Спаса Господа і Владику сповіщають світу.», тропар: «Одержавши бажане, і сподобившись Божого пришестя, христоімениті люди нині утішаються духовним народженням; бо Ти, Діво чиста, подаєш живоносну благодать поклонятися славі.». 1-ий хор приспів (замість «Слави»): «Величай, душе моя, триіпостасного і нероздільного Божества державу.», тропар: «Одержавши бажане, сподобившись Божого пришестя, христоімениті люди нині утішаються духовним народженням; бо Ти, Діво чиста, подаєш живоносну благодать поклонятися славі». 2-й хор приспів (замість «І нині»): «Величай, душе моя, Того, Хто визволив нас від клятви.», тропар: «Одержавши бажане, і сподобившись Божого пришестя, христоімениті люди нині утішаються духовним народженням; бо Ти, Діво чиста, подаєш живоносну бл"}]}
];
